INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('stuffed-breakfast-potatoes', 'Stuffed Breakfast Potatoes', 1, 0, 20, '{"calories": 357, "protein": 21.4, "carbs": 15.9, "fat": 23.2, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['imported'], '[{"item": "baked potatoes, fully cooked and slightly cooled", "quantity": 1, "unit": "serving", "category": "other"}, {"item": "melted butter", "quantity": 1, "unit": "serving", "category": "other"}, {"item": "kosher salt and black pepper", "quantity": 1, "unit": "serving", "category": "other"}, {"item": "shredded cheese (your choice)", "quantity": 1, "unit": "serving", "category": "other"}, {"item": "eggs", "quantity": 1, "unit": "serving", "category": "other"}, {"item": "additional fillings of your choice: sauteed vegetables, bacon or ham, etc.", "quantity": 1, "unit": "serving", "category": "other"}]'::jsonb, '["Preheat your Oven to 350", "Slice the top off your cooked potato", "Scoop out the middle", "Brush the inside with a little butter, salt, pepper, cayenne, etc... (if you like em a little spicy)", "Start layering your toppings starting with the Cheese", "Add whatever else you like, Peppers, Bacon Bits, Ham, etc...", "Crack an egg on top, then MORE CHEESE :)", "Place on a baking sheet and bake for 20 minutes until the whites are set''"]'::jsonb, NULL, NULL, FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('neapolitan-pizza-dough-recipe', 'Neapolitan Pizza Dough Recipe', 4, 15, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['nutrition-generated'], '[{"item": "bread flour ((3 dipped and leveled cups))", "quantity": 461.0, "unit": "grams", "category": "other"}, {"item": "fine sea salt ((2 teaspoons))", "quantity": 13.0, "unit": "grams", "category": "other"}, {"item": "instant dry yeast ((scant 1/4 teaspoon))", "quantity": 0.9, "unit": "grams", "category": "other"}, {"item": "cool water ((scant 1¼ cups))", "quantity": 276.0, "unit": "grams", "category": "other"}]'::jsonb, '["In a large bowl with an airtight lid, mix together the flour, salt, and yeast with a wooden spoon or dough whisk. Pour in the water and mix with the spoon or dough whisk until most of the dry flour in the bottom of the bowl has been absorbed by the dough, then use your hands to turn and knead the dough just until all the flour is incorporated. (I like to push my fingers in and out of the dough like a cat kneading with its paws. That way, I know the last bits of dry flour are fully incorporated, not just stuck to the surface.)", "Cover the bowl with its lid and let the dough rise at room temperature for 18 to 24 hours (20 hours is my sweet spot) or until it has doubled in volume.", "Scrape the dough onto a floured surface (it will be goopy with bubbles throughout). Divide it into two or three equal-size pieces—two if you like to make 12 to 14-inch pizzas, three if you like to make 10 to 12-inch pizzas. Form the dough pieces into balls, dusting your hands with flour if needed, and place each one in a separate airtight quart-size container. Cover and refrigerate for 24 to 48 hours (or up to 72 hours).", "Take the dough out of the refrigerator at least 1 hour (preferably 2 hours) before you plan to stretch it for pizza."]'::jsonb, NULL, NULL, FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('homemade-french-fries-in-air-fry-range', 'Homemade French Fries in Air Fry Range', 4, 45, 20, '{"calories": 153, "protein": 3.0, "carbs": 26.0, "fat": 5.0, "saturated_fat": 1.0, "polyunsaturated_fat": 4.0, "monounsaturated_fat": null, "sodium": 782.0, "potassium": null, "fiber": 2.0, "sugar": 1.0, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['baking', 'vegetarian', 'vegan'], '[{"item": "Russet Potatoes", "quantity": 1.0, "unit": "serving", "category": "produce"}, {"item": "Avocado Oil", "quantity": 1.0, "unit": "tbsp", "category": "produce"}, {"item": "Lawry''s Seasoned Salt", "quantity": 2.0, "unit": "tsp", "category": "pantry", "notes": "season to taste"}]'::jsonb, '["Select Air Fry and set the cooking temperature to 400°F.", "Wash the potatoes. Peel if you prefer no skins. I recommend leaving them on.", "Cut the ends off of the potato and slice the potatoes into 1/2 in. slices lengthwise.", "Now cut each slice into even strips that are around 1/2 inch thick.", "Place the sliced potatoes in a bowl of cold water.", "Agitate the potatoes in the water with your hands until the water becomes cloudy.", "Pour out the water and refill the bowl with cold water again.", "Allow the potatoes to soak for 15-30 minutes. (the longer the better)", "Drain the water and place the potatoes on a paper towel-lined baking sheet.", "Pat with paper towels to remove excess water. Allow the potatoes to air dry for a minimum of 15 minutes.", "Return the dry potatoes to the mixing bowl and drizzle oven avocado oil.", "Toss the potatoes to coat them lightly in oil.", "Season the potatoes and toss again to coat evenly.", "Dump the oiled and seasoned potatoes onto the Frigidaire ReadyCook Air FryTray.", "Spread the potatoes out into one layer.", "Place the air fry tray into the Frigidaire Air Fry Oven with a prepared drip tray two rack spaces below the air fry tray to prevent any crumbs or drips from falling onto the bottom of the oven.", "Air fry French Fries for 20 minutes turning with a spatula halfway through the cooking cycle.", "For extra crispy fries turn the air frying temperature up to 500° for an additional 5 minutes or until the fries reach the desired crispness."]'::jsonb, 'https://www.hollishomestead.com/homemade-french-fries-in-air-fry-range/#recipe', 'https://www.hollishomestead.com/wp-content/uploads/2022/01/Air-Fried-Crunchwrap-Supreme-87.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mini-heart-shaped-cakes', 'Mini Heart Shaped Cakes', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['nutrition-generated'], '[{"item": "all-purpose flour", "quantity": 120.0, "unit": "g", "category": "grains"}, {"item": "baking powder", "quantity": 0.75, "unit": "tsp", "category": "pantry"}, {"item": "baking soda", "quantity": 0.25, "unit": "tsp", "category": "pantry"}, {"item": "fine salt", "quantity": 0.25, "unit": "tsp", "category": "pantry"}, {"item": "unsalted butter", "quantity": 57.0, "unit": "g", "category": "dairy", "notes": "melted and cooled"}, {"item": "neutral oil", "quantity": 55.0, "unit": "g", "category": "pantry"}, {"item": "granulated sugar", "quantity": 150.0, "unit": "g", "category": "pantry"}, {"item": "large egg", "quantity": 50.0, "unit": "g", "category": "dairy"}, {"item": "egg yolk", "quantity": 18.0, "unit": "g", "category": "dairy"}, {"item": "full-fat sour cream", "quantity": 120.0, "unit": "g", "category": "dairy"}, {"item": "vanilla extract", "quantity": 1.0, "unit": "tsp", "category": "pantry"}, {"item": "chocolate chips", "quantity": 130.0, "unit": "g", "category": "pantry"}, {"item": "coconut oil", "quantity": 1.5, "unit": "tsp", "category": "pantry"}]'::jsonb, '["Preheat the oven to 325°F.", "In a medium bowl, whisk together all-purpose flour (1 cup), baking powder (¾ tsp), baking soda (¼ tsp), and fine salt (¼ tsp) until evenly combined.", "In a separate bowl, whisk unsalted butter (¼ cup), neutral oil (¼ cup), and granulated sugar (¾ cup) until smooth. Add large egg (1) and egg yolk (1) and whisk until fully incorporated, then mix in full-fat sour cream (½ cup) and vanilla extract (1 tsp).", "Gently fold the dry ingredients into the wet ingredients just until combined.", "Place the silicone heart mold on a quarter sheet pan. Fill each cavity with 60–65 grams of batter, or about halfway full.", "Bake 16–20 minutes, or until the cakes are set in the center. Let cool, then transfer the entire mold to the freezer and freeze for at least 3 hours. The cakes should release easily once fully frozen. If they don’t, freeze longer.", "Once the cakes are removed, wash and dry the silicone molds thoroughly.", "Add chocolate chips (¾ cup) and coconut oil (1½ tsp) to a microwave-safe bowl. Microwave in 20–30 second intervals, stirring well between each, until fully melted and smooth.", "Pour the melted chocolate evenly into each clean mold cavity. Working quickly, place the frozen cakes upside down into the chocolate, gently pressing so the tops make contact with the coating. Return the mold to the freezer for 15 minutes, then pop the cakes loose."]'::jsonb, 'https://www.simplysissom.com/mini-heart-shaped-cakes/#tasty-recipes-18913-jump-target', NULL, FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('buttermilk-banana-bread-recipe', 'Buttermilk Banana Bread Recipe', 4, 10, 50, '{"calories": 224, "protein": 3.0, "carbs": 33.0, "fat": 8.0, "saturated_fat": 5.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 77.0, "potassium": null, "fiber": null, "sugar": 18.0, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['dessert', 'baking', 'vegetarian'], '[{"item": "unsalted butter", "quantity": 0.5, "unit": "cup", "category": "dairy", "notes": "(softened"}, {"item": "granulated sugar", "quantity": 1.0, "unit": "cup", "category": "pantry"}, {"item": "eggs", "quantity": 1.0, "unit": "serving", "category": "dairy"}, {"item": "mashed brown bananas", "quantity": 1.0, "unit": "cup", "category": "produce"}, {"item": "buttermilk", "quantity": 0.25, "unit": "cup", "category": "dairy"}, {"item": "vanilla extract", "quantity": 0.5, "unit": "teaspoon", "category": "pantry"}, {"item": "all-purpose flour", "quantity": 1.75, "unit": "cups", "category": "grains"}, {"item": "baking powder", "quantity": 1.0, "unit": "teaspoon", "category": "pantry"}, {"item": "salt", "quantity": 0.25, "unit": "teaspoon", "category": "pantry"}, {"item": "baking soda", "quantity": 0.125, "unit": "teaspoon", "category": "pantry"}]'::jsonb, '["Preheat the oven to 350 degrees F. Grease a 9x5-inch loaf pan with nonstick cooking spray and set aside.", "In the bowl of a stand mixer or by using a hand mixer, cream butter and sugar together. Add eggs, mashed bananas, buttermilk, and vanilla until combined.", "Add in the flour, baking powder, salt and soda. Mix until just combined. Pour batter into prepared pan and bake for 50-55 minutes or until a toothpick comes out clean.", "Let bread cool on a wire rack for 15 minutes. Loosen the bread with a knife and carefully remove from pan. Let the bread cool completely on the cooling rack. Slice and enjoy!"]'::jsonb, 'https://www.twopeasandtheirpod.com/buttermilk-banana-bread/', 'https://www.twopeasandtheirpod.com/wp-content/uploads/2018/02/Buttermilk-Banana-Bread-2.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('all-purpose-chicken-thigh-marinade', 'All-Purpose Chicken Thigh Marinade', 6, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['imported'], '[{"item": "soy sauce", "quantity": 3.0, "unit": "tablespoons", "category": "pantry", "notes": "or tamari (for gluten-free)"}, {"item": "mirin sweet rice wine", "quantity": 2.0, "unit": "tablespoons", "category": "grains", "notes": "maple syrup or honey"}, {"item": "Dijon mustard", "quantity": 1.0, "unit": "tablespoon", "category": "pantry"}, {"item": "rice wine vinegar", "quantity": 1.0, "unit": "tablespoon", "category": "grains", "notes": "or white wine vinegar"}, {"item": "neutral vegetable oil", "quantity": 1.0, "unit": "tablespoon", "category": "pantry"}, {"item": "crushed", "quantity": 1.0, "unit": "tablespoon", "category": "other", "notes": "grated garlic"}, {"item": "cayenne pepper", "quantity": 1.0, "unit": "teaspoon", "category": "produce"}, {"item": "boneless chicken thighs", "quantity": 2.0, "unit": "pounds", "category": "meat", "notes": "or 2½-3 pounds bone-in chicken thighs"}, {"item": "Kosher salt and fresh", "quantity": 1.0, "unit": "", "category": "pantry", "notes": "ground black pepper"}]'::jsonb, '["Combine all ingredients and mix well."]'::jsonb, 'https://familystylefood.com/chicken-thigh-marinade/#wprm-recipe-container-92945', NULL, FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('algerian-kefta-meatballs', 'Algerian Kefta (Meatballs)', 4, 0, 0, '{"calories": 546, "protein": 22.7, "carbs": 372.2, "fat": 30.6, "saturated_fat": 12.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 10070.3, "potassium": 6.0, "fiber": 9.2, "sugar": 5.9, "vitamin_a": null, "vitamin_c": 6.6, "calcium": 144.9, "iron": 10.5}'::jsonb, ARRAY['beef', 'algerian', 'themealdb', 'nutrition-generated'], '[{"quantity": 1.0, "unit": "lb", "item": "Ground Beef", "notes": null, "category": "meat"}, {"quantity": 4.0, "unit": "cloves", "item": "Crushed Garlic", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Water", "notes": null, "category": "other"}]'::jsonb, '["Combine ground beef with 1/2 of the minced garlic and 1 tablespoon chopped onion in a large bowl. Mix with your hands until fully incorporated. Shape meat mixture into 1 1/2-inch oblong patties; you should have 12 to 14 meatballs.", "Heat a large skillet over medium-high heat. Brown patties in batches in the hot skillet until crispy on both sides and no longer pink in the center, about 10 minutes. Set meatballs aside in a rimmed serving dish.", "Reduce heat to medium and stir remaining chopped onion into drippings in the skillet. Season with salt and pepper. Cook, stirring constantly, until onion has softened and turned translucent, about 5 minutes. Stir in remaining garlic and cook for 30 seconds. Stir in Roma tomatoes, dried parsley, and ras el hanout. Pour in water. Cook until tomatoes are soft, about 5 minutes.", "Pour tomato sauce over meatballs to serve."]'::jsonb, 'https://www.allrecipes.com/recipe/153790/algerian-kefta-meatballs/', 'https://www.themealdb.com/images/media/meals/8rfd4q1764112993.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('arepa-pabellón', 'Arepa Pabellón', 4, 0, 0, '{"calories": 1302, "protein": 97.4, "carbs": 35.7, "fat": 83.0, "saturated_fat": 26.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1425.2, "potassium": 314.8, "fiber": 2.9, "sugar": 9.7, "vitamin_a": null, "vitamin_c": null, "calcium": 151.2, "iron": 6.4}'::jsonb, ARRAY['beef', 'venezulan', 'themealdb', 'nutrition-generated', 'baking', 'grilling'], '[{"quantity": 1.0, "unit": "serving", "item": "Arepa Filled With Mozarella Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Ripe Bananas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "can", "item": "Black Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "De Gallo Sauce", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "kg", "item": "Shredded Meat", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Prepare the meat in a skillet and add salt and pepper to taste, heat the beans over medium heat in a pan, fry or grill the ripe plantains as indicated on its package and cut the tomato into small cubes. Reserve these ingredients until filling.", "Preheat the grill or pan and grill the arepa, putting it once on each side until they are golden brown.", "With the help of a knife, open it by the edge through the middle, creating a space to fill it with the ripe plantain, the beans, meat and chopped tomato.", "Serve with a little pico de gallo or guacamole dip sauce."]'::jsonb, 'https://goya.es/en/recipes/arepa-rellena-con-carne-frijol-y-madurito', 'https://www.themealdb.com/images/media/meals/13fg4j1764441982.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('arepa-pelua', 'Arepa pelua', 4, 0, 0, '{"calories": 697, "protein": 43.4, "carbs": 67.3, "fat": 25.9, "saturated_fat": 18.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1268.8, "potassium": 145.0, "fiber": 9.9, "sugar": 25.8, "vitamin_a": null, "vitamin_c": 6.5, "calcium": 140.3, "iron": 14.5}'::jsonb, ARRAY['beef', 'venezulan', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 500.0, "unit": "g", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Oregano", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "l", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 2.5, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Extra Virgin Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Cook the meat: Place the flank steak in a pot with broth or water and salt. Cook over low heat for about 2 hours, until tender and easy to shred.", "Shred the meat: Once cooked, drain and shred the meat using two forks.", "Prepare the vegetables: Sauté chopped onion, bell pepper, and garlic in a little oil. Add cumin, oregano, paprika, and salt. Stir in the meat and cook for a few minutes until the flavors are well combined.", "Make the dough: In a bowl, mix the cornmeal with warm water and salt until a soft dough forms. Let it rest for 5 minutes.", "Form the arepas: Divide the dough into 6 portions, shape into balls, and flatten into thick discs.", "Cook: Cook the arepas on a griddle or skillet over medium heat for 2–3 minutes on each side until golden. You can then bake them for a few minutes if you prefer them crispier.", "Fill: Slice the arepas open on one side, fill with the hot shredded beef, and top with grated cheese."]'::jsonb, 'https://goya.es/en/recipes/arepa-pelua', 'https://www.themealdb.com/images/media/meals/jgl9qq1764437635.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('asado', 'Asado', 4, 0, 0, '{"calories": 146, "protein": 72.3, "carbs": 686.5, "fat": 39.6, "saturated_fat": 3.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 10385.3, "potassium": 1879.5, "fiber": 0.5, "sugar": 0.4, "vitamin_a": null, "vitamin_c": 1.1, "calcium": 265.5, "iron": 19.6}'::jsonb, ARRAY['beef', 'argentinian', 'themealdb', 'nutrition-generated', 'grilling'], '[{"quantity": 2.0, "unit": "kg", "item": "Mixed Beef Cuts", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Morcilla", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}]'::jsonb, '["Prepare the Fire: Start a wood fire in your grill and let it burn down to coals.", "Season the Meat: Generously salt the beef cuts.", "Grill the Meat: Place the beef on the grill, starting with the thickest cuts farthest from the coals. Add chorizo and morcilla after the beef has been cooking for a while.", "Cook to Perfection: Cook the meat, turning occasionally, until it reaches your desired doneness. Typically, ribs may take up to 2 hours; thinner cuts will cook faster.", "Rest and Serve: Let the meat rest for about 10 minutes before slicing. Serve with chimichurri sauce and grilled vegetables.", "Pro Tips:", "Use a mix of wood and charcoal for a consistent heat source. Wood adds flavor, while charcoal maintains temperature.", "Season the meat just before grilling to ensure it retains its moisture and flavor.", "Serving Suggestions:", "Serve with a side of chimichurri sauce, a fresh tomato salad, and crusty bread. Pair with a robust Malbec wine to complement the rich flavors of the meat."]'::jsonb, 'https://www.munchery.com/blog/the-ten-iconic-dishes-of-argentina-and-how-to-cook-them-at-home/', 'https://www.themealdb.com/images/media/meals/kgfh3q1763075438.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('aussie-burgers', 'Aussie Burgers', 4, 0, 0, '{"calories": 203, "protein": 26.7, "carbs": 26.9, "fat": 20.6, "saturated_fat": 6.7, "polyunsaturated_fat": 0.1, "monounsaturated_fat": 8.1, "sodium": 338.1, "potassium": 795.9, "fiber": 3.9, "sugar": 10.1, "vitamin_a": null, "vitamin_c": null, "calcium": 97.3, "iron": 2.3}'::jsonb, ARRAY['beef', 'australian', 'themealdb', 'nutrition-generated', 'grilling', 'vegetarian'], '[{"quantity": 500.0, "unit": "g", "item": "Lean", "notes": "Minced Steak", "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Cooked Beetroot", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Naan Bread", "notes": null, "category": "grains"}, {"quantity": 50.0, "unit": "g", "item": "Rocket", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Soured cream and chive dip", "notes": null, "category": "dairy"}]'::jsonb, '["step 1", "Make the burgers: Tip the meat into a bowl and sprinkle over 1 tsp salt and a good grinding of black pepper.Work with wet hands to mix in the seasoning. Divide into four with your hands and shape into burgers. (It can be frozen at this stage.)", "step 2", "Sort out your ingredients: Slice the beetroot and split the naan breads.", "step 3", "Toast the naans: Heat a griddle pan or barbecue. Griddle the naans on both sides until lightly toasted and set aside. Add the burgers to the grill or barbecue and cook for 2-3 minutes, then turn and cook the other side for a further 2-3 minutes.", "step 4", "Assemble the dish: Set half a toasted naan on each serving plate and put a pile of rocket on each. Top with a burger, then a few slices of beetroot and a dollop of soured cream. Sprinkle with salt and freshly ground black pepper and serve immediately with a big green salad and chips. A glass of red wine wouldn’t go amiss, either."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/aussie-burgers', 'https://www.themealdb.com/images/media/meals/44bzep1761848278.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-and-broccoli-stir-fry', 'Beef and Broccoli Stir-Fry', 4, 0, 0, '{"calories": 35, "protein": 28.3, "carbs": 6.8, "fat": 6.5, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 334.2, "potassium": 654.7, "fiber": 4.0, "sugar": 1.8, "vitamin_a": null, "vitamin_c": 1.2, "calcium": 81.1, "iron": 3.5}'::jsonb, ARRAY['beef', 'chinese', 'themealdb', 'nutrition-generated', 'soup'], '[{"quantity": 1.0, "unit": "tsp", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Dry sherry", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tsp", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 0.125, "unit": "teaspoon", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "lb", "item": "Sirloin steak", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Oyster Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Dry sherry", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "cup", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "lb", "item": "Broccoli", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "High Heat Cooking Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Water", "notes": null, "category": "other"}]'::jsonb, '["Marinate the beef:", "Stir together the beef marinade ingredients (1 teaspoon soy sauce, 1 teaspoon Chinese rice wine, 1/2 teaspoon cornstarch, 1/8 teaspoon black pepper) in a medium bowl.", "Add the beef slices and stir until coated. Let stand for 10 minutes.", "Prepare the sauce:", "Stir together the sauce ingredients (2 tablespoons oyster sauce, 1 teaspoon Chinese rice wine, 1 teaspoon soy sauce, 1/4 cup chicken broth) in a small bowl. Set aside.", "Blanch or steam the broccoli:", "Bring a pot of water to a boil. Add the broccoli and cook until crisp-tender, about 2 minutes. Drain thoroughly.", "Stir-fry the beef:", "Heat a large frying pan or wok over high heat until a bead of water sizzles and instantly evaporates upon contact. Add the cooking oil and swirl to coat.", "Add the beef and immediately spread it out all over the surface of the wok or pan in a single layer (preferably not touching).", "Let the beef fry undisturbed for 1 minute. Flip the beef slices over, add the garlic to the pan, and fry for an additional 30 seconds to 1 minute until no longer pink.", "Add the sauce, cornstarch, and broccoli:", "Pour in the sauce and the cornstarch slurry (1 teaspoon cornstarch dissolved in 1 tablespoon of water). Stir until the sauce boils and thickens, about 30 seconds. Stir in the broccoli.", "Serve immediately, with steamed rice or on its own."]'::jsonb, 'https://www.simplyrecipes.com/recipes/broccoli_beef/', 'https://www.themealdb.com/images/media/meals/m0p0j81765568742.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-and-mustard-pie', 'Beef and Mustard Pie', 4, 0, 0, '{"calories": 1226, "protein": 68.1, "carbs": 103.3, "fat": 63.1, "saturated_fat": 34.4, "polyunsaturated_fat": null, "monounsaturated_fat": 8.0, "sodium": 1401.2, "potassium": 426.2, "fiber": 5.8, "sugar": 37.0, "vitamin_a": null, "vitamin_c": 9.9, "calcium": 126.8, "iron": 16.7}'::jsonb, ARRAY['beef', 'british', 'themealdb', 'nutrition-generated', 'dessert', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "kg", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tbs", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tbs", "item": "Rapeseed Oil", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "ml", "item": "Red Wine", "notes": null, "category": "other"}, {"quantity": 400.0, "unit": "ml", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "sliced Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Mustard", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "free-range Egg Yolks", "notes": null, "category": "dairy"}, {"quantity": 400.0, "unit": "g", "item": "Puff Pastry", "notes": null, "category": "other"}, {"quantity": 300.0, "unit": "g", "item": "Green Beans", "notes": null, "category": "produce"}, {"quantity": 25.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Preheat the oven to 150C/300F/Gas 2.", "Toss the beef and flour together in a bowl with some salt and black pepper.", "Heat a large casserole until hot, add half of the rapeseed oil and enough of the beef to just cover the bottom of the casserole.", "Fry until browned on each side, then remove and set aside. Repeat with the remaining oil and beef.", "Return the beef to the pan, add the wine and cook until the volume of liquid has reduced by half, then add the stock, onion, carrots, thyme and mustard, and season well with salt and pepper.", "Cover with a lid and place in the oven for two hours.", "Remove from the oven, check the seasoning and set aside to cool. Remove the thyme.", "When the beef is cool and you''re ready to assemble the pie, preheat the oven to 200C/400F/Gas 6.", "Transfer the beef to a pie dish, brush the rim with the beaten egg yolks and lay the pastry over the top. Brush the top of the pastry with more beaten egg.", "Trim the pastry so there is just enough excess to crimp the edges, then place in the oven and bake for 30 minutes, or until the pastry is golden-brown and cooked through.", "For the green beans, bring a saucepan of salted water to the boil, add the beans and cook for 4-5 minutes, or until just tender.", "Drain and toss with the butter, then season with black pepper.", "To serve, place a large spoonful of pie onto each plate with some green beans alongside."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/beef_and_mustard_pie_58002', 'https://www.themealdb.com/images/media/meals/sytuqu1511553755.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-and-oyster-pie', 'Beef and Oyster pie', 4, 0, 0, '{"calories": 1147, "protein": 71.0, "carbs": 114.4, "fat": 84.5, "saturated_fat": 49.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2150.0, "potassium": 384.2, "fiber": 4.8, "sugar": 9.1, "vitamin_a": null, "vitamin_c": 5.0, "calcium": 49.6, "iron": 11.8}'::jsonb, ARRAY['beef', 'british', 'themealdb', 'nutrition-generated', 'dessert', 'breakfast', 'soup', 'baking'], '[{"quantity": 900.0, "unit": "g", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 3.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 125.0, "unit": "g", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tbs", "item": "chopped Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 330.0, "unit": "ml", "item": "Stout", "notes": null, "category": "other"}, {"quantity": 400.0, "unit": "ml", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tbs", "item": "Corn Flour", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Oysters", "notes": null, "category": "other"}, {"quantity": 400.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "To Glaze Eggs", "notes": null, "category": "dairy"}]'::jsonb, '["Season the beef cubes with salt and black pepper. Heat a tablespoon of oil in the frying pan and fry the meat over a high heat. Do this in three batches so that you don’t overcrowd the pan, transferring the meat to a large flameproof casserole dish once it is browned all over. Add extra oil if the pan seems dry.", "In the same pan, add another tablespoon of oil and cook the shallots for 4-5 minutes, then add the garlic and fry for 30 seconds. Add the bacon and fry until slightly browned. Transfer the onion and bacon mixture to the casserole dish and add the herbs.", "Preheat the oven to 180C/350F/Gas 4.", "Pour the stout into the frying pan and bring to the boil, stirring to lift any stuck-on browned bits from the bottom of the pan. Pour the stout over the beef in the casserole dish and add the stock. Cover the casserole and place it in the oven for 1½-2 hours, or until the beef is tender and the sauce is reduced.", "Skim off any surface fat, taste and add salt and pepper if necessary, then stir in the cornflour paste. Put the casserole dish on the hob – don’t forget that it will be hot – and simmer for 1-2 minutes, stirring, until thickened. Leave to cool.", "Increase the oven to 200C/400F/Gas 6. To make the pastry, put the flour and salt in a very large bowl. Grate the butter and stir it into the flour in three batches. Gradually add 325ml/11fl oz cold water – you may not need it all – and stir with a round-bladed knife until the mixture just comes together. Knead the pastry lightly into a ball on a lightly floured surface and set aside 250g/9oz for the pie lid.", "Roll the rest of the pastry out until about 2cm/¾in larger than the dish you’re using. Line the dish with the pastry then pile in the filling, tucking the oysters in as well. Brush the edge of the pastry with beaten egg.", "Roll the remaining pastry until slightly larger than your dish and gently lift over the filling, pressing the edges firmly to seal, then trim with a sharp knife. Brush with beaten egg to glaze. Put the dish on a baking tray and bake for 25-30 minutes, or until the pastry is golden-brown and the filling is bubbling."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/beef_and_oyster_pie_65230', 'https://www.themealdb.com/images/media/meals/wrssvt1511556563.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-asado', 'Beef Asado', 4, 0, 0, '{"calories": 936, "protein": 81.0, "carbs": 46.9, "fat": 47.7, "saturated_fat": 19.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1729.3, "potassium": 814.7, "fiber": 1.5, "sugar": 23.7, "vitamin_a": null, "vitamin_c": 8.3, "calcium": 34.0, "iron": 17.8}'::jsonb, ARRAY['beef', 'filipino', 'themealdb', 'nutrition-generated', 'soup'], '[{"quantity": 1.5, "unit": "kg", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Stock Concentrate", "notes": null, "category": "pantry"}, {"quantity": 8.0, "unit": "ounces", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 6.0, "unit": "tablespoons", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "White Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Lemon", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Tomato Sauce", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}]'::jsonb, '["0.\tCombine beef, crushed peppercorn, soy sauce, vinegar, dried bay leaves, lemon, and tomato sauce. Mix well. Marinate beef for at least 30 minutes.", "1.\tPut the marinated beef in a cooking pot along with remaining marinade. Add water. Let boil.", "2.\tAdd Knorr Beef Cube. Stir. Cover the pot and cook for 40 minutes in low heat.", "3.\tTurn the beef over. Add tomato paste. Continue cooking until beef tenderizes. Set aside.", "4.\tHeat oil in a pan. Fry the potato until it browns. Turn over and continue frying the opposite side. Remove from the pan and place on a clean plate. Do the same with the carrots.", "5.\tSave 3 tablespoons of cooking oil from the pan where the potato was fried. Saute onion and garlic until onion softens.", "6.\tPour-in the sauce from the beef stew. Let boil. Add the beef. Cook for 2 minutes.", "7.\tAdd butter and let it melt. Continue cooking until the sauce reduces to half."]'::jsonb, 'https://panlasangpinoy.com/beef-asado/', 'https://www.themealdb.com/images/media/meals/pkopc31683207947.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-banh-mi-bowls-with-sriracha-mayo-carrot-pickled-cucumber', 'Beef Banh Mi Bowls with Sriracha Mayo, Carrot & Pickled Cucumber', 4, 0, 0, '{"calories": 576, "protein": 26.1, "carbs": 47.2, "fat": 30.6, "saturated_fat": 12.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1069.6, "potassium": 138.4, "fiber": 1.7, "sugar": 3.1, "vitamin_a": null, "vitamin_c": 1.6, "calcium": 34.0, "iron": 3.4}'::jsonb, ARRAY['beef', 'vietnamese', 'themealdb', 'nutrition-generated'], '[{"quantity": 1.0, "unit": "serving", "item": "White Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Cucumber", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "oz", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "lb", "item": "Ground Beef", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "oz", "item": "Soy Sauce", "notes": null, "category": "pantry"}]'::jsonb, '["Add''l ingredients: mayonnaise, siracha", "1", "Place rice in a fine-mesh sieve and rinse until water runs clear. Add to a small pot with 1 cup water (2 cups for 4 servings) and a pinch of salt. Bring to a boil, then cover and reduce heat to low. Cook until rice is tender, 15 minutes. Keep covered off heat for at least 10 minutes or until ready to serve.", "2", "Meanwhile, wash and dry all produce. Peel and finely chop garlic. Zest and quarter lime (for 4 servings, zest 1 lime and quarter both). Trim and halve cucumber lengthwise; thinly slice crosswise into half-moons. Halve, peel, and medium dice onion. Trim, peel, and grate carrot.", "3", "In a medium bowl, combine cucumber, juice from half the lime, ¼ tsp sugar (½ tsp for 4 servings), and a pinch of salt. In a small bowl, combine mayonnaise, a pinch of garlic, a squeeze of lime juice, and as much sriracha as you’d like. Season with salt and pepper.", "4", "Heat a drizzle of oil in a large pan over medium-high heat. Add onion and cook, stirring, until softened, 4-5 minutes. Add beef, remaining garlic, and 2 tsp sugar (4 tsp for 4 servings). Cook, breaking up meat into pieces, until beef is browned and cooked through, 4-5 minutes. Stir in soy sauce. Turn off heat; taste and season with salt and pepper.", "5", "Fluff rice with a fork; stir in lime zest and 1 TBSP butter. Divide rice between bowls. Arrange beef, grated carrot, and pickled cucumber on top. Top with a squeeze of lime juice. Drizzle with sriracha mayo."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/z0ageb1583189517.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-bourguignon', 'Beef Bourguignon', 4, 0, 0, '{"calories": 1188, "protein": 30.3, "carbs": 172.7, "fat": 61.9, "saturated_fat": 18.1, "polyunsaturated_fat": null, "monounsaturated_fat": 0.8, "sodium": 4714.7, "potassium": 1056.3, "fiber": 12.9, "sugar": 10.6, "vitamin_a": 41.6, "vitamin_c": 10.0, "calcium": 104.8, "iron": 4.4}'::jsonb, ARRAY['beef', 'french', 'themealdb', 'nutrition-generated', 'breakfast', 'baking'], '[{"quantity": 3.0, "unit": "tsp", "item": "Goose Fat", "notes": null, "category": "other"}, {"quantity": 600.0, "unit": "g", "item": "Beef Shin", "notes": null, "category": "meat"}, {"quantity": 100.0, "unit": "g", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 350.0, "unit": "g", "item": "Challots", "notes": null, "category": "other"}, {"quantity": 250.0, "unit": "g", "item": "Chestnut Mushroom", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garni", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbs", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 750.0, "unit": "ml", "item": "Red Wine", "notes": null, "category": "other"}, {"quantity": 600.0, "unit": "g", "item": "Celeriac", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "sprigs of", "notes": "fresh Thyme", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "sprigs of", "notes": "fresh Rosemary", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Cardamom", "notes": null, "category": "spices"}]'::jsonb, '["Heat a large casserole pan and add 1 tbsp goose fat. Season the beef and fry until golden brown, about 3-5 mins, then turn over and fry the other side until the meat is browned all over, adding more fat if necessary. Do this in 2-3 batches, transferring the meat to a colander set over a bowl when browned.", "In the same pan, fry the bacon, shallots or pearl onions, mushrooms, garlic and bouquet garni until lightly browned. Mix in the tomato purée and cook for a few mins, stirring into the mixture. This enriches the bourguignon and makes a great base for the stew. Then return the beef and any drained juices to the pan and stir through.", "Pour over the wine and about 100ml water so the meat bobs up from the liquid, but isn’t completely covered. Bring to the boil and use a spoon to scrape the caramelised cooking juices from the bottom of the pan – this will give the stew more flavour.", "Heat oven to 150C/fan 130C/gas 2. Make a cartouche: tear off a square of foil slightly larger than the casserole, arrange it in the pan so it covers the top of the stew and trim away any excess foil. Then cook for 3 hrs. If the sauce looks watery, remove the beef and veg with a slotted spoon, and set aside. Cook the sauce over a high heat for a few mins until the sauce has thickened a little, then return the beef and vegetables to the pan.", "To make the celeriac mash, peel the celeriac and cut into cubes. Heat the olive oil in a large frying pan. Tip in the celeriac and fry for 5 mins until it turns golden. Season well with salt and pepper. Stir in the rosemary, thyme, bay and cardamom pods, then pour over 200ml water, enough to nearly cover the celeriac. Turn the heat to low, partially cover the pan and leave to simmer for 25-30 mins.", "After 25-30 mins, the celeriac should be soft and most of the water will have evaporated. Drain away any remaining water, then remove the herb sprigs, bay and cardamom pods. Lightly crush with a potato masher, then finish with a glug of olive oil and season to taste. Spoon the beef bourguignon into serving bowls and place a large spoonful of the celeriac mash on top. Garnish with one of the bay leaves, if you like."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/5032/beef-bourguignon', 'https://www.themealdb.com/images/media/meals/vtqxtu1511784197.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-brisket-pot-roast', 'Beef Brisket Pot Roast', 4, 0, 0, '{"calories": 2039, "protein": 98.7, "carbs": 49.3, "fat": 159.7, "saturated_fat": 54.3, "polyunsaturated_fat": null, "monounsaturated_fat": 7.1, "sodium": 991.7, "potassium": 244.6, "fiber": 5.1, "sugar": 6.4, "vitamin_a": null, "vitamin_c": 9.5, "calcium": 196.4, "iron": 12.0}'::jsonb, ARRAY['beef', 'american', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 5.0, "unit": "pound", "item": "4-5 pound Beef Brisket", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 5.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Rosemary", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "cups", "item": "beef stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "Mustard", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}]'::jsonb, '["1 Prepare the brisket for cooking: On one side of the brisket there should be a layer of fat, which you want. If there are any large chunks of fat, cut them off and discard them. Large pieces of fat will not be able to render out completely.", "Using a sharp knife, score the fat in parallel lines, about 3/4-inch apart. Slice through the fat, not the beef. Repeat in the opposite direction to make a cross-hatch pattern.", "Salt the brisket well and let it sit at room temperature for 30 minutes.", "2 Sear the brisket: You''ll need an oven-proof, thick-bottomed pot with a cover, or Dutch oven, that is just wide enough to hold the brisket roast with a little room for the onions.", "Pat the brisket dry and place it, fatty side down, into the pot and place it on medium high heat. Cook for 5-8 minutes, lightly sizzling, until the fat side is nicely browned. (If the roast seems to be cooking too fast, turn the heat down to medium. You want a steady sizzle, not a raging sear.)", "Turn the brisket over and cook for a few minutes more to brown the other side.", "3 Sauté the onions and garlic: When the brisket has browned, remove it from the pot and set aside. There should be a couple tablespoons of fat rendered in the pot, if not, add some olive oil.", "Add the chopped onions and increase the heat to high. Sprinkle a little salt on the onions. Sauté, stirring often, until the onions are lightly browned, 5-8 minutes. Stir in the garlic and cook 1-2 more minutes.", "4 Return brisket to pot, add herbs, stock, bring to simmer, cover, cook in oven: Preheat the oven to 300°F. Use kitchen twine to tie together the bay leaves, rosemary and thyme.", "Move the onions and garlic to the sides of the pot and nestle the brisket inside. Add the beef stock and the tied-up herbs. Bring the stock to a boil on the stovetop.", "Cover the pot, place the pot in the 300°F oven and cook for 3 hours. Carefully flip the brisket every hour so it cooks evenly.", "5 Add carrots, continue to cook: After 3 hours, add the carrots. Cover the pot and cook for 1 hour more, or until the carrots are cooked through and the brisket is falling-apart tender.", "6 Remove brisket to cutting board, tent with foil: When the brisket is falling-apart tender, take the pot out of the oven and remove the brisket to a cutting board. Cover it with foil. Pull out and discard the herbs.", "7 Make sauce (optional): At this point you have two options. You can serve as is, or you can make a sauce with the drippings and some of the onions. If you serve as is, skip this step.", "To make a sauce, remove the carrots and half of the onions, set aside and cover them with foil. Pour the ingredients that are remaining into the pot into a blender, and purée until smooth. If you want, add 1 tablespoon of mustard to the mix. Put into a small pot and keep warm.", "8 Slice the meat across the grain: Notice the lines of the muscle fibers of the roast. This is the \"grain\" of the meat. Slice the meat perpendicular to these lines, or across the grain (cutting this way further tenderizes the meat), in 1/4-inch to 1/2-inch slices.", "Serve with the onions, carrots and gravy. Serve with mashed, roasted or boiled potatoes, egg noodles or polenta."]'::jsonb, 'http://www.simplyrecipes.com/recipes/beef_brisket_pot_roast/', 'https://www.themealdb.com/images/media/meals/ursuup1487348423.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-caldereta', 'Beef Caldereta', 4, 0, 0, '{"calories": 1727, "protein": 133.6, "carbs": 56.3, "fat": 112.8, "saturated_fat": 39.6, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2970.6, "potassium": 407.4, "fiber": 3.2, "sugar": 26.4, "vitamin_a": 8.0, "vitamin_c": 38.4, "calcium": 93.9, "iron": 19.1}'::jsonb, ARRAY['beef', 'filipino', 'themealdb', 'nutrition-generated', 'soup', 'instant-pot'], '[{"quantity": 2.0, "unit": "kg", "item": "cut cubes Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Green Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 8.0, "unit": "ounces", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Peanut Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Powder", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 5.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["0.\tHeat oil in a cooking pot. Saute onion and garlic until onion softens", "1.\tAdd beef. Saute until the outer part turns light brown.", "2.\tAdd soy sauce. Pour tomato sauce and water. Let boil.", "3.\tAdd Knorr Beef Cube. Cover the pressure cooker. Cook for 30 minutes.", "4.\tPan-fry carrot and potato until it browns. Set aside.", "5.\tAdd chili pepper, liver spread and peanut butter. Stir.", "6.\tAdd bell peppers, fried potato and carrot. Cover the pot. Continue cooking for 5 to 7 minutes.", "7.\tSeason with salt and ground black pepper. Serve."]'::jsonb, 'https://www.kawalingpinoy.com/beef-caldereta/', 'https://www.themealdb.com/images/media/meals/41cxjh1683207682.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-dumpling-stew', 'Beef Dumpling Stew', 4, 0, 0, '{"calories": 716, "protein": 47.2, "carbs": 103.5, "fat": 31.1, "saturated_fat": 18.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 4489.2, "potassium": 461.8, "fiber": 4.9, "sugar": 3.6, "vitamin_a": null, "vitamin_c": 14.5, "calcium": 79.0, "iron": 9.2}'::jsonb, ARRAY['beef', 'british', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 2.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 25.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 750.0, "unit": "g", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 175.0, "unit": "g", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "g", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "g", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leek", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Swede", "notes": null, "category": "other"}, {"quantity": 150.0, "unit": "ml", "item": "Red Wine", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "g", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tbs", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Parsley", "notes": null, "category": "produce"}, {"quantity": 125.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 60.0, "unit": "g", "item": "Suet", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Splash Water", "notes": null, "category": "other"}]'::jsonb, '["Preheat the oven to 180C/350F/Gas 4.", "For the beef stew, heat the oil and butter in an ovenproof casserole and fry the beef until browned on all sides.", "Sprinkle over the flour and cook for a further 2-3 minutes.", "Add the garlic and all the vegetables and fry for 1-2 minutes.", "Stir in the wine, stock and herbs, then add the Worcestershire sauce and balsamic vinegar, to taste. Season with salt and freshly ground black pepper.", "Cover with a lid, transfer to the oven and cook for about two hours, or until the meat is tender.", "For the dumplings, sift the flour, baking powder and salt into a bowl.", "Add the suet and enough water to form a thick dough.", "With floured hands, roll spoonfuls of the dough into small balls.", "After two hours, remove the lid from the stew and place the balls on top of the stew. Cover, return to the oven and cook for a further 20 minutes, or until the dumplings have swollen and are tender. (If you prefer your dumplings with a golden top, leave the lid off when returning to the oven.)", "To serve, place a spoonful of mashed potato onto each of four serving plates and top with the stew and dumplings. Sprinkle with chopped parsley."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/beefstewwithdumpling_87333', 'https://www.themealdb.com/images/media/meals/uyqrrv1511553350.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-empanadas', 'Beef Empanadas', 4, 0, 0, '{"calories": 990, "protein": 48.3, "carbs": 495.7, "fat": 43.0, "saturated_fat": 9.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 10181.1, "potassium": 753.6, "fiber": 10.2, "sugar": 22.8, "vitamin_a": null, "vitamin_c": 15.3, "calcium": 156.7, "iron": 12.1}'::jsonb, ARRAY['beef', 'uruguayan', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 60.0, "unit": "g", "item": "Lard", "notes": null, "category": "other"}, {"quantity": 340.0, "unit": "g", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 600.0, "unit": "g", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 750.0, "unit": "g", "item": "Sirloin steak", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Dried Oregano", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Red Pepper Flakes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Splash Egg Wash", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Drizzle Chimichurri sauce", "notes": null, "category": "other"}]'::jsonb, '["For the dough place lard, warm water and salt in a large kneading bowl and stir. Add flour and oregano and either knead five miutes by hand or with the kneading function of your machine. Let rest covered for at least half an hour or overnight in the fridge.", "2", "For the filling place tomatoes for about 30 seconds in boiling water, then cool with cold water and peel of skin and cut into cubes. Press garlic through garlic press, cut onions into cubes. Simmer garlic and onions in some olive oil until translucent. Take out onions and garlic and brown the meat at high heat from all sides. Season with all herbs and add the onions, garlic and tomatoes. Let simmer for a few minutes, add salt, pepper and additional spices to taste. You can prepare the meat the night before, chill in fridge if doing so. Boil eggs and also cut into cubes and mix with prepared meat.", "3", "Cut dough into half and roll out one half thinnly on floured surface. Cut out circles about 12-15cm in diameter. Mine have a diameter of 12.5 cm. Place about 2-4 teaspoons of filling on one circle, put a bit of water all around the edges and fold over the other half so that you get half moons. Be sure to seal the edges with a fork. Repeat until you have no dough and filling left.", "4", "Meanwhile preheat oven to 200 degrees Celsius. Brush empanadas with egg wash and bake about 8 empanadas on a baking sheet lined with parchment paper for about 25min or until golden. Serve warm with chimichurri sauce."]'::jsonb, 'https://jennyisbaking.com/2019/10/25/traditionelle-uruguayische-empanadas/#recipe', 'https://www.themealdb.com/images/media/meals/dxpc7j1764370714.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-lo-mein', 'Beef Lo Mein', 4, 0, 0, '{"calories": 579, "protein": 25.3, "carbs": 72.1, "fat": 23.5, "saturated_fat": 8.7, "polyunsaturated_fat": null, "monounsaturated_fat": 0.9, "sodium": 831.3, "potassium": 268.3, "fiber": 5.3, "sugar": 17.6, "vitamin_a": null, "vitamin_c": null, "calcium": 27.1, "iron": 7.5}'::jsonb, ARRAY['beef', 'chinese', 'themealdb', 'nutrition-generated', 'dessert', 'pasta'], '[{"quantity": 0.5, "unit": "lb", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Pepper", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Egg", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tbs", "item": "Starch", "notes": null, "category": "other"}, {"quantity": 5.0, "unit": "tbs", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "lb", "item": "Noodles", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "cup", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Bean Sprouts", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "cup", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbs", "item": "Oyster Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Soy Sauce", "notes": null, "category": "pantry"}]'::jsonb, '["STEP 1 - MARINATING THE BEEF", "In a bowl, add the beef, salt, 1 pinch white pepper, 1 Teaspoon sesame seed oil, 1/2 egg, corn starch,1 Tablespoon of oil and mix together.", "STEP 2 - BOILING THE THE NOODLES", "In a 6 qt pot add your noodles to boiling water until the noodles are submerged and boil on high heat for 10 seconds. After your noodles is done boiling strain and cool with cold water.", "STEP 3 - STIR FRY", "Add 2 Tablespoons of oil, beef and cook on high heat untill beef is medium cooked.", "Set the cooked beef aside", "In a wok add 2 Tablespoon of oil, onions, minced garlic, minced ginger, bean sprouts, mushrooms, peapods and 1.5 cups of water or until the vegetables are submerged in water.", "Add the noodles to wok", "To make the sauce, add oyster sauce, 1 pinch white pepper, 1 teaspoon sesame seed oil, sugar, and 1 Teaspoon of soy sauce.", "Next add the beef to wok and stir-fry"]'::jsonb, 'https://sueandgambo.com/pages/beef-lo-mein', 'https://www.themealdb.com/images/media/meals/1529444830.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-mandi', 'Beef Mandi', 4, 0, 0, '{"calories": 121, "protein": 14.3, "carbs": 171.3, "fat": 4.2, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1944.3, "potassium": 91.0, "fiber": 6.6, "sugar": 3.0, "vitamin_a": null, "vitamin_c": null, "calcium": 15.8, "iron": 1.8}'::jsonb, ARRAY['beef', 'indian', 'themealdb', 'nutrition-generated', 'soup', 'grilling'], '[{"quantity": 1.0, "unit": "kg", "item": "Basmati Rice", "notes": null, "category": "grains"}, {"quantity": 5.0, "unit": "cups", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "cloves Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 2.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Turmeric Powder", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Cardamom", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Cloves", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Bay Leaf", "notes": null, "category": "spices"}]'::jsonb, '["1. Wash the beef and cut into large pieces. Season lightly with salt and turmeric.", "2. Heat ghee/oil in a large pot. Add sliced onions and sauté until light golden.", "3. Add garlic, green chilies, and tomato; cook until softened.", "4. Add the mandi spice mix: coriander, cumin, black pepper, cinnamon, cardamom, cloves, and bay leaves.", "5. Add beef pieces and stir on medium heat until the meat is well coated with spices.", "6. Pour in water or beef stock. Cover and simmer until beef is tender (about 1.5–2 hours depending on cut).", "7. Remove beef carefully and set aside. Strain and measure the broth.", "8. Add washed, soaked basmati rice to the broth (usually 1 cup rice = 1.5–2 cups liquid). Adjust seasoning and bring to a boil.", "9. Lower heat, cover, and cook the rice until fluffy.", "10. Place the beef pieces over the rice and steam on low heat for 10 minutes so flavors combine.", "11. Optional: For smoky flavor, place a small hot charcoal on foil in the pot, add 1 tsp butter/oil, immediately cover for 5 minutes. Remove coal before serving.", "12. Fluff rice and serve beef mandi with salad or chutney."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/1nalo51765188375.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-mechado', 'Beef Mechado', 4, 0, 0, '{"calories": 268, "protein": 7.9, "carbs": 376.8, "fat": 7.3, "saturated_fat": 0.9, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 11044.5, "potassium": 298.2, "fiber": 2.7, "sugar": 11.9, "vitamin_a": null, "vitamin_c": 8.5, "calcium": 27.8, "iron": 2.0}'::jsonb, ARRAY['beef', 'filipino', 'themealdb', 'nutrition-generated', 'grilling'], '[{"quantity": 3.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "lbs", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 8.0, "unit": "ounces", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "slice", "item": "Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}]'::jsonb, '["0.\tMake the beef tenderloin marinade by combining soy sauce, vinegar, ginger, garlic, sesame oil, olive oil, sugar, salt, and ground black pepper in a large bowl. Mix well.", "1.\tAdd the cubed beef tenderloin to the bowl with the beef tenderloin marinade. Gently toss to coat the beef. Let it stay for 1 hour.", "2.\tUsing a metal or bamboo skewer, assemble the beef kebob by skewering the vegetables and marinated beef tenderloin.", "3.\tHeat-up the grill and start grilling the beef kebobs for 3 minutes per side. This will give you a medium beef that is juicy and tender on the inside. Add more time if you want your beef well done, but it will be less tender.", "4.\tTransfer to a serving plate. Serve with Saffron rice.", "5.\tShare and enjoy!"]'::jsonb, 'https://panlasangpinoy.com/filipino-pinoy-food-tomato-sauce-beef-mechado-recipe/', 'https://www.themealdb.com/images/media/meals/cgl60b1683206581.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-pho', 'Beef pho', 4, 0, 0, '{"calories": 396, "protein": 24.3, "carbs": 82.6, "fat": 26.3, "saturated_fat": 11.4, "polyunsaturated_fat": null, "monounsaturated_fat": 4.2, "sodium": 1621.7, "potassium": 338.8, "fiber": 1.5, "sugar": 5.8, "vitamin_a": 189.5, "vitamin_c": 2.5, "calcium": 33.3, "iron": 2.8}'::jsonb, ARRAY['beef', 'vietnamese', 'themealdb', 'nutrition-generated', 'dessert', 'soup', 'pasta', 'grilling'], '[{"quantity": 1.0, "unit": "l", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Stick", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Anise", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Coriander Seeds", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Cloves", "notes": null, "category": "spices"}, {"quantity": 225.0, "unit": "g", "item": "Sirloin steak", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tsp", "item": "Palm Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tbsp", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Rice Noodles", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Birds-eye Chillies", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Basil", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Lime", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Tip the beef stock along with 500ml of water into a large saucepan. Sit the onion and ginger in a frying pan over a high heat and char on all sides, around 3-5 mins (you can also do this under your grill). Once charred, add to the beef stock. In the same pan, toast the spices for 2-3 mins and once they begin to smell fragrant, add them to the beef stock as well. Bring the stock to the boil, then turn to a simmer and cook for 30mins before straining.", "step 2", "Meanwhile, cut the fat from the steak and wrap in cling film, then put into the freezer for 15 mins – this will make your steak really easy to slice! Slice it thinly, then cover with cling film again and pop into the fridge.", "step 3", "Taste the beef stock and use the palm sugar, fish sauce and soy to season. Cook the noodles according to package instructions and split between two bowls, topping each with the sliced beef. Bring the stock to the boil and then pour into the bowls (the heat will cook the beef). Top each with the spring onions, chilli slices and herbs. Serve with the lime wedges to squeeze over."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/beef-pho', 'https://www.themealdb.com/images/media/meals/pbzcrx1763765096.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-rendang', 'Beef Rendang', 4, 0, 0, '{"calories": 340, "protein": 24.3, "carbs": 18.1, "fat": 39.0, "saturated_fat": 27.2, "polyunsaturated_fat": null, "monounsaturated_fat": 4.2, "sodium": 394.5, "potassium": 5.8, "fiber": null, "sugar": 7.9, "vitamin_a": 189.5, "vitamin_c": null, "calcium": 5.2, "iron": 5.4}'::jsonb, ARRAY['beef', 'malaysian', 'themealdb', 'nutrition-generated', 'dessert'], '[{"quantity": 1.0, "unit": "lb", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 5.0, "unit": "tbs", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Stick", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "cloves", "item": "Cloves", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Anise", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Cardamom", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "cup", "item": "Coconut Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Tamarind Paste", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Challots", "notes": null, "category": "other"}]'::jsonb, '["Chop the spice paste ingredients and then blend it in a food processor until fine.", "Heat the oil in a stew pot, add the spice paste, cinnamon, cloves, star anise, and cardamom and stir-fry until aromatic. Add the beef and the pounded lemongrass and stir for 1 minute. Add the coconut milk, tamarind juice, water, and simmer on medium heat, stirring frequently until the meat is almost cooked. Add the kaffir lime leaves, kerisik (toasted coconut), sugar or palm sugar, stirring to blend well with the meat.", "Lower the heat to low, cover the lid, and simmer for 1 to 1 1/2 hours or until the meat is really tender and the gravy has dried up. Add more salt and sugar to taste. Serve immediately with steamed rice and save some for overnight."]'::jsonb, 'https://rasamalaysia.com/beef-rendang-recipe-rendang-daging/', 'https://www.themealdb.com/images/media/meals/bc8v651619789840.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-stroganoff', 'Beef stroganoff', 4, 0, 0, '{"calories": 407, "protein": 7.3, "carbs": 7.0, "fat": 44.9, "saturated_fat": 14.7, "polyunsaturated_fat": null, "monounsaturated_fat": 0.4, "sodium": 144.1, "potassium": 190.8, "fiber": 1.6, "sugar": 1.4, "vitamin_a": null, "vitamin_c": 2.0, "calcium": 12.3, "iron": 1.0}'::jsonb, ARRAY['beef', 'russian', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 250.0, "unit": "g", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "g", "item": "Beef Fillet", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tbsp", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 150.0, "unit": "g", "item": "Creme Fraiche", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbsp", "item": "English Mustard", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "ml", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Topping Parsley", "notes": null, "category": "produce"}]'::jsonb, '["Heat the olive oil in a non-stick frying pan then add the sliced onion and cook on a medium heat until completely softened, so around 15 mins, adding a little splash of water if they start to stick at all. Crush in the garlic and cook for a 2-3 mins further, then add the butter. Once the butter is foaming a little, add the mushrooms and cook for around 5 mins until completely softened. Season everything well, then tip onto a plate.", "Tip the flour into a bowl with a big pinch of salt and pepper, then toss the steak in the seasoned flour. Add the steak pieces to the pan, splashing in a little oil if the pan looks particularly dry, and fry for 3-4 mins, until well coloured. Tip the onions and mushrooms back into the pan. Whisk the crème fraîche, mustard and beef stock together, then pour into the pan. Cook over a medium heat for around 5 mins. Scatter with parsley, then serve with pappardelle or rice."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/beef-stroganoff', 'https://www.themealdb.com/images/media/meals/svprys1511176755.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-sunday-roast', 'Beef Sunday Roast', 4, 0, 0, '{"calories": 96, "protein": 10.6, "carbs": 36.5, "fat": 3.9, "saturated_fat": 1.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 87.6, "potassium": 285.4, "fiber": 2.8, "sugar": 4.7, "vitamin_a": null, "vitamin_c": 7.0, "calcium": 108.0, "iron": 1.3}'::jsonb, ARRAY['beef', 'british', 'themealdb', 'nutrition-generated', 'baking'], '[{"quantity": 8.0, "unit": "slices", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Broccoli", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 140.0, "unit": "g", "item": "plain flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "ml", "item": "milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "drizzle for cooking sunflower oil", "notes": null, "category": "pantry"}]'::jsonb, '["Cook the Broccoli and Carrots in a pan of boiling water until tender.", "Roast the Beef and Potatoes in the oven for 45mins, the potatoes may need to be checked regularly to not overcook.", "To make the Yorkshire puddings:", "Heat oven to 230C/fan 210C/gas 8. Drizzle a little sunflower oil evenly into 2 x 4-hole Yorkshire pudding tins or a 12-hole non-stick muffin tin and place in the oven to heat through", "To make the batter, tip 140g plain flour into a bowl and beat in four eggs until smooth. Gradually add 200ml milk and carry on beating until the mix is completely lump-free. Season with salt and pepper. Pour the batter into a jug, then remove the hot tins from the oven. Carefully and evenly pour the batter into the holes. Place the tins back in the oven and leave undisturbed for 20-25 mins until the puddings have puffed up and browned. Serve immediately.", "Plate up and add the Gravy as desired."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/9020/best-yorkshire-puddings', 'https://www.themealdb.com/images/media/meals/ssrrrs1503664277.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beef-wellington', 'Beef Wellington', 4, 0, 0, '{"calories": 824, "protein": 12.3, "carbs": 91.2, "fat": 61.4, "saturated_fat": 22.5, "polyunsaturated_fat": null, "monounsaturated_fat": 10.7, "sodium": 531.5, "potassium": 268.2, "fiber": 3.6, "sugar": 27.5, "vitamin_a": null, "vitamin_c": null, "calcium": 102.7, "iron": 3.4}'::jsonb, ARRAY['beef', 'british', 'themealdb', 'nutrition-generated', 'baking'], '[{"quantity": 400.0, "unit": "g", "item": "mushrooms", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "1-2tbsp English Mustard", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 750.0, "unit": "g", "item": "piece Beef Fillet", "notes": null, "category": "meat"}, {"quantity": 8.0, "unit": "slices", "item": "6-8 slices Parma ham", "notes": null, "category": "meat"}, {"quantity": 500.0, "unit": "g", "item": "Puff Pastry", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Dusting Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Egg Yolks", "notes": null, "category": "dairy"}]'::jsonb, '["Put the mushrooms into a food processor with some seasoning and pulse to a rough paste. Scrape the paste into a pan and cook over a high heat for about 10 mins, tossing frequently, to cook out the moisture from the mushrooms. Spread out on a plate to cool.", "Heat in a frying pan and add a little olive oil. Season the beef and sear in the hot pan for 30 secs only on each side. (You don''t want to cook it at this stage, just colour it). Remove the beef from the pan and leave to cool, then brush all over with the mustard.", "Lay a sheet of cling film on a work surface and arrange the Parma ham slices on it, in slightly overlapping rows. With a palette knife, spread the mushroom paste over the ham, then place the seared beef fillet in the middle. Keeping a tight hold of the cling film from the edge, neatly roll the Parma ham and mushrooms around the beef to form a tight barrel shape. Twist the ends of the cling film to secure. Chill for 15-20 mins to allow the beef to set and keep its shape.", "Roll out the puff pastry on a floured surface to a large rectangle, the thickness of a £1 coin. Remove the cling film from the beef, then lay in the centre. Brush the surrounding pastry with egg yolk. Fold the ends over, the wrap the pastry around the beef, cutting off any excess. Turn over, so the seam is underneath, and place on a baking sheet. Brush over all the pastry with egg and chill for about 15 mins to let the pastry rest.", "Heat the oven to 200C, 400F, gas 6.", "Lightly score the pastry at 1cm intervals and glaze again with beaten egg yolk. Bake for 20 minutes, then lower the oven setting to 180C, 350F, gas 4 and cook for another 15 mins. Allow to rest for 10-15 mins before slicing and serving with the side dishes of your choice. The beef should still be pink in the centre when you serve it."]'::jsonb, 'http://www.goodtoknow.co.uk/recipes/164868/Gordon-Ramsay-s-beef-Wellington', 'https://www.themealdb.com/images/media/meals/vvpprx1487325699.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('big-mac', 'Big Mac', 4, 0, 0, '{"calories": 902, "protein": 34.7, "carbs": 40.5, "fat": 71.0, "saturated_fat": 17.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1343.9, "potassium": 169.3, "fiber": 1.9, "sugar": 5.9, "vitamin_a": null, "vitamin_c": 0.6, "calcium": 58.6, "iron": 7.3}'::jsonb, ARRAY['beef', 'american', 'themealdb', 'nutrition-generated', 'salad'], '[{"quantity": 400.0, "unit": "g", "item": "Minced Beef", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Seed Burger Buns", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Lettuce", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Dill Pickles", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Mayonnaise", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "White Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Pepper", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Mustard", "notes": null, "category": "pantry"}, {"quantity": 1.5, "unit": "tsp", "item": "Onion Salt", "notes": null, "category": "produce"}, {"quantity": 1.5, "unit": "tsp", "item": "Garlic Powder", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}]'::jsonb, '["For the Big Mac sauce, combine all the ingredients in a bowl, season with salt and chill until ready to use.", "2. To make the patties, season the mince with salt and pepper and form into 4 balls using about 1/3 cup mince each. Place each onto a square of baking paper and flatten to form into four x 15cm circles. Heat oil in a large frypan over high heat. In 2 batches, cook beef patties for 1-2 minutes each side until lightly charred and cooked through. Remove from heat and keep warm. Repeat with remaining two patties.", "3. Carefully slice each burger bun into three acrossways, then lightly toast.", "4. To assemble the burgers, spread a little Big Mac sauce over the bottom base. Top with some chopped onion, shredded lettuce, slice of cheese, beef patty and some pickle slices. Top with the middle bun layer, and spread with more Big Mac sauce, onion, lettuce, pickles, beef patty and then finish with more sauce. Top with burger lid to serve.", "5. After waiting half an hour for your food to settle, go for a jog."]'::jsonb, 'https://www.delicious.com.au/recipes/finally-recipe-worlds-top-selling-burger-big-mac/5221ee4a-279e-4a0b-8629-f442dc46822e', 'https://www.themealdb.com/images/media/meals/urzj1d1587670726.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bigos-polish-hunters-stew', 'Bigos (Polish hunter''s stew)', 4, 0, 0, '{"calories": 1127, "protein": 79.0, "carbs": 82.9, "fat": 63.7, "saturated_fat": 26.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2902.5, "potassium": 291.1, "fiber": 16.1, "sugar": 40.0, "vitamin_a": null, "vitamin_c": 21.4, "calcium": 186.4, "iron": 17.2}'::jsonb, ARRAY['beef', 'polish', 'themealdb', 'nutrition-generated', 'breakfast', 'soup'], '[{"quantity": 1.0, "unit": "serving", "item": "White Cabbage", "notes": null, "category": "produce"}, {"quantity": 250.0, "unit": "ml", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 100.0, "unit": "g", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Lard", "notes": null, "category": "other"}, {"quantity": 400.0, "unit": "g", "item": "German Sausages", "notes": null, "category": "meat"}, {"quantity": 250.0, "unit": "g", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 750.0, "unit": "g", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 200.0, "unit": "g", "item": "Prunes", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "cloves", "item": "Cloves", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Peppercorns", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Berries", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Berries", "notes": null, "category": "other"}, {"quantity": 90.0, "unit": "ml", "item": "Red Wine", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Tomato Puree", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Put the cabbage in a heavy casserole dish, add the stock and cook over a low heat for about 50 mins, until tender.", "step 2", "Cut the soaked mushrooms into strips and save the soaking water. Heat the lard and fry the sausages and bacon, then scoop out, leaving the fat in the pan. Fry the onion in the same pan for 5-8 mins until lightly browned.", "step 3", "Add the mushrooms and their liquid along with all the cooked meat, onions and prunes, then cover and cook for 20 mins. Add the spices, red wine and tomato purée and bring to a simmer, then cover and cook for 1 hr. Season well and leave to cool. Will keep covered and chilled for up to two days. Bigos improves in flavour over a couple of days. Leave to cool first. Reheat until piping hot before serving."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/bigos', 'https://www.themealdb.com/images/media/meals/fl4brj1764361323.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bistek', 'Bistek', 4, 0, 0, '{"calories": 322, "protein": 25.4, "carbs": 357.0, "fat": 14.4, "saturated_fat": 5.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 10385.9, "potassium": null, "fiber": 0.6, "sugar": 9.0, "vitamin_a": null, "vitamin_c": 2.8, "calcium": 19.0, "iron": 5.7}'::jsonb, ARRAY['beef', 'filipino', 'themealdb', 'nutrition-generated'], '[{"quantity": 1.0, "unit": "lb", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 5.0, "unit": "tablespoons", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Lemon", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Salt", "notes": null, "category": "pantry"}]'::jsonb, '["0.\tMarinate beef in soy sauce, lemon (or calamansi), and ground black pepper for at least 1 hour. Note: marinate overnight for best result", "1.\tHeat the cooking oil in a pan then pan-fry half of the onions until the texture becomes soft. Set aside", "2.\tDrain the marinade from the beef. Set it aside. Pan-fry the beef on the same pan where the onions were fried for 1 minute per side. Remove from the pan. Set aside", "3.\tAdd more oil if needed. Saute garlic and remaining raw onions until onion softens.", "4.\tPour the remaining marinade and water. Bring to a boil.", "5.\tAdd beef. Cover the pan and simmer until the meat is tender. Note: Add water as needed.", "6.\tSeason with ground black pepper and salt as needed. Top with pan-fried onions.", "7.\tTransfer to a serving plate. Serve hot. Share and Enjoy!"]'::jsonb, 'https://panlasangpinoy.com/bistek-tagalog-beefsteak-recipe/', 'https://www.themealdb.com/images/media/meals/4pqimk1683207418.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bitterballen-dutch-meatballs', 'Bitterballen (Dutch meatballs)', 4, 0, 0, '{"calories": 927, "protein": 36.6, "carbs": 86.4, "fat": 48.3, "saturated_fat": 26.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 951.5, "potassium": 240.0, "fiber": 3.7, "sugar": 29.5, "vitamin_a": null, "vitamin_c": null, "calcium": 26.4, "iron": 9.9}'::jsonb, ARRAY['beef', 'dutch', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 100.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 150.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 700.0, "unit": "ml", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 30.0, "unit": "g", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 50.0, "unit": "g", "item": "Breadcrumbs", "notes": null, "category": "grains"}]'::jsonb, '["Melt the butter in a skillet or pan. When melted, add the flour little by little and stir into a thick paste. Slowly stir in the stock, making sure the roux absorbs the liquid. Simmer for a couple of minutes on a low heat while you stir in the onion, parsley and the shredded meat. The mixture should thicken and turn into a heavy, thick sauce.", "Pour the mixture into a shallow container, cover and refrigerate for several hours, or until the sauce has solidified.", "Take a heaping tablespoon of the cold, thick sauce and quickly roll it into a small ball. Roll lightly through the flour, then the egg and finally the breadcrumbs. Make sure that the egg covers the whole surface of the bitterbal. When done, refrigerate the snacks while the oil in your fryer heats up to 190C (375F). Fry four bitterballen at a time, until golden.", "Serve on a plate with a nice grainy or spicy mustard."]'::jsonb, 'https://www.holland.com/global/tourism/information/traditional-dutch-food/bitterballen.htm', 'https://www.themealdb.com/images/media/meals/lhqev81565090111.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('borsch', 'Borsch', 4, 0, 0, '{"calories": 2317, "protein": 62.8, "carbs": 381.5, "fat": 63.5, "saturated_fat": 28.3, "polyunsaturated_fat": null, "monounsaturated_fat": 9.5, "sodium": 4062.5, "potassium": 4395.4, "fiber": 29.3, "sugar": 41.8, "vitamin_a": 19.9, "vitamin_c": 140.0, "calcium": 299.7, "iron": 15.7}'::jsonb, ARRAY['beef', 'ukrainian', 'themealdb', 'nutrition-generated'], '[{"quantity": 1.0, "unit": "kg", "item": "Beef Shin", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 2.5, "unit": "kg", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Beetroot", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Tinned Tomatos", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Prunes", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Kidney Beans", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "ml", "item": "Creme Fraiche", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Dill", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Crusty Bread", "notes": null, "category": "grains"}]'::jsonb, '["step 1", "To make the stock, put the meat, whole onion, bay leaf and 2 litres of lightly salted cold water in a large saucepan. Cook over a very low heat for 1 hr 30 mins or until the beef shin is soft and falls apart easily – this can take up to 3 hrs. Skim off the scum with a spoon from time to time. Break up any larger pieces of beef into the broth, remove the whole onion and discard.", "step 2", "Add the potatoes to the borscht, season well with salt and pepper and cook for 10-15 mins until tender. Meanwhile, heat the sunflower oil in a large, deep frying pan. Add the diced onion and carrot, and cook over a medium heat, stirring, until the carrot is soft and is about to start caramelising.", "step 3", "Add the beetroot and cook for around 5 mins, stirring occasionally. Add the red pepper, if using, and cook for another 2 mins, then add the tomatoes and prunes, stir, then increase the heat and boil to reduce slightly, before adding everything to the borscht.", "step 4", "Add the shredded cabbage and the kidney beans, and cook for 7-10 mins or until tender. Serve with a dollop of sour cream or crème fraîche, lots of chopped dill and some crusty bread."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/borsch', 'https://www.themealdb.com/images/media/meals/804v1j1764367088.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('braised-beef-chilli', 'Braised Beef Chilli', 4, 0, 0, '{"calories": 1064, "protein": 76.2, "carbs": 44.8, "fat": 86.0, "saturated_fat": 33.9, "polyunsaturated_fat": null, "monounsaturated_fat": 4.2, "sodium": 2236.6, "potassium": 87.7, "fiber": 8.2, "sugar": 14.4, "vitamin_a": 189.5, "vitamin_c": 5.4, "calcium": 86.7, "iron": 13.3}'::jsonb, ARRAY['beef', 'mexican', 'themealdb', 'nutrition-generated', 'dessert', 'baking'], '[{"quantity": 1.0, "unit": "kg", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Olive oil", "notes": null, "category": "pantry"}, {"quantity": 300.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tsp", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Cloves", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Cinnamon stick", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "dried Oregano", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Ancho Chillies", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tbsp", "item": "Balsamic Vinegar", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "400g Plum Tomatoes", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "Tomato Ketchup", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "Dark Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "400g tins Borlotti Beans", "notes": null, "category": "pantry"}]'::jsonb, '["Preheat the oven to 120C/225F/gas mark 1.", "Take the meat out of the fridge to de-chill. Pulse the onions and garlic in a food processor until finely chopped. Heat 2 tbsp olive oil in a large casserole and sear the meat on all sides until golden.", "Set to one side and add another small slug of oil to brown the chorizo. Remove and add the onion and garlic, spices, herbs and chillies then cook until soft in the chorizo oil. Season with salt and pepper and add the vinegar, tomatoes, ketchup and sugar.", "Put all the meat back into the pot with 400ml water (or red wine if you prefer), bring up to a simmer and cook, covered, in the low oven.", "After 2 hours, check the meat and add the beans. Cook for a further hour and just before serving, pull the meat apart with a pair of forks."]'::jsonb, 'http://www.telegraph.co.uk/food-and-drink/recipes/braised-beef-chilli-con-carne/', 'https://www.themealdb.com/images/media/meals/uuqvwu1504629254.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('brun-lapskaus-norwegian-beef-vegetable-stew', 'Brun Lapskaus (Norwegian Beef Vegetable Stew)', 4, 0, 0, '{"calories": 596, "protein": 10.4, "carbs": 71.5, "fat": 26.9, "saturated_fat": 4.6, "polyunsaturated_fat": null, "monounsaturated_fat": 0.6, "sodium": 2534.6, "potassium": 598.0, "fiber": 3.7, "sugar": 5.9, "vitamin_a": 18.8, "vitamin_c": 26.5, "calcium": 84.2, "iron": 2.5}'::jsonb, ARRAY['beef', 'norwegian', 'themealdb', 'nutrition-generated', 'soup'], '[{"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "lbs", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cups", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Swede", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "lb", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Leek", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garnish Parsley", "notes": null, "category": "produce"}]'::jsonb, '["▢", "Heat olive oil in a large pot. Cut beef into 1 inch (2.5 cm) cubes and brown in oil.", "▢", "Dice the onion and add to browning beef. Add the stock and bring to a boil, then lower the heat, cover, and let simmer for about 30 minutes.", "▢", "Peel and cut the rutabaga and celery root into 1 inch (2.5 cm) cubes. Add to the pot, cover, and continue simmering for another 30 minutes.", "▢", "Peel and chop the rest of the vegetables into 1 inch (2.5 cm) cubes and add to the pot. Slice the leek into rings. Cover and continue simmering for about 20 minutes. Stir as little as possible.", "▢", "Top with fresh parsley."]'::jsonb, 'https://scandinaviancookbook.com/brun-lapskaus-norwegian-beef-vegetable-root-stew/', 'https://www.themealdb.com/images/media/meals/6vi2cv1763075785.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('carbonada-criolla', 'Carbonada Criolla', 4, 0, 0, '{"calories": 431, "protein": 29.9, "carbs": 392.2, "fat": 7.5, "saturated_fat": 5.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 10281.2, "potassium": 191.0, "fiber": 13.2, "sugar": 20.3, "vitamin_a": null, "vitamin_c": 11.7, "calcium": 163.5, "iron": 15.3}'::jsonb, ARRAY['beef', 'argentinian', 'themealdb', 'nutrition-generated', 'soup'], '[{"quantity": 500.0, "unit": "g", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pumpkin", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Dried Apricots", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Brown the Beef: In a large pot, brown the beef cubes. Remove and set aside.", "Sauté Vegetables: In the same pot, cook the onion until translucent. Add carrots, potatoes, and pumpkin, cooking for a few minutes.", "Simmer: Return the beef to the pot. Add broth and dried apricots. Season with salt and pepper. Simmer for 1-2 hours, until the beef is tender.", "Serve: Enjoy hot, with a crusty piece of bread.", "Pro Tips:", "Brown the beef in batches to ensure it gets a good sear, which adds depth to the stew''s flavor.", "Adding the fruits towards the end of cooking preserves their texture and adds a subtle sweetness to the dish."]'::jsonb, 'https://www.munchery.com/blog/the-ten-iconic-dishes-of-argentina-and-how-to-cook-them-at-home/', 'https://www.themealdb.com/images/media/meals/8b2msz1763074897.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cevapi-sausages', 'Cevapi Sausages', 4, 0, 0, '{"calories": 410, "protein": 43.8, "carbs": 22.1, "fat": 17.1, "saturated_fat": 12.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 4032.8, "potassium": null, "fiber": 0.6, "sugar": 4.5, "vitamin_a": null, "vitamin_c": 2.4, "calcium": 24.0, "iron": 7.0}'::jsonb, ARRAY['beef', 'croatian', 'themealdb', 'nutrition-generated', 'soup', 'baking', 'grilling'], '[{"quantity": 500.0, "unit": "g", "item": "Minced Beef", "notes": null, "category": "meat"}, {"quantity": 250.0, "unit": "g", "item": "Minced Pork", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 0.75, "unit": "teaspoon", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 3.0, "unit": "tbs", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Stock Cube", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Place the ground meat in a bowl. Chop the onion very finely and grate the garlic cloves. Add to the bowl. Add the chopped parsley, all sorts of paprika, baking soda, dried breadcrumbs, water, Vegeta, salt, and pepper.", "Mix well with the hand mixer fitted with the dough hooks. Cover the bowl with cling film/ plastic foil and leave to rest for 1 or 2 hours in the refrigerator.", "Take portions of the meat mixture, about 50-55 g/ 1.7-1.9 oz/ ¼ cup portions, and form the cevapi. The rolls should be about as thick as your thumb and about 7-10 cm/ 3-4 inches long. I had 18 sausages. The recipe can be easily doubled.", "Grill the cevapcici on the hot grill pan or on the barbecue for about 12-14 minutes, turning them several times in between, or until brown and cooked through. I checked by cutting one in the middle and then grilling the following batches for the same period of time.", "Serve hot as suggested above. The cevapcici can be reheated in the oven at 180 degrees Celsius/ 350 degrees Fahrenheit for about 10 minutes or until heated through. Check one, if it is not hot enough, give the sausages a few more minutes."]'::jsonb, 'https://whereismyspoon.co/cevapi-or-cevapcici-recipe-grilled-sausages-croatian-food/', 'https://www.themealdb.com/images/media/meals/vc08jn1628769553.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chivito-sandwich', 'Chivito sandwich', 4, 0, 0, '{"calories": 1070, "protein": 33.5, "carbs": 203.3, "fat": 41.4, "saturated_fat": 15.9, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1612.0, "potassium": 299.6, "fiber": 6.8, "sugar": 25.7, "vitamin_a": null, "vitamin_c": 0.2, "calcium": 102.4, "iron": 9.6}'::jsonb, ARRAY['beef', 'uruguayan', 'themealdb', 'nutrition-generated', 'breakfast', 'salad', 'baking', 'grilling'], '[{"quantity": 80.0, "unit": "g", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 60.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Molasses", "notes": null, "category": "pantry"}, {"quantity": 220.0, "unit": "g", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 500.0, "unit": "g", "item": "Bread Flour", "notes": null, "category": "grains"}, {"quantity": 10.0, "unit": "g", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 10.0, "unit": "g", "item": "Yeast", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Splash Egg Wash", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Sprinkling Sesame Seed", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "steak", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 8.0, "unit": "slices", "item": "Ham", "notes": null, "category": "meat"}, {"quantity": 8.0, "unit": "slices", "item": "Mozzarella", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "1/4  Lettuce", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Mustard", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Chimichurri sauce", "notes": null, "category": "other"}]'::jsonb, '["For the brioche buns heat the milk with the butter and molasses until the butter has melted. Add the cold water and egg to this mix.", "2", "In a large bowl place flour, salt and yeast and mix. Then add the milk and water mix and stir with a wooden spoon until combined. You don''t have to knead the dough, it is perfectly fine to do this by hand with a wooden spoon, this doesn''t need to be very thorough. Cover with a damp towel and stick in the fridge overnight.", "3", "The next morning knead dough on a generously floured surface for a little and cut into eight equal pieces. Shape these into balls and place on a baking sheet lined with parchment paper. Cover again with damp towel and let rise for about an hour or until double in size.", "4", "Heat oven to 220 degrees Celsius. Brush the buns with either milk, heavy cream or egg wash and sprinkle with sesame seeds, if desired. Bake for about 15-20min or until golden. Let cool.", "5", "For the toppings chop the onions and sauté in a bit of butter, let caramelize, this may take ten to 15 minutes, stir occasionally. Rub the steaks with a bit of garlic and then grill or fry the steaks, the bacon, and eggs with salt and pepper, toast the buns after having cut in half. Spread mustard on one bun half, layer each chivito with steak, a slice of ham, a slice of cheese, one bacon stripe, a tomato slice, and some lettuce. Place fried egg on top and sprinkle generously with chimichurri and some onions right before serving."]'::jsonb, 'https://jennyisbaking.com/2019/06/14/lets-grill-chivito-uruguays-national-dish/#recipe', 'https://www.themealdb.com/images/media/meals/j80gmw1764372176.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chivito-uruguayo', 'Chivito uruguayo', 4, 0, 0, '{"calories": 702, "protein": 23.6, "carbs": 81.6, "fat": 26.0, "saturated_fat": 12.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 944.0, "potassium": 34.8, "fiber": 10.6, "sugar": 16.3, "vitamin_a": null, "vitamin_c": 5.2, "calcium": 282.8, "iron": 8.3}'::jsonb, ARRAY['beef', 'uruguayan', 'themealdb', 'nutrition-generated', 'breakfast', 'salad'], '[{"quantity": 1.0, "unit": "serving", "item": "Brisket", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Lettuce", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Ham", "notes": null, "category": "meat"}, {"quantity": 100.0, "unit": "g", "item": "Mozzarella", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Crush the meat so that it is finite and we put it on a griddle to brown. Put the eggs, bacon and ham to fry.", "Cut the bread in half, put the beef brisket, the fried eggs, the bacon, the ham, the mozzarella, the tomato and the lettuce. Cover with the other half of the bread and serve."]'::jsonb, 'https://cookpad.com/uy/recetas/116102-chivito-uruguayo', 'https://www.themealdb.com/images/media/meals/n7qnkb1630444129.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('classic-tourtière', 'Classic Tourtière', 4, 0, 0, '{"calories": 1088, "protein": 43.5, "carbs": 406.0, "fat": 69.7, "saturated_fat": 26.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 10931.3, "potassium": 434.5, "fiber": 9.7, "sugar": 15.6, "vitamin_a": null, "vitamin_c": 13.0, "calcium": 214.6, "iron": 11.4}'::jsonb, ARRAY['beef', 'canadian', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "Canola Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "lb", "item": "Ground Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "lb", "item": "Ground Pork", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tsp", "item": "Dried Leaves Of Summer Savoury", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Ground Clove", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Ground Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "cup", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Russet Potato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pastry", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}]'::jsonb, '["Heat oil on medium-high heat in a large sauté pan or skillet, then sauté the onion and garlic until softened, about 5 minutes. Add the ground beef, pork, and spices and cook until the meat is browned.", "Add the beef broth and bring it up to a simmer then reduce heat to medium low. Add the grated potato and stir it in. Cook until liquid is almost absorbed, about 15 min. Remove the bay leaves and add salt to taste. Remove the pan from the heat and let the mixture cool completely — it bakes best if the filling is chilled.", "Preheat the oven to 375 °F (190 °C). On a lightly floured surface, roll out one disc of the pie dough to less than the 1/4-inch thickness and line the 9-inch pie plate. Fill this with the cooled tourtière mixture and spread out evenly. Roll out the remaining dough to the same thickness, cut a hole in the centre (for steam to escape) and place on top of the filling. Trim the dough to 1/2-inch beyond the edge of the pie plate and pinch the edges of the crust together. Brush the crust with the egg wash.", "Bake tourtière for about 45 minutes or until the pastry is a rich golden brown. Let cool for 15 minutes before slicing to serve.", "Serves: 8-10 (makes 2 9-inch pies)"]'::jsonb, 'https://canadianfoodfocus.org/recipes/classic-canadian-dish-classic-tourtiere/', 'https://www.themealdb.com/images/media/meals/0sd7ac1764787957.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('corned-beef-and-cabbage', 'Corned Beef and Cabbage', 4, 0, 0, '{"calories": 28, "protein": 0.8, "carbs": 6.6, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 19.2, "potassium": 185.0, "fiber": 1.0, "sugar": 1.8, "vitamin_a": null, "vitamin_c": 6.5, "calcium": 10.0, "iron": 0.3}'::jsonb, ARRAY['beef', 'irish', 'themealdb', 'nutrition-generated', 'baking'], '[{"quantity": 3.0, "unit": "lbs", "item": "Beef Brisket", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "head", "item": "Cabbage", "notes": null, "category": "produce"}]'::jsonb, '["1", "Place corned beef in large pot or Dutch oven and cover with water. Add the spice packet that came with the corned beef. Cover pot and bring to a boil, then reduce to a simmer. Simmer approximately 50 minutes per pound or until tender.", "2", "Add whole potatoes and peeled and cut carrots, and cook until the vegetables are almost tender. Add cabbage and cook for 15 more minutes. Remove meat and let rest 15 minutes.", "3", "Place vegetables in a bowl and cover. Add as much broth (cooking liquid reserved in the Dutch oven or large pot) as you want. Slice meat across the grain."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/xb97a81583266727.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('corned-beef-and-cabbage-jamaican-style', 'Corned Beef and Cabbage – Jamaican Style', 4, 0, 0, '{"calories": 389, "protein": 22.8, "carbs": 372.5, "fat": 15.6, "saturated_fat": 6.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 10644.0, "potassium": 87.3, "fiber": 9.5, "sugar": 4.1, "vitamin_a": null, "vitamin_c": 31.8, "calcium": 126.1, "iron": 10.3}'::jsonb, ARRAY['beef', 'jamaican', 'themealdb', 'nutrition-generated'], '[{"quantity": 1.0, "unit": "tablespoon", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Green Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 12.0, "unit": "ounces", "item": "Corned Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Plum Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Tomato Ketchup", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Heat olive oil in a skillet or Dutch pot over medium-high heat. Add onion and green pepper and sauté for about 3-5 minutes.", "Add garlic and stir for about 1 minute.", "Add shredded cabbage and stir. Cook for about about 3-5 minutes, stirring often until softened.", "Add corned beef, Roma tomatoes, and thyme and stir. Add ketchup and scotch bonnet pepper sauce and stir. Reduce heat and cook on medium for about 3-5 minutes, until the corned beef is heated through. Remove from heat.", "Serve with white rice, bread, or on its own."]'::jsonb, 'https://www.myforkinglife.com/corned-beef-and-cabbage-jamaican-style/#recipe', 'https://www.themealdb.com/images/media/meals/kdz63q1764793442.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('corned-beef-hash', 'Corned Beef Hash', 4, 0, 0, '{"calories": 610, "protein": 52.3, "carbs": 46.5, "fat": 41.5, "saturated_fat": 13.7, "polyunsaturated_fat": null, "monounsaturated_fat": 10.0, "sodium": 1636.4, "potassium": 291.1, "fiber": 4.3, "sugar": 6.0, "vitamin_a": null, "vitamin_c": 4.5, "calcium": 73.5, "iron": 7.9}'::jsonb, ARRAY['beef', 'british', 'themealdb', 'nutrition-generated'], '[{"quantity": 3.0, "unit": "tablespoons", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Onion", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cups", "item": "Corned Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Kosher Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped", "notes": "Freshly Chopped Parsley", "category": "other"}]'::jsonb, '["Sauté the onions:", "Heat butter in a large skillet (preferably cast iron) on medium heat. Add the onion and cook a few minutes, until translucent.", "Add the potatoes and corned beef:", "Mix in the chopped corned beef and potatoes. Spread out evenly over the pan. Increase the heat to high or medium high and press down on the mixture with a metal spatula.", "Cook until browned and then flip:", "Do not stir the potatoes and corned beef, but let them brown. If you hear them sizzling, this is good.", "Use a metal spatula to peek underneath and see if they are browning. If nicely browned, use the spatula to flip sections over in the pan so that they brown on the other side. Press down again with the spatula.", "If there is too much sticking, you can add a little more butter to the pan. Continue to cook in this manner until the potatoes and the corned beef are nicely browned.", "Stir in the parsley and season:", "Remove from heat, stir in chopped parsley. Add plenty of freshly ground black pepper, and add salt to taste."]'::jsonb, 'https://www.simplyrecipes.com/recipes/corned_beef_hash/', 'https://www.themealdb.com/images/media/meals/vz94r81760534692.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('croatian-bean-stew', 'Croatian Bean Stew', 4, 0, 0, '{"calories": 567, "protein": 36.3, "carbs": 17.2, "fat": 42.5, "saturated_fat": 13.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2033.3, "potassium": 113.0, "fiber": 1.9, "sugar": 4.7, "vitamin_a": null, "vitamin_c": 7.5, "calcium": 31.3, "iron": 4.6}'::jsonb, ARRAY['beef', 'croatian', 'themealdb', 'nutrition-generated', 'soup', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 2.0, "unit": "cans", "item": "Cannellini Beans", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tbs", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "cups", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Challots", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Parsley", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "kg", "item": "chopped  Chorizo", "notes": null, "category": "other"}]'::jsonb, '["Heat the oil in a pan.", "Add the chopped vegetables and sauté until tender.", "Take a pot, empty the beans together with the vegetables into it, put the sausages inside and cook for further 20 minutes on a low heat.", "Or, put it in an oven and bake it at a temperature of 180ºC/350ºF for 30 minutes.", "This dish is even better reheated the next day."]'::jsonb, 'https://www.visit-croatia.co.uk/croatian-cuisine/croatian-recipes/', 'https://www.themealdb.com/images/media/meals/tnwy8m1628770384.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('croatian-lamb-peka', 'Croatian lamb peka', 4, 0, 0, '{"calories": 826, "protein": 60.6, "carbs": 71.6, "fat": 86.9, "saturated_fat": 10.1, "polyunsaturated_fat": null, "monounsaturated_fat": 6.7, "sodium": 1600.2, "potassium": 1465.0, "fiber": 4.6, "sugar": 7.7, "vitamin_a": null, "vitamin_c": 54.1, "calcium": 86.5, "iron": 10.2}'::jsonb, ARRAY['beef', 'croatian', 'themealdb', 'nutrition-generated', 'baking'], '[{"quantity": 600.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Courgettes", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Green Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Aubergine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Onion", "notes": null, "category": "produce"}, {"quantity": 800.0, "unit": "g", "item": "Lamb Shoulder", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tbs", "item": "Garlic Sauce", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 80.0, "unit": "ml", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Sprinking Thyme", "notes": null, "category": "produce"}, {"quantity": 250.0, "unit": "ml", "item": "White Wine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Preheat oven to 200°C fan / 220°C / 425°F / Gas mark 7", "If you have not bought diced lamb, cut your lamb shoulder or leg into large chunks and place to one side.", "Chunks of chopped lamb of a red chopping board", "Make oil marinade -", "Mix 80ml of olive oil in a bowl with garlic puree, sundried tomato puree ,black pepper and salt.", "olive oil, gia sundried tomato puree and gia garlic puree and black pepper mixed together in a silver bowl to make Croatian peka", "Add potatoes and vegetables into a large lidded casserole dish.", "Chopped up vegetables which consist of chopped up red onion, courgette, potatoes red peppers in a cast iron pan", "Place diced lamb on top of the vegetables, pour the marinade and wine over the top.", "Chunks of lamb covered in in a sundried tomato oil sauce which is on top of chopped red onion, aubergine, courgette and potatoes in a cast iron pan", "Add the rosemary, thyme and sage, trying to keep the herbs on top.", "So you can easily remove the herb stalks once cooked.", "Chunks of lamb coated in a sundried tomato oil sauce and covered with thyme, rosemary and sage which is on top of chopped red onion, aubergine, courgette and potatoes in a cast iron pan", "Place lid on the casserole dish and cook for 1hr 30 minute", "If you do not have a lid cover very well with kitchen foil", "Cast iron dish with lid on in the oven", "Take the lid off, remove any thick herb stems. Stir in 2 tbsp of olive oil.", "Cook for a further 20-30 mins.", "Cooked Croatian Lamb Peka in a cast iron pan in the oven", "Serve with fresh homemade bread to dip into the juices."]'::jsonb, 'https://flawlessfood.co.uk/croatian-lamb-peka/', 'https://www.themealdb.com/images/media/meals/pn59o51628769837.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cumberland-pie', 'Cumberland Pie', 4, 0, 0, '{"calories": 605, "protein": 13.0, "carbs": 60.8, "fat": 36.8, "saturated_fat": 12.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 3818.4, "potassium": 1018.5, "fiber": 5.0, "sugar": 9.1, "vitamin_a": 19.1, "vitamin_c": 43.2, "calcium": 126.7, "iron": 3.0}'::jsonb, ARRAY['beef', 'british', 'themealdb', 'nutrition-generated', 'dessert', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Worcestershire Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Stock Cubes", "notes": null, "category": "pantry"}, {"quantity": 800.0, "unit": "g", "item": "Feather blade beef", "notes": null, "category": "meat"}, {"quantity": 800.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 25.0, "unit": "g", "item": "Mature Cheddar", "notes": null, "category": "dairy"}, {"quantity": 25.0, "unit": "g", "item": "Parmesan Cheese", "notes": null, "category": "dairy"}]'::jsonb, '["step 1", "Heat oven to 160C/140C fan/gas 3. Soften the celery, onion, carrots, bay and 1 thyme sprig in a casserole with 1 tbsp oil and the butter for 10 mins. Stir in the flour, followed by the purée, Worcestershire sauce and stock cubes.", "step 2", "Gradually stir in 600ml hot water, then tip in the beef and bring to a gentle simmer. Cover and cook in the oven for 2 hrs 30 mins, then uncover and cook for 30 mins -1 hr more until the meat is really tender and sauce thickened.", "step 3", "Meanwhile, cook potatoes in a pan of boiling water until they’re not done but about ¾ of the way there.", "step 4", "Transfer meat to a baking dish. Slice spuds into 1cm thick rounds and gently toss with seasoning, the remaining oil and thyme leaves. Layer on the beef, scattering with the cheese as you layer. You can cover and chill the pie now for 1 day, or freeze for up to 3 months.", "step 5", "Increase oven to 200C/180C fan/gas 6 and bake for 30-40 mins until golden and crispy, and sauce bubbling if the dish went in cold. Serve with peas."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/crispy-topped-cumberland-pie', 'https://www.themealdb.com/images/media/meals/pvfkz61761595976.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('drunken-noodles-pad-kee-mao', 'Drunken noodles (pad kee mao)', 4, 0, 0, '{"calories": 601, "protein": 23.0, "carbs": 65.6, "fat": 30.0, "saturated_fat": 4.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1582.1, "potassium": 249.5, "fiber": 37.5, "sugar": 29.0, "vitamin_a": null, "vitamin_c": 1.8, "calcium": 764.1, "iron": 21.4}'::jsonb, ARRAY['beef', 'thai', 'themealdb', 'nutrition-generated', 'dessert', 'pasta'], '[{"quantity": 200.0, "unit": "g", "item": "Flat Rice Noodles", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "cloves", "item": "Chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Birds-eye Chillies", "notes": null, "category": "other"}, {"quantity": 225.0, "unit": "g", "item": "Sirloin steak", "notes": null, "category": "meat"}, {"quantity": 100.0, "unit": "g", "item": "Broccoli", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Basil Leaves", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tbsp", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "tbsp", "item": "Oyster Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Prepare the noodles following pack instructions, then drain and set aside. Combine all the ingredients for the sauce in a small bowl or jug, and set aside.", "step 2", "Heat the oil in a large wok or frying pan over a high heat and stir-fry the garlic and chilli for 20 seconds until just starting to turn golden. Add the steak and stir-fry for 1 minute until seared and starting to brown. Add the broccoli and stir-fry for another minute, then tip in the noodles and add the sauce. Stir-fry for another 1-2 mins until well combined and piping hot.", "step 3", "Stir through the basil and turn off the heat. Serve immediately to avoid overcooking."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/drunken-noodles-pad-kee-mao', 'https://www.themealdb.com/images/media/meals/2wx8cm1763373419.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('egyptian-fatteh', 'Egyptian Fatteh', 4, 0, 0, '{"calories": 1671, "protein": 34.2, "carbs": 415.2, "fat": 129.2, "saturated_fat": 31.9, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 14284.1, "potassium": 21.9, "fiber": 11.9, "sugar": 6.8, "vitamin_a": null, "vitamin_c": 8.9, "calcium": 143.7, "iron": 15.2}'::jsonb, ARRAY['beef', 'egyptian', 'themealdb', 'nutrition-generated', 'soup', 'pasta'], '[{"quantity": 1.0, "unit": "lb", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Stock Cube", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tbs", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "Rice", "notes": null, "category": "grains"}, {"quantity": 0.25, "unit": "cup", "item": "Noodles", "notes": null, "category": "grains"}, {"quantity": 0.25, "unit": "cup", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "cups", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tbs", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 3.0, "unit": "tbs", "item": "White Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}]'::jsonb, '["To prepare bread for bottom of dish: Take pita bread and rip into bite size pieces. In a frying pan, add about a 1/4 stick of butter, add bread pieces and fry until golden brown and crisp. Put these pieces in a glass baking dish, preferably a square sized dish. Set aside.", "Then add to same pan, a little more butter, salt, approximately 2 cloves of crushed fresh garlic, and a teaspoon or so of cumin stir around a bit until you can smell aroma, then add fried bread pieces to this mixture, stir to coat bread and put back into glass baking dish. Set aside.", "To prepare meat: put some butter in a pot, stir fry meat until brown, add 1 onion quartered, salt & pepper, 1 cube of chicken bouillon and water to cover meat. Bring to a boil, turn down to simmer, cover and cook until tender, approximately 2 hours. After meat has cooled, take out chunks of meat and put in a bowl, set aside. Reserve soup from the meat separately.", "To prepare the rice: Put some butter into a pot, add shareya (fideo noodles) like a handful or so, keep stirring until golden brown, not too dark, but very golden. Then add two cups of rice, stir a little bit until some of the rice turns an opaque white. Add 2-1/4 cups of water and salt to taste. Bring to a boil, cover and turn down to simmer, cook until tender. Test the rice tenderness after about 35 minutes.", "Now take some of the soup from meat and add to the top of the bread pieces in baking dish to saturate.Add cooked rice on top of bread pieces. Slowly spoon remainder of soup onto rice, looking at glass dish sides to see level of soup, should reach just to top of rice, don’t worry, this doesn’t have to be exact. Now you’re ready to make the sauce and fry the meat to put on top.", "To prepare red sauce: In a pan, add a little oil or butter, crushed tomato, a half teaspoon of tomato paste, salt & pepper, 2 cloves of fresh crushed garlic and cumin. Add also approximately 3 tablespoons of vinegar, stir this until you smell aroma and it is a bit smooth. It should be a bit thick, not watery, but if too thick you can add a bit of water. Spread with a wooden spoon atop the rice to cover.", "To fry meat: In a pan add a bit of butter or oil, the meat, just a touch of tomato paste, about a tablespoon of fresh crushed garlic, salt & pepper, a teaspoon of cumin. Cook until meat is golden fried.", "Spoon this atop the rice and serve. Enjoy!"]'::jsonb, 'https://www.food.com/recipe/egyptian-faatah-rice-meat-with-crispy-bread-on-bottom-194764', 'https://www.themealdb.com/images/media/meals/rlwcc51598734603.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('empanadas', 'Empanadas', 4, 0, 0, '{"calories": 1526, "protein": 29.7, "carbs": 478.4, "fat": 86.8, "saturated_fat": 44.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 11545.4, "potassium": null, "fiber": 11.4, "sugar": 18.6, "vitamin_a": null, "vitamin_c": 5.2, "calcium": 251.0, "iron": 11.6}'::jsonb, ARRAY['beef', 'argentinian', 'themealdb', 'nutrition-generated', 'baking'], '[{"quantity": 500.0, "unit": "g", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 200.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 120.0, "unit": "ml", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 500.0, "unit": "g", "item": "Ground Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Green Olives", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Make the Dough: Mix flour and salt in a large bowl. Add butter, using your fingers to blend into a crumbly texture. Gradually add water, mixing until a dough forms. Wrap and chill for 30 minutes.", "Prepare the Filling: Cook onions in a pan until translucent. Add ground beef, cooking until browned. Stir in spices, then remove from heat. Once cooled, mix in eggs and olives.", "Assemble: Roll out the dough and cut into circles. Place a spoonful of filling in each, fold over, and seal the edges.", "Cook: Bake at 200°C (400°F) for 20-25 minutes, or until golden.", "Pro Tips:", "For a flakier crust, incorporate a tablespoon of vinegar into the dough mixture. This helps prevent gluten formation.", "Seal the edges of the empanadas with a fork to ensure they do not open during baking or frying."]'::jsonb, 'https://www.munchery.com/blog/the-ten-iconic-dishes-of-argentina-and-how-to-cook-them-at-home/', 'https://www.themealdb.com/images/media/meals/q99te31763075494.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('golabki-cabbage-roll', 'Golabki (cabbage roll)', 4, 0, 0, '{"calories": 699, "protein": 32.7, "carbs": 35.3, "fat": 48.0, "saturated_fat": 17.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 879.8, "potassium": 153.3, "fiber": 1.5, "sugar": 2.7, "vitamin_a": null, "vitamin_c": 11.8, "calcium": 64.5, "iron": 4.6}'::jsonb, ARRAY['beef', 'polish', 'themealdb', 'nutrition-generated', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "lb", "item": "Ground Beef", "notes": null, "category": "meat"}, {"quantity": 0.5, "unit": "lb", "item": "Ground Pork", "notes": null, "category": "meat"}, {"quantity": 1.5, "unit": "cups", "item": "Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cans", "item": "Tomato Puree", "notes": null, "category": "produce"}]'::jsonb, '["Bring a large pot of lightly salted water to a boil. Place cabbage head into water, cover pot, and cook until cabbage leaves are slightly softened enough to remove from head, 3 minutes. Remove cabbage from pot and let cabbage sit until leaves are cool enough to handle, about 10 minutes.", "Remove 18 whole leaves from the cabbage head, cutting out any thick tough center ribs. Set whole leaves aside. Chop the remainder of the cabbage head and spread it in the bottom of a casserole dish.", "Melt butter in a large skillet over medium-high heat. Cook and stir onion in hot butter until tender, 5 to 10 minutes. Cool.", "Stir onion, beef, pork, rice, garlic, 1 teaspoon salt, and 1/4 teaspoon pepper together in a large bowl.", "Preheat oven to 350 degrees F (175 degrees C).", "Place about 1/2 cup beef mixture on a cabbage leaf. Roll cabbage around beef mixture, tucking in sides to create an envelope around the meat. Repeat with remaining leaves and meat mixture. Place cabbage rolls in a layer atop the chopped cabbage in the casserole dish; season rolls with salt and black pepper.", "Whisk tomato soup, tomato juice, and ketchup together in a bowl. Pour tomato soup mixture over cabbage rolls and cover dish wish aluminum foil.", "Bake in the preheated oven until cabbage is tender and meat is cooked through, about 1 hour."]'::jsonb, 'https://www.allrecipes.com/recipe/234975/golabki-stuffed-cabbage-rolls/', 'https://www.themealdb.com/images/media/meals/q8sp3j1593349686.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('irish-stew', 'Irish stew', 4, 0, 0, '{"calories": 1073, "protein": 141.9, "carbs": 121.2, "fat": 79.1, "saturated_fat": 12.9, "polyunsaturated_fat": null, "monounsaturated_fat": 4.0, "sodium": 1658.7, "potassium": 2397.5, "fiber": 13.1, "sugar": 30.7, "vitamin_a": null, "vitamin_c": 9.2, "calcium": 68.8, "iron": 8.8}'::jsonb, ARRAY['beef', 'irish', 'themealdb', 'nutrition-generated', 'dessert', 'soup', 'baking'], '[{"quantity": 300.0, "unit": "g", "item": "soaked overnight in water whole wheat", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "kg", "item": "cut into 3cm cubes lamb loin chops", "notes": null, "category": "meat"}, {"quantity": 120.0, "unit": "ml", "item": "olive oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "shallots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "turnips", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "celeriac", "notes": null, "category": "other"}, {"quantity": 350.0, "unit": "g", "item": "charlotte potatoes", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "ml", "item": "white wine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "caster sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "fresh thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "oregano", "notes": null, "category": "spices"}, {"quantity": 450.0, "unit": "ml", "item": "chicken stock", "notes": null, "category": "meat"}]'::jsonb, '["Heat the oven to 180C/350F/gas mark 4. Drain and rinse the soaked wheat, put it in a medium pan with lots of water, bring to a boil and simmer for an hour, until cooked. Drain and set aside.", "Season the lamb with a teaspoon of salt and some black pepper. Put one tablespoon of oil in a large, deep sauté pan for which you have a lid; place on a medium-high heat. Add some of the lamb – don''t overcrowd the pan – and sear for four minutes on all sides. Transfer to a bowl, and repeat with the remaining lamb, adding oil as needed.", "Lower the heat to medium and add a tablespoon of oil to the pan. Add the shallots and fry for four minutes, until caramelised. Tip these into the lamb bowl, and repeat with the remaining vegetables until they are all nice and brown, adding more oil as you need it.", "Once all the vegetables are seared and removed from the pan, add the wine along with the sugar, herbs, a teaspoon of salt and a good grind of black pepper. Boil on a high heat for about three minutes.", "Tip the lamb, vegetables and whole wheat back into the pot, and add the stock. Cover and boil for five minutes, then transfer to the oven for an hour and a half.", "Remove the stew from the oven and check the liquid; if there is a lot, remove the lid and boil for a few minutes."]'::jsonb, 'http://www.ottolenghi.co.uk/recipes/meat/irish-stew-shop', 'https://www.themealdb.com/images/media/meals/sxxpst1468569714.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamaican-beef-patties', 'Jamaican Beef Patties', 4, 0, 0, '{"calories": 987, "protein": 61.3, "carbs": 135.6, "fat": 71.5, "saturated_fat": 44.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 537.3, "potassium": 390.6, "fiber": 6.2, "sugar": 34.5, "vitamin_a": null, "vitamin_c": 42.6, "calcium": 71.1, "iron": 11.0}'::jsonb, ARRAY['beef', 'jamaican', 'themealdb', 'nutrition-generated', 'baking'], '[{"quantity": 4.0, "unit": "cups", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Curry Powder", "notes": null, "category": "spices"}, {"quantity": 250.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 900.0, "unit": "g", "item": "Minced Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tsp", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Ground Red Pepper", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "ground Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Tomato Ketchup", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "cup", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbs", "item": "Water", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "cup", "item": "Water", "notes": null, "category": "other"}]'::jsonb, '["Make the Pastry Dough", "To a large bowl, add flour, 1 teaspoon salt, and turmeric and mix thoroughly.", "Rub shortening into flour until there are small pieces of shortening completely covered with flour.", "Pour in 1/2 cup of the ice water and mix with your hands to bring the dough together. Keep adding ice water 2 to 3 tablespoons at a time until the mixture forms a dough.", "At this stage, you can cut the dough into 2 large pieces, wrap in plastic and refrigerate for 30 minutes before using it.", "Alternatively, cut the dough into 10 to 12 equal pieces, place on a platter or baking sheet, cover securely with plastic wrap and let chill for 30 minutes while you make the filling.", "Make the Filling", "Add ground beef to a large bowl. Sprinkle in allspice and black pepper. Mix together and set aside.", "Heat oil in a skillet until hot.", "Add onions and sauté until translucent. Add hot pepper, garlic and thyme and continue to sauté for another minute. Add 1/4 teaspoon salt.", "Add seasoned ground beef and toss to mix, breaking up any clumps, and let cook until the meat is no longer pink.", "Add ketchup and more salt to taste.", "Pour in 2 cups of water and stir. Bring the mixture to a boil then reduce heat and let simmer until most of the liquid has evaporated and whatever is remaining has reduced to a thick sauce.", "Fold in green onions. Remove from heat and let cool completely.", "Assemble the Patties", "Beat the egg and water together to make an egg wash. Set aside.", "Now you can prepare the dough in two ways.", "First Method: Flour the work surface and rolling pin. If you had cut it into 2 large pieces, then take one of the large pieces and roll it out into a very large circle. Take a bowl with a wide rim (about 5 inches) and cut out three circles.", "Place about 3 heaping tablespoons of the filling onto 1/2 of each circle. Dip a finger into the water and moisten the edges of the pastry. Fold over the other half and press to seal.", "Take a fork and crimp the edges. Cut off any extra to make it look neat and uniform. Place on a parchment-lined baking sheet and continue to work until you have rolled all the dough and filled the patties.", "Second Method: If you had pre-cut the dough into individual pieces, work with one piece of dough at a time. Roll it out on a floured surface into a 5-inch circle or a little larger. Don’t worry if the edges are not perfect.", "Place 3 heaping tablespoons of the filling on one side of the circle. Dip a finger into the water and moisten the edges of the pastry. Fold over the other half and press to seal.", "Take a fork and crimp the edges. Cut off any extra to make it look neat and uniform. Place on a parchment-lined baking sheet and continue work until you have rolled all the dough and filled the patties.", "Frying and Serving the Patties", "After forming the patties, place the pans in the refrigerator while you heat the oven to 350 F.", "Just before adding the pans with the patties to the oven, brush the patties with egg wash.", "Bake patties for 30 minutes or until golden brown.", "Cool on wire racks.", "Serve warm."]'::jsonb, 'https://www.thespruce.com/jamaican-beef-patties-recipe-2137762', 'https://www.themealdb.com/images/media/meals/wsqqsw1515364068.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jiggs-dinner', 'Jiggs Dinner', 4, 0, 0, '{"calories": 172, "protein": 14.2, "carbs": 86.9, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 48.5, "potassium": 250.5, "fiber": 27.7, "sugar": 4.4, "vitamin_a": null, "vitamin_c": 13.2, "calcium": 44.2, "iron": 2.7}'::jsonb, ARRAY['beef', 'canadian', 'themealdb', 'nutrition-generated'], '[{"quantity": 2.0, "unit": "lbs", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "cup", "item": "Yellow Split Peas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "head", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Turnips", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Black Pepper", "notes": null, "category": "produce"}]'::jsonb, '["The night before, break salt beef into big chunks and soak in water overnight, at least 8-10 hours. Put split peas into a bowl and cover with water to soak overnight.", "Drain the salt beef and place it into a large stockpot. Cover with fresh water, at least 6-7 litres. Place the split peas into a pease pudding canvas bag or triple layer of cheesecloth and tie, making sure to leave room for peas to expand inside the bag.", "Put the bag inside the pot, tying the strings to the outside handle so it doesn''t stick to the bottom of the pot with the salt beef. Bring to a boil, then lower the heat and simmer for 2 hours.", "Remove the peas pudding bag and empty contents into a bowl, mixing with butter and pepper for taste. Set aside.", "Add your cabbage to the pot and boil for 20 more minutes. Then add turnip, carrots and potatoes then boil for 20 more, or until vegetables are tender.", "Remove salt beef and vegetables from the pot and put them on a platter.", "Use the cooking liquid in two ways; as a pot liquor which some people like to drink or reduce it to make a jus or gravy to pour over the meal."]'::jsonb, 'https://canadianfoodfocus.org/recipes/classic-canadian-dishes-jiggs-dinner/', 'https://www.themealdb.com/images/media/meals/z1tfnw1764443171.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('karbonader-lean-beef-patties-with-caramelized-onions', 'Karbonader (Lean Beef Patties) with Caramelized Onions', 4, 0, 0, '{"calories": 635, "protein": 22.0, "carbs": 16.2, "fat": 53.0, "saturated_fat": 26.4, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 184.5, "potassium": null, "fiber": 0.6, "sugar": 3.1, "vitamin_a": null, "vitamin_c": null, "calcium": 24.4, "iron": 2.7}'::jsonb, ARRAY['beef', 'norwegian', 'themealdb', 'nutrition-generated'], '[{"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "lb", "item": "Ground Beef", "notes": null, "category": "meat"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tbs", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 50.0, "unit": "ml", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Butter", "notes": null, "category": "dairy"}]'::jsonb, '["Grate half an onion and set aside. Slice the rest of the onions and fry in butter on low/medium heat until caramelized.", "▢", "In a bowl, mix together ground beef, grated onion, salt, pepper, nutmeg, potato/corn starch, and water.", "▢", "Form into a sausage and cut 6 patties. Using a knife make a light grid pattern in each patty.", "▢", "Brown both sides of the karbonader in butter on high heat, then turn down to low heat and fry for another 2 – 3 minutes.", "▢", "Serve the karbonader and onions with potatoes, stewed peas, and brown sauce for dinner, or on a slice of bread for lunch or a snack."]'::jsonb, 'https://scandinaviancookbook.com/karbonader/', 'https://www.themealdb.com/images/media/meals/0bpjb11763075817.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('kenyan-beef-curry', 'Kenyan Beef Curry', 4, 0, 0, '{"calories": 470, "protein": 2.0, "carbs": 40.6, "fat": 32.3, "saturated_fat": 3.4, "polyunsaturated_fat": null, "monounsaturated_fat": 7.1, "sodium": 290.0, "potassium": 49.2, "fiber": 3.2, "sugar": 25.7, "vitamin_a": null, "vitamin_c": 2.0, "calcium": 4.2, "iron": 0.7}'::jsonb, ARRAY['beef', 'kenyan', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 4.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "lbs", "item": "Sirloin Steak tips", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "teaspoons", "item": "Ground Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "Curry Powder", "notes": null, "category": "spices"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves Cilantro", "notes": null, "category": "produce"}]'::jsonb, '["Bring the 4 cups of water to a boil in a Dutch oven or soup pot. Add the beef, garlic, and ginger, and stir well. Bring to a gentle simmer, cover, and cook, stirring occasionally, for 20 minutes. If you get any foamy scum on the top, not to worry, simply spoon it away or stir it back in.", "Remove from the heat, and drain, but reserve the excess water for later.", "Return the pot or Dutch oven to medium heat with the 2 tablespoons of cooking oil. Once the oil is shimmering, add the onions and cook, stirring occasionally, until softened, 5 to 7 minutes.", "Add the tomatoes to the onions, and continue cooking, stirring occasionally, until the tomatoes are falling apart, 3 to 5 minutes.", "Add the drained beef to the tomato and onion mixture, and stir well. Continue cooking over medium heat for 5 minutes, stirring occasionally.", "Add the paprika, pepper, curry powder, tomato paste, and salt to taste, and stir well.", "Add back the excess water that was used for cooking the beef, along with enough extra water to cover. Bring to a boil, reduce heat, and simmer, uncovered, stirring occasionally, for about 1 hour, or until the meat is tender and the sauce is thickened. Add additional water if your beef curry begins to dry and stick, or if would like your curry to have more of a soupy consistency.", "When the beef curry is ready, remove from the heat, give it a taste, and adjust the seasonings as desired. Garnish with fresh chilis and cilantro."]'::jsonb, 'https://tasteoftheplace.com/kenyan-beef-curry/', 'https://www.themealdb.com/images/media/meals/lqampv1762325397.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lemongrass-beef-stew-with-noodles', 'Lemongrass beef stew with noodles', 4, 0, 0, '{"calories": 601, "protein": 21.8, "carbs": 51.1, "fat": 34.8, "saturated_fat": 6.6, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2190.0, "potassium": 51.2, "fiber": 2.2, "sugar": 4.5, "vitamin_a": null, "vitamin_c": null, "calcium": 46.2, "iron": 4.7}'::jsonb, ARRAY['beef', 'thai', 'themealdb', 'nutrition-generated', 'dessert', 'soup', 'pasta'], '[{"quantity": 1.0, "unit": "tablespoon", "item": "chopped Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Stalks", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Coriander Leaves", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Five Spice Powder", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "ml", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 100.0, "unit": "g", "item": "Rice Noodles", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Lime", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Put the ginger, garlic, lemongrass, coriander and 1 chilli in a food processor, then pulse until puréed. Heat the oil in a pan over a low heat. Add the purée and cook for 5 mins. Stir in the beef, soy, five-spice, sugar and stock. Put on a lid and bring to the boil, then lower heat and simmer for 1 hr 15 mins. Remove the lid and cook for a further 15 mins until the beef is tender.", "step 2", "Just before serving, prepare noodles following pack instructions. Drain well, then divide between 2 bowls and spoon over the beef stew. Serve sprinkled with the remaining chilli and coriander leaves, with lime wedges for squeezing over."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/lemongrass-beef-stew-noodles', 'https://www.themealdb.com/images/media/meals/ntafxw1763586291.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ma-po-tofu', 'Ma Po Tofu', 4, 0, 0, '{"calories": 89, "protein": 5.5, "carbs": 14.0, "fat": 1.6, "saturated_fat": 1.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 86.6, "potassium": 107.2, "fiber": 1.1, "sugar": 10.9, "vitamin_a": null, "vitamin_c": 3.2, "calcium": 29.1, "iron": 1.4}'::jsonb, ARRAY['beef', 'chinese', 'themealdb', 'nutrition-generated'], '[{"quantity": 450.0, "unit": "g", "item": "Tofu", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Minced Beef", "notes": null, "category": "meat"}, {"quantity": 0.5, "unit": "tbs", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 1.5, "unit": "tsp", "item": "Doubanjiang", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tsp", "item": "Fermented Black Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Sichuan pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "ml", "item": "Water", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Scallions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 2.5, "unit": "tbs", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbs", "item": "Cornstarch", "notes": null, "category": "produce"}]'::jsonb, '["Add a small pinch of salt and sesame oil to minced beef. Mix well and set aside.", "Mix 1 tablespoon of cornstarch with 2 and ½ tablespoons of water in a small bowl to make water starch.", "Cut tofu into square cubes (around 2cms). Bring a large amount of water to a boil and then add a pinch of salt. Slide the tofu in and cook for 1 minute. Move out and drain.", "Get a wok and heat up around 2 tablespoons of oil, fry the minced meat until crispy. Transfer out beef out and leave the oil in.", "Fry doubanjiang for 1 minute over slow fire and then add garlic, scallion white, ginger and fermented black beans to cook for 30 seconds until aroma. Then mix pepper flakes in.", "Add water to the seasonings and bring to boil over high fire. Gently slide the tofu cubes. Add light soy sauce and beef.Slow the heat after boiling and then simmer for 6-8 minutes. Then add chopped garlic greens.", "Stir the water starch and then pour half of the mixture to the simmering pot. Wait for around 30 seconds and then pour the other half. You can slightly taste the tofu and add pinch of salt if not salty enough. By the way, if you feel it is too spicy, add some sugar can milder the taste. But be carefully as the broth is very hot at this point.", "Transfer out when almost all the seasonings stick to tofu cubes. Sprinkle Szechuan peppercorn powder (to taste)and chopped garlic greens if using.", "Serve immediately with steamed rice."]'::jsonb, 'https://www.chinasichuanfood.com/mapo-tofu-recipe/', 'https://www.themealdb.com/images/media/meals/1525874812.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('massaman-beef-curry', 'Massaman Beef curry', 4, 0, 0, '{"calories": 369, "protein": 53.6, "carbs": 160.1, "fat": 57.9, "saturated_fat": 12.9, "polyunsaturated_fat": null, "monounsaturated_fat": 4.2, "sodium": 1044.1, "potassium": 2587.2, "fiber": 12.5, "sugar": 4.9, "vitamin_a": 189.5, "vitamin_c": 12.4, "calcium": 93.6, "iron": 18.7}'::jsonb, ARRAY['beef', 'thai', 'themealdb', 'nutrition-generated', 'dessert', 'baking'], '[{"quantity": 85.0, "unit": "g", "item": "Peanuts", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "ml", "item": "can Coconut cream", "notes": null, "category": "dairy"}, {"quantity": 4.0, "unit": "tbsp", "item": "Massaman curry paste", "notes": null, "category": "spices"}, {"quantity": 600.0, "unit": "g", "item": "stewing cut into strips Beef", "notes": null, "category": "meat"}, {"quantity": 450.0, "unit": "g", "item": "waxy Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "thin wedges Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "stick", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbsp", "item": "Tamarind paste", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbsp", "item": "palm or soft light Brown sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbsp", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "deseeded and finely", "notes": "sliced, to serve chilli", "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Jasmine Rice", "notes": null, "category": "grains"}]'::jsonb, '["Heat oven to 200C/180C fan/gas 6, then roast the peanuts on a baking tray for 5 mins until golden brown. When cool enough to handle, roughly chop. Reduce oven to 180C/160C fan/gas 4.", "Heat 2 tbsp coconut cream in a large casserole dish with a lid. Add the curry paste and fry for 1 min, then stir in the beef and fry until well coated and sealed. Stir in the rest of the coconut with half a can of water, the potatoes, onion, lime leaves, cinnamon, tamarind, sugar, fish sauce and most of the peanuts. Bring to a simmer, then cover and cook for 2 hrs in the oven until the beef is tender.", "Sprinkle with sliced chilli and the remaining peanuts, then serve straight from the dish with jasmine rice."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/420631/beef-massaman-curry', 'https://www.themealdb.com/images/media/meals/tvttqv1504640475.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('matambre-a-la-pizza', 'Matambre a la Pizza', 4, 0, 0, '{"calories": 323, "protein": 61.9, "carbs": 354.2, "fat": 42.7, "saturated_fat": 17.7, "polyunsaturated_fat": 1.0, "monounsaturated_fat": 9.0, "sodium": 11762.8, "potassium": 962.5, "fiber": 10.8, "sugar": 1.6, "vitamin_a": null, "vitamin_c": 5.2, "calcium": 479.1, "iron": 13.6}'::jsonb, ARRAY['beef', 'argentinian', 'themealdb', 'nutrition-generated', 'grilling'], '[{"quantity": 1.0, "unit": "kg", "item": "Beef Flank Steak", "notes": null, "category": "meat"}, {"quantity": 200.0, "unit": "g", "item": "Tomato Sauce", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Mozzarella", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbsp", "item": "Oregano", "notes": null, "category": "spices"}, {"quantity": 100.0, "unit": "g", "item": "Green Olives", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Prepare the Steak: Season the steak with salt and pepper. Grill one side until half-cooked.", "Add Toppings: Spread tomato sauce over the cooked side, then add cheese, oregano, and olives.", "Finish Grilling: Grill until the cheese is melted and bubbly.", "Serve: Slice and serve hot.", "Pro Tips:", "Tenderize the matambre by scoring it lightly on both sides. This helps it cook more evenly and absorb the flavors.", "Precook the matambre on the grill before adding the toppings to ensure it''s fully cooked without burning the cheese."]'::jsonb, 'https://www.munchery.com/blog/the-ten-iconic-dishes-of-argentina-and-how-to-cook-them-at-home/', 'https://www.themealdb.com/images/media/meals/wf49qs1763075222.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('milanesa', 'Milanesa', 4, 0, 0, '{"calories": 242, "protein": 5.6, "carbs": 367.3, "fat": 7.6, "saturated_fat": 4.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 9928.8, "potassium": null, "fiber": 10.3, "sugar": 13.6, "vitamin_a": null, "vitamin_c": 6.5, "calcium": 226.8, "iron": 7.4}'::jsonb, ARRAY['beef', 'argentinian', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Cutlet", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "Breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tbs", "item": "chopped Parsley", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Season the Cutlets: Salt and pepper the cutlets.", "Bread the Cutlets: Dip each cutlet in egg, then coat with a mixture of breadcrumbs, parsley, and garlic.", "Fry: Heat oil in a large pan over medium heat. Fry the cutlets until golden and cooked through, about 3-4 minutes per side.", "Serve: Serve hot with lemon wedges or a side salad.", "Pro Tips:", "For an extra crispy crust, use panko breadcrumbs mixed with finely grated Parmesan cheese.", "Gently pound the cutlets to an even thickness for uniform cooking."]'::jsonb, 'https://www.munchery.com/blog/the-ten-iconic-dishes-of-argentina-and-how-to-cook-them-at-home/', 'https://www.themealdb.com/images/media/meals/wdfa171763065079.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('minced-beef-pie', 'Minced Beef Pie', 4, 0, 0, '{"calories": 615, "protein": 32.8, "carbs": 75.5, "fat": 20.8, "saturated_fat": 9.9, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 987.8, "potassium": 95.5, "fiber": 3.1, "sugar": 36.5, "vitamin_a": null, "vitamin_c": 0.9, "calcium": 7.2, "iron": 6.7}'::jsonb, ARRAY['beef', 'british', 'themealdb', 'nutrition-generated', 'dessert', 'soup', 'baking'], '[{"quantity": 2.0, "unit": "tbs", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 500.0, "unit": "g", "item": "Minced Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tbsp", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 75.0, "unit": "g", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 250.0, "unit": "ml", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Worcestershire Sauce", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Shortcrust Pastry", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}]'::jsonb, '["Preheat the oven to 200C/400F/Gas 6.", "Heat the oil in a deep frying pan and fry the beef mince for 4-5 minutes, breaking it up with a wooden spoon as it browns.", "Add the onion and cook for 2-3 minutes, then stir in the tomato purée and cook for 2-3 more minutes. Stir in the flour and cook for a further minute, then add the chopped mushrooms, the stout or beef stock and a couple of dashes of Worcestershire sauce. Bring to the boil, then reduce the heat, cover the pan with a lid and leave to simmer for 20 minutes. Set aside and leave to cool, then turn the meat mixture into a one litre pie dish.", "Roll out the pastry on a floured work surface until it is slightly larger than the pie dish. Gently drape the pastry over the dish, pressing firmly onto the edges. Trim, then shape the edges into a fluted shape.", "Cut some leaf shapes out of the pastry trimmings and decorate the top of the pie, sticking them to the pastry with the beaten egg yolk.", "Make three or four slits in the pastry to allow the steam to escape, then brush the pie with the rest of the beaten egg yolk and bake in the oven for 20-25 minutes, or until golden-brown.", "To serve, slice into wedges."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/mincedbeefpie_89198', 'https://www.themealdb.com/images/media/meals/xwutvy1511555540.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mini-chilli-beef-pies', 'Mini chilli beef pies', 4, 0, 0, '{"calories": 792, "protein": 28.7, "carbs": 96.1, "fat": 33.2, "saturated_fat": 10.1, "polyunsaturated_fat": null, "monounsaturated_fat": 1.8, "sodium": 656.6, "potassium": 287.5, "fiber": 7.3, "sugar": 36.9, "vitamin_a": null, "vitamin_c": 5.4, "calcium": 49.1, "iron": 7.9}'::jsonb, ARRAY['beef', 'australian', 'themealdb', 'nutrition-generated', 'dessert', 'soup', 'baking'], '[{"quantity": 450.0, "unit": "g", "item": "Ready rolled shortcrust pastry", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Hot Chilli Powder", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 250.0, "unit": "g", "item": "Minced Beef", "notes": null, "category": "meat"}, {"quantity": 85.0, "unit": "g", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "ml", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch", "notes": "Ground Cinnamon", "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "Kidney Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Sour Cream", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Chopped Chive", "notes": null, "category": "other"}]'::jsonb, '["step 1", "To make chilli, heat oil in a pan and fry onion for 5 mins until soft. Add spices; fry for 1 min. Stir in beef and cook for a few mins. Add tomato purée, stock and cinnamon. Give it a stir, bring to the boil, then simmer for 15-20 mins until very little liquid is left. Add beans 5 mins before the end of cooking. Check seasoning and cool.", "step 2", "Heat oven to 200C/fan 180C/gas 6. Using a 7cm pastry cutter, stamp out 12 circles from the pastry. Use to line a 12-hole mini muffin tray, prick the base of the pastry with a fork, and bake for 10 mins. Remove from oven and cool on a wire tray. Repeat with remaining pastry.", "step 3", "Meanwhile, cook the potato in boiling water until tender. Drain, mash with soured cream and seasoning, then stir through chives. Spoon 1-2 tsp of chilli mix into the pastry cases and top with a tsp of mash. Ruffle mash with a fork; return to the oven for 15 mins or until golden."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/mini-chilli-beef-pies', 'https://www.themealdb.com/images/media/meals/6sarfo1762340107.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('montreal-smoked-meat', 'Montreal Smoked Meat', 4, 0, 0, '{"calories": 125, "protein": 0.0, "carbs": 25.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['beef', 'canadian', 'themealdb', 'nutrition-generated', 'dessert', 'grilling', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Brisket", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tbs", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tbs", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tbs", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Bay Leaf", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Cloves", "notes": null, "category": "spices"}, {"quantity": 3.0, "unit": "tbs", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tbs", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tbs", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Dill", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "English Mustard", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Celery Salt", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Red Pepper Flakes", "notes": null, "category": "produce"}]'::jsonb, '["To make the cure, in a small bowl mix together salt, pink salt, black pepper, coriander, sugar, bay leaf, and cloves. Coat entire brisket with the cure and place in an extra-large resealable plastic bag. Place in the coldest part of the refrigerator and cure for 4 days, flipping brisket twice a day.", "Remove brisket from bag and wash as much cure off as possible under cold running water. Place brisket in a large container and fill with water and let soak for 2 hours, replacing water every 30 minutes. Remove from water and pat dry with paper towels.", "To make the rub, mix together black pepper, coriander, paprika, garlic powder, onion powder, dill weed, mustard, celery seed, and crushed red papper in a small bowl. Coat entire brisket with the rub.", "Fire up smoker or grill to 225 degrees, adding chunks of smoking wood chunks when at temperature. When wood is ignited and producing smoke, place brisket in, fat side up, and smoke until an instant read thermometer registers 165 degrees when inserted into thickest part of the brisket, about 6 hours.", "Transfer brisket to large roasting pan with V-rack. Place roasting pan over two burners on stovetop and fill with 1-inch of water. Bring water to a boil over high heat, reduce heat to medium, cover roasting pan with aluminum foil, and steam brisket until an instant read thermometer registers 180 degrees when inserted into thickest part of the meat, 1 to 2 hours, adding more hot water as needed.", "Transfer brisket to cutting board and let cool slightly. Slice and serve, preferably on rye with mustard."]'::jsonb, 'http://www.meatwave.com/blog/montreal-smoked-meat-recipe', 'https://www.themealdb.com/images/media/meals/uttupv1511815050.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('moussaka', 'Moussaka', 4, 0, 0, '{"calories": 563, "protein": 29.6, "carbs": 57.7, "fat": 25.0, "saturated_fat": 15.4, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 529.6, "potassium": 424.9, "fiber": 3.3, "sugar": 42.1, "vitamin_a": null, "vitamin_c": 15.9, "calcium": 94.1, "iron": 5.9}'::jsonb, ARRAY['beef', 'greek', 'themealdb', 'nutrition-generated', 'baking', 'grilling'], '[{"quantity": 500.0, "unit": "g", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Aubergine", "notes": null, "category": "other"}, {"quantity": 150.0, "unit": "g", "item": "Greek Yogurt", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tbs", "item": "Parmesan", "notes": null, "category": "dairy"}, {"quantity": 400.0, "unit": "g", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tbs", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 350.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}]'::jsonb, '["Heat the grill to high. Brown the beef in a deep ovenproof frying pan over a high heat for 5 mins. Meanwhile, prick the aubergine with a fork, then microwave on High for 3-5 mins until soft. Mix the yogurt, egg and parmesan together, then add a little seasoning.", "Stir the tomatoes, purée and potatoes in with the beef with some seasoning and heat through. Smooth the surface of the beef mixture with the back of a spoon, then slice the cooked aubergine and arrange on top. Pour the yogurt mixture over the aubergines, smooth out evenly, then grill until the topping has set and turned golden."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/must-make-moussaka', 'https://www.themealdb.com/images/media/meals/ctg8jd1585563097.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mulukhiyah', 'Mulukhiyah', 4, 0, 0, '{"calories": 416, "protein": 17.7, "carbs": 17.6, "fat": 30.0, "saturated_fat": 6.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 268.5, "potassium": null, "fiber": 0.6, "sugar": 4.5, "vitamin_a": null, "vitamin_c": null, "calcium": 4.0, "iron": 4.1}'::jsonb, ARRAY['beef', 'egyptian', 'themealdb', 'nutrition-generated', 'instant-pot'], '[{"quantity": 800.0, "unit": "g", "item": "Mulukhiyah", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "cup", "item": "Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Saute the onions in the 3-4 tablespoons olive oil", "Add the beef cubes or the chicken cutlets, sear for 3-4 min on each side", "Add 1 liter of water or just enough to cover the meat", "Cook over medium heat until the meat is done (I usually do this in the pressure cooker and press them for 5 min)", "Add the frozen mulukhyia and stir until it thaws completely and then comes to a boil", "In another pan add the 1/4 to 1/2 cup of olive oil and the cloves of garlic and cook over medium low heat until you can smell the garlic (don’t brown it, it will become bitter)", "Add the oil and garlic to the mulukhyia and lower the heat and simmer for 5-10 minutes", "Add salt to taste", "Serve with a generous amount of lemon juice.", "You can serve it with some short grain rice or some pita bread"]'::jsonb, 'https://chefindisguise.com/2017/05/15/mulukhiyah-a-stew-fit-for-royals/', 'https://www.themealdb.com/images/media/meals/x372ug1598733932.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('oxtail-with-broad-beans', 'Oxtail with broad beans', 4, 0, 0, '{"calories": 175, "protein": 7.0, "carbs": 60.7, "fat": 0.5, "saturated_fat": 0.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1347.8, "potassium": 455.5, "fiber": 3.5, "sugar": 47.9, "vitamin_a": null, "vitamin_c": 4.2, "calcium": 34.3, "iron": 4.3}'::jsonb, ARRAY['beef', 'jamaican', 'themealdb', 'nutrition-generated', 'instant-pot', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 450.0, "unit": "g", "item": "Oxtail", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Scotch Bonnet", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Fresh Thyme", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 350.0, "unit": "ml", "item": "Water", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "Broad Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Corn Flour", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Water", "notes": null, "category": "other"}]'::jsonb, '["Toss the oxtail with the onion, spring onion, garlic, ginger, chilli, soy sauce, thyme, salt and pepper. Heat the vegetable oil in a large frying pan over medium-high heat. Brown the oxtail in the pan until browned all over, about 10 minutes. Place into a pressure cooker, and pour in 375ml water. Cook at pressure for 25 minutes, then remove from heat, and remove the lid according to manufacturer''s directions.", "Add the broad beans and pimento berries, and bring to a simmer over medium-high heat. Dissolve the cornflour in 2 tablespoons water, and stir into the simmering oxtail. Cook and stir a few minutes until the sauce has thickened, and the broad beans are tender."]'::jsonb, 'http://allrecipes.co.uk/recipe/5392/jamaican-oxtail-with-broad-beans.aspx', 'https://www.themealdb.com/images/media/meals/1520083578.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('paszteciki-polish-pasties', 'Paszteciki (Polish Pasties)', 4, 0, 0, '{"calories": 855, "protein": 23.6, "carbs": 91.8, "fat": 38.9, "saturated_fat": 22.4, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2863.6, "potassium": null, "fiber": 2.1, "sugar": 28.6, "vitamin_a": null, "vitamin_c": null, "calcium": 92.0, "iron": 3.4}'::jsonb, ARRAY['beef', 'polish', 'themealdb', 'nutrition-generated', 'baking'], '[{"quantity": 1.0, "unit": "cup", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 0.25, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 5.0, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Swede", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "lb", "item": "Beef Brisket", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Sift flour and salt into a large mixing bowl.", "Use a spoon to push the egg yolk through a fine sieve into the flour.", "Add the raw egg and mix well.", "Beat in butter 1 tablespoon at a time.", "Place dough on a floured surface and knead until smooth and elastic, then wrap in waxed paper and refrigerate until firm (at least 30 minutes).", "In a heavy skillet, melt 2 tablespoons butter over medium heat; saute the onion and rutabaga until the onion is soft and transparent (5 minutes).", "Put the onions, rutabaga, and beef through a meat grinder twice if you have one, if not just chop them up as fine as possible.", "Melt the remaining 4 tablespoons butter over medium heat, and add the meat mixture.", "Cook over low heat, stirring occasionally, until all of the liquid has evaporated and the mixture is thick enough to hold its shape.", "Remove from heat and let cool, then stir in 1 egg, and season with salt and pepper.", "Preheat oven to 350°F.", "On a lightly floured surface, roll the dough out into a 13x8\" rectangle (1/8\" thick).", "Spoon the filling down the center of the rectangle lengthwise, leaving about an inch of space on each end.", "Lightly brush the long sides with cold water, then fold one of the long sides over the filling and the other side over the top of that.", "Brush the short ends with cold water and fold them over the top, enclosing the filling.", "Place pastry seam side down on a baking sheet and brush the top evenly with the remaining scrambled egg.", "Bake in preheated oven until rich golden brown (30 minutes).", "Slice pastry diagonally into 1.5\" long pieces and serve as an appetizer or with soup."]'::jsonb, 'https://www.food.com/recipe/paszteciki-polish-pasties-117909', 'https://www.themealdb.com/images/media/meals/c9a3l31593261890.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pate-chinois', 'Pate Chinois', 4, 0, 0, '{"calories": 762, "protein": 35.5, "carbs": 89.2, "fat": 30.4, "saturated_fat": 13.1, "polyunsaturated_fat": null, "monounsaturated_fat": 8.5, "sodium": 559.3, "potassium": 991.3, "fiber": 7.5, "sugar": 5.8, "vitamin_a": null, "vitamin_c": 43.4, "calcium": 75.9, "iron": 9.3}'::jsonb, ARRAY['beef', 'canadian', 'themealdb', 'nutrition-generated', 'baking'], '[{"quantity": 4.0, "unit": "cups", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 60.0, "unit": "ml", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 450.0, "unit": "g", "item": "Minced Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "chopped  Onion", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "ml", "item": "Creamed Corn", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "to taste Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "to taste Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Pepper", "notes": null, "category": "produce"}]'::jsonb, '["In a large pot of salted water, cook the potatoes until they are very tender. Drain.", "With a masher, coarsely crush the potatoes with at least 30 ml (2 tablespoons) of butter. With an electric mixer, purée with the milk. Season with salt and pepper. Set aside.", "With the rack in the middle position, preheat the oven to 190 °C (375 °F).", "In a large skillet, brown the onion in the remaining butter. Add the meat and cook until golden brown. Season with salt and pepper. Remove from the heat.", "Lightly press the meat at the bottom of a 20-cm (8-inch) square baking dish. Cover with the corn and the mashed potatoes. Sprinkle with paprika and parsley.", "Bake for about 30 minutes. Finish cooking under the broiler. Let cool for 10 minutes."]'::jsonb, 'https://www.ricardocuisine.com/en/recipes/5541-pate-chinois-shepherd--s-pie-', 'https://www.themealdb.com/images/media/meals/yyrrxr1511816289.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('portuguese-prego-with-green-piri-piri', 'Portuguese prego with green piri-piri', 4, 0, 0, '{"calories": 284, "protein": 4.7, "carbs": 49.8, "fat": 4.6, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": 0.6, "sodium": 394.0, "potassium": 118.5, "fiber": 38.6, "sugar": 6.8, "vitamin_a": null, "vitamin_c": 6.3, "calcium": 773.8, "iron": 31.2}'::jsonb, ARRAY['beef', 'portuguese', 'themealdb', 'nutrition-generated', 'dessert'], '[{"quantity": 1.0, "unit": "clove", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Beef Fillet", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Ciabatta", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Rocket", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Small bunch Basil Leaves", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Small bunch Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Jalapeno", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbs", "item": "Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Garlic", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Caster Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["STEP 1", "Rub the garlic over the steaks then put in a sandwich bag and tip in the olive oil, sherry vinegar and parsley stalks. Smoosh everything together, then use a rolling pin to bash the steaks a few times. Leave for 1-2 hours.", "STEP 2", "To make the sauce, put all the ingredients into a blender with 1 tbsp water and whizz until as smooth as possible. This will make more than you’ll need for the recipe but will keep for a week in an airtight jar.", "STEP 3", "Heat a griddle or frying pan to high. Brush away the garlic and parsley stalks from the steaks and season well. Sear the steaks for 2 minutes on each side then rest on a plate. Put the ciabatta halves onto the plate, toasted-side down, to soak up any juices.", "STEP 4", "Slice the steaks then stuff into the rolls with the green sauce and rocket."]'::jsonb, 'https://www.olivemagazine.com/recipes/meat-and-poultry/portuguese-prego-with-green-piri-piri/', 'https://www.themealdb.com/images/media/meals/ewcikl1614348364.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('red-peas-soup', 'Red Peas Soup', 4, 0, 0, '{"calories": 628, "protein": 18.0, "carbs": 123.8, "fat": 16.8, "saturated_fat": 5.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 463.3, "potassium": 274.9, "fiber": 10.7, "sugar": 61.9, "vitamin_a": 8.0, "vitamin_c": 10.1, "calcium": 105.3, "iron": 4.4}'::jsonb, ARRAY['beef', 'jamaican', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 2.0, "unit": "cups", "item": "Kidney Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "lbs", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "l", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 0.25, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "cup", "item": "Coconut Milk", "notes": null, "category": "dairy"}]'::jsonb, '["Wash and rinse the dried kidney beans.. then cover with water in a deep bowl. Remember as they soak they will expand to at least triple the size they were originally so add a lot of water to the bowl. Soak them overnight or for at least 2 hrs to make the cooking step go quicker. I tossed out the water they were soaked in after it did the job.", "Have your butcher cut the salted pigtail into 2 inch pieces as it will be very difficult to cut with an ordinary kitchen knife. Wash, then place a deep pot with water and bring to a boil. Cook for 20 minutes, then drain + rinse and repeat (boil again in water). The goal is to make the pieces of pig tails tender and to remove most of the salt it was cured in.", "Time to start the soup. Place everything in the pot (except the flour and potato), then cover with water and place on a high flame to bring to a boil. As it comes to a boil, skim off any scum/froth at the top and discard. Reduce the heat to a gentle boil and allow it to cook for 1 hr and 15 mins.. basically until the beans are tender and start falling apart.", "It’s now time to add the potato (and Yams etc if you’re adding it) as well as the coconut milk and continue cooking for 15 minutes.", "Now is a good time to start making the basic dough for the spinner dumplings. Mix the flour and water (add a pinch of salt if you want) until you have a soft/smooth dough. allow it to rest for 5 minutes, then pinch of a tablespoon at a time and roll between your hands to form a cigarette shape.", "Add them to the pot, stir well and continue cooking for another 15 minutes on a rolling boil.", "You’ll notice that I didn’t add any salt to the pot as the remaining salt from the salted pigtails will be enough to properly season this dish. However you can taste and adjust accordingly. Lets recap the timing part of things so you’re not confused. Cook the base of the soup for 1 hr and 15 minute or until tender, then add the potatoes and cook for 15 minutes, then add the dumplings and cook for a further 15 minutes. Keep in mind that this soup will thicken quite a bit as it cools.", "While this is not a traditional recipe to any one specific island, versions of this soup (sometimes called stewed peas) can be found throughout the Caribbean, Latin America and Africa. A hearty bowl of this soup will surely give you the sleepies (some may call it ethnic fatigue). You can certainly freeze the leftovers and heat it up another day."]'::jsonb, 'http://caribbeanpot.com/caribbean-red-peas-soup/', 'https://www.themealdb.com/images/media/meals/sqpqtp1515365614.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('roti-john', 'Roti john', 4, 0, 0, '{"calories": 226, "protein": 17.3, "carbs": 364.9, "fat": 5.6, "saturated_fat": 2.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 10045.6, "potassium": 87.3, "fiber": 8.9, "sugar": 1.8, "vitamin_a": null, "vitamin_c": 5.2, "calcium": 125.4, "iron": 10.3}'::jsonb, ARRAY['beef', 'malaysian', 'themealdb', 'nutrition-generated', 'grilling'], '[{"quantity": 0.25, "unit": "lb", "item": "Minced Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbs", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Baguette", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Top Mayonnaise", "notes": null, "category": "pantry"}]'::jsonb, '["Mix all the ingredients in a bowl.", "Heat a pan or griddle with a little vegetable oil.", "Pour the mixture onto the pan and place a piece of open-faced baguette on top.", "Press on the bread with a spatula and grill for 2 minutes.", "Turn the bread over to make it a little crispy.", "Remove from pan and cut the bread into small portions.", "Add mayonnaise and/or Sambal before cutting the sandwich (optional)."]'::jsonb, 'https://www.196flavors.com/malaysia-roti-john/', 'https://www.themealdb.com/images/media/meals/hx335q1619789561.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('shawarma-chuck-roast-wrap', 'Shawarma chuck roast wrap', 4, 0, 0, '{"calories": 648, "protein": 43.1, "carbs": 2.3, "fat": 49.1, "saturated_fat": 20.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 290.5, "potassium": 14.2, "fiber": null, "sugar": 0.2, "vitamin_a": null, "vitamin_c": null, "calcium": 39.3, "iron": 6.8}'::jsonb, ARRAY['beef', 'saudi arabian', 'themealdb', 'nutrition-generated', 'soup', 'slow-cooker', 'baking', 'grilling'], '[{"quantity": 1.0, "unit": "kg", "item": "Chuck Roast", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "cup", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Ground Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Turmeric", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Cayenne Pepper", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Ground Cinnamon", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Ground Coriander", "notes": null, "category": "spices"}, {"quantity": 0.25, "unit": "tsp", "item": "Ground Clove", "notes": null, "category": "spices"}]'::jsonb, '["1", "In a dutch oven or slow cooker, add all the spices, beef broth and lemon juice. Stir to combine..", "2", "Add the beef and turn to coat, spoon some sauce over the top.", "3", "Cover and cook on low for 8-10 hours.", "4", "After cooking, remove beef and use two forks to shred. Discard any excess fat.", "5", "Skim fat off of the top of the liquid remaining.", "6", "Mix shredded beef into sauce. Keep warm until you are ready to serve.", "7", "Build wrap by spreading garlic sauce on the pita. Top with beef and add garnishes to your liking.", "8", "Fold it burrito style.", "9", "Heat a grill pan and grill the wrap."]'::jsonb, 'https://cookpad.com/eng/recipes/24415920?ref=search&search_term=saudi+arabia', 'https://www.themealdb.com/images/media/meals/swo87v1763595282.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('soy-glazed-meatloaves-with-wasabi-mashed-potatoes-roasted-carrots', 'Soy-Glazed Meatloaves with Wasabi Mashed Potatoes & Roasted Carrots', 4, 0, 0, '{"calories": 270, "protein": 7.5, "carbs": 33.4, "fat": 11.3, "saturated_fat": 6.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1311.5, "potassium": 455.3, "fiber": 3.1, "sugar": 18.1, "vitamin_a": null, "vitamin_c": 12.3, "calcium": 58.7, "iron": 2.3}'::jsonb, ARRAY['beef', 'american', 'themealdb', 'nutrition-generated', 'dessert', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 12.0, "unit": "ounces", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Scallions", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "slice", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Powder", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tsp", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbsp", "item": "Butter", "notes": null, "category": "dairy"}]'::jsonb, '["1. Preheat oven to 425 degrees. Wash and dry all produce. Dice potatoes into 1/2-inch pieces. Trim, peel, and cut carrots on a diagonal into 1/2-inch-thick pieces. Trim and thinly slice scallions, separating whites from greens; finely chop whites. Peel and finely chop garlic.", "2. In a medium bowl, soak bread with 2 TBSP water (4 TBSP for 4 servings); break up with your hands until pasty. Stir in beef, sriracha, scallion whites, half the garlic, salt (we used 3/4 tsp kosher salt; 11/2 tsp for 4), and pepper. Form into two 1-inch-tall loaves (four loaves for 4). Place on one side of a baking sheet. Toss carrots on empty side of same sheet with a drizzle of oil, salt, and pepper. (For 4, spread meatloaves out across whole sheet and add carrots to a second sheet.) Bake for 20 minutes (we''ll glaze the meatloaves then).", "3. Meanwhile, place potatoes in a medium pot with enough salted water to cover by 2 inches. Bring to a boil and cook until very", "tender, 12-15 minutes. Reserve 1/2 cup potato cooking liquid, then drain. While potatoes cook, in a small bowl, combine soy sauce, garlic powder, 1/4 cup ketchup (1/2 cup for 4 servings), and 2 tsp sugar (4 tsp for 4).", "4. Once meatloaves and carrots have baked 20 minutes, remove from oven. Spoon half the ketchup glaze over meatloaves (save", "the rest for serving); return to oven until carrots are browned and tender, meatloaves are cooked through, and glaze is tacky, 4-5 minutes more.", "5. Meanwhile, melt 2 TBSP butter (4 TBSP for 4 servings) in pot used for potatoes over medium heat. Add remaining garlic and cook", "until fragrant, 30 seconds. Add potatoes and 1/4 tsp wasabi. Mash, adding splashes of reserved potato cooking liquid as necessary until smooth. Season with salt and pepper. (If you like things spicy, stir in more wasabi!)", "6. Divide meatloaves, mashed potatoes, and roasted carrots between plates. Sprinkle with scallion greens and serve with remaining ketchup glaze on the side for dipping."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/o2wb6p1581005243.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spaghetti-bolognese', 'Spaghetti Bolognese', 4, 0, 0, '{"calories": 378, "protein": 34.0, "carbs": 79.0, "fat": 17.0, "saturated_fat": 3.3, "polyunsaturated_fat": 0.1, "monounsaturated_fat": 3.6, "sodium": 313.5, "potassium": 794.9, "fiber": 6.0, "sugar": 3.6, "vitamin_a": null, "vitamin_c": 12.6, "calcium": 52.3, "iron": 5.6}'::jsonb, ARRAY['beef', 'italian', 'themealdb', 'nutrition-generated', 'soup', 'pasta'], '[{"quantity": 1.0, "unit": "serving", "item": "onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "olive oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "g", "item": "lean", "notes": "minced beef", "category": "other"}, {"quantity": 90.0, "unit": "g", "item": "mushrooms", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "dried oregano", "notes": null, "category": "spices"}, {"quantity": 400.0, "unit": "g", "item": "can tomatoes", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "ml", "item": "hot beef stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tbsp", "item": "tomato puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "worcestershire sauce", "notes": null, "category": "pantry"}, {"quantity": 350.0, "unit": "g", "item": "spaghetti", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Topping parmesan", "notes": null, "category": "dairy"}]'::jsonb, '["Put the onion and oil in a large pan and fry over a fairly high heat for 3-4 mins. Add the garlic and mince and fry until they both brown. Add the mushrooms and herbs, and cook for another couple of mins.", "Stir in the tomatoes, beef stock, tomato ketchup or purée, Worcestershire sauce and seasoning. Bring to the boil, then reduce the heat, cover and simmer, stirring occasionally, for 30 mins.", "Meanwhile, cook the spaghetti in a large pan of boiling, salted water, according to packet instructions. Drain well, run hot water through it, put it back in the pan and add a dash of olive oil, if you like, then stir in the meat sauce. Serve in hot bowls and hand round Parmesan cheese, for sprinkling on top."]'::jsonb, NULL, 'https://www.themealdb.com/images/media/meals/sutysw1468247559.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('steak-vietnamese-noodle-salad', 'Steak & Vietnamese noodle salad', 4, 0, 0, '{"calories": 171, "protein": 16.8, "carbs": 34.7, "fat": 6.1, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 149.1, "potassium": 534.2, "fiber": 1.6, "sugar": 6.0, "vitamin_a": null, "vitamin_c": 14.0, "calcium": 54.4, "iron": 2.6}'::jsonb, ARRAY['beef', 'vietnamese', 'themealdb', 'nutrition-generated', 'dessert', 'salad'], '[{"quantity": 85.0, "unit": "g", "item": "Brown Rice Noodle", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Rapeseed Oil", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Fillet Of Steak", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "sliced Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1 Lime", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Rice Vinegar", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tbs", "item": "Fish Sauce", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Mix all the ingredients for the dressing together in a bowl with 1 tbsp water until the sugar has dissolved.", "step 2", "Cook the noodles following pack instructions, then plunge into a bowl of cold water to cool completely. Drain the noodles, then add the carrot, cabbage, spring onion and dressing, and toss to combine.", "step 3", "Heat the oil in a frying pan over a high heat. Season the steak, then cook to your liking; 2-3 mins on each side for medium rare. Leave to rest for 5 mins, then slice. Divide the salad and steak slices between bowls and scatter over some coriander to serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/steak-vietnamese-noodle-salad', 'https://www.themealdb.com/images/media/meals/st9shl1763755808.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('steak-and-kidney-pie', 'Steak and Kidney Pie', 4, 0, 0, '{"calories": 687, "protein": 24.1, "carbs": 79.2, "fat": 47.3, "saturated_fat": 18.0, "polyunsaturated_fat": null, "monounsaturated_fat": 6.0, "sodium": 882.8, "potassium": 491.6, "fiber": 3.3, "sugar": 30.2, "vitamin_a": null, "vitamin_c": 2.0, "calcium": 69.3, "iron": 5.7}'::jsonb, ARRAY['beef', 'british', 'themealdb', 'nutrition-generated', 'dessert', 'soup', 'baking'], '[{"quantity": 300.0, "unit": "g", "item": "Puff Pastry", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Beaten Egg White", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Beaten Egg Yolks", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 70.0, "unit": "ml", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 200.0, "unit": "g", "item": "Lamb Kidney", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 30.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 85.0, "unit": "ml", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Worcestershire Sauce", "notes": null, "category": "pantry"}]'::jsonb, '["Preheat the oven to 220C/425F/Gas 7", "Heat the vegetable oil in a large frying pan, and brown the beef all over. (You may need to do this in batches.) Set aside, then brown the kidneys on both sides in the same pan. Add the onions and cook for 3-4 minutes.", "Return the beef to the pan, sprinkle flour over and coat the meat and onions", "Add the stock to the pan, stir well and bring to the boil.", "Turn the heat down and simmer for 1½ hours without a lid. If the liquid evaporates too much, add more stock.", "Remove from the heat. Add salt, pepper and Worcestershire sauce and allow to cool completely. Place the cooked meat mixture into a pie dish.", "Roll out the pastry to 5mm/¼in thick and 5cm/2in larger than the dish you are using.", "Using a rolling pin, lift the pastry and place it over the top of the pie dish. Trim and crimp the edges with your fingers and thumb.", "Brush the surface with the beaten egg mixture and bake for 30-40 minutes until golden-brown and puffed.", "Serve with creamy mash and steamed vegetables to soak up the gravy."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/steakandkidneypie_73308', 'https://www.themealdb.com/images/media/meals/qysyss1511558054.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('steak-diane', 'Steak Diane', 4, 0, 0, '{"calories": 217, "protein": 8.4, "carbs": 382.6, "fat": 8.4, "saturated_fat": 4.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 11010.5, "potassium": 86.9, "fiber": 10.2, "sugar": 7.3, "vitamin_a": null, "vitamin_c": 12.4, "calcium": 128.9, "iron": 8.0}'::jsonb, ARRAY['beef', 'french', 'themealdb', 'nutrition-generated', 'soup'], '[{"quantity": 2.0, "unit": "tbs", "item": "Canola Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Fillet", "notes": null, "category": "other"}, {"quantity": 1.5, "unit": "cup", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "finely", "notes": "diced Challots", "category": "other"}, {"quantity": 4.0, "unit": "oz", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "Brandy", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "cup", "item": "Heavy Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbs", "item": "Dijon Mustard", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Worcestershire Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Tabasco Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbs", "item": "minced Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "minced Chives", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "to taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "to taste Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Heat oil in a 12\" skillet over medium-high heat. Season steaks with salt and pepper, and add to skillet; cook, turning once, until browned on both sides and cooked to desired doneness, about 4 to 5 minutes for medium-rare. Transfer steaks to a plate, and set aside.", "Return skillet to high heat, and add stock; cook until reduced until to 1⁄2 cup, about 10 minutes. Pour into a bowl, and set aside. Return skillet to heat, and add butter; add garlic and shallots, and cook, stirring, until soft, about 2 minutes. Add mushrooms, and cook, stirring, until they release any liquid and it evaporates and mushrooms begin to brown, about 2 minutes. Add cognac, and light with a match to flambée; cook until flame dies down. Stir in reserved stock, cream, Dijon, Worcestershire, and hot sauce, and then return steaks to skillet; cook, turning in sauce, until warmed through and sauce is thickened, about 4 minutes. Transfer steak to serving plates and stir parsley and chives into sauce; pour sauce over steaks to serve."]'::jsonb, 'https://www.saveur.com/article/Recipes/Classic-Steak-Diane', 'https://www.themealdb.com/images/media/meals/vussxq1511882648.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('szechuan-beef', 'Szechuan Beef', 4, 0, 0, '{"calories": 333, "protein": 17.4, "carbs": 57.4, "fat": 3.7, "saturated_fat": 2.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 471.0, "potassium": 195.7, "fiber": 12.4, "sugar": 12.5, "vitamin_a": null, "vitamin_c": 56.5, "calcium": 151.0, "iron": 11.9}'::jsonb, ARRAY['beef', 'chinese', 'themealdb', 'nutrition-generated', 'dessert'], '[{"quantity": 0.5, "unit": "lb", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "White", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tbs", "item": "Starch", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "tbs", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 0.75, "unit": "cup", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 0.75, "unit": "cup", "item": "Green Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Cooking wine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbs", "item": "Oyster Sauce", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tsp", "item": "Hotsauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Soy Sauce", "notes": null, "category": "pantry"}]'::jsonb, '["STEP 1 - MARINATING THE BEEF", "In a bowl, add the beef, salt, sesame seed oil, white pepper, egg white, 2 Tablespoon of corn starch and 1 Tablespoon of oil.", "STEP 2 - STIR FRY", "First Cook the beef by adding 2 Tablespoon of oil until the beef is golden brown.", "Set the beef aside", "In a wok add 1 Tablespoon of oil, minced ginger, minced garlic and stir-fry for few seconds.", "Next add all of the vegetables and then add sherry cooking wine and 1 cup of water.", "To make the sauce add oyster sauce, hot pepper sauce, and sugar.", "add the cooked beef and 1 spoon of soy sauce", "To thicken the sauce, whisk together 1 Tablespoon of cornstarch and 2 Tablespoon of water in a bowl and slowly add to your stir-fry until it''s the right thickness."]'::jsonb, 'https://sueandgambo.com/pages/szechuan-beef', 'https://www.themealdb.com/images/media/meals/1529443236.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-beef-stir-fry', 'Thai beef stir-fry', 4, 0, 0, '{"calories": 299, "protein": 20.8, "carbs": 6.4, "fat": 12.7, "saturated_fat": 5.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1274.0, "potassium": null, "fiber": 35.7, "sugar": 4.7, "vitamin_a": null, "vitamin_c": null, "calcium": 731.0, "iron": 23.8}'::jsonb, ARRAY['beef', 'thai', 'themealdb', 'nutrition-generated'], '[{"quantity": 2.0, "unit": "tbsp", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Oyster Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Basil Leaves", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat a wok or large frying pan until smoking hot. Pour in the oil and swirl around the pan, then tip in the beef strips and chilli. Cook, stirring all the time, until the meat is lightly browned, about 3 mins, then pour over the oyster sauce. Cook until heated through and the sauce coats the meat. stir in the basil leaves and serve with plain rice."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/thai-beef-stir-fry', 'https://www.themealdb.com/images/media/meals/kyuxew1763479470.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, re