INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('traditional-croatian-goulash', 'Traditional Croatian Goulash', 4, 0, 0, '{"calories": 195, "protein": 25.8, "carbs": 58.2, "fat": 7.4, "saturated_fat": 5.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1747.8, "potassium": 198.8, "fiber": 1.2, "sugar": 4.3, "vitamin_a": null, "vitamin_c": 8.9, "calcium": 30.7, "iron": 5.6}'::jsonb, ARRAY['beef', 'croatian', 'themealdb', 'nutrition-generated'], '[{"quantity": 500.0, "unit": "g", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "ml", "item": "Red Wine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Water", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tbs", "item": "Mustard", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tbs", "item": "Vegetable Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Clean the meat from the veins if there are some and cut it into smaller pieces, 3 × 3 cm. Marinate the meat in the mustard and spices and let it sit in the refrigerator for one hour", "Heat one tablespoon of pork fat or vegetable oil in a pot and fry the meat on all sides until it gets browned. Once the meat is cooked, transfer it to a plate and add another tablespoon of fat to the pot", "Cut the onions very fine, peel the carrots and shred it using a grater. Cook the onions and carrots over low heat for 15 minutes. You can salt the vegetables a little to make them soften faster", "Once the vegetables have browned and become slightly mushy, add the meat and bay leaves and garlic. Pour over with wine and simmer for 10-15 minutes to allow the alcohol to evaporate. Now is the right time to add 2/3 the amount of liquid", "Cover the pot and cook over low heat for an hour, stirring occasionally. After the first hour, pour over the rest of the water or stock and cook for another 30-45 minutes", "Allow the stew to cool slightly and serve it with a sprinkle of chopped parsley and few slices of fresh hot pepper if you like to spice it up a bit", "Slice ​​some fresh bread, season the salad and simply enjoying these wonderful flavors"]'::jsonb, 'https://www.chasingthedonkey.com/croatian-recipes-traditional-croatian-goulash/', 'https://www.themealdb.com/images/media/meals/n1hcou1628770088.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('turkish-lahmacun', 'Turkish lahmacun', 4, 0, 0, '{"calories": 899, "protein": 34.5, "carbs": 124.2, "fat": 30.6, "saturated_fat": 8.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 183.1, "potassium": 406.2, "fiber": 3.0, "sugar": 1.6, "vitamin_a": null, "vitamin_c": 4.0, "calcium": 43.5, "iron": 10.6}'::jsonb, ARRAY['beef', 'vietnamese', 'themealdb', 'nutrition-generated', 'baking'], '[{"quantity": 500.0, "unit": "g", "item": "Strong white bread flour", "notes": null, "category": "grains"}, {"quantity": 10.0, "unit": "g", "item": "Fast action yeast", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Sprinkling Corn Flour", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 250.0, "unit": "g", "item": "Ground Beef", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tsp", "item": "Chilli Flakes", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch", "notes": "Ground Cumin", "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Sift the flour into a large bowl, make a well in the middle and sprinkle in the yeast. Pour 125ml water over the yeast, then flick flour over the liquid to create a layer. Cover and leave to rise in a warm place for 15 mins until cracks appear on the surface of that layer.", "step 2", "Use your hands to mix in 250ml more water along with 1 tsp salt and knead the dough for about 10 mins until elastic and no longer sticky. Add a little more flour if you need to. Cover and leave to rise again in a warm place for 30 mins until doubled in size.", "step 3", "Heat the oven to as high as it will go (about 240C/220C fan/gas 9) and sprinkle one or two baking trays thinly with cornmeal.", "step 4", "Pour boiling water from the kettle over the tomatoes, leave to stand briefly, then drain and slip off the skins. Cut the tomatoes in half, cut out the stalks, scoop out the seeds and discard, then chop the flesh.", "step 5", "Halve the chillies lengthways, cut out the stalks, seeds and white inner membrane, then rinse. Cut lengthwise into fine strips, then crosswise into fine dice.", "step 6", "Put the tomatoes, chillies, spring onions, finely chopped parsley, beef mince, spices, 1 tsp salt and ½ tsp freshly ground black pepper into a bowl and mix well.", "step 7", "Take the dough and knead it briefly, then divide into four pieces and shape each into a ball. Roll each ball into a thin circle, place on the prepared baking trays. Spread with a thin layer of the meat mixture.", "step 8", "Bake each flatbread for 10-15 mins until the edges begin to darken. After removing from the oven, sprinkle the lahmacun with the roughly chopped parsley and sliced onion, then squeeze over a few drops of lemon juice. Serve straightaway."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/lahmacun', 'https://www.themealdb.com/images/media/meals/tqd3ac1763786065.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vegetable-shepherds-pie', 'Vegetable Shepherds Pie', 4, 0, 0, '{"calories": 1151, "protein": 29.7, "carbs": 150.1, "fat": 47.0, "saturated_fat": 17.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2228.2, "potassium": 512.5, "fiber": 12.3, "sugar": 18.6, "vitamin_a": null, "vitamin_c": 3.9, "calcium": 80.0, "iron": 9.1}'::jsonb, ARRAY['beef', 'irish', 'themealdb', 'nutrition-generated', 'dessert', 'soup', 'baking', 'vegetarian'], '[{"quantity": 3.0, "unit": "lbs", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "lbs", "item": "Small Potatoes", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Salted Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "oz", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 0.75, "unit": "cup", "item": "Brown Lentils", "notes": null, "category": "pantry"}, {"quantity": 6.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Kosher Salt", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "cups", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Bay Leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "cups", "item": "Dry White Wine", "notes": null, "category": "other"}, {"quantity": 8.0, "unit": "cups", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbsp", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Rosemary", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sage", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Chives", "notes": null, "category": "other"}]'::jsonb, '["Add Ingredients:", "12 cups chopped mixed vegetables", "1   cup chopped fresh mushrooms", "1   cup pearl onions", "TOPPING:", "Preheat oven to 450°. Bake potatoes on a foil-lined baking sheet until tender, about 45 minutes. Let cool slightly, then peel. Press potatoes through a ricer, food mill, or colander into a large bowl. Add butter; stir until well blended. Stir in milk. Season to taste with salt.", "FILLING:", "Soak dried porcini in 3 cups hot water; set aside. Combine lentils, 1 garlic clove, 1 tsp. salt, and 4 cups water in a medium saucepan. Bring to a boil; reduce heat and simmer, stirring occasionally, until lentils are tender but not mushy, 15–20 minutes. Drain lentils and discard garlic.", "Heat 3 Tbsp. oil in a large heavy pot over medium heat. Add onions and cook, stirring occasionally, until soft, about 12 minutes. Add chopped garlic and cook for 1 minute. Stir in tomato paste. Cook, stirring constantly, until tomato paste is caramelized, 2–3 minutes.", "Add bay leaves and wine; stir, scraping up any browned bits. Stir in porcini, slowly pouring porcini soaking liquid into pan but leaving any sediment behind. Bring to a simmer and cook until liquid is reduced by half, about 10 minutes. Stir in broth and cook, stirring occasionally, until reduced by half, about 45 minutes.", "Strain mixture into a large saucepan and bring to a boil; discard solids in strainer. Stir cornstarch and 2 Tbsp. water in a small bowl to dissolve. Add cornstarch mixture; simmer until thickened, about 5 minutes. Whisk in miso. Season sauce with salt and pepper. Set aside.", "Preheat oven to 450°. Toss vegetables and pearl onions with remaining 2 Tbsp. oil, 5 garlic cloves, and rosemary sprigs in a large bowl; season with salt and pepper. Divide between 2 rimmed baking sheets. Roast, stirring once, until tender, 20–25 minutes. Transfer garlic cloves to a small bowl; mash well with a fork and stir into sauce. Discard rosemary. DO AHEAD: Lentils, sauce, and vegetables can be made 1 day ahead. Cover separately; chill.", "Arrange lentils in an even layer in a 3-qt. baking dish; set dish on a foil-lined rimmed baking sheet. Toss roasted vegetables with fresh mushrooms and chopped herbs; layer on top of lentils. Pour sauce over vegetables. Spoon potato mixture evenly over.", "Bake until browned and bubbly, about 30 minutes. Let stand for 15 minutes before serving."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/w8umt11583268117.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('venezuelan-sancocho', 'Venezuelan Sancocho', 4, 0, 0, '{"calories": 356, "protein": 12.1, "carbs": 397.1, "fat": 1.9, "saturated_fat": 0.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 11205.3, "potassium": 267.9, "fiber": 14.7, "sugar": 7.0, "vitamin_a": null, "vitamin_c": 37.8, "calcium": 238.4, "iron": 10.4}'::jsonb, ARRAY['beef', 'venezulan', 'themealdb', 'nutrition-generated', 'soup'], '[{"quantity": 2.0, "unit": "lbs", "item": "Hind Shank", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Pepper", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cloves", "item": "Chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cloves", "item": "Crushed Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leek", "notes": null, "category": "produce"}, {"quantity": 8.0, "unit": "cups", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 0.5, "unit": "cup", "item": "Sweet Red Peppers", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Scallions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sweetcorn", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "lb", "item": "Cassaba", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "lb", "item": "Yautia", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "lb", "item": "White Yam", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "lb", "item": "Butternut Squash", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Cilantro", "notes": null, "category": "produce"}]'::jsonb, '["Add hind shank, 1 halved small onion, halved bell pepper, 4 whole garlic cloves, the dark green leaves of the leek, and stock to a large stockpot. Cook for 45-60 minutes until the meat is fork-tender. NOTE: the meat can take a bit longer to be fork-tender; that is okay, just add more cooking time if necessary.", "When the meat is tender, remove the big pieces of vegetables and bones. Discard.", "Add diced onion, 2 minced garlic, mini sweet peppers, sliced leeks (light green part), scallions, yucca, and corn; Mix and simmer covered over medium heat for 5- 8 minutes, until the yucca is starting to soften. NOTE: the yuca can take a bit longer to start softening; that is okay, just add more cooking time if necessary.", "Add yautia, white yam, and butternut squash. Mix to combine. Simmer covered over medium heat for 5 – 6 minutes, until all the root vegetables are tender. NOTE: Do not cook too much, or they will fall apart.", "Taste and add salt to your taste, if necessary. Add cilantro and the remaining 2 minced garlic cloves. Mix and let simmer for 2 more minutes.", "Serve hot in large soup bowls, dividing the meat and vegetables evenly. Add a squish of lime juice and/or hot sauce, if desired. Serve along with arepas and or casabe (cassava bread)."]'::jsonb, 'https://mommyshomecooking.com/easy-venezuelan-sancocho/#recipe', 'https://www.themealdb.com/images/media/meals/8859m71764377470.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('venezuelan-shredded-beef', 'Venezuelan Shredded Beef', 4, 0, 0, '{"calories": 378, "protein": 9.5, "carbs": 389.1, "fat": 11.7, "saturated_fat": 1.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 10836.6, "potassium": 115.6, "fiber": 10.2, "sugar": 9.0, "vitamin_a": 14.0, "vitamin_c": 12.6, "calcium": 184.0, "iron": 9.3}'::jsonb, ARRAY['beef', 'venezulan', 'themealdb', 'nutrition-generated', 'soup', 'instant-pot'], '[{"quantity": 2.0, "unit": "lbs", "item": "Skirty Steak", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "thinly Tomato", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cups", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tsp", "item": "Worcestershire Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 0.25, "unit": "cup", "item": "Tomato Ketchup", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Season beef with salt, pepper and minced garlic", "Chop 1 onion in 4 big wedges", "Place in the beef pressure cooker with the 4 wedges of onion and the stock", "Pressure cook for 20 minutes", "Release the pressure and open the lid", "Remove the beef and SAVE 2 cups of stock in another container", "With 2 forks, shred the beef. Beef should be tender enough to so easily. If not, cook for another 10 minutes", "Press the saute button of the Instant pot. Add the olive oil", "When the machine beeps, add the sliced onion, pepper and tomatoes. Cook until tender", "Add the shredded beef back in the pot and mix", "Pour in 1 1/2 cups of the saved stock, the Worcestershire sauce, tomato paste, ketchup and cumin. Mix", "If sauce seems to dry, add a tad more of stock", "Season with salt and pepper", "Serve!"]'::jsonb, 'https://livingsweetmoments.com/venezuelan-shredded-beef-made-instant-pot/', 'https://www.themealdb.com/images/media/meals/mq27gf1764436795.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bread-omelette', 'Bread omelette', 4, 0, 0, '{"calories": 165, "protein": 2.5, "carbs": 22.5, "fat": 27.8, "saturated_fat": 15.4, "polyunsaturated_fat": null, "monounsaturated_fat": 4.2, "sodium": 263.5, "potassium": 5.8, "fiber": 1.7, "sugar": 13.6, "vitamin_a": 189.5, "vitamin_c": null, "calcium": 37.2, "iron": 0.0}'::jsonb, ARRAY['breakfast', 'indian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "0.5 Salt", "notes": null, "category": "pantry"}]'::jsonb, '["Make and enjoy."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/hqaejl1695738653.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('breakfast-potatoes', 'Breakfast Potatoes', 4, 0, 0, '{"calories": 531, "protein": 17.8, "carbs": 40.5, "fat": 32.3, "saturated_fat": 11.4, "polyunsaturated_fat": null, "monounsaturated_fat": 0.6, "sodium": 799.5, "potassium": 302.8, "fiber": 2.6, "sugar": 9.4, "vitamin_a": 18.8, "vitamin_c": 6.4, "calcium": 52.2, "iron": 3.2}'::jsonb, ARRAY['breakfast', 'canadian', 'themealdb', 'nutrition-generated'], '[{"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Minced Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Maple Syrup", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Garnish Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Allspice", "notes": null, "category": "spices"}]'::jsonb, '["Before you do anything, freeze your bacon slices that way when you''re ready to prep, it''ll be so much easier to chop!", "Wash the potatoes and cut medium dice into square pieces. To prevent any browning, place the already cut potatoes in a bowl filled with water.", "In the meantime, heat 1-2 tablespoons of oil in a large skillet over medium-high heat. Tilt the skillet so the oil spreads evenly.", "Once the oil is hot, drain the potatoes and add to the skillet. Season with salt, pepper, and Old Bay as needed.", "Cook for 10 minutes, stirring the potatoes often, until brown. If needed, add a tablespoon more of oil.", "Chop up the bacon and add to the potatoes. The bacon will start to render and the fat will begin to further cook the potatoes. Toss it up a bit! The bacon will take 5-6 minutes to crisp.", "Once the bacon is cooked, reduce the heat to medium-low, add the minced garlic and toss. Season once more. Add dried or fresh parsley. Control heat as needed.", "Let the garlic cook until fragrant, about one minute.", "Just before serving, drizzle over the maple syrup and toss. Let that cook another minute, giving the potatoes a caramelized effect.", "Serve in a warm bowl with a sunny side up egg!"]'::jsonb, 'http://www.vodkaandbiscuits.com/2014/03/06/bangin-breakfast-potatoes/', 'https://www.themealdb.com/images/media/meals/1550441882.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('dutch-poffertjes-mini-pancakes', 'Dutch poffertjes (mini pancakes)', 4, 0, 0, '{"calories": 471, "protein": 10.4, "carbs": 50.2, "fat": 24.7, "saturated_fat": 14.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 85.8, "potassium": 1.8, "fiber": 3.2, "sugar": 4.3, "vitamin_a": null, "vitamin_c": 0.8, "calcium": 110.1, "iron": 3.1}'::jsonb, ARRAY['breakfast', 'dutch', 'themealdb', 'nutrition-generated', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 125.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 125.0, "unit": "g", "item": "Buckwheat Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 300.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 10.0, "unit": "g", "item": "Yeast", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "vanilla sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Icing Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["Mix the dry yeast with some of the luke warm milk en stir until dissolved.", "Place buckwheat and the flour together in a bowl and make a small circle in the middle. Add the yeast mixture into it. Add the milk and stir until you have a smooth batter.", "Add the eggs, salt and vanille sugar and stir through. Leave to stand and rise for about 45 minutes.", "Heat the poffertjespan and add a bit of butter into each hole. Fill halfway with batter and first bake one side until you can see the top dry out a little. Turn the poffertjes around with a small fork and bake the other side until cooked and golden brown.", "Serve the poffertjes with butter and icing sugar"]'::jsonb, 'https://insimoneskitchen.com/old-dutch-poffertjes/#recipe', 'https://www.themealdb.com/images/media/meals/oaqz9f1766593912.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('english-breakfast', 'English Breakfast', 4, 0, 0, '{"calories": 191, "protein": 12.2, "carbs": 1.3, "fat": 13.9, "saturated_fat": 5.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 518.2, "potassium": 12.0, "fiber": 0.6, "sugar": 0.7, "vitamin_a": null, "vitamin_c": 1.3, "calcium": 16.8, "iron": 0.8}'::jsonb, ARRAY['breakfast', 'british', 'themealdb', 'nutrition-generated', 'baking', 'grilling'], '[{"quantity": 1.0, "unit": "serving", "item": "Sausages", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "slice", "item": "Black Pudding", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "slice", "item": "Bread", "notes": null, "category": "grains"}]'::jsonb, '["Heat the flat grill plate over a low heat, on top of 2 rings/flames if it fits, and brush sparingly with light olive oil.", "Cook the sausages first. Add the sausages to the hot grill plate/the coolest part if there is one and allow to cook slowly for about 15-20 minutes, turning occasionally, until golden. After the first 10 minutes, increase the heat to medium before beginning to cook the other ingredients. If you are struggling for space, completely cook the sausages and keep hot on a plate in the oven.", "Snip a few small cuts into the fatty edge of the bacon. Place the bacon straight on to the grill plate and fry for 2-4 minutes each side or until your preferred crispiness is reached. Like the sausages, the cooked bacon can be kept hot on a plate in the oven.", "For the mushrooms, brush away any dirt using a pastry brush and trim the stalk level with the mushroom top. Season with salt and pepper and drizzle over a little olive oil. Place stalk-side up on the grill plate and cook for 1-2 minutes before turning and cooking for a further 3-4 minutes. Avoid moving the mushrooms too much while cooking, as this releases the natural juices, making them soggy.", "For the tomatoes, cut the tomatoes across the centre/or in half lengthways if using plum tomatoes , and with a small, sharp knife remove the green ''eye''. Season with salt and pepper and drizzle with a little olive oil. Place cut-side down on the grill plate and cook without moving for 2 minutes. Gently turn over and season again. Cook for a further 2-3 minutes until tender but still holding their shape.", "For the black pudding, cut the black pudding into 3-4 slices and remove the skin. Place on the grill plate and cook for 1½-2 minutes each side until slightly crispy.", "For ''proper'' fried bread it''s best to cook it in a separate pan. Ideally, use bread that is a couple of days old. Heat a frying pan to a medium heat and cover the base with oil. Add the bread and cook for 2-3 minutes each side until crispy and golden. If the pan becomes too dry, add a little more oil. For a richer flavour, add a knob of butter after you turn the slice.", "For the fried eggs, break the egg straight into the pan with the fried bread and leave for 30 seconds. Add a good knob of butter and lightly splash/baste the egg with the butter when melted. Cook to your preferred stage, season and gently remove with a fish slice.", "Once all the ingredients are cooked, serve on warm plates and enjoy straight away with a good squeeze of tomato ketchup or brown sauce."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/stressfreefullenglis_67721', 'https://www.themealdb.com/images/media/meals/utxryw1511721587.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fruit-and-cream-cheese-breakfast-pastries', 'Fruit and Cream Cheese Breakfast Pastries', 4, 0, 0, '{"calories": 468, "protein": 5.4, "carbs": 107.6, "fat": 3.5, "saturated_fat": 1.9, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 30.3, "potassium": 151.0, "fiber": 3.4, "sugar": 66.0, "vitamin_a": null, "vitamin_c": 16.9, "calcium": 26.5, "iron": 1.6}'::jsonb, ARRAY['breakfast', 'american', 'themealdb', 'nutrition-generated', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 1.25, "unit": "oz", "item": "Cream Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.25, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Pastry", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Strawberries", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Raspberries", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Blackberries", "notes": null, "category": "other"}]'::jsonb, '["Preheat oven to 400ºF (200ºC), and prepare two cookie sheets with parchment paper. In a bowl, mix cream cheese, sugar, and vanilla until fully combined. Lightly flour the surface and roll out puff pastry on top to flatten. Cut each sheet of puff pastry into 9 equal squares. On the top right and bottom left of the pastry, cut an L shape approximately ½ inch (1 cm) from the edge.", "NOTE: This L shape should reach all the way down and across the square, however both L shapes should not meet at the ends. Your pastry should look like a picture frame with two corners still intact.", "Take the upper right corner and fold down towards the inner bottom corner. You will now have a diamond shape.", "Place 1 to 2 teaspoons of the cream cheese filling in the middle, then place berries on top.", "Repeat with the remaining pastry squares and place them onto the parchment covered baking sheet.", "Bake for 15-20 minutes or until pastry is golden brown and puffed.", "Enjoy!"]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/1543774956.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('full-english-breakfast', 'Full English Breakfast', 4, 0, 0, '{"calories": 222, "protein": 13.7, "carbs": 10.8, "fat": 14.2, "saturated_fat": 5.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 629.8, "potassium": 58.6, "fiber": 2.0, "sugar": 3.3, "vitamin_a": null, "vitamin_c": 1.8, "calcium": 29.3, "iron": 1.2}'::jsonb, ARRAY['breakfast', 'british', 'themealdb', 'nutrition-generated', 'baking', 'grilling'], '[{"quantity": 1.0, "unit": "serving", "item": "Sausages", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Black Pudding", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "slice", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 100.0, "unit": "g", "item": "Baked Beans", "notes": null, "category": "pantry"}]'::jsonb, '["Heat the flat grill plate over a low heat, on top of 2 rings/flames if it fits, and brush sparingly with light olive oil.", "Cook the sausages first. Add the sausages to the hot grill plate/the coolest part if there is one and allow to cook slowly for about 15-20 minutes, turning occasionally, until golden. After the first 10 minutes, increase the heat to medium before beginning to cook the other ingredients. If you are struggling for space, completely cook the sausages and keep hot on a plate in the oven.", "Snip a few small cuts into the fatty edge of the bacon. Place the bacon straight on to the grill plate and fry for 2-4 minutes each side or until your preferred crispiness is reached. Like the sausages, the cooked bacon can be kept hot on a plate in the oven.", "For the mushrooms, brush away any dirt using a pastry brush and trim the stalk level with the mushroom top. Season with salt and pepper and drizzle over a little olive oil. Place stalk-side up on the grill plate and cook for 1-2 minutes before turning and cooking for a further 3-4 minutes. Avoid moving the mushrooms too much while cooking, as this releases the natural juices, making them soggy.", "For the tomatoes, cut the tomatoes across the centre/or in half lengthways if using plum tomatoes , and with a small, sharp knife remove the green ''eye''. Season with salt and pepper and drizzle with a little olive oil. Place cut-side down on the grill plate and cook without moving for 2 minutes. Gently turn over and season again. Cook for a further 2-3 minutes until tender but still holding their shape.", "For the black pudding, cut the black pudding into 3-4 slices and remove the skin. Place on the grill plate and cook for 1½-2 minutes each side until slightly crispy.", "For ''proper'' fried bread it''s best to cook it in a separate pan. Ideally, use bread that is a couple of days old. Heat a frying pan to a medium heat and cover the base with oil. Add the bread and cook for 2-3 minutes each side until crispy and golden. If the pan becomes too dry, add a little more oil. For a richer flavour, add a knob of butter after you turn the slice.", "For the fried eggs, break the egg straight into the pan with the fried bread and leave for 30 seconds. Add a good knob of butter and lightly splash/baste the egg with the butter when melted. Cook to your preferred stage, season and gently remove with a fish slice.", "Once all the ingredients are cooked, serve on warm plates and enjoy straight away with a good squeeze of tomato ketchup or brown sauce."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/stressfreefullenglis_67721', 'https://www.themealdb.com/images/media/meals/sqrtwu1511721265.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('home-made-mandazi', 'Home-made Mandazi', 4, 0, 0, '{"calories": 68, "protein": 24.2, "carbs": 132.5, "fat": 6.0, "saturated_fat": 2.4, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1147.5, "potassium": null, "fiber": 3.4, "sugar": 3.1, "vitamin_a": null, "vitamin_c": 0.6, "calcium": 88.7, "iron": 0.4}'::jsonb, ARRAY['breakfast', 'kenyan', 'themealdb', 'nutrition-generated', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 750.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 6.0, "unit": "tablespoons", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}]'::jsonb, '["This is one recipe a lot of people have requested and I have tried to make it as simple as possible and I hope it will work for you. Make sure you use the right flour which is basically one with raising agents. Adjust the amount of sugar to your taste and try using different flavours to have variety whenever you have them.", "You can use Coconut milk instead of regular milk, you can also add desiccated coconut to the dry flour or other spices like powdered cloves or cinnamon.", "For “healthy looking” mandazis do not roll the dough too thin before frying and use the procedure I have indicated above.", "1. Mix the flour,cinnamon and sugar in a suitable bowl.", "2. In a separate bowl whisk the egg into the milk", "3. Make a well at the centre of the flour and add the milk and egg mixture and slowly mix to form a dough.", "4. Knead the dough for 3-4 minutes or until it stops sticking to the sides of the bowl and you have a smooth surface.", "5. Cover the dough with a damp cloth  and allow to rest for 15 minutes.", "6. Roll the dough on a lightly floured surface into a 1cm thick piece.", "7. Using a sharp small knife, cut the dough into the desired size setting aside ready for deep frying.", "8. Heat your oil in a suitable pot and gently dip the mandazi pieces to cook until light brown on the first side then turn to cook on the second side.", "9. Serve them warm or cold"]'::jsonb, 'http://chef-raphael.com/home-made-mandazi-recipe/#more-106', 'https://www.themealdb.com/images/media/meals/thazgm1555350962.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamaican-cornmeal-porridge', 'Jamaican Cornmeal Porridge', 4, 0, 0, '{"calories": 535, "protein": 7.2, "carbs": 94.2, "fat": 15.2, "saturated_fat": 7.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 70.8, "potassium": 139.8, "fiber": 2.5, "sugar": 43.3, "vitamin_a": null, "vitamin_c": null, "calcium": 62.5, "iron": 3.1}'::jsonb, ARRAY['breakfast', 'jamaican', 'themealdb', 'nutrition-generated', 'dessert', 'vegetarian'], '[{"quantity": 4.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 380.0, "unit": "g", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "cup", "item": "Fine Yellow Cornmeal", "notes": null, "category": "produce"}, {"quantity": 1.5, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Ground Cinnamon", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Ground Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Ground Allspice", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "cup", "item": "Sweetened Condensed Milk", "notes": null, "category": "dairy"}]'::jsonb, '["Add 2 ½ cups water, 1 can coconut milk to a 4 QT heavy bottomed pot. Bring to a boil over medium-high heat.", "Meanwhile, add 1 cup cornmeal and 1 ½ cup water to a large mixing cup and whisk until smooth.", "Once the pot begins to boil, whisk in cornmeal mixture and continue to whisk for about 1 minute, ensuring there are no lumps. Reduce heat to low and cover with a tight fitting lid.", "Cook over low heat for 15-20 minutes, stirring occasionally. When there is about 5 minutes left, stir in vanilla extract, cinnamon, nutmeg, and all-spice. Remove from heat and sweeten with condensed milk.", "Serve and enjoy."]'::jsonb, 'https://www.myforkinglife.com/jamaican-cornmeal-porridge/#recipe', 'https://www.themealdb.com/images/media/meals/sng9bm1765320170.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('oatmeal-pancakes', 'Oatmeal pancakes', 4, 0, 0, '{"calories": 719, "protein": 10.1, "carbs": 97.0, "fat": 45.9, "saturated_fat": 27.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 128.6, "potassium": 122.6, "fiber": 6.1, "sugar": 25.9, "vitamin_a": null, "vitamin_c": 10.6, "calcium": 68.7, "iron": 1.2}'::jsonb, ARRAY['breakfast', 'venezulan', 'themealdb', 'nutrition-generated', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 80.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 150.0, "unit": "g", "item": "Ground Oats", "notes": null, "category": "grains"}, {"quantity": 150.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Sugar Syrup", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Strawberries", "notes": null, "category": "other"}]'::jsonb, '["Place all the ingredients in the glass and beat.", "Let the mixture stand for 10 minutes.", "Grease a hot frying pan with a little butter and pour a little of the mixture.", "When it starts to bubble on the surface, turn over with a spatula. Cook over medium-low heat so that they do not burn.", "Finally, add the caramel and strawberries."]'::jsonb, 'https://goya.es/en/recipes/oatmeal-pancakes', 'https://www.themealdb.com/images/media/meals/c400ok1764439058.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('rømmegrøt-norwegian-sour-cream-porridge', 'Rømmegrøt – Norwegian Sour Cream Porridge', 4, 0, 0, '{"calories": 414, "protein": 9.3, "carbs": 47.3, "fat": 43.5, "saturated_fat": 26.7, "polyunsaturated_fat": null, "monounsaturated_fat": 4.5, "sodium": 126.3, "potassium": 181.9, "fiber": null, "sugar": 24.9, "vitamin_a": null, "vitamin_c": 1.2, "calcium": 281.8, "iron": 0.8}'::jsonb, ARRAY['breakfast', 'norwegian', 'themealdb', 'nutrition-generated', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "Full fat sour cream", "notes": null, "category": "dairy"}, {"quantity": 0.75, "unit": "cup", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "cups", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Sprinkling Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Sprinkling Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Butter", "notes": null, "category": "dairy"}]'::jsonb, '["▢", "Cook the sour cream in a covered saucepan on medium heat for about 5 minutes.", "▢", "Turn down the heat and add half of the flour and stir well with a whisk. Once the flour is fully incorporated, let the mixture continue to cook, stirring occasionally, until fat starts to release. Use a spoon to gather as much of the fat as you can in a small bowl, saving for later. (Don''t worry if you can''t get any fat – in that case you can add butter later.)", "▢", "Whisk in the rest of the flour and then slowly add the milk, whisking constantly to avoid lumps. Let the porridge continue to cook on low heat for 5 minutes and then add salt.", "▢", "Serve with sugar, cinnamon, and the fat from the porridge. If you''re using lower fat sour cream you can top the rømmegrøt with some butter instead."]'::jsonb, 'https://scandinaviancookbook.com/rommegrot-norwegian-sour-cream-porridge/', 'https://www.themealdb.com/images/media/meals/hyk47c1762772689.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('salmon-eggs-eggs-benedict', 'Salmon Eggs Eggs Benedict', 4, 0, 0, '{"calories": 484, "protein": 6.1, "carbs": 25.2, "fat": 39.2, "saturated_fat": 21.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 156.0, "potassium": null, "fiber": 0.8, "sugar": 20.2, "vitamin_a": 200.9, "vitamin_c": null, "calcium": 53.8, "iron": 0.7}'::jsonb, ARRAY['breakfast', 'american', 'themealdb', 'nutrition-generated'], '[{"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "White Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Muffins", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Butter", "notes": null, "category": "dairy"}, {"quantity": 8.0, "unit": "slices", "item": "Smoked Salmon", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "White Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 125.0, "unit": "g", "item": "Unsalted Butter", "notes": null, "category": "dairy"}]'::jsonb, '["First make the Hollandaise sauce. Put the lemon juice and vinegar in a small bowl, add the egg yolks and whisk with a balloon whisk until light and frothy. Place the bowl over a pan of simmering water and whisk until mixture thickens. Gradually add the butter, whisking constantly until thick – if it looks like it might be splitting, then whisk off the heat for a few mins. Season and keep warm.", "To poach the eggs, bring a large pan of water to the boil and add the vinegar. Lower the heat so that the water is simmering gently. Stir the water so you have a slight whirlpool, then slide in the eggs one by one. Cook each for about 4 mins, then remove with a slotted spoon.", "Lightly toast and butter the muffins, then put a couple of slices of salmon on each half. Top each with an egg, spoon over some Hollandaise and garnish with chopped chives."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/73606/eggs-benedict-with-smoked-salmon-and-chives', 'https://www.themealdb.com/images/media/meals/1550440197.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('smoked-haddock-kedgeree', 'Smoked Haddock Kedgeree', 4, 0, 0, '{"calories": 406, "protein": 10.2, "carbs": 66.9, "fat": 56.3, "saturated_fat": 21.4, "polyunsaturated_fat": null, "monounsaturated_fat": 4.2, "sodium": 642.2, "potassium": 45.2, "fiber": 3.3, "sugar": 3.5, "vitamin_a": 189.5, "vitamin_c": 1.0, "calcium": 20.5, "iron": 1.7}'::jsonb, ARRAY['breakfast', 'indian', 'themealdb', 'nutrition-generated', 'soup'], '[{"quantity": 50.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cardamom", "notes": null, "category": "spices"}, {"quantity": 0.25, "unit": "tsp", "item": "Turmeric", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Cinnamon Stick", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Sprigs of", "notes": "fresh Bay Leaf", "category": "other"}, {"quantity": 450.0, "unit": "g", "item": "Basmati Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 750.0, "unit": "g", "item": "Smoked Haddock", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Lemon", "notes": null, "category": "produce"}]'::jsonb, '["Melt 50g butter in a large saucepan (about 20cm across), add 1 finely chopped medium onion and cook gently over a medium heat for 5 minutes, until softened but not browned.", "Stir in 3 split cardamom pods, ¼ tsp turmeric, 1 small cinnamon stick and 2 bay leaves, then cook for 1 minute.", "Tip in 450g basmati rice and stir until it is all well coated in the spicy butter.", "Pour in 1 litre chicken or fish stock, add ½ teaspoon salt and bring to the boil, stir once to release any rice from the bottom of the pan. Cover with a close-fitting lid, reduce the heat to low and leave to cook very gently for 12 minutes.", "Meanwhile, bring some water to the boil in a large shallow pan. Add 750g un-dyed smoked haddock fillet and simmer for 4 minutes, until the fish is just cooked. Lift it out onto a plate and leave until cool enough to handle.", "Hard-boil 3 eggs for 8 minutes.", "Flake the fish, discarding any skin and bones. Drain the eggs, cool slightly, then peel and chop.", "Uncover the rice and remove the bay leaves, cinnamon stick and cardamom pods if you wish to. Gently fork in the fish and the chopped eggs, cover again and return to the heat for 2-3 minutes, or until the fish has heated through.", "Gently stir in almost all the 3 tbsp chopped fresh parsley, and season with a little salt and black pepper to taste. Serve scattered with the remaining parsley and garnished with 1 lemon, cut into wedges."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/2256/smoked-haddock-kedgeree', 'https://www.themealdb.com/images/media/meals/1550441275.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('torrijas-with-sherry', 'Torrijas with sherry', 4, 0, 0, '{"calories": 451, "protein": 8.5, "carbs": 20.2, "fat": 50.6, "saturated_fat": 19.5, "polyunsaturated_fat": null, "monounsaturated_fat": 18.6, "sodium": 214.0, "potassium": 30.9, "fiber": 0.8, "sugar": 18.1, "vitamin_a": null, "vitamin_c": 0.2, "calcium": 255.5, "iron": null}'::jsonb, ARRAY['breakfast', 'spanish', 'themealdb', 'nutrition-generated', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbsp", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tsp", "item": "Golden Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Sweet Sherry", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "slices Bread", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Creme Fraiche", "notes": null, "category": "other"}]'::jsonb, '["step 1", "In a wide, shallow bowl, beat the eggs with the cream, milk, golden caster sugar and sherry. Cut each slice of bread in two and dip them into the egg mix, turning to make sure they get a good coating on either side. Soak bread in egg mixture for 10 mins to absorb the liquid (carefully turn them over from time to time and make sure they don’t get too soggy).", "step 2", "Heat 1½ tbsp olive oil in a large frying pan and cook the bread for about 3 mins on each side until dark golden and crisp on the edge. Keep the slices warm in a low oven as you cook the rest.", "step 3", "Divide the torrijas between plates and dust with the icing sugar. Serve with crème fraîche or Greek yogurt on the side."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/torrijas-sherry', 'https://www.themealdb.com/images/media/meals/f3ee3y1763309332.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ugali-kenyan-cornmeal', 'Ugali – Kenyan cornmeal', 4, 0, 0, '{"calories": 345, "protein": 5.9, "carbs": 83.8, "fat": 1.5, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 9.5, "potassium": null, "fiber": 2.9, "sugar": 15.8, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": 2.1}'::jsonb, ARRAY['breakfast', 'kenyan', 'themealdb', 'nutrition-generated', 'vegetarian', 'vegan'], '[{"quantity": 2.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.5, "unit": "cups", "item": "White Cornmeal", "notes": null, "category": "produce"}]'::jsonb, '["Bring the water to a boil in a medium saucepan.", "Reduce the heat to low, and stirring constantly with a whisk, slowly add the cornmeal to the boiling water. The ugali will begin to thicken quite quickly.", "Continue cooking on low heat, stirring constantly with a sturdy wooden spoon, until the ugali begins to pull away from the sides of the pan, hold together, and takes on the aroma of roasted corn. Turn it out immediately onto a serving plate. If you would like, using a spoon or spatula, quickly shape it into a thick disk or round.", "The ugali will continue to firm as it cools and will be thick enough to cut with a knife (similar to firm polenta)."]'::jsonb, 'https://tasteoftheplace.com/ugali-kenyan-cornmeal/', 'https://www.themealdb.com/images/media/meals/smoa3h1762341142.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('yemeni-lahsa-elite-shakshuka', 'Yemeni Lahsa (Elite Shakshuka)', 4, 0, 0, '{"calories": 200, "protein": 4.3, "carbs": 29.3, "fat": 7.4, "saturated_fat": 4.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 151.5, "potassium": null, "fiber": 1.4, "sugar": 15.4, "vitamin_a": null, "vitamin_c": null, "calcium": 36.0, "iron": 0.9}'::jsonb, ARRAY['breakfast', 'saudi arabian', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 0.25, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Liquid Cheese", "notes": null, "category": "dairy"}]'::jsonb, '["1", "First, On medium heat, heat the olive oil and add the diced onion until it wethers. Next, add the tomatoes and cook for another 4-5 min. Lastly, add the all spice, salt, and cracked pepper.", "2", "Add the eggs and mix throughly for 2 minutes and cover to cook 5-6 minutes until top is solidified. Lastly, spread the liquid cheese and have it covered for a minute.", "3", "I served mine Mediterranean style with hash-browns, Egyptian fava beans, Turkish salami and olives, cheese wedges, and greek feta."]'::jsonb, 'https://cookpad.com/eng/recipes/24629321?ref=search&search_term=saudi+arabia', 'https://www.themealdb.com/images/media/meals/30s7vf1763741844.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('15-minute-chicken-halloumi-burgers', '15-minute chicken & halloumi burgers', 4, 0, 0, '{"calories": 501, "protein": 21.7, "carbs": 41.7, "fat": 28.3, "saturated_fat": 14.0, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.3, "sodium": 850.2, "potassium": 196.2, "fiber": 8.8, "sugar": 9.8, "vitamin_a": 17.7, "vitamin_c": 24.7, "calcium": 153.4, "iron": 8.0}'::jsonb, ARRAY['chicken', 'american', 'themealdb', 'nutrition-generated', 'salad', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Breasts", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbsp", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "tbsp", "item": "Hotsauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Juice", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Buns", "notes": null, "category": "grains"}, {"quantity": 250.0, "unit": "g", "item": "Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "Mayonnaise", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "tbsp", "item": "Sour Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Lettuce", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}]'::jsonb, '["STEP 1", "Put the chicken breasts between two pieces of baking parchment and use a rolling pin to gently bash them until they are approximately 1cm thick. Cut each chicken breast into two even pieces.", "STEP 2", "If you''re using a frying pan, heat two frying pans over medium-high heat, with one of them containing oil. Fry the chicken in the oiled pan for 3-4 mins on each side until they are cooked through. Season the chicken, reduce the heat, drizzle in the chilli sauce and half of the lemon juice, and cook for an additional 1-2 mins until the sauce is reduced. Remove the chicken from the heat.", "STEP 3", "If you''re using an air-fryer, preheat it to 180C for 4 mins. Add the chicken to the air-fryer and cook for 12 mins. Drizzle over the chilli sauce and half the lemon juice and cook for an additional 1-2 mins until the chicken is cooked through and the sauce is reduced. Remove the chicken and keep it warm.", "STEP 4", "While the chicken is cooking, toast the buns in the dry frying pan for 30 seconds. Transfer them to a plate. If you''re using an air fryer, put the buns in the air fryer for 1-2 mins until they are warm. Increase the air fryer temperature to 200C. Add the halloumi to the air fryer basket and cook for 10 mins, turning halfway through, until it''s golden. Toss the cabbage with the mayo and the remaining lemon juice.", "STEP 5", "Spoon the hummus (or dip of your choice) into the toasted buns, then top with the rocket, chilli chicken, halloumi, and peppers. Drizzle with a little more chilli sauce, spoon over the cabbage, season with black pepper, and top with the bun lids. Serve with any extra cabbage on the side or a green salad."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/15-minute-chicken-halloumi-burgers', 'https://www.themealdb.com/images/media/meals/vdwloy1713225718.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ayam-percik', 'Ayam Percik', 4, 0, 0, '{"calories": 108, "protein": 4.7, "carbs": 23.1, "fat": 2.0, "saturated_fat": 0.4, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.6, "sodium": 20.3, "potassium": 68.0, "fiber": 8.3, "sugar": 6.4, "vitamin_a": null, "vitamin_c": 5.2, "calcium": 110.7, "iron": 7.4}'::jsonb, ARRAY['chicken', 'malaysian', 'themealdb', 'nutrition-generated', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Thighs", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Challots", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Turmeric", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Fennel", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Tamarind Paste", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "can", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Water", "notes": null, "category": "other"}]'::jsonb, '["In a blender, add the ingredients for the spice paste and blend until smooth.", "Over medium heat, pour the spice paste in a skillet or pan and fry for 10 minutes until fragrant. Add water or oil 1 tablespoon at a time if the paste becomes too dry. Don''t burn the paste. Lower the fire slightly if needed.", "Add the cloves, cardamom, tamarind pulp, coconut milk, water, sugar and salt. Turn the heat up and bring the mixture to boil. Turn the heat to medium low and simmer for 10 minutes. Stir occasionally. It will reduce slightly. This is the marinade/sauce, so taste and adjust seasoning if necessary. Don''t worry if it''s slightly bitter. It will go away when roasting.", "When the marinade/sauce has cooled, pour everything over the chicken and marinate overnight to two days.", "Preheat the oven to 425 F.", "Remove the chicken from the marinade. Spoon the marinade onto a greased (or aluminum lined) baking sheet. Lay the chicken on top of the sauce (make sure the chicken covers the sauce and the sauce isn''t exposed or it''ll burn) and spread the remaining marinade on the chicken. Roast for 35-45 minutes or until internal temp of the thickest part of chicken is at least 175 F.", "Let chicken rest for 5 minutes. Brush the chicken with some of the oil. Serve chicken with the sauce over steamed rice (or coconut rice)."]'::jsonb, 'http://www.curiousnut.com/roasted-spiced-chicken-ayam-percik/', 'https://www.themealdb.com/images/media/meals/020z181619788503.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('brown-stew-chicken', 'Brown Stew Chicken', 4, 0, 0, '{"calories": 371, "protein": 11.1, "carbs": 23.5, "fat": 24.0, "saturated_fat": 9.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 283.4, "potassium": 129.5, "fiber": 1.7, "sugar": 4.0, "vitamin_a": 8.0, "vitamin_c": 5.5, "calcium": 55.8, "iron": 0.9}'::jsonb, ARRAY['chicken', 'jamaican', 'themealdb', 'nutrition-generated', 'soup'], '[{"quantity": 1.0, "unit": "whole", "item": "Chicken", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Lime", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tbs", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbs", "item": "Vegetable Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Squeeze lime over chicken and rub well. Drain off excess lime juice.", "Combine tomato, scallion, onion, garlic, pepper, thyme, pimento and soy sauce in a large bowl with the chicken pieces. Cover and marinate at least one hour.", "Heat oil in a dutch pot or large saucepan. Shake off the seasonings as you remove each piece of chicken from the marinade. Reserve the marinade for sauce.", "Lightly brown the chicken a few pieces at a time in very hot oil. Place browned chicken pieces on a plate to rest while you brown the remaining pieces.", "Drain off excess oil and return the chicken to the pan. Pour the marinade over the chicken and add the carrots. Stir and cook over medium heat for 10 minutes.", "Mix flour and coconut milk and add to stew, stirring constantly. Turn heat down to minimum and cook another 20 minutes or until tender."]'::jsonb, 'http://www.geniuskitchen.com/recipe/authentic-jamaican-brown-stew-chicken-347996', 'https://www.themealdb.com/images/media/meals/sypxpx1515365095.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chick-fil-a-sandwich', 'Chick-Fil-A Sandwich', 4, 0, 0, '{"calories": 724, "protein": 11.3, "carbs": 37.2, "fat": 59.9, "saturated_fat": 11.6, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.1, "sodium": 193.8, "potassium": 104.0, "fiber": 1.3, "sugar": 15.9, "vitamin_a": null, "vitamin_c": 0.2, "calcium": 103.4, "iron": 1.3}'::jsonb, ARRAY['chicken', 'american', 'themealdb', 'nutrition-generated', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Breast", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "cup", "item": "Pickle Juice", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 0.25, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tbs", "item": "Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "Garlic Powder", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "Celery Salt", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Cayenne Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Seed Burger Buns", "notes": null, "category": "grains"}]'::jsonb, '["Wrap the chicken loosely between plastic wrap and pound gently with the flat side of a meat tenderizer until about 1/2 inch thick all around.", "Cut into two pieces, as even as possible.", "Marinate in the pickle juice for 30 minutes to one hour (add a teaspoon of Tabasco sauce now for a spicy sandwich).", "Beat the egg with the milk in a bowl.", "Combine the flour, sugar, and spices in another bowl.", "Dip the chicken pieces each into the egg on both sides, then coat in flour on both sides.", "Heat the oil in a skillet (1/2 inch deep) to about 345-350.", "Fry each cutlet for 2 minutes on each side, or until golden and cooked through.", "Blot on paper and serve on toasted buns with pickle slices."]'::jsonb, 'https://hilahcooking.com/chick-fil-a-copycat/', 'https://www.themealdb.com/images/media/meals/sbx7n71587673021.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-chorizo-rice-pot', 'Chicken & chorizo rice pot', 4, 0, 0, '{"calories": 893, "protein": 40.9, "carbs": 47.8, "fat": 59.4, "saturated_fat": 12.5, "polyunsaturated_fat": null, "monounsaturated_fat": 4.0, "sodium": 2847.1, "potassium": 320.0, "fiber": 2.8, "sugar": 6.0, "vitamin_a": 8.0, "vitamin_c": 5.0, "calcium": 81.2, "iron": 4.6}'::jsonb, ARRAY['chicken', 'spanish', 'themealdb', 'nutrition-generated', 'soup'], '[{"quantity": 1.0, "unit": "serving", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "whole", "item": "Chicken", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "Crushed Garlic", "notes": null, "category": "produce"}, {"quantity": 225.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "chopped Thyme", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "ml", "item": "White Wine", "notes": null, "category": "other"}, {"quantity": 800.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 400.0, "unit": "g", "item": "Rice", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tbs", "item": "chopped Parsley", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat the oil in a large flameproof casserole dish and brown the chicken pieces on all sides – you may have to do this in batches. Remove from the dish and put to one side.", "step 2", "Lower the heat, add the onion and pepper, and gently cook for 10 mins until softened. Add the garlic and chorizo, and cook for a further 2 mins until the chorizo has released some of its oils into the dish. Stir in the tomato purée and cook for 1 min more.", "step 3", "Return the chicken pieces to the dish along with the thyme, white wine and stock. Bring the liquid to a boil, cover the dish with a tight-fitting lid and lower the heat. Cook for 30 mins.", "step 4", "Tip in the rice and stir everything together. Cover, set over a low heat and cook for a further 15 mins, or until the rice is cooked and has absorbed most of the cooking liquid. Remove from the heat and leave the dish to sit for 10 mins to absorb any remaining liquid. Season to taste and scatter with parsley to serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/chicken-chorizo-rice-pot', 'https://www.themealdb.com/images/media/meals/fk80jp1763280767.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-mushroom-hotpot', 'Chicken & mushroom Hotpot', 4, 0, 0, '{"calories": 675, "protein": 22.9, "carbs": 58.6, "fat": 42.2, "saturated_fat": 27.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 3959.1, "potassium": 130.3, "fiber": 5.0, "sugar": 24.3, "vitamin_a": null, "vitamin_c": 4.5, "calcium": 20.4, "iron": 2.2}'::jsonb, ARRAY['chicken', 'british', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 50.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 40.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Stock Cube", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Mustard Powder", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Chicken", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Sweetcorn", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Butter", "notes": null, "category": "dairy"}]'::jsonb, '["Heat oven to 200C/180C fan/gas 6. Put the butter in a medium-size saucepan and place over a medium heat. Add the onion and leave to cook for 5 mins, stirring occasionally. Add the mushrooms to the saucepan with the onions.", "Once the onion and mushrooms are almost cooked, stir in the flour – this will make a thick paste called a roux. If you are using a stock cube, crumble the cube into the roux now and stir well. Put the roux over a low heat and stir continuously for 2 mins – this will cook the flour and stop the sauce from having a floury taste.", "Take the roux off the heat. Slowly add the fresh stock, if using, or pour in 500ml water if you’ve used a stock cube, stirring all the time. Once all the liquid has been added, season with pepper, a pinch of nutmeg and mustard powder. Put the saucepan back onto a medium heat and slowly bring it to the boil, stirring all the time. Once the sauce has thickened, place on a very low heat. Add the cooked chicken and vegetables to the sauce and stir well. Grease a medium-size ovenproof pie dish with a little butter and pour in the chicken and mushroom filling.", "Carefully lay the potatoes on top of the hot-pot filling, overlapping them slightly, almost like a pie top.", "Brush the potatoes with a little melted butter and cook in the oven for about 35 mins. The hot-pot is ready once the potatoes are cooked and golden brown."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/chicken-mushroom-hot-pot', 'https://www.themealdb.com/images/media/meals/uuuspp1511297945.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-alfredo-primavera', 'Chicken Alfredo Primavera', 4, 0, 0, '{"calories": 1344, "protein": 59.6, "carbs": 144.5, "fat": 56.7, "saturated_fat": 27.0, "polyunsaturated_fat": null, "monounsaturated_fat": 3.2, "sodium": 1996.7, "potassium": 507.6, "fiber": 14.8, "sugar": 14.0, "vitamin_a": null, "vitamin_c": 7.4, "calcium": 921.2, "iron": 13.0}'::jsonb, ARRAY['chicken', 'italian', 'themealdb', 'nutrition-generated', 'pasta'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Chicken", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "into 1/2-inch cubes Squash", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "head", "item": "chopped Broccoli", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "8", "notes": "ounce sliced mushrooms", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "onion", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "red pepper flakes", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "white wine", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "cup", "item": "milk", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "heavy cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "cup", "item": "grated Parmesan cheese", "notes": null, "category": "dairy"}, {"quantity": 16.0, "unit": "ounces", "item": "bowtie pasta", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "pinch  Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Parsley", "notes": null, "category": "produce"}]'::jsonb, '["Heat 1 tablespoon of butter and 2 tablespoons of olive oil in a large skillet over medium-high heat.", "Season both sides of each chicken breast with seasoned salt and a pinch of pepper.", "Add the chicken to the skillet and cook for 5-7 minutes on each side, or until cooked through.", "While the chicken is cooking, bring a large pot of water to a boil.", "Season the boiling water with a few generous pinches of kosher salt.", "Add the pasta and give it a stir.", "Cook, stirring occasionally, until al dente, about 12 minutes.", "Reserve 1/2 cup of  pasta water before draining the pasta.", "Remove the chicken from the pan and transfer it to a cutting board; allow it to rest.", "Turn the heat down to medium and dd the remaining 1 tablespoon of butter and olive oil to the same pan you used to cook the chicken.", "Add the veggies (minus the garlic) and red pepper flakes to the pan and stir to coat with the oil and butter (refrain from seasoning with salt until the veggies are finished browning).", "Cook, stirring often, until the veggies are tender, about 5 minutes.", "Add the garlic and a generous pinch of salt and pepper to the pan and cook for 1 minute.", "Deglaze the pan with the white wine.", "Continue to cook until the wine has reduced by half, about 3 minutes.", "Stir in the milk, heavy cream, and reserved pasta water.", "Bring the mixture to a gentle boil and allow to simmer and reduce for 2-3 minutes.", "Turn off the heat and add the Parmesan cheese and cooked pasta.", "Season with salt and pepper to taste.", "Garnish with Parmesan cheese and chopped parsley, if desired."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/syqypv1486981727.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-basquaise', 'Chicken Basquaise', 4, 0, 0, '{"calories": 1061, "protein": 97.5, "carbs": 62.0, "fat": 64.5, "saturated_fat": 14.9, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2253.3, "potassium": 331.9, "fiber": 6.5, "sugar": 4.5, "vitamin_a": 8.0, "vitamin_c": 9.8, "calcium": 123.7, "iron": 1.9}'::jsonb, ARRAY['chicken', 'french', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 1.5, "unit": "kg", "item": "Chicken", "notes": null, "category": "meat"}, {"quantity": 25.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 130.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Sun", "notes": "Dried Tomatoes", "category": "other"}, {"quantity": 6.0, "unit": "cloves", "item": "sliced Garlic", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Basmati Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "drizzle Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Thyme", "notes": null, "category": "produce"}, {"quantity": 350.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 180.0, "unit": "g", "item": "Dry White Wine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Lemons", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Black Olives", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Preheat the oven to 180°C/Gas mark 4. Have the chicken joints ready to cook. Heat the butter and 3 tbsp olive oil in a flameproof casserole or large frying pan. Brown the chicken pieces in batches on both sides, seasoning them with salt and pepper as you go. Don''t crowd the pan - fry the chicken in small batches, removing the pieces to kitchen paper as they are done.", "Add a little more olive oil to the casserole and fry the onions over a medium heat for 10 minutes, stirring frequently, until softened but not browned. Add the rest of the oil, then the peppers and cook for another 5 minutes.", "Add the chorizo, sun-dried tomatoes and garlic and cook for 2-3 minutes. Add the rice, stirring to ensure it is well coated in the oil. Stir in the tomato paste, paprika, bay leaves and chopped thyme. Pour in the stock and wine. When the liquid starts to bubble, turn the heat down to a gentle simmer. Press the rice down into the liquid if it isn''t already submerged and place the chicken on top. Add the lemon wedges and olives around the chicken.", "Cover and cook in the oven for 50 minutes. The rice should be cooked but still have some bite, and the chicken should have juices that run clear when pierced in the thickest part with a knife. If not, cook for another 5 minutes and check again."]'::jsonb, 'https://www.rivercottage.net/recipes/chicken-basquaise', 'https://www.themealdb.com/images/media/meals/wruvqv1511880994.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-congee', 'Chicken Congee', 4, 0, 0, '{"calories": 572, "protein": 19.2, "carbs": 83.5, "fat": 19.5, "saturated_fat": 6.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 473.3, "potassium": 213.5, "fiber": 2.4, "sugar": 61.6, "vitamin_a": null, "vitamin_c": 0.6, "calcium": 17.9, "iron": 3.0}'::jsonb, ARRAY['chicken', 'chinese', 'themealdb', 'nutrition-generated'], '[{"quantity": 8.0, "unit": "oz", "item": "Chicken", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Ginger Cordial", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Rice", "notes": null, "category": "grains"}, {"quantity": 8.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "oz", "item": "Coriander", "notes": null, "category": "spices"}]'::jsonb, '["STEP 1 - MARINATING THE CHICKEN", "In a bowl, add chicken, salt, white pepper, ginger juice and then mix it together well.", "Set the chicken aside.", "STEP 2 - RINSE THE WHITE RICE", "Rinse the rice in a metal bowl or pot a couple times and then drain the water.", "STEP 2 - BOILING THE WHITE RICE", "Next add 8 cups of water and then set the stove on high heat until it is boiling. Once rice porridge starts to boil, set the stove on low heat and then stir it once every 8-10 minutes for around 20-25 minutes.", "After 25 minutes, this is optional but you can add a little bit more water to make rice porridge to make it less thick or to your preference.", "Next add the marinated chicken to the rice porridge and leave the stove on low heat for another 10 minutes.", "After an additional 10 minutes add the green onions, sliced ginger, 1 pinch of salt, 1 pinch of white pepper and stir for 10 seconds.", "Serve the rice porridge in a bowl", "Optional: add Coriander on top of the rice porridge."]'::jsonb, 'https://sueandgambo.com/pages/chicken-congee', 'https://www.themealdb.com/images/media/meals/1529446352.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-couscous', 'Chicken Couscous', 4, 0, 0, '{"calories": 808, "protein": 30.1, "carbs": 95.8, "fat": 20.8, "saturated_fat": 4.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1865.8, "potassium": 432.1, "fiber": 8.7, "sugar": 23.7, "vitamin_a": null, "vitamin_c": 0.8, "calcium": 175.7, "iron": 5.6}'::jsonb, ARRAY['chicken', 'moroccan', 'themealdb', 'nutrition-generated', 'soup'], '[{"quantity": 1.0, "unit": "tbsp", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Chicken Breast", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Harissa Spice", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Apricots", "notes": null, "category": "other"}, {"quantity": 220.0, "unit": "g", "item": "Chickpeas", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Couscous", "notes": null, "category": "grains"}, {"quantity": 200.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander", "notes": null, "category": "spices"}]'::jsonb, '["Heat the olive oil in a large frying pan and cook the onion for 1-2 mins just until softened. Add the chicken and fry for 7-10 mins until cooked through and the onions have turned golden. Grate over the ginger, stir through the harissa to coat everything and cook for 1 min more.", "Tip in the apricots, chickpeas and couscous, then pour over the stock and stir once. Cover with a lid or tightly cover the pan with foil and leave for about 5 mins until the couscous has soaked up all the stock and is soft. Fluff up the couscous with a fork and scatter over the coriander to serve. Serve with extra harissa, if you like."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/13139/onepan-chicken-couscous', 'https://www.themealdb.com/images/media/meals/qxytrx1511304021.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-enchilada-casserole', 'Chicken Enchilada Casserole', 4, 0, 0, '{"calories": 776, "protein": 50.9, "carbs": 16.4, "fat": 58.0, "saturated_fat": 31.8, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.1, "sodium": 1314.8, "potassium": 82.5, "fiber": 2.6, "sugar": 1.7, "vitamin_a": null, "vitamin_c": null, "calcium": 1303.7, "iron": 1.0}'::jsonb, ARRAY['chicken', 'mexican', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 14.0, "unit": "oz", "item": "jar Enchilada sauce", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "cups", "item": "shredded Monterey Jack cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "tortillas", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "breasts", "notes": null, "category": "other"}]'::jsonb, '["Cut each chicken breast in about 3 pieces, so that it cooks faster and put it in a small pot. Pour Enchilada sauce over it and cook covered on low to medium heat until chicken is cooked through, about 20 minutes. No water is needed, the chicken will cook in the Enchilada sauce. Make sure you stir occasionally so that it doesn''t stick to the bottom.", "Remove chicken from the pot and shred with two forks.", "Preheat oven to 375 F degrees.", "Start layering the casserole. Start with about ¼ cup of the leftover Enchilada sauce over the bottom of a baking dish. I used a longer baking dish, so that I can put 2 corn tortillas across. Place 2 tortillas on the bottom, top with ⅓ of the chicken and ⅓ of the remaining sauce. Sprinkle with ⅓ of the cheese and repeat starting with 2 more tortillas, then chicken, sauce, cheese. Repeat with last layer with the remaining ingredients, tortillas, chicken, sauce and cheese.", "Bake for 20 to 30 minutes uncovered, until bubbly and cheese has melted and started to brown on top.", "Serve warm."]'::jsonb, NULL, 'https://www.themealdb.com/images/media/meals/qtuwxu1468233098.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-fajita-mac-and-cheese', 'Chicken Fajita Mac and Cheese', 4, 0, 0, '{"calories": 1041, "protein": 39.6, "carbs": 128.5, "fat": 45.9, "saturated_fat": 22.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2355.3, "potassium": 441.3, "fiber": 13.0, "sugar": 1.6, "vitamin_a": 8.0, "vitamin_c": 3.2, "calcium": 829.8, "iron": 7.9}'::jsonb, ARRAY['chicken', 'american', 'themealdb', 'nutrition-generated', 'soup', 'pasta'], '[{"quantity": 500.0, "unit": "g", "item": "macaroni", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "cups", "item": "chicken stock", "notes": null, "category": "meat"}, {"quantity": 0.5, "unit": "cup", "item": "heavy cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "fajita seasoning", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "chicken breast", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tbsp", "item": "olive oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "finely", "notes": "diced onion", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "diced red pepper", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "cheddar cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "garnish", "notes": "chopped parsley", "category": "other"}]'::jsonb, '["Fry your onion, peppers and garlic in olive oil until nicely translucent. Make a well in your veg and add your chicken. Add your seasoning and salt. Allow to colour slightly.", "Add your cream, stock and macaroni.", "Cook on low for 20 minutes. Add your cheeses, stir to combine.", "Top with roasted peppers and parsley."]'::jsonb, 'http://twistedfood.co.uk/chicken-fajita-mac-n-cheese/', 'https://www.themealdb.com/images/media/meals/qrqywr1503066605.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-fried-rice', 'Chicken Fried Rice', 4, 0, 0, '{"calories": 1222, "protein": 38.7, "carbs": 201.2, "fat": 26.8, "saturated_fat": 10.2, "polyunsaturated_fat": null, "monounsaturated_fat": 0.1, "sodium": 973.6, "potassium": 157.8, "fiber": 4.4, "sugar": 19.9, "vitamin_a": null, "vitamin_c": 6.9, "calcium": 81.6, "iron": 3.1}'::jsonb, ARRAY['chicken', 'chinese', 'themealdb', 'nutrition-generated'], '[{"quantity": 1.0, "unit": "lb", "item": "Chicken Thighs", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Canola Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 0.6666666666666666, "unit": "cup", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Ground Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 0.6666666666666666, "unit": "cup", "item": "Peas", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cups", "item": "Jasmine Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Scallions", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Chinese five spice powder", "notes": null, "category": "spices"}, {"quantity": 2.5, "unit": "tbsp", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Fried rice is best made with leftover rice that''s at least a day old. Otherwise it becomes gummy in the skillet.", "If you don’t have any leftover rice from the night before, cook a batch of rice and spread it on a large baking sheet or several large plates. Let the rice dry out for about 1 to 2 hours before using it for fried rice.", "Rice sticks to the pan very easily, so make sure to use a wok or pan that doesn’t have a sticky surface. I usually cook stir-fries in my seasoned carbon steel wok, but cast iron or nonstick pans work well, too. You might need to add a little more oil if things aren’t releasing easily.", "Prepare the chicken:", "Chop the chicken into small 1/4-inch to 1/2-inch cubes. Sprinkle 1/2 teaspoon of salt over the chicken and mix to combine. Set the chicken aside for about 10 minutes (I usually use this time to chop all the vegetables).", "Scramble the egg:", "Heat a wok or large sauté pan over medium-high heat. Swirl in a tablespoon of oil and add the whisked eggs. Use a spatula to quickly scramble the eggs, breaking the curds into smaller pieces as they come together. Transfer the eggs to a plate.", "Cook the chicken:", "Add another tablespoon of oil in the wok or pan. Add the chicken and cook for 4 to 5 minutes, stirring occasionally. Turn off the heat and transfer the cooked chicken to a plate.", "Using your spatula, scrape off any chicken bits that are still stuck to the wok so they don''t burn during the next step. You can also use paper towels to wipe down your wok or pan.", "Cook the vegetables:", "Swirl 1 tablespoon of oil into the wok over medium-high heat. Add the diced onions and cook them for 1 minute, until they start to soften. Mix in the minced garlic and ginger and cook until fragrant, about 30 seconds. Add the diced carrots and cook for 2 minutes, stirring frequently. Add 1/2 teaspoon salt and the peas, and stir to incorporate.", "Cook the rice:", "Add the rice to the wok or pan on top of the vegetables and stir to combine. Using the back of your spatula, smash any large chunks of rice to break them apart. Add the white and green parts of the sliced scallions (save the dark green parts) and five-spice powder. Stir to incorporate. If the rice starts to stick to the pan, stir in a little more oil.", "Drizzle the soy sauce and sesame oil over the rice and stir to incorporate. Stir in the cooked chicken, scrambled eggs, and the dark parts of the scallions. Stir briefly to bring it together, and cook for another 1 to 2 minutes.", "Serve:", "Taste, and add more soy sauce if necessary. Serve immediately."]'::jsonb, 'https://www.simplyrecipes.com/recipes/chicken_fried_rice/', 'https://www.themealdb.com/images/media/meals/wuyd2h1765655837.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-ham-and-leek-pie', 'Chicken Ham and Leek Pie', 4, 0, 0, '{"calories": 793, "protein": 45.6, "carbs": 89.3, "fat": 88.0, "saturated_fat": 46.6, "polyunsaturated_fat": 0.1, "monounsaturated_fat": 2.8, "sodium": 1017.1, "potassium": 767.6, "fiber": 4.2, "sugar": 6.0, "vitamin_a": null, "vitamin_c": 1.7, "calcium": 181.9, "iron": 4.0}'::jsonb, ARRAY['chicken', 'british', 'themealdb', 'nutrition-generated', 'dessert', 'soup', 'baking'], '[{"quantity": 450.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Breast", "notes": null, "category": "other"}, {"quantity": 75.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Leek", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 50.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 200.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tbs", "item": "White Wine", "notes": null, "category": "other"}, {"quantity": 150.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 150.0, "unit": "g", "item": "Ham", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "spinkling Sea Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Pepper", "notes": null, "category": "produce"}, {"quantity": 350.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 200.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Free-range Egg", "notes": "Beaten", "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Cold Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Free-range Egg", "notes": "Beaten", "category": "dairy"}]'::jsonb, '["Heat the chicken stock in a lidded saucepan. Add the chicken breast and bring to a low simmer. Cover with a lid and cook for 10 minutes. Remove the chicken breasts from the water with tongs and place on a plate. Pour the cooking liquor into a large jug.", "Melt 25g/1oz of the butter in a large heavy-based saucepan over a low heat. Stir in the leeks and fry gently for two minutes, stirring occasionally until just softened. Add the garlic and cook for a further minute. Add the remaining butter and stir in the flour as soon as the butter has melted. Cook for 30 seconds, stirring constantly.", "Slowly pour the milk into the pan, just a little at a time, stirring well between each adding. Gradually add 250ml/10fl oz of the reserved stock and the wine, if using, stirring until the sauce is smooth and thickened slightly. Bring to a gentle simmer and cook for 3 minutes.", "Season the mixture, to taste, with salt and freshly ground black pepper. Remove from the heat and stir in the cream. Pour into a large bowl and cover the surface of the sauce with cling ilm to prevent a skin forming. Set aside to cool.", "Preheat the oven to 200C/400F/Gas 6. Put a baking tray in the oven to heat.", "For the pastry, put the flour and butter in a food processor and blend on the pulse setting until the mixture resembles fine breadcrumbs. With the motor running, add the beaten egg and water and blend until the mixture forms a ball. Portion off 250g/10oz of pastry for the lid.", "Roll the remaining pastry out on a lightly floured surface, turning the pastry frequently until around 5mm/¼in thick and 4cm/1½in larger than the pie dish. Lift the pastry over the rolling pin and place it gently into the pie dish. Press the pastry firmly up the sides, making sure there are no air bubbles. Leave the excess pastry overhanging the sides.", "Cut the chicken breasts into 3cm/1¼in pieces. Stir the chicken, ham and leeks into the cooled sauce. Pour the chicken filling into the pie dish. Brush the rim of the dish with beaten egg. Roll out the reserved pastry for the lid.", "Cover the pie with the pastry lid and press the edges together firmly to seal. Trim any excess pastry.", "Make a small hole in the centre of the pie with the tip of a knife. Glaze the top of the pie with beaten egg. Bake on the preheated tray in the centre of the oven for 35-40 minutes or until the pie is golden-brown all over and the filling is piping hot."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/creamy_chicken_ham_and_03877', 'https://www.themealdb.com/images/media/meals/xrrtss1511555269.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-handi', 'Chicken Handi', 4, 0, 0, '{"calories": 606, "protein": 71.6, "carbs": 368.9, "fat": 37.8, "saturated_fat": 14.8, "polyunsaturated_fat": null, "monounsaturated_fat": 3.3, "sodium": 10534.3, "potassium": 43.0, "fiber": 3.3, "sugar": 11.8, "vitamin_a": null, "vitamin_c": 6.7, "calcium": 174.4, "iron": 2.7}'::jsonb, ARRAY['chicken', 'indian', 'themealdb', 'nutrition-generated'], '[{"quantity": 1.2, "unit": "kg", "item": "Chicken", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "sliced Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Tomatoes", "notes": null, "category": "produce"}, {"quantity": 8.0, "unit": "cloves", "item": "chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "Ginger paste", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "Vegetable oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Cumin seeds", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tsp", "item": "Coriander seeds", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Turmeric powder", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Chilli powder", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "cup", "item": "Yogurt", "notes": null, "category": "dairy"}, {"quantity": 0.75, "unit": "cup", "item": "Cream", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tsp", "item": "Dried fenugreek", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Garam masala", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}]'::jsonb, '["Take a large pot or wok, big enough to cook all the chicken, and heat the oil in it. Once the oil is hot, add sliced onion and fry them until deep golden brown. Then take them out on a plate and set aside.", "To the same pot, add the chopped garlic and sauté for a minute. Then add the chopped tomatoes and cook until tomatoes turn soft. This would take about 5 minutes.", "Then return the fried onion to the pot and stir. Add ginger paste and sauté well.", "Now add the cumin seeds, half of the coriander seeds and chopped green chillies. Give them a quick stir.", "Next goes in the spices – turmeric powder and red chilli powder. Sauté the spices well for couple of minutes.", "Add the chicken pieces to the wok, season it with salt to taste and cook the chicken covered on medium-low heat until the chicken is almost cooked through. This would take about 15 minutes. Slowly sautéing the chicken will enhance the flavor, so do not expedite this step by putting it on high heat.", "When the oil separates from the spices, add the beaten yogurt keeping the heat on lowest so that the yogurt doesn’t split. Sprinkle the remaining coriander seeds and add half of the dried fenugreek leaves. Mix well.", "Finally add the cream and give a final mix to combine everything well.", "Sprinkle the remaining kasuri methi and garam masala and serve the chicken handi hot with naan or rotis. Enjoy!"]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/wyxwsp1486979827.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-karaage', 'Chicken Karaage', 4, 0, 0, '{"calories": 291, "protein": 24.1, "carbs": 19.5, "fat": 29.5, "saturated_fat": 3.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 231.5, "potassium": 385.5, "fiber": null, "sugar": 2.9, "vitamin_a": null, "vitamin_c": 0.8, "calcium": 11.1, "iron": 0.4}'::jsonb, ARRAY['chicken', 'japanese', 'themealdb', 'nutrition-generated', 'dessert'], '[{"quantity": 450.0, "unit": "grams", "item": "Boneless skin Chicken", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Soy sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Sake", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "teaspoon", "item": "Granulated sugar", "notes": null, "category": "pantry"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Potato starch", "notes": null, "category": "produce"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Vegetable oil", "notes": null, "category": "pantry"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Lemon", "notes": null, "category": "produce"}]'::jsonb, '["Add the ginger, garlic, soy sauce, sake and sugar to a bowl and whisk to combine. Add the chicken, then stir to coat evenly. Cover and refrigerate for at least 1 hour.", "Add 1 inch of vegetable oil to a heavy bottomed pot and heat until the oil reaches 360 degrees F. Line a wire rack with 2 sheets of paper towels and get your tongs out. Put the potato starch in a bowl", "Add a handful of chicken to the potato starch and toss to coat each piece evenly.", "Fry the karaage in batches until the exterior is a medium brown and the chicken is cooked through. Transfer the fried chicken to the paper towel lined rack. If you want the karaage to stay crispy longer, you can fry the chicken a second time, until it''s a darker color after it''s cooled off once. Serve with lemon wedges."]'::jsonb, 'https://norecipes.com/karaage-recipe', 'https://www.themealdb.com/images/media/meals/tyywsw1505930373.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-mandi', 'Chicken Mandi', 4, 0, 0, '{"calories": 227, "protein": 11.3, "carbs": 85.3, "fat": 2.2, "saturated_fat": 0.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 178.4, "potassium": 96.1, "fiber": 4.6, "sugar": 27.4, "vitamin_a": null, "vitamin_c": 6.2, "calcium": 34.0, "iron": 1.3}'::jsonb, ARRAY['chicken', 'indian', 'themealdb', 'nutrition-generated', 'grilling'], '[{"quantity": 1.0, "unit": "serving", "item": "Chicken", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "cups", "item": "Basmati Rice", "notes": null, "category": "grains"}, {"quantity": 4.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Turmeric Powder", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tbsp", "item": "Cardamom", "notes": null, "category": "spices"}, {"quantity": 0.25, "unit": "teaspoon", "item": "Cloves", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}]'::jsonb, '["1. Clean and cut the chicken; marinate briefly with salt, turmeric and a little oil.", "2. Rinse and soak basmati rice 20–30 minutes.", "3. In a large pot, heat ghee/oil. Fry chopped onion until golden. Add minced garlic and green chillies and fry 1–2 min.", "4. Add whole spices (cardamom, cloves, cinnamon, bay leaves) and ground spices (coriander, cumin). Stir until fragrant.", "5. Add chicken pieces, brown lightly and add enough water/chicken stock to cover. Simmer until chicken is nearly cooked.", "6. Remove chicken; measure remaining liquid and add soaked rice. Bring to a boil, then reduce heat, cover and cook rice until almost done.", "7. Return the chicken to the rice pot on top, cover tightly and steam on low for 10–15 min so flavors meld.", "8. (Optional) For authentic smoky aroma: heat a small charcoal until red hot, place it on a small foil cup in the centre of the pot, add a tsp of butter/oil on the coal then cover immediately to trap smoke for 5–10 minutes. Remove coal.", "9. Garnish with fried onions, chopped coriander and serve with chutney or raita."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/er4d081765186828.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-marengo', 'Chicken Marengo', 4, 0, 0, '{"calories": 150, "protein": 9.2, "carbs": 13.9, "fat": 8.7, "saturated_fat": 5.6, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 3980.9, "potassium": 84.2, "fiber": 3.0, "sugar": 2.8, "vitamin_a": null, "vitamin_c": 12.0, "calcium": 44.2, "iron": 1.1}'::jsonb, ARRAY['chicken', 'french', 'themealdb', 'nutrition-generated', 'soup', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 300.0, "unit": "g", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Legs", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "g", "item": "Passata", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Stock Cube", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Black Olives", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Parsley", "notes": null, "category": "produce"}]'::jsonb, '["Heat the oil in a large flameproof casserole dish and stir-fry the mushrooms until they start to soften. Add the chicken legs and cook briefly on each side to colour them a little.", "Pour in the passata, crumble in the stock cube and stir in the olives. Season with black pepper – you shouldn’t need salt. Cover and simmer for 40 mins until the chicken is tender. Sprinkle with parsley and serve with pasta and a salad, or mash and green veg, if you like."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/3146682/chicken-marengo', 'https://www.themealdb.com/images/media/meals/qpxvuq1511798906.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-parmentier', 'Chicken Parmentier', 4, 0, 0, '{"calories": 752, "protein": 49.8, "carbs": 86.2, "fat": 35.4, "saturated_fat": 17.5, "polyunsaturated_fat": null, "monounsaturated_fat": 3.4, "sodium": 1318.0, "potassium": 2046.8, "fiber": 8.1, "sugar": 7.8, "vitamin_a": 23.9, "vitamin_c": 90.9, "calcium": 204.9, "iron": 3.7}'::jsonb, ARRAY['chicken', 'french', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 1.5, "unit": "kg", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 30.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 30.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "chopped  Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tbsp", "item": "White Wine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Tinned Tomatos", "notes": null, "category": "produce"}, {"quantity": 350.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 600.0, "unit": "g", "item": "Chicken", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Olives", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 50.0, "unit": "g", "item": "Gruyere cheese", "notes": null, "category": "dairy"}]'::jsonb, '["For the topping, boil the potatoes in salted water until tender. Drain and push through a potato ricer, or mash thoroughly. Stir in the butter, cream and egg yolks. Season and set aside.", "For the filling, melt the butter in a large pan. Add the shallots, carrots and celery and gently fry until soft, then add the garlic. Pour in the wine and cook for 1 minute. Stir in the tomato purée, chopped tomatoes and stock and cook for 10–15 minutes, until thickened. Add the shredded chicken, olives and parsley. Season to taste with salt and pepper.", "Preheat the oven to 180C/160C Fan/Gas 4.", "Put the filling in a 20x30cm/8x12in ovenproof dish and top with the mashed potato. Grate over the Gruyère. Bake for 30–35 minutes, until piping hot and the potato is golden-brown."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/chicken_parmentier_25434', 'https://www.themealdb.com/images/media/meals/uwvxpv1511557015.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-quinoa-greek-salad', 'Chicken Quinoa Greek Salad', 4, 0, 0, '{"calories": 652, "protein": 27.1, "carbs": 73.6, "fat": 22.4, "saturated_fat": 14.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 993.5, "potassium": 49.2, "fiber": 3.9, "sugar": 28.1, "vitamin_a": null, "vitamin_c": 3.7, "calcium": 201.5, "iron": 2.4}'::jsonb, ARRAY['chicken', 'greek', 'themealdb', 'nutrition-generated', 'salad'], '[{"quantity": 225.0, "unit": "g", "item": "Quinoa", "notes": null, "category": "grains"}, {"quantity": 25.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "clove", "item": "finely", "notes": "chopped Garlic", "category": "other"}, {"quantity": 400.0, "unit": "g", "item": "Chicken Breast", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Black Olives", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Feta", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Mint", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1/2 Lemon", "notes": null, "category": "produce"}]'::jsonb, '["Cook the quinoa following the pack instructions, then rinse in cold water and drain thoroughly.", "Meanwhile, mix the butter, chilli and garlic into a paste. Toss the chicken fillets in 2 tsp of the olive oil with some seasoning. Lay in a hot griddle pan and cook for 3-4 mins each side or until cooked through. Transfer to a plate, dot with the spicy butter and set aside to melt.", "Next, tip the tomatoes, olives, onion, feta and mint into a bowl. Toss in the cooked quinoa. Stir through the remaining olive oil, lemon juice and zest, and season well. Serve with the chicken fillets on top, drizzled with any buttery chicken juices."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/griddled-chicken-quinoa-greek-salad', 'https://www.themealdb.com/images/media/meals/k29viq1585565980.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-shawarma-with-homemade-garlic-herb-yoghurt-sauce', 'Chicken Shawarma with homemade garlic herb yoghurt sauce', 4, 0, 0, '{"calories": 832, "protein": 57.5, "carbs": 98.5, "fat": 41.4, "saturated_fat": 22.1, "polyunsaturated_fat": null, "monounsaturated_fat": 1.5, "sodium": 2080.6, "potassium": 198.3, "fiber": 7.7, "sugar": 43.2, "vitamin_a": null, "vitamin_c": 5.5, "calcium": 791.1, "iron": 15.9}'::jsonb, ARRAY['chicken', 'saudi arabian', 'themealdb', 'nutrition-generated'], '[{"quantity": 1.0, "unit": "kg", "item": "Chicken Breast", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Ground Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Ground Cardomom", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Cayenne Pepper", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Smoked Paprika", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Greek Yogurt", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Splash Lemon Juice", "notes": null, "category": "produce"}]'::jsonb, '["1", "Start by cutting your chicken up into reasonably small slices. Grab your ziplock bag and dump the freshly sliced chicken inside.", "2", "Add garlic, coriander, cumin, cardomom, cayenne pepper, paprika, salt, pepper, lemon juice and olive oil to the bag. Close the bag and mix thoroughly. Place in fridge for 10-12 hours (shorter is fine but longer is better).", "3", "Once ready to cook, heat your fry pan to medium-high and add a tiny bit of olive oil. Fry one side of all of your flatbreads until slightly toasty. Remove from pan, add enough oil to coat the fry pan. Put crumble fries into air fryer on 180 for 15 minutes shaking occasionally.", "4", "The pan should be pretty hot by now, add the chicken in 2 batches (unless you have a big fry pan) to avoid overcrowding. The chicken should get a nice sear and darker colour which is perfect. Cook for a further 5-8 minutes or until cooked through. Repeat with next chicken batch.", "5", "While chicken is cooking, place your Greek yoghurt into a bowl. Combine garlic, finely chopped mint and parsley, squeeze or so of lemon and cumin. Combine and add salt to taste. In a small bowl, combine 1tsp garlic powder, paprika, cumin, onion powder, oregano, dried parsley, cayenne pepper (optional) mix and leave aside for fries.", "6", "Season fries immediately once cooked and add salt to taste. Once the chicken is complete, serve immediately by laying out your flatbread, spreading the sauce evenly over the bread, add lettuce, onion, tomato, fries, chicken, feta and more sauce on top. Serve immediately."]'::jsonb, 'https://cookpad.com/eng/recipes/24343467?ref=search&search_term=saudi+arabia', 'https://www.themealdb.com/images/media/meals/hcg6l91763596970.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-wings-with-cumin-lemon-garlic', 'Chicken wings with cumin, lemon & garlic', 4, 0, 0, '{"calories": 18, "protein": 4.6, "carbs": 4.7, "fat": 2.7, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 21.0, "potassium": 48.5, "fiber": null, "sugar": 4.3, "vitamin_a": null, "vitamin_c": 1.2, "calcium": 13.4, "iron": 0.1}'::jsonb, ARRAY['chicken', 'turkish', 'themealdb', 'nutrition-generated', 'baking', 'grilling', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Wings", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Zest and juice of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin Seeds", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Honey", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Using a pair of sharp kitchen scissors, cut each wing at the knuckle into two pieces. Mix the garlic, lemon zest and juice, cumin and oil with plenty of seasoning, then tip into a dish with the chicken wings and toss to coat. Cover and put in the fridge to marinate for at least 1 hr, or overnight if you have time.", "step 2", "Heat oven to 200C/180C fan/gas 6, or heat an outdoor barbecue. Bake the chicken wings on an oven tray for 45-50 mins until crisp, or barbecue for 20 mins, drizzling over the honey for the final 10 mins of each method. Serve on a platter with plenty of paper napkins. Fill small bowls with olives, pistachios or almonds, dates and pickled chillies and flatbreads to serve alongside, along with the dishes below."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/chicken-wings-cumin-lemon-garlic', 'https://www.themealdb.com/images/media/meals/4hzyvq1763792564.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-with-saffron-raisins-pine-nuts', 'Chicken with saffron, raisins & pine nuts', 4, 0, 0, '{"calories": 858, "protein": 80.2, "carbs": 31.4, "fat": 56.0, "saturated_fat": 20.1, "polyunsaturated_fat": 0.0, "monounsaturated_fat": null, "sodium": 885.1, "potassium": 544.9, "fiber": 0.7, "sugar": 8.1, "vitamin_a": 128.5, "vitamin_c": 1.8, "calcium": 43.2, "iron": 2.9}'::jsonb, ARRAY['chicken', 'spanish', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 1.25, "unit": "kg", "item": "Chicken", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "cloves", "item": "Chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Saffron", "notes": null, "category": "spices"}, {"quantity": 125.0, "unit": "ml", "item": "Dry sherry", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tbsp", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 50.0, "unit": "g", "item": "Raisins", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbsp", "item": "Pine Nuts", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Parsley", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat a large frying pan on a high heat and season the chicken. Add the olive oil to the pan, then the chicken. Brown for about 5 mins on each side, remove onto a plate, then set aside.", "step 2", "Lower the heat to medium. In the remaining fat, fry the onions for 3 mins, then add the garlic and saffron. Cook for 3-4 mins more. Add the sherry, then simmer for 3-5 mins until syrupy.", "step 3", "Put the chicken leg pieces back into the pan, tip in the stock, thyme and raisins, cover, then gently cook on a low heat for 20 mins. Add the breast meat and any juices left on the plate. Simmer for 10 mins more until cooked through and the sauce in the pan has reduced.", "step 4", "While the chicken is cooking, heat oven to 200C/180C fan/gas 6. Scatter the pine nuts over a baking sheet, then roast for 10 mins until golden and toasted. Once the chicken has cooked through, season to taste, scatter with pine nuts and parsley, then serve with rice."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/chicken-saffron-raisins-pine-nuts', 'https://www.themealdb.com/images/media/meals/4mhr3u1763481087.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chinese-orange-chicken', 'Chinese Orange Chicken', 4, 0, 0, '{"calories": 1910, "protein": 39.5, "carbs": 110.0, "fat": 160.1, "saturated_fat": 31.4, "polyunsaturated_fat": null, "monounsaturated_fat": 1.4, "sodium": 1118.3, "potassium": 258.6, "fiber": 3.1, "sugar": 51.8, "vitamin_a": null, "vitamin_c": 7.2, "calcium": 105.0, "iron": 3.9}'::jsonb, ARRAY['chicken', 'chinese', 'themealdb', 'nutrition-generated', 'dessert', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Orange", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "Orange Juice", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Rice Vinegar", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 650.0, "unit": "g", "item": "Chicken Thighs", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "cups", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "cloves", "item": "chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sliced Scallions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garnish Sesame Seed", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Rice", "notes": null, "category": "grains"}]'::jsonb, '["Make the orange sauce:", "Whisk together sauce ingredients in a medium bowl. Set aside.", "Prep the chicken:", "Cut chicken into about 1-inch cubes. Whisk eggs with salt and black pepper in a bowl and add chicken. Stir together.", "In a separate bowl, whisk together flour and cornstarch. Remove chicken from eggs with a slotted spoon or tongs, letting excess egg drain off, then transfer to cornstarch mixture and coat well.", "Fry the chicken:", "Add oil to a large 10- to 12-inch skillet. Heat over medium-high heat until it reaches 350°F. If you don’t have a thermometer, you can also test the temperature by sprinkling in some flour. If the oil is hot enough, it should fizzle immediately.", "Once oil is hot, fry the chicken in two batches. The oil might not completely cover the chicken—that’s okay. Cook for 3 to 4 minutes. Flip the chicken pieces and cook until the chicken is cooked through, about 3 to 4 more minutes. Total cook time is about 6 to 8 minutes.", "Remove fried chicken cubes and transfer to a plate lined with paper towels, so the chicken can drain. Repeat until all the chicken is cooked.", "Simmer the chicken in the sauce:", "Once chicken is done, pour out hot oil and wipe pan clean. Add a fresh tablespoon of oil along with chopped garlic and shallot. Cook for a minute and then add the sauce. Simmer the sauce until it starts to thicken.", "Once the sauce is lightly bubbling, add fried chicken and toss together to coat. The sauce should continue to thicken and stick to the chicken. Let simmer for a minute or two more. Serve orange chicken over cooked white rice, garnished with sesame seeds and fresh scallions.", "Did you love this recipe? Let us know with a rating and review!", "LEFTOVERS! The orange chicken keeps well in the fridge for 5 days. Reheat in a skillet with a splash of water over low heat. Freeze the orange chicken for up to 3 months, but be sure to thaw it before reheating so the chicken doesn’t clump together."]'::jsonb, 'https://www.simplyrecipes.com/recipes/chinese_orange_chicken/', 'https://www.themealdb.com/images/media/meals/s73ytv1765567838.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('coq-au-vin', 'Coq au vin', 4, 0, 0, '{"calories": 336, "protein": 73.3, "carbs": 90.9, "fat": 34.8, "saturated_fat": 7.4, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 5.3, "sodium": 1387.3, "potassium": 1628.7, "fiber": 7.8, "sugar": 8.7, "vitamin_a": 18.8, "vitamin_c": 24.5, "calcium": 373.7, "iron": 3.2}'::jsonb, ARRAY['chicken', 'french', 'themealdb', 'nutrition-generated', 'breakfast', 'soup', 'baking'], '[{"quantity": 1.5, "unit": "tbsp", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "chopped dry-cured Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 460.0, "unit": "g", "item": "Legs", "notes": null, "category": "other"}, {"quantity": 650.0, "unit": "g", "item": "Thighs", "notes": null, "category": "other"}, {"quantity": 280.0, "unit": "g", "item": "Breasts", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbsp", "item": "Brandy", "notes": null, "category": "other"}, {"quantity": 600.0, "unit": "ml", "item": "Red Wine", "notes": null, "category": "other"}, {"quantity": 150.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tsp", "item": "tomato puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Rosemary", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "garnish parsley", "notes": null, "category": "produce"}, {"quantity": 250.0, "unit": "g", "item": "chestnut mushroom", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "plain flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "butter", "notes": null, "category": "dairy"}]'::jsonb, '["Heat 1 tbsp of the oil in a large, heavy-based saucepan or flameproof dish. Tip in the bacon and fry until crisp. Remove and drain on kitchen paper. Add the shallots to the pan and fry, stirring or shaking the pan often, for 5-8 mins until well browned all over. Remove and set aside with the bacon.", "Pat the chicken pieces dry with kitchen paper. Pour the remaining oil into the pan, then fry half the chicken pieces, turning regularly, for 5-8 mins until well browned. Remove, then repeat with the remaining chicken. Remove and set aside.", "Scatter in the garlic and fry briefly, then, with the heat medium-high, pour in the brandy or Cognac, stirring the bottom of the pan to deglaze. The alcohol should sizzle and start to evaporate so there is not much left.", "Return the chicken legs and thighs to the pan along with any juices, then pour in a little of the wine, stirring the bottom of the pan again. Stir in the rest of the wine, the stock and tomato purée, drop in the bouquet garni, season with pepper and a pinch of salt, then return the bacon and shallots to the pan. Cover, lower the heat to a gentle simmer, add the chicken breasts and cook for 50 mins-1hr.", "Just before ready to serve, heat the oil for the mushrooms in a large non-stick frying pan. Add the mushrooms and fry over a high heat for a few mins until golden. Remove and keep warm.", "Lift the chicken, shallots and bacon from the pan and transfer to a warmed serving dish. Remove the bouquet garni. To make the thickener, mix the flour, olive oil and butter in a small bowl using the back of a teaspoon. Bring the wine mixture to a gentle boil, then gradually drop in small pieces of the thickener, whisking each piece in using a wire whisk. Simmer for 1-2 mins. Scatter the mushrooms over the chicken, then pour over the wine sauce. Garnish with chopped parsley."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/1913655/coq-au-vin', 'https://www.themealdb.com/images/media/meals/qstyvs1505931190.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('crock-pot-chicken-baked-tacos', 'Crock Pot Chicken Baked Tacos', 4, 0, 0, '{"calories": 585, "protein": 35.8, "carbs": 29.1, "fat": 54.1, "saturated_fat": 20.8, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 8.8, "sodium": 880.1, "potassium": 359.9, "fiber": 3.6, "sugar": 6.1, "vitamin_a": null, "vitamin_c": 0.0, "calcium": 763.7, "iron": 1.8}'::jsonb, ARRAY['chicken', 'mexican', 'themealdb', 'nutrition-generated', 'salad', 'slow-cooker', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "- 6 Chicken Breasts", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Vinaigrette Dressing", "notes": null, "category": "other"}, {"quantity": 1.5, "unit": "tablespoon", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Smoked Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "can", "item": "Refried Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Taco Shells", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "cups", "item": "Shredded Mexican Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Halved Grape Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sliced", "notes": "Seeded Jalapeno", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Peeled", "notes": "Sliced Avocado", "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Green Salsa", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Sour Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Milk", "notes": null, "category": "dairy"}]'::jsonb, '["Put the uncooked chicken breasts in the crock pot. Pour the full bottle of salad dressing over the chicken. Sprinkle the rest of the ingredients over the top and mix them in a bit with a spoon.", "Cover your crock pot with the lid and cook on high for 4 hours.", "Remove all the chicken breasts from the crock pot and let cool.", "Shred the chicken breasts and move to a glass bowl.", "Pour most of the liquid over the shredded chicken.", "FOR THE TACOS:", "Make the guacamole sauce by mixing the avocado and green salsa together. Pour the guacamole mixture through a strainer until smooth and transfer to a squeeze bottle. Cut the tip off the lid of the squeeze bottle to make the opening more wide if needed.", "Make the sour cream sauce by mixing the sour cream and milk together until you get a more liquid sour cream sauce. Transfer to a squeeze bottle.", "In a 9x 13 glass baking dish, fill all 12+ tacos with a layer of refried beans, cooked chicken and shredded cheese.", "Bake at 450 for 10-15 minutes just until the cheese is melted and bubbling.", "Out of the oven top all the tacos with the sliced grape tomaotes, jalapeno and cilantro.", "Finish with a drizzle of guacamole and sour cream.", "Enjoy!"]'::jsonb, 'http://www.nobiggie.net/crock-pot-chicken-baked-tacos/', 'https://www.themealdb.com/images/media/meals/ypxvwv1505333929.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('easy-spanish-chicken', 'Easy Spanish chicken', 4, 0, 0, '{"calories": 599, "protein": 22.3, "carbs": 69.6, "fat": 28.3, "saturated_fat": 7.2, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.6, "sodium": 3101.5, "potassium": 260.8, "fiber": 24.7, "sugar": 2.6, "vitamin_a": 23.9, "vitamin_c": 30.6, "calcium": 394.8, "iron": 19.8}'::jsonb, ARRAY['chicken', 'spanish', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "tbsp", "item": "Extra Virgin Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sweet smoked paprika", "notes": null, "category": "spices"}, {"quantity": 4.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Tinned Tomatos", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "g", "item": "Green Olives", "notes": null, "category": "other"}, {"quantity": 400.0, "unit": "g", "item": "Butter Beans", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Thighs", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Parsley", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat the oven to 200C/180C fan/gas 6. Heat the olive oil in a large ovenproof frying pan over a medium heat and fry the onion, chorizo and peppers along with a pinch of salt and pepper for 15 mins until the veg has softened and the chorizo has released its oils. Add the paprika and garlic, and cook for another few minutes until fragrant.", "step 2", "Tip in the chopped tomatoes, olives and butter beans, stir to combine and season. Nestle in the chicken thighs and season well. Transfer to the oven and bake for 40 mins until the chicken skin is crisp and the meat cooked through and tender. Scatter with the parsley and serve.", "Watch after ad (0.04):", "3 Budget Egg Ideas"]'::jsonb, 'https://www.bbcgoodfood.com/recipes/easy-spanish-chicken', 'https://www.themealdb.com/images/media/meals/kzxflc1763194887.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('french-onion-chicken-with-roasted-carrots-mashed-potatoes', 'French Onion Chicken with Roasted Carrots & Mashed Potatoes', 4, 0, 0, '{"calories": 998, "protein": 29.2, "carbs": 406.0, "fat": 69.0, "saturated_fat": 29.7, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.1, "sodium": 10282.3, "potassium": 473.8, "fiber": 11.5, "sugar": 32.8, "vitamin_a": 8.9, "vitamin_c": 16.6, "calcium": 625.2, "iron": 8.8}'::jsonb, ARRAY['chicken', 'american', 'themealdb', 'nutrition-generated', 'dessert', 'soup', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Breasts", "notes": null, "category": "other"}, {"quantity": 12.0, "unit": "ounces", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Stock", "notes": null, "category": "pantry"}, {"quantity": 1.5, "unit": "cup", "item": "Mozzarella", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbsp", "item": "Sour Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}]'::jsonb, '["1", "Preheat oven to 425 degrees. Wash and dry all produce. Trim, peel, and cut carrots on a diagonal into ¼-inch-thick pieces. Dice potatoes into ½-inch pieces. Halve, peel, and thinly slice onion.", "2", "Toss carrots on a baking sheet with a drizzle of oil, salt, and pepper. Roast until browned and tender, 15-20 minutes.", "3", "Meanwhile, place potatoes in a medium pot with enough salted water to cover by 2 inches. Bring to a boil and cook until tender, 12-15 minutes. Drain and return potatoes to pot; cover to keep warm.", "4", "While potatoes cook, heat a drizzle of oil in a large pan over medium-high heat. Add onion and cook, stirring occasionally, until lightly browned and softened, 8-10 minutes. Sprinkle with 1 tsp sugar (2 tsp for 4 servings). Stir in stock concentrate and 2 TBSP water (¼ cup for 4); season with salt and pepper. Cook until jammy, 2-3 minutes more. Turn off heat; transfer to a small bowl. Wash out pan.", "5", "Pat chicken dry with paper towels; season all over with salt and pepper. Heat a drizzle of oil in pan used for onion over medium-high heat. Add chicken and cook until browned and cooked through, 5-6 minutes per side. In the last 1-2 minutes of cooking, top with caramelized onion and cheese. Cover pan until cheese melts. (If your pan doesn’t have a lid, cover with a baking sheet!)", "6", "Heat pot with drained potatoes over low heat; mash with sour cream, 2 TBSP butter (4 TBSP for 4 servings), salt, pepper, and a splash of water (or milk, for extra richness) until smooth. Divide chicken, roasted carrots, and mashed potatoes between plates."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/b5ft861583188991.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('general-tsos-chicken', 'General Tsos Chicken', 4, 0, 0, '{"calories": 188, "protein": 10.5, "carbs": 46.2, "fat": 8.1, "saturated_fat": 4.1, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.1, "sodium": 246.9, "potassium": 198.3, "fiber": 1.9, "sugar": 25.4, "vitamin_a": null, "vitamin_c": 2.0, "calcium": 41.4, "iron": 0.4}'::jsonb, ARRAY['chicken', 'chinese', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Breast", "notes": null, "category": "other"}, {"quantity": 0.75, "unit": "cup", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "Starch", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbs", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Onion Salt", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "Garlic Powder", "notes": null, "category": "produce"}, {"quantity": 0.75, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "cup", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 0.25, "unit": "cup", "item": "Duck Sauce", "notes": null, "category": "meat"}, {"quantity": 3.0, "unit": "tbs", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Honey", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Rice Vinegar", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tbs", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tbs", "item": "Gochujang", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Starch", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "clove", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Ginger", "notes": null, "category": "produce"}]'::jsonb, '["DIRECTIONS:", "STEP 1 - SAUCE", "In a bowl, add 2 Cups of water, 2 Tablespoon soy sauce, 2 Tablespoon white vinegar, sherry cooking wine, 1/4 Teaspoon white pepper, minced ginger, minced garlic, hot pepper, ketchup, hoisin sauce, and sugar.", "Mix together well and set aside.", "STEP 2 - MARINATING THE CHICKEN", "In a bowl, add the chicken, 1 pinch of salt, 1 pinch of white pepper, 2 egg whites, and 3 Tablespoon of corn starch", "STEP 3 - DEEP FRY THE CHICKEN", "Deep fry the chicken at 350 degrees for 3-4 minutes or until it is golden brown and loosen up the chicken so that they don''t stick together.", "Set the chicken aside.", "STEP 4 - STIR FRY", "Add the sauce to the wok and then the broccoli and wait until it is boiling.", "To thicken the sauce, whisk together 2 Tablespoon of cornstarch and 4 Tablespoon of water in a bowl and slowly add to your stir-fry until it''s the right thickness.", "Next add in the chicken and stir-fry for a minute and serve on a plate"]'::jsonb, 'https://www.skinnytaste.com/general-tsos-chicken/', 'https://www.themealdb.com/images/media/meals/1529444113.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('honey-balsamic-chicken-with-crispy-broccoli-potatoes', 'Honey Balsamic Chicken with Crispy Broccoli & Potatoes', 4, 0, 0, '{"calories": 201, "protein": 7.1, "carbs": 29.7, "fat": 9.9, "saturated_fat": 2.8, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.1, "sodium": 75.4, "potassium": 270.8, "fiber": 1.2, "sugar": 24.1, "vitamin_a": null, "vitamin_c": 5.8, "calcium": 29.2, "iron": 0.5}'::jsonb, ARRAY['chicken', 'american', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Broccoli", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Breast", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Balsamic Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Honey", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tbsp", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbsp", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbsp", "item": "Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["2 Servings", "1. Preheat oven to 425 degrees. Wash and dry all produce. Cut potatoes into 1/2-inch-thick wedges. Toss on one side of a baking sheet with a drizzle of oil, salt, and pepper. (For 4 servings, spread potatoes out across entire sheet.) Roast on top rack for 5 minutes (we''ll add the broccoli then).", "2. Meanwhile, cut broccoli florets into bite-size pieces, if necessary. Peel and finely chop garlic. In a small microwave-safe bowl, combine 1 TBSP olive oil (2 TBSP for 4 servings) and half the garlic. Microwave until garlic sizzles, 30 seconds.", "3. Once potatoes have roasted 5 minutes, remove sheet from oven and add broccoli to empty side; carefully toss with garlic oil, salt, and pepper. (For 4 servings, add broccoli to a second sheet.) Continue roasting until potatoes and broccoli are browned and crispy, 15-20 minutes more.", "4. While veggies roast, pat chicken dry with paper towels; season all over with salt and pepper. Heat a drizzle of oil in a large pan over medium-high heat. Add chicken and cook until browned and cooked through, 5-6 minutes per side. (If chicken browns too quickly, reduce heat to medium.) Turn off heat; set chicken aside to rest. Wash out pan.", "5. Heat pan used for chicken over medium-high heat. Add a drizzle of oil and remaining garlic; cook until fragrant, 30 seconds. Stir in vinegar, honey, stock concentrate, and 1/4 cup water (1/3 cup for 4 servings). Simmer until thick and glossy, 2-3 minutes. Remove from heat and stir in 1 TBSP butter (2 TBSP for 4). Season with salt and pepper.", "6. Return chicken to pan and turn to coat in glaze. Divide chicken, broccoli, and potatoes between plates. Spoon any remaining glaze over chicken and serve."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/kvbotn1581012881.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamaican-curry-chicken-recipe', 'Jamaican Curry Chicken Recipe', 4, 0, 0, '{"calories": 261, "protein": 3.5, "carbs": 416.0, "fat": 0.3, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 10967.9, "potassium": 568.0, "fiber": 17.8, "sugar": 28.4, "vitamin_a": null, "vitamin_c": 17.6, "calcium": 248.7, "iron": 17.7}'::jsonb, ARRAY['chicken', 'jamaican', 'themealdb', 'nutrition-generated', 'baking'], '[{"quantity": 2.0, "unit": "lbs", "item": "Chicken Thighs", "notes": null, "category": "meat"}, {"quantity": 2.5, "unit": "tbs", "item": "Curry Powder", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "All-purpose Seasoning", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cloves", "item": "Chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Scotch Bonnet", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Russet Potato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Equipment", "Dutch Oven", "Instructions", "Add chicken thighs, all-purpose seasoning, 1 tablespoon of curry powder, onion, green onions, green pepper, garlic cloves, scotch bonnet pepper (if using), and thyme to a large bowl and combine, making sure all chicken pieces are covered with the seasoning. Cover and refrigerate for at least 1 hour or up to overnight.", "One the chicken is done marinating, remove onions, peppers, and garlic cloves from chicken and set aside.", "Heat olive oil in a large heavy bottom pot over medium heat. Add remaining curry powder and stir, cooking for about 20-30 seconds. Add onions, green pepper, garlic cloves, thyme, and scotch bonnet pepper (if using) to pot and stir until onions have softened, about 3-5 minutes. If your onions and peppers are looking dry, add about 1 tablespoon of water.", "Add chicken and ¼ cup of water to the pot. Cover and reduce heat to medium low. Cook, stirring occasionally, for 30-35 minutes.", "When there is about 15 minutes remaining, stir in potato and continue to cook covered.", "Once chicken is cooked and potatoes are softened, remove from heat. Salt and pepper to taste."]'::jsonb, 'https://www.myforkinglife.com/jamaican-curry-chicken/', 'https://www.themealdb.com/images/media/meals/o5fuq51764789643.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jerk-chicken-with-rice-peas', 'Jerk chicken with rice & peas', 4, 0, 0, '{"calories": 348, "protein": 23.8, "carbs": 50.4, "fat": 16.0, "saturated_fat": 6.7, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.6, "sodium": 276.9, "potassium": 125.8, "fiber": 13.6, "sugar": 2.8, "vitamin_a": null, "vitamin_c": 3.0, "calcium": 109.2, "iron": 5.3}'::jsonb, ARRAY['chicken', 'jamaican', 'themealdb', 'nutrition-generated', 'dessert', 'baking', 'grilling', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Thighs", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "bunch", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "chopped Ginger", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1 Lime", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tbs", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 200.0, "unit": "g", "item": "Basmati Rice", "notes": null, "category": "grains"}, {"quantity": 400.0, "unit": "g", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "bunch", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 800.0, "unit": "g", "item": "Kidney Beans", "notes": null, "category": "pantry"}]'::jsonb, '["To make the jerk marinade, combine all the ingredients in a food processor along with 1 tsp salt, and blend to a purée. If you’re having trouble getting it to blend, just keep turning off the blender, stirring the mixture, and trying again. Eventually it will start to blend up – don’t be tempted to add water, as you want a thick paste.", "Taste the jerk mixture for seasoning – it should taste pretty salty, but not unpleasantly, puckering salty. You can now throw in more chillies if it’s not spicy enough for you. If it tastes too salty and sour, try adding in a bit more brown sugar until the mixture tastes well balanced.", "Make a few slashes in the chicken thighs and pour the marinade over the meat, rubbing it into all the crevices. Cover and leave to marinate overnight in the fridge.", "If you want to barbecue your chicken, get the coals burning 1 hr or so before you’re ready to cook. Authentic jerked meats are not exactly grilled as we think of grilling, but sort of smoke-grilled. To get a more authentic jerk experience, add some wood chips to your barbecue, and cook your chicken over slow, indirect heat for 30 mins. To cook in the oven, heat to 180C/160C fan/gas 4. Put the chicken pieces in a roasting tin with the lime halves and cook for 45 mins until tender and cooked through.", "While the chicken is cooking, prepare the rice & peas. Rinse the rice in plenty of cold water, then tip it into a large saucepan with all the remaining ingredients except the kidney beans. Season with salt, add 300ml cold water and set over a high heat. Once the rice begins to boil, turn it down to a medium heat, cover and cook for 10 mins.", "Add the beans to the rice, then cover with a lid. Leave off the heat for 5 mins until all the liquid is absorbed. Squeeze the roasted lime over the chicken and serve with the rice & peas, and some hot sauce if you like it really spicy."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/2369635/jerk-chicken-with-rice-and-peas', 'https://www.themealdb.com/images/media/meals/tytyxu1515363282.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('kabse', 'kabse', 4, 0, 0, '{"calories": 514, "protein": 27.0, "carbs": 72.1, "fat": 10.2, "saturated_fat": 5.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 583.1, "potassium": 223.8, "fiber": 21.4, "sugar": 9.2, "vitamin_a": null, "vitamin_c": 14.0, "calcium": 257.0, "iron": 16.8}'::jsonb, ARRAY['chicken', 'saudi arabian', 'themealdb', 'nutrition-generated', 'baking'], '[{"quantity": 400.0, "unit": "g", "item": "Chicken", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "cup", "item": "Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sweetcorn", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Raisins", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Turmeric", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Kabse Spice", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Black Pepper", "notes": null, "category": "produce"}]'::jsonb, '["1", "Caramelize the chicken with olive oil then add a maggi cube and boil it for around 30 minutes.", "2", "In another pot, add all the veggies and caramelize them till they are soft.", "3", "Once everything is done, add the rice, raisins & spices to the veggies and add 2 and a half cups of water for the rice to cook.", "4", "Once the rice is done put everything in the oven."]'::jsonb, 'https://cookpad.com/eng/recipes/17108731?ref=search&search_term=saudi+arabia', 'https://www.themealdb.com/images/media/meals/utqnjv1763598650.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('katsu-chicken-curry', 'Katsu Chicken curry', 4, 0, 0, '{"calories": 630, "protein": 13.7, "carbs": 43.8, "fat": 61.2, "saturated_fat": 11.7, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 13.3, "sodium": 411.7, "potassium": 495.3, "fiber": 2.9, "sugar": 14.2, "vitamin_a": null, "vitamin_c": 5.8, "calcium": 62.7, "iron": 0.9}'::jsonb, ARRAY['chicken', 'japanese', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "to 1cm thickness chicken breast", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tablespoons", "item": "plain flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "egg", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "fine breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 230.0, "unit": "ml", "item": "frying vegetable oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "sunflower oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "cloves garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "carrot", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "plain flour", "notes": null, "category": "grains"}, {"quantity": 4.0, "unit": "teaspoons", "item": "curry powder", "notes": null, "category": "spices"}, {"quantity": 600.0, "unit": "ml", "item": "chicken stock", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "teaspoons", "item": "honey", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "teaspoons", "item": "soy sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "teaspoon", "item": "garam masala", "notes": null, "category": "spices"}]'::jsonb, '["Prep:15min  ›  Cook:30min  ›  Ready in:45min", "For the curry sauce: Heat oil in medium non-stick saucepan, add onion and garlic and cook until softened. Stir in carrots and cook over low heat for 10 to 12 minutes.", "Add flour and curry powder; cook for 1 minute. Gradually stir in stock until combined; add honey, soy sauce and bay leaf. Slowly bring to the boil.", "Turn down heat and simmer for 20 minutes or until sauce thickens but is still of pouring consistency. Stir in garam masala. Pour the curry sauce through a sieve; return to saucepan and keep on low heat until ready to serve.", "For the chicken: Season both sides of chicken breasts with salt and pepper. Place flour, egg and breadcrumbs in separate bowls and arrange in a row. Coat the chicken breasts in flour, then dip them into the egg, then coat in breadcrumbs, making sure you cover both sides.", "Heat oil in large frying pan over medium-high heat. Place chicken into hot oil and cook until golden brown, about 3 or 4 minutes each side. Once cooked, place on kitchen paper to absorb excess oil.", "Pour curry sauce over chicken, serve with white rice and enjoy!"]'::jsonb, 'http://allrecipes.co.uk/recipe/29578/chicken-katsu-curry.aspx', 'https://www.themealdb.com/images/media/meals/vwrpps1503068729.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('kentucky-fried-chicken', 'Kentucky Fried Chicken', 4, 0, 0, '{"calories": 296, "protein": 31.0, "carbs": 85.4, "fat": 0.8, "saturated_fat": 0.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1833.7, "potassium": 239.8, "fiber": null, "sugar": 3.1, "vitamin_a": null, "vitamin_c": null, "calcium": 26.0, "iron": 1.6}'::jsonb, ARRAY['chicken', 'american', 'themealdb', 'nutrition-generated', 'dessert', 'baking'], '[{"quantity": 1.0, "unit": "whole", "item": "Chicken", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "quarts", "item": "neutral frying Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "White", "notes": null, "category": "other"}, {"quantity": 1.5, "unit": "cups", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "paprika", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "teaspoons", "item": "onion salt", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "chili powder", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "teaspoon", "item": "black pepper", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "celery salt", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "sage", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "teaspoon", "item": "garlic powder", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "allspice", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "teaspoon", "item": "oregano", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "teaspoon", "item": "basil", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "marjoram", "notes": null, "category": "spices"}]'::jsonb, '["Preheat fryer to 350°F. Thoroughly mix together all the spice mix ingredients.", "Combine spice mix with flour, brown sugar and salt.", "Dip chicken pieces in egg white to lightly coat them, then transfer to flour mixture. Turn a few times and make sure the flour mix is really stuck to the chicken. Repeat with all the chicken pieces.", "Let chicken pieces rest for 5 minutes so crust has a chance to dry a bit.", "Fry chicken in batches. Breasts and wings should take 12-14 minutes, and legs and thighs will need a few more minutes. Chicken pieces are done when a meat thermometer inserted into the thickest part reads 165°F.", "Let chicken drain on a few paper towels when it comes out of the fryer. Serve hot."]'::jsonb, 'http://www.tablespoon.com/recipes/copycat-kfc-original-style-chicken/97c93d14-9d8c-4bc7-96dc-1e0b37e4fcaa', 'https://www.themealdb.com/images/media/meals/40r49m1763197022.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
