rry if it sticks to the bottom of the wok - it will char and which adds authentic flavour.", "Add noodles, Chinese broccoli leaves and sauce. Gently mix together until the noodles are stained dark and leaves are wilted. Serve immediately!"]'::jsonb, NULL, 'https://www.themealdb.com/images/media/meals/uuuspp1468263334.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('panang-chicken-curry-kaeng-panang-gai', 'Panang chicken curry (kaeng panang gai)', 4, 0, 0, '{"calories": 742, "protein": 27.3, "carbs": 54.9, "fat": 36.2, "saturated_fat": 12.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1603.7, "potassium": 308.5, "fiber": 40.5, "sugar": 5.7, "vitamin_a": null, "vitamin_c": 5.9, "calcium": 862.0, "iron": 21.8}'::jsonb, ARRAY['chicken', 'thai', 'themealdb', 'nutrition-generated', 'dessert'], '[{"quantity": 400.0, "unit": "ml", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbsp", "item": "1-2tbsp Panang Curry Paste", "notes": null, "category": "spices"}, {"quantity": 200.0, "unit": "g", "item": "Chicken Breast", "notes": null, "category": "meat"}, {"quantity": 100.0, "unit": "g", "item": "Green Beans", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbsp", "item": "2-3 tbsp Fish Sauce", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbsp", "item": "1-2tbsp Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "lime leaves", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Basil Leaves", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Boiled Jasmine Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chillies", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Shrimp Paste", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "cloves", "item": "Chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Galangal", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Lemongrass", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 2 Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Ground Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Ground Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Peanuts", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "First, make the curry paste. Use a pestle and mortar to pound together the dried and fresh chillies, shrimp paste, garlic, galangal, lemongrass, lime zest, white pepper, coriander, cumin, nutmeg and peanuts, plus 1 tsp salt. You should have a rough paste. Alternatively, add all the ingredients to a food processor along with 2-3 tbsp of coconut milk and pulse until you have a paste. Store in a lidded jar in the fridge. Will keep for up to two weeks.", "step 2", "Add 2-3 tbsp of the thick part of the coconut milk into a saucepan over a medium-high heat. When the coconut milk starts bubbling, add 1-2 tbsp of the curry paste and stir well for about 1 min, until fragrant.", "step 3", "Stir in the chicken and let it cook for about 3-4 mins until beginning to brown all over. Follow with the French beans and stir well.", "step 4", "Season with the fish sauce and sugar, then add the rest of coconut milk. Mix well, add half the makrut lime leaves and simmer for 3-5 mins until the chicken is cooked through. Taste and add more sugar or fish sauce if necessary – it should be salty and nutty, and the sweetness should come through. Add the Thai basil leaves, give it a quick mix and take off the heat. Serve with steamed jasmine rice, garnished with the sliced chilli and the rest of the makrut lime leaves."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/panang-chicken-curry-kaeng-panang-gai', 'https://www.themealdb.com/images/media/meals/0dhtwr1763371444.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('piri-piri-chicken-and-slaw', 'Piri-piri chicken and slaw', 4, 0, 0, '{"calories": 566, "protein": 84.7, "carbs": 22.8, "fat": 13.0, "saturated_fat": 6.0, "polyunsaturated_fat": null, "monounsaturated_fat": 4.5, "sodium": 825.8, "potassium": 609.0, "fiber": 3.9, "sugar": 10.5, "vitamin_a": null, "vitamin_c": 15.2, "calcium": 62.2, "iron": 1.4}'::jsonb, ARRAY['chicken', 'portuguese', 'themealdb', 'nutrition-generated', 'salad', 'baking'], '[{"quantity": 1.5, "unit": "kg", "item": "Chicken", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Dried Oregano", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tbs", "item": "Red Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Beetroot", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Mayonnaise", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Greek Yogurt", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "Red Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin Seeds", "notes": null, "category": "pantry"}]'::jsonb, '["STEP 1", "Whizz together all of the marinade ingredients in a small food processor. Rub the marinade onto the chicken and leave for 1 hour at room temperature.", "STEP 2", "Heat the oven to 190C/fan 170C/gas 5. Put the chicken in a roasting tray and cook for 1 hour 20 minutes. Rest under loose foil for 20 minutes. While the chicken is resting, mix together the slaw ingredients and season. Serve the chicken with slaw, fries and condiments."]'::jsonb, 'https://www.olivemagazine.com/recipes/family/piri-piri-chicken-and-winter-slaw/', 'https://www.themealdb.com/images/media/meals/hglsbl1614346998.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pollo-en-pepitoria', 'Pollo en pepitoria', 4, 0, 0, '{"calories": 975, "protein": 39.2, "carbs": 95.8, "fat": 101.1, "saturated_fat": 34.7, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 4.8, "sodium": 1206.3, "potassium": 998.0, "fiber": 7.5, "sugar": 21.4, "vitamin_a": 318.0, "vitamin_c": 4.0, "calcium": 214.5, "iron": 8.4}'::jsonb, ARRAY['chicken', 'spanish', 'themealdb', 'nutrition-generated', 'soup'], '[{"quantity": 1.0, "unit": "serving", "item": "Pinch Saffron", "notes": null, "category": "spices"}, {"quantity": 4.0, "unit": "tbsp", "item": "Extra Virgin Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 35.0, "unit": "g", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 30.0, "unit": "g", "item": "Stale bread", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tbs", "item": "chopped Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thighs", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 250.0, "unit": "ml", "item": "Dry sherry", "notes": null, "category": "other"}, {"quantity": 350.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Stick", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Cloves", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Almonds", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Put the saffron in a small bowl with 75ml of just-boiled water. Stir and set aside. Heat 2 tbsp of the oil in a broad, shallow casserole dish. Cook the garlic until pale gold in colour, then add the blanched almonds and bread, and continue to fry until everything is golden. Tip into a food processor with some salt and pepper and the parsley, and whizz together.", "step 2", "Heat 2 more tbsp of the oil in the pan and brown the chicken all over, seasoning as you cook. Put in a bowl and set aside.", "step 3", "Remove all but about 2 tbsp of chicken fat from the pan and cook the onion, carrot and celery until golden. Add the sherry, stirring to dislodge any brown bits that have stuck to the pan. Pour in the stock and the saffron (with its water), and bring to the boil, then turn the heat down to a simmer. Add the spices and bay leaves, and put the chicken back in the pan with any juices. Season and gently cook the chicken for about 40 mins with the lid on.", "step 4", "Transfer the chicken to a bowl again, leaving the sauce in the pan, and cover with foil to keep warm. Remove the yolks from the eggs and roughly chop the whites. Mash the egg yolks in a small bowl and gradually mix in a couple of tbsp of the sauce. Bring the remaining sauce to the boil to reduce a bit (you want it to just coat the chicken), then turn the heat down. Remove the bay and cinnamon stick. Add the egg yolks and cook for a few mins until the mixture has thickened. Stir in the almond mixture that you made earlier (this will thicken the sauce, too). Put the chicken back in the pan and heat it for about 3 mins, spooning the sauce over it. Season to taste.", "step 5", "Scatter over the extra parsley, the almonds pieces and the chopped egg whites (if you’re going to use them). You can serve this straight from the dish with some rice, if you like."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/pollo-en-pepitoria', 'https://www.themealdb.com/images/media/meals/li30ck1763281992.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('potato-gratin-with-chicken', 'Potato Gratin with Chicken', 4, 0, 0, '{"calories": 626, "protein": 24.7, "carbs": 54.7, "fat": 46.1, "saturated_fat": 13.8, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.1, "sodium": 552.9, "potassium": 1456.5, "fiber": 3.7, "sugar": 2.4, "vitamin_a": 70.8, "vitamin_c": 45.1, "calcium": 68.2, "iron": 3.4}'::jsonb, ARRAY['chicken', 'italian', 'themealdb', 'nutrition-generated', 'breakfast', 'soup', 'baking', 'grilling'], '[{"quantity": 800.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Creme Fraiche", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Topping Parmesan", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Breasts", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Topping Spinach", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Topping Peas", "notes": null, "category": "produce"}]'::jsonb, '["15 minute potato gratin with chicken and bacon greens: a gratin always seems more effort and more indulgent than ordinary boiled or roasts, but it doesn''t have to take 45mins, it''s nice for a change and you can control the calorie content by going with full fat to low fat creme fraiche.", "(It''s always tastes better full fat though obviously!) to serve 4: use 800g of potatoes, finely slice and boil in a pan for about 5-8 mins till firmish, not soft.", "Finely slice 3 onions and place in an oven dish with 2 tblsp of olive oil and 100ml of chicken stock.", "Cook till the onions are soft then drain the potatoes and pour onto the onions.", "Season and spoon over cream or creme fraiche till all is covered but not swimming.", "Grate Parmesan over the top then finish under the grill till nicely golden.", "serve with chicken and bacon, peas and spinach."]'::jsonb, 'https://www.instagram.com/p/BHxR7hYBJ6P', 'https://www.themealdb.com/images/media/meals/qwrtut1468418027.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('poulet-roti-a-lalgerienne-algerian-roast-chicken', 'Poulet Roti a l''Algerienne (Algerian Roast Chicken)', 4, 0, 0, '{"calories": 132, "protein": 8.1, "carbs": 355.0, "fat": 0.6, "saturated_fat": 0.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 10099.2, "potassium": 4.5, "fiber": 0.6, "sugar": 8.2, "vitamin_a": null, "vitamin_c": null, "calcium": 8.5, "iron": 0.9}'::jsonb, ARRAY['chicken', 'algerian', 'themealdb', 'nutrition-generated', 'baking'], '[{"quantity": 1.0, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 5.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Balsamic Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Dijon Mustard", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "cloves", "item": "Crushed Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Cayenne Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Chicken", "notes": null, "category": "meat"}]'::jsonb, '["Preheat oven to 350 degrees F (175 degrees C).", "Mix water, onion, olive oil, balsamic vinegar, Dijon mustard, garlic, black pepper, cayenne pepper, and salt together in a roasting dish. Add chicken; turn until well coated with mixture.", "Bake in the preheated oven until an instant-read thermometer inserted into the thickest part of the thigh, near the bone, reads 165 degrees F (74 degrees C), about 1 hour 30 minutes."]'::jsonb, 'https://www.allrecipes.com/recipe/258886/poulet-roti-a-lalgerienne-algerian-roast-chicken/', 'https://www.themealdb.com/images/media/meals/nlxald1764112200.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('rappie-pie', 'Rappie Pie', 4, 0, 0, '{"calories": 1370, "protein": 97.1, "carbs": 188.3, "fat": 30.4, "saturated_fat": 17.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1624.0, "potassium": 4239.2, "fiber": 16.1, "sugar": 9.4, "vitamin_a": null, "vitamin_c": 190.4, "calcium": 736.8, "iron": 8.8}'::jsonb, ARRAY['chicken', 'canadian', 'themealdb', 'nutrition-generated', 'dessert', 'soup', 'baking'], '[{"quantity": 2.0, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "qt", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.5, "unit": "kg", "item": "Chicken Breast", "notes": null, "category": "meat"}, {"quantity": 4.0, "unit": "kg", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbsp", "item": "Black Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Preheat oven to 400 degrees F (200 degrees C). Grease a 10x14x2-inch baking pan.", "Heat margarine in a skillet over medium heat; stir in onion. Cook and stir until onion has softened and turned translucent, about 5 minutes. Reduce heat to low and continue to cook and stir until onion is very tender and dark brown, about 40 minutes more.", "Bring chicken broth to a boil in a large pot; stir in chicken breasts, reduce heat, and simmer until chicken is no longer pink at the center, about 20 minutes. Remove from heat. Remove chicken breasts to a plate using a slotted spoon; reserve broth.", "Juice potatoes with an electric juicer; place dry potato flesh into a bowl and discard juice. Stir salt and pepper into potatoes; stir in enough reserved broth to make the mixture the consistency of oatmeal. Set remaining broth aside.", "Spread half of potato mixture evenly into the prepared pan. Lay cooked chicken breast evenly over potatoes; scatter caramelized onion evenly over chicken. Spread remaining potato mixture over onions and chicken to cover.", "Bake in the preheated oven until golden brown, about 1 hour. Reheat chicken broth; pour over individual servings as desired."]'::jsonb, 'http://allrecipes.com/recipe/234025/rappie-pie/', 'https://www.themealdb.com/images/media/meals/ruwpww1511817242.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('red-curry-chicken-kebabs', 'Red curry chicken kebabs', 4, 0, 0, '{"calories": 242, "protein": 9.1, "carbs": 23.4, "fat": 15.7, "saturated_fat": 3.0, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.1, "sodium": 785.4, "potassium": 131.8, "fiber": 1.2, "sugar": 1.2, "vitamin_a": 8.0, "vitamin_c": 3.6, "calcium": 90.0, "iron": 2.9}'::jsonb, ARRAY['chicken', 'thai', 'themealdb', 'nutrition-generated', 'grilling', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Breasts", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Thai Red Curry Paste", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Courgettes", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "thin wedges Red Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Lime", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Fire up the barbecue or heat a griddle pan to high. Tip chicken, curry paste and coconut milk into a bowl, then mix well until the chicken is evenly coated. Thread vegetables and chicken onto skewers. Cook the skewers on the barbecue or griddle for 5-8 mins, turning every so often, until the chicken is cooked through and charred. Serve with herby rice, salad and a lime half to squeeze over."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/red-curry-chicken-kebabs', 'https://www.themealdb.com/images/media/meals/prjve31763486864.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('roasted-chicken-with-creamy-walnut-sauce', 'Roasted chicken with creamy walnut sauce', 4, 0, 0, '{"calories": 425, "protein": 18.2, "carbs": 33.5, "fat": 35.0, "saturated_fat": 4.9, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 5.3, "sodium": 514.2, "potassium": 412.9, "fiber": 4.6, "sugar": 5.6, "vitamin_a": null, "vitamin_c": 1.2, "calcium": 255.6, "iron": 2.7}'::jsonb, ARRAY['chicken', 'turkish', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Thighs", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 150.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 175.0, "unit": "g", "item": "Walnuts", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 50.0, "unit": "ml", "item": "Single Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander", "notes": null, "category": "spices"}]'::jsonb, '["step 1", "Heat oven to 200C/180C fan/gas 6. In a roasting tin, toss together the chicken, cumin, paprika, 1 tbsp olive oil and seasoning. Cook for 40 mins until the chicken is crisp and cooked through.", "step 2", "Meanwhile, tear up 1 pitta bread and place in a small bowl. Pour over a couple of tbsp chicken stock and leave to soak. Dry-fry the walnuts in a frying pan for about 3 mins until golden and toasted. Set aside. Heat the remaining oil in the pan and cook the onion and garlic until softened. Place the softened pitta bread, onion mixture and most of the nuts into a blender. Pour over the rest of the chicken stock and whizz together until a rough paste forms. Return the mixture to the pan. Add the cream and lemon juice, season and keep warm.", "step 3", "When the chicken is cooked, arrange on a platter. Stir the coriander through the sauce and spoon into a bowl. Roughly chop the remaining walnuts and scatter over the chicken. Toast the pittas, cut into wedges and serve alongside"]'::jsonb, 'https://www.bbcgoodfood.com/recipes/roasted-chicken-creamy-walnut-sauce', 'https://www.themealdb.com/images/media/meals/ro8mzj1763800655.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('rosol-polish-chicken-soup', 'Rosol (Polish Chicken Soup)', 4, 0, 0, '{"calories": 24, "protein": 5.1, "carbs": 6.9, "fat": 0.1, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 239.5, "potassium": 326.8, "fiber": 2.4, "sugar": 2.1, "vitamin_a": null, "vitamin_c": 9.8, "calcium": 67.0, "iron": 0.6}'::jsonb, ARRAY['chicken', 'polish', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Chicken Legs", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leek", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "1/4  Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "whole", "item": "Cloves", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Dill", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Salt", "notes": null, "category": "pantry"}]'::jsonb, '["Add chicken to a large Dutch oven or stock pot", "Cover with water", "Bring to a boil and simmer for 2 to 2 1/2 hours, skimming any impurities off the top to insure a clear broth", "If your pot is big enough, add the vegetables and spices for the last hour of the cooking time", "My Dutch oven wasn’t big enough to hold everything, just the chicken and other bones filled the pot, so I cooked the meat/bones for the full cooking time, then removed them, and cooked the vegetables and spices separately", "Strain everything out of the broth", "Bone the chicken, pulling the meat into large chunks", "Slice the carrots", "Return the chicken and carrots to the broth", "Cook noodles according to package instructions if you’re using them", "Add noodles to bowl and then top with hot soup"]'::jsonb, 'https://polishhousewife.com/rosol-polish-chicken-soup/', 'https://www.themealdb.com/images/media/meals/lx1kkj1593349302.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('shawarma', 'Shawarma', 4, 0, 0, '{"calories": 915, "protein": 43.2, "carbs": 50.3, "fat": 52.0, "saturated_fat": 23.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 279.5, "potassium": 34.8, "fiber": 2.9, "sugar": 41.4, "vitamin_a": null, "vitamin_c": null, "calcium": 82.2, "iron": 1.6}'::jsonb, ARRAY['chicken', 'egyptian', 'themealdb', 'nutrition-generated', 'salad', 'grilling'], '[{"quantity": 1.0, "unit": "kg", "item": "Chicken Thighs", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tbs", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tbs", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tbs", "item": "Cardamom", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Cayenne Pepper", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tbs", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Greek Yogurt", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Splash Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sliced Lettuce", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sliced Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}]'::jsonb, '["Combine the marinade ingredients in a large ziplock bag (or bowl).", "Add the chicken and use your hands to make sure each piece is coated. If using a ziplock bag, I find it convenient to close the bag then massage the bag to disperse the rub all over each chicken piece.", "Marinate overnight or up to 24 hours.", "Combine the Yoghurt Sauce ingredients in a bowl and mix. Cover and put in the fridge until required (it will last for 3 days in the fridge).", "Heat grill/BBQ (or large heavy based pan on stove) on medium high. You should not need to oil it because the marinade has oil in it and also thigh fillets have fat. But if you are worried then oil your hotplate/grill. (See notes for baking)", "Place chicken on the grill and cook the first side for 4 to 5 minutes until nicely charred, then turn and cook the other side for 3 to 4 minutes (the 2nd side takes less time).", "Remove chicken from the grill and cover loosely with foil. Set aside to rest for 5 minutes.", "TO SERVE", "Slice chicken and pile onto platter alongside flatbreads, Salad and the Yoghurt Sauce.", "To make a wrap, get a piece of flatbread and smear with Yoghurt Sauce. Top with a bit of lettuce and tomato and Chicken Shawarma. Roll up and enjoy!"]'::jsonb, 'https://www.recipetineats.com/chicken-sharwama-middle-eastern/', 'https://www.themealdb.com/images/media/meals/kcv6hj1598733479.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('smoky-chicken-skewers', 'Smoky chicken skewers', 4, 0, 0, '{"calories": 0, "protein": 4.7, "carbs": 0.0, "fat": 2.0, "saturated_fat": 0.4, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.6, "sodium": 15.6, "potassium": 68.0, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": 1.4, "iron": 0.2}'::jsonb, ARRAY['chicken', 'turkish', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Thighs", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Fennel Seeds", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "sweet smoked paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Red Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Smoky Aïoli", "notes": null, "category": "other"}]'::jsonb, '["step 1", "You need 15 skewers: if wooden, soak in water for 10 mins. Cut chicken into 3cm pieces and place in a bowl. Add 1 tbsp olive oil, the spices, garlic and vinegar, toss well and season. You can do this up to a day before and refrigerate.", "step 2", "Thread 2-3 pieces on each skewer. Pour remaining oil in a frying pan or rub onto a griddle pan. Get the pan hot and sear the chicken for 3-4 mins on each side – you may have to do this in batches, keeping the cooked skewers warm in a low oven. Serve with smoky aïoli if you like."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/smoky-chicken-skewers', 'https://www.themealdb.com/images/media/meals/3um6il1763794322.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spanish-beans-with-chicken-chorizo', 'Spanish beans with chicken & chorizo', 4, 0, 0, '{"calories": 558, "protein": 30.4, "carbs": 41.8, "fat": 36.0, "saturated_fat": 8.7, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.6, "sodium": 1574.8, "potassium": 68.0, "fiber": 6.5, "sugar": 4.2, "vitamin_a": null, "vitamin_c": 13.3, "calcium": 78.4, "iron": 4.1}'::jsonb, ARRAY['chicken', 'spanish', 'themealdb', 'nutrition-generated', 'vegetarian', 'vegan'], '[{"quantity": 300.0, "unit": "g", "item": "Pinto Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Sprigs of", "notes": "fresh Thyme", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Bay Leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thighs", "notes": null, "category": "other"}, {"quantity": 250.0, "unit": "g", "item": "Jersey Royal Potatoes", "notes": null, "category": "produce"}, {"quantity": 250.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Spinach", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Soak the beans for at least 4 hrs or overnight in a large bowl with plenty of water to cover. Next day, rinse and drain, then put in a large heavy based pan with the onion, paprika, herb bundle and chicken. Pour over enough water or stock to cover, bring to the boil, then reduce the heat, cover and simmer for 45 mins.", "step 2", "Remove the chicken to a plate, then add the potatoes and chorizo to the pan. Continue cooking for 30 mins until the beans and potatoes are tender.", "step 3", "Discard the skin and bones from the chicken and tear into large chunks. Return the chicken to the pan with the spinach and simmer for 5 mins."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/spanish-beans-chicken-chorizo', 'https://www.themealdb.com/images/media/meals/bpkxtw1763332446.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spanish-chicken', 'Spanish Chicken', 4, 0, 0, '{"calories": 74, "protein": 9.0, "carbs": 2.8, "fat": 7.0, "saturated_fat": 1.9, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.6, "sodium": 145.3, "potassium": 242.9, "fiber": 0.6, "sugar": 0.2, "vitamin_a": null, "vitamin_c": 2.0, "calcium": 5.7, "iron": 0.3}'::jsonb, ARRAY['chicken', 'spanish', 'themealdb', 'nutrition-generated', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Thighs", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "thinly Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Zest and juice of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Parsley", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Heat oven to 190C/170C fan/gas 5. Put all the ingredients into a large, wide ovenproof dish. Mix everything together with your hands and season.", "step 2", "Bake for 45 mins, stirring the onions after 20 mins, until the chicken is golden and the onions tender. Serve with rice."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/spanish-chicken', 'https://www.themealdb.com/images/media/meals/pqulvm1763282839.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spanish-chicken-pie', 'Spanish chicken pie', 4, 0, 0, '{"calories": 340, "protein": 25.5, "carbs": 68.6, "fat": 2.4, "saturated_fat": 0.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 241.8, "potassium": 1490.2, "fiber": 6.3, "sugar": 3.5, "vitamin_a": 47.8, "vitamin_c": 117.0, "calcium": 71.6, "iron": 3.0}'::jsonb, ARRAY['chicken', 'spanish', 'themealdb', 'nutrition-generated', 'dessert', 'baking'], '[{"quantity": 1.0, "unit": "kg", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "teaspoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 800.0, "unit": "g", "item": "Tinned Tomatos", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Chicken", "notes": null, "category": "meat"}, {"quantity": 140.0, "unit": "g", "item": "Roasted pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Green Olives", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Heat oven to 200C/fan 180C/gas 6. Boil the potatoes for 15-20 mins until tender. Drain, return to the pan, then mash with some seasoning and 2 tsp of the paprika.", "step 2", "Meanwhile, heat the oil in a large pan, then fry the onions and garlic for a few mins until softened. Stir in the remaining paprika for 1 min, add the tomatoes , then, bring to a simmer. Tip into a large ovenproof dish, then stir in the chicken, peppers, olives and some seasoning.", "step 3", "Spoon over the mash, then bake for 15 mins until the mash is golden on top and the sauce is bubbling."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/spanish-chicken-pie', 'https://www.themealdb.com/images/media/meals/8ovxf41763253962.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spiced-smoky-barbecued-chicken', 'Spiced smoky barbecued chicken', 4, 0, 0, '{"calories": 256, "protein": 10.5, "carbs": 20.2, "fat": 20.4, "saturated_fat": 3.3, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.6, "sodium": 331.1, "potassium": 212.2, "fiber": 1.7, "sugar": 2.5, "vitamin_a": null, "vitamin_c": 1.2, "calcium": 16.7, "iron": 1.6}'::jsonb, ARRAY['chicken', 'australian', 'themealdb', 'nutrition-generated', 'grilling', 'vegetarian', 'vegan'], '[{"quantity": 2.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Juice/zest of one Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Curry Powder", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Chilli Flakes", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Thighs", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Rosemary", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Rosemary", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Make the marinade. Smash the garlic with a little salt using a pestle and mortar. Add the lemon zest and juice, the spice mix, chilli, oil and a good grinding of black pepper. Mix to a paste. This can be done in a mini food processor.", "step 2", "Toss the chicken in the marinade and set aside while you light the barbecue. When the barbecue’s hot, lay the bunches of herbs on the grid and put the chicken, skin side up, on top. Close the lid, if your barbecue has one, and cook the chicken on the smouldering herbs for about 10 minutes until the meat starts to colour. Turn the chicken and continue to cook for a further 20-30 minutes, turning as necessary, until it is slightly charred from the burnt herbs and cooked through to the bone."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/spiced-smoky-barbecued-chicken', 'https://www.themealdb.com/images/media/meals/a08uqk1761848682.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sticky-chicken', 'Sticky Chicken', 4, 0, 0, '{"calories": 252, "protein": 7.9, "carbs": 5.8, "fat": 24.8, "saturated_fat": 3.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1644.7, "potassium": 61.0, "fiber": null, "sugar": 4.3, "vitamin_a": null, "vitamin_c": null, "calcium": 2.1, "iron": 0.2}'::jsonb, ARRAY['chicken', 'australian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "drumsticks", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Honey", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "Dijon Mustard", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Make 3 slashes on each of the drumsticks. Mix together the soy, honey, oil, tomato purée and mustard. Pour this mixture over the chicken and coat thoroughly. Leave to marinate for 30 mins at room temperature or overnight in the fridge. Heat oven to 200C/fan 180C/gas 6.", "step 2", "Tip the chicken into a shallow roasting tray and cook for 35 mins, turning occasionally, until the chicken is tender and glistening with the marinade."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/sticky-chicken', 'https://www.themealdb.com/images/media/meals/cj56fs1762340001.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('stir-fried-chicken-with-chillies-basil', 'Stir-fried chicken with chillies & basil', 4, 0, 0, '{"calories": 260, "protein": 24.4, "carbs": 13.9, "fat": 2.0, "saturated_fat": 1.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 393.3, "potassium": null, "fiber": 36.1, "sugar": 3.8, "vitamin_a": null, "vitamin_c": 20.0, "calcium": 881.0, "iron": 19.3}'::jsonb, ARRAY['chicken', 'thai', 'themealdb', 'nutrition-generated', 'dessert'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 450.0, "unit": "g", "item": "Chicken", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Shallots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Basil Leaves", "notes": null, "category": "produce"}]'::jsonb, '["Heat a wok or large frying pan until it is very hot, then add 1 tbsp of the oil. When it is very hot, add the chicken and stir-fry over a high heat for 8-10 minutes, until browned all over. Using a slotted spoon, take the chicken from the pan and set aside.", "step 2", "Reheat the wok and add the remaining oil. Toss in the garlic and shallots and stir fry for 3 minutes, until golden brown.", "step 3", "Return the chicken to the wok and add the chillies, fish sauce, dark soy sauce and sugar. Stir fry over a high heat for a further 8-10 minutes or until the chicken is cooked through. Stir in the basil leaves and serve at once."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/ken-homs-stir-fried-chicken-chillies-basil', 'https://www.themealdb.com/images/media/meals/el64dy1763483009.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sweet-and-sour-chicken', 'Sweet and Sour Chicken', 4, 0, 0, '{"calories": 471, "protein": 19.8, "carbs": 21.3, "fat": 30.5, "saturated_fat": 7.9, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 410.2, "potassium": 59.0, "fiber": 2.2, "sugar": 13.2, "vitamin_a": 17.2, "vitamin_c": 39.4, "calcium": 61.7, "iron": 1.3}'::jsonb, ARRAY['chicken', 'chinese', 'themealdb', 'nutrition-generated', 'dessert'], '[{"quantity": 1.0, "unit": "lb", "item": "Chicken Thighs", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Egg White", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Kosher Salt", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 10.0, "unit": "oz", "item": "Pineapple Chunks", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "Pineapple Juice", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "White Vinegar", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "cup", "item": "Tomato Ketchup", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "tsp", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Yellow Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Ginger", "notes": null, "category": "produce"}]'::jsonb, '["Coat the chicken with egg white:", "In a bowl, combine the chicken with the egg white, 1/2 teaspoon kosher salt, and cornstarch. Stir to coat the chicken evenly. Let sit for 15 minutes at room temperature or up to overnight in the refrigerator.", "Make the sweet and sour sauce:", "Whisk together the pineapple juice, vinegar, ketchup, 1/2 teaspoon kosher salt, and brown sugar.", "Stir-fry the chicken over high heat:", "Heat a large frying pan or wok over high heat until a bead of water instantly sizzles and evaporates. Pour in 1 tablespoon of cooking oil and swirl to coat. It''s important that the pan is very hot.", "Add the chicken and spread the pieces out in one layer. Let the chicken fry untouched for 1 minute, until the bottoms are browned.", "Flip and fry the other side for 1 minute. The chicken should still be pinkish in the middle. Dish out the chicken onto a clean plate, leaving as much oil in the pan as possible.", "Stir-fry the bell pepper and ginger:", "Reduce the heat to medium and add the remaining 1 teaspoon of cooking oil. Let the oil heat up before adding the bell pepper chunks and ginger. Fry for 1 minute.", "Add the pineapple, sauce, and then, the chicken:", "Add the pineapple chunks and the sweet and sour sauce. Turn up the heat to high. When the sauce is simmering, add the chicken pieces back in.", "Let simmer for 1 to 2 minutes, until the chicken is cooked through. Timing depends on how thick you''ve cut your chicken. The best way to tell if the chicken is done is to take a piece out and cut into it. If it''s pink, add another minute to the cooking.", "Adjust the seasoning and serve:", "Taste the sauce and add more brown sugar or vinegar to suit your tastes, if you’d like.", "Serve hot with steamed white or brown rice."]'::jsonb, 'https://www.simplyrecipes.com/recipes/sweet_and_sour_chicken/', 'https://www.themealdb.com/images/media/meals/arzs741766434335.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tajine-de-poulet-aux-carottes-et-patates-douces-chicken-and-sweet-potato-tagine', 'Tajine de Poulet aux Carottes et Patates Douces (Chicken and Sweet Potato Tagine)', 4, 0, 0, '{"calories": 168, "protein": 9.6, "carbs": 414.5, "fat": 2.2, "saturated_fat": 0.4, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.6, "sodium": 10141.1, "potassium": 389.3, "fiber": 13.9, "sugar": 14.9, "vitamin_a": null, "vitamin_c": 2.0, "calcium": 47.3, "iron": 1.6}'::jsonb, ARRAY['chicken', 'algerian', 'themealdb', 'nutrition-generated', 'dessert', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cilantro", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Turmeric", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 0.25, "unit": "tsp", "item": "Ground Ginger", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "Cayenne Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thighs", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Drizzle Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "cup", "item": "Raisins", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Sweet Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "thinly Carrots", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "Prunes", "notes": null, "category": "other"}]'::jsonb, '["Combine onions, celery, cilantro, and parsley in a large pot. Stir in turmeric, cumin, paprika, ginger, cayenne pepper, salt, and pepper. Place chicken thighs on top. Drizzle olive oil over chicken. Cover and simmer over low heat until chicken is tender, about 40 minutes.", "Place raisins in a small bowl and cover with hot water; let soak for 10 minutes. Drain.", "Preheat oven to 400 degrees F (200 degrees C).", "Transfer chicken mixture into an oven-safe tagine or casserole dish. Add sweet potato and carrots. Cover with lid or aluminum foil.", "Bake in the preheated oven until sweet potato is soft, about 40 minutes. Add drained raisins and prunes. Continue baking, covered, until raisins and prunes are heated through, about 10 minutes."]'::jsonb, 'https://www.allrecipes.com/recipe/258873/tajine-de-poulet-aux-carottes-et-patates-douces-chicken-and-sweet-potato-tagine/', 'https://www.themealdb.com/images/media/meals/d8bfyg1764117503.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tandoori-chicken', 'Tandoori chicken', 4, 0, 0, '{"calories": 476, "protein": 11.8, "carbs": 62.8, "fat": 19.5, "saturated_fat": 13.9, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 839.8, "potassium": 237.8, "fiber": 5.2, "sugar": 54.8, "vitamin_a": null, "vitamin_c": 2.0, "calcium": 123.2, "iron": 1.0}'::jsonb, ARRAY['chicken', 'indian', 'themealdb', 'nutrition-generated', 'grilling'], '[{"quantity": 1.0, "unit": "serving", "item": "lemons", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tsp", "item": "paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "chopped red onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "chicken thighs", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "For brushing vegetable oil", "notes": null, "category": "pantry"}, {"quantity": 300.0, "unit": "ml", "item": "Greek yogurt", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "large piece ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "clove", "notes": null, "category": "spices"}, {"quantity": 0.75, "unit": "tsp", "item": "garam masala", "notes": null, "category": "spices"}, {"quantity": 0.75, "unit": "tsp", "item": "ground cumin", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "chilli powder", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "tsp", "item": "turmeric", "notes": null, "category": "spices"}]'::jsonb, '["Mix the lemon juice with the paprika and red onions in a large shallow dish. Slash each chicken thigh three times, then turn them in the juice and set aside for 10 mins.", "Mix all of the marinade ingredients together and pour over the chicken. Give everything a good mix, then cover and chill for at least 1 hr. This can be done up to a day in advance.", "Heat the grill. Lift the chicken pieces onto a rack over a baking tray. Brush over a little oil and grill for 8 mins on each side or until lightly charred and completely cooked through."]'::jsonb, 'http://www.bbcgoodfood.com/recipes/1660651/tandoori-chicken', 'https://www.themealdb.com/images/media/meals/qptpvt1487339892.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('teriyaki-chicken-casserole', 'Teriyaki Chicken Casserole', 4, 0, 0, '{"calories": 617, "protein": 22.5, "carbs": 130.8, "fat": 5.4, "saturated_fat": 0.1, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.1, "sodium": 2755.6, "potassium": 514.5, "fiber": 8.8, "sugar": 17.8, "vitamin_a": null, "vitamin_c": null, "calcium": 41.2, "iron": 3.4}'::jsonb, ARRAY['chicken', 'japanese', 'themealdb', 'nutrition-generated', 'dessert', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 0.75, "unit": "cup", "item": "soy sauce", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "water", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "cup", "item": "brown sugar", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground ginger", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "minced garlic", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tablespoons", "item": "cornstarch", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "breasts", "notes": null, "category": "other"}, {"quantity": 12.0, "unit": "oz", "item": "stir-fry vegetables", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "cups", "item": "brown rice", "notes": null, "category": "grains"}]'::jsonb, '["Preheat oven to 350° F. Spray a 9x13-inch baking pan with non-stick spray.", "Combine soy sauce, ½ cup water, brown sugar, ginger and garlic in a small saucepan and cover. Bring to a boil over medium heat. Remove lid and cook for one minute once boiling.", "Meanwhile, stir together the corn starch and 2 tablespoons of water in a separate dish until smooth. Once sauce is boiling, add mixture to the saucepan and stir to combine. Cook until the sauce starts to thicken then remove from heat.", "Place the chicken breasts in the prepared pan. Pour one cup of the sauce over top of chicken. Place chicken in oven and bake 35 minutes or until cooked through. Remove from oven and shred chicken in the dish using two forks.", "*Meanwhile, steam or cook the vegetables according to package directions.", "Add the cooked vegetables and rice to the casserole dish with the chicken. Add most of the remaining sauce, reserving a bit to drizzle over the top when serving. Gently toss everything together in the casserole dish until combined. Return to oven and cook 15 minutes. Remove from oven and let stand 5 minutes before serving. Drizzle each serving with remaining sauce. Enjoy!"]'::jsonb, NULL, 'https://www.themealdb.com/images/media/meals/wvpsxx1468256321.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-chicken-cakes-with-sweet-chilli-sauce', 'Thai chicken cakes with sweet chilli sauce', 4, 0, 0, '{"calories": 416, "protein": 9.7, "carbs": 32.6, "fat": 25.6, "saturated_fat": 4.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 299.5, "potassium": 72.5, "fiber": 1.1, "sugar": 11.9, "vitamin_a": null, "vitamin_c": 2.4, "calcium": 83.0, "iron": 1.6}'::jsonb, ARRAY['chicken', 'thai', 'themealdb', 'nutrition-generated', 'dessert'], '[{"quantity": 1.0, "unit": "serving", "item": "Chicken Breast", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "clove", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tbs", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Green Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve sweet chilli sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Red Chilli", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Toss the chicken, garlic, ginger, onion, coriander and chilli into a food processor and season well. Blitz until the chicken is finely ground and everything is well mixed. Use your hands to shape six small cakes.", "step 2", "Heat the oil in a frying pan, then fry the cakes over a medium heat for about 6-8 mins, turning once. Serve hot, with sweet chilli sauce, lime wedges, coriander, shredded spring onion and red chilli."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/thai-chicken-cakes-sweet-chilli-sauce', 'https://www.themealdb.com/images/media/meals/6s3i3p1763488540.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-drumsticks', 'Thai drumsticks', 4, 0, 0, '{"calories": 246, "protein": 7.1, "carbs": 40.5, "fat": 10.0, "saturated_fat": 2.6, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 647.5, "potassium": 61.0, "fiber": null, "sugar": 31.2, "vitamin_a": null, "vitamin_c": 1.6, "calcium": 15.3, "iron": 0.6}'::jsonb, ARRAY['chicken', 'thai', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "sweet chilli sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Orange", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Orange", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Thai Red Curry Paste", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "drumsticks", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Heat oven to 200C/180C fan/gas 6 and line a baking tray with foil. Mix the chilli sauce with the orange zest and juice, garlic, curry paste and ¼ tsp salt. Add the chicken and coat really well.", "step 2", "Arrange the drumsticks on the foil, spaced apart. Coat the chicken with any marinade left in the bowl, then roast for 35-40 mins until tender. Wrap in foil or pack into a food container."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/fragrant-thai-drumsticks', 'https://www.themealdb.com/images/media/meals/ittake1763586925.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-green-chicken-soup', 'Thai green chicken soup', 4, 0, 0, '{"calories": 978, "protein": 30.6, "carbs": 49.5, "fat": 68.6, "saturated_fat": 15.7, "polyunsaturated_fat": null, "monounsaturated_fat": 13.3, "sodium": 4479.5, "potassium": 61.8, "fiber": 4.1, "sugar": 8.2, "vitamin_a": null, "vitamin_c": 7.4, "calcium": 48.5, "iron": 3.5}'::jsonb, ARRAY['chicken', 'thai', 'themealdb', 'nutrition-generated', 'soup'], '[{"quantity": 1.0, "unit": "serving", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "g", "item": "Chicken Thighs", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 280.0, "unit": "g", "item": "Thai Green Curry Paste", "notes": null, "category": "spices"}, {"quantity": 400.0, "unit": "ml", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "bunch", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 280.0, "unit": "g", "item": "Green Beans", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "g", "item": "Bamboo Shoot", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 2 Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Basil", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat the oil in your largest pan, add the onion and fry for 3 mins to soften. Add the chicken and garlic, and cook until the chicken changes colour.", "step 2", "Add the curry paste, coconut milk, stock, lime leaves and fish sauce, then simmer for 12 mins. Add the chopped onion tops, green beans and bamboo shoots and cook for 4-6 mins, until the beans are just tender.", "step 3", "Meanwhile, put the lime juice and basil in a narrow jug and blitz with a hand blender to make a smooth green paste. Pour into the soup with the sliced spring onion and heat through. Serve with lime wedges for a light lunch or supper or as a make-ahead starter."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/thai-green-chicken-soup', 'https://www.themealdb.com/images/media/meals/7kb44y1763589084.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-green-curry', 'Thai Green Curry', 4, 0, 0, '{"calories": 389, "protein": 31.3, "carbs": 54.6, "fat": 27.5, "saturated_fat": 7.7, "polyunsaturated_fat": null, "monounsaturated_fat": 1.8, "sodium": 789.6, "potassium": 749.8, "fiber": 3.6, "sugar": 5.0, "vitamin_a": 36.5, "vitamin_c": 7.1, "calcium": 74.1, "iron": 7.6}'::jsonb, ARRAY['chicken', 'thai', 'themealdb', 'nutrition-generated', 'dessert'], '[{"quantity": 225.0, "unit": "g", "item": "new Potatoes", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "green beans", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "sunflower oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tsp", "item": "Thai green curry paste", "notes": null, "category": "spices"}, {"quantity": 400.0, "unit": "ml", "item": "coconut milk", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tsp", "item": "Thai fish sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 450.0, "unit": "g", "item": "boneless Chicken", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "kaffir leaves lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "handfull basil", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Boiled Rice", "notes": null, "category": "grains"}]'::jsonb, '["Put the potatoes in a pan of boiling water and cook for 5 minutes. Throw in the beans and cook for a further 3 minutes, by which time both should be just tender but not too soft. Drain and put to one side.", "In a wok or large frying pan, heat the oil until very hot, then drop in the garlic and cook until golden, this should take only a few seconds. Don’t let it go very dark or it will spoil the taste. Spoon in the curry paste and stir it around for a few seconds to begin to cook the spices and release all the flavours. Next, pour in the coconut milk and let it come to a bubble.", "Stir in the fish sauce and sugar, then the pieces of chicken. Turn the heat down to a simmer and cook, covered, for about 8 minutes until the chicken is cooked.", "Tip in the potatoes and beans and let them warm through in the hot coconut milk, then add a lovely citrussy flavour by stirring in the shredded lime leaves (or lime zest). The basil leaves go in next, but only leave them briefly on the heat or they will quickly lose their brightness. Scatter with the lime garnish and serve immediately with boiled rice."]'::jsonb, 'http://www.bbcgoodfood.com/recipes/3235/thai-green-chicken-curry', 'https://www.themealdb.com/images/media/meals/sstssx1487349585.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tom-kha-gai', 'Tom kha gai', 4, 0, 0, '{"calories": 824, "protein": 33.5, "carbs": 32.2, "fat": 56.7, "saturated_fat": 20.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1273.1, "potassium": 329.1, "fiber": 3.7, "sugar": 8.8, "vitamin_a": null, "vitamin_c": null, "calcium": 27.1, "iron": 3.4}'::jsonb, ARRAY['chicken', 'thai', 'themealdb', 'nutrition-generated', 'dessert', 'soup'], '[{"quantity": 800.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 800.0, "unit": "g", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Galangal Paste", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Stalks", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "g", "item": "Chicken Thighs", "notes": null, "category": "meat"}, {"quantity": 300.0, "unit": "g", "item": "Oyster Mushrooms", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Birds-eye Chillies", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 5.0, "unit": "tablespoons", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 3 Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Coriander Leaves", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Rice", "notes": null, "category": "grains"}]'::jsonb, '["step 1", "Pour the chicken stock and coconut milk into a large saucepan set over a medium heat. Tip in the galangal, lemongrass and lime leaves, and bring to a gentle simmer, around 6-8 mins. Keeping at a gentle simmer, add the chicken. Cook for 8-10 mins until tender and cooked through.", "step 2", "Stir in the mushrooms and chillies, and simmer for a further 3-5 mins until everything is cooked through. Sprinkle in the sugar and 3 tbsp each of the fish sauce and lime juice. Taste and add the remaining if required.", "step 3", "Remove the galangal, lemongrass and lime leaves before serving using a slotted spoon. Ladle into bowls and serve with coriander leaves sprinkled over and steamed rice on the side. Will keep chilled for up to three days. Leave to cool first."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/tom-kha-gai', 'https://www.themealdb.com/images/media/meals/ol2xxt1763582263.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('venezuelan-coconut-chicken', 'Venezuelan Coconut Chicken', 4, 0, 0, '{"calories": 774, "protein": 20.4, "carbs": 69.0, "fat": 53.4, "saturated_fat": 11.4, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.1, "sodium": 658.6, "potassium": 471.4, "fiber": 4.4, "sugar": 19.2, "vitamin_a": null, "vitamin_c": 0.5, "calcium": 18.2, "iron": 4.9}'::jsonb, ARRAY['chicken', 'venezulan', 'themealdb', 'nutrition-generated', 'dessert', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Breasts", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Turmeric", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Ginger Paste", "notes": null, "category": "produce"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "can", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Water", "notes": null, "category": "other"}]'::jsonb, '["Cut the chicken up into bite size pieces. Peel and cut the onions, mince the garlic.", "Assemble the rest of the ingredients and you are ready to start cooking.", "Make the Dish", "Heat up a fry pan over medium heat. Add the oil and when hot, sauté the onion until translucent. Remove from pan and transfer to a blender or food processor.", "Add tomatoes, garlic, turmeric, cumin, sugar, ginger paste, coconut milk, water and blend smooth.", "In the same pan you cooked the onion, add the chicken and brown all sides. This should take about 3 minutes.", "Add the blender ingredients and bay leaves to the pan, bring to a simmer and cook until the chicken is white inside and the liquid is creamy. (15 to 20 minutes)", "Remove the bay leaves and serve with white rice."]'::jsonb, 'https://www.reluctantgourmet.com/venezuelan-coconut-chicken/#recipe', 'https://www.themealdb.com/images/media/meals/z2sw3o1764378271.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vietnamese-chicken-salad', 'Vietnamese chicken salad', 4, 0, 0, '{"calories": 370, "protein": 9.0, "carbs": 72.1, "fat": 5.2, "saturated_fat": 0.8, "polyunsaturated_fat": 0.0, "monounsaturated_fat": 0.8, "sodium": 1017.2, "potassium": 278.9, "fiber": 2.0, "sugar": 28.0, "vitamin_a": null, "vitamin_c": 6.2, "calcium": 32.3, "iron": 0.8}'::jsonb, ARRAY['chicken', 'vietnamese', 'themealdb', 'nutrition-generated', 'salad', 'pasta'], '[{"quantity": 140.0, "unit": "g", "item": "Rice Noodles", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Cucumber", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Breasts", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Radish", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Mint", "notes": null, "category": "produce"}, {"quantity": 25.0, "unit": "g", "item": "Peanuts", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Zest and juice of 1 Lime", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tbsp", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tbsp", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tbsp", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "To make the dressing, whisk all the ingredients together in a large serving bowl. Cook the noodles following pack instructions, then drain and add to the bowl with the dressing.", "step 2", "Peel the carrot into long strips using a vegetable peeler. Do the same for the cucumber, until you reach the seeds (discard them). Add the carrot and cucumber to the noodle mixture along with the shredded chicken, radishes, red onion and mint. Toss well to coat in the dressing, scatter over the peanuts and serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/vietnamese-chicken-salad', 'https://www.themealdb.com/images/media/meals/pk8wtn1763758591.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('æbleskiver', 'Æbleskiver', 4, 0, 0, '{"calories": 805, "protein": 9.4, "carbs": 103.3, "fat": 37.9, "saturated_fat": 15.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 100.8, "potassium": null, "fiber": 0.8, "sugar": 60.5, "vitamin_a": null, "vitamin_c": 0.6, "calcium": 173.9, "iron": 2.2}'::jsonb, ARRAY['dessert', 'norwegian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Granulated Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Cardamom", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "cups", "item": "Buttermilk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "For Greasing Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Sprinkling Powdered Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Raspberry Jam", "notes": null, "category": "produce"}]'::jsonb, '["Whisk the flour, salt, sugar, baking soda, and cardamom together in a large bowl.", "▢", "Separate the eggs and add the egg yolks to the flour mixture. Pour in the buttermilk (or cultured milk) and whisk the batter together until smooth. Cover and refrigerate for about 30 minutes.", "▢", "Use a hand (or stand) mixer to beat the egg whites until stiff. Carefully fold into the æbleskiver batter.", "▢", "Heat the pan on medium heat. Once hot, brush the pan with butter and fill each æbleskive hole almost full with the batter.", "▢", "Once the edges become firm use a knitting needle or wooden skewer to turn the æbleskiver about 1/4. Continue turning until you get round pancake spheres. They should be golden brown.", "▢", "Remove the æbleskiver from the pan and serve with powdered sugar and jam."]'::jsonb, 'https://scandinaviancookbook.com/aebleskiver-danish-pancake-balls/', 'https://www.themealdb.com/images/media/meals/wkhg581762773124.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('alfajores', 'Alfajores', 4, 0, 0, '{"calories": 1296, "protein": 14.0, "carbs": 144.3, "fat": 70.6, "saturated_fat": 26.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 104.8, "potassium": 57.8, "fiber": 1.7, "sugar": 38.2, "vitamin_a": null, "vitamin_c": null, "calcium": 226.2, "iron": 4.7}'::jsonb, ARRAY['dessert', 'argentinian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 300.0, "unit": "g", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 200.0, "unit": "g", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Lemon Zest", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Dulce de leche", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Sprinkling Desiccated Coconut", "notes": null, "category": "pantry"}]'::jsonb, '["Make the Dough: Cream butter and sugar. Add egg yolks and lemon zest. Gradually mix in flour and cornstarch to form a dough. Chill for 1 hour.", "Bake the Cookies: Roll out the dough, cut into circles, and bake at 180°C (350°F) for 12-15 minutes. Let cool.", "Assemble: Spread dulce de leche on one cookie, then sandwich with another. Roll the edges in coconut flakes.", "Pro Tips:", "Chill the dough before rolling it out to make it easier to handle and to prevent the cookies from spreading too much while baking.", "Dip the alfajores in melted chocolate and let them set on a wire rack for an extra decadent treat."]'::jsonb, 'https://www.munchery.com/blog/the-ten-iconic-dishes-of-argentina-and-how-to-cook-them-at-home/', 'https://www.themealdb.com/images/media/meals/a4kgf21763075288.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('anzac-biscuits', 'Anzac biscuits', 4, 0, 0, '{"calories": 577, "protein": 6.4, "carbs": 80.5, "fat": 34.5, "saturated_fat": 12.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": 33.9, "fiber": 3.7, "sugar": 38.3, "vitamin_a": null, "vitamin_c": null, "calcium": 106.4, "iron": 2.9}'::jsonb, ARRAY['dessert', 'australian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 85.0, "unit": "g", "item": "Porridge oats", "notes": null, "category": "grains"}, {"quantity": 85.0, "unit": "g", "item": "Desiccated Coconut", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 100.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Golden Syrup", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Bicarbonate Of Soda", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Heat oven to 180C/fan 160C/gas 4. Put the oats, coconut, flour and sugar in a bowl. Melt the butter in a small pan and stir in the golden syrup. Add the bicarbonate of soda to 2 tbsp boiling water, then stir into the golden syrup and butter mixture.", "step 2", "Make a well in the middle of the dry ingredients and pour in the butter and golden syrup mixture. Stir gently to incorporate the dry ingredients.", "step 3", "Put dessertspoonfuls of the mixture on to buttered baking sheets, about 2.5cm/1in apart to allow room for spreading. Bake in batches for 8-10 mins until golden. Transfer to a wire rack to cool."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/anzac-biscuits', 'https://www.themealdb.com/images/media/meals/q47rkb1762324620.jpg', FALSE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('apam-balik', 'Apam balik', 4, 0, 0, '{"calories": 1601, "protein": 31.8, "carbs": 293.9, "fat": 21.2, "saturated_fat": 6.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 177.5, "potassium": null, "fiber": null, "sugar": 13.9, "vitamin_a": 40.2, "vitamin_c": 0.5, "calcium": 76.7, "iron": 14.8}'::jsonb, ARRAY['dessert', 'malaysian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 200.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 60.0, "unit": "ml", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1600.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 3.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 25.0, "unit": "g", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 45.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tbs", "item": "Peanut Butter", "notes": null, "category": "dairy"}]'::jsonb, '["Mix milk, oil and egg together. Sift flour, baking powder and salt into the mixture. Stir well until all ingredients are combined evenly.", "Spread some batter onto the pan. Spread a thin layer of batter to the side of the pan. Cover the pan for 30-60 seconds until small air bubbles appear.", "Add butter, cream corn, crushed peanuts and sugar onto the pancake. Fold the pancake into half once the bottom surface is browned.", "Cut into wedges and best eaten when it is warm."]'::jsonb, 'https://www.nyonyacooking.com/recipes/apam-balik~SJ5WuvsDf9WQ', 'https://www.themealdb.com/images/media/meals/adxcbq1619787919.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('apple-blackberry-crumble', 'Apple & Blackberry Crumble', 4, 0, 0, '{"calories": 293, "protein": 3.8, "carbs": 56.6, "fat": 18.2, "saturated_fat": 11.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": 171.8, "fiber": 4.7, "sugar": 27.5, "vitamin_a": null, "vitamin_c": 2.3, "calcium": 14.3, "iron": 0.7}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 120.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 60.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 60.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 300.0, "unit": "g", "item": "Braeburn Apples", "notes": null, "category": "produce"}, {"quantity": 30.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 30.0, "unit": "g", "item": "Demerara Sugar", "notes": null, "category": "pantry"}, {"quantity": 120.0, "unit": "g", "item": "Blackberries", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "teaspoon", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Ice Cream", "notes": null, "category": "dairy"}]'::jsonb, '["Heat oven to 190C/170C fan/gas 5. Tip the flour and sugar into a large bowl. Add the butter, then rub into the flour using your fingertips to make a light breadcrumb texture. Do not overwork it or the crumble will become heavy. Sprinkle the mixture evenly over a baking sheet and bake for 15 mins or until lightly coloured.", "Meanwhile, for the compote, peel, core and cut the apples into 2cm dice. Put the butter and sugar in a medium saucepan and melt together over a medium heat. Cook for 3 mins until the mixture turns to a light caramel. Stir in the apples and cook for 3 mins. Add the blackberries and cinnamon, and cook for 3 mins more. Cover, remove from the heat, then leave for 2-3 mins to continue cooking in the warmth of the pan.", "To serve, spoon the warm fruit into an ovenproof gratin dish, top with the crumble mix, then reheat in the oven for 5-10 mins. Serve with vanilla ice cream."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/778642/apple-and-blackberry-crumble', 'https://www.themealdb.com/images/media/meals/xvsurr1511719182.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('apple-cake', 'Apple cake', 4, 0, 0, '{"calories": 470, "protein": 21.8, "carbs": 129.2, "fat": 40.9, "saturated_fat": 8.7, "polyunsaturated_fat": null, "monounsaturated_fat": 18.8, "sodium": 447.5, "potassium": 555.2, "fiber": 8.1, "sugar": 69.1, "vitamin_a": null, "vitamin_c": 0.8, "calcium": 157.7, "iron": 4.4}'::jsonb, ARRAY['dessert', 'dutch', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 200.0, "unit": "g", "item": "Melted Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Ground Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Apples", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Sprinkling", "notes": "Ground Sugar", "category": "other"}]'::jsonb, '["Preheat the oven to 180°C. (350˚F) Grease a cake pan and line it with baking paper.", "In a large bowl, break the four eggs with the sugar and beat until they have tripled in volume and become fluffy.", "Sift the self-rising baking flour and add it to your egg mixture. Fold this over, preserving as much air as possible. Add the melted (and slightly cooled) butter and mix until combined.", "Add cinnamon, pinch of salt and vanilla extract.", "Add the diced apple to the batter and gently fold them into the batter so that the apple pieces are evenly distributed. You can roll the apple pieces through some more cinnamon.", "Pour the batter into the prepared cake pan and smooth the top with a spatula.", "Place the apple slices on top of the batter and press lightly. Sprinkle optionally with some almond shavings.", "Bake the apple cake in the preheated oven for about 45-50 minutes, or until a wooden skewer comes out clean when inserted into the center of the cake.", "Remove the cake from the oven and let it cool in the mold for a few minutes. Then carefully remove the cake from the mold and let cool completely on a wire rack.", "Sprinkle the cooled apple cake with powdered sugar"]'::jsonb, 'https://insimoneskitchen.com/dutch-apple-cake/#recipe', 'https://www.themealdb.com/images/media/meals/c0gmo31766594751.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('apple-frangipan-tart', 'Apple Frangipan Tart', 4, 0, 0, '{"calories": 35, "protein": 3.0, "carbs": 0.0, "fat": 2.5, "saturated_fat": 0.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 35.0, "potassium": 34.5, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": 14.0, "iron": 0.5}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 175.0, "unit": "g", "item": "175g/6oz digestive biscuits", "notes": null, "category": "other"}, {"quantity": 75.0, "unit": "g", "item": "75g/3oz butter", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "200g/7oz Bramley apples", "notes": null, "category": "produce"}, {"quantity": 75.0, "unit": "g", "item": "75g/3oz Salted Butter", "notes": null, "category": "dairy"}, {"quantity": 75.0, "unit": "g", "item": "75g/3oz caster sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "free-range eggs", "notes": "beaten", "category": "dairy"}, {"quantity": 75.0, "unit": "g", "item": "75g/3oz", "notes": "ground almonds", "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "almond extract", "notes": null, "category": "pantry"}, {"quantity": 1.75, "unit": "oz", "item": "50g/1¾oz flaked almonds", "notes": null, "category": "pantry"}]'::jsonb, '["Preheat the oven to 200C/180C Fan/Gas 6.", "Put the biscuits in a large re-sealable freezer bag and bash with a rolling pin into fine crumbs. Melt the butter in a small pan, then add the biscuit crumbs and stir until coated with butter. Tip into the tart tin and, using the back of a spoon, press over the base and sides of the tin to give an even layer. Chill in the fridge while you make the filling.", "Cream together the butter and sugar until light and fluffy. You can do this in a food processor if you have one. Process for 2-3 minutes. Mix in the eggs, then add the ground almonds and almond extract and blend until well combined.", "Peel the apples, and cut thin slices of apple. Do this at the last minute to prevent the apple going brown. Arrange the slices over the biscuit base. Spread the frangipane filling evenly on top. Level the surface and sprinkle with the flaked almonds.", "Bake for 20-25 minutes until golden-brown and set.", "Remove from the oven and leave to cool for 15 minutes. Remove the sides of the tin. An easy way to do this is to stand the tin on a can of beans and push down gently on the edges of the tin.", "Transfer the tart, with the tin base attached, to a serving plate. Serve warm with cream, crème fraiche or ice cream."]'::jsonb, NULL, 'https://www.themealdb.com/images/media/meals/wxywrq1468235067.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('apricot-turkish-delight-mess', 'Apricot & Turkish delight mess', 4, 0, 0, '{"calories": 644, "protein": 4.2, "carbs": 92.4, "fat": 25.8, "saturated_fat": 18.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 74.4, "potassium": 120.1, "fiber": 2.5, "sugar": 84.0, "vitamin_a": null, "vitamin_c": 4.9, "calcium": 113.8, "iron": 0.3}'::jsonb, ARRAY['dessert', 'turkish', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 100.0, "unit": "g", "item": "Mascarpone", "notes": null, "category": "dairy"}, {"quantity": 50.0, "unit": "g", "item": "Greek Yogurt", "notes": null, "category": "dairy"}, {"quantity": 25.0, "unit": "g", "item": "Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Orange Blossom Water", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Nests", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Apricot", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "pieces", "item": "Turkish Delight", "notes": null, "category": "other"}, {"quantity": 25.0, "unit": "g", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Mint", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Place the mascarpone, yogurt, sugar and orange flower water into a large bowl and whisk until thickened. Fold the remaining ingredients through, then divide the mix between 2 dessert glasses or bowls and decorate with extra mint, if you like."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/apricot-turkish-delight-mess', 'https://www.themealdb.com/images/media/meals/p277uc1764109195.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('authentic-norwegian-kransekake', 'Authentic Norwegian Kransekake', 4, 0, 0, '{"calories": 2466, "protein": 92.9, "carbs": 188.2, "fat": 152.8, "saturated_fat": 29.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2719.2, "potassium": 479.5, "fiber": 23.4, "sugar": 80.9, "vitamin_a": null, "vitamin_c": null, "calcium": 873.9, "iron": 12.6}'::jsonb, ARRAY['dessert', 'norwegian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 3.0, "unit": "cups", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "White", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "cups", "item": "Powdered Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "cups", "item": "Powdered Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "White", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Lemon Juice", "notes": null, "category": "produce"}]'::jsonb, '["Grind almonds in an almond grinder or food processor.", "▢", "Mix almonds and powdered sugar together in a large mixing bowl. Add three of the egg whites and knead the dough together with your hands until it comes together in a ball. Wrap in cling film and leave in the fridge for at least an hour, preferably until the next day.", "▢", "Grease the kransekake forms thoroughly and coat with semolina, flour, or bread crumbs.", "▢", "Preheat oven to 210°C (410°F) top and bottom heat. Divide the dough into six sections.", "▢", "Slowly add the remaining egg white to the dough and knead it until you can roll it into long sausages about as thick as your index finger. Fill the forms with the dough sausages, pinching the ends together to make rings.", "▢", "Set the forms on a baking sheet and back in the middle of the oven for about 10 – 12 minutes, until the tops are golden brown."]'::jsonb, 'https://scandinaviancookbook.com/classic-norwegian-kransekake-recipe/', 'https://www.themealdb.com/images/media/meals/yk78uc1763075719.jpg', FALSE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bakewell-tart', 'Bakewell tart', 4, 0, 0, '{"calories": 44, "protein": 3.0, "carbs": 2.4, "fat": 2.5, "saturated_fat": 0.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 35.0, "potassium": 34.5, "fiber": null, "sugar": 2.4, "vitamin_a": null, "vitamin_c": null, "calcium": 14.0, "iron": 0.5}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 175.0, "unit": "g", "item": "175g/6oz plain flour", "notes": null, "category": "grains"}, {"quantity": 2.5, "unit": "oz", "item": "75g/2½oz chilled butter", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tbsp", "item": "2", "notes": "3 tbsp cold water", "category": "other"}, {"quantity": 1.0, "unit": "tbsp", "item": "raspberry jam", "notes": null, "category": "produce"}, {"quantity": 4.5, "unit": "oz", "item": "125g/4½oz butter", "notes": null, "category": "dairy"}, {"quantity": 4.5, "unit": "oz", "item": "125g/4½oz caster sugar", "notes": null, "category": "pantry"}, {"quantity": 4.5, "unit": "oz", "item": "125g/4½oz", "notes": "ground almonds", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "free-range egg", "notes": "beaten", "category": "dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "almond extract", "notes": null, "category": "pantry"}, {"quantity": 1.75, "unit": "oz", "item": "50g/1¾oz flaked almonds", "notes": null, "category": "pantry"}]'::jsonb, '["To make the pastry, measure the flour into a bowl and rub in the butter with your fingertips until the mixture resembles fine breadcrumbs. Add the water, mixing to form a soft dough.", "Roll out the dough on a lightly floured work surface and use to line a 20cm/8in flan tin. Leave in the fridge to chill for 30 minutes.", "Preheat the oven to 200C/400F/Gas 6 (180C fan).", "Line the pastry case with foil and fill with baking beans. Bake blind for about 15 minutes, then remove the beans and foil and cook for a further five minutes to dry out the base.", "For the filing, spread the base of the flan generously with raspberry jam.", "Melt the butter in a pan, take off the heat and then stir in the sugar. Add ground almonds, egg and almond extract. Pour into the flan tin and sprinkle over the flaked almonds.", "Bake for about 35 minutes. If the almonds seem to be browning too quickly, cover the tart loosely with foil to prevent them burning."]'::jsonb, NULL, 'https://www.themealdb.com/images/media/meals/wyrqqq1468233628.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('baklava-with-spiced-nuts-ricotta-chocolate', 'Baklava with spiced nuts, ricotta & chocolate', 4, 0, 0, '{"calories": 2480, "protein": 40.3, "carbs": 269.1, "fat": 165.6, "saturated_fat": 44.3, "polyunsaturated_fat": null, "monounsaturated_fat": 8.7, "sodium": 133.0, "potassium": 733.7, "fiber": 19.1, "sugar": 140.0, "vitamin_a": 401.9, "vitamin_c": 3.7, "calcium": 289.7, "iron": 7.5}'::jsonb, ARRAY['dessert', 'turkish', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 500.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Walnuts", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Pecan Nuts", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Ground Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Ground Cardomom", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "g", "item": "Ricotta", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Orange", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Vanilla Bean Paste", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 500.0, "unit": "g", "item": "Filo Pastry", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Ground Pistachios", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "First, make the syrup. Tip the sugar into a large saucepan with 650ml water. Stir over a low heat until the sugar has dissolved, then turn up the heat and bring to the boil. Reduce the heat to a simmer and cook for 15 mins, then squeeze in a few drops of lemon juice and simmer for a further 5 mins. Remove from the heat and leave to cool. Meanwhile, for assembling the baklava later, melt the butter in a small pan over a low heat for 5 mins, skimming and discarding any froth that rises to the surface.", "step 2", "For the filling, crush all of the nuts in a pestle and mortar, or blitz in a food processor – you want a mixture of finely ground nuts with a few chunky pieces. Tip into a bowl, stir through the spices and set aside.", "step 3", "In a separate bowl, mix the ricotta with the lemon and orange zests and vanilla. Heat the oven to 180C/160C fan/gas 4. Brush the bottom of a large baking tray (about 35 x 47cm) with some of the melted butter. Working with one sheet of filo at a time (covering the rest with a damp tea towel to prevent it drying out), lay the sheet out on a board so one of the short ends is facing you. Sprinkle 30g of the nut mixture evenly over the whole sheet, then spoon 1 tbsp of the ricotta mixture across the end closest to you. Fold this end over to enclose the filling, then lay a long, thin skewer next to the folded edge and roll the pastry around it to create a long roll. When it’s fully rolled up, it should be roughly the thickness of a chipolata sausage. While holding one end of the rolling pin or skewer, gently scrunch the filo roll like an accordion and carefully push it off the skewer and onto the prepared tray. Repeat with the rest of the filo and fillings – you should get about 12 rolls. Cut each roll into four to make 48 large baklava, or eight to make 96 mini.", "step 4", "Brush with the remaining melted butter. Bake for 20-25 mins until evenly golden, turning the tray around halfway through. While still hot, immediately pour over 5-6 ladlefuls of the syrup. You should hear the syrup sizzle as it hits the hot baklava. Set aside to cool and absorb.", "step 5", "Melt the dark chocolate in a heatproof bowl set over a pan of simmering water, ensuring the bowl doesn’t touch the water, or in the microwave in short bursts. Drizzle this over the cooled baklava and sprinkle with the ground pistachios."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/baklava-with-spiced-nuts-ricotta-chocolate', 'https://www.themealdb.com/images/media/meals/ytme8t1764111401.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('banana-pancakes', 'Banana Pancakes', 4, 0, 0, '{"calories": 308, "protein": 11.7, "carbs": 54.6, "fat": 19.8, "saturated_fat": 3.3, "polyunsaturated_fat": null, "monounsaturated_fat": 0.8, "sodium": 327.8, "potassium": 159.9, "fiber": 5.0, "sugar": 4.7, "vitamin_a": null, "vitamin_c": 12.3, "calcium": 53.5, "iron": 2.5}'::jsonb, ARRAY['dessert', 'american', 'themealdb', 'nutrition-generated', 'breakfast', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Banana", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "spinkling Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 25.0, "unit": "g", "item": "Pecan Nuts", "notes": null, "category": "pantry"}, {"quantity": 125.0, "unit": "g", "item": "Raspberries", "notes": null, "category": "other"}]'::jsonb, '["In a bowl, mash the banana with a fork until it resembles a thick purée. Stir in the eggs, baking powder and vanilla.", "Heat a large non-stick frying pan or pancake pan over a medium heat and brush with half the oil. Using half the batter, spoon two pancakes into the pan, cook for 1-2 mins each side, then tip onto a plate. Repeat the process with the remaining oil and batter. Top the pancakes with the pecans and raspberries."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/banana-pancakes', 'https://www.themealdb.com/images/media/meals/sywswr1511383814.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('battenberg-cake', 'Battenberg Cake', 4, 0, 0, '{"calories": 2346, "protein": 31.6, "carbs": 345.3, "fat": 124.1, "saturated_fat": 47.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 566.0, "potassium": 35.5, "fiber": 15.8, "sugar": 263.2, "vitamin_a": null, "vitamin_c": 8.8, "calcium": 225.8, "iron": 3.9}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 175.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 175.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 140.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 50.0, "unit": "g", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "teaspoon", "item": "Almond Extract", "notes": null, "category": "pantry"}, {"quantity": 175.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 175.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 140.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 50.0, "unit": "g", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "teaspoon", "item": "Almond Extract", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Pink Food Colouring", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "Apricot", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "kg", "item": "Marzipan", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Dusting Icing Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["Heat oven to 180C/160C fan/gas 4 and line the base and sides of a 20cm square tin with baking parchment (the easiest way is to cross 2 x 20cm-long strips over the base). To make the almond sponge, put the butter, sugar, flour, ground almonds, baking powder, eggs, vanilla and almond extract in a large bowl. Beat with an electric whisk until the mix comes together smoothly. Scrape into the tin, spreading to the corners, and bake for 25-30 mins – when you poke in a skewer, it should come out clean. Cool in the tin for 10 mins, then transfer to a wire rack to finish cooling while you make the second sponge.", "For the pink sponge, line the tin as above. Mix all the ingredients together as above, but don’t add the almond extract. Fold in some pink food colouring. Then scrape it all into the tin and bake as before. Cool.", "To assemble, heat the jam in a small pan until runny, then sieve. Barely trim two opposite edges from the almond sponge, then well trim a third edge. Roughly measure the height of the sponge, then cutting from the well-trimmed edge, use a ruler to help you cut 4 slices each the same width as the sponge height. Discard or nibble leftover sponge. Repeat with pink cake.", "Take 2 x almond slices and 2 x pink slices and trim so they are all the same length. Roll out one marzipan block on a surface lightly dusted with icing sugar to just over 20cm wide, then keep rolling lengthways until the marzipan is roughly 0.5cm thick. Brush with apricot jam, then lay a pink and an almond slice side by side at one end of the marzipan, brushing jam in between to stick sponges, and leaving 4cm clear marzipan at the end. Brush more jam on top of the sponges, then sandwich remaining 2 slices on top, alternating colours to give a checkerboard effect. Trim the marzipan to the length of the cakes.", "Carefully lift up the marzipan and smooth over the cake with your hands, but leave a small marzipan fold along the bottom edge before you stick it to the first side. Trim opposite side to match size of fold, then crimp edges using fingers and thumb (or, more simply, press with prongs of fork). If you like, mark the 10 slices using the prongs of a fork.", "Assemble second Battenberg and keep in an airtight box or well wrapped in cling film for up to 3 days. Can be frozen for up to a month."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/1120657/battenberg-cake', 'https://www.themealdb.com/images/media/meals/ywwrsp1511720277.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beavertails', 'BeaverTails', 4, 0, 0, '{"calories": 811, "protein": 6.2, "carbs": 94.2, "fat": 49.1, "saturated_fat": 17.3, "polyunsaturated_fat": null, "monounsaturated_fat": 7.1, "sodium": 146.4, "potassium": 18.0, "fiber": 0.6, "sugar": 58.2, "vitamin_a": null, "vitamin_c": 0.3, "calcium": 56.0, "iron": 1.1}'::jsonb, ARRAY['dessert', 'canadian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Yeast", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cups", "item": "2-1/2 cups Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "for frying Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "garnish Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "garnish Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "garnish Cinnamon", "notes": null, "category": "spices"}]'::jsonb, '["In the bowl of a stand mixer, add warm water, a big pinch of sugar and yeast. Allow to sit until frothy.", "Into the same bowl, add 1/2 cup sugar, warm milk, melted butter, eggs and salt, and whisk until combined.", "Place a dough hook on the mixer, add the flour with the machine on, until a smooth but slightly sticky dough forms.", "Place dough in a bowl, cover with plastic wrap, and allow to proof for 1 1/2 hours.", "Cut dough into 12 pieces, and roll out into long oval-like shapes about 1/4 inch thick that resemble a beaver’s tail.", "In a large, deep pot, heat oil to 350 degrees. Gently place beavertail dough into hot oil and cook for 30 to 45 seconds on each side until golden brown.", "Drain on paper towels, and garnish as desired. Toss in cinnamon sugar, in white sugar with a squeeze of lemon, or with a generous slathering of Nutella and a handful of toasted almonds. Enjoy!"]'::jsonb, 'https://www.tastemade.com/videos/beavertails', 'https://www.themealdb.com/images/media/meals/ryppsv1511815505.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beetroot-pancakes', 'Beetroot pancakes', 4, 0, 0, '{"calories": 422, "protein": 10.5, "carbs": 81.4, "fat": 24.3, "saturated_fat": 14.3, "polyunsaturated_fat": null, "monounsaturated_fat": 4.5, "sodium": 436.6, "potassium": 427.8, "fiber": 5.2, "sugar": 40.7, "vitamin_a": null, "vitamin_c": 0.1, "calcium": 95.9, "iron": 0.9}'::jsonb, ARRAY['dessert', 'ukrainian', 'themealdb', 'nutrition-generated', 'breakfast', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Beetroot", "notes": null, "category": "produce"}, {"quantity": 50.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Maple Syrup", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 25.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "Frozen Mixed Berries", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Blackcurrant Jam", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Greek Yogurt", "notes": null, "category": "dairy"}]'::jsonb, '["step 1", "Put the beetroot in a jug with the milk and blend with a stick blender until smooth. Pour into a bowl with the rest of the pancake ingredients and whisk until smooth and vibrant purple.", "step 2", "Put a small knob of butter in a large non-stick frying pan and heat over a medium-low heat until melted and foamy. Now create 3 or 4 pancakes each made from 2 tbsp of the batter. Cook for 2-3 mins then flip over and cook for a further minute until cooked through. Repeat with any remaining batter. Heat oven to lowest setting and keep the pancakes warm in there until needed.", "step 3", "Serve with your favourite pancake toppings or make a simple compote by simmering frozen berries in with 1 tbsp blackcurrant jam until bubbling and syrupy (about 5-10 mins). In a small bowl stir together the remaining jam and the yogurt. Stack the cooked pancakes with the yogurt and pour the warm berry compote over the top."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/beetroot-pancakes', 'https://www.themealdb.com/images/media/meals/xlqqhw1764369924.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('blackberry-fool', 'Blackberry Fool', 4, 0, 0, '{"calories": 652, "protein": 10.1, "carbs": 107.0, "fat": 65.3, "saturated_fat": 32.8, "polyunsaturated_fat": null, "monounsaturated_fat": 5.5, "sodium": 225.7, "potassium": 366.5, "fiber": 9.6, "sugar": 60.0, "vitamin_a": null, "vitamin_c": 1.2, "calcium": 140.7, "iron": 1.8}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 50.0, "unit": "g", "item": "Hazlenuts", "notes": null, "category": "pantry"}, {"quantity": 125.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 150.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Grated Lemon", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 600.0, "unit": "g", "item": "Blackberries", "notes": null, "category": "other"}, {"quantity": 75.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "ml", "item": "Yogurt", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Garnish with Mint", "notes": null, "category": "produce"}]'::jsonb, '["For the biscuits, preheat the oven to 200C/180C (fan)/Gas 6 and line two large baking trays with baking parchment. Scatter the nuts over a baking tray and roast in the oven for 6-8 minutes, or until golden-brown. Watch them carefully so that they don’t have a chance to burn. Remove from the oven, tip onto a board and leave to cool.", "Put the butter and sugar in a large bowl and beat with a wooden spoon until light and creamy. Roughly chop the cooled nuts and add to the creamed butter and sugar, along with the lemon zest, flour and baking powder. Stir well until the mixture comes together and forms a ball – you may need to use your hands.", "Divide the biscuit dough into 24 even pieces and roll into small balls. Place the balls the prepared baking trays, spaced well apart to allow for spreading.", "Press the biscuits to flatten to around 1cm/½in thick. Bake the biscuits, one tray at a time, for 12 minutes or until very pale golden-brown. Leave to cool on the trays. They will be very soft when you take them out of the oven, but will crisp as they cool.", "Store in an airtight tin and eat within five days.", "For the fool, rinse the blackberries in a colander to wash away any dust or dirt. Put the blackberries in a non-stick saucepan and sprinkle over the caster sugar.", "Stir in the lemon juice and heat gently for two minutes, or until the blackberries begin to soften and release their juices. Remove and reserve 12 blackberries for decoration and continue cooking the rest.", "Simmer the blackberries very gently for 15 minutes, stirring regularly until very soft and squidgy. Remove from the heat and press the berries and juice through a sieve over a bowl, using the bottom of a ladle to help you extract as much of the purée as possible. Leave the purée to cool and discard the seeds. You should end up with around 325ml/11fl oz of purée.", "Put the cream and yoghurt in a large bowl and whip with an electric whisk until soft peaks form when the whisk is removed from the bowl – the acidity of the fruit will thicken the cream further, so don’t take it too far.", "When the purée is completely cold, adjust the sweetness to taste by adding more sugar if needed. Pour it into the bowl with the whipped cream and yoghurt and stir just once or twice until very lightly combined.", "Spoon the blackberry fool into individual wide, glass dishes – or one large, single bowl. It should look quite marbled, so don’t over-stir it. Scatter a few tiny mint leaves on top and decorate with the reserved blackberries. Sprinkle with a little sugar if you like and serve with the hazelnut biscuits."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/blackberry_fool_with_11859', 'https://www.themealdb.com/images/media/meals/rpvptu1511641092.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('blueberry-lemon-friands', 'Blueberry & lemon friands', 4, 0, 0, '{"calories": 632, "protein": 25.7, "carbs": 43.5, "fat": 39.5, "saturated_fat": 14.4, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 590.8, "potassium": 274.8, "fiber": 3.2, "sugar": 2.5, "vitamin_a": 160.8, "vitamin_c": 1.0, "calcium": 103.2, "iron": 1.2}'::jsonb, ARRAY['dessert', 'australian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 100.0, "unit": "g", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 125.0, "unit": "g", "item": "Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 25.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 85.0, "unit": "g", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "White", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Lemon", "notes": null, "category": "produce"}, {"quantity": 85.0, "unit": "g", "item": "Blackberries", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Preheat the oven to fan 180C/conventional 200C/gas 6. Generously butter six non-stick friand or muffin tins. Melt the butter and set aside to cool.", "step 2", "Sift the icing sugar and flour into a bowl. Add the almonds and mix everything between your fingers.", "step 3", "Whisk the egg whites in another bowl until they form a light, floppy foam. Make a well in the centre of the dry ingredients, tip in the egg whites and lemon rind, then lightly stir in the butter to form a soft batter.", "step 4", "Divide the batter among the tins, a large serving spoon is perfect for this job. Sprinkle a handful of blueberries over each cake and bake for 15-20 minutes until just firm to the touch and golden brown.", "step 5", "Cool in the tins for 5 minutes, then turn out and cool on a wire rack. To serve, dust lightly with icing sugar."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/blueberry-lemon-friands', 'https://www.themealdb.com/images/media/meals/e756bf1761848342.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bread-and-butter-pudding', 'Bread and Butter Pudding', 4, 0, 0, '{"calories": 35, "protein": 14.1, "carbs": 5.9, "fat": 22.8, "saturated_fat": 5.9, "polyunsaturated_fat": null, "monounsaturated_fat": 10.1, "sodium": 185.5, "potassium": 244.6, "fiber": 2.4, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": 267.1, "iron": 1.5}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 25.0, "unit": "g", "item": "25g/1oz butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "slices bread", "notes": null, "category": "grains"}, {"quantity": 50.0, "unit": "g", "item": "50g/2oz sultanas", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "cinnamon", "notes": null, "category": "spices"}, {"quantity": 350.0, "unit": "ml", "item": "350ml/12fl milk", "notes": null, "category": "dairy"}, {"quantity": 50.0, "unit": "ml", "item": "50ml/2fl oz double cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "free-range eggs", "notes": null, "category": "dairy"}, {"quantity": 25.0, "unit": "g", "item": "25g/1oz sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "grated", "notes": "to taste nutmeg", "category": "other"}]'::jsonb, '["Grease a 1 litre/2 pint pie dish with butter.", "Cut the crusts off the bread. Spread each slice with on one side with butter, then cut into triangles.", "Arrange a layer of bread, buttered-side up, in the bottom of the dish, then add a layer of sultanas. Sprinkle with a little cinnamon, then repeat the layers of bread and sultanas, sprinkling with cinnamon, until you have used up all of the bread. Finish with a layer of bread, then set aside.", "Gently warm the milk and cream in a pan over a low heat to scalding point. Don''t let it boil.", "Crack the eggs into a bowl, add three quarters of the sugar and lightly whisk until pale.", "Add the warm milk and cream mixture and stir well, then strain the custard into a bowl.", "Pour the custard over the prepared bread layers and sprinkle with nutmeg and the remaining sugar and leave to stand for 30 minutes.", "Preheat the oven to 180C/355F/Gas 4.", "Place the dish into the oven and bake for 30-40 minutes, or until the custard has set and the top is golden-brown."]'::jsonb, 'https://cooking.nytimes.com/recipes/1018529-coq-au-vin', 'https://www.themealdb.com/images/media/meals/xqwwpy1483908697.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('budino-di-ricotta', 'Budino Di Ricotta', 4, 0, 0, '{"calories": 365, "protein": 3.4, "carbs": 87.4, "fat": 2.4, "saturated_fat": 0.9, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 34.2, "potassium": 0.5, "fiber": null, "sugar": 62.5, "vitamin_a": null, "vitamin_c": null, "calcium": 11.5, "iron": 0.4}'::jsonb, ARRAY['dessert', 'italian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 500.0, "unit": "g", "item": "Ricotta", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tbs", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 250.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Grated Zest of 2 Lemons", "notes": null, "category": "produce"}, {"quantity": 5.0, "unit": "tbs", "item": "Dark Rum", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "sprinking Icing Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["Mash the ricotta and beat well with the egg yolks, stir in the flour, sugar, cinnamon, grated lemon rind and the rum and mix well. You can do this in a food processor. Beat the egg whites until stiff, fold in and pour into a buttered and floured 25cm cake tin. Bake in the oven at 180ºC/160ºC fan/gas 4 for about 40 minutes, or until it is firm.", "Serve hot or cold dusted with icing sugar."]'::jsonb, 'https://thehappyfoodie.co.uk/recipes/ricotta-cake-budino-di-ricotta', 'https://www.themealdb.com/images/media/meals/1549542877.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('canadian-butter-tarts', 'Canadian Butter Tarts', 4, 0, 0, '{"calories": 773, "protein": 10.6, "carbs": 114.7, "fat": 34.0, "saturated_fat": 13.0, "polyunsaturated_fat": null, "monounsaturated_fat": 1.4, "sodium": 228.2, "potassium": 191.1, "fiber": 3.5, "sugar": 42.1, "vitamin_a": null, "vitamin_c": null, "calcium": 115.0, "iron": 1.2}'::jsonb, ARRAY['dessert', 'canadian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 375.0, "unit": "g", "item": "Shortcrust Pastry", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 175.0, "unit": "g", "item": "Muscovado Sugar", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Raisins", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 4.0, "unit": "tsp", "item": "Single Cream", "notes": null, "category": "dairy"}, {"quantity": 50.0, "unit": "g", "item": "Walnuts", "notes": null, "category": "pantry"}]'::jsonb, '["Preheat the oven to fan 170C/ conventional 190C/gas 5. Roll out the pastry on a lightly floured surface so it’s slightly thinner than straight from the pack. Then cut out 18-20 rounds with a 7.5cm fluted cutter, re-rolling the trimmings. Use the rounds to line two deep 12-hole tart tins (not muffin tins). If you only have a regular-sized, 12-hole tart tin you will be able to make a few more slightly shallower tarts.", "Beat the eggs in a large bowl and combine with the rest of the ingredients except the walnuts. Tip this mixture into a pan and stir continuously for 3-4 minutes until the butter melts, and the mixture bubbles and starts to thicken. It should be thick enough to coat the back of a wooden spoon. Don’t overcook, and be sure to stir all the time as the mixture can easily burn. Remove from the heat and stir in the nuts.", "Spoon the filling into the unbaked tart shells so it’s level with the pastry. Bake for 15-18 minutes until set and pale golden. Leave in the tin to cool for a few minutes before lifting out on to a wire rack. Serve warm or cold."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/1837/canadian-butter-tarts', 'https://www.themealdb.com/images/media/meals/wpputp1511812960.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('caribbean-tamarind-balls', 'Caribbean Tamarind balls', 4, 0, 0, '{"calories": 395, "protein": 0.0, "carbs": 97.7, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": 11.3, "sugar": 154.4, "vitamin_a": null, "vitamin_c": 17.0, "calcium": 249.5, "iron": 4.3}'::jsonb, ARRAY['dessert', 'jamaican', 'themealdb', 'nutrition-generated', 'vegetarian', 'vegan'], '[{"quantity": 16.0, "unit": "ounces", "item": "Tamarind Pulp", "notes": null, "category": "other"}, {"quantity": 1.5, "unit": "cups", "item": "Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["Add tamarind pulp and 1 cup granulated sugar to a bowl and mash together with a spoon or fork. Take small amounts of the tamarind and sugar mix and shape them into small balls by rolling them in your hands. Make them the size of a marble or slightly bigger, as you like.", "Add the remaining sugar to a flat surface, like a plate or a sheet pan. Roll the tamarind balls in granulated sugar until they''re well-coated.", "You can eat the tamarind balls immediately, or you can let them set for a few hours or overnight. Allowing them to set will give them a firmer texture and more crystallized sugar coating. Enjoy."]'::jsonb, 'https://www.myforkinglife.com/tamarind-balls/#recipe', 'https://www.themealdb.com/images/media/meals/z1hz7z1765316430.jpg', FALSE, 5, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('carrot-cake', 'Carrot Cake', 4, 0, 0, '{"calories": 2122, "protein": 25.8, "carbs": 243.6, "fat": 167.8, "saturated_fat": 41.2, "polyunsaturated_fat": null, "monounsaturated_fat": 3.5, "sodium": 300.2, "potassium": 701.0, "fiber": 8.2, "sugar": 154.9, "vitamin_a": null, "vitamin_c": 9.6, "calcium": 133.2, "iron": 3.0}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 450.0, "unit": "ml", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tsp", "item": "Bicarbonate Of Soda", "notes": null, "category": "other"}, {"quantity": 550.0, "unit": "ml", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 500.0, "unit": "g", "item": "grated Carrots", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "g", "item": "Walnuts", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Cream Cheese", "notes": null, "category": "dairy"}, {"quantity": 150.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}]'::jsonb, '["For the carrot cake, preheat the oven to 160C/325F/Gas 3. Grease and line a 26cm/10in springform cake tin.", "Mix all of the ingredients for the carrot cake, except the carrots and walnuts, together in a bowl until well combined. Stir in the carrots and walnuts.", "Spoon the mixture into the cake tin and bake for 1 hour 15 minutes, or until a skewer inserted into the middle comes out clean. Remove the cake from the oven and set aside to cool for 10 minutes, then carefully remove the cake from the tin and set aside to cool completely on a cooling rack.", "Meanwhile, for the icing, beat the cream cheese, caster sugar and butter together in a bowl until fluffy. Spread the icing over the top of the cake with a palette knife."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/classic_carrot_cake_08513', 'https://www.themealdb.com/images/media/meals/vrspxv1511722107.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cashew-ghoriba-biscuits', 'Cashew Ghoriba Biscuits', 4, 0, 0, '{"calories": 939, "protein": 27.8, "carbs": 75.7, "fat": 63.9, "saturated_fat": 10.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 687.6, "potassium": 58.8, "fiber": 4.8, "sugar": 5.3, "vitamin_a": null, "vitamin_c": null, "calcium": 195.6, "iron": 7.3}'::jsonb, ARRAY['dessert', 'tunisian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 250.0, "unit": "g", "item": "Cashew Nuts", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Orange Blossom Water", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To Glaze Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Almonds", "notes": null, "category": "pantry"}]'::jsonb, '["Preheat the oven at 180 C / Gas 4. Line a baking tray with greaseproof paper.", "In a bowl, mix the cashews and icing sugar. Add the egg yolks and orange blossom water and mix to a smooth homogeneous paste.", "Take lumps of the cashew paste and shape into small balls. Roll the balls in icing sugar and transfer to the baking tray. Push an almond in the centre of each ghribia.", "Bake until the biscuits are lightly golden, about 20 minutes. Keep an eye on them, they burn quickly."]'::jsonb, 'http://allrecipes.co.uk/recipe/40152/cashew-ghoriba-biscuits.aspx', 'https://www.themealdb.com/images/media/meals/t3r3ka1560461972.jpg', FALSE, 5, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chelsea-buns', 'Chelsea Buns', 4, 0, 0, '{"calories": 717, "protein": 14.9, "carbs": 127.7, "fat": 18.5, "saturated_fat": 10.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 91.1, "potassium": 130.9, "fiber": 0.7, "sugar": 22.9, "vitamin_a": null, "vitamin_c": 20.0, "calcium": 120.0, "iron": 0.7}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 500.0, "unit": "g", "item": "White Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 7.0, "unit": "g", "item": "Yeast", "notes": null, "category": "pantry"}, {"quantity": 300.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 40.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 25.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 75.0, "unit": "g", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 150.0, "unit": "g", "item": "Dried Fruit", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "Caster Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["Sift the flour and salt into a large bowl. Make a well in the middle and add the yeast.", "Meanwhile, warm the milk and butter in a saucepan until the butter melts and the mixture is lukewarm.", "Add the milk mixture and egg to the flour mixture and stir until the contents of the bowl come together as a soft dough. (You may need to add a little extra flour.)", "Tip the dough onto a generously floured work surface. Knead for five minutes, adding more flour if necessary, until the dough is smooth and elastic and no longer feels sticky.", "Lightly oil a bowl with a little of the vegetable oil. Place the dough into the bowl and turn until it is covered in the oil. Cover the bowl with cling film and set aside in a warm place for one hour, or until the dough has doubled in size.", "Lightly grease a baking tray.", "For the filling, knock the dough back to its original size and turn out onto a lightly floured work surface. Roll the dough out into a rectangle 0.5cm/¼in thick. Brush all over with the melted butter, then sprinkle over the brown sugar, cinnamon and dried fruit.", "Roll the dough up into a tight cylinder , cut ten 4cm/1½in slice and place them onto a lightly greased baking sheet, leaving a little space between each slice. Cover with a tea towel and set aside to rise for 30 minutes.", "Preheat oven to 190C/375F/Gas 5.", "Bake the buns in the oven for 20-25 minutes, or until risen and golden-brown.", "Meanwhile, for the glaze, heat the milk and sugar in a saucepan until boiling. Reduce the heat and simmer for 2-3 minutes.", "Remove the buns from the oven and brush with the glaze, then set aside to cool on a wire rack."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/chelsea_buns_95015', 'https://www.themealdb.com/images/media/meals/vqpwrv1511723001.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chinon-apple-tarts', 'Chinon Apple Tarts', 4, 0, 0, '{"calories": 495, "protein": 4.8, "carbs": 49.3, "fat": 30.6, "saturated_fat": 18.2, "polyunsaturated_fat": null, "monounsaturated_fat": 6.4, "sodium": 268.5, "potassium": 126.7, "fiber": 1.6, "sugar": 21.1, "vitamin_a": null, "vitamin_c": 0.8, "calcium": 56.0, "iron": 1.7}'::jsonb, ARRAY['dessert', 'french', 'themealdb', 'nutrition-generated', 'baking', 'grilling', 'vegetarian', 'vegan'], '[{"quantity": 320.0, "unit": "g", "item": "Puff Pastry", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "tbs", "item": "Dark Brown Soft Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Apples", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tbs", "item": "Red Wine Jelly", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "ml", "item": "Creme Fraiche", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbs", "item": "Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Cardamom", "notes": null, "category": "spices"}]'::jsonb, '["To make the red wine jelly, put the red wine, jam sugar, star anise, clove, cinnamon stick, allspice, split vanilla pod and seeds in a medium saucepan. Stir together, then heat gently to dissolve the sugar. Turn up the heat and boil for 20 mins until reduced and syrupy. Strain into a small, sterilised jam jar and leave to cool completely. Will keep in the fridge for up to 1 month.", "Take the pastry out of the fridge and leave at room temperature for 10 mins, then unroll. Heat the grill to high and heat the oven to 180C/160C fan/gas 4. Cut out 2 x 13cm circles of pastry, using a plate as a guide, and place on a non-stick baking sheet. Sprinkle each circle with 1 tbsp sugar and grill for 5 mins to caramelise, watching carefully so that the sugar doesn’t burn. Remove from the grill. Can be done a few hours ahead, and left, covered, out of the fridge.", "Peel, quarter and core the apples, cut into 2mm-thin slices and arrange on top of the pastry. Sprinkle over the remaining sugar and pop in the oven for 20-25 mins until the pastry is cooked through and golden, and the apples are softened. Remove and allow to cool slightly. Warm 3 tbsp of the red wine jelly in a small pan over a low heat with 1 tsp water to make it a little more runny, then brush over the top of the tarts.", "Tip the crème fraîche into a bowl, sift over the icing sugar and cardamom, and mix together. Carefully lift the warm tarts onto serving plates and serve with the cardamom crème fraîche."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/chinon-apple-tarts', 'https://www.themealdb.com/images/media/meals/qtqwwu1511792650.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('choc-chip-pecan-pie', 'Choc Chip Pecan Pie', 4, 0, 0, '{"calories": 1796, "protein": 24.5, "carbs": 227.6, "fat": 127.2, "saturated_fat": 41.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 120.0, "potassium": 243.6, "fiber": 12.7, "sugar": 135.3, "vitamin_a": null, "vitamin_c": 4.3, "calcium": 164.3, "iron": 3.7}'::jsonb, ARRAY['dessert', 'american', 'themealdb', 'nutrition-generated', 'breakfast', 'baking', 'vegetarian'], '[{"quantity": 300.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 75.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Cream Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 150.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "ml", "item": "Maple Syrup", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Light Brown Soft Sugar", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Dark Brown Soft Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Pecan Nuts", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Dark Chocolate Chips", "notes": null, "category": "pantry"}]'::jsonb, '["First, make the pastry. Tip the ingredients into a food processor with 1 /4 tsp salt. Blend until the mixture resembles breadcrumbs. Drizzle 2-3 tsp cold water into the funnel while the blade is running – the mixture should start to clump together. Tip onto a work surface and bring together, kneading briefly into a ball. Pat into a disc, wrap in cling film, and chill for at least 20 mins. Heat oven to 200C/180C fan/gas 6.", "Remove the pastry from the fridge and leave at room temperature for 5 mins to soften. Flour the work surface, then unwrap the pastry and roll to a circle the thickness of a £1 coin. Use the pastry to line a deep, 23cm round fluted tin – mine was about 3cm deep. Press the pastry into the corners and up the sides, making sure there are no gaps. Leave 1cm pastry overhanging (save some of the pastry scraps for later). Line with baking parchment (scrunch it up first to make it more pliable) and fill with baking beans. Blind-bake for 15-20 mins until the sides are set, then remove the parchment and beans and return to the oven for 5 mins until golden brown. Trim the pastry so it’s flush with the top of the tin – a small serrated knife is best for this. If there are any cracks, patch them up with the pastry scraps.", "Meanwhile, weigh the butter, syrup and sugars into a pan, and add 1 /4 tsp salt. Heat until the butter has melted and the sugar dissolved, stirring until smooth. Remove from the heat and cool for 10 mins. Reduce oven to 160C/140C fan/gas 3.", "Beat the eggs in a bowl. Add the syrup mixture, vanilla and pecans, and mix until well combined. Pour half the mixture into the tart case, scatter over half the chocolate chips, then cover with the remaining filling and chocolate chips. Bake on the middle shelf for 50-55 mins until set. Remove from the oven and leave to cool, then chill for at least 2 hrs before serving."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/choc-chip-pecan-pie', 'https://www.themealdb.com/images/media/meals/rqvwxt1511384809.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chocolate-alfajores', 'Chocolate alfajores', 4, 0, 0, '{"calories": 1871, "protein": 16.1, "carbs": 226.6, "fat": 104.6, "saturated_fat": 63.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 283.9, "potassium": 112.5, "fiber": 3.8, "sugar": 157.4, "vitamin_a": null, "vitamin_c": 1.6, "calcium": 352.6, "iron": 3.5}'::jsonb, ARRAY['dessert', 'uruguayan', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 150.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 70.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 25.0, "unit": "g", "item": "Honey", "notes": null, "category": "pantry"}, {"quantity": 175.0, "unit": "g", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 80.0, "unit": "g", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 30.0, "unit": "g", "item": "Unsweetened Cocoa", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Dulce de leche", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "g", "item": "Milk Chocolate", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Orange", "notes": null, "category": "produce"}]'::jsonb, '["For the cookies cream the butter with the sugar for a few minutes. Then add the egg and honey and mix well. Add flour, cornstarch, cocoa, baking soda and baking powder and mix until you get a dough. Wrap in plastic wrap and chill for at least half an hour or overnight.", "2", "Line two baking sheets with parchment paper, preheat oven to 200 degrees Celsius.", "3", "Divide dough into two parts, put one part back in the fridge before using. Roll out second part to about 2 millimeters and cut out round cookies with 5-6 centimeters in diameter. This can be done with a cookie cutter or glass. You should get 30 cookies in total or even more, I get about 40. Bake one baking sheet at the time for about 8-10min. Let cookies cool.", "4", "For the filling look for two cookies of the same size and place about one teaspoon of dulce de leche onto the bottom one before sandwiching together.", "5", "Chop semi-sweet chocolate and melt with butter and orange zest on low heat. Dunk each sandwich cookie into the chocolate and let cool off on parchment paper before serving."]'::jsonb, 'https://jennyisbaking.com/2018/07/02/alfajores-the-best-cookies-from-uruguay/#recipe', 'https://www.themealdb.com/images/media/meals/k9o0xr1764373018.jpg', FALSE, 5, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chocolate-avocado-mousse', 'Chocolate Avocado Mousse', 4, 0, 0, '{"calories": 349, "protein": 6.5, "carbs": 53.7, "fat": 17.1, "saturated_fat": 4.4, "polyunsaturated_fat": null, "monounsaturated_fat": 0.8, "sodium": 214.1, "potassium": 229.1, "fiber": 2.5, "sugar": 31.8, "vitamin_a": null, "vitamin_c": 3.8, "calcium": 41.9, "iron": 2.2}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Banana", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbsp", "item": "Cacao", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Avocado", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Honey", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbsp", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Sea Salt", "notes": null, "category": "pantry"}]'::jsonb, '["1. Blend all the mousse ingredients together in your food processor until smooth. Add the cacao powder first and, as you blend, have all the ingredients to hand in order to adjust the ratios slightly as the size of avocados and bananas varies so much. The perfect ratio in order to avoid the dish tasting too much of either is to use equal amounts of both.", "2. Taste and add a few drops of stevia if you feel you need more sweetness.", "3. Fill little cups or shot glasses with the mousse, sprinkle with the cacao powder or nibs and serve.", "Tip If you don’t have a frozen banana to hand you can just use a normal one and then chill the mousse before serving for a cooling dessert."]'::jsonb, 'http://www.hemsleyandhemsley.com/recipe/chocolate-avocado-mousse/', 'https://www.themealdb.com/images/media/meals/uttuxy1511382180.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chocolate-caramel-crispy', 'Chocolate Caramel Crispy', 4, 0, 0, '{"calories": 680, "protein": 4.2, "carbs": 58.0, "fat": 49.4, "saturated_fat": 28.7, "polyunsaturated_fat": 0.1, "monounsaturated_fat": 1.6, "sodium": 188.3, "potassium": 44.7, "fiber": 1.1, "sugar": 41.4, "vitamin_a": null, "vitamin_c": null, "calcium": 55.0, "iron": 1.1}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Mars Bar", "notes": null, "category": "other"}, {"quantity": 150.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 120.0, "unit": "g", "item": "Rice Krispies", "notes": null, "category": "grains"}, {"quantity": 150.0, "unit": "g", "item": "Milk Chocolate", "notes": null, "category": "dairy"}]'::jsonb, '["Grease and line a 20 x 20cm/8\" x 8\" baking tin with parchment paper.", "Put the mars bars and butter in a heat proof bowl and place over a pan of barely simmering water. Mixing with a whisk, melt until the mixture is smooth.", "Pour over the rice krispies in a mixing bowl and mix until all the ingredients are evenly combined. Press evenly into the prepare baking tin and set aside.", "Melt the milk chocolate in the microwave or over a pan of barely simmering water.", "Spread the melted chocolate over the rice krispie mixture and leave to set in a cool place. Once set slice into squares and serve!"]'::jsonb, 'http://www.donalskehan.com/recipes/chocolate-caramel-rice-crispy-treats/', 'https://www.themealdb.com/images/media/meals/1550442508.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chocolate-churros-with-chocolate-salted-caramel-sauce', 'Chocolate churros with chocolate & salted caramel sauce', 4, 0, 0, '{"calories": 472, "protein": 16.0, "carbs": 110.4, "fat": 53.6, "saturated_fat": 24.8, "polyunsaturated_fat": null, "monounsaturated_fat": 8.9, "sodium": 19.8, "potassium": 364.9, "fiber": 11.4, "sugar": 23.5, "vitamin_a": null, "vitamin_c": null, "calcium": 115.6, "iron": 7.5}'::jsonb, ARRAY['dessert', 'spanish', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "For frying Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Ice Cream", "notes": null, "category": "dairy"}, {"quantity": 120.0, "unit": "g", "item": "Muscovado Sugar", "notes": null, "category": "pantry"}, {"quantity": 60.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 250.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Dark Chocolate", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Golden Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "teaspoon", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 200.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 50.0, "unit": "g", "item": "Cocoa Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "Melted Butter", "notes": null, "category": "dairy"}]'::jsonb, '["step 1", "To make the sauce, tip the sugar and butter into a saucepan and bring to a simmer until the sugar has melted, then stir in the cream and simmer until you have a smooth sauce, about 2-3 mins. Remove from the heat, stir through a pinch of sea salt and the chocolate, and continue to stir for 2-3 mins, or until it has completely melted. Keep warm or leave to cool for reheating later. For the coating, mix the sugar with the cinnamon and a small pinch of fine sea salt and set aside.", "step 2", "For the churros, tip the flour, cocoa, baking powder and a large pinch of salt into a bowl. Add the vanilla extract and melted butter, then carefully pour in 250-300ml boiling water and whisk to make a smooth, very thick batter. Leave to cool for a few minutes, then scrape the mixture into a piping bag fitted with a medium star nozzle.", "step 3", "Tip sunflower oil into a deep-fat fryer following the manufacturer’s instructions, or a heavy-based pan, ensuring it is no more than a third full. Heat to 170C, or until a cube of bread dropped in browns in 30 seconds. Pipe 12-15cm lengths of dough into the oil, snipping off the end of each one with a pair of scissors as you go. Pipe four or five at a time and cook for around 4 mins, or until golden and crisp, turning them with tongs or a slotted spoon as they cook. Remove from the oil and place on a wire rack. Repeat with the rest of the dough. Leave to cool if reheating later, otherwise roll the churros in the cinnamon sugar and serve immediately with the warm chocolate sauce and ice cream. To reheat the churros, put on a tray and bake for 5-8 mins, then roll in the sugar coating. Meanwhile, warm the sauce in a pan and serve alongside for dipping."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/chocolate-churros-with-chocolate-salted-caramel-sauce', 'https://www.themealdb.com/images/media/meals/erzs951763296201.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chocolate-coconut-squares', 'Chocolate Coconut Squares', 4, 0, 0, '{"calories": 699, "protein": 7.8, "carbs": 92.3, "fat": 47.8, "saturated_fat": 19.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 258.7, "potassium": 53.1, "fiber": 3.1, "sugar": 31.9, "vitamin_a": null, "vitamin_c": null, "calcium": 174.1, "iron": 2.4}'::jsonb, ARRAY['dessert', 'australian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 100.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 140.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Cocoa Powder", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Plain Chocolate", "notes": null, "category": "pantry"}, {"quantity": 25.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Desiccated Coconut", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Heat oven to 180C/fan 160C/gas 4. Butter and line the base of a 20cm square baking tin. Beat together the butter and sugar until pale and creamy, then beat in the eggs. Add 1 tbsp of the flour if the mix starts to curdle.", "step 2", "Sieve in the flour, baking powder and cocoa and fold in with a metal spoon. Stir in the milk. Scrape mix into the tin and level the top. Bake for 18-20 mins or until the cake springs back when pressed. Allow to cool in the tin.", "step 3", "To make the icing, put the chocolate, butter and 4 tbsp water in a pan and gently heat until melted. Allow to cool slightly, then beat in the icing sugar.", "step 4", "Remove cake from tin and peel away paper. Cut into 16 squares. Dip the squares into the icing, then roll in the coconut. Allow to set on cooling rack."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/isaacs-chocolate-coconut-squares', 'https://www.themealdb.com/images/media/meals/8oupz51761848432.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chocolate-empanadas', 'Chocolate empanadas', 4, 0, 0, '{"calories": 1112, "protein": 15.1, "carbs": 146.4, "fat": 51.8, "saturated_fat": 27.4, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 129.6, "potassium": 178.8, "fiber": 4.3, "sugar": 28.1, "vitamin_a": null, "vitamin_c": null, "calcium": 46.5, "iron": 3.5}'::jsonb, ARRAY['dessert', 'uruguayan', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 400.0, "unit": "g", "item": "Condensed Milk", "notes": null, "category": "dairy"}, {"quantity": 250.0, "unit": "g", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 25.0, "unit": "g", "item": "Unsweetened Cocoa", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 125.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 30.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 30.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}]'::jsonb, '["For the filling place the can in a large pot and cover completely with water. Boil for two and a half hours, occassionally adding water. Let cool before opening. For further tips, please check here.", "2", "For the dough combine the flour, cocoa powder, and salt in a large bowl. Add the cold butter in small pieces and rub into crumbs with your fingers Add the egg and work into a dough. You may have to add milk, a tablespoon at a time if it still is to dry. Wrap and chill for at least half an hour or overnight.", "3", "Line a baking sheeet with parchment paper and preheat the oven to 180 degrees Celsius.", "4", "Roll out the dough on a lightly floured surface, it should be thin. Cut out circles of 12cm either with a cookie cutter or with a smaller plate/dish. Put two to three teaspoons of the dulce de leche in the middle of each circle. Brush the edges with milk, I do this with my pinkie. Fold each circle in half so that you have a half moon and press down the edges with a fork. You can also turn the edges about half a centimeter inwards every centimeter or so to create a pattern.", "5", "Place the prepared empanadas on the baking sheet and brush with egg wash. Bake for about 20-25min.", "6", "Towards the end of the baking time, melt the remaining butter and mix the sugar and cinnamon in a small bowl. Once you take the empanadas out, immediately brush with the butter and sprinkle with the sugar mix. Empanadas can be enjoyed either still warm or cold. If eating warm, be careful not to burn yourself with hot filling!"]'::jsonb, 'https://jennyisbaking.com/2020/05/01/chocolate-empanadas-with-dulce-de-leche/', 'https://www.themealdb.com/images/media/meals/u9ezi21764375474.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chocolate-gateau', 'Chocolate Gateau', 4, 0, 0, '{"calories": 614, "protein": 8.1, "carbs": 70.7, "fat": 36.7, "saturated_fat": 22.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 66.2, "potassium": 131.6, "fiber": null, "sugar": 43.8, "vitamin_a": null, "vitamin_c": null, "calcium": 115.9, "iron": 1.5}'::jsonb, ARRAY['dessert', 'french', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 250.0, "unit": "g", "item": "Plain chocolate", "notes": null, "category": "pantry"}, {"quantity": 175.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 175.0, "unit": "g", "item": "Granulated Sugar", "notes": null, "category": "pantry"}, {"quantity": 125.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}]'::jsonb, '["Preheat the oven to 180°C/350°F/Gas Mark 4. Grease and line the base of an 8 in round spring form cake tin with baking parchment", "Break the chocolate into a heatproof bowl and place over a saucepan of gently simmering water and stir until it melts. (or melt in the microwave for 2-3 mins stirring occasionally)", "Place the butter and sugar in a mixing bowl and cream together with a wooden spoon until light and fluffy. Gradually beat in the eggs, adding a little flour if the mixture begins to curdle. Fold in the remaining flour with the cooled, melted chocolate and milk. Mix until smooth.", "Spread the mixture into the cake tin and bake for 50-55 mins or until firm in the centre and a skewer comes out cleanly. Cool for 10 minutes, then turn out and cool completely."]'::jsonb, 'http://www.goodtoknow.co.uk/recipes/536028/chocolate-gateau', 'https://www.themealdb.com/images/media/meals/tqtywx1468317395.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chocolate-raspberry-brownies', 'Chocolate Raspberry Brownies', 4, 0, 0, '{"calories": 1278, "protein": 18.2, "carbs": 172.4, "fat": 81.6, "saturated_fat": 44.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 453.9, "potassium": 595.4, "fiber": 14.4, "sugar": 124.7, "vitamin_a": null, "vitamin_c": 13.2, "calcium": 129.8, "iron": 10.1}'::jsonb, ARRAY['dessert', 'american', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 200.0, "unit": "g", "item": "Dark Chocolate", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Milk Chocolate", "notes": null, "category": "dairy"}, {"quantity": 250.0, "unit": "g", "item": "Salted Butter", "notes": null, "category": "dairy"}, {"quantity": 400.0, "unit": "g", "item": "Light Brown Soft Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 140.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 50.0, "unit": "g", "item": "Cocoa", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Raspberries", "notes": null, "category": "other"}]'::jsonb, '["Heat oven to 180C/160C fan/gas 4. Line a 20 x 30cm baking tray tin with baking parchment. Put the chocolate, butter and sugar in a pan and gently melt, stirring occasionally with a wooden spoon. Remove from the heat.", "Stir the eggs, one by one, into the melted chocolate mixture. Sieve over the flour and cocoa, and stir in. Stir in half the raspberries, scrape into the tray, then scatter over the remaining raspberries. Bake on the middle shelf for 30 mins or, if you prefer a firmer texture, for 5 mins more. Cool before slicing into squares. Store in an airtight container for up to 3 days."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/2121648/bestever-chocolate-raspberry-brownies', 'https://www.themealdb.com/images/media/meals/yypvst1511386427.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chocolate-souffle', 'Chocolate Souffle', 4, 0, 0, '{"calories": 565, "protein": 39.7, "carbs": 53.4, "fat": 55.8, "saturated_fat": 19.9, "polyunsaturated_fat": null, "monounsaturated_fat": 10.4, "sodium": 834.7, "potassium": 893.9, "fiber": 9.6, "sugar": 28.2, "vitamin_a": null, "vitamin_c": null, "calcium": 719.3, "iron": 6.9}'::jsonb, ARRAY['dessert', 'french', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 142.0, "unit": "ml", "item": "Single Cream", "notes": null, "category": "dairy"}, {"quantity": 25.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Dark Chocolate", "notes": null, "category": "pantry"}, {"quantity": 25.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "drizzle Butter", "notes": null, "category": "dairy"}, {"quantity": 50.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 175.0, "unit": "g", "item": "Dark Chocolate", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "White", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Icing Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["Heat oven to 220C/fan 200C/gas 7 and place a baking tray on the top shelf. For the sauce, heat the cream and sugar until boiling. Remove from the heat, stir in the chocolate and butter until melted, then keep warm.", "Brush 6 x 150ml ramekins with melted butter, sprinkle with the 2 tbsp caster sugar, then tip out any excess. Melt the chocolate and cream in a bowl over a pan of simmering water, cool, then mix in the egg yolks. Whisk the egg whites until they hold their shape, then add the sugar, 1 tbsp at a time, whisking back to the same consistency. Mix a spoonful into the chocolate, then gently fold in the rest.", "Working quickly, fill the ramekins, wipe the rims clean and run your thumb around the edges. Turn oven down to 200C/fan 180C/gas 6, place the ramekins onto the baking tray, then bake for 8-10 mins until risen with a slight wobble. Don’t open the oven door too early as this may make them collapse.", "Once the soufflés are ready, dust with icing sugar, scoop a small hole from their tops, then pour in some of the hot chocolate sauce. Replace the lids and serve straight away."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/5816/hot-chocolate-souffls-with-chocolate-cream-sauce', 'https://www.themealdb.com/images/media/meals/twspvx1511784937.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('christmas-cake', 'Christmas cake', 4, 0, 0, '{"calories": 1155, "protein": 19.7, "carbs": 197.0, "fat": 65.4, "saturated_fat": 28.3, "polyunsaturated_fat": null, "monounsaturated_fat": 0.7, "sodium": 60.4, "potassium": 575.7, "fiber": 14.5, "sugar": 83.6, "vitamin_a": null, "vitamin_c": 1.1, "calcium": 170.3, "iron": 4.8}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 200.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "Muscovado Sugar", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 50.0, "unit": "g", "item": "Ground Almonds", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "ml", "item": "Sherry", "notes": null, "category": "other"}, {"quantity": 85.0, "unit": "g", "item": "Candied Peel", "notes": null, "category": "other"}, {"quantity": 85.0, "unit": "g", "item": "Glace Cherry", "notes": null, "category": "other"}, {"quantity": 250.0, "unit": "g", "item": "Raisins", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Currants", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Pecan Nuts", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Grated zest of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tbsp", "item": "Mixed Spice", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tbsp", "item": "Rose water", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}]'::jsonb, '["Heat oven to 160C/fan 140C/gas 3. Line the base and sides of a 20 cm round, 7.5 cm deep cake tin. Beat the butter and sugar with an electric hand mixer for 1-2 mins until very creamy and pale in colour, scraping down the sides of the bowl half way through. Stir in a spoonful of the flour, then stir in the beaten egg and the rest of the flour alternately, a quarter at a time, beating well each time with a wooden spoon. Stir in the almonds.", "Mix in the sherry (the mix will look curdled), then add the peel, cherries, raisins, cherries, nuts, lemon zest, spice, rosewater and vanilla. Beat together to mix, then stir in the baking powder.", "Spoon mixture into the tin and smooth the top, making a slight dip in the centre. Bake for 30 mins, then lower temperature to 150C/fan 130C/gas 2 and bake a further 2-2¼ hrs, until a skewer insterted in the middle comes out clean. Leave to cool in the tin, then take out of the tin and peel off the lining paper. When completely cold, wrap well in cling film and foil to store until ready to decorate. The cake will keep for several months."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/angela-nilsens-christmas-cake', 'https://www.themealdb.com/images/media/meals/ldnrm91576791881.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('christmas-pudding-flapjack', 'Christmas Pudding Flapjack', 4, 0, 0, '{"calories": 1575, "protein": 19.6, "carbs": 224.1, "fat": 67.8, "saturated_fat": 37.2, "polyunsaturated_fat": null, "monounsaturated_fat": 3.1, "sodium": 592.6, "potassium": null, "fiber": 12.5, "sugar": 120.9, "vitamin_a": null, "vitamin_c": 1.6, "calcium": 38.4, "iron": 6.1}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 250.0, "unit": "g", "item": "salted butter", "notes": null, "category": "dairy"}, {"quantity": 225.0, "unit": "g", "item": "dark soft brown sugar", "notes": null, "category": "pantry"}, {"quantity": 150.0, "unit": "g", "item": "golden syrup", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 orange", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "g", "item": "rolled oats", "notes": null, "category": "grains"}, {"quantity": 250.0, "unit": "g", "item": "Christmas pudding", "notes": null, "category": "other"}]'::jsonb, '["Preheat the oven to 180°C/fan 160°C/gas mark 4 and grease and line a 25cm x 20cm tin. Melt the butter, sugar, syrup and orange zest in a large saucepan over a medium heat. The aim is to dissolve all the ingredients so that they are smooth, but to not lose any volume through boiling so be careful not to overheat.", "Add the oats and stir well until evenly coated. Stir through the leftover Christmas pudding and tip into the prepared tin. Use a spoon to flatten the top and bake for 40 minutes until the edges start to brown. Whilst still warm in the tin, score into 12 squares. Allow to cool completely before cutting along the scores.", "Keeps for 5 days in an air tight tin or freeze for up to 1 month."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/vvusxs1483907034.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('christmas-pudding-trifle', 'Christmas Pudding Trifle', 4, 0, 0, '{"calories": 860, "protein": 21.7, "carbs": 101.4, "fat": 84.1, "saturated_fat": 39.5, "polyunsaturated_fat": null, "monounsaturated_fat": 5.2, "sodium": 392.6, "potassium": 378.3, "fiber": 4.9, "sugar": 65.3, "vitamin_a": null, "vitamin_c": null, "calcium": 359.4, "iron": 2.8}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Orange", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Demerara Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Grand Marnier", "notes": null, "category": "other"}, {"quantity": 300.0, "unit": "g", "item": "Christmas Pudding", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "g", "item": "Custard", "notes": null, "category": "other"}, {"quantity": 250.0, "unit": "g", "item": "Mascarpone", "notes": null, "category": "dairy"}, {"quantity": 284.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Flaked Almonds", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Grated Dark Chocolate", "notes": null, "category": "pantry"}]'::jsonb, '["Peel the oranges using a sharp knife, ensuring all the pith is removed. Slice as thinly as possible and arrange over a dinner plate. Sprinkle with the demerara sugar followed by the Grand Marnier and set aside.", "Crumble the Christmas pudding into large pieces and scatter over the bottom of a trifle bowl. Lift the oranges onto the pudding in a layer and pour over any juices.", "Beat the mascarpone until smooth, then stir in the custard. Spoon the mixture over the top of the oranges.", "Lightly whip the cream and spoon over the custard. Sprinkle with the flaked almonds and grated chocolate. You can make this a day in advance if you like, chill until ready to serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/1826685/christmas-pudding-trifle', 'https://www.themealdb.com/images/media/meals/r33cud1576791081.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('churros', 'Churros', 4, 0, 0, '{"calories": 2332, "protein": 16.0, "carbs": 98.7, "fat": 240.9, "saturated_fat": 34.9, "polyunsaturated_fat": null, "monounsaturated_fat": 124.7, "sodium": 120.8, "potassium": 394.4, "fiber": 7.8, "sugar": 30.1, "vitamin_a": null, "vitamin_c": 0.3, "calcium": 129.2, "iron": 4.6}'::jsonb, ARRAY['dessert', 'spanish', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 50.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "l", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 200.0, "unit": "g", "item": "Dark Chocolate", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Golden Syrup", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "teaspoon", "item": "Cinnamon", "notes": null, "category": "spices"}]'::jsonb, '["step 1", "Boil the kettle, then measure 300ml boiling water into a jug and add the melted butter and vanilla extract. Sift the flour and baking powder into a big mixing bowl with a big pinch of salt. Make a well in the centre, then pour in the contents of the jug and very quickly beat into the flour with a wooden spoon until lump-free. Rest for 10-15 mins while you make the sauce.", "step 2", "Put all the sauce ingredients into a pan and gently melt together, stirring occasionally until you have a smooth shiny sauce. Keep warm on a low heat.", "step 3", "Fill a large deep saucepan one-third full of oil. Cooking with hot oil can be dangerous – before you start, read up on how to deep-fry safely to avoid accidents in the kitchen. Heat until a cube of bread browns in 45 seconds to 1 min. Cover a tray with kitchen paper and mix the caster sugar and cinnamon together.", "step 4", "Fit a star nozzle to a piping bag – 1.5-2cm wide is a good size. Fill with the rested dough, then pipe 2-3 strips directly into the pan, snipping off each dough strip with a pair of kitchen scissors. Fry until golden brown and crisp. Be very careful here – if air bubbles form in the churros they can explode, especially if the oil overheats or you use old flour. Cooking with hot oil can be dangerous – before you start, read up on how to deep-fry safely to avoid accidents in the kitchen. Keep children out of the kitchen and protect yourself by wearing long sleeves and eye protection, and keeping your face away from the pan.", "step 5", "Once the churros are crisp and golden brown, remove them from the oil with a slotted spoon and drain on the kitchen paper-lined tray. Carry on cooking the rest of the dough in batches, sprinkling the cooked churros with some cinnamon sugar as you go. When you’ve cooked all the churros, toss with any remaining cinnamon sugar and serve with the chocolate sauce, for dipping.", "To see a video of how to prepare churros, take a look at our churros ice cream sandwich recipe."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/churros-chocolate-dipping-sauce', 'https://www.themealdb.com/images/media/meals/nxnny61763250596.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cinnamon-buns', 'Cinnamon buns', 4, 0, 0, '{"calories": 1419, "protein": 13.5, "carbs": 169.3, "fat": 74.0, "saturated_fat": 33.9, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 119.5, "potassium": 46.9, "fiber": 1.9, "sugar": 66.4, "vitamin_a": 281.3, "vitamin_c": 0.5, "calcium": 133.2, "iron": 2.4}'::jsonb, ARRAY['dessert', 'norwegian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 100.0, "unit": "g", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 250.0, "unit": "g", "item": "Strong White Flour", "notes": null, "category": "grains"}, {"quantity": 1.5, "unit": "tsp", "item": "Fast action yeast", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Cardamom", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 75.0, "unit": "g", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}]'::jsonb, '["In a small saucepan heat the butter, milk and salt until the butter is melted. Allow the mixture to cool until it is lukewarm.", "In a large bowl, stir together the flours, yeast, cardamom and sugar until combined.", "Make a well in the centre and crack in the eggs. Pour in the lukewarm milk mixture and stir everything together to form a sticky dough. You may have to use your hands as the dough becomes stiffer.", "Oil the work surface with a teaspoon of olive oil. Turn the dough out onto the oiled surface and knead vigorously for 5–8 minutes, using a plastic scraper as needed to prise the dough from the work surface. Don’t be tempted to add flour, as this will make the buns dry and tough. Keep kneading until the dough is considerably less sticky, smoother and more elastic.", "Shape into a ball, and put into a large, greased bowl. Cover the bowl with a clean tea towel and set aside in a warm place to prove for an hour, or until doubled in size.", "Meanwhile, for the filling and topping, mix the softened butter in a bowl with half the sugar and 1 tablespoon cinnamon. Use a fork to mix the sugar and spice into the butter until it is completely combined.", "Mix the remaining sugar and cinnamon in a separate bowl and set aside.", "When the dough has risen, turn out onto a floured work surface and gently roll out into a 36x24cm/14x9½in rectangle. Spread the cinnamon-sugar-butter evenly over the dough with a table or palette knife.", "With the longest edge closest to you, roll the dough up into a cylinder. Cut into 12 even slices.", "Place each slice onto a flattened out paper cupcake case on a baking tray, or into a greased muffin tin. (Baking in a muffin tin will make your cinnamon buns taller and domed.)", "Cover with a clean tea towel and set aside to prove again for 30–45 minutes, or until risen.", "Preheat the oven to 200C/180C Fan/Gas 6.", "Brush the tops of the buns with beaten egg and dust liberally with the cinnamon sugar. Bake for 12 minutes until the buns are dark golden-brown. Enjoy warm with a cup of coffee."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/cinnamon_buns_10634', 'https://www.themealdb.com/images/media/meals/as88dq1762772486.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('classic-christmas-pudding', 'Classic Christmas pudding', 4, 0, 0, '{"calories": 1632, "protein": 20.9, "carbs": 286.6, "fat": 63.9, "saturated_fat": 36.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 242.0, "potassium": 1408.7, "fiber": 14.4, "sugar": 185.0, "vitamin_a": null, "vitamin_c": null, "calcium": 246.8, "iron": 5.4}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 50.0, "unit": "g", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Bramley Apples", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Candied Peel", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "whole", "item": "Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "kg", "item": "Raisins", "notes": null, "category": "pantry"}, {"quantity": 140.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 100.0, "unit": "g", "item": "Breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 100.0, "unit": "g", "item": "Muscovado Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "Brandy", "notes": null, "category": "other"}, {"quantity": 250.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}]'::jsonb, '["Get everything for the pudding prepared. Chop the almonds coarsely. Peel, core and chop the cooking apples. Sharpen your knife and chop the candied peel. (You can chop the almonds and apples in a food processor, but the peel must be done by hand.) Grate three quarters of the nutmeg (sounds a lot but it''s correct).", "Mix the almonds, apples, candied peel, nutmeg, raisins, flour, breadcrumbs, light muscovado sugar, eggs and 2 tbsp brandy or cognac in a large bowl.", "Holding the butter in its wrapper, grate a quarter of it into the bowl, then stir everything together. Repeat until all the butter is grated, then stir for 3-4 mins – the mixture is ready when it subsides slightly after each stir. Ask the family to stir too, and get everyone to make a wish.", "Generously butter two 1.2 litre bowls and put a circle of baking parchment in the bottom of each. Pack in the pudding mixture. Cover with a double layer of baking parchment, pleating it to allow for expansion, then tie with string (keep the paper in place with a rubber band while tying). Trim off any excess paper.", "Now stand each bowl on a large sheet of foil and bring the edges up over the top, then put another sheet of foil over the top and bring it down underneath to make a double package (this makes the puddings watertight). Tie with more string, and make a handle for easy lifting in and out of the pan. Watch our video to see how to tie up a pudding correctly.", "Boil or oven steam the puddings for 8 hrs, topping up with water as necessary. Remove from the pans and leave to cool overnight. When cold, discard the messy wrappings and re-wrap in new baking parchment, foil and string. Store in a cool, dry place until Christmas.", "To make the brandy butter, cream the butter with the orange zest and icing sugar. Gradually beat in the brandy or cognac and chopped stem ginger. Put in a small bowl, fork the top attractively and put in the fridge to set. The butter will keep for a week in the fridge, or it can be frozen for up to six weeks.", "On Christmas Day, boil or oven steam for 1 hr. Unwrap and turn out. To flame, warm 3-4 tbsp brandy in a small pan, pour it over the pudding and set light to it."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/classic-christmas-pudding', 'https://www.themealdb.com/images/media/meals/1d85821576790598.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cornes-de-gazelle-gazelle-horns', 'Cornes de Gazelle (Gazelle Horns)', 4, 0, 0, '{"calories": 1560, "protein": 32.8, "carbs": 464.6, "fat": 103.8, "saturated_fat": 28.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 10375.2, "potassium": null, "fiber": 13.4, "sugar": 71.8, "vitamin_a": 182.5, "vitamin_c": null, "calcium": 457.9, "iron": 4.3}'::jsonb, ARRAY['dessert', 'algerian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 0.75, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Ground Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Orange Blossom Water", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "cup", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tbsp", "item": "Orange Blossom Water", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Pistachio", "notes": null, "category": "pantry"}]'::jsonb, '["Preheat oven to 300 degrees F (150 degrees C). Line a baking sheet with parchment paper. Spread almonds over the baking sheet.", "Bake in the preheated oven until almonds are fragrant and roasted, 20 to 25 minutes.", "Prepare pastry dough while almonds are roasting. Combine flour, 1/2 cup plus 1 tablespoon butter, and salt in a bowl and rub together until the mixture resembles breadcrumbs. Add egg, oil, and 1 1/2 tablespoons orange blossom water; knead everything into a smooth pastry dough. Add a little water, 1 teaspoon at a time, if dough is too dry. Shape pastry dough into a ball, wrap in plastic wrap, and set aside for 30 minutes.", "Remove almonds from oven and cool slightly, about 5 minutes. Place almonds in the bowl of a food processor; process until finely and evenly ground. Add 3/4 cup plus 1 tablespoon sugar, cinnamon, egg, and 1 tablespoon orange blossom water in that order to the food processor, pulsing after each addition until mixture is evenly combined and resembles a paste.", "Remove small walnut-sized portions of filling with greased hands. Roll them into small logs with thin ends. Set aside.", "Preheat oven to 325 degrees F (165 degrees C). Line a baking sheet with parchment paper.", "Roll out half of the pastry dough on a lightly floured surface until very thin. Place one of the almond paste logs on the edge of the pastry, fold pastry over the filling, covering it completely, and seal the edges. Mold with your fingers into a crescent shape. Using a pastry cutter, cut around the crescent, and transfer to the prepared baking sheet. Repeat with remaining dough and filling.", "Bake in the preheated oven until gazelle horns are lightly golden and baked through, about 20 minutes. They should not get too dark. Let cool slightly, about 3 minutes.", "Heat honey in a small saucepan over low-medium heat. Remove from heat and stir in 1 tablespoon orange blossom water. Dip gazelle horns into the honey and place on a serving plate. Sprinkle with crushed pistachios."]'::jsonb, 'https://www.allrecipes.com/recipe/262056/cornes-de-gazelle-gazelle-horns/', 'https://www.themealdb.com/images/media/meals/0h1b7m1764120235.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('crema-catalana', 'Crema Catalana', 4, 0, 0, '{"calories": 349, "protein": 14.0, "carbs": 37.6, "fat": 50.5, "saturated_fat": 20.4, "polyunsaturated_fat": null, "monounsaturated_fat": 7.0, "sodium": 236.5, "potassium": 99.9, "fiber": 0.8, "sugar": 23.5, "vitamin_a": 189.5, "vitamin_c": 1.0, "calcium": 226.7, "iron": 2.6}'::jsonb, ARRAY['dessert', 'spanish', 'themealdb', 'nutrition-generated', 'baking', 'grilling', 'vegetarian'], '[{"quantity": 400.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 150.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Stick", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Zest", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Zest", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 6.0, "unit": "tablespoons", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 45.0, "unit": "g", "item": "Corn Flour", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Put the milk, cream, cinnamon stick and all the citrus zest in a saucepan set over a medium heat. Cook, stirring often, until the milk is just steaming but not boiling, about 3-5 mins. Remove from the heat, cover with a plate and leave to infuse for at least 30 mins.", "step 2", "When the cream mixture has infused, whisk the egg yolks, sugar and cornflour together in a separate bowl for 3-5 mins, or until light and pale in colour. Pour the infused milk through a sieve into the egg mixture, whisking continuously. Return the mixture to the saucepan.", "step 3", "Put the saucepan over a medium-high heat and whisk for around 10-12 mins. The mixture should start thickening to a custard-like consistency – you can tell it’s ready by dipping a wooden spoon in the mixture, then running a finger through the mixture on the back of the spoon. If the line holds, it''s ready. Sieve the mixture into a jug to remove any froth.", "step 4", "Divide the custard between six 150ml ramekins or small terracotta dishes, then leave to cool for 1 hr at room temperature until set with a slight wobble. Chill overnight.", "step 5", "Just before serving, sprinkle 1 tbsp caster sugar over the top of each ramekin and caramelise using a kitchen blowtorch. Alternatively, slide the ramekins under a hot grill until the sugar turns golden and starts to bubble. Serve straightaway."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/crema-catalana', 'https://www.themealdb.com/images/media/meals/x73ll91763247842.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('date-squares', 'Date squares', 4, 0, 0, '{"calories": 1688, "protein": 9.7, "carbs": 150.3, "fat": 70.8, "saturated_fat": 36.7, "polyunsaturated_fat": null, "monounsaturated_fat": 1.1, "sodium": 177.9, "potassium": null, "fiber": 4.5, "sugar": 85.6, "vitamin_a": 364.9, "vitamin_c": null, "calcium": 24.8, "iron": 2.0}'::jsonb, ARRAY['dessert', 'canadian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 2.5, "unit": "cups", "item": "Pitted Dates", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.5, "unit": "cup", "item": "Vanilla", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "cups", "item": "Oats", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "cup", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "cup", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Unsalted Butter", "notes": null, "category": "dairy"}]'::jsonb, '["Preheat oven to 350°F (180°C). Grease an 8-inch (20 cm) square baking pan.", "To make the date filing: Combine the dates and water in a medium saucepan over high heat and bring to a boil. Reduce heat to low and simmer gently, stirring occasionally until the mixture thickens, around 6 to 8 minutes. Remove from heat, stir in vanilla and let cool. Set aside.", "Combine rolled oats, flour, sugar, baking soda and salt in a food processor. Pulse 3 times (careful not to overmix, you don’t want the mixture to be powdery, just combined). Add butter and pulse again until the mixture is crumbly in pea-sized clumps. Transfer to a mixing bowl to thoroughly mix in the butter.", "Spread half of the oat mixture on the bottom of the prepared baking pan, pressing down to make a flat, equal bottom later. Add the date mixture over the crust and then spread evenly. Layer with the remaining oat mixture and press down to flatten the top layer.", "Bake in the centre of the oven until the top is golden brown, 30 to 35 minutes. Let cool completely in the pan before cutting and serving. Date Squares keep well, covered in the refrigerator for up to a week, and frozen for 2 to 3 months."]'::jsonb, 'https://canadianfoodfocus.org/recipes/classic-canadian-dishes-date-squares/', 'https://www.themealdb.com/images/media/meals/u4scbo1764446514.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('dulce-de-leche', 'Dulce de Leche', 4, 0, 0, '{"calories": 295, "protein": 0.8, "carbs": 76.3, "fat": 0.5, "saturated_fat": 0.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 13.8, "potassium": null, "fiber": null, "sugar": 76.3, "vitamin_a": null, "vitamin_c": 0.2, "calcium": 31.8, "iron": null}'::jsonb, ARRAY['dessert', 'argentinian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 300.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Vanilla Extract", "notes": null, "category": "pantry"}]'::jsonb, '["Combine Ingredients: In a large, heavy-bottomed pot, mix the milk, sugar, and baking soda. Cook over low heat, stirring constantly to prevent burning.", "Thicken: Continue to cook, stirring frequently, until the mixture becomes thick and caramel-colored, about 1-2 hours.", "Flavor: Stir in the vanilla extract.", "Cool: Let the dulce de leche cool, then transfer to a jar. It will thicken further as it cools.", "Pro Tips:", "Stir continuously and keep the heat low to prevent the milk from burning and sticking to the bottom of the pan.", "A drop of vanilla extract added at the end of cooking enhances the flavor."]'::jsonb, 'https://www.munchery.com/blog/the-ten-iconic-dishes-of-argentina-and-how-to-cook-them-at-home/', 'https://www.themealdb.com/images/media/meals/jyjlhj1763075323.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('dundee-cake', 'Dundee cake', 4, 0, 0, '{"calories": 828, "protein": 21.7, "carbs": 135.8, "fat": 67.4, "saturated_fat": 28.3, "polyunsaturated_fat": null, "monounsaturated_fat": 1.5, "sodium": 175.5, "potassium": 395.3, "fiber": 10.5, "sugar": 13.1, "vitamin_a": null, "vitamin_c": 65.5, "calcium": 185.1, "iron": 3.9}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 100.0, "unit": "g", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 180.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 180.0, "unit": "g", "item": "Muscovado Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Orange", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbs", "item": "Apricot Jam", "notes": null, "category": "other"}, {"quantity": 225.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Ground Almonds", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 500.0, "unit": "g", "item": "Dried Fruit", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Glace Cherry", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbs", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tsp", "item": "Caster Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["Put the almonds into a small bowl and pour over boiling water to just cover. Leave for 5 mins then drain in a sieve and leave to dry.", "Preheat the oven to 180C/160 C fan/Gas Mark 4. Line a deep loose-based 20cm cake tin with baking parchment.", "Put the butter in a large bowl and beat well until soft. Add the sugar and beat until light and fluffy. Stir in the orange zest and apricot jam.", "Sieve together the flour and baking powder. Add the eggs to the creamed butter and sugar, a little at a time, beating well between each addition. If the mixture starts to curdle, stir in a little flour.", "Add the remaining flour and ground almonds and mix well. Mix in the milk and then add the dried fruit and cherries and mix gently together.", "Spoon the mixture into the prepared tin and spread level using the back of a spoon. Arrange the whole almonds close together in neat circles on the top of the cake. Bake in the oven for 45 mins.", "Lower the oven temperature to 160C/140 C fan/Gas Mark 3 and cook for a further 60–80 minutes. Check the cake after 50 minutes by inserting a wooden or metal skewer into the cake. When it’s done it should have just a few crumbs attached. Check every 10 minutes - it’s important not to overcook this cake so the centre will be a little soft.", "When cooked, remove the cake briefly from the oven, put the milk and sugar into a small pan and heat gently until the sugar has dissolved. Brush over the top of the cake and return the cake to the oven for 2-3 mins. Remove and allow the cake to cool in the tin. When quite cold remove from the tin and wrap in foil and keep for at least 2 days before cutting."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/2155640/dundee-cake', 'https://www.themealdb.com/images/media/meals/wxyvqq1511723401.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('dutch-stroopwafel', 'Dutch stroopwafel', 4, 0, 0, '{"calories": 1229, "protein": 7.2, "carbs": 161.0, "fat": 62.0, "saturated_fat": 38.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 253.3, "potassium": 85.0, "fiber": 2.1, "sugar": 88.4, "vitamin_a": 321.5, "vitamin_c": 0.0, "calcium": 43.9, "iron": 2.0}'::jsonb, ARRAY['dessert', 'dutch', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 15.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 10.0, "unit": "g", "item": "Instant Yeast", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 120.0, "unit": "g", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 80.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Dutch Stroop", "notes": null, "category": "other"}, {"quantity": 120.0, "unit": "g", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 80.0, "unit": "g", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}]'::jsonb, '["Combine milk and yeast in a bowl. Let stand for a moment to allow the yeast to dissolve.", "In another bowl, combine flour, butter, sugar, egg, and salt. Pour in the yeast mixture and knead until smooth. Cover the bowl and let the dough rise for one hour.", "When the dough is almost ready, make the stroop filling. Combine all the ingredients in a saucepan and stir until the butter is melted and the sugar is dissolved. Let it simmer for a while. The stroop will continue to thicken as it cools.", "Shape the dough into balls weighing about 35 grams each. Make a total of 14. Turn your stroopwafel iron on the highest setting.", "Place a ball of dough in the iron and close the iron. Don’t flatten the waffle too much; you should still be able to cut through it. Bake for 1-2 minutes until the waffle is nicely golden brown.", "When the waffle is done, work quickly. Remove the waffle from the iron and immediately use a round cutter to cut out a nice circle of about 8 to 9 cm (3 to 3.5 inches).", "Place the hot waffle on a cutting board and cut horizontally with a sharp knife. The stroopwafel is very hot, so use an oven mitt to hold it in place.", "Take half a waffle and spread the (hot!) stroop on it. Place the other half on top, pressing gently if necessary, and place the waffle on a wire rack to cool. Repeat for all the balls."]'::jsonb, 'https://www.inlaurasbakery.com/dutch-stroopwafels-recipe/', 'https://www.themealdb.com/images/media/meals/8cvkcz1766596315.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('dziriat-algerian-almond-tarts', 'Dziriat (Algerian Almond Tarts)', 4, 0, 0, '{"calories": 2448, "protein": 64.3, "carbs": 572.7, "fat": 163.8, "saturated_fat": 19.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 10814.1, "potassium": 163.7, "fiber": 26.2, "sugar": 141.5, "vitamin_a": null, "vitamin_c": null, "calcium": 857.0, "iron": 9.9}'::jsonb, ARRAY['dessert', 'algerian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Orange Blossom Water", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Orange Blossom Water", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cups", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Orange Blossom Water", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sprinkling Cornstarch", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Pine Nuts", "notes": null, "category": "pantry"}]'::jsonb, '["Prepare the almonds the day before. Bring 6 cups of water to a boil. Remove from heat, and add the almonds. Let the almonds soak in water for about 5 minutes, then drain and peel. Spread the almonds on baking sheets, and bake at 200 degrees F(95 degrees C) until completely dry and toasted. This takes several hours, and needs to be prepared ahead. Be careful not to burn the nuts, as this will give a bitter taste to the filling.", "Combine 1 cup sugar and 1 cup water in a saucepan, and bring to a boil. Add 1 teaspoon lemon juice, reduce heat to low, and let it simmer until syrupy, about 30 to 40 minutes. Stir in orange blossom water, and remove from heat. Set sugar syrup aside.", "Combine flour and salt in a large mixing bowl. Make a hole in the center, and pour oil, egg, 1/2 teaspoon lemon juice, and 1 tablespoon orange blossom water into the center. Mix with fingers until the dough resembles coarse crumbs. Gradually sprinkle with warm water while mixing until the dough becomes soft and pliable. Divide into 4 equal portions. Cover dough with a wet cloth, and set aside.", "In a food processor, finely grind the almonds. Measure 3 cups of the finely ground almonds into a mixing bowl, and stir together with 1 cup sugar, baking powder, vanilla powder, lemon zest, and 2 tablespoons orange flower water. Mix in three eggs one at a time, stirring constantly; mix until you get a sticky, paste-like mixture.", "Sprinkle cornstarch on the rolling surface to prevent sticking. Roll each portion of dough very thinly, 1 to 2 millimeters (1/16 inch). Cut the rolled dough into circles of about 10 centimeters (4 inches) in diameter each. Lightly wipe the surface of each circle with cornstarch, and fit into a tart mold, cornstarch side down to prevent sticking. Gently press the dough onto the sides and bottom of the mold, and trim extra dough from around the rim. Fill three quarters of each mold with the almond filling.", "Bake on the top shelf at 350 degrees F (175 degrees C) for 20 to 25 minutes, or until the surface of the tart is golden and the dough is firm. Remove the tarts from the molds as soon as they come out of the oven. Dip each tart in the sugar syrup while still hot. Stick a pine nut into the middle of each tart for decoration. Place on a wire rack to drain."]'::jsonb, 'https://www.allrecipes.com/recipe/69501/dziriat-algerian-almond-tarts/', 'https://www.themealdb.com/images/media/meals/ne5wzp1764115568.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('eccles-cakes', 'Eccles Cakes', 4, 0, 0, '{"calories": 855, "protein": 16.0, "carbs": 152.8, "fat": 57.8, "saturated_fat": 35.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 34.7, "potassium": 186.8, "fiber": 6.1, "sugar": 33.8, "vitamin_a": null, "vitamin_c": null, "calcium": 72.6, "iron": 2.5}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 250.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 350.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1/2 Lemon", "notes": null, "category": "produce"}, {"quantity": 25.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "Currants", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Mixed Peel", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Muscovado Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "spinkling Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["To make the pastry, dice the butter and put it in the freezer to go really hard. Tip flour into the bowl of a food processor with half the butter and pulse to the texture of breadcrumbs. Pour in the lemon juice and 100ml iced water, and pulse to a dough. Tip in the rest of the butter and pulse a few times until the dough is heavily flecked with butter. It is important that you don’t overdo this as the flecks of butter are what makes the pastry flaky.", "On a floured surface roll the pastry out to a neat rectangle about 20 x 30cm. Fold the two ends of the pastry into the middle (See picture 1), then fold in half (pic 2). Roll the pastry out again and refold the same way 3 more times resting the pastry for at least 15 mins each time between roll and fold, then leave to rest in the fridge for at least 30 mins before using.", "To make the filling, melt the butter in a large saucepan. Take it off the heat and stir in all the other ingredients until completely mixed, then set aside.", "To make the cakes, roll the pastry out until it’s just a little thicker than a £1 coin and cut out 8 rounds about 12cm across. Re-roll the trimming if needed. Place a good heaped tablespoon of mixture in the middle of each round, brush the edges of the rounds with water, then gather the pastry around the filling and squeeze it together (pic 3). Flip them over so the smooth top is upwards and pat them into a smooth round. Flatten each round with a rolling pin to an oval until the fruit just starts to poke through, then place on a baking tray. Cut 2 little slits in each Eccles cakes, brush generously with egg white and sprinkle with the sugar (pic 4).", "Heat the oven to 220C/200C fan/gas 8. Bake the Eccles cakes for 15-20 mins until just past golden brown and sticky. Leave to cool on a rack and enjoy while still warm or cold with a cup of tea. If you prefer, Eccles cakes also go really well served with a wedge of hard, tangy British cheese such as Lancashire or cheddar."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/786659/eccles-cakes', 'https://www.themealdb.com/images/media/meals/wtqrqw1511639627.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ensaimada', 'Ensaimada', 4, 0, 0, '{"calories": 1081, "protein": 23.1, "carbs": 168.6, "fat": 34.8, "saturated_fat": 13.6, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 53.1, "potassium": 191.4, "fiber": 0.8, "sugar": 50.3, "vitamin_a": null, "vitamin_c": null, "calcium": 60.8, "iron": 8.4}'::jsonb, ARRAY['dessert', 'spanish', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 5.0, "unit": "g", "item": "Yeast", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 600.0, "unit": "g", "item": "Strong white bread flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Drizzle Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Lard", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Pour 230ml lukewarm water into a bowl and add the yeast. Leave to stand for 3 mins, then add the caster sugar, eggs, flour and 1 tsp sea salt flakes. Mix together to form a dough, then knead for 10 mins in stand mixer using a dough hook (or 15 mins by hand) until the dough is elastic enough to be almost see-through when stretched. Cover and set aside to rest for 30 mins, then cut into four equal pieces. Transfer to a baking tray lined with baking parchment. Leave to rest for another 30 mins.", "step 2", "Oil the work surface and a rolling pin with vegetable oil. Working with one portion of dough at a time, flatten it against the surface using the palm of your hand, then roll it out into a thin rectangle, about 30 x 50cm. Let it rest for 2 mins while you spread a quarter of the lard over the top. (If you want to fill your pastry with sobrasada de Mallorca, mix 50g lard with the sobrasada, and spread this over the dough instead.) Pull one corner of the flattened dough and stretch it out as far as it will go without breaking. Repeat every 10cm or so around the dough rectangle in every direction until it reaches about 50 x 70cm.", "step 3", "Cut a strip from each of the shorter sides and lay these beside each other along one of the longer sides of the rectangle; this is what we call the heart of the ensaimada. From there, begin rolling the dough until you have a long pastry snake. Repeat with the remaining portions of dough.", "step 4", "Take the first roll of dough and stretch it until it is over a metre long. Then, roll it up into a spiral, leaving 1cm between each turn of the spiral so the dough can expand. Flatten a little and transfer to a baking sheet lined with baking parchment. Repeat with the remaining dough. Leave to rise in a warm place for at least 12 hrs, or ideally 24 hrs.", "step 5", "Heat the oven to 200C/180C fan/gas 6. Put the ensaimadas in the top third of the oven and immediately reduce the temperature to 180C/160C fan/gas 4. Bake for 18 mins until dark golden. Leave to cool on a wire rack. To fill your ensaimada with whipped cream, slice and open, then spread over the cream and close. Dust with a generous amount of icing sugar, if you like and cut into pieces to serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/ensaimada', 'https://www.themealdb.com/images/media/meals/1ugsho1763248007.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('eton-mess', 'Eton Mess', 4, 0, 0, '{"calories": 322, "protein": 3.8, "carbs": 31.5, "fat": 58.7, "saturated_fat": 30.6, "polyunsaturated_fat": null, "monounsaturated_fat": 7.3, "sodium": 164.1, "potassium": 356.7, "fiber": 3.5, "sugar": 19.7, "vitamin_a": null, "vitamin_c": 51.8, "calcium": 115.2, "iron": 0.9}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 500.0, "unit": "g", "item": "strawberries", "notes": null, "category": "other"}, {"quantity": 400.0, "unit": "ml", "item": "double cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "7.5cm meringue nests", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbsp", "item": "ginger cordial", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "sprigs of", "notes": "fresh Mint", "category": "other"}]'::jsonb, '["Purée half the strawberries in a blender. Chop the remaining strawberries, reserving four for decoration.", "Whip the double cream until stiff peaks form, then fold in the strawberry purée and crushed meringue. Fold in the chopped strawberries and ginger cordial, if using.", "Spoon equal amounts of the mixture into four cold wine glasses. Serve garnished with the remaining strawberries and a sprig of mint."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/uuxwvq1483907861.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('figgy-duff', 'Figgy Duff', 4, 0, 0, '{"calories": 603, "protein": 8.0, "carbs": 153.4, "fat": 10.0, "saturated_fat": 0.8, "polyunsaturated_fat": null, "monounsaturated_fat": 6.6, "sodium": 40.1, "potassium": 436.7, "fiber": 4.0, "sugar": 85.0, "vitamin_a": null, "vitamin_c": null, "calcium": 170.9, "iron": 3.7}'::jsonb, ARRAY['dessert', 'canadian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "cup", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "cup", "item": "Raisins", "notes": null, "category": "pantry"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Melted Butter", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Molasses", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Water", "notes": null, "category": "other"}]'::jsonb, '["In a medium bowl, whisk together flour, brown sugar, baking powder, and spices.", "Add raisins and stir well, making sure to coat the raisins in the flour mixture.", "Add melted butter, molasses and water and mix with a wooden spoon. Form a ball with the spoon or your hands and put the dough ball in a cotton pudding bag. Tie the bag, leaving at least 1 inch of room to allow the pudding to expand while cooking.", "Boil pudding for 1.5 hours. (In NL, this is typically done in the pot along with Jiggs Dinner, but it can be done independently.)", "When the duff is firm, remove it from the boiling water and let it cool slightly before removing it from the pudding bag.", "Slice pudding like a cake and serve with the warm sauce of your choice: rum butter sauce, warmed molasses or Molasses Coady sauce (1 cup (250 mL) molasses, 1/4 cup (60 mL) butter, 1/4 cup (60 mL) water) is common in Newfoundland."]'::jsonb, 'https://canadianfoodfocus.org/recipes/classic-canadian-dish-figgy-duff/', 'https://www.themealdb.com/images/media/meals/kzi6p51764787198.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('flan', 'Flan', 4, 0, 0, '{"calories": 479, "protein": 8.4, "carbs": 80.8, "fat": 13.5, "saturated_fat": 6.4, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 159.9, "potassium": null, "fiber": 8.3, "sugar": 72.5, "vitamin_a": null, "vitamin_c": 0.9, "calcium": 195.9, "iron": 1.8}'::jsonb, ARRAY['dessert', 'uruguayan', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 100.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 350.0, "unit": "g", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 45.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "pod", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Dulce de leche", "notes": null, "category": "other"}]'::jsonb, '["For the caramel place 100 grams of sugar in a frying pan without any fat and melt on medium heat. Try not to stir with a spoon, but swirl the pan itself. Let melt until you have an amber color and sugar is fully melted. Fill the bottom of four flan containers with it. Caramel will harden immediately, so you need to be fast. My containers yield about 120 milliliters each.", "2", "Preheat oven to 150 degrees Celsius and look for a casserole or container all your four flan containers fit into.", "3", "Heat milk with 45 grams of sugar and the cut and scraped out vanilla pod. The milk does not need to boil, just needs to be heated. Take out vanilla pod after a few minutes. Meanwhile stir the egg yolks and eggs gently, try not to incorporate any air in it. Them pour milk-mix into egg-mix and again only stir very gently. Pour into prepared flan containers and place these into your casserole or container. Boil water and pour the water into the large casserole. Be sure not to touch the flan mixture. Place on middle rack in the oven and let bake for about 35-40 minutes. An inserted toothpick should come out clean.", "4", "Let cool inside the container for an hour before transferring to the fridge. Chill overnight. The next day gently release the rim and then turn upside down on a plate. Serve with some dulce de leche on the side."]'::jsonb, 'https://jennyisbaking.com/2019/12/20/uruguayan-flan-and-merry-christmas/', 'https://www.themealdb.com/images/media/meals/0s80wo1764374393.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('flapper-pie', 'Flapper Pie', 4, 0, 0, '{"calories": 973, "protein": 40.5, "carbs": 146.4, "fat": 24.1, "saturated_fat": 5.4, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 910.9, "potassium": 297.5, "fiber": null, "sugar": 90.7, "vitamin_a": null, "vitamin_c": 1.5, "calcium": 288.9, "iron": 4.8}'::jsonb, ARRAY['dessert', 'canadian', 'themealdb', 'nutrition-generated', 'baking'], '[{"quantity": 1.5, "unit": "cups", "item": "Graham Cracker Crumbs", "notes": null, "category": "meat"}, {"quantity": 6.0, "unit": "tablespoons", "item": "Melted Butter", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Ground Cinnamon", "notes": null, "category": "spices"}, {"quantity": 2.5, "unit": "cups", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "cup", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "White", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Cream Of Tartar", "notes": null, "category": "dairy"}]'::jsonb, '["Preheat the oven to 350˚F.", "Mix all the crust ingredients (graham cracker crumbs, melted butter, granulated sugar and ground cinnamon) in a medium bowl. Set aside about 2 Tbsp (30 mL) for later and press the mixture into a 9-inch deep-dish pie plate in the bottom and up the sides. Bake crust for 10 minutes, it will only brown slightly.", "Combine the vanilla custard filling ingredients (milk, granulated sugar, cornstarch, egg yolks, vanilla extract and salt together) and cook on medium heat, stirring constantly, until it bubbles and thickens to the texture of pudding. Set aside to cool while you make the meringue topping.", "In the bowl of a stand mixer fitted with the beater attachment or in a large bowl using an electric mixer beat the meringue ingredients (egg whites, granulated sugar, cream of tartar) together until it holds stiff and glossy peaks.", "To assemble the pie, pour the filling into the crust and top with a thick layer of the meringue, making little spikes that will brown on top. Sprinkle the reserved crumb over the top and place it into the preheated oven.", "Bake until the meringue browns, around 10 minutes, making sure to watch it carefully.", "Chill in the fridge and eat within a few hours of baking. This pie is best eaten the same day as the meringue will soften and liquify."]'::jsonb, 'https://canadianfoodfocus.org/recipes/classic-canadian-dish-flapper-pie/', 'https://www.themealdb.com/images/media/meals/6ht8141764786479.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fyrstekake-norwegian-prince-cake', 'Fyrstekake – Norwegian Prince Cake', 4, 0, 0, '{"calories": 1569, "protein": 29.4, "carbs": 159.2, "fat": 98.2, "saturated_fat": 31.7, "polyunsaturated_fat": null, "monounsaturated_fat": 2.5, "sodium": 413.7, "potassium": 52.9, "fiber": 11.2, "sugar": 105.2, "vitamin_a": null, "vitamin_c": null, "calcium": 378.2, "iron": 5.6}'::jsonb, ARRAY['dessert', 'norwegian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 0.75, "unit": "cup", "item": "Granulated Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 0.6666666666666666, "unit": "cup", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "cups", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.5, "unit": "cups", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 0.75, "unit": "cup", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbsp", "item": "Melted Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Brandy", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Almond Extract", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}]'::jsonb, '["Crust", "▢", "Mix together sugar, vanilla and butter until light and fluffy. Mix in the egg yolks. Add in the flour and baking powder and knead with hands until the dough is smooth.", "▢", "Pack the dough in plastic wrap and chill in refrigerator for at least 30 minutes.", "Almond filling", "▢", "Run the almonds and sugar together in a food processor until the almonds are finely ground (you can decide for yourself how coarse or fine you want them).", "▢", "Stir in the butter, egg, cognac and/or almond extract (if using).", "Assembly", "▢", "Line the bottom of your cake form with baking paper and grease the sides of the form.", "▢", "Preheat oven to 350°F (175°C).", "▢", "Cut 2/3 of the crust dough into slices and press down into the cake form. Cover the bottom of the cake form with the dough and bring the dough 2-3 cm (1 inch) up the sides of the form, pressing until even.", "▢", "Scoop the almond filling on top of the crust, spreading it evenly across the cake form.", "▢", "Roll out of the rest of the dough and slice into long strips. Lay the strips of dough across the cake in a grid. Don''t worry of the strips break – simply press them back together on the cake.", "▢", "Gently brush the dough with egg wash.", "▢", "Bake for about 45 minutes. The top of the cake should be golden brown while the almond filling will remain soft."]'::jsonb, 'https://scandinaviancookbook.com/fyrstekake-norwegian-prince-cake/', 'https://www.themealdb.com/images/media/meals/9zqrod1763075574.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('gevulde-speculaas', 'Gevulde speculaas', 4, 0, 0, '{"calories": 1002, "protein": 26.2, "carbs": 165.8, "fat": 71.0, "saturated_fat": 26.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1246.7, "potassium": 514.2, "fiber": 9.3, "sugar": 91.8, "vitamin_a": null, "vitamin_c": 0.2, "calcium": 203.8, "iron": 3.7}'::jsonb, ARRAY['dessert', 'dutch', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 300.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 150.0, "unit": "g", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 10.0, "unit": "g", "item": "Speculaas Spice Mix", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 125.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 300.0, "unit": "g", "item": "Almond Paste", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "For brushing Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Garnish Almonds", "notes": null, "category": "pantry"}]'::jsonb, '["Mix the self-rising flour, sugar, speculaas spice mix and salt. Add the butter and milk and knead into a firm ball of dough. Start with 6 tablespoons of milk, if the dough is too stiff you can add more milk.", "Wrap the dough in plastic wrap and refrigerate overnight. You can process and bake it immediately, but the flavor will be much better if you let it rest.", "Mix the almond paste with half of the beaten egg and knead well. This makes it easier to work with and gives it a better and tastier texture.", "Take half of the dough and roll it out to 20 x 20 cm. Place in a baking pan lined with parchment paper. Spread the almond paste mixture evenly. Roll out the remaining dough and place on top of the almond paste.", "Brush the top with the remaining beaten egg. Garnish with almonds and top with another layer of egg wash.", "Bake the filled speculaas for 40 minutes at 180°C/350℉ (conventional oven) or until done."]'::jsonb, 'https://www.inlaurasbakery.com/gevulde-speculaas-dutch-almond-paste-filled-spiced-cookies/', 'https://www.themealdb.com/images/media/meals/rw64di1766595573.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('grape-nut-ice-cream', 'Grape Nut Ice Cream', 4, 0, 0, '{"calories": 423, "protein": 11.0, "carbs": 26.5, "fat": 63.1, "saturated_fat": 23.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 41.9, "potassium": 377.5, "fiber": 2.4, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": 24.8, "iron": 3.5}'::jsonb, ARRAY['dessert', 'jamaican', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "Heavy Cream", "notes": null, "category": "dairy"}, {"quantity": 1.25, "unit": "oz", "item": "Condensed Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Grape Nut Cereal", "notes": null, "category": "grains"}]'::jsonb, '["In a large bowl, use an electric mixer to whip the cold heavy cream until stiff peaks form. Gently fold in the sweetened condensed milk and vanilla extract until well combined.", "Fold in the cereal and stir until evenly distributed throughout the mixture.", "Pour the mixture into a freezer-safe container (such as a loaf pan). Lay plastic wrap on top of the ice cream to avoid freezer burn. Cover the container and freeze for at least 6 hours or until solid.", "Once frozen, let the ice cream sit at room temperature for a few minutes to soften slightly before scooping and serving."]'::jsonb, 'https://www.myforkinglife.com/grape-nut-ice-cream-recipe/#recipe', 'https://www.themealdb.com/images/media/meals/1xscby1764790242.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('honey-yogurt-cheesecake', 'Honey Yogurt Cheesecake', 4, 0, 0, '{"calories": 1910, "protein": 20.1, "carbs": 159.1, "fat": 134.3, "saturated_fat": 85.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 430.1, "potassium": null, "fiber": 5.9, "sugar": 138.6, "vitamin_a": null, "vitamin_c": 1.6, "calcium": 446.5, "iron": 2.2}'::jsonb, ARRAY['dessert', 'greek', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 100.0, "unit": "g", "item": "Digestive Biscuits", "notes": null, "category": "other"}, {"quantity": 85.0, "unit": "g", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 85.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 250.0, "unit": "ml", "item": "Greek Yogurt", "notes": null, "category": "dairy"}, {"quantity": 750.0, "unit": "g", "item": "Mascarpone", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Orange", "notes": null, "category": "produce"}, {"quantity": 250.0, "unit": "ml", "item": "Honey", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Fruit Mix", "notes": null, "category": "other"}]'::jsonb, '["Heat oven to 160C/140C fan/gas 3. Crush the biscuits and most of the almonds inside a plastic food bag using a rolling pin. Mix with the butter, then press into the bottom of a deep, oval, 23cm dish (or something similar in size – a roasting tin, baking dish or cake tin will work). Bake for 10 mins until crisp.", "Stir or mash together the yogurt and mascarpone, then whisk in the eggs, one at a time. Stir in the lemon and orange zests, then stir in most of the honey, reserving about 3 tbsp. Spread over the biscuit base, cover loosely with foil and cook for 1 hr. Remove the foil and cook for 15 mins more until lightly golden and the top is firm with just the slightest wobble in the middle. Leave to cool. Can be kept in the fridge for up to 2 days.", "To serve, scatter with almonds, drizzle over the remaining honey, and hand around fresh fruit to go with it."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/honey-yogurt-cheesecake', 'https://www.themealdb.com/images/media/meals/y2irzl1585563479.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('hot-chocolate-fudge', 'Hot Chocolate Fudge', 4, 0, 0, '{"calories": 723, "protein": 10.2, "carbs": 118.9, "fat": 33.3, "saturated_fat": 20.9, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 113.6, "potassium": 137.8, "fiber": 8.4, "sugar": 89.5, "vitamin_a": null, "vitamin_c": 2.6, "calcium": 4.4, "iron": 4.0}'::jsonb, ARRAY['dessert', 'american', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "Chocolate Chips", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Heavy Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "– 14-ounce can Condensed Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 0.333, "unit": "cups", "item": "1-⅓ cups White Chocolate Chips", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cups", "item": "1-½ cups Miniature Marshmallows", "notes": null, "category": "other"}]'::jsonb, '["Line an 8-inch-square baking pan with wax paper or foil, and coat with non-stick spray.", "In a microwave-safe bowl, combine the dark chocolate chips, heavy cream and half of the sweetened condensed milk. Microwave the dark chocolate mixture in 20-second intervals, stirring in between each interval, until the chocolate is melted.", "Add the vanilla extract to the dark chocolate mixture and stir well until smooth.", "Transfer the dark chocolate mixture into the prepared pan and spread into an even layer.", "In a separate bowl, combine the white chocolate chips with the remaining half of the sweetened condensed milk. Microwave the white chocolate mixture in 20-second intervals, stirring in between each interval, until the chocolate is melted.", "Evenly spread the white chocolate mixture on top of dark chocolate layer.", "Top the chocolate layers with the Mallow Bits or miniature marshmallows, and gently press them down.", "Refrigerate for 4 hours, or until set.", "Remove the fudge and wax paper from the pan. Carefully peel all of the wax paper from the fudge.", "Cut the fudge into bite-sized pieces and serve."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/xrysxr1483568462.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jam-jam-cookies', 'Jam jam cookies', 4, 0, 0, '{"calories": 1535, "protein": 9.6, "carbs": 283.8, "fat": 51.8, "saturated_fat": 32.4, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1033.2, "potassium": null, "fiber": 0.8, "sugar": 152.3, "vitamin_a": null, "vitamin_c": null, "calcium": 111.0, "iron": 6.4}'::jsonb, ARRAY['dessert', 'canadian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "cup", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "Molasses", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Water", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "cups", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "cups", "item": "Jam", "notes": null, "category": "other"}]'::jsonb, '["Preheat the oven to 350 °F (180 °C) and line a large baking sheet with parchment paper.", "In a stand mixer with the paddle attachment, cream the butter, white sugar and egg until combined, then add the molasses and vanilla and mix until smooth.", "Once combined, add the baking soda water mixture and mix for another minute to combine.", "Combine dry ingredients; mix baking powder, cinnamon, flour and salt in a separate bowl then add to the wet ingredients a little at a time, mixing on low until fully combined and scraping down the sides to ensure everything is incorporated. The dough should be easily shaped.", "Portion dough with a small spoon, roll them into balls and place them on the lined cookie sheet, press them into flat discs using a floured glass or your moistened palm.", "Place cookies on parchment-lined baking sheets and bake for 10-12 mins. Remove from the oven and let them cool for at least 10 minutes.", "Once cooled the cookie sandwiches by spreading at least two teaspoons of your favourite jam between the two cookies. Repeat and enjoy with a cup of tea."]'::jsonb, 'https://canadianfoodfocus.org/recipes/jam-jam-cookies/#recipe', 'https://www.themealdb.com/images/media/meals/sktequ1764447186.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jam-roly-poly', 'Jam Roly-Poly', 4, 0, 0, '{"calories": 390, "protein": 8.7, "carbs": 72.7, "fat": 29.9, "saturated_fat": 15.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 428.4, "potassium": null, "fiber": 1.1, "sugar": 26.1, "vitamin_a": null, "vitamin_c": 0.4, "calcium": 56.1, "iron": null}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 50.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 250.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Vanilla", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "Suet", "notes": null, "category": "other"}, {"quantity": 150.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Raspberry Jam", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Custard", "notes": null, "category": "other"}]'::jsonb, '["Put a deep roasting tin onto the bottom shelf of the oven, and make sure that there’s another shelf directly above it. Pull the roasting tin out on its shelf, fill two-thirds with boiling water from the kettle, then carefully slide it back in. Heat oven to 180C/160C fan/gas 4. Tear off a large sheet of foil and greaseproof paper (about 30 x 40cm). Sit the greaseproof on top of the foil and butter it.", "Tip butter, flour and vanilla seeds into a food processor; pulse until the butter has disappeared. Tip into a mixing bowl. Stir through the suet, pour in the milk and work together with a cutlery knife until you get a sticky dough. You may need a drop more milk, depending on your flour.", "Tip the dough out onto a floured surface, quickly pat together to smooth, then roll out to a square roughly 25 x 25cm. Spread the jam all over, leaving a gap along one edge, then roll up from the opposite edge. Pinch the jam-free edge into the dough where it meets, and pinch the ends roughly, too. Carefully lift onto the greased paper, join-side down (you might find a flat baking sheet helpful for this), loosely bring up the paper and foil around it, then scrunch together along the edges and ends to seal. The roly-poly will puff quite a bit during cooking so don’t wrap it tightly. Lift the parcel directly onto the rack above the tin and cook for 1 hr.", "Let the pudding sit for 5 mins before unwrapping, then carefully open the foil and paper, and thickly slice to serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/13354/jam-rolypoly', 'https://www.themealdb.com/images/media/meals/ysqupp1511640538.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamaican-banana-fritters', 'Jamaican Banana Fritters', 4, 0, 0, '{"calories": 522, "protein": 6.1, "carbs": 49.2, "fat": 32.6, "saturated_fat": 7.6, "polyunsaturated_fat": null, "monounsaturated_fat": 7.9, "sodium": 223.4, "potassium": 85.0, "fiber": 2.5, "sugar": 8.6, "vitamin_a": null, "vitamin_c": 3.8, "calcium": 38.2, "iron": 1.3}'::jsonb, ARRAY['dessert', 'jamaican', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Banana", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 0.25, "unit": "tsp", "item": "Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Mash bananas with fork in bowl.", "Add brown sugar, vanilla, extract, cinnamon, nutmeg and a pinch of salt. Sift in flour and stir with spoon until fully combined.", "Add oil to a 10 inch skillet over medium-high heat. Once oil is hot, drop banana fritter batter in oil by the spoonful. Once one side is golden and bubbles appear on the top, flip fritter and cook until the other side is browned as well.", "Remove fritters and drain on paper towels. Enjoy"]'::jsonb, 'https://www.myforkinglife.com/banana-fritters/#recipe', 'https://www.themealdb.com/images/media/meals/ul2uy31764794321.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamaican-spice-bun-recipe', 'Jamaican Spice Bun Recipe', 4, 0, 0, '{"calories": 976, "protein": 6.5, "carbs": 226.8, "fat": 7.6, "saturated_fat": 4.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 94.0, "potassium": 203.8, "fiber": 4.1, "sugar": 137.6, "vitamin_a": null, "vitamin_c": 0.2, "calcium": 181.0, "iron": 1.0}'::jsonb, ARRAY['dessert', 'jamaican', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 380.0, "unit": "g", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Ground Cinnamon", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 150.0, "unit": "g", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Beer", "notes": null, "category": "other"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 0.25, "unit": "cup", "item": "Honey", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Molasses", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Caramelized Sugar Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "Dried cranberries", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "cup", "item": "Raisins", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "Dried Cherries", "notes": null, "category": "other"}]'::jsonb, '["Soak the craisins, raisins, and cherries in the 1 cup of beer. Set aside and allow to soak for 30 minutes.", "Preheat the oven to 325 degrees Fahrenheit. Grease an 8x4 loaf pan. Set aside.", "Combine all-purpose flour, baking powder, ground cinnamon, salt, in a large bowl and set aside.", "In another bowl, combine brown sugar, egg, milk, honey, melted butter, molasses, browning, vanilla extract, and the beer that’s soaking the fruit. Do not pour the fruit in at this time, just the beer. Mix to combine.", "Remove 2 tablespoon of flour from the flour mixture and toss the fruit in it. Set aside.", "Make a well in the middle of the bowl of dry ingredients and pour in wet mixture, stirring until fully combined. And the fruits to the mixture and stir until incpororated.", "Pour mixture into prepared loaf pan and bake in the preheated oven for 50-60 minutes or until a toothpick comes out clean.", "Cool for 5 minutes in the pan and then move to a cooling rack to finish cooling. Serve with slices of cheddar cheese."]'::jsonb, 'https://www.myforkinglife.com/easter-spice-bread-jamaican-style/#recipe', 'https://www.themealdb.com/images/media/meals/08c5f41764791918.jpg', FALSE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamaican-sweet-potato-pudding', 'Jamaican Sweet Potato Pudding', 4, 0, 0, '{"calories": 609, "protein": 3.3, "carbs": 119.3, "fat": 17.2, "saturated_fat": 8.6, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 40.5, "potassium": 147.9, "fiber": 1.1, "sugar": 97.8, "vitamin_a": null, "vitamin_c": null, "calcium": 21.0, "iron": 1.0}'::jsonb, ARRAY['dessert', 'jamaican', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "lbs", "item": "Sweet Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.5, "unit": "cup", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 1.5, "unit": "cup", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Ground Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Ground Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Ground Ginger", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "Raisins", "notes": null, "category": "pantry"}, {"quantity": 0.75, "unit": "cup", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.125, "unit": "teaspoon", "item": "Ground Cinnamon", "notes": null, "category": "spices"}, {"quantity": 0.125, "unit": "teaspoon", "item": "Ground Nutmeg", "notes": null, "category": "pantry"}]'::jsonb, '["Preheat oven to 350°F (175°C). Grease and line a 9-inch round pan or loaf pan with parchment paper.", "Place your cut sweet potatoes in the bowl of a food processor and process until finely grated. In a small bowl, toss raisins in 2 teaspoons flour from the ½ cup. Set aside.", "In a large bowl, combine grated sweet potatoes, light brown sugar, all-purpose flour, vanilla extract, allspice, cinnamon, nutmeg, ginger, and salt. Stir in 1½ cups of coconut milk until a batter forms. Fold in the raisins that were tossed in the flour.", "Pour the batter into the prepared pan and smooth the top. Bake uncovered for 1 hour 30 minutes, until mostly set but still slightly soft in the center"]'::jsonb, 'https://www.myforkinglife.com/jamaican-sweet-potato-pudding/#recipe', 'https://www.themealdb.com/images/media/meals/xj9sa81764788866.jpg', FALSE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('key-lime-pie', 'Key Lime Pie', 4, 0, 0, '{"calories": 1281, "protein": 23.8, "carbs": 145.3, "fat": 95.1, "saturated_fat": 44.1, "polyunsaturated_fat": null, "monounsaturated_fat": 5.5, "sodium": 717.2, "potassium": 195.5, "fiber": 5.5, "sugar": 12.5, "vitamin_a": 6.0, "vitamin_c": null, "calcium": 120.7, "iron": 4.3}'::jsonb, ARRAY['dessert', 'american', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 300.0, "unit": "g", "item": "Digestive Biscuits", "notes": null, "category": "other"}, {"quantity": 150.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 400.0, "unit": "g", "item": "Condensed Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Lime", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Lime", "notes": null, "category": "produce"}]'::jsonb, '["Heat the oven to 160C/fan 140C/gas 3. Whizz the biscuits to crumbs in a food processor (or put in a strong plastic bag and bash with a rolling pin). Mix with the melted butter and press into the base and up the sides of a 22cm loose-based tart tin. Bake in the oven for 10 minutes. Remove and cool.", "Put the egg yolks in a large bowl and whisk for a minute with electric beaters. Add the condensed milk and whisk for 3 minutes then add the zest and juice and whisk again for 3 minutes. Pour the filling into the cooled base then put back in the oven for 15 minutes. Cool then chill for at least 3 hours or overnight if you like.", "When you are ready to serve, carefully remove the pie from the tin and put on a serving plate. To decorate, softly whip together the cream and icing sugar. Dollop or pipe the cream onto the top of the pie and finish with extra lime zest."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/2155644/key-lime-pie', 'https://www.themealdb.com/images/media/meals/qpqtuu1511386216.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('knafeh', 'Knafeh', 4, 0, 0, '{"calories": 500, "protein": 16.8, "carbs": 64.2, "fat": 21.5, "saturated_fat": 12.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 211.1, "potassium": null, "fiber": null, "sugar": 61.6, "vitamin_a": null, "vitamin_c": 0.9, "calcium": 443.7, "iron": null}'::jsonb, ARRAY['dessert', 'saudi arabian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 400.0, "unit": "g", "item": "Knafeh", "notes": null, "category": "other"}, {"quantity": 6.0, "unit": "tablespoons", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Yellow Food Colouring", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "cup", "item": "Mozzarella", "notes": null, "category": "dairy"}, {"quantity": 0.25, "unit": "cup", "item": "Cream Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.5, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Corn Flour", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Rose water", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Lemon Juice", "notes": null, "category": "produce"}]'::jsonb, '["1", "Take kanfhe in a bowl and roughly cut them. Pour melted butter, yellow food color and mix well with your hands.", "In a separate bowl mix milk, cream cheese, sugar, cornstarch well.", "2", "Turn on the flame and boil the liquid, when it gets thick turn off the flame let it cool down a little bit.", "Add mozzarella in it and mix it well.", "Now make a base with half of the kanfhe in a dish, gently press it to level the dough well.", "Pour the cheese mixture on the top and level it with a spoon.", "3", "Cover it with the other half of the kanfhe.", "Put the dish in a preheated oven at 200 degree for about 20-25 minutes.", "It''s ready when kunafa is golden and crunchy in the surface.", "4", "Boil water in a pan and dissolve sugar in it for 4–5 minutes. OR cook it until slightly thicken and keep on stirring. Add lemon juice with rose water, mix well.", "Evenly pour the syrup over the kunafa as soon as it comes out of the oven.", "Your kunafa is ready to serve."]'::jsonb, 'https://cookpad.com/eng/recipes/24934496?ref=search&search_term=saudi+arabia', 'https://www.themealdb.com/images/media/meals/76nffj1763593933.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('krispy-kreme-donut', 'Krispy Kreme Donut', 4, 0, 0, '{"calories": 1356, "protein": 9.3, "carbs": 196.8, "fat": 61.0, "saturated_fat": 26.5, "polyunsaturated_fat": 0.9, "monounsaturated_fat": null, "sodium": 228.9, "potassium": 1.2, "fiber": 0.0, "sugar": 166.0, "vitamin_a": null, "vitamin_c": 0.3, "calcium": 75.2, "iron": 1.4}'::jsonb, ARRAY['dessert', 'american', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 0.25, "unit": "ounce", "item": "Yeast", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.5, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Shortening", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Sprinking Canola Oil", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "cups", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.5, "unit": "cups", "item": "Vanilla", "notes": null, "category": "pantry"}, {"quantity": 6.0, "unit": "tablespoons", "item": "Boiling Water", "notes": null, "category": "pantry"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Butter", "notes": null, "category": "dairy"}]'::jsonb, '["Dissolve yeast in warm water in 2 1/2-quart bowl. Add milk, sugar, salt, eggs, shortening and 2 cups flour. Beat on low for 30 seconds, scraping bowl constantly. Beat on medium speed for 2 minutes, scraping bowl occasionally. Stir in remaining flour until smooth. Cover and let rise until double, 50-60 minutes. (Dough is ready when indentation remains when touched.) Turn dough onto floured surface; roll around lightly to coat with flour. Gently roll dough 1/2-inch thick with floured rolling pin. Cut with floured doughnut cutter. Cover and let rise until double, 30-40 minutes.", "Heat vegetable oil in deep fryer to 350°. Slide doughnuts into hot oil with wide spatula. Turn doughnuts as they rise to the surface. Fry until golden brown, about 1 minute on each side. Remove carefully from oil (do not prick surface); drain. Dip the doughnuts into creamy glaze set on rack.", "Glaze:", "Heat butter until melted. Remove from heat. Stir in powdered sugar and vanilla until smooth. Stir in water, 1 tablespoon at a time, until desired consistency."]'::jsonb, 'https://www.mythirtyspot.com/krispy-kreme-copycat-recipe-for/', 'https://www.themealdb.com/images/media/meals/4i5cnx1587672171.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('kvæfjord-cake-verdens-beste-worlds-best-cake', 'Kvæfjord Cake “Verdens Beste” (World’s Best Cake)', 4, 0, 0, '{"calories": 1692, "protein": 33.4, "carbs": 199.3, "fat": 83.5, "saturated_fat": 43.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 508.6, "potassium": 338.1, "fiber": 10.0, "sugar": 139.6, "vitamin_a": null, "vitamin_c": 0.8, "calcium": 258.6, "iron": 4.0}'::jsonb, ARRAY['dessert', 'norwegian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Egg Yolks", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "Granulated Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.6666666666666666, "unit": "cup", "item": "Heavy Cream", "notes": null, "category": "dairy"}, {"quantity": 0.75, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "pod", "notes": null, "category": "other"}, {"quantity": 0.6666666666666666, "unit": "cup", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 0.75, "unit": "cup", "item": "Granulated Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg Yolks", "notes": null, "category": "dairy"}, {"quantity": 1.25, "unit": "cup", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.5, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "White", "notes": null, "category": "other"}, {"quantity": 1.5, "unit": "cups", "item": "Granulated Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Sliced Almonds", "notes": null, "category": "pantry"}, {"quantity": 1.25, "unit": "cup", "item": "Whipping Cream", "notes": null, "category": "dairy"}]'::jsonb, '["Vanilla custard", "▢", "Separate the egg yolks and set aside the whites to use in the meringue.", "▢", "Whisk together the egg yolks, cornstarch and sugar in a bowl.", "▢", "Heat the cream and milk in a saucepan. Split open the vanilla pod and add the beans to the saucepan. Once the milk begins to bubble pour about half of it into the bowl with the egg mixture, whisking constantly. Then return the saucepan to the heat and pour the egg mixture back into the saucepan with remaining milk, whisking constantly. Once the mixture thickens lower the heat and continue whisking for about 30 seconds.", "▢", "Pour the custard into a clean bowl and cover with plastic wrap, placing the plastic directly on the top layer of the custard. Chill in the fridge.", "Cake", "▢", "Mix together butter and sugar until light and fluffy. Add egg yolks one at a time, setting aside the egg whites for the meringue. Add the flour mixed with baking powder. Stir in the milk, beating until smooth (you can use an electric mixer if you prefer).", "▢", "Preheat oven to 320°F (160°C). Cover a baking sheet with baking paper and spread out the batter into a large, even rectangle.", "Meringue topping", "▢", "Whisk together the egg whites and sugar until you get glossy, stiff peaks. The meringue should hold its form – if it still melts continue whisking.", "▢", "Spread out the meringue on top of the cake batter. Use a spatula to form light waves with the meringue. Sprinkle almonds on top of the meringue. Bake for about 30 minutes, until the meringue and almonds are golden.", "Cream filling", "▢", "Whisk the cream into stiff peaks. Carefully fold in the vanilla custard.", "Assembly", "▢", "Once the cake has cooled, cut it in half. You can use scissors for this, or a knife on a cutting board, slicing through the baking paper as well.", "▢", "Place half of the cake on a serving platter with the meringue side down and peel off the baking paper.", "▢", "Spread the cream filling across the cake. Then carefully remove the other half of the cake from the baking paper and place it over the cream filling, meringue side up.", "▢", "Serve with fresh berries."]'::jsonb, 'https://scandinaviancookbook.com/kvaefjord-cake-verdens-beste-worlds-best-cake/', 'https://www.themealdb.com/images/media/meals/gdn1ot1763075684.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lamingtons', 'Lamingtons', 4, 0, 0, '{"calories": 1961, "protein": 20.3, "carbs": 298.1, "fat": 128.1, "saturated_fat": 43.5, "polyunsaturated_fat": null, "monounsaturated_fat": 4.6, "sodium": 654.5, "potassium": 63.1, "fiber": 14.0, "sugar": 95.1, "vitamin_a": 128.6, "vitamin_c": 0.6, "calcium": 503.4, "iron": 13.0}'::jsonb, ARRAY['dessert', 'australian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 125.0, "unit": "g", "item": "Salted Butter", "notes": null, "category": "dairy"}, {"quantity": 250.0, "unit": "g", "item": "Golden Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 250.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Raspberry Jam", "notes": null, "category": "produce"}, {"quantity": 350.0, "unit": "g", "item": "Desiccated Coconut", "notes": null, "category": "pantry"}, {"quantity": 80.0, "unit": "g", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 250.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 50.0, "unit": "g", "item": "Cocoa Powder", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Icing Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Heat the oven to 200C/180C fan/gas 6. Butter and line a 20 x 30cm rectangle tin.", "step 2", "Beat the butter and sugar in a free-standing mixer until pale and fluffy. Add the eggs one at a time and beat well. Beat through the flour, milk and salt until fully combined, then spoon into the tin. Bake in the oven for 25 mins or until golden and firm to the touch. Set aside to cool completely.", "step 3", "Slice the sponge horizontally to create two halves. Trim the edges to make perfect corners. Cut the sponge into 18 squares. Lightly whip the cream with the icing sugar until it reaches soft peaks. Spread a little of the jam on half of the sponge squares then pipe or spread over a little of the cream. Sandwich each one with a second square of sponge then set aside in the fridge to chill.", "step 4", "To make the icing, whisk together the melted butter and milk in a bowl. Sieve the cocoa powder and icing sugar together in a seperate bowl. Gradually add the cocoa and sugar to the butter and milk mixture, whisking continuously to ensure there are no lumps. If it gets lumpy, whizz with a hand blender until smooth.", "step 5", "Divide the coconut between three shallow bowls (this keeps it from getting coated in too much chocolate whilst you’re dipping).", "step 6", "Dip each lamington in the icing until completely covered. Roll in the coconut and set on a wire rack. Repeat with the remaining sponges. Chill for a minimum of 1 hr."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/lamingtons', 'https://www.themealdb.com/images/media/meals/j2n7vg1761848636.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('madeira-cake', 'Madeira Cake', 4, 0, 0, '{"calories": 498, "protein": 9.8, "carbs": 82.6, "fat": 37.5, "saturated_fat": 23.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 394.4, "potassium": 42.4, "fiber": 1.1, "sugar": 32.0, "vitamin_a": null, "vitamin_c": null, "calcium": 15.3, "iron": 0.4}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 175.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 175.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 250.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 3.0, "unit": "tbs", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To Glaze Mixed Peel", "notes": null, "category": "other"}]'::jsonb, '["Pre-heat the oven to 180C/350F/Gas 4. Grease an 18cm/7in round cake tin, line the base with greaseproof paper and grease the paper.", "Cream the butter and sugar together in a bowl until pale and fluffy. Beat in the eggs, one at a time, beating the mixture well between each one and adding a tablespoon of the flour with the last egg to prevent the mixture curdling.", "Sift the flour and gently fold in, with enough milk to give a mixture that falls slowly from the spoon. Fold in the lemon zest.", "Spoon the mixture into the prepared tin and lightly level the top. Bake on the middle shelf of the oven for 30-40 minutes, or until golden-brown on top and a skewer inserted into the centre comes out clean.", "Remove from the oven and set aside to cool in the tin for 10 minutes, then turn it out on to a wire rack and leave to cool completely.", "To serve, decorate the cake with the candied peel."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/madeiracake_73878', 'https://www.themealdb.com/images/media/meals/urtqut1511723591.jpg', FALSE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mamoul-eid-biscuits', 'Mamoul (Eid biscuits)', 4, 0, 0, '{"calories": 749, "protein": 14.4, "carbs": 110.6, "fat": 57.1, "saturated_fat": 31.8, "polyunsaturated_fat": null, "monounsaturated_fat": 3.3, "sodium": 18.2, "potassium": 143.4, "fiber": 3.1, "sugar": 0.7, "vitamin_a": 401.9, "vitamin_c": 0.1, "calcium": 30.5, "iron": 2.5}'::jsonb, ARRAY['dessert', 'saudi arabian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 300.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 200.0, "unit": "g", "item": "Semolina", "notes": null, "category": "other"}, {"quantity": 25.0, "unit": "g", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 50.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 60.0, "unit": "g", "item": "Icing Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["1", "Mix butter with sugar until creamy.", "2", "Add oil flour and semolina and mix.", "3", "Add warm milk and don''t knead too much", "4", "Cover and leave aside for an hour or less until you prepare the filling", "5", "For the dates filling, fry some sesame in a pan then add butter. Add the dates paste and mixed well with sesame and butter. Then add a little bit of water until it''s mushy. Be careful don''t make it too mushy.", "6", "Take it of the pan, put in a plate until it''s cool. Then start to shape balls that weigh 15 gm.", "7", "Refrigerate for 1/2 an hour.", "8", "Get back to the dough and shape it as balls that weigh 30 gm.", "9", "Take the date filling out of the fridge and start to stuff each dough ball with dates ball.", "Then use the mamoul mould to give it this shape.", "10", "In a preheated oven 180 degrees, put it for 20 minutes until golden from below and little bit golden from above."]'::jsonb, 'https://cookpad.com/eng/recipes/16901544?ref=search&search_term=saudi+arabia', 'https://www.themealdb.com/images/media/meals/35kejr1763599712.jpg', FALSE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mazariner-scandinavian-almond-tartlets', 'Mazariner – Scandinavian Almond Tartlets', 4, 0, 0, '{"calories": 2401, "protein": 31.5, "carbs": 242.5, "fat": 144.3, "saturated_fat": 62.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1170.2, "potassium": 400.2, "fiber": 9.9, "sugar": 87.5, "vitamin_a": null, "vitamin_c": null, "calcium": 397.4, "iron": 10.8}'::jsonb, ARRAY['dessert', 'norwegian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 3.0, "unit": "cups", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.25, "unit": "cup", "item": "Powdered Sugar", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.25, "unit": "cup", "item": "Powdered Sugar", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "teaspoons", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "cups", "item": "Almond Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Almond Extract", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "cups", "item": "Powdered Sugar", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Heavy Cream", "notes": null, "category": "dairy"}, {"quantity": 0.25, "unit": "tsp", "item": "Almond Extract", "notes": null, "category": "pantry"}]'::jsonb, '["Shells", "▢", "Combine the flour and powdered sugar in a food processor. Add the butter and pulse until it''s evenly distributed. Add the egg and pulse until the dough comes together.", "▢", "Roll out the dough on a floured surface. Cut the dough in circles with a large mug. Press the circles down into a greased muffin pan. Put the pan of shells in the fridge while you prepare the almond filling.", "Almond filling", "▢", "Preheat oven to 355°F (180°C).", "▢", "Whisk the egg and powdered sugar together until thick and airy. Melt the butter and stir it into the egg mixture. Stir in the vanilla, flour, and almond extract. Stir in the almond flour.", "▢", "Pipe or spoon the almond filling onto the shells, filling the shells about 3/4 full.", "▢", "Bake the mazariner for 20 – 25 minutes, until light golden brown. Cool on a wire rack.", "Glaze", "▢", "Mix together the powdered sugar and liquid until you get a spreadable glaze. Spread the glaze on top of the mazariner and if you wish, decorate with sprinkles, or anything you like."]'::jsonb, 'https://scandinaviancookbook.com/mazariner-scandinavian-almond-tartlets/', 'https://www.themealdb.com/images/media/meals/uh1n5u1763075545.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mince-pies', 'Mince Pies', 4, 0, 0, '{"calories": 845, "protein": 12.4, "carbs": 159.2, "fat": 52.8, "saturated_fat": 32.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 176.5, "potassium": 119.1, "fiber": 4.7, "sugar": 61.4, "vitamin_a": null, "vitamin_c": 2.8, "calcium": 64.0, "iron": 1.4}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking'], '[{"quantity": 225.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 350.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 100.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 280.0, "unit": "g", "item": "Mincemeat", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Topping Icing Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["To make the pastry, rub 225g cold, diced butter into 350g plain flour, then mix in 100g golden caster sugar and a pinch of salt.", "Combine the pastry into a ball – don’t add liquid – and knead it briefly. The dough will be fairly firm, like shortbread dough. You can use the dough immediately, or chill for later.", "Preheat the oven to 200C/gas 6/fan 180C. Line 18 holes of two 12-hole patty tins, by pressing small walnut-sized balls of pastry into each hole.", "Spoon 280g mincemeat into the pies.", "Take slightly smaller balls of pastry than before and pat them out between your hands to make round lids, big enough to cover the pies.", "Top the pies with their lids, pressing the edges gently together to seal – you don’t need to seal them with milk or egg as they will stick on their own. (The pies may now be frozen for up to 1 month).", "Beat 1 small egg and brush the tops of the pies. Bake for 20 mins until golden. Leave to cool in the tin for 5 mins, then remove to a wire rack.", "To serve, lightly dust with icing sugar."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/2174/unbelievably-easy-mince-pies', 'https://www.themealdb.com/images/media/meals/qe8pf51576795532.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mini-bundt-cakes', 'Mini bundt cakes', 4, 0, 0, '{"calories": 522, "protein": 7.2, "carbs": 79.0, "fat": 37.7, "saturated_fat": 22.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 44.0, "potassium": 59.3, "fiber": 3.2, "sugar": 36.5, "vitamin_a": null, "vitamin_c": null, "calcium": 40.2, "iron": 1.3}'::jsonb, ARRAY['dessert', 'polish', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 150.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 175.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 125.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Cocoa Powder", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Icing Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Heat the oven to 180C/160C fan/gas 4. Melt 25g butter and generously brush into the holes of a mini bundt tins. Tip a little flour into each hole and shake to coat, then tip out the excess. Beat the butter, caster sugar and a pinch of salt together using an electric whisk. Add the eggs, one at a time, beating well after each addition. Combine the flour and baking powder in a separate bowl, then sift this into the wet ingredients and stir until smooth. Combine the cocoa powder and milk in a small bowl until smooth.", "step 2", "Spoon 1 tbsp of the plain batter into each hole of the bundt tin. Mix the remaining plain batter with the cocoa powder mixture, then divide this between the holes. Bake for 15-18 mins, or until a skewer inserted into the cakes comes out clean. Leave to cool in the tin for 5 mins, then turn out onto a wire rack and leave to cool completely. Dust with icing sugar to serve.", "step 3", "Pour 1 tablespoon of light batter into each mold. Mix the remaining batter with the stirred cocoa mixture and then fill the molds with a tablespoon.", "step 4", "Bake the mini Bundt cakes in the preheated oven for 15-18 minutes , depending on the size of the molds. After 15 minutes of baking time, use a toothpick to test with a skewer and, if necessary, bake for another 3 minutes. Let the mini Bundt cakes cool down completely in the tin. Then carefully remove from the mold. Dust with some icing sugar and serve. Enjoy your meal!"]'::jsonb, 'https://www.bbcgoodfood.com/recipes/mini-bundt-cakes', 'https://www.themealdb.com/images/media/meals/tzt3it1764363293.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('nanaimo-bars', 'Nanaimo Bars', 4, 0, 0, '{"calories": 1403, "protein": 15.4, "carbs": 147.2, "fat": 87.7, "saturated_fat": 36.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 445.9, "potassium": 215.4, "fiber": 11.0, "sugar": 41.1, "vitamin_a": null, "vitamin_c": null, "calcium": 259.8, "iron": 7.0}'::jsonb, ARRAY['dessert', 'canadian', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 125.0, "unit": "g", "item": "Custard", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 5.0, "unit": "tbs", "item": "Cocoa", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "shredded Digestive Biscuits", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Desiccated Coconut", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 4.0, "unit": "tbs", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tbs", "item": "Custard Powder", "notes": null, "category": "other"}, {"quantity": 250.0, "unit": "g", "item": "Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 150.0, "unit": "g", "item": "Dark Chocolate", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}]'::jsonb, '["Start by making the biscuit base. In a bowl, over a pan of simmering water, melt the butter with the sugar and cocoa powder, stirring occasionally until smooth. Whisk in the egg for 2 to 3 mins until the mixture has thickened. Remove from heat and mix in the biscuit crumbs, coconut and almonds if using, then press into the base of a lined 20cm square tin. Chill for 10 mins.", "For the middle layer, make the custard icing; whisk together the butter, cream and custard powder until light and fluffy, then gradually add the icing sugar until fully incorporated. Spread over the bottom layer and chill in the fridge for at least 10 mins until the custard is no longer soft.", "Melt the chocolate and butter together in the microwave, then spread over the chilled bars and put back in the fridge. Leave until the chocolate has fully set (about 2 hrs). Take the mixture out of the tin and slice into squares to serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/nanaimo-bars', 'https://www.themealdb.com/images/media/meals/vwuprt1511813703.jpg', FALSE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('new-york-cheesecake', 'New York cheesecake', 4, 0, 0, '{"calories": 1417, "protein": 24.0, "carbs": 86.2, "fat": 113.8, "saturated_fat": 75.4, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1022.2, "potassium": 247.1, "fiber": null, "sugar": 63.6, "vitamin_a": 162.0, "vitamin_c": null, "calcium": 350.6, "iron": 0.4}'::jsonb, ARRAY['dessert', 'american', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 85.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 140.0, "unit": "g", "item": "Sour Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 900.0, "unit": "g", "item": "Cream Cheese", "notes": null, "category": "dairy"}, {"quantity": 250.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tbs", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "teaspoons", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 250.0, "unit": "ml", "item": "Sour Cream", "notes": null, "category": "dairy"}, {"quantity": 150.0, "unit": "ml", "item": "Sour Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbsp", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Lemon Juice", "notes": null, "category": "produce"}]'::jsonb, '["Position an oven shelf in the middle of the oven. Preheat the oven to fan 160C/conventional 180C/gas 4. Line the base of a 23cm springform cake tin with parchment paper. For the crust, melt the butter in a medium pan. Stir in the biscuit crumbs and sugar so the mixture is evenly moistened. Press the mixture into the bottom of the pan and bake for 10 minutes. Cool on a wire rack while preparing the filling.", "For the filling, increase the oven temperature to fan 200C/conventional 240C/gas 9. In a table top mixer fitted with the paddle attachment, beat the soft cheese at medium-low speed until creamy, about 2 minutes. With the mixer on low, gradually add the sugar, then the flour and a pinch of salt, scraping down the sides of the bowl and the paddle twice.", "Swap the paddle attachment for the whisk. Continue by adding the vanilla, lemon zest and juice. Whisk in the eggs and yolk, one at a time, scraping the bowl and whisk at least twice. Stir the 284ml carton of soured cream until smooth, then measure 200ml/7fl oz (just over 3⁄4 of the carton). Continue on low speed as you add the measured soured cream (reserve the rest). Whisk to blend, but don''t over-beat. The batter should be smooth, light and somewhat airy.", "Brush the sides of the springform tin with melted butter and put on a baking sheet. Pour in the filling - if there are any lumps, sink them using a knife - the top should be as smooth as possible. Bake for 10 minutes. Reduce oven temperature to fan 90C/conventional 110C/gas 1⁄4 and bake for 25 minutes more. If you gently shake the tin, the filling should have a slight wobble. Turn off the oven and open the oven door for a cheesecake that''s creamy in the centre, or leave it closed if you prefer a drier texture. Let cool in the oven for 2 hours. The cheesecake may get a slight crack on top as it cools.", "Combine the reserved soured cream with the 142ml carton, the sugar and lemon juice for the topping. Spread over the cheesecake right to the edges. Cover loosely with foil and refrigerate for at least 8 hours or overnight.", "Run a round-bladed knife around the sides of the tin to loosen any stuck edges. Unlock the side, slide the cheesecake off the bottom of the tin onto a plate, then slide the parchment paper out from underneath."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/2869/new-york-cheesecake', 'https://www.themealdb.com/images/media/meals/swttys1511385853.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('no-churn-rum-raisin-ice-cream', 'No-Churn Rum Raisin Ice Cream', 4, 0, 0, '{"calories": 1069, "protein": 12.2, "carbs": 118.8, "fat": 52.9, "saturated_fat": 27.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1168.7, "potassium": 380.7, "fiber": 3.1, "sugar": 42.9, "vitamin_a": null, "vitamin_c": 17.7, "calcium": 49.0, "iron": 1.8}'::jsonb, ARRAY['dessert', 'jamaican', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "Dark Rum", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "cup", "item": "Raisins", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 14.0, "unit": "oz", "item": "jar Condensed Milk", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Ground Cinnamon", "notes": null, "category": "spices"}, {"quantity": 0.125, "unit": "teaspoon", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "cups", "item": "Heavy Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}]'::jsonb, '["Heat the rum in a small saucepan over medium heat until warm (do not boil). Remove from heat and stir in the raisins and vanilla extract. Let the mixture sit for at least 30 minutes. After soaking, drain off the extra rum, but keep ¼ cup of the rum and reserve it to mix into your ice cream base.", "In a large bowl, whisk together the sweetened condensed milk, dark brown sugar, cinnamon, allspice, salt, and reserved rum (¼ cup). Stir until the brown sugar is fully dissolved.", "In a separate bowl, whip the cold heavy cream with an electric mixer until stiff peaks form.", "Gently fold the whipped cream into the condensed milk mixture until fully combined, being careful not to deflate the cream. Fold in the drained rum-soaked raisins to distribute them evenly.", "Pour the mixture into a loaf pan or freezer-safe container. Smooth the top and cover with plastic wrap or an airtight lid. Freeze for at least 6 hours, or until firm.", "Let the ice cream sit at room temperature for 5–10 minutes before scooping for the best texture."]'::jsonb, 'https://www.myforkinglife.com/rum-raisin-ice-cream/#recipe', 'https://www.themealdb.com/images/media/meals/s9qyzd1764790772.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('norwegian-krumkake', 'Norwegian Krumkake', 4, 0, 0, '{"calories": 780, "protein": 5.0, "carbs": 99.6, "fat": 40.1, "saturated_fat": 25.6, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 151.2, "potassium": null, "fiber": 2.6, "sugar": 70.8, "vitamin_a": null, "vitamin_c": null, "calcium": 32.0, "iron": 2.0}'::jsonb, ARRAY['dessert', 'norwegian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 0.75, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.6666666666666666, "unit": "cup", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Cardamom", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.25, "unit": "cup", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Splash Water", "notes": null, "category": "other"}]'::jsonb, '["▢", "Whisk the egg and sugar until the mixture thickens.", "▢", "Melt the butter and let it cool slightly, then add the butter to the egg mixture.", "▢", "Mix in spices and then slowly add the flour while stirring to avoid lumps.", "▢", "Let the batter rest for at least 30 minutes. This improves the texture of the krumkaker.", "▢", "Spoon about one heaping tablespoon of batter onto iron and bake. If the batter is too thick, add some water to it.", "▢", "While still hot, shape the krumkake with a wooden krumkake roller or over a cup (if using a cup, make them a bit thicker). The krumkaker harden quickly, so you can just let them sit on the roller/cup until the next krumkake is ready to be shaped.", "▢", "After completely cooled, store the krumkaker in a metal or glass tin lined with paper towels at the bottom. You can also freeze them!"]'::jsonb, 'https://scandinaviancookbook.com/norwegian-krumkake/', 'https://www.themealdb.com/images/media/meals/z9g8011763075640.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pancakes', 'Pancakes', 4, 0, 0, '{"calories": 374, "protein": 8.4, "carbs": 24.8, "fat": 25.7, "saturated_fat": 3.5, "polyunsaturated_fat": null, "monounsaturated_fat": 13.3, "sodium": 404.5, "potassium": 129.0, "fiber": 0.9, "sugar": 3.9, "vitamin_a": 12.0, "vitamin_c": 0.8, "calcium": 123.5, "iron": 1.5}'::jsonb, ARRAY['dessert', 'american', 'themealdb', 'nutrition-generated', 'breakfast', 'baking', 'vegetarian'], '[{"quantity": 100.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 300.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Raspberries", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Blueberries", "notes": null, "category": "other"}]'::jsonb, '["Put the flour, eggs, milk, 1 tbsp oil and a pinch of salt into a bowl or large jug, then whisk to a smooth batter. Set aside for 30 mins to rest if you have time, or start cooking straight away.", "Set a medium frying pan or crêpe pan over a medium heat and carefully wipe it with some oiled kitchen paper. When hot, cook your pancakes for 1 min on each side until golden, keeping them warm in a low oven as you go.", "Serve with lemon wedges and sugar, or your favourite filling. Once cold, you can layer the pancakes between baking parchment, then wrap in cling film and freeze for up to 2 months."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/2907669/easy-pancakes', 'https://www.themealdb.com/images/media/meals/rwuyqx1511383174.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('parkin-cake', 'Parkin Cake', 4, 0, 0, '{"calories": 1143, "protein": 8.0, "carbs": 143.3, "fat": 49.0, "saturated_fat": 29.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 406.8, "potassium": 39.6, "fiber": 4.4, "sugar": 74.9, "vitamin_a": null, "vitamin_c": 17.1, "calcium": 149.6, "iron": 6.0}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'breakfast', 'baking', 'vegetarian'], '[{"quantity": 200.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 4.0, "unit": "tbs", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "Golden Syrup", "notes": null, "category": "pantry"}, {"quantity": 85.0, "unit": "g", "item": "Black Treacle", "notes": null, "category": "other"}, {"quantity": 85.0, "unit": "g", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Oatmeal", "notes": null, "category": "grains"}, {"quantity": 250.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tbs", "item": "Ground Ginger", "notes": null, "category": "produce"}]'::jsonb, '["Heat oven to 160C/140C fan/gas 3. Grease a deep 22cm/9in square cake tin and line with baking parchment. Beat the egg and milk together with a fork.", "Gently melt the syrup, treacle, sugar and butter together in a large pan until the sugar has dissolved. Remove from the heat. Mix together the oatmeal, flour and ginger and stir into the syrup mixture, followed by the egg and milk.", "Pour the mixture into the tin and bake for 50 mins - 1 hr until the cake feels firm and a little crusty on top. Cool in the tin then wrap in more parchment and foil and keep for 3-5 days before eating if you can – it’ll become softer and stickier the longer you leave it, up to 2 weeks."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/1940684/parkin', 'https://www.themealdb.com/images/media/meals/qxuqtt1511724269.jpg', FALSE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('passion-fruit-mousse', 'Passion fruit mousse', 4, 0, 0, '{"calories": 421, "protein": 22.0, "carbs": 80.4, "fat": 0.2, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 313.8, "potassium": 284.6, "fiber": null, "sugar": 76.3, "vitamin_a": null, "vitamin_c": 6.7, "calcium": 29.2, "iron": 0.0}'::jsonb, ARRAY['dessert', 'venezulan', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 0.5, "unit": "tbsp", "item": "Unflavoured Gelatin", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Fruit Pulp", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "can", "item": "Condensed Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "White", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Mint", "notes": null, "category": "produce"}]'::jsonb, '["Add gelatin and ¼ cup room-temperature water to small bowl; let sit until gelatin softens, about 5 minutes. In medium saucepan over medium-high heat, stir together passion fruit pulp, sugar and gelatin mixture. Cook, stirring occasionally, until mixture is thoroughly combined and smooth (mixture should not come to a boil). Remove from heat; cool completely. Stir in condensed milk.", "Meanwhile, in clean mixing bowl, using electric mixer, beat egg whites until stiff (peaks of egg whites will not droop, and egg whites will not move when bowl is tilted).", "Stir 1/3 egg whites into cooled passion fruit mixture until combined. Using spatula, gently fold in remaining egg whites until combined. Divide mousse evenly among clear glass serving cups; cover. Refrigerate mousse until well chilled, at least 2 hrs.", "Serve chilled. Garnish with mint, if desired."]'::jsonb, 'https://goya.es/en/recipes/passion-fruit-mousse', 'https://www.themealdb.com/images/media/meals/gkcdpl1764441325.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('peach-blueberry-grunt', 'Peach & Blueberry Grunt', 4, 0, 0, '{"calories": 351, "protein": 7.8, "carbs": 89.6, "fat": 16.2, "saturated_fat": 9.4, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 332.8, "potassium": 125.6, "fiber": 3.1, "sugar": 16.8, "vitamin_a": 8.1, "vitamin_c": 11.7, "calcium": 57.2, "iron": 0.7}'::jsonb, ARRAY['dessert', 'american', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "tsp", "item": "Corn Flour", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 2 Orange", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Orange", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Peaches", "notes": null, "category": "other"}, {"quantity": 250.0, "unit": "g", "item": "Blueberries", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 50.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Muscovado Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Milk", "notes": null, "category": "dairy"}]'::jsonb, '["Heat oven to 190C/170C fan/gas 5. Butter a wide shallow ovenproof dish. Blend the cornflour with the orange zest and juice, and put in a large pan with the sugar. Halve, stone and slice the peaches and add to the pan. Bring slowly to the boil, stirring gently until the sauce is shiny and thickened, about 3-4 mins. Remove from the heat, stir in the blueberries and tip into the prepared dish.", "Tip the flour into a mixing bowl and add the 50g butter. Rub the butter into the flour until it resembles fine breadcrumbs, then stir in half the sugar. Mix the remaining sugar with the cinnamon and set aside.", "Add the milk to the dry ingredients and mix to a soft dough. Turn out onto a lightly floured surface and knead briefly. Roll out to an oblong roughly 16 x 24cm. Brush with melted butter and sprinkle evenly with the spicy sugar. Roll up from one long side and cut into 12 slices. Arrange around the top of the dish, leaving the centre uncovered.", "Bake for 20-25 mins, until the topping is crisp and golden. Serve warm."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/1553651/peach-and-blueberry-grunt', 'https://www.themealdb.com/images/media/meals/ssxvup1511387476.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('peanut-butter-cheesecake', 'Peanut Butter Cheesecake', 4, 0, 0, '{"calories": 752, "protein": 15.3, "carbs": 93.9, "fat": 63.3, "saturated_fat": 24.6, "polyunsaturated_fat": null, "monounsaturated_fat": 5.0, "sodium": 109.7, "potassium": 135.9, "fiber": 3.8, "sugar": 81.8, "vitamin_a": null, "vitamin_c": 4.2, "calcium": 177.5, "iron": 1.8}'::jsonb, ARRAY['dessert', 'american', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 50.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 175.0, "unit": "g", "item": "Peanut Cookies", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Leafs", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "g", "item": "Ricotta", "notes": null, "category": "dairy"}, {"quantity": 175.0, "unit": "g", "item": "Peanut Butter", "notes": null, "category": "dairy"}, {"quantity": 175.0, "unit": "g", "item": "Golden Syrup", "notes": null, "category": "pantry"}, {"quantity": 150.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 275.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Light Brown Soft Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Crushed Peanut Brittle", "notes": null, "category": "pantry"}]'::jsonb, '["Oil and line a 20cm round loose- bottomed cake tin with cling film, making it as smooth as possible. Melt the butter in a pan. Crush the biscuits by bashing them in a bag with a rolling pin, then stir them into the butter until very well coated. Press the mixture firmly into the base of the tin and chill.", "Soak the gelatine in water while you make the filling. Tip the ricotta into a bowl, then beat in the peanut butter and syrup. Ricotta has a slightly grainy texture so blitz until smooth with a stick blender for a smoother texture if you prefer.", "Take the soaked gelatine from the water and squeeze dry. Put it into a pan with the milk and heat very gently until the gelatine dissolves. Beat into the peanut mixture, then tip onto the biscuit base. Chill until set.", "To freeze, leave in the tin and as soon as it is solid, cover the surface with cling film, then wrap the tin with cling film and foil.", "To defrost, thaw in the fridge overnight.", "To serve, carefully remove from the tin. Whisk the cream with the sugar until it holds its shape, then spread on top of the cheesecake and scatter with the peanut brittle."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/1759649/peanut-butter-cheesecake', 'https://www.themealdb.com/images/media/meals/qtuuys1511387068.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('peanut-butter-cookies', 'Peanut Butter Cookies', 4, 0, 0, '{"calories": 562, "protein": 13.0, "carbs": 50.8, "fat": 35.6, "saturated_fat": 7.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 44.0, "potassium": null, "fiber": 4.6, "sugar": 42.4, "vitamin_a": null, "vitamin_c": null, "calcium": 70.0, "iron": 1.4}'::jsonb, ARRAY['dessert', 'american', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "Peanut Butter", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}]'::jsonb, '["Preheat oven to 350ºF (180ºC).", "In a large bowl, mix together the peanut butter, sugar, and egg.", "Scoop out a spoonful of dough and roll it into a ball. Place the cookie balls onto a nonstick baking sheet.", "For extra decoration and to make them cook more evenly, flatten the cookie balls by pressing a fork down on top of them, then press it down again at a 90º angle to make a criss-cross pattern.", "Bake for 8-10 minutes or until the bottom of the cookies are golden brown.", "Remove from baking sheet and cool.", "Enjoy!"]'::jsonb, 'https://tasty.co/recipe/3-ingredient-peanut-butter-cookies', 'https://www.themealdb.com/images/media/meals/1544384070.jpg', FALSE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pear-tarte-tatin', 'Pear Tarte Tatin', 4, 0, 0, '{"calories": 880, "protein": 7.7, "carbs": 96.0, "fat": 52.1, "saturated_fat": 31.2, "polyunsaturated_fat": null, "monounsaturated_fat": 10.0, "sodium": 412.5, "potassium": 183.5, "fiber": 2.1, "sugar": 48.2, "vitamin_a": null, "vitamin_c": null, "calcium": 89.8, "iron": 2.5}'::jsonb, ARRAY['dessert', 'french', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Pears", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Anise", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Cardamom", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tbs", "item": "Brandy", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "g", "item": "Puff Pastry", "notes": null, "category": "other"}]'::jsonb, '["Core the pears, then peel as neatly as possible and halve. If you like, they can be prepared up to a day ahead and kept in the fridge, uncovered, so that they dry out.", "Tip the sugar, butter, star anise, cardamom and cinnamon into an ovenproof frying pan, about 20cm wide, and place over a high heat until bubbling. Shake the pan and stir the buttery sauce until it separates and the sugar caramelises to a toffee colour.", "Lay the pears in the pan, then cook in the sauce for 10-12 mins, tossing occasionally, until completely caramelised. Don’t worry about them burning – they won’t – but you want to caramelise them as much as possible. Splash in the brandy and let it flambé, then set the pears aside.", "Heat oven to 200C/fan 180C/gas 6. Roll the pastry out to the thickness of a £1 coin. Using a plate slightly larger than the top of the pan, cut out a circle, then press the edges of the circle of pastry to thin them out.", "When the pears have cooled slightly, arrange them in the pan, cut side up, in a floral shape, with the pears around the edge pointing inwards. Rest the cinnamon stick on the top in the centre, with the cardamom pods scattered around.", "Drape the pastry over the pears, then tuck the edges down the pan sides and under the fruit (see Gordon’s guide). Pierce the pastry a few times, then bake for 15 mins. If a lot of juice bubbles up the side of the pan, pour it off at this stage (see guide). Reduce oven to 180C/fan 160C/gas 4 and bake for 15 mins more until the pastry is golden. Leave the tart to stand for 10 mins, then invert it carefully onto a serving dish."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/4778/pear-tarte-tatin', 'https://www.themealdb.com/images/media/meals/rxvxrr1511797671.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('piernik-polish-gingerbread', 'Piernik (Polish gingerbread)', 4, 0, 0, '{"calories": 792, "protein": 17.4, "carbs": 159.0, "fat": 72.0, "saturated_fat": 39.0, "polyunsaturated_fat": null, "monounsaturated_fat": 4.3, "sodium": 606.1, "potassium": 283.7, "fiber": 7.0, "sugar": 83.2, "vitamin_a": 225.0, "vitamin_c": 1.5, "calcium": 123.6, "iron": 3.0}'::jsonb, ARRAY['dessert', 'polish', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 140.0, "unit": "g", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 300.0, "unit": "g", "item": "Clear Honey", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 375.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 3.0, "unit": "tsp", "item": "Ground Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Ground Cinnamon", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Ground Clove", "notes": null, "category": "spices"}, {"quantity": 0.25, "unit": "tsp", "item": "Ground Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "Plum Jam", "notes": null, "category": "other"}, {"quantity": 225.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 140.0, "unit": "g", "item": "Dark Chocolate", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Clear Honey", "notes": null, "category": "pantry"}]'::jsonb, '["Heat oven to 160C/140C fan/gas 3. Grease and line the base and sides of a deep 20cm cake tin with baking parchment. Put the honey, sugar and butter in a medium saucepan and cook over a medium heat until fully melted. Remove from the heat and allow to cool. Put the flour and spices in a large bowl and mix everything together.", "step 2", "Once the liquid ingredients have cooled, whisk in the eggs. Pour over the dry ingredients, whisking them together to form a smooth batter – be careful not to overmix as this can lead to a dry cake. Pour into the prepared tin and bake for 50-55 mins or until risen and a skewer inserted into the middle of the cake comes out clean. Allow the cake to cool in the pan for 20 mins before turning out onto a wire rack to cool completely.", "step 3", "Once cooled, use a large serrated knife to slice the cake into 3 layers. Spread the jam across the 2 bottom cake layers, then reassemble the cake and set aside while you make the glaze. Put the cream, chocolate and honey in a medium pan and cook over a low-medium heat until the chocolate is melted and you have a smooth, pourable mixture. Put the cake on a wire rack set over a parchment-lined baking tray and pour over the glaze, making sure to cover the entire cake. Use a fish slice to carefully transfer the cake to a serving plate and allow the glaze to set. To decorate, dust with a little edible gold powder, if you like. Uniced, this cake will keep for up to 5 days. Once iced, enjoy within 3 days – just keep in the fridge, but remove before serving and eat at room temperature."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/piernik-polish-gingerbread', 'https://www.themealdb.com/images/media/meals/kwmdk41764120884.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pistachio-cake', 'Pistachio cake', 4, 0, 0, '{"calories": 1510, "protein": 23.8, "carbs": 149.3, "fat": 136.6, "saturated_fat": 67.8, "polyunsaturated_fat": null, "monounsaturated_fat": 17.0, "sodium": 279.8, "potassium": 462.8, "fiber": 14.5, "sugar": 65.3, "vitamin_a": null, "vitamin_c": 28.4, "calcium": 272.8, "iron": 4.2}'::jsonb, ARRAY['dessert', 'polish', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 250.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "Pistachio", "notes": null, "category": "pantry"}, {"quantity": 80.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 225.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Mascarpone", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Pistachio Paste", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Raspberries", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Lime", "notes": null, "category": "produce"}]'::jsonb, '["Heat the oven to 180C/160C fan/gas 4. Butter and line a 23cm springform cake tin. Tip 150g of the pistachios into a food processor and blitz until finely ground. Tip into a bowl and mix in the flour, baking powder and pinch of salt. Beat the butter and sugar in a separate bowl until fluffy and pale, around 5 mins. Crack in the eggs one at a time, beating well for 1 min after each addition, until they have all been added. Beat in the vanilla, then fold in the flour mixture gently. Carefully spoon into the prepared tin and bake for 35-40 mins until a skewer inserted into the middle comes out clean. Set aside to cool completely on a wire rack in the tin.", "step 2", "Meanwhile, sift the icing sugar into a bowl, then tip in the mascarpone, double cream and pistachio paste. Beat until well combined, then set aside in the fridge for 20-30 mins to thicken to a spooning consistency.", "step 3", "Cut the cooled cake in half horizontally using a serrated knife, so you have two layers. Put the bottom layer on a plate or cake stand and spread over a generous spoonful of the pistachio cream. Top with a generous handful of the raspberries so the cake is covered. Top with the other sponge half, then cover the top and sides of the cake with the remaining cream. Scatter over the last of the raspberries, the remaining pistachios and the lime zest to serve. Will keep chilled in an airtight container for two days."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/pistachio-cake', 'https://www.themealdb.com/images/media/meals/xvgpng1764121726.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pistachio-kunafa-chocolate-cake-and-cupcakes', 'Pistachio Kunafa Chocolate Cake and Cupcakes', 4, 0, 0, '{"calories": 544, "protein": 17.3, "carbs": 363.4, "fat": 53.5, "saturated_fat": 15.3, "polyunsaturated_fat": null, "monounsaturated_fat": 1.8, "sodium": 9863.0, "potassium": 195.5, "fiber": 9.1, "sugar": 11.8, "vitamin_a": null, "vitamin_c": 0.3, "calcium": 135.4, "iron": 4.5}'::jsonb, ARRAY['dessert', 'saudi arabian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 6.0, "unit": "tablespoons", "item": "White Chocolate", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Unsalted Pistachio", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Condensed Milk", "notes": null, "category": "dairy"}, {"quantity": 5.0, "unit": "tablespoons", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Cream Biscuits", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 150.0, "unit": "g", "item": "Sevaiiya", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Ghee", "notes": null, "category": "other"}, {"quantity": 120.0, "unit": "ml", "item": "Dark Chocolate", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Malai", "notes": null, "category": "other"}]'::jsonb, '["1", "For Chocolate Cake:Ready all the ingredients. Powder the oreo biscuits, pinch salt and mix warm milk as needed and make a cake batter. Add in baking powder and vinegar and mix.", "2", "Grease a loose bottomed tin. Pour a 1cm thick layer of the batter.", "3", "Bake in a preheated oven @160°C for 7-8 minutes or until the knife comes out clean. Cool on wire rack.", "4", "For Homemade Pistachio Paste:Ready all the pistachio paste ingredients. Slightly melt white chocolate on a double boiler.(else the mixer blade may break) Coarsely powder the pistachio in mixer. Add in condensed milk.", "5", "Add in slightly warmed and slightly melted white chocolate and milk as required and crush to a smooth paste.(Green food colour can be add. I haven''t.)", "6", "For Kunafa: In a kadhaai take ghee and roast the sevaiiya on slow gas. Keep stirring until a pleasant roasted aroma releases. Cool it. Add in the Homemade pistachio paste.Mix well.", "7", "Lip smacking Kunafa is ready. Spread a 2 cm layer on the cooled chocolate cake.", "8", "Melt dark chocolate and strained malai and prepare the chocolate ganache. Cool and pour on the Kunafa layer.", "9", "Garnish Pistachio Kunafa Chocolate Cake with chopped pistachio and silver balls. Keep in fridge for 2-3 hours. Then unmould the Kunafa Cake.", "10", "I also prepared Kunafa cupcakes. Cut and enjoy. The cake looked so pretty that we could either save it or have it!! ☺", "11", "Cross sectional view of the Pistachio Kunafa Chocolate Cake.", "12", "Enjoy with a new sweet delicacy this festive season with family and friends."]'::jsonb, 'https://cookpad.com/eng/recipes/25116037?ref=search&search_term=saudi+arabia', 'https://www.themealdb.com/images/media/meals/yh3sg71763741307.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('polish-chocolate-walnut-cake', 'Polish chocolate & walnut cake', 4, 0, 0, '{"calories": 1155, "protein": 38.0, "carbs": 174.7, "fat": 64.6, "saturated_fat": 17.2, "polyunsaturated_fat": null, "monounsaturated_fat": 7.7, "sodium": 361.8, "potassium": 593.5, "fiber": 7.4, "sugar": 102.0, "vitamin_a": null, "vitamin_c": null, "calcium": 140.2, "iron": 2.8}'::jsonb, ARRAY['dessert', 'polish', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 150.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 50.0, "unit": "g", "item": "Coco Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "White", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Walnuts", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Potato Starch", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Chocolate Chips", "notes": null, "category": "pantry"}]'::jsonb, '["Heat the oven to 170C/150C fan/gas 3½. Line a 30 x 22cm shallow baking tin with baking parchment. Sift the flour and mix it with cocoa, then set aside. Beat the egg whites until stiff, then add the sugar to them in small batches. Add the egg yolks, one by one, whisking constantly. Tip in the flour mixture and gently fold everything together with a spatula. Pour the prepared batter into the lined tin and bake for 35 mins. Cool for 5 mins, remove from the tin and re-line the tin with baking parchment.", "step 2", "To make the meringue, whisk the whites until stiff, then gradually whisk in the sugar, one tablespoon at a time. When you have a stiff and shiny meringue, fold in the finely chopped walnuts, flour and startch. Spread the mixture into the re-lined tin and cook for 40 mins on the same heat. Remove from the oven and leave to cool.", "step 3", "For the chocolate glaze, heat the cream over low heat, then remove from the heat, pour the chopped chocolate into it and mix it until it melts and becomes shiny.", "step 4", "Cut the cooled chocolate sponge cake and meringue into two layers. Put the nut meringue on top of the bottom layer of sponge and sprinkle on some of the reserved walnuts. Add another layer of meringue and then the upper layer of chocolate sponge cake and cover the top with chocolate glaze. Decorate with walnuts. Put the finished cake in the fridge for 1-2 hrs before serving."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/polish-chocolate-cake', 'https://www.themealdb.com/images/media/meals/e8ihjp1764123021.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('polish-doughnuts-pączki', 'Polish doughnuts (Pączki)', 4, 0, 0, '{"calories": 1105, "protein": 29.2, "carbs": 144.0, "fat": 81.1, "saturated_fat": 16.8, "polyunsaturated_fat": null, "monounsaturated_fat": 11.0, "sodium": 121.8, "potassium": 294.9, "fiber": 4.2, "sugar": 25.2, "vitamin_a": null, "vitamin_c": 0.3, "calcium": 245.2, "iron": 8.4}'::jsonb, ARRAY['dessert', 'polish', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 10.0, "unit": "g", "item": "Yeast", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 125.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 15.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 10.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 500.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 200.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 15.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 125.0, "unit": "ml", "item": "Jam", "notes": null, "category": "other"}, {"quantity": 10.0, "unit": "g", "item": "Ground Almonds", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Oil", "notes": null, "category": "pantry"}, {"quantity": 75.0, "unit": "g", "item": "Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1/2 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Almond Essence", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "Almonds", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "To make the leaven, mix the yeast with the sugar and flour, and stir in the warm milk. Set aside in a warm place for 30 minutes.", "step 2", "For the dough, put egg yolks into a heatproof bowl and add the sugar and vanilla sugar. Set the bowl over a pan of simmering water and whisk until smooth and thick.", "step 3", "Sift the flour into the bowl of a stand mixer, add the beaten yolks and the warm cream, mix thoroughly, then add a pinch of salt and the leaven. Bring together to make a dough and knead for 10 minutes (or 15-20 if doing this by hand).", "step 4", "When the dough stops sticking to your hands, pour in the cooled melted butter and knead for a few more minutes. Cover with a cloth and leave in a warm place to rise for at least 1 hr-1 hr 30 mins.", "step 5", "Mix the jam with the ground almonds and spoon into a piping bag or jam syringe. Divide the dough into 16 pieces and shape them into doughnuts. Cover and leave to rise for 30 mins.", "step 6", "Fill a deep pan or a deep fat fryer one third full of oil or melted lard and heat it until it is 180C – if you don’t have a thermometer, drop in a small chunk of bread. The oil is ready when it browns in about 30 secs. Add the doughnuts and fry, turning them once for about 1-2 mins on each side (a thin lighter ring should form in the middle). After removing, drain the doughnuts of excess fat on some kitchen paper."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/polish-doughnuts', 'https://www.themealdb.com/images/media/meals/x6jqog1764359857.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('polskie-nalesniki-polish-pancakes', 'Polskie Nalesniki (Polish Pancakes)', 4, 0, 0, '{"calories": 316, "protein": 9.5, "carbs": 44.9, "fat": 9.6, "saturated_fat": 5.6, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 136.1, "potassium": 85.0, "fiber": 1.0, "sugar": 14.9, "vitamin_a": null, "vitamin_c": 0.6, "calcium": 95.7, "iron": 2.5}'::jsonb, ARRAY['dessert', 'polish', 'themealdb', 'nutrition-generated', 'breakfast', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 0.75, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}]'::jsonb, '["Add flour, eggs, milk, water, and salt in a large bowl then mix with a hand mixer until you have a smooth, lump-free batter.", "At this point, mix in the butter or the vegetable oil. Alternatively, you can use them to grease the pan before frying each pancake.", "Heat a non-stick pan over medium heat, then pour in the batter, swirling the pan to help it spread.", "When the pancake starts pulling away a bit from the sides, and the top is no longer wet, flip it and cook shortly on the other side as well.", "Transfer to a plate. Cook the remaining batter until all used up.", "Serve warm, with the filling of your choice."]'::jsonb, 'https://www.tasteatlas.com/nalesniki/recipe', 'https://www.themealdb.com/images/media/meals/58bkyo1593350017.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('portuguese-custard-tarts', 'Portuguese custard tarts', 4, 0, 0, '{"calories": 923, "protein": 18.2, "carbs": 126.4, "fat": 38.4, "saturated_fat": 22.1, "polyunsaturated_fat": null, "monounsaturated_fat": 7.5, "sodium": 539.7, "potassium": 336.7, "fiber": 2.7, "sugar": 75.4, "vitamin_a": null, "vitamin_c": null, "calcium": 318.3, "iron": 2.6}'::jsonb, ARRAY['dessert', 'portuguese', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "tbs", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tbs", "item": "Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 375.0, "unit": "g", "item": "Puff Pastry", "notes": null, "category": "other"}, {"quantity": 250.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Lemon Zest", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Corn Flour", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "ml", "item": "Whole Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Pod of Vanilla", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Cinnamon", "notes": null, "category": "spices"}]'::jsonb, '["STEP 1", "Roll the pastry", "Mix the flour and icing sugar, and use this to dust the work surface. Roll the pastry out to make a 45 x 30cm rectangle. Roll up lengthways to create a long sausage shape.", "STEP 2", "Cutting pastry into rounds", "Cut the pastry into 24 wheels, about 1-2cm thick.", "STEP 3", "Roll out each pastry portion", "Roll each wheel lightly with the rolling pin to fit 2 x 12-hole non-stick fairy cake tins.", "STEP 4", "Press pastry into the tin", "Press the pastry circles into the tins and mould into the tins to make thin cases. Chill until needed.", "STEP 5", "Make the infused syrup", "Heat the oven to 220C/fan 200C/gas 7. Make a sugar syrup by bringing the sugar, 200ml water, lemon zest and cinnamon stick to the boil. Reduce until syrupy, allow to cool, then remove the cinnamon and lemon. Whisk the eggs, egg yolks and cornflour until smooth in another large pan.", "STEP 6", "Making custard", "Heat the milk and vanilla pod seeds in a separate pan until just below the boil. Gradually pour the hot milk over the eggs and cornflour, then cook on a low heat, continually whisking.", "STEP 7", "Add syrup to custard", "Add the cooled sugar syrup to the custard and whisk until thickened slightly.", "STEP 8", "Pour custard into the tins", "Pour the custard through a sieve. Pour into the pastry cases and bake for 15 minutes until the pastry is golden and the custard has darkened.", "STEP 9", "cool and dust with icing sugar", "Cool completely in the tins then sift over icing sugar and ground cinnamon to serve."]'::jsonb, 'https://www.olivemagazine.com/recipes/baking-and-desserts/portuguese-custard-tarts/', 'https://www.themealdb.com/images/media/meals/vmz7gl1614350221.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('postre-chajá', 'Postre Chajá', 4, 0, 0, '{"calories": 1157, "protein": 26.8, "carbs": 138.3, "fat": 50.6, "saturated_fat": 30.6, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 546.2, "potassium": 557.2, "fiber": 3.5, "sugar": 102.5, "vitamin_a": null, "vitamin_c": 7.5, "calcium": 171.4, "iron": 1.3}'::jsonb, ARRAY['dessert', 'uruguayan', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 75.0, "unit": "g", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 30.0, "unit": "g", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "White", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Dulce de leche", "notes": null, "category": "other"}, {"quantity": 400.0, "unit": "g", "item": "Heavy Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 40.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 500.0, "unit": "g", "item": "Peaches", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "ml", "item": "Peach Juice", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Cornstarch", "notes": null, "category": "produce"}]'::jsonb, '["For the sponge cake preheat oven to 180 degrees Celsius and prepare either one or two 20cm/8 inch cake pan(s). Line bottom with parchment paper. Then divide the eggs into egg white and egg yolks. Use a bigger bowl for the egg yolks. If you have a glass or metal bowl, use that one for the egg whites. Be sure that bowl is free of fat/grease and that your mixer was properly cleaned. First beat the egg whites on medium speed with a pinch of salt until soft peaks form. Set aside. Without cleaning our mixer, beat the egg yolks with the sugar. Beat until the color becomes much paler and you have a creamy consistency. This usually takes several minutes.", "2", "Gently pour one third of the egg whites on top of the mixed egg yolks and sift the flour and cornstarch on top. Don''t skip this step. It is important that the flour mix was sifted. Gently mix all ingredients with a spatula. Try to incorperate the flour mix and egg whites without losing volume. Add the last two thirds of beaten egg whites and gently fold the mixture. Don''t overmix. Put batter into the prepared cake pans and immediately bake. Don''t let the batter sit for too long as it will quickly lose volume. Bake for 35 minutes if using one springform or 25 minutes if using two. Let cool a little before gently getting them out of the form. Tip: if making the day before, wrap in cling wrap, it is much easier to cut in half once cold.", "3", "For the meringue beat egg white until soft peaks form, add pinch of salt and continue beating on high while adding the sugar. Beat for at least three more minutes until glossy and shiny. Pipe small stars or other shapes with the meringue on a baking sheet lined with parchment paper. Dry for about 45min at 100 degrees Celsius in the oven. Keep in airtight container until further use.", "4", "For the filling beat heavy cream, vanilla extract and sugar until stiff peaks form, slice peaches in thin slices. Cut cake in four layers, this is much easier done once the cake layers are cold. Brush cake layer with some of the peach juice left, then pipe thin layer of whipped cream around the edges, place the peach slices in the middle on first layer on cake, on the second layer only spread the dulce de leche. Repeat layer with brushed peach juice, whipped cream and peaches for the third and final layer. Be sure to reserve enough peach slices for the top. Spread thin layer of whipped cream on the sides of the cake and pipe on some roses around the edges if desired. Heat the peach juice and mix the cornstarch with a bit of water until you see no lumps. Once juice is hot, add the cornstarch and stir until glaze thickenes. Pour over peaches of the top layer cake. Crush the meringue and pat around the sides. Serve immediately."]'::jsonb, 'https://jennyisbaking.com/2018/08/31/uruguays-version-of-a-peach-layer-cake-postre-chaja/#recipe', 'https://www.themealdb.com/images/media/meals/wii0591764375062.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pouding-chomeur', 'Pouding chomeur', 4, 0, 0, '{"calories": 1378, "protein": 23.8, "carbs": 255.0, "fat": 62.2, "saturated_fat": 37.6, "polyunsaturated_fat": null, "monounsaturated_fat": 4.3, "sodium": 1337.5, "potassium": 439.0, "fiber": null, "sugar": 205.8, "vitamin_a": null, "vitamin_c": 0.8, "calcium": 1525.8, "iron": 3.7}'::jsonb, ARRAY['dessert', 'canadian', 'themealdb', 'nutrition-generated', 'breakfast', 'baking', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "cups", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.25, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.5, "unit": "cup", "item": "Maple Syrup", "notes": null, "category": "pantry"}, {"quantity": 1.5, "unit": "cup", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.5, "unit": "cup", "item": "Single Cream", "notes": null, "category": "dairy"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Butter", "notes": null, "category": "dairy"}]'::jsonb, '["In a large bowl, with an electric mixer, mix the butter and sugar till the mix is light.", "Add eggs and vanilla and mix.", "In another bowl, mix flour and baking powder.", "Alternate flour mix and milk to the butter mix.", "Pour into a 13 inch by 9 inch greased pan.", "MAPLE SAUCE.", "In a large casserole, bring to boil the syrup, brown sugar, cream and butter and constantly stir.", "Reduce heat and and gently cook 2 minutes or till sauce has reduced a little bit.", "Pour sauce gently over cake.", "Bake at 325°f (160°c) about 35 minutes or till cake is light brown and when toothpick inserted comes out clean."]'::jsonb, 'http://www.geniuskitchen.com/recipe/pouding-chomeur-poor-mans-pudding-with-maple-syrup-sauce-218797', 'https://www.themealdb.com/images/media/meals/yqqqwu1511816912.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pumpkin-pie', 'Pumpkin Pie', 4, 0, 0, '{"calories": 685, "protein": 12.5, "carbs": 139.4, "fat": 20.1, "saturated_fat": 8.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 181.3, "potassium": 34.4, "fiber": 8.3, "sugar": 58.6, "vitamin_a": null, "vitamin_c": 0.4, "calcium": 116.7, "iron": 3.7}'::jsonb, ARRAY['dessert', 'american', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 750.0, "unit": "g", "item": "Pumpkin", "notes": null, "category": "produce"}, {"quantity": 350.0, "unit": "g", "item": "Shortcrust Pastry", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Dusting Plain Flour", "notes": null, "category": "grains"}, {"quantity": 140.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 25.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 175.0, "unit": "g", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Icing Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["Place the pumpkin in a large saucepan, cover with water and bring to the boil. Cover with a lid and simmer for 15 mins or until tender. Drain pumpkin; let cool.", "Heat oven to 180C/160C fan/gas 4. Roll out the pastry on a lightly floured surface and use it to line a 22cm loose-bottomed tart tin. Chill for 15 mins. Line the pastry with baking parchment and baking beans, then bake for 15 mins. Remove the beans and paper, and cook for a further 10 mins until the base is pale golden and biscuity. Remove from the oven and allow to cool slightly.", "Increase oven to 220C/200C fan/gas 7. Push the cooled pumpkin through a sieve into a large bowl. In a separate bowl, combine the sugar, salt, nutmeg and half the cinnamon. Mix in the beaten eggs, melted butter and milk, then add to the pumpkin purée and stir to combine. Pour into the tart shell and cook for 10 mins, then reduce the temperature to 180C/160C fan/gas 4. Continue to bake for 35-40 mins until the filling has just set.", "Leave to cool, then remove the pie from the tin. Mix the remaining cinnamon with the icing sugar and dust over the pie. Serve chilled."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/1742633/pumpkin-pie', 'https://www.themealdb.com/images/media/meals/usuqtp1511385394.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('raspberry-mousse', 'Raspberry mousse', 4, 0, 0, '{"calories": 471, "protein": 1.6, "carbs": 33.2, "fat": 38.2, "saturated_fat": 25.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 51.0, "potassium": 420.7, "fiber": 5.6, "sugar": 23.1, "vitamin_a": null, "vitamin_c": 26.9, "calcium": 116.1, "iron": 0.8}'::jsonb, ARRAY['dessert', 'polish', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Leafs", "notes": null, "category": "other"}, {"quantity": 350.0, "unit": "g", "item": "Raspberries", "notes": null, "category": "other"}, {"quantity": 60.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "ml", "item": "Whipping Cream", "notes": null, "category": "dairy"}]'::jsonb, '["step 1", "Put the gelatine leaves in a bowl, cover with warm water and leave to soak for 5 mins. Drain and squeeze out any excess water.", "step 2", "Tip the raspberries into a pan over a medium-low heat along with the sugar and lemon juice. Cook for 5-6 mins until the berries have completely broken down. Push the mixture through a sieve set over a bowl, discarding the seeds. Stir in the gelatine leaves until dissolved (if they don’t dissolve, pour the mixture into a clean saucepan and heat gently until dissolved). Set aside to cool for 15 mins.", "step 3", "Whip the cream to soft peaks using an electric whisk, then gently fold this into the raspberry mixture. Spoon into the ramekins or moulds and chill overnight, or for at least 6 hrs. Serve with raspberries scattered over the top."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/raspberry-mousse', 'https://www.themealdb.com/images/media/meals/v5jrnn1764362830.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('rock-cakes', 'Rock Cakes', 4, 0, 0, '{"calories": 322, "protein": 9.1, "carbs": 62.8, "fat": 27.7, "saturated_fat": 16.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 360.6, "potassium": 36.0, "fiber": 1.0, "sugar": 13.7, "vitamin_a": null, "vitamin_c": 19.2, "calcium": 13.9, "iron": 0.4}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 225.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 75.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 125.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 150.0, "unit": "g", "item": "Dried Fruit", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbs", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}]'::jsonb, '["Preheat oven to 180C/350F/Gas 4 and line a baking tray with baking parchment.", "Mix the flour, sugar and baking powder in a bowl and rub in the cubed butter until the mixture looks like breadcrumbs, then mix in the dried fruit.", "In a clean bowl, beat the egg and milk together with the vanilla extract.", "Add the egg mixture to the dry ingredients and stir with a spoon until the mixture just comes together as a thick, lumpy dough. Add a teaspoon more milk if you really need it to make the mixture stick together.", "Place golfball-sized spoons of the mixture onto the prepared baking tray. Leave space between them as they will flatten and spread out to double their size during baking.", "Bake for 15-20 minutes, until golden-brown. Remove from the oven, allow to cool for a couple of minutes then turn them out onto a wire rack to cool."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/rock_cakes_03094', 'https://www.themealdb.com/images/media/meals/tqrrsq1511723764.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('rocky-road-fudge', 'Rocky Road Fudge', 4, 0, 0, '{"calories": 1477, "protein": 21.2, "carbs": 227.3, "fat": 67.3, "saturated_fat": 32.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 304.2, "potassium": 99.8, "fiber": 15.4, "sugar": 163.6, "vitamin_a": null, "vitamin_c": null, "calcium": 21.7, "iron": 5.9}'::jsonb, ARRAY['dessert', 'american', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "Miniature Marshmallows", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "cups", "item": "Chocolate Chips", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "Peanut Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "cups", "item": "Peanuts", "notes": null, "category": "pantry"}]'::jsonb, '["Line an 8-inch-square baking pan with wax paper or foil, and coat with non-stick spray.", "Pour ½ cup of the miniature marshmallows into the bottom of the lined baking dish.", "In a microwave-safe bowl, combine the chocolate chips and peanut butter. Microwave the chocolate mixture in 20-second intervals, stirring in between each interval, until the chocolate is melted.", "Add the vanilla extract and stir well, until smooth.", "Reserve 2 tablespoons of the chopped almonds or peanuts, and set aside.", "Fold 1 ½ cups of the miniature marshmallows and the remaining chopped nuts into the chocolate mixture.", "Transfer the chocolate mixture into the prepared pan and spread into an even layer. Immediately top with the reserved chopped nuts and the mallow bits or additional miniature marshmallows, if using.", "Refrigerate for 4 hours, or until set.", "Remove the fudge and wax paper from the pan. Carefully peel all of wax paper from the fudge.", "Cut the fudge into bite-sized pieces and serve."]'::jsonb, 'http://tiphero.com/rocky-road-fudge/', 'https://www.themealdb.com/images/media/meals/vtxyxv1483567157.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('rogaliki-polish-croissant-cookies', 'Rogaliki (Polish Croissant Cookies)', 4, 0, 0, '{"calories": 1113, "protein": 18.6, "carbs": 82.3, "fat": 76.7, "saturated_fat": 40.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 229.5, "potassium": 57.8, "fiber": null, "sugar": 15.8, "vitamin_a": null, "vitamin_c": null, "calcium": 107.8, "iron": 5.6}'::jsonb, ARRAY['dessert', 'polish', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 8.0, "unit": "oz", "item": "Cream Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "cups", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Jam", "notes": null, "category": "other"}]'::jsonb, '["In a medium bowl mix egg yolks, philly cheese and baking powder using a hand held mixer. Carefully start adding the flour. When the mixture will not be mixing well, and will look like wood chips, put away the blending mixer and using your hands knead the dough.", "Create a roll and cover in foil and freeze for 15 minutes. At this time preheat the oven to 375.", "Take the dough out and separate into two. Roll and cut out 3 inch trangles.", "Make as many as you can and on centre of each put a small spoon of jam. Roll them into a croissant shape.", "Place the croissants onto a greased cookie sheet, and bake for 10-12 minutes or until golden.", "Repeat with the rest of the dough.", "When you take them out, put aside and sprinkle with powdered sugar on top.", "This makes about 3 batches of 20 cookies each.", "Total count about 60 cookies."]'::jsonb, 'https://www.food.com/recipe/rogaliki-polish-croissant-cookies-with-jam-filling-200668', 'https://www.themealdb.com/images/media/meals/7mxnzz1593350801.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('salted-caramel-cheescake', 'Salted Caramel Cheescake', 4, 0, 0, '{"calories": 1503, "protein": 24.8, "carbs": 147.1, "fat": 127.7, "saturated_fat": 77.6, "polyunsaturated_fat": null, "monounsaturated_fat": 5.5, "sodium": 1254.3, "potassium": 247.6, "fiber": 6.3, "sugar": 57.8, "vitamin_a": null, "vitamin_c": null, "calcium": 198.1, "iron": 2.7}'::jsonb, ARRAY['dessert', 'american', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 250.0, "unit": "g", "item": "Digestive Biscuits", "notes": null, "category": "other"}, {"quantity": 75.0, "unit": "g", "item": "Pretzels", "notes": null, "category": "other"}, {"quantity": 135.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 450.0, "unit": "g", "item": "Cream Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Icing Sugar", "notes": null, "category": "pantry"}, {"quantity": 150.0, "unit": "g", "item": "Caramel", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Sea Salt", "notes": null, "category": "pantry"}, {"quantity": 300.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "drizzle Caramel Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Top Toffee Popcorn", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Top Pretzels", "notes": null, "category": "other"}]'::jsonb, '["1) Blitz the biscuits and the pretzels in a food processor and mix the biscuits with the melted butter. Spread on the bottom of an 8″/20cm Deep Springform Tin and press down firmly. Leave to set in the fridge whilst you make the rest!", "2) Using an electric mixer, I use my KitchenAid with the whisk attachment, whisk together the cream cheese, vanilla, and icing sugar until smooth and then add the caramel and whisk again until smooth and lump free – this could take a couple of minutes, I whisk it at half speed so not too quick or slow!", "3) Pour in the double cream & Salt flakes and continue to whisk for a couple of minutes until its very thick and mousse like (I mix it on a medium speed, level 6/10) – Now this could take up to 5 minutes depending on your mixer, but you seriously have to stick at it – it will hold itself completely when finished mixing (like a meringue does!) If you don’t mix it enough it will not set well enough, but don’t get impatient and whisk it really quick because that’ll make it split! Spread over the biscuit base and leave to set in the fridge overnight.", "4) Remove the Cheesecake from the tin carefully and decorate the cheesecake – I drizzled over some of the spare caramel, and then some Toffee Popcorn and more Pretzels!"]'::jsonb, 'http://www.janespatisserie.com/2015/11/09/no-bake-salted-caramel-cheesecake/', 'https://www.themealdb.com/images/media/meals/xqrwyr1511133646.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('saskatoon-pie', 'Saskatoon Pie', 4, 0, 0, '{"calories": 2061, "protein": 39.0, "carbs": 229.8, "fat": 118.2, "saturated_fat": 51.2, "polyunsaturated_fat": null, "monounsaturated_fat": 12.3, "sodium": 1163.9, "potassium": null, "fiber": 1.6, "sugar": 174.3, "vitamin_a": 364.9, "vitamin_c": null, "calcium": 64.0, "iron": null}'::jsonb, ARRAY['dessert', 'canadian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 6.0, "unit": "cups", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "cup", "item": "Vegetable Shortening", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Splash Water", "notes": null, "category": "other"}, {"quantity": 5.0, "unit": "cups", "item": "Saskatoon Berries", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Water", "notes": null, "category": "other"}]'::jsonb, '["To make the pastry, place the flour and salt in a large bowl. Mix well. Add the cubes of butter and shortening and mix them in (I like to use my hands to mix the fat into the flour, but you can use a pastry blender) just until it looks like coarse oatmeal with some pea-sized bits remaining. Place the egg in a 2-cup measure and beat it with a fork. Beat in the vinegar and just enough ice-cold water to bring it to the 1-cup mark. Stir this into the flour mixture, just until the dough clings together. I like to use my hands for this part as well, but a wooden spoon would also work. Try not to overmix it.", "On a lightly floured surface, gather the dough into a ball and divide it into 5 evenly sized portions. Shape each portion into a disc and wrap tightly in plastic. Chill 2 of these discs for 1 hour. Freeze the other 3 in a resealable freezer bag for future use. The pastry keeps well in the freezer for up to 2 months.", "Preheat the oven to 350°F. Place the rack in the lower third of the oven. Line a baking sheet with aluminum foil to catch drippings.", "On a lightly floured surface, roll out 1 disc of pastry into a 12-inch circle, or thereabouts. Place it in the bottom of a 9-inch pie plate, with the pastry overhanging the edges of the pie plate.", "To make the filling, place the saskatoon berries in a large bowl and stir in the 1/2 cup sugar and the cornstarch until well combined. Pour the berry mixture into the bottom of the pie. Dot with the butter. On a lightly floured surface, roll out the pastry in another 12-inch circle for the top crust. Use a ruler to guide you when cutting the pastry into 6 wide, long strips to keep the edges straight. Save the 2 end pieces in case you need to do any patching. I like wide strips, but if you like a thinner look, feel free to cut thin strips of pastry. Weave the pastry strips, going over and under, making sure they connect with the edges of the pie crust. Fold over the edges of the bottom crust, tucking in the lattice ends. This will help to trap the juices and give a rustic look.", "If you prefer a cleaner, tidier look, you can trim the overhanging pieces and crimp the edges with a fork. Brush the top of the pie with the egg wash. Sprinkle with the remaining Tbsp sugar. Place the pie on the prepared baking sheet and bake it for about 90 – 100 minutes, until it’s golden brown and bubbling. Remove the pie from the oven and place it on a wire rack to cool.", "Serve the pie warm or at room temperature with whipped cream or ice cream. Makes 6 servings. This keeps well if covered with plastic and refrigerated for up to 4 days."]'::jsonb, 'https://canadianfoodfocus.org/canadian-food-stories/classic-canadian-recipes-saskatoon-pie/#recipe', 'https://www.themealdb.com/images/media/meals/5xdrkw1764444472.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('seri-muka-kuih', 'Seri muka kuih', 4, 0, 0, '{"calories": 469, "protein": 8.6, "carbs": 67.1, "fat": 19.5, "saturated_fat": 12.6, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 526.2, "potassium": null, "fiber": 1.4, "sugar": 40.8, "vitamin_a": null, "vitamin_c": 2.5, "calcium": 39.2, "iron": 2.9}'::jsonb, ARRAY['dessert', 'malaysian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 400.0, "unit": "g", "item": "Rice", "notes": null, "category": "grains"}, {"quantity": 150.0, "unit": "ml", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "ml", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 5.0, "unit": "tbs", "item": "Corn Flour", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbs", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "ml", "item": "Coconut Cream", "notes": null, "category": "dairy"}, {"quantity": 140.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["Soak glutinous rice with water for at least 1 ½ hours prior to using. Drain.", "Prepare a 9-inch round or square cake pan and spray with cooking spray or line with plastic wrap.", "Mix coconut milk, water, salt and the rice. Pour it into cake pan, topped with the pandan knots.", "Steam for 30 minutes.", "After 30 minutes, fluff up the rice and remove pandan knots. Then, using a greased spatula, flatten the steamed rice. Make sure there are no holes/air bubbles and gaps in the rice, especially the sides.", "Steam for another 10 minutes.", "Combine pandan juice, coconut milk, all purpose flour, cornflour, and sugar. Mix well.", "Add eggs and whisk well then strain into a medium sized metal bowl or pot.", "Place pandan mixture over simmering water (double boiler or bain-marie)", "Stir continuously and cook till custard starts to thicken. (15 minutes)", "Pour pandan custard into glutinous rice layer, give it a little tap (for air bubbles) and continue to steam for 30 minutes.", "Remove kuih seri muka from the steamer and allow to cool completely before cutting into rectangles or diamond shapes."]'::jsonb, 'https://makan.ch/recipe/kuih-seri-muka/', 'https://www.themealdb.com/images/media/meals/6ut2og1619790195.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spanish-fig-almond-balls', 'Spanish fig & almond balls', 4, 0, 0, '{"calories": 779, "protein": 14.8, "carbs": 116.7, "fat": 156.5, "saturated_fat": 1.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 122.4, "potassium": 812.5, "fiber": 15.1, "sugar": 81.1, "vitamin_a": null, "vitamin_c": null, "calcium": 301.5, "iron": 1.9}'::jsonb, ARRAY['dessert', 'spanish', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 100.0, "unit": "g", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 500.0, "unit": "g", "item": "Figs", "notes": null, "category": "pantry"}, {"quantity": 85.0, "unit": "g", "item": "Dried Apricots", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Dried cranberries", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Brandy", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Clear Honey", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Cloves", "notes": null, "category": "spices"}, {"quantity": 100.0, "unit": "g", "item": "Sesame Seed", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Whizz the almonds in a food processor until most are finely chopped, then tip into a large bowl. Roughly chop the figs, then whizz to a smooth sticky paste. Scrape onto the almonds then, using your hands, mix together well with the dried fruit, brandy, honey and cloves.", "step 2", "Divide the mixture into 6 and roll into balls. Tip the sesame seeds onto a tray, then roll the balls in them until covered. Cover the tray loosely with a clean tea towel, then leave the fig balls to dry for a week before packaging. Will keep in a cool place for 2 months."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/spanish-fig-almond-balls', 'https://www.themealdb.com/images/media/meals/si2rty1763282314.jpg', FALSE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spotted-dick', 'Spotted Dick', 4, 0, 0, '{"calories": 720, "protein": 13.6, "carbs": 128.0, "fat": 41.8, "saturated_fat": 23.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 478.6, "potassium": 125.2, "fiber": 5.4, "sugar": 61.7, "vitamin_a": null, "vitamin_c": 2.0, "calcium": 106.6, "iron": 2.6}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 250.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 125.0, "unit": "g", "item": "Suet", "notes": null, "category": "other"}, {"quantity": 175.0, "unit": "g", "item": "Currants", "notes": null, "category": "other"}, {"quantity": 80.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Orange", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Custard", "notes": null, "category": "other"}]'::jsonb, '["Put the flour and salt in a bowl. Add the suet, currants, sugar, lemon and orange zest.", "Pour in 150ml milk and mix to a firm but moist dough, adding the extra milk if necessary.", "Shape into a fat roll about 20cm long. Place on a large rectangle of baking parchment. Wrap loosely to allow for the pudding to rise and tie the ends with string like a Christmas cracker.", "Place a steamer over a large pan of boiling water, add the pudding to the steamer, cover and steam for 1 1/2 hours. Top up the pan with water from time to time.", "Remove from the steamer and allow to cool slightly before unwrapping. Serve sliced with custard."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/2686661/spotted-dick', 'https://www.themealdb.com/images/media/meals/xqvyqr1511638875.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sticky-toffee-pudding', 'Sticky Toffee Pudding', 4, 0, 0, '{"calories": 726, "protein": 13.3, "carbs": 121.6, "fat": 70.7, "saturated_fat": 42.3, "polyunsaturated_fat": null, "monounsaturated_fat": 5.5, "sodium": 577.2, "potassium": 138.7, "fiber": 1.5, "sugar": 3.6, "vitamin_a": 6.0, "vitamin_c": 0.7, "calcium": 155.0, "iron": 0.6}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 100.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 175.0, "unit": "g", "item": "Muscovado Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 225.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Bicarbonate Of Soda", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tbs", "item": "Black Treacle", "notes": null, "category": "other"}, {"quantity": 275.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Double Cream", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 125.0, "unit": "g", "item": "Muscovado Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Black Treacle", "notes": null, "category": "other"}, {"quantity": 300.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}]'::jsonb, '["Preheat the oven to 180C/160C Fan/Gas 4. Butter a wide shallow 1.7-litre/3-pint ovenproof dish.", "Put the butter, sugar, eggs, flour, baking powder, bicarbonate of soda and treacle into a mixing bowl. Beat using an electric handheld whisk for about 30 seconds or until combined. Pour in the milk gradually and whisk again until smooth. Pour into the prepared dish. Bake for 35–40 minutes or until well risen and springy in the centre.", "To make the sauce, put all the ingredients into a saucepan and stir over a low heat until the sugar has dissolved and the butter has melted. Bring to the boil, stirring for a minute.", "To serve, pour half the sauce over the pudding in the baking dish. Serve with the cream or ice cream."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/marys_sticky_toffee_41970', 'https://www.themealdb.com/images/media/meals/xqqqtu1511637379.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sticky-toffee-pudding-ultimate', 'Sticky Toffee Pudding Ultimate', 4, 0, 0, '{"calories": 808, "protein": 13.2, "carbs": 162.8, "fat": 53.3, "saturated_fat": 31.3, "polyunsaturated_fat": null, "monounsaturated_fat": 4.9, "sodium": 332.2, "potassium": 517.9, "fiber": 3.7, "sugar": 79.7, "vitamin_a": 58.9, "vitamin_c": 7.6, "calcium": 198.7, "iron": 1.3}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 225.0, "unit": "g", "item": "Medjool dates", "notes": null, "category": "pantry"}, {"quantity": 175.0, "unit": "ml", "item": "Boiling water", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "vanilla extract", "notes": null, "category": "pantry"}, {"quantity": 175.0, "unit": "g", "item": "self-raising flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "bicarbonate of soda", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "eggs", "notes": null, "category": "dairy"}, {"quantity": 85.0, "unit": "g", "item": "butter", "notes": null, "category": "dairy"}, {"quantity": 140.0, "unit": "g", "item": "demerara sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbsp", "item": "black treacle", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "ml", "item": "milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "ice cream", "notes": null, "category": "dairy"}, {"quantity": 175.0, "unit": "g", "item": "muscovado sugar", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "butter", "notes": null, "category": "dairy"}, {"quantity": 225.0, "unit": "ml", "item": "double cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbsp", "item": "black treacle", "notes": null, "category": "other"}]'::jsonb, '["Stone and chop the dates quite small, put them in a bowl, then pour the boiling water over. Leave for about 30 mins until cool and well-soaked, then mash a bit with a fork. Stir in the vanilla extract. Butter and flour seven mini pudding tins (each about 200ml/7fl oz) and sit them on a baking sheet. Heat oven to 180C/fan 160C/gas 4.", "While the dates are soaking, make the puddings. Mix the flour and bicarbonate of soda together and beat the eggs in a separate bowl. Beat the butter and sugar together in a large bowl for a few mins until slightly creamy (the mixture will be grainy from the sugar). Add the eggs a little at a time, beating well between additions. Beat in the black treacle then, using a large metal spoon, gently fold in one-third of the flour, then half the milk, being careful not to overbeat. Repeat until all the flour and milk is used. Stir the soaked dates into the pudding batter. The mix may look a little curdled at this point and will be like a soft, thick batter. Spoon it evenly between the tins and bake for 20-25 mins, until risen and firm.", "Meanwhile, put the sugar and butter for the sauce in a medium saucepan with half the cream. Bring to the boil over a medium heat, stirring all the time, until the sugar has completely dissolved. Stir in the black treacle, turn up the heat slightly and let the mixture bubble away for 2-3 mins until it is a rich toffee colour, stirring occasionally to make sure it doesn’t burn. Take the pan off the heat and beat in the rest of the cream.", "Remove the puddings from the oven. Leave in the tins for a few mins, then loosen them well from the sides of the tins with a small palette knife before turning them out. You can serve them now with the sauce drizzled over, but they’ll be even stickier if left for a day or two coated in the sauce. To do this, pour about half the sauce into one or two ovenproof serving dishes. Sit the upturned puddings on the sauce, then pour the rest of the sauce over them. Cover with a loose tent of foil so that the sauce doesn’t smudge (no need to chill).", "When ready to serve, heat oven to 180C/fan 160C/gas 4. Warm the puddings through, still covered, for 15-20 mins or until the sauce is bubbling. Serve them on their own, or with cream or custard."]'::jsonb, 'https://www.youtube.com/watch?v=Wytv3bjqJII', 'https://www.themealdb.com/images/media/meals/xrptpq1483909204.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('strawberries-romanoff', 'Strawberries Romanoff', 4, 0, 0, '{"calories": 30, "protein": 1.7, "carbs": 3.2, "fat": 23.5, "saturated_fat": 13.8, "polyunsaturated_fat": null, "monounsaturated_fat": 4.3, "sodium": 36.9, "potassium": 84.4, "fiber": null, "sugar": 0.5, "vitamin_a": 17.7, "vitamin_c": null, "calcium": 55.9, "iron": null}'::jsonb, ARRAY['dessert', 'russian', 'themealdb', 'nutrition-generated', 'vegetarian'], '[{"quantity": 2.0, "unit": "pint", "item": "Strawberries", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "tbs", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "tbs", "item": "Grand Marnier", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "cup", "item": "Cream", "notes": null, "category": "dairy"}, {"quantity": 0.25, "unit": "cup", "item": "Sour Cream", "notes": null, "category": "dairy"}]'::jsonb, '["In a medium bowl, combine hulled and quartered strawberries, 4 Tbsp sugar and 4 Tbsp liqueur, stir to combine then cover and refrigerate at least 1 hour and up to 2 hours, stirring once or twice.", "Two photos of cut strawberries in a bowl with one having sugar being added to the bowl Two photos of cut up strawberries for Strawberry Romanoff", "Just before serving, in a large mixing bowl, combine 1 cup cold heavy cream and 1/4 cup powdered sugar, and beat with an electric mixer until stiff peaks form. Using a spatula, fold in 1/4 cup sour cream just until well blended.", "To serve, stir strawberries then divide between 6 serving glasses or bowls. You can spoon a little syrup over the berries if you like. You can also use this syrup to soak a cake. Spoon cream over strawberries, dividing evenly. You can also use an ice cream scoop with trigger release for a nice rounded puff of cream. Serve right away or chill and enjoy within 2 hours of assembly."]'::jsonb, 'https://natashaskitchen.com/strawberries-romanoff-recipe/', 'https://www.themealdb.com/images/media/meals/oe8rg51699014028.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('strawberry-rhubarb-pie', 'Strawberry Rhubarb Pie', 4, 0, 0, '{"calories": 1240, "protein": 6.6, "carbs": 204.8, "fat": 44.7, "saturated_fat": 28.4, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2.6, "potassium": 169.2, "fiber": 2.4, "sugar": 107.4, "vitamin_a": null, "vitamin_c": 46.6, "calcium": 128.5, "iron": 4.0}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 350.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 450.0, "unit": "g", "item": "Rhubarb", "notes": null, "category": "other"}, {"quantity": 450.0, "unit": "g", "item": "Strawberries", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tbs", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Spinkling Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["Pie Crust:  In a food processor, place the flour, salt, and sugar and process until combined. Add the butter and process until the mixture resembles coarse", "meal (about 15 seconds). Pour 1/4 cup (60 ml) water in a slow, steady stream, through the feed tube until the dough just holds together when pinched. If necessary, add more water. Do not process more than 30 seconds.", "Turn the dough onto your work surface and gather into a ball. Divide the dough in half, flattening each half into a disk, cover with plastic wrap, and refrigerate for about one hour before using. This will chill the butter and relax the gluten in the flour.", "After the dough has chilled sufficiently, remove one portion of the dough from the fridge and place it on a lightly floured surface.  Roll the pastry into a 12 inch (30 cm) circle. (To prevent the pastry from sticking to the counter and to ensure uniform thickness, keep lifting up and turning the pastry a quarter turn as you roll (always roll from the center of the pastry outwards).)  Fold the dough in half and gently transfer to a 9 inch (23 cm) pie pan. Brush off any excess flour and trim any overhanging pastry to an edge of 1/2 inch (1.5 cm). Refrigerate the pastry, covered with plastic wrap, while you make the filling.", "Remove the second round of pastry and roll it into a 13 inch (30 cm) circle. Using a pastry wheel or pizza cutter, cut the pastry into about 3/4 inch (2 cm) strips. Place the strips of pastry on a parchment paper-lined baking sheet, cover with plastic wrap, and place in the refrigerator for about 10 minutes.", "Make the Strawberry Rhubarb Filling: Place the cut strawberries and rhubarb in a large bowl. In a small bowl mix together the cornstarch, sugar, and ground cinnamon.", "Remove the chilled pie crust from the fridge. Sprinkle about 2 tablespoons of the sugar mixture over the bottom of the pastry crust. Add the remaining sugar mixture to the strawberries and rhubarb and gently toss to combine. Pour the fruit mixture into the prepared pie shell. Sprinkle the fruit with about 1 teaspoon of lemon juice and dot with 2 tablespoons of butter.", "Remove the lattice pastry from the refrigerator and, starting at the center with the longest strips and working outwards, place half the strips, spacing about 1 inch (2.5 cm) apart, on top of the filling. (Use the shortest pastry strips at the outer edges.) Then, gently fold back, about halfway, every other strip of pastry. Take another strip of pastry and place it perpendicular on top of the first strips of pastry. Unfold the bottom strips of pastry and then fold back the strips that weren''t folded back the first time. Lay another strip of pastry perpendicular on top of the filling and then continue with the remaining strips. Trim the edges of the pastry strips, leaving a 1 inch (2.5 cm) overhang. Seal the edges of the pastry strips by folding them under the bottom pastry crust and flute the edges of the pastry. Brush the lattice pastry with milk and sprinkle with a little sugar. Cover and place in the refrigerator while you preheat the oven to 400 degrees F (205 degrees C) and place the oven rack in the lower third of the oven. Put a baking sheet, lined with aluminum foil, on the oven rack (to catch any spills.)", "Place the pie plate on the hot baking sheet and bake the pie for about 35 minutes and then, if the edges of the pie are browning too much, cover with a foil ring. Continue to bake the pie for about another 10 minutes or until the crust is a golden brown color and the fruit juices begin to bubble.", "Remove the pie from the oven and place on a wire rack to cool for several hours. Serve at room temperature with softly whipped cream or vanilla ice cream. Leftovers can be stored in the refrigerator for about 3 days. Reheat before serving. This pie can be frozen.", "Makes one 9 inch (23 cm) pie."]'::jsonb, 'https://www.joyofbaking.com/StrawberryRhubarbPie.html', 'https://www.themealdb.com/images/media/meals/178z5o1585514569.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sugar-pie', 'Sugar Pie', 4, 0, 0, '{"calories": 561, "protein": 8.2, "carbs": 115.8, "fat": 15.6, "saturated_fat": 9.1, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 84.3, "potassium": 20.3, "fiber": 0.4, "sugar": 104.6, "vitamin_a": null, "vitamin_c": 0.9, "calcium": 130.3, "iron": 0.6}'::jsonb, ARRAY['dessert', 'canadian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "cup", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.5, "unit": "cups", "item": "Milk", "notes": null, "category": "dairy"}]'::jsonb, '["Preheat oven to 350 degrees F (175 degrees C). Grease a 9-inch pie dish.", "Place the brown sugar and butter in a mixing bowl, and beat them together with an electric mixer until creamy and very well combined, without lumps. Beat in eggs, one at a time, incorporating the first egg before adding the next one. Add the vanilla extract and salt; beat the flour in, a little at a time, and then the milk, making a creamy batter. Pour the batter into the prepared pie dish.", "Bake in the preheated oven for 35 minutes; remove pie, and cover the rim with aluminum foil to prevent burning. Return to oven, and bake until the middle sets and the top forms a crusty layer, about 15 more minutes. Let the pie cool to room temperature, then refrigerate for at least 1 hour before serving."]'::jsonb, 'http://allrecipes.com/recipe/213595/miraculous-canadian-sugar-pie/', 'https://www.themealdb.com/images/media/meals/yrstur1511816601.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('suksessterte-norwegian-almond-success-cake', 'Suksessterte (Norwegian almond “success cake”)', 4, 0, 0, '{"calories": 1698, "protein": 39.4, "carbs": 127.1, "fat": 117.6, "saturated_fat": 28.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 525.1, "potassium": 57.8, "fiber": 12.6, "sugar": 96.7, "vitamin_a": null, "vitamin_c": null, "calcium": 493.4, "iron": 7.5}'::jsonb, ARRAY['dessert', 'norwegian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.25, "unit": "cup", "item": "Granulated Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "cup", "item": "Heavy Cream", "notes": null, "category": "dairy"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Granulated Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}]'::jsonb, '["Almond base", "▢", "Preheat oven to 345°F (175°C) and grease cake form (I use a 27 cm spring form) – you can line the bottom with baking paper if you like.", "▢", "Grind almonds in an almond grinder or food processor. I like to keep them a bit coarse.", "▢", "Gently whisk the eggs and sugar together until combined (no longer). Stir in the ground almonds, flour, and baking powder.", "▢", "Pour batter into cake form and bake for about 45 – 50 minutes, monitoring to make sure the top doesn''t burn.", "Yellow egg cream", "▢", "Add egg yolks, heavy cream, sugar, and vanilla to a saucepan. Heat over low/medium heat while stirring constantly until the mixture thickens – about 15 minutes. Turn up the heat if the mixture doesn''t thicken, but be careful not to boil.", "▢", "Let the mixture cool to room temperature and then add the butter. You can use an electric mixer for a fluffy egg cream.", "Assembly", "▢", "Wait for the cake to cool completely before removing from form and frosting."]'::jsonb, 'https://scandinaviancookbook.com/suksessterte-success-cake/', 'https://www.themealdb.com/images/media/meals/de83k51763075604.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('šúĺlance-s-makom', 'Šúĺlance s Makom', 4, 0, 0, '{"calories": 984, "protein": 15.3, "carbs": 157.8, "fat": 31.5, "saturated_fat": 18.4, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 389.1, "potassium": 870.5, "fiber": 5.3, "sugar": 16.4, "vitamin_a": null, "vitamin_c": 31.8, "calcium": 68.4, "iron": 4.9}'::jsonb, ARRAY['dessert', 'slovakian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 700.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 100.0, "unit": "g", "item": "Semolina", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 150.0, "unit": "g", "item": "Ground Poppy seeds", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Powdered Sugar", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}]'::jsonb, '["1. Prepare the Potatoes", "Boil the potatoes with their skins on until tender.", "Let them cool completely (preferably overnight), then peel and mash them finely.", "2. Make the Dough", "In a bowl, combine mashed potatoes, flour, semolina, and salt.", "Knead the mixture until you get a smooth, non-sticky dough.", "3. Shape the Šúĺlance", "Divide the dough into portions and roll each into a thin rope (about 1.5 cm in diameter).", "Cut into 3 cm-long pieces and roll between your palms to shape small dumplings.", "4. Cook the Dumplings", "Bring a pot of salted water to a boil.", "Drop in the dumplings in batches and cook until they float to the surface (about 2-3 minutes).", "Drain and transfer to a bowl.", "5. Prepare the Topping", "In a separate bowl, mix ground poppy seeds and powdered sugar.", "Melt the butter and keep it ready.", "6. Assemble the Dish", "Drizzle the cooked dumplings with melted butter.", "Toss them in the poppy seed-sugar mixture until evenly coated.", "7. Serve and Enjoy", "Serve warm, optionally with a dusting of extra powdered sugar or a drizzle of honey."]'::jsonb, 'https://www.slovakia-foods.co.uk/blog/post/sullance-s-makom-recipe-how-to-make-authentic-slovak-sweet-poppy-seed-rolls.html', 'https://www.themealdb.com/images/media/meals/d6o4nu1763362422.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('summer-pudding', 'Summer Pudding', 4, 0, 0, '{"calories": 330, "protein": 3.2, "carbs": 82.9, "fat": 1.1, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": 401.2, "fiber": 12.7, "sugar": 59.5, "vitamin_a": null, "vitamin_c": 64.0, "calcium": 54.9, "iron": 1.9}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'vegetarian', 'vegan'], '[{"quantity": 300.0, "unit": "g", "item": "Strawberries", "notes": null, "category": "other"}, {"quantity": 250.0, "unit": "g", "item": "Blackberries", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Redcurrants", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "g", "item": "Raspberries", "notes": null, "category": "other"}, {"quantity": 175.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 7.0, "unit": "slices", "item": "Bread", "notes": null, "category": "grains"}]'::jsonb, '["Bring out the juices: Wash fruit and gently dry on kitchen paper – keep strawberries separate. Put sugar and 3 tbsp water into a large pan. Gently heat until sugar dissolves – stir a few times. Bring to a boil for 1 min, then tip in the fruit (not strawberries). Cook for 3 mins over a low heat, stirring 2-3 times. The fruit will be softened, mostly intact and surrounded by dark red juice. Put a sieve over a bowl and tip in the fruit and juice.", "Line the bowl with cling film and prepare the bread: Line the 1.25-litre basin with cling film as this will help you to turn out the pudding. Overlap two pieces of cling film in the middle of the bowl as it’s easier than trying to get one sheet to stick to all of the curves. Let the edges overhang by about 15cm. Cut the crusts off the bread. Cut 4 pieces of bread in half, a little on an angle, to give 2 lopsided rectangles per piece. Cut 2 slices into 4 triangles each and leave the final piece whole.", "Build the pud: Dip the whole piece of bread into the juice for a few secs just to coat. Push this into the bottom of the basin. Now dip the wonky rectangular pieces one at a time and press around the basin’s sides so that they fit together neatly, alternately placing wide and narrow ends up. If you can’t quite fit the last piece of bread in it doesn’t matter, just trim into a triangle, dip in juice and slot in. Now spoon in the softened fruit, adding the strawberries here and there as you go.", "Let flavours mingle then serve: Dip the bread triangles in juice and place on top – trim off overhang with scissors. Keep leftover juice for later. Bring cling film up and loosely seal. Put a side plate on top and weight down with cans. Chill for 6 hrs or overnight. To serve, open out cling film then put a serving plate upside-down on top and flip over. serve with leftover juice, any extra berries and cream."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/4516/summer-pudding', 'https://www.themealdb.com/images/media/meals/rsqwus1511640214.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tall-skoleboller', 'Tall Skoleboller', 4, 0, 0, '{"calories": 1469, "protein": 17.6, "carbs": 203.1, "fat": 63.6, "saturated_fat": 40.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 736.2, "potassium": 0.7, "fiber": 11.5, "sugar": 62.3, "vitamin_a": null, "vitamin_c": 1.4, "calcium": 254.6, "iron": 7.5}'::jsonb, ARRAY['dessert', 'norwegian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tsp", "item": "Instant Yeast", "notes": null, "category": "pantry"}, {"quantity": 0.333, "unit": "cups", "item": "1-⅓ cups Granulated Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Cardamom", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 2.25, "unit": "cups", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.25, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 0.333, "unit": "cups", "item": "1-⅓ cups Granulated Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "pod", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "cups", "item": "Powdered Sugar", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "cup", "item": "Shredded Coconut", "notes": null, "category": "pantry"}]'::jsonb, '["▢", "Heat the milk until it''s lukewarm. Add the yeast and dissolve.", "▢", "Add the sugar, cardamom, vanilla, and about 2/3 of the flour.", "▢", "Mix the dough together either by hand or in a mixer with a dough hook, slowly adding the rest of the flour. You might need a bit more or less flour to form dough that isn''t too sticky to knead. When the dough forms a nice ball, add the softened butter and continue to knead the dough for about ten minutes.", "▢", "Roll the dough into a cylinder and cut into six equal parts. Roll each piece into a round bun and set them in a greased muffin/cake tin. Cover and let rise until doubled in size (about an hour)."]'::jsonb, 'https://scandinaviancookbook.com/skoleboller-school-buns-from-lille-betong/', 'https://www.themealdb.com/images/media/meals/xihiu41762773169.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tarte-tatin', 'Tarte Tatin', 4, 0, 0, '{"calories": 709, "protein": 7.3, "carbs": 87.2, "fat": 46.4, "saturated_fat": 28.1, "polyunsaturated_fat": null, "monounsaturated_fat": 6.0, "sodium": 252.0, "potassium": 154.4, "fiber": 2.2, "sugar": 38.3, "vitamin_a": null, "vitamin_c": 0.8, "calcium": 57.2, "iron": 1.8}'::jsonb, ARRAY['dessert', 'french', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 300.0, "unit": "g", "item": "Puff Pastry", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Dusting Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Apples", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 85.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Creme Fraiche", "notes": null, "category": "other"}]'::jsonb, '["Roll the pastry to a 3mm-thick round on a lightly floured surface and cut a 24cm circle, using a plate as a guide. Lightly prick all over with a fork, wrap in cling film on a baking sheet and freeze while preparing the apples.", "Heat oven to 180C/160C fan/gas 4. Peel, quarter and core the apples. Put the sugar in a flameproof 20cm ceramic Tatin dish or a 20cm ovenproof heavy-based frying pan and place over a medium-high heat. Cook the sugar for 5-7 mins to a dark amber caramel syrup that’s starting to smoke, then turn off the heat and stir in the 60g diced chilled butter.", "To assemble the Tarte Tatin, arrange the apple quarters very tightly in a circle around the edge of the dish first, rounded-side down, then fill in the middle in a similar fashion. Gently press with your hands to ensure there are no gaps. Brush the fruit with the melted butter.", "Bake in the oven for 30 mins, then remove and place the disc of frozen puff pastry on top – it will quickly defrost. Tuck the edges down the inside of the dish and, with a knife, prick a few holes in the pastry to allow steam to escape. Bake for a further 40-45 mins until the pastry is golden brown and crisp.", "Allow to cool to room temperature for 1 hr before running a knife around the edge of the dish and inverting it onto a large serving plate that is deep enough to contain the juices. Serve with crème fraîche or vanilla ice cream."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/tarte-tatin', 'https://www.themealdb.com/images/media/meals/ryspuw1511786688.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('timbits', 'Timbits', 4, 0, 0, '{"calories": 726, "protein": 7.2, "carbs": 100.3, "fat": 33.3, "saturated_fat": 8.2, "polyunsaturated_fat": null, "monounsaturated_fat": 7.1, "sodium": 69.4, "potassium": 0.5, "fiber": 0.8, "sugar": 32.6, "vitamin_a": null, "vitamin_c": 0.5, "calcium": 90.4, "iron": 2.2}'::jsonb, ARRAY['dessert', 'canadian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 0.75, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tbs", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "for frying Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "garnish Icing Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["Sift together dry ingredients.", "Mix together wet ingredients and incorporate into dry. Stir until smooth.", "Drop by teaspoonfuls(no bigger) into hot oil (365 degrees, no hotter), turning after a few moments until golden brown on all sides.", "Remove and drain.", "Roll in cinnamon sugar while still warm and serve."]'::jsonb, 'http://www.geniuskitchen.com/recipe/drop-doughnuts-133877', 'https://www.themealdb.com/images/media/meals/txsupu1511815755.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('treacle-tart', 'Treacle Tart', 4, 0, 0, '{"calories": 642, "protein": 10.5, "carbs": 136.5, "fat": 29.7, "saturated_fat": 17.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 34.0, "potassium": 84.7, "fiber": 1.7, "sugar": 80.0, "vitamin_a": null, "vitamin_c": null, "calcium": 89.9, "iron": 1.0}'::jsonb, ARRAY['dessert', 'british', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 250.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 135.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 400.0, "unit": "g", "item": "Golden Syrup", "notes": null, "category": "pantry"}, {"quantity": 150.0, "unit": "g", "item": "Breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 2 Lemons", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}]'::jsonb, '["First make the short crust pastry: measure the flour into a large bowl and rub in the butter with your fingertips until the mixture resembles fine breadcrumbs (alternatively, this can be done in a food processor). Add about three tablespoons of cold water and mix to a firm dough, wrap in cling film and chill in the fridge for about 20 minutes.", "Preheat the oven to 200C/400F/Gas 6 and put a heavy baking tray in the oven to heat up. Grease a deep 18cm/7in loose-bottomed fluted flan tin with butter.", "Remove about 150g/5½oz of pastry from the main ball and set aside for the lattice top.", "Roll the rest of the pastry out thinly on a lightly floured work surface and line the prepared flan tin with the pastry.", "Prick the base with a fork, to stop the base rising up during baking.", "Place the reserved pastry for the lattice top on cling film and roll out thinly. Egg wash the pastry and set aside to chill in the fridge (the cling film makes it easier to move about). Do not cut into strips at this stage. Do not egg wash the strips once they are on the tart as it will drip into the treacle mixture.", "To make the filling, heat the syrup gently in a large pan but do not boil.", "Once melted, add the breadcrumbs, lemon juice and zest to the syrup. (You can add less lemon if you would prefer less citrus taste.) If the mixture looks runny, add a few more breadcrumbs.", "Pour the syrup mixture into the lined tin and level the surface.", "Remove the reserved pastry from the fridge and cut into long strips, 1cm/½in wide. Make sure they are all longer than the edges of the tart tin.", "Egg wash the edge of the pastry in the tin, and start to make the woven laying lattice pattern over the mixture, leave the strips hanging over the edge of the tin.", "Once the lattice is in place, use the tin edge to cut off the strips by pressing down with your hands, creating a neat finish.", "Bake on the pre-heated baking tray in the hot oven for about 10 minutes until the pastry has started to colour, and then reduce the oven temperature to 180C/350F/Gas 4. If at this stage the lattice seems to be getting too dark brown, cover the tart with tin foil.", "Bake for a further 25-30 minutes until the pastry is golden-brown and the filling set.", "Remove the tart from the oven and leave to firm up in the tin. Serve warm or cold."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/mary_berrys_treacle_tart_28524', 'https://www.themealdb.com/images/media/meals/wprvrw1511641295.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tunisian-orange-cake', 'Tunisian Orange Cake', 4, 0, 0, '{"calories": 772, "protein": 9.3, "carbs": 141.1, "fat": 18.4, "saturated_fat": 3.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 130.1, "potassium": null, "fiber": null, "sugar": 77.4, "vitamin_a": null, "vitamin_c": null, "calcium": 11.2, "iron": 2.9}'::jsonb, ARRAY['dessert', 'tunisian', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Orange", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 75.0, "unit": "ml", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 280.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tbs", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}]'::jsonb, '["Preheat oven to 190 C / Gas 5. Grease a 23cm round springform tin.", "Cut off the hard bits from the top and bottom of the orange. Slice the orange and remove all seeds. Puree the orange with its peel in a food processor. Add one third of the sugar and the olive oil and continue to mix until well combined.", "Sieve together flour and baking powder.", "Beat the eggs and the remaining sugar with an electric hand mixer for at least five minutes until very fluffy. Fold in half of the flour mixture, then the orange and the vanilla, then fold in the remaining flour. Mix well but not for too long.", "Pour cake mixture into prepared tin and smooth out. Bake in preheated oven for 20 minutes. Reduce the oven temperature to 160 C / Gas 2 and bake again for 30 minutes Bake until the cake is golden brown and a skewer comes out clean. Cool on a wire cake rack."]'::jsonb, 'http://allrecipes.co.uk/recipe/16067/tunisian-orange-cake.aspx', 'https://www.themealdb.com/images/media/meals/y4jpgq1560459207.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vanilla-alfajores', 'Vanilla alfajores', 4, 0, 0, '{"calories": 118, "protein": 2.0, "carbs": 19.7, "fat": 3.0, "saturated_fat": 2.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 64.1, "potassium": null, "fiber": null, "sugar": 19.7, "vitamin_a": null, "vitamin_c": null, "calcium": 79.1, "iron": null}'::jsonb, ARRAY['dessert', 'uruguayan', 'themealdb', 'nutrition-generated', 'baking', 'vegetarian'], '[{"quantity": 150.0, "unit": "g", "item": "Dulce de leche", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Coconut Flakes", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 150.0, "unit": "g", "item": "Dulce de leche", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Coconut Flakes", "notes": null, "category": "pantry"}]'::jsonb, '["For the sandwich cookie cream the soft butter for about a minute, then add the sugar and cream for another two minutes. Incorporate the egg fully before mixing in the egg yolk. Once everything is nicely combined, add all remaining ingredients and mix one more time. Form dough into a ball and wrap in plastic wrap. Chill for at least half an hour or overnight.", "2", "Preheat oven to 180 degrees Celsius and line two baking sheets with parchment paper.", "3", "Divide dough in half, put one back in the fridge and roll out the other thickly on a lightly floured surface. Cut out cookies with either the bottom of a glass or a cookie cutter around 6cm in diameter. Repeat with all the dough.", "4", "Bake for about 8-10min, the cookies will look very pale. Let cool off before filling half with each a teaspoon of dulce de leche. Place other half of cookies on top and roll the sides of each cookie in the coconut flakes (it helps if the dulce de leche was pressed down to the sides of the cookie). Enjoy."]'::jsonb, 'https://jennyisbaking.com/2019/05/17/classic-alfajores-from-uruguay/#recipe', 'https://www.themealdb.com/images/media/meals/3wnyvh1764373818.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('walnut-roll-gužvara', 'Walnut Roll Gužvara', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['dessert', 'croatian', 'themealdb', 'baking', 'vegetarian'], '[{"quantity": 450.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 55.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Yeast", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 6.0, "unit": "oz", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 30.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 140.0, "unit": "g", "item": "Walnuts", "notes": null, "category": "pantry"}, {"quantity": 85.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 85.0, "unit": "g", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "To Glaze Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "To Glaze Icing Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["Mix all the ingredients for the dough together and knead well. Cover the dough and put to rise until doubled in size which should take about 2 hours. Knock back the dough and knead lightly.", "Divide the dough into two equal pieces; roll each piece into an oblong about 12 inches by 8 inches. Mix the filling ingredients together and divide between the dough, spreading over each piece. Roll up the oblongs as tightly as possible to give two 12 inch sausages. Place these side by side, touching each other, on a greased baking sheet. Cover and leave to rise for about 40 minutes. Heat oven to 200ºC (425ºF). Bake for 30-35 minutes until well risen and golden brown. Bread should sound hollow when the base is tapped.", "Remove from oven and brush the hot bread top with milk. Sift with a generous covering of icing sugar."]'::jsonb, 'https://www.visit-croatia.co.uk/croatian-cuisine/croatian-recipes/', 'https://www.themealdb.com/images/media/meals/u9l7k81628771647.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('walnut-date-honey-cake', 'Walnut, date & honey cake', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['dessert', 'turkish', 'themealdb', 'baking', 'vegetarian'], '[{"quantity": 225.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Ground Cinnamon", "notes": null, "category": "spices"}, {"quantity": 175.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Muscovado Sugar", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Clear Honey", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Banana", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Stoned Dates", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "Walnuts", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Preheat the oven to 160C/Gas 3/fan oven 140C. Line the base and long sides of a 900g/2lb loaf tin with greaseproof paper, buttering the tin and paper.", "step 2", "Tip the flour, cinnamon, butter, sugar, 2 tablespoons of the honey and the eggs into a large mixing bowl. Mash the bananas and chop the dates (kitchen scissors are easiest for this) and add to the bowl. Beat the mixture for 2-3 minutes, using a wooden spoon or hand-held mixer, until well blended.", "step 3", "Spoon into the prepared tin and level the top. Scatter the walnut pieces over. Bake for 1 hour, then lightly press the top – it will feel firm if cooked. If not, bake for a further 10 minutes.", "step 4", "Cool for 15 minutes, then lift out of the tin using the paper. When cold, drizzle the remaining honey over. Cut into thick slices."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/walnut-date-honey-cake', 'https://www.themealdb.com/images/media/meals/towo9c1763814590.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('white-chocolate-creme-brulee', 'White chocolate creme brulee', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['dessert', 'french', 'themealdb', 'baking', 'grilling', 'vegetarian'], '[{"quantity": 568.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "White Chocolate Chips", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pod of Vanilla", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Top Caster Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["Heat the cream, chocolate and vanilla pod in a pan until the chocolate has melted. Take off the heat and allow to infuse for 10 mins, scraping the pod seeds into the cream. If using the vanilla extract, add straight away. Heat oven to 160C/fan 140C/gas 3.", "Beat yolks and sugar until pale. stir in the chocolate cream. Strain into a jug and pour into ramekins. Place in a deep roasting tray and pour boiling water halfway up the sides. Bake for 15-20 mins until just set with a wobbly centre. Chill in the fridge for at least 4 hrs.", "To serve, sprinkle some sugar on top of the brûlées and caramelise with a blowtorch or briefly under a hot grill. Leave caramel to harden, then serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/2540/white-chocolate-crme-brle', 'https://www.themealdb.com/images/media/meals/uryqru1511798039.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamaican-curry-goat', 'Jamaican Curry Goat', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['goat', 'jamaican', 'themealdb', 'instant-pot'], '[{"quantity": 3.0, "unit": "lbs", "item": "Goat Meat", "notes": null, "category": "meat"}, {"quantity": 2.5, "unit": "tbsp", "item": "Jamaican Curry Powder", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Ground Ginger", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "All-purpose Seasoning", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "tsp", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 6.0, "unit": "cloves", "item": "sliced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 1.25, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Bonnet", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Russet Potato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Equipment", "6QT Pressure cooker", "Instructions", "Rinse goat meat with vinegar and water.", "Season goat meat with 1 ½ tablespoon curry powder, all-purpose seasoning, ground ginger, allspice, onion, garlic cloves, and thyme. Marinate for at least 4 hours or up to overnight.", "Remove onion and garlic from goat and set aside.", "Set an electric pressure cooker, like an Instant Pot, on high sauté and add oil. Add goat meat and brown, about 2-3 minutes per side. Remove goat from insert and add 1 tablespoon oil and remaining curry powder and sauté for about 10 seconds. Then add onions and garlic and sauté until softened. About 4 minutes. If the onions look dry, add a little water and continue to sauté.", "Add goat and water to the pressure cooker and cover the pressure cooker. Cook for 40 minutes on high pressure. Allow to naturally release for 10 minutes, then release the remaining pressure.", "Once all the pressure has been released, open the pressure cooker. Place on sauté for 10-15 minutes, add potatoes and a whole scotch bonnet pepper. Cook until potatoes have softened. Remove scotch bonnet pepper."]'::jsonb, 'https://www.myforkinglife.com/jamaican-curry-goat/#recipe', 'https://www.themealdb.com/images/media/meals/uc9qp11764796575.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mbuzi-choma-roasted-goat', 'Mbuzi Choma (Roasted Goat)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['goat', 'kenyan', 'themealdb', 'baking'], '[{"quantity": 1.0, "unit": "kg", "item": "Goat Meat", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "kg", "item": "Corn Flour", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "bunch", "item": "Coriander Leaves", "notes": null, "category": "spices"}]'::jsonb, '["1. Steps for the Meat:", "Roast meat over medium heat for 50 minutes and salt it as you turn it.", "2. Steps for Ugali:", "Bring the water and salt to a boil in a heavy-bottomed saucepan. Stir in the cornmeal slowly, letting it fall through the fingers of your hand.", "3. Reduce heat to medium-low and continue stirring regularly, smashing any lumps with a spoon, until the mush pulls away from the sides of the pot and becomes very thick, about 10 minutes.", "4.Remove from heat and allow to cool.", "5. Place the ugali into a large serving bowl. Wet your hands with water, form a ball and serve.", "6. Steps for Kachumbari: Mix the tomatoes, onions, chili and coriander leaves in a bowl.", "7. Serve and enjoy!"]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/cuio7s1555492979.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('adana-kebab', 'Adana kebab', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'turkish', 'themealdb', 'baking', 'grilling'], '[{"quantity": 1.0, "unit": "serving", "item": "Romano Pepper", "notes": null, "category": "produce"}, {"quantity": 800.0, "unit": "g", "item": "Lamb Mince", "notes": null, "category": "meat"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Red Pepper Paste", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Pul Biber", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Sunflower Oil", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Finely chop the peppers in a food processor, then tip them in a sieve and press into the sieve so that the peppers release all of their juices. Tip into a bowl along with the mince, red pepper paste, pul biber, 1½ tsp flaky sea salt, and 2 tbsp of the oil. Mix together, kneading well for at least 2-3 mins. If you need to, wet your hands with cold water to prevent the mixture from sticking. The mixture should be sticky when ready. Cover and chill for at least 2 hrs, or up to 12 hrs.", "step 2", "When ready to cook, heat the grill to high or an oven to 220C/200C fan/gas 6. Divide the mixture into 12 equal portions, around 85g each. If you’d like to skewer them, divide into 8 equal portions and roll into balls. Using wet hands, thread the balls onto the end of the skewers, massaging the mixture down the skewers in between the palms of your hands, until evenly distributed. Ensure that the mixture is fully wrapped tightly around the skewers without any exposed metal. Alternatively, lay them on a large baking tray lined with parchment paper if cooking in the oven, or foil if cooking under the grill. Shape into 20cm-long köfte. Wet your fingers with a little cold water and make indents all along the köfte for the traditional shape.", "step 3", "Gently brush each köfte with the remaining 1 tbsp oil and cook under the grill, on the top shelf for 10-12 mins, turning regularly, or cook in the oven for 16-18 mins, until crispy on the outside and juicy in the middle"]'::jsonb, 'https://www.bbcgoodfood.com/recipes/adana-kebab', 'https://www.themealdb.com/images/media/meals/04axct1763793018.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chilli-ginger-lamb-chops', 'Chilli ginger lamb chops', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'turkish', 'themealdb', 'grilling', 'vegetarian', 'vegan'], '[{"quantity": 4.0, "unit": "cloves", "item": "Crushed Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Chili Powder", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Loin Chops", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Put the garlic in a bowl with the ginger, lemon juice, oil, spices and seasoning. Blitz with a hand blender until smooth, then use to coat the lamb chops on both sides. Leave to marinate in the fridge for a couple of hours or overnight.", "step 2", "Heat a barbecue until hot. Barbecue the chops over the coals for 3 mins on each side until cooked but still pink and juicy in the centre."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/chilli-ginger-lamb-chops', 'https://www.themealdb.com/images/media/meals/8xuvhj1763794991.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chorba-hamra-bel-frik-algerian-lamb-tomato-and-freekeh-soup', 'Chorba Hamra bel Frik (Algerian Lamb, Tomato, and Freekeh Soup)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'algerian', 'themealdb', 'soup'], '[{"quantity": 1.0, "unit": "cup", "item": "Freekeh", "notes": null, "category": "other"}, {"quantity": 12.0, "unit": "ounces", "item": "Lamb", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "chopped  Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Ground Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "bunch", "item": "Cilantro", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "bunch", "item": "Mint", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 14.0, "unit": "oz", "item": "jar Chickpeas", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Zucchini", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}]'::jsonb, '["Place freekeh in a small bowl and cover with cold water. Set aside.", "Combine lamb, onion, black pepper, paprika, cinnamon, and salt in a pot. Stir in oil, 1/2 the cilantro, 1/2 the mint, and celery stalk until combined. Simmer over low heat for 15 minutes. Stir in chickpeas; pour in just enough water to cover, and return to a simmer. Stir in zucchini, carrot, and tomato paste.", "Set a steamer over the pot; add tomatoes. Cover and steam tomatoes until soft, about 5 minutes. Crush tomatoes using a wooden spoon, so pulp drips into soup. Remove the steamer and discard leftover tomato peels.", "Add potato to soup and just enough water to cover. Simmer until potato is soft, about 10 minutes.", "Drain freekeh and add to soup. Simmer until soft, about 15 minutes. Remove celery stalk and discard. Sprinkle soup with remaining 1/2 cilantro and remaining 1/2 mint before serving."]'::jsonb, 'https://www.allrecipes.com/recipe/264552/chorba-hamra-bel-frik-algerian-lamb-tomato-and-freekeh-soup/', 'https://www.themealdb.com/images/media/meals/p9tebp1764118792.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fårikål-norwegian-national-dish', 'Fårikål (Norwegian National Dish)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'norwegian', 'themealdb', 'baking'], '[{"quantity": 3.0, "unit": "lbs", "item": "Lamb", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "head", "item": "White Cabbage", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Whole black peppercorns", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.5, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 5.0, "unit": "tablespoons", "item": "Flour", "notes": null, "category": "grains"}]'::jsonb, '["▢", "Cut the lamb into large pieces.", "▢", "Slice the cabbage into large wedges, keeping the core attached.", "▢", "Add a layer of lamb pieces to the bottom of a large pot, fatty side down. Sprinkle with peppercorns and salt. Add a layer of cabbage wedges on top. Repeat with more layers of lamb, peppercorns, and cabbage, ending with cabbage on top.", "▢", "Optional: Sprinkle a couple of tablespoons on top of the lamb for a thicker stew.", "▢", "Add water to the pot and bring to a boil. Cover and reduce heat. Cook on low heat for 2 – 3 hours, until the lamb gently falls away from the bone.", "▢", "Serve with boiled potatoes and fresh parsley, covering generously with the fårikål broth."]'::jsonb, 'https://scandinaviancookbook.com/farikal-national-dish-of-norway/', 'https://www.themealdb.com/images/media/meals/ttfxxn1762773067.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('hot-cumin-lamb-wrap-with-crunchy-slaw-spicy-mayo', 'Hot cumin lamb wrap with crunchy slaw & spicy mayo', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'turkish', 'themealdb', 'dessert', 'salad'], '[{"quantity": 1.0, "unit": "serving", "item": "Lamb Leg", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tsp", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "White Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "White Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Peppadew Peppers", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Mayonnaise", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pita Bread", "notes": null, "category": "grains"}]'::jsonb, '["step 1", "Heat a griddle pan. Rub the lamb steaks with the oil, cumin and some seasoning. Griddle for about 3-4 mins on each side or until cooked to your liking. Place to one side on a plate to rest.", "step 2", "In a large bowl, stir the sugar into the vinegar until dissolved. Add the carrots, spring onions, cabbage and some seasoning, and toss together.", "step 3", "Blitz the whole peppers and the mayo in a food processor. Add a heap of the salad to each flatbread. Slice the lamb, trimming off any excess fat and lay on top of the salad, drizzling with the resting juices. Spoon over the mayo and scatter with a few of the sliced peppers. Roll up and eat. If using pitta, split and stuff. Serve any extra salad on the side."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/hot-cumin-lamb-wrap-crunchy-slaw-spicy-mayo', 'https://www.themealdb.com/images/media/meals/jyylmo1763790808.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('imam-bayildi-with-bbq-lamb-tzatziki', 'Imam bayildi with BBQ lamb & tzatziki', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'turkish', 'themealdb', 'baking', 'grilling', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Aubergine", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Loin Chops", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Lemon", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "g", "item": "Greek Yogurt", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Cucumber", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "chopped Mint", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat oven to 190C/170C fan/gas 5. Halve the aubergines lengthways and score the flesh side deeply, brush with a good layer of olive oil and put on a baking sheet. Roast for 20 mins or until the flesh is soft enough to scoop out.", "step 2", "Fry the onion in a little oil until soft, add the garlic and cinnamon and fry for 1 min. Once the aubergines are cool enough to handle, scoop out the centres. Roughly chop the flesh and add it to the onions. Halve the tomatoes, scoop the seeds and juice into a sieve set over a bowl, then chop the flesh. Add the chopped tomatoes to the pan and cook everything for 10 mins until nice and soft. Add a little more oil if you need to. Stir in the parsley, leaving a little for scattering at the end.", "step 3", "Lay the aubergine halves in a baking dish and divide the tomato mixture between them. Pour over the juice from the tomatoes, drizzle with more olive oil and bake for 30 mins until the aubergines have collapsed.", "step 4", "Meanwhile, mix the tzatziki ingredients together and put in a small serving bowl.", "step 5", "Season the lamb with salt, black pepper and a pinch of paprika. Griddle, grill or barbecue for 3 mins on each side or until the fat is nicely browned, then put in a serving dish and squeeze over the lemon halves. Scatter the aubergines with parsley, then serve with the lamb and tzatziki."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/imam-bayildi-bbq-lamb-tzatziki', 'https://www.themealdb.com/images/media/meals/ampz9v1763787134.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('kapsalon', 'Kapsalon', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'dutch', 'themealdb', 'salad', 'baking'], '[{"quantity": 250.0, "unit": "grams", "item": "Fries", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "grams", "item": "Doner Meat", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Topping Garlic sauce", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Topping Hotsauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Lettuce", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cucumber", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "grams", "item": "Gouda cheese", "notes": null, "category": "dairy"}]'::jsonb, '["Cut the meat into strips. Heat oil in a pan and fry the strips for 6 minutes until it''s ready.", "Bake the fries until golden brown in a deep fryrer. When ready transfer to a backing dish. Make sure the fries are spread over the whole dish.", "Cover the fries with a new layer of meat and spread evenly.", "Add a layer of cheese over the meat. You can also use grated cheese. When done put in the oven for a few minutes until the cheese is melted.", "Chop the lettuce, tomato and cucumber in small pieces and mix together. for a basic salad. As extra you can add olives jalapenos and a red union.", "Dived the salad over the dish and Serve with garlicsauce and hot sauce"]'::jsonb, NULL, 'https://www.themealdb.com/images/media/meals/sxysrt1468240488.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('keleya-zaara', 'Keleya Zaara', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'tunisian', 'themealdb'], '[{"quantity": 4.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 750.0, "unit": "g", "item": "Lamb", "notes": null, "category": "meat"}, {"quantity": 1.5, "unit": "tsp", "item": "Saffron", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Onion", "notes": null, "category": "produce"}, {"quantity": 25.0, "unit": "ml", "item": "Water", "notes": null, "category": "other"}, {"quantity": 30.0, "unit": "g", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Lemon", "notes": null, "category": "produce"}]'::jsonb, '["Heat the vegetable oil in a large frying pan over medium-high heat. Add the lamb and cook until browned on all sides, about 5 minutes. Season with saffron, salt and pepper to taste; stir in all but 4 tablespoons of the onion, and pour in the water. Bring to the boil, then cover, reduce heat to medium-low, and simmer until the lamb is tender, about 15 minutes.", "Uncover the pan, stir in the butter and allow the sauce reduce 5 to 10 minutes to desired consistency. Season to taste with salt and pepper, then pour into a serving dish. Sprinkle with the remaining chopped onions and parsley. Garnish with lemon wedges to serve."]'::jsonb, 'http://allrecipes.co.uk/recipe/43723/keleya-zaara-tunisian-lamb-with-saffron.aspx', 'https://www.themealdb.com/images/media/meals/8x09hy1560460923.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('kofta-burgers', 'kofta burgers', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'turkish', 'themealdb', 'grilling'], '[{"quantity": 1.0, "unit": "kg", "item": "Lamb", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Bulb", "notes": null, "category": "other"}, {"quantity": 6.0, "unit": "tablespoons", "item": "Garam Masala", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Chilli Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Small pack Yogurt", "notes": null, "category": "dairy"}]'::jsonb, '["step 1", "Tip the mince into a large bowl (use a clean washing-up bowl if you don’t have anything big enough) with all the other burger ingredients and a good pinch of salt. Roll up your sleeves, get your hands into the mix and squelch everything together through your fingers until completely mixed. Pat the mix into 16 small burgers. These may now be frozen for up to 1 month or chilled up to a day ahead.", "step 2", "To cook, heat grill to its highest setting and lay the burgers in a single layer on a baking tray (you may need to do this in batches, depending on how big your tray is). Grill on the highest shelf for 5-6 mins on each side until browned and cooked through. Pile burgers onto a platter and serve with all the accompaniments, so everyone can construct their own sandwich."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/diy-kofta-burgers', 'https://www.themealdb.com/images/media/meals/lgmnff1763789847.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lamb-apricot-meatballs', 'Lamb & apricot meatballs', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'turkish', 'themealdb', 'dessert'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cloves", "item": "Crushed Garlic", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tsp", "item": "Ground Coriander", "notes": null, "category": "spices"}, {"quantity": 400.0, "unit": "g", "item": "Tinned Tomatos", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 10.0, "unit": "g", "item": "Mint", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "g", "item": "Lamb Mince", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Apricots", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Pita Bread", "notes": null, "category": "grains"}]'::jsonb, '["step 1", "Heat 2 tsp oil in a pan and soften the onions for 5 mins. Add the garlic and spices and cook for a few mins more. Spoon half the onion mixture into a bowl and set aside to cool. Add the tomatoes, sugar and seasoning to the remaining onions in the pan and simmer for about 10 mins until reduced.", "step 2", "Meanwhile, add the mint, lamb, apricots and breadcrumbs to the cooled onions, season and mix well with your hands. Shape into little meatballs.", "step 3", "Heat the rest of the oil in a non-stick pan and fry the meatballs until golden (in batches if you need to). Stir in the sauce with a splash of water and gently cook everything for a few mins until the meatballs are cooked through. Serve with pitta bread and salad."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/lamb-apricot-meatballs', 'https://www.themealdb.com/images/media/meals/72fgzj1764109947.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lamb-and-lemon-souvlaki', 'Lamb and Lemon Souvlaki', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'greek', 'themealdb', 'grilling'], '[{"quantity": 2.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Sea Salt", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Zest and juice of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Dill", "notes": null, "category": "produce"}, {"quantity": 750.0, "unit": "g", "item": "Lamb Leg", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Pita Bread", "notes": null, "category": "grains"}]'::jsonb, '["Pound the garlic with sea salt in a pestle and mortar (or use a small food processor), until the garlic forms a paste. Whisk together the oil, lemon juice, zest, dill and garlic. Mix in the lamb and combine well. Cover and marinate for at least 2 hrs or overnight in the fridge. If you’re going to use bamboo skewers, soak them in cold water.", "If you’ve prepared the lamb the previous day, take it out of the fridge 30 mins before cooking. Thread the meat onto the soaked or metal skewers. Heat the grill to high or have a hot griddle pan or barbecue ready. Cook the skewers for 2-3 mins on each side, basting with the remaining marinade. Heat the pitta or flatbreads briefly, then stuff with the souvlaki. Add Greek salad (see ''Goes well with'', right) and Tzatziki (below), if you like."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/lamb-lemon-dill-souvlaki', 'https://www.themealdb.com/images/media/meals/rjhf741585564676.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lamb-and-potato-pie', 'Lamb and Potato pie', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'british', 'themealdb', 'dessert', 'soup', 'baking'], '[{"quantity": 500.0, "unit": "g", "item": "Lamb Shoulder", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 350.0, "unit": "ml", "item": "350ml/12fl Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 500.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 450.0, "unit": "g", "item": "Shortcrust Pastry", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "To Glaze Eggs", "notes": null, "category": "dairy"}]'::jsonb, '["Dust the meat with flour to lightly coat.", "Heat enough vegetable oil in a large saucepan to fill the base, and fry the onion and meat until lightly browned. Season with salt and pepper.", "Add the carrots, stock and more seasoning to taste.", "Bring to the boil, cover and reduce the heat to a simmer. Simmer for at least an hour or until the meat is tender. Take your time cooking the meat, the longer you leave it to cook, the better the flavour will be.", "Preheat the oven to 180C/350F/Gas 4.", "Add the drained potato cubes to the lamb.", "Turn the mixture into a pie dish or casserole and cover with the shortcrust pastry. Make three slits in the top of the pastry to release any steam while cooking.", "Brush with beaten egg and bake for about 40 minutes, until the pastry is golden brown.", "Serve."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/lambandpotatopie_83913', 'https://www.themealdb.com/images/media/meals/sxrpws1511555907.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lamb-biryani', 'Lamb Biryani', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'indian', 'themealdb', 'instant-pot', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "nuts", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tbsp", "item": "Khus khus", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tbsp", "item": "Cumin seeds", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "thinly Onions", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Ginger garlic paste", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "whole", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves Mint", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves Cilantro", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "dissolved in ½ cup warm milk Saffron", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbsp", "item": "Ghee", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "cups", "item": "Basmati rice", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "cup", "item": "Full fat yogurt", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbsp", "item": "Cumin Seeds", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "piece Cinnamon", "notes": null, "category": "spices"}, {"quantity": 3.0, "unit": "cloves", "item": "Cloves", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Cardamom", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "lb", "item": "Lamb", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tsp", "item": "Red Chilli powder", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbsp", "item": "Biryani masala", "notes": null, "category": "other"}]'::jsonb, '["Grind the cashew, poppy seeds and cumin seeds into a smooth paste, using as little water as possible. Set aside.", "Deep fry the sliced onions when it is hot. Don’t overcrowd the oil. When the onions turn light brown, remove from oil and drain on paper towel. The fried onion will crisp up as it drains. Also fry the cashewnuts till golden brown. Set aside.", "Wash the rice and soak in water for twenty minutes.", "Meanwhile, take a big wide pan, add oil in medium heat, add the sliced onions, add the blended paste, to it add the green chillies, ginger garlic paste and garlic and fry for a minute.", "Then add the tomatoes and sauté them well till they are cooked and not mushy.", "Then to it add the red chilli powder, biryani powder, mint, coriander leaves and sauté them well.", "Add the yogurt and mix well. I always move the skillet away from the heat when adding yogurt which prevents it from curdling.", "Now after returning the skillet back to the stove, add the washed lamb and salt and ½ cup water and mix well. Cook for 1 hour and cook it covered in medium low heat or put it in a pressure cooker for 6 whistles. If the water is not drained totally, heat it by keeping it open.", "Take another big pan, add thrice the cup of rice you use, and boil it. When it is boiling high, add the rice, salt and jeera and mix well. After 7 minutes exact or when the rice is 80% done. Switch off and drain the rice.", "Now, the layering starts. To the lamb, pat and level it. Add the drained hot rice on the top of it. Garnish with fried onions, ghee, mint, coriander leaves and saffron dissolved in milk.", "Cover the dish and bake in a 350f oven for 15 minutes or till the cooked but not mushy. Or cook in the stove medium heat for 12 minutes and lowest heat for 5 minutes. And switch off. Mix and serve hot!", "Notes", "1. If you are cooking in oven, do make sure to cook in a big oven safe pan and cover it tight and then keep in oven for the final step.", "2. You can skip biryani masala if you don’t have and add just garam masala (1 tsp and red chilli powder – 3 tsp instead of 1 tsp)", "3. If it is spicy in the end, squeeze some lemon, it will reduce the heat and enhance the flavors also."]'::jsonb, 'http://www.relishthebite.com/restaurant-style-lamb-biryani/', 'https://www.themealdb.com/images/media/meals/xrttsx1487339558.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lamb-pilaf-plov', 'Lamb Pilaf (Plov)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'russian', 'themealdb', 'soup'], '[{"quantity": 50.0, "unit": "g", "item": "Lamb", "notes": null, "category": "meat"}, {"quantity": 120.0, "unit": "g", "item": "Prunes", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbs", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 450.0, "unit": "g", "item": "Lamb", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 600.0, "unit": "ml", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "cups", "item": "Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Saffron", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Garnish Parsley", "notes": null, "category": "produce"}]'::jsonb, '["Place the raisins and prunes into a small bowl and pour over enough water to cover. Add lemon juice and let soak for at least 1 hour. Drain. Roughly chop the prunes.", "Meanwhile, heat the butter in a large pan, add the onion, and cook for 5 minutes. Add cubed lamb, ground lamb, and crushed garlic cloves. Fry for 5 minutes, stirring constantly until browned.", "Pour 2/3 cup (150 milliliters) of stock into the pan. Bring to a boil, then lower the heat, cover, and simmer for 1 hour, or until the lamb is tender.", "Add the remaining stock and bring to a boil. Add rinsed long-grain white rice and a large pinch of saffron. Stir, then cover, and simmer for 15 minutes, or until the rice is tender.", "Add the drained raisins, drained chopped prunes, and salt and pepper to taste. Heat through for a few minutes, then turn out onto a warmed serving dish and garnish with sprigs of flat-leaf parsley."]'::jsonb, 'https://www.thespruceeats.com/russian-lamb-pilaf-plov-recipe-1137309', 'https://www.themealdb.com/images/media/meals/kos9av1699014767.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lamb-rogan-josh', 'Lamb Rogan josh', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'indian', 'themealdb'], '[{"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tbsp", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thumb sized peeled and very finely", "notes": "grated Ginger", "category": "other"}, {"quantity": 2.0, "unit": "tbsp", "item": "Madras Paste", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "stick", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "to break shells Cardamom", "notes": null, "category": "spices"}, {"quantity": 4.0, "unit": "cloves", "item": "Cloves", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbsp", "item": "Tomato Purée", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "kg", "item": "cubed Lamb", "notes": null, "category": "meat"}, {"quantity": 150.0, "unit": "ml", "item": "Greek yogurt", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Garnish", "notes": "chopped  Coriander", "category": "other"}]'::jsonb, '["Put the onions in a food processor and whizz until very finely chopped. Heat the oil in a large heavy-based pan, then fry the onion with the lid on, stirring every now and then, until it is really golden and soft. Add the garlic and ginger, then fry for 5 mins more.", "Tip the curry paste, all the spices and the bay leaves into the pan, with the tomato purée. Stir well over the heat for about 30 secs, then add the meat and 300ml water. Stir to mix, turn down the heat, then add the yogurt.", "Cover the pan, then gently simmer for 40-60 mins until the meat is tender and the sauce nice and thick. Serve scattered with coriander, with plain basmati or pilau rice."]'::jsonb, 'http://www.bbcgoodfood.com/recipes/9643/onepan-rogan-josh', 'https://www.themealdb.com/images/media/meals/vvstvq1487342592.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lamb-tagine', 'Lamb Tagine', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'moroccan', 'themealdb', 'soup'], '[{"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "sliced Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "g", "item": "Lamb Leg", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "Saffron", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Honey", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Apricot", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Stock Cube", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Butternut Squash", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Steamed Couscous", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Parsley", "notes": null, "category": "produce"}]'::jsonb, '["Heat the olive oil in a heavy-based pan and add the onion and carrot. Cook for 3- 4 mins until softened.", "Add the diced lamb and brown all over. Stir in the garlic and all the spices and cook for a few mins more or until the aromas are released.", "Add the honey and apricots, crumble in the stock cube and pour over roughly 500ml boiling water or enough to cover the meat. Give it a good stir and bring to the boil. Turn down to a simmer, put the lid on and cook for 1 hour.", "Remove the lid and cook for a further 30 mins, then stir in the squash. Cook for 20 – 30 mins more until the squash is soft and the lamb is tender. Serve alongside rice or couscous and sprinkle with parsley and pine nuts, if using."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/2303638/family-meals-easy-lamb-tagine-', 'https://www.themealdb.com/images/media/meals/yuwtuu1511295751.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lamb-tomato-and-sweet-spices', 'Lamb tomato and sweet spices', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'moroccan', 'themealdb', 'dessert'], '[{"quantity": 2.0, "unit": "tbsp", "item": "olive oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "piece finely", "notes": "chopped ginger", "category": "other"}, {"quantity": 2.0, "unit": "cloves", "item": "peeled", "notes": "chopped garlic", "category": "other"}, {"quantity": 800.0, "unit": "g", "item": "peeled", "notes": "chopped  tomatoes", "category": "other"}, {"quantity": 2.0, "unit": "tbsp", "item": "lemon juice", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "caster sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "fennel bulb", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "lamb mince", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "peeled and coarsely", "notes": "grated potatoes", "category": "other"}, {"quantity": 2.0, "unit": "tbsp", "item": "basmati rice", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tbsp", "item": "chopped parsley", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "chopped coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tbsp", "item": "lemon juice", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "ground clove", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "ground  cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "tomatoes", "notes": null, "category": "produce"}]'::jsonb, '["Use pickled vine leaves here, preserved in brine. Small delicate leaves are better than the large bristly ones but, if only large leaves are to hand, then trim them to roughly 12 by 12 cms so that you don''t get too many layers of leaves around the filling. And remove any stalks. Drain the preserved leaves, immerse them in boiling water for 10 minutes and then leave to dry on a tea towel before use.", "Basmati rice with butter and pine nuts is an ideal accompaniment. Couscous is great, too. Serves four.", "First make the filling. Put all the ingredients, apart from the tomatoes, in a bowl. Cut the tomatoes in half, coarsely grate into the bowl and discard the skins. Add half a teaspoon of salt and some black pepper, and stir. Leave on the side, or in the fridge, for up to a day. Before using, gently squeeze with your hands and drain away any juices that come out.", "To make the sauce, heat the oil in a medium pan. Add the ginger and garlic, cook for a minute or two, taking care not to burn them, then add the tomato, lemon juice and sugar. Season, and simmer for 20 minutes.", "While the sauce is bubbling away, prepare the vine leaves. Use any torn or broken leaves to line the base of a wide, heavy saucepan. Trim any leaves from the fennel, cut it vertically into 0.5cm-thick slices and spread over the base of the pan to cover completely.", "Lay a prepared vine leaf (see intro) on a work surface, veiny side up. Put two teaspoons of filling at the base of the leaf in a 2cm-long by 1cm-wide strip. Fold the sides of the leaf over the filling, then roll it tightly from bottom to top, in a cigar shape. Place in the pan, seam down, and repeat with the remaining leaves, placing them tightly next to each other in lines or circles (in two layers if necessary).", "Pour the sauce over the leaves (and, if needed, add water just to cover). Place a plate on top, to weigh the leaves down, then cover with a lid. Bring to a boil, reduce the heat and cook on a bare simmer for 70 minutes. Most of the liquid should evaporate. Remove from the heat, and leave to cool a little - they are best served warm. When serving, bring to the table in the pan - it looks great. Serve a few vine leaves and fennel slices with warm rice. Spoon the braising juices on top and garnish with coriander."]'::jsonb, 'http://www.ottolenghi.co.uk/recipes/meat/lamb-tomato-and-sweet-spices-shop', 'https://www.themealdb.com/images/media/meals/qtwtss1468572261.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lamb-tzatziki-burgers', 'Lamb Tzatziki Burgers', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'greek', 'themealdb', 'grilling'], '[{"quantity": 25.0, "unit": "g", "item": "Bulgur Wheat", "notes": null, "category": "grains"}, {"quantity": 500.0, "unit": "g", "item": "Lamb Mince", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "clove", "item": "finely", "notes": "chopped Garlic", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Bun", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Grated Cucumber", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Greek Yogurt", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "Mint", "notes": null, "category": "produce"}]'::jsonb, '["Tip the bulghar into a pan, cover with water and boil for 10 mins. Drain really well in a sieve, pressing out any excess water.", "To make the tzatziki, squeeze and discard the juice from the cucumber, then mix into the yogurt with the chopped mint and a little salt.", "Work the bulghar into the lamb with the spices, garlic (if using) and seasoning, then shape into 4 burgers. Brush with a little oil and fry or barbecue for about 5 mins each side until cooked all the way through. Serve in the buns (toasted if you like) with the tzatziki, tomatoes, onion and a few mint leaves."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/lamb-burgers-tzatziki', 'https://www.themealdb.com/images/media/meals/k420tj1585565244.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lancashire-hotpot', 'Lancashire hotpot', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'british', 'themealdb', 'soup', 'baking', 'grilling'], '[{"quantity": 100.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 900.0, "unit": "g", "item": "Lamb", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Kidney", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 25.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tsp", "item": "Worcestershire Sauce", "notes": null, "category": "pantry"}, {"quantity": 500.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 900.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}]'::jsonb, '["Heat oven to 160C/fan 140C/gas 3. Heat some dripping or butter in a large shallow casserole dish, brown the lamb in batches, lift to a plate, then repeat with the kidneys.", "Fry the onions and carrots in the pan with a little more dripping until golden. Sprinkle over the flour, allow to cook for a couple of mins, shake over the Worcestershire sauce, pour in the stock, then bring to the boil. Stir in the meat and bay leaves, then turn off the heat. Arrange the sliced potatoes on top of the meat, then drizzle with a little more dripping. Cover, then place in the oven for about 1½ hrs until the potatoes are cooked.", "Remove the lid, brush the potatoes with a little more dripping, then turn the oven up to brown the potatoes, or finish under the grill for 5-8 mins until brown."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/9099/lancashire-hotpot', 'https://www.themealdb.com/images/media/meals/uttrxw1511637813.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mcsinghs-scotch-pie', 'McSinghs Scotch pie', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'british', 'themealdb', 'dessert', 'baking'], '[{"quantity": 2.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tbs", "item": "Rapeseed Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Red Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Green Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "chopped  Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "kg", "item": "Lamb Mince", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tsp", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbs", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 340.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 90.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 150.0, "unit": "g", "item": "Lard", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Beaten Egg Yolks", "notes": null, "category": "dairy"}]'::jsonb, '["Heat a large frying pan and toast the cumin seeds for a few minutes, then set aside. Heat the oil in the same pan and fry the onion, garlic, chilli, pepper and a good pinch of salt for around eight minutes, until there is no moisture left. Remove from the heat, stir in the toasted cumin seeds, ground mace (or nutmeg) and ground coriander. Leave to cool.", "In a large bowl mix together the minced lamb, white pepper, fresh coriander, and the cooled spiced onion mixture until combined. Set aside, covered, in the fridge.", "Preheat the oven to 200C/400F/Gas 6 and generously grease a 20cm/8in diameter loose-bottomed or springform round cake tin with lard.", "To make the pastry, sift the flour and salt in a large bowl and make a well in the centre.", "Put the milk, lard and 90ml/3fl oz of water in a saucepan and heat gently. When the lard has melted, increase the heat and bring to the boil.", "Pour the boiling liquid into the flour, and use a wooden spoon to combine until cool enough to handle. Bring together into a ball.", "Dust a work surface with flour and, working quickly, knead the dough briefly – it will be soft and moist. Set aside a third of the pastry and roll the rest out on a well-floured surface. Line the pie dish with the pastry, pressing it right up the sides until it pokes just over the top of the tin.", "Add the filling into the pastry-lined tin bit by bit. As you reach the top, form a slight peak. Roll out the reserved pastry and top the pie with it. Pinch the edges to seal and trim the excess. Poke a hole in the top of the pie and insert a small tube made from aluminium foil to allow steam to escape.", "Brush the top of the pie with a little beaten egg yolk, and bake in the preheated oven for 30 minutes (put a tray on the shelf below to catch any drips). Then reduce the temperature to 160C/325F/Gas 3 and cook for a further 1¼ hours until golden-brown. Leave to cool completely before refrigerating for two hours, or overnight.", "Run a knife around the edge of the pie, remove from the tin and serve with chutneys, salads or pickles."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/mcsinghs_scotch_pie_98356', 'https://www.themealdb.com/images/media/meals/vssrtx1511557680.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('rigatoni-with-fennel-sausage-sauce', 'Rigatoni with fennel sausage sauce', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'italian', 'themealdb', 'dessert'], '[{"quantity": 2.5, "unit": "tbsp", "item": "olive oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "into 1.5cm-thick slices Italian fennel sausages", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "peeled", "notes": "chopped onion", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "and roughly", "notes": "chopped; reserve any fronds to garnish fennel bulb", "category": "other"}, {"quantity": 0.5, "unit": "tsp", "item": "smoky paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "clove", "item": "clove", "notes": "peeled and sliced garlic", "category": "spices"}, {"quantity": 2.0, "unit": "tsp", "item": "lightly", "notes": "toasted and then gently crushed fennel seeds", "category": "other"}, {"quantity": 100.0, "unit": "ml", "item": "red wine", "notes": null, "category": "other"}, {"quantity": 400.0, "unit": "g", "item": "tinned", "notes": "chopped tomatoes", "category": "other"}, {"quantity": 0.5, "unit": "tsp", "item": "caster sugar", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "cut in half lengthways pitted black olives", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "g", "item": "rigatoni", "notes": null, "category": "other"}, {"quantity": 30.0, "unit": "g", "item": "roughly crumbled into 0.5cm pieces pecorino", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "and patted dry anchovy fillet", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "clove", "item": "clove", "notes": "peeled and crushed garlic", "category": "spices"}, {"quantity": 60.0, "unit": "ml", "item": "olive oil", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "torn basil leaves", "notes": null, "category": "produce"}]'::jsonb, '["Heat a tablespoon of oil in a large saute pan for which you have a lid. Add the sausage pieces and fry on a medium-high heat for 10 minutes, stirring regularly, until golden-brown all over. Transfer the sausages to a plate, then add the onion and fennel to the hot pan and fry for 15 minutes, stirring once in a while, until soft and caramelised; if the pan goes a bit dry, add a teaspoon or so of extra oil. Stir in the paprika, garlic and half the fennel seeds, fry for two minutes more, then pour on the wine and boil for 30 seconds, to reduce by half. Add the tomatoes, sugar, 100ml water, the seared sausage and half a teaspoon of salt, cover and simmer for 30 minutes; remove the lid after 10 minutes, and cook until the sauce is thick and rich. Remove from the heat, stir through the olives and remaining fennel seeds and set aside until you’re ready to serve.", "Bring a large pot of salted water to a boil, add the pasta and cook for 12-14 minutes (or according to the instructions on the packet), until al dente. Meanwhile, reheat the sauce. Drain the pasta, return it to the pot, stir in a tablespoon of oil, then divide between the bowls.", "Put all the pesto ingredients except the basil in the small bowl of a food processor. Add a tablespoon of water and blitz to a rough paste. Add the basil, then blitz until just combined (the pesto has a much better texture if the basil is not overblended).", "Spoon over the ragù and top with a spoonful of pesto. Finish with a sprinkling of chopped fennel fronds, if you have any, and serve at once."]'::jsonb, 'http://www.ottolenghi.co.uk/recipes/meat/rigatoni-with-fennel-sausage-sauce-and-pecorino-and-anchovy-pesto-shop', 'https://www.themealdb.com/images/media/meals/qtqvys1468573168.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('slow-roast-lamb-with-cinnamon-fennel-citrus', 'Slow-roast lamb with cinnamon, fennel & citrus', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'turkish', 'themealdb', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Leg", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Zest and juice of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Clear Honey", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Fennel Seeds", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 3.0, "unit": "cloves", "item": "Crushed Garlic", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Put the lamb into a large food bag with all the juice and marinate overnight.", "step 2", "The next day, take the lamb out of the fridge 1 hr before you want to cook it. Heat oven to 220C/200C fan/gas 7. Take the lamb out of the marinade (reserve remaining marinade) and pat dry. Rub with half the oil and roast for 15-20 mins until browned. Remove lamb and reduce oven to 160C/140C fan/gas 3.", "step 3", "Mix the zests, remaining oil, honey, spices and garlic with plenty of seasoning. Lay a large sheet of baking parchment on a large sheet of foil. Sit the lamb leg on top, rub all over with the paste and pull up the sides of the foil. Drizzle marinade into base, and scrunch foil to seal.", "step 4", "Roast for 4 hrs, until very tender. Rest, still wrapped, for 30 mins. Unwrap and serve with juices."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/slow-roast-lamb-cinnamon-fennel-citrus', 'https://www.themealdb.com/images/media/meals/gr4lo51763791826.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spanish-style-slow-cooked-lamb-shoulder-beans', 'Spanish-style slow-cooked lamb shoulder & beans', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'spanish', 'themealdb', 'soup', 'baking'], '[{"quantity": 2.5, "unit": "kg", "item": "Lamb Shoulder", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Bulb", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1200.0, "unit": "g", "item": "Butter Beans", "notes": null, "category": "dairy"}, {"quantity": 450.0, "unit": "g", "item": "Roasted pepper", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Black Olives", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cloves", "item": "Crushed Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Hot smoked paprika", "notes": null, "category": "spices"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Rosemary", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "To make the spice mix, combine all of the ingredients together with a large pinch of salt. Slash the lamb shoulder all over with a sharp knife and rub in. If you have the time, marinate for up to 24 hrs, but this is not essential.", "step 2", "Heat the oven to 150C/130C fan/gas 2. Heat the oil in a large flameproof casserole dish or roasting tin over a medium-high heat, add the onions, carrots and garlic and sizzle for 5 mins until the onions and carrots are softened. Pour over the stock, then bring to the boil. Nestle the lamb in the pan and cover, then transfer to the oven and roast for 2 hrs.", "step 3", "Uncover and transfer the lamb to a plate using tongs. Stir the beans, peppers and olives through the stock in the pan, sit the lamb back on top and return to the oven, uncovered, for 1 hr 30 mins until the lamb is cooked through. Transfer the lamb to a board and shred using two forks. Stir the parsley through the braised beans before serving."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/spanish-style-slow-cooked-lamb-shoulder-beans', 'https://www.themealdb.com/images/media/meals/9kwatm1763327074.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('stuffed-lamb-tomatoes', 'Stuffed Lamb Tomatoes', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'greek', 'themealdb', 'dessert', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Sugar", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Lamb", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tbs", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tbs", "item": "chopped Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 50.0, "unit": "g", "item": "Rice", "notes": null, "category": "grains"}, {"quantity": 100.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 4.0, "unit": "tbs", "item": "Dill", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Chopped Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Mint", "notes": null, "category": "produce"}]'::jsonb, '["Heat oven to 180C/160C fan/gas 4. Slice the tops off the tomatoes and reserve. Scoop out most of the pulp with a teaspoon, being careful not to break the skin. Finely chop the pulp, and keep any juices. Sprinkle the insides of the tomatoes with a little sugar to take away the acidity, then place them on a baking tray.", "Heat 2 tbsp olive oil in a large frying pan, add the onion and garlic, then gently cook for about 10 mins until soft but not coloured. Add the lamb, cinnamon and tomato purée, turn up the heat, then fry until the meat is browned. Add the tomato pulp and juice, the rice and the stock. Season generously. Bring to the boil, then simmer for 15 mins or until the rice is tender and the liquid has been absorbed. Set aside to cool a little, then stir in the herbs.", "Stuff the tomatoes up to the brim, top tomatoes with their lids, drizzle with 2 tbsp more olive oil, sprinkle 3 tbsp water into the tray, then bake for 35 mins. Serve with salad and crusty bread, hot or cold."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/stuffed-tomatoes-lamb-mince-dill-rice', 'https://www.themealdb.com/images/media/meals/u55lbp1585564013.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tunisian-lamb-soup', 'Tunisian Lamb Soup', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'tunisian', 'themealdb', 'soup', 'pasta'], '[{"quantity": 500.0, "unit": "g", "item": "Lamb Mince", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Spinach", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbs", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 3.0, "unit": "tsp", "item": "Harissa Spice", "notes": null, "category": "other"}, {"quantity": 400.0, "unit": "g", "item": "Chickpeas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Juice", "notes": null, "category": "other"}, {"quantity": 150.0, "unit": "g", "item": "Macaroni", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Add the lamb to a casserole and cook over high heat. When browned, remove from the heat and set aside.", "Keep a tablespoon of fat in the casserole and discard the rest. Reduce to medium heat then add the garlic, onion and spinach and cook until the onion is translucent and the spinach wilted or about 5 minutes.", "Return the lamb to the casserole with the onion-spinach mixture, add the tomato puree, cumin, harissa, chicken, chickpeas, lemon juice, salt and pepper in the pan. Simmer over low heat for about 20 minutes.", "Add the pasta and cook for 15 minutes or until pasta is cooked."]'::jsonb, 'http://allrecipes.co.uk/recipe/16694/tunisian-lamb-soup.aspx', 'https://www.themealdb.com/images/media/meals/t8mn9g1560460231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('turkish-lamb-pilau', 'Turkish lamb pilau', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'turkish', 'themealdb', 'soup'], '[{"quantity": 1.0, "unit": "serving", "item": "Handful Pine Nuts", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 500.0, "unit": "g", "item": "Lamb", "notes": null, "category": "meat"}, {"quantity": 250.0, "unit": "g", "item": "Basmati Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Apricots", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Mint", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Dry-fry the pine nuts or almonds in a large pan until lightly toasted, then tip onto a plate. Add the oil to the pan, then fry the onion and cinnamon together until starting to turn golden. Turn up the heat, stir in the lamb, fry until the meat changes colour, then tip in the rice and cook for 1 min, stirring all the time.", "step 2", "Pour in 500ml boiling water, crumble in the stock cube, add the apricots, then season to taste. Turn the heat down, cover and simmer for 12 mins until the rice is tender and the stock has been absorbed. Toss in the pine nuts and mint and serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/turkish-lamb-pilau', 'https://www.themealdb.com/images/media/meals/cr2kyr1763793839.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('turkish-style-lamb', 'Turkish-style lamb', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'turkish', 'themealdb', 'salad', 'grilling', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Leg", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "Seasoning", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Dried Oregano", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Mint", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Yogurt", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Lettuce", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Lemon", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat grill to high. Season the lamb, then grill for 2 mins on each side until browned, but still very rare. Meanwhile, mix the seasoning, oregano and half of the mint into one of the tubs of yogurt, smother this over the lamb, then return to the grill for another 2-3 mins or until the yogurt is blistered and the meat is cooked to your liking.", "step 2", "Leave the meat to rest on a board for a few mins while you toast the pittas, shred the lettuce and thinly slice the red onion. Stir the rest of the mint into the second tub of yogurt. Thickly slice the meat and stuff into the pitta bread with the salad and minted yogurt. Squeeze over lemon juice before tucking in, if you like."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/turkish-style-lamb', 'https://www.themealdb.com/images/media/meals/0p7l6b1763813981.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vietnamese-lamb-shanks-with-sweet-potatoes', 'Vietnamese lamb shanks with sweet potatoes', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['lamb', 'vietnamese', 'themealdb', 'dessert', 'soup', 'baking'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "Ground Nut Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Shanks", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "chopped Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "thinly Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Anise", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Stalks", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "l", "item": "Lamb Stock", "notes": null, "category": "meat"}, {"quantity": 0.5, "unit": "tbsp", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 2 Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Mint", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Basil Leaves", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat oven to 160C/140C fan/gas 3. Heat 1 tbsp oil in a heavy-bottomed casserole, season the shanks, then brown them 2 at a time on all sides, adding the remaining oil for the second batch. Remove the lamb and add the onions. Fry them quite briskly, about 30 secs, add the ginger, garlic and chopped chilli, then turn the heat down and cook for 1 min. Add 1 tbsp sugar, stir, then add the star anise, lemongrass, stock, purée and seasoning. Bring to the boil.", "step 2", "Cover and cook in the oven for 1½ hrs, then add the sweet potatoes and cook for 1 hr more. The lamb should be completely tender and almost falling off the bones. Stir in the fish sauce, lime juice and 1 tsp sugar to just lift the flavour, then scatter with the mint, basil and the sliced chilli to serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/vietnamese-lamb-shanks-sweet-potatoes', 'https://www.themealdb.com/images/media/meals/7xte3u1763757761.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bean-sausage-hotpot', 'Bean & Sausage Hotpot', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'british', 'themealdb'], '[{"quantity": 1.0, "unit": "serving", "item": "Sausages", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato Sauce", "notes": null, "category": "produce"}, {"quantity": 1200.0, "unit": "g", "item": "Butter Beans", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Black Treacle", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "English Mustard", "notes": null, "category": "pantry"}]'::jsonb, '["In a large casserole, fry the sausages until brown all over – about 10 mins.", "Add the tomato sauce, stirring well, then stir in the beans, treacle or sugar and mustard. Bring to the simmer, cover and cook for 30 mins. Great served with crusty bread or rice."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/339607/bean-and-sausage-hotpot', 'https://www.themealdb.com/images/media/meals/vxuyrx1511302687.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('callaloo-jamaican-style', 'Callaloo Jamaican Style', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'jamaican', 'themealdb', 'breakfast'], '[{"quantity": 1.0, "unit": "bunch", "item": "Kale", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 3.0, "unit": "cloves", "item": "Chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Banana", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Splash Vegetable Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Cut leaves and soft stems from the kale branches, them soak in a bowl of cold water for about 5-10 minutes or until finish with prep.", "Proceed to slicing the onions, mincing the garlic and dicing the tomatoes. Set aside", "Remove kale from water cut in chunks.", "Place bacon on saucepan and cook until crispy. Then add onions, garlic, thyme, stir for about a minute or more", "Add tomatoes; scotch bonnet pepper, smoked paprika. Sauté for about 2-3 more minutes.", "Finally add vegetable, salt, mix well, and steamed for about 6-8 minutes or until leaves are tender. Add a tiny bit of water as needed. Adjust seasonings and turn off the heat.", "Using a sharp knife cut both ends off the plantain. This will make it easy to grab the skin of the plantains. Slit a shallow line down the long seam of the plantain; peel only as deep as the peel. Remove plantain peel by pulling it back.", "Slice the plantain into medium size lengthwise slices and set aside.", "Coat a large frying pan with cooking oil spray. Spray the tops of the plantains with a generous layer of oil spray and sprinkle with salt, freshly ground pepper.", "Let the plantains \"fry\" on medium heat, shaking the frying pan to redistribute them every few minutes.", "As the plantains brown, continue to add more cooking oil spray, salt and pepper (if needed) until they have reached the desired color and texture.", "Remove and serve with kale"]'::jsonb, 'https://www.africanbites.com/callaloo-jamaican-style/', 'https://www.themealdb.com/images/media/meals/ussyxw1515364536.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chakchouka', 'Chakchouka ', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'tunisian', 'themealdb', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Green Pepper", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "Crushed Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 0.75, "unit": "teaspoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Chili Powder", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}]'::jsonb, '["In a large cast iron skillet or sauté pan with a lid, heat oil over medium high heat.", "Add the onion and sauté for 2-3 minutes, until softened.", "Add the peppers and garlic, and sauté for an additional 3-5 minutes.", "Add the tomatoes, cumin, paprika, salt, and chili powder.", "Mix well and bring the mixture to a simmer.", "Reduce the heat to medium low and continue to simmer, uncovered, 10-15 minutes until the mixture has thickened to your desired consistency.", "(Taste the sauce at this point and adjust for salt and spice, as desired.", ") Using the back of a spoon, make four craters in the mixture, large enough to hold an egg.", "Crack one egg into each of the craters.", "Cover the skillet and simmer for 5-7 minutes, until the eggs have set.", "Serve immediately with crusty bread or pita."]'::jsonb, 'https://www.curiouscuisiniere.com/chakchouka/', 'https://www.themealdb.com/images/media/meals/gpz67p1560458984.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('duck-confit', 'Duck Confit', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'french', 'themealdb', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Handful Sea Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Legs", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "ml", "item": "White Wine", "notes": null, "category": "other"}]'::jsonb, '["The day before you want to make the dish, scatter half the salt, half the garlic and half of the herbs over the base of a small shallow dish. Lay the duck legs, skin-side up, on top, then scatter over the remaining salt, garlic and herbs. Cover the duck and refrigerate overnight. This can be done up to 2 days ahead.", "Pour the wine into a saucepan that will snugly fit the duck legs in a single layer. Brush the salt off the duck legs and place them, skin-side down, in the wine. Cover the pan with a lid and place over a medium heat. As soon as the wine starts to bubble, turn the heat down to the lowest setting and cook for 2 hours, checking occasionally that the liquid is just barely simmering. (If you own a heat diffuser, it would be good to use it here.) After 2 hours, the duck legs should be submerged in their own fat and the meat should feel incredibly tender when prodded. Leave to cool.", "The duck legs are now cooked and can be eaten immediately – or you can follow the next step if you like them crisp. If you are preparing ahead, pack the duck legs tightly into a plastic container or jar and pour over the fat, but not the liquid at the bottom of the pan. Cover and leave in the fridge for up to a month, or freeze for up to 3 months. The liquid you are left with makes a tasty gravy, which can be chilled or frozen until needed.", "To reheat and crisp up the duck legs, heat oven to 220C/fan 200C/gas 7. Remove the legs from the fat and place them, skin-side down, in an ovenproof frying pan. Roast for 30-40 mins, turning halfway through, until brown and crisp. Serve with the reheated gravy, a crisp salad and some crisp golden ptoatoes."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/2085/barneys-confit-of-duck', 'https://www.themealdb.com/images/media/meals/wvpvsu1511786158.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('french-lentils-with-garlic-and-thyme', 'French Lentils With Garlic and Thyme', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'french', 'themealdb', 'vegetarian', 'vegan'], '[{"quantity": 3.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 2.25, "unit": "cups", "item": "French Lentils", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}]'::jsonb, '["Place a large saucepan over medium heat and add oil. When hot, add chopped vegetables and sauté until softened, 5 to 10 minutes.", "Add 6 cups water, lentils, thyme, bay leaves and salt. Bring to a boil, then reduce to a fast simmer.", "Simmer lentils until they are tender and have absorbed most of the water, 20 to 25 minutes. If necessary, drain any excess water after lentils have cooked. Serve immediately, or allow them to cool and reheat later.", "For a fuller taste, use some chicken stock and reduce the water by the same amount."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/vwwspt1487394060.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('french-omelette', 'French Omelette', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'french', 'themealdb', 'breakfast', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Parmesan", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Tarragon Leaves", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tbs", "item": "chopped Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "chopped Chives", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "tbs", "item": "Gruyère", "notes": null, "category": "other"}]'::jsonb, '["Get everything ready. Warm a 20cm (measured across the top) non-stick frying pan on a medium heat. Crack the eggs into a bowl and beat them with a fork so they break up and mix, but not as completely as you would for scrambled egg. With the heat on medium-hot, drop one knob of butter into the pan. It should bubble and sizzle, but not brown. Season the eggs with the Parmesan and a little salt and pepper, and pour into the pan.", "Let the eggs bubble slightly for a couple of seconds, then take a wooden fork or spatula and gently draw the mixture in from the sides of the pan a few times, so it gathers in folds in the centre. Leave for a few seconds, then stir again to lightly combine uncooked egg with cooked. Leave briefly again, and when partly cooked, stir a bit faster, stopping while there’s some barely cooked egg left. With the pan flat on the heat, shake it back and forth a few times to settle the mixture. It should slide easily in the pan and look soft and moist on top. A quick burst of heat will brown the underside.", "Grip the handle underneath. Tilt the pan down away from you and let the omelette fall to the edge. Fold the side nearest to you over by a third with your fork, and keep it rolling over, so the omelette tips onto a plate – or fold it in half, if that’s easier. For a neat finish, cover the omelette with a piece of kitchen paper and plump it up a bit with your fingers. Rub the other knob of butter over to glaze. Serve immediately."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/1669/ultimate-french-omelette', 'https://www.themealdb.com/images/media/meals/yvpuuy1511797244.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('locro', 'Locro', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'argentinian', 'themealdb'], '[{"quantity": 500.0, "unit": "g", "item": "Dried white corn", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Dried white beans", "notes": null, "category": "pantry"}, {"quantity": 300.0, "unit": "g", "item": "Pumpkin", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Beef", "notes": null, "category": "meat"}, {"quantity": 200.0, "unit": "g", "item": "Pork", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Soak: Soak corn and beans overnight in water.", "Cook Meats: In a large pot, brown the beef and pork. Add onions and spices, cooking until translucent.", "Simmer the Stew: Add soaked corn and beans, pumpkin, potato, and enough water to cover. Simmer for 2-3 hours, until thick.", "Serve: Enjoy hot, with bread on the side.", "Pro Tips:", "Toasting the corn slightly before adding it to the stew enhances its flavor.", "Add a spoonful of paprika or a dash of cumin for an extra layer of warmth and complexity"]'::jsonb, 'https://www.munchery.com/blog/the-ten-iconic-dishes-of-argentina-and-how-to-cook-them-at-home/', 'https://www.themealdb.com/images/media/meals/5sgsob1763196284.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('migas', 'Migas', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'spanish', 'themealdb'], '[{"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 1.5, "unit": "l", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Half Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pork", "notes": null, "category": "meat"}]'::jsonb, '["Crumble the bread into small pieces. Sprinkle with cold water, cover with a damp cloth and leave for 30 minutes.", "Heat 2 tsp of olive oil in a deep pan. Add the garlic cloves separated, skins on; just make a small cut with a knife to open them and keep frying for 5 minutes. Set the garlic aside.", "In the same oil, where we fried everything, simmer the bread, stirring constantly for 15 minutes and add a grinding of black pepper.", "Add the garlic, continue stirring for about 20 minutes. It will be ready when the bread is soft and golden."]'::jsonb, 'https://www.ibericafood.com/Recipes/post/migas-with-pork', 'https://www.themealdb.com/images/media/meals/xd9aj21740432378.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mutabbaq', 'Mutabbaq', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'saudi arabian', 'themealdb', 'dessert', 'baking'], '[{"quantity": 500.0, "unit": "g", "item": "Mincemeat", "notes": null, "category": "meat"}, {"quantity": 1.5, "unit": "tbs", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.5, "unit": "tbs", "item": "minced Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pastry", "notes": null, "category": "other"}, {"quantity": 1.5, "unit": "cups", "item": "Melted Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Turmeric", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["1", "Heat the frying pan and add in some oil. Fry the mashed garlic and ginger first and then add in the minced meat and all seasoning. When the meat is cooked, set aside to cool down.", "2", "Get another big bowl. Add in egg, chopped tomato, chopped spring onion and minced meat.", "3", "Get one 2 sheets of filo pastry or 1 sheet spring roll wrap. Brush it with some butter and then put some filling in the middle. Fold the pastry and brush more butter on the seal part.", "4", "Heat a frying pan and add in some oil to cook the parcel until its both sides and 4 edges all turn into golden brown. (Or brush melted butter all over the parcel and bake it in 180°C oven for 10-15 minutes)", "5", "Enjoy"]'::jsonb, 'https://cookpad.com/eng/recipes/14701273?ref=search&search_term=saudi+arabia', 'https://www.themealdb.com/images/media/meals/i5o2b61763739053.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('osso-buco-alla-milanese', 'Osso Buco alla Milanese', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'italian', 'themealdb', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "shanks Veal", "notes": null, "category": "meat"}, {"quantity": 0.5, "unit": "cup", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "chopped into ½-inch pieces Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "into ½-inch pieces Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "into ½-inch pieces Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "chopped into ½-inch pieces Fennel", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Orange Zest", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoons", "item": "Marjoram", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "cup", "item": "Dry White Wine", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "cup", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "cup", "item": "chopped with juice Tomatoes", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "chopped Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "grated  Lemon Zest", "notes": null, "category": "produce"}]'::jsonb, '["Heat the oven to 300 degrees.", "Dredging the shanks: pour the flour into a shallow dish (a pie plate works nicely). Season the veal shanks on all sides with salt and pepper. One at a time, roll the shanks around in the flour coat, and shake and pat the shank to remove any excuses flour. Discard the remaining flour.", "Browning the shanks: put the oil and 1 tablespoon of the butter in a wide Dutch oven or heavy braising pot (6 to 7 quart) and heat over medium-high heat. When the butter has melted and the oil is shimmering, lower the shanks into the pot, flat side down; if the shanks won’t fit without touching one another, do this in batches. Brown the shanks, turning once with tongs, until both flat sides are well caramelized, about 5 minutes per side. If the butter-oil mixture starts to burn, lower the heat just a bit. Transfer the shanks to a large platter or tray and set aside.", "The aromatics: pour off and discard the fat from the pot. Wipe out any burnt bits with a damp paper towel, being careful not to remove any delicious little caramelized bits. Ad the remaining 2 tablespoons butter to the pot and melt it over medium heat. When the butter has stopped foaming, add the onion, carrot, celery, and fennel. Season with salt and pepper, stir, and cook the vegetables until they begin to soften but do not brown, about 6 minutes. Stir in the garlic, orange zest, marjoram, and bay leaf, and stew for another minute or two.", "The braising liquid: add the wine, increase the heat to high, and bring to a boil. Boil, stirring occasionally, to reduce the wine by about half, 5 minutes. Add the stock and tomatoes, with their juice, and boil again to reduce the liquid to about 1 cup total, about 10 minutes.", "The braise: Place the shanks in the pot so that they are sitting with the exposed bone facing up, and pour over any juices that accumulated as they sat. Cover with parchment paper, pressing down so the parchment nearly touches the veal and the edges hang over the sides of the pot by about an inch. Cover tightly with the lid, and slide into the lower part of the oven to braise at a gentle simmer. Check the pot after the first 15 minutes, and if the liquid is simmering too aggressively, lower the oven heat by 10 or 15 degrees. Continue braising, turning the shanks and spooning some pan juices over the top after the first 40 minutes, until the meat is completely tender and pulling away from the bone, about 2 hours.", "The gremolata: While the shanks are braising, stir together the garlic, parsley, and lemon zest in a small bowl. Cover with plastic wrap and set aside in a cool place (or the refrigerator, if your kitchen is very warm.)", "The finish: When the veal is fork-tender and falling away from the bone, remove the lid and sprinkle over half of the gremolata. Return the veal to the oven, uncovered, for another 15 minutes to caramelize it some.", "Using a slotted spatula or spoon, carefully lift the shanks from the braising liquid, doing your best to keep them intact. The shanks will be very tender and threatening to fall into pieces, and the marrow will be wobbly inside the bones, so this can be a bit tricky. But if they do break apart, don’t worry, the flavor won’t suffer at all. Arrange the shanks on a serving platter or other large plate, without stacking, and cover with foil to keep warm.", "Finishing the sauce: Set the braising pot on top of the stove and evaluate the sauce: if there is a visible layer of fat floating on the surface, use a large spoon to skim it off and discard it. Taste the sauce for concentration of flavor. If it tastes a bit weak or flat, bring it to a boil over high heat, and boil to reduce the volume and intensify the flavor for 5 to 10 minutes. Taste again for salt and pepper. If the sauce wants more zip, stir in a teaspoon or two of the remaining gremolata.", "Portioning the veal shanks: if the shanks are reasonably sized, serve one per person. If the shanks are gargantuan or you’re dealing with modest appetites, pull apart the larger shanks, separating them at their natural seams, and serve smaller amounts. Be sure to give the marrow bones to whomever prizes them most.", "Serving: Arrange the veal shanks on warm dinner plates accompanied by the risotto, if serving. Just before carrying the plates to the table, sprinkle on the remaining gremolata and then spoon over a generous amount of sauce – the contact with the hot liquid will aromatize the gremolata and perk up everyone’s appetite with the whiff of garlic and lemon."]'::jsonb, 'https://www.cookstr.com/Meat/Osso-Buco-alla-Milanese', 'https://www.themealdb.com/images/media/meals/wwuqvt1487345467.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pizza-express-margherita', 'Pizza Express Margherita', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'italian', 'themealdb', 'dessert', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 150.0, "unit": "ml", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 15.0, "unit": "g", "item": "Yeast", "notes": null, "category": "pantry"}, {"quantity": 225.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Drizzle Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 80.0, "unit": "g", "item": "Passata", "notes": null, "category": "other"}, {"quantity": 70.0, "unit": "g", "item": "Mozzarella", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Peeled", "notes": "Sliced Oregano", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves Basil", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Black Pepper", "notes": null, "category": "produce"}]'::jsonb, '["1 Preheat the oven to 230°C.", "2 Add the sugar and crumble the fresh yeast into warm water.", "3 Allow the mixture to stand for 10 – 15 minutes in a warm place (we find a windowsill on a sunny day works best) until froth develops on the surface.", "4 Sift the flour and salt into a large mixing bowl, make a well in the middle and pour in the yeast mixture and olive oil.", "5 Lightly flour your hands, and slowly mix the ingredients together until they bind.", "6 Generously dust your surface with flour.", "7 Throw down the dough and begin kneading for 10 minutes until smooth, silky and soft.", "8 Place in a lightly oiled, non-stick baking tray (we use a round one, but any shape will do!)", "9 Spread the passata on top making sure you go to the edge.", "10 Evenly place the mozzarella (or other cheese) on top, season with the oregano and black pepper, then drizzle with a little olive oil.", "11 Cook in the oven for 10 – 12 minutes until the cheese slightly colours.", "12 When ready, place the basil leaf on top and tuck in!"]'::jsonb, 'https://www.dailymail.co.uk/femail/food/article-8240361/Pizza-Express-release-secret-recipe-Margherita-Pizza-make-home.html', 'https://www.themealdb.com/images/media/meals/x0lk931587671540.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('poutine', 'Poutine', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'canadian', 'themealdb'], '[{"quantity": 1.0, "unit": "serving", "item": "Dash Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "can", "item": "Beef Gravy", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "cut Potatoes", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "Cheese Curds", "notes": null, "category": "dairy"}]'::jsonb, '["Heat oil in a deep fryer or deep heavy skillet to 365°F (185°C).", "Warm gravy in saucepan or microwave.", "Place the fries into the hot oil, and cook until light brown, about 5 minutes.", "Remove to a paper towel lined plate to drain.", "Place the fries on a serving platter, and sprinkle the cheese over them.", "Ladle gravy over the fries and cheese, and serve immediately."]'::jsonb, 'http://www.food.com/recipe/real-canadian-poutine-113388', 'https://www.themealdb.com/images/media/meals/uuyrrx1487327597.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('purple-sprouting-broccoli-tempura-with-nuoc-cham', 'Purple sprouting broccoli tempura with nuoc cham', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'vietnamese', 'themealdb', 'dessert', 'baking'], '[{"quantity": 50.0, "unit": "g", "item": "Corn Flour", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Sesame Seed", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "ml", "item": "Soda Water", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "Purple Sprouting Broccoli", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 2 Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Birds-eye Chillies", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "For the nuoc cham, whisk together all of the ingredients with 5 tbsp hot water in a small bowl. Set aside while you make the tempura.", "step 2", "Whisk the cornflour, plain flour, sesame seeds (if using) and a large pinch of salt together. Fill a large, deep pan no more than a third full with the vegetable oil and heat until it reaches 180C or a cube of bread dropped in browns in 20 seconds.", "step 3", "Quickly whisk the soda water into the flour mixture, being careful not to overmix, then dunk in the broccoli using tongs. Carefully lower into the hot oil and cook for 2-3 mins until crisp. Drain on kitchen paper, then serve with the nuoc cham on the side for dipping."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/purple-sprouting-broccoli-tempura-with-nuoc-cham', 'https://www.themealdb.com/images/media/meals/xnv4wf1763756529.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ramen-noodles-with-boiled-egg', 'Ramen Noodles with Boiled Egg', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'chinese', 'themealdb', 'soup', 'pasta', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Noodles", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbsp", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Chilli Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tbs", "item": "Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Boil: Bring water to a boil, gently add eggs, and cook for exactly 6½ to 7 minutes.", "Ice Bath: Immediately transfer the eggs to a bowl of ice water for 3–5 minutes to stop cooking.", "Marinate (Optional but recommended): Peel the eggs and marinate in a mix of 2 tbsp soy sauce, 2 tbsp mirin, 1 tsp sugar, and 4 tbsp water for at least 4 hours (or overnight).", "Serve: Slice in half, letting the yolk flow into the broth"]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/ip5xtp1769779958.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('shakshouka', 'Shakshouka', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'saudi arabian', 'themealdb', 'vegetarian'], '[{"quantity": 250.0, "unit": "g", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 40.0, "unit": "ml", "item": "Extra Virgin Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}]'::jsonb, '["1", "First, pan fry the black pepper and garlic over a dry medium heat until fragrant.", "2", "Add a good amount of extra virgin olive oil and infuse for a minute.", "3", "Once the oil heats up, add the tomatoes and salt, and cover with a lid. Simmer for 5 minutes.", "4", "Remove the lid and mash the tomatoes. Reduce until you reach the desired consistency of choice.", "5", "Make craters for the eggs and lower the heat. Carefully crack the eggs into the craters, making sure it touches the pan and not the tomato sauce.", "6", "Cover the eggs and leave it for 5 minutes without lifting the lid.", "7", "Remove from the heat and let the residual heat steam the eggs for 1-2 minutes.", "8", "Serve with flatbread. Enjoy!"]'::jsonb, 'https://cookpad.com/eng/recipes/24999905?ref=search&search_term=saudi+arabia', 'https://www.themealdb.com/images/media/meals/crd1jz1763592990.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('shakshuka-feta-cheese', 'Shakshuka Feta Cheese', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'saudi arabian', 'themealdb', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Tomato Sauce", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 1.0, "unit": "cup", "item": "Spinach", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Feta", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Black Pepper", "notes": null, "category": "produce"}]'::jsonb, '["1", "In a pan heat the oil medium to high heat, with a tablespoon of olive oil", "2", "Add the chopped vegetables as onions, garlic, celery and red pepper. Stir all together for 5 mins.", "3", "Add the cumin powder and salt and pepper and the tomato sauce and let it cook for another 7 mins.", "4", "Add the eggs, cover and leave to coo for 8 mins. Add the fresh spinach and feta cheese at the end.", "5", "Serve with fresh bread."]'::jsonb, 'https://cookpad.com/eng/recipes/22551672?ref=search&search_term=saudi+arabia', 'https://www.themealdb.com/images/media/meals/wpkfin1763597958.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spanish-meatballs-with-clams-chorizo-squid', 'Spanish meatballs with clams, chorizo & squid', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'spanish', 'themealdb'], '[{"quantity": 25.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Smoked Paprika", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "finely", "notes": "chopped Garlic", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Dry sherry", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 300.0, "unit": "g", "item": "Pork", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "ml", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 300.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 300.0, "unit": "g", "item": "Squid", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "ml", "item": "White Wine", "notes": null, "category": "other"}, {"quantity": 300.0, "unit": "g", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Clams", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Drizzle Extra Virgin Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Melt the butter in a heavy-based casserole, then soften the shallots for 5 mins. Add the paprika and crushed garlic and cook for 1 min until the paprika becomes fragrant. Splash in the sherry, then pour the whole lot into a bowl with the breadcrumbs. Season and cool.", "step 2", "Add the pork mince and the egg yolk to the bowl, then beat well. Shape into 18 small meatballs. Wipe the pan, put on a medium-high heat, then add the oil. Fry the meatballs for 5 mins, just to colour, then lift onto a plate, but keep the oil in the pan. Sizzle the chorizo with the sliced garlic. Add the squid and fry to give a little colour. Now tip in the white wine and bring to the boil, scraping the bottom. Stir in the pulped tomatoes, bring to the boil, then add the meatballs and the clams. Cover and cook for 5 mins until the clam shells open. Discard any that stay shut. Sprinkle with the chopped parsley, drizzle with the extra virgin oil, then serve with crusty bread."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/spanish-meatballs-clams-chorizo-squid', 'https://www.themealdb.com/images/media/meals/2wt8721763334199.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('syrian-bread', 'Syrian Bread', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'syrian', 'themealdb', 'dessert', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 0.125, "unit": "cup", "item": "1/8 cup Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "cups", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.5, "unit": "tsp", "item": "Yeast", "notes": null, "category": "pantry"}]'::jsonb, '["Place ingredients in the pan of the bread machine in the order recommended by the manufacturer. Select Dough cycle; press Start.", "When the Dough cycle is almost complete, preheat the oven to 475 degrees F (245 degrees C).", "Turn dough out onto a lightly floured surface. Divide into eight equal pieces and form into rounds. Cover the rounds with a damp cloth and let rest.", "Roll dough into thin flat circles, about 8 inches in diameter. Cook two at a time on preheated baking sheets or a baking stone until puffed up and golden brown, about 5 minutes. Repeat for remaining loaves."]'::jsonb, 'https://www.allrecipes.com/recipe/20834/syrian-bread/', 'https://www.themealdb.com/images/media/meals/54xzk31760524666.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('syrian-rice-with-meat', 'Syrian Rice with Meat', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'syrian', 'themealdb', 'soup'], '[{"quantity": 0.25, "unit": "cup", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "pounds", "item": "Ground Beef", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "teaspoons", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 5.0, "unit": "cups", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "cups", "item": "Rice", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Pine Nuts", "notes": null, "category": "pantry"}]'::jsonb, '["Heat 1/4 cup butter in a large saucepan over medium-high heat. Add ground beef and season with salt, allspice, cinnamon, and black pepper. Cook and stir until beef is browned and crumbly, 7 to 10 minutes.", "Stir chicken broth and rice into beef in the saucepan; bring to a boil. Reduce heat to low, cover, and cook until liquid is absorbed, about 20 minutes.", "Meanwhile, melt 2 tablespoons butter in a small skillet over medium heat. Cook and stir pine nuts in hot butter until lightly browned, 3 to 5 minutes.", "Mix pine nuts into beef-rice mixture before serving."]'::jsonb, 'https://www.allrecipes.com/recipe/272233/syrian-rice-with-meat/', 'https://www.themealdb.com/images/media/meals/zg2b9l1760524940.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('three-cheese-souffles', 'Three-cheese souffles', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'french', 'themealdb', 'baking', 'vegetarian'], '[{"quantity": 50.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 25.0, "unit": "g", "item": "Parmesan", "notes": null, "category": "dairy"}, {"quantity": 300.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 5.0, "unit": "tbs", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "tsp", "item": "English Mustard", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pod of Cayenne Pepper", "notes": null, "category": "produce"}, {"quantity": 140.0, "unit": "g", "item": "Gruyère", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 8.0, "unit": "slices", "item": "Goats Cheese", "notes": null, "category": "dairy"}, {"quantity": 150.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Spinach", "notes": null, "category": "produce"}]'::jsonb, '["Heat oven to 200C/180C fan/ gas 6 and butter 4 small (about 200ml) ramekins. Sprinkle the Parmesan into the ramekins, turning until all sides are covered. Place the milk and bay leaves in a large saucepan over a gentle heat and bring to the boil. Turn off the heat and leave to infuse for 15 mins.", "Discard the bay leaves, add the butter and flour, and return to a low heat. Very gently simmer, stirring continuously with a balloon whisk, for about 6 mins until you get a smooth, thick white sauce. Make sure that you get right into the corners of the pan to stop the sauce from catching or becoming lumpy.", "Once thickened, transfer the sauce to a large bowl and stir in the mustard powder, cayenne pepper, Gruyère and egg yolks until fully combined.", "In a spotlessly clean bowl and with a clean whisk, beat the egg whites just until peaks begin to form.", "Carefully fold the egg whites into the cheese sauce in three stages making sure you fold, rather than stir, to keep the egg whites light and airy. Fill the prepared ramekins with the soufflé mix.", "Top each soufflé with a slice of goat’s cheese, then place on a baking tray. Bake for 20-25 mins or until springy and well risen but cooked through.", "Leave to cool, then run a knife around the edge of each dish and remove the soufflés. If preparing in advance, place soufflés upside down (for neat presentation), on a tray. Cover tray in cling film. Chill for a few days or freeze for up to 1 month.", "When ready to re-bake, heat oven to 200C/180C fan/gas 6. Place the upside-down soufflés in a shallow baking dish, top with the remaining goat’s cheese slices and pour over the cream (this stops them from drying out when baked for the second time). Cook for 8-10 mins until golden. Serve immediately alongside some simply dressed salad."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/3028701/threecheese-souffls', 'https://www.themealdb.com/images/media/meals/sxwquu1511793428.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('turkey-bánh-mì', 'Turkey Bánh mì', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'vietnamese', 'themealdb', 'dessert'], '[{"quantity": 1.0, "unit": "serving", "item": "Baguette", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Chicken Liver", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "1/4  Cucumber", "notes": null, "category": "produce"}, {"quantity": 140.0, "unit": "g", "item": "Turkey", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Mayonnaise", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Mint", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 75.0, "unit": "g", "item": "Red Cabbage", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "Ground Ginger", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tablespoon", "item": "Rice Vinegar", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Golden Caster Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "To make the pickled slaw, tip the carrots and cabbage into a large bowl. In a small bowl, combine the ginger, rice vinegar, sugar and a few pinches of salt. Pour over the vegetables and toss together. Set aside for at least 15 mins.", "step 2", "Halve the baguettes lengthways and spread the pâté over the bottom half. Top with the pickled slaw, cucumber and turkey. Mix the mayonnaise with the chopped chilli and dollop over the top. Scatter over the mint leaves and sliced chilli. Sandwich together and dig in."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/turkey-banh-mi', 'https://www.themealdb.com/images/media/meals/1wj8w31763781990.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('turkey-meatloaf', 'Turkey Meatloaf', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'british', 'themealdb', 'baking', 'grilling'], '[{"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Worcestershire Sauce", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tsp", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "g", "item": "Turkey Mince", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 85.0, "unit": "g", "item": "Breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Barbeque Sauce", "notes": null, "category": "other"}, {"quantity": 800.0, "unit": "g", "item": "Cannellini Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Parsley", "notes": null, "category": "produce"}]'::jsonb, '["Heat oven to 180C/160C fan/gas 4. Heat the oil in a large frying pan and cook the onion for 8-10 mins until softened. Add the garlic, Worcestershire sauce and 2 tsp tomato purée, and stir until combined. Set aside to cool.", "Put the turkey mince, egg, breadcrumbs and cooled onion mix in a large bowl and season well. Mix everything to combine, then shape into a rectangular loaf and place in a large roasting tin. Spread 2 tbsp barbecue sauce over the meatloaf and bake for 30 mins.", "Meanwhile, drain 1 can of beans only, then pour both cans into a large bowl. Add the remaining barbecue sauce and tomato purée. Season and set aside.", "When the meatloaf has had its initial cooking time, scatter the beans around the outside and bake for 15 mins more until the meatloaf is cooked through and the beans are piping hot. Scatter over the parsley and serve the meatloaf in slices."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/turkey-meatloaf', 'https://www.themealdb.com/images/media/meals/ypuxtw1511297463.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('turkish-rice-vermicelli-rice', 'Turkish rice (vermicelli rice)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'turkish', 'themealdb', 'soup', 'pasta'], '[{"quantity": 300.0, "unit": "g", "item": "Rice", "notes": null, "category": "grains"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 70.0, "unit": "g", "item": "Vermicelli Pasta", "notes": null, "category": "grains"}, {"quantity": 30.0, "unit": "g", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 600.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}]'::jsonb, '["step 1", "Pour the rice into a very large bowl under cold running water and carefully drain the water out of the bowl through a sieve. Repeat a few times until the water in the bowl is clear, then fill the bowl up with cold water and leave rice to soak for 10 mins while you cook the vermicelli.", "step 2", "Put the oil into a medium pan over medium heat. Add the vermicelli and stir continuously until the strands turn a rich golden brown, 2-3 mins. Remove from the heat, stir through the butter until it melts and allow the vermicelli to cool for 1-2 mins.", "step 3", "Drain the rice thoroughly through a sieve. Add the rice to the pan and stir well. Pour the hot stock into the pan, sprinkle in ½ tsp salt, stir well then return the pan to the hob over a high heat. Bring to the boil, then reduce the heat to the lowest it will go, put the lid on the pan and simmer for 7-9 mins. Remove the pan from the heat, cover with a couple of sheets of kitchen paper or a light tea towel and the pan lid, and let the rice sit in the pan for 10 mins. Fluff up with a fork before serving."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/turkish-rice-vermicelli-rice', 'https://www.themealdb.com/images/media/meals/xw1ruy1763786501.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('yorkshire-puddings', 'Yorkshire Puddings', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['miscellaneous', 'british', 'themealdb', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 140.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Drizzle Sunflower Oil", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Heat oven to 230C/fan 210C/gas 8.", "step 2", "Drizzle a little sunflower oil evenly into two 4-hole Yorkshire pudding tins or two 12-hole non-stick muffin tins and place in the oven to heat through.", "step 3", "To make the batter, tip 140g plain flour into a bowl and beat in 4 eggs until smooth.", "step 4", "Gradually add 200ml milk and carry on beating until the mix is completely lump-free. Season with salt and pepper.", "step 5", "Pour the batter into a jug, then remove the hot tins from the oven. Carefully and evenly pour the batter into the holes.", "step 6", "Place the tins back in the oven and leave undisturbed for 20-25 mins until the puddings have puffed up and browned.", "step 7", "Serve immediately. You can now cool them and freeze for up to 1 month."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/best-yorkshire-puddings', 'https://www.themealdb.com/images/media/meals/x5qz5k1761595900.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chilli-prawn-linguine', 'Chilli prawn linguine', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pasta', 'italian', 'themealdb', 'dessert', 'salad', 'vegetarian', 'vegan'], '[{"quantity": 280.0, "unit": "g", "item": "Linguine Pasta", "notes": null, "category": "grains"}, {"quantity": 200.0, "unit": "g", "item": "Sugar Snap Peas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "cloves", "item": "chopped Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "King Prawns", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Basil Leaves", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves Lettuce", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Bread", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tbsp", "item": "Fromage Frais", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Grated Zest of 2 Lime", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Caster Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["Mix the dressing ingredients in a small bowl and season with salt and pepper. Set aside.", "Cook the pasta according to the packet instructions. Add the sugar snap peas for the last minute or so of cooking time.", "Meanwhile, heat the oil in a wok or large frying pan, toss in the garlic and chilli and cook over a fairly gentle heat for about 30 seconds without letting the garlic brown. Tip in the prawns and cook over a high heat, stirring frequently, for about 3 minutes until they turn pink.", "Add the tomatoes and cook, stirring occasionally, for 3 minutes until they just start to soften. Drain the pasta and sugar snaps well, then toss into the prawn mixture. Tear in the basil leaves, stir, and season with salt and pepper.", "Serve with salad leaves drizzled with the lime dressing, and warm crusty bread."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/1269/chilli-prawn-linguine', 'https://www.themealdb.com/images/media/meals/usywpp1511189717.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fettuccine-alfredo', 'Fettuccine Alfredo', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pasta', 'italian', 'themealdb', 'vegetarian'], '[{"quantity": 1.0, "unit": "lb", "item": "Fettuccine", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "cup", "item": "Heavy Cream", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Parmesan", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbsp", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Black Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Cook pasta according to package instructions in a large pot of boiling water and salt.", "Add heavy cream and butter to a large skillet over medium heat until the cream bubbles and the butter melts.", "Whisk in parmesan and add seasoning (salt and black pepper).", "Let the sauce thicken slightly and then add the pasta and toss until coated in sauce.", "Garnish with parsley, and it''s ready."]'::jsonb, 'https://www.delish.com/cooking/recipe-ideas/a55312/best-homemade-fettuccine-alfredo-recipe/', 'https://www.themealdb.com/images/media/meals/0jv5gx1661040802.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fettucine-alfredo', 'Fettucine alfredo', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pasta', 'italian', 'themealdb', 'baking', 'vegetarian'], '[{"quantity": 227.0, "unit": "g", "item": "Clotted Cream", "notes": null, "category": "dairy"}, {"quantity": 25.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Corn Flour", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Parmesan Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Grated Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Fettuccine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Parsley", "notes": null, "category": "produce"}]'::jsonb, '["In a medium saucepan, stir the clotted cream, butter and cornflour over a low-ish heat and bring to a low simmer. Turn off the heat and keep warm.", "Meanwhile, put the cheese and nutmeg in a small bowl and add a good grinding of black pepper, then stir everything together (don’t add any salt at this stage).", "Put the pasta in another pan with 2 tsp salt, pour over some boiling water and cook following pack instructions (usually 3-4 mins). When cooked, scoop some of the cooking water into a heatproof jug or mug and drain the pasta, but not too thoroughly.", "Add the pasta to the pan with the clotted cream mixture, then sprinkle over the cheese and gently fold everything together over a low heat using a rubber spatula. When combined, splash in 3 tbsp of the cooking water. At first, the pasta will look wet and sloppy: keep stirring until the water is absorbed and the sauce is glossy. Check the seasoning before transferring to heated bowls. Sprinkle over some chives or parsley, then serve immediately."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/fettucine-alfredo', 'https://www.themealdb.com/images/media/meals/uquqtu1511178042.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('grilled-mac-and-cheese-sandwich', 'Grilled Mac and Cheese Sandwich', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pasta', 'american', 'themealdb', 'baking', 'grilling', 'vegetarian'], '[{"quantity": 8.0, "unit": "ounces", "item": "Macaroni", "notes": null, "category": "other"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 0.75, "unit": "teaspoon", "item": "Mustard Powder", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Garlic powder", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Kosher salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Black pepper", "notes": null, "category": "produce"}, {"quantity": 0.125, "unit": "teaspoon", "item": "Cayenne pepper", "notes": null, "category": "produce"}, {"quantity": 85.0, "unit": "grams", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.5, "unit": "cups", "item": "Whole Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "cup", "item": "Heavy Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "pound", "item": "Monterey Jack Cheese", "notes": null, "category": "dairy"}, {"quantity": 55.0, "unit": "grams", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "garlic powder", "notes": null, "category": "produce"}, {"quantity": 16.0, "unit": "slices", "item": "square Bread", "notes": null, "category": "grains"}, {"quantity": 8.0, "unit": "slices", "item": "mild Cheddar Cheese", "notes": null, "category": "dairy"}, {"quantity": 8.0, "unit": "slices", "item": "Colby Jack Cheese", "notes": null, "category": "dairy"}, {"quantity": 55.0, "unit": "grams", "item": "Butter", "notes": null, "category": "dairy"}]'::jsonb, '["Make the mac and cheese", "1. Bring a medium saucepan of generously salted water (you want it to taste like seawater) to a boil. Add the pasta and cook, stirring occasionally, until al dente, 8 to 10 minutes, or according to the package directions. The pasta should be tender but still chewy.", "2. While the pasta is cooking, in a small bowl, whisk together the flour, mustard powder, garlic powder, salt, black pepper, and cayenne pepper.", "3. Drain the pasta in a colander. Place the empty pasta pan (no need to wash it) over low heat and add the butter. When the butter has melted, whisk in the flour mixture and continue to cook, whisking frequently, until the mixture is beginning to brown and has a pleasant, nutty aroma, about 1 minute. Watch carefully so it does not scorch on the bottom of the pan.", "4. Slowly whisk the milk and cream into the flour mixture until everything is really well combined. Cook, whisking constantly, until the sauce is heated through and just begins to thicken, about 2 minutes. Remove from the heat. Gradually add the cheese while stirring constantly with a wooden spoon or silicone spatula and keep stirring until the cheese has melted into the sauce. Then stir in the drained cooked pasta.", "5. Line a 9-by-13-inch (23-by-33-centimeter) rimmed baking sheet with parchment paper or aluminum foil. Coat the paper or foil with nonstick cooking spray or slick it with butter. Pour the warm mac and cheese onto the prepared baking sheet and spread it evenly with a spatula. Coat another piece of parchment paper with cooking spray or butter and place it, oiled or buttered side down, directly on the surface of the mac and cheese. Refrigerate until cool and firm, about 1 hour.", "Make the grilled cheese", "6. Heat a large cast-iron or nonstick skillet over medium-low heat.", "7. In a small bowl, stir together the 4 tablespoons (55 grams) butter and garlic powder until well blended.", "8. Remove the mac and cheese from the refrigerator and peel off the top layer of parchment paper. Carefully cut into 8 equal pieces. Each piece will make 1 grilled mac and cheese sandwich. (You can stash each individual portion in a double layer of resealable plastic bags and refrigerate for up to 3 days or freeze it for up to 1 month.)", "9. Spread 3/4 teaspoon garlic butter on one side of each bread slice. Place half of the slices, buttered-side down, on a clean cutting board. Top each with one slice of Cheddar, then 1 piece of the mac and cheese. (Transfer from the baking sheet by scooting your hand or a spatula under each piece of mac and cheese and then flipping it over onto a sandwich.) Place 1 slice of Jack on top of each. Finish with the remaining bread slices, buttered-side up.", "10. Using a wide spatula, place as many sandwiches in the pan as will fit without crowding it. Cover and cook until the bottoms are nicely browned, about 4 minutes. Turn and cook until the second sides are browned, the cheese is melted, and the mac and cheese is heated through, about 4 minutes more.", "11. Repeat with the remaining ingredients. Cut the sandwiches in half, if desired, and serve."]'::jsonb, 'https://leitesculinaria.com/103647/recipes-grilled-mac-and-cheese-sandwich.html', 'https://www.themealdb.com/images/media/meals/xutquv1505330523.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lasagna-sandwiches', 'Lasagna Sandwiches', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pasta', 'american', 'themealdb', 'breakfast'], '[{"quantity": 0.25, "unit": "cup", "item": "Sour Cream", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "Chopped Onion", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tbs", "item": "Dried Oregano", "notes": null, "category": "spices"}, {"quantity": 0.25, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 8.0, "unit": "slices", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 8.0, "unit": "slices", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 8.0, "unit": "slices", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "slices", "item": "Mozzarella", "notes": null, "category": "dairy"}, {"quantity": 2.5, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}]'::jsonb, '["1. In a small bowl, combine the first four ingredients; spread on four slices of bread. Layer with bacon, tomato and cheese; top with remaining bread.", "2. In a large skillet or griddle, melt 2 tablespoons butter. Toast sandwiches until lightly browned on both sides and cheese is melted, adding butter if necessary.", "Nutrition Facts", "1 sandwich: 445 calories, 24g fat (12g saturated fat), 66mg cholesterol, 1094mg sodium, 35g carbohydrate (3g sugars, 2g fiber), 21g protein."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/xr0n4r1576788363.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lasagne', 'Lasagne', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pasta', 'italian', 'themealdb', 'breakfast', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "chopped  Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "g", "item": "Minced Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 800.0, "unit": "g", "item": "Chopped Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Honey", "notes": null, "category": "pantry"}, {"quantity": 500.0, "unit": "g", "item": "Lasagne Sheets", "notes": null, "category": "other"}, {"quantity": 400.0, "unit": "ml", "item": "Creme Fraiche", "notes": null, "category": "other"}, {"quantity": 125.0, "unit": "g", "item": "Mozzarella Balls", "notes": null, "category": "dairy"}, {"quantity": 50.0, "unit": "g", "item": "Parmesan Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Topping Basil Leaves", "notes": null, "category": "produce"}]'::jsonb, '["Heat the oil in a large saucepan. Use kitchen scissors to snip the bacon into small pieces, or use a sharp knife to chop it on a chopping board. Add the bacon to the pan and cook for just a few mins until starting to turn golden. Add the onion, celery and carrot, and cook over a medium heat for 5 mins, stirring occasionally, until softened.", "Add the garlic and cook for 1 min, then tip in the mince and cook, stirring and breaking it up with a wooden spoon, for about 6 mins until browned all over.", "Stir in the tomato purée and cook for 1 min, mixing in well with the beef and vegetables. Tip in the chopped tomatoes. Fill each can half full with water to rinse out any tomatoes left in the can, and add to the pan. Add the honey and season to taste. Simmer for 20 mins.", "Heat oven to 200C/180C fan/gas 6. To assemble the lasagne, ladle a little of the ragu sauce into the bottom of the roasting tin or casserole dish, spreading the sauce all over the base. Place 2 sheets of lasagne on top of the sauce overlapping to make it fit, then repeat with more sauce and another layer of pasta. Repeat with a further 2 layers of sauce and pasta, finishing with a layer of pasta.", "Put the crème fraîche in a bowl and mix with 2 tbsp water to loosen it and make a smooth pourable sauce. Pour this over the top of the pasta, then top with the mozzarella. Sprinkle Parmesan over the top and bake for 25–30 mins until golden and bubbling. Serve scattered with basil, if you like."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/classic-lasagne', 'https://www.themealdb.com/images/media/meals/wtsvxx1511296896.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pilchard-puttanesca', 'Pilchard puttanesca', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pasta', 'italian', 'themealdb', 'vegetarian', 'vegan'], '[{"quantity": 300.0, "unit": "g", "item": "Spaghetti", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "chopped  Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 425.0, "unit": "g", "item": "Pilchards", "notes": null, "category": "produce"}, {"quantity": 70.0, "unit": "g", "item": "Black Olives", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Shaved Parmesan", "notes": null, "category": "dairy"}]'::jsonb, '["Cook the pasta following pack instructions. Heat the oil in a non-stick frying pan and cook the onion, garlic and chilli for 3-4 mins to soften. Stir in the tomato purée and cook for 1 min, then add the pilchards with their sauce. Cook, breaking up the fish with a wooden spoon, then add the olives and continue to cook for a few more mins.", "Drain the pasta and add to the pan with 2-3 tbsp of the cooking water. Toss everything together well, then divide between plates and serve, scattered with Parmesan."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/pilchard-puttanesca', 'https://www.themealdb.com/images/media/meals/vvtvtr1511180578.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spaghetti-alla-carbonara', 'Spaghetti alla Carbonara', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pasta', 'italian', 'themealdb', 'breakfast'], '[{"quantity": 320.0, "unit": "g", "item": "Spaghetti", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "As required Salt", "notes": null, "category": "pantry"}, {"quantity": 150.0, "unit": "g", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 50.0, "unit": "g", "item": "Pecorino", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "As required Black Pepper", "notes": null, "category": "produce"}]'::jsonb, '["STEP 1", "Put a large saucepan of water on to boil.", "STEP 2", "Finely chop the 100g pancetta, having first removed any rind. Finely grate 50g pecorino cheese and 50g parmesan and mix them together.", "STEP 3", "Beat the 3 large eggs in a medium bowl and season with a little freshly grated black pepper. Set everything aside.", "STEP 4", "Add 1 tsp salt to the boiling water, add 350g spaghetti and when the water comes back to the boil, cook at a constant simmer, covered, for 10 minutes or until al dente (just cooked).", "STEP 5", "Squash 2 peeled plump garlic cloves with the blade of a knife, just to bruise it.", "STEP 6", "While the spaghetti is cooking, fry the pancetta with the garlic. Drop 50g unsalted butter into a large frying pan or wok and, as soon as the butter has melted, tip in the pancetta and garlic.", "STEP 7", "Leave to cook on a medium heat for about 5 minutes, stirring often, until the pancetta is golden and crisp. The garlic has now imparted its flavour, so take it out with a slotted spoon and discard.", "STEP 8", "Keep the heat under the pancetta on low. When the pasta is ready, lift it from the water with a pasta fork or tongs and put it in the frying pan with the pancetta. Don’t worry if a little water drops in the pan as well (you want this to happen) and don’t throw the pasta water away yet.", "STEP 9", "Mix most of the cheese in with the eggs, keeping a small handful back for sprinkling over later.", "STEP 10", "Take the pan of spaghetti and pancetta off the heat. Now quickly pour in the eggs and cheese. Using the tongs or a long fork, lift up the spaghetti so it mixes easily with the egg mixture, which thickens but doesn’t scramble, and everything is coated.", "STEP 11", "Add extra pasta cooking water to keep it saucy (several tablespoons should do it). You don’t want it wet, just moist. Season with a little salt, if needed.", "STEP 12", "Use a long-pronged fork to twist the pasta on to the serving plate or bowl. Serve immediately with a little sprinkling of the remaining cheese and a grating of black pepper. If the dish does get a little dry before serving, splash in some more hot pasta water and the glossy sauciness will be revived."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/ultimate-spaghetti-carbonara-recipe', 'https://www.themealdb.com/images/media/meals/llcbn01574260722.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('syrian-spaghetti', 'Syrian Spaghetti', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pasta', 'syrian', 'themealdb', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 16.0, "unit": "ounces", "item": "Spaghetti", "notes": null, "category": "grains"}, {"quantity": 8.0, "unit": "ounces", "item": "Tomato Sauce", "notes": null, "category": "produce"}, {"quantity": 6.0, "unit": "oz", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 0.25, "unit": "cup", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Preheat oven to 350 degrees F (175 degrees C). Grease a 9x13 inch baking dish.", "Bring a large pot of lightly salted water to a boil. Add spaghetti and cook for 8 to 10 minutes or until al dente; drain and stir in tomato sauce, tomato paste, cinnamon, oil, salt and pepper. Transfer to prepared dish.", "Bake in preheated oven for 1 hour, or until top is crunchy."]'::jsonb, 'https://www.allrecipes.com/recipe/26303/syrian-spaghetti/', 'https://www.themealdb.com/images/media/meals/5fu4ew1760524857.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('venetian-duck-ragu', 'Venetian Duck Ragu', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pasta', 'italian', 'themealdb', 'dessert', 'soup', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Legs", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Onions", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "ground Cinnamon", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tsp", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 250.0, "unit": "ml", "item": "Red Wine", "notes": null, "category": "other"}, {"quantity": 800.0, "unit": "g", "item": "Chopped Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Stock Cube", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Rosemary", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 600.0, "unit": "g", "item": "Paccheri Pasta", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Grated Parmesan Cheese", "notes": null, "category": "dairy"}]'::jsonb, '["Heat the oil in a large pan. Add the duck legs and brown on all sides for about 10 mins. Remove to a plate and set aside. Add the onions to the pan and cook for 5 mins until softened. Add the garlic and cook for a further 1 min, then stir in the cinnamon and flour and cook for a further min. Return the duck to the pan, add the wine, tomatoes, stock, herbs, sugar and seasoning. Bring to a simmer, then lower the heat, cover with a lid and cook for 2 hrs, stirring every now and then.", "Carefully lift the duck legs out of the sauce and place on a plate – they will be very tender so try not to lose any of the meat. Pull off and discard the fat, then shred the meat with 2 forks and discard the bones. Add the meat back to the sauce with the milk and simmer, uncovered, for a further 10-15 mins while you cook the pasta.", "Cook the pasta following pack instructions, then drain, reserving a cup of the pasta water, and add the pasta to the ragu. Stir to coat all the pasta in the sauce and cook for 1 min more, adding a splash of cooking liquid if it looks dry. Serve with grated Parmesan, if you like."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/venetian-duck-ragu', 'https://www.themealdb.com/images/media/meals/qvrwpt1511181864.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bubble-squeak', ' Bubble & Squeak', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'british', 'themealdb', 'breakfast'], '[{"quantity": 1.0, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "sliced Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sprouts", "notes": null, "category": "other"}, {"quantity": 400.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}]'::jsonb, '["Melt the fat in a non-stick pan, allow it to get nice and hot, then add the bacon. As it begins to brown, add the onion and garlic. Next, add the sliced sprouts or cabbage and let it colour slightly. All this will take 5-6 mins.", "Next, add the potato. Work everything together in the pan and push it down so that the mixture covers the base of the pan – allow the mixture to catch slightly on the base of the pan before turning it over and doing the same again. It’s the bits of potato that catch in the pan that define the term ‘bubble and squeak’, so be brave and let the mixture colour. Cut into wedges and serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/164622/bubble-and-squeak', 'https://www.themealdb.com/images/media/meals/xusqvw1511638311.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('arroz-al-horno-baked-rice', 'Arroz al horno (baked rice)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'spanish', 'themealdb', 'breakfast', 'soup', 'baking'], '[{"quantity": 2.0, "unit": "tbsp", "item": "Extra Virgin Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 800.0, "unit": "g", "item": "Pork belly slices", "notes": null, "category": "meat"}, {"quantity": 150.0, "unit": "g", "item": "Black Pudding", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Bacon lardon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Plum Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 4.0, "unit": "teaspoons", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Chilli Flakes", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "Dried white beans", "notes": null, "category": "pantry"}, {"quantity": 1.5, "unit": "l", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 375.0, "unit": "g", "item": "Paella Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Juice", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Heat oven to 200C/180C/gas 6. Heat half the oil in a deep frying or sauté pan (or shallow casserole dish) measuring around 30cm in diameter. Over a high heat, colour the pork belly slices on each side in several batches, then transfer to a bowl. Add the remaining oil to the pan and lower the heat to medium, then add the black pudding and bacon and fry all over for several mins. Remove with a slotted spoon. Fry the onion and peppers for around 10 mins until soft and pale gold, then add the tomato and cook until soft. Add the garlic, smoked paprika and chilli flakes and cook for another 2 mins, then put the pork, black pudding and bacon back in the pan. Add the beans, stock and whichever herb you''re using, and bring everything to the boil.", "step 2", "Sprinkle the rice around the pork belly, pushing it underneath the stock. Let the stock come to the boil again, season well, then transfer to the oven (leave it uncovered). Cook for 20 mins without stirring, then check to see how the rice is doing. The rice should be tender and the stock absorbed. If it’s not ready, put back in the oven for another 5 mins, then check again. Taste for seasoning.", "step 3", "Squeeze lemon juice over the top and drizzle over some extra virgin olive oil just before serving, if you like."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/arroz-al-horno-baked-rice', 'https://www.themealdb.com/images/media/meals/qt4i0n1763256454.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('barbecue-pork-buns', 'Barbecue pork buns', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'vietnamese', 'themealdb', 'dessert', 'breakfast', 'baking', 'grilling'], '[{"quantity": 85.0, "unit": "g", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 500.0, "unit": "g", "item": "White Bread Mix", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Knob Ginger", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Clear Honey", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}]'::jsonb, '["step 1", "Heat the oven to 200C/fan 180C/gas. Mix the sugar into the bread mix in a large bowl, then add water as instructed on the pack. Bring the dough together with a wooden spoon, then knead on a lightly floured surface for 5 mins until smooth. Put into a large bowl, cover with oiled cling film then leave in a warm place until doubled in size.", "step 2", "Meanwhile, heat the oil in a pan, then fry the bacon until crisp, about 5 mins. Add the ginger and garlic and fry for 1 min until soft, then tip in the soy, honey and tomato purée and stir well. Can be made up to 3 days ahead.", "step 3", "Turn out the dough and knead briefly, then pull into 12 even-sized balls. Flatten with your hands, then put a teaspoon-size blob of the filling in the middle. Draw the dough up and pinch it closed like a purse, then turn the bun over and sit it on a large baking sheet. Cover with oiled cling film and leave to rise for about 30 mins until the dough feels pillowy. Brush with egg and bake for 20 mins until golden. Serve warm with dipping sauce. Can be frozen after second rise for up to 1 month or baked up to a day ahead and re-warmed."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/barbecue-pork-buns', 'https://www.themealdb.com/images/media/meals/tzsy461763769901.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bbq-pork-sloppy-joes', 'BBQ Pork Sloppy Joes', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'american', 'themealdb', 'dessert', 'baking', 'grilling'], '[{"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "lb", "item": "Pork", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Barbeque Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Hotsauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato Ketchup", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}]'::jsonb, '["1", "Preheat oven to 450 degrees. Wash and dry all produce. Cut sweet potatoes into ½-inch-thick wedges. Toss on a baking sheet with a drizzle of oil, salt, and pepper. Roast until browned and tender, 20-25 minutes.", "2", "Meanwhile, halve and peel onion. Slice as thinly as possible until you have ¼ cup (½ cup for 4 servings); finely chop remaining onion. Peel and finely chop garlic. Halve lime; squeeze juice into a small bowl. Halve buns. Add 1 TBSP butter (2 TBSP for 4) to a separate small microwave-safe bowl; microwave until melted, 30 seconds. Brush onto cut sides of buns.", "3", "To bowl with lime juice, add sliced onion, ¼ tsp sugar (½ tsp for 4 servings), and a pinch of salt. Stir to combine; set aside to quick-pickle.", "4", "Heat a drizzle of oil in a large pan over medium-high heat. Add chopped onion and season with salt and pepper. Cook, stirring, until softened, 4-5 minutes. Add garlic and cook until fragrant, 30 seconds more. Add pork and season with salt and pepper. Cook, breaking up meat into pieces, until browned and cooked through, 4-6 minutes.", "5", "While pork cooks, in a third small bowl, combine BBQ sauce, pickling liquid from onion, 3 TBSP ketchup (6 TBSP for 4 servings), ½ tsp sugar (1 tsp for 4), and ¼ cup water (⅓ cup for 4). Once pork is cooked through, add BBQ sauce mixture to pan. Cook, stirring, until sauce is thickened, 2-3 minutes. Taste and season with salt and pepper.", "6", "Meanwhile, toast buns in oven or toaster oven until golden, 3-5 minutes. Divide toasted buns between plates and fill with as much BBQ pork as you’d like. Top with pickled onion and hot sauce. Serve with sweet potato wedges on the side."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/atd5sh1583188467.jpg', TRUE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bigos-hunters-stew', 'Bigos (Hunters Stew)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'polish', 'themealdb', 'breakfast', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "lb", "item": "Kielbasa", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "lb", "item": "Pork", "notes": null, "category": "meat"}, {"quantity": 0.25, "unit": "cup", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.5, "unit": "cup", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cups", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sauerkraut", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "cup", "item": "Red Wine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Basil", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Marjoram", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tbs", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 0.125, "unit": "teaspoon", "item": "Caraway Seed", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Hotsauce", "notes": null, "category": "other"}, {"quantity": 5.0, "unit": "cups", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tbs", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Diced Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Worcestershire Sauce", "notes": null, "category": "pantry"}]'::jsonb, '["Preheat the oven to 350 degrees F (175 degrees C).", "Heat a large pot over medium heat. Add the bacon and kielbasa; cook and stir until the bacon has rendered its fat and sausage is lightly browned. Use a slotted spoon to remove the meat and transfer to a large casserole or Dutch oven.", "Coat the cubes of pork lightly with flour and fry them in the bacon drippings over medium-high heat until golden brown. Use a slotted spoon to transfer the pork to the casserole. Add the garlic, onion, carrots, fresh mushrooms, cabbage and sauerkraut. Reduce heat to medium; cook and stir until the carrots are soft, about 10 minutes. Do not let the vegetables brown.", "Deglaze the pan by pouring in the red wine and stirring to loosen all of the bits of food and flour that are stuck to the bottom. Season with the bay leaf, basil, marjoram, paprika, salt, pepper, caraway seeds and cayenne pepper; cook for 1 minute.", "Mix in the dried mushrooms, hot pepper sauce, Worcestershire sauce, beef stock, tomato paste and tomatoes. Heat through just until boiling. Pour the vegetables and all of the liquid into the casserole dish with the meat. Cover with a lid.", "Bake in the preheated oven for 2 1/2 to 3 hours, until meat is very tender."]'::jsonb, 'https://www.allrecipes.com/recipe/138131/bigos-hunters-stew/', 'https://www.themealdb.com/images/media/meals/md8w601593348504.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('boxty-breakfast', 'Boxty Breakfast', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'irish', 'themealdb', 'breakfast', 'baking', 'grilling'], '[{"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "bunch", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "White", "notes": null, "category": "other"}, {"quantity": 150.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Bicarbonate Of Soda", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}]'::jsonb, '["STEP 1", "Before you start, put your oven on its lowest setting, ready to keep things warm. Peel the potatoes, grate 2 of them, then set aside. Cut the other 2 into large chunks, then boil for 10-15 mins or until tender. Meanwhile, squeeze as much of the liquid from the grated potatoes as you can using a clean tea towel. Mash the boiled potatoes, then mix with the grated potato, spring onions and flour.", "STEP 2", "Whisk the egg white in a large bowl until it holds soft peaks. Fold in the buttermilk, then add the bicarbonate of soda. Fold into the potato mix.", "STEP 3", "Heat a large non-stick frying pan over a medium heat, then add 1 tbsp butter and some of the oil. Drop 3-4 spoonfuls of the potato mixture into the pan, then gently cook for 3-5 mins on each side until golden and crusty. Keep warm on a plate in the oven while you cook the next batch, adding more butter and oil to the pan before you do so. You will get 16 crumpet-size boxty from the mix. Can be made the day ahead, drained on kitchen paper, then reheated in a low oven for 20 mins.", "STEP 4", "Heat the grill to medium and put the tomatoes in a heavy-based pan. Add a good knob of butter and a little oil, then fry for about 5 mins until softened. Grill the bacon, then pile onto a plate and keep warm. Stack up the boxty, bacon and egg, and serve the tomatoes on the side."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/boxty-bacon-eggs-tomatoes', 'https://www.themealdb.com/images/media/meals/naqyel1608588563.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bryndzové-halušky', 'Bryndzové Halušky', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'slovakian', 'themealdb', 'breakfast', 'baking'], '[{"quantity": 500.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Bryndza cheese", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Garnish Chives", "notes": null, "category": "other"}]'::jsonb, '["1. Prepare the Dough", "Grate the potatoes finely using a hand grater or food processor. Place the grated potatoes in a bowl and mix them with flour, egg, and salt until a sticky dough forms. The consistency should be thick but pliable.", "2. Cook the Dumplings", "Bring a large pot of salted water to a boil. Using a halušky maker (similar to a spaetzle maker), press the dough directly into the boiling water. If you don’t have one, use a tilted cutting board and a knife to scrape small pieces of dough into the water.", "Let the dumplings cook until they float to the surface, usually within 2-3 minutes. Scoop them out with a slotted spoon and set aside in a large bowl.", "3. Prepare the Toppings", "Chop the bacon into small pieces and fry in a skillet over medium heat until crispy. If using a bryndza substitute, mix crumbled feta with a dollop of sour cream to mimic the tangy flavour of traditional Slovak sheep cheese.", "4. Assemble the Dish", "Toss the cooked dumplings with the bryndza cheese (or substitute) until they’re well-coated and creamy. Top with the crispy bacon and its drippings. Garnish with chopped chives or parsley for an extra touch of colour and flavour."]'::jsonb, 'https://www.slovakia-foods.co.uk/blog/post/bryndzove-halusky-recipe-a-taste-of-slovakia-national-dish.html', 'https://www.themealdb.com/images/media/meals/g33c901763365484.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cassava-pizza', 'Cassava pizza', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'venezulan', 'themealdb', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "thick slices Casabe", "notes": null, "category": "other"}, {"quantity": 450.0, "unit": "g", "item": "Tomato Sauce", "notes": null, "category": "produce"}, {"quantity": 225.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 225.0, "unit": "g", "item": "Turkey Ham", "notes": null, "category": "meat"}, {"quantity": 75.0, "unit": "g", "item": "Sweetcorn", "notes": null, "category": "produce"}, {"quantity": 40.0, "unit": "g", "item": "Green Olives", "notes": null, "category": "other"}, {"quantity": 55.0, "unit": "g", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 50.0, "unit": "g", "item": "Mozzarella", "notes": null, "category": "dairy"}]'::jsonb, '["Preheat the oven to 200ºC.", "Cut the bacon or chorizo into medium pieces and the paprika into strips.", "Spread a little tomato sauce and mozzarella cheese on each portion of cassava.", "Add the bacon or chorizo, corn, turkey ham, some olives and paprika.", "Bake for 7 to 10 minutes.", "Remove from the oven and enjoy."]'::jsonb, 'https://goya.es/en/recipes/cassava-pizza', 'https://www.themealdb.com/images/media/meals/lrfdwz1764438393.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chickpea-chorizo-spinach-stew', 'Chickpea, chorizo & spinach stew', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'spanish', 'themealdb', 'soup', 'vegetarian', 'vegan'], '[{"quantity": 4.0, "unit": "tablespoons", "item": "Extra Virgin Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "cloves", "item": "chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 800.0, "unit": "g", "item": "Chickpeas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sherry vinegar", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Spinach", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat the oil in a large pan, then gently fry the onion for 3-4 mins until it begins to soften. Stir in the carrot, celery, thyme and bay leaves. Season, then cook for 2-3 mins, stirring occasionally. Add the garlic, chorizo, cinnamon and smoked paprika. Gently fry until the vegetables soften and the chorizo starts to release its oils and crisp up.", "step 2", "Stir in the chickpeas, vinegar and 150ml water, then bring to a simmer for 1-2 mins until the chickpeas have heated up. Add the spinach, then stir through the chickpeas until it wilts a little. Remove from the heat, season to taste, then serve warm with crusty bread."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/chickpea-chorizo-spinach-stew', 'https://www.themealdb.com/images/media/meals/xvnx8j1763287209.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('choripán', 'Choripán', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'argentinian', 'themealdb', 'grilling', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Drizzle Chimichurri sauce", "notes": null, "category": "other"}]'::jsonb, '["Grill the Chorizos: Cook the chorizos on a grill or pan until fully cooked, about 10-15 minutes.", "Prepare the Rolls: Slice the rolls and toast them lightly on the grill or in a pan.", "Assemble: Slice each chorizo lengthwise and place in a roll. Top with a generous amount of chimichurri sauce.", "Serve: Enjoy immediately while hot.", "Pro Tips:", "Grill the chorizo slowly on medium heat to prevent the skin from bursting and to ensure it cooks evenly throughout.", "Toast the bread on the grill to absorb some of the chorizo''s flavors."]'::jsonb, 'https://www.munchery.com/blog/the-ten-iconic-dishes-of-argentina-and-how-to-cook-them-at-home/', 'https://www.themealdb.com/images/media/meals/5i25sg1763075353.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chorizo-chickpea-soup', 'Chorizo & chickpea soup', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'spanish', 'themealdb', 'soup', 'vegetarian', 'vegan'], '[{"quantity": 400.0, "unit": "g", "item": "Tinned Tomatos", "notes": null, "category": "produce"}, {"quantity": 110.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 140.0, "unit": "g", "item": "Savoy Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sprinkling Chilli Flakes", "notes": null, "category": "other"}, {"quantity": 400.0, "unit": "g", "item": "can Chickpeas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Crusty Bread", "notes": null, "category": "grains"}]'::jsonb, '["step 1", "Put a medium pan on the heat and tip in the tomatoes, followed by a can of water. While the tomatoes are heating, quickly chop the chorizo into chunky pieces (removing any skin) and shred the cabbage.", "step 2", "Pile the chorizo and cabbage into the pan with the chilli flakes and chickpeas, then crumble in the stock cube. Stir well, cover and leave to bubble over a high heat for 6 mins or until the cabbage is just tender. Ladle into bowls and eat with crusty or garlic bread."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/chorizo-chickpea-soup', 'https://www.themealdb.com/images/media/meals/kggfo91763288633.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chorizo-soft-boiled-egg-salad', 'Chorizo & soft-boiled egg salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'spanish', 'themealdb', 'salad', 'vegetarian'], '[{"quantity": 500.0, "unit": "g", "item": "Baby New Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 225.0, "unit": "g", "item": "Green Beans", "notes": null, "category": "produce"}, {"quantity": 225.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "Sherry vinegar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbsp", "item": "chopped Parsley", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Cook the potatoes in a large pan of boiling salted water for 12 mins, adding the eggs after 6 mins, and the beans for the final 2 mins. Drain everything and cool the eggs under cold running water.", "step 2", "Meanwhile fry chorizo slices for 1-2 mins, until beginning to crisp. Remove from the pan with a slotted spoon and set aside, leaving the oil from the chorizo in the pan. Add the garlic to the pan and cook gently for 1 min.", "step 3", "Remove the pan from the heat, stir in the vinegar and parsley, then toss with the potatoes, beans, chorizo and seasoning. Shell the eggs, cut into quarters and add to the salad."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/chorizo-soft-boiled-egg-salad', 'https://www.themealdb.com/images/media/meals/v8eaed1763257313.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chorizo-tomato-salad', 'Chorizo & tomato salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'spanish', 'themealdb', 'salad', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sprigs of", "notes": "fresh Thyme", "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Sherry vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Extra Virgin Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Put the tomatoes in a bowl with the onion and thyme. Season, then drizzle with the vinegar and oil. Let the flavours mingle while you cook the chorizo.", "step 2", "In a hot, dry pan, fry the chorizo slices until browned on both sides. Serve the tomatoes with the fried chorizo, drizzled with a little oil from the pan."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/chorizo-tomato-salad', 'https://www.themealdb.com/images/media/meals/6cskio1763338156.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chorizo-potato-cheese-omelette', 'Chorizo, potato & cheese omelette', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'spanish', 'themealdb', 'breakfast', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Parsley", "notes": null, "category": "produce"}, {"quantity": 25.0, "unit": "g", "item": "Cheddar Cheese", "notes": null, "category": "dairy"}]'::jsonb, '["step 1", "Cook the potato in boiling water for 8-10 mins or until tender. Drain and allow to steam-dry. Heat oil in an omelette pan, add chorizo and cook for 2 mins. Add the potato and cook for a further 5 mins until the potato starts to crisp. Spoon pan contents out, wipe pan and cook a 2 or 3-egg omelette in the same pan. When almost cooked, scatter with the chorizo and potato, parsley and cheese. Fold the omelette in the pan and cook for 1 min more to melt the cheese."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/chorizo-potato-cheese-omelette', 'https://www.themealdb.com/images/media/meals/0y6uvc1763258983.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('coddled-pork-with-cider', 'Coddled pork with cider', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'irish', 'themealdb', 'breakfast', 'soup'], '[{"quantity": 1.0, "unit": "serving", "item": "Knob Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Chops", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Swede", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "ml", "item": "Cider", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Chicken Stock", "notes": null, "category": "meat"}]'::jsonb, '["STEP 1", "Heat the butter in a casserole dish until sizzling, then fry the pork for 2-3 mins on each side until browned. Remove from the pan.", "STEP 2", "Tip the bacon, carrot, potatoes and swede into the pan, then gently fry until slightly coloured. Stir in the cabbage, sit the chops back on top, add the bay leaf, then pour over the cider and stock. Cover the pan, then leave everything to gently simmer for 20 mins until the pork is cooked through and the vegetables are tender.", "STEP 3", "Serve at the table spooned straight from the dish."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/irish-coddled-pork-cider', 'https://www.themealdb.com/images/media/meals/7vpsfp1608588991.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('crispy-sausages-and-greens', 'Crispy Sausages and Greens', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'irish', 'themealdb', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "bunch", "item": "Kale", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Fennel Sausages", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "head", "item": "chopped Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Sliced Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sliced Shiitake Mushrooms", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Preheat the oven to 350°. Remove the stems from one bunch of Tuscan kale and tear the leaves into 1\" pieces (mustard greens, collards, spinach, and chard are great, too). Coarsely chop half a head of green cabbage. Combine the greens in a large baking dish and add 4 cloves of thinly sliced garlic. Adding some sliced onions and shiitake mushrooms at this point is optional, but highly recommended (I''ll sauté the onions and mushrooms in a cast iron baking dish right on the stove before adding to the greens). Coat the greens with some olive oil and pour ½ cup chicken stock or broth over everything. Cover the dish with foil and bake until the greens are wilted, about 15 minutes. Remove foil and season with salt and pepper. Continue to bake until cabbage is tender, about 20-25 minutes more.", "Meanwhile, heat a little olive oil in a large skillet over medium-high. Prick four sweet Italian sausages with a fork and cook until browned on all sides and cooked through, 10 to 12 minutes. When the greens are done, slice the sausage and toss into the greens with a splash of your favorite vinegar (I like sherry or red wine)."]'::jsonb, 'https://www.bonappetit.com/columns/cooking-without-recipes/article/kale-cabbage-sausage-weeknight-dinner', 'https://www.themealdb.com/images/media/meals/st1ifa1583267248.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fašírky', 'Fašírky', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'slovakian', 'themealdb', 'baking'], '[{"quantity": 500.0, "unit": "g", "item": "Ground Pork", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Marjoram", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Mustard", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "chopped Parsley", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "cup", "item": "Breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Vegetable Oil", "notes": null, "category": "pantry"}]'::jsonb, '["1. Prepare the Bread Mixture", "Soak the bread slices in milk or water until soft.", "Squeeze out excess liquid and mash into small crumbs.", "2. Mix the Ingredients", "In a large bowl, combine ground meat, chopped onions, garlic, soaked bread, egg, and seasonings.", "Mix well until evenly combined.", "3. Shape the Meat Patties", "Take portions of the mixture and shape them into palm-sized patties.", "Flatten slightly to help with even cooking.", "4. Coat the Patties", "Lightly dust each patty with flour.", "Dip into beaten egg, then coat with breadcrumbs for a crispy finish.", "5. Fry the Fašírky", "Heat vegetable oil in a pan over medium heat.", "Fry the patties for 4-5 minutes per side until golden brown and fully cooked.", "Transfer to a paper towel-lined plate to drain excess oil.", "6. Serve and Enjoy", "Serve Fašírky hot with mashed potatoes, cabbage salad, or fresh bread.", "Enjoy with mustard, pickles, or garlic sauce for extra flavor."]'::jsonb, 'https://www.slovakia-foods.co.uk/blog/post/fasirky-recipe-how-to-make-authentic-slovak-meat-patties.html', 'https://www.themealdb.com/images/media/meals/gtpvwp1763363947.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ham-croquetas', 'Ham croquetas', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'spanish', 'themealdb', 'soup', 'baking', 'vegetarian'], '[{"quantity": 75.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 75.0, "unit": "g", "item": "Breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "tbsp", "item": "Extra Virgin Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Leek", "notes": null, "category": "produce"}, {"quantity": 70.0, "unit": "g", "item": "jamón ibérico", "notes": null, "category": "other"}, {"quantity": 60.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 75.0, "unit": "ml", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 330.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Grated Nutmeg", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "To make the filling, heat the olive oil in a pan until it starts to shimmer. Add the leek and sauté until soft but not coloured. Stir in the ham with a wooden spoon, fry for 1 min, then stir in the flour and fry over a medium heat, stirring occasionally, until the mixture is golden but not burnt – this will take about 5 mins.", "step 2", "Meanwhile, combine the stock and milk in a small pan and heat until steaming but not boiling. Season with a few scrapes of nutmeg. Gradually add the liquid, a few tbsp at a time, stirring constantly.", "step 3", "Once you’ve incorporated all the milk stock, continue to cook the filling over a medium heat for about 10 mins or until it thickens and leaves the sides of the pan when you stir it.", "step 4", "Season with black pepper, taste and adjust the salt if necessary – the ham can be very salty to start with. The filling is now done: it has to be really thick because you don’t want the croquetas to turn into pancakes.", "step 5", "Smooth the mixture onto a baking tray (30 x 20cm is fine). Once it has stopped steaming, cover with cling film to stop it drying out. Leave to cool before putting it in the fridge for 1 hr.", "step 6", "When you''re ready for the next stage, line up three bowls: the first filled with the flour, the second with beaten egg and the third with breadcrumbs. Take the ham mixture out of the fridge. Put a little bit of olive oil on your hands to make it easier to roll the croquetas.", "step 7", "Roll a spoonful of the mixture between your palms. The size and shape of the croquetas is up to you, but the easiest is a walnut-sized ball. Then begin coating as follows.", "step 8", "Dunk the croquetas into the flour – you want a dusting – followed by the egg, then the breadcrumbs. Put them on a tray and, when you’ve used up all the mixture, place in the fridge for 30 mins.", "step 9", "If you have a deep-fat fryer, heat the oil to 180C and fry for a couple of mins. If not, heat the oil in a deep, heavy-bottomed saucepan until it starts to shimmer. Then add 5-6 croquetas at a time and fry until golden all over. Once cooked, drain on kitchen paper and eat straight away."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/ham-croquetas', 'https://www.themealdb.com/images/media/meals/6dpa7m1763331105.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ham-hock-colcannon', 'Ham hock colcannon', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'irish', 'themealdb', 'baking'], '[{"quantity": 800.0, "unit": "g", "item": "Floury Potatoes", "notes": null, "category": "produce"}, {"quantity": 50.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "Mustard", "notes": null, "category": "pantry"}, {"quantity": 180.0, "unit": "g", "item": "Ham", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}]'::jsonb, '["STEP 1", "Peel and cut the potatoes into even, medium-sized chunks. Put in a large pan filled with cold salted water, bring to the boil and cook for 10-15 mins until a knife can be inserted into the potatoes easily.", "STEP 2", "Meanwhile, melt the butter in a large sauté pan over a medium heat. Add the garlic, cabbage, spring onions and some seasoning. Stir occasionally until the cabbage is wilted but still retains a little bite, then set aside.", "STEP 3", "Drain the potatoes, leave to steam-dry for a couple of mins, then mash with the cream, mustard and seasoning in the same saucepan. Stir in the cabbage and ham hock. Keep warm over a low heat.", "STEP 4", "Reheat the pan you used to cook the cabbage (no need to wash first), add a splash of oil, crack in the eggs and fry to your liking. To serve, divide the colcannon between bowls and top each with a fried egg."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/ham-hock-colcannon', 'https://www.themealdb.com/images/media/meals/n41ny81608588066.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('hot-and-sour-soup', 'Hot and Sour Soup', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'chinese', 'themealdb', 'dessert', 'soup', 'grilling'], '[{"quantity": 0.3333333333333333, "unit": "cup", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Wood Ear Mushrooms", "notes": null, "category": "produce"}, {"quantity": 0.6666666666666666, "unit": "cup", "item": "Tofu", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "cup", "item": "Pork", "notes": null, "category": "meat"}, {"quantity": 0.5, "unit": "cups", "item": "2-1/2 cups Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Hotsauce", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "cups", "item": "1-½ cups Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Water", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "cup", "item": "Spring Onions", "notes": null, "category": "produce"}]'::jsonb, '["STEP 1 - MAKING THE SOUP", "In a wok add chicken broth and wait for it to boil.", "Next add salt, sugar, sesame seed oil, white pepper, hot pepper sauce, vinegar and soy sauce and stir for few seconds.", "Add Tofu, mushrooms, black wood ear mushrooms to the wok.", "To thicken the sauce, whisk together 1 Tablespoon of cornstarch and 2 Tablespoon of water in a bowl and slowly add to your soup until it''s the right thickness.", "Next add 1 egg slightly beaten with a knife or fork and add it to the soup and stir for 8 seconds", "Serve the soup in a bowl and add the bbq pork and sliced green onions on top."]'::jsonb, 'https://sueandgambo.com/pages/chinese-hot-and-sour-soup', 'https://www.themealdb.com/images/media/meals/1529445893.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamon-wild-garlic-croquetas', 'Jamon & wild garlic croquetas', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'spanish', 'themealdb', 'baking', 'vegetarian'], '[{"quantity": 150.0, "unit": "g", "item": "Wild Garlic Leaves", "notes": null, "category": "produce"}, {"quantity": 350.0, "unit": "g", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 45.0, "unit": "g", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 65.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 35.0, "unit": "g", "item": "manchego", "notes": null, "category": "other"}, {"quantity": 80.0, "unit": "g", "item": "jamón ibérico", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 75.0, "unit": "g", "item": "Breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "l", "item": "Vegetable Oil", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Wash the wild garlic leaves well in a colander, then pour over boiling water from the kettle until just wilted. Immediately rinse under cold running water, then squeeze out the excess water and finely chop.", "step 2", "Warm the milk in a pan over a low heat until just steaming. Heat the oil or butter in a second pan and, once warm or melted, stir in the flour for a couple of minutes until it starts to brown a little. Gradually add the warm milk, a little at a time, until you have a thick, silky sauce. Bubble for a minute or two, stirring to make sure all the flour has cooked out. Season.", "step 3", "Add the manchego, jamón and wild garlic to the pan, and beat to combine. Tip out onto a lightly oiled baking tray or plate, spread out then cover and chill for at least 1 hr. Will keep chilled for up to 24 hrs.", "step 4", "Lightly oil your hands and shape the mixture into 18-20 even-sized balls. Arrange on a baking tray and freeze for 30 mins to firm up.", "step 5", "Beat the egg in a shallow dish with a little seasoning. Tip the panko into a second dish. Dip each of the croquetas in the egg, then turn to coat in the breadcrumbs. At this point, the raw croquetas can be frozen for up to three months. Pour the oil into a large, deep pan ensuring it is no more than a third full and heat to 170C, or until a cube of bread browns lightly in 30 seconds. Fry the croquetas in batches for 2-3 mins until deeply golden. To cook from frozen, fry at 160C for a few minutes longer until they’re piping hot inside. Remove to a sheet of kitchen paper using a slotted spoon and leave to drain. Serve warm with a glass of sherry."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/jamon-wild-garlic-croquetas', 'https://www.themealdb.com/images/media/meals/zc9cwz1763196177.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('japanese-katsudon', 'Japanese Katsudon', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'japanese', 'themealdb', 'dessert', 'soup'], '[{"quantity": 1.0, "unit": "tbs", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pork", "notes": null, "category": "meat"}, {"quantity": 150.0, "unit": "ml", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Mirin", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "Sushi Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Chives", "notes": null, "category": "other"}]'::jsonb, '["STEP 1", "Heat the oil in a pan, fry the sliced onion until golden brown, then add the tonkatsu (see recipe here), placing it in the middle of the pan. Mix the dashi, soy, mirin and sugar together and tip three-quarters of the mixture around the tonkatsu. Sizzle for a couple of mins so the sauce thickens a little and the tonkatsu reheats.", "STEP 2", "Tip the beaten eggs around the tonkatsu and cook for 2-3 mins until the egg is cooked through but still a little runny. Divide the rice between two bowls, then top each with half the egg and tonkatsu mix, sprinkle over the chives and serve immediately, drizzling with a little more soy if you want an extra umami kick."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/japanese-katsudon', 'https://www.themealdb.com/images/media/meals/d8f6qx1604182128.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pork-sauerkraut-goulash', 'Pork & sauerkraut goulash', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'polish', 'themealdb', 'soup', 'baking'], '[{"quantity": 3.0, "unit": "tablespoons", "item": "Lard", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Cumin Seeds", "notes": null, "category": "pantry"}, {"quantity": 800.0, "unit": "g", "item": "Pork Shoulder", "notes": null, "category": "meat"}, {"quantity": 4.0, "unit": "cloves", "item": "Crushed Garlic", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.5, "unit": "l", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 400.0, "unit": "g", "item": "White Sauerkraut", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "ml", "item": "Whipping Cream", "notes": null, "category": "dairy"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Sour Cream", "notes": null, "category": "dairy"}]'::jsonb, '["step 1", "Heat the lard in a saucepan over a medium heat and fry the finely chopped onion until golden, around 5-8 mins. Tip in the cumin and pork, and fry for 10 mins all over until browned. Add the garlic, season well and scatter over the flour. Cook for about a minute, then add the paprika and cook for 1 min more.", "step 2", "Pour in half of the stock, add the bay leaves, and simmer with the lid on over a low heat for 30 mins.", "step 3", "Add the sauerkraut, remaining stock and a drizzle of the sauerkraut pickling juices. Simmer with the lid for 30 mins, stirring occasionally, until the meat is tender. Stir in the cream and simmer for 5 mins to combine the flavours. Season to taste, the serve garnished with a spoonful of soured cream.", "This recipe has been provided by Apetit Online and not been re-tested by us."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/pork-sauerkraut-goulash', 'https://www.themealdb.com/images/media/meals/cyuhwp1764362103.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pork-cassoulet', 'Pork Cassoulet', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'french', 'themealdb', 'soup', 'baking', 'grilling'], '[{"quantity": 4.0, "unit": "tbsp", "item": "Goose Fat", "notes": null, "category": "other"}, {"quantity": 350.0, "unit": "g", "item": "Pork", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "sliced Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Fennel Seeds", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 600.0, "unit": "ml", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Rosemary", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Parsley", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Haricot Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "drizzle Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Bread", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Broccoli", "notes": null, "category": "produce"}]'::jsonb, '["Heat oven to 140C/120C fan/gas 1. Put a large ovenproof pan (with a tight-fitting lid) on a high heat. Add your fat and diced meat, cook for a few mins to seal the edges, giving it a quick stir to cook evenly. Reduce the heat to low, add the sliced onion, whole garlic cloves, carrot and fennel seeds, and cook gently to soften the veg for a few mins.", "Pour over the red wine vinegar, scraping any meaty bits off the bottom of the pan. Add the stock, tomato purée, and half the rosemary and parsley. Bring to the boil and simmer for 10 mins, then season, cover with a lid and put into the oven for 2 hrs, removing the lid for the final hour of cooking. Stir occasionally and add the beans with 30 mins to go.", "Remove the pan from the oven and heat the grill. Scatter the top with the remaining herbs and breadcrumbs, drizzle a little oil over the top, and return to the oven for 5-10 mins, until the breadcrumbs are golden. Serve with crusty bread and green veg."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/jacks-pork-cassoulet', 'https://www.themealdb.com/images/media/meals/wxuvuv1511299147.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pork-rib-bortsch', 'Pork rib bortsch', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'polish', 'themealdb'], '[{"quantity": 1.0, "unit": "kg", "item": "Pork Back Ribs", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Dried white beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "thinly Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Beetroot", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Dill", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Sour Cream", "notes": null, "category": "dairy"}]'::jsonb, '["step 1", "Cut the meat into large pieces, put in your largest saucepan and cover with 5 litres water. Bring to the boil over a high heat, skimming away any foam that rises to the surface. Add the bay leaves. Season. Turn the heat down to a simmer and cook for 1 hr, or until the meat is soft and falls off the bone. Add the beans if using dried.", "step 2", "Turn the heat up. Bring back to the boil, then reduce the heat and simmer for another 20 mins – the beans should still be slightly raw. Add the carrots, onions, garlic and pepper. Stir well, then add the chillies, if using. Cook for 15 mins more.", "step 3", "Stir in the beetroot and cook for 10 mins before adding the potatoes. After 15 mins, add the tomato purée to taste and beans, if using canned, and bring to the boil. Cook for 5 mins, add the cabbage and cook for 5 mins more. Season, then garnish with the parsley and dill. Turn off the heat and leave to stand for 5 mins. Serve with soured cream on the side."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/pork-rib-bortsch', 'https://www.themealdb.com/images/media/meals/om5hsl1764364721.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('portuguese-barbecued-pork-febras-assadas', 'Portuguese barbecued pork (Febras assadas)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'portuguese', 'themealdb', 'grilling'], '[{"quantity": 1.0, "unit": "serving", "item": "Pork", "notes": null, "category": "meat"}, {"quantity": 200.0, "unit": "ml", "item": "White Wine", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Juice", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Mayonnaise", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "kg", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Vegetable Oil", "notes": null, "category": "pantry"}]'::jsonb, '["STEP 1", "Cut the tenderloins into 5 equal-size pieces leaving the tail ends a little longer. Take a clear plastic bag and slip one of the pieces in. Bash it into an escalope the size of a side-plate with a rolling pin and repeat with the remaining pieces.", "STEP 2", "Put the wine, paprika, some salt and pepper and the juice of ½ a lemon in a bowl and add the pork. Leave to marinate for 20-30 minutes, while you get your barbecue to the stage where the coals are glowing but there are no flames.", "STEP 3", "To make the chips, fill a basin with cool water and cut the potatoes into 3cm-thick chips. Soak them in the water for 5 minutes and then change the water. Leave for 5 more minutes. Drain and then pat dry on a towel or with kitchen paper.", "STEP 4", "Heat the oil in a deep fryer or a deep heavy-based pan with a lid to 130C and lower the chips into the oil (in batches). Blanch for 8-10 minutes. Remove from the oil and drain well. Place on a tray to cool. Reheat the oil to 180C (make sure it’s hot or your chips will be soggy) and lower the basket of chips into the oil (again, do this in batches). Leave to cook for 2 minutes and then give them a little shake. Cook for another minute or so until they are well coloured and crisp to the touch. Drain well for a few minutes, tip into a bowl and sprinkle with sea salt.", "STEP 5", "The pork will cook quickly so do it in 2 batches. Take the pieces out of the marinade, rub them with oil, and drop them onto the barbecue (you could also use a chargrill). Cook for 1 minute on each side – they may flare up as you do so. This should really be enough time as they will keep on cooking. Take them off the barbecue and pile onto a plate. Repeat with the remaining batch.", "STEP 6", "Serve by piling a plate with chips, drop the pork on top of each pile and pouring the juices from the plate over so the chips take up the flavours. Top with a spoon of mayonnaise and a wedge of lemon."]'::jsonb, 'https://www.olivemagazine.com/recipes/meat-and-poultry/febras-assadas-portuguese-barbecued-pork-served-with-lemon-and-mayo-on-chips/', 'https://www.themealdb.com/images/media/meals/cybyue1614349443.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('raspeballer-norwegian-potato-dumplings', 'Raspeballer (Norwegian Potato Dumplings)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'norwegian', 'themealdb', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "knuckle", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Sausages", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "lb", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "lbs", "item": "Red Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.25, "unit": "cup", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Cubes", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Freshly", "notes": "Chopped Parsley", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Swede", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Nutmeg", "notes": null, "category": "pantry"}]'::jsonb, '["Raspeballer & (Optional) Salted Meat", "▢", "If you''re making pork knuckle, cook it in simmering water for about 3 hours, until the meat falls from the bone. Remove the pork and save the broth to cook the raspeballer.", "▢", "Boil the boiled potatoes and peel once cooled. Also peel the raw potatoes, and then grate them or run them through a food processor. Use a paper towel to remove some of the moisture from the grated potatoes.", "▢", "Mash the boiled potatoes in a potato ricer or with a masher. Make sure there are no lumps. Add the grated raw potatoes to the mashed potatoes in a large mixing bowl and stir together. Add the barley flour, all purpose flour, and salt and mix together with your hands until the mixture is fully blended.", "▢", "You can cook the raspeballer in either vegetable or beef broth, or if you''re making pork knuckle, cook them in the broth from the pork knuckle. Bring the broth to a very light simmer – you don''t want it to fully boil because then the raspeballer might break apart.", "▢", "Use a tablespoon dipped in cold water to shape each raspeball in your hand. Try to make them as smooth as possible and then gently drop them into the simmering broth. Dip the tablespoon in a bowl of cold water between each raspeball.", "▢", "Let the raspeballer simmer for about 30 minutes. If you''re making smoked sausage, you can heat the sausage in the same pot with the raspeballer. Top with fresh chopped parsley.", "Mashed Rutabaga", "▢", "Peel the rutabaga and carrots and cut into small pieces. Boil in water for about 30 minutes, or until tender. Then drain the water, add the cream/milk, butter and nutmeg and mash until smooth.", "▢", "Serve alongside the raspeballer and meat."]'::jsonb, 'https://scandinaviancookbook.com/raspeballer-norwegian-potato-dumplings/', 'https://www.themealdb.com/images/media/meals/hhm7xy1763075871.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('rice-paper-dumplings', 'Rice paper dumplings', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'vietnamese', 'themealdb'], '[{"quantity": 1.0, "unit": "serving", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Shiitake Mushrooms", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Ground Pork", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 20.0, "unit": "g", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "thinly Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Paper Sheets", "notes": null, "category": "other"}, {"quantity": 75.0, "unit": "ml", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Rice Vinegar", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "tbs", "item": "Sesame Seed", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Tip the cabbage into a food processor and blitz until finely chopped. Season with ½ tsp salt, toss well and set aside for 15 mins. Tip into a clean tea towel and squeeze out as much water as you can. Tip into a bowl with the carrot, mushrooms, pork mince, garlic, ginger, soy sauce, sesame oil and spring onions. Season with black pepper. Scrunch everything together using your hands, mixing well until everything is combined.", "step 2", "Soak the spring roll sheets for a couple of seconds in a shallow dish of warm water, then transfer to an oiled chopping board. Working with one sheet at a time, spoon 1 heaped tbsp of the filling into the middle, then fold the bottom up and over the filling. Fold down the top of the sheet, then the sides to fully encase and make a neat square. If the dumpling feels a little fragile, soak another sheet and wrap it again. Repeat with the remaining sheets and filling, transferring the dumplings to an oiled plate as you go.", "step 3", "Heat the oil in a large, non-stick frying pan (ensuring it is no more than a third full) over a medium-high heat and fry the dumplings for 3-5 mins until golden brown. Use a slotted spoon or spider to turn them, then cover with a lid and cook for another 3-4 mins until golden. Remove the lid and cook for 1-2 mins.", "step 4", "Meanwhile, combine all the dipping sauce ingredients in small bowl. Serve the dumplings with the dipping sauce on the side."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/rice-paper-dumplings', 'https://www.themealdb.com/images/media/meals/sfahy01763752319.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('rosemary-braised-red-cabbage-with-kabanos', 'Rosemary braised red cabbage with kabanos', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'ukrainian', 'themealdb', 'dessert'], '[{"quantity": 1.0, "unit": "serving", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Knob Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 125.0, "unit": "ml", "item": "Red Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 140.0, "unit": "g", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Rosemary", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Bramley Apples", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sausages", "notes": null, "category": "meat"}]'::jsonb, '["step 1", "Halve the cabbage, remove the tough stem and thinly slice. Place in a large pan with all the other ingredients apart from the sausages, then mix in 300ml water and some salt and pepper.", "step 2", "Bring to a simmer, then reduce the heat, cover with a well-fitting lid and gently cook for 1½ hrs, stirring frequently. If too dry, you can add a little more water.", "step 3", "Add the kabanos to the cabbage mixture, place a lid on the pan and gently simmer for 20 mins. Remove the lid and cook for a further 10 mins. Serve alongside some simple mash or boiled potatoes."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/rosemary-braised-red-cabbage-kabanos', 'https://www.themealdb.com/images/media/meals/s1jxzl1764369317.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('skillet-apple-pork-chops-with-roasted-sweet-potatoes-zucchini', 'Skillet Apple Pork Chops with Roasted Sweet Potatoes & Zucchini', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'american', 'themealdb', 'dessert', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Apples", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pork", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Zucchini", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbsp", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.5, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbsp", "item": "Butter", "notes": null, "category": "dairy"}]'::jsonb, '["Serves 2", "1.", "Adjust racks to top and middle positions and preheat oven to 450 degrees. Wash and dry all produce. Dice sweet potatoes into 1/2-inch pieces. Toss on a baking sheet with a drizzle of oil, salt, and pepper. Roast on top rack for 12 minutes (we''ll roast the zucchini then).", "2.", "Meanwhile, halve and core apple; thinly slice into half-moons. Peel and finely chop garlic. Quarter lemon. Trim and halve zucchini lengthwise; cut crosswise into 1/2-inch-thick half-moons. Toss on a second baking sheet with a drizzle of oil and a pinch of salt and pepper. Set aside.", "3.", "Pat pork dry with paper towels and season all over with salt and pepper. Heat a drizzle of oil in a large pan over medium-high heat. Add pork and cook until browned and cooked through, 4-5 minutes per side. Turn off heat; transfer to a plate.", "4.", "Once sweet potatoes have roasted 12 minutes, transfer baking sheet with zucchini to middle rack and continue roasting until both veggies are browned and softened, 12-15 minutes more.", "5.", "Meanwhile, melt 1 TBSP butter (2 TBSP for 4 servings) in pan used for pork over medium-high heat. Add apple and season with salt and pepper. Cook, scraping up any browned bits from bottom of pan, until apple is slightly softened, 2-3 minutes. Add garlic; cook until fragrant, 30 seconds. Add 1/z cup water (3/4 cup for 4), stock concentrate, and 11/2 tsp sugar (3 tsp for 4). Cook, stirring, until sauce has thickened and apple is very tender, 3-5 minutes. Season with salt and pepper.", "6.", "Remove pan with apple from heat; stir in 1 TBSP butter (2 TBSP for 4 servings) and a squeeze of lemon juice. Divide pork, zucchini, and sweet potatoes between plates. Top pork with glazed apple sauce. Top zucchini with a squeeze of lemon juice."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/h3ijwo1581013377.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('slow-roasted-ham-with-lemon-garlic-sage', 'Slow-roasted ham with lemon, garlic & sage', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'polish', 'themealdb', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "cloves Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 15.0, "unit": "g", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 10.0, "unit": "g", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 50.0, "unit": "ml", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "kg", "item": "Pork Shoulder", "notes": null, "category": "meat"}, {"quantity": 500.0, "unit": "ml", "item": "Dry White Wine", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Heat the oven to 200C/180C fan/gas 6. Bash the garlic, sage, lemon zest, salt and pepper together using a pestle and mortar until the mixture becomes a paste. Stir in the oil, then spread the mixture over the pork shoulder, avoiding the skin on top. Score the skin using a sharp knife, then rub a large pinch of salt into the skin. Tie the pork together using kitchen string.", "step 2", "Line a large baking tray with a double layer of foil and put the pork on top, skin-side up. Bring the sides of the foil up around the pork to create a parcel, then pour the wine into the tray around the sides. Transfer to the oven and reduce the temperature to 140C/120C fan/gas 1. Roast for 4-5 hrs, or until a meat thermometer inserted into the thickest part of the pork reads 70C.", "step 3", "Turn the oven up to 240C/220C fan/gas 9. Carefully spoon the pork roasting juices from the pan into a saucepan and cook over a medium heat for 10-15 mins, or until reduced by a third. Season to taste.", "step 4", "Meanwhile, arrange the foil around the meat so only the skin is exposed, then return to the oven for 10-15 mins until the skin is puffed up and browned all over. Leave to rest for 20 mins before slicing. Serve with the sauce drizzled over."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/slow-roasted-ham-with-lemon-garlic-sage', 'https://www.themealdb.com/images/media/meals/w36ets1764362474.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spaghetti-with-spanish-flavours', 'Spaghetti with Spanish flavours', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'spanish', 'themealdb', 'pasta', 'vegetarian'], '[{"quantity": 80.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 300.0, "unit": "g", "item": "Spaghetti", "notes": null, "category": "grains"}, {"quantity": 20.0, "unit": "g", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "Parmesan Cheese", "notes": null, "category": "dairy"}]'::jsonb, '["step 1", "Put a pan of water on over a high heat to boil. Meanwhile, snip the chorizo into strips with scissors, and chop the parsley and peppers (check for stray seeds first).", "step 2", "When the water is boiling briskly, add the spaghetti with a good measure of salt, stir and return to the boil. Cook for 3 minutes.", "step 3", "In a large frying pan, heat the oil, add the chorizo and peppers and plenty of black pepper. Cook for a minute or so, until heated through and the juices are stained red from the paprika in the chorizo. Scoop half a mugful of pasta water from the pan, drain the remainder and tip the spaghetti into the frying pan.", "step 4", "Add the parsley and parmesan, toss well and splash in the pasta water, to moisten. Hand round extra parmesan at the table."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/spaghetti-spanish-flavours', 'https://www.themealdb.com/images/media/meals/vpcqn01763335688.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spanish-tomato-bread-with-jamón-serrano', 'Spanish tomato bread with jamón Serrano', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'spanish', 'themealdb', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "finely", "notes": "chopped Garlic", "category": "other"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Pepper", "notes": null, "category": "produce"}, {"quantity": 20.0, "unit": "slices", "item": "Baguette", "notes": null, "category": "other"}, {"quantity": 5.0, "unit": "slices", "item": "Serrano Ham", "notes": null, "category": "meat"}]'::jsonb, '["step 1", "Mix together the chopped tomatoes, garlic clove, olive oil, salt and pepper. Keep in the fridge until needed.", "step 2", "To serve, toast 20 slices of baguette. Spoon a little tomato topping on to each piece of toast. Tear 5-6 slices of jamón Serrano into pieces and put one piece on each slice of bread."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/spanish-tomato-bread-jamon-serrano', 'https://www.themealdb.com/images/media/meals/hsp1fo1763327867.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('stamppot', 'Stamppot', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'dutch', 'themealdb'], '[{"quantity": 1.5, "unit": "kg", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Bay Leaf", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 750.0, "unit": "g", "item": "Kale", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sausages", "notes": null, "category": "meat"}, {"quantity": 500.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Grated Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Wash and peel the potatoes and cut into similarly sized pieces for even cooking.", "In a large soup pot, boil the potatoes and the bay leaves in salted water for 20 minutes. Discard the bay leaves.", "If you''re not using a bag of ready-cut curly kale, wash the bunches thoroughly under cool running water to get rid of all soil—you wouldn''t want that gritty texture in your finished dish. Trim any coarse stems and discard any brown leaves. With a sharp knife, cut the curly kale into thin strips.", "Peel and chop the shallots.", "In a frying pan or skillet, melt 1 tbsp. of butter and saute the shallots for a few minutes before adding the curly kale and 2 tbsp. of water. Season and cook for about 10 minutes, or until tender.", "Warm the milk on the stove or in the microwave.", "Drain, shake and dry the potatoes with kitchen towels before mashing with a potato masher or ricer. Working quickly, add the warm milk and the remaining butter. Season to taste with nutmeg, salt, and pepper.", "Mix the cooked curly kale through the cooked mashed potato mixture.", "Top with slices of the smoked sausage and serve hot with your favorite mustard or gravy.", "Serve and enjoy!"]'::jsonb, 'https://www.thespruceeats.com/stamppot-with-curly-kale-and-rookworst-1128837', 'https://www.themealdb.com/images/media/meals/hyarod1565090529.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sweet-and-sour-pork', 'Sweet and Sour Pork', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'chinese', 'themealdb', 'dessert'], '[{"quantity": 200.0, "unit": "g", "item": "Pork", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Water", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 10.0, "unit": "g", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 10.0, "unit": "g", "item": "Starch", "notes": null, "category": "other"}, {"quantity": 30.0, "unit": "g", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 10.0, "unit": "g", "item": "Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Coriander", "notes": null, "category": "spices"}]'::jsonb, '["Preparation", "1. Crack the egg into a bowl. Separate the egg white and yolk.", "Sweet and Sour Pork", "2. Slice the pork tenderloin into strips.", "3. Prepare the marinade using a pinch of salt, one teaspoon of starch, two teaspoons of light soy sauce, and an egg white.", "4. Marinade the pork strips for about 20 minutes.", "5. Put the remaining starch in a bowl. Add some water and vinegar to make a starchy sauce.", "Sweet and Sour Pork", "Cooking Instructions", "1. Pour the cooking oil into a wok and heat to 190°C (375°F). Add the marinated pork strips and fry them until they turn brown. Remove the cooked pork from the wok and place on a plate.", "2. Leave some oil in the wok. Put the tomato sauce and white sugar into the wok, and heat until the oil and sauce are fully combined.", "3. Add some water to the wok and thoroughly heat the sweet and sour sauce before adding the pork strips to it.", "4. Pour in the starchy sauce. Stir-fry all the ingredients until the pork and sauce are thoroughly mixed together.", "5. Serve on a plate and add some coriander for decoration."]'::jsonb, 'https://www.chinahighlights.com/travelguide/chinese-food/cooking/sweet-sour-pork.htm', 'https://www.themealdb.com/images/media/meals/1529442316.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-pork-peanut-curry', 'Thai pork & peanut curry', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'thai', 'themealdb', 'dessert'], '[{"quantity": 1.0, "unit": "tablespoon", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 400.0, "unit": "g", "item": "Pork Tenderloin", "notes": null, "category": "meat"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Thai Red Curry Paste", "notes": null, "category": "spices"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Peanut Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbsp", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "ml", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 175.0, "unit": "g", "item": "Sweetcorn", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1 Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Steamed Jasmine Rice", "notes": null, "category": "grains"}]'::jsonb, '["step 1", "Heat the oil in a large saucepan or flameproof casserole. Add the spring onions and coriander stalks and cook for 1 min. Add the pork slices and cook for 5 mins until starting to brown.", "step 2", "Stir in the curry paste and peanut butter. After 30 secs, add the sugar, soy and coconut milk, plus ½ can of water. Mix well, put a lid on and leave to simmer for 15 mins, stirring occasionally.", "step 3", "Remove the lid, add the baby corn and increase the heat. Bubble for 3 mins until the corn is cooked and the sauce has thickened a little. Stir in the lime juice and check the seasoning. Can now be frozen for up to 2 months. To cook from frozen: thoroughly defrost, then heat in a pan on the hob until curry is hot all the way through. Serve scattered with the coriander leaves and rice."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/thai-pork-peanut-curry', 'https://www.themealdb.com/images/media/meals/snmtd61763426568.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('toad-in-the-hole', 'Toad In The Hole', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'british', 'themealdb', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "sausages", "notes": null, "category": "meat"}, {"quantity": 3.0, "unit": "tbsp", "item": "vegetable oil", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "plain flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbsp", "item": "grated horseradish", "notes": null, "category": "produce"}, {"quantity": 225.0, "unit": "ml", "item": "milk", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "cherry tomatoes", "notes": null, "category": "produce"}]'::jsonb, '["Preheat the oven to 200°C/fan180°C/gas 6. fry sausages in a non-stick pan until browned.", "Drizzle vegetable oil in a 30cm x 25cm x 6cm deep roasting tray and heat in the oven for 5 minutes.", "Put the plain flour in a bowl, crack in the medium free-range eggs, then stir in the grated horseradish. Gradually beat in the semi-skimmed milk. Season.", "Put the sausages into the hot roasting tray and pour over the batter. Top with cherry tomatoes on the vine and cook for 30 minutes until puffed and golden."]'::jsonb, 'http://www.deliciousmagazine.co.uk/recipes/georgina-fuggles-horseradish-and-vine-tomato-toad-in-the-hole/', 'https://www.themealdb.com/images/media/meals/ytuvwr1503070420.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tonkatsu-pork', 'Tonkatsu pork', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'japanese', 'themealdb', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Chops", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Fry Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Tomato Ketchup", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Worcestershire Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Oyster Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Caster Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["STEP 1", "Remove the large piece of fat on the edge of each pork loin, then bash each of the loins between two pieces of baking parchment until around 1cm in thickness – you can do this using a meat tenderiser or a rolling pin. Once bashed, use your hands to reshape the meat to its original shape and thickness – this step will ensure the meat is as succulent as possible.", "STEP 2", "Put the flour, eggs and panko breadcrumbs into three separate wide-rimmed bowls. Season the meat, then dip first in the flour, followed by the eggs, then the breadcrumbs.", "STEP 3", "In a large frying or sauté pan, add enough oil to come 2cm up the side of the pan. Heat the oil to 180C – if you don’t have a thermometer, drop a bit of panko into the oil and if it sinks a little then starts to fry, the oil is ready. Add two pork chops and cook for 1 min 30 secs on each side, then remove and leave to rest on a wire rack for 5 mins. Repeat with the remaining pork chops.", "STEP 4", "While the pork is resting, make the sauce by whisking the ingredients together, adding a splash of water if it’s particularly thick. Slice the tonkatsu and serve drizzled with the sauce."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/tonkatsu-pork', 'https://www.themealdb.com/images/media/meals/lwsnkl1604181187.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('torta-de-fiambre', 'Torta de fiambre', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'uruguayan', 'themealdb', 'baking'], '[{"quantity": 150.0, "unit": "g", "item": "Cheddar Cheese", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "Ham", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 240.0, "unit": "g", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 120.0, "unit": "g", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste", "notes": "Dried Oregano", "category": "other"}]'::jsonb, '["Line the bottom of a springform of 20-2cm (8-9inches) with parchment paper, I usually leave some overhang as the batter is very liquid and may spill a bit. Preheat oven to 220 degrees Celsius.", "2", "Grate the cheese and take out the ham.", "3", "Mix all remaining ingredients in a large bowl for about one to two minutes.", "4", "Pour half the batter into the prepared pan, it is going to be very liquid. Then place ham and cheese on top and pour the remaining batter on top.", "5", "Bake for about 20-25 minutes or until top is golden. Wait for a few minutes before releasing from the pan and enjoy either hot or cold with some fresh herbs."]'::jsonb, 'https://jennyisbaking.com/2020/12/30/klassische-torta-de-fiambre-aus-uruguay/#recipe', 'https://www.themealdb.com/images/media/meals/okl9cm1764371087.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tourtiere', 'Tourtiere', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'canadian', 'themealdb', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 500.0, "unit": "g", "item": "Minced Pork", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "chopped  Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "chopped  Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 0.25, "unit": "tsp", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 0.25, "unit": "tsp", "item": "Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "ml", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Shortcrust Pastry", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "To Glaze Egg", "notes": null, "category": "dairy"}]'::jsonb, '["Heat oven to 200C/180C fan/gas 6. Boil the potato until tender, drain and mash, then leave to cool. Heat the oil in a non-stick pan, add the mince and onion and quickly fry until browned. Add the garlic, spices, stock, plenty of pepper and a little salt and mix well. Remove from the heat, stir into the potato and leave to cool.", "Roll out half the pastry and line the base of a 20-23cm pie plate or flan tin. Fill with the pork mixture and brush the edges of the pastry with water. Roll out the remaining dough and cover the pie. Press the edges of the pastry to seal, trimming off the excess. Prick the top of the pastry case to allow steam to escape and glaze the top with the beaten egg.", "Bake for 30 mins until the pastry is crisp and golden. Serve cut into wedges with a crisp green salad. Leftovers are good cold for lunch the next day, served with a selection of pickles."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/531644/spiced-pork-and-potato-pie', 'https://www.themealdb.com/images/media/meals/ytpstt1511814614.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vietnamese-grilled-pork-bun-thit-nuong', 'Vietnamese Grilled Pork (bun-thit-nuong)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'vietnamese', 'themealdb', 'dessert', 'baking', 'grilling'], '[{"quantity": 1.5, "unit": "pounds", "item": "sliced Pork", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "package", "item": "thin Rice Vermicelli", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "4-6 Egg Rolls", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tablespoons", "item": "minced Challots", "notes": null, "category": "other"}, {"quantity": 1.5, "unit": "tablespoons", "item": "minced garlic Garlic", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tablespoon", "item": "thick Soy sauce", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tablespoon", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Sliced Cucumber", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves Mint", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Crushed Peanuts", "notes": null, "category": "pantry"}]'::jsonb, '["Slice the uncooked pork thinly, about ⅛\". It helps to slightly freeze it (optional).", "Mince garlic and shallots. Mix in a bowl with sugar, fish sauce, thick soy sauce, pepper, and oil until sugar dissolves.", "Marinate the meat for 1 hour, or overnight for better results.", "Bake the pork at 375F for 10-15 minutes or until about 80% cooked. Finish cooking by broiling in the oven until a nice golden brown color develops, flipping the pieces midway.", "Assemble your bowl with veggies, noodles, and garnish. Many like to mix the whole bowl up and pour the fish sauce on top, but I like to make individual bites and sauce it slowly."]'::jsonb, 'http://www.hungryhuy.com/bun-thit-nuong-recipe-vietnamese-grilled-bbq-pork-with-rice-vermicelli-vegetables/', 'https://www.themealdb.com/images/media/meals/qqwypw1504642429.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vietnamese-pork-salad', 'Vietnamese pork salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'vietnamese', 'themealdb', 'dessert', 'salad', 'baking'], '[{"quantity": 1.0, "unit": "tsp", "item": "Golden Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 2 Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 500.0, "unit": "g", "item": "Pork Tenderloin", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "For brushing Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cucumber", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "thinly Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Lemongrass Stalks", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Mint", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "The day before: make the dressing. Put the sugar and lime juice in a pan with 1 tbsp water and bring to the boil to dissolve the sugar. Add the chilli and coriander and stir well, then pulse in a blender until smooth. Tip into a bowl, then stir in the sesame oil, fish sauce, soy sauce and sesame seeds to make a dressing. Cover and chill until needed.", "step 2", "Two hours before serving: heat a griddle pan. Preheat the oven to 200C/gas 6/fan 180C. Brush the pork with oil and griddle on all sides for a few minutes until seared. Transfer to a baking tray and put in the oven for about 10-12 minutes until cooked through. Cool, thinly slice against the grain of the meat. Tip into a bowl and pour over half the dressing.", "step 3", "To serve: toss the remaining salad ingredients in a bowl with the remaining dressing. Pile on to a platter, top with the pork slices and spoon over any juices."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/vietnamese-pork-salad', 'https://www.themealdb.com/images/media/meals/g7jomp1763763994.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vietnamese-style-caramel-pork', 'Vietnamese-style caramel pork', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'vietnamese', 'themealdb', 'dessert'], '[{"quantity": 0.5, "unit": "tbsp", "item": "Ground Nut Oil", "notes": null, "category": "pantry"}, {"quantity": 500.0, "unit": "g", "item": "Pork Shoulder Steaks", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Ground Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 75.0, "unit": "g", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "Chilli Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Steamed Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Pak Choi", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Heat 1 tbsp of the oil in a wok over a high heat and stir-fry the pork in batches until browned all over. Remove with a slotted spoon and set aside.", "step 2", "Turn the heat right down and add the remaining oil, then stir in the shallots, ginger and chilli. Cook over a low heat for a couple of mins until just starting to soften. Add the sugar, fish sauce and 200ml water to the pan and stir everything together. Bring to the boil, stirring, so that the sugar dissolves, then return the pork to the pan. Bubble vigorously for 8-10 mins until the sauce thickens to coat the meat and become glossy. Taste and stir in a little more fish sauce, if needed, along with the chilli sauce. Sprinkle with the spring onions and serve with steamed rice and pak choi."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/vietnamese-style-caramel-pork', 'https://www.themealdb.com/images/media/meals/4mzt101763761546.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('warm-roast-asparagus-salad', 'Warm roast asparagus salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'australian', 'themealdb', 'breakfast', 'salad', 'baking'], '[{"quantity": 500.0, "unit": "g", "item": "Asparagus", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "Red Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "Extra Virgin Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Clear Honey", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Royal Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Extra Virgin Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Dijon Mustard", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Rocket", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Preheat the oven to 200C/Gas 6/fan 180C. Snap off the woody ends of the asparagus and discard. Arrange the asparagus in a single layer in a baking tray with sides. Cut the tomatoes in half widthways, nestle them in with the asparagus, season with sea salt and pepper and drizzle with olive oil. Roll each bacon rasher into a tight roll (if large, first cut in half crosswise), and arrange in the tray. Drizzle the bacon rolls with the honey and bake for 20 minutes until the tomatoes are soft and the bacon is crisp.", "step 2", "In the meantime, boil the potatoes until tender. Whisk the vinegar, olive oil, mustard, some sea salt and pepper in a large bowl until blended. Toss the rocket or spinach leaves in half of the dressing, and arrange on a large serving platter.", "step 3", "Drain the potatoes and cut in half. Gently toss them in the rest of the dressing, and arrange on the platter with the asparagus. Tuck in the tomatoes and bacon."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/warm-roast-asparagus-salad', 'https://www.themealdb.com/images/media/meals/ktsws11761998344.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('wontons', 'Wontons', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'chinese', 'themealdb'], '[{"quantity": 1.0, "unit": "lb", "item": "Pork", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Wonton Skin", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Fry Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Bottle Water", "notes": null, "category": "other"}]'::jsonb, '["Combine pork, garlic, ginger, soy sauce, sesame oil, and vegetables in a bowl.", "Separate wonton skins.", "Place a heaping teaspoon of filling in the center of the wonton.", "Brush water on 2 borders of the skin, covering 1/4 inch from the edge.", "Fold skin over to form a triangle, sealing edges.", "Pinch the two long outside points together.", "Heat oil to 450 degrees and fry 4 to 5 at a time until golden.", "Drain and serve with sauce."]'::jsonb, 'http://www.geniuskitchen.com/recipe/chinese-wontons-20235', 'https://www.themealdb.com/images/media/meals/1525876468.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('zapiekanki', 'Zapiekanki', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['pork', 'polish', 'themealdb', 'dessert', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Baguette", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tsp", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Mayonnaise", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "Cheddar Cheese", "notes": null, "category": "dairy"}, {"quantity": 75.0, "unit": "g", "item": "Ham", "notes": null, "category": "meat"}, {"quantity": 75.0, "unit": "g", "item": "Polish Kabanos", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Mozzarella", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Dill", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Chives", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Drizzle Tomato Ketchup", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat the oven to 200C/180C fan/gas 6. Bake the baguettes on a baking tray for 8-10 mins, then leave to cool.", "step 2", "Heat 2 tsp of the butter and 1 tsp of the oil in a pan over a low heat and cook the chopped onion for 5 mins until soft. Stir in the mushrooms, turn the heat to medium and cook for 5-10 mins more until the veg is soft and the mushroom liquid has evaporated. Stir in the garlic and cook for 1-2 mins until soft. Season, then stir in the mayonnaise and remove from the heat.", "step 3", "Halve the baguettes lengthways, then return to the baking tray, cut-side up and spread over the mushroom mixture, then sprinkle over the cheddar, ham, kabanos and mozzarella. Bake for 8-10 mins, or until the cheese has melted and turned golden.", "step 4", "Meanwhile, heat the remaining butter and oil in a pan over a medium heat and fry the sliced onions for 5 mins until golden and soft. Remove from the heat and set aside. Once the pizzas are cooked, top with the caramelised onions, dill pickles (if using), the chives and a zig-zag drizzle of ketchup."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/zapiekanki', 'https://www.themealdb.com/images/media/meals/72lmpt1764122511.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('arroz-con-gambas-y-calamar', 'Arroz con gambas y calamar', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'spanish', 'themealdb', 'soup'], '[{"quantity": 1.0, "unit": "serving", "item": "King Prawns", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbsp", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Saffron", "notes": null, "category": "spices"}, {"quantity": 450.0, "unit": "g", "item": "Paella Rice", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "teaspoons", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "ml", "item": "White Wine", "notes": null, "category": "other"}, {"quantity": 650.0, "unit": "ml", "item": "Seafood stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Squid", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Peel and devein most of the prawns (a fishmonger should be able to do this for you), keeping a few whole for decoration, if you like. Heat the olive oil in a large frying pan or shallow flameproof casserole over a medium-low heat and fry the onion for 5 mins until softened. Add the bay leaf, saffron, rice and tomato purée, and cook for 1-2 mins more, stirring.", "step 2", "Pour in the wine and bubble for 1-2 mins, then pour in the seafood stock and 150ml water. Cook for 5 mins, then add the squid, season well and stir to combine. Bring to the boil, then cover and reduce the heat to a gentle simmer. Cook for 12 mins more, adding a little more water if the mixture starts to look dry.", "step 3", "Uncover the pan and stir through the peeled prawns, then arrange any whole prawns on top of the rice mixture. Cover again and simmer for a further 5-6 mins until the prawns are pink and cooked through. Leave to stand for a couple of minutes before serving from the pan."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/arroz-con-gambas-y-calamar', 'https://www.themealdb.com/images/media/meals/jc6oub1763196663.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('baked-salmon-with-fennel-tomatoes', 'Baked salmon with fennel & tomatoes', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'british', 'themealdb', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Fennel", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "chopped Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 175.0, "unit": "g", "item": "Cherry Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 350.0, "unit": "g", "item": "Salmon", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Black Olives", "notes": null, "category": "other"}]'::jsonb, '["Heat oven to 180C/fan 160C/gas 4. Trim the fronds from the fennel and set aside. Cut the fennel bulbs in half, then cut each half into 3 wedges. Cook in boiling salted water for 10 mins, then drain well. Chop the fennel fronds roughly, then mix with the parsley and lemon zest.", "Spread the drained fennel over a shallow ovenproof dish, then add the tomatoes. Drizzle with olive oil, then bake for 10 mins. Nestle the salmon among the veg, sprinkle with lemon juice, then bake 15 mins more until the fish is just cooked. Scatter over the parsley and serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/7745/baked-salmon-with-fennel-and-tomatoes', 'https://www.themealdb.com/images/media/meals/1548772327.jpg', TRUE, 1, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bang-bang-prawn-salad', 'Bang bang prawn salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'vietnamese', 'themealdb', 'salad', 'pasta', 'vegetarian'], '[{"quantity": 140.0, "unit": "g", "item": "Rice Noodles", "notes": null, "category": "grains"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Peanut Butter", "notes": null, "category": "dairy"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tablespoons", "item": "sweet chilli sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "thinly Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cucumber", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Bean Sprouts", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "Prawns", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Cook the noodles following pack instructions, then rinse under cold water and drain thoroughly. In a small saucepan melt together the peanut butter, coconut milk, sweet chilli sauce and half the spring onions, adding 1-2 tbsp of water to loosen the mixture to a drizzling consistency.", "step 2", "Mix the noodles, cucumber and beansprouts in a serving dish. Top with the prawns, drizzle over the peanut sauce and scatter over the remaining spring onions."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/bang-bang-prawn-salad', 'https://www.themealdb.com/images/media/meals/4xcfai1763765676.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('barramundi-with-moroccan-spices', 'Barramundi with Moroccan spices', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'australian', 'themealdb', 'baking', 'grilling', 'vegetarian', 'vegan'], '[{"quantity": 400.0, "unit": "g", "item": "400g barramundi", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Chili Powder", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 5.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Coriander", "notes": null, "category": "spices"}]'::jsonb, '["step 1", "Tip all the dressing ingredients into a food processor with a pinch of salt and blitz to a dressing. Slash the fish three times on each side, coat with half of the dressing, then set aside to marinate for about 30 mins.", "step 2", "Heat oven to 220C/fan 200C/gas 7. Place the fish on a roasting tray, then cook in the oven for 20 mins until the flesh is firm and the eyes have turned white. Serve the fish with the rest of the dressing and steamed couscous or rice.", "step 3", "KNOW HOW: HOW TO COOK IT: Cooking barramundi on the bone, as we have done here, has its advantages – it will stay more moist during cooking, and some would say that the flavour is enhanced, too. If you want to take out the bones they are easy to locate and less likely to be lodged in the fillet if the fish is cooked whole. Fillets can be simply pan-fried or grilled. If you like trout, you will really enjoy the flavour of barramundi, which lends itself to similar ingredients and cooking methods – citrus flavours are particularly good, as are garlic and wild mushrooms. Simply roasting the fish with some fresh herbs, olive oil and seasoning is delicious, and in the summer months you could barbecue it, too. One thing that you mustn’t miss are the cheeks or ‘pearls’ of the fish, these are simply lovely, moist and really sweet – well worth leaving the head on for!"]'::jsonb, 'https://www.bbcgoodfood.com/recipes/barramundi-moroccan-spices', 'https://www.themealdb.com/images/media/meals/4o4wh11761848573.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cajun-spiced-fish-tacos', 'Cajun spiced fish tacos', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'mexican', 'themealdb', 'salad'], '[{"quantity": 2.0, "unit": "tbsp", "item": "cajun", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "cayenne pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "white fish", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "vegetable oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "tortilla", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "avocado", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "little gem lettuce", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "ml", "item": "300ml salsa", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "sour cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "finely", "notes": "chopped garlic", "category": "other"}]'::jsonb, '["Cooking in a cajun spice and cayenne pepper marinade makes this fish super succulent and flavoursome. Top with a zesty dressing and serve in a tortilla for a quick, fuss-free main that''s delightfully summery.", "On a large plate, mix the cajun spice and cayenne pepper with a little seasoning and use to coat the fish all over.", "Heat a little oil in a frying pan, add in the fish and cook over a medium heat until golden. Reduce the heat and continue frying until the fish is cooked through, about 10 minutes. Cook in batches if you don’t have enough room in the pan.", "Meanwhile, prepare the dressing by combining all the ingredients with a little seasoning.", "Soften the tortillas by heating in the microwave for 5-10 seconds. Pile high with the avocado, lettuce and spring onion, add a spoonful of salsa, top with large flakes of fish and drizzle over the dressing."]'::jsonb, 'https://realfood.tesco.com/recipes/cajun-spiced-fish-tacos.html', 'https://www.themealdb.com/images/media/meals/uvuyxu1503067369.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('clam-chorizo-white-bean-stew', 'Clam, chorizo & white bean stew', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'spanish', 'themealdb', 'soup', 'vegetarian'], '[{"quantity": 50.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "ml", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Tinned Tomatos", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Butter Beans", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Sherry vinegar", "notes": null, "category": "pantry"}, {"quantity": 600.0, "unit": "g", "item": "Clams", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Crusty Bread", "notes": null, "category": "grains"}]'::jsonb, '["step 1", "Fry the chorizo in a large frying pan with a lid, over a medium heat until it is starting to crisp up and release its oil. Add the onion and cook for 5 mins until starting to soften. Then add the garlic and finely chopped parsley, and fry for 1 min more.", "step 2", "Pour on the stock and tomatoes. Bring to the boil, reduce the heat, then add the beans and sherry vinegar. Simmer for 10 mins until the liquid is slightly reduced.", "step 3", "Scatter over the clams, cover with the lid and steam for 2-4 mins, shaking the pan occasionally until the clams are open. Have a little taste before seasoning, as the clams can be quite salty. Then scatter over the chopped parsley. Eat with lots of crusty bread."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/clam-chorizo-white-bean-stew', 'https://www.themealdb.com/images/media/meals/92wbmf1763252334.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('egg-foo-young', 'Egg Foo Young', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'chinese', 'themealdb', 'dessert', 'soup'], '[{"quantity": 1.0, "unit": "cup", "item": "Unsalted Beef Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Shaoxing Wine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Oyster Sauce", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tsp", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "Kosher Salt", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Mung Bean Sprouts", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Shrimp", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "cups", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "cups", "item": "Jasmine Rice", "notes": null, "category": "grains"}]'::jsonb, '["Make the gravy:", "In a small saucepan, add the beef stock, soy sauce, Shaoxing wine, oyster sauce, and white pepper powder over medium heat. Whisk together and bring to a simmer.", "Combine the cornstarch and water in a small bowl and whisk to dissolve. Add to the saucepan and whisk until the gravy thickens and coats the back of the spoon, 2 to 3 minutes. Cover the saucepan with a lid and keep it warm on the lowest possible heat.", "Make the egg foo young batter:", "In a medium bowl, whisk together the cornstarch and water until dissolved. Add the eggs, salt, and sugar. Whisk until well combined and there are no more egg white clumps.", "Add the green onion, bean sprouts, and shrimp. Stir until everything is evenly coated.", "Fry the egg foo young:", "Add the vegetable oil to a large wok; it should reach about 2 inches up the sides. Heat the oil over medium-high heat to 350°F, or until vigorous bubbles form around an inserted wooden chopstick.", "With a ladle, gently and slowly add 1/4 of the omelet batter. Egg foo young should immediately bubble and puff up like magic. Fry until golden brown and crispy on each side, about 2 minutes per side. If there are any light spots, use a ladle to gently baste it with hot oil.", "Tip", "Egg foo young can be a bit tricky to flip. The easiest method is to put a tool in each hand (a spider, slotted spoon, tongs, and large chopsticks are all good candidates) and gently coax the omelet over, pulling up on one side and pushing down and around on the other.", "Remove the omelet and place it on a paper towel-lined baking sheet. Let it cool for 5 minutes. Meanwhile, repeat with the remaining batter to make 4 omelets. If needed, add more oil to the pan between batches.", "Serve and enjoy:", "Plate each egg foo young over a bed of rice. Spoon the warm gravy over the top and serve immediately."]'::jsonb, 'https://www.simplyrecipes.com/egg-foo-young-recipe-6890222', 'https://www.themealdb.com/images/media/meals/47y6ii1765658818.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('escovitch-fish', 'Escovitch Fish', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'jamaican', 'themealdb', 'dessert', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 2.0, "unit": "pounds", "item": "Red Snapper", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "cup", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 0.5, "unit": "tsp", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Worcestershire Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Bonnet", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Lime", "notes": null, "category": "produce"}, {"quantity": 0.75, "unit": "cup", "item": "Malt Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Rinse fish; rub with lemon or lime, seasoned with salt and pepper or use your favorite seasoning. I used creole seasoning. Set aside or place in the oven to keep it warm until sauce is ready.", "In large skillet heat oil over medium heat, until hot, add the fish, cook each side- for about 5-7 minutes until cooked through and crispy on both sides. Remove fish and set aside. Drain oil and leave about 2-3 tablespoons of oil", "Add, bay leave, garlic and ginger, stir-fry for about a minute making sure the garlic does not burn", "Then add onion, bell peppers, thyme, scotch bonnet, sugar, all spice-continue stirring for about 2-3 minutes. Add vinegar, mix an adjust salt and pepper according to preference. Let it simmer for about 2 more minutes.", "Discard bay leave, thyme spring and serve over fish with a side of this bammy. You may make the sauce about 2 days in advance."]'::jsonb, 'https://www.africanbites.com/jamaican-escovitched-fish/', 'https://www.themealdb.com/images/media/meals/1520084413.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fish-fofos', 'Fish fofos', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'portuguese', 'themealdb', 'baking', 'vegetarian'], '[{"quantity": 600.0, "unit": "g", "item": "Haddock", "notes": null, "category": "other"}, {"quantity": 300.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Green Chilli", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tbs", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin Seeds", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "pieces", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 75.0, "unit": "g", "item": "Breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Vegetable Oil", "notes": null, "category": "pantry"}]'::jsonb, '["STEP 1", "Put the fish into a lidded pan and pour over enough water to cover. Bring to a simmer and gently poach for 10 minutes over a low heat with the lid on. Drain and flake the fish.", "STEP 2", "Put the fish, potato, green chilli, coriander, cumin, black pepper, garlic and ginger in a large bowl. Season, add the rice flour, mix well and break in 1 egg. Stir the mixture and divide into 15, then form into small logs. Break the remaining eggs into a bowl and whisk lightly. Put the breadcrumbs into another bowl. Dip each fofo in the beaten egg followed by the breadcrumb mixture. Chill for 20 minutes.", "STEP 3", "Heat 1cm of oil in a large frying pan over a medium heat. Fry the fofos in batches for 2 minutes on each side, turning gently to get an even golden brown colour all over. Drain on kitchen paper and repeat with the remaining fofos.", "STEP 4", "For the onion salad, mix together the onion, coriander and lemon juice with a pinch of salt. Serve with the fofos and mango chutney."]'::jsonb, 'https://www.olivemagazine.com/recipes/fish-and-seafood/fish-fofos/', 'https://www.themealdb.com/images/media/meals/a15wsa1614349126.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fish-pie', 'Fish pie', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'british', 'themealdb', 'dessert', 'baking'], '[{"quantity": 900.0, "unit": "g", "item": "Floury Potatoes", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 600.0, "unit": "ml", "item": "Semi-skimmed Milk", "notes": null, "category": "dairy"}, {"quantity": 800.0, "unit": "g", "item": "White Fish Fillets", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbsp", "item": "Plain flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Grating Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tbsp", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 200.0, "unit": "g", "item": "Jerusalem Artichokes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "sliced Leek", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "peeled raw Prawns", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Large handful Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Dill", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Grated zest of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 25.0, "unit": "g", "item": "grated Gruyère", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1 Lemon", "notes": null, "category": "produce"}]'::jsonb, '["01.Put the potatoes in a large pan of cold salted water and bring to the boil. Lower the heat, cover, then simmer gently for 15 minutes until tender. Drain, then return to the pan over a low heat for 30 seconds to drive off any excess water. Mash with 1 tbsp olive oil, then season.", "02.Meanwhile put the milk in a large sauté pan, add the fish and bring to the boil. Remove from the heat, cover and stand for 3 minutes. Remove the fish (reserving the milk) and pat dry with kitchen paper, then gently flake into an ovenproof dish, discarding the skin and any bones.", "03.Heat the remaining oil in a pan, stir in the flour and cook for 30 seconds. Gradually stir in 200-250ml of the reserved milk (discard the rest). Grate in nutmeg, season, then bubble until thick. Stir in the cream.", "04.Preheat the oven to 190°C/fan170°C/gas 5. Grate the artichokes and add to the dish with the leek, prawns and herbs. Stir the lemon zest and juice into the sauce, then pour over. Mix gently with a wooden spoon.", "05.Spoon the mash onto the fish mixture, then use a fork to make peaks, which will crisp and brown as it cooks. Sprinkle over the cheese, then bake for 35-40 minutes until golden and bubbling. Serve with wilted greens."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/ysxwuq1487323065.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fish-soup-ukha', 'Fish Soup (Ukha)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'russian', 'themealdb', 'soup'], '[{"quantity": 2.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cups", "item": "Fish Stock", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Cod", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Salmon", "notes": null, "category": "other"}]'::jsonb, '["In a medium pot, heat the olive oil over medium-high heat. Add the onions and cook, stirring occasionally until the onions start to caramelize. Add the carrots and cook until the carrots start to soften, about 4 more minutes.", "Add the stock, water, potatoes, bay leaves, and black peppercorns. Season with salt and bring to a boil. Reduce heat, cover and cook for 10 minutes. Add the millet and cook for 15 more minutes until millet and potatoes are cooked.", "Gently add the fish cubes. Stir and bring the soup to a simmer. The fish will cook through very fast, so make sure to not overcook them. They are done when the flesh is opaque and flakes easily.", "Garnish the soup with chopped fresh dill or parsley before serving."]'::jsonb, 'https://www.curiouscuisiniere.com/ukha-russian-fish-soup/', 'https://www.themealdb.com/images/media/meals/7n8su21699013057.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fish-stew-with-rouille', 'Fish Stew with Rouille', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'french', 'themealdb', 'soup'], '[{"quantity": 1.0, "unit": "serving", "item": "Prawns", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 150.0, "unit": "ml", "item": "Dry White Wine", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "ml", "item": "Fish Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "finely", "notes": "diced Fennel", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "finely", "notes": "diced Onion", "category": "other"}, {"quantity": 3.0, "unit": "cloves", "item": "Chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Orange", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Anise", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.5, "unit": "tsp", "item": "Harissa Spice", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Chopped Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Mussels", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "White Fish", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Bread", "notes": null, "category": "grains"}]'::jsonb, '["Twist the heads from the prawns, then peel away the legs and shells, but leave the tails intact. Devein each prawn. Fry the shells in 1 tbsp oil for 5 mins, until dark pink and golden in patches. Add the wine, boil down by two thirds, then pour in the stock. Strain into a jug, discarding the shells.", "Heat the rest of the oil in a deep frying pan or casserole. Add the fennel, onion and garlic, season, then cover and gently cook for 10 mins until softened. Meanwhile, peel the potato and cut into 2cm-ish chunks. Put into a pan of cold water, bring to the boil and cook for 5 mins until almost tender. Drain in a colander.", "Peel a strip of zest from the orange. Put the zest, star anise, bay and ½ tsp harissa into the pan. Fry gently, uncovered, for 5-10 mins, until the vegetables are soft, sweet and golden.", "Stir in the tomato purée, cook for 2 mins, then add the tomatoes and stock. Simmer for 10 mins until the sauce thickens slightly. Season to taste. The sauce can be made ahead, then reheated later in the day. Meantime, scrub the mussels or clams and pull away any stringy beards. Any that are open should be tapped sharply on the worktop – if they don’t close after a few seconds, discard them.", "Reheat the sauce if necessary, then stir the potato, chunks of fish and prawns very gently into the stew. Bring back to the boil, then cover and gently simmer for 3 mins. Scatter the mussels or clams over the stew, then cover and cook for 2 mins more or until the shells have opened wide. Discard any that remain closed. The chunks of fish should flake easily and the prawns should be pink through. Scatter with the thyme leaves.", "To make the quick rouille, stir the rest of the harissa through the mayonnaise. Serve the stew in bowls, topped with spoonfuls of rouille, which will melt into the sauce and enrich it. Have some good bread ready, as you’ll definitely want to mop up the juices."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/532640/summer-fish-stew-with-rouille', 'https://www.themealdb.com/images/media/meals/vptqpw1511798500.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fiskesuppe-creamy-norwegian-fish-soup', 'Fiskesuppe (Creamy Norwegian Fish Soup)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'norwegian', 'themealdb', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "lb", "item": "Fish fillet", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "clove", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leek", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 5.0, "unit": "tablespoons", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 4.0, "unit": "cups", "item": "Fish Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.25, "unit": "cup", "item": "Creme Fraiche", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "cup", "item": "Shrimp", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Chives", "notes": null, "category": "other"}]'::jsonb, '["▢", "Cut the fish fillets in cubes or strips. Crush or chop the garlic. Rinse the vegetables and cut into thin strips.", "▢", "Heat the butter in a pot and add the garlic. Once the garlic starts to turn golden add the flour, whisking well.", "▢", "Add the fish stock and continue to whisk until there are no lumps.", "▢", "Add the vegetables and milk and bring to a boil. Cook for about 10 minutes.", "▢", "Add the crème fraîche (or sour cream). Bring the soup back to a simmer and once the soup begins to bubble again turn off the heat. Keep the soup on the burner and add the fish. Let the fish cook in the hot soup for 5 minutes. If using shrimp, add right before serving.", "▢", "Sprinkle with chives (or dill or parsley) before serving."]'::jsonb, 'https://scandinaviancookbook.com/fiskesuppe-creamy-norwegian-fish-soup/', 'https://www.themealdb.com/images/media/meals/raqjbj1762773035.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fried-calamari', 'Fried calamari', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'spanish', 'themealdb', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 300.0, "unit": "g", "item": "Squid", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Capers", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Mayonnaise", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Lemon", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Cut the squid into rings about ½cm thick. Tip the flour into a freezer bag and season well. Add the capers, then give everything a good shake to mix together. Tip the squid into the bag, then shake again until all the rings are well coated. Mix together the garlic and mayonnaise, then place in a serving bowl.", "step 2", "Pour some oil into a large pan until it comes about 7cm up the sides, but the pan is no more than a third full. Place over a medium heat and let the oil warm up. To test that the oil is ready, place a small piece of bread in the pan – it should sizzle when it touches the oil.", "step 3", "Remove a handful of squid from the flour and shake off any excess. Gently drop into the oil, then cook for about 3 mins until crisp. Remove with a slotted spoon and place on kitchen paper. Repeat with the remaining squid. Serve straight away with the mayonnaise and lemon wedges."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/crispy-squid-capers', 'https://www.themealdb.com/images/media/meals/yhi46r1763330279.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('gambas-al-ajillo', 'Gambas al ajillo', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'spanish', 'themealdb', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "King Prawns", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 100.0, "unit": "ml", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "chopped Parsley", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Peel the prawns, leaving the tails intact, and, using a cocktail stick, remove the digestive tracts. Or, if you are using a frying pan rather than a terracotta pot, you can cook the prawns in their shells. Season with a little sea salt.", "step 2", "Put the garlic, olive oil and chillies in a flameproof terracotta pot or frying pan and set over a high heat. When the garlic starts to turn golden, add the prawns and cook for 1-2 mins on each side until just pink. Sprinkle over the chopped parsley and some freshly cracked black pepper, and serve immediately. If using a terracotta pot, you can take that straight to the table, but be careful with it as the oil and terracotta will remain hot for several minutes."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/gambas-al-ajillo', 'https://www.themealdb.com/images/media/meals/ze8uwg1763196123.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('garides-saganaki', 'Garides Saganaki', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'greek', 'themealdb', 'vegetarian'], '[{"quantity": 500.0, "unit": "g", "item": "Raw king prawns", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Olive oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Freshly", "notes": "chopped parsley", "category": "other"}, {"quantity": 250.0, "unit": "ml", "item": "White wine", "notes": null, "category": "other"}, {"quantity": 400.0, "unit": "g", "item": "Chopped tomatoes", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Minced garlic", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Cubed Feta cheese", "notes": null, "category": "dairy"}]'::jsonb, '["Place the prawns in a pot and add enough water to cover. Boil for 5 minutes. Drain, reserving the liquid, and set aside.", "Heat 2 tablespoons of oil in a saucepan. Add the onion; cook and stir until soft. Mix in the parsley, wine, tomatoes, garlic and remaining olive oil. Simmer, stirring occasionally, for about 30 minutes, or until the sauce is thickened.", "While the sauce is simmering, the prawns should become cool enough to handle. First remove the legs by pinching them, and then pull off the shells, leaving the head and tail on.", "When the sauce has thickened, stir in the prawns. Bring to a simmer again if the sauce has cooled with the prawns, and cook for about 5 minutes. Add the feta and remove from the heat. Let stand until the cheese starts to melt. Serve warm with slices of crusty bread.", "Though completely untraditional, you can add a few tablespoons of stock or passata to this recipe to make a delicious pasta sauce. Toss with pasta after adding the feta, and serve."]'::jsonb, NULL, 'https://www.themealdb.com/images/media/meals/wuvryu1468232995.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('garlicky-prawns-with-sherry', 'Garlicky prawns with sherry', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'spanish', 'themealdb', 'vegetarian', 'vegan'], '[{"quantity": 3.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "cloves", "item": "Chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Prawns", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbsp", "item": "Dry sherry", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Parsley", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat the olive oil in a large frying pan. Tip in the garlic slices and cook for a few secs. Then stir through the prawns and cook for a couple of mins until they start to turn pink.", "step 2", "Pour over the sherry and cook for a few mins more, just until the prawns are cooked through. Sprinkle with parsley before serving."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/garlicky-prawns-sherry', 'https://www.themealdb.com/images/media/meals/u2lhqb1763331899.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('grilled-portuguese-sardines', 'Grilled Portuguese sardines', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'portuguese', 'themealdb', 'grilling', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Sardines", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Rosemary", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chilli", "notes": null, "category": "other"}]'::jsonb, '["STEP 1", "Put all of the ingredients, except the sardines, into a bowl and mix together with some seasoning. Pour into a baking dish, add the sardines and toss really well. Cover and chill for a few hours.", "STEP 2", "Heat a BBQ or griddle pan until hot. Cook the sardines for 4-5 minutes on each side or until really caramelised and charred. Put onto a serving plate, drizzle with oil, sprinkle with a little more paprika and squeeze over the lemon wedges."]'::jsonb, 'https://www.olivemagazine.com/recipes/fish-and-seafood/grilled-portuguese-sardines/', 'https://www.themealdb.com/images/media/meals/lpd4wy1614347943.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('honey-teriyaki-salmon', 'Honey Teriyaki Salmon', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'japanese', 'themealdb'], '[{"quantity": 1.0, "unit": "lb", "item": "Salmon", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Olive oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Sake", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Sesame Seed", "notes": null, "category": "pantry"}]'::jsonb, '["Mix all the ingredients in the Honey Teriyaki Glaze together. Whisk to blend well. Combine the salmon and the Glaze together.", "Heat up a skillet on medium-low heat. Add the oil, Pan-fry the salmon on both sides until it’s completely cooked inside and the glaze thickens.", "Garnish with sesame and serve immediately."]'::jsonb, NULL, 'https://www.themealdb.com/images/media/meals/xxyupu1468262513.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamaican-curry-shrimp-recipe', 'Jamaican Curry Shrimp Recipe', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'jamaican', 'themealdb'], '[{"quantity": 1.0, "unit": "lb", "item": "Jumbo Shrimp", "notes": null, "category": "other"}, {"quantity": 2.5, "unit": "tbsp", "item": "Jamaican Curry Powder", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "All-purpose Seasoning", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Green Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Scotch Bonnet", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "cloves", "item": "Chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 380.0, "unit": "g", "item": "Unsweetened Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "tbs", "item": "Tomato Ketchup", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Season shrimp with 1 Tablespoon of curry powder and all-purpose seasoning and set aside for about 10 minutes while you prepare the other ingredients like chopping your onions, peppers, and garlic.", "Heat 2 Tablespoons of olive oil in a large skillet over medium heat. Add sliced yellow onion, red bell pepper, green bell pepper, scotch bonnet pepper, if using, and chopped garlic and stir for 5 minutes, until peppers are slightly softened.", "Add 1.5 Tablespoons of curry powder to the skillet and stir for an additional minute.", "Then add coconut milk, seasoned shrimp, ketchup, and thyme, making sure the shrimp is covered in the sauce.", "Allow the sauce to come to a simmer and continue to cook over medium heat, stirring occasionally and flipping the shrimp halfway, until the shrimp is fully cooked on both sides. This should take about 5-6 minutes. Salt and pepper to taste."]'::jsonb, 'https://www.myforkinglife.com/jamaican-curry-shrimp/#recipe', 'https://www.themealdb.com/images/media/meals/n7h5zs1765318909.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamaican-pepper-shrimp', 'Jamaican Pepper Shrimp', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'jamaican', 'themealdb', 'soup'], '[{"quantity": 1.0, "unit": "lb", "item": "Shrimp", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Scotch Bonnet", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "All-purpose Seasoning", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "Ground Annatto", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 0.75, "unit": "cup", "item": "Shrimp Stock", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "cup", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "White Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}]'::jsonb, '["In a medium bowl, combine shrimp with minced Scotch Bonnet peppers, all-purpose seasoning, ground annatto, and grounf allspice. Toss well to coat evenly and let marinate for 10 minutes.", "Heat a large pan over medium heat. Add the shrimp stock and bring to a gentle simmer. Stir in the diced onion and garlic, cooking until softened and fragrant, about 2 minutes.", "Add the seasoned shrimp and thyme sprigs, spreading the shrimp in the pan. Cover and cook for about 5–7 minutes, stirring occasionally, until the shrimp turn bright orange and are cooked through.", "Add the white vinegar, stir, and cook for another minute. Taste; add salt to taste. Using a slotted spoon, transfer the shrimp to a plate. Serve hot with some cooking liquid drizzled on top."]'::jsonb, 'https://www.myforkinglife.com/jamaican-pepper-shrimp-recipe/#recipe', 'https://www.themealdb.com/images/media/meals/bx07m71764792853.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('kedgeree', 'Kedgeree', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'british', 'themealdb', 'vegetarian'], '[{"quantity": 300.0, "unit": "g", "item": "Smoked Haddock", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 300.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tbs", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tsp", "item": "Curry Powder", "notes": null, "category": "spices"}, {"quantity": 300.0, "unit": "g", "item": "Rice", "notes": null, "category": "grains"}]'::jsonb, '["For the rice, heat the oil in a large, lidded pan, add the onion, then gently fry for 5 mins until softened but not coloured. Add the spices, season with salt, then continue to fry until the mix start to go brown and fragrant; about 3 mins.", "Add the rice and stir in well. Add 600ml water, stir, then bring to the boil. Reduce to a simmer, then cover for 10 mins. Take off the heat and leave to stand, covered, for 10-15 mins more. The rice will be perfectly cooked if you do not lift the lid before the end of the cooking.", "Meanwhile, put the haddock and bay leaves in a frying pan, cover with the milk, then poach for 10 mins until the flesh flakes. Remove from the milk, peel away the skin, then flake the flesh into thumbsize pieces. Place the eggs in a pan, cover with water, bring to the boil, then reduce to a simmer. Leave for 4½-5 mins, plunge into cold water, then peel and cut the eggs into quarters. Gently mix the fish, eggs, parsley, coriander and rice together in the pan. Serve hot, sprinkled with a few extra herbs."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/10421/kedgeree', 'https://www.themealdb.com/images/media/meals/utxqpt1511639216.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('kung-po-prawns', 'Kung Po Prawns', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'chinese', 'themealdb', 'dessert', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 400.0, "unit": "g", "item": "Prawns", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Corn Flour", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 85.0, "unit": "g", "item": "Peanuts", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbs", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 6.0, "unit": "cloves", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 450.0, "unit": "g", "item": "Water Chestnut", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "to taste Ginger", "notes": null, "category": "produce"}]'::jsonb, '["Mix the cornflour and 1 tbsp soy sauce, toss in the prawns and set aside for 10 mins. Stir the vinegar, remaining soy sauce, tomato purée, sugar and 2 tbsp water together to make a sauce.", "When you’re ready to cook, heat a large frying pan or wok until very hot, then add 1 tbsp oil. Fry the prawns until they are golden in places and have opened out– then tip them out of the pan.", "Heat the remaining oil and add the peanuts, chillies and water chestnuts. Stir-fry for 2 mins or until the peanuts start to colour, then add the ginger and garlic and fry for 1 more min. Tip in the prawns and sauce and simmer for 2 mins until thickened slightly. Serve with rice."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/1415664/kung-po-prawns', 'https://www.themealdb.com/images/media/meals/1525873040.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('laksa-king-prawn-noodles', 'Laksa King Prawn Noodles', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'malaysian', 'themealdb', 'soup', 'pasta'], '[{"quantity": 1.0, "unit": "tbsp", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "sliced Red Chilli", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tbsp", "item": "Thai red curry paste", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "stock cube", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "ml", "item": "can coconut milk", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tsp", "item": "fish sauce", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "rice noodles", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "of 1", "notes": "the other halved lime", "category": "other"}, {"quantity": 150.0, "unit": "g", "item": "king prawns", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "pack coriander", "notes": null, "category": "spices"}]'::jsonb, '["Heat the oil in a medium saucepan and add the chilli. Cook for 1 min, then add the curry paste, stir and cook for 1 min more. Dissolve the stock cube in a large jug in 700ml boiling water, then pour into the pan and stir to combine. Tip in the coconut milk and bring to the boil.", "Add the fish sauce and a little seasoning. Toss in the noodles and cook for a further 3-4 mins until softening. Squeeze in the lime juice, add the prawns and cook through until warm, about 2-3 mins. Scatter over some of the coriander.", "Serve in bowls with the remaining coriander and lime wedges on top for squeezing over."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/prawn-laksa-curry-bowl', 'https://www.themealdb.com/images/media/meals/rvypwy1503069308.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mediterranean-pasta-salad', 'Mediterranean Pasta Salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'italian', 'themealdb', 'salad', 'pasta'], '[{"quantity": 200.0, "unit": "g", "item": "mozzarella balls", "notes": null, "category": "dairy"}, {"quantity": 250.0, "unit": "g", "item": "baby plum tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "bunch", "item": "fresh basil", "notes": null, "category": "produce"}, {"quantity": 350.0, "unit": "g", "item": "farfalle", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tablespoons", "item": "extra virgin olive oil", "notes": null, "category": "pantry"}, {"quantity": 40.0, "unit": "g", "item": "Green Olives", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "tuna", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "to taste salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "to taste pepper", "notes": null, "category": "produce"}]'::jsonb, '["Bring a large saucepan of salted water to the boil", "Add the pasta, stir once and cook for about 10 minutes or as directed on the packet.", "Meanwhile, wash the tomatoes and cut into quarters. Slice the olives. Wash the basil.", "Put the tomatoes into a salad bowl and tear the basil leaves over them. Add a tablespoon of olive oil and mix.", "When the pasta is ready, drain into a colander and run cold water over it to cool it quickly.", "Toss the pasta into the salad bowl with the tomatoes and basil.", "Add the sliced olives, drained mozzarella balls, and chunks of tuna. Mix well and let the salad rest for at least half an hour to allow the flavours to mingle.", "Sprinkle the pasta with a generous grind of black pepper and drizzle with the remaining olive oil just before serving."]'::jsonb, 'https://thelemonsqueezy.com/recipe/mediterranean-pasta-salad/', 'https://www.themealdb.com/images/media/meals/wvqpwt1468339226.jpg', FALSE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mee-goreng-mamak', 'Mee goreng mamak', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'malaysian', 'themealdb', 'pasta', 'vegetarian'], '[{"quantity": 50.0, "unit": "g", "item": "Peanuts", "notes": null, "category": "pantry"}, {"quantity": 15.0, "unit": "g", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 10.0, "unit": "g", "item": "Prawns", "notes": null, "category": "other"}, {"quantity": 5.0, "unit": "tbs", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 750.0, "unit": "ml", "item": "Water", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tbs", "item": "Tamarind Paste", "notes": null, "category": "other"}, {"quantity": 250.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 30.0, "unit": "g", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 30.0, "unit": "g", "item": "Chinese Broccoli", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tofu", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbs", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Noodles", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}]'::jsonb, '["Heat oil in a pan at medium heat. Then, add peanuts, dried chilies, dried shrimps and dhal. Fry the aromatics until fragrant. Remove from pan and leave aside.", "Blend fried ingredients with tamarind paste and water until fine. Then, sauté the blended ingredients in oil heated over low heat. Continue cooking until the oil separates from the paste and turns a darker shade.", "Skin and cut potatoes into small chunks and boil them in a pot of water until knife-tender. Once ready, remove them from the pot and leave aside. Discard water.", "Slice onion and fried tofu, mince garlic, cut some cabbage and Chinese flowering cabbage (choi sam). Prepare prawn fritters and cut them. Boil noodles to soften them if bought dried. Also mix black soy sauce with water.", "To fry one portion of mee goreng mamak, heat oil and add 1/4 of the following ingredients in this order: garlic, onion, paste. Sauté until fragrant. Optionally, add prawns.", "Add in 1/4 amount of tofu, boiled potatoes, cabbage, Chinese flowering cabbage and prawn fritters. Sauté for another 30 seconds.", "Add noodles to the wok. Add 3 tablespoons of dark soy sauce mixture. Mix evenly for the next 1 minute. Then, move the noodles to the side of the wok. Stir in an egg. Garnish with a slice of lime and slices of green chilies. To cook another plate of noodles, repeat from step 5 onwards."]'::jsonb, 'https://www.nyonyacooking.com/recipes/mee-goreng-mamak~BkTLRjTuX', 'https://www.themealdb.com/images/media/meals/xquakq1619787532.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('napa-cabbage-with-dried-shrimp', 'Napa Cabbage with Dried Shrimp', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'chinese', 'themealdb'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "Dried Shrimp", "notes": null, "category": "other"}, {"quantity": 0.75, "unit": "cup", "item": "Boiling Water", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "head", "item": "Napa Cabbage", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Peanut Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Scallions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Water", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Kosher Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Dried shrimp gives this Chinese dish a punch of salty umami flavor. You can find it at an Asian grocery store in the frozen or refrigerated section. Look for small-sized dried shrimp, about a 1/4-inch in size. If you use medium or large dried shrimp, hydrate the shrimp with more water (1 cup for medium-sized shrimp, 1 1/4 cup for large) and for longer time (45 to 60 minutes), then chop it up into smaller 1/4-inch chunks. To make this recipe vegetarian, omit the dried shrimp and use four or five dried shiitake mushrooms, rehydrated, and sliced thin.", "Rehydrate the dried shrimp:", "Place the dried shrimp in a small bowl and pour the boiling water over it. Cover with a small plate and let sit for 30 minutes so the shrimp can rehydrate. The shrimp will be lighter in color and plump up slightly.", "Prep the cabbage:", "Meanwhile, split the napa cabbage in half lengthwise. Rinse the cabbage and shake it dry. Cut out the core of the cabbage and discard.", "Set out two large bowls. Cut the remaining cabbage into 1-inch pieces, putting the thicker white pieces at the bottom of the cabbage into one bowl and the top thinner leafy green pieces into the other bowl.", "Drain the shrimp:", "Once the shrimp has rehydrated, drain it and discard the liquid.", "Cook the shrimp and cabbage:", "In a large wok or skillet over high heat add the peanut oil, swirling it around to coat the pan.", "Heat until the oil looks shimmering hot, then carefully add the scallions, ginger, and rehydrated shrimp, paying specially attention as the wet ingredients may cause the hot oil to splatter. Toss with a spatula until the scallions are bright green and the entire mixture is fragrant, about 1 minute.", "Add the thicker white part of the napa cabbage to the pan and lower the heat to medium high. Continue to cook and stir for 3 to 4 minutes, or until the edges of the cabbage pieces start to look slightly translucent but the center of the cabbage pieces are still opaque white.", "Reduce the heat to medium low and add the leafy green pieces of cabbage into the pan. Cook until the leaves are wilted, about 2 minutes.", "Make a cornstarch slurry:", "In a small bowl, combine the soy sauce, cold water, and cornstarch, stirring to make a slurry. Then pour over the cabbage and continue to cook and stir until a sauce has thickened slightly to the consistency of whole milk.", "Season the stir fry:", "Season the stir fry with salt and pepper, then taste and add more salt and pepper if you wish. The cabbage will be translucent and silky looking, with specks of dried shrimp all over."]'::jsonb, 'https://www.simplyrecipes.com/napa-cabbage-dried-shrimp-recipe-5208805', 'https://www.themealdb.com/images/media/meals/9nh4dl1766435484.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('nasi-lemak', 'Nasi lemak', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'malaysian', 'themealdb', 'dessert'], '[{"quantity": 2.0, "unit": "cups", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "tsp", "item": "Ginger Paste", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "cups", "item": "Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Cucumber", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Peanuts", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "oz", "item": "Anchovy Fillet", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Chilli Powder", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "oz", "item": "Anchovy Fillet", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tbs", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Tamarind Paste", "notes": null, "category": "other"}]'::jsonb, '["In a medium saucepan over medium heat, stir together coconut milk, water, ground ginger, ginger root, salt, bay leaf, and rice. Cover, and bring to a boil. Reduce heat, and simmer for 20 to 30 minutes, or until done.", "Step 2", "Place eggs in a saucepan, and cover with cold water. Bring water to a boil, and immediately remove from heat. Cover, and let eggs stand in hot water for 10 to 12 minutes. Remove eggs from hot water, cool, peel and slice in half. Slice cucumber.", "Step 3", "Meanwhile, in a large skillet or wok, heat 1 cup vegetable oil over medium-high heat. Stir in peanuts and cook briefly, until lightly browned. Remove peanuts with a slotted spoon and place on paper towels to soak up excess grease. Return skillet to stove. Stir in the contents of one package anchovies; cook briefly, turning, until crisp. Remove with a slotted spoon and place on paper towels. Discard oil. Wipe out skillet.", "Step 4", "Heat 2 tablespoons oil in the skillet. Stir in the onion, garlic, and shallots; cook until fragrant, about 1 or 2 minutes. Mix in the chile paste, and cook for 10 minutes, stirring occasionally. If the chile paste is too dry, add a small amount of water. Stir in remaining anchovies; cook for 5 minutes. Stir in salt, sugar, and tamarind juice; simmer until sauce is thick, about 5 minutes.", "Step 5", "Serve the onion and garlic sauce over the warm rice, and top with peanuts, fried anchovies, cucumbers, and eggs."]'::jsonb, 'https://www.allrecipes.com/recipe/78938/malaysian-nasi-lemak/', 'https://www.themealdb.com/images/media/meals/wai9bw1619788844.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('noodle-bowl-salad', 'Noodle bowl salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'vietnamese', 'themealdb', 'dessert', 'salad', 'pasta'], '[{"quantity": 125.0, "unit": "g", "item": "Rice Noodles", "notes": null, "category": "grains"}, {"quantity": 200.0, "unit": "g", "item": "Sugar Snap Peas", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander", "notes": null, "category": "spices"}, {"quantity": 150.0, "unit": "g", "item": "Hot Smoked Flaked Salmon", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Pretzels", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Clear Honey", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Ground Nut Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "clove", "item": "finely", "notes": "chopped Garlic", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Knob Ginger", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Drop the noodles into a large bowl, then pour over enough boiling water to cover. Tip in the sliced sugar snaps and leave for 4 minutes. Drain in a colander, put under cold running water to cool off, then drain again. Tip into a bowl and toss in the sesame oil.", "step 2", "Mix the dressing ingredients. Pile spring onions, coriander and salmon onto the noodles, pour over the dressing and toss everything together. Serve with a pretzel or bread roll."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/noodle-bowl-salad', 'https://www.themealdb.com/images/media/meals/zry07j1763779321.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pad-thai', 'Pad Thai', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'thai', 'themealdb', 'dessert', 'pasta'], '[{"quantity": 125.0, "unit": "g", "item": "Rice Noodles", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 3 Lime", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Cayenne Pepper", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "Muscovado Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Tiger Prawns", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "sliced Spring Onions", "notes": null, "category": "produce"}, {"quantity": 140.0, "unit": "g", "item": "Bean Sprouts", "notes": null, "category": "other"}, {"quantity": 25.0, "unit": "g", "item": "Peanuts", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To serve sweet chilli sauce", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Put the noodles in a large heatproof bowl, pour boiling water over them and leave for 4 minutes, then drain and refresh under cold running water.", "step 2", "Put the lime juice, cayenne, sugar and fish sauce in a bowl and mix well. Have all the other ingredients ready by the cooker.", "step 3", "Heat the oil and fry the prawns until warmed through. Add the spring onions and noodles and toss around. Tip in the lime juice mixture, then stir in the beansprouts and half the peanuts and coriander. Cook for 1 minute until everything is heated through.", "step 4", "Pile into a large dish, scatter with the rest of the peanuts and coriander, and serve with lime wedges and sweet chilli sauce."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/easy-pad-thai', 'https://www.themealdb.com/images/media/meals/rg9ze01763479093.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('paella', 'Paella', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'spanish', 'themealdb', 'vegetarian', 'vegan'], '[{"quantity": 3.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "tiger prawns", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "ml", "item": "Dry sherry", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "g", "item": "Mussels", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Saffron", "notes": null, "category": "spices"}, {"quantity": 150.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Squid", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 250.0, "unit": "g", "item": "Paella Rice", "notes": null, "category": "grains"}, {"quantity": 100.0, "unit": "g", "item": "Broad Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Zest", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Heat 1 tbsp of the oil in a wide, shallow pan. Add the prawn heads and parsley stalks and sizzle until the heads turn pink, then mash with a potato masher. Pour over the sherry or wine and 300ml water, season with salt and simmer for 10 mins to make a stock, mashing the prawn heads as they cook.", "step 2", "Scatter the mussels into the pan, cover the pan loosely with a lid or tea towel, then put over a high heat for 3-4 mins until the mussels just open. Stir to release the mussel juices, then pour the contents of the pan into a colander set over a large bowl containing the saffron. Let the saffron steep in the stock – you will need 700ml in total, so top up with water if needed and give everything a good stir. Pick the mussels out from the colander, then set aside.", "step 3", "Wipe out the pan and add the rest of the olive oil. Sizzle the chorizo until it releases its oil, then add the onion and garlic and cook until softened. Add the squid and turn over until it turns white. Add the tomatoes and cook down for a minute, then pour over most of the stock, give everything a good stir and bring to the boil. Scatter the rice over the stock, stir well once, then boil vigorously for 5 mins. Reduce the heat to the lowest setting and slowly simmer for 10 mins without stirring until the rice has absorbed most of the liquid.", "step 4", "Tuck the prawn tails into the rice and simmer for 5 mins, turning them over until cooked through. Stir through the mussels and broad beans or peas. Taste the rice – if it is still a little raw but the pan is dry, add a splash more stock and continue to cook; if it’s too soupy, then increase the heat to cook off the last of the stock.", "step 5", "Once the rice is just cooked, turn off the heat and cover with a tea towel for a few minutes. Scatter over the parsley leaves and lemon zest, then season with smoked salt if you like. Stir everything once, then serve straight from the pan, with lemon wedges on the side."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/next-level-paella', 'https://www.themealdb.com/images/media/meals/9bl20p1763248192.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pan-fried-hake-white-bean-chorizo-broth', 'Pan-fried hake, white bean & chorizo broth', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'spanish', 'themealdb', 'soup'], '[{"quantity": 450.0, "unit": "g", "item": "Dried white beans", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 6.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 100.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "l", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Hake", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Drain the beans, then tip into a large pan with 2 litres of water. Simmer with the whole garlic cloves, bay leaves and thyme for 30 mins or until cooked and tender. Remove from the heat and set aside.", "step 2", "Meanwhile, heat 2 tbsp oil in a frying pan. Fry the bread with the remaining garlic clove. When golden and crisp, scoop out and drain on kitchen paper. Add the chorizo to the pan, fry until crisp, tip out and keep warm with the bread.", "step 3", "Add another 2 tbsp oil and the onion to the pan, and cook for 5 mins until softened. Stir in the paprika. Drain the beans and add to the onions with the chicken stock and 2 tsp salt. Cook for 5-10 mins. Stir through the parsley and keep warm.", "step 4", "Season the hake and heat the remaining 2 tbsp oil in the frying pan. Put the hake, skin-side down, in the pan and cook for 3-5 mins over a mediumhigh heat to crisp up the skin. Flip the fish over and cook for a further 3-5 mins until cooked through. Spoon the white bean mix into bowls, place the hake on top and finish with the fried bread, chorizo and a little more thyme."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/pan-fried-hake-white-bean-chorizo-broth', 'https://www.themealdb.com/images/media/meals/4yjart1763248459.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('portuguese-fish-stew-caldeirada-de-peixe', 'Portuguese fish stew (Caldeirada de peixe)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'portuguese', 'themealdb', 'soup', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "chopped Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Small bunch Coriander", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "ml", "item": "Dry White Wine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Saffron", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 300.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Plum Tomatoes", "notes": null, "category": "produce"}, {"quantity": 600.0, "unit": "g", "item": "Cod", "notes": null, "category": "other"}, {"quantity": 300.0, "unit": "g", "item": "Squid", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Prawns", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "g", "item": "Clams", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "g", "item": "Mussels", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Baguette", "notes": null, "category": "other"}]'::jsonb, '["STEP 1", "Heat a drizzle of oil in a large, deep-sided frying pan, and fry the onion and pepper on a medium heat until softened but not browned. Finely chop the coriander stalks (keep the leaves for later), and add to the pan with the chilli and chopped garlic. Fry for another few minutes. Add the wine, saffron and bay leaf and let it simmer until reduced by half.", "STEP 2", "Add the potatoes, tomatoes, and 300ml water and bring to a gentle boil. Break up the tomatoes with a spoon on the side of the pan and simmer for 20-25 minutes until the potatoes are just tender, and the tomatoes have broken down.", "STEP 3", "Season well, then gently push the fish into the sauce, and arrange the squid, prawns, clams and mussels on the surface. Put the lid on and cook for 6-8 minutes until the mussel and clam shells have opened, the prawns are cooked and the fish is flaky. Toast the bread, rub lightly with the halved garlic clove and drizzle with olive oil. Serve the stew scatted with chopped coriander leaves, and the toasts for dunking."]'::jsonb, 'https://www.olivemagazine.com/recipes/one-pots/portuguese-fish-stew-caldeirada-de-peixe/', 'https://www.themealdb.com/images/media/meals/do7zps1614349775.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('prawn-noodle-salad-with-crispy-shallots', 'Prawn & noodle salad with crispy shallots', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'vietnamese', 'themealdb', 'dessert', 'salad', 'pasta', 'baking'], '[{"quantity": 200.0, "unit": "g", "item": "Rice Noodles", "notes": null, "category": "grains"}, {"quantity": 200.0, "unit": "g", "item": "Prawns", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Cucumber", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Mint", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Roasted Peanut", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 3 Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 5.0, "unit": "slices", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Sprinkling Flour", "notes": null, "category": "grains"}]'::jsonb, '["step 1", "For the crispy shallots, heat 5cm of oil until hot in a wok. You will know the oil is hot enough when one piece of shallot sizzles as soon as it’s dropped in. Toss the shallot slices with flour, shake off excess and fry in the oil until golden. They fry quickly, about 1 min. Drain on kitchen paper, sprinkle with salt and set aside.", "step 2", "To make the dressing, mix the lime juice, sugar, fish sauce and garlic and set aside. In a large mixing bowl, pour boiling water over the noodles. Leave them for 2 mins or until they are just cooked, then rinse under cold water. Drain well, shaking the sieve numerous times to get out the excess water, then place back in the bowl. Add prawns, onion, chilli, cucumber and herbs. Pour the dressing over, mix, then sprinkle with the shallots and peanuts."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/vietnamese-prawn-noodle-salad-crispy-shallots', 'https://www.themealdb.com/images/media/meals/0iryz91763778419.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('prawn-stir-fry', 'Prawn stir-fry', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'thai', 'themealdb', 'dessert', 'pasta'], '[{"quantity": 200.0, "unit": "g", "item": "Raw tiger prawns", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Green Chilli", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "cloves", "item": "Crushed Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "bunch", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1 Lime", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbsp", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Ground Nut Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "piece Ginger", "notes": null, "category": "produce"}, {"quantity": 8.0, "unit": "slices", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 85.0, "unit": "g", "item": "Water Chestnut", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Bean Sprouts", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Rice Noodles", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Lime", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Put the prawns in a bowl. Put the chilli, garlic, coriander stalks (snip these up using scissors first) and caster sugar in a spice grinder or small food processor and whizz together. Add half of the lime juice and the fish sauce, then pour this over the prawns.", "step 2", "Heat 1 tbsp oil in a wok, add the ginger and spring onions and fry for 1 min. Add the red pepper and fry for 1 min, until the pepper starts to soften. Add the water chestnuts and bean sprouts, and toss together until the bean sprouts start to wilt. Add the soy sauce and a really good grind of black pepper, then tip the lot into a serving dish.", "step 3", "Heat the remaining oil in the wok and add the prawns, lifting them out of their juices. Toss for 1-2 mins until they turn pink, add the marinade and swirl the wok quickly, then tip the lot onto the veg. Snip over the coriander leaves and sprinkle on the remaining lime. Serves over noodles with extra lime for squeezing over."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/thai-prawn-ginger-spring-onion-stir-fry', 'https://www.themealdb.com/images/media/meals/96lt871763480970.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('prawns-with-romesco-sauce', 'Prawns with Romesco sauce', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'spanish', 'themealdb', 'grilling', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Hazelnuts", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 120.0, "unit": "ml", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Red Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Tiger Prawns", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Prepare ahead - halve the pepper lengthways and remove the seeds and stalk. Line a grill pan with foil and put the pepper halves, skin side up, on the grill pan with the whole garlic cloves, chilli and tomato. Grill for 2 minutes, turn the tomato, then grill for a further 2 minutes. Remove the tomato with a large spoon, then peel, quarter and remove the seeds. Then chop the tomato roughly.", "step 2", "Continue grilling the pepper, chilli and garlic for 4-5 minutes, until the pepper and chilli skins have blackened and the garlic is starting to soften (the garlic skin will start to split when it is ready). When cool enough to handle, peel and halve the chilli, and scrape out and discard the seeds. Peel the pepper and roughly chop both the pepper and chilli.", "step 3", "Spread nuts over the foil and grill until toasted. Finely chop the nuts and parsley in a food processor. Tip into a small bowl.", "step 4", "Heat 3 tablespoons of oil in a frying pan, add the pepper, garlic and chilli and fry for 3 minutes. Tear up the bread and add to the pan, turning it in the oil until lightly browned. Pulse in food processor with the tomatoes, salt, vinegar and oil until roughly chopped. Tip into a bowl. Leave to cool and store in fridge for up to 3 days.", "step 5", "On the day add the nuts and parsley to the sauce and mix. Serve in a small bowl on a plate with the peeled prawns. Supply cocktail sticks for spearing the prawns."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/prawns-romesco-sauce', 'https://www.themealdb.com/images/media/meals/u03xhi1763308917.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('quick-salt-pepper-squid', 'Quick salt & pepper squid', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'australian', 'themealdb', 'grilling', 'vegetarian', 'vegan'], '[{"quantity": 400.0, "unit": "g", "item": "Squid", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Chinese five spice powder", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Sprigs of", "notes": "fresh Coriander", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Drizzle sweet chilli sauce", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Ask the fishmonger to clean the squid; little ones often come ready-cleaned. Using kitchen scissors, cut open the body and open out. Wash well, then pat dry. If you have a large squid, cut the body into four portions, roughly square. Small squid can just be opened up.", "step 2", "Using the tip of a very sharp knife, score the top in a neat criss-cross. Brush with oil and set aside while you heat the barbecue or griddle until ready to cook.", "step 3", "Mix together 2 tsp sea salt, Chinese five-spice and 1 tsp freshly ground black pepper. Sprinkle on both sides of the squid just before cooking, according to taste. You may not need it all. Heat the griddle pan to hot and cook about 1 min each side, until it starts to curl. Remove with tongs to a serving plate and drizzle with a little sesame oil. To serve, garnish with coriander leaves and serve with small bowls of sweet chilli sauce to dip into."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/salt-pepper-squid-0', 'https://www.themealdb.com/images/media/meals/cp74zo1762341241.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('recheado-masala-fish', 'Recheado Masala Fish', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'indian', 'themealdb', 'dessert', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Mackerel", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 8.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.5, "unit": "tsp", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Turmeric", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Cinnamon stick", "notes": null, "category": "spices"}, {"quantity": 4.0, "unit": "cloves", "item": "Cloves", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Cardamom", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tbsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "sized Tamarind ball", "notes": null, "category": "other"}, {"quantity": 2.5, "unit": "tbsp", "item": "Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "for frying Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Soak all the spices, ginger, garlic, tamarind pulp and kashmiri chilies except oil in vinegar.", "Add sugar and salt.", "Also add turmeric powder.", "Combine all nicely and marinate for 35-40 mins.", "Grind the mixture until soft and smooth. Add more vinegar if required but ensure the paste has to be thick so add vinegar accordingly. If the masala paste is thin then it would not stick to the fish.", "Rinse the fish slit from the center and give some incision from the top. You could see the fish below for clarity.", "Now stuff the paste into the center and into the incision. Coat the entire fish with this paste. Marinate the fish for 30 mins.", "Place oil in a shallow pan, once oil is quite hot shallow fry the stuffed mackerels.", "Fry until golden brown from both sides", "Serve the recheado mackerels hot with salad, lime wedges, rice and curry.", "Notes", "1. Ensure the masala paste is thick else the result won''t be good.", "2. If you aren''t able to find kashmiri chilies then use bedgi chilies or kashmiri red chili powder.", "3. You could use white vinegar or coconut vinegar.", "4. Any left over paste could be stored in the fridge for future use.", "5. Cinnamon could be avoided as it''s a strong spice used generally for meat or chicken."]'::jsonb, 'http://www.flavorsofmumbai.com/fish-recheado-masala-recipe/', 'https://www.themealdb.com/images/media/meals/uwxusv1487344500.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('salmon-avocado-salad', 'Salmon Avocado Salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'british', 'themealdb', 'salad'], '[{"quantity": 400.0, "unit": "g", "item": "Salmon", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Avocado", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cucumber", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Spinach", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tbs", "item": "Mint", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "zest and juice of 1 Lime", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Honey", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Season the salmon, then rub with oil. Mix the dressing ingredients together. Halve, stone, peel and slice the avocados. Halve and quarter the cucumber lengthways, then cut into slices. Divide salad, avocado and cucumber between four plates, then drizzle with half the dressing.", "Heat a non-stick pan. Add the salmon and fry for 3-4 mins on each side until crisp but still moist inside. Put a salmon fillet on top of each salad and drizzle over the remaining dressing. Serve warm."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/4521/salmon-avocado-and-cucumber-salad', 'https://www.themealdb.com/images/media/meals/1549542994.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('salmon-noodle-soup', 'Salmon noodle soup', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'vietnamese', 'themealdb', 'dessert', 'soup', 'pasta'], '[{"quantity": 1.0, "unit": "l", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tsp", "item": "Thai Red Curry Paste", "notes": null, "category": "spices"}, {"quantity": 100.0, "unit": "g", "item": "Rice Noodles", "notes": null, "category": "grains"}, {"quantity": 150.0, "unit": "g", "item": "Shiitake Mushrooms", "notes": null, "category": "produce"}, {"quantity": 125.0, "unit": "g", "item": "Sweetcorn", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Salmon", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 2 Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Coriander", "notes": null, "category": "spices"}]'::jsonb, '["step 1", "Pour the stock into a large pan, bring to the boil, then stir in the curry paste. Add the noodles and cook for 8 mins. Tip in the mushrooms and corn and cook for 2 mins more.", "step 2", "Add the salmon to the pan and cook for 3 mins or until cooked through. Remove from the heat and stir in the lime juice, soy sauce and a pinch of sugar. Ladle into 4 bowls and sprinkle over the coriander just before you serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/salmon-noodle-soup', 'https://www.themealdb.com/images/media/meals/ikizdm1763760862.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('salmon-noodle-wraps', 'Salmon noodle wraps', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'vietnamese', 'themealdb', 'pasta', 'baking'], '[{"quantity": 100.0, "unit": "g", "item": "Rice Noodles", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "thinly Spring Onions", "notes": null, "category": "produce"}, {"quantity": 50.0, "unit": "g", "item": "Petit Pois", "notes": null, "category": "other"}, {"quantity": 85.0, "unit": "g", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 85.0, "unit": "g", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 85.0, "unit": "g", "item": "Lime", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Salmon", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Heat oven to 200C/fan 180C/gas 6. Put the noodles in a bowl and pour over enough boiling water to just cover them. Leave for 2 mins, until they are bendable, but not too soft, then drain well. Return to the bowl with the spring onions, petit pois, salt and pepper and a third of the butter. Mix well until the butter has melted.", "step 2", "Pile the noodles and vegetables onto two large squares of baking parchment, then sit the salmon on top. Slice the remaining butter and arrange over the top of the salmon. Bring the ends of the paper over the fish, fold them together to seal, then tuck the ends of the paper underneath so there are no gaps. Put the parcels on a baking sheet and bake for 15-20 mins. Transfer to dinner plates and serve without delay."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/salmon-noodle-wraps', 'https://www.themealdb.com/images/media/meals/prrirc1763781360.jpg', FALSE, 1, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('salmon-prawn-risotto', 'Salmon Prawn Risotto', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'italian', 'themealdb', 'soup', 'grilling'], '[{"quantity": 50.0, "unit": "g", "item": "50g/2oz butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "chopped  onion", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "g", "item": "rice", "notes": null, "category": "grains"}, {"quantity": 125.0, "unit": "ml", "item": "white wine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "hot vegetable stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "The juice and zest of one lemon", "notes": null, "category": "produce"}, {"quantity": 240.0, "unit": "g", "item": "large King Prawns", "notes": null, "category": "other"}, {"quantity": 150.0, "unit": "g", "item": "salmon", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "tips", "notes": "blanched briefly in boiling water asparagus", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "ground black pepper", "notes": null, "category": "produce"}, {"quantity": 50.0, "unit": "g", "item": "shavings Parmesan", "notes": null, "category": "dairy"}]'::jsonb, '["Melt the butter in a thick-based pan and gently cook the onion without colour until it is soft.", "Add the rice and stir to coat all the grains in the butter", "Add the wine and cook gently stirring until it is absorbed", "Gradually add the hot stock, stirring until each addition is absorbed. Keep stirring until the rice is tender", "Season with the lemon juice and zest, and pepper to taste. (there will probably be sufficient saltiness from the salmon to not need to add salt) Stir gently to heat through", "Serve scattered with the Parmesan and seasonal vegetables.", "Grill the salmon and gently place onto the risotto with the prawns and asparagus"]'::jsonb, 'http://www.rangemaster.co.uk/rangemaster-owners/recipes-ideas-inspiration/recipes/mains/prawn-and-hot-smoked-salmon-risotto-with-asparagus', 'https://www.themealdb.com/images/media/meals/xxrxux1503070723.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('salt-pepper-squid', 'Salt & pepper squid', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'vietnamese', 'themealdb', 'dessert', 'baking'], '[{"quantity": 85.0, "unit": "g", "item": "Corn Flour", "notes": null, "category": "produce"}, {"quantity": 85.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Szechuan Peppercorns", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Squid", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Sliced Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sliced Green Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Cucumber", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "ml", "item": "Rice Vinegar", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Fish Sauce", "notes": null, "category": "other"}]'::jsonb, '["step 1", "To make the dipping sauce, mix all the ingredients in a small bowl until the sugar has dissolved, then set aside. Mix the cornflour and plain flour with both peppers and 2 tsp sea salt in a large bowl, then set aside. Line a tray with kitchen paper and make sure you have more salt to sprinkle with.", "step 2", "Heat about 7cm of oil to 180C in a deep fryer, wok or deep pan. If you don’t have a thermometer, you can test it with a cube of bread – it should brown in 20 secs. Coat the squid well with the flour mix and fry in batches for about 2 mins each or until crisp. Use a slotted spoon to lift out the squid, then drain on the kitchen paper and sprinkle with a little more salt. Serve the squid scattered with the spring onion and chilli, with the dipping sauce on the side."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/salt-pepper-squid', 'https://www.themealdb.com/images/media/meals/yxiilf1763759428.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('salt-cod-tortilla', 'Salt cod tortilla', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'spanish', 'themealdb', 'grilling', 'vegetarian'], '[{"quantity": 4.0, "unit": "tbsp", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Onion", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Jersey Royal Potatoes", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 2.5, "unit": "tbs", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Salt Cod", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Heat half the oil in a frying pan, and sauté the onion over a medium heat until soft and pale gold – this will take about 8 mins. Remove from the pan, set aside, and add the potatoes to the pan. Cook until they are tender but not falling apart, carefully turning every so often. Cover the pan some of the time to help the slices cook through. Add the onions back to the pan along with the garlic and cook for another 4 mins. Tip into a bowl with the eggs, parsley and some seasoning and mix together. Leave to sit for half an hour.", "step 2", "Meanwhile, put the cod in a saucepan and cover with water. Bring up to a simmer. Remove from the heat, cover and leave for 10 mins. Drain, leave to cool and remove the skin and any bones. Break into large flakes and add to the potato and egg mixture.", "step 3", "Heat the rest of the oil in a non-stick frying pan. Pour in the tortilla mix and cook over a medium-low heat until it is just set and coming away from the sides of the pan. You might need to cover it to help the centre set. Be careful not to overcook it. Put a spatula underneath the tortilla every so often to make sure it isn’t sticking. Slide the tortilla onto a plate, then put the pan on top and flip the tortilla into it, uncooked side-down. Cook over a low heat until golden, or grill until just set. Leave to cool a little before serving."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/salt-cod-tortilla', 'https://www.themealdb.com/images/media/meals/njj1681763297231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('saltfish-and-ackee', 'Saltfish and Ackee', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'jamaican', 'themealdb', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 450.0, "unit": "g", "item": "Salt Cod", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Ackee", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tsp", "item": "Curry Powder", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tsp", "item": "Jerusalem Artichokes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Hotsauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Yellow Pepper", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "to taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "to taste Pepper", "notes": null, "category": "produce"}, {"quantity": 250.0, "unit": "g", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 30.0, "unit": "g", "item": "Suet", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "for frying Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["For the saltfish, soak the salt cod overnight, changing the water a couple of times.", "Drain, then put the cod in a large pan of fresh water and bring to the boil. Drain again, add fresh water and bring to the boil again.", "Simmer for about five minutes, or until cooked through, then drain and flake the fish into large pieces. Discard any skin or bones.", "For the dumplings, mix the flour and suet with a pinch of salt and 250ml/9fl oz water to make a dough.", "Wrap the mixture in clingfilm and leave in the fridge to rest.", "Open the can of ackee, drain and rinse, then set aside.", "Heat a tablespoon of olive oil in a pan and fry the onion until softened but not brown.", "Add the spices, seasoning, pepper sauce and sliced peppers and continue to fry until the peppers are tender.", "Add the chopped tomatoes, then the salt cod and mix together. Lastly stir in the ackee very gently and leave to simmer until ready to serve.", "When you’re almost ready to eat, heat about 1cm/½in vegetable oil in a frying pan and heat until just smoking.", "Shape the dumpling mix into plum-size balls and shallow-fry until golden-brown. (CAUTION: hot oil can be dangerous. Do not leave the pan unattended.)", "Drain the dumplings on kitchen paper and serve with the saltfish and ackee."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/saltfish__ackee_with_64803', 'https://www.themealdb.com/images/media/meals/vytypy1511883765.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sea-bass-with-sizzled-ginger-chilli-spring-onions', 'Sea bass with sizzled ginger, chilli & spring onions', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'vietnamese', 'themealdb', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Bass Fillets", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Knob Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "thinly Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Soy Sauce", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Season 6 sea bass fillets with salt and pepper, then slash the skin 3 times.", "step 2", "Heat a heavy-based frying pan and add 1 tbsp sunflower oil.", "step 3", "Once hot, fry the sea bass fillets, skin-side down, for 5 mins or until the skin is very crisp and golden. The fish will be almost cooked through.", "step 4", "Turn over, cook for another 30 seconds - 1 minute, then transfer to a serving plate and keep warm. You’ll need to fry the sea bass fillets in 2 batches.", "step 5", "Heat 2 tbsp sunflower oil, then fry the large knob of peeled ginger, cut into matchsticks, 3 thinly sliced garlic cloves and 3 thinly shredded red chillies for about 2 mins until golden.", "step 6", "Take off the heat and toss in the bunch of shredded spring onions. Splash the fish with 1 tbsp soy sauce and spoon over the contents of the pan."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/sea-bass-sizzled-ginger-chilli-spring-onions', 'https://www.themealdb.com/images/media/meals/tqd7s21763780609.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('seafood-fideuà', 'Seafood fideuà', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'spanish', 'themealdb', 'soup', 'pasta'], '[{"quantity": 400.0, "unit": "g", "item": "Mussels", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Prawns", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Saffron", "notes": null, "category": "spices"}, {"quantity": 350.0, "unit": "g", "item": "Vermicelli Pasta", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Monkfish", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Squid", "notes": null, "category": "other"}, {"quantity": 650.0, "unit": "ml", "item": "Fish Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Topping Parsley", "notes": null, "category": "produce"}]'::jsonb, '["Boil the kettle. Empty the mussels into a colander and run under cold water. Throw away any with broken shells. Pick through the shells, tapping each one on the side of the sink – they should be closed or should slowly close when tapped – if they stay open, throw them away. If any of the shells still have barnacles or stringy beards attached, pull them off with a cutlery knife and rinse the shells well. Keep in the colander, covered with a cold, damp cloth, until you’re ready to cook. Peel the prawn shells on the body section only – leave the heads and tails intact. Score down the backs and pull out any gritty entrails. Chill until you’re ready to cook.", "Put the saffron in a small cup, cover with 50ml kettle-hot water and set aside for 10 mins. If using vermicelli, put in a bowl and crush to little pieces (about 1cm long) with your hands.", "Heat the oil in a large frying pan with at least a 3cm lip, or a 40cm paella pan. Add the onion and stir around the pan for 5 mins until soft. Add the garlic and cook for 1 min more, then tip in the vermicelli and cook for 5 mins, stirring from time to time, until the vermicelli is toasted brown. Stir in the paprika.", "Keeping the heat moderate, stir through the monkfish, squid and saffron with its water, seasoning well. Spread the ingredients out in an even layer, then pour over the hot stock and scatter the tomatoes on top. Bring to a simmer, then cover the whole dish with a tight-fitting lid (or foil). Turn the heat to medium and cook for 6 mins.", "Uncover and stir to incorporate the dry top layer of pasta. Push the mussels into the pasta so the hinges are buried in the bottom of the dish, and they stand straight up. Arrange the prawns on top, cover tightly and cook for another 6 mins or until the mussels are open, the prawns are pink and the pasta is cooked through. Leave to simmer for another 2-3 mins to cook off most of the remaining liquid (leave a little in the pan to prevent the pasta from sticking together). Allow to sit for 2-3 mins, then squeeze over the lemon juice and arrange the wedges on top. Scatter with parsley before serving."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/seafood-fideua-paella', 'https://www.themealdb.com/images/media/meals/wqqvyq1511179730.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('seafood-rice', 'Seafood rice', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'spanish', 'themealdb', 'soup'], '[{"quantity": 1.0, "unit": "tbsp", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Leek", "notes": null, "category": "produce"}, {"quantity": 110.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Turmeric", "notes": null, "category": "spices"}, {"quantity": 300.0, "unit": "g", "item": "Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "l", "item": "Fish Stock", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Peas", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Frozen Seafood mix", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Heat the oil in a deep frying pan, then soften the leek for 5 mins without browning. Add the chorizo and fry until it releases its oils. Stir in the turmeric and rice until coated by the oils, then pour in the stock. Bring to the boil, then simmer for 15 mins, stirring occasionally.", "step 2", "Tip in the peas and cook for 5 mins, then stir in the seafood to heat through for a final 1-2 mins cooking or until rice is cooked. Check for seasoning and serve immediately with lemon wedges."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/easiest-ever-paella', 'https://www.themealdb.com/images/media/meals/5r5rvx1763287943.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('shrimp-chow-fun', 'Shrimp Chow Fun', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'chinese', 'themealdb', 'dessert', 'pasta', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Rice Stick Noodles", "notes": null, "category": "grains"}, {"quantity": 8.0, "unit": "oz", "item": "Prawns", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Pepper", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tbs", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tbs", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Bean Sprouts", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "cup", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Cooking wine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbs", "item": "Oyster Sauce", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tbs", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tbs", "item": "Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Soy Sauce", "notes": null, "category": "pantry"}]'::jsonb, '["STEP 1 - SOAK THE RICE NOODLES", "Soak the rice noodles overnight untill they are soft", "STEP 2 - BOIL THE RICE NOODLES", "Boil the noodles for 10-15 minutes and then rinse with cold water to stop the cooking process of the noodles.", "STEP 3 -MARINATING THE SHRIMP", "In a bowl add the shrimp, egg, 1 pinch of white pepper, 1 Teaspoon of sesame seed oil, 1 Tablespoon corn starch and 1 tablespoon of oil", "Mix together well", "STEP 4 - STIR FRY", "In a wok add 2 Tablespoons of oil, shrimp and stir fry them until it is golden brown", "Set the shrimp aside", "Add 1 Tablespoon of oil to the work and then add minced garlic, ginger and all of the vegetables.", "Add the noodles to the wok", "Next add sherry cooking wine, oyster sauce, sugar, vinegar, sesame seed oil, 1 pinch white pepper, and soy sauce", "Add back in the shrimp", "To thicken the sauce, whisk together 1 Tablespoon of corn starch and 2 Tablespoon of water in a bowl and slowly add to your stir-fry until it''s the right thickness."]'::jsonb, 'https://sueandgambo.com/pages/shrimp-chow-fun', 'https://www.themealdb.com/images/media/meals/1529445434.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('shrimp-with-snow-peas', 'Shrimp With Snow Peas', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'chinese', 'themealdb', 'soup'], '[{"quantity": 2.0, "unit": "tsp", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Dry sherry", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tsp", "item": "Kosher Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "lb", "item": "Shrimp", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Peanut Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Ground Ginger", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "Chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "lb", "item": "Snow Peas", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "cup", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Scallions", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}]'::jsonb, '["You can also use sugar snap peas for this recipe. Save prep time by prepping the peas, ginger, and garlic while the shrimp is marinating.", "Marinate the shrimp:", "Mix all marinade ingredients in a large bowl, then add the shrimp. Toss to coat. Let sit for 15 to 20 minutes while you prep the peas, ginger, and garlic.", "Stir-fry the ginger and garlic:", "Heat a wok or large sauté pan over high heat for 1 minute. Add the peanut oil and let it get hot, about 30 seconds. Add the ginger and garlic and toss to combine. Stir-fry for about 30 seconds.", "Add the shrimp, snow peas, soy sauce, stock:", "Add the shrimp and all the marinade to the pan (scrape out all the marinade with a rubber spatula). Add the snow peas, soy sauce and chicken stock. Stir-fry until the shrimp turns pink, about 2 minutes.", "Add the scallions and finish with sesame oil:", "Add the scallions and stir-fry 1 more minute. Turn off the heat and add the sesame oil. Toss to combine once more and serve with steamed rice."]'::jsonb, 'https://www.simplyrecipes.com/recipes/shrimp_with_snow_peas/', 'https://www.themealdb.com/images/media/meals/fpl3mv1766433431.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('singapore-noodles-with-shrimp', 'Singapore Noodles with Shrimp', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'chinese', 'themealdb', 'pasta', 'baking'], '[{"quantity": 2.0, "unit": "tsp", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Seasoned Rice Vinegar", "notes": null, "category": "grains"}, {"quantity": 6.0, "unit": "oz", "item": "Vermicelli Rice Noodles", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Ground Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "finely", "notes": "chopped Garlic", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Jalapeno", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Onion", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "oz", "item": "Ham", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Scallions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Curry Powder", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "lb", "item": "Shrimp", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Cilantro Leaves", "notes": null, "category": "produce"}]'::jsonb, '["For the sweet onion, look for Vidalia, OSO Sweet, or Walla Walla. The super-sweet varieties are more suited to this stir-fry because at the end of cooking, the onion still has a slight crunch.", "Make the sauce:", "In a bowl, combine the sesame oil, soy sauce, and rice vinegar.", "Cook the rice noodles:", "Bring a large saucepan of water to a boil, add the noodles, and use tongs to turn them so they are submerged. Cook for 2 minutes, or until they are tender but still have some bite (they will cook a little more once you add them to the skillet).", "Drain, rinse with cold water, and use scissors to snip the noodles several times to break them up into shorter lengths.", "Scramble the eggs:", "In a small bowl whisk together the eggs. Heat the skillet or Dutch oven over medium heat. Add 1 tablespoon of the peanut or canola oil. Add the eggs and scramble them for 2 minutes, or until they form large, soft curds. Transfer them from the pan to a plate or bowl.", "Cook the vegetables:", "Add 1 tablespoon of the remaining oil to the pan. When it is hot, add the ginger, garlic, carrots, jalapeño, onion, and salt. Cook, stirring constantly, for 2 minutes or until the vegetables start to soften.", "Add the remaining ingredients:", "Sprinkle the vegetable mixture with the remaining 1 tablespoon peanut or canola oil. When the oil is hot, add the ham, cabbage, scallions, red pepper, and curry powder to the pan. Cook, stirring constantly, for 1 minute.", "Add the shrimp and cook, stirring, for 3 more minutes or until the shrimp are bright pink and cooked through.", "Add the noodles in batches:", "Add the eggs, the sauce mixture, and half the noodles to the pan. Toss for 1 minute.", "Add the remaining noodles and continue tossing for 1 minute more until they are thoroughly combined and the mixture is heated through.", "Serve:", "Taste for seasoning and add more salt or soy sauce, if you like. Sprinkle with cilantro leaves and serve."]'::jsonb, 'https://www.simplyrecipes.com/recipes/singapore_noodles_with_shrimp/', 'https://www.themealdb.com/images/media/meals/f3cxnc1765656994.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sledz-w-oleju-polish-herrings', 'Sledz w Oleju (Polish Herrings)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'polish', 'themealdb', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Herring", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}]'::jsonb, '["Soak herring in cold water for at least 1 hour. If very salty, repeat, changing the water each time.", "Drain thoroughly and slice herring into bite-size pieces.", "Place in a jar large enough to accommodate the pieces and cover with oil, allspice, peppercorns, and bay leaf. Close the jar.", "Refrigerate for 2 to 3 days before eating. This will keep refrigerated up to 2 weeks.", "Serve with finely chopped onion or onion slices, lemon, and parsley or dill."]'::jsonb, 'https://www.thespruceeats.com/polish-herrings-in-oil-recipe-1135618', 'https://www.themealdb.com/images/media/meals/7ttta31593350374.jpg', FALSE, 5, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spanish-rice-prawn-one-pot', 'Spanish rice & prawn one-pot', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'spanish', 'themealdb', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Green Pepper", "notes": null, "category": "produce"}, {"quantity": 50.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Basmati Rice", "notes": null, "category": "grains"}, {"quantity": 400.0, "unit": "g", "item": "Tinned Tomatos", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Prawns", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Boil the kettle. In a non-stick frying or shallow pan with a lid, fry the onion, peppers, chorizo and garlic in the oil over a high heat for 3 mins. Stir in the rice and chopped tomatoes with 500ml boiling water, cover, then cook over a high heat for 12 mins.", "step 2", "Uncover, then stir – the rice should be almost tender. Stir in the prawns, with a splash more water if the rice is looking dry, then cook for another min until the prawns are just pink and rice tender."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/spanish-rice-prawn-one-pot', 'https://www.themealdb.com/images/media/meals/sl6vqv1763335988.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spanish-seafood-rice', 'Spanish seafood rice', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'spanish', 'themealdb', 'soup'], '[{"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 250.0, "unit": "g", "item": "Paella Rice", "notes": null, "category": "grains"}, {"quantity": 800.0, "unit": "ml", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Saffron", "notes": null, "category": "spices"}, {"quantity": 400.0, "unit": "g", "item": "Frozen Seafood mix", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1/2 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Parsley", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat the oil in a large saucepan and soften the onion for 6-7 mins. Add the pepper and garlic, cook for 2 mins more, then stir in the paella rice and cook for 1 min, stirring to coat.", "step 2", "Pour in the stock, add the saffron and bring to the boil. Cook, uncovered, at a gentle bubble, for 20 mins, stirring occasionally until the rice is tender.", "step 3", "Stir in the seafood and lemon juice and cook for 2 mins or until piping hot and completely cooked through. Serve in warm bowls scattered with the parsley."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/spanish-seafood-rice', 'https://www.themealdb.com/images/media/meals/c6ghxm1763335584.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spicy-thai-prawn-noodles', 'Spicy Thai prawn noodles', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'thai', 'themealdb', 'pasta', 'vegetarian'], '[{"quantity": 200.0, "unit": "g", "item": "Rice Noodles", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "piece Ginger", "notes": null, "category": "produce"}, {"quantity": 450.0, "unit": "g", "item": "Prawns", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Mint", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Zest and juice of 1 Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Peanuts", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Cook the noodles following the pack instructions, drain and set aside for later. Heat the oil in a large frying pan and pour in the beaten egg. Swirl around the pan to make a thin omelette, cook for 1-2 mins, then flip over and cook the other side for 1 min. Tip out and slice into thin strips.", "step 2", "Add the chilli and ginger to the pan, fry for 1-2 mins then tip in the noodles, prawns and egg. Splash in the soy sauce and stir-fry for 1 min more. Throw in the chopped herbs and pour over the lime juice and zest, then sprinkle over the chopped peanuts and serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/spicy-thai-prawn-noodles', 'https://www.themealdb.com/images/media/meals/568t931763584227.jpg', TRUE, 1, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spring-onion-and-prawn-empanadas', 'Spring onion and prawn empanadas', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'portuguese', 'themealdb', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "bunch", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "sliced Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "clove", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 350.0, "unit": "g", "item": "Prawns", "notes": null, "category": "other"}, {"quantity": 75.0, "unit": "g", "item": "Feta", "notes": null, "category": "dairy"}, {"quantity": 15.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 250.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "White Wine Vinegar", "notes": null, "category": "pantry"}]'::jsonb, '["STEP 1", "To make the dough, rub the butter into the flour and then add the egg white and half the yolk (keep the rest), vinegar, a pinch of salt and enough cold water to make a soft dough. Knead on a floured surface until smooth and then wrap and rest for 30 minutes.", "STEP 2", "Heat the oven to 180c/fan 160c/gas 4. Trim the green ends of the spring onions and then finely slice the rest. Heat a little oil in a pan and fry them gently until soft but not browned. Add the chilli and garlic, stir and then add the prawns and cook until they are opaque. Season well. Scoop out the prawns and bubble the juices until they thicken, then add back the prawns.", "STEP 3", "Divide the empanada dough into eight balls and roll out to thin circles on a floured surface. Put some filling on one half of the dough, sprinkle the feta on top and fold the other half over. Trim the edge and then fold and crimp the dough together so the empanada is tightly sealed, put it on an oiled baking sheet either on its side or sitting on its un-crimped edge like a cornish pasty. Repeat with the remaining dough and mixture. Mix the leftover egg yolk with a splash of water and brush the top of the empanadas.", "STEP 4", "Bake for 30 minutes or until golden and slightly crisp around the edges."]'::jsonb, 'https://www.olivemagazine.com/recipes/fish-and-seafood/spring-onion-and-prawn-empanadas/', 'https://www.themealdb.com/images/media/meals/1c5oso1614347493.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('squid-chickpea-chorizo-salad', 'Squid, chickpea & chorizo salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'australian', 'themealdb', 'salad', 'grilling', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Cans Can of chickpeas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 100.0, "unit": "ml", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 600.0, "unit": "g", "item": "Squid", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "Chorizo", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Juice/zest of one Lemon", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Cook the peppers whole under a grill, on a barbecue or griddle, until completely charred. Place the peppers in a bowl, cover with a plate until cool enough to handle, then peel, deseed and finely slice. In a large bowl mix the peppers and any juices with the chickpeas, parsley, chilli and garlic. Set aside.", "step 2", "Heat a large frying pan until smoking. Working quickly and carefully, add a splash of oil to the pan, then the squid. Stir-fry for about 30 secs. Scatter the chorizo over the squid, continue to cook for 30 secs more, then tip into the bowl with the peppers. Season everything with salt and pepper, then dress with the remaining oil, lemon juice and lemon zest. Mix together, pile onto a platter and let everyone help themselves."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/squid-chickpea-chorizo-salad', 'https://www.themealdb.com/images/media/meals/wsu0rc1761848482.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sushi', 'Sushi', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'japanese', 'themealdb', 'dessert', 'vegetarian', 'vegan'], '[{"quantity": 300.0, "unit": "ml", "item": "Sushi Rice", "notes": null, "category": "grains"}, {"quantity": 100.0, "unit": "ml", "item": "Rice wine", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tbs", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tbs", "item": "Mayonnaise", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Rice wine", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tbs", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Cucumber", "notes": null, "category": "produce"}]'::jsonb, '["STEP 1", "TO MAKE SUSHI ROLLS: Pat out some rice. Lay a nori sheet on the mat, shiny-side down. Dip your hands in the vinegared water, then pat handfuls of rice on top in a 1cm thick layer, leaving the furthest edge from you clear.", "STEP 2", "Spread over some Japanese mayonnaise. Use a spoon to spread out a thin layer of mayonnaise down the middle of the rice.", "STEP 3", "Add the filling. Get your child to top the mayonnaise with a line of their favourite fillings – here we’ve used tuna and cucumber.", "STEP 4", "Roll it up. Lift the edge of the mat over the rice, applying a little pressure to keep everything in a tight roll.", "STEP 5", "Stick down the sides like a stamp. When you get to the edge without any rice, brush with a little water and continue to roll into a tight roll.", "STEP 6", "Wrap in cling film. Remove the mat and roll tightly in cling film before a grown-up cuts the sushi into thick slices, then unravel the cling film.", "STEP 7", "TO MAKE PRESSED SUSHI: Layer over some smoked salmon. Line a loaf tin with cling film, then place a thin layer of smoked salmon inside on top of the cling film.", "STEP 8", "Cover with rice and press down. Press about 3cm of rice over the fish, fold the cling film over and press down as much as you can, using another tin if you have one.", "STEP 9", "Tip it out like a sandcastle. Turn block of sushi onto a chopping board. Get a grown-up to cut into fingers, then remove the cling film.", "STEP 10", "TO MAKE SUSHI BALLS: Choose your topping. Get a small square of cling film and place a topping, like half a prawn or a small piece of smoked salmon, on it. Use damp hands to roll walnut-sized balls of rice and place on the topping.", "STEP 11", "Make into tight balls. Bring the corners of the cling film together and tighten into balls by twisting it up, then unwrap and serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/simple-sushi', 'https://www.themealdb.com/images/media/meals/g046bb1663960946.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-curry-noodle-soup', 'Thai curry noodle soup', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'thai', 'themealdb', 'soup', 'pasta', 'vegetarian'], '[{"quantity": 1.0, "unit": "teaspoon", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbsp", "item": "Thai Green Curry Paste", "notes": null, "category": "spices"}, {"quantity": 220.0, "unit": "g", "item": "Stir-fry Vegetables", "notes": null, "category": "other"}, {"quantity": 150.0, "unit": "g", "item": "Raw King Prawns", "notes": null, "category": "other"}, {"quantity": 150.0, "unit": "ml", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 225.0, "unit": "ml", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Udon Noodles", "notes": null, "category": "grains"}, {"quantity": 10.0, "unit": "g", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 10.0, "unit": "g", "item": "Basil", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat the oil in a saucepan over a medium heat and cook the curry paste for 1 min before adding the stir-fry veg and prawns. Cook for 3 mins until the prawns are mostly pink, then add the coconut milk, veg stock and noodles.", "step 2", "Bring to the boil, then reduce the heat to a simmer and cook for 5 mins until the noodles are cooked through and the veg is tender but still has a bite. Divide between two bowls and sprinkle over the herbs, chilli and spring onion."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/thai-curry-noodle-soup', 'https://www.themealdb.com/images/media/meals/118oj61763423896.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-fried-rice-with-prawns-peas', 'Thai fried rice with prawns & peas', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'thai', 'themealdb'], '[{"quantity": 2.0, "unit": "tbsp", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 250.0, "unit": "g", "item": "Raw King Prawns", "notes": null, "category": "other"}, {"quantity": 140.0, "unit": "g", "item": "Brown Rice", "notes": null, "category": "grains"}, {"quantity": 75.0, "unit": "g", "item": "Frozen Peas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Hotsauce", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Heat 1 tbsp of the oil in a wok, add the onion, garlic and chilli, and cook for 2-3 mins until golden. Add the prawns and cook for 1 min. Tip in the rice and peas, and keep tossing until very hot. Add the soy and fish sauce, then stir through the chopped coriander. Keep warm while you fry the eggs.", "step 2", "Heat the remaining oil in a frying pan and fry the eggs with some seasoning. Divide the fried rice mix between 4 bowls and top each with a fried egg. Serve scattered with coriander, with chilli sauce, if you like."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/thai-fried-rice-prawns-peas', 'https://www.themealdb.com/images/media/meals/hblwvg1763478203.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-prawn-curry', 'Thai prawn curry', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'thai', 'themealdb', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Thai Red Curry Paste", "notes": null, "category": "spices"}, {"quantity": 400.0, "unit": "g", "item": "Tinned Tomatos", "notes": null, "category": "produce"}, {"quantity": 50.0, "unit": "g", "item": "Coconut Cream", "notes": null, "category": "dairy"}, {"quantity": 400.0, "unit": "g", "item": "Raw", "notes": "Frozen Prawns", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Coriander", "notes": null, "category": "spices"}]'::jsonb, '["step 1", "Heat the oil in a medium saucepan. Tip in the onion and ginger, then cook for a few mins until softened. Stir in the curry paste, then cook for 1 min more. Pour over the chopped tomatoes and coconut cream. Bring to the boil, then leave to simmer for 5 mins, adding a little boiling water if the mixture gets too thick.", "step 2", "Tip in the prawns, then cook for 5-10 mins more, depending on how large they are. Serve alongside some plain rice and sprinkle with a little chopped coriander, if you like."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/easy-thai-prawn-curry', 'https://www.themealdb.com/images/media/meals/qqlwv91763501559.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-style-fish-broth-with-greens', 'Thai-style fish broth with greens', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'thai', 'themealdb', 'soup'], '[{"quantity": 100.0, "unit": "g", "item": "Brown Rice Noodle", "notes": null, "category": "grains"}, {"quantity": 500.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Thai Red Curry Paste", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "White Fish", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Raw King Prawns", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Choi", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander Leaves", "notes": null, "category": "spices"}]'::jsonb, '["step 1", "Cook the noodles following pack instructions. Refresh in cold water and drain well.", "step 2", "Put the stock in a large saucepan and stir in the curry paste, lime leaves, fish sauce and 250ml cold water. Bring to a simmer and cook for 5 mins.", "step 3", "Cut the fish into roughly 3cm cubes and add to the pan. Return to a simmer, then cook for 2 mins uncovered.", "step 4", "Stir in the noodles, prawns and pak choi, and simmer for 2-3 mins or until the fish and prawns are just cooked. Serve in bowls scattered with coriander."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/thai-style-fish-broth-greens', 'https://www.themealdb.com/images/media/meals/a2ec961763587756.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-style-steamed-fish', 'Thai-style steamed fish', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'thai', 'themealdb', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Trout", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Knob Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "finely", "notes": "diced Garlic Clove", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "finely", "notes": "diced Red Chilli", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Juice/zest of one Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pak Koi", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Soy Sauce", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Nestle the fish fillets side by side on a large square of foil and scatter the ginger, garlic, chilli and lime zest over them. Drizzle the lime juice on top and then scatter the pieces of pak choi around and on top of the fish. Pour the soy sauce over the pak choi and loosely seal the foil to make a package, making sure you leave space at the top for the steam to circulate as the fish cooks.", "step 2", "Steam for 15 minutes. (If you haven’t got a steamer, put the parcel on a heatproof plate over a pan of gently simmering water, cover with a lid and steam.)"]'::jsonb, 'https://www.bbcgoodfood.com/recipes/thai-style-steamed-fish', 'https://www.themealdb.com/images/media/meals/yx8j1i1763484612.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('three-fish-pie', 'Three Fish Pie', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'british', 'themealdb', 'dessert', 'baking'], '[{"quantity": 1.0, "unit": "kg", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Knob Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Milk", "notes": null, "category": "dairy"}, {"quantity": 50.0, "unit": "g", "item": "Gruyere", "notes": null, "category": "other"}, {"quantity": 75.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Leek", "notes": null, "category": "produce"}, {"quantity": 75.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 150.0, "unit": "ml", "item": "White Wine", "notes": null, "category": "other"}, {"quantity": 568.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "chopped Parsley", "notes": null, "category": "produce"}, {"quantity": 250.0, "unit": "g", "item": "Salmon", "notes": null, "category": "other"}, {"quantity": 250.0, "unit": "g", "item": "Haddock", "notes": null, "category": "other"}, {"quantity": 250.0, "unit": "g", "item": "Smoked Haddock", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}]'::jsonb, '["Preheat the oven to 200C/400F/Gas 6 (180C fan).", "Put the potatoes into a saucepan of cold salted water. Bring up to the boil and simmer until completely tender. Drain well and then mash with the butter and milk. Add pepper and taste to check the seasoning. Add salt and more pepper if necessary.", "For the fish filling, melt the butter in a saucepan, add the leeks and stir over the heat. Cover with a lid and simmer gently for 10 minutes, or until soft. Measure the flour into a small bowl. Add the wine and whisk together until smooth.", "Add the milk to the leeks, bring to the boil and then add the wine mixture. Stir briskly until thickened. Season and add the parsley and fish. Stir over the heat for two minutes, then spoon into an ovenproof casserole. Scatter over the eggs. Allow to cool until firm.", "Spoon the mashed potatoes over the fish mixture and mark with a fork. Sprinkle with cheese.", "Bake for 30-40 minutes, or until lightly golden-brown on top and bubbling around the edges."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/three_fish_pie_58875', 'https://www.themealdb.com/images/media/meals/spswqs1511558697.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tom-yum-hot-sour-soup-with-prawns', 'Tom yum (hot & sour) soup with prawns', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'thai', 'themealdb', 'soup'], '[{"quantity": 700.0, "unit": "ml", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Lemongrass", "notes": null, "category": "produce"}, {"quantity": 5.0, "unit": "slices", "item": "Galangal", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "lime leaves", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Prawns", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Green Chilli", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Lime juice", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Bring the stock to a boil in a medium-sized saucepan. Add the lemongrass, galangal, coriander roots and lime leaves, then simmer for 2 mins.", "step 2", "Add the prawns, fish sauce, chillies and lime juice, then return to the boil. Taste and adjust the seasoning with either more lime juice or fish sauce, then garnish with coriander leaves and serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/tom-yum-hot-sour-soup-prawns', 'https://www.themealdb.com/images/media/meals/9c5nlx1763424766.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tom-yum-soup-with-prawns', 'Tom yum soup with prawns', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'thai', 'themealdb', 'soup'], '[{"quantity": 200.0, "unit": "g", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "g", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 20.0, "unit": "g", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 15.0, "unit": "g", "item": "Galangal", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Stalks", "notes": null, "category": "other"}, {"quantity": 250.0, "unit": "g", "item": "Raw King Prawns", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Stock Cube", "notes": null, "category": "pantry"}, {"quantity": 120.0, "unit": "g", "item": "Oyster Mushrooms", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "lime leaves", "notes": null, "category": "produce"}, {"quantity": 25.0, "unit": "ml", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 25.0, "unit": "ml", "item": "Lime juice", "notes": null, "category": "produce"}, {"quantity": 70.0, "unit": "ml", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Thai Chilli Jam", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander", "notes": null, "category": "spices"}]'::jsonb, '["step 1", "Pour 1.3 litres water into a large saucepan over a high heat. Add the onion, tomato, chilli, galangal, lemongrass, prawn heads and chicken stock cube. Stir and bring to a boil, then reduce the heat to medium and simmer for 20 mins until the liquid has reduced.", "step 2", "Carefully strain the hot broth into a large heatproof bowl or jug, then discard the prawn heads. Return the strained veg and herb mixture to the saucepan and pour over the broth. Stir through the mushrooms and lime leaves, then cook for 3 mins until the mushrooms are tender.", "step 3", "Add 1 tbsp sugar, the fish sauce, lime juice, coconut milk and prawns. Bring to the boil and cook until the prawns are cooked through, about 1-2 mins. Remove from the heat. Remove the lemongrass, then stir in the Thai chilli jam, if using. Scatter over the coriander to finish, if you like, and serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/tom-yum-soup-with-prawns', 'https://www.themealdb.com/images/media/meals/l50vz41763422681.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tuna-and-egg-briks', 'Tuna and Egg Briks', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'tunisian', 'themealdb', 'baking'], '[{"quantity": 2.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Spinach", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pastry", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "can", "item": "Tuna", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Hotsauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "1/4  Cucumber", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tbs", "item": "Apricot Jam", "notes": null, "category": "other"}]'::jsonb, '["Heat 2 tsp of the oil in a large saucepan and cook the spring onions over a low heat for 3 minutes or until beginning to soften. Add the spinach, cover with a tight-fitting lid and cook for a further 2–3 minutes or until tender and wilted, stirring once or twice. Tip the mixture into a sieve or colander and leave to drain and cool.", "Using a saucer as a guide, cut out 24 rounds about 12.5 cm (5 in) in diameter from the filo pastry, cutting 6 rounds from each sheet. Stack the filo rounds in a pile, then cover with cling film to prevent them from drying out.", "When the spinach mixture is cool, squeeze out as much excess liquid as possible, then transfer to a bowl. Add the tuna, eggs, hot pepper sauce, and salt and pepper to taste. Mix well.", "Preheat the oven to 200°C (400°F, gas mark 6). Take one filo round and very lightly brush with some of the remaining oil. Top with a second round and brush with a little oil, then place a third round on top and brush with oil.", "Place a heaped tbsp of the filling in the middle of the round, then fold the pastry over to make a half-moon shape. Fold in the edges, twisting them to seal, and place on a non-stick baking sheet. Repeat with the remaining pastry and filling to make 8 briks in all.", "Lightly brush the briks with the remaining oil. Bake for 12–15 minutes or until the pastry is crisp and golden brown.", "Meanwhile, combine the tomatoes and cucumber in a bowl and sprinkle with the lemon juice and seasoning to taste. Serve the briks hot with this salad and the chutney."]'::jsonb, 'http://allrecipes.co.uk/recipe/3096/tunisian-tuna-and-egg-briks.aspx', 'https://www.themealdb.com/images/media/meals/2dsltq1560461468.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tuna-nicoise', 'Tuna Nicoise', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'french', 'themealdb', 'baking'], '[{"quantity": 450.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Red Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Capers", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Spinach", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Tuna", "notes": null, "category": "other"}]'::jsonb, '["Heat oven to 200C/fan 180C/gas 6. Toss the potatoes with 2 tsp oil and some seasoning. Tip onto a large baking tray, then roast for 20 mins, stirring halfway, until crisp, golden and cooked through.", "Meanwhile, put eggs in a small pan of water, bring to the boil, then simmer for 8-10 mins, depending on how you like them cooked. Plunge into a bowl of cold water to cool for a few mins. Peel away the shells, then cut into halves.", "In a large salad bowl, whisk together the remaining oil, red wine vinegar, capers and chopped tomatoes. Season, tip in the onion, spinach, tuna and potatoes, then gently toss together. Top with the eggs, then serve straight away."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/9529/winter-tuna-nioise', 'https://www.themealdb.com/images/media/meals/yypwwq1511304979.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vietnamese-caramel-trout', 'Vietnamese caramel trout', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'vietnamese', 'themealdb', 'dessert'], '[{"quantity": 50.0, "unit": "g", "item": "Golden Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "large piece Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Trout", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "heads", "item": "Bok Choi", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1/2 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sprigs of", "notes": "fresh Coriander", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Steamed Rice", "notes": null, "category": "grains"}]'::jsonb, '["step 1", "Put the sugar in a large shallow pan, along with a small splash of water. Heat gently, swirling the pan, until the sugar has dissolved. Increase the heat and bubble the syrup until it turns a dark amber colour. Add the fish sauce, most of the chilli and ginger, then splash in 1 tbsp water to dilute. Boil again until syrupy, then add the fish fillets, skin-side down, and the bok choi, cut-side down.", "step 2", "Cover the pan with a lid and simmer for 4-5 mins until the fish is cooked and the bok choi has wilted. Turn off the heat, squeeze over the lemon and scatter with the remaining chilli, ginger and the coriander sprigs. Serve with rice."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/vietnamese-caramel-trout', 'https://www.themealdb.com/images/media/meals/p02vq41763754350.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vietnamese-prawn-spiralized-rolls', 'Vietnamese prawn spiralized rolls', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['seafood', 'vietnamese', 'themealdb', 'dessert'], '[{"quantity": 1.0, "unit": "serving", "item": "Juice of 1/2 Lime", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Rice Vinegar", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Palm Sugar", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Birds-eye Chillies", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Paper Sheets", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Small bunch Mint", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Small bunch Coriander", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Prawns", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Courgettes", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Mix all the ingredients for the dipping sauce along with 50ml water in a bowl and set aside to allow the sugar to dissolve and flavour to infuse.", "step 2", "To assemble the rolls, fill a wide bowl with warm water and grab a clean damp tea towel to work on. Dip a rice paper wrapper into the water for a few seconds until it softens then carefully place onto the tea towel.", "step 3", "Put a few mint and coriander leaves in the centre of the wrapper then top with two prawns and a small handful of the spiralized veg, which may need to be cut up if the spirals are too long.", "step 4", "Fold the sides of the wrapper into the centre, over the filling, then fold in the edges, so that the filling is completely encased, then tightly roll. Repeat until all of the wrappers and filling have been used. To serve, slice on a diagonal and eat with the dipping sauce."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/vietnamese-prawn-spiralized-rolls', 'https://www.themealdb.com/images/media/meals/9r2xrg1763771238.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('air-fryer-egg-rolls', 'Air Fryer Egg Rolls', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'chinese', 'themealdb'], '[{"quantity": 1.0, "unit": "tablespoon", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "lb", "item": "Ground Pork", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Scallions", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cups", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Rice Vinegar", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Roll Wrappers", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "For brushing Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Duck Sauce", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Plum Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Soy Sauce", "notes": null, "category": "pantry"}]'::jsonb, '["Alternative Pan Fry Method: If you don’t have access to an air fryer, you can make these egg rolls using a traditional pan fry method. Add enough oil to a medium skillet with high walls so the oil is about 1/2 inch up the side of the skillet. Heat oil on medium high heat until it reaches 350°F. Add egg rolls and fry for 3 to 4 minutes, flip, and fry for another 3 to 4 minutes until golden brown. Remove and let them drain and cool on a few paper towels.", "Cook the filling:", "In a large skillet over medium heat, add the olive oil along with the ground pork or chicken. Break apart the meat with a spatula or wooden spoon as it cooks. Cook until the meat is cooked through, 6 to 8 minutes.", "Add garlic, ginger, carrot, scallions, and cabbage. Continue to cook until cabbage wilts down and is soft, another 3 to 4 minutes, stirring regularly. Season the filling with soy sauce and rice wine vinegar, and take off the heat to cool. (This filling can be made in advance.)", "Assemble the egg rolls:", "Place a single egg roll wrapper on a dry surface with one point of the square facing you (like a diamond). Place about 1/4 cup of the egg roll filling mixture in the middle of the wrapper.", "Dip your fingers in water and run around the edges of the wrapper. Then fold the edges of the wrapper over the center and start rolling the egg roll away from you to form a tight cylinder. Place on a plate and repeat until you are out of filling. You should get at least a dozen egg rolls.", "Air fry the egg rolls:", "Place the egg rolls in the basket of your air fryer. Spray or brush them lightly with oil. Add as many as you can without stacking the egg rolls, making sure they don’t touch. Air needs to circulate around them. Brush the egg rolls lightly with oil.", "Place the basket in the air fryer and turn the air fryer to 350°F. Cook for 6 to 7 minutes, then flip the egg rolls, spray or brush with oil a second time on the bottom side, and cook for another 4 to 5 minutes.", "Finished egg rolls should be golden brown and crispy! Serve immediately."]'::jsonb, 'https://www.simplyrecipes.com/recipes/air_fryer_chinese_egg_rolls/', 'https://www.themealdb.com/images/media/meals/grhn401765687086.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('algerian-bouzgene-berber-bread-with-roasted-pepper-sauce', 'Algerian Bouzgene Berber Bread with Roasted Pepper Sauce', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'algerian', 'themealdb', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "cloves", "item": "Chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Jalapeno", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "lbs", "item": "Semolina", "notes": null, "category": "other"}, {"quantity": 1.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 6.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Preheat your oven''s broiler. Place red bell peppers and tomatoes on a baking sheet, and roast under the broiler for about 8 minutes, turning occasionally. This should blacken the skin and help it peel off more easily. Cool, then scrape the skins off of the tomatoes and peppers, and place them in a large bowl. Remove cores and seeds from the bell peppers.", "Heat 1 tablespoon of olive oil in a skillet over medium heat. Add the jalapenos and garlic, and cook until tender, stirring frequently. Remove from heat, and transfer the garlic and jalapeno to the bowl with the tomatoes and red peppers. Using two sharp steak knives (one in each hand), cut up the tomatoes and peppers to a coarse and soupy consistency. Stir, and set sauce aside.", "Place the semolina in a large bowl, and stir in salt and 4 tablespoons of olive oil. Gradually add water while mixing and squeezing with your hand until the dough holds together without being sticky or dry, and molds easily with the hand. Divide into 6 pieces and form into balls.", "For each round, heat 1 tablespoon of olive oil in a large heavy skillet over medium heat. Roll out dough one round at a time, to no thicker than 1/4 inch. Fry in the hot skillet until dark brown spots appear on the surface, and they are crispy. Remove from the skillet, and wrap in a clean towel while preparing the remaining flat breads.", "To eat the bread and sauce, break off pieces of the bread, and scoop them into the sauce. It will slide off, but just keep reaching in!"]'::jsonb, 'https://www.allrecipes.com/recipe/72363/algerian-bouzgene-berber-bread-with-roasted-pepper-sauce/', 'https://www.themealdb.com/images/media/meals/se5vhk1764114880.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('algerian-carrots', 'Algerian Carrots', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'algerian', 'themealdb', 'vegetarian', 'vegan'], '[{"quantity": 1.5, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "lbs", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 5.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Ground Cinnamon", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 3.0, "unit": "cloves", "item": "Crushed Garlic", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Lemon Juice", "notes": null, "category": "produce"}]'::jsonb, '["Place a steamer insert into a saucepan, and fill with 1 1/2 cups of water, or just below the bottom of the steamer. Cover, and bring the water to a boil over high heat. Add the sliced carrots, reduce the heat to medium, and cover the pan again. Steam until tender but not mushy, 4 to 6 minutes depending on the thickness of the slices. Reserve 1/2 cup of the cooking liquid.", "Heat the olive oil in a skillet over medium heat. Reduce the heat to low and stir in the salt, pepper, cinnamon, cumin, garlic, and thyme. Cook the spices and garlic, stirring frequently, until fragrant, about 10 minutes. Add the 1/2 cup reserved cooking liquid and the bay leaf, cover, and simmer for 20 minutes.", "Stir in the carrots, tossing well to coat with the spice mixture, and cook until heated through, about 2 to 3 minutes. Sprinkle with lemon juice and remove the bay leaf before serving."]'::jsonb, 'https://www.allrecipes.com/recipe/99244/algerian-carrots/', 'https://www.themealdb.com/images/media/meals/o2cd4r1764113576.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('baba-ghanoush', 'Baba Ghanoush', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'syrian', 'themealdb', 'baking', 'grilling', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Egg Plants", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "Kosher Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Lemon", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Tahini", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Extra Virgin Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Greek Yogurt", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Cayenne Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Mint", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Parsley", "notes": null, "category": "produce"}]'::jsonb, '["Preheat an outdoor grill for medium-high heat and lightly oil the grate. Prick the surface of the skin of eggplants several times with the tip of a knife.", "Place eggplants directly on grill. Turn frequently with tongs while skin chars. Cook until eggplants have collapsed and are very soft, 25 to 30 minutes. Transfer to a bowl and cover tightly with aluminum foil and allow to cool, about 15 minutes.", "When eggplants are cool enough to handle, split them in half and scrape flesh into a colander placed over a bowl. Drain 5 or 10 minutes.", "Transfer eggplant to mixing bowl. Add crushed garlic and salt; mash until creamy but with a little texture, about 5 minutes. Whisk in lemon juice, tahini, olive oil, and cayenne pepper. Stir in yogurt.", "Cover bowl with plastic wrap and refrigerate until completely chilled. Stir in mint and parsley, and taste to adjust seasonings before serving."]'::jsonb, 'https://www.allrecipes.com/recipe/244553/chef-johns-baba-ghanoush/', 'https://www.themealdb.com/images/media/meals/dlmh401760524897.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('blini-pancakes', 'Blini Pancakes', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'russian', 'themealdb', 'dessert', 'breakfast', 'baking', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "Buckwheat", "notes": null, "category": "grains"}, {"quantity": 0.6666666666666666, "unit": "cup", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Yeast", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}]'::jsonb, '["In a large bowl, whisk together 1/2 cup buckwheat flour, 2/3 cup all-purpose flour, 1/2 teaspoon salt, and 1 teaspoon yeast.", "Make a well in the center and pour in 1 cup warm milk, whisking until the batter is smooth.", "Cover the bowl and let the batter rise until doubled, about 1 hour.", "Enrich and Rest the Batter", "Stir 2 tablespoons melted butter and 1 egg yolk into the batter.", "In a separate bowl, whisk 1 egg white until stiff, but not dry.", "Fold the whisked egg white into the batter.", "Cover the bowl and let the batter stand 20 minutes.", "Pan-Fry the Blini", "Heat butter in a large nonstick skillet over medium heat.", "Drop quarter-sized dollops of batter into the pan, being careful not to overcrowd the pan. Cook for about 1 minute or until bubbles form.", "Turn and cook for about 30 additional seconds.", "Remove the finished blini onto a plate and cover them with a clean kitchen towel to keep warm. Add more butter to the pan and repeat the frying process with the remaining batter."]'::jsonb, 'https://www.thespruceeats.com/russian-blini-recipe-buckwheat-pancakes-1136797', 'https://www.themealdb.com/images/media/meals/0206h11699013358.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('boulangère-potatoes', 'Boulangère Potatoes', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'french', 'themealdb', 'soup', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "chopped Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "sprigs of", "notes": "fresh Thyme", "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.5, "unit": "kg", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 425.0, "unit": "g", "item": "Vegetable Stock", "notes": null, "category": "pantry"}]'::jsonb, '["Heat oven to 200C/fan 180C/gas 6. Fry the onions and thyme sprigs in the oil until softened and lightly coloured (about 5 mins).", "Spread a layer of potatoes over the base of a 1.5-litre oiled gratin dish. Sprinkle over a few onions (see picture, above) and continue layering, finishing with a layer of potatoes. Pour over the stock and bake for 50-60 mins until the potatoes are cooked and the top is golden and crisp."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/5056/boulangre-potatoes', 'https://www.themealdb.com/images/media/meals/qywups1511796761.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('brie-wrapped-in-prosciutto-brioche', 'Brie wrapped in prosciutto & brioche', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'french', 'themealdb', 'dessert', 'baking'], '[{"quantity": 375.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 50.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 7.0, "unit": "g", "item": "Yeast", "notes": null, "category": "pantry"}, {"quantity": 75.0, "unit": "g", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "To Glaze Eggs", "notes": null, "category": "dairy"}, {"quantity": 180.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 250.0, "unit": "g", "item": "Brie", "notes": null, "category": "dairy"}, {"quantity": 8.0, "unit": "slices", "item": "Prosciutto", "notes": null, "category": "other"}]'::jsonb, '["Mix the flour, 1 tsp salt, caster sugar, yeast, milk and eggs together in a mixer using the dough attachment for 5 mins until the dough is smooth. Add the butter and mix for a further 4 mins on medium speed. Scrape the dough bowl and mix again for 1 min. Place the dough in a container, cover with cling film and leave in the fridge for at least 6 hrs before using.", "Wrap the Brie in the prosciutto and set aside. Turn out the dough onto a lightly floured surface. Roll into a 25cm circle. Place the wrapped Brie in the middle of the circle and fold the edges in neatly. Put the parcel onto a baking tray lined with baking parchment and brush with beaten egg. Chill in the fridge for 30 mins, then brush again with beaten egg and chill for a further 30 mins. Leave to rise for 1 hr at room temperature. Heat oven to 200C/180C fan/gas 6, then bake for 22 mins. Serve warm."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/1803634/brie-wrapped-in-prosciutto-and-brioche', 'https://www.themealdb.com/images/media/meals/qqpwsy1511796276.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('burek', 'Burek', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'croatian', 'themealdb', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Filo Pastry", "notes": null, "category": "other"}, {"quantity": 150.0, "unit": "g", "item": "Minced Beef", "notes": null, "category": "meat"}, {"quantity": 150.0, "unit": "g", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 40.0, "unit": "g", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Fry the finely chopped onions and minced meat in oil.", "Add the salt and pepper.", "Grease a round baking tray and put a layer of pastry in it.", "Cover with a thin layer of filling and cover this with another layer of filo pastry which must be well coated in oil.", "Put another layer of filling and cover with pastry.", "When you have five or six layers, cover with filo pastry, bake at 200ºC/392ºF for half an hour and cut in quarters and serve."]'::jsonb, 'https://www.visit-croatia.co.uk/croatian-cuisine/croatian-recipes/', 'https://www.themealdb.com/images/media/meals/tkxquw1628771028.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cacik', 'Cacik', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'turkish', 'themealdb', 'vegetarian', 'vegan'], '[{"quantity": 500.0, "unit": "g", "item": "Natural Yoghurt", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Extra Virgin Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Dried Mint", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cucumber", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Put a sieve over a large bowl, line it with a thick sheet of non-dyed kitchen paper or a clean muslin cloth, and spoon in the yogurt. Cover with another sheet of kitchen paper and leave to strain in the fridge for a minimum of 12 hrs.", "step 2", "Add the lemon juice, most of the olive oil and the dried mint to a bowl and stir well for the dried mint to soften and soak up the juices. Mix in the strained yogurt, then pour away the strained yogurt liquid and leave that bowl to one side.", "step 3", "Halve the cucumber(s) lengthways and remove the seeds by running a teaspoon from the top to the bottom of the flesh, halve the cucumbers widthways to make them shorter and easier to handle, then coarsely grate each one into the bowl the yogurt was straining over. Using clean hands (or a clean muslin cloth), squeeze as much of the liquid out of the cucumber as possible.", "step 4", "Add the strained, grated cucumber, garlic and ¾ tsp flaky salt to the rest of the ingredients and mix well. Garnish with a drizzle of extra virgin olive oil and a sprinkling of dried mint."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/cacik', 'https://www.themealdb.com/images/media/meals/16zbeu1763789342.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('callaloo-and-saltfish', 'Callaloo and SaltFish', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'jamaican', 'themealdb', 'breakfast'], '[{"quantity": 0.5, "unit": "lb", "item": "Salt Cod", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 525.0, "unit": "g", "item": "Callaloo", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Scotch Bonnet", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Plum Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Soak salted fish in water overnight. Next, heat salted fish in water on stove until water boils. You should see a foam on top. Remove from heat and drain. Set aside and shred salted fish once it cools.", "Cook bacon in skillet over medium heat until crispy. Remove bacon from heat and drain the majority of the bacon grease, leaving about 1 tablespoon in the skillet.", "Add yellow onion, green onion, scotch bonnet pepper, and garlic to the skillet and stir. Cook for about 2 minutes or until onions soften. Add salted fish to skillet and stir. Cook for about a minute.", "Next, add callaloo, roma tomatoes, thyme, and black pepper. Stir to combine and cook until heated through, about 2 minutes.", "Enjoy"]'::jsonb, 'https://www.myforkinglife.com/callaloo-and-saltfish/#recipe', 'https://www.themealdb.com/images/media/meals/73o3vq1765317873.jpg', TRUE, 1, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('challah', 'Challah', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'polish', 'themealdb', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 500.0, "unit": "g", "item": "Strong white bread flour", "notes": null, "category": "grains"}, {"quantity": 70.0, "unit": "g", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 10.0, "unit": "g", "item": "Yeast", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 70.0, "unit": "ml", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Poppy Seeds", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Combine the yeast, a pinch of the sugar and a couple tablespoons of lukewarm water in a small bowl. Stir to dissolve the yeast, then leave for 10 mins until foamy.", "step 2", "Meanwhile, combine the flour, the remaining sugar and 2 tsp fine salt in a large bowl. Make a well in the centre, then add half the beaten egg, the yeast mixture and the oil. Pour in 200ml lukewarm water (it should feel slightly warm to the touch) and stir with a spoon, then mix using one hand, keeping the other clean while you bring the dough together. If there are a lot of very dry bits, gradually add a little water to just bring it together – you don''t want it to get too wet and sticky. The dough should be moist, but not soggy.", "step 3", "Once the dough has come together, turn it out onto a lightly floured surface. Knead using both hands for 10 mins until smooth and a bit springy. If it gets very sticky, add a very small amount of flour – as little as possible. A dough scraper is useful if the dough is sticking to the work surface. Stretch the sides of the dough down and pull together to form a ball. Lightly oil a bowl, then lightly roll the dough ball around the bowl so it''s coated in the oil. Cover with a clean tea towel and leave in a warm place for 1 hr, or until dough has doubled in size.", "step 4", "Line a baking sheet with baking parchment. Turn the dough out onto a clean work surface and divide into three equal pieces, weighing for accuracy, if you like. Roll each piece into a long sausage shape about 25cm long, tapering them slightly at both ends. Lay the pieces out in front of you, parallel to one another with a couple centimetres between each. Bring the sausages together at the top end, then plait them down the length, tucking in the ends when you reach the bottom. Carefully transfer the loaf to the prepared baking sheet and loosely cover with a clean tea towel. Leave to rise until puffy and billowy, about 40 mins.", "step 5", "Meanwhile, heat the oven to 200C/180C fan/gas 6. Gently brush the rest of the beaten egg all over the challah, getting it into all the crevices, and sprinkle with the poppy or sesame seeds, if using. Bake on a middle shelf of the oven for 25-30 mins, until the loaf is golden brown underneath and sounds hollow when tapped. Check after about 15 mins – if the top of the loaf has started to get too dark, cover it with foil. Leave to cool on a wire rack, then serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/challah', 'https://www.themealdb.com/images/media/meals/fm01ky1764366365.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cheese-borek', 'Cheese Borek', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'algerian', 'themealdb', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "bunch", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 0.75, "unit": "teaspoon", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 6.0, "unit": "oz", "item": "Gouda Cheese", "notes": null, "category": "dairy"}, {"quantity": 6.0, "unit": "oz", "item": "Emmentaler Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Dough", "notes": null, "category": "other"}, {"quantity": 1.5, "unit": "cups", "item": "Unsalted Butter", "notes": null, "category": "dairy"}]'::jsonb, '["In a medium bowl, whisk together egg, parsley, garlic and crushed red pepper. Mix in Gouda and Emmentaler.", "One sheet at a time, place phyllo dough on a flat surface and brush with about 1 tablespoon butter. Cut lengthwise into 4 strips. Place a rounded teaspoon of the egg mixture at one end of each strip. Fold corner of strip over the filling, forming a triangular fold. Continue folding the length of the strip in triangular folds to form a small stuffed triangle. Repeat with remaining phyllo dough.", "Preheat oven to 350 degrees F (175 degrees C). Lightly butter a large baking sheet.", "Arrange stuffed phyllo triangles in a single layer on the prepared baking sheet. Bake in the preheated oven 30 minutes, or until lightly browned. Serve warm"]'::jsonb, 'https://www.allrecipes.com/recipe/26728/cheese-borek/', 'https://www.themealdb.com/images/media/meals/oal8x31764119345.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('corba', 'Corba', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'turkish', 'themealdb', 'soup', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "cup", "item": "Lentils", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Mint", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "Red Pepper Flakes", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cups", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Sea Salt", "notes": null, "category": "pantry"}]'::jsonb, '["Pick through your lentils for any foreign debris, rinse them 2 or 3 times, drain, and set aside.  Fair warning, this will probably turn your lentils into a solid block that you’ll have to break up later", "In a large pot over medium-high heat, sauté the olive oil and the onion with a pinch of salt for about 3 minutes, then add the carrots and cook for another 3 minutes.", "Add the tomato paste and stir it around for around 1 minute. Now add the cumin, paprika, mint, thyme, black pepper, and red pepper as quickly as you can and stir for 10 seconds to bloom the spices. Congratulate yourself on how amazing your house now smells.", "Immediately add the lentils, water, broth, and salt. Bring the soup to a (gentle) boil.", "After it has come to a boil, reduce heat to medium-low, cover the pot halfway, and cook for 15-20 minutes or until the lentils have fallen apart and the carrots are completely cooked.", "After the soup has cooked and the lentils are tender, blend the soup either in a blender or simply use a hand blender to reach the consistency you desire. Taste for seasoning and add more salt if necessary.", "Serve with crushed-up crackers, torn up bread, or something else to add some extra thickness.  You could also use a traditional thickener (like cornstarch or flour), but I prefer to add crackers for some texture and saltiness.  Makes great leftovers, stays good in the fridge for about a week."]'::jsonb, 'https://findingtimeforcooking.com/main-dishes/red-lentil-soup-corba/', 'https://www.themealdb.com/images/media/meals/58oia61564916529.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fainá', 'Fainá', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'argentinian', 'themealdb', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 200.0, "unit": "g", "item": "Chickpea Flour", "notes": null, "category": "grains"}, {"quantity": 600.0, "unit": "ml", "item": "Water", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Prepare the Batter: Whisk together chickpea flour, water, salt, and pepper. Let sit for at least 4 hours.", "Bake: Preheat the oven to 220°C (430°F). Pour olive oil into a round baking dish and heat in the oven. Pour in the batter and bake for 25-30 minutes, until golden.", "Serve: Slice and serve hot, optionally with black pepper on top.", "Pro Tips:", "Let the batter rest for at least 2 hours, or overnight in the refrigerator, to ensure the chickpea flour fully hydrates and the flavors meld.", "For a crispy edge, preheat the baking pan with oil in the oven before adding the batter."]'::jsonb, 'https://www.munchery.com/blog/the-ten-iconic-dishes-of-argentina-and-how-to-cook-them-at-home/', 'https://www.themealdb.com/images/media/meals/849jd81763075251.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fennel-dauphinoise', 'Fennel Dauphinoise', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'french', 'themealdb', 'baking', 'vegetarian'], '[{"quantity": 225.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Fennel", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "finely", "notes": "chopped Garlic", "category": "other"}, {"quantity": 75.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "For Greasing Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Parmesan Cheese", "notes": null, "category": "dairy"}]'::jsonb, '["Heat oven to 180C/160C fan/gas 4. Put potatoes, fennel, and garlic in a medium non-stick pan. Pour in milk and double cream, season well and simmer gently, covered, for 10 mins, stirring halfway through, until potatoes are just tender.", "Divide the mixture between 2 small (about 150ml) buttered ramekins and scatter with Parmesan. Bake for 40 mins until the potatoes are golden and tender when pierced with a knife. Snip the reserved fennel fronds over before serving."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/fennel-dauphinoise', 'https://www.themealdb.com/images/media/meals/ytttsv1511798734.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('feteer-meshaltet', 'Feteer Meshaltet', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'egyptian', 'themealdb', 'baking', 'vegetarian'], '[{"quantity": 4.0, "unit": "cups", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.5, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 0.25, "unit": "cup", "item": "Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Mix the flour and salt then pour one cup of water and start kneading.", "If you feel the dough is still not coming together or too dry, gradually add the remaining water until you get a dough that is very elastic so that when you pull it and it won’t be torn.", "Let the dough rest for just 10 minutes then divide the dough into 6-8 balls depending on the size you want for your feteer.", "Warm up the butter/ghee or oil you are using and pour into a deep bowl.", "Immerse the dough balls into the warm butter. Let it rest for 15 to 20 minutes.", "Preheat oven to 550F.", "Stretch the first ball with your hands on a clean countertop. Stretch it as thin as you can, the goal here is to see your countertop through the dough.", "Fold the dough over itself to form a square brushing in between folds with the butter mixture.", "Set aside and start making the next ball.", "Stretch the second one thin as we have done for the first ball.", "Place the previous one on the middle seam side down. Fold the outer one over brushing with more butter mixture as you fold. Set aside.", "Keep doing this for the third and fourth balls. Now we have one ready, place on a 10 inch baking/pie dish seam side down and brush the top with more butter.", "Repeat for the remaining 4 balls to make a second one. With your hands lightly press the folded feteer to spread it on the baking dish.", "Place in preheated oven for 10 minutes when the feteer starts puffing turn on the broiler to brown the top.", "When it is done add little butter on top and cover so it won’t get dry."]'::jsonb, 'https://amiraspantry.com/egyptian-feteer-meshaltet/', 'https://www.themealdb.com/images/media/meals/9f4z6v1598734293.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('french-onion-soup', 'French Onion Soup', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'french', 'themealdb', 'dessert', 'soup', 'baking', 'grilling'], '[{"quantity": 50.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "kg", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 250.0, "unit": "ml", "item": "Dry White Wine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "l", "item": "Beef Stock", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 140.0, "unit": "g", "item": "Gruyère", "notes": null, "category": "other"}]'::jsonb, '["Melt the butter with the oil in a large heavy-based pan. Add the onions and fry with the lid on for 10 mins until soft. Sprinkle in the sugar and cook for 20 mins more, stirring frequently, until caramelised. The onions should be really golden, full of flavour and soft when pinched between your fingers. Take care towards the end to ensure that they don’t burn.", "Add the garlic for the final few mins of the onions’ cooking time, then sprinkle in the flour and stir well. Increase the heat and keep stirring as you gradually add the wine, followed by the hot stock. Cover and simmer for 15-20 mins.", "To serve, turn on the grill, and toast the bread. Ladle the soup into heatproof bowls. Put a slice or two of toast on top of the bowls of soup, and pile on the cheese. Grill until melted. Alternatively, you can complete the toasts under the grill, then serve them on top."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/3020694/french-onion-soup', 'https://www.themealdb.com/images/media/meals/xvrrux1511783685.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fresh-sardines', 'Fresh sardines', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'croatian', 'themealdb', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 500.0, "unit": "g", "item": "Sardines", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To Glaze Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Salt", "notes": null, "category": "pantry"}]'::jsonb, '["Wash the fish under the cold tap.", "Roll in the flour and deep fry in oil until crispy.", "Lay on kitchen towel to get rid of the excess oil and serve hot or cold with a slice of lemon."]'::jsonb, 'https://www.visit-croatia.co.uk/croatian-cuisine/croatian-recipes/', 'https://www.themealdb.com/images/media/meals/nv5lf31628771380.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('griddled-flatbreads', 'Griddled flatbreads', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'turkish', 'themealdb', 'dessert', 'baking', 'grilling', 'vegetarian', 'vegan'], '[{"quantity": 250.0, "unit": "g", "item": "Strong Wholemeal Flour", "notes": null, "category": "grains"}, {"quantity": 250.0, "unit": "g", "item": "Strong white bread flour", "notes": null, "category": "grains"}, {"quantity": 15.0, "unit": "g", "item": "Yeast", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Tip the flours into a food processor. Add the yeast, sugar and 1tsp salt, then mix well. Pour in 350ml warm water and the oil, then process to a soft dough. Mix for 1 min, then leave until doubled in size, about 1 hour.", "step 2", "Pulse the dough a couple of times just to knock out the air, then tip onto a floured surface. Cut the dough in half and roll out one half to a rectangle about 20 x 40cm. Trim the edges using a large sharp knife, then cut into eight 10cm squares. Line a large tray or two baking sheets with non-stick paper and arrange the bread rectangles over the tray in one layer. Repeat with the other half of the dough. Leave in a warm place for about 30 mins until the dough is just starting to rise.", "step 3", "Place bread directly onto the BBQ racks and cook for a couple of mins until they puff up, then flip over and cook on the other side. Tip into a basket and serve with the dips."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/griddled-flatbreads', 'https://www.themealdb.com/images/media/meals/8825lo1763815264.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('hummus', 'Hummus', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'turkish', 'themealdb', 'vegetarian'], '[{"quantity": 400.0, "unit": "g", "item": "Chickpeas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Tahini Paste", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Greek Yogurt", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of half Lemon", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Drain the chickpeas into a sieve set over a bowl or jug to catch the liquid. Tip the chickpeas, tahini, garlic and yogurt into a food processor or blender and whizz to smooth.", "step 2", "Whizz in a tbsp of the chickpea liquid at a time until you have a nice consistency, then scrape into a bowl.", "step 3", "Stir in a squeeze of lemon juice and season to taste."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/easy-hummus-recipe', 'https://www.themealdb.com/images/media/meals/gpon5u1763801180.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamaican-boiled-dumplings', 'Jamaican Boiled Dumplings', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'jamaican', 'themealdb', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 8.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tbs", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "cups", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "Water", "notes": null, "category": "other"}]'::jsonb, '["Instructions", "In a large pot, bring water and salt to a boil to boil the dumplings.", "In a large mixing bowl, combine the all-purpose flour and salt, stirring to distribute the salt evenly throughout the flour. Gradually add water to the flour mixture, mixing with your hands until a dough forms.", "Divide the dough into equal-sized pieces, rolling each into a smooth ball. Flatten each ball slightly with the palm of your hand to form a round, circular dumpling. It should look like a thick disk.", "Carefully drop the dumplings into the boiling water, one at a time, ensuring that they don''t stick together. You can use a wooden spoon to stir the dumplings in the water.", "Boil the dumplings for 15-20 minutes, or until they are cooked through and have risen to the surface of the water. Stir occasionally to prevent sticking.", "Use a slotted spoon to remove the cooked dumplings from the pot, allowing any excess water to drain.", "Serve with your favorite recipes."]'::jsonb, 'https://www.myforkinglife.com/jamaican-boiled-dumplings/#recipe', 'https://www.themealdb.com/images/media/meals/tsdbcq1764795636.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamaican-festival-sweet-dumpling', 'Jamaican Festival (Sweet Dumpling)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'jamaican', 'themealdb', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 1.5, "unit": "cups", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "cup", "item": "Cornmeal", "notes": null, "category": "produce"}, {"quantity": 6.0, "unit": "tablespoons", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Vanilla Extract", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.75, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Heat a heavy bottom pot of oil that has at least 3 inches of oil in it or use a deep fryer if you have one. Turn the heat over medium heat until the temperature reaches 350 degrees Fahrenheit.", "Add the all-purpose flour, cornmeal, granulated sugar, baking powder, and salt to a large bowl and stir to combine.", "Add the vanilla extract and milk and stir until the dough comes together. Then use your hands to lightly form the mixture into a ball.", "Pinch off pieces of dough and roll them into long oval shapes. Make about 12 dumplings.", "Once the oil has reached the temperature of 350 degrees Fahrenheit, fry the dough on all sides, until golden brown. This should take about 4-6 minutes.", "Remove dough and drain off any excess grease. Serve and enjoy."]'::jsonb, 'https://www.myforkinglife.com/jamaican-festival-recipe/#recipe', 'https://www.themealdb.com/images/media/meals/g6xb8m1764875029.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamaican-fried-dumplings', 'Jamaican Fried Dumplings', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'jamaican', 'themealdb', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.75, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.5, "unit": "cup", "item": "Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Add flour, baking powder, and salt in a large bowl and stir to combine. Pour in the milk and stir until combined. Then roll the mixture into a ball and lightly knead until it comes together.", "Break off about 10 pieces of dough and form them into balls. Set them aside.", "In a 10-inch skillet, heat enough oil over medium heat to fry the dumplings, until the oil is about 350 degrees.", "Once the dumplings are browned on one side, flip them and cook until both sides are browned, about 2-3 minutes each.", "Once done, remove the dumplings from the oil and place them on paper towels or a cooling rack to drain off any excess oil.", "Serve and enjoy."]'::jsonb, 'https://www.myforkinglife.com/jamaican-fried-dumplings/#recipe', 'https://www.themealdb.com/images/media/meals/dd7t4d1764877271.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamaican-steamed-cabbage', 'Jamaican Steamed Cabbage', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'jamaican', 'themealdb', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "1/2  Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Plum Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cloves", "item": "Chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Bonnet", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Water", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tsp", "item": "Kosher Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Add all the ingredients to a large pan over medium heat and cover with a lid.", "Cook on medium heat for 10 minutes, stirring occasionally.", "After 10 minutes, reduce the heat to low and continue to cook for an additional 5 minutes, until the cabbage is soft and tender. Remove from the heat and remove the stalks of thyme before serving."]'::jsonb, 'https://www.myforkinglife.com/jamaican-cabbage/#recipe', 'https://www.themealdb.com/images/media/meals/paejva1765321314.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('japanese-gohan-rice', 'Japanese gohan rice', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'japanese', 'themealdb', 'vegetarian', 'vegan'], '[{"quantity": 300.0, "unit": "g", "item": "Sushi Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tbs", "item": "Mirin", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Garnish Pickle Juice", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Garnish Spring Onions", "notes": null, "category": "produce"}]'::jsonb, '["STEP 1", "Rinsing and soaking your rice is key to achieving the perfect texture. Measure the rice into a bowl, cover with cold water, then use your fingers to massage the grains of rice – the water will become cloudy. Drain and rinse again with fresh water. Repeat five more times until the water stays clear.", "STEP 2", "Tip the rinsed rice into a saucepan with 400ml water, or 200ml dashi and 200ml water, bring to the boil, then turn down the heat to a low simmer, cover with a tight-fitting lid with a steam hole and cook for 15 mins. Remove from the heat and leave to sit for another 15 mins, then stir through the mirin. Remove the lid and give it a good stir. Serve with any or all of the optional toppings."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/japanese-rice-gohan', 'https://www.themealdb.com/images/media/meals/kw92t41604181871.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('khobz-el-dar-algerian-semolina-bread', 'Khobz el Dar (Algerian Semolina Bread)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'algerian', 'themealdb', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "Semolina Flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Semolina Flour", "notes": null, "category": "grains"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Sesame Seed", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Yeast", "notes": null, "category": "pantry"}, {"quantity": 0.75, "unit": "teaspoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "cup", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "cup", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "cups", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tablespoons", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Water", "notes": null, "category": "other"}]'::jsonb, '["Mix 1/2 cup plus 2 tablespoons semolina, 2 tablespoons sesame seeds, sugar, yeast, and salt together in a large bowl. Whisk in oil, egg, and egg white. Stir in warm milk slowly until a liquid dough forms.", "Cover the bowl with a plate or plastic wrap; let stand at room temperature until frothy, about 1 hour.", "Stir in 2 3/4 cups flour with a wooden spoon until a sticky dough forms. Cover again and allow to rest for 30 minutes.", "Line a baking sheet with parchment paper or a baking mat.", "Sprinkle 1 tablespoon flour over the dough and your hands. Mix dough, adding flour as needed, 1 tablespoon at a time, until it pulls away from the sides of the bowl. Shape into a round loaf and place on the prepared baking sheet. Cover loosely with a towel and let rise for 1 hour in a warm place until loaf doubles in volume.", "Preheat oven to 400 degrees F (200 degrees C).", "Beat egg yolk and water in a bowl with a fork; brush over the entire surface of the loaf. Sprinkle 1 tablespoon sesame seeds on top.", "Bake in the preheated oven until loaf is golden brown, about 20 to 25 minutes."]'::jsonb, 'https://www.allrecipes.com/recipe/258887/khobz-el-dar-algerian-semolina-bread/', 'https://www.themealdb.com/images/media/meals/5u37fy1764116774.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('kumpir', 'Kumpir', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'turkish', 'themealdb', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 150.0, "unit": "g", "item": "Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Red Chilli Flakes", "notes": null, "category": "other"}]'::jsonb, '["If you order kumpir in Turkey, the standard filling is first, lots of butter mashed into the potato, followed by cheese. There’s then a row of other toppings that you can just point at to your heart’s content – sweetcorn, olives, salami, coleslaw, Russian salad, allsorts – and you walk away with an over-stuffed potato because you got ever-excited by the choices on offer.", "Grate (roughly – you can use as much as you like) 150g of cheese.", "Finely chop one onion and one sweet red pepper.", "Put these ingredients into a large bowl with a good sprinkling of salt and pepper, chilli flakes (optional)."]'::jsonb, 'http://www.turkeysforlife.com/2013/10/firinda-kumpir-turkish-street-food.html', 'https://www.themealdb.com/images/media/meals/mlchx21564916997.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mushroom-soup-with-buckwheat', 'Mushroom soup with buckwheat', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'croatian', 'themealdb', 'soup', 'vegetarian'], '[{"quantity": 150.0, "unit": "g", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 50.0, "unit": "g", "item": "Buckwheat", "notes": null, "category": "grains"}, {"quantity": 4.0, "unit": "tbs", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 40.0, "unit": "g", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbsp", "item": "Vegetable Stock Cube", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "ml", "item": "Sour Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Dash White Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Top Parsley", "notes": null, "category": "produce"}]'::jsonb, '["Chop the onion and garlic, slice the mushrooms and wash the buckwheat.", "Heat the oil and lightly sauté the onion.", "Add the mushrooms and the garlic and continue to sauté.", "Add the salt, vegetable seasoning, buckwheat and the bay leaf and cover with water.", "Simmer gently and just before it is completely cooked, add pepper, sour cream mixed with flour, the chopped parsley and vinegar to taste."]'::jsonb, 'https://www.visit-croatia.co.uk/croatian-cuisine/croatian-recipes/', 'https://www.themealdb.com/images/media/meals/1ngcbf1628770793.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mustard-champ', 'Mustard champ', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'irish', 'themealdb', 'vegetarian'], '[{"quantity": 1.0, "unit": "kg", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 50.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "Mustard", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}]'::jsonb, '["STEP 1", "Boil the potatoes for 15 mins or until tender. Drain, then mash.", "STEP 2", "Heat the milk and half the butter in the corner of the pan, then beat into the mash, along with the wholegrain mustard.", "STEP 3", "Gently fry the spring onions in the remaining butter for 2 mins until just soft but still a perky green. Fold into the mash and serve. Great with gammon or to top a fish pie."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/mustard-champ', 'https://www.themealdb.com/images/media/meals/o7p9581608589317.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('norwegian-potato-lefse', 'Norwegian Potato Lefse', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'norwegian', 'themealdb', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 3.0, "unit": "lbs", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "cup", "item": "Melted Butter", "notes": null, "category": "dairy"}, {"quantity": 0.25, "unit": "cup", "item": "Heavy Cream", "notes": null, "category": "dairy"}, {"quantity": 1.5, "unit": "cups", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "cup", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 14.0, "unit": "tablespoons", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 0.75, "unit": "cup", "item": "Granulated Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Heavy Cream", "notes": null, "category": "dairy"}]'::jsonb, '["Boil the potatoes. Peel the potatoes while still warm and run them through a potato ricer twice.", "▢", "Let the potatoes cool in an uncovered bowl in the fridge.", "▢", "Stir the salt, sugar, melted butter, and cream into the riced potatoes.", "▢", "Slowly add the flour and knead by hand until you get a good consistency. Don''t add more flour than necessary! Roll the dough into a long sausage and divide into about 7 or 8 pieces if using an 18 inch griddle. If using a smaller griddle or frying pan, divide the dough into 10 – 12 pieces.", "▢", "Roll each piece into a ball and then press into a flat circle, using the edges of your hands to form the dough into a nice circle shape without any cracks. This is important, otherwise you won''t get round lefser.", "▢", "Heat up your griddle on medium/high heat.", "▢", "Flour your rolling surface and roll the lefse dough into a large circle slightly smaller than your griddle or frying pan. Begin rolling with a smooth rolling pin, then switch to a corrugated rolling pin as the lefse gets thinner. Don''t use too much flour, as then the edges can become hard.", "▢", "Roll the lefse onto your lefse stick and then gently unroll it onto your griddle. After a minute or two check the underside of the lefse for brown spots and then use the lefse stick to flip the lefse and cook on the other side.", "▢", "Use the lefse stick to remove the lefse from the griddle and place it in a folded damp sheet or tablecloth."]'::jsonb, 'https://scandinaviancookbook.com/norwegian-potato-lefse-recipe/', 'https://www.themealdb.com/images/media/meals/hxcuj01762772827.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pierogi-polish-dumplings', 'Pierogi (Polish Dumplings)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'polish', 'themealdb', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Chopped Onion", "notes": null, "category": "produce"}, {"quantity": 1.5, "unit": "cups", "item": "Sauerkraut", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tbs", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Chopped Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Sour Cream", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "cups", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 0.25, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Baking Powder", "notes": null, "category": "pantry"}]'::jsonb, '["To prepare the sauerkraut filling, melt the butter in a skillet over medium heat. Stir in the onion, and cook until translucent, about 5 minutes. Add the drained sauerkraut and cook for an additional 5 minutes. Season to taste with salt and pepper, then remove to a plate to cool.", "For the mashed potato filling, melt the butter in a skillet over medium heat. Stir in the onion, and cook until translucent, about 5 minutes. Stir into the mashed potatoes, and season with salt and white pepper.", "To make the dough, beat together the eggs and sour cream until smooth. Sift together the flour, salt, and baking powder; stir into the sour cream mixture until dough comes together. Knead the dough on a lightly floured surface until firm and smooth. Divide the dough in half, then roll out one half to 1/8 inch thickness. Cut into 3 inch rounds using a biscuit cutter.", "Place a small spoonful of the mashed potato filling into the center of each round. Moisten the edges with water, fold over, and press together with a fork to seal. Repeat procedure with the remaining dough and the sauerkraut filling.", "Bring a large pot of lightly salted water to a boil. Add perogies and cook for 3 to 5 minutes or until pierogi float to the top. Remove with a slotted spoon."]'::jsonb, 'https://www.allrecipes.com/recipe/109914/pierogi-polish-dumplings/', 'https://www.themealdb.com/images/media/meals/45xxr21593348847.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('polish-patties-kotlety', 'Polish patties (kotlety)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'polish', 'themealdb'], '[{"quantity": 1.0, "unit": "serving", "item": "Rolls", "notes": null, "category": "grains"}, {"quantity": 120.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "ml", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 500.0, "unit": "g", "item": "Ground Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Marjoram", "notes": null, "category": "spices"}, {"quantity": 75.0, "unit": "g", "item": "Breadcrumbs", "notes": null, "category": "grains"}]'::jsonb, '["step 1", "Soak the bread roll in the milk so it softens completely. Meanwhile, fry the onion in the oil for around 8 mins or until soft and golden. Add the fried onion to the beef mince along with the egg, garlic, marjoram and some seasoning. Squeeze the excess milk from the bread roll and add it to the mince mixture. Mix everything together and season well.", "step 2", "Divide the meat into 8 patties. Tip the dried breadcrumbs into a shallow bowl and coat the patties in it, all over. Heat some oil in a deep frying pan and fry the patties in batches on both sides until browned and cooked through, about 6-7 mins on each side."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/polish-patties', 'https://www.themealdb.com/images/media/meals/vvn5f71764360273.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('prawn-fennel-bisque', 'Prawn & Fennel Bisque', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'french', 'themealdb', 'soup', 'baking'], '[{"quantity": 450.0, "unit": "g", "item": "Tiger Prawns", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Fennel", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "ml", "item": "Dry White Wine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tbs", "item": "Brandy", "notes": null, "category": "other"}, {"quantity": 400.0, "unit": "g", "item": "Chopped Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "l", "item": "Fish Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 150.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Prawns", "notes": null, "category": "other"}]'::jsonb, '["Shell the prawns, then fry the shells in the oil in a large pan for about 5 mins. Add the onion, fennel and carrots and cook for about 10 mins until the veg start to soften. Pour in the wine and brandy, bubble hard for about 1 min to drive off the alcohol, then add the tomatoes, stock and paprika. Cover and simmer for 30 mins. Meanwhile, chop the prawns.", "Blitz the soup as finely as you can with a stick blender or food processor, then press through a sieve into a bowl. Spend a bit of time really working the mixture through the sieve as this will give the soup its velvety texture.", "Tip back into a clean pan, add the prawns and cook for 10 mins, then blitz again until smooth. You can make and chill this a day ahead or freeze it for 1 month. Thaw ovenight in the fridge. To serve, gently reheat in a pan with the cream. If garnishing, cook the 8 prawns in a little butter. Spoon into small bowls and top with the prawns and snipped fennel fronds."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/71600/prawn-and-fennel-bisque', 'https://www.themealdb.com/images/media/meals/rtwwvv1511799504.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('rye-bread', 'Rye bread', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'polish', 'themealdb', 'baking', 'vegetarian'], '[{"quantity": 200.0, "unit": "g", "item": "Rye", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "Strong white bread flour", "notes": null, "category": "grains"}, {"quantity": 10.0, "unit": "g", "item": "Yeast", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Honey", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Caraway Seed", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Tip the flours, yeast and salt into a bowl. In a jug, mix the honey with 250ml warm water, pour the liquid into the bowl and mix to form a dough. Rye flour can be quite dry and absorbs lots of water, if the dough looks too dry add more warm water until you have a soft dough Tip out onto your work surface and knead for 10 mins until smooth. Rye contains less gluten than white flour so the dough will not feel as springy as a conventional white loaf.", "step 2", "Place the dough in a well oiled bowl, cover with cling film and leave to rise in a warm place for 1-2 hrs, or until roughly doubled in size. Dust a 2lb/900g loaf tin with flour.", "step 3", "Tip the dough back onto your work surface and knead briefly to knock out any air bubbles. If using caraway seeds work these in to the dough. Shape into a smooth oval loaf and pop into your tin. Cover the tin with oiled cling film and leave to rise somewhere warm for a further 1 – 1.5 hr, or until doubled in size.", "step 4", "Heat oven to 220C/200C fan/gas 7. Remove the cling film and dust the surface of the loaf with rye flour. Slash a few incisions on an angle then bake for 30 mins until dark brown and hollow sounding when tapped. Transfer to a wire cooling rack and leave to cool for at least 20 mins before serving"]'::jsonb, 'https://www.bbcgoodfood.com/recipes/rye-bread', 'https://www.themealdb.com/images/media/meals/lmc6r51764365554.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sesame-cucumber-salad', 'Sesame Cucumber Salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'chinese', 'themealdb', 'salad', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Cucumber", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Rice Vinegar", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "tsp", "item": "Red Chilli Flakes", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "Sesame Seed", "notes": null, "category": "pantry"}]'::jsonb, '["Prep the cucumbers:", "Peel the cucumbers. Cut them into quarters, lengthwise. (If the seeds are bitter, scrape out the seeds and discard.) Cut the cucumbers again, crosswise, into 1/2-inch thick pieces.", "Toss the salad:", "Place cucumbers into a serving bowl. Sprinkle with salt. Toss with sesame oil, seasoned rice vinegar, basil (if using), and chili flakes. Sprinkle with toasted sesame seeds if using."]'::jsonb, 'https://www.simplyrecipes.com/recipes/sesame_cucumber_salad/', 'https://www.themealdb.com/images/media/meals/93iok31766436070.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('shawarma-bread', 'Shawarma bread', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'saudi arabian', 'themealdb', 'dessert', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "cup", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Splash Water", "notes": null, "category": "other"}]'::jsonb, '["1", "Sieve flour and add baking powder,salt,sugar,oil nd mix together", "2", "Add water nd knead the dough for like 10mins", "3", "Cover the mixture and allow it to rise", "4", "After it rised transfer it to a work surface and form a round (you can use a plate or pot''s lid)", "5", "Heat ur pan and put it", "6", "It''ll start puffing then you turn it", "7", "And lastly put it in in a warm place, then you''ll see it has pocket"]'::jsonb, 'https://cookpad.com/eng/recipes/22607524?ref=search&search_term=saudi+arabia', 'https://www.themealdb.com/images/media/meals/i8l2fu1763742525.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('smoked-aubergine-purée', 'Smoked aubergine purée', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'turkish', 'themealdb', 'grilling', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Aubergine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "Crushed Garlic", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "ml", "item": "Yogurt", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Dill", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat grill to very hot. Slice the aubergines in half lengthways, then grill for 25 mins, turning occasionally, until soft – the skin will remain firm, but the flesh will soften. Lift the aubergines off the grill and leave until cool enough to handle.", "step 2", "Using a sharp knife, score the grilled flesh and scoop out the flesh with a spoon. Tip into a bowl and mash with a fork until you get a thick pulp. Beat in the lemon juice and garlic. Add the yogurt and dill, and season. Serve while still warm."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/smoked-aubergine-puree', 'https://www.themealdb.com/images/media/meals/8c8m4q1763791156.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('snert-dutch-split-pea-soup', 'Snert (Dutch Split Pea Soup)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'dutch', 'themealdb', 'soup'], '[{"quantity": 2.0, "unit": "l", "item": "Water", "notes": null, "category": "other"}, {"quantity": 300.0, "unit": "g", "item": "Peas", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Pork", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Stock Cube", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leek", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Celeriac", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "pound", "item": "Sausages", "notes": null, "category": "meat"}]'::jsonb, '["Gather the ingredients.", "In a large soup pot, bring water, split peas, pork belly or bacon, pork chop, and bouillon cube to a boil. Reduce the heat to a simmer, cover and let cook for 45 minutes, stirring occasionally and skimming off any foam that rises to the top.", "Remove the pork chop, debone, and thinly slice the meat. Set aside.", "Add the celery, carrots, potato, onion, leek, and celeriac to the soup. Return to the boil, reduce the heat to a simmer and let cook, uncovered, for another 30 minutes, adding a little extra water if the ingredients start to stick to the bottom of the pot.", "Add the smoked sausage for the last 15 minutes of cooking time. When the vegetables are tender, remove the bacon and smoked sausage, slice thinly and set aside.", "If you prefer a smooth consistency, purée the soup with a stick blender. Season to taste with salt and pepper. Add the meat back to the soup, setting some slices of rookworst aside.", "Serve in heated bowls or soup plates, garnished with slices of rookworst and chopped celery leaf.", "Enjoy!"]'::jsonb, 'https://www.thespruceeats.com/traditional-dutch-split-pea-soup-1129011', 'https://www.themealdb.com/images/media/meals/9ptx0a1565090843.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('split-pea-soup', 'Split Pea Soup', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'canadian', 'themealdb', 'soup'], '[{"quantity": 1.0, "unit": "kg", "item": "Ham", "notes": null, "category": "meat"}, {"quantity": 200.0, "unit": "g", "item": "soaked overnight Peas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Frozen Peas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Bread", "notes": null, "category": "grains"}]'::jsonb, '["Put the gammon in a very large pan with 2 litres water and bring to the boil. Remove from the heat and drain off the water – this helps to get rid of some of the saltiness. Recover with 2 litres cold water and bring to the boil again. Put everything but the frozen peas into the pan and bring to the boil. Reduce to a simmer and cook for 1½-2½ hrs, topping up the water as and when you need to, to a similar level it started at. As the ham cooks and softens, you can halve it if you want, so it is all submerged under the liquid. When the ham is tender enough to pull into shreds, it is ready.", "Lift out the ham, peel off and discard the skin. While it is still hot (wear a clean pair of rubber gloves), shred the meat. Remove bay from the soup and stir in the frozen peas. Simmer for 1 min, then blend until smooth. Add a splash of water if too thick, and return to the pan to heat through if it has cooled, or if you are making ahead.", "When you are ready to serve, mix the hot soup with most of the ham – gently reheat if made ahead. Serve in bowls with the remaining ham scattered on top, and eat with crusty bread and butter."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/1022639/split-pea-and-green-pea-smoked-ham-soup', 'https://www.themealdb.com/images/media/meals/xxtsvx1511814083.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('venezuelan-arepas', 'Venezuelan Arepas', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'venezulan', 'themealdb', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 2.0, "unit": "cups", "item": "Cornmeal", "notes": null, "category": "produce"}, {"quantity": 2.5, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Vegetable Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Preheat oven to 410° F.", "Pour the water into a large bowl. Make sure it is room temperature.", "Add the salt. Blend well with a mixer, fork or spatula to make sure it dissolves well.", "While you continue to beat the mixture, slowly add the corn meal—a little bit at a time.", "Once all the flour is added, keep mixing until the corn meal, water and salt are thoroughly blended and dissolved.", "Set aside the masa in its bowl. Let it rest for 5 minutes so that the flour is thoroughly hydrated. This type of corn flour does not have any gluten, so it doesn’t need to be kneaded. The masa should be smooth, firm yet malleable.", "While waiting for the 5 minutes’ rest, heat your budare (or comal, griddle, cast-iron pan or non-stick pan) over medium heat. Coat with a little bit of the oil.", "Fill a small bowl with water to wet your hands to make the arepas.", "Take about 2 Tbsp of the masa in your damp hands. The masa should fit easily in your palm so that it is easy to shape into a small ball.", "Cross your hands, so that one is on top of the other, with the masa ball between them. Rotate your right hand in a circle, so that you are at the same time both pressing the masa into a flat disc and keeping its round shape.", "arepa making", "The last step in shaping your arepa is to quickly pass and lightly press the masa disc from one hand to the other until it is about ¾ of an inch thick and 4 inches wide. Smooth the edges with your fingertips (quickly dip them into the water bowl first) so that they stay as round as possible and without cracks.", "arepa making", "Place your arepas in batches on the preheated surface of your budare griddle or nonstick pan. Let each side turn golden, about 4 to 5 minutes per side. Check them often so that they don’t burn.", "Once they are nicely browned on both sides, place the arepas on a baking sheet in your preheated oven for 10 minutes. They should be somewhat puffy, so that if you tap an arepa lightly on top, it will sound like you are tapping an empty box.", "Serve arepas hot, whether you stuff with them with your choice of fillings or serve solo to accompany your favorite Venezuelan guiso or stew."]'::jsonb, 'https://familiakitchen.com/how-to-make-arepas/', 'https://www.themealdb.com/images/media/meals/3hcy191764376285.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('venezuelan-turnovers', 'Venezuelan turnovers', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'venezulan', 'themealdb'], '[{"quantity": 450.0, "unit": "g", "item": "Ground Beef", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch", "notes": "Ground Cumin", "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Green Pepper", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Garlic Powder", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "Capers", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "can", "item": "Tomato Sauce", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "can", "item": "Sazon", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Masarepa", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Vegetable Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Season meat with Adobo. In skillet, heat oil on medium high. Cook meat until pink is gone. Stir in onion, pepper, garlic, alcaparras, tomato sauce and Sazón. Cook, stirring often until most of the liquid has evaporated (about 20 minutes). Cool.", "Prepared dough should be moist and should hold together, but it should not stick to your fingers. Start with about ½ cup of dough and roll into a ball between palms of your hands. Working on a sheet of non-stick parchment paper, form the ball into a 5-inch circle about ⅛ inch thick. Place a generous tbsp. of filling on one half of circle and using parchment paper close dough over to form a semi-circle. To seal and trim edges of the empanada, press lip of inverted bowl over semi-circle shaped patty. Repeat for all the Empanadas.", "In large skillet on medium high, heat ½ inch of oil until hot but not smoking. Cook empanadas in batches, turning once or twice until lightly browned. Drain on paper towel. Do not over crowd skillet or let oil get too hot."]'::jsonb, 'https://goya.es/en/recipes/venezuelan-turnovers', 'https://www.themealdb.com/images/media/meals/zjtfp31764440795.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('zemiakové-placky', 'Zemiakové Placky', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['side', 'slovakian', 'themealdb', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "kg", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 4.0, "unit": "tablespoons", "item": "All purpose flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Marjoram", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Oil", "notes": null, "category": "pantry"}]'::jsonb, '["1. Prepare the Potatoes", "Start by peeling and finely grating the potatoes. To ensure extra crispiness, use a clean kitchen towel to squeeze out as much moisture as possible.", "2. Mix the Ingredients", "In a large mixing bowl, combine the grated potatoes, chopped onion, minced garlic, eggs, flour, marjoram, salt, and black pepper. Stir well until the mixture forms a thick, consistent batter.", "3. Heat the Oil", "In a large frying pan, heat a generous amount of oil over medium heat. The oil should be hot but not smoking.", "4. Fry the Pancakes", "Spoon portions of the batter into the pan, flattening each into a thin pancake. Fry until golden brown and crispy on one side, then flip and cook the other side until equally golden and crispy.", "5. Drain & Serve", "Transfer the cooked pancakes onto a plate lined with paper towels to remove excess oil. Serve immediately while hot, with sour cream, garlic dip, or as a side dish."]'::jsonb, 'https://www.slovakia-foods.co.uk/blog/post/zemiakove-placky-recipe-how-to-make-authentic-slovak-potato-pancakes.html', 'https://www.themealdb.com/images/media/meals/0umm891763364625.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ajo-blanco', 'Ajo blanco', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['starter', 'spanish', 'themealdb', 'vegetarian', 'vegan'], '[{"quantity": 150.0, "unit": "g", "item": "White bread", "notes": null, "category": "grains"}, {"quantity": 200.0, "unit": "g", "item": "Almonds", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "ml", "item": "Extra Virgin Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tbsp", "item": "Red Wine Vinegar", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Tip the bread into a bowl and pour over 350ml water. Leave to soak for 10 mins.", "step 2", "Blend the ingredients together with 350ml water and 1 tsp salt.", "step 3", "Let the soup cool in the fridge for 1 hr or so, then serve with a drizzle of oil and some black pepper."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/ajo-blanco', 'https://www.themealdb.com/images/media/meals/5jdtie1763289302.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('broccoli-stilton-soup', 'Broccoli & Stilton soup', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['starter', 'british', 'themealdb', 'soup', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Rapeseed Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "chopped  Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leek", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "hot Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "head", "item": "chopped Broccoli", "notes": null, "category": "produce"}, {"quantity": 140.0, "unit": "g", "item": "Stilton Cheese", "notes": null, "category": "dairy"}]'::jsonb, '["Heat the rapeseed oil in a large saucepan and then add the onions. Cook on a medium heat until soft. Add a splash of water if the onions start to catch.", "Add the celery, leek, potato and a knob of butter. Stir until melted, then cover with a lid. Allow to sweat for 5 minutes. Remove the lid.", "Pour in the stock and add any chunky bits of broccoli stalk. Cook for 10 – 15 minutes until all the vegetables are soft.", "Add the rest of the broccoli and cook for a further 5 minutes. Carefully transfer to a blender and blitz until smooth. Stir in the stilton, allowing a few lumps to remain. Season with black pepper and serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/1940679/broccoli-and-stilton-soup', 'https://www.themealdb.com/images/media/meals/tvvxpv1511191952.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('clam-chowder', 'Clam chowder', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['starter', 'american', 'themealdb', 'breakfast', 'soup', 'baking'], '[{"quantity": 1.5, "unit": "kg", "item": "Clams", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 150.0, "unit": "g", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "chopped  Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "sprigs of", "notes": "fresh Thyme", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 150.0, "unit": "ml", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 150.0, "unit": "ml", "item": "Double Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Parsley", "notes": null, "category": "produce"}]'::jsonb, '["Rinse the clams in several changes of cold water and drain well. Tip the clams into a large pan with 500ml of water. Cover, bring to the boil and simmer for 2 mins until the clams have just opened. Tip the contents of the pan into a colander over a bowl to catch the clam stock. When cool enough to handle, remove the clams from their shells – reserving a handful of empty shells for presentation if you want. Strain the clam stock into a jug, leaving any grit in the bottom of the bowl. You should have around 800ml stock.", "Heat the butter in the same pan and sizzle the bacon for 3-4 mins until it starts to brown. Stir in the onion, thyme and bay and cook everything gently for 10 mins until the onion is soft and golden. Scatter over the flour and stir in to make a sandy paste, cook for 2 mins more, then gradually stir in the clam stock then the milk and the cream.", "Throw in the potatoes, bring everything to a simmer and leave to bubble away gently for 10 mins or until the potatoes are cooked. Use a fork to crush a few of the potato chunks against the side of the pan to help thicken – you still want lots of defined chunks though. Stir through the clam meat and the few clam shells, if you''ve gone down that route, and simmer for a minute to reheat. Season with plenty of black pepper and a little salt, if needed, then stir through the parsley just before ladling into bowls or hollowed-out crusty rolls."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/clam-chowder', 'https://www.themealdb.com/images/media/meals/rvtvuw1511190488.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cream-cheese-tart', 'Cream Cheese Tart', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['starter', 'american', 'themealdb', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 250.0, "unit": "g", "item": "Flour", "notes": null, "category": "grains"}, {"quantity": 125.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 300.0, "unit": "g", "item": "Cheese", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "ml", "item": "milk Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "Parmesan Cheese", "notes": null, "category": "dairy"}, {"quantity": 350.0, "unit": "g", "item": "Plum tomatoes", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbsp", "item": "White Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbsp", "item": "Honey", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Topping Basil", "notes": null, "category": "produce"}]'::jsonb, '["Crust: make a dough from 250g flour (I like mixing different flours like plain and wholegrain spelt flour), 125g butter, 1 egg and a pinch of salt, press it into a tart form and place it in the fridge.", "Filling: stir 300g cream cheese and 100ml milk until smooth, add in 3 eggs, 100g grated parmesan cheese and season with salt, pepper and nutmeg.", "Take the crust out of the fridge and prick the bottom with a fork.", "Pour in the filling and bake at 175 degrees C for about 25 minutes.", "Cover the tart with some aluminium foil after half the time.", "In the mean time, slice about 350g mini tomatoes.", "In a small pan heat 3tbsp olive oil, 3tbsp white vinegar, 1 tbsp honey, salt and pepper and combine well.", "Pour over the tomato slices and mix well.", "With a spoon, place the tomato slices on the tart, avoiding too much liquid on it.", "Decorate with basil leaves and enjoy."]'::jsonb, 'https://www.instagram.com/p/BHyuMZ1hZX0', 'https://www.themealdb.com/images/media/meals/wurrux1468416624.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('creamy-tomato-soup', 'Creamy Tomato Soup', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['starter', 'british', 'themealdb', 'dessert', 'soup', 'vegetarian'], '[{"quantity": 3.0, "unit": "tbsp", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "White Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.5, "unit": "kg", "item": "Chopped Tomatoes", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "g", "item": "Passata", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Stock Cube", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "ml", "item": "Whole Milk", "notes": null, "category": "dairy"}]'::jsonb, '["Put the oil, onions, celery, carrots, potatoes and bay leaves in a big casserole dish, or two saucepans. Fry gently until the onions are softened – about 10-15 mins. Fill the kettle and boil it.", "Stir in the tomato purée, sugar, vinegar, chopped tomatoes and passata, then crumble in the stock cubes. Add 1 litre boiling water and bring to a simmer. Cover and simmer for 15 mins until the potato is tender, then remove the bay leaves. Purée with a stick blender (or ladle into a blender in batches) until very smooth. Season to taste and add a pinch more sugar if it needs it. The soup can now be cooled and chilled for up to 2 days, or frozen for up to 3 months.", "To serve, reheat the soup, stirring in the milk – try not to let it boil. Serve in small bowls with cheesy sausage rolls."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/2604646/creamy-tomato-soup', 'https://www.themealdb.com/images/media/meals/stpuws1511191310.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('quick-gazpacho', 'Quick gazpacho', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['starter', 'spanish', 'themealdb', 'soup', 'vegetarian', 'vegan'], '[{"quantity": 250.0, "unit": "g", "item": "Passata", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Sherry vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1/2 Lime", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "In a blender (or with a stick blender), whizz together the passata, red pepper, chilli, garlic, sherry vinegar and lime juice until smooth. Season to taste, then serve with ice cubes"]'::jsonb, 'https://www.bbcgoodfood.com/recipes/quick-gazpacho', 'https://www.themealdb.com/images/media/meals/h5qmn31763304965.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fasoliyyeh-bi-z-zayt-syrian-green-beans-with-olive-oil', 'Fasoliyyeh Bi Z-Zayt (Syrian Green Beans with Olive Oil)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegan', 'syrian', 'themealdb', 'vegetarian'], '[{"quantity": 16.0, "unit": "ounces", "item": "Green Beans", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "clove", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "Cilantro", "notes": null, "category": "produce"}]'::jsonb, '["Place the green beans into a large pot, and drizzle with olive oil. Season with salt to taste, and put the lid on the pot. Cook over medium-high heat, stirring occasionally, until beans are cooked to your desired doneness. Syrians like it cooked until the green beans are turning brownish in color. The idea is not to saute them, but to let them steam in the moisture released by the ice crystals.", "Add cilantro and garlic to the beans, and continue to cook just until the cilantro has started to wilt. Eat as a main course by scooping up with warm pita bread or serve as a side dish."]'::jsonb, 'https://www.allrecipes.com/recipe/56161/fasoliyyeh-bi-z-zayt-syrian-green-beans-with-olive-oil/', 'https://www.themealdb.com/images/media/meals/21yc5s1760524759.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('padron-peppers', 'Padron peppers', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegan', 'spanish', 'themealdb', 'vegetarian'], '[{"quantity": 1.0, "unit": "tablespoon", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 500.0, "unit": "g", "item": "Padron peppers", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat the olive oil in a large frying pan over a high heat, or if using an air-fryer, heat to 205C for 3 mins. Fry the peppers, stirring frequently, for 5 mins until blistered and wilted. The peppers should be soft and slightly charred.", "step 2", "Transfer the peppers to a serving plate and season with some sea salt. Serve with dips or as part of a tapas spread, if you like."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/padron-peppers', 'https://www.themealdb.com/images/media/meals/0ljvc51763248075.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('red-onion-pickle', 'Red onion pickle', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegan', 'norwegian', 'themealdb', 'dessert', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Sea Salt", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "ml", "item": "Cider Vinegar", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "Granulated Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}]'::jsonb, '["Peel the onions, cut them in half from top to bottom and finely slice into half-moon pieces. Put in a colander placed over a bowl and sprinkle with salt, lightly turning over the onion pieces with your hands so the surfaces are all covered. Set aside for an hour or so to brine.", "Meanwhile put the vinegar, 50ml/2fl oz water and the sugar in a saucepan. Bring to a simmer, stirring to help the sugar dissolve, and cook for a couple of minutes. Set aside.", "Pack the onions into the sterilised jars, sprinkling in a little pepper as you go. Cover with the warm vinegar and finish by tucking a couple of bay leaves down the side of the jars. Seal. The onions are best kept in the fridge and used within to 4 weeks."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/red_onion_pickle_98165', 'https://www.themealdb.com/images/media/meals/ppodrp1762325183.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('roast-fennel-and-aubergine-paella', 'Roast fennel and aubergine paella', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegan', 'spanish', 'themealdb', 'soup', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "serving", "item": "Baby Aubergine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Fennel", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "sliced Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Courgettes", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "chopped  Onion", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "g", "item": "Paella Rice", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Saffron", "notes": null, "category": "spices"}, {"quantity": 200.0, "unit": "ml", "item": "White Wine", "notes": null, "category": "other"}, {"quantity": 700.0, "unit": "ml", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 100.0, "unit": "g", "item": "Frozen Peas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Black Pepper", "notes": null, "category": "produce"}]'::jsonb, '["1 Put the fennel, aubergine, pepper and courgette in a roasting tray. Add a glug of olive oil, season with salt and pepper and toss around to coat the veggies in the oil. Roast in the oven for 20 minutes, turning a couple of times until the veg are pretty much cooked through and turning golden.", "2 Meanwhile, heat a paella pan or large frying pan over a low– medium heat and add a glug of olive oil. Sauté the onion for 8–10 minutes until softened. Increase the heat to medium and stir in the rice, paprika and saffron. Cook for around 1 minute to start toasting the rice, then add the white wine. Reduce by about half before stirring in two-thirds of the stock. Reduce to a simmer and cook for 10 minutes without a lid, stirring a couple of times.", "3 Stir in the peas, add some seasoning, then gently mix in the roasted veg. Pour over the remaining stock, arrange the lemon wedges on top and cover with a lid or some aluminium foil. Cook for a further 10 minutes.", "4 To ensure you get the classic layer of toasted rice at the bottom of the pan, increase the heat to high until you hear a slight crackle. Remove from the heat and sit for 5 minutes before sprinkling over the parsley and serving."]'::jsonb, 'https://www.homestylemag.co.uk/recipe/517/main-courses/roast-fennel-and-aubergine-paella', 'https://www.themealdb.com/images/media/meals/1520081754.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vegan-banh-mi', 'Vegan banh mi', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegan', 'vietnamese', 'themealdb', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 150.0, "unit": "g", "item": "Raw Vegetables", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Vegan White Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Golden Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Baguette", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Hummus", "notes": null, "category": "other"}, {"quantity": 175.0, "unit": "g", "item": "Tempeh", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Mint", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Hotsauce", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Put the shredded veg in a bowl and add the vinegar, sugar and 1 tsp salt. Toss everything together, then set aside to pickle quickly while you prepare the rest of the sandwich.", "step 2", "Heat oven to 180C/160C fan/gas 4. Cut the baguette into four, then slice each piece horizontally in half. Put the baguette pieces in the oven for 5 mins until lightly toasted and warm. Spread each piece with a layer of hummus, then top four pieces with the tempeh slices and pile the pickled veg on top. To serve, sprinkle over the herbs and squeeze over some hot sauce, then top with the other baguette pieces to make sandwiches."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/boxing-day-banh-mi', 'https://www.themealdb.com/images/media/meals/sonirb1763782831.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vegan-chocolate-cake', 'Vegan Chocolate Cake', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegan', 'american', 'themealdb', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 1.25, "unit": "cup", "item": "Self-raising Flour", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "cup", "item": "coco sugar", "notes": null, "category": "pantry"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "raw cacao", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "baking powder", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "eggs", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "almond milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "vanilla", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "boiling water", "notes": null, "category": "pantry"}]'::jsonb, '["Simply mix all dry ingredients with wet ingredients and blend altogether.", "Bake for 45 min on 180 degrees.", "Decorate with some melted vegan chocolate."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/qxutws1486978099.jpg', FALSE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vegan-lasagna', 'Vegan Lasagna', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegan', 'italian', 'themealdb', 'pasta', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "cups", "item": "green red lentils", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "zucchini", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "sprinking coriander", "notes": null, "category": "spices"}, {"quantity": 150.0, "unit": "g", "item": "spinach", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "sheets", "notes": null, "category": "other"}, {"quantity": 35.0, "unit": "g", "item": "vegan butter", "notes": null, "category": "dairy"}, {"quantity": 4.0, "unit": "tablespoons", "item": "flour", "notes": null, "category": "grains"}, {"quantity": 300.0, "unit": "ml", "item": "soya milk", "notes": null, "category": "dairy"}, {"quantity": 1.5, "unit": "teaspoons", "item": "mustard", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "vinegar", "notes": null, "category": "pantry"}]'::jsonb, '["1) Preheat oven to 180 degrees celcius.", "2) Boil vegetables for 5-7 minutes, until soft. Add lentils and bring to a gentle simmer, adding a stock cube if desired. Continue cooking and stirring until the lentils are soft, which should take about 20 minutes.", "3) Blanch spinach leaves for a few minutes in a pan, before removing and setting aside.", "4) Top up the pan with water and cook the lasagne sheets. When cooked, drain and set aside.", "5) To make the sauce, melt the butter and add the flour, then gradually add the soya milk along with the mustard and the vinegar. Cook and stir until smooth and then assemble the lasagne as desired in a baking dish.", "6) Bake in the preheated oven for about 25 minutes."]'::jsonb, NULL, 'https://www.themealdb.com/images/media/meals/rvxxuy1468312893.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('air-fryer-patatas-bravas', 'Air fryer patatas bravas', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'spanish', 'themealdb', 'vegan'], '[{"quantity": 900.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 225.0, "unit": "g", "item": "Tinned Tomatos", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Basil Leaves", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Soak the potatoes in just-boiled water for 30 mins, then drain and leave to air-dry for 5 mins. Heat the air fryer to 200C. Tip the potatoes into a bowl and drizzle over 1 tbsp of the oil and add 1/2 tsp each of salt and freshly ground black pepper. Mix to coat the potatoes all over, then tip into the air fryer basket and cook for 20-30 mins until crisp and golden.", "step 2", "Meanwhile, heat the remaining oil in a small pan over a medium-low heat and fry the onion for 8-10 mins until softened but not golden. Stir in the garlic and cook for a minute before adding the paprika and cooking for 30 seconds more. Stir in the tomato purée, cook for 1 min, then tip in the chopped tomatoes. Cook for 5-10 mins over a medium heat until thickened slightly.", "step 3", "Once the potatoes are cooked, tip out onto a platter and pour over the tomato sauce. Sprinkle with the basil leaves, then serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/air-fryer-patatas-bravas', 'https://www.themealdb.com/images/media/meals/3m8yae1763257951.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('algerian-flafla-bell-pepper-salad', 'Algerian Flafla (Bell Pepper Salad)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'algerian', 'themealdb', 'salad', 'baking', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "chopped Red Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Plum Tomatoes", "notes": null, "category": "produce"}]'::jsonb, '["Preheat an oven to 450 degrees F (230 degrees C). Place the whole peppers on aluminum foil. Bake until the skin is spotted black and the peppers are soft, 30 to 45 minutes, turning the peppers once if necessary.", "Remove peppers from the oven and set aside to cool for 10 minutes. Peel off the skin and remove the stem and seeds. Chop the roasted peppers into half-inch pieces.", "Heat the olive oil in a skillet over medium heat. Stir in the onion and cook, stirring frequently, until the onion has softened and turned translucent, about 5 minutes. Add the garlic, salt, and pepper; stir in the chopped peppers and tomato. Cook over medium heat, stirring occasionally, until the tomato is soft and the mixture is well incorporated, about 5 minutes."]'::jsonb, 'https://www.allrecipes.com/recipe/153802/algerian-flafla-bell-pepper-salad/', 'https://www.themealdb.com/images/media/meals/tbj1bs1764118062.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('aubergine-hummus-grills', 'Aubergine & hummus grills', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'turkish', 'themealdb', 'grilling', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Aubergine", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "thinly Bread", "notes": null, "category": "grains"}, {"quantity": 300.0, "unit": "g", "item": "Hummus", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "Walnuts", "notes": null, "category": "pantry"}, {"quantity": 40.0, "unit": "g", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Cherry Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1/2 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Splash Extra Virgin Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Lay the aubergine out in one layer on a large baking sheet. Brush sparingly with vegetable oil, then season generously. Grill for 15 mins, turning twice and brushing with oil until the slices are softened and cooked through. Meanwhile, whizz the bread into crumbs. Add 2 tsp oil and whizz briefly again, to coat.", "step 2", "Spread a couple of tsps of hummus on top of each slice of aubergine. Tip the breadcrumbs onto a large plate, then press the hummus side of the aubergines into the crumbs to coat. Grill again, crumb-side up, for about 3 mins until golden.", "step 3", "Toss the walnuts, parsley and cherry tomatoes in a bowl, season, then add the lemon juice and olive oil and toss again. Serve the grills with the salad, a dollop more hummus and some pitta bread."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/aubergine-hummus-grills', 'https://www.themealdb.com/images/media/meals/zub3s91764110535.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('aubergine-couscous-salad', 'Aubergine couscous salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'turkish', 'themealdb', 'soup', 'salad', 'grilling'], '[{"quantity": 1.0, "unit": "serving", "item": "Aubergine", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 140.0, "unit": "g", "item": "Couscous", "notes": null, "category": "grains"}, {"quantity": 225.0, "unit": "g", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Cherry Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Mint", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Goats Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1/2 Lemon", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat grill to high. Put the aubergine on a baking sheet, brush with oil and season. Grill for about 15 mins, turning and brushing with more oil halfway, until browned and softened.", "step 2", "Meanwhile, tip the couscous into a large bowl, pour over the stock, then cover and leave for 10 mins. Mix the tomatoes, mint, goat’s cheese and remaining oil together. Fluff the couscous up with a fork, then stir in the aubergines, tomato mixture and lemon juice."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/aubergine-couscous-salad', 'https://www.themealdb.com/images/media/meals/02s6gc1763799560.jpg', FALSE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('avocado-dip-with-new-potatoes', 'Avocado dip with new potatoes', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'australian', 'themealdb', 'baking', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Avocado", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Natural Yoghurt", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Zest and juice of 1 Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1/2 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.25, "unit": "kg", "item": "Baby New Potatoes", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Hot Chilli Powder", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Cumin Seeds", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Tortillas", "notes": null, "category": "grains"}]'::jsonb, '["step 1", "Whizz half the avocado flesh with the yogurt, lime and lemon juice and seasoning. Dice the remaining avocado, then gently stir into the whizzed mix with most of the lime zest. Cover, then chill until ready to serve.", "step 2", "Boil potatoes for 6 mins, then drain well and toss with olive oil, chilli powder and cumin seeds. Now set aside until half an hour before your guests arrive.", "step 3", "Heat oven to 200C/180C fan/gas 6, then roast potatoes for about 30 mins, shaking the tray halfway, until golden and tender. Transfer the dip to one or two bowls, scatter with the remaining lime zest and serve with the hot potatoes, and tortilla chips for dipping."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/avocado-citrus-dip-spicy-spuds-tortilla-chips', 'https://www.themealdb.com/images/media/meals/flrajf1762341295.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('baingan-bharta', 'Baingan Bharta', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'indian', 'themealdb', 'baking', 'grilling', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Aubergine", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "cup", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 6.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "teaspoon", "item": "Red Chilli Powder", "notes": null, "category": "other"}, {"quantity": 1.5, "unit": "tablespoon", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "chopped Coriander Leaves", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "as required salt", "notes": null, "category": "pantry"}]'::jsonb, '["Rinse the baingan (eggplant or aubergine) in water. Pat dry with a kitchen napkin. Apply some oil all over and", "keep it for roasting on an open flame. You can also grill the baingan or roast in the oven. But then you won''t get", "the smoky flavor of the baingan. Keep the eggplant turning after a 2 to 3 minutes on the flame, so that its evenly", "cooked. You could also embed some garlic cloves in the baingan and then roast it.", "2. Roast the aubergine till its completely cooked and tender. With a knife check the doneness. The knife should slid", "easily in aubergines without any resistance. Remove the baingan and immerse in a bowl of water till it cools", "down.", "3. You can also do the dhungar technique of infusing charcoal smoky flavor in the baingan. This is an optional step.", "Use natural charcoal for this method. Heat a small piece of charcoal on flame till it becomes smoking hot and red.", "4. Make small cuts on the baingan with a knife. Place the red hot charcoal in the same plate where the roasted", "aubergine is kept. Add a few drops of oil on the charcoal. The charcoal would begin to smoke.", "5. As soon as smoke begins to release from the charcoal, cover the entire plate tightly with a large bowl. Allow the", "charcoal smoke to get infused for 1 to 2 minutes. The more you do, the more smoky the baingan bharta will", "become. I just keep for a minute. Alternatively, you can also do this dhungar method once the baingan bharta is", "cooked, just like the way we do for Dal Tadka.", "6. Peel the skin from the roasted and smoked eggplant.", "7. Chop the cooked eggplant finely or you can even mash it.", "8. In a kadai or pan, heat oil. Then add finely chopped onions and garlic.", "9. Saute the onions till translucent. Don''t brown them.", "10. Add chopped green chilies and saute for a minute.", "11. Add the chopped tomatoes and mix it well.", "12. Bhuno (saute) the tomatoes till the oil starts separating from the mixture.", "13. Now add the red chili powder. Stir and mix well.", "14. Add the chopped cooked baingan.", "15. Stir and mix the chopped baingan very well with the onion­tomato masala mixture.", "16. Season with salt. Stir and saute for some more 4 to 5 minutes more.", "17. Finally stir in the coriander leaves with the baingan bharta or garnish it with them. Serve Baingan Bharta with", "phulkas, rotis or chapatis. It goes well even with bread, toasted or grilled bread and plain rice or jeera rice."]'::jsonb, 'http://www.vegrecipesofindia.com/baingan-bharta-recipe-punjabi-baingan-bharta-recipe/', 'https://www.themealdb.com/images/media/meals/urtpqw1487341253.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beetroot-red-cabbage-sauerkraut', 'Beetroot & red cabbage sauerkraut', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'polish', 'themealdb', 'vegan'], '[{"quantity": 320.0, "unit": "g", "item": "Beetroot", "notes": null, "category": "produce"}, {"quantity": 450.0, "unit": "g", "item": "Red Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Caraway Seed", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Sea Salt", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Tip all the ingredients into a large bowl, add 1-1½ tsp freshly ground black pepper, then scrunch it all together with your hands for 5 mins. You might want to wear gloves to avoid staining your skin with the beetroot juices.", "step 2", "Press the veg down in the bowl with your hands, then cover the surface and up the side of the bowl with a large sheet of compostable cling film or something reusable like a beeswax wrap. Now place another similar-sized bowl on top. Press down hard and add anything heavy (packs of rice or cans work well) to weigh it down so the juices rise to cover the surface. Cover again.", "step 3", "Leave to ferment at room temperature for at least five days, but for maximum flavour, leave for one-five weeks (until the bubbling subsides).", "step 4", "Check the sauerkraut. After a few days, you will see bubbles that have built up as it ferments. Give it a stir, then cover and weigh it down again as before. The cabbage will become increasingly sour the longer it’s fermented, so taste it now and again. When you like the flavour, transfer it to sterilised jars and keep chilled. Will keep chilled for up to six months."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/beetroot-red-cabbage-sauerkraut', 'https://www.themealdb.com/images/media/meals/ra2k8a1764365055.jpg', FALSE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beetroot-latkes', 'Beetroot latkes', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'ukrainian', 'themealdb', 'baking'], '[{"quantity": 1.0, "unit": "tablespoon", "item": "Rapeseed Oil", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Greek Yogurt", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Mint", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "g", "item": "Rocket", "notes": null, "category": "other"}, {"quantity": 130.0, "unit": "g", "item": "Cherry Tomatoes", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Beetroot", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "clove", "item": "finely", "notes": "chopped Garlic", "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Caraway Seed", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Zest of 1 Lemon", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat the oven to 180C/160C fan/gas 4. Make the latkes by combining all of the ingredients.", "step 2", "Heat the oil in a large non-stick pan. Spoon in the mixture to make six round latkes. Fry for 4-5 mins on each side, then transfer to a baking sheet and bake for 10 mins.", "step 3", "Combine the yogurt and mint in a small bowl. Toss the salad leaves and tomatoes together, then serve the latkes with the mint yogurt and salad."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/beetroot-latkes', 'https://www.themealdb.com/images/media/meals/qwicc91764368097.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beetroot-soup-borscht', 'Beetroot Soup (Borscht)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'ukrainian', 'themealdb', 'soup', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Beetroot", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Stock Cube", "notes": null, "category": "pantry"}, {"quantity": 6.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "can", "item": "Cannellini Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Garnish Dill", "notes": null, "category": "produce"}]'::jsonb, '["Chop the beetroot, add water and stock cube and cook for 15mins.", "Add the other ingredients and boil until soft.", "Finally add the beans and cook for 5mins.", "Serve in the soup pot."]'::jsonb, 'https://natashaskitchen.com/classic-russian-borscht-recipe/', 'https://www.themealdb.com/images/media/meals/zadvgb1699012544.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('braised-stuffed-cabbage', 'Braised stuffed cabbage', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'polish', 'themealdb', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Cabbage Leaves", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Rosemary", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 140.0, "unit": "g", "item": "Basmati Rice", "notes": null, "category": "grains"}, {"quantity": 140.0, "unit": "g", "item": "Cooked Chestnut", "notes": null, "category": "pantry"}, {"quantity": 50.0, "unit": "g", "item": "Cranberry", "notes": null, "category": "produce"}, {"quantity": 300.0, "unit": "ml", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Balsamic Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Clear Honey", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Heat oven to 180C/fan 160C/gas 4. Remove the tough central stalk from the cabbage leaves. Bring a large pan of salted water to the boil, add the cabbage, then cook for just 1-2 mins until the leaves are starting to wilt. Drain and refresh under cold running water. Drain well, then pat dry with a tea towel.", "step 2", "Heat the oil in a pan, add the onion, then fry for 5 mins until slightly browned. Add the rosemary and celery, then cook for 8 mins more. Stir in the rice, then cook for a min or so until the grains are glistening. Remove from the heat, stir in the chestnuts and cranberries, then season.", "step 3", "Spoon a little stuffing onto a cabbage leaf, roll up and fold in the sides to enclose the filling. Put in a single layer in a large, oiled, shallow ovenproof dish with the join underneath. Fill the remaining leaves in the same way. Mix the stock, vinegar and honey, then pour over the cabbage. Cover the dish tightly with foil, bake for 1 hr, uncover, then cook for a further 15 mins."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/braised-stuffed-cabbage', 'https://www.themealdb.com/images/media/meals/z267f71764364072.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cabbage-soup-shchi', 'Cabbage Soup (Shchi)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'russian', 'themealdb', 'soup', 'baking'], '[{"quantity": 3.0, "unit": "tbs", "item": "Unsalted Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 8.0, "unit": "cups", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garnish Sour Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Garnish Dill", "notes": null, "category": "produce"}]'::jsonb, '["Add the butter to a large Dutch oven or other heavy-duty pot over medium heat. When the butter has melted, add the onion and sauté until translucent.", "Add the cabbage, carrot, and celery. Sauté until the vegetables begin to soften, stirring frequently, about 3 minutes.", "Add the bay leaf and vegetable stock and bring to a boil over high heat. Reduce the heat to low and simmer, covered, until the vegetables are crisp-tender, about 15 minutes.", "Add the potatoes and bring it back to a boil over high heat. Reduce the heat to low and simmer, covered, until the potatoes are tender, about 10 minutes.", "Add the tomatoes (or undrained canned tomatoes) and bring the soup back to a boil over high heat. Reduce the heat to low and simmer, uncovered, for 5 minutes. Season to taste with salt and pepper.", "emove and discard the bay leaf from the pot.", "Serve topped with fresh sour cream and fresh dill."]'::jsonb, 'https://www.thespruceeats.com/traditional-russian-cabbage-soup-shchi-recipe-1135534', 'https://www.themealdb.com/images/media/meals/60oc3k1699009846.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chickpea-fajitas', 'Chickpea Fajitas', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'mexican', 'themealdb', 'baking'], '[{"quantity": 400.0, "unit": "g", "item": "Chickpeas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "cut chunks Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "sliced Red Onions", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Red Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Avocado", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1 Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Lime", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Sour Cream", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tsp", "item": "Harissa Spice", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Tortillas", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Coriander", "notes": null, "category": "spices"}]'::jsonb, '["Heat oven to 200C/180C fan/gas 6 and line a baking tray with foil. Drain the chickpeas, pat dry and tip onto the prepared baking tray. Add the oil and paprika, toss to coat, then roast for 20-25 mins until browned and crisp, shaking halfway through cooking.", "Meanwhile, put the tomatoes and onion in a small bowl with the vinegar and set aside to pickle. Put the avocado in another bowl and mash with a fork, leaving some larger chunks. Stir in the lime juice and season well. Mix the soured cream with the harissa and set aside until ready to serve.", "Heat a griddle pan until nearly smoking. Add the tortillas , one at a time, charring each side until hot with griddle lines.", "Put everything on the table and build the fajitas : spread a little of the harissa cream over the tortilla, top with roasted chickpeas, guacamole, pickled salsa and coriander, if you like. Serve with the lime wedges for squeezing over."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/chickpea-fajitas', 'https://www.themealdb.com/images/media/meals/tvtxpq1511464705.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chinese-tomato-egg-stir-fry', 'Chinese Tomato Egg Stir Fry', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'chinese', 'themealdb', 'dessert', 'soup'], '[{"quantity": 1.0, "unit": "lb", "item": "Plum Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tsp", "item": "Chicken Bouillon Powder", "notes": null, "category": "meat"}, {"quantity": 2.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "Jasmine Rice", "notes": null, "category": "grains"}]'::jsonb, '["You can use chicken broth in place of the chicken bouillon powder. Add 1/4 cup of broth followed by 2 teaspoons of cornstarch dissolved in 1 tablespoPrepare the tomatoes:", "Slice the tomatoes in half. Remove the tough stem from each half that connects to the vine. Cut each half into equal thirds (you’ll get 6 slices from each tomato).", "Make the soft scrambled eggs:", "In a cold, 8 to 10-inch nonstick skillet, add the vegetable oil and beaten eggs. Turn the heat to medium. Once a thin layer of eggs is just beginning to cook on the bottom, push the eggs in one direction to create layers of scrambled eggs.", "Cook, gently stirring the whole time, until the scramble eggs are mostly set but still slightly wet and shiny, 2 to 5 minutes. Remove the eggs to a plate and, if needed, wipe out the pan.", "Stir-fry the tomatoes and seasonings:", "Add the sesame oil to the pan followed by the tomatoes and stir-fry over medium heat until the tomatoes are softened but not mushy, about 3 minutes. Add the chicken bouillon powder, sugar, and white pepper. Toss until combined and the sugar and bouillon have dissolved, about 1 minute.", "Add eggs, stir-fry, and garnish:", "Add the eggs back to the pan with the tomatoes. Stir-fry for about 2 minutes to heat through and combine. Taste, adding salt only if needed. Sprinkle with the green onions and serve with steamed rice.on of water, plus salt to taste."]'::jsonb, 'https://www.simplyrecipes.com/chinese-tomato-egg-recipe-7562056', 'https://www.themealdb.com/images/media/meals/rwvw8q1765660071.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chtitha-batata-algerian-potato-stew', 'Chtitha Batata (Algerian Potato Stew)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'algerian', 'themealdb', 'soup', 'vegan'], '[{"quantity": 4.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Cayenne Pepper", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "lbs", "item": "New Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Boiled Water", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}]'::jsonb, '["Combine garlic, chile pepper, cumin, paprika, black pepper, cayenne, and salt in a mortar; grind with a pestle until it forms a paste. Add olive oil and mix dersa well.", "Heat a large saucepan over medium heat and stir-fry dersa until fragrant, 2 to 4 minutes. Add potato halves and stir to combine with the dersa. Stir in tomato paste. Pour in enough water to just cover the potatoes and bring to a boil. Reduce heat and simmer until potatoes are tender, about 40 minutes.", "Ladle potatoes into a serving bowl. Spoon any remaining sauce over the potatoes."]'::jsonb, 'https://www.allrecipes.com/recipe/265319/chtitha-batata-algerian-potato-stew/', 'https://www.themealdb.com/images/media/meals/q8pu1k1764114334.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('crispy-eggplant', 'Crispy Eggplant', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'filipino', 'themealdb'], '[{"quantity": 1.0, "unit": "serving", "item": "Egg Plants", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "cup", "item": "Breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 50.0, "unit": "g", "item": "Sesame Seed", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Vegetable Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Slice eggplant into 1 cm (0.4-inch) slices. Place them in a bowl and sprinkle them with salt. allow them to sit for 30 minutes to render some of their liquid and bitterness.", "2. After 30 minutes wash eggplant slices from salt and pat dry with a kitchen towel.", "3. In a large bowl/plate place breadcrumbs and sesame seeds. In another bowl beat 2 eggs with pinch salt and pepper.", "4. Heal oil in a large skillet over high heat.", "5. Dip eggplant slices in egg, then in crumbs, and place in hot oil. Fry 2 to 3 minutes on each side, or until golden brown. Drain on a paper towel."]'::jsonb, 'https://yummyfood.ph/recipe/crispiest-fried-eggplant/', 'https://www.themealdb.com/images/media/meals/c7lzrl1683208757.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cucumber-fennel-salad', 'Cucumber & fennel salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'polish', 'themealdb', 'dessert', 'salad'], '[{"quantity": 1.0, "unit": "serving", "item": "Cucumber", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Fennel Bulb", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "ml", "item": "Sour Cream", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "White Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Dill", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Put cucumber in a sieve. Sprinkle with 1 tsp salt and the sugar, then leave for 10 mins. Add fennel.", "step 2", "Mix soured cream, lemon juice, vinegar and dill, then season with black pepper and add to fennel mix."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/cucumber-fennel-salad', 'https://www.themealdb.com/images/media/meals/ei21r61764365935.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
