0.25, "unit": "tsp", "item": "Garam Masala", "notes": null, "category": "spices"}]'::jsonb, '["Wash and soak toor dal in approx. 3 cups of water, for at least one hours. Dal will be double in volume after soaking. Drain the water.", "Cook dal with 2-1/2 cups water and add salt, turmeric, on medium high heat, until soft in texture (approximately 30 mins) it should be like thick soup.", "In a frying pan, heat the ghee. Add cumin seeds, and mustard seeds. After the seeds crack, add bay leaves, green chili, ginger and chili powder. Stir for a few seconds.", "Add tomatoes, salt and sugar stir and cook until tomatoes are tender and mushy.", "Add cilantro and garam masala cook for about one minute.", "Pour the seasoning over dal mix it well and cook for another minute.", "Serve with Naan."]'::jsonb, 'https://www.instagram.com/p/BO21bpYD3Fu', 'https://www.themealdb.com/images/media/meals/wuxrtu1483564410.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('egg-drop-soup', 'Egg Drop Soup', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'chinese', 'themealdb', 'dessert', 'soup'], '[{"quantity": 3.0, "unit": "cups", "item": "Chicken Stock", "notes": null, "category": "meat"}, {"quantity": 0.25, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Peas", "notes": null, "category": "produce"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Cornstarch", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Water", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "cup", "item": "Spring Onions", "notes": null, "category": "produce"}]'::jsonb, '["In a wok add chicken broth and wait for it to boil.", "Next add salt, sugar, white pepper, sesame seed oil.", "When the chicken broth is boiling add the vegetables to the wok.", "To thicken the sauce, whisk together 1 Tablespoon of cornstarch and 2 Tablespoon of water in a bowl and slowly add to your soup until it''s the right thickness.", "Next add 1 egg slightly beaten with a knife or fork and add it to the soup slowly and stir for 8 seconds", "Serve the soup in a bowl and add the green onions on top."]'::jsonb, 'https://sueandgambo.com/pages/egg-drop-soup', 'https://www.themealdb.com/images/media/meals/1529446137.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('eggplant-adobo', 'Eggplant Adobo', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'filipino', 'themealdb', 'dessert', 'baking'], '[{"quantity": 1.0, "unit": "lb", "item": "Egg Plants", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "whole", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 4.0, "unit": "oz", "item": "Ground Pork", "notes": null, "category": "meat"}, {"quantity": 3.0, "unit": "tbs", "item": "Rice Vinegar", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tbs", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}]'::jsonb, '["1.\tSlice 1 lb. small Japanese or Italian eggplant (about 3) into quarters lengthwise, then cut crosswise into 2\"-wide pieces. Place in a medium bowl. Add 1 Tbsp. sugar, 1 tsp. Diamond Crystal or ½ tsp. Morton kosher salt, and ½ tsp. freshly ground black pepper. Toss to evenly coat eggplant and let sit at room temperature at least 20 minutes and up to 2 hours.", "2.\tPeel and thinly slice 8 garlic cloves. Add 3 Tbsp. vegetable oil and half of garlic to a medium Dutch oven or other heavy pot. Cook over medium-high heat, stirring constantly with a wooden spoon, until light golden and crisp, about 5 minutes. Using a slotted spoon, transfer garlic chips to a plate; season lightly with salt.", "3. Place 4 oz. ground pork in same pot and break up into small pieces with wooden spoon. Season with ¼ tsp. Diamond Crystal or Morton kosher salt and cook, undisturbed, until deeply browned underneath, about 5 minutes. Using a slotted spoon, transfer to another plate, leaving fat behind in the pot.", "4. Place eggplant on a clean kitchen towel and blot away any moisture the salt has drawn out.", "5. Working in batches and adding more oil if needed, cook eggplant in the same pot until lightly browned, about 3 minutes per side. Transfer to a plate with pork.", "6. Pour 1½ cups of water into the pot and scrape up browned bits from the bottom with a wooden spoon. Add remaining garlic, 3 Tbsp. coconut vinegar or unseasoned rice vinegar, 2 Tbsp. soy sauce, 2 bay leaves, 1 tsp. freshly ground black pepper, and remaining 1 Tbsp. sugar. Bring to a simmer, then return pork and eggplant to pot. Reduce heat to medium-low, partially cover, and simmer until eggplant is tender and silky and sauce is reduced by half, 20–25 minutes. Taste and season with more salt and pepper and add a little more sugar if needed.", "7. Top with garlic chips and serve with cooked white rice."]'::jsonb, 'https://salu-salo.com/eggplant-adobo/', 'https://www.themealdb.com/images/media/meals/y7h0lq1683208991.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ezme', 'Ezme', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'turkish', 'themealdb', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Romano Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Green Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 25.0, "unit": "g", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Red Pepper Paste", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Pomegranate Molasses", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Pul Biber", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "Sumac", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Dried Mint", "notes": null, "category": "produce"}, {"quantity": 60.0, "unit": "ml", "item": "Extra Virgin Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Put the tomatoes and all of the peppers in a food processor and blitz until finely chopped. Tip out into a sieve, set over a bowl and leave to strain. Add the onions, garlic and parsley to the food processor and blitz until finely chopped, then set aside.", "step 2", "Add red pepper paste, tomato purée, pomegranate molasses, pul biber, sumac, dried mint and most of the extra virgin olive oil to a serving bowl and whisk well so everything comes together as a sauce. Tip in the blitzed onion mixture and the strained pepper mixture along with 1 tsp flaky sea salt . Stir well, then drizzle with the remaining extra virgin olive oil to serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/ezme', 'https://www.themealdb.com/images/media/meals/pb6mj11763788331.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('falafel', 'Falafel', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'turkish', 'themealdb'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 400.0, "unit": "g", "item": "Chickpeas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Ground Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}]'::jsonb, '["step 1", "Heat 1 tbsp oil in a large pan, then fry the onion and garlic over a low heat for 5 mins until softened. Tip into a large mixing bowl with the chickpeas and spices, then mash together with a fork or potato masher until the chickpeas are totally broken down. Stir in the parsley or dried herbs, with seasoning to taste. Add the egg, then squish the mixture together with your hands.", "step 2", "Mould the mix into 6 balls, then flatten into patties. Heat the remaining oil in the pan, then fry the falafels on a medium heat for 3 mins on each side, until golden brown and firm. Serve hot or cold with couscous, pitta bread or salad."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/spicy-falafels', 'https://www.themealdb.com/images/media/meals/u5e9qq1763795441.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('falafel-pita-sandwich-with-tahini-sauce', 'Falafel Pita Sandwich with Tahini Sauce', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'syrian', 'themealdb', 'salad', 'baking', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Falafel", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "cup", "item": "Tahini", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Lettuce", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Cucumber", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pickles", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tsp", "item": "Harissa Spice", "notes": null, "category": "other"}]'::jsonb, '["Preheat the oven to 450 degrees F (230 degrees C). Place falafel on a baking sheet.", "Bake in the preheated oven until heated through, 8 to 10 minutes.", "While falafel bake, whisk tahini, water, lemon juice, garlic, and paprika together in a bowl.", "Cut about 1 inch from the top of each pita to form a pocket. Add 2 falafel to each pita with equal amounts lettuce, tomato, cucumber, pickle, and red onion. Drizzle each with about 1 tablespoon tahini sauce and some harissa."]'::jsonb, 'https://www.allrecipes.com/recipe/266014/falafel-pita-sandwich-with-tahini-sauce/', 'https://www.themealdb.com/images/media/meals/ae6clc1760524712.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('flamiche', 'Flamiche', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'french', 'themealdb', 'baking'], '[{"quantity": 75.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "kg", "item": "Leek", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 300.0, "unit": "ml", "item": "Creme Fraiche", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Yolks", "notes": null, "category": "other"}, {"quantity": 0.25, "unit": "teaspoon", "item": "Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 225.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 60.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 60.0, "unit": "g", "item": "Lard", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Cheddar Cheese", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tbs", "item": "Water", "notes": null, "category": "other"}]'::jsonb, '["For the pastry, sift the flour and salt into the bowl of a food processor, add the butter and lard, then whizz together briefly until the mixture looks like fine breadcrumbs. Tip the mixture into a bowl, then stir in the cheese and enough of the water for the mixture to come together. Tip out onto a lightly floured surface and knead briefly until smooth. Roll out thinly and line a 23cm x 4cm loose-?bottomed fluted flan tin. Prick the base with a fork. Chill for 20 minutes.", "02.Melt the 75g butter in a saucepan over a low heat, then add the leeks and the salt. Cover and cook for ?10 minutes until soft. Uncover the pan, increase the heat and cook ?for 2 minutes, stirring occasionally, until the liquid has evaporated. Spoon onto a plate and leave to cool.", "03.Preheat the oven to 200°C/fan180°C/gas 6. Line the pastry case with baking paper and baking beans or rice and blind bake for 15-20 minutes until the edges are biscuit-coloured. Remove the paper and beans/rice and return the case to the oven for 7-10 minutes until the base is crisp and lightly golden. Remove and set aside. Reduce the oven temperature to 190°C/fan170°C/gas 5.", "04.Put the crème fraîche into a bowl with the whole egg, egg yolks and nutmeg. Lightly beat together, then season. Stir in the leeks. Spoon ?the mixture into the tart case and bake for 35-40 minutes until set ?and lightly golden. Remove from ?the oven and leave for 10 minutes. Take out of the tin and serve."]'::jsonb, 'http://www.deliciousmagazine.co.uk/recipes/flamiche-flemish-leek-tart/', 'https://www.themealdb.com/images/media/meals/wssvvs1511785879.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ful-medames', 'Ful Medames', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'egyptian', 'themealdb', 'vegan'], '[{"quantity": 2.0, "unit": "cups", "item": "Broad Beans", "notes": null, "category": "pantry"}, {"quantity": 0.3333333333333333, "unit": "cup", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Lemons", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Sprinking Cumin", "notes": null, "category": "spices"}]'::jsonb, '["As the cooking time varies depending on the quality and age of the beans, it is good to cook them in advance and to reheat them when you are ready to serve. Cook the drained beans in a fresh portion of unsalted water in a large saucepan with the lid on until tender, adding water to keep them covered, and salt when the beans have softened. They take 2–2 1/2 hours of gentle simmering. When the beans are soft, let the liquid reduce. It is usual to take out a ladle or two of the beans and to mash them with some of the cooking liquid, then stir this back into the beans. This is to thicken the sauce.", "Serve the beans in soup bowls sprinkled with chopped parsley and accompanied by Arab bread.", "Pass round the dressing ingredients for everyone to help themselves: a bottle of extra-virgin olive oil, the quartered lemons, salt and pepper, a little saucer with the crushed garlic, one with chili-pepper flakes, and one with ground cumin.", "The beans are eaten gently crushed with the fork, so that they absorb the dressing.", "Optional Garnishes", "Peel hard-boiled eggs—1 per person—to cut up in the bowl with the beans.", "Top the beans with a chopped cucumber-and-tomato salad and thinly sliced mild onions or scallions. Otherwise, pass round a good bunch of scallions and quartered tomatoes and cucumbers cut into sticks.", "Serve with tahina cream sauce (page 65) or salad (page 67), with pickles and sliced onions soaked in vinegar for 30 minutes.", "Another way of serving ful medames is smothered in a garlicky tomato sauce (see page 464).", "In Syria and Lebanon, they eat ful medames with yogurt or feta cheese, olives, and small cucumbers.", "Variations", "A traditional way of thickening the sauce is to throw a handful of red lentils (1/4 cup) into the water at the start of the cooking.", "In Iraq, large brown beans are used instead of the small Egyptian ones, in a dish called badkila, which is also sold for breakfast in the street."]'::jsonb, 'https://www.epicurious.com/recipes/food/views/ful-medames-352993', 'https://www.themealdb.com/images/media/meals/lvn2d51598732465.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('gigantes-plaki', 'Gigantes Plaki', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'greek', 'themealdb', 'dessert', 'baking'], '[{"quantity": 400.0, "unit": "g", "item": "Butter Beans", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 800.0, "unit": "g", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tbs", "item": "Dried Oregano", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Cinnamon", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tbs", "item": "Chopped Parsley", "notes": null, "category": "produce"}]'::jsonb, '["Soak the beans overnight in plenty of water. Drain, rinse, then place in a pan covered with water. Bring to the boil, reduce the heat, then simmer for approx 50 mins until slightly tender but not soft. Drain, then set aside.", "Heat oven to 180C/160C fan/gas 4. Heat the olive oil in a large frying pan, tip in the onion and garlic, then cook over a medium heat for 10 mins until softened but not browned. Add the tomato purée, cook for a further min, add remaining ingredients, then simmer for 2-3 mins. Season generously, then stir in the beans. Tip into a large ovenproof dish, then bake for approximately 1 hr, uncovered and without stirring, until the beans are tender. The beans will absorb all the fabulous flavours and the sauce will thicken. Allow to cool, then scatter with parsley and drizzle with a little more olive oil to serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/gigantes-plaki', 'https://www.themealdb.com/images/media/meals/b79r6f1585566277.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('griddled-aubergines-with-sesame-dressing', 'Griddled aubergines with sesame dressing', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'turkish', 'themealdb', 'grilling'], '[{"quantity": 1.0, "unit": "serving", "item": "Aubergine", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 250.0, "unit": "g", "item": "Greek Yogurt", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Tahini Paste", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Mint", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Brush each aubergine slice with some oil, then season. Heat a griddle pan or barbecue. When hot, griddle the aubergine slices for 2-3 mins on each side until golden brown and tender.", "step 2", "Mix the yogurt with the tahini, garlic, lemon juice and herbs, then season. Top the aubergines with the dressing and scatter over extra herb leaves."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/griddled-aubergines-sesame-dressing', 'https://www.themealdb.com/images/media/meals/yoj48r1763817100.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('grilled-aubergines-with-spicy-chickpeas-walnut-sauce', 'Grilled aubergines with spicy chickpeas & walnut sauce', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'turkish', 'themealdb', 'grilling'], '[{"quantity": 4.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "piece Ginger", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "Ground Cumin", "notes": null, "category": "spices"}, {"quantity": 400.0, "unit": "g", "item": "Chickpeas", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1/2 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Aubergine", "notes": null, "category": "other"}, {"quantity": 200.0, "unit": "g", "item": "Greek Yogurt", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 25.0, "unit": "g", "item": "Walnuts", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander", "notes": null, "category": "spices"}]'::jsonb, '["step 1", "Heat 2 tbsp oil in a pan, add the onion and fry until soft and lightly browned, about 10 mins. Add the chilli, ginger and spices and mix well. Stir in the chickpeas, tomatoes and 5 tbsp water, bring to the boil, then simmer for 10 mins. Add a little salt and pepper and the lemon juice.", "step 2", "Arrange the aubergines over a grill pan. Brush lightly with oil, sprinkle with salt and pepper, then grill until golden. Flip them over, brush again with oil, season and grill again until tender and golden.", "step 3", "Mix the yogurt with the garlic, most of the walnuts and coriander and a little salt and pepper. Arrange the aubergine slices over a warm platter and spoon over the chickpea mix. Drizzle with the walnut sauce and scatter with the remaining walnuts and coriander."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/grilled-aubergines-spicy-chickpeas-walnut-sauce', 'https://www.themealdb.com/images/media/meals/ctw3ba1763788978.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('grilled-eggplant-with-coconut-milk', 'Grilled eggplant with coconut milk', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'filipino', 'themealdb', 'grilling'], '[{"quantity": 1.0, "unit": "serving", "item": "Plants", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "can", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbs", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Red Pepper Flakes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}]'::jsonb, '[".  Prepare the eggplants for grilling by pricking them all over with a fork.  This is so it won’t burst during the grilling process as the natural water in it heats up.", "2.  Grill the eggplants, turning them over frequently to ensure even cooking.  Grill until the skins are dark brown, even black and the eggplant is soft when you touch it.", "3.  Soak the grilled eggplant in a bowl of water to cool it down.  Peel the skin off the eggplant.  Place the whole eggplants in a shallow dish (my mom actually cuts the eggplant into small, bite-sized pieces).", "4.  In a small mixing bowl, mix together the coconut milk or cream, lemon powder, salt and hot pepper.  Mix until the lemon powder and salt dissolve.  Taste, then adjust the amount of lemon powder, salt and hot pepper to your liking.  Pour the mixture over the eggplant.  Sprinkle the green onions over the eggplant and coconut milk.  Stir gently to combine."]'::jsonb, 'https://simplybakings.com/grilled-eggplant-with-coconut-milk/', 'https://www.themealdb.com/images/media/meals/bopa2i1683209167.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('hodge-podge', 'Hodge Podge', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'canadian', 'themealdb', 'baking'], '[{"quantity": 1.0, "unit": "lb", "item": "New Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "lb", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Green Beans", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Peas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Dill", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Chives", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "cups", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Heavy Cream", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "cup", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}]'::jsonb, '["First, cook your vegetables. Bring a large pot of salted water to boil. Par-cook carrots and potatoes for five minutes until carrots and potatoes are fork tender, then blanch the peas and beans for about a minute in the same pot. Strain vegetables and set aside.", "In a heavy-bottomed pot or Dutch oven, melt butter over medium heat, add vegetables, and cook to warm through.", "Add milk and cream and bring the soup to a boil. Turn the heat down to low and season with salt and pepper.", "Add dill and chives and let simmer for at least 10 minutes. Serve warm."]'::jsonb, 'https://canadianfoodfocus.org/recipes/classic-canadian-dish-hodge-podge/', 'https://www.themealdb.com/images/media/meals/xihv0c1764447887.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamaican-instant-pot-rice-and-beans', 'Jamaican Instant Pot Rice and Beans', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'jamaican', 'themealdb', 'instant-pot'], '[{"quantity": 1.0, "unit": "tablespoon", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "finely", "notes": "chopped Garlic", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "Rice", "notes": null, "category": "grains"}, {"quantity": 0.75, "unit": "cup", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 0.75, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Allspice", "notes": null, "category": "spices"}, {"quantity": 0.25, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 450.0, "unit": "g", "item": "Kidney Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}]'::jsonb, '["Instructions", "Set Instant Pot to \"Sauté.\" Once Hot, add olive oil. Then add yellow onion and stir until softened, about 3 minutes. Add garlic and green onions and stir for about 30 more seconds.", "Press “Cancel” on the Instant Pot. Add rice, coconut milk, water, salt, allspice, and black pepper and stir.", "Pour undrained kidney beans on top of the rice mixture. Do not stir. Lay sprigs of thyme on top. Cover the Instant Pot, ensuring the valve is set to “Sealing.”", "Press “Manual” or “Pressure Cook” on the Instant Pot and set for High pressure for 6 minutes.", "Once the pressure cooking time is done, allow it to natural release for 10 minutes, then quick release any remaining pressure by moving valve to \"Venting\"", "Open lid and remove thyme sprigs. Fluff rice with fork and Enjoy!", "Stove Top Instructions", "Heat olive oil in a large pot over medium heat. Add yellow onion and stir until softened, about 3 minutes. Add garlic and green onions and stir for about 30 more seconds.", "Add rice, undrained kidney beans, coconut milk, water, salt, allspice, and black pepper and stir until combined. Lay thyme on top. Bring mixture to a simmer.", "Cover with a lid and reduce heat to low. Allow to cook for 18 minutes over low heat, then remove from heat. Leave the lid on for an additional 5 minutes.", "Open the lid and remove the thyme. Fluff rice with fork. Enjoy."]'::jsonb, 'https://www.myforkinglife.com/jamaican-instant-pot-rice-and-beans/#recipe', 'https://www.themealdb.com/images/media/meals/11bvtm1764795135.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jamaican-rice-and-peas', 'Jamaican Rice and Peas', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'jamaican', 'themealdb', 'baking'], '[{"quantity": 2.0, "unit": "cups", "item": "Rice", "notes": null, "category": "grains"}, {"quantity": 380.0, "unit": "g", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 450.0, "unit": "g", "item": "Kidney Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Water", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "Kosher Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Ground Allspice", "notes": null, "category": "spices"}, {"quantity": 0.25, "unit": "tsp", "item": "Black Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Bonnet", "notes": null, "category": "other"}]'::jsonb, '["Equipment", "Dutch oven", "Add rice, coconut milk, kidney beans, water, kosher salt, allspice, and black pepper to a large pot and stir until combined. Lay green onions, thyme and Scotch bonnet pepper on top. Bring mixture to a boil.", "Once boiling, reduce heat to low and cover with a lid. Allow to cook covered for 18 minutes over low heat, then remove from heat. Leave the lid on for an additional 5 minutes.", "Open the lid and remove the green onion, Scotch bonnet pepper, and thyme. Fluff the rice and peas with a fork. Serve and enjoy."]'::jsonb, 'https://www.myforkinglife.com/jamaican-rice-and-peas/#recipe', 'https://www.themealdb.com/images/media/meals/pkyvrn1764878267.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('kafteji', 'Kafteji', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'tunisian', 'themealdb', 'grilling'], '[{"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Ras el hanout", "notes": null, "category": "other"}, {"quantity": 500.0, "unit": "g", "item": "Pumpkin", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Peel potatoes and cut into 5cm cubes.", "Pour 1-2 cm of olive oil into a large pan and heat up very hot. Fry potatoes until golden brown for 20 minutes, turning from time to time. Place on kitchen paper to drain.", "Cut the peppers in half and remove seeds. Rub a little olive oil on them and place the cut side down on a baking tray. Place them under the grill. Grill until the skin is dark and bubbly. While the peppers are still hot, put them into a plastic sandwich bag and seal it. Take them out after 15 minutes and remove skins.", "In the meantime, heat more olive oil another pan. Peel the onions and cut into thin rings. Fry for 15 minutes until golden brown, turning them often. Add the Ras el hanout at the end.", "Cut the pumpkin into 5cm cubes and fry in the same pan you used for the potatoes for 10-15 minutes until it is soft and slightly browned. Place on kitchen paper.", "Pour the remaining olive oil out of the pan and put all the cooked vegetables into the pan and mix. Whisk eggs and pour them over the vegetables. Put the lid on the pan so that the eggs cook. Put the contents of the pan onto a large chopping board, add salt and pepper and chopped and mix everything with a big knife."]'::jsonb, 'http://allrecipes.co.uk/recipe/12294/kafteji--tunisian-fried-vegetables-.aspx', 'https://www.themealdb.com/images/media/meals/1bsv1q1560459826.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('kidney-bean-curry', 'Kidney Bean Curry', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'indian', 'themealdb', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "chopped  Onion", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tsp", "item": "Garam Masala", "notes": null, "category": "spices"}, {"quantity": 400.0, "unit": "g", "item": "Chopped Tomatoes", "notes": null, "category": "produce"}, {"quantity": 400.0, "unit": "g", "item": "Kidney Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Basmati Rice", "notes": null, "category": "grains"}]'::jsonb, '["Heat the oil in a large frying pan over a low-medium heat. Add the onion and a pinch of salt and cook slowly, stirring occasionally, until softened and just starting to colour. Add the garlic, ginger and coriander stalks and cook for a further 2 mins, until fragrant.", "Add the spices to the pan and cook for another 1 min, by which point everything should smell aromatic. Tip in the chopped tomatoes and kidney beans in their water, then bring to the boil.", "Turn down the heat and simmer for 15 mins until the curry is nice and thick. Season to taste, then serve with the basmati rice and the coriander leaves."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/kidney-bean-curry', 'https://www.themealdb.com/images/media/meals/sywrsu1511463066.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('koshari', 'Koshari', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'egyptian', 'themealdb', 'pasta', 'vegan'], '[{"quantity": 1.5, "unit": "cups", "item": "Brown Lentils", "notes": null, "category": "pantry"}, {"quantity": 1.5, "unit": "cups", "item": "Rice", "notes": null, "category": "grains"}, {"quantity": 0.5, "unit": "tsp", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "cups", "item": "Macaroni", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Chickpeas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Sprinking Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "cup", "item": "Vegetable Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Cook the lentils. Bring lentils and 4 cups of water to a boil in a medium pot or saucepan over high heat. Reduce the heat to low and cook until lentils are just tender (15-17 minutes). Drain from water and season with a little salt. (Note: when the lentils are ready, they should not be fully cooked. They should be only par-cooked and still have a bite to them as they need to finish cooking with the rice).", "Now, for the rice. Drain the rice from its soaking water. Combine the par-cooked lentils and the rice in the saucepan over medium-high heat with 1 tbsp cooking oil, salt, pepper, and coriander. Cook for 3 minutes, stirring regularly. Add warm water to cover the rice and lentil mixture by about 1 1/2 inches (you’ll probably use about 3 cups of water here). Bring to a boil; the water should reduce a bit. Now cover and cook until all the liquid has been absorbed and both the rice and lentils are well cooked through (about 20 minutes).  Keep covered and undisturbed for 5 minutes or so.", "Now make the pasta. While the rice and lentils are cooking, make the pasta according to package instructions by adding the elbow pasta to boiling water with a dash of salt and a little oil. Cook until the pasta is al dente. Drain.", "Cover the chickpeas and warm in the microwave briefly before serving.", "Make the crispy onion topping.", "Sprinkle the onion rings with salt, then toss them in the flour to coat. Shake off excess flour.", "In a large skillet, heat the cooking oil over medium-high heat, cook the onion rings, stirring often, until they turn a nice caramelized brown. Onions must be crispy, but not burned (15-20 minutes)."]'::jsonb, 'https://www.themediterraneandish.com/egyptian-koshari-recipe/', 'https://www.themealdb.com/images/media/meals/4er7mj1598733193.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('leblebi-soup', 'Leblebi Soup', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'tunisian', 'themealdb', 'soup', 'vegan'], '[{"quantity": 2.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "finely", "notes": "diced Onion", "category": "other"}, {"quantity": 250.0, "unit": "g", "item": "Chickpeas", "notes": null, "category": "produce"}, {"quantity": 1.5, "unit": "l", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 5.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Harissa Spice", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "1/2  Lime", "notes": null, "category": "produce"}]'::jsonb, '["Heat the oil in a large pot. Add the onion and cook until translucent.", "Drain the soaked chickpeas and add them to the pot together with the vegetable stock. Bring to the boil, then reduce the heat and cover. Simmer for 30 minutes.", "In the meantime toast the cumin in a small ungreased frying pan, then grind them in a mortar. Add the garlic and salt and pound to a fine paste.", "Add the paste and the harissa to the soup and simmer until the chickpeas are tender, about 30 minutes.", "Season to taste with salt, pepper and lemon juice and serve hot."]'::jsonb, 'http://allrecipes.co.uk/recipe/43419/leblebi--tunisian-chickpea-soup-.aspx', 'https://www.themealdb.com/images/media/meals/x2fw9e1560460636.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('matar-paneer', 'Matar Paneer', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'indian', 'themealdb', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 225.0, "unit": "g", "item": "Paneer", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Turmeric", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "g", "item": "Peas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Garam Masala", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Small bunch Coriander", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Naan Bread", "notes": null, "category": "grains"}]'::jsonb, '["Heat the oil in a frying pan over high heat until it’s shimmering hot. Add the paneer, then turn the heat down a little. Fry until it starts to brown at the edges, then turn it over and brown on each side – the paneer will brown faster than you think, so don’t walk away. Remove the paneer from the pan and drain on kitchen paper.", "Put the ginger, cumin, turmeric, ground coriander and chilli in the pan, and fry everything for 1 min. Add the tomatoes, mashing them with the back of a spoon and simmer everything for 5 mins until the sauce smells fragrant. Add a splash of water if it’s too thick. Season well. Add the peas and simmer for a further 2 mins, then stir in the paneer and sprinkle over the garam masala. Divide between two bowls, top with coriander leaves and serve with naan bread, roti or rice."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/matar-paneer', 'https://www.themealdb.com/images/media/meals/xxpqsy1511452222.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('molasses-baked-beans', 'Molasses Baked Beans', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'canadian', 'themealdb', 'dessert', 'breakfast', 'baking'], '[{"quantity": 2.0, "unit": "cups", "item": "Dried White Navy Beans", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "lb", "item": "Bacon", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "Molasses", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "cup", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Cider Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Ground Mustard", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Place the dried beans into a Dutch oven with 6 cups (1.5 L) of water. Soak overnight.", "Drain and pour beans back into the pot with enough water to cover the beans by a couple of inches, cook for 30 minutes until they are tender but still firm. Drain beans, making sure to reserve cooking liquid, set aside.", "Preheat the oven to 325 °F (160 °C). While the oven is preheating, cook pork over medium-high heat in the Dutch Oven until fat is rendered and pork is beginning to brown, then add the onion cooking until tender.", "Add the beans back to the pot, along with molasses, brown sugar, apple cider vinegar, ground mustard, salt and pepper and 3 cups (750 mL) of reserved bean water.", "Bake uncovered for 3 to 5 hours until the beans are tender, and the sauce has thickened, and the edges of the pot get sticky.", "(Note: if beans get dry, add another cup of water.)"]'::jsonb, 'https://canadianfoodfocus.org/recipes/classic-canadian-dishes-molasses-baked-beans/', 'https://www.themealdb.com/images/media/meals/9tddhg1764443699.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('moroccan-carrot-soup', 'Moroccan Carrot Soup', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'moroccan', 'themealdb', 'soup', 'baking', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 0.25, "unit": "tsp", "item": "Garam Masala", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Lemon Juice", "notes": null, "category": "produce"}]'::jsonb, '["Step 1", "Preheat oven to 180° C.", "Step 2", "Combine carrots, onion, garlic, cumin seeds, coriander seeds, salt and olive oil in a bowl and mix well. Transfer on a baking tray.", "Step 3", "Put the baking tray in preheated oven and roast for 10-12 minutes or till carrots soften. Remove from heat and cool.", "Step 4", "Grind the baked carrot mixture along with some water to make a smooth paste and strain in a bowl.", "Step 5", "Heat the carrot mixture in a non-stick pan. Add two cups of water and bring to a boil. Add garam masala powder and mix. Add salt and mix well.", "Step 6", "Remove from heat, add lemon juice and mix well.", "Step 7", "Serve hot."]'::jsonb, 'https://www.sanjeevkapoor.com/Recipe/Moroccan-Carrot-Soup.html', 'https://www.themealdb.com/images/media/meals/jcr46d1614763831.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mushroom-chestnut-rotolo', 'Mushroom & Chestnut Rotolo', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'british', 'themealdb', 'baking', 'vegan'], '[{"quantity": 30.0, "unit": "g", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 240.0, "unit": "g", "item": "Chestnuts", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Challots", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Rosemary", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "g", "item": "Wild Mushrooms", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 125.0, "unit": "ml", "item": "White Wine", "notes": null, "category": "other"}, {"quantity": 350.0, "unit": "g", "item": "Lasagne Sheets", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "tbsp", "item": "Breadcrumbs", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Sage", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Truffle Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Soak the dried mushrooms in 350ml boiling water and set aside until needed. Blitz ¾ of the chestnuts with 150ml water until creamy. Roughly chop the remaining chestnuts.", "Heat 2 tbsp olive oil in a large non-stick frying pan. Fry the shallots with a pinch of salt until softened, then add the garlic, chopped chestnuts and rosemary, and fry for 2 mins more. Add the wild mushrooms, 2 tbsp oil and some seasoning. Cook for 3 mins until they begin to soften. Drain and roughly chop the dried mushrooms (reserve the soaking liquid), then add those too, along with the soy sauce, and fry for 2 mins more.", "Whisk the wine, reserved mushroom liquid and chestnut cream together to create a sauce. Season, then add half to the mushroom mixture in the pan and cook for 1 min until the sauce becomes glossy. Remove and discard the rosemary sprigs, then set the mixture aside.", "Heat oven to 180C/160C fan/gas 4. Bring a large pan of salted water to the boil and get a large bowl of ice water ready. Drop the lasagne sheets into the boiling water for 2 mins or until pliable and a little cooked, then immediately plunge them into the cold water. Using your fingers, carefully separate the sheets and transfer to a clean tea towel. Spread a good spoonful of the sauce on the bottom two thirds of each sheet, then, rolling away from yourself, roll up the shorter ends. Cut each roll in half, then position the rolls of pasta cut-side up in a pie dish that you are happy to serve from at the table. If you have any mushroom sauce remaining after you’ve rolled up all the sheets, simply push it into some of the exposed rolls of pasta.", "Pour the rest of the sauce over the top of the pasta, then bake for 10 mins or until the pasta no longer has any resistance when tested with a skewer.", "Meanwhile, put the breadcrumbs, the last 2 tbsp olive oil, sage leaves and some seasoning in a bowl, and toss everything together. Scatter the rotolo with the crumbs and sage, then bake for another 10 mins, until the top is golden and the sage leaves are crispy. Leave to cool for 10 mins to allow the pasta to absorb the sauce, then drizzle with a little truffle oil, if you like, before taking your dish to the table."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/mushroom-chestnut-rotolo', 'https://www.themealdb.com/images/media/meals/ssyqwr1511451678.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('nordic-smørrebrød-with-asparagus-and-horseradish-cream', 'Nordic smørrebrød with asparagus and horseradish cream', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'norwegian', 'themealdb', 'grilling'], '[{"quantity": 150.0, "unit": "ml", "item": "Creme Fraiche", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Horseradish", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Asparagus", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Asparagus", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "slices", "item": "Rye Bread", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 100.0, "unit": "g", "item": "västerbottensost cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Sprinking Dill", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Black Pepper", "notes": null, "category": "produce"}]'::jsonb, '["To make the horseradish cream, mix the crème fraîche, grated horseradish, lemon juice, salt and white pepper in a bowl. Refrigerate until serving.", "To make the crispy shallots, heat some vegetable oil in a frying pan over a medium heat. Add the sliced shallots and fry until golden brown and crispy.", "Remove with a slotted spoon and drain on a plate lined with kitchen paper. Season with a pinch of salt.", "To make the open sandwich, bring a large saucepan of salted water to the boil, then blanch half of the asparagus (four white and four green) until tender-crisp, about 2–3 minutes.", "Add ice to a bowl of cold water. Use a slotted spoon to remove the asparagus from the boiling water and immediately transfer to the iced water to stop cooking. Thinly slice the remaining asparagus lengthwise to serve raw.", "Pre-heat the grill until hot. Spread the rye bread with butter and grill until golden and crisp.", "To serve, place the grilled bread slices on serving plates. Arrange both the blanched and raw asparagus on the bread. Drizzle with horseradish cream, then sprinkle grated cheese over the top. Garnish with the crispy shallots and some fresh dill to finish."]'::jsonb, 'https://www.bbc.co.uk/food/recipes/nordic_smorrebrod_69435', 'https://www.themealdb.com/images/media/meals/8a8fu01762772651.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('patatas-bravas', 'Patatas bravas', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'spanish', 'themealdb', 'dessert', 'baking', 'vegan'], '[{"quantity": 3.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "finely", "notes": "diced Onion", "category": "other"}, {"quantity": 2.0, "unit": "cloves", "item": "chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 225.0, "unit": "g", "item": "Tinned Tomatos", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Tomato Puree", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "teaspoon", "item": "Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Chilli Powder", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Parsley", "notes": null, "category": "produce"}, {"quantity": 900.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Heat the oil in a pan and fry the onion for about 5 mins until softened. Add the garlic, chopped tomatoes, tomato purée, sweet paprika, chilli powder, sugar and a pinch of salt, then bring to the boil, stirring occasionally. Lower to a simmer and cook for 10 mins until pulpy. Can be kept chilled for up to 24 hrs.", "step 2", "Heat oven to 200C/180C fan/gas 6. Pat the potatoes dry with kitchen paper, then tip into a roasting tin and toss in the olive oil and some seasoning. Roast for 40-50 mins until crisp and golden. Tip the potatoes into serving dishes and spoon over the tomato sauce. Sprinkle with some fresh parsley to serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/patatas-bravas-0', 'https://www.themealdb.com/images/media/meals/bvg8sn1763298713.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pisto-con-huevos', 'Pisto con huevos', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'spanish', 'themealdb'], '[{"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "peppers", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Oregano", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Sprigs of", "notes": "fresh Thyme", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Bay Leaves", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Courgettes", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Aubergine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Parsley", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Heat the oil in a large flameproof casserole dish or a cast-iron skillet over a low heat. Add the onions and a sprinkle of salt, cover and cook gently for 15 mins, stirring occasionally. Add the garlic and cook for another 2 mins.", "step 2", "Next, throw in the peppers and cook over a medium heat, covered, for about 5 mins, stirring every so often, until the peppers are just tender.", "step 3", "Mix in the oregano, thyme, bay leaves, some black pepper and a little salt, if needed. Tip in the courgettes and aubergine, combine thoroughly, and cook over a medium heat, covered, for 10 mins. Stir in the tomatoes, cover and cook for 20 mins, stirring occasionally.", "step 4", "Carefully crack the eggs over the pisto – try not to break the yolks. Cook in the sauce on a medium heat for 5-6 mins until the eggs are cooked through but still a little soft, then scatter with parsley before serving"]'::jsonb, 'https://www.bbcgoodfood.com/recipes/pisto-con-huevos', 'https://www.themealdb.com/images/media/meals/0nswfe1763279040.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pomegranate-salad', 'Pomegranate salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'polish', 'themealdb', 'salad'], '[{"quantity": 60.0, "unit": "ml", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Lemon Juice", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Honey", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Thyme", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Baby Lettuce Leaves", "notes": null, "category": "produce"}, {"quantity": 250.0, "unit": "g", "item": "Cherry Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pomegranate", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Feta", "notes": null, "category": "dairy"}]'::jsonb, '["step 1", "Combine the olive oil, lemon juice, honey and thyme leaves in a large bowl. Season well, then tip in the lettuce, tomatoes, spring onions and chilli, and toss to combine.", "step 2", "Scoop out the pomegranate seeds over a bowl and remove any white membrane. Arrange the dressed salad on a platter, then scatter over the pomegranate seeds and feta."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/pomegranate-salad', 'https://www.themealdb.com/images/media/meals/fqpqml1764359125.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('potato-salad-olivier-salad', 'Potato Salad (Olivier Salad)', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'russian', 'themealdb', 'salad'], '[{"quantity": 1.0, "unit": "serving", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbs", "item": "Salt", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tbs", "item": "White Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 7.0, "unit": "oz", "item": "Sausages", "notes": null, "category": "meat"}, {"quantity": 4.0, "unit": "oz", "item": "Dill", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "can", "item": "Peas", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Mayonnaise", "notes": null, "category": "pantry"}]'::jsonb, '["Cut the potatoes and carrots into small uniform cubes.", "Place them in a large pot and fill with water.", "Add salt and vinegar. Bring it to a boil over medium high heat, and then reduce the heat to medium and continue to cook until the potatoes are cooked through, about 15 minutes. Drain the potatoes and let it cool to room temperature.", "Meanwhile, cut the sausage and pickles into small cubes, and chop the green onions.", "Cut the hard-boiled eggs into small cubes as well.", "If using fresh dill, chop them as well.", "In a large bowl, combine potatoes, carrots, sausage, pickles, peas and green onions.", "Add mayo and dill and mix until well combined.", "Salt and pepper to taste. Cover with a plastic wrap and refrigerate for at least 1 hour before serving."]'::jsonb, 'https://www.sweetandsavorybyshinee.com/russian-potato-salad/', 'https://www.themealdb.com/images/media/meals/ebvuir1699013665.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('provençal-omelette-cake', 'Provençal Omelette Cake', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'french', 'themealdb', 'dessert', 'breakfast'], '[{"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Courgettes", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic Clove", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 300.0, "unit": "g", "item": "Cream Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 4.0, "unit": "tbs", "item": "Chives", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Basil", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Rocket", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "to serve Parmesan", "notes": null, "category": "dairy"}]'::jsonb, '["Break the eggs into two bowls, five in each. Whisk lightly and season with salt and pepper. Heat the oil in a pan, add the courgettes and spring onions, then fry gently for about 10 mins until softened. Cool, then stir into one bowl of eggs with a little salt and pepper. Add the roasted peppers to the other bowl of eggs with the garlic, chilli, salt and pepper.", "Heat a little oil in a 20-23cm frying pan, preferably non-stick. Pour the eggs with courgette into a measuring jug, then pourabout one-third of the mixture into the pan, swirling it to cover the base of the pan. Cook until the egg is set and lightly browned underneath, then cover the pan with a plate and invert the omelette onto it. Slide it back into the pan to cook the other side. Repeat with the remaining mix to make two more omelettes, adding a little oil to the pan each time. Stack the omelettes onto a plate. Make three omelettes in the same way with the red pepper mixture, then stack them on a separate plate.", "Now make the filling. Beat the cheese to soften it, then beat in the milk to make a spreadable consistency. Stir in the herbs, salt and pepper. Line a deep, 20-23cm round cake tin with cling film (use a tin the same size as the frying pan). Select the best red pepper omelette and place in the tin, prettiest side down. Spread with a thin layer of cheese filling, then cover with a courgette omelette. Repeat, alternating the layers, until all the omelettes and filling are in the tin, finishing with an omelette. Flip the cling film over the omelette, then chill for up to 24 hrs.", "To serve, invert the omelette cake onto a serving plate and peel off the cling film. Pile rocket on the top and scatter over the cheese, a drizzle of olive oil and a little freshly ground black pepper. Serve cut into wedges."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/6428/provenal-omelette-cake', 'https://www.themealdb.com/images/media/meals/qwtrtp1511799242.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ratatouille', 'Ratatouille', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'french', 'themealdb', 'dessert', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Aubergine", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Courgettes", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomato", "notes": null, "category": "produce"}, {"quantity": 5.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Basil", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Red Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Sugar", "notes": null, "category": "pantry"}]'::jsonb, '["Cut the aubergines in half lengthways. Place them on the board, cut side down, slice in half lengthways again and then across into 1.5cm chunks. Cut off the courgettes ends, then across into 1.5cm slices. Peel the peppers from stalk to bottom. Hold upright, cut around the stalk, then cut into 3 pieces. Cut away any membrane, then chop into bite-size chunks.", "Score a small cross on the base of each tomato, then put them into a heatproof bowl. Pour boiling water over the tomatoes, leave for 20 secs, then remove. Pour the water away, replace the tomatoes and cover with cold water. Leave to cool, then peel the skin away. Quarter the tomatoes, scrape away the seeds with a spoon, then roughly chop the flesh.", "Set a sauté pan over medium heat and when hot, pour in 2 tbsp olive oil. Brown the aubergines for 5 mins on each side until the pieces are soft. Set them aside and fry the courgettes in another tbsp oil for 5 mins, until golden on both sides. Repeat with the peppers. Don’t overcook the vegetables at this stage, as they have some more cooking left in the next step.", "Tear up the basil leaves and set aside. Cook the onion in the pan for 5 mins. Add the garlic and fry for a further min. Stir in the vinegar and sugar, then tip in the tomatoes and half the basil. Return the vegetables to the pan with some salt and pepper and cook for 5 mins. Serve with basil."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/2903/ratatouille', 'https://www.themealdb.com/images/media/meals/wrpwuu1511786491.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ribollita', 'Ribollita', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'italian', 'themealdb', 'baking', 'vegan'], '[{"quantity": 5.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "stalk", "item": "chopped Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "Cannellini Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "tomatoes", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "sprig Rosemary", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "sprig Thyme", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "pound", "item": "chopped Kale", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "slices Wholegrain Bread", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "sliced Red Onions", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "freshly", "notes": "grated Parmesan", "category": "other"}]'::jsonb, '["Put 2 tablespoons of the oil in a large pot over medium heat. When it’s hot, add onion, carrot, celery and garlic; sprinkle with salt and pepper and cook, stirring occasionally, until vegetables are soft, 5 to 10 minutes.", "Heat the oven to 500 degrees. Drain the beans; if they’re canned, rinse them as well. Add them to the pot along with tomatoes and their juices and stock, rosemary and thyme. Bring to a boil, then reduce heat so the soup bubbles steadily; cover and cook, stirring once or twice to break up the tomatoes, until the flavors meld, 15 to 20 minutes.", "Fish out and discard rosemary and thyme stems, if you like, and stir in kale. Taste and adjust seasoning. Lay bread slices on top of the stew so they cover the top and overlap as little as possible. Scatter red onion slices over the top, drizzle with the remaining 3 tablespoons oil and sprinkle with Parmesan.", "Put the pot in the oven and bake until the bread, onions and cheese are browned and crisp, 10 to 15 minutes. (If your pot fits under the broiler, you can also brown the top there.) Divide the soup and bread among 4 bowls and serve."]'::jsonb, 'https://cooking.nytimes.com/recipes/1016052-ribollita', 'https://www.themealdb.com/images/media/meals/xrrwpx1487347049.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('roast-aubergine-with-goats-cheese-toasted-flatbread', 'Roast aubergine with goat''s cheese & toasted flatbread', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'turkish', 'themealdb', 'baking'], '[{"quantity": 1.0, "unit": "serving", "item": "Aubergine", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Extra Virgin Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Bread", "notes": null, "category": "grains"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Balsamic Vinegar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Mint", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}, {"quantity": 50.0, "unit": "g", "item": "Goats Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Rocket", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Heat oven to 200C/180C fan/gas 6. Brush the aubergine slices with 1 tbsp of the oil, then season. Arrange on a baking tray or sheet and roast for 20 mins until browned, popping the tomatoes on the tray for the final 5 mins. Tear the flatbread into pieces and place on a separate baking sheet. Brown in the oven for 8 mins, or until crisp, then remove.", "step 2", "For the dressing, in a small bowl, mix the vinegar, mint, chopped shallots, chilli, remaining oil and some salt and pepper.", "step 3", "Scatter the aubergine slices, tomatoes, sliced shallot and crisp flatbread into a serving bowl. Pour over the dressing, sprinkle with the goat’s cheese and scatter over a little rocket."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/roast-aubergine-goats-cheese-toasted-flatbread', 'https://www.themealdb.com/images/media/meals/iydbwy1763816111.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('roasted-eggplant-with-tahini-pine-nuts-and-lentils', 'Roasted Eggplant With Tahini, Pine Nuts, and Lentils', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'american', 'themealdb', 'baking'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "cut into chunks Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "stalks Celery", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "finely", "notes": "diced Onion", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "cloves", "notes": "sliced Garlic", "category": "spices"}, {"quantity": 12.0, "unit": "ounces", "item": "Brown Lentils", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Leaves", "notes": null, "category": "other"}, {"quantity": 4.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "teaspoons", "item": "Apple Cider Vinegar", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Egg Plants", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Rosemary", "notes": null, "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "Pine nuts", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Parsley", "notes": null, "category": "produce"}]'::jsonb, '["For the Lentils: Adjust oven rack to center position and preheat oven to 450°F to prepare for roasting eggplant. Meanwhile, heat 2 tablespoons olive oil in a medium saucepan over medium heat until shimmering. Add carrots, celery, and onion and cook, stirring, until softened but not browned, about 4 minutes. Add garlic and cook, stirring, until fragrant, about 30 seconds. Add lentils, bay leaves, stock or water, and a pinch of salt. Bring to a simmer, cover with the lid partially ajar, and cook until lentils are tender, about 30 minutes. (Top up with water if lentils are at any point not fully submerged.) Remove lid, stir in vinegar, and reduce until lentils are moist but not soupy. Season to taste with salt and pepper, cover, and keep warm until ready to serve.", "2.", "For the Eggplant: While lentils cook, cut each eggplant in half. Score flesh with the tip of a paring knife in a cross-hatch pattern at 1-inch intervals. Transfer to a foil-lined rimmed baking sheet, cut side up, and brush each eggplant half with 1 tablespoon oil, letting each brushstroke be fully absorbed before brushing with more. Season with salt and pepper. Place a rosemary sprig on top of each one. Transfer to oven and roast until completely tender and well charred, 25 to 35 minutes. Remove from oven and discard rosemary.", "3.", "To Serve: Heat 2 tablespoons olive oil and pine nuts in a medium skillet set over medium heat. Cook, tossing nuts frequently, until golden brown and aromatic, about 4 minutes. Transfer to a bowl to halt cooking. Stir half of parsley and rosemary into lentils and transfer to a serving platter. Arrange eggplant halves on top. Spread a few tablespoons of tahini sauce over each eggplant half and sprinkle with pine nuts. Sprinkle with remaining parsley and rosemary, drizzle with additional olive oil, and serve."]'::jsonb, 'http://www.seriouseats.com/recipes/2016/03/roasted-eggplant-tahini-pine-nut-lentil-vegan-experience-recipe.html', 'https://www.themealdb.com/images/media/meals/ysqrus1487425681.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sauerkraut-pierogi', 'Sauerkraut pierogi', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'polish', 'themealdb', 'dessert', 'baking'], '[{"quantity": 1.0, "unit": "tablespoon", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "g", "item": "Sauerkraut", "notes": null, "category": "other"}, {"quantity": 150.0, "unit": "g", "item": "Hispi sweetheart Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "tbs", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 350.0, "unit": "g", "item": "Plain Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "For frying Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Dusting Plain Flour", "notes": null, "category": "grains"}, {"quantity": 45.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 60.0, "unit": "ml", "item": "Sour Cream", "notes": null, "category": "dairy"}]'::jsonb, '["step 1", "First, make the crispy shallots. Heat the oil in a saucepan to 180C (a cube of bread will turn golden in 15 secs). Toss the shallots in a little flour and deep-fry for 1 min or until light golden and crispy. Drain on kitchen paper. Can be made up to two days before and kept in an airtight container.", "step 2", "To make the filling, heat the oil in a medium non-stick frying pan and gently fry the shallots for 10 mins until starting to turn golden.", "step 3", "Add the sauerkraut and cabbage, and cook for 5-10 mins until the cabbage has softened. Taste and add a little salt if under-seasoned, or sugar if stringent. Scrape into a bowl and leave to cool completely.", "step 4", "To make the dough, mix the eggs and oil with 125ml water, then gradually add in the flour, mixing well with your hands. Knead it on a well-floured surface until the dough stops sticking to your hands. You should end up with firm, elastic dough. Wrap it in cling film and rest in the fridge for at least 30 mins, or overnight.", "step 5", "Flour your work surface generously. Roll out the dough to a 40cm circle or until the dough is as thick as £1 coin.", "step 6", "Using a 9cm cookie cutter, cut out discs in the dough – you should end up with about 25 discs. Do not throw away the off-cuts – we throw them in with the pierogi when boiling to minimise any waste.", "step 7", "Have a well-floured tray ready. Put 1 tsp of the filling into the centre of each disc. In your hand, fold in half around the filling and seal to create half-moon shapes. Put them on the floured tray, making sure they don’t touch each other.", "step 8", "Bring a large saucepan of salted water to the boil and carefully lower the pierogi in. Boil them for 2 mins or until they float to the top.", "step 9", "Drain and serve with a knob of butter and some soured cream. Finish by sprinkling the crispy shallots on top to serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/pierogi', 'https://www.themealdb.com/images/media/meals/ckbx1h1764123606.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
