INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('silken-tofu-with-sesame-soy-sauce', 'Silken Tofu with Sesame Soy Sauce', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'chinese', 'themealdb', 'vegan'], '[{"quantity": 16.0, "unit": "ounces", "item": "Silken Tofu", "notes": null, "category": "other"}, {"quantity": 3.0, "unit": "tablespoons", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Chinese Sesame Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Scallions", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Sesame Seed", "notes": null, "category": "pantry"}]'::jsonb, '["Prepare the tofu:", "Drain the tofu and gently remove it from its packaging onto a large plate. Carefully slice the tofu into 1/2-inch slabs widthwise. With the palm of your hands, gently push the sliced tofu sidewise so that they fan out over the plate.", "Garnish with toppings and serve:", "Drizzle the soy sauce and sesame sauce on top. Then garnish it with scallions and sesame seeds, and serve.", "Tightly cover leftovers and refrigerate for up to 2 days. You can enjoy it cold straight out of the fridge or you can reheat it by microwaving in 30-second increments until warmed through"]'::jsonb, 'https://www.simplyrecipes.com/silken-tofu-with-sesame-soy-sauce-recipe-6979877', 'https://www.themealdb.com/images/media/meals/j9nray1765657692.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('smoky-lentil-chili-with-squash', 'Smoky Lentil Chili with Squash', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'british', 'themealdb', 'dessert', 'soup', 'vegan'], '[{"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leek", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tsp", "item": "ground  Cumin", "notes": null, "category": "spices"}, {"quantity": 2.0, "unit": "tsp", "item": "ground Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Smoked Paprika", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Cinnamon", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Chili Powder", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Cocoa", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Dried Oregano", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "can", "item": "Diced Tomatoes", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "cups", "item": "Water", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.5, "unit": "cups", "item": "Brown Lentils", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Sea Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Squash", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "Cashews", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Apple Cider Vinegar", "notes": null, "category": "produce"}]'::jsonb, '["Begin by roasting the squash. Slice it into thin crescents and drizzle with a little oil and sprinkle with sea salt. I added a fresh little sage I had in the fridge, but it’s unnecessary. Roast the squash a 205 C (400 F) for 20-30 minutes, flipping halfway through, until soft and golden. Let cool and chop into cubes.", "Meanwhile, rinse the lentils and cover them with water. Bring them to the boil then turn down to a simmer and let cook (uncovered) for 20-30 minutes, or until tender. Drain and set aside.", "While the lentils are cooking heat the 1 Tbsp. of oil on low in a medium pot. Add the onions and leeks and sauté for 5 or so minutes, or until they begin to soften. Add the garlic next along with the cumin and coriander, cooking for a few more minutes. Add the remaining spices – paprika, cinnamon, chilli, cocoa, Worcestershire sauce, salt, and oregano. Next add the can of tomatoes, the water or stock, and carrots. Let simmer, covered, for 20 minutes or until the veg is tender and the mixture has thickened up. You’ll need to check on the pot periodically for a stir and a top of of liquid if needed.", "Add the lentils and chopped roasted squash. Let cook for 10 more minutes to heat through.", "Serve with sliced jalapeno, lime wedges, cilantro, green onions, and cashew sour cream.", "SIMPLE CASHEW SOUR CREAM", "1 Cup Raw Unsalted Cashews", "Pinch Sea Salt", "1 tsp. Apple Cider Vinegar", "Water", "Bring some water to the boil, and use it to soak the cashews for at least four hours. Alternatively, you can use cold water and let the cashews soak overnight, but I’m forgetful/lazy, so often use the boil method which is much faster.", "After the cashews have soaked, drain them and add to a high speed blender. Begin to puree, slowly adding about 1/2 cup fresh water, until a creamy consistency is reached. You may need to add less or more water to reach the desired consistency.", "Add a pinch of sea salt and vinegar (or lemon juice)."]'::jsonb, 'http://www.wholeheartedeats.com/2016/11/smoky-lentil-chili-squash/', 'https://www.themealdb.com/images/media/meals/uwxqwy1483389553.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spanish-tortilla', 'Spanish Tortilla', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'spanish', 'themealdb'], '[{"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tbsp", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 25.0, "unit": "g", "item": "Butter", "notes": null, "category": "dairy"}, {"quantity": 400.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 6.0, "unit": "cloves", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Eggs", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Parsley", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Baguette", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "drizzle Olive Oil", "notes": null, "category": "pantry"}]'::jsonb, '["Put a large non-stick frying pan on a low heat. Cook the onion slowly in the oil and butter until soft but not brown – this should take about 15 mins. Add the potatoes, cover the pan and cook for a further 15-20 mins, stirring occasionally to make sure they fry evenly.", "When the potatoes are soft and the onion is shiny, crush 2 garlic cloves and stir in, followed by the beaten eggs.", "Put the lid back on the pan and leave the tortilla to cook gently. After 20 mins, the edges and base should be golden, the top set but the middle still a little wobbly. To turn it over, slide it onto a plate and put another plate on top, turn the whole thing over and slide it back into the pan to finish cooking. Once cooked, transfer to a plate and serve the tortilla warm or cold, scattered with the chopped parsley.", "To accompany, take slices of warmed baguette, stab all over with a fork and rub with the remaining garlic, pile on grated tomatoes and season with sea salt and a drizzle of olive oil."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/spanish-tortilla', 'https://www.themealdb.com/images/media/meals/quuxsx1511476154.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spiced-tortilla', 'Spiced tortilla', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'spanish', 'themealdb', 'grilling'], '[{"quantity": 1.0, "unit": "tbsp", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chilli", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "teaspoon", "item": "Curry Powder", "notes": null, "category": "spices"}, {"quantity": 300.0, "unit": "g", "item": "Cherry Tomatoes", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "g", "item": "Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "Egg", "notes": null, "category": "dairy"}]'::jsonb, '["step 1", "Heat the oil in a large frying pan. Fry the onion and half the chilli for 5 mins until softened. Tip in the spices, fry for 1 min more, then add the cherry tomatoes, potatoes and coriander stalks to the pan. Season the eggs well, pour over the top of the veg and leave to cook gently for 8-10 mins until almost set.", "step 2", "Heat the grill and flash the tortilla underneath for 1-2 mins until the top is set. Scatter the coriander leaves and remaining chilli over the top, slice into wedges and serve with a green salad."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/spiced-tortilla', 'https://www.themealdb.com/images/media/meals/7b862e1763194846.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spicy-arrabiata-penne', 'Spicy Arrabiata Penne', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'italian', 'themealdb', 'pasta'], '[{"quantity": 1.0, "unit": "pound", "item": "penne rigate", "notes": null, "category": "grains"}, {"quantity": 0.25, "unit": "cup", "item": "olive oil", "notes": null, "category": "pantry"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "chopped tomatoes", "notes": null, "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "red chilli flakes", "notes": null, "category": "other"}, {"quantity": 0.5, "unit": "teaspoon", "item": "italian seasoning", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "basil", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "sprinkling Parmigiano-Reggiano", "notes": null, "category": "dairy"}]'::jsonb, '["Bring a large pot of water to a boil. Add kosher salt to the boiling water, then add the pasta. Cook according to the package instructions, about 9 minutes.", "In a large skillet over medium-high heat, add the olive oil and heat until the oil starts to shimmer. Add the garlic and cook, stirring, until fragrant, 1 to 2 minutes. Add the chopped tomatoes, red chile flakes, Italian seasoning and salt and pepper to taste. Bring to a boil and cook for 5 minutes. Remove from the heat and add the chopped basil.", "Drain the pasta and add it to the sauce. Garnish with Parmigiano-Reggiano flakes and more basil and serve warm."]'::jsonb, NULL, 'https://www.themealdb.com/images/media/meals/ustsqw1468250014.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spicy-north-african-potato-salad', 'Spicy North African Potato Salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'moroccan', 'themealdb', 'salad', 'vegan'], '[{"quantity": 650.0, "unit": "g", "item": "650g/1lb 8 oz Small Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Harissa Spice", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tsp", "item": "olive oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "juice of half Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "onions", "notes": null, "category": "produce"}, {"quantity": 150.0, "unit": "g", "item": "150g/6oz Rocket", "notes": null, "category": "other"}, {"quantity": 80.0, "unit": "g", "item": "80g/3oz Feta", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Mint", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Pine nuts", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Pepper", "notes": null, "category": "produce"}]'::jsonb, '["Cook potatoes - place potatoes in a pot of cold water, and bring to the boil. Boil 20 minutes, or until potatoes are tender. You know they are cooked when you can stick a knife in them and the knife goes straight through.", "Combine harissa spice, olive oil, salt and pepper and lemon juice in a small bowl and whisk until combined.", "Once potatoes are cooked, drain water and roughly chop potatoes in half.", "Add harissa mix and spring onions/green onions to potatoes and stir.", "In a large salad bowl, lay out arugula/rocket.", "Top with potato mix and toss.", "Add fetta, mint and sprinkle over pine nuts.", "Adjust salt and pepper to taste."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/urtwux1486983078.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spinach-ricotta-cannelloni', 'Spinach & Ricotta Cannelloni', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'italian', 'themealdb', 'dessert', 'baking'], '[{"quantity": 3.0, "unit": "tbsp", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 8.0, "unit": "cloves", "item": "chopped Garlic", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbsp", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Red Wine Vinegar", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Cans", "notes": "Chopped Tomatoes", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Basil Leaves", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Mascarpone", "notes": null, "category": "dairy"}, {"quantity": 3.0, "unit": "tbsp", "item": "Milk", "notes": null, "category": "dairy"}, {"quantity": 85.0, "unit": "g", "item": "Parmesan", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Mozzarella", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "kg", "item": "Spinach", "notes": null, "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "Parmesan", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Ricotta", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "pinch Nutmeg", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Cannellini Beans", "notes": null, "category": "pantry"}]'::jsonb, '["First make the tomato sauce. Heat the oil in a large pan and fry the garlic for 1 min. Add the sugar, vinegar, tomatoes and some seasoning and simmer for 20 mins, stirring occasionally, until thick. Add the basil and divide the sauce between 2 or more shallow ovenproof dishes (see Tips for freezing, below). Set aside. Make a sauce by beating the mascarpone with the milk until smooth, season, then set aside.", "Put the spinach in a large colander and pour over a kettle of boiling water to wilt it (you may need to do this in batches). When cool enough to handle squeeze out the excess water. Roughly chop the spinach and mix in a large bowl with 100g Parmesan and ricotta. Season well with salt, pepper and the nutmeg.", "Heat oven to 200C/180C fan/gas 6. Using a piping bag or plastic food bag with the corner snipped off, squeeze the filling into the cannelloni tubes. Lay the tubes, side by side, on top of the tomato sauce and spoon over the mascarpone sauce. Top with Parmesan and mozzarella. You can now freeze the cannelloni, uncooked, or you can cook it first and then freeze. Bake for 30-35 mins until golden and bubbling. Remove from oven and let stand for 5 mins before serving."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/531632/spinach-and-ricotta-cannelloni', 'https://www.themealdb.com/images/media/meals/wspuvp1511303478.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('squash-linguine', 'Squash linguine', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'italian', 'themealdb', 'pasta', 'baking'], '[{"quantity": 350.0, "unit": "g", "item": "Butternut Squash", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbs", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 350.0, "unit": "g", "item": "Linguine Pasta", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Small bunch Sage", "notes": null, "category": "grains"}]'::jsonb, '["Heat oven to 200C/180C fan/gas 6. Put the squash and garlic on a baking tray and drizzle with the olive oil. Roast for 35-40 mins until soft. Season.", "Cook the pasta according to pack instructions. Drain, reserving the water. Use a stick blender to whizz the squash with 400ml cooking water. Heat some oil in a frying pan, fry the sage until crisp, then drain on kitchen paper. Tip the pasta and sauce into the pan and warm through. Scatter with sage."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/creamy-squash-linguine', 'https://www.themealdb.com/images/media/meals/wxswxy1511452625.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('stovetop-eggplant-with-harissa-chickpeas-and-cumin-yogurt', 'Stovetop Eggplant With Harissa, Chickpeas, and Cumin Yogurt', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'american', 'themealdb'], '[{"quantity": 4.0, "unit": "tablespoons", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Egg Plants", "notes": null, "category": "dairy"}, {"quantity": 0.5, "unit": "tablespoon", "item": "Harissa Spice", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "can", "item": "Chickpeas", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "halved Cherry Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.5, "unit": "cups", "item": "Greek yogurt", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Ground cumin", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "cup", "item": "Parsley", "notes": null, "category": "produce"}]'::jsonb, '["Heat the oil in a 12-inch skillet over high heat until shimmering. Add the eggplants and lower the heat to medium. Season with salt and pepper as you rotate the eggplants, browning them on all sides. Continue to cook, turning regularly, until a fork inserted into the eggplant meets no resistance (you may have to stand them up on their fat end to finish cooking the thickest parts), about 20 minutes, lowering the heat and sprinkling water into the pan as necessary if the eggplants threaten to burn or smoke excessively.", "2.", "Mix the harissa, chickpeas and tomatoes together, then add to the eggplants. Cook until the tomatoes have blistered and broken down, about 5 minutes more. Season with salt and pepper and add water as necessary to thin to a saucy consistency. Meanwhile, combine the yogurt and cumin in a serving bowl. Season with salt and pepper.", "3.", "Top the eggplant mixture with the parsley, drizzle with more extra virgin olive oil, and serve with the yogurt on the side."]'::jsonb, 'http://www.seriouseats.com/2014/09/one-pot-wonders-stovetop-eggplant-harissa-chickpeas-cumin.html', 'https://www.themealdb.com/images/media/meals/yqwtvu1487426027.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('stuffed-bell-peppers-with-quinoa-and-black-beans', 'Stuffed Bell Peppers with Quinoa and Black Beans', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'mexican', 'themealdb', 'baking'], '[{"quantity": 4.0, "unit": "whole", "item": "Green Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "finely", "notes": "diced Onion", "category": "other"}, {"quantity": 2.0, "unit": "cloves", "item": "minced Garlic", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "cups", "item": "Quinoa", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "can", "item": "Black Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Sweetcorn", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "can", "item": "Diced Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Chili Powder", "notes": null, "category": "spices"}, {"quantity": 0.5, "unit": "tsp", "item": "Smoked Paprika", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Pepper", "notes": null, "category": "produce"}, {"quantity": 1.5, "unit": "cup", "item": "Shredded Mexican Cheese", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Chopped Cilantro", "notes": null, "category": "produce"}]'::jsonb, '["1. Preheat your oven to 375°F (190°C). Lightly grease a 9x13-inch baking dish or a similar-sized casserole dish.", "2. Place the bell pepper halves in the prepared baking dish, cut side up. Bake for 15-20 minutes, or until slightly softened.", "3. While the bell peppers are baking, prepare the filling. In a large skillet, heat the olive oil over medium heat. Add the chopped onion, and cook for 3-4 minutes, until softened. Add the garlic, and cook for another 1 minute, until fragrant.", "4. Stir in the cooked quinoa, black beans, corn, diced tomatoes, ground cumin, chili powder, smoked paprika, salt, and pepper. Cook for 5-7 minutes, until heated through. Remove the skillet from heat, and stir in 1 cup of the shredded cheese, if using.", "5. Remove the bell peppers from the oven, and carefully stuff each pepper half with the quinoa and black bean mixture. Top the stuffed peppers with the remaining 1/2 cup of shredded cheese, if using.", "6. Return the stuffed peppers to the oven, and bake for another 15-20 minutes, until the cheese is melted and the peppers are tender.", "7. Remove from the oven, and allow the stuffed peppers to cool for 5 minutes before serving. Garnish with fresh chopped cilantro."]'::jsonb, '', 'https://www.themealdb.com/images/media/meals/b66myb1683207208.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sukuma-wiki', 'Sukuma Wiki', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'kenyan', 'themealdb'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "lb", "item": "Kale", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Dash Salt", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "cup", "item": "Double Cream", "notes": null, "category": "dairy"}]'::jsonb, '["Heat the 2 tablespoons of oil in a large skillet or pot over medium heat until shimmering. Add the onions and cook, stirring occasionally, until softened, 5 to 7 minutes.", "Add the shredded kale to the onions and mix well. Turn the heat to medium-low, cover and cook for 5 minutes.", "After 5 minutes, remove the lid, add salt to taste, and stir in the cream. Continue cooking for another 5 minutes, uncovered, stirring occasionally. The cream will thicken slightly, making for a deliciously rich creamed kale and onions. Yumm!", "Serve it up with your favorite Kenyan stew, and a side of ugali!"]'::jsonb, 'https://tasteoftheplace.com/sukuma-wiki/', 'https://www.themealdb.com/images/media/meals/60o82j1762341177.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('summer-pistou', 'Summer Pistou', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'french', 'themealdb', 'soup', 'vegan'], '[{"quantity": 1.0, "unit": "tbs", "item": "Rapeseed Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "chopped Leek", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Courgettes", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "l", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "g", "item": "Cannellini Beans", "notes": null, "category": "pantry"}, {"quantity": 200.0, "unit": "g", "item": "Green Beans", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Garlic Clove", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Small pack Basil", "notes": null, "category": "produce"}, {"quantity": 40.0, "unit": "g", "item": "Parmesan", "notes": null, "category": "dairy"}]'::jsonb, '["Heat the oil in a large pan and fry the leeks and courgette for 5 mins to soften. Pour in the stock, add three-quarters of the haricot beans with the green beans, half the tomatoes, and simmer for 5-8 mins until the vegetables are tender.", "Meanwhile, blitz the remaining beans and tomatoes, the garlic and basil in a food processor (or in a bowl with a stick blender) until smooth, then stir in the Parmesan. Stir the sauce into the soup, cook for 1 min, then ladle half into bowls or pour into a flask for a packed lunch. Chill the remainder. Will keep for a couple of days."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/summer-pistou', 'https://www.themealdb.com/images/media/meals/rqtxvr1511792990.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sweet-potato-salad', 'Sweet potato salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'turkish', 'themealdb', 'dessert', 'salad', 'baking'], '[{"quantity": 1200.0, "unit": "g", "item": "Sweet Potatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Shallots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Chives", "notes": null, "category": "other"}, {"quantity": 5.0, "unit": "tablespoons", "item": "Sherry vinegar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Extra Virgin Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Honey", "notes": null, "category": "pantry"}]'::jsonb, '["step 1", "Heat oven to 200C/180C fan/gas 6. Toss the sweet potato chunks with the olive oil and some seasoning, and spread on a baking parchment-lined baking sheet. Roast for 30 - 35 mins until tender and golden. Cool at room temperature.", "step 2", "When just about cool whisk together all the dressing ingredients with a little more seasoning and gently toss through the potato chunks – use your hands to avoid breaking them up."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/sweet-potato-salad', 'https://www.themealdb.com/images/media/meals/z458v91763817681.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tahini-lentils', 'Tahini Lentils', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'moroccan', 'themealdb', 'vegan'], '[{"quantity": 50.0, "unit": "g", "item": "Tahini", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "zest and juice of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Olive Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "peeled", "notes": "crushed Garlic", "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "sliced Yellow Pepper", "notes": null, "category": "produce"}, {"quantity": 200.0, "unit": "g", "item": "Green Beans", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Courgettes", "notes": null, "category": "other"}, {"quantity": 100.0, "unit": "g", "item": "shredded Kale", "notes": null, "category": "produce"}, {"quantity": 250.0, "unit": "g", "item": "pack Lentils", "notes": null, "category": "pantry"}]'::jsonb, '["In a jug, mix the tahini with the zest and juice of the lemon and 50ml of cold water to make a runny dressing. Season to taste, then set aside.", "Heat the oil in a wok or large frying pan over a medium-high heat. Add the red onion, along with a pinch of salt, and fry for 2 mins until starting to soften and colour. Add the garlic, pepper, green beans and courgette and fry for 5 min, stirring frequently.", "Tip in the kale, lentils and the tahini dressing. Keep the pan on the heat for a couple of mins, stirring everything together until the kale is wilted and it’s all coated in the creamy dressing."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/veggie-tahini-lentils', 'https://www.themealdb.com/images/media/meals/vpxyqt1511464175.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tamiya', 'Tamiya', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'egyptian', 'themealdb', 'baking', 'vegan'], '[{"quantity": 3.0, "unit": "cups", "item": "Broad Beans", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Clove", "notes": null, "category": "spices"}, {"quantity": 0.25, "unit": "cup", "item": "Parsley", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "Cumin", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Baking Powder", "notes": null, "category": "pantry"}, {"quantity": 0.5, "unit": "tsp", "item": "Cayenne Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Spinkling Flour", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "As required Vegetable Oil", "notes": null, "category": "pantry"}]'::jsonb, '["oak the beans in water to cover overnight.Drain. If skinless beans are unavailable, rub to loosen the skins, then discard the skins. Pat the beans dry with a towel.", "Grind the beans in a food mill or meat grinder.If neither appliance is available, process them in a food processor but only until the beans form a paste. (If blended too smoothly, the batter tends to fall apart during cooking.) Add the scallions, garlic, cilantro, cumin, baking powder, cayenne, salt, pepper, and coriander, if using.  Refrigerate for at least 30 minutes.", "Shape the bean mixture into 1-inch balls.Flatten slightly and coat with flour.", "Heat at least 1½-inches of oil over medium heat to 365 degrees.", "Fry the patties in batches, turning once, until golden brown on all sides, about 5 minutes.Remove with a wire mesh skimmer or slotted spoon. Serve as part of a meze or in pita bread with tomato-cucumber salad and tahina sauce."]'::jsonb, 'https://oukosher.org/recipes/tamiya-egyptian-dried-fava-bean-fritters/', 'https://www.themealdb.com/images/media/meals/n3xxd91598732796.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tangy-cabbage-slaw', 'Tangy cabbage slaw', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'ukrainian', 'themealdb', 'salad', 'vegan'], '[{"quantity": 250.0, "unit": "ml", "item": "Mayonnaise", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Zest and juice of 1 Lemon", "notes": null, "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Cider Vinegar", "notes": null, "category": "pantry"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Wholegrain Mustard", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Celery Salt", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Celery", "notes": null, "category": "produce"}]'::jsonb, '["step 1", "Whisk together mayonnaise, lemon zest and juice, vinegar, mustard and celery salt in a small bowl, then season generously.", "step 2", "Add cabbage, carrots, onion and celery. Mix well and refrigerate. Can be made up to 1 day ahead."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/tangy-cabbage-slaw', 'https://www.themealdb.com/images/media/meals/e2g2r21764367568.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
