d-cabbage-onion-salad', 'https://www.themealdb.com/images/media/meals/dbazbg1763779999.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-coconut-veg-broth', 'Thai coconut & veg broth', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'thai', 'themealdb', 'dessert', 'soup', 'pasta'], '[{"quantity": 0.5, "unit": "tbsp", "item": "Thai Red Curry Paste", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "tsp", "item": "Vegetable Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "l", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 400.0, "unit": "ml", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 2.0, "unit": "tsp", "item": "Brown Sugar", "notes": null, "category": "pantry"}, {"quantity": 175.0, "unit": "g", "item": "Egg Noodles", "notes": null, "category": "dairy"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Leaf", "notes": null, "category": "other"}, {"quantity": 150.0, "unit": "g", "item": "Bean Sprouts", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Tomatoes", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1 Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "thinly Spring Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Handful Coriander", "notes": null, "category": "spices"}]'::jsonb, '["step 1", "Place the curry paste in a large saucepan or wok with the oil. Fry for 1 min until fragrant. Tip in the vegetable stock, coconut milk and brown sugar. Simmer for 3 mins.", "step 2", "Add the noodles, carrots and Chinese leaf and simmer for 4-6 mins, until all are tender. Mix in beansprouts and tomatoes. Add lime juice to taste and some extra seasoning, if you like. Spoon into bowls and sprinkle with spring onions and coriander."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/thai-coconut-veg-broth', 'https://www.themealdb.com/images/media/meals/4k8nzy1763583384.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-pumpkin-soup', 'Thai pumpkin soup', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'thai', 'themealdb', 'dessert', 'soup', 'baking'], '[{"quantity": 1.5, "unit": "kg", "item": "Pumpkin", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tsp", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "grated Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Lemongrass", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Thai Red Curry Paste", "notes": null, "category": "spices"}, {"quantity": 400.0, "unit": "ml", "item": "Coconut Milk", "notes": null, "category": "dairy"}, {"quantity": 800.0, "unit": "ml", "item": "Vegetable Stock", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Lime juice", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To taste Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Red Chilli", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Heat oven to 200C/180C fan/gas 6. Toss the pumpkin or squash in a roasting tin with half the oil and seasoning, then roast for 30 mins until golden and tender.", "step 2", "Meanwhile, put the remaining oil in a pan with the onion, ginger and lemongrass. Gently cook for 8-10 mins until softened. Stir in the curry paste for 1 min, followed by the roasted pumpkin, all but 3 tbsp of the coconut milk and the stock. Bring to a simmer, cook for 5 mins, then fish out the lemongrass. Cool for a few mins, then whizz until smooth with a hand blender, or in a large blender in batches. Return to the pan to heat through, seasoning with salt, pepper, lime juice and sugar, if it needs it. Serve drizzled with the remaining coconut milk and scattered with chilli, if you like."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/thai-pumpkin-soup', 'https://www.themealdb.com/images/media/meals/1brbso1763585098.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-rice-noodle-salad', 'Thai rice noodle salad', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'thai', 'themealdb', 'dessert', 'salad', 'pasta'], '[{"quantity": 1.0, "unit": "serving", "item": "Vermicelli Rice Noodles", "notes": null, "category": "grains"}, {"quantity": 200.0, "unit": "g", "item": "Bean Sprouts", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Zest and juice of 2 Lime", "notes": null, "category": "produce"}, {"quantity": 3.0, "unit": "tbsp", "item": "2-3 tbsp Fish Sauce", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "tsp", "item": "Muscovado Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Red Onions", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Lettuce", "notes": null, "category": "produce"}, {"quantity": 500.0, "unit": "g", "item": "Minced Pork", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Knob Ginger", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Pinch Cayenne Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "Sunflower Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Sesame Seed", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "tsp", "item": "Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "steak", "notes": null, "category": "meat"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Place the noodles and beansprouts in a heatproof bowl and cover with boiling water. Leave for 4 mins, or until the noodles are tender. Drain, then cool under cold running water and drain again. Return to the bowl.", "step 2", "Stir together the lime zest and juice, fish or soy sauce and sugar. Stir into the noodles with the red onion and lettuce.", "step 3", "To make with mince, heat a little oil in a non-stick frying pan and stir-fry 500g minced pork, a small knob of grated ginger and pinch cayenne pepper or chilli powder for 10 mins, until the mince is browned and cooked through. Mix into the noodles, divide between four bowls and serve warm.", "step 4", "To make with steak, make the rice noodle salad. Heat 1 tsp sunflower oil in a frying pan. Tip 2 tbsp sesame seeds onto a plate. Rub 1 tsp oil into 4 x 175g sirloin steaks and press into sesame seeds. Fry for 5 mins for medium rare, turning halfway. Leave to rest for 5 mins, then thinly slice. Toss 1 deseeded and shredded red chilli, and a handful mint leaves into noodles. Top with steak to serve."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/thai-rice-noodle-salad', 'https://www.themealdb.com/images/media/meals/6g3rso1763486069.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
