ions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
