null, "category": "pantry"}]'::jsonb, '["Heat the oil in a large, heavy-based pan. Add the onions and cook gently for 5 – 10 mins until softened.", "Add the garlic, spices, dried thyme, carrots, celery and peppers and cook for 5 minutes.", "Add the tomatoes, stock, courgettes and fresh thyme and cook for 20 - 25 minutes.", "Take out the thyme sprigs. Stir in the lentils and bring back to a simmer. Serve with wild and white basmati rice, mash or quinoa."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/1993645/vegetarian-casserole', 'https://www.themealdb.com/images/media/meals/vptwyt1511450962.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
