ish and serve with toast"]'::jsonb, 'https://cookpad.com/eng/recipes/16275721?ref=search&search_term=saudi+arabia', 'https://www.themealdb.com/images/media/meals/eo0yfb1763600916.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vietnamese-veg-parcels', 'Vietnamese veg parcels', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'vietnamese', 'themealdb', 'salad', 'pasta', 'baking'], '[{"quantity": 100.0, "unit": "g", "item": "Rice Flour Pancakes", "notes": null, "category": "grains"}, {"quantity": 50.0, "unit": "g", "item": "Rice Noodles", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Breast", "notes": null, "category": "other"}, {"quantity": 1.0, "unit": "serving", "item": "Carrots", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Cucumber", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Pepper", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Lettuce", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Coriander", "notes": null, "category": "spices"}, {"quantity": 1.0, "unit": "serving", "item": "To serve Mint", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tablespoons", "item": "Fish Sauce", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tablespoons", "item": "Rice Vinegar", "notes": null, "category": "grains"}, {"quantity": 1.0, "unit": "serving", "item": "Juice of 1/2 Lime", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Red Chilli", "notes": null, "category": "other"}]'::jsonb, '["step 1", "Soak the rice fl our pancakes according to pack instructions or in boiling water for 30 secs. Remove and cool on kitchen paper. Soak the rice noodles according to pack instructions, then drain and cut them into 2cm strips.", "step 2", "Lay a rice pancake on a board and arrange some rice noodles, chicken, vegetables and herb leaves about a third of the way up, leaving a 1cm edge at the side. Fold the sides over the vegetables and then roll up lengthways to make a cigar. Store in the fridge, covered with moist kitchen paper for up to 1 day.", "step 3", "Mix together the ingredients for the dipping sauce and put into a bowl. To serve, arrange the rolls on a plate along with the leaves and herbs. To eat, wrap each roll in a piece of lettuce with a herb sprig and dunk into the sauce."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/vietnamese-veg-parcels', 'https://www.themealdb.com/images/media/meals/f698g91763768731.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
