cook for 3 mins more until the squash and beans are tender. Stir the spring onions through at the last minute, then sprinkle with coriander and serve with rice."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/vietnamese-veggie-hotpot', 'https://www.themealdb.com/images/media/meals/4uje7l1763762276.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('yaki-udon', 'Yaki Udon', 4, 0, 0, '{"calories": 0, "protein": 0.0, "carbs": 0.0, "fat": 0.0, "saturated_fat": null, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": null, "potassium": null, "fiber": null, "sugar": null, "vitamin_a": null, "vitamin_c": null, "calcium": null, "iron": null}'::jsonb, ARRAY['vegetarian', 'japanese', 'themealdb', 'dessert', 'pasta', 'vegan'], '[{"quantity": 250.0, "unit": "g", "item": "Udon Noodles", "notes": null, "category": "grains"}, {"quantity": 2.0, "unit": "tbs", "item": "Sesame Seed Oil", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Onion", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "0.25 Cabbage", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Mushrooms", "notes": null, "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "Onions", "notes": null, "category": "produce"}, {"quantity": 4.0, "unit": "tbsp", "item": "Mirin", "notes": null, "category": "other"}, {"quantity": 2.0, "unit": "tbs", "item": "Soy Sauce", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Caster Sugar", "notes": null, "category": "pantry"}, {"quantity": 1.0, "unit": "serving", "item": "Worcestershire Sauce", "notes": null, "category": "pantry"}]'::jsonb, '["Boil some water in a large saucepan. Add 250ml cold water and the udon noodles. (As they are so thick, adding cold water helps them to cook a little bit slower so the middle cooks through). If using frozen or fresh noodles, cook for 2 mins or until al dente; dried will take longer, about 5-6 mins. Drain and leave in the colander.", "Heat 1 tbsp of the oil, add the onion and cabbage and sauté for 5 mins until softened. Add the mushrooms and some spring onions, and sauté for 1 more min. Pour in the remaining sesame oil and the noodles. If using cold noodles, let them heat through before adding the ingredients for the sauce – otherwise tip in straight away and keep stir-frying until sticky and piping hot. Sprinkle with the remaining spring onions."]'::jsonb, 'https://www.bbcgoodfood.com/recipes/yaki-udon', 'https://www.themealdb.com/images/media/meals/wrustq1511475474.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
