seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "garlic powder", "notes": "1 tsp. garlic powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "chili powder", "notes": "1 tsp. chili powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "ground oregano", "notes": "1 tsp. ground oregano", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "ground cumin", "notes": "1 tsp. ground cumin", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "lettuce", "notes": "lettuce", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "tomato", "notes": "tomato", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "cucumber", "notes": "cucumber", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "smooth mustard", "notes": "2 – 3 tablespoons smooth mustard – your favorite", "category": "condiments"}, {"quantity": 2.0, "unit": "tablespoons", "item": "balsamic vinegar", "notes": "2 tablespoons balsamic vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tablespoons", "item": "honey", "notes": "2 – 3 tablespoons honey", "category": "nut butters, jams, and honey"}, {"quantity": 0.25, "unit": "tsp", "item": "salt", "notes": "¼ tsp. salt", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "tsp", "item": "pepper", "notes": "¼ tsp. black pepper", "category": "spices and seasonings"}]'::jsonb, '["Make a rub by combining the paprika, garlic powder, chili powder, oregano, and ground cumin in a medium sized bowl. Set aside.", "Place the ground chicken in a large bowl and add the chopped sun dried tomatoes, chopped garlic, juice and zest of 1 lemon, chopped cilantro, salt, pepper, grated Parmesan, chopped scallions, and olive oil.Shape the burgers into a ball and roll in the rub; then flatten the burgers to desired thickness.Grill burger until juices run clear. The cooking time depends on the thickness of the burger.Prepare the dressing by combining the mustard, balsamic vinegar, honey, 1/4 tsp salt, and 1/4 tsp pepper in a small bowl and whisk.", "Serve burgers with lettuce, tomato, and cucumber drizzled with honey mustard dressing. Feel free to drizzle some over the burger as well!"]'::jsonb, 'https://www.foodista.com/recipe/P2LJZTHF/chicken-burgers-with-spiced-rub', 'https://img.spoonacular.com/recipes/1096060-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('how-to-make-the-perfect-sweet-potato-sloppy-joes', 'How to Make the Perfect Sweet Potato Sloppy Joes', 4, 15, 25, '{"calories": 679, "protein": 48.91, "carbs": 84.96, "fat": 18.06, "saturated_fat": 2.92, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1278.71, "potassium": null, "fiber": 14.18, "sugar": 24.56, "vitamin_a": null, "vitamin_c": 49.97, "calcium": 145.6, "iron": 5.82}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'paleolithic', 'primal', 'whole 30', 'spoonacular', 'dessert', 'baking'], '[{"quantity": 0.5, "unit": "cup", "item": "bell pepper", "notes": "1/2 cup diced bell pepper", "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": "1 clove garlic diced", "category": "produce"}, {"quantity": 1.5, "unit": "pounds", "item": "ground turkey", "notes": "1 1/2 pounds lean ground turkey", "category": "meat"}, {"quantity": 4.0, "unit": "servings", "item": "olive oil", "notes": "olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.5, "unit": "cup", "item": "onion", "notes": "1/2 cup diced onion", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper to taste", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "large", "item": "sweet potatoes", "notes": "4 large sweet potatoes", "category": "produce"}, {"quantity": 6.0, "unit": "ounces", "item": "tomato paste", "notes": "6 ounces tomato paste", "category": "pasta and rice"}, {"quantity": 14.0, "unit": "ounces", "item": "tomato sauce", "notes": "14 ounces tomato sauce", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "cup", "item": "water", "notes": "1 cup water", "category": "beverages"}]'::jsonb, '["Preheat the oven to 425 degrees. Pierce the sweet potatoes all over the skin with a fork. Rub the outside of the potatoes with olive oil and cover with foil.", "Bake in the oven for 1 hour until fully cooked.", "Brown the ground turkey in a skillet on medium heat. Once it''s finished cooking, add the onion, bell pepper, and garlic.", "Mix well. Cook until the mixture is fully cooked and starts to crumble.", "Stir in the garlic, water, tomato paste, and tomato sauce. Stir until mixed well. Turn heat down to low and simmer for 20 minutes, stirring occasionally.", "Remove the sweet potatoes from the foil and slice down the middle. Mash up the insides with a fork and pour the sloppy joe mix over sweet potatoes.", "Serve and enjoy!"]'::jsonb, 'https://www.pinkwhen.com/how-to-make-the-perfect-sweet-potato-sloppy-joes/', 'https://img.spoonacular.com/recipes/1046982-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chili-verde-tomatillo-soup-with-bone-broth', 'Chili Verde Tomatillo Soup With Bone Broth', 4, 0, 0, '{"calories": 307, "protein": 34.25, "carbs": 12.77, "fat": 13.96, "saturated_fat": 2.47, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 307.66, "potassium": null, "fiber": 3.93, "sugar": 6.22, "vitamin_a": null, "vitamin_c": 25.31, "calcium": 48.68, "iron": 2.84}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'paleolithic', 'primal', 'whole 30', 'spoonacular', 'baking'], '[{"quantity": 1.0, "unit": "pound", "item": "tomatillos", "notes": "1 pound tomatillos husked", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "servings", "item": "kosher salt", "notes": "Kosher salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 yellow onion", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "paprika", "notes": "1 teaspoon sweet paprika", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ground garlic", "notes": "1 teaspoon ground garlic", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ground cumin", "notes": "1 teaspoon ground cumin", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "mexican oregano", "notes": "½ teaspoon dried Mexican oregano", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "jalapeno pepper", "notes": "1 jalapeno pepper minced", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "cups", "item": "kettle & fire mushroom chicken bone broth", "notes": "2 cups Kettle & Fire Mushroom Chicken Bone Broth", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "", "item": "chicken breasts", "notes": "2 cooked chicken breasts shredded", "category": "meat"}, {"quantity": 4.0, "unit": "servings", "item": "pepper", "notes": "Freshly ground black pepper.", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "lime", "notes": "1 lime", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "pumpkin seeds", "notes": "2 tablespoons shelled pumpkin seeds toasted", "category": "savory snacks"}, {"quantity": 4.0, "unit": "sprigs", "item": "cilantro", "notes": "4 sprigs fresh cilantro chopped", "category": "spices and seasonings"}]'::jsonb, '["Heat the oven to 400F.", "Place the tomatillos on a sheet pan and drizzles with 1 tablespoon of the oil and a sprinkle of salt.", "Transfer to the oven and cook until tomatillos are soft and slightly roasted, 8 to 10 minutes.", "Remove from the heat and let cool slightly. Then finely chop and set aside.In a medium sauce pot over high heat, warm the remaining olive oil.", "Add the onion and a pinch of salt and cook until starting to soften, 4 to 6 minutes. Stir in the spices and jalapeno and cook until fragrant, 1 to 2 minutes.", "Add the broth, chopped tomatillos and 1 cup of water. Bring to a boil, then reduce to a simmer. Cook, stirring occasionally, until slightly thickened, 3 to 4 minutes.Stir in the shredded chicken and continue simmering until the sauce is the consistency of a thick stew, 6 to 8 minutes. Slice the lime in half. Juice one half and cut the other half into wedges.", "Remove the stew from the heat, stir in the lime juice and season to taste with salt and pepper.", "Serve in bowls.", "Garnish with the pumpkin seeds, cilantro, and jicama, if using."]'::jsonb, 'https://www.foodista.com/recipe/FY8BMTM5/chili-verde-tomatillo-soup-with-bone-broth', 'https://img.spoonacular.com/recipes/1096221-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('grilled-ham-and-cheese-french-toast-for-a-quick-weeknight-dinner', 'Grilled Ham and Cheese French Toast For A Quick Weeknight Dinner', 4, 0, 0, '{"calories": 432, "protein": 31.17, "carbs": 27.53, "fat": 21.64, "saturated_fat": 9.61, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1738.49, "potassium": null, "fiber": 4.52, "sugar": 4.9, "vitamin_a": null, "vitamin_c": 1.23, "calcium": 369.97, "iron": 2.63}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'breakfast', 'baking', 'grilling'], '[{"quantity": 0.5, "unit": "cup", "item": "buttermilk", "notes": "1/2 cup buttermilk", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "large", "item": "egg whites", "notes": "2 egg whites or 1 large egg", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "dijon mustard", "notes": "1/4 cup spicy brown mustard or Dijon mustard", "category": "condiments"}, {"quantity": 8.0, "unit": "slices", "item": "wheat bread", "notes": "8 slices Oroweat healthfull nutty grain or hearty wheat bread", "category": "bakery/bread"}, {"quantity": 4.0, "unit": "oz", "item": "jarlsberg cheese", "notes": "4 slices (1 oz each) reduced-fat Havarti, Swiss or Jarlsberg cheese", "category": "cheese"}, {"quantity": 8.0, "unit": "ounces", "item": "turkey ham", "notes": "8 ounces sliced lean ham or turkey ham", "category": "meat"}, {"quantity": 3.0, "unit": "", "item": "dill pickles", "notes": "3 deli style dill pickles, each sliced lengthwise into thin slices", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tablespoons", "item": "smart balance heart right", "notes": "2 tablespoons reduced-fat butter or Smart Balance Heart Right Light", "category": "meat"}]'::jsonb, '["Preheat oven to 350 degrees.", "In a shallow bowl or pie plate, whisk together buttermilk and egg whites. Set aside.", "Spread mustard on one side of each slice of bread.  Top 4 slices with 1 slice of cheese.  Arrange ham on top of cheese.", "Add to each 3-4 thin slices of pickle. Top with remaining bread slices, mustard side down.", "Melt 1 tablespoon reduced-fat butter in a large nonstick pan over medium heat.  Dip 2 sandwiches into buttermilk mixture; carefully flip and dip other side.  Dont soak the sandwiches in this mixture. Just lightly dip and remove sandwiches, allowing excess buttermilk mixture to drip back into dish.", "Add sandwiches to pan; cover and cook 3-5 minutes.  Uncover, flip sandwiches, press top down with a spatula, cover and cook for 2-3 minutes until golden and cheese is melted.", "Remove sandwiches, place on a baking sheet and keep warm in oven.", "Repeat steps 4 and 5 with remaining 2 sandwiches.", "Slice each sandwich in half and serve with a fork and knife."]'::jsonb, 'https://www.foodista.com/recipe/45YYRH68/grilled-ham-and-cheese-french-toast-for-a-quick-weeknight-dinner', 'https://img.spoonacular.com/recipes/645732-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('janas-homemade-mac-and-cheese', 'Jana’s Homemade Mac and Cheese', 8, 0, 0, '{"calories": 579, "protein": 26.89, "carbs": 61.74, "fat": 24.71, "saturated_fat": 13.82, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 458.1, "potassium": null, "fiber": 2.65, "sugar": 8.52, "vitamin_a": null, "vitamin_c": 0, "calcium": 581.08, "iron": 1.16}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'lacto ovo vegetarian', 'spoonacular', 'pasta', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "tsp", "item": "pepper", "notes": "1 tsp black pepper", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "tablespoons", "item": "butter", "notes": "3 tablespoons melted butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tbsp", "item": "onion flakes", "notes": "1 tbsp dried onion flakes", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "cups", "item": "elbow pasta", "notes": "4 cups elbow pasta", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "tsp", "item": "paprika", "notes": "1 tsp paprika", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "cups", "item": "sharp cheddar cheese", "notes": "4 cups of grated sharp cheddar cheese", "category": "cheese"}, {"quantity": 4.0, "unit": "cups", "item": "skim milk", "notes": "4 cups of skim milk", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "tbsp", "item": "flour", "notes": "2 tbsp whole wheat flour", "category": "baking"}]'::jsonb, '["Preheat your oven to 350F.In a large pot, cook pasta as directed until al dente.", "Drain, rinse, and set aside.While the pasta is cooking, heat up the butter in a large saucepan*. As the butter melts, add the flour and whisk until a rue forms. Slowly stir in milk.", "Add paprika, black pepper, and onion flakes. Bring to a slight boil and let simmer for about 15 minutes, stirring frequently. Sauce should thicken a bit as it cooks.Turn off the heat and add 3 cups of the grated cheese. Stir until cheese is about melted.", "Add the pasta to the milk and cheese sauce mix. Stir until the pasta is all covered; you should be able to hear the elbows filling up with liquid as your stir.** Once youve mixed the pasta and sauce, add the remaining cup of cheese and gently fold it in.", "Sprinkle the top of the mix with the breadcrumbs.", "Bake for 30 to 35 minutes, uncovered.", "Remove from oven and let cool for 5 minutes before serving.A few notes:If you dont have whole wheat flour, regular flour is fine. You can use any milk, but the higher the fat content in your milk, the richer and thicker your sauce will be.Back East, we would always use Cabot Creamery Extra Sharp or Sharp Cheddar cheese exclusively for my homemade mac and cheese. Here in Oregon, we cant get Cabot easily, so Ive been making it with Tillamook Sharp Cheddar.No Italian breadcrumbs? Just use Planko instead.*If you have an oven-safe saucepan, you can use that. Otherwise, you will need to transfer the ingredients to an oven-safe baking dish after youve added the pasta to the sauce mix.**Here is where you transfer the pasta and sauce mix to an oven-safe baking dish."]'::jsonb, 'https://www.foodista.com/recipe/LQP3QPXR/jana-s-homemade-mac-and-cheese', 'https://img.spoonacular.com/recipes/648446-312x231.png', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('best-buffalo-chicken-chili', 'Best Buffalo Chicken Chili', 10, 0, 0, '{"calories": 298, "protein": 29.14, "carbs": 32.59, "fat": 7.39, "saturated_fat": 1.16, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1429.61, "potassium": null, "fiber": 11.09, "sugar": 8.21, "vitamin_a": null, "vitamin_c": 27.29, "calcium": 144.96, "iron": 9.18}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular'], '[{"quantity": 15.0, "unit": "oz", "item": "black beans", "notes": "1 (15 oz) black beans, drained", "category": "pasta and rice"}, {"quantity": 30.0, "unit": "oz", "item": "tomato sauce", "notes": "2 (15 oz) cans tomato sauce", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "large", "item": "carrots", "notes": "2 large carrots", "category": "produce"}, {"quantity": 3.0, "unit": "stalks", "item": "celery", "notes": "3 stalks celery", "category": "produce"}, {"quantity": 5.0, "unit": "tablespoons", "item": "chili powder", "notes": "5 tablespoons of chili powder", "category": "spices and seasonings"}, {"quantity": 15.0, "unit": "oz", "item": "chili beans sauce", "notes": "1 inch (15 oz) chili beans sauce (do not drain)", "category": "canned and jarred"}, {"quantity": 4.0, "unit": "teaspoons", "item": "garlic", "notes": "4 teaspoons garlic (salt or powder)", "category": "produce"}, {"quantity": 12.0, "unit": "tablespoons", "item": "ground cumin", "notes": "12 tablespoons ground cumin (IMPORTANT)", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "frank''s hot sauce", "notes": "1/2 cup Frank''s Hot Sauce", "category": "condiments"}, {"quantity": 1.0, "unit": "tablespoon", "item": "olive oil", "notes": "1 tablespoon olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "tablespoons", "item": "paprika", "notes": "4 tablespoons paprika", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "teaspoons", "item": "pepper", "notes": "4 teaspoons red pepper, ground", "category": "produce"}, {"quantity": 10.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper to taste", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "pounds", "item": "chicken breasts", "notes": "2 pounds boneless, skinless chicken breasts", "category": "meat"}, {"quantity": 15.0, "unit": "oz", "item": "tomatoes", "notes": "1 (15 oz) diced tomatoes", "category": "produce"}]'::jsonb, '["Put chicken breasts in food processor to grind up  if you can find ground chicken breast, you can use that too.", "Heat oil and add ground chicken and cook about 10 minutes on medium heat until no longer pink.  Rinse out processor and add carrots, celery, garlic and red pepper and puree.", "Add to chicken mixture and cook about 5 minutes until veggies start to soften.Next add the rest of the ingredients, put stove on simmer and cook for 1 hour.Nutrition Per Cup: 239 calories, 3.4 fat, 29 carbs, 7.5 fiber and 23.5 protein.Good points:  low in saturated fat, high in fiber,  niacin, potassium, vitamin A, vitamin B6 and vitamin C!"]'::jsonb, 'https://www.foodista.com/recipe/C53B32ZC/best-buffalo-chicken-chili', 'https://img.spoonacular.com/recipes/634888-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('hawaiian-chicken-chili', 'Hawaiian Chicken Chili', 8, 0, 0, '{"calories": 435, "protein": 23.29, "carbs": 36.02, "fat": 24.02, "saturated_fat": 18.13, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 743.69, "potassium": null, "fiber": 6.42, "sugar": 15.89, "vitamin_a": null, "vitamin_c": 61.65, "calcium": 85.4, "iron": 3.36}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'spoonacular'], '[{"quantity": 8.0, "unit": "servings", "item": "jamaican allspice", "notes": "• Jamaican AllSpice", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "can", "item": "coconut milk", "notes": "• 1 can Coconut Milk", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "", "item": "carrots", "notes": "• 2 Organic Carrots", "category": "produce"}, {"quantity": 3.0, "unit": "", "item": "chicken breasts", "notes": "• 3 Organic Chicken Breasts", "category": "meat"}, {"quantity": 32.0, "unit": "oz", "item": "chicken broth", "notes": "• 32 oz. Organic Chicken Broth", "category": "canned and jarred"}, {"quantity": 8.0, "unit": "servings", "item": "cilantro", "notes": "• Organic Cilantro", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "servings", "item": "coconut flakes", "notes": "• Coconut Flakes", "category": "baking"}, {"quantity": 8.0, "unit": "servings", "item": "cumin", "notes": "• Cumin", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "", "item": "garlic cloves", "notes": "• 4 Garlic Cloves", "category": "produce"}, {"quantity": 2.0, "unit": "Cans", "item": "great northern beans", "notes": "• 2 Cans Great Northern Beans", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "cup", "item": "brown rice", "notes": "1/2 cup Long Grain Brown Rice", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "", "item": "pineapple", "notes": "• 1 Pineapple", "category": "produce"}, {"quantity": 8.0, "unit": "servings", "item": "sea salt", "notes": "• Sea Salt", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "servings", "item": "cream", "notes": "sour cream", "category": "milk, eggs, other dairy"}, {"quantity": 8.0, "unit": "servings", "item": "thyme", "notes": "• Organic Thyme", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "• 1 white onion", "category": "produce"}, {"quantity": 8.0, "unit": "servings", "item": "pepper", "notes": "• white pepper", "category": "spices and seasonings"}]'::jsonb, '["Cut 1/2 of a pineapple into small cubes.", "Add to food processor.Puree pineapple until liquified.", "Cut chicken into cubes.", "Add to pan.", "Pour puree''d pinapple over top. Cook chicken.Chop 1/2 onion.When chicken is almost fully cooked, add onion to chicken &amp; pineapple mixture.", "Add a scoop of Coconut Milk to chicken mixture.", "Add a tablespoon of white pepper.", "Add  4 cloves of pressed garlic.Grab a small bunch of cilantro and few sprigs of thyme. Chop them.", "Add cilantro and thyme to chicken mixture.Once chicken is fully cooked and onions are almost see through, scoop mixture into food processor. Lightly grind food until chicken looks shredded.Grate 2 medium sized carrots finely.", "Pour in a new pan 1 can of coconut milk, 32 oz. chicken broth, 1 can of water.", "Add 2 cans Great Northern Beans &amp; Shredded chicken mixture.", "Mix well. Bring to a boil. Then simmer.", "Add carrots.In another pan, add 1 cup of water. 1 tsp garlic, 1/4 tsp. cumin, 2 tbsp. coconut flakes, sea salt, 4 dashes of Jamaican Allspice.", "Add 1/2 cup Long Grain Brown Rice.Cook rice until al dente. (Still slightly crunchy.)", "Add rice to simmering mixture. Simmer until carrots and rice are cooked thoroughly.", "Serve with sour cream."]'::jsonb, 'https://www.foodista.com/recipe/Z7C777S3/hawaiian-chicken-chili', 'https://img.spoonacular.com/recipes/646358-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lemongrass-and-chilli-prawns', 'Lemongrass And Chilli Prawns', 5, 0, 0, '{"calories": 163, "protein": 14.53, "carbs": 4.87, "fat": 9.53, "saturated_fat": 0.75, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 964.35, "potassium": null, "fiber": 0.38, "sugar": 1.9, "vitamin_a": null, "vitamin_c": 26.71, "calcium": 63.3, "iron": 0.61}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'pescatarian', 'spoonacular', 'dessert', 'vegetarian', 'vegan'], '[{"quantity": 0.5, "unit": "kg", "item": "tiger prawns - remove head", "notes": "1/2 kg tiger prawns - remove head, gently pull out the veins; wash and pat dry.", "category": "seafood"}, {"quantity": 2.0, "unit": "", "item": "chilies", "notes": "2 red chilies - chopped", "category": "produce"}, {"quantity": 4.0, "unit": "", "item": "garlic", "notes": "4 garlic - chopped", "category": "produce"}, {"quantity": 1.0, "unit": "inch", "item": "ginger", "notes": "1 inch ginger - chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "lemongrass", "notes": "1 lemongrass - - chopped", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "tbsp", "item": "soy sauce", "notes": "1/2 tbsp dark soy sauce", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "tbsp", "item": "soy sauce", "notes": "1/2 tbsp light soy sauce", "category": "condiments"}, {"quantity": 1.0, "unit": "tsp", "item": "sugar", "notes": "1 tsp sugar", "category": "baking"}, {"quantity": 3.0, "unit": "", "item": "kaffir lime leaves -tear into pieces", "notes": "3-4 kaffir lime leaves -tear into pieces", "category": "ethnic foods"}, {"quantity": 3.0, "unit": "tbsp", "item": "oil", "notes": "3 tbsp oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.5, "unit": "cup", "item": "water", "notes": "1/2 cup water", "category": "beverages"}, {"quantity": 5.0, "unit": "servings", "item": "salt", "notes": "Salt to taste (only if needed)", "category": "spices and seasonings"}]'::jsonb, '["Saut chilies, garlic, ginger and lemongrass.", "Add prawns, dark and light sauce, sugar and season with salt.", "Stir all in and pour water (just enough to cook the prawns).", "Cook over medium size heat until sauce becomes thick.", "Put in lime leaves.", "Stir once more and remove from heat."]'::jsonb, 'https://www.foodista.com/recipe/7N8JQW5H/lemongrass-and-chilli-prawns', 'https://img.spoonacular.com/recipes/649867-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tex-mex-burger', 'Tex-Mex Burger', 4, 0, 0, '{"calories": 884, "protein": 50.53, "carbs": 32.26, "fat": 61.3, "saturated_fat": 22.92, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1300.92, "potassium": null, "fiber": 5.94, "sugar": 6.13, "vitamin_a": null, "vitamin_c": 9.16, "calcium": 298.27, "iron": 7.5}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'baking'], '[{"quantity": 1.0, "unit": "", "item": "avocado", "notes": "1 avocado, thinly sliced", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "chili powder", "notes": "1 tsp Chili Powder", "category": "spices and seasonings"}, {"quantity": 0.75, "unit": "cup", "item": "cilantro", "notes": "¾ cup cilantro, chopped", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tsp", "item": "cumin", "notes": "2 tsp Cumin", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "lb", "item": "ground beef", "notes": "2 lb ground beef", "category": "meat"}, {"quantity": 4.0, "unit": "", "item": "hamburger buns", "notes": "4 Hamburger Buns, Toasted", "category": "bakery/bread"}, {"quantity": 1.0, "unit": "tsp", "item": "paprika", "notes": "1 tsp Paprika", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "pepper", "notes": "1 tsp Pepper", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "Slices", "item": "pepper jack cheese", "notes": "4 Slices Pepper jack Cheese", "category": "cheese"}, {"quantity": 8.0, "unit": "slices", "item": "onion", "notes": "8 thin slices red onion", "category": "produce"}, {"quantity": 8.0, "unit": "tablespoons", "item": "salsa", "notes": "8 tablespoons salsa", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "tsp", "item": "salt", "notes": "1 tsp Salt", "category": "spices and seasonings"}]'::jsonb, '["Preheat broiler.", "Heat large frying pan to medium high heat. Make patties: Take the ground beef, add salsa and spices.", "Mix together till evenly distributed.", "Place patty on bun. Top with 1 TBSP Salsa, then 2 slices of red onion.", "Place  of the cilantro on red onion and then place avocado on top bun.", "Add bun to burger and serve."]'::jsonb, 'https://www.foodista.com/recipe/NSYCCHLT/tex-mex-burger', 'https://img.spoonacular.com/recipes/663050-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chili-lime-chicken-burgers', 'Chili Lime Chicken Burgers', 6, 0, 0, '{"calories": 746, "protein": 53.9, "carbs": 41.55, "fat": 41.1, "saturated_fat": 9.65, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 970.67, "potassium": null, "fiber": 6.59, "sugar": 5.7, "vitamin_a": null, "vitamin_c": 24.91, "calcium": 51.24, "iron": 13.82}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'soup', 'grilling'], '[{"quantity": 6.0, "unit": "servings", "item": "chicken burgers", "notes": "Chicken Burgers", "category": "meat"}, {"quantity": 2.0, "unit": "lbs", "item": "ground chicken", "notes": "2 lbs ground chicken", "category": "meat"}, {"quantity": 0.25, "unit": "cup", "item": "onion", "notes": "¼ cup diced onion", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "bell pepper", "notes": "¼ cup diced red bell pepper", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "cilantro", "notes": "¼ cup chopped cilantro", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "", "item": "garlic cloves", "notes": "4 garlic cloves, finely diced", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "pepper flakes", "notes": "1 tsp crushed red pepper flakes", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tsp", "item": "chili powder", "notes": "2 tsp chili powder", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tsp", "item": "lime juice", "notes": "2 tsp lime juice", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "salt", "notes": "1 tsp salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "pepper", "notes": "1 tsp pepper", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "servings", "item": "buns", "notes": "Buns for serving", "category": "bakery/bread"}, {"quantity": 6.0, "unit": "servings", "item": "guacamole", "notes": "Guacamole", "category": "refrigerated"}, {"quantity": 2.0, "unit": "", "item": "avocados", "notes": "2 avocados", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "cumin", "notes": "1 tsp cumin", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "lime juice", "notes": "1 tsp lime juice", "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "salt", "notes": "¼ tsp salt", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "", "item": "bell pepper", "notes": "¼ pepper", "category": "produce"}]'::jsonb, '["Mix together chicken, onions, red pepper, cilantro, crushed red pepper, chili powder, lime juice, salt and pepper. I mixed together that morning and let sit in the fridge until dinner that night, about 8 hours. You dont have to do that, it just gives the meat some time to absorb all the flavor.", "Heat up the grill on Medium heat.", "Form into 6 patties.", "Once grill is hot, add burgers and cook about 5-7 minutes on each side or until internal temperature reaches 165 degrees. Try not to move them around so you can get some grill marks.", "Meanwhile, in a small bowl, mash avocado with cumin, lime, salt and pepper to your desired guacamole consistency. I leave mine a little chunky.", "When burgers are finished, place on a bun and top with guacamole. We had this with a side of Spanish rice. So fresh and delicious!", "Printable Recipe", "Recipe adapted from The Housewife in Training Files"]'::jsonb, 'https://www.foodista.com/recipe/BJSKJDH3/chili-lime-chicken-burgers', 'https://img.spoonacular.com/recipes/638566-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('new-england-clam-chowder', 'New England Clam Chowder', 4, 0, 0, '{"calories": 358, "protein": 13.41, "carbs": 40.24, "fat": 16.29, "saturated_fat": 7.58, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 890.97, "potassium": null, "fiber": 2.89, "sugar": 10.8, "vitamin_a": null, "vitamin_c": 23.69, "calcium": 253.96, "iron": 1.41}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'spoonacular', 'breakfast', 'baking'], '[{"quantity": 3.0, "unit": "slices", "item": "bacon", "notes": "3 slices bacon, chopped", "category": "meat"}, {"quantity": 1.0, "unit": "tablespoon", "item": "butter", "notes": "1 tablespoon butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "celery salt", "notes": "1 teaspoon celery salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "flour", "notes": "2 tablespoons flour", "category": "baking"}, {"quantity": 3.0, "unit": "cups", "item": "milk", "notes": "3 cups milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "medium", "item": "onion", "notes": "1 medium onion finely diced", "category": "produce"}, {"quantity": 1.0, "unit": "Dash", "item": "pepper", "notes": "Dash pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cups", "item": "potato", "notes": "2 cups diced raw potato", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon salt (if not using seaweed)", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "cup", "item": "clam liquid and water", "notes": "1 cup clam liquid and water", "category": "beverages"}, {"quantity": 1.5, "unit": "cups", "item": "kernel corn", "notes": "1 1/2 cups drained whole kernel corn", "category": "produce"}, {"quantity": 8.0, "unit": "ounces", "item": "each", "notes": "8 ounces each minced or chopped clams", "category": "seafood"}]'::jsonb, '["Drain clams.", "Pour clam liquid into measuring cup and add water to make 1 cup.Fry bacon until crisp.", "Add onion and cook until tender.", "Add potatoes, clam liquid and water. Lower heat and simmer gently until potatoes are tender.", "Add corn and milk. Blend flour and butter and stir into soup. Cook slowly until mixture thickens slightly, stirring constantly.", "Add seasonings and clams. Simmer 5 minutes. Top with 1/2 cup coarse cracker crumbs, optional."]'::jsonb, 'https://www.foodista.com/recipe/FVHY7M2L/new-england-clam-chowder', 'https://img.spoonacular.com/recipes/653025-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mini-zucchini-avocado-burgers', 'Mini Zucchini Avocado Burgers', 2, 0, 0, '{"calories": 527, "protein": 22.16, "carbs": 7.6, "fat": 46.02, "saturated_fat": 11.74, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2154.9, "potassium": null, "fiber": 3.62, "sugar": 4.35, "vitamin_a": null, "vitamin_c": 31.45, "calcium": 55.59, "iron": 3.07}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'paleolithic', 'whole 30', 'ketogenic', 'spoonacular', 'baking', 'grilling'], '[{"quantity": 1.0, "unit": "large", "item": "zucchini", "notes": "1 large zucchini, chopped into 1/2-inch (1 cm) thick slices (around 14-16 slices)", "category": "produce"}, {"quantity": 225.0, "unit": "g", "item": "ground beef", "notes": "1/2 lb (225 g) ground beef", "category": "meat"}, {"quantity": 0.25, "unit": "", "item": "avocado", "notes": "1/4 avocado, cut into small slices", "category": "produce"}, {"quantity": 30.0, "unit": "ml", "item": "avocado oil", "notes": "2 Tablespoons (30 ml) olive or avocado oil for greasing baking tray", "category": "health foods"}, {"quantity": 10.0, "unit": "g", "item": "salt", "notes": "2 teaspoons (10 g) salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "mayo", "notes": "1 Tablespoon Paleo mayo (optional – omit for AIP)", "category": "condiments"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "mustard", "notes": "1 Tablespoon mustard (optional – omit for AIP)", "category": "condiments"}]'::jsonb, '["Preheat oven to 400F (200C).", "Grease a baking tray with olive or avocado oil and sprinkle 1 teaspoon of salt across it.", "Place the zucchini slices on the baking tray.", "Form small balls from the ground beef and press into patties  around 7 or 8 patties  and place on the baking tray.", "Place baking tray into oven and bake for 15 minutes. Alternatively, instead of baking them, you can grill the zucchini and beef patties or pan-fry them in some olive or avocado oil.", "Meanwhile, slice the avocado into small thin slices.", "Put the mini burgers together using the zucchini slices as buns  add a slice of avocado to each burger and top with condiments like Paleo mayo and mustard."]'::jsonb, 'https://www.foodista.com/recipe/GFVZTMSY/mini-zucchini-avocado-burgers-recipe-paleo-keto-aip', 'https://img.spoonacular.com/recipes/1095682-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('slow-cooker-spicy-hot-wings', 'Slow Cooker Spicy Hot Wings', 4, 10, 4, '{"calories": 384, "protein": 22.82, "carbs": 28.42, "fat": 19.76, "saturated_fat": 5.52, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 890.48, "potassium": null, "fiber": 0.25, "sugar": 27.12, "vitamin_a": null, "vitamin_c": 24.27, "calcium": 44.21, "iron": 1.57}'::jsonb, ARRAY['american', 'antipasti', 'lunch', 'main course', 'starter', 'snack', 'appetizer', 'main dish', 'antipasto', 'hor d''oeuvre', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'dessert', 'quick', 'slow-cooker', 'baking', 'grilling'], '[{"quantity": 0.5, "unit": "cup", "item": "brown sugar", "notes": "½ cup brown sugar", "category": "baking"}, {"quantity": 1.0, "unit": "tsp", "item": "cayenne pepper", "notes": "1 tsp cayenne pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "pounds", "item": "regular chicken wings", "notes": "2 - 4 pounds regular chicken wings", "category": "meat"}, {"quantity": 1.0, "unit": "Tbsp", "item": "garlic", "notes": "1 Tbsp crushed garlic", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "louisiana hot sauce", "notes": "½ cup Louisiana Hot sauce", "category": "condiments"}]'::jsonb, '["Yes, these are called SPICY hot wings for a reason. I like adding the brown sugar to give them a little sweeter taste, but it is by far a delicious spicy recipe more than anything.To get started, mix the brown sugar, crushed garlic, hot sauce, and cayenne pepper into a medium mixing bowl.", "Mix well and then set aside.Take the cooking spray and spray the entire inside portion of the slow cooker AND also the wings. (Spraying the wings before you grill, bake, or cook chicken keeps the flavor and makes them super juicy. TRUST ME.)Take the wings and add them into the mixing bowl with your spices and toss to get a good even coat over the wings.", "Place in the slow cooker on low for 4 hours. After 4hours, remove carefully and place on a prepared cookie sheet.", "Place in the oven under broiler setting for 4-6 minutes, allowing the wings to get a little crisp.", "Serve immediately with a little blue cheese dressing and celery."]'::jsonb, 'https://www.pinkwhen.com/slow-cooker-spicy-hot-wings/', 'https://img.spoonacular.com/recipes/715419-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('south-carolina-style-pulled-pork', 'South Carolina Style Pulled Pork', 10, 0, 0, '{"calories": 691, "protein": 47.76, "carbs": 79.27, "fat": 20.7, "saturated_fat": 6.14, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2415.84, "potassium": null, "fiber": 4.76, "sugar": 63.19, "vitamin_a": null, "vitamin_c": 12.42, "calcium": 125.99, "iron": 6.33}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'breakfast', 'baking', 'grilling'], '[{"quantity": 1.0, "unit": "cup", "item": "apple cider vinegar", "notes": "1 cup apple cider vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "cups", "item": "barbecue sauce", "notes": "2 cups barbecue sauce (see Ina''s recipe below)", "category": "condiments"}, {"quantity": 2.0, "unit": "tablespoons", "item": "chili powder", "notes": "2 tablespoons chili powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "dijon mustard", "notes": "1 cup Dijon mustard", "category": "condiments"}, {"quantity": 1.0, "unit": "teaspoon", "item": "garlic", "notes": "Garlic crushed 1 teaspoon", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "ground cumin", "notes": "1 tablespoon ground cumin", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "hoisin sauce", "notes": "1 cup hoisin sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "cup", "item": "honey", "notes": "1 cup honey", "category": "nut butters, jams, and honey"}, {"quantity": 2.0, "unit": "tablespoons", "item": "maple syrup", "notes": "2 tablespoons maple syrup", "category": "cereal"}, {"quantity": 8.0, "unit": "pounds", "item": "boston butt pork shoulder", "notes": "8 pounds Boston butt pork shoulder", "category": "meat"}, {"quantity": 0.5, "unit": "tablespoon", "item": "pepper flakes", "notes": "1/2 tablespoon crushed red pepper flakes", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "soy sauce", "notes": "1 teaspoon soy sauce", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "teaspoons", "item": "table salt", "notes": "2 teaspoons table salt", "category": "spices and seasonings"}, {"quantity": 10.0, "unit": "ounces", "item": "tomato paste", "notes": "1 cup tomato paste (10 ounces)", "category": "pasta and rice"}, {"quantity": 0.5, "unit": "cup", "item": "vegetable oil", "notes": "1/2 cup vegetable oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.5, "unit": "cup", "item": "worcestershire sauce", "notes": "1/2 cup Worcestershire sauce", "category": "condiments"}, {"quantity": 1.5, "unit": "cups", "item": "onion", "notes": "1 1/2 cups chopped yellow onion (1 large onion)", "category": "produce"}]'::jsonb, '["Massage mustard sauce into the meat. Wrap the meat tightly in a double layer of plastic wrap and refrigerate for at least 3 hours or up to 3 days. (The sauce was really thin and liquid-y so after dumping about half on the meat and realizing massaging was just not going to happen, I threw the meat and the sauce into a ziplock bag, shook it up and made sure it was coated then threw it in the fridge for the three day marinating marathon.)At least one hour prior to cooking, remove the roast from the refrigerator and unwrap, placing the meat and the marinating juices into a disposable 913 disposable aluminum pan and let it come to room temperature. (As I mentioned above, my pans were a bit flimsy so I doubled up.) Soak the wood chips in cold water to cover for 1 hour and drain.Meanwhile, light a large chimney starter filled halfway with charcoal (about 3 quarts) and allow to burn until the coals are partially covered with a layer of ash. Build a modified two-level fire by arranging all the coals over half of the grill, leaving the other half empty. Open the bottom grill vents completely.", "Place the wood chips on the coals. Set the cooking grate in place, cover and heat the grate until hot, about 5 minutes. Use a grill brush to scrape the cooking grate clean. Sip a wad of paper towels in vegetable oil; holding the wad with tongs, oil the cooking grate.Set the aluminum pan with the roast on the grate opposite the coals. Open the grill lid vents three-quarters of the way and cover, making sure the vent is above the meat to draw smoke through the grill. Cook, adding about eight briquettes every hour or so to maintain an average temperature of 275F for three hours. (When I added coals, I also basted the marinade over the roast to ensure moistness.)Adjust an oven rack to the middle position and heat the oven to 325F. Wrap the pan holding the roast, being careful not to spill the marinating liquid, with heavy duty aluminum foil to cover completely.", "Place the pan in the oven and cook until the meat is fork-tender, about 2 hours.Carefully slide the foil-wrapped pan with the roast into a brown paper bag. Crimp the end shut.", "Let rest for 1 hour. (I found it easiest to lay the paper bag open on its side and slide the roast in, instead of dropping it downward, then folding the opening up and taping it shut.)While roast is resting, prepare barbecue sauce. If wanting true South Carolina style barbecue sauce, make the marinade above. If wanting a thicker, tangier sauce with a hot finish, I highly recommend Inas barbecue sauce below. Its a bit of an ingredient dump with 11 of 13 items being from jars and bottles, but with flavors so loud and clamoring for your taste-buds attention, you wont regret it.In a large sauce pan on low heat, saute onions and garlic with the oil until the onions are translucent, about 10 to 15 minutes.", "Add the rest of the ingredients. Simmer uncovered on low heat for 30 minutes. Use immediately or store in fridge. Makes about 6 cups.Keeping: This sauce freezes excellently. I made a big batch last fall and froze it, pulling it out for the pulled pork. I re-heated in a sauce pan on low heat until hot.Once pork has rested, transfer the roast to a carving board and dispose of the marinade liquid and pan. When cool enough to handle, separate the roast into sections, removing fat if desired, and tear the meat into shreds with your fingers (forks work just as well without your fingers getting messy).", "Place the shredded meat in a large bowl. Toss with 1 cup of the barbecue sauce, adding more to taste.", "Serve, passing the remaining sauce separately."]'::jsonb, 'https://www.foodista.com/recipe/668T4HVK/south-carolina-style-pulled-pork', 'https://img.spoonacular.com/recipes/660680-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-and-chickpea-chili', 'Chicken and Chickpea Chili', 6, 0, 0, '{"calories": 609, "protein": 36.61, "carbs": 79.85, "fat": 17.8, "saturated_fat": 3.49, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 685.26, "potassium": null, "fiber": 16.31, "sugar": 18.06, "vitamin_a": null, "vitamin_c": 22.11, "calcium": 165.16, "iron": 8.14}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'dessert', 'pasta', 'baking'], '[{"quantity": 3.0, "unit": "cups", "item": "baby spinach", "notes": "3 cups of baby spinach, cut into thin strips", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bay leaf", "notes": "1 bay leaf", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "servings", "item": "pepper", "notes": "freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 28.0, "unit": "ounce", "item": "canned tomatoes", "notes": "1 can (28- ounce) of crushed tomatoes", "category": "canned and jarred"}, {"quantity": 4.0, "unit": "cups", "item": "chicken stock", "notes": "4 cups of Chicken Stock", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "teaspoons", "item": "chili powder", "notes": "2 teaspoons of chili powder", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cups", "item": "chickpeas", "notes": "2 cups of chickpeas (preferably, dried beans that have been soaked/cooked)", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tablespoons", "item": "garlic", "notes": "2 tablespoons garlic, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "pound", "item": "ground chicken", "notes": "1 pound of ground chicken", "category": "meat"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ground cinnamon", "notes": "1 teaspoon ground cinnamon", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ground cumin", "notes": "1 teaspoon ground cumin", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "servings", "item": "kosher salt", "notes": "kosher salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons of olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "large", "item": "onion", "notes": "1 large onion, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "orzo pasta", "notes": "1 cup of whole-wheat orzo pasta", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "teaspoon", "item": "paprika", "notes": "1 teaspoon of paprika", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sugar", "notes": "1 teaspoon of sugar", "category": "baking"}]'::jsonb, '["Heat olive oil in a Dutch oven or soup pot.Flame should be medium to low.", "Add onions and cook for about 5 minutes, or until soft and translucent.", "Add the garlic.  Cook for about 1 minutes.", "Add the spices and move around pot for about 1-2 minutes.", "Add the ground meat, 1 teaspoon of salt and  a teaspoon of pepper.  Cook meat until completely cooked thru.Then add the chickpeas.", "Add the tomatoes, sugar and chicken stock.Bring the soup to a bowl.Then reduce heat and allow to simmer for about 40-45 minutes.  Taste.", "Add more salt and pepper if necessary.", "Add the orzo pasta.  Cook for 6 minutes.Turn off heat and add the spinach.", "Serve with crusty bread or crackers"]'::jsonb, 'https://www.foodista.com/recipe/PD75LLZQ/chicken-and-chickpea-chili', 'https://img.spoonacular.com/recipes/637897-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('easy-chicken-wings', 'Easy Chicken Wings', 4, 0, 0, '{"calories": 427, "protein": 17.91, "carbs": 20.57, "fat": 30.97, "saturated_fat": 5.52, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 614.44, "potassium": null, "fiber": 0.26, "sugar": 16.82, "vitamin_a": null, "vitamin_c": 2.66, "calcium": 22.64, "iron": 1.15}'::jsonb, ARRAY['american', 'antipasti', 'lunch', 'main course', 'starter', 'snack', 'appetizer', 'main dish', 'antipasto', 'hor d''oeuvre', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'grilling'], '[{"quantity": 700.0, "unit": "grams", "item": "chicken wings& drumettes", "notes": "700 grams chicken wings& drumettes", "category": "meat"}, {"quantity": 0.75, "unit": "cup", "item": "ketchup", "notes": "3/4 cup ketchup", "category": "condiments"}, {"quantity": 3.0, "unit": "tablespoons", "item": "smoky bbq sauce", "notes": "3 tablespoons smoky BBQ sauce", "category": "condiments"}, {"quantity": 2.0, "unit": "teaspoons", "item": "honey", "notes": "2 teaspoons honey", "category": "nut butters, jams, and honey"}, {"quantity": 0.5, "unit": "tablespoon", "item": "sesame oil", "notes": "1/2 tablespoon sesame oil", "category": "ethnic foods"}, {"quantity": 3.0, "unit": "drop", "item": "capsico sauce", "notes": "Few drop of Capsico sauce (or Tabasco sauce)", "category": "condiments"}, {"quantity": 4.0, "unit": "servings", "item": "oil", "notes": "Oil for deep fry", "category": "oil, vinegar, salad dressing"}]'::jsonb, '["Clean and wash chicken wings and drumettes in running water and pat dry.", "Heat oil in the pan over medium heat.", "When the oil is hot add chicken wings and fry for 3-4 minutes or until golden brown.", "Remove from the oil and keep aside.", "In another pan, mix ketchup, BBQ sauce, honey, sesame oil, and Capsico sauce. Stir over the medium flame for few minutes or until sticky and thicken.", "Add deep fried wings in the sauce and toss together until everything is coated with sauce.", "Serve hot with your favorite dips."]'::jsonb, 'https://www.foodista.com/recipe/Y4H5VXG4/easy-chicken-wings', 'https://img.spoonacular.com/recipes/641907-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('asian-salmon-burgers-with-tangy-ginger-lime-sauce', 'Asian Salmon Burgers With Tangy Ginger Lime Sauce', 4, 0, 0, '{"calories": 565, "protein": 27.62, "carbs": 23.13, "fat": 39.79, "saturated_fat": 6.46, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 646.13, "potassium": null, "fiber": 0.96, "sugar": 3.61, "vitamin_a": null, "vitamin_c": 2.07, "calcium": 89.04, "iron": 2.65}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'pescatarian', 'spoonacular'], '[{"quantity": 4.0, "unit": "", "item": "burger buns", "notes": "4 burger buns", "category": "bakery/bread"}, {"quantity": 1.0, "unit": "tablespoon", "item": "basil", "notes": "1 tablespoon Fresh Basil, Chopped (about 5 leaves worth)", "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": "1 clove Garlic", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "green onion", "notes": "1 Green Onion, Chopped", "category": "produce"}, {"quantity": 0.25, "unit": "", "item": "juice of lime", "notes": "1/4 Lime, Juiced", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "mayonnaise", "notes": "1/4 cup Mayonnaise", "category": "condiments"}, {"quantity": 1.0, "unit": "teaspoon", "item": "oyster sauce", "notes": "1 teaspoon Oyster Sauce", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "teaspoon", "item": "powdered ginger", "notes": "1/2 teaspoon Powdered Ginger", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "pound", "item": "salmon", "notes": "1 pound Salmon", "category": "seafood"}, {"quantity": 5.5, "unit": "tablespoons", "item": "sesame oil", "notes": "5 1/2 tablespoons Sesame Oil", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "tablespoons", "item": "cream", "notes": "2 tablespoons Sour Cream", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "soy sauce", "notes": "1 tablespoon Soy Sauce", "category": "ethnic foods"}]'::jsonb, '["Cut the salmon into large hunks and run it through a food processor until no large pieces remain.", "Add to the salmon the soy sauce, garlic, ginger, oyster sauce, green onion, and basil.", "Combine ingredients well and form 4 large patties from mixture.", "Heat up the sesame oil in a large frying pan on medium high heat and add in the patties. Cook for about 10 minutes flipping once half way through.To make the sauce, add together all the above listed ingredients and stir to combine.", "Pour a spoonful of sauce over the top of the finished salmon burger and serve inside a toasted bun."]'::jsonb, 'https://www.foodista.com/recipe/FRT38YTC/asian-salmon-burgers-with-tangy-ginger-lime-sauce', 'https://img.spoonacular.com/recipes/632874-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('an-american-beef-burger', 'An American Beef Burger', 4, 0, 0, '{"calories": 823, "protein": 39.49, "carbs": 76.67, "fat": 39.04, "saturated_fat": 13.17, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1103.55, "potassium": null, "fiber": 4.12, "sugar": 11.41, "vitamin_a": null, "vitamin_c": 13.44, "calcium": 149.49, "iron": 5.61}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'salad'], '[{"quantity": 550.0, "unit": "gr", "item": ".2 lb beef mince", "notes": "550gr / 1.2 lb good quality beef mince", "category": "meat"}, {"quantity": 4.0, "unit": "servings", "item": "egg", "notes": "1 x egg, beaten", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "large", "item": "garlic cloves", "notes": "2 x large garlic cloves, crushed", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "i x shallot", "notes": "I x large shallot, chopped finely", "category": "produce"}, {"quantity": 1.0, "unit": "pinch", "item": "salt and a nice grind of pepper", "notes": "A good pinch of salt and a nice grind of fresh black pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tbsp", "item": "sunflower oil", "notes": "1 x tbsp sunflower oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "servings", "item": "to serve", "notes": "To Serve", "category": "pasta and rice"}, {"quantity": 4.0, "unit": "", "item": "burger buns", "notes": "4 x burger buns, sliced in half", "category": "bakery/bread"}, {"quantity": 1.0, "unit": "small", "item": "onion thinly", "notes": "1 x small red onion sliced thinly", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "tomatoes", "notes": "2 x tomatoes, sliced", "category": "produce"}, {"quantity": 1.0, "unit": "leaves", "item": "the of 2 x little gem lettuce", "notes": "The leaves of 2 x little gem lettuce (or Cos / Romaine leaves)", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "pickled gherkins thinly", "notes": "2 x pickled gherkins sliced thinly, lengthwise", "category": "canned and jarred"}, {"quantity": 4.0, "unit": "servings", "item": "tomato ketchup and american mustard", "notes": "Tomato ketchup and yellow American mustard", "category": "condiments"}]'::jsonb, '["Place the meat, egg, garlic shallot, salt and pepper in a bowl and mix through with your hands. Do this until everything is as even as possible - you wouldn''t want to get a mouthful of onion or garlic!  Divide the burger mix into 4 equal parts.  Form each burger by rolling it into a ball in your hands and flatten a little, but keep them nice and thick.", "Heat the oil in a heavy bottomed pan, when hot, place the burgers in the pan. The heat should be medium/hot.", "The cooking time will depend on how thick you make your burger and how you like them cooked. I find that my burgers take about 4 to 6 minutes on each side for a burger that is about 3cm thick (just over an inch) for a medium result.", "When the burgers are cooked, lift them out of the pan and set aside. Take your burger buns and place them face down in the pan, toast them in the burger flavour for a minute or two on each side.", "To serve, place the little gem leaves on your bread, then the tomato, the burgers on top, lay over a couple of slices of pickle and some sliced raw onion on top."]'::jsonb, 'https://www.foodista.com/recipe/XVQW332P/an-american-beef-burger', 'https://img.spoonacular.com/recipes/632342-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('salmon-amaranth-burgers-with-radish-slaw', 'Salmon Amaranth Burgers with Radish Slaw', 6, 0, 0, '{"calories": 311, "protein": 23.16, "carbs": 33.85, "fat": 8.83, "saturated_fat": 1.38, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 704.25, "potassium": null, "fiber": 2.68, "sugar": 4.45, "vitamin_a": null, "vitamin_c": 9.51, "calcium": 111.33, "iron": 3.4}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'pescatarian', 'spoonacular', 'salad'], '[{"quantity": 500.0, "unit": "g", "item": "salmon filet", "notes": "500 g salmon filet, fresh or frozen, skinless and boneless", "category": "seafood"}, {"quantity": 1.0, "unit": "cup", "item": "amaranth", "notes": "1 cup cooked amaranth (rinsed and strained well)", "category": "health foods"}, {"quantity": 1.0, "unit": "tablespoon", "item": "horseradish sauce", "notes": "1 heaped tablespoon horseradish sauce", "category": "condiments"}, {"quantity": 3.0, "unit": "tablespoons", "item": "capers", "notes": "3 tablespoons capers", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tablespoons", "item": "breadcrumbs", "notes": "2 tablespoons breadcrumbs for coating and 2 for adding to the burger mixture", "category": "pasta and rice"}, {"quantity": 0.75, "unit": "teaspoon", "item": "sea salt", "notes": "3/4 teaspoon fine sea salt, plus plenty of black pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons olive oil for the slaw, plus a little more for frying", "category": "oil, vinegar, salad dressing"}, {"quantity": 250.0, "unit": "g", "item": "radish", "notes": "250 g radish, grated, sliced or spiralized", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "dill", "notes": "1 tablespoon dill, finely chopped", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "lemon juice", "notes": "2 tablespoons lemon juice", "category": "produce"}, {"quantity": 6.0, "unit": "", "item": "burger buns", "notes": "6 burger buns", "category": "bakery/bread"}]'::jsonb, '["If you are using frozen salmon filets leave them in a strainer to get rid of excess water and squeeze any remaining water out.Chop up the fish roughly and pulse in a blender to obtain a smooth mixture.  Season, add the amaranth, horseradish, breadcrumbs and stir well.  Fold in the capers.  Form thick (about 2 cm) burgers and coat in the remaining breadcrumbs.", "Heat up about 2 tablespoons of oil and fry the burgers for 3 minutes on each side on a low/medium heat.To make the radish slaw, grate, spiralize or finely slice the radishes, add the dill, lemon juice, oil and seasoning, and stir well to combine.", "Serve the burgers with the radish slaw in your favorite burger buns."]'::jsonb, 'https://www.foodista.com/recipe/JN6QMFDT/salmon-amaranth-burgers-with-radish', 'https://img.spoonacular.com/recipes/1095894-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('falafel-burgers', 'Falafel Burgers', 4, 0, 0, '{"calories": 709, "protein": 23.31, "carbs": 80.23, "fat": 35.46, "saturated_fat": 4.99, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1172.55, "potassium": null, "fiber": 14.4, "sugar": 1.79, "vitamin_a": null, "vitamin_c": 11.48, "calcium": 204.64, "iron": 7.06}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cans", "item": "garbanzo beans", "notes": "2 cans garbanzo beans (chickpeas), drained and rinsed", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "tablespoon", "item": "chili powder", "notes": "1 tablespoon chili powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "coriander", "notes": "1 tablespoon coriander", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "cumin", "notes": "1 tablespoon cumin", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "tablespoons", "item": "flour", "notes": "4 tablespoons flour", "category": "baking"}, {"quantity": 1.0, "unit": "large handful", "item": "parsley", "notes": "1 large handful parsley, chopped", "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves garlic, grated or finely chopped", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "juice of lemon", "notes": "2 Zest and juice of lemons", "category": "produce"}, {"quantity": 4.0, "unit": "", "item": "pita pockets", "notes": "4 pita pockets", "category": "bakery/bread"}, {"quantity": 1.0, "unit": "small", "item": "onion", "notes": "1 small red onion, chopped", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and pepper, to taste", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "tahini", "notes": "1/2 cup tahini", "category": "health foods"}, {"quantity": 1.5, "unit": "teaspoons", "item": "turmeric", "notes": "1 1/2 teaspoons turmeric", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "vegetable oil", "notes": "1/4 cup vegetable oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 3.0, "unit": "tablespoons", "item": "water", "notes": "3 tablespoons water", "category": "beverages"}]'::jsonb, '["Combine the chickpeas, onion, garlic, parsley, flour, spices, and salt, and pulse until the mixture is well combined. Form the mixture into 4 large patties.", "Whisk the tahini paste with the water, lemon juice and zest, salt, and freshly ground black pepper in a mixing bowl.", "Serve the burgers in pita pockets or on a bun. Top them with tahini sauce, lettuce, and tomato."]'::jsonb, 'https://www.foodista.com/recipe/FBWMX8MY/falafel-burgers', 'https://img.spoonacular.com/recipes/642540-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-red-pepper-and-white-bean-chili', 'Chicken, Red Pepper, and White Bean Chili', 6, 0, 0, '{"calories": 505, "protein": 44.43, "carbs": 43.29, "fat": 17.17, "saturated_fat": 4.86, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 839.53, "potassium": null, "fiber": 8.35, "sugar": 6.68, "vitamin_a": null, "vitamin_c": 23.31, "calcium": 247.4, "iron": 6.34}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'spoonacular'], '[{"quantity": 15.0, "unit": "ounce", "item": "canned tomatoes", "notes": "15 ounce can stewed tomato quarters and juice (canned diced tomatoes work, too)", "category": "canned and jarred"}, {"quantity": 30.0, "unit": "oz", "item": "cannellini beans", "notes": "2 15 oz cans Cannellini beans (also called white kidney beans)", "category": "canned and jarred"}, {"quantity": 3.0, "unit": "", "item": "chicken breasts", "notes": "3 boneless chicken breasts", "category": "meat"}, {"quantity": 5.0, "unit": "cups", "item": "chicken stock", "notes": "5 cups of chicken stock (or broth)", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "teaspoons", "item": "garlic", "notes": "2 cloves of garlic, minced (about 2 teaspoons)", "category": "spices and seasonings"}, {"quantity": 0.125, "unit": "teaspoon", "item": "ground cloves", "notes": "1/8 teaspoon ground cloves", "category": "spices and seasonings"}, {"quantity": 0.75, "unit": "teaspoon", "item": "ground cumin", "notes": "3/4 teaspoon ground cumin", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "tablespoons", "item": "olive oil", "notes": "3 tablespoons olive oil, divided", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "medium", "item": "onion", "notes": "1 medium onion, finely diced", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "oregano", "notes": "1 teaspoon oregano", "category": "produce"}, {"quantity": 1.0, "unit": "handful", "item": "parsley", "notes": "1 handful fresh parsley, chopped (reserve 3 whole leaves for garnish)", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "bell pepper", "notes": "1/2 red bell pepper, finely diced", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "salt", "notes": "salt, to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "mozzarella cheese", "notes": "1 cup shredded mozzarella cheese (for garnish)", "category": "cheese"}]'::jsonb, '["In a stockpot, heat 2 tablespoons of the olive oil over medium heat.", "Add the onion and saute until it''s soft and translucent, about 10 minutes.  (Try not to let the onion brown...turn down the heat if you have to.)Toss in the minced garlic and cook for another 4 minutes or so.", "Add the red bell pepper and cook for about 5-10 minutes.Reduce heat to low and cover.In a large skillet, heat remaining tablespoon of olive oil.", "Saute diced chicken until cooked through, about 15 minutes.  (Check a piece for \"doneness\"--no pink meat should be hiding in the middle.)", "Add in the tomatoes and juice and the green chilies (if using).Bring to a feisty simmer.", "Add in the beans.Return to a simmer.", "Add chicken stock to the stockpot.", "Pour in the chicken/tomato/bean mixture.", "Add cumin, oregano, cayenne pepper, and ground cloves to the pot.Taste it.", "Add salt if needed.Simmer over low heat for about 30-45 minutes.", "Add the chopped parsley 15 minutes before the end of the cooking time.", "Garnish each bowl with shredded cheese and a few whole parsley leaves."]'::jsonb, 'https://www.foodista.com/recipe/HYGDBGMT/chicken-red-pepper-and-white-bean-chili', 'https://img.spoonacular.com/recipes/638464-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('turkey-spinach-burgers-with-sweet-soy-ginger-sauce', 'Turkey-Spinach Burgers With Sweet Soy-Ginger Sauce', 4, 0, 0, '{"calories": 218, "protein": 28.82, "carbs": 11.88, "fat": 6.88, "saturated_fat": 0.98, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 850.03, "potassium": null, "fiber": 1.03, "sugar": 8.26, "vitamin_a": null, "vitamin_c": 10.89, "calcium": 49.35, "iron": 2.18}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'dessert'], '[{"quantity": 5.0, "unit": "ounce", "item": "baby spinach", "notes": "1 package (5-ounce) fresh baby spinach", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "pepper", "notes": "freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "canola oil", "notes": "1 tablespoon macadamia nut oil or canola oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tablespoons", "item": "brown sugar", "notes": "2 tablespoons dark brown sugar", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "ginger", "notes": "1 tablespoon minced fresh ginger", "category": "produce"}, {"quantity": 1.0, "unit": "pound", "item": "ground turkey", "notes": "1 pound Ground turkey", "category": "meat"}, {"quantity": 2.0, "unit": "tablespoons", "item": "mirin", "notes": "2 tablespoons mirin", "category": "ethnic foods"}, {"quantity": 4.0, "unit": "servings", "item": "salt", "notes": "Salt", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "tablespoons", "item": "scallions", "notes": "3 tablespoons sliced scallions for garnish, optional", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sesame oil", "notes": "1 teaspoon toasted sesame oil", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "tablespoons", "item": "soy sauce", "notes": "2 tablespoons soy sauce", "category": "ethnic foods"}]'::jsonb, '["In small saucepan, combine soy sauce, mirin, brown sugar, and ginger; bring to boil over medium-high heat, whisking to dissolve sugar. Reduce until slightly syrupy, about 3 minutes. Adjust heat, if necessary, to prevent boil-over.", "Remove from heat and allow to cool completely. (Sauce may be prepared up to 2 days in advance and refrigerated in a covered container.)Bring large pot of water to boil. Cook spinach for 1 minute.", "Drain and transfer to cold water bath to stop the cooking.", "Drain again. Dry thoroughly between layers of paper towels. (Spinach may be prepared up to 2 days in advance and refrigerated in covered container.)In large bowl, combine turkey, scallions, sesame oil, reserved spinach, and 1 tablespoon of reserved sauce. Season with salt and pepper and blend well without overworking.Form turkey-spinach mixture into 4 patties, about 3\" across and 1\" thick.", "Heat oil in large nonstick skillet over medium-high heat. When hot, add patties and cook about 5 minutes per side, until nicely browned and cooked through. Lower heat if necessary to prevent burning.", "Serve with some of the sauce spooned over.", "Garnish with the sliced scallions, if desired."]'::jsonb, 'https://www.foodista.com/recipe/CC4PQZMN/turkey-spinach-burgers-with-sweet-soy-ginger-sauce', 'https://img.spoonacular.com/recipes/664080-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('low-carb-brunch-burger', 'Low Carb Brunch Burger', 2, 0, 0, '{"calories": 1024, "protein": 53.8, "carbs": 17.58, "fat": 82.6, "saturated_fat": 27.03, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 735.91, "potassium": null, "fiber": 8.83, "sugar": 4.22, "vitamin_a": null, "vitamin_c": 105.96, "calcium": 108.73, "iron": 7.15}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'ketogenic', 'spoonacular', 'breakfast', 'baking'], '[{"quantity": 1.0, "unit": "", "item": "avocado", "notes": "1 avocado sliced", "category": "produce"}, {"quantity": 4.0, "unit": "strips", "item": "bacon", "notes": "4 strips bacon", "category": "meat"}, {"quantity": 2.0, "unit": "servings", "item": "cumin", "notes": "freshly ground cumin", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "servings", "item": "garlic powder", "notes": "garlic powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "lb", "item": "ground beef", "notes": "1 lb ground beef", "category": "meat"}, {"quantity": 2.0, "unit": "servings", "item": "onion powder", "notes": "onion powder", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "servings", "item": "bell pepper", "notes": "pepper", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "salt", "notes": "salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "large slices", "item": "sharp cheddar", "notes": "2 large slices sharp cheddar", "category": "cheese"}, {"quantity": 2.0, "unit": "dashes", "item": "tabasco sauce", "notes": "2 dashes Tabasco sauce", "category": "condiments"}, {"quantity": 2.0, "unit": "dashes", "item": "worcestershire sauce", "notes": "2 dashes Worcestershire sauce", "category": "condiments"}]'::jsonb, '["Fry up 4 strips of bacon and set aside.Leave some of the bacon fat in the pan but remove from the eye.Put all of the spices and sauces into the ground beef, mix well and form even patties.", "Heat a large non-stick skillet until the pan (with some of the bacon fat in it) is hot.", "Place patties in hot pan and sear for 1 minute and 30 seconds each side. After searing the burgers, remove them from stove top and bake off in the oven at 415 degrees until it reaches your desired temperature (3-4 minutes).While the burgers are in the oven, get your egg going. On the same hot eye where you did your burger, use a new non-stick pan for the eggs. On the two over easy eggs, grind 2 grinds of salt, 2 grinds of pepper and a dash of Tabasco onto each egg yolk.", "Add the cheese on the burgers when the burgers have about 1 minute of cook time remaining, so the cheese melts."]'::jsonb, 'https://www.foodista.com/recipe/5SPTY657/low-carb-brunch-burger', 'https://img.spoonacular.com/recipes/650377-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chili-garlic-stir-fry', 'Chili-Garlic Stir Fry', 6, 0, 0, '{"calories": 147, "protein": 14.72, "carbs": 12.47, "fat": 3.93, "saturated_fat": 0.71, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 391.22, "potassium": null, "fiber": 2.93, "sugar": 5.3, "vitamin_a": null, "vitamin_c": 89.59, "calcium": 45.9, "iron": 1.51}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'soup'], '[{"quantity": 2.0, "unit": "teaspoons", "item": "sesame oil", "notes": "2 teaspoons sesame oil, divided", "category": "ethnic foods"}, {"quantity": 12.0, "unit": "ounces", "item": "chicken breast", "notes": "12 ounces boneless, skinless chicken breast, cubed", "category": "meat"}, {"quantity": 4.0, "unit": "large stalks", "item": "bok choy", "notes": "4 large stalks bok choy, chopped (stalk and leaf divided)", "category": "produce"}, {"quantity": 8.0, "unit": "ounces", "item": "snow peas", "notes": "8 ounces snow peas", "category": "produce"}, {"quantity": 3.0, "unit": "medium", "item": "carrots", "notes": "3 mediums carrots, peeled and chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 yellow pepper, sliced", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "orange pepper", "notes": "1 orange pepper, sliced", "category": "produce"}, {"quantity": 3.0, "unit": "medium", "item": "green onions", "notes": "3 mediums green onions, white and green parts, chopped", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "sauce", "notes": "Sauce", "category": "condiments"}, {"quantity": 0.75, "unit": "cup", "item": "chicken broth", "notes": "3/4 cup low sodium chicken broth", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tablespoons", "item": "cooking sherry", "notes": "2 tablespoons cooking sherry", "category": "alcoholic beverages"}, {"quantity": 2.0, "unit": "teaspoons", "item": "cornstarch", "notes": "2 teaspoons cornstarch", "category": "baking"}, {"quantity": 2.0, "unit": "tablespoons", "item": "sriracha", "notes": "2 tablespoons Sriracha or other chili-garlic sauce", "category": "ethnic foods"}, {"quantity": 6.0, "unit": "cloves", "item": "garlic", "notes": "6 cloves garlic, minced", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sesame oil", "notes": "1 teaspoon sesame oil", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "serving", "item": "stir fry", "notes": "Stir fry", "category": "?"}, {"quantity": 6.0, "unit": "servings", "item": "stir fry", "notes": "Stir fry", "category": "?"}]'::jsonb, '["I a wok or large skillet, heat 1 teaspoon sesame oil over medium-high heat.", "Add chicken and saute until cooked through. Set aside and cover.", "In the same pan, heat 1 teaspoon sesame oil over medium-high heat.", "Add bok choy stalks (not the leaves), carrots and snow peas and saute until just tender. Set aside and cover.", "Meanwhile, in a medium bowl, combine broth, sherry, cornstarch and Sriracha.", "Heat final teaspoon sesame oil over medium high heat and add garlic.", "Saute until fragrant, 30 seconds to 1 minute.", "Add sauce and bring to a boil. Stir until it thickens then add chicken, veggies, bok choy leaves and green onion. Stir until all are coated and heated through."]'::jsonb, 'https://www.foodista.com/recipe/7B6SJL27/chili-garlic-stir-fry', 'https://img.spoonacular.com/recipes/638586-312x231.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('amazing-chicken-burgers', 'Amazing Chicken Burgers', 3, 0, 0, '{"calories": 416, "protein": 36.44, "carbs": 17.19, "fat": 22.54, "saturated_fat": 7.94, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1288.4, "potassium": null, "fiber": 1.86, "sugar": 1.76, "vitamin_a": null, "vitamin_c": 19.63, "calcium": 224.25, "iron": 2.94}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'grilling'], '[{"quantity": 1.0, "unit": "cup", "item": "baby spinach", "notes": "1 cup loosely packed finely chopped baby spinach", "category": "produce"}, {"quantity": 3.0, "unit": "servings", "item": "mozzarella", "notes": "fresh mozzarella", "category": "cheese"}, {"quantity": 1.0, "unit": "lb", "item": "ground chicken", "notes": "1 lb lean ground chicken", "category": "meat"}, {"quantity": 0.5, "unit": "cup", "item": "seasoned bread crumbs", "notes": "1/2 cup Italian seasoned bread crumbs", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.5, "unit": "Tbsp", "item": "pesto", "notes": "1 1/2- 2 Tbsp pesto", "category": "pasta and rice"}, {"quantity": 0.75, "unit": "cup", "item": "roasted peppers", "notes": "3/4 cup finely chopped roasted peppers", "category": "canned and jarred"}, {"quantity": 3.0, "unit": "servings", "item": "salt & pepper", "notes": "salt & pepper", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "servings", "item": "grain sandwich thins", "notes": "whole grain sandwich thins", "category": "bread"}]'::jsonb, '["In a bowl mix together the chicken, spinach, roasted peppers, pesto, bread crumbs, salt and pepper.Form into 3 equal sized patties.Cook on a hot grill pan for about 5-6 mins per side, depending on thickness and temp of the grill (pan), or until the juices run clear. Top with fresh mozzarella and place a bowl overtop to allow the steam to melt the cheese."]'::jsonb, 'https://www.foodista.com/recipe/J6B7KZJP/amazing-chicken-burgers', 'https://img.spoonacular.com/recipes/632300-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('la-bella-italian-turkey-burger', 'La Bella Italian Turkey Burger', 4, 0, 0, '{"calories": 845, "protein": 63.94, "carbs": 33.43, "fat": 51.4, "saturated_fat": 15.72, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2451.69, "potassium": null, "fiber": 3.92, "sugar": 8.97, "vitamin_a": null, "vitamin_c": 80.98, "calcium": 447.55, "iron": 15.64}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'salad', 'grilling'], '[{"quantity": 1.0, "unit": "pinch", "item": "pepper", "notes": "a pinch of black pepper", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "", "item": "burger buns", "notes": "4 burger buns", "category": "bakery/bread"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "extra virgin olive oil", "notes": "1 tablespoon extra virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "tablespoons", "item": "extra virgin olive oil", "notes": "4 tablespoons extra virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "cup", "item": "basil", "notes": "1 cup finely chopped fresh basil", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "basil", "notes": "finely chopped fresh basil (remaining cup)", "category": "produce"}, {"quantity": 8.0, "unit": "ounces", "item": "mozzarella", "notes": "8 ounces of fresh mozzarella", "category": "cheese"}, {"quantity": 1.0, "unit": "tablespoon", "item": "rosemary", "notes": "1 tablespoon finely chopped fresh rosemary", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "garlic", "notes": "1 tablespoon fresh garlic", "category": "produce"}, {"quantity": 1.0, "unit": "pound", "item": "ground turkey", "notes": "1 pound ground turkey", "category": "meat"}, {"quantity": 1.0, "unit": "pound", "item": "turkey sausage", "notes": "1 pound sweet Italian turkey sausage (usually found in links)", "category": "meat"}, {"quantity": 1.0, "unit": "tablespoon", "item": "mayonnaise", "notes": "1 tablespoon mayonnaise", "category": "condiments"}, {"quantity": 1.0, "unit": "tablespoon", "item": "oregano", "notes": "1 tablespoon finely chopped dry oregano", "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "pepper", "notes": "1/2 tsp pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "pine nuts", "notes": "2 tablespoons pine nuts – toasted", "category": "baking"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 red bell pepper sliced", "category": "produce"}, {"quantity": 0.25, "unit": "teaspoon", "item": "salt", "notes": "1/4 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "spinach leaves", "notes": "1 cup spinach leaves (remove stems)", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "thyme", "notes": "1 tablespoon finely chopped dry thyme", "category": "produce"}]'::jsonb, '["Mix first 8 ingredients together thoroughly then add salt &amp; pepper and olive oil. Form 8 thin patties with the meat mixture.", "Cut mozzarella into 1/4 inch pieces. On top of one patty, scatter 4-5 mozzarella pieces throughout the center of the meat leaving a little space between each cube. Be careful not to put cheese too close to the edges or it will leak out during grilling.", "Place another patty on top and seal edges together until cheese is completely buried.", "Cut off the top of the red bell pepper and remove seeds and core. Then slice into 1/4 rings and brush lightly with olive oil.Pesto Sauce:  In a dry frying pan, quickly toast the pine nuts. Should take less than 3 minutes. In a food processor, pulse basil leaves, toasted pine nuts and salt &amp; pepper. simultaneously adding olive oil through the feed tube. Once good puree is achieved, add the mayo and pulse 2-3 more times, scraping sides to make sure its thoroughly mixed. Cook burgers meat over low to medium heat. Be sure to coat grill with non-stick spray. Cook about 8-10 minutes on each side. Try not to flip the burger too often as it tends to crumble. If the mozzarella starts to ooze out, don''t worry... that''s a sign that your burger is almost done.", "Place red pepper rings on the upper or outer edges of grill. Cook 2-3 minutes on each side.", "Brush olive oil on the insides of both halves of the sourdough buns and also place on the upper or outer edges of grill.", "Remove when lightly toasted.", "Spread pesto sauce on top &amp; bottom bun. place spinach leaves on bottom bun and place meat on top of spinach leaves.", "Garnish top of meat with grilled red bell pepper, fold the halves together and you have La Bella Burger!"]'::jsonb, 'https://www.foodista.com/recipe/PLJM7MZK/la-bella-burger', 'https://img.spoonacular.com/recipes/649141-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('almost-guilt-free-mac-and-cheese', 'Almost Guilt Free Mac and Cheese', 8, 0, 0, '{"calories": 585, "protein": 38.13, "carbs": 38.12, "fat": 30.93, "saturated_fat": 15.47, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 863.8, "potassium": null, "fiber": 3.53, "sugar": 5.86, "vitamin_a": null, "vitamin_c": 43.62, "calcium": 600.69, "iron": 2.66}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'pasta', 'baking'], '[{"quantity": 0.5, "unit": "pound", "item": "cellantani pasta", "notes": "1/2 pound Cellantani Pasta (elbow macaroni or small shells pasta)", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "medium Head", "item": "cauliflower", "notes": "1 medium Head Cauliflower (chopped and roasted)", "category": "produce"}, {"quantity": 1.0, "unit": "pound", "item": "chicken breast", "notes": "1 pound Chicken Breast (sauteed and diced)", "category": "meat"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons Olive Oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 5.0, "unit": "tablespoons", "item": "butter", "notes": "5 tablespoons Butter (divided)", "category": "milk, eggs, other dairy"}, {"quantity": 3.0, "unit": "tablespoons", "item": "flour", "notes": "3 tablespoons Flour", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "coleman''s mustard", "notes": "1 tablespoon Coleman''s Prepared Mustard (could also use Dijon mustard)", "category": "condiments"}, {"quantity": 3.0, "unit": "cups", "item": "soy milk", "notes": "3 cups Soy Milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "medium", "item": "onion", "notes": "1 medium Yellow Onion (finely diced)", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "bay leaves", "notes": "2 Bay Leaves", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "paprika", "notes": "1/2 teaspoon Paprika", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "", "item": "juice of lemon", "notes": "1/2 Lemon (juiced)", "category": "produce"}, {"quantity": 0.25, "unit": "teaspoon", "item": "thyme", "notes": "1/4 teaspoon Thyme", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "garlic powder", "notes": "1/2 teaspoon Garlic Powder", "category": "spices and seasonings"}, {"quantity": 0.125, "unit": "teaspoon", "item": "szechuan peppers", "notes": "1/8 teaspoon Szechuan Peppers (ground - can use more to taste)*", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 Eggs", "category": "milk, eggs, other dairy"}, {"quantity": 5.0, "unit": "ounces", "item": "goat cheese", "notes": "5 ounces Goat Cheese", "category": "cheese"}, {"quantity": 5.0, "unit": "ounces", "item": "parmesan cheese", "notes": "5 ounces Shredded Parmesan Cheese", "category": "cheese"}, {"quantity": 6.0, "unit": "ounces", "item": "emmental cheese", "notes": "6 ounces Shredded Emmental Cheese (or Swiss cheese)", "category": "cheese"}, {"quantity": 1.0, "unit": "cup", "item": "panko bread crumbs", "notes": "1 cup Panko Bread Crumbs (or other bread crumbs)", "category": "baking"}, {"quantity": 8.0, "unit": "servings", "item": "kosher salt", "notes": "Kosher Salt", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "servings", "item": "ground pepper", "notes": "Fresh Ground Black Pepper", "category": "spices and seasonings"}]'::jsonb, '["Preheat oven to 425 degrees Farenheit.", "For Roasted Cauliflower", "Clean core and leaves from cauliflower (you do not have to have any precision when doing this).  Chop cauliflower into pieces.  Pieces should be roughly 1/2\" - 3/4\".", "Place chopped cauliflower pieces onto a baking sheet.", "Drizzle olive oil over top of cauliflower and mix to thoroughly coat pieces.", "After 20 minutes, toss cauliflower pieces to brown all sides.", "Bake for another 20 minutes or until edges are browned.", "Remove from oven and lower temperature to 350 degrees Farenheit.", "For Macaroni and Cheese", "In a large pot of boiling and salted water, cook pasta until it is al dente.  Once done, drain.", "In another large saucepan, over medium high heat, melt 3 tablespoons of butter.  Once melted, whisk in flour.  Keep whisking to ensure that there are no lumps.  After 5-7 minutes, the butter and flour mixture should be a light caramel color.", "Add the soy milk, bay leaves, paprika, lemon juice, thyme, garlic powder and Szechuan pepper.  Stir occasionally for 10 - 15 minutes.  The mixture should thicken up.", "Remove bay leaves.", "In a medium size bowl thoroughly mix eggs.  Using a 1/4 cup measuring cup, slowly add milk mixture to eggs (temper the eggs).  While adding the hot mixture to the eggs, make sure that you keep whisking.  Once you have roughly 2 cups of the soy milk mixture in with the eggs, dump everything into the main saucepan and stir.", "Add in 3/4 of the shredded cheeses, and all of the goat cheese, and stir to combine.", "Add in the cooked, diced chicken and roasted cauliflower.  Once these are combined, add the cooked pasta and stir thoroughly.", "Season with salt and pepper.", "Pour into a 9\"x13\" baking pan.", "Cover with remaining cheese.", "Melt 2 tablespoons of butter in a saute pan.", "Add panko bread crumbs and stir to coat all of the crumbs with butter.", "Top the mac and cheese with the panko crumbs and bake for 30 minutes.", "Let rest for 15-20 minutes before serving.", "If you really want to kick up the heat factor in this, you can add tablespoon of Sriracha hot sauce to the mix."]'::jsonb, 'https://www.foodista.com/recipe/PKMRS8DL/almost-guilt-free-mac-and-cheese', 'https://img.spoonacular.com/recipes/632213-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('healthy-cauliflower-soup-with-bacon-and-chili-oil', 'Healthy Cauliflower Soup with Bacon and Chili Oil', 4, 0, 0, '{"calories": 301, "protein": 17.68, "carbs": 19.69, "fat": 18.87, "saturated_fat": 4.94, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 564.86, "potassium": null, "fiber": 7.14, "sugar": 7.23, "vitamin_a": null, "vitamin_c": 111.67, "calcium": 105.89, "iron": 2.33}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'paleolithic', 'primal', 'whole 30', 'spoonacular', 'breakfast', 'baking'], '[{"quantity": 1.0, "unit": "large head", "item": "cauliflower", "notes": "1 large head cauliflower", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "servings", "item": "sea salt", "notes": "Kosher salt or sea salt", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "pepper", "notes": "Freshly ground pepper", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "slices", "item": "bacon", "notes": "3 slices thick-cut bacon", "category": "meat"}, {"quantity": 2.0, "unit": "", "item": "anchovies", "notes": "2 anchovies", "category": "seafood"}, {"quantity": 1.0, "unit": "small", "item": "fennel bulb", "notes": "1 small fennel bulb chopped", "category": "produce"}, {"quantity": 1.0, "unit": "small", "item": "leek", "notes": "1 small leek chopped", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "garlic cloves", "notes": "2 garlic cloves chopped", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "ground coriander", "notes": "1 tablespoon ground coriander", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "cups", "item": "bone broth", "notes": "4 cups Bone Broth", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "", "item": "bay leaves", "notes": "2 bay leaves", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "paprika", "notes": "½ teaspoon smoked paprika", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "chili powder", "notes": "¼ teaspoon red chili powder", "category": "spices and seasonings"}]'::jsonb, '["Chop vegetables and garlic.", "Heat the oven to 400F. On a baking sheet, toss the chopped cauliflower with 1 tablespoon of the olive oil and season with salt and pepper.", "Transfer to the oven and roast, tossing once, until florets are browned all over and tender, 20 to 25 minutes.Meanwhile, in a large pot or large saucepan over medium heat, add the bacon, flipping occasionally, until browned and crisp, 6 to 8 minutes.", "Transfer to paper towels, but reserve the bacon fat in the pot. Once the bacon cools, chop very finely.In the same pot over medium heat, add the anchovies, fennel, leek, and garlic to the bacon fat and cook until the onion and fennel are very soft, 8 to 10 minutes. Stir in the coriander and cook until fragrant, about 1 minute.", "Add the roasted cauliflower, broth, bay leaves and 1 cup water. Season with salt and pepper. Bring to a boil, reduce heat, and cook at a high simmer until the cauliflower is very tender, 10 to 15 minutes.Discard the bay leaves and let cool slightly.In a blender or immersion blender, pure the cauliflower mixture until very smooth.Meanwhile, make the chili oil. Wipe out the pot used to make the cauliflower soup. Over very low heat, add the remaining olive oil, paprika, and chili powder and warm until fragrant, about 1 minute.Ladle the delicious soup into bowls and top with bacon bits and chili oil."]'::jsonb, 'https://www.foodista.com/recipe/CBPKBPB5/healthy-cauliflower-soup-with-bacon-and-chili-oil', 'https://img.spoonacular.com/recipes/1096216-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('instant-pot-chili', 'Instant Pot Chili', 6, 5, 15, '{"calories": 318, "protein": 27.18, "carbs": 38.35, "fat": 7.71, "saturated_fat": 2.32, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1057.05, "potassium": null, "fiber": 11.63, "sugar": 11.57, "vitamin_a": null, "vitamin_c": 35.19, "calcium": 132.99, "iron": 6.87}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'quick', 'instant-pot'], '[{"quantity": 0.5, "unit": "cup", "item": "onion", "notes": "1/2 cup onion chopped", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "bell pepper", "notes": "1/2 cup bell pepper red, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "lb", "item": "ground beef extra", "notes": "1 lb ground beef extra lean", "category": "meat"}, {"quantity": 0.75, "unit": "cup", "item": "beef broth", "notes": "3/4 cup beef broth", "category": "canned and jarred"}, {"quantity": 28.0, "unit": "oz", "item": "tomatoes", "notes": "28 oz crushed tomatoes", "category": "canned and jarred"}, {"quantity": 15.0, "unit": "oz", "item": "tomato sauce", "notes": "15 oz tomato sauce", "category": "canned and jarred"}, {"quantity": 15.0, "unit": "oz", "item": "kidney beans", "notes": "15 oz kidney beans canned, drained", "category": "canned and jarred"}, {"quantity": 15.0, "unit": "oz", "item": "pinto beans", "notes": "15 oz pinto beans canned, drained", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "tbsp", "item": "olive oil", "notes": "1 tbsp olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.25, "unit": "tsp", "item": "cayenne pepper", "notes": "1/4 tsp cayenne pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tsp", "item": "garlic powder", "notes": "2 tsp garlic powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "oregano", "notes": "1/2 tsp oregano", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "ground pepper", "notes": "1 tsp ground black pepper", "category": "spices and seasonings"}, {"quantity": 1.5, "unit": "tsp", "item": "cumin", "notes": "1 1/2 tsp cumin", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tbsp", "item": "chili powder", "notes": "1/2 tbsp chili powder", "category": "spices and seasonings"}]'::jsonb, '["Set the Instant Pot to Sauté mode and allow it to warm up for a couple of minutes.", "Add olive oil, onion, and bell pepper. Sauté for 2-3 minutes.", "Add ground beef and stir well. Make sure to stir constantly and to scrape off any brown bits that may be sticking to the bottom while browning the beef.", "Hit the off button on the Instant Pot 2 times.", "Pour in the tomatoes, tomato sauce, kidney beans, pinto beans, seasonings, and beef broth and stir.", "Mix the ingredients well.", "Secure the lid in place and seal the vent.", "Press manual and cook on high for 15 minutes. Allow a natural release for 10 – 20 minutes.", "Remove the lid and stir well. Allow the chili to cool slightly before serving. Ingredients will be HOT just after cooking."]'::jsonb, 'https://www.pinkwhen.com/instant-pot-chili/', 'https://img.spoonacular.com/recipes/1178323-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chili-con-carne-thatll-make-your-taste-buds-go-silly', 'Chili con Carne that''ll make your taste buds go silly', 4, 15, 135, '{"calories": 795, "protein": 74.65, "carbs": 58.3, "fat": 30.93, "saturated_fat": 12.36, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1691.27, "potassium": null, "fiber": 18.99, "sugar": 16.32, "vitamin_a": null, "vitamin_c": 59.96, "calcium": 432.36, "iron": 13.66}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'spoonacular'], '[{"quantity": 2.0, "unit": "lbs", "item": "ground beef", "notes": "2 lbs lean ground beef (85/15)", "category": "meat"}, {"quantity": 2.0, "unit": "Tbsp", "item": "vegetable oil", "notes": "2 Tbsp vegetable oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "medium", "item": "shallots", "notes": "2 shallots (or one medium onion), chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 bell pepper, chopped", "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves garlic, chopped", "category": "produce"}, {"quantity": 2.0, "unit": "c", "item": "beef stock", "notes": "2 c beef stock (or 1 c beef stock + 1 c red wine)", "category": "canned and jarred"}, {"quantity": 32.0, "unit": "oz", "item": "kidney beans", "notes": "2 (16-oz) can kidney beans, drained and rinsed", "category": "canned and jarred"}, {"quantity": 28.0, "unit": "oz", "item": "canned tomatoes", "notes": "1 (28-oz) can plum tomatoes", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "Tbsp", "item": "chili powder", "notes": "2 Tbsp chili powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "Tbsp", "item": "oregano", "notes": "1 Tbsp dried oregano", "category": "produce"}, {"quantity": 1.0, "unit": "Tbsp", "item": "ground cumin", "notes": "1 Tbsp ground cumin", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "ground cayenne pepper", "notes": "1/2 tsp ground cayenne pepper", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and pepper to taste", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "toppings", "notes": "Toppings, like shredded cheddar cheese, sour cream, sliced green onions (scallions), Saltine crackers, sliced jalapeños, etc. ", "category": "cheese"}]'::jsonb, '["Heat 2 Tbsp vegetable oil over medium heat. ", "Add ground beef and brown it, using a wooden spoon to break it up for about 8 minutes. ", "Season with a pinch of salt and pepper. Taste it. ", "Add chopped shallots (or onion), bell pepper, and garlic, and cook for another 5 minutes. ", "Add 2 cups of beef stock OR 1 cup of red wine and 1 cup of beef stock. ", "Add drained beans and tomatoes (which I don’t drain), and all the spices. ", "Stir and bring to a boil for a couple of minutes. ", "Reduce heat to a simmer. At this point, it’s a good idea to taste again. Make sure the spices are balanced. Don’t worry about adding salt yet if it tastes under-salted. You might add more beef stock later, which will add more salt. ", "Cover and cook on low heat (when you lift the lid, it should just bubble but not boil) for about two hours. ", "Check and stir occasionally. If it gets too dry, add more beef stock. ", "Tip: If you can’t wait any longer or your chili is too runny after simmering for two hours, just remove the lid, crank up the heat and let it reduce to your desired thickness. Just make sure to stir regularly so the meat doesn’t get stuck to the bottom of the pan.  ", "Add toppings.", "Serve and enjoy!"]'::jsonb, 'https://maplewoodroad.com/chili-con-carne/', 'https://img.spoonacular.com/recipes/1697611-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('instant-pot-chili-mac', 'Instant Pot Chili Mac', 6, 10, 4, '{"calories": 565, "protein": 38.84, "carbs": 60.24, "fat": 19.64, "saturated_fat": 9.55, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1084.23, "potassium": null, "fiber": 9.21, "sugar": 10.76, "vitamin_a": null, "vitamin_c": 39.74, "calcium": 393.76, "iron": 6.58}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'soup', 'pasta', 'quick', 'instant-pot'], '[{"quantity": 1.0, "unit": "tbsp", "item": "olive oil", "notes": "1 tbsp olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "lb", "item": "ground beef", "notes": "1 lb ground beef lean", "category": "meat"}, {"quantity": 1.0, "unit": "medium", "item": "onion", "notes": "1 onion medium", "category": "produce"}, {"quantity": 1.0, "unit": "medium", "item": "bell pepper", "notes": "1 bell pepper red, medium", "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "cayenne pepper", "notes": "1/2 tsp cayenne pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "garlic powder", "notes": "1 tsp garlic powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tbsp", "item": "cumin", "notes": "1 tbsp cumin", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tbsp", "item": "chili powder", "notes": "1 tbsp chili powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "pepper", "notes": "1 tsp black pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "pepper", "notes": "1 tsp white pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "oregano", "notes": "1 tsp oregano", "category": "produce"}, {"quantity": 3.0, "unit": "cups", "item": "chicken broth", "notes": "3 cups chicken broth", "category": "canned and jarred"}, {"quantity": 28.0, "unit": "oz", "item": "tomatoes", "notes": "28 oz crushed tomatoes", "category": "canned and jarred"}, {"quantity": 14.0, "unit": "oz", "item": "kidney beans", "notes": "14 oz red kidney beans canned, drained", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "cups", "item": "monterrey jack cheese", "notes": "2 cups Monterrey Jack Cheese", "category": "cheese"}, {"quantity": 2.0, "unit": "cups", "item": "elbow macaroni", "notes": "2 cups elbow macaroni uncooked", "category": "pasta and rice"}]'::jsonb, '["Turn on the pressure cooker and place on sauté mode. Once heated, add the olive oil, onion, and bell pepper. Sauté for 3 minutes.", "Add in the ground beef and continue to stir until the beef is thoroughly cooked.", "Add in the seasonings. Stir.", "Add crushed tomatoes and kidney beans and mix well.", "Pour in chicken broth and macaroni noodles. Stir the mixture until well combined.", "Hit the cancel button on the Instant Pot.", "Securely place the lid on the pressure cooker and lock the lid in place. Set the vent to seal and start the manual cook time for 4 minutes.", "Once the cooking time is finished, carefully place the valve to vent and allow the pressure pin to drop before unlocking the lid to the Instant Pot.", "Remove the lid and stir the chili mac recipe well.", "Mix in the cheese.", "Add your favorite toppings and serve."]'::jsonb, 'https://www.pinkwhen.com/instant-pot-chili-mac/', 'https://img.spoonacular.com/recipes/1165787-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('crunchy-panko-breaded-shrimp-with-sour-cream-and-chili-garlic-sauce', 'Crunchy Panko Breaded Shrimp With Sour Cream and Chili Garlic Sauce', 2, 0, 0, '{"calories": 288, "protein": 34.8, "carbs": 21.76, "fat": 6.71, "saturated_fat": 3.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 591.97, "potassium": null, "fiber": 1.1, "sugar": 2.1, "vitamin_a": null, "vitamin_c": 1.56, "calcium": 188.93, "iron": 1.87}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'pescatarian', 'spoonacular', 'soup', 'baking'], '[{"quantity": 2.0, "unit": "servings", "item": "chili garlic sauce", "notes": "chili garlic sauce to taste (hot!)", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "large", "item": "egg white", "notes": "1 large egg white", "category": "milk, eggs, other dairy"}, {"quantity": 0.125, "unit": "cup", "item": "flour", "notes": "1/8 cup flour", "category": "baking"}, {"quantity": 0.25, "unit": "", "item": "juice of lime", "notes": "1/4 medium lime, juiced", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "panko bread crumbs", "notes": "1/2 cup panko bread crumbs", "category": "baking"}, {"quantity": 10.0, "unit": "ounces", "item": "ez peel shrimp", "notes": "10 ounces EZ Peel White Shrimp", "category": "seafood"}, {"quantity": 8.0, "unit": "tablespoons", "item": "cream", "notes": "8 tablespoons light sour cream", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "water", "notes": "1 tablespoon water", "category": "beverages"}]'::jsonb, '["Preheat oven to 400.Peel shrimp leaving tails on, and dry on paper towel.Whip egg white with water, and place flour, egg white and panko bread crumbs in separate bowls.Spray cookie sheet with cooking spray.Dip shrimp in flour, then egg white, and then panko and place on cookie sheet.Spray the tops of shrimp with cooking spray and bake for 5  7 minutes until shrimp just curls. Do not over bake, or you will have tough shrimp.Prepare sauce by combining lime juice, sour cream and chili garlic sauce.", "Serve with sauce."]'::jsonb, 'https://www.foodista.com/recipe/FLKS8RTD/crunchy-panko-breaded-shrimp-with-sour-cream-and-chili-garlic-sauce', 'https://img.spoonacular.com/recipes/640953-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('coriander-chili-monkfish-cheeks-stir-fry', 'Coriander & Chili Monkfish Cheeks Stir-Fry', 3, 0, 0, '{"calories": 250, "protein": 17.77, "carbs": 7.02, "fat": 16.8, "saturated_fat": 1.68, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 491.28, "potassium": null, "fiber": 0.8, "sugar": 1.89, "vitamin_a": null, "vitamin_c": 2.83, "calcium": 26.39, "iron": 0.99}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'pescatarian', 'spoonacular', 'dessert', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "cup", "item": "chicken stock", "notes": "1 cup chicken stock", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "bunch", "item": "coriander", "notes": "1 bunch coriander", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "corn flour", "notes": "1 tablespoon Corn flour", "category": "baking"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves garlic (minced)", "category": "produce"}, {"quantity": 300.0, "unit": "grams", "item": "monkfish cheeks", "notes": "300 grams Monkfish cheeks", "category": "seafood"}, {"quantity": 3.0, "unit": "servings", "item": "oil", "notes": "Oil, enough for shallow-frying and reserve some for stir-frying", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "teaspoons", "item": "chili flakes", "notes": "2 teaspoons Red chili (chopped) or dried chili flakes", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "soya sauce", "notes": "1 tablespoon Soya sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "pinch", "item": "sugar", "notes": "pinch of sugar", "category": "baking"}]'::jsonb, '["Lightly coat monkfish cheeks with corn flour.Then, shallow-fry the monkfish cheeks in hot oil until slightly brown.", "Drain and set aside.Chop the garlic and coriander together.Stir-fry the chopped garlic and coriander until slightly brown, and add together the chopped chili or chili flakes and all remaining ingredients.Lastly, put in monkfish cheeks and mix well.", "Garnish with some coriander and  serve warm."]'::jsonb, 'https://www.foodista.com/recipe/RTCXCX6G/coriander-chili-monkfish-cheeks-stir-fry', 'https://img.spoonacular.com/recipes/640054-312x231.jpg', TRUE, 1, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('crock-pot-chili-with-beans', 'Crock Pot Chili with Beans', 12, 0, 0, '{"calories": 311, "protein": 28.56, "carbs": 17.06, "fat": 14.42, "saturated_fat": 7.16, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 708.92, "potassium": null, "fiber": 4.43, "sugar": 3.42, "vitamin_a": null, "vitamin_c": 4.69, "calcium": 268.13, "iron": 3.18}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'spoonacular', 'slow-cooker'], '[{"quantity": 1.0, "unit": "pound", "item": "pinto beans", "notes": "1 pound pinto beans, soaked overnight in water, drained and rinsed", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "pounds", "item": "you can use stew meat in a pinch", "notes": "2 pounds chili meat – or you can use stew meat in a pinch.", "category": "meat"}, {"quantity": 2.0, "unit": "cups", "item": "beef broth", "notes": "2 cups beef broth", "category": "canned and jarred"}, {"quantity": 14.0, "unit": "ounce", "item": "canned tomatoes", "notes": "1 14-ounce can diced tomatoes", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "cup", "item": "onions", "notes": "1/2 cup diced onions", "category": "produce"}, {"quantity": 1.0, "unit": "package", "item": "chili seasoning", "notes": "1 package chili seasoning", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "ketchup", "notes": "1/4 cup ketchup", "category": "condiments"}, {"quantity": 2.0, "unit": "tablespoons", "item": "onion powder", "notes": "2 tablespoons onion powder", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "worcestershire sauce", "notes": "2 tablespoons Worcestershire sauce", "category": "condiments"}, {"quantity": 1.0, "unit": "tablespoon", "item": "garlic powder", "notes": "1 tablespoon garlic powder", "category": "spices and seasonings"}, {"quantity": 12.0, "unit": "servings", "item": "additional salt and pepper", "notes": "Additional salt and pepper as needed", "category": "spices and seasonings"}, {"quantity": 12.0, "unit": "servings", "item": "to serve: cheese", "notes": "To Serve: shredded cheese, sour cream, Fritos chips, cornbread, crackers, or tortillas", "category": "cheese"}]'::jsonb, '["Soak Pinto beans overnight in water, drain and rinse the next morning.", "Next add diced onions and tomatoes.", "Add chili meat and seasoning packet along with onion powder and garlic powder, stir to mix. Then pour in beef broth. Two cups is plenty  you wont completely cover your beans and meat, but during cooking the meat will release quite a bit of juice and fat, adding to the liquid content. We want to make chili, not soup.", "Cook on high for two hours in the Crock Pot.", "Add ketchup and Worcestershire sauce, stir to mix well. Reduce heat to low and continue to cook for 6-8 hours, stirring every couple of hours. Taste an hour or so before serving time and add salt and pepper if needed.", "I love to serve our chili with a batch of Christy Jordans Dixie Cornbread. Its the best cornbread Ive ever eaten."]'::jsonb, 'https://www.foodista.com/recipe/B3R7M7SZ/crock-pot-chili-with-beans', 'https://img.spoonacular.com/recipes/640859-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('loaded-turkey-burgers', 'Loaded Turkey Burgers', 6, 0, 0, '{"calories": 611, "protein": 39.8, "carbs": 28.6, "fat": 37.43, "saturated_fat": 10.64, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1026.82, "potassium": null, "fiber": 1.28, "sugar": 4.49, "vitamin_a": null, "vitamin_c": 4.32, "calcium": 186.89, "iron": 3.08}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'breakfast', 'baking'], '[{"quantity": 0.33333334, "unit": "c", "item": "breadcrumbs", "notes": "1/3 c. dry breadcrumbs (such as panko)", "category": "pasta and rice"}, {"quantity": 0.25, "unit": "t", "item": "garlic powder", "notes": "1/4 t. garlic powder", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "t", "item": "ground pepper", "notes": "1/4 t. ground black pepper", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "", "item": "hamburger buns", "notes": "6 hamburger buns", "category": "bakery/bread"}, {"quantity": 1.0, "unit": "T", "item": "ketchup", "notes": "1 T. ketchup", "category": "condiments"}, {"quantity": 1.5, "unit": "lb", "item": "ground turkey", "notes": "1 1/2 lb. (93% lean) ground turkey", "category": "meat"}, {"quantity": 0.25, "unit": "t", "item": "onion powder", "notes": "1/4 t. onion powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "roasted pepper", "notes": "1 roasted red pepper, chopped (fresh or jarred)", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "t", "item": "salt", "notes": "1/2 t. salt", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "oz", "item": "sharp cheddar cheese", "notes": "3 oz. sharp cheddar cheese, cut into 1/4-inch cubes", "category": "cheese"}, {"quantity": 3.0, "unit": "drops", "item": "tabasco", "notes": "3 drops of Tabasco", "category": "condiments"}, {"quantity": 6.0, "unit": "slices", "item": "center cut bacon", "notes": "6 slices center cut bacon, cooked crisp and crumbled", "category": "meat"}, {"quantity": 6.0, "unit": "servings", "item": "vegetable oil", "notes": "vegetable oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "tablespoon", "item": "worcestershire sauce", "notes": "1 tablespoon Worcestershire sauce", "category": "condiments"}, {"quantity": 1.0, "unit": "T", "item": "mustard", "notes": "1 T. yellow mustard", "category": "condiments"}]'::jsonb, '["Preheat oven to 375 degrees f. In a large bowl, mix together ground turkey, Worcestershire, mustard, ketchup, Tabasco, garlic &amp; onion powders, salt, pepper and breadcrumbs.", "Add the roasted pepper, cheese and bacon, evenly mix. Form the meat mixture into 6, 3/4-inch thick patties.", "Heat about 2 teaspoons of oil in a 12-inch nonstick skillet over medium-high heat until the oil shimmers.", "Add half the patties and cook until well browned on the first side, about 2-3 minutes, flip the patties and brown on the second side, 2-3 minutes more.", "Transfer the patties to a large baking sheet. Wipe out the skillet and repeat this step with 2 more teaspoons of oil and the remaining patties.", "Bake the turkey burgers until the internal temperature reaches reaches 165 degrees f. anywhere from 8-10 minutes."]'::jsonb, 'https://www.foodista.com/recipe/4SF5CVZ7/loaded-turkey-burgers', 'https://img.spoonacular.com/recipes/650235-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-caesar-salad', 'Chicken Caesar Salad', 2, 0, 0, '{"calories": 292, "protein": 31.24, "carbs": 6.21, "fat": 15.68, "saturated_fat": 3.85, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 514.36, "potassium": null, "fiber": 2.41, "sugar": 2.11, "vitamin_a": null, "vitamin_c": 25.79, "calcium": 98.2, "iron": 2.47}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'gluten free', 'spoonacular'], '[{"quantity": 4.0, "unit": "", "item": "olives", "notes": "4 pitted black olives, sliced", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "cup", "item": "celery", "notes": "1/2 cup diced chilled celery", "category": "produce"}, {"quantity": 8.0, "unit": "ounces", "item": "chicken", "notes": "8 ounces cooked chicken", "category": "meat"}, {"quantity": 0.5, "unit": "", "item": "garlic clove", "notes": "1/2 garlic clove", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "lemon juice", "notes": "2 tablespoons plus 2 tsp. lemon juice", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "mayonnaise", "notes": "1 tablespoon plus 1 tsp. mayonnaise", "category": "condiments"}, {"quantity": 2.0, "unit": "teaspoons", "item": "parmesan cheese", "notes": "2 teaspoons grated Parmesan cheese", "category": "cheese"}, {"quantity": 2.0, "unit": "tablespoons", "item": "pimientos", "notes": "2 tablespoons diced drained canned pimientos", "category": "produce"}, {"quantity": 4.0, "unit": "", "item": "romaine lettuce leaves", "notes": "4 chilled iceberg or romaine lettuce leaves", "category": "produce"}, {"quantity": 0.125, "unit": "teaspoon", "item": "salt and pepper", "notes": "1/8 teaspoon each salt and pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "scallion", "notes": "2 tablespoons chopped scallion (green onion)", "category": "produce"}]'::jsonb, '["Rub a medium wooden bowl with cut side of garlic clove and discard garlic; add lemon juice, mayonnaise, and cheese to bowl and stir to combine.", "Add remaining ingredients except lettuce and mix well; line serving platter with lettuce and top with chicken mixture."]'::jsonb, 'https://www.foodista.com/recipe/HSP3BYFZ/caesar-chicken-salad', 'https://img.spoonacular.com/recipes/636682-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('suzannes-red-chili', 'Suzanne’s Red Chili', 6, 0, 0, '{"calories": 505, "protein": 29.77, "carbs": 55.41, "fat": 20.5, "saturated_fat": 6.62, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 638.01, "potassium": null, "fiber": 18.76, "sugar": 8.13, "vitamin_a": null, "vitamin_c": 15.89, "calcium": 178.38, "iron": 8.52}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'baking'], '[{"quantity": 1.0, "unit": "TBSP", "item": "ground cumin", "notes": "1 TBSP ground cumin", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "TBSP", "item": "ground coriander", "notes": "1 TBSP ground coriander", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "servings", "item": "olive oil", "notes": "Olive oil for frying", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "large", "item": "onion", "notes": "1 large yellow onion, diced finely", "category": "produce"}, {"quantity": 1.0, "unit": "TBSP", "item": "garlic", "notes": "1 generous TBSP finely chopped garlic", "category": "produce"}, {"quantity": 450.0, "unit": "g", "item": "stewing beef", "notes": "450g 1lb stewing beef, cubed into roughly 1/2” chunks (1.5cm)", "category": "frozen"}, {"quantity": 1.0, "unit": "TBSP", "item": "paprika", "notes": "1 TBSP sweet paprika", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "TBSP", "item": "chili powder", "notes": "4 TBSP chili powder (see notes)", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "TBSP", "item": "all purpose flour", "notes": "1 TBSP plain all purpose flour", "category": "baking"}, {"quantity": 2.0, "unit": "tsp", "item": "oregano", "notes": "2 tsp dry oregano", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "beef knorr stock cubes dissolved into 16oz/475ml water", "notes": "2 beef Knorr stock cubes dissolved into 16oz/475ml boiling water", "category": "canned and jarred"}, {"quantity": 30.0, "unit": "oz", "item": "cans of pinto beans rinsed/drained", "notes": "2 x 15oz/400g cans of pinto beans rinsed/drained", "category": "pasta and rice"}, {"quantity": 28.0, "unit": "oz", "item": "canned tomatoes", "notes": "1 x 28oz/800g can of tomatoes, drained and diced/chopped into bit size pieces", "category": "canned and jarred"}, {"quantity": 6.0, "unit": "servings", "item": "salt & ground pepper", "notes": "Salt & ground black pepper to taste", "category": "spices and seasonings"}]'::jsonb, '["Heat a large heavy pan (with a tight fitting lid) over medium high heat. Once hot, add a few TBSP of oil and brown the beef in batches.", "Add more oil as needed. Take care not to overcrowd the meat so that it doesn''t steam. You want a nice color on it  color means flavor so don''t skimp on this part! Keep the batches of browned beef in a bowl and do not drain, you want all the juices from the meat.", "Once all the meat is browned and removed from the pan, turn the heat down to medium, then add the onions and garlic and a little more oil if needed.", "Saute the onions and garlic gently. You don''t want to brown them. Once they have softened, turn the heat up to medium high again, pile the onions and garlic in the middle of the pan and add the spices on top (cumin/coriander/paprika/chili powder) to the pan. Stir the spices into the onions until you can smell them (just a few seconds).", "Add in the flour, oregano and the meat along with any juices to the pan and stir to combine. Carefully pour in the water/stock cube mixture and stir well.", "Bring to a boil, turn down the heat to a simmer and put the lid on. Simmer covered for 1 to 1.5 hours, checking and stirring every 20 to 30 minutes.", "Once the meat just starts to go tender add the beans and tomatoes, stir well, cover and cook for a further half hour or until the meat is so tender it easily breaks apart with a fork.", "Taste and season with salt & pepper as needed.", "Serve over what ever you want with what ever you want on top!"]'::jsonb, 'https://www.foodista.com/recipe/62VM4DZM/suzanne-s-red-chili-recipe', 'https://img.spoonacular.com/recipes/662391-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chili-and-garlic-spiced-beef-and-broccoli-stir-fry', 'Chili and Garlic Spiced Beef and Broccoli Stir Fry', 4, 0, 0, '{"calories": 394, "protein": 23.24, "carbs": 38.5, "fat": 17.26, "saturated_fat": 8.58, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 840.34, "potassium": null, "fiber": 4.27, "sugar": 7.22, "vitamin_a": null, "vitamin_c": 81.57, "calcium": 63.12, "iron": 2.92}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'dessert', 'soup', 'baking'], '[{"quantity": 12.0, "unit": "ounces", "item": "beef steak", "notes": "12 ounces beef steak, very thinly sliced", "category": "meat"}, {"quantity": 4.0, "unit": "cups", "item": "broccoli florets", "notes": "4 cups broccoli florets", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "coconut oil", "notes": "1 tablespoon coconut oil", "category": "baking"}, {"quantity": 0.75, "unit": "cup", "item": "chicken broth", "notes": "3/4 cup low fat chicken broth", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "tablespoon", "item": "cornstarch", "notes": "1 tablespoon cornstarch", "category": "baking"}, {"quantity": 2.0, "unit": "tablespoons", "item": "soy sauce", "notes": "2 tablespoons soy sauce", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "tablespoons", "item": "rice vinegar", "notes": "2 tablespoons rice vinegar", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "tablespoons", "item": "mirin", "notes": "2 tablespoons mirin", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "teaspoon", "item": "sesame oil", "notes": "1/2 teaspoon sesame oil", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tablespoon", "item": "sugar", "notes": "1 tablespoon sugar", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "asian chili sauce", "notes": "2 teaspoons Asian Chili sauce", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "cups", "item": "brown rice", "notes": "2 cups brown rice, cooked", "category": "pasta and rice"}]'::jsonb, '["Combine chicken broth, cornstarch, soy sauce, rice vinegar, Mirin, sesame oil, sugar and Asian chili sauce in a small bowl.", "Preheat non-skillet over medium high heat with 1/2 tablespoon coconut oil.", "Add beef and stir fry until beef is cooked through, 3  4 minutes.", "Remove from pan.", "Add remaining coconut oil and saute broccoli for 3  4 minutes until crisp-tender.", "Add chicken broth or water as needed to keep pan from becoming too dry.", "Add beef and sauce into the pan with the broccoli and stir until sauce thickens, 4  5 minutes.", "Serve over rice."]'::jsonb, 'https://www.foodista.com/recipe/4HJ5M7RQ/chili-and-garlic-spiced-beef-and-broccoli-stir-fry', 'https://img.spoonacular.com/recipes/638549-312x231.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('green-chili-sloppy-joes', 'Green Chili Sloppy Joes', 5, 0, 0, '{"calories": 401, "protein": 21.15, "carbs": 33.21, "fat": 20.22, "saturated_fat": 7.39, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 842.77, "potassium": null, "fiber": 4.31, "sugar": 9.69, "vitamin_a": null, "vitamin_c": 50.1, "calcium": 99.03, "iron": 3.99}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'dessert', 'soup'], '[{"quantity": 1.0, "unit": "teaspoon", "item": "chili powder", "notes": "1 teaspoon chili powder", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves of minced garlic", "category": "produce"}, {"quantity": 8.0, "unit": "ounces", "item": "chilies", "notes": "8 ounces diced green chilies (2 of those little cans)", "category": "produce"}, {"quantity": 1.0, "unit": "pound", "item": "ground beef", "notes": "1 pound ground beef or turkey", "category": "meat"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground mustard", "notes": "1/2 teaspoon dry ground mustard", "category": "spices and seasonings"}, {"quantity": 5.0, "unit": "", "item": "hamburger buns", "notes": "5 hamburger buns", "category": "bakery/bread"}, {"quantity": 1.0, "unit": "teaspoon", "item": "brown sugar", "notes": "1 teaspoon light brown sugar", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "onion", "notes": "1 cup diced onion", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "orange peppers", "notes": "1 cup diced orange peppers", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "red wine vinegar", "notes": "1 tablespoon red wine vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 5.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper to taste", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "ounces", "item": "tomato sauce", "notes": "8 ounces can tomato sauce (plain)", "category": "canned and jarred"}]'::jsonb, '["Brown the onions", "Add the garlic and saute till fragrant, about 30 seconds. You can saute the orange peppers here too, if you like them very soft.", "Add the beef and brown it well.", "Add the chilies, tomato sauce, sugar, vinegar and spices.", "Let simmer, stirring occasionally, over medium-low heat for 10-15 minutes or until as thick as you like.", "Add the orange peppers at the end to keep a fresher flavor and crispier texture."]'::jsonb, 'https://www.foodista.com/recipe/7RJHTMLW/green-chili-sloppy-joes', 'https://img.spoonacular.com/recipes/645443-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('barnabys-caesar-salad', 'Barnaby''s Caesar Salad', 4, 0, 0, '{"calories": 595, "protein": 21.11, "carbs": 36.5, "fat": 41.35, "saturated_fat": 18.67, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 970.46, "potassium": null, "fiber": 5.32, "sugar": 19.85, "vitamin_a": null, "vitamin_c": 9.16, "calcium": 505.93, "iron": 3.28}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'pescatarian', 'spoonacular'], '[{"quantity": 1.0, "unit": "tablespoon", "item": "anchovy paste", "notes": "1 tablespoon anchovy paste", "category": "pasta and rice"}, {"quantity": 0.5, "unit": "loaf", "item": "ciabatta", "notes": "1/2 loaf ciabatta or other good Italian bread", "category": "bakery/bread"}, {"quantity": 1.0, "unit": "", "item": "juice of lemon", "notes": "Juice of 1 lemon", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "olive oil", "notes": "1 cup olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.5, "unit": "cups", "item": "parmigiano reggiano cheese", "notes": "1 1/2 cups Parmigiano Reggiano cheese, grate", "category": "cheese"}, {"quantity": 4.0, "unit": "servings", "item": "cracked pepper", "notes": "Fresh cracked black pepper to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "large head", "item": "romaine lettuce", "notes": "1 large head Romaine lettuce, chopped", "category": "produce"}]'::jsonb, '["Combine lemon juice and anchovy paste in a blender.Start blender and drizzle olive into mixture until it thickens.", "Cut bread into 1 inch cubes and toast until brown. The trick here is to have it crispy on the outside and soft on the inside.", "Combine lettuce and bread cubes in a salad bowl and cover with Parmigiano Reggiano (Parmesan) cheese.", "Pour dressing over top and toss."]'::jsonb, 'https://www.foodista.com/recipe/222ZYXGD/barnabys-caesar-salad', 'https://img.spoonacular.com/recipes/634345-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('creamy-white-chili', 'Creamy White Chili', 4, 0, 0, '{"calories": 809, "protein": 52.63, "carbs": 33.4, "fat": 51.85, "saturated_fat": 23.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1130.32, "potassium": null, "fiber": 7.27, "sugar": 4.77, "vitamin_a": null, "vitamin_c": 8.4, "calcium": 378.21, "iron": 4.3}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'spoonacular'], '[{"quantity": 2.0, "unit": "teaspoons", "item": "pepper", "notes": "2 teaspoons black pepper", "category": "spices and seasonings"}, {"quantity": 15.5, "unit": "oz", "item": "great northern beans", "notes": "1 (15.5 oz.) can Great Northern beans, drained", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "pound", "item": "chicken", "notes": "1 pound cubed chicken", "category": "meat"}, {"quantity": 14.0, "unit": "oz", "item": "chicken broth", "notes": "1 (14 oz.) can chicken broth", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "teaspoon", "item": "cumin", "notes": "1 teaspoon cumin", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": "1 clove garlic", "category": "produce"}, {"quantity": 4.5, "unit": "oz", "item": "chilies", "notes": "1 (4.5oz.) can green chilies, drained", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "heavy whipping cream", "notes": "½ cup heavy whipping cream", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "olive oil", "notes": "1 tablespoon olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "small", "item": "onion", "notes": "1 small onion, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "oregano", "notes": "1 teaspoon oregano", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "cheddar cheese", "notes": "1 cup shredded cheddar cheese for garnish", "category": "cheese"}, {"quantity": 1.0, "unit": "cup", "item": "cream", "notes": "1 cup sour cream", "category": "milk, eggs, other dairy"}]'::jsonb, '["In heavy saucepan, saut chicken, onion, and garlic in olive oil.When chicken is cooked, add broth, beans, chilies, and seasonings.Simmer on low heat for 20 minutes.", "Remove from heat and add sour cream and whipping cream.Top with shredded cheddar cheese."]'::jsonb, 'https://www.foodista.com/recipe/5QVKF6LG/creamy-white-chili', 'https://img.spoonacular.com/recipes/640722-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('hooters-hot-wings-copy-cat', 'Hooter''s Hot Wings (Copy Cat )', 6, 0, 0, '{"calories": 808, "protein": 40.86, "carbs": 20.6, "fat": 61.69, "saturated_fat": 21.02, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1854.52, "potassium": null, "fiber": 1.41, "sugar": 1.76, "vitamin_a": null, "vitamin_c": 18.44, "calcium": 47.84, "iron": 3.29}'::jsonb, ARRAY['american', 'antipasti', 'lunch', 'main course', 'starter', 'snack', 'appetizer', 'main dish', 'antipasto', 'hor d''oeuvre', 'dinner', 'spoonacular', 'baking'], '[{"quantity": 5.0, "unit": "pounds", "item": "chicken wings", "notes": "5 pounds chicken wings", "category": "meat"}, {"quantity": 1.0, "unit": "cup", "item": "flour", "notes": "1 cup flour", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "johnny''s seasoning salt", "notes": "2 teaspoons Johnny''s seasoning salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "cayenne pepper", "notes": "1/2 teaspoon cayenne pepper", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "servings", "item": "oil", "notes": "Oil for deep frying (peanut, canola, vegetable)", "category": "frozen"}, {"quantity": 0.5, "unit": "cup", "item": "butter", "notes": "1/2 cup butter", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "cup", "item": "franks hot sauce", "notes": "1/2 cup Franks Red Hot Sauce", "category": "condiments"}, {"quantity": 6.0, "unit": "servings", "item": "ranch dressing", "notes": "Blue cheese or ranch dressing", "category": "oil, vinegar, salad dressing"}, {"quantity": 6.0, "unit": "servings", "item": "carrot and celery sticks", "notes": "Carrot and celery sticks", "category": "produce"}]'::jsonb, '["Cut wings (separate at the joints, freeze tips for making stock later).", "Mix flour and seasoning salt. Coat wings in seasoned flour.", "Place on a plate and cover. Refrigerate for 1 hour. Reserve the leftover flour for later.", "In a large Dutch oven or deep fryer, heat oil to 375 F. In a small saucepan over low heat melt the butter and add the hot sauce. Keep warm. Deep fry the chicken, several pieces at time (amount depends on your size of fryer/panmake sure there is enough of space between the wings so they dont touch).", "Fry until golden brown, about 12 minutes.", "Drain on a wire rack.", "Place the wings in a large bowl, pour sauce over them, cover and toss to coat wings.", "Remove with a slotted spoon or tongs.", "Serve with blue cheese or ranch dressing, carrot sticks and celery sticks."]'::jsonb, 'https://www.foodista.com/recipe/L8MLQZB5/hooters-hot-wings-copy-cat-recipe', 'https://img.spoonacular.com/recipes/647349-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chavrie-stuffed-turkey-burgers', 'Chavrie Stuffed Turkey Burgers', 6, 0, 0, '{"calories": 361, "protein": 45.24, "carbs": 21.9, "fat": 10.02, "saturated_fat": 4.31, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 380.02, "potassium": null, "fiber": 0.83, "sugar": 3.36, "vitamin_a": null, "vitamin_c": 1.25, "calcium": 103.38, "iron": 3.32}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'grilling'], '[{"quantity": 2.0, "unit": "", "item": "ea. eggs", "notes": "2 ea. Eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "½ garlic", "notes": "teaspoon ½ Chopped garlic", "category": "produce"}, {"quantity": 4.0, "unit": "ounces", "item": "chavrie goat cheese", "notes": "4 ounces Chavrie fresh goat cheese (log works best)", "category": "cheese"}, {"quantity": 2.0, "unit": "pounds", "item": "ground turkey", "notes": "2 pounds ½ Ground Turkey", "category": "meat"}, {"quantity": 6.0, "unit": "", "item": "ea. hamburger rolls", "notes": "6 ea. Hamburger rolls", "category": "bakery/bread"}, {"quantity": 1.0, "unit": "teaspoon", "item": "½ thyme leaves", "notes": "teaspoon ½ Thyme leaves", "category": "produce"}]'::jsonb, '["Slice Chavrie goat cheese log into 6 equal disks", "In a large bowl, combine the ground turkey, eggs, garlic and a pinch each of salt and pepper.", "Mix gently to bring all the ingredients together; do not over mix.Form meat mixture into 12 patties. On 6 of the patties, gently place Chavrie disks onto patties, pressing down lightly.", "Place remaining patties on top, press, and seal edges to totally enclose filling, forming 6 total patties.", "Place patties on grill 4 minutes, until bottom is brown. Turn the burgers over and cook an additional 4 minutes, or until done to your preference.", "Place in rolls and serve with your favorite accompaniments"]'::jsonb, 'https://www.foodista.com/recipe/5ZHK4WKR/chavrie-stuffed-turkey-burgers', 'https://img.spoonacular.com/recipes/637488-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pulled-pork-sandwich-with-mango-bbq-sauce', 'Pulled Pork Sandwich with Mango BBQ sauce', 4, 0, 0, '{"calories": 875, "protein": 82.57, "carbs": 58.94, "fat": 34.1, "saturated_fat": 10.43, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 772.42, "potassium": null, "fiber": 3.49, "sugar": 34.52, "vitamin_a": null, "vitamin_c": 60.69, "calcium": 123.47, "iron": 5.74}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'dessert', 'grilling'], '[{"quantity": 0.25, "unit": "cup", "item": "apple cider vinegar", "notes": "1/4 cup apple cider vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 3.0, "unit": "pounds", "item": "pork shoulder", "notes": "3 pounds 1 boneless pork shoulder (Boston butt), about, excess fat removed, cut into chun", "category": "meat"}, {"quantity": 4.0, "unit": "servings", "item": "brioche rolls", "notes": "Brioche rolls, split", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "cumin seeds", "notes": "1/2 teaspoon cumin seeds", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "brown sugar", "notes": "2 tablespoons dark brown sugar", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "fennel seeds", "notes": "1/2 teaspoon fennel seeds", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "ginger", "notes": "2 tablespoons minced ginger", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "kosher salt", "notes": "Kosher salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "lime juice", "notes": "1/2 cup fresh lime juice", "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "mango puree", "notes": "2 cups mango puree", "category": "not in grocery store/homemade"}, {"quantity": 2.0, "unit": "tablespoons", "item": "molasses", "notes": "2 tablespoons molasses", "category": "baking"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 onion, finely minced", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "paprika", "notes": "1 tablespoon paprika", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "serrano pepper", "notes": "1 serrano pepper, thinly sliced (seeds discarded if you don''t like it spicy)", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "vegetable oil", "notes": "1/4 cup vegetable oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.25, "unit": "cup", "item": "worcestershire sauce", "notes": "1/4 cup Worcestershire sauce", "category": "condiments"}]'::jsonb, '["Combine the rub ingredients, in a small bowl and massage it into the pork shoulder until well coated. Set aside while you make BBQ sauce. You could do this a day ahead and keep refrigerated until ready to use.BBQ sauce: In a large saucepan, warm the oil, over low heat, until hot and shimmering.", "Add the cumin and fennel; they should splutter upon contact - be careful! Once the spluttering subsides, add the onions, ginger and serrano and a little salt, to taste.", "Saute until they soften but don''t let them get any color.", "Add the rest of the sauce ingredients. Simmer about 5 minutes. Taste and season.", "Add the pork shoulder to the saucepan, coating it with the sauce. Cover, and gently simmer until the pork falls apart easily, stirring and turning often, about 3 hours.", "Remove the pork from the saucepan and shred it using 2 forks. Return it to the sauce and stir to coat with the sauce. Put a generous spoonful of the pork inside a brioche bun, top with a few slices of pickle and serve. Aarti''s Note: prepare to have your loved one swoon over you!"]'::jsonb, 'https://www.foodista.com/recipe/TV32HN3D/pulled-pork-sandwich-with-mango-bbq-sauce', 'https://img.spoonacular.com/recipes/657226-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('light-clam-chowder', 'Light Clam Chowder', 6, 0, 0, '{"calories": 497, "protein": 13.39, "carbs": 42.36, "fat": 33.41, "saturated_fat": 19.92, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 740.15, "potassium": null, "fiber": 8.54, "sugar": 8.94, "vitamin_a": null, "vitamin_c": 25.73, "calcium": 106.53, "iron": 4.48}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'vegetarian'], '[{"quantity": 2.0, "unit": "teaspoons", "item": "pepper", "notes": "2 teaspoons crushed black pepper", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "cups", "item": "carrots", "notes": "5-6 medium carrots (about 4 cups), peeled and thinly sliced into rounds", "category": "produce"}, {"quantity": 1.0, "unit": "stalk", "item": "celery", "notes": "1 stalk celery, thinly sliced", "category": "produce"}, {"quantity": 1.5, "unit": "tablespoons", "item": "chili paste", "notes": "1 1/2 tablespoons chili paste, to taste", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "pounds", "item": "clams", "notes": "2 pounds clams, shucked and in it''s juice (sold at fish markets)", "category": "seafood"}, {"quantity": 1.5, "unit": "cups", "item": "coconut milk", "notes": "1 1/2 cups coconut milk", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "tablespoons", "item": "coconut oil", "notes": "2 tablespoons coconut oil", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "thyme", "notes": "1 tablespoon dried thyme", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cups", "item": "corn", "notes": "2 cups frozen corn", "category": "frozen"}, {"quantity": 5.0, "unit": "cloves", "item": "garlic", "notes": "5-6 cloves garlic, minced", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "kosher salt", "notes": "1 teaspoon kosher salt, to taste", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "pound", "item": "pancetta", "notes": "1/2 pound bacon (about 7 slices), sliced, or pancetta, if you like", "category": "meat"}, {"quantity": 1.0, "unit": "pound", "item": "parsnips", "notes": "1 pound parsnips (about 6 medium), peeled, chopped into 1/2-inch cubes", "category": "produce"}, {"quantity": 1.0, "unit": "large", "item": "onion", "notes": "1 large red onion, peeled, halved, thinly sliced", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "vegan buttery spread", "notes": "1 teaspoon vegan buttery spread", "category": "milk, eggs, other dairy"}]'::jsonb, '["In a large stock pot, bring about 5 cups of water to a boil and cook the parsnips until slightly softened, 5 to 7 minutes.When ready, remove the parsnips with a slotted spoon, but do not drain off the water.", "Transfer to a bowl. Set aside.Turn heat down to simmer and cover with lid.In the meantime, begin to prepare the other ingredients.While the parsnips are boiling.", "Heat a heavy-bottomed saut pan, set over over medium heat.", "Add coconut oil.When hot (throw in a piece to see if it sizzles) add the bacon to the oil and thyme and cook, stirring often, about 5 minutes, making sure not to burn the bacon.", "Add the red onion, celery and garlic, and cook, stirring often, until the vegetables are translucent, 4 to 5 minutes.", "Add the carrots and chili paste, stir often, and cook until the carrots soften slightly, 3 to 4 minutes and all the chili paste is blended.Note: This allows the flavor of the chili paste to coat all the ingredients before being diluted by the liquid.", "Add the parsnips and transfer most of the parsnip water (or all if you can fit it into your skillet, mine couldnt, I left about a cup in the pot) and stir to combine well.The liquid will turn a light red hue.", "Transfer to the simmering pot (with any remaining parsnip water, if some).", "Add the shucked clams and its juice and raise the heat to medium.", "Add the coconut milk, non dairy butter spread, and corn to the pot.Bring chowder to a boil.When it comes to a boil, reduce heat to simmer for 5-10 minutes.Ladle individual servings into large soup bowls.", "Garnish with parsley (optional)."]'::jsonb, 'https://www.foodista.com/recipe/RJZ64N2L/light-clam-chowder-and-product-giveaway', 'https://img.spoonacular.com/recipes/650009-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('salmon-burgers-with-roasted-red-pepper-aioli', 'Salmon Burgers With Roasted Red Pepper Aioli', 2, 0, 0, '{"calories": 537, "protein": 39.5, "carbs": 14.52, "fat": 34.72, "saturated_fat": 5.83, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1060.01, "potassium": null, "fiber": 1.58, "sugar": 1.72, "vitamin_a": null, "vitamin_c": 24.87, "calcium": 94.43, "iron": 3.17}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'pescatarian', 'ketogenic', 'spoonacular', 'baking'], '[{"quantity": 0.25, "unit": "cup", "item": "mayonnaise", "notes": "1/4 cup mayonnaise", "category": "condiments"}, {"quantity": 0.25, "unit": "cup", "item": "roasted peppers", "notes": "1/4 cup roasted red peppers", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": "1 clove garlic", "category": "produce"}, {"quantity": 12.0, "unit": "ounces", "item": "salmon", "notes": "12 ounces of salmon, chopped with a sharp knife", "category": "seafood"}, {"quantity": 2.0, "unit": "tablespoons", "item": "onion", "notes": "2 tablespoons finely diced red onion", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "green onion", "notes": "2 tablespoons diced green onion", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "roasted peppers", "notes": "1/4 cup finely diced roasted red peppers", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves of garlic, minced", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "very bread crumbs", "notes": "1/4 cup very dry bread crumbs (or more as needed to shape patties)", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "tablespoons", "item": "parsley", "notes": "2 tablespoons minced fresh parsley or cilantro", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper", "category": "spices and seasonings"}]'::jsonb, '["Mix the mayonnzise, roasted red peppers and a clove of garlic in a food processor until creamy to make the aoili and set aside.", "Mix together all remaining ingredients except the salmon, then gently fold in the salmon and shape into patties.", "Pan sear patties in a non-stick skillet on medium heat until lightly browned on one side, then turn the burgers, lower the heat to medium low, cover, and cook until done, about 5 minutes more.", "Serve the salmon burgers without a bun with a healthy dollop of the Roasted Red Pepper Aioli and a mound of shredded cucumber on top or serve on a traditional bun with condiments of your choice."]'::jsonb, 'https://www.foodista.com/recipe/CB5TXT5P/salmon-burgers-with-roasted-red-pepper-aioli', 'https://img.spoonacular.com/recipes/659058-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pulled-pork-nachos', 'Pulled Pork Nachos', 8, 10, 480, '{"calories": 351, "protein": 18.62, "carbs": 36.24, "fat": 15.69, "saturated_fat": 4.27, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 661.22, "potassium": null, "fiber": 2.93, "sugar": 3.86, "vitamin_a": null, "vitamin_c": 3.08, "calcium": 162.88, "iron": 4.08}'::jsonb, ARRAY['american', 'fingerfood', 'antipasti', 'lunch', 'main course', 'starter', 'snack', 'appetizer', 'main dish', 'antipasto', 'hor d''oeuvre', 'dinner', 'gluten free', 'spoonacular', 'soup', 'slow-cooker'], '[{"quantity": 1.0, "unit": "bag", "item": "nacho chips", "notes": "1 bag nacho chips", "category": "savory snacks"}, {"quantity": 1.0, "unit": "cup", "item": "pico de gallo", "notes": "1 cup pico de gallo", "category": "canned and jarred"}, {"quantity": 4.0, "unit": "tbsp", "item": "pork rub", "notes": "4 tbsp pork rub", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "lb", "item": "pork shoulder", "notes": "1 2lb pork shoulder", "category": "meat"}, {"quantity": 0.5, "unit": "cup", "item": "cheese", "notes": "1/2 cup shredded cheese", "category": "cheese"}, {"quantity": 2.0, "unit": "tbsp", "item": "cream", "notes": "2 tbsp sour cream", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "cups", "item": "vegetable broth", "notes": "2 cups vegetable broth", "category": "canned and jarred"}]'::jsonb, '["Clean the pork and pat dry.", "Add the pork rub to the shoulder and season all over.", "Place the pork shoulder into the crock pot and set the temperature to low.", "Add in the vegetable broth and cook on low for 8-10 hours.", "Remove from slow cooker and shred the pork. Top the nachos with the shredded pork, pico de gallo, shredded cheese, and sour cream if desired."]'::jsonb, 'https://www.pinkwhen.com/pulled-pork-nachos/', 'https://img.spoonacular.com/recipes/1039293-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('17-bean-white-chicken-chili', '17 Bean White Chicken Chili', 8, 0, 0, '{"calories": 177, "protein": 21.64, "carbs": 16.0, "fat": 3.37, "saturated_fat": 0.6, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 917.95, "potassium": null, "fiber": 2.9, "sugar": 3.01, "vitamin_a": null, "vitamin_c": 42.06, "calcium": 63.46, "iron": 2.27}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular'], '[{"quantity": 1.0, "unit": "pound", "item": "beans", "notes": "1 pound Assorted Dry Beans, Cooked According to Package Directions", "category": "produce"}, {"quantity": 5.0, "unit": "cups", "item": "chicken broth", "notes": "5 cups Chicken Broth", "category": "canned and jarred"}, {"quantity": 3.0, "unit": "", "item": "chicken breasts", "notes": "3 Chicken Breasts", "category": "meat"}, {"quantity": 3.0, "unit": "tablespoons", "item": "cornstarch", "notes": "3 tablespoons Cornstarch", "category": "baking"}, {"quantity": 3.0, "unit": "tablespoons", "item": "water", "notes": "3 tablespoons Cold Water", "category": "beverages"}, {"quantity": 1.0, "unit": "cup", "item": "corn", "notes": "1 cup Corn", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 Bell Pepper, Chopped", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "onion", "notes": "1/2 Large Onion, Chopped", "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves Garlic, Minced", "category": "produce"}, {"quantity": 1.0, "unit": "can", "item": "chiles", "notes": "1 can Diced Green Chiles", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "", "item": "tomato", "notes": "1 Tomato, Chopped", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "lime", "notes": "1/2 Lime, Squeezed", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "cumin", "notes": "1 tablespoon Cumin", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "chili powder", "notes": "1 tablespoon Chili Powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "oregano", "notes": "1 teaspoon Oregano", "category": "produce"}, {"quantity": 0.25, "unit": "teaspoon", "item": "bell pepper", "notes": "1/4 teaspoon Crushed Red Pepper", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "pepper", "notes": "1/4 teaspoon Pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "bunch cilantro", "notes": "1 Small Bunch Cilantro, Chopped", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "servings", "item": "salt", "notes": "Salt to Taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "corriander", "notes": "1 teaspoon Corriander", "category": "?"}, {"quantity": 1.0, "unit": "teaspoon", "item": "corriander", "notes": "1 teaspoon Corriander", "category": "?"}]'::jsonb, '["Cook your beans according to package directions.", "Add the broth to a large pot and bring to a boil.", "Add in the chicken and cook through.", "Shred chicken and set aside.", "Mix together the water and cornstarch.", "Add to broth and boil for a minute until slightly thickened.", "Add the chicken back into the broth along with the corn, bell pepper, onion, garlic, chiles, tomato, and lime.", "Add in the spices; the cumin, chile powder, oregano, coriander, crushed pepper, and pepper.", "Add the cooked beans into the chili along with the cilantro.", "Salt to taste and let simmer on low heat covered until ready to eat."]'::jsonb, 'https://www.foodista.com/recipe/WM748VQ5/17-bean-white-chicken-chili', 'https://img.spoonacular.com/recipes/631843-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chunky-two-bean-chili', 'Chunky Two-Bean Chili', 6, 0, 0, '{"calories": 636, "protein": 23.06, "carbs": 84.78, "fat": 26.39, "saturated_fat": 8.24, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1021.91, "potassium": null, "fiber": 26.35, "sugar": 16.74, "vitamin_a": null, "vitamin_c": 66.04, "calcium": 238.54, "iron": 8.03}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 6.0, "unit": "servings", "item": "avocado", "notes": "Sliced avocado", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bay leaf", "notes": "1 bay leaf", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "bittersweet chocolate chips", "notes": "1/2 cup bittersweet chocolate chips (I like Ghirardelli)", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "black beans", "notes": "1 cup black beans", "category": "pasta and rice"}, {"quantity": 6.0, "unit": "servings", "item": "black beans", "notes": "Black Beans", "category": "pasta and rice"}, {"quantity": 15.0, "unit": "oz", "item": "kidney beans", "notes": "1 (15 oz.) can red kidney beans, drained and rinsed", "category": "canned and jarred"}, {"quantity": 28.0, "unit": "oz", "item": "canned tomatoes", "notes": "1 (28 oz.) can crushed tomatoes", "category": "canned and jarred"}, {"quantity": 6.0, "unit": "servings", "item": "chili", "notes": "Chili", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "chili powder", "notes": "2 teaspoons chili powder (mine is a bit on the hot side)", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "servings", "item": "flour tortillas", "notes": "Toasted corn or flour tortillas for scooping", "category": "pasta and rice"}, {"quantity": 6.0, "unit": "servings", "item": "cilantro", "notes": "Chopped fresh cilantro", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "garlic cloves", "notes": "2 garlic cloves, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ground coriander", "notes": "1 teaspoon ground coriander", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "ground cumin", "notes": "2 teaspoons ground cumin", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground pepper", "notes": "1/2 teaspoon ground black pepper", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "servings", "item": "monterey jack cheese", "notes": "Shredded Monterey Jack cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "tablespoon", "item": "olive oil", "notes": "1 tablespoon olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "teaspoon", "item": "oregano", "notes": "1 teaspoon dried oregano", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 red bell pepper, cored, seeded and chopped", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sea salt", "notes": "1 teaspoon sea salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "large", "item": "shallot", "notes": "1 large shallot, chopped", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "cream", "notes": "Sour cream or plain yogurt", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "", "item": "tomatillos", "notes": "4 tomatillos, husked, cleaned and chopped", "category": "produce"}, {"quantity": 6.0, "unit": "cups", "item": "water", "notes": "6 cups water", "category": "beverages"}, {"quantity": 6.0, "unit": "servings", "item": "garnishes", "notes": "Garnishes", "category": "?"}, {"quantity": 6.0, "unit": "servings", "item": "garnishes", "notes": "Garnishes", "category": "?"}]'::jsonb, '["Rinse and drain black beans and discard any rocks or funky-looking (discolored, wrinkly) beans.In heavy soup pot, combine black beans, 6 cups of water, salt and bay leaf.Bring to a boil.Reduce heat and simmer, partially covered, until beans are tender, about 1 hours.Keep an eye on the water, and add more if needed, 1 cup at a time. Beans should have some liquid remaining, but they should not be overly soupy.When beans are almost done, prepare the vegetables.In large saucepan, heat the olive oil and saut the shallot, garlic, red pepper, and tomatillos until tender, 10-15 minutes.When beans are completely tender, remove the bay leaf, and add the sauted vegetables and any remaining oil, the salt, pepper, spices, kidney beans, crushed tomatoes, and chocolate chips.Bring chili to a boil.Reduce heat and simmer, uncovered, until chili thickens and flavors meld, about 30 minutes.Stir occasionally.", "Remove pot from heat and let chili cool for about 20 minutes before pureeing two cups in blender. If you try to puree hot liquid in a blender, the people who move into your house after you will inherit the splatter, and they will curse you.Return pureed chili to pot and mix through.Taste, and add salt and pepper if needed.", "Heat through until warm, about 5 minutes.Ladle into bowls and heap on whichever garnishes speak to you."]'::jsonb, 'https://www.foodista.com/recipe/3RLLDMHY/chunky-two-bean-chili', 'https://img.spoonacular.com/recipes/639392-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('baked-macaroni-and-cheese', 'Baked Macaroni and Cheese', 8, 10, 35, '{"calories": 366, "protein": 15.61, "carbs": 25.93, "fat": 22.34, "saturated_fat": 13.05, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 647.36, "potassium": null, "fiber": 1.08, "sugar": 3.92, "vitamin_a": null, "vitamin_c": 5.32, "calcium": 359.78, "iron": 0.84}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'pasta', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "mild cheddar", "notes": "2 cups mild cheddar", "category": "cheese"}, {"quantity": 1.0, "unit": "cup", "item": "mozzarella", "notes": "1 cup mozzarella", "category": "cheese"}, {"quantity": 2.0, "unit": "cups", "item": "milk", "notes": "2 cups milk", "category": "milk, eggs, other dairy"}, {"quantity": 5.0, "unit": "tbsp", "item": "butter", "notes": "5 tbsp butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "salt", "notes": "1 tsp salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "pepper", "notes": "1/2 tsp pepper", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "tbsp", "item": "flour", "notes": "3 tbsp flour ", "category": "baking"}, {"quantity": 8.0, "unit": "servings", "item": "parsley to garnish", "notes": "Fresh parsley to garnish ", "category": "produce"}, {"quantity": 1.5, "unit": "cups", "item": "elbow macaroni", "notes": "1 1/2 cups elbow macaroni ", "category": "pasta and rice"}]'::jsonb, '["Heat oven to 350 degrees Fahrenheit. ", "Cook noodles until slightly tender but not fully cooked. About 7 minutes.", "Drain.", "Melt butter in a saucepan over medium heat. ", "Add flour and whisk for about 1-2 minutes until slightly brown. ", "Add milk and continue to whisk occasionally for 6 minutes. ", "Add cheese and stir well to combine.", "Remove from heat.", "Stir in noodles and then pour into an 8×8 or 9×13 baking dish.", "Bake uncovered for 20 minutes. ", "Place the broiler on high and move the macaroni and cheese to the top of the oven.", "Carefully watch as the cheese starts to brown and then remove. ", "Garnish with fresh parsley and serve. "]'::jsonb, 'https://www.pinkwhen.com/baked-macaroni-and-cheese/', 'https://img.spoonacular.com/recipes/1487863-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chipotle-turkey-chili', 'Chipotle Turkey Chili', 4, 0, 0, '{"calories": 549, "protein": 51.63, "carbs": 42.81, "fat": 21.95, "saturated_fat": 4.42, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 956.44, "potassium": null, "fiber": 14.04, "sugar": 15.47, "vitamin_a": null, "vitamin_c": 65.2, "calcium": 158.19, "iron": 7.15}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'spoonacular', 'baking'], '[{"quantity": 1.0, "unit": "large", "item": "poblano pepper", "notes": "1 large poblano pepper", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "jalapeno pepper", "notes": "1 jalapeno pepper", "category": "canned and jarred"}, {"quantity": 4.0, "unit": "servings", "item": "extra virgin olive oil", "notes": "Extra virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "large", "item": "onion", "notes": "1 large yellow onion, chopped", "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves garlic, minced", "category": "produce"}, {"quantity": 1.5, "unit": "pounds", "item": "ground turkey", "notes": "1 1/2 pounds ground lean turkey", "category": "meat"}, {"quantity": 3.0, "unit": "tablespoons", "item": "chili powder", "notes": "3 tablespoons chili powder (I used Medium Hatch Chili Powder)", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "chipotle peppers in adobo sauce", "notes": "2 chipotle peppers in adobo sauce, chopped", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "tablespoon", "item": "adobo sauce from chipotle peppers", "notes": "1 tablespoon adobo sauce from can of chipotle peppers", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "cup", "item": "chicken stock", "notes": "1/2 cup chicken stock", "category": "canned and jarred"}, {"quantity": 14.5, "unit": "oz", "item": "kidney beans", "notes": "14 1/2 oz can kidney beans, drained and rinsed", "category": "canned and jarred"}, {"quantity": 28.0, "unit": "oz", "item": "canned tomatoes", "notes": "28 oz. can crushed tomatoes", "category": "canned and jarred"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "cream", "notes": "sour cream, for serving", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "servings", "item": "parsley", "notes": "chopped parsley, for serving", "category": "produce"}]'::jsonb, '["Preheat oven to 400 degrees F.", "Place poblano and jalapeno peppers on a baking sheet lined with foil, drizzle with olive oil, and rub to coat. Roast peppers in oven about 30 minutes, turning once during roasting.", "Remove from oven, immediately wrap loosely in foil, and let sit 15-30 minutes. Peel off and discard the skin.", "Remove the seeds and ribs, and discard. Dice peppers and set aside.", "Heat 2 Tbsp olive in in a large pot over medium heat.", "Add onion and garlic and saute until softened, 5 to 8 minutes.", "Add ground turkey and heat until cooked through, breaking up into pieces and stirring occasionally as it cooks. Season with salt and pepper. Once cooked, add chili powder, chipotle peppers, jalapeno and poblano peppers, and adobo sauce. Stir to combine then add chicken stock, beans, and tomatoes. Cover, reduce heat to low, and let cook at least 1 to 2 hours, stirring ocassionally. Season with salt, pepper, and chili powder to taste before serving.", "Serve in bowls topped with sour cream and chopped fresh parsley."]'::jsonb, 'https://www.foodista.com/recipe/TTW5KQMM/chipotle-turkey-chili', 'https://img.spoonacular.com/recipes/638764-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('kettle-corn-crusted-chicken-tenders', 'Kettle Corn Crusted Chicken Tenders', 2, 0, 0, '{"calories": 574, "protein": 54.79, "carbs": 24.19, "fat": 28.66, "saturated_fat": 7.76, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 441.98, "potassium": null, "fiber": 3.84, "sugar": 2.68, "vitamin_a": null, "vitamin_c": 50.4, "calcium": 49.68, "iron": 2.53}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'fodmap friendly', 'spoonacular', 'baking'], '[{"quantity": 0.5, "unit": "cup", "item": "flour", "notes": "1/2 cup gluten-free flour* (or substitute all-purpose)", "category": "baking"}, {"quantity": 1.0, "unit": "large", "item": "egg", "notes": "1 large egg, beaten", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "pound", "item": "chicken tenders", "notes": "1 pound boneless, skinless chicken tenders (about 7 or 8 strips)", "category": "meat"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "ghee", "notes": "1 Tablespoon ghee or butter", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "Tablespoons", "item": "vegetable oil", "notes": "2 Tablespoons vegetable oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "serving", "item": "salt", "notes": "salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "serving", "item": "bell pepper", "notes": "pepper", "category": "produce"}, {"quantity": 3.0, "unit": "cups", "item": "kettle popcorners", "notes": "3 cups Kettle PopCorners", "category": "?"}]'::jsonb, '["Dredge each chicken strip in flour and shake off excess, then dip it in beaten egg, then in the PopCorners crumbs. Turn each chicken tender to coat fully.", "Transfer to a large plate and repeat with the remaining chicken tenders. Throw out any leftover flour, egg, or crumbs.", "In a large skillet over medium to medium-high heat, add ghee and oil. Once the ghee melts, add the chicken tenders. Do not crowd the pan; you may have to work in batches. Cook, turning one time, until chicken is golden brown on each side and is cooked through, about 8-10 minutes total. If you''d like, sprinkle some additional salt on top of the Kettle Corn Crusted Chicken Tenders while they''re hot.", "I served", "my Kettle Corn Crusted Chicken Tenders with honey mustard for dipping;", "it has a similar savory-and-sweet flavor profile to the chicken. But you", "can use any dipping sauce you like!", "If you''re interested in trying Degustabox, check out their website or follow them on Instagram.", "If you sign up to receive your own Degustabox through one of our links,", "I''ll receive a referral fee and you''ll help to support this blog!"]'::jsonb, 'https://fullbellysisters.blogspot.com/2016/09/kettle-corn-crusted-chicken-tenders.html', 'https://img.spoonacular.com/recipes/803367-312x231.png', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('blue-cheese-burgers', 'Blue Cheese Burgers', 4, 0, 0, '{"calories": 658, "protein": 44.76, "carbs": 33.8, "fat": 36.95, "saturated_fat": 16.12, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1640.69, "potassium": null, "fiber": 1.58, "sugar": 6.64, "vitamin_a": null, "vitamin_c": 2.57, "calcium": 263.45, "iron": 6.09}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'grilling'], '[{"quantity": 0.75, "unit": "tsp", "item": "kosher salt", "notes": "3/4 tsp kosher salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "pounds", "item": "ground sirloin", "notes": "1 pound(s) ground sirloin", "category": "meat"}, {"quantity": 0.5, "unit": "pound", "item": "ground sirloin", "notes": "1/2 pound ground Sirloin", "category": "meat"}, {"quantity": 0.25, "unit": "cup", "item": "bread crumbs", "notes": "1/4 cup dry bread Crumbs", "category": "pasta and rice"}, {"quantity": 0.5, "unit": "cup", "item": "steak sauce", "notes": "1/2 cup steak sauce", "category": "condiments"}, {"quantity": 1.0, "unit": "large", "item": "egg", "notes": "1 large egg", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "ground pepper", "notes": "1/2 tsp ground black pepper", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "", "item": "hamburger buns", "notes": "4 hamburger buns", "category": "bakery/bread"}, {"quantity": 4.0, "unit": "ounces", "item": "cheese", "notes": "4 ounces sliced blue cheese", "category": "cheese"}]'::jsonb, '["In a bowl, add chuck, sirloin, bread crumbs, steak sauce, eggs, salt, and pepper, and mix gently with fork.", "Form 4 patties out of this mixture.", "Cook the hamburgers patties on each side, then cover with aluminium foil.", "Cut the sides of the bun, then grill in a stove-top grill until toasted.", "Place patties and a slice of blue cheese in each bun.", "Serve hot."]'::jsonb, 'https://www.foodista.com/recipe/ZVXPQHB5/blue-cheese-burgers', 'https://img.spoonacular.com/recipes/635350-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('50000-burger', '$50,000 Burger', 4, 0, 0, '{"calories": 769, "protein": 30.56, "carbs": 46.98, "fat": 52.69, "saturated_fat": 12.35, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1228.74, "potassium": null, "fiber": 5.41, "sugar": 16.67, "vitamin_a": null, "vitamin_c": 12.59, "calcium": 146.84, "iron": 4.52}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'breakfast', 'salad', 'grilling'], '[{"quantity": 1.5, "unit": "cups", "item": "pre-washed bagged baby arugula", "notes": "1 1/2 cups • pre-washed bagged baby arugula, roughly torn", "category": "produce"}, {"quantity": 4.0, "unit": "slices", "item": "regular bacon", "notes": "4 slices • thick-cut black pepper bacon or regular thick-cut bacon", "category": "meat"}, {"quantity": 4.0, "unit": "servings", "item": "drain off the bacon fat from the skillet", "notes": "8Drain off the bacon fat from the skillet, wipe out the skillet with paper towels, and set the skillet back on the grill. Add the walnuts to the skillet and toast until golden and fragrant; set aside.", "category": "meat"}, {"quantity": 2.0, "unit": "tablespoons", "item": "balsamic vinegar", "notes": "2 tablespoons • balsamic vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "", "item": "combine the chuck", "notes": "3Combine the chuck, basil, sun-dried tomatoes, onion, garlic, and salt in a large bowl, handling as little as possible. Shape into 2 patties to fit the bun size. Loosely cover with plastic wrap and set aside.", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "medium", "item": "fennel bulbs", "notes": "1 • medium fennel bulbs, tops removed, sliced thin", "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "basil leaves", "notes": "3 tablespoons • packed fresh basil leaves, chopped", "category": "produce"}, {"quantity": 4.0, "unit": "", "item": "figs", "notes": "4 • fresh figs, stemmed and sliced lengthwise", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "garlic cloves", "notes": "1 • garlic cloves, minced or pressed", "category": "produce"}, {"quantity": 0.5, "unit": "pound", "item": "ground turkey", "notes": "1/2 pound • ground turkey", "category": "meat"}, {"quantity": 2.0, "unit": "", "item": "hamburger buns", "notes": "2 • good-quality hamburger buns, split (Oroweat Wheat Buns)", "category": "bakery/bread"}, {"quantity": 2.0, "unit": "ounces", "item": "aged teleme cheese thinly 2 • hamburger buns", "notes": "2 ounces • aged Teleme cheese sliced thinly (Camembert or Brie may be (I used Fromager d''Affinois Brie)2 • good-quality hamburger buns, split (Oroweat Wheat Buns)", "category": "bakery/bread"}, {"quantity": 4.0, "unit": "servings", "item": "prepare a medium-hot fire in a charcoal grill", "notes": "1Prepare a medium-hot fire in a charcoal grill with a cover, or preheat a gas grill to medium-high.", "category": "meat"}, {"quantity": 0.5, "unit": "", "item": "lemons", "notes": "1/2 • medium lemons, preferably Meyer lemons", "category": "produce"}, {"quantity": 0.5, "unit": "tablespoon", "item": "olive oil", "notes": "1/2 tablespoon • extra-virgin olive oil (recommended: Colavita)", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons • extra-virgin olive oil (recommended: Colavita)", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tablespoons", "item": "onion", "notes": "2 tablespoons • grated onion", "category": "produce"}, {"quantity": 1.0, "unit": "pinch", "item": "salt", "notes": "• pinch salt", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "salt", "notes": "• Salt", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "salt", "notes": "• salt to taste", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "tablespoons", "item": "sun-dried tomatoes", "notes": "3 tablespoons • drained and chopped sun-dried tomatoes, packed in oil", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "servings", "item": "to assemble the burgers", "notes": "11To assemble the burgers, place equal servings of the warm grilled fennel on each bun bottom, followed by a cheese-topped patty, 2 bacon slices, and an equal serving of the fig-arugula topping. (I would use a lot of the fig topping) Add the bun tops and", "category": "meat"}, {"quantity": 3.0, "unit": "tablespoons", "item": "vegetable oil", "notes": "3 tablespoons • vegetable oil, for brushing on the grill rack", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "tablespoons", "item": "walnuts", "notes": "4 tablespoons • chopped walnuts", "category": "nuts"}, {"quantity": 1.0, "unit": "stick", "item": "heat a", "notes": "6Heat a large, heavy nonstick fire-proof skillet on the grill. Add the bacon and cook until crisp. Transfer to paper towels to drain. Wrap in foil to keep warm.", "category": "meat"}]'::jsonb, '["Combine the chuck, basil, sun-dried tomatoes, onion, garlic, and salt in a large bowl, handling as little as possible. Shape into 2 patties to fit the bun size. Loosely cover with plastic wrap and set aside.For the fennel:Grate 1/2 teaspoons zest from the lemons.", "Put the fennel rings in a medium-sized bowl (I used half a fennel bulb) and juice the lemon over half the fennel and toss to coat all the fennel rings.", "Add oil and season with salt.", "Put the fennel in a grill basket and grill, shaking the basket occasionally, until soft, 10 to 12 minutes. (I did this on the stove top)", "Transfer the fennel to a sheet of foil, sprinkle with the lemon zest, and wrap to keep warm.", "Heat a large, heavy nonstick fire-proof skillet on the grill.", "Add the bacon and cook until crisp.", "Drain off the bacon fat from the skillet, wipe out the skillet with paper towels, and set the skillet back on the grill.", "Add the walnuts to the skillet and toast until golden and fragrant; set aside.", "Whisk the vinegar with the oil in a small bowl and season with salt, to taste.", "Combine the figs, arugula, and toasted walnuts in a medium bowl. Toss with just enough dressing to coat. (I like a tart vinaigrette so I use a 1:1 ratio for the oil and vinegar)When the grill is ready, brush the grill rack with vegetable oil.", "Place the patties on the rack, cover, and cook, turning once, until done to preference, 5 to 7 minutes on each side for medium.", "Place the cheese slices on the patties during the last 3 minutes of grilling.", "Place the buns, cut side down, on the outer edges of the rack to toast lightly during the last 2 minutes of grilling.To assemble the burgers, place equal portions of the warm grilled fennel on each bun bottom, followed by a cheese-topped patty, 2 bacon slices, and an equal portion of the fig-arugula topping. (I would use a lot of the fig topping)", "Add the bun tops and serve."]'::jsonb, 'https://www.foodista.com/recipe/FHT4DDYV/50000-burger', 'https://img.spoonacular.com/recipes/631814-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('crack-chicken-chili', 'Crack Chicken Chili', 6, 5, 25, '{"calories": 585, "protein": 25.62, "carbs": 36.88, "fat": 38.02, "saturated_fat": 18.88, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1946.96, "potassium": null, "fiber": 9.56, "sugar": 1.88, "vitamin_a": null, "vitamin_c": 0, "calcium": 369.39, "iron": 3.3}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'spoonacular', 'breakfast', 'quick'], '[{"quantity": 2.0, "unit": "", "item": "chicken breasts", "notes": "2 chicken breasts cooked and shredded", "category": "meat"}, {"quantity": 4.0, "unit": "tbsp", "item": "ranch seasoning", "notes": "4 tbsp ranch seasoning", "category": "oil, vinegar, salad dressing"}, {"quantity": 15.0, "unit": "oz", "item": "cannellini beans", "notes": "15 oz cannellini beans", "category": "canned and jarred"}, {"quantity": 15.0, "unit": "oz", "item": "tomatoes", "notes": "15 oz diced tomatoes with juice", "category": "other"}, {"quantity": 15.0, "unit": "oz", "item": "black beans", "notes": "15 oz black beans", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "cups", "item": "chicken broth", "notes": "2 cups chicken broth", "category": "canned and jarred"}, {"quantity": 8.0, "unit": "oz", "item": "cream cheese", "notes": "8 oz cream cheese", "category": "cheese"}, {"quantity": 8.0, "unit": "pieces", "item": "bacon", "notes": "8 pieces bacon", "category": "meat"}, {"quantity": 2.0, "unit": "cups", "item": "cheddar cheese", "notes": "2 cups cheddar cheese", "category": "cheese"}, {"quantity": 6.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper to taste", "category": "spices and seasonings"}]'::jsonb, '["Add shredded chicken, black beans, cannellini beans, tomatoes, and chicken broth to a large pot on medium-high heat. ", "Add ranch dressing and stir to combine.", "Bring to a boil and then lower to simmer. Simmer chili for 10 minutes, then add cream cheese. Allow simmering for 10 minutes, stirring often.", "Add crumbled bacon and shredded cheese and serve immediately."]'::jsonb, 'https://www.pinkwhen.com/crack-chicken-chili/', 'https://img.spoonacular.com/recipes/1502521-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('butternut-squash-quinoa-burgers', 'Butternut Squash Quinoa Burgers', 4, 0, 0, '{"calories": 383, "protein": 13.97, "carbs": 35.32, "fat": 22.61, "saturated_fat": 11.89, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1216.02, "potassium": null, "fiber": 4.29, "sugar": 4.1, "vitamin_a": null, "vitamin_c": 23.0, "calcium": 265.48, "iron": 4.03}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'lacto ovo vegetarian', 'spoonacular', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "butternut squash", "notes": "1/2 cup butternut squash, cooked", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "quinoa", "notes": "1/4 cup quinoa, dry", "category": "pasta and rice"}, {"quantity": 5.0, "unit": "ounces", "item": "feta", "notes": "5 ounces feta, crumbled", "category": "cheese"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 organic egg", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "tablespoons", "item": "walnuts", "notes": "2 tablespoons walnuts, chopped", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "ground cumin", "notes": "2 teaspoons ground cumin", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground pepper", "notes": "1/2 teaspoon ground red pepper", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground cinnamon", "notes": "1/2 teaspoon ground cinnamon", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "ground turmeric", "notes": "1/4 teaspoon ground turmeric", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sea salt", "notes": "1 teaspoon sea salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "pepper", "notes": "1/2 teaspoon freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "coconut oil", "notes": "2 tablespoons coconut oil or organic butter", "category": "baking"}, {"quantity": 1.0, "unit": "", "item": "lemon", "notes": "1 fresh lemon", "category": "produce"}, {"quantity": 4.0, "unit": "", "item": "rolls", "notes": "4 whole wheat rolls (optional)", "category": "bakery/bread"}, {"quantity": 2.0, "unit": "cups", "item": "baby greens", "notes": "2 cups mixed baby greens", "category": "produce"}]'::jsonb, '["In a small saucepan, bring 1/2 cup water to a boil.", "Add quinoa, cover, and reduce heat to low. Cook until liquid is absorbed, ~ 3-5 minutes. Set aside.", "In a food processor, pulse butternut squash, 2 oz. feta, 1 1/2 teaspoon cumin, red pepper, cinnamon, turmeric, sea salt and pepper until just combined. Fold in the quinoa, the walnuts and the egg.", "Form mixture into four patties. In a large skillet, with a splash of coconut oil or organic butter cook burgers on medium heat until cooked through and crispy on the outside, 8-10 minutes per side.", "Meanwhile, in a small bowl, combine remaining feta, 1/4 teaspoon lemon zest, lemon juice from half a lemon, and dash of cumin (~1/2 teaspoon). Season with salt and pepper.", "Serve burgers on a whole wheat roll topped with a few baby greens and creamy feta sauce."]'::jsonb, 'https://www.foodista.com/recipe/WTTVRVNH/butternut-squash-quinoa-burgers', 'https://img.spoonacular.com/recipes/636595-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('superbowl-chili', 'Superbowl Chili', 8, 0, 0, '{"calories": 661, "protein": 64.39, "carbs": 28.56, "fat": 32.58, "saturated_fat": 11.79, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1164.02, "potassium": null, "fiber": 8.6, "sugar": 8.81, "vitamin_a": null, "vitamin_c": 17.53, "calcium": 148.44, "iron": 9.88}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'spoonacular'], '[{"quantity": 15.0, "unit": "ounces", "item": "black beans", "notes": "15 ounces cans black beans, drained and rinsed", "category": "canned and jarred"}, {"quantity": 28.0, "unit": "ounces", "item": "canned tomatoes", "notes": "28 ounces can diced tomatoes, drained", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "medium", "item": "carrots", "notes": "2 mediums carrots", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "plus 1 chili powder", "notes": "2 teaspoons tablespoons plus 1 chili powder", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "chipotle chile pepper in adobo sauce", "notes": "2 tablespoons chopped chipotle chile pepper in adobo sauce", "category": "ethnic foods"}, {"quantity": 4.0, "unit": "teaspoons", "item": "cumin", "notes": "4 teaspoons cumin", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "servings", "item": "cilantro", "notes": "chopped fresh cilantro", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "garlic", "notes": "2 tablespoons finely minced garlic", "category": "produce"}, {"quantity": 8.0, "unit": "servings", "item": "green onions", "notes": "chopped green onions", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "kosher salt", "notes": "2 teaspoons kosher salt", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "pounds", "item": "ground beef", "notes": "3 pounds lean ground beef", "category": "meat"}, {"quantity": 8.0, "unit": "servings", "item": "lime", "notes": "freshly squeezed lime", "category": "produce"}, {"quantity": 6.0, "unit": "cups", "item": "chicken stock", "notes": "6 cups to 7 reduced-sodium beef or chicken stock", "category": "canned and jarred"}, {"quantity": 8.0, "unit": "servings", "item": "monterey jack cheese", "notes": "monterey jack cheese", "category": "cheese"}, {"quantity": 0.25, "unit": "cup", "item": "olive oil", "notes": "1/4 cup olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "medium", "item": "onions", "notes": "2 mediums yellow onions", "category": "produce"}, {"quantity": 4.0, "unit": "teaspoons", "item": "oregano", "notes": "4 teaspoons dried oregano", "category": "produce"}, {"quantity": 1.5, "unit": "pounds", "item": "sirloin steak", "notes": "1 1/2 pounds sirloin steak, cut into small chunks", "category": "meat"}, {"quantity": 8.0, "unit": "servings", "item": "cream", "notes": "sour cream", "category": "milk, eggs, other dairy"}]'::jsonb, '["In a large heavy pot set over high heat, saute ground beef and steak chunks, stirring frequently, until browned, about 8 minutes. With a slotted spoon, remove beef to a plate and pour off the remaining liquid in the pan. (I used a strainer over a large bowl, and put all the meat in it to drain the excess fat off).", "Add olive oil to the same pot that you cooked your meat in and set over medium heat. When hot, add carrots, onions, and garlic and saute, stirring, until softened, about 5 minutes. Return beef to pot, and add chili powder, cumin, oregano, salt, and chopped chipotle chile; stir and cook 1 minute.", "Add tomatoes and broth. Bring to a simmer, reduce heat to a gentle simmer, and cook for 30 minutes more, stirring occasionally. Much of the liquid will cook down during this time.Stir in all but 1/3 cup of black beans and cook 5 minutes more. Mash reserved beans with a fork, and stir into the chili to give it extra body. If chili is too thick, stir in as much as 1 cup additional broth and heat several minutes to warm. Chili can be prepared two days ahead. Cool, cover and refrigerate. Reheat over medium heat, stirring often.Ladle into bowls and garnish with toppings. Enjoy!"]'::jsonb, 'https://www.foodista.com/recipe/DMQTR5ZC/superbowl-chili', 'https://img.spoonacular.com/recipes/662376-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('the-blarney-burger', 'The Blarney Burger', 4, 0, 0, '{"calories": 777, "protein": 51.46, "carbs": 25.94, "fat": 46.55, "saturated_fat": 20.26, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 883.86, "potassium": null, "fiber": 1.53, "sugar": 5.14, "vitamin_a": null, "vitamin_c": 14.83, "calcium": 197.28, "iron": 6.75}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'grilling'], '[{"quantity": 2.0, "unit": "pounds", "item": "ground sirloin", "notes": "2 pounds ground sirloin", "category": "meat"}, {"quantity": 0.25, "unit": "cup", "item": "irish whiskey", "notes": "1/4 cup Irish whiskey", "category": "alcoholic beverages"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "cup", "item": "onion", "notes": "1/2 cup sweet onion – diced", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "garlic", "notes": "1 tablespoon fresh garlic", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "piccante gorgonzola crumbles", "notes": "1/2 cup Piccante Gorgonzola crumbles (set aside 1 tablespoon)", "category": "cheese"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "pepper", "notes": "1/2 teaspoon pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "butter", "notes": "2 tablespoons butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "purple cabbage", "notes": "1 cup shredded purple cabbage", "category": "produce"}, {"quantity": 4.0, "unit": "", "item": "hamburger buns", "notes": "4 potato bread baker''s rolls or hamburger buns", "category": "bakery/bread"}, {"quantity": 2.0, "unit": "tablespoons", "item": "worchester", "notes": "2 tablespoons Worchester", "category": "?"}, {"quantity": 2.0, "unit": "tablespoons", "item": "worchester", "notes": "2 tablespoons Worchester", "category": "?"}]'::jsonb, '["Irish Mustard Sauce: 1 tbsp cornstarch, 2 tsp sugar, 1 tsp dry mustard, 1/2 tsp salt, 1 cup water, 1 tbsp butter, 1/4 cup vinegar, 1 tsp horseradish, 2 egg yolks, beaten. Put all ingredients in a sauce pan over medium heat. Continue whisking until smooth and thickened to consistency of pudding.", "Gorgonzola Butter-Wash: In a microwave safe bowl, add remaining tablespoon of Gorgonzola crumbles and 2 tablespoons of butter and melt.", "Whisk together to create a Gorgonzola butter-wash.", "Brush Gorgonzola butter-wash on the inside of the top & bottom buns and toast on the upper or outer edges of grill. Once rolls are lightly toasted, remove.", "Mix first 7 ingredients together thoroughly then add salt & pepper. Form patties and pat together well.", "Cook meat over medium heat - be sure to coat grill with non-stick spray.", "Cook about 8-10 minutes on each side.", "Set meat on bottom bun and spoon Irish mustard sauce on top of meat patty.", "Add shredded cabbage and fold top and bottom together."]'::jsonb, 'https://www.foodista.com/recipe/6W7QVCWV/the-blarney-burger', 'https://img.spoonacular.com/recipes/663252-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('crispy-chicken-burger', 'Crispy Chicken Burger', 4, 15, 15, '{"calories": 933, "protein": 58.4, "carbs": 84.79, "fat": 40.1, "saturated_fat": 19.75, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1846.64, "potassium": null, "fiber": 3.7, "sugar": 6.13, "vitamin_a": null, "vitamin_c": 11.42, "calcium": 484.58, "iron": 5.19}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'quick', 'baking'], '[{"quantity": 24.0, "unit": "oz", "item": "chicken breasts", "notes": "Two 12-oz chicken breasts, halved", "category": "meat"}, {"quantity": 4.0, "unit": "", "item": "brioche buns", "notes": "4 brioche buns", "category": "baking"}, {"quantity": 4.0, "unit": "slices", "item": "american cheese", "notes": "4 slices American cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "c", "item": "cole slaw", "notes": "1 c cole slaw", "category": "produce"}, {"quantity": 1.0, "unit": "Tbsp", "item": "butter", "notes": "1 Tbsp butter", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "servings", "item": "vegetable oil", "notes": "Vegetable oil for frying", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.5, "unit": "c", "item": "buttermilk", "notes": "1-1/2 c buttermilk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "Tbsp", "item": "hot sauce", "notes": "1 Tbsp hot sauce", "category": "condiments"}, {"quantity": 1.0, "unit": "tsp", "item": "paprika", "notes": "1 tsp paprika", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "onion powder", "notes": "1 tsp onion powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "garlic powder", "notes": "1 tsp garlic powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "kosher salt", "notes": "1 tsp kosher salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "pepper", "notes": "1 tsp black pepper", "category": "spices and seasonings"}, {"quantity": 1.5, "unit": "c", "item": "flour", "notes": "1-1/2 c all-purpose flour", "category": "baking"}, {"quantity": 2.0, "unit": "Tbsp", "item": "paprika", "notes": "2 Tbsp paprika", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "baking powder", "notes": "1 tsp baking powder", "category": "baking"}, {"quantity": 1.0, "unit": "tsp", "item": "cayenne pepper", "notes": "1 tsp cayenne pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "oregano", "notes": "1 tsp oregano", "category": "produce"}]'::jsonb, '["Place the chicken on a large cutting board and dry them with a paper towel.", "Next, place plastic wrap over the chicken breast and, using a rolling pin, start pounding the thickest part of the breast, working your way around until you achieve an even thickness (about ½”). You’ll also end up with a larger piece of meat.", "Cut in half (each 12-oz chicken breast will result in two 6-oz crispy fried chicken sandwiches). ", "Season the chicken breasts with paprika, onion powder, garlic powder, kosher salt, and black pepper.", "Pour the buttermilk into a mixing bowl and add the hot sauce. Stir.", "Add the seasoned chicken to the bowl, cover tightly with plastic wrap, and marinate in the fridge for a minimum of two hours, ideally overnight. ", "Important: Make sure to remove the chicken from the fridge 30 minutes before dredging and frying them. Once I forgot and went ahead anyway. The result was as expected. When the chicken was perfectly fried on the outside, the internal temperature of the chicken was at a paltry 130°F. By the time it reached 160°F, the outside didn’t look so golden crispy anymore.", "In a mixing bowl, mix the all-purpose flour, paprika, baking powder, cayenne pepper, onion powder, garlic powder, oregano, kosher salt, and black pepper.", "Mix well. Do not dredge the chicken yet. Instead, wait until the oil is ready (see next step).", "In a large enough frying pan to accommodate at least two halved chicken breasts, add enough oil to cover the bottom about ¾” deep.", "Carefully bring the temperature up to 350°F, checking with an instant-read thermometer.", "Once your oil reaches 350°F, lift a piece of chicken from the buttermilk and allow the excess to drip off a little, then place it in the flour and spice mixture. This dry mix must reach every nook and cranny of the meat to achieve a perfect crispy outside. Use your fingers to coat the chicken breast evenly. Gently shake off the excess batter and carefully lower it into the hot oil.", "Fry for about four minutes, turn, and fry for another four minutes. Use your instant-read thermometer to make sure the internal temperature of the chicken has reached 160°F. ", "In the meantime, have a cooling rack ready with a paper towel underneath. Once the chicken is at 160°F, remove with tongs and place on the cooling rack. ", "While the fried crispy chicken is resting on the cooling rack, butter up some brioche buns, add a slice of American cheese, and lightly toast in the toaster oven.", "Remove, add some coleslaw and a piece of chicken breast. Enjoy!"]'::jsonb, 'https://maplewoodroad.com/crispy-chicken-burger/', 'https://img.spoonacular.com/recipes/1697575-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('baked-habanero-hot-wings', 'Baked Habanero Hot Wings', 4, 0, 0, '{"calories": 496, "protein": 38.75, "carbs": 16.21, "fat": 30.95, "saturated_fat": 8.11, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 3559.25, "potassium": null, "fiber": 1.74, "sugar": 10.45, "vitamin_a": null, "vitamin_c": 9.9, "calcium": 117.88, "iron": 4.31}'::jsonb, ARRAY['american', 'antipasti', 'lunch', 'main course', 'starter', 'snack', 'appetizer', 'main dish', 'antipasto', 'hor d''oeuvre', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'baking'], '[{"quantity": 14.0, "unit": "", "item": "chicken wings", "notes": "•14 - 16 chicken wings", "category": "meat"}, {"quantity": 2.0, "unit": "", "item": "habaneros", "notes": "•2 habaneros, deseeded (alter for spiciness)", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "soy sauce", "notes": "•1 cup soy sauce", "category": "ethnic foods"}, {"quantity": 3.0, "unit": "", "item": "garlic cloves", "notes": "•3 garlic cloves", "category": "produce"}, {"quantity": 1.0, "unit": "small piece", "item": "ginger", "notes": "•1 small piece (or 1 tsp) ginger", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "pear", "notes": "•1/2 pear or apple (or 2 tbsp brown sugar)", "category": "baking"}, {"quantity": 0.5, "unit": "small", "item": "onion", "notes": "•1/2 small onion", "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "honey", "notes": "•2 tbsp honey", "category": "nut butters, jams, and honey"}, {"quantity": 4.0, "unit": "servings", "item": "salt & pepper", "notes": "•salt & pepper (pre-rub)", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "slices", "item": "scallions", "notes": "•scallions slices (garnish)", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "sesame seeds", "notes": "•sesame seeds (garnish)", "category": "spices and seasonings"}]'::jsonb, '["Apply the salt and pepper on the chicken wings for the pre-rub.", "Let sit at room temperature for 15 minutes and preheat oven to 375 degrees.", "Meanwhile, prepare the marinade/glaze by adding all ingredients (minus the honey) to a food processor. Pulse until smooth and completely mixed through.", "Transfer to a saucepan and add the 2 tbsp honey. Bring to a boil until thickened, 5 minutes. Keep ready until basting.", "Bake the wings for about 30 minutes while basting them frequently every 10 minutes or so.", "After 30 minutes, set to broil and let cook for another 15~20 minutes while basting with remaining glaze. Broiling near the end creates crispier and crunchier wings that we personally enjoy.", "When wings are charred and slightly burned, transfer to a serving plate.", "Let cool for several minutes and garnish with thinly sliced scallion and/or toasted sesame seeds. Enjoy!!"]'::jsonb, 'https://www.foodista.com/recipe/V556846N/baked-habanero-hot-wings', 'https://img.spoonacular.com/recipes/633637-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('masala-tofu-burger', 'Masala-Tofu Burger', 4, 0, 0, '{"calories": 494, "protein": 18.73, "carbs": 84.97, "fat": 10.53, "saturated_fat": 1.85, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1526.48, "potassium": null, "fiber": 10.25, "sugar": 17.43, "vitamin_a": null, "vitamin_c": 189.6, "calcium": 183.45, "iron": 15.11}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular'], '[{"quantity": 1.0, "unit": "medium", "item": "onion- shopping list", "notes": "1 medium white onion- finely chopped shopping list", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "red/orange/green bell pepper- shopping list", "notes": "1 red/orange/green bell pepper- finely diced shopping list", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "peas-carrots mix shopping list", "notes": "1 cup frozen peas-carrots mix (thawed) shopping list", "category": "frozen"}, {"quantity": 4.0, "unit": "small", "item": "chillies shopping list", "notes": "4 small green chillies (not serrano) shopping list", "category": "produce"}, {"quantity": 0.75, "unit": "cup", "item": "tofu - shopping list", "notes": "3/4 cup firm cubed tofu (I used Nasoya Brand)- drained well shopping list", "category": "refrigerated"}, {"quantity": 1.0, "unit": "medium", "item": "potato- boils", "notes": "1 medium potato- boils, peeled, diced shopping list", "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic- shopping list", "notes": "2 cloves garlic- minced shopping list", "category": "produce"}, {"quantity": 0.5, "unit": "tablespoon", "item": "mustard seeds shopping list", "notes": "1/2 tablespoon black mustard seeds shopping list", "category": "spices and seasonings"}, {"quantity": 5.0, "unit": "", "item": "curry leaves shopping list", "notes": "5 curry leaves shopping list", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "pinch", "item": "hing shopping list", "notes": "pinch hing (Asafoetida optional) shopping list", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "cumin powder shopping list", "notes": "1 teaspoon cumin powder shopping list", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "turmeric shopping list", "notes": "1 teaspoon turmeric shopping list", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "lemon shopping list", "notes": "1 lemon shopping list", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt shopping list", "notes": "1 teaspoon salt (or to taste) shopping list", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "bunch", "item": "cilantro- washed-finely shopping list", "notes": "1/2 bunch cilantro- washed-finely chopped shopping list", "category": "spices and seasonings"}, {"quantity": 0.75, "unit": "cup", "item": "indian breadcrumbs shopping list", "notes": "3/4 cup Indian Breadcrumbs (recipe below) shopping list", "category": "pasta and rice"}, {"quantity": 0.5, "unit": "tablespoon", "item": "vegetable oil shopping list", "notes": "1/2 tablespoon vegetable oil shopping list", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "servings", "item": "pam original flavor shopping list", "notes": "PAM original flavor shopping list", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "", "item": "red/white onion", "notes": "1 red/white onion- cut into thick slices shopping list", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "beefsteak tomatoes", "notes": "2 beefsteak tomatoes- cut into thick slices shopping list", "category": "produce"}, {"quantity": 3.0, "unit": "sprigs", "item": "cilantro shopping list", "notes": "few sprigs of cilantro shopping list", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "mint-cilantro chutney spread shopping list", "notes": "1/2 cup mint-cilantro chutney spread (recipe below) shopping list", "category": "condiments"}, {"quantity": 4.0, "unit": "", "item": "portugese rolls", "notes": "4 Portugese Rolls (Or anything you like)- toasted shopping list", "category": "bakery/bread"}]'::jsonb, '["In a large skillet over medium-high heat, add spray with a generous amount of PAM and add oil.", "Add mustard seeds and saute for 30 seconds-till you hear popping noises.", "Add curry leaves- BE CAREFUL, they pop hot oil!", "Add onions and peppers- sweat for about 30 seconds.", "Add chopped garlic, chilies and turmeric.", "Saute for about 5-7 minutes, until the onions and peppers are soft.", "Add peas and carrots mixture, cumin powder and salt.", "Saute for about 7-10 minutes- you want all the veggies to be soft and cooked through.", "Meanwhile in a small bowl, add the cubed tofu, a pinch of turmeric, cumin powder, coarse black pepper and some cayenne pepper (totally optional!).", "Mix and set aside to marinate for a bit.", "Once the veggies are cooked, add the tofu- saute until slightly brown and soft enough that it crumbles.", "Add juice form half a lemon and half of the chopped cilantro.", "Mix and add the diced boiled potato, and toss until everything is coated, soft and taste for salt/spices. Using a masher, mash the mixture until mushy and until the veggies are small. Set aside to cool. Once cooled, add a bit of the breadcrumbs and mix with your hands. Start forming into thick patties (mixture should make 4). If its still giving you a hard time, add more breadcrumbs. Make 4 patties, place on a plate and wrap with plastic wrap until ready to use.", "In a small skillet sprayed with PAM over medium-high heat, add one patty at a time. Cook for about 2 minutes on each side- until browned and crispy.At the same time, saute the thick slices of onion, until charred and slightly soft.", "Spread a generous amount of the chutney spread on each side on the bread, place burger, onions tomato and cilantro leaves.", "Serve with a slice of lemon and reduced-fat chips on the side."]'::jsonb, 'https://www.foodista.com/recipe/DGH6HX5S/masala-tofu-burger', 'https://img.spoonacular.com/recipes/651190-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('crab-mac-and-cheese', 'Crab Mac and Cheese', 8, 5, 60, '{"calories": 499, "protein": 27.38, "carbs": 32.8, "fat": 28.54, "saturated_fat": 16.76, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1104.1, "potassium": null, "fiber": 1.38, "sugar": 6.62, "vitamin_a": null, "vitamin_c": 1.4, "calcium": 554.58, "iron": 1.18}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'pescatarian', 'spoonacular', 'pasta', 'baking'], '[{"quantity": 1.0, "unit": "lb", "item": "elbow macaroni", "notes": "1 lb elbow macaroni (cooked)", "category": "pasta and rice"}, {"quantity": 4.0, "unit": "cups", "item": "milk", "notes": "4 cups whole milk", "category": "milk, eggs, other dairy"}, {"quantity": 7.0, "unit": "Tbsp", "item": "butter", "notes": "7 Tbsp unsalted butter", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "cup", "item": "flour", "notes": "1/2 cup flour", "category": "baking"}, {"quantity": 0.5, "unit": "Tbsp", "item": "salt", "notes": "1/2 Tbsp salt", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "oz", "item": "cheddar cheese", "notes": "8 oz cheddar cheese (shredded)", "category": "cheese"}, {"quantity": 4.0, "unit": "oz", "item": "pecorino romano cheese", "notes": "4 oz Pecorino Romano cheese (shredded)", "category": "cheese"}, {"quantity": 12.0, "unit": "oz", "item": "crab meat", "notes": "Two 6-oz cans crab meat", "category": "canned and jarred"}, {"quantity": 0.25, "unit": "cup", "item": "breadcrumbs", "notes": "1/4 cup breadcrumbs", "category": "pasta and rice"}]'::jsonb, '["Cook pasta in a pot of salted water and drain.  Set aside.", "To make a bechamel sauce, melt butter in a pan over medium heat, just until it melts.", "Add flour and whisk together with butter for 3-4 minutes, until it turns a light golden color.&nbsp;", "Increase temperature to medium-high and slowly add milk while whisking continuously.  Cook for about 5 minutes, until sauce has thickened so it coats the back of a spoon.", "Preheat oven to 425℉.", "Add both cheeses to the bechamel sauce and stir with a spoon until thoroughly mixed.", "In your sauce pot or a large bowl, stir cooked pasta together with bechamel cheese sauce and crab meat until mixed well.&nbsp;", "Transfer crab mac &amp; cheese to a baking dish and sprinkle the top with breadcrumbs.", "Bake for 30-40 minutes.", "Let cool a few minutes.", "Serve as a main dish, or as a side to steak or chicken.&nbsp;&nbsp;"]'::jsonb, 'https://maplewoodroad.com/crab-mac-cheese/', 'https://img.spoonacular.com/recipes/1697757-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('crispy-baked-green-bean-fries', 'Crispy Baked Green Bean Fries', 2, 0, 0, '{"calories": 677, "protein": 31.86, "carbs": 42.78, "fat": 48.68, "saturated_fat": 5.21, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 113.63, "potassium": null, "fiber": 16.99, "sugar": 11.04, "vitamin_a": null, "vitamin_c": 29.22, "calcium": 328.98, "iron": 7.44}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'whole 30', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.5, "unit": "cups", "item": "almond meal", "notes": "1 1/2 cups almond meal", "category": "health foods"}, {"quantity": 1.0, "unit": "Tbsp", "item": "black pepper", "notes": "1 Tbsp black pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "cayenne pepper", "notes": "1 tsp cayenne pepper", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "", "item": "eggs", "notes": "3 eggs (lightly beaten)", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "lb", "item": "fresh green beans", "notes": "1lb fresh green beans (snapped)", "category": "produce"}, {"quantity": 1.0, "unit": "Tbsp", "item": "garlic powder", "notes": "1 Tbsp garlic powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "Tbsp", "item": "onion powder", "notes": "1 Tbsp onion powder", "category": "spices and seasonings"}]'::jsonb, '["Heat oven to 42", "Prepare a cookie sheet, and then line the coated green beans onto the sheet.", "Bake in oven for 12-15 minutes, turning the beans, and then baking for another 5 minutes. (Start checking the coating after the first 12 minutes periodically to make sure that they are not burning.)", "Remove from oven when they have reached a lightly crisp golden brown color.", "Remove from oven and serve immediately. These are SO completely delicious!", "Arent these just amazing?  (Trust me, they REALLY are!) If you are looking for even more healthy recipes, you can find them in the Simple Fit Forty Section of this site.  If you want even more inspiration, make sure you are also following us on Instagram.", "Facebook", "Pinterest", "Yummly", "Twitter", "Google+", "email"]'::jsonb, 'https://www.pinkwhen.com/crispy-baked-green-bean-fries/', 'https://img.spoonacular.com/recipes/982377-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('best-baked-macaroni-and-cheese', 'Best Baked Macaroni and Cheese', 12, 0, 0, '{"calories": 578, "protein": 25.95, "carbs": 44.75, "fat": 32.81, "saturated_fat": 18.84, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 906.18, "potassium": null, "fiber": 1.67, "sugar": 7.3, "vitamin_a": null, "vitamin_c": 0, "calcium": 666.99, "iron": 1.27}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'dessert', 'pasta', 'baking', 'vegetarian'], '[{"quantity": 0.25, "unit": "teaspoon", "item": "pepper", "notes": "1/4 teaspoon freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "cayenne pepper", "notes": "1/4 teaspoon cayenne pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "pound", "item": "elbow macaroni", "notes": "1 pound elbow macaroni", "category": "pasta and rice"}, {"quantity": 0.5, "unit": "cup", "item": "flour", "notes": "1/2 cup all-purpose flour", "category": "baking"}, {"quantity": 8.0, "unit": "ounces", "item": "gruyere", "notes": "2 cups (about 8 ounces) grated Gruyere", "category": "cheese"}, {"quantity": 2.0, "unit": "teaspoons", "item": "kosher salt", "notes": "2 teaspoons kosher salt", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "nutmeg", "notes": "1/4 teaspoon freshly grated nutmeg", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "tablespoons", "item": "butter", "notes": "8 tablespoons (1 stick) unsalted butter, plus more for dish", "category": "milk, eggs, other dairy"}, {"quantity": 6.0, "unit": "slices", "item": "bread", "notes": "6 slices white bread", "category": "bakery/bread"}, {"quantity": 18.0, "unit": "ounces", "item": "cheddar cheese", "notes": "4 1/2 cups (about 18 ounces) grated white cheddar cheese", "category": "cheese"}, {"quantity": 5.5, "unit": "cups", "item": "milk", "notes": "5 1/2 cups whole milk", "category": "milk, eggs, other dairy"}]'::jsonb, '["Heat the oven to 375 degrees. Butter a 3-quart casserole dish; set aside.", "Place bread pieces in a medium bowl. In a small saucepan over medium heat, melt 2 tablespoons butter.", "Pour butter into the bowl with bread, and toss. Set the breadcrumbs aside. In a medium saucepan set over medium heat, heat milk. Melt remaining 6 tablespoons butter in a high-sided skillet over medium heat. When butter bubbles, add flour. Cook, stirring, 1 minute.Slowly pour hot milk into flour-butter mixture while whisking. Continue cooking, whisking constantly, until the mixture bubbles and becomes thick.", "Remove the pan from the heat. Stir in salt, nutmeg, black pepper, cayenne pepper, 3 cups cheddar, and 1 1/2 cups Gruyere. Set cheese sauce aside.Fill a large saucepan with water. Bring to a boil.", "Add macaroni; cook 2 to 3 fewer minutes than manufacturers directions, until outside of pasta is cooked and inside is underdone. (Different brands of macaroni cook at different rates; be sure to read the instructions.)", "Transfer the macaroni to a colander, rinse under cold running water, and drain well. Stir macaroni into the reserved cheese sauce.", "Pour the mixture into the prepared casserole dish.", "Sprinkle remaining 1 1/2 cups cheddar and 1/2 cup Gruyere; scatter breadcrumbs over the top.", "Bake until browned on top, about 30 minutes.", "Transfer dish to a wire rack to cool for 5 minutes; serve."]'::jsonb, 'https://www.foodista.com/recipe/H3FCFX57/best-baked-macaroni-and-cheese', 'https://img.spoonacular.com/recipes/634873-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUD