INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('classic-macaroni-and-cheese', 'Classic Macaroni and Cheese', 6, 0, 0, '{"calories": 951, "protein": 35.34, "carbs": 79.64, "fat": 54.77, "saturated_fat": 31.94, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 748.44, "potassium": null, "fiber": 3.59, "sugar": 10.79, "vitamin_a": null, "vitamin_c": 0, "calcium": 776.81, "iron": 2.21}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'dessert', 'pasta', 'baking', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "bread crumbs", "notes": "1⁄2 cup fresh bread crumbs", "category": "pasta and rice"}, {"quantity": 8.0, "unit": "tbsp", "item": "butter", "notes": "8 tbsp. butter", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "cayenne pepper", "notes": "1⁄2 tsp. cayenne pepper", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "tbsp", "item": "flour", "notes": "6 tbsp. flour", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "heavy cream", "notes": "1⁄2 cup heavy cream", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "lb", "item": "short macaroni", "notes": "1 lb. short macaroni, cooked", "category": "pasta and rice"}, {"quantity": 6.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and freshly ground white pepper", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "cups", "item": "sharp cheddar", "notes": "4 cups grated sharp cheddar", "category": "cheese"}, {"quantity": 3.75, "unit": "cups", "item": "milk", "notes": "3 3⁄4 cups hot whole milk", "category": "milk, eggs, other dairy"}]'::jsonb, '["Preheat oven to 35", "Melt 6 tbsp. butter in a medium saucepan over low heat.", "Add flour and cook, stirring constantly, for about 4 minutes.Stir in cayenne and season to taste with salt and pepper.", "Whisk in hot milk, 1/2 cup at a time, and cook, stirring, until sauce thickens. Reduce heat to low and stir in 2 cups of cheese. Cook, stirring, until cheese melts, about 2 minutes.", "Combine pasta and sauce in a large bowl, and season with salt.", "Sprinkle 1/2 cup cheese over the bottom of a buttered 8\"  11\" baking dish.", "Place one-third of the pasta in the baking dish, top with 1/2 cup of cheese, then repeat, layering pasta and cheese, ending with cheese, making three layers in all.", "Pour cream over assembled macaroni and cheese. Melt remaining butter in a skillet.", "Add bread crumbs, coat with melted butter, and sprinkle over macaroni and cheese.", "Bake until crust is golden, about 30 minutes. Allow to rest for 15 minutes before serving."]'::jsonb, 'https://www.foodista.com/recipe/RL6K6X3J/classic-macaroni-and-cheese', 'https://img.spoonacular.com/recipes/639629-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
