INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('feta-stuffed-burgers', 'Feta Stuffed Burgers', 4, 0, 0, '{"calories": 562, "protein": 51.86, "carbs": 36.42, "fat": 23.08, "saturated_fat": 11.84, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1006.77, "potassium": null, "fiber": 5.18, "sugar": 11.16, "vitamin_a": null, "vitamin_c": 129.08, "calcium": 409.9, "iron": 7.51}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'grilling'], '[{"quantity": 0.5, "unit": "pound", "item": "feta cheese", "notes": "1/2 pound feta cheese", "category": "cheese"}, {"quantity": 4.0, "unit": "", "item": "hamburger buns", "notes": "4 hamburger buns", "category": "bakery/bread"}, {"quantity": 1.5, "unit": "pounds", "item": "ground beef", "notes": "1 1/2 pounds lean ground beef", "category": "meat"}, {"quantity": 4.0, "unit": "servings", "item": "bell pepper", "notes": "pepper", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "onion", "notes": "red onion", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "spinach", "notes": "fresh spinach", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "tomatoes", "notes": "tomatoes", "category": "produce"}]'::jsonb, '["Season meat with black pepper.Shape meat into 8 thin patties. Top 4 patties each with 1/4 of the feta cheese. Top those patties with remaining patties; pinch edges together to seal.", "Place on grill over medium coals. Grill 7 to 9 minutes on each side or until cooked through (160 degrees).", "Serve patties in rolls with your favorite toppings - we recommend sliced red onion, fresh spinach, and tomato slices."]'::jsonb, 'https://www.foodista.com/recipe/V27NW364/feta-stuffed-burgers', 'https://img.spoonacular.com/recipes/642695-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('north-carolina-style-bbq-pulled-pork', 'North Carolina-Style BBQ Pulled Pork', 12, 0, 0, '{"calories": 229, "protein": 25.85, "carbs": 18.66, "fat": 4.66, "saturated_fat": 1.67, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 598.77, "potassium": null, "fiber": 0.3, "sugar": 17.03, "vitamin_a": null, "vitamin_c": 0, "calcium": 29.02, "iron": 1.36}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'spoonacular', 'dessert', 'baking', 'grilling'], '[{"quantity": 2.0, "unit": "cups", "item": "apple cider vinegar", "notes": "2 cups Apple cider vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 3.0, "unit": "pounds", "item": "pork shoulder", "notes": "3 pounds Boneless pork shoulder or roast", "category": "meat"}, {"quantity": 0.75, "unit": "cup", "item": "firmly-packed brown sugar", "notes": "3/4 cup Firmly-packed dark brown sugar", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "butter", "notes": "2 teaspoons Butter", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "teaspoon", "item": "celery salt", "notes": "1/2 teaspoon Celery salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "mustard", "notes": "1/2 teaspoon Dry mustard", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "garlic salt", "notes": "1/2 teaspoon Garlic salt", "category": "spices and seasonings"}, {"quantity": 1.5, "unit": "teaspoons", "item": "ground pepper", "notes": "1 1/2 teaspoons Ground black pepper", "category": "spices and seasonings"}, {"quantity": 0.6666667, "unit": "cup", "item": "ketchup", "notes": "2/3 cup Ketchup", "category": "condiments"}, {"quantity": 2.0, "unit": "teaspoons", "item": "brown sugar", "notes": "2 teaspoons Light brown sugar", "category": "baking"}, {"quantity": 3.0, "unit": "tablespoons", "item": "liquid hickory smoke", "notes": "3 tablespoons Liquid hickory smoke", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "onion powder", "notes": "1/2 teaspoon Onion powder", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "teaspoons", "item": "pepper flakes", "notes": "3 teaspoons Red crushed pepper flakes", "category": "spices and seasonings"}, {"quantity": 12.0, "unit": "servings", "item": "salt", "notes": "salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cups", "item": "water", "notes": "cups Water", "category": "beverages"}]'::jsonb, '["Mix paprika, light brown sugar, celery and garlic salts, dry mustard, black pepper, onion powder and salt in a small bowl. Season the entire pork roast and cover overnight in the refrigerator.Preheat the oven to 325F.", "Place the pork roast in a large, disposable aluminum roasting pan.In a small bowl, mix together the melted butter and the liquid hickory smoke for the basting marinade.", "Pour the basting marinade over the pork and cover with aluminum foil. Cook for approximately 4 1/2 hours (or until the pork becomes tender enough to start \"pulling\" away, turning the pork every hour, and basting every 1/2 hour. Alternatively, cook pork over white hot coals, covered, for 3-3 1/2 hours, basting and turning frequently with basting marinade.", "Transfer the pork roast to a cutting board.", "Drain the excess juices from the pan. Slice the pork roast and pull apart the meat (trimming the fat) and place back into roasting pan.Prepare the BBQ sauce: In a large bowl, mix the cider vinegar, water, ketchup, dark brown sugar, salt, and red pepper flakes and pour over pulled pork, stirring to make sure all pork is covered; cover with aluminum foil.", "Place pulled pork back into the oven (still at 325F) or in pan on grill and cook for 1 1/2 hours, stirring pork and BBQ every 30 minutes."]'::jsonb, 'https://www.foodista.com/recipe/NLC22Q5D/north-carolina-style-bbq-pulled-pork', 'https://img.spoonacular.com/recipes/653308-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('how-to-make-the-best-chili', 'How to Make the Best Chili', 8, 10, 120, '{"calories": 303, "protein": 32.13, "carbs": 31.87, "fat": 6.74, "saturated_fat": 2.74, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 773.83, "potassium": null, "fiber": 8.62, "sugar": 15.12, "vitamin_a": null, "vitamin_c": 32.99, "calcium": 112.65, "iron": 7.24}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'dessert'], '[{"quantity": 0.25, "unit": "cup", "item": "bell pepper", "notes": "1/4 cup bell pepper", "category": "produce"}, {"quantity": 15.0, "unit": "oz", "item": "kidney beans", "notes": "1 15 oz can kidney beans", "category": "canned and jarred"}, {"quantity": 0.25, "unit": "tsp", "item": "cayenne pepper", "notes": "1/4 tsp cayenne pepper", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tbsp", "item": "chili powder", "notes": "1/2 tbsp chili powder", "category": "spices and seasonings"}, {"quantity": 1.5, "unit": "tsp", "item": "cumin", "notes": "1 1/2 tsp cumin", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "lbs", "item": "ground beef", "notes": "2 lbs lean ground beef", "category": "meat"}, {"quantity": 1.5, "unit": "cups", "item": "onions", "notes": "1 1/2 cups chopped onions", "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "oregano", "notes": "1/2 tsp oregano", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "group pepper", "notes": "1 tsp group black pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "can", "item": "z pinto beans", "notes": "1 150z can pinto beans", "category": "pasta and rice"}, {"quantity": 46.0, "unit": "oz", "item": "tomato juice", "notes": "1 46 oz can tomato juice", "category": "canned and jarred"}, {"quantity": 12.0, "unit": "oz", "item": "tomato paste can be subbed", "notes": "2 6oz cans tomato paste Can be subbed with a 15oz can of tomato sauce", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "cup", "item": "water", "notes": "1 cup water", "category": "beverages"}, {"quantity": 0.5, "unit": "tsp", "item": "sugar", "notes": "1/2 tsp white sugar", "category": "baking"}]'::jsonb, '["Brown the lean ground beef in a deep skillet. Cook over medium heat until cooked all the way through, and then drain.", "In a large pan over high heat add in all of your additional ingredients: cooked ground beef, tomato juice, kidney beans, pinto beans, water, tomato paste, chili powder, cumin, black pepper, oregano, sugar, cayenne pepper, bell pepper, and chopped onions. Bring to a boil.", "Once your large pot of chili has started to boil, lower the heat and simmer for 2 hours uncovered."]'::jsonb, 'https://www.pinkwhen.com/the-best-chili-recipe/', 'https://img.spoonacular.com/recipes/1066893-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lobster-macaroni-and-cheese', 'Lobster Macaroni and Cheese', 6, 0, 0, '{"calories": 800, "protein": 33.98, "carbs": 56.33, "fat": 48.66, "saturated_fat": 23.66, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 866.71, "potassium": null, "fiber": 2.23, "sugar": 6.15, "vitamin_a": null, "vitamin_c": 0, "calcium": 750.29, "iron": 1.61}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'pescatarian', 'spoonacular', 'dessert', 'pasta', 'baking', 'vegetarian'], '[{"quantity": 3.0, "unit": "cups", "item": "elbow macaroni pasta", "notes": "3 cups uncooked elbow macaroni pasta", "category": "pasta and rice"}, {"quantity": 12.0, "unit": "ounces", "item": "lobster tail pieces", "notes": "12 ounces lobster tail pieces, fully cooked", "category": "seafood"}, {"quantity": 0.25, "unit": "cup", "item": "butter", "notes": "1/4 cup butter", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "flour", "notes": "1/4 cup flour", "category": "baking"}, {"quantity": 2.0, "unit": "cups", "item": "milk", "notes": "2 cups milk, room temperature", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "cups", "item": "cups cheese", "notes": "4 cups + cups white cheese, shredded (For this recipe, I like to use a combination of w", "category": "cheese"}, {"quantity": 0.25, "unit": "cup", "item": "truffle oil", "notes": "1/4 cup white truffle oil (optional - but why the hell not?)", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.5, "unit": "cup", "item": "bread crumbs", "notes": "1/2 cup fresh bread crumbs", "category": "pasta and rice"}, {"quantity": 0.5, "unit": "cup", "item": "parmesan cheese", "notes": "1/2 cup grated Parmesan cheese", "category": "cheese"}]'::jsonb, '["Cook the macaroni according to package directions; drain. Start the cheese sauce by making a roux: Melt the butter in a heavy-bottomed saucepan over medium-low heat. When melted and foamy, add the flour and whisk together to form a paste.", "Add 1 cup of milk; continue to whisk until mixture is blended and creamy. Start adding the cheese 1 cup at a time, stirring constantly. As the cheese melts, continue to add remaining milk and cheese in 1-cup increments. If the cheese sauce seems too thick for your liking, you can add in more milk as desired - just use small increments and keep stirring.", "Add the white truffle oil once all the cheese and milk have been incorporated. Once the cheese sauce is fully melted"]'::jsonb, 'https://www.foodista.com/recipe/3K42X3ZH/lobster-macaroni-and-cheese', 'https://img.spoonacular.com/recipes/650255-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chili-chops-with-cauliflower-salad', 'Chili chops with cauliflower salad', 4, 0, 0, '{"calories": 455, "protein": 33.69, "carbs": 25.56, "fat": 25.87, "saturated_fat": 7.89, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 986.86, "potassium": null, "fiber": 7.92, "sugar": 13.29, "vitamin_a": null, "vitamin_c": 98.38, "calcium": 203.92, "iron": 4.24}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'spoonacular', 'salad'], '[{"quantity": 800.0, "unit": "gr", "item": "canned tomatoes", "notes": "800 gr.s of Italian little pomodori tomatoes a can, with their juice ( This means 2 cans ). I used the brand Ci", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "medium head", "item": "cauliflower", "notes": "1 medium head cauliflower, broken into small florets", "category": "produce"}, {"quantity": 2.0, "unit": "Tbs", "item": "cream cheese", "notes": "2 Tbs cream cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "tsp", "item": "cumin", "notes": "1 tsp cumin", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "tarragon", "notes": "½ tsp dried tarragon", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "parsley", "notes": "½ tsp fresh parsley, chopped", "category": "produce"}, {"quantity": 130.0, "unit": "g", "item": "chilies", "notes": "130g green chilies, drained and diced", "category": "produce"}, {"quantity": 2.0, "unit": "Tbs", "item": "lemon juice", "notes": "2 Tbs fresh lemon juice", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "mayonnaise", "notes": "¼ cup mayonnaise", "category": "condiments"}, {"quantity": 1.0, "unit": "tsp", "item": "oil", "notes": "1 tsp oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "pound", "item": "pork chops", "notes": "4 boneless pork chops (about 1 pound)", "category": "meat"}, {"quantity": 2.0, "unit": "Tbs", "item": "bell pepper", "notes": "2 Tbs green or red bell pepper, chopped", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "salt", "notes": "salt to taste", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and pepper", "category": "spices and seasonings"}, {"quantity": 0.33333334, "unit": "cup", "item": "swiss cheese", "notes": "1/3 cup Cheddar or Swiss cheese, grated", "category": "cheese"}]'::jsonb, '["Season chops with salt and pepper and brown them in a nonstick skillet over medium-high heat for about 2 minutes per side.", "Combine salsa, chilies and cumin in a bowl.", "Pour mixture over chops. Reduce heat to low, cover skillet and simmer chops 5 minutes or until cooked through.", "Mix cheeses in a bowl. Divide cheese mixture over chops, cover and cook 1 minute, just until cheese melts.Cauliflower salad:Cook cauliflower florets in a large pot of salted, boiling water until tender-crisp, 5 to 10 minutes.", "Drain and rinse under cold water.Or cook in MWC for 15 minutes.In a large bowl, combine mayonnaise, lemon juice and tarragon.", "Add cauliflower, jalapeno, salt and pepper.", "Mix well until cauliflower florets are evenly coated with dressing. Chill at least 30 minutes for flavors to blend. (Can be made ahead. Store in an airtight container and refrigerate up to 24 hours.)", "Sprinkle with parsley just before serving."]'::jsonb, 'https://www.foodista.com/recipe/B2NXFCCF/chili-chops-with-cauliflower-salad', 'https://img.spoonacular.com/recipes/638552-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
