spoon ground cumin", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground pepper", "notes": "1/2 teaspoon ground black pepper", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "ground pepper", "notes": "1/4 teaspoon ground black pepper", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "garlic powder", "notes": "1/4 teaspoon garlic powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "water", "notes": "1 cup water", "category": "beverages"}]'::jsonb, '["Brown the ground beef over medium heat, breaking into small pieces as it cooks.", "Add salt and pepper to taste while cooking.", "Remove the cooked meat from the heat, drain to remove grease (you can rinse well under hot water to remove the grease).", "Transfer beef into large pot, or dutch oven, and add the remaining ingredients.  Stir together and cook over medium heat, bringing to a simmer.  Reduce the heat to low and continue simmering 50-60 minutes, stirring occasionally."]'::jsonb, 'https://www.foodista.com/recipe/PH3FYJW7/hearty-chili-with-beans', 'https://img.spoonacular.com/recipes/646567-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('baked-honey-sriracha-chicken-wings', 'Baked Honey Sriracha Chicken Wings', 4, 0, 0, '{"calories": 506, "protein": 29.78, "carbs": 25.69, "fat": 31.78, "saturated_fat": 7.94, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 716.16, "potassium": null, "fiber": 1.41, "sugar": 18.07, "vitamin_a": null, "vitamin_c": 15.78, "calcium": 48.25, "iron": 2.65}'::jsonb, ARRAY['american', 'antipasti', 'lunch', 'main course', 'starter', 'snack', 'appetizer', 'main dish', 'antipasto', 'hor d''oeuvre', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'dessert', 'soup', 'baking'], '[{"quantity": 4.0, "unit": "tablespoons", "item": "brown sugar", "notes": "4 tablespoons brown sugar", "category": "baking"}, {"quantity": 40.0, "unit": "oz", "item": "chicken wings", "notes": "40 oz chicken wings", "category": "meat"}, {"quantity": 0.5, "unit": "cup", "item": "cilantro", "notes": "1/2 cup Cilantro, Roughly Chopped", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tbsp", "item": "garlic powder", "notes": "2 tbsp Garlic Powder", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tbsp", "item": "ground ginger", "notes": "2 tbsp Ground Ginger", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "teaspoons", "item": "honey", "notes": "4 teaspoons honey", "category": "nut butters, jams, and honey"}, {"quantity": 0.5, "unit": "", "item": "lime", "notes": "1/2 lime", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "chicken broth", "notes": "1/4 cup Low Sodium Chicken Broth", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tbsp", "item": "olive oil", "notes": "2 tbsp Olive Oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "tbsp", "item": "onion powder", "notes": "1 tbsp Onion Powder", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and Pepper", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "sriracha", "notes": "1/4 cup Sriracha", "category": "condiments"}]'::jsonb, '["Preheat oven to 425 degrees Fahrenheit.", "Place chicken on baking sheets ( you will need 2).", "Add olive oil, salt and pepper to chicken. Toss chicken on baking sheet.", "Place in a single layer, making sure that no chicken touch. Cook for 10 minutes, then flip and cook for 10 more.", "Preheat broiler.Take chicken out. Spoon about 1 TBSP of sauce over each wing.", "Place in oven and cook until turned slightly browned, about 5 minutes. Flip the chicken so that all have skin side up.", "Pour the rest of the sauce over chicken.", "Place back in broiler and cook till skin is crispy, about 10 minutes.", "Once done, toss chicken with sauce created on pan.", "Serve and garnish with cilantro.ENJOY!"]'::jsonb, 'https://www.foodista.com/recipe/VK2D4Q2P/baked-honey-sriracha-chicken-wings', 'https://img.spoonacular.com/recipes/633651-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('alton-browns-baked-macaroni-and-cheese', 'Alton Brown''s Baked Macaroni and Cheese', 8, 20, 0, '{"calories": 431, "protein": 18.68, "carbs": 33.81, "fat": 24.59, "saturated_fat": 13.87, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 444.05, "potassium": null, "fiber": 1.59, "sugar": 6.25, "vitamin_a": null, "vitamin_c": 0, "calcium": 442.11, "iron": 1.03}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'pasta', 'quick', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "", "item": "bay leaf", "notes": "1 bay leaf", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "servings", "item": "pepper", "notes": "Fresh black pepper", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "butter", "notes": "1/4 cup butter, melted", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 Egg", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "pound", "item": "elbow macaroni", "notes": "1/2 pound elbow macaroni", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "tablespoon", "item": "flour", "notes": "1 tablespoon Flour", "category": "baking"}, {"quantity": 3.0, "unit": "cups", "item": "milk", "notes": "3 cups milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "powdered mustard", "notes": "1 tablespoon powdered mustard", "category": "condiments"}, {"quantity": 1.0, "unit": "cup", "item": "panko bread crumbs", "notes": "1 cup panko bread crumbs", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "paprika", "notes": "1/2 teaspoon paprika", "category": "spices and seasonings"}, {"quantity": 12.0, "unit": "ounces", "item": "sharp cheddar", "notes": "12 ounces sharp cheddar, shredded", "category": "cheese"}, {"quantity": 0.5, "unit": "cup", "item": "onion", "notes": "1/2 cup yellow onion, finely diced", "category": "produce"}]'::jsonb, '["Whisk in the flour and mustard and keep it moving for about five minutes. Make sure it''s free of lumps. Stir in the milk, onion, bay leaf, and paprika. Simmer for ten minutes and remove the bay leaf.Temper in the egg. Stir in 3/4 of the cheese. Season with salt and pepper. Fold the macaroni into the mix and pour into a 2-quart casserole dish. Top with remaining cheese.Melt the butter in a saute pan and toss the bread crumbs to coat. Top the macaroni with the bread crumbs.", "Bake for 30 minutes.", "Remove from oven and rest for five minutes before serving.Remember to save leftovers for fried Macaroni and Cheese.Prep time 20 minutes. Cook time 45 minutes."]'::jsonb, 'https://www.foodista.com/recipe/WH8B2YQT/alton-browns-baked-macaroni-and-cheese', 'https://img.spoonacular.com/recipes/632275-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('the-benedict-burger', 'The Benedict Burger', 6, 0, 0, '{"calories": 617, "protein": 25.02, "carbs": 31.19, "fat": 43.94, "saturated_fat": 23.35, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 887.4, "potassium": null, "fiber": 2.06, "sugar": 1.25, "vitamin_a": null, "vitamin_c": 2.22, "calcium": 85.58, "iron": 2.61}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'breakfast', 'grilling'], '[{"quantity": 1.0, "unit": "cup", "item": "butter", "notes": "1 cup butter, softened", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "teaspoon", "item": "cayenne", "notes": "1/2 teaspoon cayenne", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "egg yolks", "notes": "2 egg yolks, slightly beaten", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "water", "notes": "1 tablespoon water", "category": "beverages"}, {"quantity": 1.0, "unit": "tablespoon", "item": "lemon juice", "notes": "1 tablespoon lemon juice", "category": "produce"}, {"quantity": 1.0, "unit": "pound", "item": "ground chicken", "notes": "1 pound ground chicken", "category": "meat"}, {"quantity": 0.5, "unit": "cup", "item": "oatmeal", "notes": "1/2 cup oatmeal", "category": "cereal"}, {"quantity": 6.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "shallot", "notes": "1 shallot chopped", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "worcestershire sauce", "notes": "2 tablespoons Worcestershire sauce", "category": "condiments"}, {"quantity": 6.0, "unit": "", "item": "eggs", "notes": "6 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 6.0, "unit": "", "item": "muffins", "notes": "6 english muffins", "category": "bakery/bread"}]'::jsonb, '["Save 2 tbsp butter and keep cold in refrigerator.In small saucepan, melt remaining butter; keep warm.In a stainless steel bowl, whisk egg yolks until thickened and pale.", "Whisk in water, lemon juice, and cayenne.", "Add 1 tbsp of the cold butter.Set the bowl over a pot with about 2 inches of barely simmering water; whisk until bottom of pan can be seen between whisks and wires of whisk become lightly coated, 1 to 2 minutes.", "Remove from heat and immediately whisk in remaining cold butter to stop the cooking of the yolks.", "Slowly drizzle in the butter while whisking to thicken to consistency of whipping cream. Increasing amount of butter slightly, and seasoning.", "Mix the ground chicken, oatmeal, salt and pepper, shallot, and Worcestshire sauce in a bowl just until combined.  Shape into 6 balls, flatten with the bottom of a plate.Throw into the fridge or freezer for a few minutes while you are heating the grill.Bbq about 6 minutes on each side", "Next, poach the eggs. In a pot place about 3-4 inches of water.  Bring to a boil and add 2 tbsp. vinegar.Slowly drop an egg into the water.  Keep in the water for about 2 minutes.", "Remove with a slotted spoon.Assemble burgers on english muffins with poached eggs and sauce."]'::jsonb, 'https://www.foodista.com/recipe/W76B2R82/the-benedict-burger', 'https://img.spoonacular.com/recipes/663209-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sun-dried-tomato-artichoke-tuna-casserole', 'Sun-dried Tomato & Artichoke Tuna Casserole', 4, 0, 0, '{"calories": 828, "protein": 40.87, "carbs": 101.48, "fat": 27.02, "saturated_fat": 12.17, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1187.1, "potassium": null, "fiber": 6.33, "sugar": 14.41, "vitamin_a": null, "vitamin_c": 8.04, "calcium": 604.28, "iron": 4.72}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'pescatarian', 'spoonacular', 'pasta', 'baking'], '[{"quantity": 4.0, "unit": "", "item": "sundried tomato & artichoke tuna casserole: serves", "notes": "Sundried Tomato & Artichoke Tuna Casserole: Serves 4", "category": "bakery/bread"}, {"quantity": 375.0, "unit": "g", "item": "macaroni", "notes": "375g dried whole-wheat macaroni", "category": "pasta and rice"}, {"quantity": 4.0, "unit": "", "item": "artichoke hearts", "notes": "4 canned artichoke hearts", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "sundried tomatoes", "notes": "½ cup sundried tomatoes", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves garlic", "category": "produce"}, {"quantity": 1.0, "unit": "medium", "item": "onion", "notes": "1 medium onion, quartered", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "milk", "notes": "1 cup 2% milk", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "tbsp", "item": "butter", "notes": "2 tbsp butter", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "tbsp", "item": "flour", "notes": "2 tbsp flour", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "marsala", "notes": "¼ cup marsala", "category": "alcoholic beverages"}, {"quantity": 1.5, "unit": "cup", "item": "parmesan", "notes": "1 ½ cup freshly grated Parmesan, divided", "category": "cheese"}, {"quantity": 1.0, "unit": "can", "item": "tuna", "notes": "1 can tuna, drained", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tbsp", "item": "grain mustard", "notes": "2 tbsp whole grain mustard", "category": "condiments"}, {"quantity": 1.0, "unit": "cup", "item": "panko breadcrumbs", "notes": "1 cup panko breadcrumbs", "category": "baking"}, {"quantity": 2.0, "unit": "tbsp", "item": "olive oil", "notes": "2 tbsp olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and pepper to taste", "category": "spices and seasonings"}]'::jsonb, '["Preheat oven to 375", "Place six cups of water in a large pot and bring to a boil over high heat.", "Liberally salt the water and add the macaroni.  Cook for approximately nine minutes or until al dente.", "Drain, reserving one cup of the pasta water and set aside.", "Squeeze excess moisture from the artichoke hearts and place them in a food processor along with the tomatoes, onion and garlic.", "Pulse until the mixture is finely minced and evenly distributed.  Set aside.", "In a small saucepan melt butter over medium heat.", "Add flour whisking constantly until it forms a paste.", "Add marsala and whisk until incorporated.", "Add the milk in increments whisking constantly until it forms a thin sauce.", "Whisk in one of Parmesan and the artichoke mixture.  Reduce and bring to a simmer until the cheese is completely melted.", "Add mustard and tuna and stir to combine.", "Season with salt and pepper to taste.", "Remove sauce from heat and pour over macaroni, adding as much pasta water as you need to thin the sauce enough to coat the pasta.", "Pour macaroni into a prepared nine-inch casserole dish, approximately three inches deep.  Set aside.", "In a small bowl combine breadcrumbs, the rest of the cheese and olive oil.", "Cover macaroni with breadcrumb mixture and garnish with strips of Parmesan if desired.", "Bake for 20-25 minutes or until golden brown and bubbly."]'::jsonb, 'https://www.foodista.com/recipe/QXNWZ7SQ/sun-dried-artichoke-tuna-casserole', 'https://img.spoonacular.com/recipes/662287-312x231.png', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
