 rice"}, {"quantity": 1.0, "unit": "medium", "item": "zucchini", "notes": "1 medium zucchini, grated", "category": "produce"}]'::jsonb, '["Mix all ingredients in a large bowl. Don''t overwork it - just combine enough to have it well mixed.Form 4-6 round patties. Cook on med-high heat until done. If unsure, insert a thermometer - 165 F is the temp. you are aiming for.For roasted red pepper rings, seed and slice red pepper, spritz with olive oil and bake at 425 for 20 minutes."]'::jsonb, 'https://www.foodista.com/recipe/FMFZ4LVZ/turkey-burgers', 'https://img.spoonacular.com/recipes/664011-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
