INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('creamy-bacon-mac-and-cheese', 'Creamy Bacon Mac and Cheese', 6, 0, 0, '{"calories": 1145, "protein": 37.95, "carbs": 62.4, "fat": 82.98, "saturated_fat": 47.86, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1150.97, "potassium": null, "fiber": 2.54, "sugar": 7.02, "vitamin_a": null, "vitamin_c": 1.72, "calcium": 444.65, "iron": 1.69}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'breakfast', 'pasta'], '[{"quantity": 4.0, "unit": "cups", "item": "heavy cream", "notes": "4 cups heavy cream", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "teaspoons", "item": "rosemary", "notes": "2 teaspoons dried rosemary", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and pepper, to taste", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "pound", "item": "bacon", "notes": "1/2 pound bacon, cooked crisp and crumbled", "category": "meat"}, {"quantity": 1.0, "unit": "pound", "item": "elbow macaroni", "notes": "1 pound elbow macaroni", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "cup", "item": "gruyere cheese", "notes": "1 cup shredded Gruyere cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "cup", "item": "mozzarella cheese", "notes": "1 cup shredded mozzarella cheese", "category": "cheese"}, {"quantity": 2.0, "unit": "", "item": "green onions", "notes": "2-3 chopped green onions, for garnish", "category": "produce"}]'::jsonb, '["Cook pasta according to package directions.", "Drain; reserving 1/3 cup of pasta water.  Meanwhile, combine cream and rosemary in a large saucepan.  Season with salt and pepper.  Bring to a boil.  Reduce heat slightly and continue to simmer until reduced by half, 15-20 minutes.  Stir cheeses into cream until melted.  Stir in cooked pasta along with 1/3 cup of pasta water.  Cook a few more minutes until everything is heated through.  Stir in bacon just before serving.", "Garnish with chopped green onions."]'::jsonb, 'https://www.foodista.com/recipe/LWCQQX55/creamy-bacon-mac-and-cheese', 'https://img.spoonacular.com/recipes/640592-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
