prepared casserole dish, top with extra cheese if desired, and bake for 20 minutes.", "Remove from oven and serve hot."]'::jsonb, 'https://www.pinkwhen.com/mac-and-cheese-recipe/', 'https://img.spoonacular.com/recipes/715595-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-and-green-pepper-chili', 'Chicken and Green Pepper Chili', 6, 0, 0, '{"calories": 343, "protein": 34.36, "carbs": 28.22, "fat": 10.1, "saturated_fat": 1.93, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 392.51, "potassium": null, "fiber": 5.36, "sugar": 5.81, "vitamin_a": null, "vitamin_c": 23.2, "calcium": 77.52, "iron": 2.6}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'baking'], '[{"quantity": 15.0, "unit": "oz", "item": "great northern beans", "notes": "15 oz. cans of Great Northern beans, undrained", "category": "canned and jarred"}, {"quantity": 3.0, "unit": "large", "item": "carrots", "notes": "3 large carrots, peeled and chopped", "category": "produce"}, {"quantity": 1.5, "unit": "pounds", "item": "chicken breasts", "notes": "1 1/2 pounds chicken breasts, cut into bite-size pieces", "category": "meat"}, {"quantity": 4.0, "unit": "cups", "item": "chicken stock", "notes": "4 cups chicken stock", "category": "canned and jarred"}, {"quantity": 4.0, "unit": "cloves", "item": "garlic", "notes": "4 cloves garlic, minced", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 green pepper, chopped", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "ground cumin", "notes": "2 teaspoons ground cumin", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons good quality olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "teaspoon", "item": "taco seasoning", "notes": "1 teaspoon taco seasoning (Mexican or enchilado seasoning would work too)", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "large", "item": "onion", "notes": "1 large yellow onion, chopped", "category": "produce"}]'::jsonb, '["Heat oil in Dutch oven over high heat.", "Add onions and carrots, stirring to cook until carrots are fork tender.", "Add the garlic, cumin and taco seasoning stirring to coat veggies.", "Add chicken and cook over med-high heat until pieces are no longer pink on the outside.Stir in green pepper and cook for a few minutes.", "Pour in a little of the chicken stock if you need to keep the chicken from sticking.", "Add the beans and chicken stock.Bring to a boil and then reduce the heat to let it simmer for 20-25 minutes.Note: We like a soupier chili in our house because everyone adds something to their own bowl, like crushed up crackers, sour cream or grated cheese. If you like a thicker chili, you can sprinkle a few tablespoons of flour over the onions and carrots at the same time that you add the seasonings."]'::jsonb, 'https://www.foodista.com/recipe/NQ6MBZJM/chicken-and-green-pepper-chili', 'https://img.spoonacular.com/recipes/637902-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
