"}, {"quantity": 1.0, "unit": "Handful", "item": "cilantro", "notes": "Handful of fresh cilantro", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "Dashes", "item": "salt", "notes": "Dashes of salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "Dashes", "item": "ground pepper", "notes": "Dashes of fresh ground black pepper", "category": "spices and seasonings"}]'::jsonb, '["Combine all of the ingredients for the marinade.", "Add the chicken wings and place in the refrigerator for at least 1 hour or up to a few hours.", "Place the chicken wings in a baking pan and spoon the marinade over the wings.", "Place in the oven for 35-40 minutes until a beautiful golden color."]'::jsonb, 'https://www.foodista.com/recipe/YFLKPJ7V/baked-lemon-lime-chicken-wings', 'https://img.spoonacular.com/recipes/633668-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
