"tablespoon", "item": "worcestershire sauce", "notes": "2/3 tablespoon Worcestershire sauce", "category": "condiments"}]'::jsonb, '["Heat the olive oil in a large skillet.", "Add in minced garlic, shallots, and green bell pepper.  Stir until fragrant and tender, about 3 minutes. Season it with salt and black pepper.", "Add the ground beef to the vegetables. Stir and cook about 5 minutes, until the meat is no longer pink and fully cooked.", "Add tomato sauce, barbecue sauce, Worcestershire, and hot sauce into the skillet. Stir to combine. Simmer until thickened.To serve, spoon and pile sloppy meat onto the toasted, buttered bun bottoms and cover with bun tops with your favourite side dish or pickles."]'::jsonb, 'http://www.foodista.com/recipe/DNFR7JZT/sloppy-joe', 'https://img.spoonacular.com/recipes/632071-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
