lk", "notes": "1/2 cup cream/milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "water", "notes": "1/4 cup water", "category": "beverages"}, {"quantity": 4.0, "unit": "tbsp", "item": "oil", "notes": "4 tbsp oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 8.0, "unit": "servings", "item": "salt", "notes": "Salt for taste", "category": "spices and seasonings"}]'::jsonb, '["Heat oil and saute shallots with ginger and garlic paste.", "Add chicken and break it up into bits and pieces.", "Put in chili flakes, all spice and nutmeg powder, rosemary leaves and salt.", "Stir all together; pour water and simmer.", "Once heated through, add beans and cream.", "Stir and after about 2-3 minutes, remove from heat."]'::jsonb, 'https://www.foodista.com/recipe/G2J5CXW5/chicken-chili-with-black-eyed-peas', 'https://img.spoonacular.com/recipes/638026-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
