uce", "notes": "½ tbsp. soya sauce", "category": "ethnic foods"}, {"quantity": 0.75, "unit": "tbsp", "item": "soya sauce", "notes": "¾ tbsp. soya sauce", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "servings", "item": "spring onions", "notes": "Spring onions for garnish", "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "sugar", "notes": "½ tsp. sugar", "category": "baking"}, {"quantity": 0.5, "unit": "tbsp", "item": "chilli sauce", "notes": "½ tbsp. chilli sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tsp", "item": "chilli sauce", "notes": "1 tsp chilli sauce", "category": "ethnic foods"}, {"quantity": 0.75, "unit": "tsp", "item": "vinegar", "notes": "¾ tsp. vinegar", "category": "oil, vinegar, salad dressing"}]'::jsonb, '["Find Complete instructions on swasthi''s recipes"]'::jsonb, 'https://spoonacular.com/-1424528841847', 'https://img.spoonacular.com/recipes/629963-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
