INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spicy-chili-w-boneless-beef-short-ribs', 'Spicy Chili w Boneless Beef Short Ribs', 6, 0, 0, '{"calories": 1003, "protein": 88.6, "carbs": 35.84, "fat": 54.98, "saturated_fat": 22.06, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1102.06, "potassium": null, "fiber": 10.73, "sugar": 5.35, "vitamin_a": null, "vitamin_c": 17.9, "calcium": 121.06, "iron": 12.31}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'soup', 'baking'], '[{"quantity": 4.0, "unit": "lb", "item": "beef short ribs", "notes": "•4 lb boneless beef short ribs, cut into 1-inch pieces", "category": "meat"}, {"quantity": 1.0, "unit": "can", "item": "black beans", "notes": "•1 can black beans", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "can", "item": "kidney beans", "notes": "•1 can kidney beans", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tbsp", "item": "chili pepper flakes", "notes": "•2 tbsp red chili pepper flakes", "category": "produce"}, {"quantity": 2.0, "unit": "packets", "item": "spicy chili powder", "notes": "•2 packets spicy chili powder", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "", "item": "garlic cloves", "notes": "•3 garlic cloves, minced", "category": "produce"}, {"quantity": 1.5, "unit": "lb", "item": "ground chuck", "notes": "•1.5 lb ground chuck", "category": "meat"}, {"quantity": 2.0, "unit": "cups", "item": "mushrooms", "notes": "•2 cups mushrooms, thinly sliced", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "salt and pepper", "notes": "•salt and pepper to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "large can", "item": "tomato", "notes": "•1 large can tomato, diced", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "can", "item": "kernel corn", "notes": "•1 can whole kernel corn", "category": "produce"}]'::jsonb, '["Brown both meats in a Dutch oven or large pot over medium-high heat.", "Add 2 cups of water and bring to a boil. Discard fatty oil either by draining or with a strainer.", "Add about 4 cups of new water and bring to a boil for 10 minutes.", "Add remaining ingredients; keep at a boil for another 10 minutes. Reduce heat to low, and simmer, slightly uncovered, stirring occasionally, 45 minutes or until beef is tender.", "Serve with rice or/and desired toppings like diced onions, cheese, or crackers.*Instead of using pre-made chili mix packets (like we do), you can also combine the following ingredients to make your own chili seasoning: chili powder, cumin, oregano, cayenne pepper, and salt."]'::jsonb, 'http://www.foodista.com/recipe/Y4HNTZ6S/spicy-chili-w-boneless-beef-short-ribs', 'https://img.spoonacular.com/recipes/661055-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
