ixture. Continue to add mayo until the consistency is to your liking.Salt to taste."]'::jsonb, 'http://www.foodista.com/recipe/32TFG87M/chili-chicken-salad', 'https://img.spoonacular.com/recipes/638550-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spicy-chicken-corn-dogs-with-homemade-chili-sauce', 'Spicy Chicken Corn Dogs with Homemade Chili Sauce', 8, 0, 0, '{"calories": 554, "protein": 13.43, "carbs": 42.38, "fat": 38.35, "saturated_fat": 4.24, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 833.75, "potassium": null, "fiber": 3.97, "sugar": 9.91, "vitamin_a": null, "vitamin_c": 6.46, "calcium": 82.12, "iron": 2.75}'::jsonb, ARRAY['american', 'fingerfood', 'lunch', 'antipasti', 'main course', 'starter', 'snack', 'appetizer', 'main dish', 'antipasto', 'dinner', 'hor d''oeuvre', 'gluten free', 'dairy free', 'spoonacular', 'dessert', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "", "item": "ancho chili pepper", "notes": "1 ancho chili pepper", "category": "produce"}, {"quantity": 2.0, "unit": "large", "item": "prunes", "notes": "2 large pitted prunes", "category": "dried fruits"}, {"quantity": 1.0, "unit": "cup", "item": "beef broth", "notes": "1 cup low-sodium chicken or beef broth", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "cup", "item": "fire-roasted tomatoes", "notes": "1 cup fire-roasted tomatoes", "category": "canned and jarred"}, {"quantity": 0.25, "unit": "cup", "item": "tomato paste", "notes": "¼ cup tomato paste", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "small", "item": "onion", "notes": "1 small onion, peeled cut into quarters", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "molasses", "notes": "1 teaspoon molasses", "category": "baking"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves garlic, peeled", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "pumpkin seeds", "notes": "¼ cup raw, unsalted pumpkin seeds", "category": "savory snacks"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ground cumin", "notes": "1 teaspoon ground cumin", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "oregano", "notes": "1 teaspoon fresh oregano", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "masa harina", "notes": "½ cup masa harina, Masabrosa preferred (see Kitchen Tip #1)", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "cornmeal", "notes": "¼ cup stone-ground cornmeal", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "cup", "item": "rice flour", "notes": "1 cup rice flour, divided", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "baking powder", "notes": "1 teaspoon baking powder", "category": "baking"}, {"quantity": 2.0, "unit": "tablespoons", "item": "brown sugar", "notes": "2 tablespoons brown sugar", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "kosher salt", "notes": "½ teaspoon kosher salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "large", "item": "eggs", "notes": "2 large eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "", "item": "juice of lime", "notes": "Juice of 1 lime", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "rice milk", "notes": "½ cup plus 2 tablespoons rice milk", "category": "milk, eggs, other dairy"}, {"quantity": 5.0, "unit": "cups", "item": "canola oil", "notes": "5 cups peanut or canola oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "", "item": "spicy chicken sausage links", "notes": "4 spicy cooked chicken sausage links", "category": "meat"}]'::jsonb, '["Soak 8 bamboo skewers in water for at least 30 minutes. Set aside.", "Cut the top of the dried chili and shake out the seeds.", "Transfer them into a saucepan along with the prunes, broth, tomatoes, tomato paste, onion, molasses, garlic, pumpkin seeds, cumin, and oregano. Bring the mixture to a boil over high heat and cook for 2 minutes; then lower the heat to a simmer and cook for 20 minutes more.", "Using an immersion blender, puree the mixture until completely smooth. Return to the heat and simmer, uncovered, for another 15 to 20 minutes. (If you dont have an immersion blender, carefully ladle the sauce into a food processor, and process until smooth, working in batches; then return to the pot.) Set the sauce aside until ready to serve with the corndogs, or if you are making this ahead of time, once the sauce has cooled, transfer it to a container and refrigerate.", "In a mixing bowl, combine the masa harina, cornmeal,  cup of the rice flour, baking powder, brown sugar, and salt and mix to combine.", "Add the eggs, one at a time, mixing well to combine.", "Add the rice milk and lime juice and mix to combine. The mixture should resemble a thick pancake batter; if more milk is needed, add by the tablespoonful. Cover and refrigerate the mixture if you are not going to be frying right away.", "When you are ready to cook, heat the oil in a saucepan until it registers 350F on a deep-frying thermometer. While the oil is heating, place the remaining rice flour on a paper plate and set aside.", "Cut each chicken sausage in half crosswise, to make eight pieces.", "Roll each piece of sausage in the rice flour to lightly coat. Thread the moistened bamboo skewers through the sausage pieces, so that the tips of the skewers are not quite poking out the top. Holding it by its skewer, dip a floured sausage piece into the batter, until it is completely coated. Carefully lift the stick and hold it over the bowl for a few seconds, allowing any excess batter to drip off. Repeat with another skewer. Carefully place two corn dogs into the hot oil and cook until they are crusty on the outside, and dark golden brown, 3 to 4 minutes.", "Drain on paper towels and keep warm. Repeat with each skewered sausage, allowing the oil to return to 350F in between.", "Serve immediately with the chili."]'::jsonb, 'https://www.foodista.com/recipe/VVLHPBNS/spicy-chicken-corn-dogs-with-homemade-chili-sauce', 'https://img.spoonacular.com/recipes/661048-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('game-day-jerk-wings', 'Game Day Jerk Wings', 10, 0, 0, '{"calories": 721, "protein": 54.06, "carbs": 10.49, "fat": 50.88, "saturated_fat": 15.19, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 3072.27, "potassium": null, "fiber": 2.56, "sugar": 5.39, "vitamin_a": null, "vitamin_c": 3.71, "calcium": 59.12, "iron": 3.74}'::jsonb, ARRAY['american', 'antipasti', 'lunch', 'main course', 'starter', 'snack', 'appetizer', 'main dish', 'antipasto', 'hor d''oeuvre', 'dinner', 'gluten free', 'ketogenic', 'spoonacular', 'grilling'], '[{"quantity": 60.0, "unit": "jumbo", "item": "chicken wings", "notes": "60 jumbo chicken wings split with wing tips removed", "category": "meat"}, {"quantity": 0.25, "unit": "cup", "item": "pasilla chile powder", "notes": "1/4 cup pasilla chile powder", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "kosher salt", "notes": "1/4 cup kosher salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "ground pepper", "notes": "1 tablespoon ground black pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "ground cayenne pepper", "notes": "2 tablespoons ground cayenne pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "jamaican ground allspice", "notes": "2 tablespoons jamaican ground allspice", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "bottle", "item": "pickapeppa sauce", "notes": "1 bottle Pickapeppa Sauce (available at most supermarkets)", "category": "condiments"}, {"quantity": 3.0, "unit": "tablespoons", "item": "butter", "notes": "3 tablespoons of unsalted butter", "category": "milk, eggs, other dairy"}, {"quantity": 3.0, "unit": "tablespoons", "item": "honey", "notes": "3 tablespoons honey", "category": "nut butters, jams, and honey"}, {"quantity": 5.0, "unit": "dashes", "item": "tabasco sauce", "notes": "5 or more dashes Tabasco sauce (depending how hot you like it!)", "category": "condiments"}, {"quantity": 1.0, "unit": "tablespoon", "item": "pepper flakes", "notes": "1 tablespoon red pepper flakes", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "sticks", "item": "carrot and celery sticks", "notes": "carrot sticks and celery sticks", "category": "produce"}, {"quantity": 10.0, "unit": "servings", "item": "cheese dressing", "notes": "Blue Cheese Dressing", "category": "cheese"}]'::jsonb, '["Split wings apart into 2 sections and slash a slit in the flat part of the wing for quicker cooking.", "Combine chile powder, salt, black pepper, cayenne, and allspice in a bowl and sprinkle liberally over the wings (you don''t need to use all of it).  Refrigerate for at least 1 hour.", "Combine Pickapeppa sauce, butter, honey, Tabasco, and pepper flakes in a medium saucepan over low heat until it is well incorporated.", "Let wings come to room temperature.", "Prepare grill for medium high direct heat. Grill dry rubbed wings for 20-25 mins, constantly turning the wings with tongs to maintain good grill marks without over-charing the wings. Take the biggest wing after 20 mins and take a bite out of it, and if the juices run clear, they are done.", "Place wings in a large bowl and toss with the jerk sauce.", "Serve with blue cheese dressing and carrots."]'::jsonb, 'https://www.foodista.com/recipe/HZFC3WHJ/game-day-jerk-wings', 'https://img.spoonacular.com/recipes/644149-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cheesy-bacon-burger-with-spicy-chipotle-aiolo-sauce', 'Cheesy Bacon Burger with Spicy Chipotle Aiolo Sauce', 4, 0, 0, '{"calories": 475, "protein": 49.05, "carbs": 27.67, "fat": 18.22, "saturated_fat": 7.27, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 743.51, "potassium": null, "fiber": 3.24, "sugar": 6.27, "vitamin_a": null, "vitamin_c": 33.18, "calcium": 161.5, "iron": 6.59}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'breakfast', 'grilling'], '[{"quantity": 2.0, "unit": "teaspoons", "item": "chipotle chiles in adobo", "notes": "2 teaspoons Chopped Chipotle Chiles In Adobo", "category": "canned and jarred"}, {"quantity": 3.0, "unit": "Tablespoons", "item": "mayonnaise", "notes": "3 Tablespoons Fat Free Mayonnaise", "category": "condiments"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": "1 clove garlic, pressed or grated", "category": "produce"}, {"quantity": 0.25, "unit": "teaspoons", "item": "garlic powder", "notes": "¼ teaspoons Garlic Powder", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "Tablespoons", "item": "greek yogurt", "notes": "3 Tablespoons Greek Yogurt, Non-fat", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "bell pepper", "notes": "1 cup Green Bell Pepper, Sliced Into Strips", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoons", "item": "ground cumin", "notes": "½ teaspoons Ground Cumin", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoons", "item": "ground pepper", "notes": "¼ teaspoons Ground Black Pepper", "category": "spices and seasonings"}, {"quantity": 1.5, "unit": "pounds", "item": "ground beef", "notes": "1 1/2 pounds lean ground beef", "category": "meat"}, {"quantity": 4.0, "unit": "teaspoons", "item": "lime juice", "notes": "4 teaspoons Lime Juice, Fresh", "category": "produce"}, {"quantity": 0.5, "unit": "cups", "item": "onion", "notes": "½ cups Onion, Sliced Into Strips", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "wedges of laughing cow swiss cheese", "notes": "2 whole Wedges Of Laughing Cow Swiss Cheese, Sliced In Half", "category": "cheese"}, {"quantity": 4.0, "unit": "slices", "item": "turkey bacon", "notes": "4 slices Turkey Bacon, Cooked According To Package", "category": "meat"}, {"quantity": 4.0, "unit": "", "item": "hamburger buns", "notes": "4 whole Wheat Hamburger Buns", "category": "bakery/bread"}]'::jsonb, '["For Burgers:In a pan cook turkey bacon according to directions on package.Once bacon is done being cooked, take the bacon out and set aside.", "Add bell pepper and onion into same pan, cook until tender about 10 minutes.", "Add ground beef to a small bowl, add garlic powder and ground pepper, mix well.Divide the raw meat into 8 equal pieces (I used my scale to measure into 2oz each piece). Flatten out the hamburger, and place 1/2 a cheese wedge onto each piece of hamburger. Take the other pieces of the hamburger and place on top of the cheese , and squish them togther and seal the edges so the cheese doesnt ozzz out.", "Place on grill and cook until done. About 5 minutes per side.", "Place burger on buns, top the burgers with bacon, peppers & onions and sauce.For Spicy Chipotle Aiolo Sauce:In a small bowl place all the ingredients together and wisk together until combined.Makes 3/4 cups or 12 Tablespoons"]'::jsonb, 'http://www.foodista.com/recipe/VWDL3M4T/cheesy-bacon-burger-with-spicy-chipotle-aiolo-sauce', 'https://img.spoonacular.com/recipes/637631-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('drunken-turkey-chili', 'Drunken Turkey Chili', 8, 0, 0, '{"calories": 190, "protein": 18.46, "carbs": 16.89, "fat": 5.25, "saturated_fat": 0.88, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 477.75, "potassium": null, "fiber": 5.85, "sugar": 3.01, "vitamin_a": null, "vitamin_c": 31.68, "calcium": 59.02, "iron": 2.89}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'dessert'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "extra virgin olive oil", "notes": "2 tablespoons extra virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "large", "item": "onion", "notes": "1 large white onion, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 red bell pepper, chopped", "category": "produce"}, {"quantity": 4.0, "unit": "cloves", "item": "garlic", "notes": "4-6 cloves garlic, minced", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "jalapeno peppers", "notes": "2 jalapeno peppers, minced", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "tablespoons", "item": "paprika", "notes": "1-2 tablespoons smoked paprika", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "chili powder", "notes": "2-4 teaspoons of chili powder, or more to taste", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "ground cumin", "notes": "2 teaspoons ground cumin", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "pepper", "notes": "1 teaspoon black pepper", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "cocoa powder", "notes": "1/4 teaspoon unsweetened cocoa powder", "category": "baking"}, {"quantity": 1.0, "unit": "pound", "item": "ground turkey meat", "notes": "1 pound lean ground turkey meat", "category": "meat"}, {"quantity": 14.5, "unit": "ounce", "item": "canned tomatoes", "notes": "1 14.5 ounce can peeled tomatoes", "category": "canned and jarred"}, {"quantity": 16.0, "unit": "ounce", "item": "black beans", "notes": "1 16 ounce can black beans, drained and rinsed", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "bottle", "item": "beer", "notes": "1 bottle of beer (I used Miller Light)", "category": "alcoholic beverages"}, {"quantity": 2.0, "unit": "tablespoons", "item": "soy sauce", "notes": "2 tablespoons low-sodium soy sauce", "category": "condiments"}, {"quantity": 1.0, "unit": "bunch", "item": "cilantro", "notes": "1 bunch of fresh cilantro, minced", "category": "spices and seasonings"}]'::jsonb, '["Gently heat the oil in a large pot. Do not let it smoke!", "Add the onion, bell pepper, garlic, and jalapenos.", "Saute over medium heat until soft, about 5 minutes.", "Add all powdered spices and stir to coat vegetables.", "Add turkey.", "Saute for three or four minutes, until just cooked through. Use your spoon or spatula to break it up.", "Drain the juice from the peeled tomatoes into your chili pot. Then finely chop the tomatoes and add them as well. Stir.", "Add the black beans, the beer, and the soy sauce. Stir.", "Add cilantro and stir well.", "Cover and allow to simmer over low heat for five to ten minutes. Then turn off the heat and let it rest for about fifteen minutes before serving.", "Optional", "Garnishes: Top with low-fat sour cream, grated cheese, avocado slices, chopped green onions, or anything else that suits your fancy! I love to eat it with tortilla chips."]'::jsonb, 'https://www.foodista.com/recipe/5KJFZQ7L/drunken-turkey-chili', 'https://img.spoonacular.com/recipes/641679-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('salmon-caesar-salad', 'Salmon Caesar Salad', 2, 0, 0, '{"calories": 393, "protein": 26.9, "carbs": 7.17, "fat": 28.96, "saturated_fat": 6.62, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 835.98, "potassium": null, "fiber": 3.24, "sugar": 2.54, "vitamin_a": null, "vitamin_c": 10.39, "calcium": 307.1, "iron": 2.4}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'gluten free', 'primal', 'pescatarian', 'ketogenic', 'spoonacular'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "caesar dressing", "notes": "2 tablespoons light caesar dressing", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tablespoons", "item": "lemon juice", "notes": "2 tablespoons freshly squeezed lemon juice", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "olive oil", "notes": "1 tablespoon Olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.25, "unit": "teaspoon", "item": "paprika", "notes": "1/4 teaspoon paprika", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "tablespoons", "item": "parmesan cheese", "notes": "8 tablespoons Parmesan cheese, shredded", "category": "cheese"}, {"quantity": 2.0, "unit": "servings", "item": "add pepper", "notes": "add black pepper to taste", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "oz", "item": "romaine", "notes": "1 8 oz head of Romaine", "category": "produce"}, {"quantity": 6.0, "unit": "ounces", "item": "salmon fillet", "notes": "6 ounces Salmon fillet", "category": "seafood"}, {"quantity": 0.25, "unit": "teaspoon", "item": "salt", "notes": "1/4 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "slivered almonds", "notes": "1 tablespoon slivered almonds", "category": "baking"}]'::jsonb, '["Heat up a skillet/frying pan and sir the Salmon in the coconut oil/olive oil (don''t forget to add the salt and paprika to it) until very lightly browned on each side (i like my salmon slightly undercooked-its up to you if you want it more done). Top with freshly squeezed lemon juice and let it sit in the frying pan for about 1 minute. In a Large bowl, mix the romaine lettuce with the Caesar salad dressing and dump it out into a large plate, top off with Asiago/Parmesan cheese and you can also sprinkle the toasted almonds on now.", "Place the Salmon (sliced) on top. You can sprinkle it with some more fresh lemon juice:) and black pepper!"]'::jsonb, 'http://www.foodista.com/recipe/36WZD7DS/healthy-salmon-caesar-salad-recipe', 'https://img.spoonacular.com/recipes/646512-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bbq-mac-and-cheese', 'BBQ Mac and Cheese', 4, 0, 0, '{"calories": 812, "protein": 36.22, "carbs": 109.2, "fat": 25.59, "saturated_fat": 13.88, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1250.65, "potassium": null, "fiber": 4.94, "sugar": 17.21, "vitamin_a": null, "vitamin_c": 16.05, "calcium": 553.86, "iron": 2.94}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'dessert', 'pasta', 'baking', 'grilling', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "cottage cheese", "notes": "1 cup cottage cheese", "category": "cheese"}, {"quantity": 0.5, "unit": "cup", "item": "parmesan cheese", "notes": "½ cup Parmesan cheese", "category": "cheese"}, {"quantity": 0.5, "unit": "cup", "item": "ketchup", "notes": "½ cup ketchup", "category": "condiments"}, {"quantity": 1.0, "unit": "tsp", "item": "brown sugar", "notes": "1 tsp. brown sugar", "category": "baking"}, {"quantity": 0.5, "unit": "", "item": "jalapeño", "notes": "½ jalapeño", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "cup", "item": "parsley", "notes": "½ cup Italian parsley", "category": "produce"}, {"quantity": 1.25, "unit": "cup", "item": "milk", "notes": "1¼ cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves garlic", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 onion – diced", "category": "produce"}, {"quantity": 0.75, "unit": "tsp", "item": "ground cumin", "notes": "¾ tsp. ground cumin", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "salt", "notes": "½ tsp. salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "pepper", "notes": "½ tsp. black pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "Tbs", "item": "butter", "notes": "2-3 Tbs. butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "cheddar cheese or", "notes": "1 cup cheddar cheese shredded or your favorite", "category": "cheese"}, {"quantity": 0.25, "unit": "cup", "item": "style breadcrumbs", "notes": "¼ cup Italian style breadcrumbs or homemade breadcrumbs", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "lb", "item": "macaroni", "notes": "1 lb. of your favorite macaroni", "category": "pasta and rice"}]'::jsonb, '["Prepare the macaroni as directed.", "Combine in a food processor the cottage cheese, milk, Parmesan cheese, ketchup, brown sugar, jalapeo, garlic, parsley and seasonings.", "Heat a frying pan with butter and saut the onions until softened and transparent.", "Heat another frying pan with a pat of butter; add the bread crumbs; toss and brown a bit.", "Butter a baking dish.", "Add the macaroni, the mixture from the food processor, the shredded cheese, the onions and toss.", "Top with the bread crumbs a few pats of butter and grated Parmesan cheese and a little shredded cheese.", "Bake 25  30 minutes; until slightly golden."]'::jsonb, 'https://www.foodista.com/recipe/FNMKDX42/bbq-mac-and-cheese', 'https://img.spoonacular.com/recipes/634496-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ancho-chipotle-chili', 'Ancho Chipotle Chili', 2, 0, 0, '{"calories": 697, "protein": 43.21, "carbs": 40.64, "fat": 42.69, "saturated_fat": 15.78, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1564.43, "potassium": null, "fiber": 13.52, "sugar": 23.85, "vitamin_a": null, "vitamin_c": 104.82, "calcium": 143.5, "iron": 9.38}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'paleolithic', 'primal', 'whole 30', 'spoonacular'], '[{"quantity": 1.0, "unit": "", "item": "ancho chile", "notes": "1 dried ancho chile", "category": "produce"}, {"quantity": 5.0, "unit": "g", "item": "vegetable bouillon powder", "notes": "5 g vegetable bouillon powder", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "tsp", "item": "cumin", "notes": "1 tsp cumin", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "chipotle chile", "notes": "1 dried chipotle chile", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "cilantro", "notes": "fresh cilantro", "category": "spices and seasonings"}, {"quantity": 400.0, "unit": "grams", "item": "ground beef", "notes": "400 grams ground beef", "category": "meat"}, {"quantity": 6.0, "unit": "large", "item": "mushrooms", "notes": "6 large mushrooms, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 onion, chopped", "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "oregano", "notes": "2 tsp dried oregano", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 red bell pepper, chopped", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper", "category": "spices and seasonings"}, {"quantity": 500.0, "unit": "grams", "item": "tomato sauce", "notes": "500 grams tomato sauce", "category": "canned and jarred"}, {"quantity": 500.0, "unit": "ml", "item": "water", "notes": "500 ml hot water", "category": "beverages"}]'::jsonb, '["Slice open the dried ancho and chipotle chili and remove the seeds/pith.", "Place the dried chili peppers in a warm skillet (medium heat) and press them flat with a spatula to toast them for a few seconds per side until fragrant (be careful not to burn them!). Be sure to wear gloves or wash your hands directly after handling the chili peppers.", "Remove the dried chili and put them in a bowl or sauce pan.", "Pour 250 ml boiling water over it and leave it to soak for at least 15 minutes.", "In a large pot, saute the chopped bell pepper, onion, and mushrooms over medium heat.", "Meanwhile, fry the beef in a hot skillet until crispy.", "While the beef is frying, blend the chili peppers you''ve been soaking with the soaking liquid.", "Add the beef to the large pot filled with the sauteed vegetables.", "Add the tomato sauce and blended chili peppers to the pot. If it is not enough liquid, add beef or vegetable broth (the other 250 ml water and 5 grams bouillon powder, unless you have \"real\" broth on hand) until everything is covered.", "Season with salt, pepper, cumin, and oregano to taste.", "Simmer for about 45 minutes or until thick enough.", "Serve with fresh cilantro."]'::jsonb, 'https://spoonacular.com/-1409557476964', 'https://img.spoonacular.com/recipes/610281-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('quinoa-and-kidney-bean-burgers', 'Quinoa and Kidney Bean Burgers', 4, 0, 0, '{"calories": 254, "protein": 12.16, "carbs": 45.55, "fat": 2.86, "saturated_fat": 0.54, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1177.14, "potassium": null, "fiber": 7.36, "sugar": 5.76, "vitamin_a": null, "vitamin_c": 2.63, "calcium": 107.57, "iron": 3.74}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 0.25, "unit": "cup", "item": "quinoa", "notes": "1/4 cup Uncooked Quinoa", "category": "pasta and rice"}, {"quantity": 0.5, "unit": "cup", "item": "water", "notes": "1/2 cup Water", "category": "beverages"}, {"quantity": 0.5, "unit": "", "item": "onion", "notes": "1/2 white Onion", "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": "1 clove garlic", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "chilli powder", "notes": "1 tsp Chilli Powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "ground cumin", "notes": "1/2 tsp Ground Cumin", "category": "spices and seasonings"}, {"quantity": 14.0, "unit": "oz", "item": "kidney beans", "notes": "1 14 oz can Kidney Beans", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tbsp", "item": "soy sauce", "notes": "2 tbsp Soy Sauce", "category": "ethnic foods"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "", "item": "burger buns", "notes": "4 burger buns", "category": "bakery/bread"}]'::jsonb, '["Preheat the oven to 200C.", "Place the quinoa and water in a saucepan and cover with a lid. Bring to a boil. Once the water is boiling, reduce the heat so that it''s simmering. Cook until all the water has been absorbed by the quinoa, then fluff it up with a fork.", "Drain and rinse the kidney beans and place them in a large bowl. Mash thoroughly with a fork.Dice the onion and saute on a medium heat with a little olive oil for 2-3 minutes until the onion starts to become translucent. Mince the garlic clove and add to the pan, stir it around and cook for a further minute.", "Add the chilli powder and cumin to the onion mix and cook for 2 minutes until the spices are fragrant.", "Add the whole mixture to the bowl with the beans.Also add the quinoa into the bean bowl with the soy sauce and mix everything together. If desired, season with a little salt and pepper.Shape the mixture into 4 burgers about 1 inch thick.", "Place on a flat baking tray lined with parchment paper and bake for 8 minutes. Then, carefully flip the burgers using a spatula and bake for another 8 minutes.", "Remove from the oven and allow to cool for around 5 minutes before serving.Top with your favourite burger toppings in a bun of your choice!"]'::jsonb, 'https://www.foodista.com/recipe/QYLZ438Q/quinoa-and-kidney-bean-burgers', 'https://img.spoonacular.com/recipes/1095755-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('turkey-burgers-with-slaw', 'Turkey Burgers with Slaw', 2, 0, 0, '{"calories": 422, "protein": 45.53, "carbs": 7.51, "fat": 24.64, "saturated_fat": 8.96, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 306.54, "potassium": null, "fiber": 2.95, "sugar": 3.56, "vitamin_a": null, "vitamin_c": 21.0, "calcium": 42.49, "iron": 2.54}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'paleolithic', 'primal', 'fodmap friendly', 'whole 30', 'spoonacular', 'salad', 'baking', 'grilling'], '[{"quantity": 13.0, "unit": "oz", "item": "ground turkey", "notes": "13 oz of ground turkey", "category": "meat"}, {"quantity": 2.0, "unit": "Tablespoons", "item": "olive oil", "notes": "2 Tablespoons of olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 3.0, "unit": "oz", "item": "cabbage", "notes": "3 oz of cabbage", "category": "produce"}, {"quantity": 2.0, "unit": "Tablespoons", "item": "coconut cream", "notes": "2 Tablespoons of coconut cream", "category": "health foods"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "lime juice", "notes": "1 Tablespoon of lime juice", "category": "produce"}, {"quantity": 2.0, "unit": "Tablespoons", "item": "cilantro", "notes": "2 Tablespoons of fresh cilantro", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "Tablespoons", "item": "coconut", "notes": "2 Tablespoons of shredded coconut", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "lettuce", "notes": "Lettuce, to serve", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "salt", "notes": "Salt", "category": "spices and seasonings"}]'::jsonb, '["The Patties", "Preheat the oven to 320F (160C).Season turkey with salt and form into 4 large patties.", "Heat olive oil in a pan. Grill patties until golden on both sides.", "Transfer patties to the cooking sheet and bake for 15 minutes.The Toppings", "Combine the cabbage and coconut cream. Season with lime juice and salt. Stir in chopped cilantro.", "Add coconut to a clean, dry pan and toast until golden. Set aside.", "Serve the turkey burgers on lettuce, topped with the slaw and toasted coconut."]'::jsonb, 'https://www.foodista.com/recipe/XVMGHL2B/aip-turkey-burgers-with-slaw-recipe', 'https://img.spoonacular.com/recipes/1096267-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('simple-caesar-salad', 'Simple Caesar Salad', 6, 0, 0, '{"calories": 541, "protein": 13.78, "carbs": 41.44, "fat": 35.63, "saturated_fat": 18.04, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 785.66, "potassium": null, "fiber": 2.93, "sugar": 23.79, "vitamin_a": null, "vitamin_c": 1.81, "calcium": 216.53, "iron": 2.18}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'pescatarian', 'spoonacular', 'baking'], '[{"quantity": 3.0, "unit": "fillet", "item": "anchovy", "notes": "3 anchovy fillets", "category": "seafood"}, {"quantity": 2.0, "unit": "teaspoons", "item": "dijon mustard", "notes": "2 teaspoons Dijon mustard", "category": "condiments"}, {"quantity": 0.5, "unit": "cup", "item": "tablespoons extra virgin olive oil", "notes": "1/2 cup + 3 tablespoons extra virgin olive oil, divided", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "cloves", "item": "garlic", "notes": "4 cloves garlic, divided", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "hardboiled egg", "notes": "1 hard-boiled egg, chopped", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "loaf", "item": "bread", "notes": "1 loaf Italian bread", "category": "bakery/bread"}, {"quantity": 0.5, "unit": "", "item": "juice of lemon", "notes": "1/2 lemon, juiced", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "oregano", "notes": "1 teaspoon dried oregano", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "parmesan cheese", "notes": "1 cup shredded Parmesan cheese", "category": "cheese"}, {"quantity": 2.0, "unit": "tablespoons", "item": "red wine vinegar", "notes": "2 tablespoons red wine vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 3.0, "unit": "inches", "item": "romaine lettuce hearts", "notes": "3 inches romaine lettuce hearts, cut 2-inch pieces", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and Pepper to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "worcestershire sauce", "notes": "1 teaspoon Worcestershire sauce", "category": "condiments"}]'::jsonb, '["Preheat the oven to 400 degrees F.To make the croutons, cut the crust off the bread and cut the loaf into cubes.", "Place the cubes in a large mixing bowl.In a small pan over medium heat, add the oil, 1 clove of minced garlic, and oregano.Cook for two minutes, giving the pan a shake often.", "Pour the flavored oil over the bread cubes and toss.Season with salt and pepper.", "Spread the bread cubes in a single layer on a baking sheet and bake for 10 minutes.In a blender, add the lemon juice, remaining garlic cloves, anchovy fillets, mustard, lemon, vinegar, Worcestershire, hard-boiled egg, salt, and pepper.Process until garlic is well minced and a paste forms.With the blender still running, slowly drizzle in the olive oil. Taste for seasonings.", "Put the lettuce in a large bowl.", "Drizzle the dressing over the salad and toss.", "Add the cheese and croutons and toss well.Season with more black pepper to taste.", "Serve immediately, topping with the rest of the anchovies, if you like."]'::jsonb, 'http://www.foodista.com/recipe/F4V2LJGP/simple-caesar-salad', 'https://img.spoonacular.com/recipes/660085-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tortilla-burger-loco-vaca', 'Tortilla Burger Loco Vaca', 2, 0, 0, '{"calories": 1124, "protein": 51.47, "carbs": 42.11, "fat": 84.38, "saturated_fat": 27.91, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1030.31, "potassium": null, "fiber": 12.4, "sugar": 8.25, "vitamin_a": null, "vitamin_c": 109.58, "calcium": 279.59, "iron": 6.85}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'breakfast', 'baking'], '[{"quantity": 1.0, "unit": "", "item": "avocado", "notes": "1 avocado", "category": "produce"}, {"quantity": 4.0, "unit": "slices", "item": "bacon", "notes": "4 slices of bacon", "category": "meat"}, {"quantity": 2.0, "unit": "slices", "item": "cheddar cheese", "notes": "2 slices cheddar cheese", "category": "cheese"}, {"quantity": 2.0, "unit": "servings", "item": "cilantro", "notes": "cilantro", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "servings", "item": "cumin", "notes": "cumin", "category": "spices and seasonings"}, {"quantity": 400.0, "unit": "g", "item": "ground beef", "notes": "400g ground beef", "category": "meat"}, {"quantity": 2.0, "unit": "servings", "item": "oil", "notes": "oil for frying", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "servings", "item": "bell pepper", "notes": "pepper", "category": "produce"}, {"quantity": 1.0, "unit": "large", "item": "onion", "notes": "1 large red onion", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "salt", "notes": "salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "wheat tortillas", "notes": "2 wheat tortillas", "category": "bakery/bread"}]'::jsonb, '["Put the tortillas in the oven at about 80°C just to get them warm.Fry the strips of bacon until crispy, then put the bacon in the oven to keep it warm.Spice the ground beef with salt, pepper, and cumin.Form 2 large patties and start frying the patties in a well heated pan.Slice the avocado and the red onion.Get the tortillas out of the oven and prepare them with the onion, avocado, bacon, cheddar, cilantro, and the patties.Wrap it all up and then wrap your teeth around it."]'::jsonb, 'https://spoonacular.com/-1418388808652', 'https://img.spoonacular.com/recipes/622825-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('skillet-chili-mac', 'Skillet Chili Mac', 6, 0, 0, '{"calories": 430, "protein": 30.49, "carbs": 34.29, "fat": 18.65, "saturated_fat": 9.17, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 520.78, "potassium": null, "fiber": 2.1, "sugar": 3.98, "vitamin_a": null, "vitamin_c": 1.91, "calcium": 302.78, "iron": 3.11}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'dessert', 'soup', 'pasta'], '[{"quantity": 1.5, "unit": "t", "item": "canola oil", "notes": "1 1/2 t. canola oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "lb", "item": "ground beef", "notes": "1 lb. lean ground beef", "category": "meat"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 onion, chopped fine", "category": "produce"}, {"quantity": 1.0, "unit": "T", "item": "chili powder", "notes": "1 T. chili powder", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "t", "item": "ground cumin", "notes": "2 t. ground cumin", "category": "spices and seasonings"}, {"quantity": 0.125, "unit": "t", "item": "cayenne pepper", "notes": "1/8 - 1/4 t. cayenne pepper (to taste, I used 1/8 t.)", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "servings", "item": "salt & pepper", "notes": "salt & pepper", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "", "item": "garlic cloves", "notes": "3 garlic cloves, minced", "category": "produce"}, {"quantity": 1.0, "unit": "T", "item": "brown sugar", "notes": "1 T. brown sugar", "category": "baking"}, {"quantity": 2.0, "unit": "c", "item": "water", "notes": "2 c. water", "category": "beverages"}, {"quantity": 8.0, "unit": "oz", "item": "grain macaroni", "notes": "8 oz. whole grain macaroni", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "c", "item": "cheddar cheese", "notes": "2 c. shredded cheddar cheese", "category": "cheese"}]'::jsonb, '["Heat the oil in a large (12 inch) nonstick skillet over medium-high heat.", "Add the ground beef, onion, chili powder, cumin, cayenne and 1/2 t. salt. Cook, breaking up meat into small pieces, until it looses all the pink color, about 5 minutes.", "Add garlic and cook until fragrant, about 30 seconds or so.", "Add brown sugar, tomato sauce, water and macaroni. Bring to a boil. Cover and cook, stirring often and adjusting the heat so that it maintains a lively simmer (somewhere between medium/medium-high heat), until the macaroni is tender, about 10 minutes or so. Season with salt & pepper if needed.", "Off heat, stir in half the cheese.", "Sprinkle the remaining cheese on top."]'::jsonb, 'https://www.foodista.com/recipe/T5H745JJ/skillet-chili-mac', 'https://img.spoonacular.com/recipes/660216-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('caribbean-cobb-salad-with-fire-roasted-pineapple-vinaigrette', 'Caribbean Cobb Salad with Fire-Roasted Pineapple Vinaigrette', 4, 0, 0, '{"calories": 307, "protein": 18.51, "carbs": 20.34, "fat": 18.7, "saturated_fat": 3.49, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 287.15, "potassium": null, "fiber": 7.89, "sugar": 10.93, "vitamin_a": null, "vitamin_c": 68.4, "calcium": 68.77, "iron": 2.29}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'gluten free', 'dairy free', 'paleolithic', 'primal', 'whole 30', 'spoonacular', 'breakfast', 'baking', 'grilling'], '[{"quantity": 2.0, "unit": "", "item": "chicken breasts", "notes": "2 boneless, skinless chicken breasts", "category": "meat"}, {"quantity": 3.0, "unit": "teaspoons", "item": "jamaican jerk seasoning", "notes": "3 teaspoons Jamaican Jerk Seasoning", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "romaine hearts torn into bite-sized pieces", "notes": "2 romaine hearts torn into bite-sized pieces", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 red bell pepper, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "large", "item": "mango", "notes": "1 mango, large dice", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "avocado", "notes": "1 avocado, diced", "category": "produce"}, {"quantity": 4.0, "unit": "slices", "item": "bacon", "notes": "4 slices bacon, cooked and crumbled", "category": "meat"}, {"quantity": 5.0, "unit": "", "item": "scallions", "notes": "5 scallions, white and green parts sliced", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "macadamia nuts", "notes": "1/4 cup chopped macadamia nuts", "category": "nuts"}, {"quantity": 0.5, "unit": "cup", "item": "fire-roasted pineapple vinaigrette", "notes": "1/2 cup Fire-Roasted Pineapple Vinaigrette", "category": "canned and jarred"}]'::jsonb, '["Heat grill. Coat the chicken breasts liberally with the jerk seasoning and cook the chicken on both sides until cooked through, approximately 10 minutes.", "Transfer to a plate and cover with foil. Allow the chicken to rest for 10 minutes while you prepare the rest of the salad.", "In a large bowl, add the torn romaine hearts and top with the bell pepper, mango, avocado, bacon and scallions.", "Cut the chicken into cubes and add to the salad.", "Sprinkle the salad with the macadamia nuts and serve with the Fire-Roasted Pineapple Vinaigrette on the side or serve with your favorite dressing."]'::jsonb, 'https://www.foodista.com/recipe/ZKCX6VHS/caribbean-cobb-salad-with-fire-roasted-pineapple-vinaigrette', 'https://img.spoonacular.com/recipes/637102-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ginger-garlic-chili-salmon', 'Ginger Garlic Chili Salmon', 2, 0, 0, '{"calories": 307, "protein": 34.59, "carbs": 14.94, "fat": 10.85, "saturated_fat": 1.68, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 478.03, "potassium": null, "fiber": 0.53, "sugar": 12.41, "vitamin_a": null, "vitamin_c": 3.77, "calcium": 49.01, "iron": 1.8}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'pescatarian', 'spoonacular', 'dessert', 'soup'], '[{"quantity": 2.0, "unit": "fillet", "item": "salmon", "notes": "2 salmon fillets (about half pound each)", "category": "seafood"}, {"quantity": 1.0, "unit": "Tbs", "item": "ginger", "notes": "1 Tbs minced ginger", "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves of crushed garlic", "category": "produce"}, {"quantity": 2.0, "unit": "Tbs", "item": "brown sugar", "notes": "2 Tbs brown sugar", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "rice vinegar", "notes": "1/4 cup of rice vinegar", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tsp", "item": "chili sauce", "notes": "1 tsp of hot chili sauce (add or reduce the amount as you like)", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tsp", "item": "soy sauce", "notes": "1 tsp of soy sauce", "category": "ethnic foods"}, {"quantity": 0.25, "unit": "cup", "item": "water", "notes": "1/4 cup of water", "category": "beverages"}, {"quantity": 2.0, "unit": "stalks", "item": "green onions", "notes": "2 stalks of green onions", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper for seasoning the salmon", "category": "spices and seasonings"}]'::jsonb, '["Season both sides of salmon fillets with salt and pepper. Chop green onions and put them aside. In a bowl, combine minced ginger, crushed garlic, brown sugar, rice vinegar, hot chili sauce, soy sauce and water. This is the sauce for simmering the salmon.", "In a deep skillet, pan sear the salmon on medium high heat for 4-5 minutes or until it''s almost half done on the side. Flip the salmon to the other side and sear for 2 minutes.", "Pour in the sauce when the salmon is still slightly raw in the middle, and let it simmer for 10 minutes on medium heat. When the sauce is reduced, add in the chopped green onions. Continuously scoop the sauce over the salmon for at least one minute to let the top side of the salmon absorb the sauce.", "Remove the salmon carefully from the skillet and transfer to a dish. If the sauce is not reduced to the desired consistency, leave it in the skillet and let it continue to reduce.", "Pour the sauce over the salmon and serve."]'::jsonb, 'https://www.foodista.com/recipe/HY66L25Y/ginger-garlic-chili-salmon', 'https://img.spoonacular.com/recipes/644581-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('make-ahead-creamy-macaroni-and-cheese', 'Make-Ahead Creamy Macaroni and Cheese', 10, 0, 0, '{"calories": 742, "protein": 29.2, "carbs": 46.91, "fat": 49.11, "saturated_fat": 29.77, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 797.58, "potassium": null, "fiber": 1.84, "sugar": 3.31, "vitamin_a": null, "vitamin_c": 0, "calcium": 606.59, "iron": 1.87}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'dessert', 'soup', 'pasta', 'baking'], '[{"quantity": 4.0, "unit": "slices", "item": "bread", "notes": "4 slices hearty white bread, torn into pieces", "category": "bakery/bread"}, {"quantity": 0.25, "unit": "cup", "item": "parmesan cheese", "notes": "1/4 cup grated Parmesan cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "", "item": "garlic clove", "notes": "1 garlic clove, minced", "category": "produce"}, {"quantity": 8.0, "unit": "tablespoons", "item": "butter", "notes": "8 tablespoons (1 stick) unsalted butter, melted", "category": "milk, eggs, other dairy"}, {"quantity": 10.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and Pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "pound", "item": "elbow macaroni", "notes": "1 pound elbow macaroni", "category": "pasta and rice"}, {"quantity": 6.0, "unit": "tablespoons", "item": "flour", "notes": "6 tablespoons all-purpose flour", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "mustard powder", "notes": "1 teaspoon dry mustard powder", "category": "spices and seasonings"}, {"quantity": 0.125, "unit": "teaspoon", "item": "cayenne pepper", "notes": "1/8 teaspoon cayenne pepper", "category": "spices and seasonings"}, {"quantity": 4.5, "unit": "cups", "item": "chicken broth", "notes": "4 1/2 cups low-sodium chicken broth", "category": "canned and jarred"}, {"quantity": 1.5, "unit": "cups", "item": "heavy cream", "notes": "1 1/2 cups heavy cream", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "cups", "item": "colby cheese", "notes": "4 cups shredded colby cheese", "category": "cheese"}, {"quantity": 2.0, "unit": "cups", "item": "cheddar cheese", "notes": "2 cups shredded extra-sharp cheddar cheese", "category": "cheese"}]'::jsonb, '["Process Topping - Pulse bread, Parmesan, garlic and 2 Tbsp. butter in food processor until coarsely ground.  Divide crumb mixture between 2 zip-lock freezer bags and freeze.", "Cook pasta - Bring 4 quarts water to boil in large pot.", "Add 1 Tbsp. salt and macaroni and cook until barely softened, about 3 minutes.", "Drain pasta, then spread out on rimmed baking sheet and let cool.", "Make Sauce -", "Heat remaining butter, flour, mustard, and cayenne in empty pot over medium-high heat, stirring constantly, until golden and fragrant, about 2 minutes.  Slowly whisk in broth and cream and bring to boil.  Reduce heat to medium and simmer until slightly thickened, about 15 minutes.  Off heat, whisk in colby, cheddar, 1 tsp. salt and 1/2 tsp. pepper until smooth.", "Freeze - Stir cooled pasta into sauce, breaking up any clumps, until well combined.  Divide pasta mixture between two 8-in square microwaveable baking dishes.  Cool to room temperature.  Wrap dishes tightly with plastic, cover with foil, and freeze for up to 2 months.", "Bake - Preheat oven to 375 degrees F.", "Remove foil from casserole and reserve.  Microwave casserole until mixture is thawed and beginning to bubble around the edges; 7 to 12 minutes, stirring and replacing plastic halfway through cooking.  Discard plastic and cover plan with reserved foil.", "Bake 20 minutes, then remove foil and sprinkle with 1 bag frozen bread crumbs.  Continue to bake until crumbs are golden brown and crisp, about 20 minutes longer.", "Let cool 10 minutes."]'::jsonb, 'https://www.foodista.com/recipe/7SX5R2RQ/make-ahead-creamy-macaroni-and-cheese', 'https://img.spoonacular.com/recipes/650660-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spicy-vegan-chili', 'Spicy Vegan Chili', 5, 0, 0, '{"calories": 248, "protein": 12.54, "carbs": 32.36, "fat": 8.59, "saturated_fat": 1.13, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1689.79, "potassium": null, "fiber": 7.55, "sugar": 6.1, "vitamin_a": null, "vitamin_c": 28.39, "calcium": 225.75, "iron": 3.05}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 260.0, "unit": "g", "item": "pinto beans", "notes": "1 cup ( - 260g) canned pinto beans, rinsed", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "tsp", "item": "cayenne pepper", "notes": "1/2 tsp cayenne pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tsp", "item": "chili powder", "notes": "2 tsp chili powder", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "cups", "item": "collard greens", "notes": "4 cups chopped collard greens", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "cumin", "notes": "1 tsp cumin", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "garlic cloves", "notes": "2 garlic cloves, minced or pressed", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "jalapeño pepper", "notes": "1 jalapeño pepper, diced (I kept the seeds for more spice)", "category": "canned and jarred"}, {"quantity": 1.5, "unit": "Tbs", "item": "olive oil", "notes": "1 1/2 Tbs olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 3.0, "unit": "medium", "item": "roma tomatoes", "notes": "3 medium roma tomatoes, diced", "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "salt", "notes": "2 tsp salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "medium", "item": "sweet potato", "notes": "1 medium sweet potato, peeled and diced", "category": "produce"}, {"quantity": 396.0, "unit": "g", "item": "tofu", "notes": "1 14-ounce package firm tofu (396g), rinsed and drained", "category": "produce"}, {"quantity": 3.0, "unit": "cups", "item": "vegetable broth", "notes": "3 cups vegetable broth", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "large", "item": "onion", "notes": "1/2 large yellow onion, diced", "category": "produce"}, {"quantity": 1.0, "unit": "medium", "item": "yukon potato", "notes": "1 medium yukon potato, diced", "category": "produce"}]'::jsonb, '["Heat the olive oil in a pot over medium-high heat. Once the pan is hot, add the onions. When the onions start to turn translucent, add the diced potatoes.", "Let it cook for a minute or two, and add the diced tomatoes, jalapeo, garlic, chili powder, cumin, and cayenne pepper.Cook everything for about another minute and add the vegetable broth. Bring the broth to a boil.While the chili is cooking, remove the rough stem from the collard green leaves. Chop them into strips.Once the chili has boiled, add the beans and chopped collards. Chop the tofu in half, and crumble each half with your hands. I did this right over the boiling pot. Be careful of hot liquids splashing out!Season with the salt and boil for another 5-10 minutes, or until the potatoes can be easily pierced with a fork.Turn off the heat and serve the chili with some ground pepper.Store any leftovers in an airtight container."]'::jsonb, 'https://www.foodista.com/recipe/QMJ37S4P/spicy-vegan-chili', 'https://img.spoonacular.com/recipes/661223-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, i