INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('crab-and-shrimp-burgers-with-garlic-grits-fries', 'Crab and Shrimp Burgers With Garlic Grits Fries', 8, 0, 0, '{"calories": 367, "protein": 24.45, "carbs": 42.73, "fat": 10.94, "saturated_fat": 4.4, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1665.18, "potassium": null, "fiber": 2.55, "sugar": 4.37, "vitamin_a": null, "vitamin_c": 10.12, "calcium": 206.48, "iron": 3.25}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'pescatarian', 'spoonacular', 'baking', 'grilling'], '[{"quantity": 1.5, "unit": "cups", "item": "shrimp", "notes": "1 1/2 cups large shrimp, cleaned, peeled and chopped", "category": "seafood"}, {"quantity": 1.5, "unit": "cups", "item": "crab meat", "notes": "1 1/2 cups fresh crab meat", "category": "seafood"}, {"quantity": 1.0, "unit": "", "item": "juice of lemon", "notes": "1 Zest and juice of lemon", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "tabasco sauce", "notes": "1 teaspoon Tabasco sauce", "category": "condiments"}, {"quantity": 1.0, "unit": "tablespoon", "item": "dijon mustard", "notes": "1 tablespoon Dijon mustard", "category": "condiments"}, {"quantity": 2.0, "unit": "tablespoons", "item": "mayonnaise", "notes": "2 tablespoons mayonnaise", "category": "condiments"}, {"quantity": 1.0, "unit": "", "item": "jalapeno", "notes": "1 jalapeno, deseeded and minced", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "medium", "item": "onion", "notes": "1 medium onion, chopped", "category": "produce"}, {"quantity": 4.0, "unit": "tablespoons", "item": "parsley", "notes": "4 tablespoons fresh parsley, chopped", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "pepper", "notes": "1/2 teaspoon white pepper", "category": "spices and seasonings"}, {"quantity": 1.5, "unit": "teaspoons", "item": "kosher salt", "notes": "1 1/2 teaspoons kosher salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "panko crumbs", "notes": "cup panko crumbs", "category": "baking"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg, lightly whisked", "category": "milk, eggs, other dairy"}, {"quantity": 1.5, "unit": "cups", "item": "bread crumbs", "notes": "1 1/2 cups bread crumbs", "category": "pasta and rice"}, {"quantity": 0.25, "unit": "cup", "item": "seafood seasoning", "notes": "1/4 cup seafood seasoning (A good friend from New Orleans gifted us with River Road seasonings!)", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "butter", "notes": "2 tablespoons unsalted butter, optional", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "grits", "notes": "1 cup grits", "category": "cereal"}, {"quantity": 3.0, "unit": "cups", "item": "water", "notes": "3 cups water", "category": "beverages"}, {"quantity": 1.0, "unit": "cup", "item": "milk", "notes": "1 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "teaspoons", "item": "kosher salt", "notes": "2 teaspoons kosher salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "mozzarella cheese", "notes": "1/2 cup mozzarella cheese, shredded", "category": "cheese"}, {"quantity": 8.0, "unit": "servings", "item": "garlic", "notes": "Dried garlic (Amir had Garlic Gold Nuggets in the back of his pantry!)", "category": "spices and seasonings"}]'::jsonb, '["In a large bowl, carefully mix all of the ingredients except the breadcrumbs, seafood seasoning and butter. Form into 8 patties and set on a baking sheet. Chill for an hour.", "Once chilled, cover all sides of the patties with bread crumbs and lay on a separate baking sheet.", "Bake in an oven preheated to 375 degrees for 15-20 minutes, flipping once.", "If desired, top with a bit of butter and set the burgers onto a vegetable grill basket.", "Heat for 1-2 minutes on a preheated grill just for flavor and a little color.", "Serve on warm buns.", "Cook the grits according to the package directions. Stir in the cheese and salt just before removing from heat.", "Carefully pour the hot grits into a large, shallow plastic container. Allow the grits to cool down to room temperature. Cover, then chill overnight.", "When ready, overturn the grits onto a large cutting board and cut into 1/2 wide pieces.", "Lay them on a parchment paper covered baking sheet and bake in a preheated oven at 425 degrees for 30-40 minutes or until browned. Flip them once to brown all sides."]'::jsonb, 'https://www.foodista.com/recipe/KG7C6P3L/crab-and-shrimp-burgers-with-garlic-grits-fries', 'https://img.spoonacular.com/recipes/640266-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('little-italy-burger', 'Little Italy Burger', 4, 0, 0, '{"calories": 962, "protein": 43.6, "carbs": 35.03, "fat": 71.32, "saturated_fat": 28.25, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1437.77, "potassium": null, "fiber": 2.13, "sugar": 3.86, "vitamin_a": null, "vitamin_c": 5.12, "calcium": 405.64, "iron": 3.19}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'salad', 'grilling'], '[{"quantity": 1.0, "unit": "pound", "item": "ground beef", "notes": "1 pound ground beef", "category": "meat"}, {"quantity": 8.0, "unit": "slices", "item": "pancetta", "notes": "8 slices pancetta", "category": "meat"}, {"quantity": 1.0, "unit": "jar", "item": "pesto", "notes": "1 jar of good pesto", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "large ball", "item": "mozzarella", "notes": "1 large ball smoked mozzarella", "category": "cheese"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 red onion, cut into thin rounds", "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "butter", "notes": "3 tablespoons butter", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "teaspoons", "item": "tomato paste", "notes": "2 teaspoons tomato paste", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "teaspoon", "item": "anchovy paste", "notes": "1 teaspoon anchovy paste", "category": "pasta and rice"}, {"quantity": 4.0, "unit": "servings", "item": "baby arugula", "notes": "Baby arugula", "category": "produce"}, {"quantity": 1.0, "unit": "slices", "item": "tomato", "notes": "Ripe tomato slices", "category": "produce"}, {"quantity": 4.0, "unit": "", "item": "ciabatta buns", "notes": "4 ciabatta buns", "category": "bakery/bread"}]'::jsonb, '["Heat the grill to high. Divide the ground beef into 4 portions. Salt and pepper and press into patties.", "Layer each patty with a slice of pancetta on top and bottom. Press the pancetta into the patty.", "Cut the onion and mozzarella into rounds.", "Melt the butter and mix it with the tomato paste and anchovy paste.", "Cut the ciabatta buns and brush the insides with tomato-butter.", "CAREFULLY brush the grill with oil or use non-stick grill spray. Grill the patties and onions at the same time. Grill the patties for 3-5 minutes per side and the onions for 1-2 minutes per side.", "Once you flip the burgers, lay the onion rounds over the top of each patty, followed by the mozzarella slices. The cheese will melt while the burgers finish cooking.", "Place the buns on the open grill and toast for 1 minute.", "Once the buns are toasted, slather them with pesto.", "Layer arugula leaves, tomato slices and a patty on each bun. Top and serve!", "Serves 4."]'::jsonb, 'https://www.foodista.com/recipe/DXM5KVFD/little-italy-burger', 'https://img.spoonacular.com/recipes/650181-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-and-white-bean-chili', 'Chicken and White Bean Chili', 9, 0, 0, '{"calories": 433, "protein": 24.04, "carbs": 20.55, "fat": 29.44, "saturated_fat": 12.79, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 491.24, "potassium": null, "fiber": 5.12, "sugar": 5.5, "vitamin_a": null, "vitamin_c": 122.86, "calcium": 107.78, "iron": 3.24}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'spoonacular', 'baking'], '[{"quantity": 4.0, "unit": "pounds", "item": "chicken", "notes": "4 pounds whole chicken cut into quarters or approximately 1 ½ pounds (750g) boneless chicken", "category": "meat"}, {"quantity": 1.0, "unit": "liter", "item": "water", "notes": "4 cups (1 liter) water", "category": "beverages"}, {"quantity": 2.0, "unit": "tablespoons", "item": "chicken soup base", "notes": "2 tablespoons chicken bouillon granules or chicken soup base", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "large", "item": "bay leaf", "notes": "1 large bay leaf", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "medium size", "item": "onion", "notes": "1 medium size yellow onion, finely diced", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 medium to large size orange, red or yellow bell pepper, with seeds", "category": "produce"}, {"quantity": 3.0, "unit": "large", "item": "garlic cloves", "notes": "3 large garlic cloves, finely minced", "category": "produce"}, {"quantity": 5.0, "unit": "tablespoons", "item": "flour", "notes": "5 tablespoons all-purpose flour", "category": "baking"}, {"quantity": 439.0, "unit": "g", "item": ".5 can cannellini beans", "notes": "1 ounce – 15.5 (439g) tin cannellini beans (or any other white bean), drained and rinsed", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tablespoons", "item": "mild chili powder", "notes": "2 tablespoons mild chili powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ground coriander", "notes": "1 teaspoon ground coriander", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "ground cumin", "notes": "2 teaspoons ground cumin", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "coriander", "notes": "1 tablespoon chopped fresh coriander", "category": "spices and seasonings"}, {"quantity": 250.0, "unit": "ml", "item": "heavy whipping cream", "notes": "1 cup (250ml) single cream or heavy whipping cream", "category": "milk, eggs, other dairy"}, {"quantity": 187.0, "unit": "ml", "item": "soured cream", "notes": "3/4 cup (187ml) soured cream", "category": "milk, eggs, other dairy"}, {"quantity": 9.0, "unit": "servings", "item": "bell pepper", "notes": "Pepper to taste", "category": "produce"}]'::jsonb, '["Rinse the chicken quarters really well and place them in a stock pot.", "To the chicken in the pot, add the water (water should mostly cover the chicken), bouillon, bay leaf, onion, bell pepper and garlic.", "Place the stock pot over medium high heat and bring to a boil; reduce the heat to medium, cover and simmer until chicken is cooked through, approximately 30 minutes.", "Remove pot from the heat.", "Remove chicken quarters from the pot and transfer them to a cutting board and cool until they can be comfortably handled.", "Remove meat from the bones and chop it into small pieces then shred slightly; set aside.", "Remove approximately 1 cup (250ml) of the liquid from the stock pot and set aside.", "Return the stock pot to medium heat and bring to a simmer.", "Place the flour into a small bowl.", "While stirring constantly, gradually add the reserved liquid to the flour until a smooth paste is formed.", "Pour the paste into the stock pot and stir constantly until the mixture starts to thicken.", "Add the beans, chopped chicken, chili powder, coriander and cumin.", "Increase the heat to medium and, stirring frequently, simmer, uncovered for approximately 15-20 minutes or until the mixture is thick enough to coat the back of a spoon.", "Reduce the heat to low and add the fresh coriander, single cream and soured cream.", "Stir well until the single and soured creams are completely incorporated into the chili.", "Add pepper to taste.", "Serve immediately.", "Garnish with chopped avocado, spring onion, fresh coriander or grated cheese.", "Like most soups, this chili is great refrigerated and served the next day but if you intend on freezing it, leave out the whipping cream and soured cream (they separate when frozen) and add them just before serving.", "If youd like to spice things up a bit, add  -  teaspoon cayenne pepper or red pepper flakes for a slightly hot flavor."]'::jsonb, 'https://www.foodista.com/recipe/J3VSRLHM/chicken-and-white-bean-chili', 'https://img.spoonacular.com/recipes/637932-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tomatillo-turkey-chili', 'Tomatillo Turkey Chili', 6, 0, 0, '{"calories": 301, "protein": 29.38, "carbs": 30.25, "fat": 7.52, "saturated_fat": 1.73, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 896.93, "potassium": null, "fiber": 9.54, "sugar": 10.1, "vitamin_a": null, "vitamin_c": 27.57, "calcium": 81.25, "iron": 5.0}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular'], '[{"quantity": 1.5, "unit": "pounds", "item": "tomatillos", "notes": "1 1/2 pounds tomatillos, husks removed and cut in half", "category": "produce"}, {"quantity": 2.0, "unit": "inches", "item": "jalapeno peppers", "notes": "2 inches jalapeno peppers, seeded and cut half", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 onion, sliced", "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves garlic, peeled", "category": "produce"}, {"quantity": 1.0, "unit": "inch", "item": "chipotle pepper adobo sauce", "notes": "1 inch chipotle pepper adobo sauce, chopped", "category": "ethnic foods"}, {"quantity": 6.0, "unit": "cups", "item": "turkey", "notes": "6 cups cooked turkey or chicken, shredded", "category": "meat"}, {"quantity": 15.0, "unit": "ounces", "item": "black beans", "notes": "15 ounces can black beans, drained and rinsed", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "cups", "item": "chicken broth", "notes": "2 cups chicken broth", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "cup", "item": "beer - optional", "notes": "1/2 cup gluten-free beer (such as Bard''s Tale) – optional, but it adds a wonderful flavor", "category": "alcoholic beverages"}, {"quantity": 2.0, "unit": "cups", "item": "tomato puree", "notes": "2 cups diced tomatoes or tomato puree", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ground cumin", "notes": "1 teaspoon ground cumin", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ground coriander", "notes": "1 teaspoon ground coriander", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "oregano", "notes": "1 teaspoon dried oregano", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and pepper to taste", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "cilantro", "notes": "1/2 cup chopped cilantro", "category": "spices and seasonings"}]'::jsonb, '["Place the tomatillos and jalapenos cut-side down on a foil-lined baking sheet. Scatter onions and garlic around tomatillos and jalapenos.", "Place under broiler for 5-7 minutes or until skins on tomatillos blacken.", "Remove, and when cool, pour tomatillos, jalapenos, onion and garlic, including any juices, into a food processor. Pulse until well blended.", "Heat a large stockpot to medium heat and add tomatillo mixture and chipotle pepper. Stur around for a minute or two, and add turkey, beans, broth, beer, tomatoes and seasonings. Bring to a boil, and reduce to a simmer. Allow to simmer, stirring occasionally, for 20-30 minutes to allow flavors to blend.", "Immediately before serving, taste and adjust salt and pepper seasonings as necessary, and stir in most of the cilantro, reserving a bit to use as garnish.", "Optional: Top with sour cream and cheese."]'::jsonb, 'https://www.foodista.com/recipe/27BTX8RS/tomatillo-turkey-chili', 'https://img.spoonacular.com/recipes/663545-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('slow-cooked-beef-chili', 'Slow Cooked Beef Chili', 5, 0, 0, '{"calories": 324, "protein": 29.41, "carbs": 41.79, "fat": 6.51, "saturated_fat": 2.35, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 932.14, "potassium": null, "fiber": 12.49, "sugar": 17.83, "vitamin_a": null, "vitamin_c": 27.86, "calcium": 171.6, "iron": 8.1}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'dessert', 'slow-cooker'], '[{"quantity": 28.0, "unit": "ounces", "item": "canned tomatoes", "notes": "28 ounces can crushed tomatoes", "category": "canned and jarred"}, {"quantity": 14.0, "unit": "ounces", "item": "canned tomatoes", "notes": "14 ounces can diced tomatoes", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tablespoons", "item": "chili powder", "notes": "2 tablespoons chili powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "ground cumin", "notes": "1 tablespoon ground cumin", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "paprika", "notes": "2 teaspoons smoked paprika", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "brown sugar", "notes": "1 tablespoon brown sugar", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "", "item": "carrots", "notes": "3 carrots, coarsely chopped", "category": "produce"}, {"quantity": 4.0, "unit": "stalks", "item": "celery", "notes": "4 stalks celery, coarsely chopped", "category": "produce"}, {"quantity": 1.0, "unit": "medium", "item": "onion", "notes": "1 medium onion, coarsely chopped", "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves garlic, minced", "category": "produce"}, {"quantity": 1.0, "unit": "pound", "item": "beef chuck", "notes": "1 pound beef chuck, trimmed and cut into 1\" pieces", "category": "meat"}, {"quantity": 15.0, "unit": "ounces", "item": "kidney beans", "notes": "15 ounces can kidney beans", "category": "canned and jarred"}]'::jsonb, '["In a medium bowl, stir together the crushed tomatoes, diced tomatoes, chili powder, cumin, paprika, brown sugar, and salt. Set aside.", "Place the carrots, celery, onions, garlic, beef, and kidney beans into the base of a slow cooker.", "Pour the tomato sauce mixture evenly over the top of the beef and vegetables. Cover and cook on high for 6 hours.", "Taste and adjust seasoning as necessary- adding more chili powder if you''d prefer more spice."]'::jsonb, 'https://www.foodista.com/recipe/R6QPSK7Y/slow-cooked-beef-chili', 'https://img.spoonacular.com/recipes/660273-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('easy-cheeseburger-casserole', 'Easy Cheeseburger Casserole', 6, 15, 85, '{"calories": 436, "protein": 25.2, "carbs": 29.89, "fat": 23.41, "saturated_fat": 10.54, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 889.53, "potassium": null, "fiber": 1.04, "sugar": 0.89, "vitamin_a": null, "vitamin_c": 10.85, "calcium": 132.37, "iron": 2.22}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'spoonacular', 'breakfast', 'baking'], '[{"quantity": 1.0, "unit": "can", "item": "cream of mushroom soup", "notes": "1 can cream of mushroom soup", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "cup", "item": "rice", "notes": "1 cup uncooked long grain rice", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "cups", "item": "water", "notes": "2 cups water", "category": "beverages"}, {"quantity": 0.5, "unit": "cup", "item": "bacon", "notes": "1/2 cup cooked, crumbled bacon", "category": "meat"}, {"quantity": 0.5, "unit": "cup", "item": "bell pepper", "notes": "1/2 cup diced green bell pepper", "category": "produce"}, {"quantity": 1.0, "unit": "lb", "item": "ground beef", "notes": "1 lb cooked ground beef", "category": "meat"}, {"quantity": 1.0, "unit": "small", "item": "onion", "notes": "1 small chopped onion", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "pepper", "notes": "1 tsp pepper", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "tsp", "item": "celery salt", "notes": "1/4 tsp celery salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "garlic powder", "notes": "1 tsp garlic powder", "category": "spices and seasonings"}, {"quantity": 0.75, "unit": "cup", "item": "cheddar cheese", "notes": "3/4 cup shredded cheddar cheese", "category": "cheese"}]'::jsonb, '["Heat oven to 35", "Stir together soup, rice, water, onion, bell pepper, seasonings, and beef. ", "Place in 9 x 13 prepared baking dish. ", "Bake for 75 minutes. ", "Top with cheese and crumbled bacon and bake an additional 10 minutes. ", "Scoop and serve."]'::jsonb, 'https://www.pinkwhen.com/easy-cheeseburger-casserole/', 'https://img.spoonacular.com/recipes/1487865-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('slow-cooker-kahlua-pork-with-sweet-chili-pineapple-sauce', 'Slow Cooker Kahlua Pork with Sweet Chili Pineapple Sauce', 12, 0, 0, '{"calories": 447, "protein": 57.07, "carbs": 11.26, "fat": 17.52, "saturated_fat": 6.08, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 3306.84, "potassium": null, "fiber": 0.37, "sugar": 9.43, "vitamin_a": null, "vitamin_c": 2.05, "calcium": 49.54, "iron": 3.83}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'dessert', 'soup', 'slow-cooker'], '[{"quantity": 5.0, "unit": "tablespoons", "item": "garlic chili sauce", "notes": "5 tablespoons garlic chili sauce", "category": "ethnic foods"}, {"quantity": 5.0, "unit": "tablespoon", "item": "hoisin sauce", "notes": "5 tablespoon hoisin sauce", "category": "ethnic foods"}, {"quantity": 0.25, "unit": "cup", "item": "honey", "notes": "1/4 cup honey", "category": "nut butters, jams, and honey"}, {"quantity": 4.0, "unit": "tablespoons", "item": "liquid smoke", "notes": "4 tablespoons liquid smoke", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "pineapple juice", "notes": "1/2 cup pineapple juice", "category": "beverages"}, {"quantity": 8.0, "unit": "lb", "item": "pork butt", "notes": "1 8 lb pork butt", "category": "meat"}, {"quantity": 0.25, "unit": "cup", "item": "rice vinegar", "notes": "1/4 cup rice vinegar", "category": "ethnic foods"}, {"quantity": 5.0, "unit": "tablespoons", "item": "regular sea salt", "notes": "5 tablespoons pink hawaiian sea salt or regular sea salt", "category": "spices and seasonings"}]'::jsonb, '["Place the pork, fat side up, in the slow cooker. Using a fork, pierce the roast all over and pour the liquid smoke over it to coat.", "Sprinkle the sea salt evenly over the roast and cover. Cook on low for 10 hours (the roast is done when the meat begins to fall apart when shredded with a fork.)In a small saucepan, whisk together the pineapple juice, rice vinegar, honey, chili sauce and hoisin sauce. Bring the mixture to a boil and cook the sauce until reduced by half stirring with a heat resistant spatula frequently. Set aside.When the roast is done, transfer to a cutting board and shred the meat using two forks. Return the shredded meat back to the slow cooker and serve immediately with the sauce."]'::jsonb, 'http://www.foodista.com/recipe/NQB678JF/slow-cooker-kahlua-pork-with-sweet-chili-pineapple-sauce', 'https://img.spoonacular.com/recipes/660288-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('the-unagi-burger', 'The Unagi Burger', 4, 0, 0, '{"calories": 806, "protein": 53.95, "carbs": 43.3, "fat": 45.53, "saturated_fat": 14.48, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1309.51, "potassium": null, "fiber": 3.55, "sugar": 5.92, "vitamin_a": null, "vitamin_c": 3.22, "calcium": 106.54, "iron": 16.9}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'baking', 'grilling'], '[{"quantity": 2.0, "unit": "pounds", "item": "ground sirloin beef", "notes": "2 pounds ground sirloin beef", "category": "meat"}, {"quantity": 0.5, "unit": "cup", "item": "panko", "notes": "1/2 cup panko", "category": "baking"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "cup", "item": "almonds", "notes": "1/2 cup sliced almonds", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "ginger", "notes": "1/4 cup fresh ginger", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "green onions", "notes": "1/2 cup green onions sliced", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "soy sauce", "notes": "2 tablespoons soy sauce", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "pepper", "notes": "1/2 teaspoon black pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "sesame oil", "notes": "2 teaspoons of sesame oil", "category": "ethnic foods"}, {"quantity": 0.75, "unit": "cup", "item": "broccoli sprouts", "notes": "3/4 cup broccoli sprouts", "category": "produce"}, {"quantity": 8.0, "unit": "pieces", "item": "cucumber ribbons", "notes": "8 pieces shaved cucumber ribbons (2 per burger)", "category": "produce"}, {"quantity": 4.0, "unit": "", "item": "baker''s rolls", "notes": "4 whole wheat baker''s rolls", "category": "bakery/bread"}]'::jsonb, '["Wasabi Dressing: 1/2 cup mayonnaise, 1/4 cup sour cream, 2 tablespoons wasabi paste or fresh grated wasabi cream -", "Mix all ingredients well.", "Taste it and add a little wasabi paste more if you like it really spicy. This can be made ahead of time and last in the refrigerator for a week or more. I always make extra because it makes a great dip.", "Mix first 7 ingredients together thoroughly then add salt & pepper.", "Form patties and pat together tightly. Because of the volume of ingredients in these burgers they will fall apart easily on the grill.", "Test one of the patties to see if it is holding up on the grill and not falling apart. These are delicate burgers to cook. Be sure to coat grill with non-stick spray. If its falling apart too much, try browning it in a skillet first so the outside is a little done. B careful not to brown it too much or itll dry out on the grill.", "Brush sesame oil on the inside of the split bakers roll and toast on the upper or outer edges of grill. When rolls are lightly toasted, spread wasabi sauce on top bun and add broccoli sprouts.", "Place meat on bottom bun and 2 cucumber ribbons on top of meat. Carefully fold together and you have The Unagi Burger!"]'::jsonb, 'https://www.foodista.com/recipe/P7YT5V88/the-unagi-burger', 'https://img.spoonacular.com/recipes/663357-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('slow-cooker-mexican-pulled-pork', 'Slow Cooker Mexican Pulled Pork', 8, 0, 0, '{"calories": 304, "protein": 45.5, "carbs": 4.52, "fat": 10.89, "saturated_fat": 2.77, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1046.66, "potassium": null, "fiber": 1.73, "sugar": 1.82, "vitamin_a": null, "vitamin_c": 0, "calcium": 39.86, "iron": 2.96}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'dessert', 'slow-cooker'], '[{"quantity": 1.0, "unit": "Tbsp", "item": "brown sugar", "notes": "1 Tbsp brown sugar", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "cayenne", "notes": "1 teaspoon cayenne", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "Tbsp", "item": "chili powder", "notes": "4 Tbsp chili powder", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "cinnamon", "notes": "1/4 teaspoon cinnamon", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "garlic powder", "notes": "1 teaspoon garlic powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "pinch", "item": "ground cloves", "notes": "pinch of ground cloves", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "ground cumin", "notes": "2 teaspoons ground cumin", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "Tbsp", "item": "kosher salt", "notes": "1 Tbsp kosher salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "onion powder", "notes": "1 teaspoon onion powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ground oregano", "notes": "1 teaspoon ground oregano", "category": "produce"}, {"quantity": 3.5, "unit": "pound", "item": "pork shoulder roast", "notes": "3 1/2 pound boneless pork shoulder roast", "category": "meat"}, {"quantity": 2.0, "unit": "Tbsp", "item": "vegetable oil", "notes": "2 Tbsp vegetable oil", "category": "oil, vinegar, salad dressing"}]'::jsonb, '["Whisk together the rub ingredients in a small bowl.2 If the roast is tied up with butcher string, untie it. Pat the roast dry with paper towels. Rub the spice mix into the roast all over, reserving any leftover spice mix for later.", "Let sit at room temperature at least one hour or chill overnight. 3", "Heat vegetable oil in a frying pan on medium high heat. (If you are using a slow cooker with a removable container that can be used on the stovetop, use that, otherwise use a separate pan.)", "Place the roast in the pan and brown on all sides.4", "Place the roast in a slow cooker, and add any reserved spice rub. Cook on the low setting for 6 to 10 hours, until the pork is fall apart tender. 5", "Remove the roast from the slow cooker and place on a cutting board.", "Cut into large chunks. Then use two forks to pull the meat apart into bite sized shreds. Return the shreds to the slow cooker and toss to coat with the juice from the roast. (Alternatively you can just shred the roast with two forks in the slow cooker itself.)", "Serve with warm tortillas, avocados, shredded cabbage, sliced radishes, cilantro, and a splash of lime juice or salsa."]'::jsonb, 'https://spoonacular.com/-1436560866727', 'https://img.spoonacular.com/recipes/667699-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('homestyle-sloppy-joes', 'Homestyle Sloppy Joes', 6, 0, 0, '{"calories": 440, "protein": 46.79, "carbs": 35.86, "fat": 11.61, "saturated_fat": 4.69, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1205.45, "potassium": null, "fiber": 3.59, "sugar": 13.32, "vitamin_a": null, "vitamin_c": 27.79, "calcium": 108.98, "iron": 7.49}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'dessert'], '[{"quantity": 2.5, "unit": "pounds", "item": "ground beef", "notes": "2 1/2 pounds Lean ground beef", "category": "meat"}, {"quantity": 1.0, "unit": "medium", "item": "sized onion", "notes": "1 medium Sized onion, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "medium", "item": "sized bell pepper", "notes": "1 medium Sized green bell pepper, chopped", "category": "produce"}, {"quantity": 30.0, "unit": "ounces", "item": "tomato sauce", "notes": "30 ounces Tomato sauce", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tablespoons", "item": "brown sugar", "notes": "2 tablespoons Light or dark brown sugar", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "garlic powder", "notes": "1/2 teaspoon Garlic powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon Salt", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "pepper", "notes": "1/4 teaspoon Black pepper", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "", "item": "hamburger buns", "notes": "6 Sandwich or hamburger buns, split", "category": "bakery/bread"}]'::jsonb, '["In a large skillet, brown the ground beef with the onion and green pepper over medium-high heat for 7 to 9 minutes; drain off the excess liquid.", "Add the remaining ingredients except the buns; mix well. Reduce the heat to low and simmer for 8 to 10 minutes, stirring occasionally.", "Serve over the hamburger buns."]'::jsonb, 'https://www.foodista.com/recipe/864STVSL/homestyle-sloppy-joes', 'https://img.spoonacular.com/recipes/647148-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('crispy-sweet-sticky-spicy-wings', 'Crispy Sweet Sticky Spicy Wings', 6, 0, 0, '{"calories": 600, "protein": 29.82, "carbs": 67.68, "fat": 23.76, "saturated_fat": 6.65, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1765.33, "potassium": null, "fiber": 2.22, "sugar": 32.04, "vitamin_a": null, "vitamin_c": 2.18, "calcium": 65.7, "iron": 4.88}'::jsonb, ARRAY['american', 'lunch', 'antipasti', 'main course', 'starter', 'snack', 'appetizer', 'main dish', 'antipasto', 'dinner', 'hor d''oeuvre', 'spoonacular', 'dessert', 'baking'], '[{"quantity": 3.0, "unit": "pounds", "item": "chicken wings", "notes": "3 pounds chicken wings, washed, trimmed and cut in pieces", "category": "meat"}, {"quantity": 2.0, "unit": "cups", "item": "flour", "notes": "2 cups flour", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "nutmeg", "notes": "2 teaspoons freshly grated nutmeg", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "cayenne pepper", "notes": "1 teaspoon cayenne pepper", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "teaspoons", "item": "five spice powder", "notes": "3 teaspoons chinese five spice powder", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "teaspoons", "item": "sea salt", "notes": "4 teaspoons sea salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "pepper", "notes": "1 teaspoon freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "tablespoons", "item": "ground ginger", "notes": "3 tablespoons ground ginger", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "tablespoons", "item": "milk", "notes": "4 tablespoons milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "", "item": "garlic clove", "notes": "1 finely minced garlic clove", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "olive oil", "notes": "2 teaspoons olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.6666667, "unit": "cup", "item": "honey", "notes": "2/3 cup honey", "category": "nut butters, jams, and honey"}, {"quantity": 2.0, "unit": "teaspoons", "item": "chili paste", "notes": "2 teaspoons freshly ground chinese chili paste (or use chopped fresh chilis) (adjust to tast", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "teaspoon", "item": "pepper", "notes": "1/2 teaspoon freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "salt", "notes": "1/4 teaspoon salt", "category": "spices and seasonings"}]'::jsonb, '["Crispy Sweet Sticky Spicy Wings", "We had a few friends in last night for sips and nibbles and I was in the mood for something spicy, so I came up with this very simple sweet spicy  glaze to toss with my crispy deep-fried wings. It was fantastic. Crispy, sticky and with great spicy heat; these were irresistable and I ate way too many of them. The heat comes from chinese fresh ground chili paste, so it is very easy to adjust the heat to suit your taste. I think this recipe will become an entertaining favorite at our house.", "Pounds chicken wings, washed, trimmed and cut in pieces.", "Mix together", "Cups flour", "Teaspoons freshly grated nutmeg", "Tsp cayenne pepper", "Tsp chinese five spice powder", "Tsp sea salt", "Tsp freshly ground black pepper", "Tbsp ground ginger", "Dip the chicken wings into an egg wash made from", "Eggs", "Tbsp milk", "Dredge the egg washed wings in the flour mixture and drop them in a canola oil filled and preheated 350 degree F deep fryer for about 8-10 minutes depending upon the size of the wings until a medium golden brown.", "Drain on a wire rack placed on a cookie sheet. Hold in a 175 degree oven if making more than one batch.", "Sweet and Spicey Glaze", "In a small saucepan add", "Finely minced garlic clove", "Tsp olive oil", "Saute over medium heat until the garlic is softened but not browned.", "Cup honey", "Tsp freshly ground chinese chili paste (or use chopped fresh chilis) (adjust to taste)", "Tsp freshly ground black pepper", "Tsp salt", "Simmer for about 5-10 minutes.", "Pour over all the cooked wings in a large bowl and toss well to cover the wings in the glaze before serving. You can also just serve the glaze as a dipping sauce"]'::jsonb, 'https://www.foodista.com/recipe/64N5RVMK/crispy-sweet-sticky-spicy-wings', 'https://img.spoonacular.com/recipes/640841-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('macaroni-and-cheese', 'Macaroni and Cheese', 2, 5, 15, '{"calories": 640, "protein": 31.08, "carbs": 54.57, "fat": 32.86, "saturated_fat": 18.18, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 689.91, "potassium": null, "fiber": 2.29, "sugar": 6.4, "vitamin_a": null, "vitamin_c": 0, "calcium": 726.43, "iron": 1.17}'::jsonb, ARRAY['american', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'dessert', 'pasta', 'quick', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "pasta", "notes": "2 cups Pasta, any shape", "category": "pasta and rice"}, {"quantity": 0.75, "unit": "cup", "item": "milk", "notes": "3/4 cup Milk ( 1/2 cup + 1/2 cup, divided)", "category": "milk, eggs, other dairy"}, {"quantity": 1.5, "unit": "cups", "item": "cheese", "notes": "1.5 cups Grated Cheese (Cheddar or any melting cheese)", "category": "cheese"}, {"quantity": 1.0, "unit": "tbsp", "item": "all purpose flour / maida", "notes": "1 tbsp All Purpose Flour / Maida", "category": "baking"}, {"quantity": 1.0, "unit": "serving", "item": "salt", "notes": "Salt to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "serving", "item": "pepper powder", "notes": "Pepper Powder as needed", "category": "spices and seasonings"}]'::jsonb, '["Bring water to a boil in a big vessel with salt.", "Add pasta and boil until cooked. ", "Do not overcook the pasta. It should be firm to bite, yet cooked through. ", "Drain water and rinse with cold water.", "Drain and keep it aside.", "Dilute the flour in 1/4 cup of milk and keep it aside.", "Warm 1/2 cup of milk in the saucepan over medium flame.", "Add the flour and milk to the warm milk and continue stirring until the milk thickens slightly.", "Turn the heat to low.", "Add the grated cheese and salt and stir well until the cheese has melted.", "When the sauce is smooth and creamy, remove the pan from the flame.", "Add the cooked pasta to the cheese sauce.", "Combine until well coated.", "Sprinkle some pepper powder and serve immediately while still warm.", "If the sauce is dry after cooing, add little milk and reheat to make it creamy again."]'::jsonb, 'http://thecuisine.blogspot.com/2016/07/macaroni-and-cheese.html', 'https://img.spoonacular.com/recipes/1681413-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pumpkin-almond-burger-patties', 'Pumpkin Almond Burger Patties', 6, 0, 0, '{"calories": 401, "protein": 14.76, "carbs": 29.23, "fat": 28.7, "saturated_fat": 2.26, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 307.89, "potassium": null, "fiber": 9.29, "sugar": 5.97, "vitamin_a": null, "vitamin_c": 19.68, "calcium": 166.41, "iron": 3.99}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 3.0, "unit": "cups", "item": "almond flour", "notes": "3 cups Almond flour", "category": "health foods"}, {"quantity": 0.75, "unit": "cup", "item": "style bread crumbs", "notes": "¾ cup Italian style bread crumbs", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 whole green pepper (finely chopped)", "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "pepper", "notes": "½ tsp crushed pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cups", "item": "pumpkin puree", "notes": "2 cups Pumpkin puree", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "sriracha sauce", "notes": "½ tsp sriracha sauce", "category": "condiments"}]'::jsonb, '["Preheat oven at 360 degree Fahrenheit. Prepare a cookie sheet with a liner.", "In the meantime combine all the ingredients in a mixing bowl.", "Mix well with a spoon or with hands.", "Take a handful of the mix between palms and shape it into a ball.", "Then press between palms just like burger patties and smoothen the sides as much as possible because while baking the patties may crack a bit. So make sure to smoothen them as much as possible.", "Put the patties onto the cookie sheet and put it in the middle rack of the oven.", "Let it bake for 20-25 minutes. Take it out and flip the patties to the other side and bake again for 20 minutes.", "Take it out of the oven when cooked and serve with your favorite burger buns and toppings, or eat it in a wrap. Nutritional information is for patties alone."]'::jsonb, 'https://www.foodista.com/recipe/G6G5S67G/pumpkin-almond-burger-patties', 'https://img.spoonacular.com/recipes/657243-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('grilled-turkey-burgers-with-roasted-jalapeños-and-bbq-sauce', 'Grilled Turkey Burgers with Roasted Jalapeños and BBQ Sauce', 5, 0, 0, '{"calories": 173, "protein": 22.93, "carbs": 6.44, "fat": 7.01, "saturated_fat": 1.17, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 255.46, "potassium": null, "fiber": 2.87, "sugar": 2.03, "vitamin_a": null, "vitamin_c": 17.93, "calcium": 17.43, "iron": 1.16}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'salad', 'baking', 'grilling'], '[{"quantity": 1.0, "unit": "slices", "item": "avocado", "notes": "Avocado slices", "category": "produce"}, {"quantity": 5.0, "unit": "", "item": "baby bella mushrooms", "notes": "5 baby bella mushrooms, chopped", "category": "produce"}, {"quantity": 5.0, "unit": "servings", "item": "bbq sauce", "notes": "BBQ Sauce", "category": "condiments"}, {"quantity": 0.125, "unit": "cup", "item": "basil", "notes": "1/8 cup fresh basil, finely chopped", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "garlic powder", "notes": "1 teaspoon garlic powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "grapeseed oil", "notes": "1 teaspoon grapeseed oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "pound", "item": "ground turkey", "notes": "1 pound ground turkey", "category": "meat"}, {"quantity": 4.0, "unit": "", "item": "jalapenos", "notes": "4 jalapenos, roasted", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "teaspoon", "item": "paprika", "notes": "1 teaspoon paprika", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "leaf", "item": "lettuce", "notes": "Red leaf lettuce", "category": "produce"}, {"quantity": 5.0, "unit": "servings", "item": "salt", "notes": "Salt to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "slices", "item": "tomato", "notes": "Tomato slices", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "onion", "notes": "½ yellow onion, chopped", "category": "produce"}]'::jsonb, '["Preheat the oven to 37", "Place whole jalapeos in a casserole dish or baking sheet and roast about 15 minutes or until skin is flaying away from flesh and flesh is soft.", "Remove from oven and allow to cool. Once cool enough to handle, peel the skin from the flesh and discard the skin.", "Cut jalapeos lengthwise, remove the stem and seeds and coarsely chop. Set aside.In a medium sized skillet, heat the grapeseed (or olive) oil. Saut onion on medium high heat until translucent, about 8 to 10 minutes.", "Add the chopped mushrooms and saut until the onion and mushroom are dark brown and soft, about 5 to 8 more minutes.", "Remove from heat and set aside.Fire up the grill to medium high heat. In a mixing bowl, add the ground meat, salt, garlic powder, paprika and basil. Once the sauted onion and mushroom is cool, add it to the mixing bowl as well and mix everything together using your hands. Form 5 patties out of the meat. Once the grill is hot, place patties on and grill until brown and charred on the first side, about 3 minutes for the elk or bison, 5 minutes for the turkey. Flip and grill an additional 3 to 5 minutes, until meat is brown and has nice grill marks. If using elk or bison, cook to desired donness. If using turkey meat, cook all the way through but careful not to over-cook."]'::jsonb, 'https://www.foodista.com/recipe/2FTWYPY5/grilled-burgers-with-roasted-jalape-os-and-cherry-bbq-sauce', 'https://img.spoonacular.com/recipes/645608-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
