ry": "produce"}, {"quantity": 8.0, "unit": "servings", "item": "jalapenos", "notes": "jalapenos", "category": "canned and jarred"}, {"quantity": 8.0, "unit": "servings", "item": "avocado", "notes": "avocado", "category": "produce"}, {"quantity": 8.0, "unit": "servings", "item": "lime", "notes": "lime", "category": "produce"}, {"quantity": 8.0, "unit": "servings", "item": "cream", "notes": "sour cream", "category": "milk, eggs, other dairy"}, {"quantity": 8.0, "unit": "servings", "item": "tortilla chips", "notes": "crushed tortilla chips", "category": "savory snacks"}, {"quantity": 8.0, "unit": "servings", "item": "cilantro", "notes": "cilantro", "category": "spices and seasonings"}]'::jsonb, '["Place boneless, skinless chicken breasts into Crock Pot set on high.", "Cover chicken with seasonings.", "Top chicken with green chilis.", "Add white beans.", "Top with chicken broth.", "Cover. Cook on high for 4 hours or low for 8 hours.", "Serve alone or with your favorite toppings."]'::jsonb, 'https://www.pinkwhen.com/crock-pot-white-chicken-chili/', 'https://img.spoonacular.com/recipes/1157762-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chicken-ranch-burgers', 'Chicken Ranch Burgers', 3, 5, 20, '{"calories": 365, "protein": 40.71, "carbs": 21.83, "fat": 11.06, "saturated_fat": 2.98, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 947.02, "potassium": null, "fiber": 1.68, "sugar": 3.08, "vitamin_a": null, "vitamin_c": 27.36, "calcium": 58.61, "iron": 2.84}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'quick', 'baking'], '[{"quantity": 0.5, "unit": "medium", "item": "bell pepper", "notes": "½ medium bell pepper (chopped)", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "bread crumbs", "notes": "½ cup bread crumbs", "category": "pasta and rice"}, {"quantity": 0.5, "unit": "cup", "item": "purple onion", "notes": "½ cup purple onion (chopped)", "category": "produce"}, {"quantity": 1.0, "unit": "packet", "item": "ranch seasoning", "notes": "1 packet Ranch seasoning", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "lb", "item": "chicken", "notes": "1 lb of lean shredded chicken", "category": "meat"}]'::jsonb, '["Heat oven to 40", "Add chicken, onion, pepper, bread crumbs, and ranch seasoning to a mixing bowl.", "Mix ingredients well.", "Scoop and make 3 large burger patties.", "Place in skillet and cook on medium low heat to sear juices and brown the patties.", "Place skillet with patties into the oven and bake for 15 minutes, or until patties are cooked thoroughly.", "Serve with your favorite toppings."]'::jsonb, 'https://www.pinkwhen.com/chicken-ranch-burgers-recipe/', 'https://img.spoonacular.com/recipes/991010-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook