INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('white-bean-turkey-chili', 'White Bean Turkey Chili', 8, 0, 0, '{"calories": 387, "protein": 39.15, "carbs": 42.88, "fat": 6.96, "saturated_fat": 1.36, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 773.82, "potassium": null, "fiber": 9.84, "sugar": 9.12, "vitamin_a": null, "vitamin_c": 53.96, "calcium": 117.69, "iron": 6.04}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'baking'], '[{"quantity": 1.0, "unit": "tablespoon", "item": "olive oil", "notes": "1 tablespoon olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "pounds", "item": "tomatillos", "notes": "2 pounds of tomatillos (about 15)", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 onion, quartered", "category": "produce"}, {"quantity": 3.0, "unit": "", "item": "pasilla peppers", "notes": "3 pasilla peppers", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "jalapeno", "notes": "1 jalapeno", "category": "canned and jarred"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves of garlic", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "chili powder", "notes": "2 tablespoons chili powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "chipotle powder", "notes": "1 teaspoon chipotle powder", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "cumin", "notes": "2 teaspoons cumin", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "coriander", "notes": "2 teaspoons coriander", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "salt", "notes": "2 teaspoons salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "pounds", "item": "ground turkey", "notes": "2 pounds ground turkey", "category": "meat"}, {"quantity": 12.0, "unit": "ounces", "item": "pale ale", "notes": "12 ounces bottle pale ale", "category": "alcoholic beverages"}, {"quantity": 2.0, "unit": "cups", "item": "chicken stock", "notes": "2 cups chicken stock", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "cans", "item": "cannellini beans", "notes": "2 cans cannellini beans, drained and rinsed", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "cup", "item": "corn", "notes": "1 cup frozen white corn (or more, I think I used about 2 cups)", "category": "canned and jarred"}]'::jsonb, '["Preheat oven to 42", "Place tomatillos, onion, peppers, jalapeno and garlic in a large roasting pan.", "Sprinkle with olive oil and roast for 30 minutes, or until vegetables have softened.", "Let vegetables cool. (Note: if the skin on the pasilla peppers isnt blistered, place under broiler for 5-10 more minutes to make peeling the skin off easier.)", "Peel the skin of the pasilla peppers and then place all vegetables in a food processor. Pulse until just chopped up.", "Heat olive oil in a large pot and add spices.", "Heat until fragrant.", "Add turkey and cook until just browned. Deglaze with the pale ale.", "Add chicken stock and vegetables from food processor. Cook for 45 min-1 hour or until thickened. And beans and continue to cook for 1/2 hour longer.", "Add in frozen corn and stir to combine. Take off heat and let cool.", "Serve with cilantro and sour cream."]'::jsonb, 'https://www.foodista.com/recipe/GHLG67VL/white-bean-turkey-chili', 'https://img.spoonacular.com/recipes/665146-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tag