INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('grilled-chuck-burgers-with-extra-sharp-cheddar-and-lemon-garlic-aioli', 'Grilled Chuck Burgers with Extra Sharp Cheddar and Lemon Garlic Aioli', 4, 0, 0, '{"calories": 802, "protein": 34.82, "carbs": 41.93, "fat": 54.97, "saturated_fat": 18.31, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 934.55, "potassium": null, "fiber": 3.34, "sugar": 9.38, "vitamin_a": null, "vitamin_c": 102.5, "calcium": 318.29, "iron": 13.79}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'salad', 'baking', 'grilling', 'vegetarian'], '[{"quantity": 4.0, "unit": "servings", "item": "arugula", "notes": "arugula, for topping", "category": "produce"}, {"quantity": 8.5, "unit": "inch", "item": "cheddar cheese", "notes": "8 ½ inch slices of a good extra-sharp cheddar cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "", "item": "garlic clove", "notes": "1 garlic clove, minced", "category": "produce"}, {"quantity": 1.0, "unit": "pound", "item": "ground chuck", "notes": "1 pound ground chuck (enough for 4 burger patties)", "category": "meat"}, {"quantity": 1.0, "unit": "teaspoon", "item": "lemon juice", "notes": "1 teaspoon fresh lemon juice", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "mayonnaise", "notes": "¼ cup mayonnaise", "category": "condiments"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.125, "unit": "cup", "item": "parsley", "notes": "1/8 cup chopped parsley", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "bell pepper", "notes": "pepper", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 red onion, cut into ¼ -inch circular slices", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "salt", "notes": "salt", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "", "item": "kaiser rolls", "notes": "4 honey wheat buns or Kaiser rolls", "category": "bakery/bread"}, {"quantity": 2.0, "unit": "teaspoons", "item": "worcestershire sauce", "notes": "2 teaspoons Worcestershire sauce", "category": "condiments"}]'::jsonb, '["To prep the burgers:  In a medium bowl, toss in the ground meat, 1/2 teaspoon salt, 1/2 teaspoon pepper, and Worcestershire sauce.", "Brush olive oil on both sides of all the slices and then sprinkle with some salt and pepper.For the lemon garlic aioli:  In a small bowl, mix all the ingredients together.", "Place back in refrigerator until burgers are cooked.To cook:  Preheat grill to around 350.If using cast iron grates, use a paper towel or cloth to wipe all grates with canola oil.", "Place burger patties on grill.Close lid and prep the buns by brushing canola oil on insides.After a few minutes, check the patties.  If the bottom half looks just about cooked, roughly 3 minutes, flip over, and place cheese on top.", "Place a handful of arugula leaves on the bottom slice of the bun.", "Place burger with cheese slice on top.", "Add the grilled red onions.Slather the aioli liberally on the top half of the bun."]'::jsonb, 'https://www.foodista.com/recipe/KLYNPLC4/grilled-chuck-burgers-with-extra-sharp-cheddar-and-lemon-garlic-aioli', 'https://img.spoonacular.com/recipes/645680-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('satay-chicken-wings', 'Satay Chicken Wings', 6, 0, 0, '{"calories": 437, "protein": 27.43, "carbs": 12.43, "fat": 30.99, "saturated_fat": 7.63, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 519.73, "potassium": null, "fiber": 2.71, "sugar": 5.08, "vitamin_a": null, "vitamin_c": 37.66, "calcium": 67.84, "iron": 3.19}'::jsonb, ARRAY['american', 'lunch', 'antipasti', 'main course', 'starter', 'snack', 'appetizer', 'main dish', 'antipasto', 'dinner', 'hor d''oeuvre', 'gluten free', 'dairy free', 'spoonacular', 'dessert', 'grilling'], '[{"quantity": 1.5, "unit": "kg", "item": "chicken wings", "notes": "Chicken wings (about 12 wings), 1.5kg", "category": "meat"}, {"quantity": 6.0, "unit": "", "item": "shallots", "notes": "6-8 Shallots", "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3-4 cloves Garlic", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "chilies", "notes": "2-3 Red chilies", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "chilies", "notes": "1-2 Dry chilies (soaked)", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "lemongrass stalk", "notes": "1 Lemongrass stalk (white part)", "category": "ethnic foods"}, {"quantity": 3.0, "unit": "", "item": "cm piece of ginger/galangal", "notes": "3 cm piece of Ginger/Galangal", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "coriander powder", "notes": "1tsp Coriander powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "cumin powder", "notes": "1 teaspoon Cumin powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "aniseed powder", "notes": "1 teaspoon Aniseed powder", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "turmeric", "notes": "2 teaspoons Turmeric", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "servings", "item": "pepper", "notes": "White pepper, a dash", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "servings", "item": "salt", "notes": "Salt, to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoons", "item": "sugar", "notes": "1-2 teaspoons Sugar", "category": "baking"}, {"quantity": 2.0, "unit": "tablespoons", "item": "vegetable oil", "notes": "2tablespoons Vegetable oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 3.0, "unit": "tablespoons", "item": "spice paste", "notes": "3-4 tablespoons Spice paste (as reserved from the marinate)", "category": "ethnic foods"}, {"quantity": 6.0, "unit": "servings", "item": "water", "notes": "Water, some", "category": "beverages"}, {"quantity": 1.0, "unit": "tablespoon", "item": "vegetable oil", "notes": "1 tablespoon Vegetable oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tablespoons", "item": "tamarind juice", "notes": "2 tablespoons Tamarind juice", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "tablespoons", "item": "roasted peanuts", "notes": "2-3 tablespoons Roasted peanuts (ground and keep slightly chunky)", "category": "nuts"}, {"quantity": 6.0, "unit": "servings", "item": "salt and sugar", "notes": "Salt and sugar, to taste", "category": "spices and seasonings"}]'::jsonb, '["In a food processor, blend shallots, garlic cloves, red chilies, dry chilies, lemongrass, and ginger/galangal until they become a paste.", "Clean the chicken wings and dry them with kitchen towels.", "In a big mixing bowl, put in the spice paste.", "Mix with coriander powder, cumin powder, aniseed powder, turmeric, white pepper, salt, oil and sugar. Keep some marinate aside in a small bowl, about 3-4 tbsp.", "Put in all chicken wings in the big bowl and mix well. Make sure the chicken wings are well coated with the paste. Cover with cling film and marinate overnight.", "To prepare a quick peanut sauce, heat a pan with oil. Put in the spice paste. Cook on low heat until fragrant and the oil starts to seep out.", "Add in tamarind juice and stir.", "Add in sugar and salt. Adjust the seasoning accordingly.", "Add in some water to dilute the paste as it gets thicken. Then, add in the toasted ground peanuts and mix well. If the sauce gets too thick, thin it down with some water and adjust the seasoning if needed.", "Heat up the grill and cook the marinated chicken wings for about 10-15 minutes on each side.", "Brush the peanut sauce on top before serving."]'::jsonb, 'https://www.foodista.com/recipe/Q6G4VN7B/satay-chicken-wings', 'https://img.spoonacular.com/recipes/659290-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chipotle-cheese-stuffed-black-bean-burgers-with-avocado-creme', 'Chipotle Cheese Stuffed Black Bean Burgers with Avocado Creme', 4, 0, 0, '{"calories": 658, "protein": 22.47, "carbs": 53.16, "fat": 40.81, "saturated_fat": 12.96, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1351.75, "potassium": null, "fiber": 12.27, "sugar": 5.75, "vitamin_a": null, "vitamin_c": 10.67, "calcium": 365.78, "iron": 4.93}'::jsonb, ARRAY['american', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular'], '[{"quantity": 15.0, "unit": "oz", "item": "black beans", "notes": "15oz can black beans, rinsed and drained", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "small", "item": "onion", "notes": "1/2 small yellow onion, diced", "category": "produce"}, {"quantity": 2.0, "unit": "large", "item": "mushrooms", "notes": "2-3 large mushrooms, diced", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg, beaten", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "cup", "item": "panko bread crumbs", "notes": "1/2 cup panko bread crumbs", "category": "baking"}, {"quantity": 1.0, "unit": "tsp", "item": "cumin", "notes": "1 tsp cumin", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "chipotle chili powder", "notes": "1/2 tsp chipotle chili powder (adjust according to how spicy you like it)", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "salt/pepper", "notes": "salt/pepper, to taste", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "olive oil", "notes": "olive oil, for saute (I like Devo Olive Oil''s Chipotle or Wild Mushroom and Sage flavors)", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "tbsp", "item": "approx cream cheese spread", "notes": "Approx 4 tbsp softened cream cheese spread, chipotle flavor if available", "category": "cheese"}, {"quantity": 4.0, "unit": "servings", "item": "hamburger buns", "notes": "hamburger buns, toasted", "category": "bakery/bread"}, {"quantity": 4.0, "unit": "slices", "item": "cheese", "notes": "4 slices of cheese, optional", "category": "cheese"}, {"quantity": 1.0, "unit": "leaves", "item": "spinach and tomato", "notes": "burgers toppings like lettuce, kale, or spinach leaves and sliced tomato", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "avocado", "notes": "1 ripe avocado, peeled, pitted, and cut into wedges", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "cream", "notes": "1/4 cup sour cream (start with 2 tbsp then add until you get the consistency you like)", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tbsp", "item": "lime juice", "notes": "1 tbsp lime juice", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "sea salt", "notes": "sea salt, to taste", "category": "spices and seasonings"}]'::jsonb, '["Add a swirl of olive oil to a skillet and add diced mushrooms and onions.", "Saute until softened then season with salt and pepper.", "Add drained black beans to a medium bowl and press and mash with a fork.", "Mix in mushrooms and onions then add egg and bread crumbs.", "Finally mix in cumin and chipotle chili powder.", "Roll and form into burger patties (sliders or full size).", "Form a indent in the center of each burger", "Add a spoonful of cream cheese spread to the indent in the burgers and then form the burger over the cream cheese.", "Heat a skillet over medium heat, add a swirl of olive oil.", "Add 2 burgers at a time and sear on each side until cooked and browned, about 4 minutes each side.", "If you want to add sliced cheese on top, add now and cover skillet to steam and melt cheese.", "Remove to a plate, then cook remaining patties.", "For the avocado creme, combine all ingredients in a food processor or blender, and mix until smooth. Taste and add more sour cream or lime juice if needed.", "To plate, add each hot cooked burger to an open toasted bun. Top with lettuce and tomato (optional) and a hearty scoop of avocado creme and then top with bun."]'::jsonb, 'https://www.foodista.com/recipe/BBKK34SS/chipotle-cheese-stuffed-black-bean-burgers-with-avocado-creme', 'https://img.spoonacular.com/recipes/638744-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('instant-pot-crack-chicken-chili', 'Instant Pot Crack Chicken Chili', 6, 6, 10, '{"calories": 532, "protein": 30.29, "carbs": 36.53, "fat": 30.13, "saturated_fat": 15.67, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1624.87, "potassium": null, "fiber": 9.56, "sugar": 1.88, "vitamin_a": null, "vitamin_c": 0, "calcium": 369.82, "iron": 3.34}'::jsonb, ARRAY['american', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'spoonacular', 'breakfast', 'quick', 'instant-pot'], '[{"quantity": 1.0, "unit": "tbsp", "item": "olive oil", "notes": "1 tbsp olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "medium", "item": "chicken breasts", "notes": "2 medium chicken breasts boneless, skinless", "category": "meat"}, {"quantity": 2.0, "unit": "cups", "item": "chicken broth", "notes": "2 cups chicken broth", "category": "canned and jarred"}, {"quantity": 15.0, "unit": "oz", "item": "cannellini beans", "notes": "15 oz cannellini beans", "category": "canned and jarred"}, {"quantity": 15.0, "unit": "oz", "item": "tomatoes", "notes": "15 oz diced tomatoes with juice", "category": "other"}, {"quantity": 15.0, "unit": "oz", "item": "black beans", "notes": "15 oz black beans rinsed", "category": "pasta and rice"}, {"quantity": 4.0, "unit": "tbsp", "item": "ranch seasoning", "notes": "4 tbsp Ranch seasoning", "category": "oil, vinegar, salad dressing"}, {"quantity": 8.0, "unit": "oz", "item": "cream cheese", "notes": "8 oz cream cheese", "category": "cheese"}, {"quantity": 8.0, "unit": "pieces", "item": "bacon", "notes": "8 pieces bacon cooked, crumbled", "category": "meat"}, {"quantity": 2.0, "unit": "cups", "item": "cheddar cheese", "notes": "2 cups cheddar cheese shredded", "category": "cheese"}]'::jsonb, '["Hit saute function on Instant Pot and add olive oil.", "Add chicken breasts and cook for 2 minutes on each side. Hit off button twice. ", "Add ranch seasoning, chicken broth, tomatoes, black beans, and then top with cubed cream cheese. Do not stir. ", "Secure lid into place, making sure the vent is set to seal. Manual cook for 4 minutes. Allow to natural release for 5 minutes and then carefully manually release, removing the lid once the pin has dropped. ", "Shred the chicken breasts. Stir the contents well.", "Add the crumbled bacon and cheddar cheese and stir until combined.", "Serve immediately. "]'::jsonb, 'https://www.pinkwhen.com/instant-pot-crack-chicken-chili/', 'https://img.spoonacular.com/recipes/1516713-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
