INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('baked-sweet-potato-fries', 'Baked Sweet Potato Fries', 1, 0, 0, '{"calories": 496, "protein": 7.31, "carbs": 91.88, "fat": 11.86, "saturated_fat": 2.68, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 381.66, "potassium": null, "fiber": 13.82, "sugar": 19.25, "vitamin_a": null, "vitamin_c": 10.94, "calcium": 142.12, "iron": 2.8}'::jsonb, ARRAY['american', 'side dish', 'gluten free', 'dairy free', 'whole 30', 'spoonacular', 'dessert', 'baking', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "T", "item": "margarine", "notes": "1 -T margarine or butter, melted", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "dash", "item": "nutmeg", "notes": "dash nutmeg", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "", "item": "t seasoned salt", "notes": "1/4 -t seasoned salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "lb", "item": "smalls sweet potatoes", "notes": "4 smalls sweet potatoes (about 1 lb)", "category": "produce"}]'::jsonb, '["Spray a 15 x 10 x 1 inch baking pan with nonstick coating. Scrub potatoes; cut lengthwise into quarters, then cut each quarter into 2 wedges. Arrange potatoes in a single layer in pan.", "Combine margarine or butter, salt, and nutmeg.", "Brush onto potatoes.", "Bake in a 450 oven 20 minutes or until brown and tender."]'::jsonb, 'https://www.foodista.com/recipe/HDVQBNZX/baked-sweet-potato-fries', 'https://img.spoonacular.com/recipes/633837-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCL