INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('smokey-rainbow-chili', 'Smokey Rainbow Chili', 8, 0, 0, '{"calories": 218, "protein": 9.43, "carbs": 36.47, "fat": 5.18, "saturated_fat": 0.78, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 683.14, "potassium": null, "fiber": 9.46, "sugar": 8.14, "vitamin_a": null, "vitamin_c": 59.54, "calcium": 93.44, "iron": 3.9}'::jsonb, ARRAY['american', 'antipasti', 'soup', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "small", "item": "zucchini", "notes": "2 small zucchini, halved and cut into small chunks", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 red bell pepper, chopped (keep the pieces a bit big...helps to keep them crisp)", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "orange bell pepper", "notes": "1 orange bell pepper, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "jalapeno pepper", "notes": "1 fresh jalapeno pepper, seeded and diced", "category": "canned and jarred"}, {"quantity": 4.0, "unit": "cloves", "item": "garlic", "notes": "4 cloves garlic, minced", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 onion, chopped", "category": "produce"}, {"quantity": 28.0, "unit": "ounce", "item": "stewed tomatoes", "notes": "2 (14 ounce) cans stewed tomatoes, with liquid (here is where I would have used fire roasted...they just don''t exist here in Saudi)", "category": "canned and jarred"}, {"quantity": 6.0, "unit": "ounce", "item": "tomato paste", "notes": "1 (6 ounce) can tomato paste", "category": "canned and jarred"}, {"quantity": 15.0, "unit": "ounce", "item": "black beans", "notes": "1 (15 ounce) can black beans, drained and rinsed", "category": "canned and jarred"}, {"quantity": 15.0, "unit": "ounce", "item": "kernel corn", "notes": "1 (15 ounce) can whole kernel corn, drained", "category": "produce"}, {"quantity": 15.0, "unit": "ounce", "item": "kidney beans", "notes": "1 (15 ounce) can red kidney beans, drained and rinsed", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "tablespoon", "item": "paprika", "notes": "1/2 tablespoon smoked paprika", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "chili powder", "notes": "1 teaspoon chili powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "oregano", "notes": "1/2 teaspoon dried oregano", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground pepper", "notes": "1/2 teaspoon ground black pepper", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "cayenne pepper", "notes": "1/4 teaspoon cayenne pepper, or to taste", "category": "spices and seasonings"}]'::jsonb, '["(if using meat...brown the meat really well, remove and set aside.", "Add the meat after sauteing the veggies)", "Heat oil in a large pot over medium-high heat. Stir in zucchini, red bell pepper, orange bell pepper, jalapeno, garlic, and onion. Cook 5 minutes, just until tender.", "Add tomatoes with liquid, tomato paste, black beans, corn, and kidney beans into the pot. Season with smoked paprika, chili powder, oregano, black pepper, and cayenne pepper. Bring to a boil.", "Reduce heat to low and simmer 1 hour, stirring occasionally.  (depending on how big you cut the veggies, you may want to let it simmer a little longer)"]'::jsonb, 'https://www.foodista.com/recipe/V62YQQWD/smokey-rainbow-chili', 'https://img.spoonacular.com/recipes/660395-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('butternut-squash-and-black-bean-chili-with-bulgar', 'Butternut Squash and Black Bean Chili with Bulgar', 6, 0, 0, '{"calories": 230, "protein": 8.86, "carbs": 45.28, "fat": 3.28, "saturated_fat": 0.51, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 640.21, "potassium": null, "fiber": 11.72, "sugar": 6.23, "vitamin_a": null, "vitamin_c": 29.32, "calcium": 120.6, "iron": 3.53}'::jsonb, ARRAY['american', 'antipasti', 'soup', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "TB", "item": "ancho chili powder", "notes": "1 TB Ancho Chili Powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "bulgur", "notes": "1/2 cup Bulgur", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "", "item": "butternut squash", "notes": "1 Medium size Butternut Squash, Peeled, seeds removed & medium diced", "category": "produce"}, {"quantity": 2.0, "unit": "TB", "item": "chipotle chiles in adobo sauce", "notes": "2 TB Chipotle Chiles in Adobo Sauce, chopped", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "cups", "item": "black beans", "notes": "2 cups Black Beans, cooked", "category": "pasta and rice"}, {"quantity": 14.0, "unit": "oz", "item": "tomatoes", "notes": "14 oz can Fire Roasted Tomatoes, Diced", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "tablespoon", "item": "garlic", "notes": "1 tablespoon garlic", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "ground coriander", "notes": "1 tsp ground Coriander", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "ground cumin", "notes": "1 tsp ground Cumin", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "TB", "item": "olive oil", "notes": "1 TB Olive Oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "tsp", "item": "mexican oregano", "notes": "1 tsp dried Mexican Oregano", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 Red Onion, chopped", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and pepper to taste", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cups", "item": "vegetable stock", "notes": "2 cups Vegetable Stock", "category": "canned and jarred"}]'::jsonb, '["-In a large pot, heat the olive oil over a medium-high flame.", "Add the onion, garlic, chili powder, cumin, coriander &amp; oregano. Sweat until the onions begin the turn translucent.-", "Add the black beans, chipotle chiles, butternut squash, tomato and vegetable stock. Season with salt and pepper. Bring the mixture to a simmer and add the bulgar. Allow the chili to cook about 30-40 minutes until the squash is tender and the bulgar to soft.", "Garnish with your favorite toppings."]'::jsonb, 'https://www.foodista.com/recipe/6SWWWS5Y/butternut-squash-and-black-bean-chili-with-bulgar', 'https://img.spoonacular.com/recipes/636573-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('kale-chips-with-parmesan-cheese-and-garlic', 'Kale Chips with Parmesan Cheese and Garlic', 2, 0, 0, '{"calories": 162, "protein": 7.15, "carbs": 6.85, "fat": 12.67, "saturated_fat": 3.67, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 617.78, "potassium": null, "fiber": 2.81, "sugar": 0.7, "vitamin_a": null, "vitamin_c": 64.05, "calcium": 321.68, "iron": 1.25}'::jsonb, ARRAY['american', 'side dish', 'gluten free', 'primal', 'ketogenic', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "bunch", "item": "curly kale", "notes": "1 bunch curly kale", "category": "produce"}, {"quantity": 0.33333334, "unit": "cup", "item": "parmesan cheese", "notes": "1/3 cup grated Parmesan cheese", "category": "cheese"}, {"quantity": 0.25, "unit": "teaspoon", "item": "kosher salt", "notes": "¼ teaspoon kosher salt", "category": "spices and seasonings"}, {"quantity": 0.125, "unit": "teaspoon", "item": "pepper", "notes": "1/8 teaspoon freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves garlic, minced", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "lemon juice", "notes": "2 teaspoons fresh lemon juice", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "olive oil", "notes": "1 tablespoon olive oil", "category": "oil, vinegar, salad dressing"}]'::jsonb, '["Heat oven to 325 degrees.Line a baking sheet with parchment paper or a Silpat for easy cleanup.Chop the leaves of the kale into medium-sized pieces.Wash and dry thoroughly, then place in a large bowl for mixing.In a small bowl, whisk Parmesan cheese, kosher salt, black pepper, and garlic.In another small bowl, mix the lemon juice and olive oil.", "Drizzle the lemon juice and olive oil mixture over the kale in the large bowl.Use tongs to help coat all the pieces.Then sprinkle the Parmesan cheese mixture, and use tongs to help coat the pieces with the mixture.", "Bake in the oven for about 12-15 minutes.You want the pieces to be brown and crispy, but not burnt.I sometimes remove pieces as they become the desired crispness and let some of the less crispy ones stay in the oven longer."]'::jsonb, 'https://www.foodista.com/recipe/M3SFPSBZ/kale-chips-with-parmesan-cheese-and-garlic', 'https://img.spoonacular.com/recipes/1096277-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cashew-chili-portabello', 'Cashew-Chili Portabello', 4, 0, 0, '{"calories": 460, "protein": 11.79, "carbs": 54.23, "fat": 23.85, "saturated_fat": 3.95, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 216.16, "potassium": null, "fiber": 4.79, "sugar": 5.69, "vitamin_a": null, "vitamin_c": 41.43, "calcium": 44.29, "iron": 3.6}'::jsonb, ARRAY['american', 'antipasti', 'soup', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "tablespoon", "item": "arrowroot powder", "notes": "1 tablespoon tsp.- 1 arrowroot powder (push vegetables to side of pan to expose liquid& whisk in to thicken)", "category": "baking"}, {"quantity": 2.0, "unit": "tablespoons", "item": "bragg''s liquid aminos", "notes": "2 tablespoons Nama Shoyu (soy sauce) or Bragg''s Liquid Aminos", "category": "condiments"}, {"quantity": 1.0, "unit": "cup", "item": "brown rice", "notes": "1 cup uncooked brown rice", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "cup", "item": "cashew nuts", "notes": "1 cup cashew nuts (raw or roasted)", "category": "nuts"}, {"quantity": 2.0, "unit": "tablespoons", "item": "extra virgin olive oil", "notes": "2 tablespoons extra virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "servings", "item": "cilantro", "notes": "fresh cilantro", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "garlic cloves", "notes": "2 garlic cloves, minced", "category": "produce"}, {"quantity": 1.0, "unit": "bunch", "item": "green onions", "notes": "1 bunch green onions (scallions)- cut in 2 inch pieces including greens", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "lemon juice", "notes": "1/2 lemon Juice", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "olive oil", "notes": "1 teaspoon olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 12.0, "unit": "ounces", "item": "portabello mushrooms", "notes": "12 ounces portabello mushrooms (should be 4 mushrooms - sliced into cubes)", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 red bell pepper, diced", "category": "produce"}, {"quantity": 3.0, "unit": "", "item": "chilies", "notes": "3 dried red chilies, chopped", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "sea salt& pepper", "notes": "Sea salt& pepper to taste", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cups", "item": "water", "notes": "2 cups filtered water", "category": "beverages"}, {"quantity": 1.0, "unit": "tablespoon", "item": "sweetner", "notes": "1 tablespoon sweetner", "category": "?"}, {"quantity": 1.0, "unit": "tablespoon", "item": "sweetner", "notes": "1 tablespoon sweetner", "category": "?"}]'::jsonb, '["Fix brown rice by cooking in 1 tsp. olive oil until lightly browned.", "Place 2 basil leaves on top of rice and add 2 cups water all at once.  Quickly put on lid and bring to boil.  Turn down heat to simmer until all water has evaporated (around 40 minutes).  Fluff rice and add juice of 1/2 lemon and lightly salt &amp; pepper to taste.While rice is cooking cut portabello mushrooms into cubes.  Set aside.Preheat a wok and then heat the 2 tbsp. oil.", "Add minced garlic and dried chopped chilies to the wok and stir-fry over a medium heat until golden.  Do not let the garlic burn.", "Add the portabello mushrooms and stir-fry until it is cooked, then add the red bell pepper.Stir in the shoyou (soy sauce) and agave.", "Add the green onions and cashew nuts.  Stir-fry for 1-2 minutes more, until heated through. Push vegetables to side of wok to expose liquid.", "Whisk in 1 tsp. - 1 Tbsp. arrowroot powder to thicken liquid.To serve:  With a very small dipping bowl for a mold, pack with brown rice  and empty onto plate (see picture above).  On top of rice place stir-fry vegetables and garnish with cilantro."]'::jsonb, 'https://www.foodista.com/recipe/N3RKYKNM/cashew-chili-portabello', 'https://img.spoonacular.com/recipes/637265-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('macaroni-and-cheese-gratin', 'Macaroni and Cheese Gratin', 6, 0, 0, '{"calories": 859, "protein": 42.43, "carbs": 85.93, "fat": 37.82, "saturated_fat": 20.21, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1122.15, "potassium": null, "fiber": 3.8, "sugar": 11.89, "vitamin_a": null, "vitamin_c": 4.81, "calcium": 1031.2, "iron": 2.73}'::jsonb, ARRAY['american', 'side dish', 'spoonacular', 'dessert', 'pasta', 'baking', 'vegetarian'], '[{"quantity": 1.5, "unit": "cups", "item": "herbed bread crumbs", "notes": "1 1/2 cups herbed bread crumbs", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "tablespoon", "item": "butter", "notes": "1 tablespoon Butter or margarine", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "cups", "item": "cheddar", "notes": "2 cups grated cheddar", "category": "cheese"}, {"quantity": 1.0, "unit": "pound", "item": "elbow macaroni", "notes": "1 pound elbow macaroni", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "tablespoon", "item": "flour", "notes": "1 tablespoon Flour", "category": "baking"}, {"quantity": 2.0, "unit": "cups", "item": "gruyere", "notes": "2 cups grated gruyere", "category": "cheese"}, {"quantity": 4.0, "unit": "cups", "item": "milk", "notes": "4 cups milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "teaspoon", "item": "nutmeg", "notes": "1/4 teaspoon nutmeg", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "parmesan", "notes": "1/4 cup grated Parmesan", "category": "cheese"}, {"quantity": 0.33333334, "unit": "cup", "item": "parsley", "notes": "1/3 cup chopped parsley", "category": "produce"}, {"quantity": 3.0, "unit": "drops", "item": "pepper sauce", "notes": "A few drops hot pepper sauce", "category": "condiments"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon Salt", "category": "spices and seasonings"}]'::jsonb, '["Bring a pot of water to a boil.", "Add salt and add macaroni and cook until not quite al dente (macaroni will continue to cook in the oven).In another pot melt the butter, add the flour and stir with a whisk or a wooden spoon for a couple of minutes to cook the flour.", "Add the milk, 1/2 cup at a time whisking until the mixture thickens, then add remaining milk and let cook over low heat until the sauce thickens, stirring constantly, scraping from the bottom of the pan and being careful not to burn it at the bottom.When the sauce is thick add the grated cheeses and stir until melted. Stir in the nutmeg, hot pepper sauce and salt, remove from heat and set aside.When the macaroni is cooked drain into colander and return to the pot.", "Pour the cheese sauce over the macaroni and stir with a wooden spoon.", "Pour the macaroni into individual gratins or a large buttered baking dish. You can add a few tomato slices into the macaroni either half way through pouring it into the pan or at the end, tucking them in with a knife. Don''t smooth out the top, allow a few peaks here and there, they will become crisp and delicious as you bake it.To make the topping:Melt the butter, pour over the bread crumbs in a bowl and mix to combine.", "Sprinkle topping over macaroni, bake in 400 oven 10-15 minutes or until crumbs are nicely golden.", "Serve immediately."]'::jsonb, 'https://www.foodista.com/recipe/CNQHCNTM/macaroni-and-cheese-gratin', 'https://img.spoonacular.com/recipes/650546-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('southwestern-vegetarian-chili', 'Southwestern Vegetarian Chili', 10, 0, 0, '{"calories": 138, "protein": 6.32, "carbs": 25.59, "fat": 2.16, "saturated_fat": 0.35, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 771.71, "potassium": null, "fiber": 7.74, "sugar": 5.8, "vitamin_a": null, "vitamin_c": 35.67, "calcium": 77.24, "iron": 3.03}'::jsonb, ARRAY['american', 'antipasti', 'soup', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 yellow onion, finely chopped", "category": "produce"}, {"quantity": 1.0, "unit": "medium", "item": "sweet potato", "notes": "1 medium sweet potato, chopped into ½” pieces (peel on)", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "olive oil", "notes": "1 tablespoon olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 green bell pepper, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 red bell pepper, chopped", "category": "produce"}, {"quantity": 2.0, "unit": "stalks", "item": "corn on the cob", "notes": "2 stalks corn on the cob, shucked, kernels removed", "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves garlic, minced", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "chili powder", "notes": "1 tablespoon chili powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "cumin", "notes": "1 tablespoon cumin", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground pepper", "notes": "½ teaspoon ground red pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "oregano", "notes": "1 teaspoon oregano", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "cocoa powder", "notes": "2 teaspoons unsweetened cocoa powder", "category": "baking"}, {"quantity": 1.0, "unit": "pinch", "item": "cinnamon", "notes": "Pinch of cinnamon", "category": "spices and seasonings"}, {"quantity": 10.0, "unit": "servings", "item": "salt and ground pepper", "notes": "Salt and ground black pepper to taste", "category": "spices and seasonings"}, {"quantity": 29.0, "unit": "ounce", "item": "tomatoes", "notes": "2 14.5-ounce cans of diced tomatoes, un-drained", "category": "canned and jarred"}, {"quantity": 14.5, "unit": "ounce", "item": "kidney beans", "notes": "1 14.5-ounce can kidney beans, drained", "category": "canned and jarred"}, {"quantity": 14.5, "unit": "ounce", "item": "black beans", "notes": "1 14.5-ounce can black beans, drained", "category": "canned and jarred"}, {"quantity": 32.0, "unit": "ounces", "item": "vegetable broth", "notes": "32 ounces vegetable broth", "category": "canned and jarred"}]'::jsonb, '["Shuck your corn and using a knife, carefully cut the kernels off the cobs. Set aside.", "In a large Dutch oven or stock pot, heat olive oil to medium high and add the chopped sweet potato.  Saut about 10 minutes before adding the onion.  Saut an additional 8 minutes.", "Add just a splash of the vegetable stock while the sweet potato and onion are sauting to give them a little steam.", "Add the chopped bell pepper and saut another 5 minutes, again adding a splash of vegetable stock to steam the veggies.", "Add the diced tomatoes, drained beans, corn kernels and the remaining veggie stock. Stir.", "Add all of the seasonings (chili powder, oregano, salt, cocoa powder, cinnamon, cumin, red pepper, black pepper).  Stir to combine all ingredients. Bring the chili to a boil then reduce the heat to medium low and cover. Allow the chili to simmer for 30 minutes before serving it in heaping bowls with your favorite toppings!", "See original recipe: http://www.perrysplate.com/2011/01/vegetarian-sweet-potato-chili.html"]'::jsonb, 'https://www.foodista.com/recipe/7CVDF2FX/southwestern-vegetarian-chili', 'https://img.spoonacular.com/recipes/660730-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('awesome-no-bake-macaroni-and-cheese', 'Awesome! No Bake ~ Macaroni and Cheese', 16, 0, 0, '{"calories": 337, "protein": 11.21, "carbs": 27.14, "fat": 20.82, "saturated_fat": 5.38, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 270.34, "potassium": null, "fiber": 1.6, "sugar": 4.44, "vitamin_a": null, "vitamin_c": 15.72, "calcium": 162.68, "iron": 1.08}'::jsonb, ARRAY['american', 'side dish', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'spoonacular', 'dessert', 'pasta', 'vegetarian'], '[{"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 bell pepper – chopped", "category": "produce"}, {"quantity": 1.0, "unit": "Handful", "item": "cilantro", "notes": "Handful cilantro – chopped", "category": "spices and seasonings"}, {"quantity": 16.0, "unit": "ounces", "item": "cottage cheese", "notes": "16 ounces container cottage cheese", "category": "cheese"}, {"quantity": 6.0, "unit": "cloves", "item": "garlic - crushed&", "notes": "6 cloves garlic – crushed& chopped", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "ketchup", "notes": "1/2 cup ketchup", "category": "condiments"}, {"quantity": 1.0, "unit": "pound", "item": "you favorite macaroni", "notes": "1 pound of you favorite macaroni", "category": "pasta and rice"}, {"quantity": 0.5, "unit": "cup", "item": "milk", "notes": "1/2 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 16.0, "unit": "servings", "item": "olive oil", "notes": "Olive oil for drizzling", "category": "oil, vinegar, salad dressing"}, {"quantity": 8.0, "unit": "oz", "item": "cheddar cheese", "notes": "8 oz. cheddar cheese- shredded", "category": "cheese"}, {"quantity": 10.0, "unit": "ounces", "item": "creamed spinach", "notes": "10 ounces package frozen creamed spinach", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "onion", "notes": "1/2 sweet onion – chopped", "category": "produce"}]'::jsonb, '["Heat a large saucepot with a drizzle of olive oil and add the onion, garlic, bell pepper and cilantro and let saut until the onion is clear.", "Add the frozen creamed spinach and continue to saut until the spinach is thawed.", "Add the ketchup and stir, continuing to saut on low.In a food processor combine the cottage cheese, milk and 4 oz. of the shredded cheddar cheese. Process until the cottage is smooth.Prepare the macaroni as directed.", "Add the cooked macaroni to the saucepot with the sauting spinach and toss add the processed cottage cheese mixture and toss. Turn off heat. Top with the remaining 4 oz. of cheddar cheese. Cover and let the cheddar cheese melt. This takes only a second or two."]'::jsonb, 'https://www.foodista.com/recipe/DJBXLXPJ/awesome-no-bake-macaroni-and-cheese', 'https://img.spoonacular.com/recipes/633185-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('try-this-at-home-tomato-gazpacho-to-cool-off-during-the-dog-days-of-summer', 'Try This at Home - Tomato Gazpacho to Cool Off During the Dog Days of Summer', 4, 10, 0, '{"calories": 365, "protein": 5.26, "carbs": 25.05, "fat": 28.44, "saturated_fat": 3.96, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1327.29, "potassium": null, "fiber": 4.63, "sugar": 9.88, "vitamin_a": null, "vitamin_c": 72.09, "calcium": 68.64, "iron": 2.3}'::jsonb, ARRAY['american', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'soup', 'quick', 'vegetarian'], '[{"quantity": 2.0, "unit": "lbs", "item": "tomatoes", "notes": "2 lbs tomatoes, cored and chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "cucumber", "notes": "1 cucumber, peeled and chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 red bell pepper, cored, deseeded, and chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "shallot", "notes": "1 shallot, peeled and chopped", "category": "produce"}, {"quantity": 0.5, "unit": "c", "item": "olive oil", "notes": "1/2 c extra-virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "Tbsp", "item": "rice vinegar", "notes": "1 Tbsp rice vinegar", "category": "ethnic foods"}, {"quantity": 3.0, "unit": "slices", "item": "baguette", "notes": "3 slices stale baguette", "category": "bakery/bread"}, {"quantity": 1.0, "unit": "tsp", "item": "cumin", "notes": "1 tsp cumin", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tsp", "item": "salt", "notes": "2 tsp salt (more to taste)", "category": "spices and seasonings"}]'::jsonb, '["Add tomatoes, cucumber, bell pepper, and shallot to a bowl.", "Soak bread in vinegar, break in pieces, and add to bowl (if not using bread, simply add 1 Tbsp rice vinegar).", "Add cumin and salt.", "Mix all ingredients together and add to food processor (in batches if necessary). Blend for 1 minute.", "Strain, put back in food processor, and slowly add olive oil to emulsify. Taste and add more salt as needed.", "Chill and serve."]'::jsonb, 'https://maplewoodroad.com/tomato-gazpacho/', 'https://img.spoonacular.com/recipes/1697717-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
