bread into the egg mixture until evenly coated on both sides, cooks on a grill heated to 350 degrees for about 2-3 minutes per side or until golden brown.", "Serve hot with butter and maple syrup or as we did with pumpkin butter."]'::jsonb, 'https://www.foodista.com/recipe/7GBXXW87/pumpkin-french-toast', 'https://img.spoonacular.com/recipes/657306-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lentil-veggie-burgers', 'Lentil Veggie Burgers', 20, 0, 0, '{"calories": 119, "protein": 5.12, "carbs": 23.03, "fat": 1.16, "saturated_fat": 0.21, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 236.79, "potassium": null, "fiber": 5.85, "sugar": 1.7, "vitamin_a": null, "vitamin_c": 1.73, "calcium": 18.48, "iron": 1.56}'::jsonb, ARRAY['american', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "lentils", "notes": "1 cup of lentils", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "cup", "item": "flour", "notes": "1 cup of flour (whole wheat)", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "oats", "notes": "1/2 cup of oats", "category": "cereal"}, {"quantity": 0.5, "unit": "cup", "item": "brown rice", "notes": "1/2 cup of brown rice (cooked)", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "", "item": "carrot", "notes": "1 carrot", "category": "produce"}, {"quantity": 1.0, "unit": "small", "item": "eggplant", "notes": "1 small eggplant", "category": "produce"}, {"quantity": 1.0, "unit": "small", "item": "onion", "notes": "1 small onion", "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves of garlic", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "corn", "notes": "1/2 cup of corn (optional)", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "salt", "notes": "2 teaspoons salt (adjust to your taste preference)", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "oregano", "notes": "2 teaspoons of oregano", "category": "produce"}, {"quantity": 1.5, "unit": "teaspoons", "item": "coriander", "notes": "1 1/2 teaspoons coriander", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "cumin", "notes": "1/2 teaspoon cumin", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "nutmeg", "notes": "1/2 teaspoon of nutmeg", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "pepper", "notes": "1/2 teaspoon of pepper (optional or adjust to your taste preference)", "category": "spices and seasonings"}, {"quantity": 20.0, "unit": "servings", "item": "cornmeal", "notes": "cornmeal to cover the “hamburger” patty", "category": "ethnic foods"}]'::jsonb, '["Place in a foil and bake for 20 minutes in a 375 degree ovenor until it is soft.", "Cook lentils in boiling water (15 to 25 minutes).", "Cook brown rice.", "Throw carrots, onions, garlic, cooked eggplant and rice in a food processor and process together.", "After the lentils are cooked, add the processed veggies and rice in, smash together with your hands or with a potato masher.  Note: try not to smash all of the lentils.", "Add corn (optional), oats, flour, and seasonings.", "Make burger patties.", "Cover in corn meal.", "Cook in a little bit of oil until the outside is crunchy.", "Place in a whole wheat bun and add your favorite fix ins.", "Enjoy!"]'::jsonb, 'https://www.foodista.com/recipe/QNJB22ZH/lentil-veggie-burgers', 'https://img.spoonacular.com/recipes/649940-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EX