INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('baked-sweet-chili-carrot-fries', 'Baked Sweet Chili Carrot Fries', 4, 0, 0, '{"calories": 150, "protein": 2.42, "carbs": 28.12, "fat": 4.17, "saturated_fat": 0.57, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 752.66, "potassium": null, "fiber": 7.07, "sugar": 15.2, "vitamin_a": null, "vitamin_c": 15.35, "calcium": 83.65, "iron": 0.88}'::jsonb, ARRAY['american', 'side dish', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'dessert', 'soup', 'baking', 'vegetarian'], '[{"quantity": 16.0, "unit": "", "item": "carrots", "notes": "16 carrots, peeled and julienned", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "olive oil", "notes": "1 tablespoon olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "agave nectar", "notes": "1 tablespoon agave nectar", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "teaspoon", "item": "paprika", "notes": "1/2 teaspoon paprika", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "onion powder", "notes": "1/2 teaspoon onion powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "garlic powder", "notes": "1/2 teaspoon garlic powder", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "chili powder", "notes": "1/4 teaspoon chili powder", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "bell pepper", "notes": "Black pepper, to taste", "category": "spices and seasonings"}]'::jsonb, '["Preheat oven to 425 degrees.", "Place the carrot sticks in a large Tupperware bowl that has a tight-fitting lid.", "Pour oil and remaining ingredients into the bowl, on top of the carrot sticks.", "Secure the lid and shake the ingredients around vigorously until every last carrot stick is coated with flavor.", "Place the carrot sticks, in a single layer, on an ungreased cookie sheet.", "Bake for about 15 minutes. Check the carrot sticks, shake the pan, flip them around, whatever you need to do.", "Continue to bake for an additional 5-15 minutes, until carrot sticks are soft in the middle but nice and crunchy around the edges. Watch them closely."]'::jsonb, 'https://www.foodista.com/recipe/V87DDC38/baked-sweet-chili-carrot-fries', 'https://img.spoonacular.com/recipes/633833-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
