, {"quantity": 4.0, "unit": "cups", "item": "water", "notes": "4 cups water", "category": "beverages"}]'::jsonb, '["Begin by Preheating oven to 350Bring a large pot of salted water to a boil over medium heat, add in elbows and cook until pasta is al dente.While waiting for pasta to cook begin preparing your sauce. In a medium size sauce pan, melt butter over medium heat, add in nutritional yeast and mix together to form a paste", "Add in soy milk, using a whisk combine together ingredients make sure your sauce is lump free, let simmer for 5 minute or until sauce begins to thicken", "Add is pureed butternut squash, thoroughly mix together ingredients to ensure everything is well blended (you may notice that the butternut squash also helps to thicken the sauce).Stir in Cheese, let sit for 1 to 2 minutes or until sauce has a creamy velvety smooth consistency.", "Remove Sauce from heat and let sit", "Drain pasta and add pasta to the cheese sauce, stir together and pour mixture into a greased 9 x 9 baking pan", "Sprinkle breadcrumbs over macaroni and cheese and let bake for 15 minutes or until cheese begins to bubble", "Serve Warm and enjoy this creamy Vegan home-style comfort food!"]'::jsonb, 'https://www.foodista.com/recipe/W2G2NLXR/creamy-vegan-butternut-squash-mac-and-cheese', 'https://img.spoonacular.com/recipes/640720-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chili-gobi', 'Chili Gobi', 4, 0, 0, '{"calories": 280, "protein": 7.09, "carbs": 29.51, "fat": 15.99, "saturated_fat": 1.62, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 633.92, "potassium": null, "fiber": 5.68, "sugar": 7.78, "vitamin_a": null, "vitamin_c": 117.96, "calcium": 63.88, "iron": 1.86}'::jsonb, ARRAY['american', 'side dish', 'dairy free', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'soup', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "medium", "item": "cauliflower", "notes": "1 medium cauliflower", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "chili powder", "notes": "1/2 teaspoon chili powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "chili sauce", "notes": "1 teaspoon chili sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "teaspoon", "item": "corn starch", "notes": "1 teaspoon corn starch", "category": "baking"}, {"quantity": 4.0, "unit": "servings", "item": "curry leaves", "notes": "curry leaves", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "ginger", "notes": "1 tablespoon ginger, made into a paste", "category": "produce"}, {"quantity": 3.0, "unit": "", "item": "chilies", "notes": "3 green chilies", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "oil", "notes": "oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "", "item": "onions", "notes": "2 onions, chopped", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "flour", "notes": "1/2 cup plain flour", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "soy sauce", "notes": "1 tablespoon soy sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sugar", "notes": "1 teaspoon sugar", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "tomato sauce", "notes": "1 tablespoon tomato sauce", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "", "item": "vegetable bouillon cube", "notes": "1 vegetable bouillon cube", "category": "canned and jarred"}]'::jsonb, '["Make a batter with chili powder, beaten egg, flour, vegetable stock (or water) and salt. Dip cauliflower pieces in the batter and fry in oil until light brown.", "Heat oil in a pan and add chopped onions, ginger-garlic paste, green chillies, and curry leaves, and saute well.", "Add vegetable stock, soy sauce, chili sauce, and tomato sauce and stir well.", "Mix corn starch with water and add to pan.", "Add fried cauliflower pieces and salt and cook until dry. Stir in sugar."]'::jsonb, 'https://www.foodista.com/recipe/X6YYBXTZ/chili-gobi', 'https://img.spoonacular.com/recipes/638557-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bacon-brownie-cupcakes', 'Bacon Brownie Cupcakes', 6, 0, 0, '{"calories": 913, "protein": 30.74, "carbs": 43.32, "fat": 72.43, "saturated_fat": 36.15, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 414.57, "potassium": null, "fiber": 4.58, "sugar": 19.4, "vitamin_a": null, "vitamin_c": 0, "calcium": 53.59, "iron": 7.16}'::jsonb, ARRAY['american', 'spoonacular', 'dessert', 'breakfast', 'baking'], '[{"quantity": 2.0, "unit": "", "item": "crossing over quintessential american desserts", "notes": "2 Crossing over quintessential American desserts, we bake our brownie dough in", "category": "meat"}, {"quantity": 4.0, "unit": "oz", "item": "chocolate", "notes": "4 oz unsweetened chocolate", "category": "baking"}, {"quantity": 1.0, "unit": "ounce", "item": "chocolate", "notes": "1 ounce sweetened chocolate", "category": "sweet snacks"}, {"quantity": 8.0, "unit": "tablespoons", "item": "butter", "notes": "8 tablespoons butter", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "cup", "item": "sugar", "notes": "1/2 cup sugar", "category": "baking"}, {"quantity": 0.25, "unit": "teaspoon", "item": "salt", "notes": "1/4 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "large", "item": "eggs", "notes": "2 large eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "ap flour", "notes": "1 cup AP Flour", "category": "baking"}, {"quantity": 2.0, "unit": "tablespoons", "item": "cocoa", "notes": "2 tablespoons cocoa (not Dutch-processed)", "category": "baking"}, {"quantity": 4.0, "unit": "strips", "item": "bacon", "notes": "4 strips bacon", "category": "meat"}]'::jsonb, '["Oven: 350F.", "Grease a standard muffin pan (we like jumbo but not mini, they''ll get to crispy).", "Fry the bacon, remove and pat dry. The bacon should be crispy but without char- any chunks of fat that are still white should be discarded.", "Melt the unsweetened chocolate and butter in a double broiler.", "Cool slightly, then whisk in the sugar and salt.", "Add the eggs, one at a time.", "Sift the flour and cocoa together, then combine with the chocolate.", "Stir in the pieces of bacon and chocolate.", "Bake ~30 min., making sure to allow brownie cupcakes to cool before removing."]'::jsonb, 'https://www.foodista.com/recipe/GK2S8GN3/bacon-brownie-cupcakes', 'https://img.spoonacular.com/recipes/633293-312x231.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
