INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vegan-green-bean-casserole', 'Vegan Green Bean Casserole', 6, 0, 0, '{"calories": 109, "protein": 4.6, "carbs": 19.8, "fat": 2.84, "saturated_fat": 1.98, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 600.51, "potassium": null, "fiber": 6.36, "sugar": 7.1, "vitamin_a": null, "vitamin_c": 23.7, "calcium": 68.72, "iron": 1.77}'::jsonb, ARRAY['american', 'side dish', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'whole 30', 'vegan', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 0.25, "unit": "cup", "item": "nutritional yeast", "notes": "¼ cup nutritional yeast", "category": "health foods"}, {"quantity": 0.5, "unit": "tsp", "item": "pepper", "notes": "½ tsp. red pepper crushed", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 red onion sliced", "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "coconut oil", "notes": "1 tbsp Coconut Oil", "category": "baking"}, {"quantity": 1.5, "unit": "tsps", "item": "salt", "notes": "1 ½ tsps. salt", "category": "spices and seasonings"}, {"quantity": 1.5, "unit": "cups", "item": "water", "notes": "1 ½ cups water", "category": "beverages"}, {"quantity": 1.5, "unit": "cups", "item": "mushroom", "notes": "1 ½ cups mushroom chopped", "category": "produce"}, {"quantity": 1.5, "unit": "lbs", "item": "green beans", "notes": "1 ½ lbs. green beans", "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "parsnips", "notes": "2 cups parsnips chopped", "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves garlic minced", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "bell pepper", "notes": "Black Pepper to taste", "category": "spices and seasonings"}]'::jsonb, '["In a wide-bottomed saucepan, add 1 tablespoon extra virgin coconut oil and set to low heat.", "Add the onions and cook for 30 minutes. Stir occasionally to caramelize. If the onions look dry, splash a bit of water into the pan.While waiting for the onions to cook, steam the parsnip. Set aside and let them cool.After that, prepare the green beans.", "Remove the ends of the beans and cut them into 2 inch pieces. Steam them for 8 minutes. Set them aside in an 8x8 baking dish.Once the onions have caramelized, set them aside. Cook the mushrooms in the same pan and saute for one minute.", "Add garlic. Stir for 5 minutes.", "Add half of the garlic and mushroom mixture to the green beans.Preheat the oven to 350 degrees Fahrenheit.", "Put the other half of the garlic and mushroom mixture, as well as the steamed parsnips in a blender.", "Add the nutritional yeast, salt, pepper, and crushed red pepper.", "Pour the blended mixture over the mushrooms and green beans. Stir to coat. Use the caramelized onions as toppings.", "Bake for another 30 minutes.", "Serve."]'::jsonb, 'https://www.foodista.com/recipe/2M3K34BV/green-bean-casserole-vegan', 'https://img.spoonacular.com/recipes/1095892-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
