er", "notes": "1/2 teaspoon garlic powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "cayenne pepper", "notes": "1/2 teaspoon cayenne pepper", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "pepper", "notes": "1/2 teaspoon crushed black pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "water", "notes": "2 tablespoons water", "category": "beverages"}, {"quantity": 2.0, "unit": "servings", "item": "home fries", "notes": "Home Fries", "category": "frozen"}, {"quantity": 3.0, "unit": "inches", "item": "potatoes", "notes": "3 inches red potatoes, diced ½ thick", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "pepper", "notes": "2 teaspoons crushed black pepper", "category": "spices and seasonings"}, {"quantity": 1.5, "unit": "teaspoons", "item": "salt", "notes": "1 1/2 teaspoons salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons olive oil", "category": "oil, vinegar, salad dressing"}]'::jsonb, '["Tofu and veggie scramble", "Press the tofu for 30 minutes prior to cooking. Chop all the veggies and leave ready to begin cooking process.", "Using a non-stick skillet, heat olive oil on medium heat.", "Add pressed tofu and crumble in large pieces. The tofu will need to cook and dry out a little for 10 to 15 minutes, so meanwhile, add onions and garlic to tofu.", "After those 15 minutes, add asparagus and mushroom and all the rest of the spices plus the water. Cook for 5 minutes and serve hot!", "Home Fries", "Prepare potatoes before starting on tofu scramble.", "Preheat oven to 450F and move oven rack to the next to last highest row. Line a small cookie sheet with parchment paper.", "Wash and scrub potatoes. Dice them and add to a medium bowl.", "Add olive oil, salt and pepper and mix well.", "Pour potatoes on cookie sheet and spread evenly.", "Bake for 20 minutes and serve while hot."]'::jsonb, 'https://www.foodista.com/recipe/HL3SWS52/country-breakfast-tofu-and-veggie-scramble-with-home-fries', 'https://img.spoonacular.com/recipes/640194-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
