 skillet for one minute on each side", "Ladle with syrup, sprinkle with confectioners sugar and garnish with more bananas"]'::jsonb, 'https://www.foodista.com/recipe/6RMLP5LZ/peanut-butter-banana-french-toast', 'https://img.spoonacular.com/recipes/655239-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('healthy-spinach-parmesan-dip-and-pita-chips', 'Healthy Spinach Parmesan Dip and Pita Chips', 8, 0, 0, '{"calories": 197, "protein": 8.57, "carbs": 24.38, "fat": 7.57, "saturated_fat": 2.05, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 456.8, "potassium": null, "fiber": 2.15, "sugar": 4.58, "vitamin_a": null, "vitamin_c": 2.85, "calcium": 173.99, "iron": 2.1}'::jsonb, ARRAY['american', 'side dish', 'spoonacular', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "basil leaves", "notes": "1/2 cup basil leaves, loosely packed", "category": "produce"}, {"quantity": 0.125, "unit": "teaspoon", "item": "pepper", "notes": "1/8 teaspoon black pepper", "category": "spices and seasonings"}, {"quantity": 10.0, "unit": "ounce", "item": "spinach", "notes": "1 package (10 -ounce) frozen spinach", "category": "frozen"}, {"quantity": 3.0, "unit": "", "item": "garlic cloves", "notes": "3 garlic cloves, grated", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "olive oil", "notes": "1 teaspoon olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "ounce", "item": "parmesan cheese", "notes": "1/4 cup (1 ounce) grated fresh Parmesan cheese", "category": "cheese"}, {"quantity": 8.0, "unit": "servings", "item": "pita chips", "notes": "pita chips", "category": "savory snacks"}, {"quantity": 3.0, "unit": "ounces", "item": "reduced fat cream cheese", "notes": "1 cup (about 3 ounces) reduced fat cream cheese, softened", "category": "cheese"}, {"quantity": 0.25, "unit": "teaspoon", "item": "salt", "notes": "1/4 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "yogurt", "notes": "cup plain fat-free yogurt (can substitute Greek yogurt)", "category": "milk, eggs, other dairy"}]'::jsonb, '["Defrost spinach and squeeze out excess water.", "Heat olive oil in a large skillet over medium-high heat.", "Add garlic; saute 1 minute.", "Add salt and spinach; saute 3 minutes or until the spinach is warmed through.", "Place spinach mixture, basil, cream cheese, and pepper in a food processor; process until smooth. Spoon spinach mixture into a medium bowl.", "Add yogurt and Parmesan; stir to combine. Chill.", "Serve with pita chips."]'::jsonb, 'https://www.foodista.com/recipe/LXRPPGBW/healthy-spinach-parmesan-dip-and-pita-chips', 'https://img.spoonacular.com/recipes/646518-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('skillet-sweet-potato-casserole-with-bacon-brown-sugar-crumble', 'Skillet Sweet Potato Casserole with Bacon, Brown Sugar Crumble', 6, 10, 40, '{"calories": 351, "protein": 6.28, "carbs": 33.73, "fat": 22.38, "saturated_fat": 5.66, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 235.64, "potassium": null, "fiber": 5.42, "sugar": 5.86, "vitamin_a": null, "vitamin_c": 2.99, "calcium": 57.52, "iron": 1.69}'::jsonb, ARRAY['american', 'side dish', 'spoonacular', 'dessert', 'breakfast', 'baking'], '[{"quantity": 3.0, "unit": "slices", "item": "bacon", "notes": "3 slices fully cooked crispy bacon chopped", "category": "meat"}, {"quantity": 0.5, "unit": "cup", "item": "flour", "notes": "1/2 cup flour", "category": "baking"}, {"quantity": 0.33333334, "unit": "cup", "item": "heavy cream", "notes": "1/3 cup heavy cream", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "pecans", "notes": "1 cup chopped pecans", "category": "savory snacks"}, {"quantity": 0.25, "unit": "teaspoon", "item": "sea salt", "notes": "1/4 teaspoon fine sea salt", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "", "item": "sweet potatoes", "notes": "3 sweet potatoes peeled and cut into 1-inch cubes", "category": "produce"}]'::jsonb, '["Preheat your oven to 350 degrees F and have a cast iron skillet or oven-safe baking dish ready.", "Place the cubed sweet potatoes in a large pot and cover with water. Bring them to a boil over high heat and cook until tender, about 10-15 minutes.", "Remove from heat and drain.", "Transfer to a large bowl and mash.To the bowl with mashed sweet potatoes, stir in 1/2 cup of the melted butter, heavy cream, 1/4 cup of the brown sugar, and the salt until fully incorporated.", "Pour the mixture into the cast iron skillet.In a medium bowl, combine the 1/3 cup melted butter, 1/2 cup brown sugar, flour, pecans, and bacon. Fold the ingredients together until moist crumbles form.", "Sprinkle the mixture on top of the sweet potato mash.", "Place the skillet in the oven and bake for 35 minutes or until golden brown.", "Remove from heat and let stand for 5 minutes before serving.Enjoy!"]'::jsonb, 'https://www.pinkwhen.com/skillet-sweet-potato-casserole-with-bacon-brown-sugar-crumble/', 'https://img.spoonacular.com/recipes/1043339-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tater-tot-chili-cheese-casserole', 'Tater Tot Chili Cheese Casserole', 6, 5, 35, '{"calories": 176, "protein": 6.19, "carbs": 16.0, "fat": 10.54, "saturated_fat": 4.27, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 320.1, "potassium": null, "fiber": 1.77, "sugar": 2.84, "vitamin_a": null, "vitamin_c": 74.79, "calcium": 146.13, "iron": 0.76}'::jsonb, ARRAY['american', 'side dish', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'spoonacular', 'soup', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "chili", "notes": "2 cups chili", "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "tater tots", "notes": "2 cups tater tots", "category": "frozen"}, {"quantity": 1.0, "unit": "cup", "item": "cheddar cheese", "notes": "1 cup shredded cheddar cheese", "category": "cheese"}]'::jsonb, '["Heat oven to 35", "Add chili to cover the bottom of a casserole dish.", "Top the chili with frozen tater tots. Cook in oven for 20 minutes.", "Carefully top casserole with shredded cheese and cook for an additional 10 minutes or until cheese is melted.", "Serve.", "FREEZER MEAL INSTRUCTIONS", "Add the chili to a freezer safe container. Top with tater tots and remove as much air as possible before freezing. Leave in the freezer for up to 3 months.", "Remove from freezer and bake at 350 degrees Fahrenheit for 45 minutes.", "Remove foil, top with cheese, and then bake for an additional 10 minutes.", "Serve.", "CROCKPOT FREEZER MEAL INSTRUCTIONS", "Add chili to freezer safe bag.", "Remove air and freeze for up to 3 months.", "To cook: Thaw chili in refrigerator overnight.", "Add chili to the crockpot and cook on low for 4 hours. Stir.", "Top chili with tater tots and cook for an additional 2 hours. Cover with cheese, and cook for an additional hour.", "Serve."]'::jsonb, 'https://www.pinkwhen.com/tater-tot-chili-cheese-casserole/', 'https://img.spoonacular.com/recipes/1416203-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('blackberry-and-figs-chutney-compote', 'Blackberry and Figs Chutney / Compote', 4, 0, 0, '{"calories": 96, "protein": 2.03, "carbs": 23.78, "fat": 0.69, "saturated_fat": 0.07, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 294.36, "potassium": null, "fiber": 6.65, "sugar": 17.06, "vitamin_a": null, "vitamin_c": 52.82, "calcium": 54.48, "iron": 0.98}'::jsonb, ARRAY['american', 'sauce', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'whole 30', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "blackberry", "notes": "Blackberry : 2 cups (fresh or 2/3 cup dried)", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "chili : 1/ soaked", "notes": "Dry whole chili : 1/2 soaked with figs", "category": "produce"}, {"quantity": 6.0, "unit": "", "item": "figs : soaked in", "notes": "Dry Figs : 6 soaked in 1/2 cup of water for 3-4 hours", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "lemon rind : 1/ lemon", "notes": "Lemon rind : 1/2 lemon large", "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "salt : or", "notes": "Salt : 1/2 tsp or to taste", "category": "spices and seasonings"}]'::jsonb, '["Grind blackberries, figs and red chili in a coarse paste in the grinder with the water in which figs and chili were soaked.", "Pour the paste out in a pan.", "Put the pan on medium heat.", "Add all the above ingredients to the paste.", "Let the ingredients simmer together for 4-5 minutes.Your sweet and spicy blackberry and fig chutney/compote is ready  .Enjoy on top of the toast or crackers.", "Serve as a side/dip for pretzels, celery sticks, breadsticks. For more fun, top a bit over your vanilla ice cream  . Enjoy it with chopped nuts as well!Note : it can be stored in an air tight jar in the fridge for upto 10-12 days.Yield : approximately 1 cup", "Serve size : 1 tbsp"]'::jsonb, 'https://www.foodista.com/recipe/CBWH7DQ4/blackberry-and-figs-chutney-compote', 'https://img.spoonacular.com/recipes/635179-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fruit-salsa-cinnamon-chips', 'Fruit Salsa & Cinnamon Chips', 5, 0, 0, '{"calories": 254, "protein": 2.29, "carbs": 65.2, "fat": 1.06, "saturated_fat": 0.13, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 21.96, "potassium": null, "fiber": 9.41, "sugar": 51.45, "vitamin_a": null, "vitamin_c": 124.64, "calcium": 82.26, "iron": 0.76}'::jsonb, ARRAY['american', 'side dish', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "brown sugar", "notes": "2 tablespoons brown sugar", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "cinnamon", "notes": "2 teaspoons cinnamon", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "bag", "item": "flour tortillas", "notes": "1 bag large flour tortillas", "category": "pasta and rice"}, {"quantity": 0.25, "unit": "cup", "item": "granulated sugar", "notes": "1/4 cup granulated sugar", "category": "baking"}, {"quantity": 5.0, "unit": "medium size", "item": "apples", "notes": "5 medium size green apples", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "jelly", "notes": "1/2 cup jelly (strawberry or apple)", "category": "produce"}, {"quantity": 5.0, "unit": "", "item": "kiwis", "notes": "5 kiwis, peeled and chopped", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "lemon juice", "notes": "2 tablespoons lemon juice", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "mango", "notes": "1 Mango, pitted and cut into very thin slices", "category": "produce"}, {"quantity": 1.0, "unit": "medium", "item": "orange", "notes": "1 medium orange", "category": "produce"}, {"quantity": 6.0, "unit": "", "item": "strawberries", "notes": "6 Strawberries, trimmed and each one thinly sliced", "category": "produce"}, {"quantity": 5.0, "unit": "servings", "item": "water", "notes": "water", "category": "beverages"}]'::jsonb, '["Peel and chop green apples.In large bowl, toss green apples with lemon juice.Chop strawberries, mango, and kiwis, adding to apple mixture as prepared.Grate approximately 2 tablespoons of orange zest from orange and add to mixture.", "Cut orange in half and squeeze juice over mixture.In small bowl, mix jelly and brown sugar.", "Combine jelly mixture with fruit.Chill fruit while preparing cinnamon chips.", "Combine granulated sugar and cinnamon.Fill a clean spray bottle with water.Spray water on each tortilla, then sprinkle with cinnamon and sugar mixture.", "Cut each tortilla into eighths.", "Bake tortilla chips in 400 degree oven for six minutes.Cool chips on rack.", "Serve chips with fruit salsa."]'::jsonb, 'https://www.foodista.com/recipe/7RJGZK36/fruit-salsa-cinnamon-chips', 'https://img.spoonacular.com/recipes/644020-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('raw-vegan-chocolate-ice-cream-cupcakes', 'Raw Vegan Chocolate Ice Cream Cupcakes', 3, 0, 0, '{"calories": 317, "protein": 4.8, "carbs": 64.46, "fat": 8.98, "saturated_fat": 0.74, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 4.83, "potassium": null, "fiber": 11.15, "sugar": 42.65, "vitamin_a": null, "vitamin_c": 22.15, "calcium": 57.99, "iron": 1.66}'::jsonb, ARRAY['american', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'whole 30', 'vegan', 'spoonacular', 'dessert', 'vegetarian'], '[{"quantity": 2.0, "unit": "", "item": "bananas", "notes": "2 frozen bananas", "category": "produce"}, {"quantity": 3.0, "unit": "servings", "item": "blueberries - if you have", "notes": "blueberries – if you have, I think it would have looked great with a lovely blueberry in the middle.", "category": "produce"}, {"quantity": 3.0, "unit": "tbsp", "item": "carob powder", "notes": "3 tbsp carob powder", "category": "health foods"}, {"quantity": 10.0, "unit": "", "item": "dates", "notes": "10 dates, pitted", "category": "dried fruits"}, {"quantity": 0.33333334, "unit": "cup", "item": "hazelnuts", "notes": "1/3 cup raw hazelnuts, soaked for at least 2 hours", "category": "baking"}, {"quantity": 1.0, "unit": "cloves", "item": "ground", "notes": "ground cloves, sprinkled", "category": "?"}]'::jsonb, '["Go to my blog for the full instructions: http://gourmandelle.com/raw-vegan-chocolate-ice-cream-cupcakes/"]'::jsonb, 'https://www.foodista.com/recipe/W377CGJG/raw-vegan-chocolate-ice-cream-cupcakes', 'https://img.spoonacular.com/recipes/658005-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('apple-pie-smoothie', 'Apple Pie Smoothie', 2, 0, 0, '{"calories": 238, "protein": 7.23, "carbs": 38.2, "fat": 7.58, "saturated_fat": 1.68, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 65.25, "potassium": null, "fiber": 3.49, "sugar": 31.09, "vitamin_a": null, "vitamin_c": 4.72, "calcium": 214.16, "iron": 0.71}'::jsonb, ARRAY['american', 'morning meal', 'brunch', 'beverage', 'breakfast', 'drink', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'vegetarian'], '[{"quantity": 1.0, "unit": "tablespoon", "item": "almond butter", "notes": "1 tablespoon unsalted almond butter", "category": "nut butters, jams, and honey"}, {"quantity": 1.0, "unit": "tablespoon", "item": "apple sauce", "notes": "1 tablespoon apple sauce", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "cup", "item": "vanilla yogurt", "notes": "1/2 cup vanilla fat free yogurt", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "grain granola", "notes": "1 tablespoon 7 grain granola", "category": "cereal"}, {"quantity": 0.25, "unit": "teaspoon", "item": "ground cinnamon", "notes": "1/4 teaspoon Ground cinnamon", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "honey", "notes": "1 teaspoon honey", "category": "nut butters, jams, and honey"}, {"quantity": 2.0, "unit": "servings", "item": "ice cubes", "notes": "ice cubes", "category": "frozen"}, {"quantity": 1.0, "unit": "teaspoon", "item": "maple syrup", "notes": "1 teaspoon Maple syrup", "category": "cereal"}, {"quantity": 0.5, "unit": "cup", "item": "milk", "notes": "1/2 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "", "item": "delicious apple", "notes": "1 red delicious apple, cut into pieces", "category": "produce"}]'::jsonb, '["Combine all ingredients in a blender and pulse until smooth.", "Serve immediately."]'::jsonb, 'https://www.foodista.com/recipe/HJPJ6D56/apple-pie-smoothie', 'https://img.spoonacular.com/recipes/632575-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cauliflower-brown-rice-and-vegetable-fried-rice', 'Cauliflower, Brown Rice, and Vegetable Fried Rice', 8, 15, 15, '{"calories": 248, "protein": 7.06, "carbs": 28.91, "fat": 12.96, "saturated_fat": 4.18, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 444.09, "potassium": null, "fiber": 5.81, "sugar": 3.23, "vitamin_a": null, "vitamin_c": 65.2, "calcium": 133.23, "iron": 2.64}'::jsonb, ARRAY['chinese', 'asian', 'side dish', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'quick', 'vegetarian'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "grapeseed oil", "notes": "2 tablespoons grapeseed oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tablespoons", "item": "coconut oil", "notes": "2 tablespoons coconut oil", "category": "baking"}, {"quantity": 7.0, "unit": "", "item": "scallions", "notes": "7 scallions, chopped (keep white/light green ends separate from dark green tops)", "category": "produce"}, {"quantity": 5.0, "unit": "cloves", "item": "garlic", "notes": "5 cloves of garlic, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "head", "item": "cauliflower", "notes": "head of cauliflower, raw", "category": "produce"}, {"quantity": 3.0, "unit": "cups", "item": "brown rice", "notes": "3 cups of cooked brown rice, cold", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "cups", "item": "broccoli", "notes": "2 cups cooked broccoli, chopped small", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "peas", "notes": "1 cup frozen peas", "category": "produce"}, {"quantity": 3.0, "unit": "T", "item": "soy sauce", "notes": "3 T reduced-sodium soy sauce", "category": "condiments"}, {"quantity": 2.0, "unit": "teaspoons", "item": "sesame oil", "notes": "2 teaspoons toasted sesame oil", "category": "ethnic foods"}, {"quantity": 8.0, "unit": "servings", "item": "sesame seeds", "notes": "toasted sesame seeds, optional", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "servings", "item": "additional scallion tops", "notes": "additional chopped scallion tops for garnish", "category": "produce"}, {"quantity": 8.0, "unit": "servings", "item": "salt", "notes": "salt, to taste", "category": "spices and seasonings"}]'::jsonb, '["Remove the cauliflower''s tough stem and reserve for another use. Using a food processor, pulse cauliflower florets until they resemble rice or couscous. You should end up with around four cups of \"cauliflower rice.\"", "Heat 1T butter and 1T oil in a large skillet over medium heat.", "Add garlic and the white and light green pieces of scallion. Sauté about a minute.", "Add the cauliflower to the pan. Stir to coat with oil, then spread out in pan and let sit; you want it cook a bit and to caramelize (get a bit brown), which will bring out the sweetness. After a couple of minutes, stir and spread out again.", "Add cold rice (it separates easily, so it won''t clump up during cooking), plus the additional grapeseed and coconut oil or butter. Raise heat to medium-high. Toss everything together and, again, spread the mixture out over the whole pan and press a bit into the bottom.", "Let it sit for about two minutes—so the rice can get toasted and a little crispy.", "Add the peas and broccoli and stir again.", "Drizzle soy sauce and toasted sesame oil over rice.Cook for another minute or so and turn off heat.", "Add chopped scallion tops and toss.I like to toast some sesame seeds in a dry pan; I sprinkle these and some more raw, chopped scallion over the top of the rice for added flavor and crunch.Season to taste with salt and, if you''d like, more soy sauce. Keep in mind that if you''re serving this with something salty and saucy (ie. teriyaki chicken) you may want to hold off on adding too much salt to the fried rice."]'::jsonb, 'https://fullbellysisters.blogspot.com/2012/01/cauliflower-fried-rice-more-veggies.html', 'https://img.spoonacular.com/recipes/716426-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vietnamese-pancakes-with-vegetables-herbs-and-a-fragrant-dipping-sauce-bánh-xèo', 'Vietnamese Pancakes with Vegetables, Herbs and a Fragrant Dipping Sauce (Bánh Xèo)', 6, 0, 0, '{"calories": 389, "protein": 8.06, "carbs": 42.92, "fat": 22.48, "saturated_fat": 13.87, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 490.36, "potassium": null, "fiber": 5.96, "sugar": 7.07, "vitamin_a": null, "vitamin_c": 74.2, "calcium": 87.56, "iron": 5.37}'::jsonb, ARRAY['vietnamese', 'asian', 'side dish', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'breakfast', 'baking', 'vegetarian'], '[{"quantity": 1.3333334, "unit": "cups", "item": "brown rice flour", "notes": "1 1/3 cups brown rice flour", "category": "health foods"}, {"quantity": 0.5, "unit": "tablespoon", "item": "brown sugar", "notes": "1/2 tablespoon brown sugar", "category": "baking"}, {"quantity": 1.0, "unit": "large", "item": "carrot", "notes": "1 large carrot, scrubbed and grated", "category": "produce"}, {"quantity": 1.0, "unit": "pinch", "item": "cayenne", "notes": "pinch of cayenne", "category": "spices and seasonings"}, {"quantity": 1.75, "unit": "cups", "item": "coconut milk", "notes": "1 3/4 cups of coconut milk + water if needed", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "medium", "item": "daikon radish", "notes": "1 medium daikon radish, scrubbed and grated", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg, beaten", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "enoki mushrooms", "notes": "1 cup enoki mushrooms, trimmed", "category": "produce"}, {"quantity": 0.6666667, "unit": "cup", "item": "basil leaves", "notes": "2/3 cup fresh basil leaves, roughly chopped", "category": "produce"}, {"quantity": 1.0, "unit": "inch", "item": "ginger", "notes": "1-inch piece fresh ginger, grated", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "mint leaves", "notes": "1/4 cup fresh mint leaves, trimmed and roughly chopped", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "parsley", "notes": "1 cup fresh parsley or cilantro, roughly chopped", "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": "1 clove garlic, crushed", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "chili", "notes": "1 fresh green chili, seeded and minced", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "chilies", "notes": "2 fresh green chilies, seeded and sliced into small strips", "category": "produce"}, {"quantity": 4.0, "unit": "", "item": "green onions", "notes": "4 green onions, washed and cut on an angle", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "juice of lime", "notes": "juice from 2 limes", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "mung bean sprouts", "notes": "1 cup mung bean sprouts (see note below)", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "", "item": "chilies", "notes": "2 fresh red chilies, seeded and minced", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "rice vinegar", "notes": "1 tablespoon rice vinegar", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "teaspoon", "item": "sea salt", "notes": "1/2 teaspoon sea salt", "category": "spices and seasonings"}, {"quantity": 1.5, "unit": "tablespoons", "item": "sesame oil", "notes": "1 1/2 tablespoons toasted sesame oil", "category": "ethnic foods"}, {"quantity": 6.0, "unit": "servings", "item": "sesame oil", "notes": "sesame oil for frying", "category": "ethnic foods"}, {"quantity": 1.5, "unit": "cups", "item": "snow peas", "notes": "1 1/2 cups snow peas, sliced into small strips", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "tamari sauce", "notes": "1 tablespoon tamari sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "teaspoon", "item": "turmeric", "notes": "1 teaspoon turmeric", "category": "spices and seasonings"}]'::jsonb, '["Begin by preparing the pancake batter.", "Whisk together the rice flour, egg, sea salt, turmeric, cayenne and green chili. Gradually whisk in the coconut milk. The mixture should be a smooth, semi-thick batter that is of pouring consistency.", "Add a little water if necessary. Cover and set aside while you prepare the rest of the food.Now prepare the sauce.", "Whisk together all of the ingredients and set aside.For the filling, combine the carrot, radish, green onions, green chilies and snow peas.", "Put the herbs in another bowl and have your sprouts ready along with the mushrooms.", "Heat a teaspoon of oil over medium heat in a non-stick skillet. When hot, ladle 1/2 cup of batter into the pan and spread with the bottom of the ladle until you have a roughly 6 to 8 inch pancake.  Fry for 6 to 8 minutes or until you have small holes forming and the bottom is crispy brown, then flip and fry for another few minutes on the other side.", "Transfer to a plate and keep warm in a 150 oven while you finish the rest of the pancakes  you should finish with 4 to 6 pancakes.To serve, scatter a portion of the vegetables, herbs and mushrooms over one half of the pancake.", "Sprinkle some sauce over top and fold the pancake.", "Drizzle with more sauce and there you go."]'::jsonb, 'https://www.foodandspice.com/2012/05/vietnamese-pancakes-with-vegetables.html', 'https://img.spoonacular.com/recipes/716217-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('skinny-veggie-fried-rice', 'Skinny Veggie Fried Rice', 2, 0, 0, '{"calories": 156, "protein": 5.05, "carbs": 18.89, "fat": 8.56, "saturated_fat": 1.22, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 507.15, "potassium": null, "fiber": 3.99, "sugar": 6.8, "vitamin_a": null, "vitamin_c": 84.44, "calcium": 44.14, "iron": 1.27}'::jsonb, ARRAY['chinese', 'asian', 'side dish', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "Tbsp", "item": "sesame oil", "notes": "1 Tbsp olive oil or sesame oil", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tsp", "item": "ginger", "notes": "1 tsp ginger, minced", "category": "produce"}, {"quantity": 1.0, "unit": "Tbsp", "item": "garlic", "notes": "1 Tbsp garlic, minced", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "mushrooms", "notes": "1 cup mushrooms, chopped", "category": "produce"}, {"quantity": 6.0, "unit": "", "item": "baby corns", "notes": "6-7 baby corns, cut in round disks", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "green onions white part", "notes": "1/4 cup green onions white part, chopped (Keep the chopped green part of green onions for garnishing)", "category": "produce"}, {"quantity": 1.0, "unit": "small", "item": "size carrot", "notes": "1 size carrot, chopped in small pieces", "category": "produce"}, {"quantity": 1.0, "unit": "small size", "item": "bell pepper", "notes": "1 small size bell pepper, chopped in small pieces", "category": "produce"}, {"quantity": 1.0, "unit": "Tbsp", "item": "soy sauce", "notes": "1 Tbsp low sodium soy sauce", "category": "condiments"}, {"quantity": 2.0, "unit": "servings", "item": "salt", "notes": "Salt to taste", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "servings", "item": "bell pepper", "notes": "Black pepper to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "sesame seeds", "notes": "1 tsp sesame seeds", "category": "spices and seasonings"}]'::jsonb, '["Heat a wok or skillet on med-high and add 1 tsp oil. To it add minced ginger and 1 tsp minced garlic.", "Saute until fragrant but not burnt.", "Add mushroom pieces. Cook until tender for 5-6 minutes. Keep mushrooms along with any juices aside in a bowl.", "Heat wok again add 1 tsp oil. To it add remaining garlic.", "Saute until fragrant and add all the vegetables. Stir it all together on high flame.", "Add salt, black pepper and splash of soy sauce. Toss to coat and let them cook for few more minutes until they get tender but not soft. You want veggies to be cooked but with a little crunch. Now add the cold already cooked rice and stir it so it all gets mixed together. Do with a gentle hand.", "Let the rice get warm at med- high flame.", "Add the remaining 1 tsp oil along with salt, black pepper and soy sauce.", "Add the mushrooms and tofu(if using).", "Mix it all together. Toss and taste.", "Garnish with chopped green parts of green onions and sesame seeds."]'::jsonb, 'https://www.foodista.com/recipe/S53BXV6Z/skinny-veggie-fried-rice', 'https://img.spoonacular.com/recipes/660231-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('indian-style-dill-and-turmeric-potato-salad', 'Indian-Style Dill and Turmeric Potato Salad', 4, 0, 0, '{"calories": 416, "protein": 7.98, "carbs": 65.96, "fat": 14.5, "saturated_fat": 2.04, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 224.14, "potassium": null, "fiber": 8.46, "sugar": 2.9, "vitamin_a": null, "vitamin_c": 83.21, "calcium": 72.24, "iron": 3.87}'::jsonb, ARRAY['indian', 'asian', 'side dish', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'whole 30', 'vegan', 'spoonacular', 'salad', 'vegetarian'], '[{"quantity": 1.0, "unit": "pinch", "item": "of chilli flakes", "notes": "Large pinch of dried chilli flakes", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "dill", "notes": "1 cup fresh dill, chopped finely", "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves of garlic, chopped finely", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "olive oil", "notes": "Olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "large", "item": "potatoes", "notes": "4 large potatoes, parboiled and chopped into cubes", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "salt", "notes": "Salt to taste", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "turmeric powder", "notes": "1/2 teaspoon turmeric powder", "category": "spices and seasonings"}]'::jsonb, '["Heat the olive oil in a large frying pan.", "Add the garlic and chilli and heat gently until fragrant. Then add the turmeric powder. Fry together for about 30 seconds.", "Add the potatoes and mix gently to coat with the turmeric.", "Add a about 1/4 cup of water and let the potatoes cook through. Then add some salt to taste.Take off the heat and add the dill.", "Serve immediately."]'::jsonb, 'https://www.foodista.com/recipe/2LQW8RTQ/indian-style-dill-and-turmeric-potatoes', 'https://img.spoonacular.com/recipes/647875-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chapchae-korean-stir-fried-noodles', 'Chapchae (Korean Stir-Fried Noodles)', 4, 0, 0, '{"calories": 396, "protein": 5.21, "carbs": 63.88, "fat": 14.54, "saturated_fat": 2.04, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1024.69, "potassium": null, "fiber": 4.66, "sugar": 8.17, "vitamin_a": null, "vitamin_c": 27.16, "calcium": 109.41, "iron": 2.55}'::jsonb, ARRAY['korean', 'asian', 'side dish', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'dessert', 'pasta', 'vegetarian'], '[{"quantity": 8.0, "unit": "ounces", "item": "sweet potato vermicelli noodles", "notes": "8 ounces sweet potato vermicelli noodles", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 sweet onion, sliced into thin strips", "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves garlic, finely chopped", "category": "produce"}, {"quantity": 0.5, "unit": "pound", "item": "baby spinach", "notes": "1/2 pound baby spinach, parboiled", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "carrots", "notes": "2 carrots, julienned", "category": "produce"}, {"quantity": 3.0, "unit": "", "item": "scallions", "notes": "3 scallions, chopped", "category": "produce"}, {"quantity": 5.0, "unit": "", "item": "mushrooms", "notes": "5 mushrooms, sliced (I like to use creminis)", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "zucchini", "notes": "1/2 cup zucchini, sliced into half-moons", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tablespoons", "item": "sesame oil", "notes": "2 tablespoons sesame oil", "category": "ethnic foods"}, {"quantity": 3.0, "unit": "tablespoons", "item": "soy sauce", "notes": "3 tablespoons soy sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sugar", "notes": "1 teaspoon sugar", "category": "baking"}, {"quantity": 4.0, "unit": "servings", "item": "salt", "notes": "Salt to taste", "category": "spices and seasonings"}]'::jsonb, '["Cook noodles according to package directions", "In a large pan or wok over medium heat, heat olive oil and 1 Tbsp sesame oil", "Add onion slices and garlic and saut for about 1 min", "Add rest of vegetables and cook for 4-5 min, until the vegetables are half-cooked and still a bit crispy", "Turn heat to low and add cooked noodles, soy sauce, sugar, and the remaining sesame oil", "Mix to combine and cook for another 2 min", "Add salt or more soy sauce if needed (or if you want it a bit sweeter, add a touch more sugar)", "If using sesame seeds, add them at finish"]'::jsonb, 'https://www.foodista.com/recipe/RSDBG48H/chapchae-korean-stir-fried-noodles', 'https://img.spoonacular.com/recipes/637440-312x231.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('kimchi', 'Kimchi', 6, 0, 0, '{"calories": 118, "protein": 6.94, "carbs": 24.83, "fat": 1.79, "saturated_fat": 0.36, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 3622.36, "potassium": null, "fiber": 8.31, "sugar": 11.59, "vitamin_a": null, "vitamin_c": 129.25, "calcium": 396.73, "iron": 3.04}'::jsonb, ARRAY['korean', 'asian', 'side dish', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'dessert', 'vegetarian'], '[{"quantity": 6.0, "unit": "pounds", "item": "napa cabbage", "notes": "6 pounds Napa cabbage", "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "salt", "notes": "3 tablespoons salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cups", "item": "scallions", "notes": "2 cups sliced scallions", "category": "produce"}, {"quantity": 3.0, "unit": "", "item": "garlic cloves", "notes": "3 minced garlic cloves", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "ginger root", "notes": "1 tablespoon ginger root minced or 2 tsp. ginger powder", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "tablespoons", "item": "ground chili pepper", "notes": "4 tablespoons dried ground chili pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "sugar", "notes": "2 tablespoons sugar", "category": "baking"}]'::jsonb, '["Shred cabbage in 2 inch strips.", "Mix with half the salt.", "Let stand 30 minutes. Wash and drain.", "Mix the scallions, garlic, ginger, chili pepper, cabbage and the rest of salt. Pack into a crock or glass jar.", "Put the containers aside for three or four days in a cool location. After that, store it in the refrigerator."]'::jsonb, 'https://www.foodista.com/recipe/KPSCVHD5/kimchi', 'https://img.spoonacular.com/recipes/648910-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('indian-style-pumpkin-side-dish', 'Indian-Style Pumpkin Side Dish', 12, 0, 0, '{"calories": 53, "protein": 2.04, "carbs": 11.21, "fat": 0.96, "saturated_fat": 0.13, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 3.08, "potassium": null, "fiber": 1.61, "sugar": 4.44, "vitamin_a": null, "vitamin_c": 19.21, "calcium": 40.11, "iron": 1.46}'::jsonb, ARRAY['indian', 'asian', 'side dish', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'whole 30', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "tablespoon", "item": "coriander powder", "notes": "1 tablespoon coriander powder", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "sprigs", "item": "curry leaves", "notes": "2 sprigs curry leaves, discard stalks", "category": "ethnic foods"}, {"quantity": 5.0, "unit": "", "item": "chili peppers", "notes": "5 dried chili peppers", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "ginger", "notes": "2 tablespoons grated ginger", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "mustard seeds", "notes": "2 tablespoons mustard seeds", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "large", "item": "onions", "notes": "2 large onions, finely chopped", "category": "produce"}, {"quantity": 1.0, "unit": "small", "item": "pumpkin", "notes": "1 small pumpkin", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "turmeric powder", "notes": "1 tablespoon turmeric powder", "category": "spices and seasonings"}]'::jsonb, '["Heat oil in pan and stir in curry leaves, mustard seeds and dried chillies until the mustard seeds start to pop.", "Remove chillies.", "Add chopped onions and grated ginger and fry until onions are soft.Toss in diced pumpkin, turmeric powder and coriander powder and stir to combine.", "Add about a half cup of water, stir and simmer covered, until liquid evaporates and pumpkin turns soft. If needed, add more water, cover and simmer until the desired texture. Do not put in too much water or pumpkin will become mushy.", "Add salt to taste.(", "Sprinkle with some chopped fresh coriander if desired)"]'::jsonb, 'https://www.foodista.com/recipe/HFH8GVJS/fried-pumpkin-indian-style', 'https://img.spoonacular.com/recipes/643775-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('asian-vegetable-salad', 'Asian Vegetable Salad', 8, 0, 0, '{"calories": 40, "protein": 1.68, "carbs": 5.97, "fat": 1.38, "saturated_fat": 0.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 157.78, "potassium": null, "fiber": 1.9, "sugar": 3.31, "vitamin_a": null, "vitamin_c": 56.21, "calcium": 24.96, "iron": 0.89}'::jsonb, ARRAY['asian', 'side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 2.0, "unit": "medium", "item": "size bell peppers", "notes": "2 mediums Size Red Bell Peppers", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "carrots", "notes": "2 Carrots, cut on an angle (about 1 cup)", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "gingerroot", "notes": "1/2 teaspoon Minced Gingerroot", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "soy sauce", "notes": "2 tablespoons Low Sodium Soy Sauce", "category": "condiments"}, {"quantity": 8.0, "unit": "servings", "item": "pineapple chunks", "notes": "Pineapple Chunks Undrained", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "teaspoons", "item": "sesame oil", "notes": "2 teaspoons Sesame oil", "category": "ethnic foods"}, {"quantity": 1.5, "unit": "teaspoons", "item": "sesame seeds", "notes": "1 1/2 teaspoons Sesame Seeds", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "pound", "item": "snow peas", "notes": "1/2 pound Snow Peas Trimmed", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bn watercress", "notes": "1 bn Watercress", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "white wine vinegar", "notes": "2 tablespoons White Wine Vinegar", "category": "oil, vinegar, salad dressing"}]'::jsonb, '["Drain Pineapple, Reserving 1/4 C. Juice; Set Pineapple Aside.", "Combine Reserved Juice, Vinegar, Soy Sauce, Oil, & Gingerroot in A Small Bowl. Stir Well, Cover & Chill.", "Place Snow Peas in A Steamer Over Boiling Water. Cover & Steam 1 Min. OR Until Crisp-Tender. Rinse With Cold Water,", "Drain & Set Aside.", "Place Carrots in Steamer Over Boiling Water. Cover & Steam 3 Min. Rinse With Cold Water;", "Drain & Set Aside.Line A Large Serving Platter With Watercress. Arrange Pinapple, Snow Peas, Carrots & Bell Peppers Attractively Over Watercress. Cover & Chill. To", "Serve", "Pour Vinegar", "Mixture Over Salad;", "Sprinkle With Sesame Seeds. (Fat 1.3 Grams.)"]'::jsonb, 'https://www.foodista.com/recipe/DCFDGJ2F/asian-vegetable-salad', 'https://img.spoonacular.com/recipes/632896-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('roasted-acorn-squash-stuffed-with-spicy-biryani-vegvegan', 'Roasted Acorn Squash Stuffed with spicy Biryani (Veg/vegan)', 4, 0, 0, '{"calories": 514, "protein": 15.02, "carbs": 94.82, "fat": 12.58, "saturated_fat": 2.07, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1686.95, "potassium": null, "fiber": 14.38, "sugar": 10.6, "vitamin_a": null, "vitamin_c": 127.17, "calcium": 225.53, "iron": 5.89}'::jsonb, ARRAY['indian', 'asian', 'side dish', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'baking'], '[{"quantity": 4.0, "unit": "", "item": "acorn squashes", "notes": "4 acorn squashes cut in half, gutted", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "basmati rice soaked in water", "notes": "1/2 cup basmati rice soaked in water", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "cup", "item": "water", "notes": "1 cup water", "category": "beverages"}, {"quantity": 3.0, "unit": "tablespoons", "item": "garam masala", "notes": "3 tablespoons garam masala (click for a homemade recipe or store-bought is fine)", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "medium", "item": "onion", "notes": "1 medium red onion- diced", "category": "produce"}, {"quantity": 4.0, "unit": "small", "item": "peppers", "notes": "4 small sweet peppers- diced", "category": "produce"}, {"quantity": 1.0, "unit": "handful", "item": "cashew nuts- a bit", "notes": "handful cashew nuts- chopped a bit", "category": "nuts"}, {"quantity": 4.0, "unit": "servings", "item": "saffron", "notes": "of saffron", "category": "gourmet"}, {"quantity": 1.0, "unit": "handful", "item": "cilantro", "notes": "handful cilantro- finely chopped", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "tablespoons", "item": "biryani paste- recipe below", "notes": "4 tablespoons biryani paste- recipe BELOW (or store-bought)", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "medium", "item": "onion", "notes": "1 medium onion- cut into thick slices (garnishing)", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "salt", "notes": "salt to taste", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "coarse pepper", "notes": "coarse black pepper", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "pam original flavor", "notes": "PAM original flavor", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "tablespoon", "item": "vegetable oil", "notes": "1 tablespoon vegetable oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "medium", "item": "onion", "notes": "1 medium white onion- diced", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "beefsteak tomato", "notes": "1 beefsteak tomato- diced", "category": "produce"}, {"quantity": 4.0, "unit": "cloves", "item": "garlic", "notes": "4 cloves garlic- crushed and minced (click HERE for amazing garlic tips!)", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "ginger", "notes": "2 tablespoons ginger- freshly grated (need help Tackling Ginger?)", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "chili powder", "notes": "1 tablespoon chili powder (it should be spicy!)", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "handful", "item": "cilantro", "notes": "handful chopped cilantro", "category": "spices and seasonings"}, {"quantity": 5.0, "unit": "tablespoons", "item": "hefty biryani paste", "notes": "5 tablespoons hefty Biryani paste (I use Patak''s Brand)", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "tablespoon", "item": "vegetable oil", "notes": "1/2 tablespoon vegetable oil", "category": "oil, vinegar, salad dressing"}]'::jsonb, '["Preheat the oven to 400 degrees. On a baking sheet place the squash halves, spray with PAM and sprinkle with 1-2 tbsp garam masala.", "Place in the oven and BROIL till tender and charred- about 10-15 minutes.", "While the squashes are roasting, in a large skillet, spray with PAM and add vegetable oil and set over medium heat.", "Add the cashews and saute until fragrant and slightly darkened.", "Add onions and peppers, sprinkle with black pepper and saute until soft, about 5-7 minutes. Once the onions and peppers are soft, but now brown, add the soaked basmati rice (make sure not to get any water in it!).", "Saute for 5-7 minutes. You want to toast the the rice.", "Remove the squash from the oven and cool for a few minutes before handling. Score the squash into small cubes, WITHOUT cutting through the skin. Scoop the cubes out into a bowl and set aside. Keep the shell aside, DONT throw out!", "Once the rice is toasted add 1 cup of water, pinch of saffron, cover and cook on medium-low heat, about 15 minutes. You want the rice to be cooked thru, not mushy so dont mix it around too much! Once the rice is cooked, add the cubed squash, tossing gently (you dont want the squash to break and mush around the rice).", "Add the Biryani paste and toss to coat.", "Mix in 3/4 of the chopped cilantro. Taste for salt and biryani flavor- it should be strong, spicy and aromatic.", "In a small skillet, spray with PAM and set over medium-high heat.", "Add onion slices, and saute without breaking up the circles. Cook until brown-ish about 4-5 minutes. Set aside.", "Fill each squash bowl with rice, just coming over the top. Top each one with an onion round and sprinkle with remaining chopped cilantro.", "Serve with yogurt or raita.", "In a medium skillet, spray with pam, add oil and set over medium-high flame.", "Add onions and tomatoes, saute until golden-brown about 4-5 minutes.", "Add garlic, ginger, chili powder and cilantro.", "Saute until vegetables are soft and fragrant about 4-5 minutes.", "Add the biryani paste and mix well, making sure all the veggies are coated.", "Remove from the heat and let cool (10-15 minutes).", "In a grinder/food processor, add the biryani mixture and grind until smooth (slightly chunky is ok). Store in an air tight container. Can be kept in the fridge for 1-2 weeks, or in the freezer- for a while!"]'::jsonb, 'https://www.foodista.com/recipe/CVYJ4256/roasted-acorn-squash-stuffed-wspicy-biryani-vegvegan', 'https://img.spoonacular.com/recipes/658482-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('asian-slaw', 'Asian Slaw', 1, 0, 0, '{"calories": 462, "protein": 8.23, "carbs": 36.24, "fat": 29.15, "saturated_fat": 4.18, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2218.76, "potassium": null, "fiber": 11.54, "sugar": 17.57, "vitamin_a": null, "vitamin_c": 67.97, "calcium": 166.26, "iron": 2.53}'::jsonb, ARRAY['asian', 'side dish', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'fodmap friendly', 'vegan', 'spoonacular', 'salad', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "cabbage", "notes": "2 cups Shredded cabbage (about a 2 pound head)", "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "carrots", "notes": "2 cups Shredded carrots", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "cayenne pepper", "notes": "teaspoon Cayenne pepper (the more the merrier!)", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ginger root", "notes": "1 teaspoon Finely chopped ginger root", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "mirin", "notes": "cup Rice vinegar or mirin (mirin is a 2 teaspoons Honey", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "tablespoons", "item": "sesame oil", "notes": "2 tablespoons Sesame oil", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "tablespoons", "item": "tamari soy sauce", "notes": "2 tablespoons Tamari soy sauce", "category": "ethnic foods"}]'::jsonb, '["Here''s a tasty recipe for \"Oriental Slaw\". It''s not especially hot, but can be made hot by upping the amount of cayenne pepper used. It''s quite tasty, is extremely healthy, and is very low in fat.In blender, combine all ingredients except carrots and cabbage. In a large bowl, mix cabbage and carrots, pour dressing over and toss well.Makes 6servings.NOTE: The dressing made for this salad can also be used as a normal green salad dressing or as a marinade for chicken, fish, or vegetables. If you want more heat, up the cayenne!"]'::jsonb, 'https://www.foodista.com/recipe/56FWKCB8/asian-slaw', 'https://img.spoonacular.com/recipes/632881-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('baked-indian-spice-chickpea', 'Baked Indian Spice Chickpea', 3, 0, 0, '{"calories": 265, "protein": 7.75, "carbs": 21.89, "fat": 17.28, "saturated_fat": 2.29, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 615.37, "potassium": null, "fiber": 7.33, "sugar": 0.06, "vitamin_a": null, "vitamin_c": 0, "calcium": 65.4, "iron": 2.72}'::jsonb, ARRAY['indian', 'asian', 'side dish', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "can", "item": "chickpeas", "notes": "1 can chickpeas", "category": "canned and jarred"}, {"quantity": 3.0, "unit": "tbsp", "item": "olive oil", "notes": "3 tbsp olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tsp", "item": "curry powder", "notes": "2 tsp curry powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "ground ginger", "notes": "1 tsp ground ginger", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "ground coriander", "notes": "1/2 tsp ground coriander", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "ground cumin", "notes": "1/2 tsp ground cumin", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "servings", "item": "sea salt", "notes": "Sea salt (to season)", "category": "spices and seasonings"}]'::jsonb, '["Preheat oven to 350F.", "Rinse chickpeas thoroughly.", "Remove skins of chickpeas (spices will stick better).", "Set chickpeas aside to dry.", "Meanwhile, in a medium bowl mix together spices and oil.", "Add dried chickpeas to bowl and toss until an even coat of seasoning has covered the chickpeas.", "Pour chickpeas onto a lined baking sheet and spread evenly.", "Stirring occasionally, bake for 40 minutes or until desired firmness is achieved.", "Toss in sea salt.", "Cool and serve! Enjoy within the same day."]'::jsonb, 'https://www.foodista.com/recipe/DWNPVY8P/baked-indian-spice-chickpea-recipe', 'https://img.spoonacular.com/recipes/633649-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('asian-carrot-dressing', 'Asian Carrot Dressing', 1, 0, 0, '{"calories": 141, "protein": 1.84, "carbs": 15.03, "fat": 8.25, "saturated_fat": 1.18, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 467.74, "potassium": null, "fiber": 1.3, "sugar": 6.22, "vitamin_a": null, "vitamin_c": 13.57, "calcium": 40.44, "iron": 0.94}'::jsonb, ARRAY['asian', 'side dish', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'fodmap friendly', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 0.6666667, "unit": "cup", "item": "carrot juice", "notes": "2/3 cup carrot juice", "category": "beverages"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ginger", "notes": "1/2 teaspoon freshly grated ginger", "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "salt", "notes": "salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "sesame oil", "notes": "2 teaspoons sesame oil", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "teaspoon", "item": "soy sauce", "notes": "1/2 teaspoon soy sauce", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "tablespoons", "item": "white wine vinegar", "notes": "2 tablespoons white wine vinegar", "category": "oil, vinegar, salad dressing"}]'::jsonb, '["Whisk Together 2/3 cup carrot juice and 1/2 teaspoon freshly grated ginger. Stir in 1/2 teaspoon soy sauce, 2 teaspoons sesame oil, 2 tablespoons white wine vinegar, and salt."]'::jsonb, 'https://www.foodista.com/recipe/L8HZRKY3/asian-carrot-dressing', 'https://img.spoonacular.com/recipes/632806-312x231.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition 