INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('asian-pear-and-gorgonzola-salad-with-pomegranate-vinaigrette', 'Asian Pear and Gorgonzola Salad With Pomegranate Vinaigrette', 20, 0, 0, '{"calories": 77, "protein": 2.48, "carbs": 7.24, "fat": 4.87, "saturated_fat": 1.04, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 236.79, "potassium": null, "fiber": 1.92, "sugar": 3.9, "vitamin_a": null, "vitamin_c": 5.68, "calcium": 37.02, "iron": 0.68}'::jsonb, ARRAY['asian', 'side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'vegetarian', 'vegan'], '[{"quantity": 8.0, "unit": "cups", "item": "greens", "notes": "8 cups Mixed Greens (ie. Arugula, Baby Spinach, Mâche, etc.)", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "asian pears", "notes": "2 Small Asian Pears, sliced paper thin", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "pomegranate seeds", "notes": "cup Fresh Pomegranate Seeds", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "gorgonzola", "notes": "1/2 cup Gorgonzola, crumbled", "category": "cheese"}, {"quantity": 1.0, "unit": "cup", "item": "pistachio nuts", "notes": "cup Pistachio Nuts, roughly chopped", "category": "savory snacks"}, {"quantity": 2.0, "unit": "tablespoons", "item": "pomegranate seeds", "notes": "2 tablespoons Fresh Pomegranate Seeds", "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "red wine vinegar", "notes": "3 tablespoons Red Wine Vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.5, "unit": "teaspoon", "item": "sugar", "notes": "1/2 teaspoon Sugar", "category": "baking"}, {"quantity": 2.0, "unit": "", "item": "shallots", "notes": "2 Shallots, thinly sliced", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "extra virgin olive oil", "notes": "1/2 cup Extra Virgin Olive Oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 20.0, "unit": "servings", "item": "kosher salt and cracked pepper", "notes": "Kosher Salt and Fresh Cracked Pepper to taste", "category": "spices and seasonings"}]'::jsonb, '["Prepare Vinaigrette. In a small sauce pan or skillet, heat olive oil on low.", "Add shallots and cook until softenedabout 2-3 minutes.", "Remove from heat and cool.", "Place pomegranate seeds in a small bowl. Using a fork, crush the seeds to allow the juices to come out.", "Add shallots, sugar, and red wine vinegar. Slowly whisk in the olive oil from the shallots until fully incorporated. Season with salt and pepper to taste.", "Arrange the greens onto a large platter.", "Place the pears over the greens and sprinkle the pomegranate seeds, pistachios, and gorgonzola on top.", "Drizzle the vinaigrette over the salad and serve immediately."]'::jsonb, 'https://www.foodista.com/recipe/Z4G2VRTD/asian-pear-and-gorgonzola-salad-with-pomegranate-vinaigrette', 'https://img.spoonacular.com/recipes/632862-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spinach-chickpea-palak-chana-rice', 'Spinach Chickpea - Palak Chana Rice', 2, 0, 0, '{"calories": 632, "protein": 12.54, "carbs": 102.36, "fat": 19.34, "saturated_fat": 4.26, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 543.44, "potassium": null, "fiber": 9.41, "sugar": 5.39, "vitamin_a": null, "vitamin_c": 25.78, "calcium": 138.68, "iron": 3.58}'::jsonb, ARRAY['indian', 'asian', 'side dish', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'salad', 'vegetarian'], '[{"quantity": 3.0, "unit": "", "item": "cardamom", "notes": "3 cardamom", "category": "spices and seasonings"}, {"quantity": 100.0, "unit": "grams", "item": "chickpeas", "notes": "100 grams chickpeas (soaked and cooked or canned chick peas)", "category": "canned and jarred"}, {"quantity": 1.5, "unit": "inches", "item": "cinnamon stick", "notes": "1 1/2 inches cinnamon stick", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "coconut", "notes": "2 tablespoons of grated coconut", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ginger garlic paste", "notes": "1 teaspoon ginger garlic paste", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "", "item": "chilies", "notes": "2 green chilies", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "oil", "notes": "2 tablespoons of oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "large", "item": "onion", "notes": "1 large onion (sliced)", "category": "produce"}, {"quantity": 200.0, "unit": "grams", "item": "basmathi rice", "notes": "200 grams basmathi rice (soaked for 30 minutes before cooking)", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "servings", "item": "salt", "notes": "Salt to taste", "category": "spices and seasonings"}, {"quantity": 100.0, "unit": "grams", "item": "spinach leaves", "notes": "100 grams fresh spinach leaves", "category": "produce"}, {"quantity": 400.0, "unit": "milliliters", "item": "water", "notes": "400 milliliters of water (you can add more depending on the rice)", "category": "beverages"}]'::jsonb, '["Grind clean spinach and green chilies into smooth paste and set it aside", "In a deep heavy bottom pot, warm 2 tbsp of oil, add cinnamon, cloves and cardamom. Wait for 30 to 45 seconds then add sliced onions. Fry onions till they are transparent or light brown. Now add in spinach chili paste. Fry till the oil separates out, add cooked chickpeas, mix well", "Add grated coconut, fry for 30 seconds. Next add in soaked rice and fry for another 2 minutes, then mix salt.", "Pour in water and cook till the rice is cooked.", "Serve with curd or rita. I garnished the food with carrot curls and flower, check this video if you want to learn  carrot curls  and  carrot flowers"]'::jsonb, 'https://www.foodista.com/recipe/P5X3D82L/spinach-chickpea-palak-chana-rice', 'https://img.spoonacular.com/recipes/661287-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pickled-asian-ginger-salad', 'Pickled Asian Ginger Salad', 4, 0, 0, '{"calories": 176, "protein": 1.99, "carbs": 31.13, "fat": 5.19, "saturated_fat": 0.72, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 25.14, "potassium": null, "fiber": 2.29, "sugar": 27.22, "vitamin_a": null, "vitamin_c": 8.68, "calcium": 99.68, "iron": 1.44}'::jsonb, ARRAY['asian', 'side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'fodmap friendly', 'vegan', 'spoonacular', 'dessert', 'vegetarian'], '[{"quantity": 4.0, "unit": "servings", "item": "sesame seeds", "notes": "Black and white sesame seeds", "category": "spices and seasonings"}, {"quantity": 0.75, "unit": "cup", "item": "carrot", "notes": "3/4 cup sliced carrot", "category": "produce"}, {"quantity": 0.75, "unit": "cup", "item": "cucumber", "notes": "3/4 cup sliced cucumber", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "daikon", "notes": "1 cup sliced daikon", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "ginger", "notes": "1 tablespoon grated ginger", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "rice vinegar", "notes": "1/2 cup rice vinegar", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sesame oil", "notes": "1 teaspoon sesame oil", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "cup", "item": "sugar", "notes": "1/2 cup sugar", "category": "baking"}]'::jsonb, '["Wash and peel daikon, carrot and cucumber.Slice all vegetables with a grater or mandolin and place in a bowl", "In another bowl, mix vinegar, sesame oil and sugar until sugar is dissolved.Grate ginger and add to vinegar mixture.", "Pour vinegar mixture on sliced veggies and stir thoroughly.Cover with plastic wrap and refrigerate for two hours.After chilling, stir again and plate.Top with sesame seeds and serve."]'::jsonb, 'https://www.foodista.com/recipe/BRL2CYK3/pickled-asian-ginger-salad', 'https://img.spoonacular.com/recipes/655926-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('indian-asparagus-with-ginger-lime', 'Indian Asparagus with Ginger & Lime', 2, 0, 0, '{"calories": 148, "protein": 3.41, "carbs": 11.61, "fat": 11.0, "saturated_fat": 1.52, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1170.54, "potassium": null, "fiber": 3.38, "sugar": 5.85, "vitamin_a": null, "vitamin_c": 10.21, "calcium": 44.7, "iron": 3.2}'::jsonb, ARRAY['indian', 'asian', 'side dish', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'dessert', 'vegetarian'], '[{"quantity": 14.0, "unit": "", "item": "asparagus spears", "notes": "14-15 asparagus spears", "category": "produce"}, {"quantity": 1.0, "unit": "pinch", "item": "chili powder", "notes": "A pinch of chili powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "cumin seeds", "notes": "½ tsp cumin seeds", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "inch", "item": "ginger", "notes": "1 inch piece peeled ginger", "category": "produce"}, {"quantity": 0.75, "unit": "tbsp", "item": "lime juice", "notes": "¾ tbsp lime juice", "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "mustard seeds", "notes": "½ tsp mustard seeds", "category": "spices and seasonings"}, {"quantity": 1.5, "unit": "tbsp", "item": "olive oil", "notes": "1 ½ tbsp olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "shallots", "notes": "2 shallots finely chopped", "category": "produce"}, {"quantity": 0.75, "unit": "tsp", "item": "sugar", "notes": "¾ tsp sugar", "category": "baking"}]'::jsonb, '["Heat the oil in the large non-stick pan (do not allow it to smoke). (To test if the oil is hot enough, throw in one mustard seed  if the oil is ready, it should sizzle and rise to the top straight away) When hot add the mustards seeds and fry until they sizzle, and add the cumin seeds and fry for 3-4 seconds.Turn the heat to medium and add the onions, ginger and fry stirring occasionally, for 5 minutes or so until the shallots are a light golden colour.", "Add the sugar, lime juice, chili powder and salt. Once the sugar has dissolved, toss the asparagus in the pan along with a sprinkling of water to help them steam. Cover and cook for 5-6 minutes until the asparagus is tender.  (The timing may vary depending on the thickness of the spears) you can test with a skewer to check for this)"]'::jsonb, 'https://www.foodista.com/recipe/QNPS8W3V/indian-asparagus-with-ginger-lime', 'https://img.spoonacular.com/recipes/647795-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('autumn-fried-rice-with-buffalo-nuts', 'Autumn Fried Rice with Buffalo Nuts®', 8, 0, 0, '{"calories": 497, "protein": 12.69, "carbs": 71.18, "fat": 17.53, "saturated_fat": 3.07, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 918.9, "potassium": null, "fiber": 2.73, "sugar": 7.23, "vitamin_a": null, "vitamin_c": 5.38, "calcium": 51.34, "iron": 1.52}'::jsonb, ARRAY['chinese', 'asian', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'spoonacular', 'soup'], '[{"quantity": 6.0, "unit": "", "item": "carrots", "notes": "6 carrots diced", "category": "produce"}, {"quantity": 8.0, "unit": "servings", "item": "chicken stock", "notes": "Chicken stock or broth as needed", "category": "canned and jarred"}, {"quantity": 1.5, "unit": "cups", "item": "tropical food''s", "notes": "1 ½ cups Tropical Food''s Buffalo Nuts®", "category": "baking"}, {"quantity": 1.0, "unit": "tbsp", "item": "ginger", "notes": "1 tbsp. fresh ginger, minced", "category": "produce"}, {"quantity": 5.0, "unit": "cloves", "item": "garlic", "notes": "5 cloves of garlic", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ground cinnamon", "notes": "1 teaspoon ground cinnamon", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "ground nutmeg", "notes": "1/4 teaspoon ground nutmeg", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "apples", "notes": "½ cup red apples, diced", "category": "produce"}, {"quantity": 0.33333334, "unit": "cup", "item": "soy sauce", "notes": "1/3 cup soy sauce", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "cup", "item": "squash", "notes": "½ cup yellow squash, diced.", "category": "produce"}, {"quantity": 8.0, "unit": "servings", "item": "vegetable oil", "notes": "Vegetable oil as needed", "category": "oil, vinegar, salad dressing"}, {"quantity": 3.0, "unit": "cups", "item": "rice", "notes": "3 cups white rice", "category": "pasta and rice"}]'::jsonb, '["In a large sauce or frying pan, add enough oil to coat the pan. Turn heat to medium high.", "Add onions and cook for 50 seconds.", "Add garlic and ginger; cook for 30 seconds.Stir mixture so it does not stick and add a very little amount of chicken stock if pan becomes too dry.", "Add carrots, squash, apples, cinnamon, and nutmeg. Cook for 20 seconds and add Buffalo Nuts.", "Mix ingredients in pan and cook for additional 20-30 seconds.", "Add more chicken stock if needed.", "Add rice to the pan and pour the soy sauce on top; mix to combine. Once the soy sauce is absorbed into the rice, turn the heat to low.", "Serve and enjoy."]'::jsonb, 'https://www.foodista.com/recipe/LTPYSJCV/autumn-fried-rice-with-buffalo-nuts', 'https://img.spoonacular.com/recipes/633093-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('easy-vegetable-fried-rice', 'Easy Vegetable Fried Rice', 4, 0, 0, '{"calories": 235, "protein": 7.47, "carbs": 30.2, "fat": 9.64, "saturated_fat": 3.03, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1061.43, "potassium": null, "fiber": 2.79, "sugar": 3.03, "vitamin_a": null, "vitamin_c": 29.5, "calcium": 43.63, "iron": 1.4}'::jsonb, ARRAY['chinese', 'asian', 'side dish', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "broccoli", "notes": "1 cup broccoli", "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "butter", "notes": "1 tbsp butter", "category": "milk, eggs, other dairy"}, {"quantity": 0.33333334, "unit": "cup", "item": "carrots", "notes": "1/3 cup thinly sliced carrots", "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "rice", "notes": "2 cups cooked rice", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": "1 clove garlic, minced", "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "ginger", "notes": "1 tbsp minced ginger", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "green beans", "notes": "½ cup green beans", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "peas", "notes": "½ cup peas", "category": "produce"}, {"quantity": 1.5, "unit": "tbsp", "item": "sesame oil", "notes": "1 ½ tbsp sesame oil", "category": "ethnic foods"}, {"quantity": 4.0, "unit": "servings", "item": "soy sauce", "notes": "soy sauce to taste", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "dash", "item": "sugar", "notes": "dash of sugar", "category": "baking"}]'::jsonb, '["First blanch the raw green vegetables by sticking them in a pot of boiling water for a couple of minutes and then draining them. If you''re using frozen vegetables, follow the package cooking instructions, but stop shy of three minutes of cooking time so they don''t get mushy.In large pan or wok, heat your sesame oil over medium heat. Throw in the garlic and ginger and fry that up for about a minute.", "Add the carrots and stir quickly for a minute or two. Then add the rice.Now add soy sauce based on your saltiness preference.", "Let that sizzle while you whip your egg in a small bowl. Move your rice to the edges of the pan so you have an empty space in the middle.", "Add the egg and scramble it up. When it looks close to being cooked, stir the rice back into the middle of the pan.Next, throw in the broccoli and peas or other blanched vegetables of your choice.", "Add the sugar and stir for a couple minutes, then add the butter. Once the butter is melted through, let the rice sit there.", "Let it sizzle a bit.That''s it!", "Serve your fried rice."]'::jsonb, 'https://www.foodista.com/recipe/H78BYQPP/easy-vegetable-fried-rice', 'https://img.spoonacular.com/recipes/642138-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-cucumber-salad-by-roz', 'Thai Cucumber Salad (By Roz)', 6, 0, 0, '{"calories": 178, "protein": 4.47, "carbs": 16.88, "fat": 11.4, "saturated_fat": 1.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 642.55, "potassium": null, "fiber": 3.01, "sugar": 11.24, "vitamin_a": null, "vitamin_c": 15.85, "calcium": 36.82, "iron": 0.98}'::jsonb, ARRAY['thai', 'asian', 'side dish', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'dessert', 'salad', 'vegetarian'], '[{"quantity": 1.0, "unit": "tablespoon", "item": "cilantro", "notes": "1 tablespoon chopped cilantro", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "cucumbers", "notes": "2 cucumbers, seeded, cubed or sliced (you can also peel them if you like)", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "jalapeno pepper", "notes": "1/2 jalapeno pepper, seeded, and finely chopped", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tablespoons", "item": "lime juice", "notes": "2 tablespoons freshly squeezed lime juice", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "lime zest", "notes": "1 Zest of lime", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "onions", "notes": "1/4 cup red or white onions, chopped", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "pepper flakes", "notes": "Red pepper flakes", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "rice wine vinegar", "notes": "1/2 cup rice wine vinegar", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "cup", "item": "chop roasted peanuts", "notes": "1/2 cup finely chop unsalted dry roasted peanuts (optional)", "category": "nuts"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "coconut & sesame oil", "notes": "2 tablespoons coconut & Sesame Oil or 3 Tbsp Peanut", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tablespoon", "item": "soy sauce", "notes": "1 tablespoon soy sauce", "category": "ethnic foods"}, {"quantity": 0.25, "unit": "cup", "item": "sugar", "notes": "1/4 cup sugar", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "thai garlic chili pepper sauce", "notes": "1 tablespoon Thai garlic chili pepper sauce", "category": "produce"}, {"quantity": 0.25, "unit": "teaspoon", "item": "pepper", "notes": "1/4 teaspoon white pepper", "category": "spices and seasonings"}]'::jsonb, '["Blend all the dressing ingredients together.", "Mix in all of the chopped vegetables, herb, and peanuts (if you want the peanuts).", "Add more of any of the flavors that you prefer, which is the true Thai way.", "Garnish each plate with cilantro leaves and sliced limes.", "Serve with a patter of add-ins:Lime slices, red pepper flakes, chopped cilantro, chopped peanuts, Thai sweet chili sauce, sugar, salt, etc. for your guests to add more of their favorite flavors."]'::jsonb, 'https://www.foodista.com/recipe/KNFYV5H8/thai-cucumber-salad-by-roz', 'https://img.spoonacular.com/recipes/663100-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('kkaetnip-jangajji-korean-pickled-perilla-leaves', 'Kkaetnip Jangajji (Korean Pickled Perilla Leaves)', 10, 0, 0, '{"calories": 37, "protein": 2.82, "carbs": 2.91, "fat": 1.76, "saturated_fat": 0.26, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1323.17, "potassium": null, "fiber": 0.9, "sugar": 0.72, "vitamin_a": null, "vitamin_c": 0.91, "calcium": 15.74, "iron": 0.91}'::jsonb, ARRAY['korean', 'asian', 'side dish', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 2.0, "unit": "", "item": "garlic cloves", "notes": "•2 garlic cloves, finely minced", "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "gochugaru", "notes": "•2 tbsp gochugaru (red pepper flakes)", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "green onions", "notes": "•1, 2 green onions, thinly chopped", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "soy sauce", "notes": "•1 cup soy sauce or light soy sauce", "category": "condiments"}, {"quantity": 0.5, "unit": "small", "item": "onion", "notes": "•1/2 small onion, thinly chopped", "category": "produce"}, {"quantity": 50.0, "unit": "", "item": "perilla leaves", "notes": "•50 perilla leaves (aka kkaetnip)", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tbsp", "item": "rice wine", "notes": "•1 tbsp rice wine", "category": "alcoholic beverages"}, {"quantity": 1.0, "unit": "tbsp", "item": "sesame oil", "notes": "•1 tbsp sesame oil", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tsp", "item": "sesame seeds", "notes": "•1 tsp sesame seeds", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "water", "notes": "•1/4 cup water", "category": "beverages"}]'::jsonb, '["Wash each perilla leaf individually through running water and shake off excess water.", "Place in a colander until dried; set aside for at least 15 minutes.2.In a mixing bowl, combine all the other ingredients together with the finely chopped onion, green onion, and minced garlic. In a tupperware or plastic container, place a spoonful of the sauce on the bottom.", "Add one perilla leaf then put another spoonful of the sauce to coat the leaf. Continue alternating the layers with a perilla leaf and the sauce until stacks are formed side by side.3.Continue lathering the leaves one at a time until each one is covered with the sauce. If you run out of sauce, it will collect at the bottom of the tupperware. Reuse any runoff sauce to complete the process4.Store in the refrigerator for at least a few days. When ready, serve as a side dish (banchan) with the main dish.*This particular side dish (along with regular gim, seaweed) is perfect with a bowl of rice. Many Koreans (with chopsticks in hand) simply wrap a single leaf around some rice and indulge in its deliciousness. The salty and sour perilla leaves with the sticky rice really go great together."]'::jsonb, 'https://www.foodista.com/recipe/LLZNLLR4/kkaetnip-jangajji-korean-pickled-perilla-leaves', 'https://img.spoonacular.com/recipes/648975-312x231.jpg', FALSE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
