y the salad as a side with or whatever you  prefer."]'::jsonb, 'https://www.foodista.com/recipe/TJDQTCKK/carrot-cucumber-salad-asian-style', 'https://img.spoonacular.com/recipes/637194-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-savory-brown-fried-rice', 'Thai Savory Brown Fried Rice', 4, 0, 0, '{"calories": 641, "protein": 13.53, "carbs": 60.63, "fat": 41.46, "saturated_fat": 20.41, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 58.85, "potassium": null, "fiber": 10.07, "sugar": 7.03, "vitamin_a": null, "vitamin_c": 35.81, "calcium": 130.08, "iron": 5.23}'::jsonb, ARRAY['chinese', 'asian', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "extra virgin olive oil", "notes": "2 tablespoons extra virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "", "item": "garlic cloves", "notes": "4 garlic cloves, minced", "category": "produce"}, {"quantity": 2.0, "unit": "small", "item": "chili peppers", "notes": "2 smalls fresh red chili peppers, seeded and finely chopped﻿", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "cup", "item": "cashew nuts", "notes": "1 cup raw cashew nuts", "category": "nuts"}, {"quantity": 1.25, "unit": "cups", "item": "coconut", "notes": "1 1/4 cups dry unsweetened shredded coconut, lightly toasted", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "stevia powder", "notes": "1/2 teaspoon stevia powder (or sweetener)", "category": "baking"}, {"quantity": 4.0, "unit": "tablespoons", "item": "bragg liquid aminos", "notes": "4 tablespoons Nama Shoyu (soy sauce) or Bragg liquid Aminos", "category": "condiments"}, {"quantity": 2.0, "unit": "tablespoons", "item": "apple cider vinegar", "notes": "2 tablespoons apple cider vinegar (or rice vinegar)", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "", "item": "flax egg", "notes": "1 flax egg (made with 1 Tbsp. ground flax seed& 3 Tbsp. wa", "category": "health foods"}, {"quantity": 2.5, "unit": "cups", "item": "green beans", "notes": "2 1/2 cups fresh green beans, cut in half", "category": "produce"}, {"quantity": 8.0, "unit": "ounces", "item": "regular bok choy", "notes": "8 ounces baby bok choy or regular bok choy (shredded", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "brown rice", "notes": "1 cup uncooked brown rice (make recipe below)", "category": "pasta and rice"}, {"quantity": 4.0, "unit": "servings", "item": "lime wedges", "notes": "lime wedges for serving", "category": "produce"}]'::jsonb, '["Make my Perfect Brown Rice recipe below.  While brown", "rice is cooking prepare rest of meal.", "PERFECT BROWN RICE", "cup uncooked brown rice", "tsp. olive oil", "cups filtered water", "basil leaves (optional)", "Fix brown rice by cooking in 1 tsp. olive oil until lightly browned.", "Place 2 basil leaves on top of rice and add 2 cups water all at once. Quickly put on lid and bring to boil. Turn down heat to simmer until all water has evaporated (around 40 minutes).", "Heat oil in a wok or large frying pan.", "Add the garlic and cook on medium until lightly golden.  Watch carefully so you do not burn garlic.", "Add the red chili peppers, cashew nuts and toasted coconut.", "Mix together stevia, Nama Shoyu and apple cider vinegar together.  Cook over medium heat for 1 minutes.", "Push stir-fry to one side of pan and add flax on opposite end.  Cook and stir the flax egg for about a minute and then incorporate into stir-fry mixture.", "Add the green beans, bok choy and brown rice to stir-fry.  Cook and stir on medium for another minute.  Bok Choy will be wilted, but green beans will still be a bit crunchy.", "Spoon into serving dish and add lime wedge on side for squeezing over rice."]'::jsonb, 'https://www.foodista.com/recipe/7C3JZV44/thai-savory-brown-fried-rice', 'https://img.spoonacular.com/recipes/663150-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
