il", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.5, "unit": "cups", "item": "onions", "notes": "1.5 cups chopped onions", "category": "produce"}, {"quantity": 250.0, "unit": "grams", "item": "paneer / indian cottage cheese", "notes": "250 grams paneer / indian cottage cheese", "category": "ethnic foods"}, {"quantity": 1.5, "unit": "cups", "item": "tomatoes", "notes": "1.5 cups chopped tomatoes", "category": "produce"}, {"quantity": 1.0, "unit": "pinch", "item": "turmeric", "notes": "Generous pinch of turmeric", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "", "item": "to", "notes": "½ to ¾ tsp. red chilli powder", "category": "spices and seasonings"}]'::jsonb, '["step by step instructions at indianhealthyrecipes.com"]'::jsonb, 'https://spoonacular.com/-1417489228874', 'https://img.spoonacular.com/recipes/621204-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
