"category": "nut butters, jams, and honey"}, {"quantity": 2.0, "unit": "teaspoons", "item": "sesame oil", "notes": "2 teaspoons toasted sesame oil", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "cup", "item": "canola oil", "notes": "1/2 cup canola oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and freshly ground pepper", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "salad", "notes": "Salad", "category": "produce"}, {"quantity": 0.5, "unit": "head", "item": "napa cabbage", "notes": "1/2 head Napa cabbage, shredded", "category": "produce"}, {"quantity": 0.5, "unit": "head", "item": "romaine lettuce", "notes": "1/2 head romaine lettuce, shredded", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "carrots", "notes": "2 carrots, shredded", "category": "produce"}, {"quantity": 0.25, "unit": "pound", "item": "snow peas", "notes": "1/4 pound snow peas, julienned", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "cilantro leaves", "notes": "1/4 cup coarsely chopped fresh cilantro leaves", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "green onion", "notes": "1/4 cup thinly sliced green onion", "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "rotisserie chicken", "notes": "2 cups shredded rotisserie chicken", "category": "meat"}, {"quantity": 0.5, "unit": "cup", "item": "roasted peanuts", "notes": "1/2 cup chopped roasted peanuts", "category": "nuts"}, {"quantity": 0.25, "unit": "cup", "item": "mint leaves", "notes": "1/4 cup chopped fresh mint leaves", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "chili oil", "notes": "Chili oil, optional", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "halves", "item": "lime", "notes": "lime halves, for garnish", "category": "produce"}]'::jsonb, '["Whisk together the vinegar, peanut & almond butters, ginger, chipotle pepper puree, soy sauce, honey, sesame oil, and canola oil in a medium bowl. Season with salt and pepper, to taste.", "Combine cabbage, lettuce, carrots, snow peas, cilantro, and green onion in a large bowl.", "Add the dressing and toss to combine.", "Transfer to a serving platter and top with the shredded chicken, chopped peanuts, and mint.", "Drizzle with chili oil, if desired.", "Garnish with lime halves."]'::jsonb, 'https://www.foodista.com/recipe/JHBGMT48/bobby-flays-chinese-chicken-salad-with-chile-pea-mond-dressing', 'https://img.spoonacular.com/recipes/638642-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
