": "servings", "item": "salt and pepper", "notes": "Salt and pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "soy sauce", "notes": "2 tablespoons soy sauce", "category": "ethnic foods"}, {"quantity": 6.0, "unit": "ounces", "item": "spaghetti", "notes": "6 ounces whole wheat spaghetti", "category": "pasta and rice"}]'::jsonb, '["Cook pasta according to package instructions. During the last minute, add in the broccoli.In the meantime, you can cook the vegetables and prepare the dressing.", "Heat olive oil in small non-stick skillet, saut onions until slightly soften.", "Add in garlic and continue to saut until fragrant. add in sweet peppers and cook until slightly softened.", "Remove from heat, add in remaining ingredients to finish making the sauce.", "Add salt and pepper to taste.When the pasta and broccoli is ready, add them to the skillet and stir well. Stir in cilantro leaves.", "Served at room temperature or chilled."]'::jsonb, 'https://www.foodista.com/recipe/JTBZ3CHD/thai-pasta-salad', 'https://img.spoonacular.com/recipes/663126-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
