"teaspoon", "item": "sambal oelek", "notes": "1 teaspoon Sambal Oelek", "category": "?"}]'::jsonb, '["In nonstick skillet, add oil and saut beef over medium-high heat for 3-4 min.", "Add red onions, garlic, saut for about 4 minutes.", "Add fresh ginger, sambal oelek, curry powder; cook, stirring, until fragrant, about 45 seconds.", "Add soy sauce, lime juice and peanuts.  Saut another 30 seconds.", "Server over rice noodles."]'::jsonb, 'https://www.foodista.com/recipe/PXR8MYRD/curry-beef-over-rice-noodles', 'https://img.spoonacular.com/recipes/641111-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
