["Whisk mayonnaise, soy sauce and ginger together in a large bowl until blended.", "Add chicken, snow peas, peppers, carrots and green onion; toss to mix and coat.", "Serve over torn spinach leaves."]'::jsonb, 'https://www.foodista.com/recipe/BPHS2ZXF/chinese-chicken-salad-with-creamy-soy-dressing', 'https://img.spoonacular.com/recipes/638649-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-tofu-with-bok-choy', 'Thai Tofu With Bok Choy', 4, 0, 0, '{"calories": 175, "protein": 11.16, "carbs": 14.62, "fat": 9.16, "saturated_fat": 1.32, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1437.81, "potassium": null, "fiber": 3.21, "sugar": 7.32, "vitamin_a": null, "vitamin_c": 96.82, "calcium": 267.65, "iron": 3.1}'::jsonb, ARRAY['thai', 'asian', 'side dish', 'gluten free', 'dairy free', 'pescatarian', 'spoonacular', 'dessert'], '[{"quantity": 1.0, "unit": "large head", "item": "bok choy", "notes": "1 large head bok choy, chopped", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "brown sugar", "notes": "2 teaspoons brown sugar", "category": "baking"}, {"quantity": 1.0, "unit": "c", "item": "carrots", "notes": "1 c. julienned carrots", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "chili paste", "notes": "2 teaspoons hot chili paste (depending on how spicy you prefer your dish- start with 1 tsp and taste test it)", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "teaspoon", "item": "corn starch", "notes": "1 teaspoon corn starch dissolved in 1 tablespoon cold water", "category": "baking"}, {"quantity": 12.0, "unit": "ounce", "item": "block extra tofu", "notes": "1 12 ounce block extra firm tofu, drained and pressed to remove water", "category": "refrigerated"}, {"quantity": 1.0, "unit": "T", "item": "fish sauce", "notes": "1 T. fish sauce", "category": "ethnic foods"}, {"quantity": 3.0, "unit": "tablespoons", "item": "oyster sauce", "notes": "3 tablespoons oyster sauce", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "tablespoons", "item": "sesame oil", "notes": "2 tablespoons Sesame oil", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "tablespoons", "item": "soy sauce", "notes": "2 tablespoons soy sauce", "category": "ethnic foods"}]'::jsonb, '["Cut the tofu into 1\" cubes.", "Whisk together sauce ingredients (soy sauce, oyster sauce, fish sauce, brown sugar, and chili paste). Set aside.", "Heat 2 tsp sesame oil over medium-high heat in a large wok or pan. When the pan is hot, add the tofu and let cook for 2 minutes on one side, undisturbed, until they develop a crisp crust. Flip and cook 2 minutes more.", "Remove the tofu to a plate. Return pan to the heat.", "Add remaining 1 tsp sesame oil to the pan along with the carrots.", "Saute for 3 minutes, until the carrots begin to soften.", "Add the bok choy and saute for 2 minutes, until it begins to soften and wilt.Stir in the sauce.Return the tofu to the pan and stir in the corn starch mixture. Allow the sauce to come to a boil for it to thicken. Stir.", "Serve with rice."]'::jsonb, 'https://www.foodista.com/recipe/DJXLVF5B/thai-tofu-with-bok-choy', 'https://img.spoonacular.com/recipes/663166-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-green-mango-salad', 'Thai Green Mango Salad', 6, 0, 0, '{"calories": 132, "protein": 4.33, "carbs": 24.93, "fat": 3.86, "saturated_fat": 0.61, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 132.19, "potassium": null, "fiber": 4.51, "sugar": 15.75, "vitamin_a": null, "vitamin_c": 69.64, "calcium": 48.09, "iron": 0.96}'::jsonb, ARRAY['thai', 'asian', 'side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'primal', 'pescatarian', 'spoonacular', 'dessert'], '[{"quantity": 6.0, "unit": "servings", "item": "fish sauce", "notes": "Fish sauce, to taste", "category": "ethnic foods"}, {"quantity": 6.0, "unit": "servings", "item": "thai palm sugar", "notes": "Thai palm sugar, to taste", "category": "baking"}, {"quantity": 4.0, "unit": "", "item": "limes", "notes": "4 limes", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "to 3 chilli padis", "notes": "2 to 3 chilli padis", "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": "1 clove of garlic, mashed", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "shallots", "notes": "2 shallots, mashed", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "shrimps", "notes": "1 tablespoon of dried shrimps, washed", "category": "seafood"}, {"quantity": 1.0, "unit": "", "item": "tomato", "notes": "1 tomato, cut into wedges", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "carrot", "notes": "1 cup carrot, shredded", "category": "produce"}, {"quantity": 3.0, "unit": "cups", "item": "mangoes", "notes": "3 cups raw green mangoes, shredded", "category": "produce"}, {"quantity": 2.0, "unit": "inches", "item": "long beans", "notes": "2 inches long beans cut into 1 pieces", "category": "produce"}, {"quantity": 4.0, "unit": "tablespoons", "item": "roasted coarse peanuts", "notes": "4 tablespoons roasted coarse peanuts", "category": "nuts"}]'::jsonb, '["Pound all the ingredients in a clay mortar using a wooden pestle, then add carrot and mangoes.", "Serve chilled with roasted coarse peanuts."]'::jsonb, 'https://www.foodista.com/recipe/JRRRFDVQ/thai-green-mango-salad', 'https://img.spoonacular.com/recipes/663113-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('asian-noodles', 'Asian Noodles', 4, 0, 0, '{"calories": 549, "protein": 18.09, "carbs": 79.79, "fat": 18.42, "saturated_fat": 3.52, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 150.57, "potassium": null, "fiber": 7.68, "sugar": 9.83, "vitamin_a": null, "vitamin_c": 76.76, "calcium": 80.67, "iron": 4.36}'::jsonb, ARRAY['asian', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'pasta', 'vegetarian'], '[{"quantity": 2.0, "unit": "medium", "item": "carrots", "notes": "2 mediums carrots julienned", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "cashews", "notes": "1/2 cup cashews (optional)", "category": "nuts"}, {"quantity": 12.0, "unit": "ounces", "item": "egg noodles", "notes": "12 ounces dry egg noodles", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "teaspoons", "item": "ginger", "notes": "2 teaspoons minced fresh ginger", "category": "produce"}, {"quantity": 4.0, "unit": "ounces", "item": "shiitake mushrooms", "notes": "4 ounces fresh shiitake mushrooms stemmed, sliced", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "garlic clove", "notes": "1 garlic clove minced", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "chile pepper", "notes": "1 green chile pepper seeded, minced", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "hoisin sauce", "notes": "1 tablespoon hoisin sauce", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "tablespoons", "item": "peanut oil", "notes": "2 tablespoons peanut oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "medium", "item": "bell pepper", "notes": "1 medium red bell pepper julienned", "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "rice wine vinegar", "notes": "3 tablespoons rice wine vinegar", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "", "item": "scallions", "notes": "2 scallions, white and light green parts sliced", "category": "produce"}, {"quantity": 8.0, "unit": "ounces", "item": "snow peas", "notes": "8 ounces snow peas", "category": "produce"}]'::jsonb, '["Cook noodles according to package directions; drain well.Blanch snow peas in boiling water 1 minute.", "Drain and refresh in cold water, then pat dry.", "Transfer to medium bowl.", "Add carrots and scallions.In medium skillet, heat oil over medium heat.", "Add garlic and chile pepper and cook, stirring often, 30 seconds.", "Add mushrooms and cook, stirring often, 2 minutes.", "Add mushrooms to bowl with vegetables.", "Add vinegar, ginger and hoisin sauce to pan and warm through.", "Pour over vegetables.", "Add noodles and toss.", "Serve warm or at room temperature.This recipe yields 4 servings.Comments: Once the vegetables have been sliced, this tasty main dish salad can be thrown together in minutes.", "Serve these noodles with a packaged miso soup mix."]'::jsonb, 'https://www.foodista.com/recipe/Z3NDBPTS/asian-noodles', 'https://img.spoonacular.com/recipes/632854-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-veggie-slaw-with-peanut-dressing-and-crispy-wontons', 'Thai Veggie Slaw with Peanut Dressing and Crispy Wontons', 6, 0, 0, '{"calories": 419, "protein": 10.67, "carbs": 29.07, "fat": 31.45, "saturated_fat": 3.36, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 386.74, "potassium": null, "fiber": 6.56, "sugar": 9.07, "vitamin_a": null, "vitamin_c": 100.37, "calcium": 121.8, "iron": 2.75}'::jsonb, ARRAY['chinese', 'asian', 'side dish', 'dairy free', 'pescatarian', 'spoonacular', 'dessert', 'salad', 'baking'], '[{"quantity": 12.0, "unit": "square", "item": "wonton wrappers", "notes": "12 square wonton wrappers", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "t", "item": "five spice", "notes": "1/2 t. Chinese five spice", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "pinch", "item": "cayenne", "notes": "pinch of cayenne", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "c", "item": "dry-roasted peanuts", "notes": "1 c. dry-roasted unsalted peanuts, divided", "category": "nuts"}, {"quantity": 0.5, "unit": "c", "item": "canola oil", "notes": "1/2 c. canola oil, divided", "category": "oil, vinegar, salad dressing"}, {"quantity": 3.0, "unit": "T", "item": "lime juice", "notes": "3 T. fresh lime juice", "category": "produce"}, {"quantity": 1.0, "unit": "T", "item": "fish sauce", "notes": "1 T. fish sauce", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "t", "item": "brown sugar", "notes": "2 t. light brown sugar", "category": "baking"}, {"quantity": 1.0, "unit": "t", "item": "sriracha", "notes": "1 t. sriracha", "category": "condiments"}, {"quantity": 0.5, "unit": "t", "item": "ginger", "notes": "1/2 t. finely minced ginger", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "garlic clove", "notes": "1 garlic clove, finely minced", "category": "produce"}, {"quantity": 3.0, "unit": "c", "item": "napa cabbage", "notes": "1 small head of napa cabbage, shredded (about 3 c.)", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "a head of cabbage", "notes": "1/2 a small head of red cabbage", "category": "produce"}, {"quantity": 6.0, "unit": "oz", "item": "snow peas", "notes": "6 oz. snow peas, trimmed, sliced on the diagonal about 1/2-inch thick", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 bell pepper, thinly sliced", "category": "produce"}, {"quantity": 1.0, "unit": "c", "item": "carrots", "notes": "1 c. julienned carrots", "category": "produce"}, {"quantity": 1.0, "unit": "c", "item": "scallion", "notes": "1 c. thinly sliced scallion", "category": "produce"}, {"quantity": 0.5, "unit": "c", "item": "cilantro leaves", "notes": "1/2 c. cilantro leaves", "category": "spices and seasonings"}]'::jsonb, '["Make the crispy wontons: Preheat oven to 375 degrees f.", "Lay the wontons out on a large baking sheet. Spray lightly with cooking spray and sprinkle with the Chinese five spice and cayenne. Flip the wontons over and repeat. Stack all the wonton skins on top of each other and slice into 1/2-3/4-inch strips.", "Spread the strips in an even layer back onto the baking sheet.", "Bake 10-12 minutes, until crisp and golden brown, flipping the strips halfway through and rotating the baking sheet. (Watch carefully that they don''t burn)", "Remove from the oven and let cool before using.", "Prepare the dressing: In the jar of a blender, add 1/2 c. peanuts and 2 T. canola oil. Blend until completely smooth, about a minute, scraping down the sides of the blender jar as necessary.", "Add in the remaining canola oil, lime juice, fish sauce, brown sugar, sriracha, ginger and garlic. Blend until smooth.", "In a large bowl combine all the vegetables.", "Add the dressing and the remaining 1/2 c. peanuts. Toss well to combine. You can either mix the wontons into the salad, or reserve them for crumbling onto individual portions."]'::jsonb, 'https://www.foodista.com/recipe/MYMKCDHF/thai-veggie-slaw-with-peanut-dressing-and-crispy-wontons', 'https://img.spoonacular.com/recipes/663169-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('green-mango-salad-thai-side-dish', 'Green Mango Salad - Thai Side Dish', 2, 0, 0, '{"calories": 213, "protein": 5.85, "carbs": 50.66, "fat": 1.39, "saturated_fat": 0.26, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2141.03, "potassium": null, "fiber": 6.59, "sugar": 42.96, "vitamin_a": null, "vitamin_c": 163.99, "calcium": 71.16, "iron": 1.72}'::jsonb, ARRAY['thai', 'asian', 'side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'pescatarian', 'spoonacular', 'dessert'], '[{"quantity": 2.0, "unit": "", "item": "chilies", "notes": "2 chilies", "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "fish sauce", "notes": "3 tablespoons fish sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "", "item": "juice of lime", "notes": "1 whole lime, juiced", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "lettuce", "notes": "lettuce", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "mango.", "notes": "2 whole green mango. peeled and julienned", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "sugar", "notes": "1 tablespoon sugar", "category": "baking"}, {"quantity": 2.0, "unit": "", "item": "wholes tomatoes", "notes": "2 wholes tomatoes, diced", "category": "produce"}]'::jsonb, '["Julianne the green mango and diced the tomato", "Mix and place in the bowl Roughly pound chilli and garlic and add the fish sauce Season with sugar to balance the taste", "Add lime juice for the final touch", "Pour the dressing in bowl of mix green mango and tomato, fold gently", "Place on the bed of your favourite lettuce and serve"]'::jsonb, 'https://www.foodista.com/recipe/GJ88XL27/green-mango-salad', 'https://img.spoonacular.com/recipes/645474-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('thai-sausage-salad', 'Thai Sausage Salad', 2, 0, 0, '{"calories": 990, "protein": 46.19, "carbs": 47.05, "fat": 68.63, "saturated_fat": 22.57, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 3219.26, "potassium": null, "fiber": 4.45, "sugar": 15.52, "vitamin_a": null, "vitamin_c": 72.83, "calcium": 114.44, "iron": 4.94}'::jsonb, ARRAY['thai', 'asian', 'side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'dessert'], '[{"quantity": 6.0, "unit": "", "item": "sausages", "notes": "6 Chinese sausages", "category": "meat"}, {"quantity": 2.0, "unit": "large", "item": "cucumbers", "notes": "2 large cucumbers", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "bean sprouts", "notes": "1 cup fresh bean sprouts", "category": "ethnic foods"}, {"quantity": 4.0, "unit": "", "item": "green onions", "notes": "4 green onions", "category": "produce"}, {"quantity": 1.0, "unit": "leaf", "item": "cilantro leaves", "notes": "Fresh flat leaf parsley or cilantro leaves for garnish", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "chili pepper", "notes": "1 thinly sliced hot, fresh red chili pepper (optional)", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "jasmine rice", "notes": "Cooked jasmine rice", "category": "pasta and rice"}, {"quantity": 0.5, "unit": "cup", "item": "lime juice", "notes": "1/2 cup fresh lime juice", "category": "produce"}, {"quantity": 3.0, "unit": "teaspoons", "item": "granulated sugar", "notes": "3 teaspoons granulated sugar", "category": "baking"}, {"quantity": 2.0, "unit": "tablespoons", "item": "thai fish sauce", "notes": "2 tablespoons Thai fish sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "teaspoon", "item": "soy sauce", "notes": "1 teaspoon soy sauce", "category": "ethnic foods"}]'::jsonb, '["In a small bowl, combine the dressing ingredients and stir until the sugar has dissolved. Taste and adjust with more sugar or fish sauce if needed (some limes are more tart than others). Set aside.", "Slice the sausage thinly on the diagonal.", "Place in a non stick skillet over medium heat and saut until the edges are slightly browned and sausage is cooked thru, about 5 minutes. Dont over cook. Set aside to cool", "Peel the cucumbers, slice thinly and place in a large bowl. Thinly slice the green onions on the diagonal and add to the bowl.", "Add the bean sprouts, cooked sausage and the dressing. Lightly toss and serve on plates with jasmine rice on the same plate.", "Garnish with a few slivers of sliced hot chili pepper, if desired, and a few leaves of fresh parsley or cilantro.", "Serves 2 as a main course salad."]'::jsonb, 'https://www.foodista.com/recipe/L22RPP5R/thai-sausage-salad', 'https://img.spoonacular.com/recipes/663149-312x231.jpg', FALSE, 1, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('soba-noodle-in-kombu-dashi-with-teriyaki-salmon', 'Soba Noodle In Kombu Dashi With Teriyaki Salmon', 2, 0, 0, '{"calories": 366, "protein": 35.21, "carbs": 12.35, "fat": 18.16, "saturated_fat": 2.79, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 683.46, "potassium": null, "fiber": 0.3, "sugar": 8.68, "vitamin_a": null, "vitamin_c": 0, "calcium": 46.12, "iron": 1.86}'::jsonb, ARRAY['japanese', 'asian', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'pescatarian', 'spoonacular', 'dessert'], '[{"quantity": 2.0, "unit": "servings", "item": "salmon filet/loin", "notes": "Salmon filet/loin, 250-300g", "category": "seafood"}, {"quantity": 1.0, "unit": "tablespoon", "item": "sake", "notes": "tablespoon Sake, 1", "category": "alcoholic beverages"}, {"quantity": 1.0, "unit": "tablespoon", "item": "soya sauce", "notes": "tablespoon Soya sauce, 4", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tablespoon", "item": "mirin", "notes": "tablespoon Mirin, 4", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tablespoon", "item": "sugar", "notes": "tablespoon Sugar, 2", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "vegetable oil", "notes": "tablespoon Vegetable oil, 1", "category": "oil, vinegar, salad dressing"}, {"quantity": 500.0, "unit": "ml", "item": "water", "notes": "Water, 500ml", "category": "beverages"}, {"quantity": 7.0, "unit": "g", "item": "kombu", "notes": "Dried kombu (seaweed/kelp), 7g", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "", "item": "soba", "notes": "Soba, 2 rolls", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "servings", "item": "goji berries", "notes": "Goji berries, some", "category": "health foods"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sesame seeds", "notes": "teaspoon Sesame seeds, 1-2", "category": "spices and seasonings"}]'::jsonb, '["To make kombu dashi, soak the dried kelp/seaweed in water for 2 hours.", "Put the kombu and water in a cooking pot. Put on medium heat. Turn off the heat when the water comes to a boil. Then, remove the kombu with a strainer. The remaining liquid is your kombu dashi. You can leave some kombu in the soup.", "Cook the soba noodles according to the packet.", "Drain and set aside.", "To make teriyaki salmon, marinate salmon filet/loin with sake, soya sauce, mirin, and sugar.", "Heat up a pan with oil.", "Put the skin side down and cook for 3 minutes or until crispy. Turn and cook the other side for another 2-3 minutes.", "Pour any remaining sauce.", "Remove from heat.", "Drizzle any remaining sauce from the frying pan.", "To serve the soba, heat up the broth. In a bowl, serve good portion of Soba noodles. Lardle good amount of kombu dashi over the noodles.", "Garnish with goji berries if desired.", "Place the teriyaki salmon on top of the noodles.", "Sprinkle with some toasted sesame seeds."]'::jsonb, 'https://www.foodista.com/recipe/W7PR76HM/soba-noodle-in-kombu-dashi-with-teriyaki-salmon', 'https://img.spoonacular.com/recipes/660493-312x231.jpg', TRUE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('healthier-pork-fried-rice', 'Healthier Pork Fried Rice', 3, 0, 0, '{"calories": 522, "protein": 27.75, "carbs": 75.03, "fat": 12.43, "saturated_fat": 3.06, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 3495.29, "potassium": null, "fiber": 5.33, "sugar": 5.82, "vitamin_a": null, "vitamin_c": 12.25, "calcium": 119.62, "iron": 4.12}'::jsonb, ARRAY['chinese', 'asian', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'baking', 'grilling'], '[{"quantity": 1.0, "unit": "cup", "item": "rice", "notes": "1 cup long grain rice ( you can use brown rice as well)", "category": "pasta and rice"}, {"quantity": 2.25, "unit": "inch", "item": "ginger", "notes": "2 1/4 inch slices of ginger", "category": "produce"}, {"quantity": 6.0, "unit": "oz", "item": "pork tenderloin", "notes": "6 oz pork tenderloin", "category": "meat"}, {"quantity": 1.0, "unit": "TBSP", "item": "garlic powder", "notes": "1 TBSP Garlic Powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "TBSP", "item": "onion powder", "notes": "1 TBSP Onion Powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "TBSP", "item": "ground ginger", "notes": "1 TBSP Ground Ginger", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "TBSP", "item": "ground pepper", "notes": "1 TBSP Ground Pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "TBSP", "item": "salt", "notes": "1 TBSP Salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "TBSP", "item": "olive oil", "notes": "1 TBSP Olive Oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "", "item": "garlic cloves", "notes": "4 Garlic Cloves, minced", "category": "produce"}, {"quantity": 3.0, "unit": "TBSP", "item": "ginger", "notes": "3 TBSP Ginger, minced", "category": "produce"}, {"quantity": 6.0, "unit": "", "item": "green onion", "notes": "6 Green Onion, thinly sliced", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "peas and carrots", "notes": "1 cup frozen peas and carrots, thawed", "category": "frozen"}, {"quantity": 3.0, "unit": "", "item": "eggs", "notes": "3 eggs, beaten", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "TBSP", "item": "soy sauce", "notes": "4 TBSP Low Sodium Soy Sauce", "category": "condiments"}, {"quantity": 3.0, "unit": "TBSP", "item": "hoisin", "notes": "3 TBSP Hoisin", "category": "ethnic foods"}]'::jsonb, '["Place 1 cup of rice, 2 cups of water ( or whatever the rice directions say) and the ginger slices in a medium pot. Bring to a boil, cover and them reduce heat to low. Simmer until rice is tender, about 20 minutes. Once done, take ginger slices out of pan.", "Prepare pork: Meanwhile, preheat oven to 350 degrees Fahrenheit and a grill pan ( or grill) to high heat). Slice pork tenderloin into 1/2 inch strips and season strips with, garlic, onion, ginger, pepper and salt on both sides. Once the grill pan is hot, add the pork. Cook 3 minutes per side to get some good grill marks. Once done.", "Place on baking sheet and in over for 2 minutes. Take out of oven set aside and let rest.", "In a frying pan or large pan on medium high heat, add olive oil. Once oil is hot, add garlic, ginger and green onion, cooking until onion is tender, about 1 minute ( make sure to stir garlic so it does not burn).", "Add peas and carrots, stir and cook until vegetables are tender about 3 minutes.", "Add eggs over veggies and stir till scrambled, about 1 minute.", "Add rice to pan. Gently fold rice in.", "Remove from heat.", "Add Pork, soy sauce and hoisin ( you may want to add more later, but go slow, it gets very strong quickly). Gently stir together till all rice is coated in sauce.", "Serve and enjoy!"]'::jsonb, 'https://www.foodista.com/recipe/KY4LQ345/healthier-pork-fried-rice', 'https://img.spoonacular.com/recipes/646425-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vietnamese-noodle-salad-with-tofu', 'Vietnamese Noodle Salad With Tofu', 2, 0, 0, '{"calories": 816, "protein": 26.78, "carbs": 92.18, "fat": 39.72, "saturated_fat": 5.69, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2394.93, "potassium": null, "fiber": 9.26, "sugar": 32.65, "vitamin_a": null, "vitamin_c": 121.77, "calcium": 233.39, "iron": 5.42}'::jsonb, ARRAY['vietnamese', 'asian', 'side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'dairy free', 'pescatarian', 'spoonacular', 'dessert', 'pasta'], '[{"quantity": 1.0, "unit": "cup", "item": "broccoli florets", "notes": "200 grams (1 cup) Broccoli florets", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "cane sugar", "notes": "50 grams (1/4 cup) Cane sugar", "category": "baking"}, {"quantity": 1.0, "unit": "", "item": "carrot", "notes": "1 Carrot", "category": "produce"}, {"quantity": 0.25, "unit": "", "item": "cucumber", "notes": "1/4 Cucumber", "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "fish sauce", "notes": "3 tablespoons Fish sauce", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "", "item": "garlic gloves", "notes": "2 Garlic gloves", "category": "produce"}, {"quantity": 4.0, "unit": "", "item": "centimeters ginger", "notes": "4 centimeters (1.5 inches) Ginger", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "handfull herbs", "notes": "1 Large handfull mixed herbs (coriander, mint, thai basil)", "category": "produce"}, {"quantity": 3.0, "unit": "", "item": "iceberg leaves", "notes": "3 Large Iceberg leaves", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "juice of lime", "notes": "1 Lime (juice)", "category": "produce"}, {"quantity": 0.33333334, "unit": "cup", "item": "peanuts", "notes": "50 grams (1/3 cup) Peanuts", "category": "nuts"}, {"quantity": 0.5, "unit": "", "item": "bell pepper", "notes": "1/2 Red pepper", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "chili", "notes": "1 Red chili", "category": "produce"}, {"quantity": 100.0, "unit": "grams", "item": "rice noodles", "notes": "100 grams Rice noodles", "category": "gluten free"}, {"quantity": 5.0, "unit": "tablespoons", "item": "rice vinegar", "notes": "5 tablespoons Rice vinegar", "category": "ethnic foods"}, {"quantity": 3.0, "unit": "tablespoons", "item": "sesame oil", "notes": "3 tablespoons Sesame oil", "category": "ethnic foods"}, {"quantity": 4.0, "unit": "tablespoons", "item": "soya", "notes": "4 tablespoons Soya", "category": "frozen"}, {"quantity": 1.0, "unit": "", "item": "spring onion", "notes": "1 Spring onion", "category": "produce"}, {"quantity": 7.0, "unit": "ounces", "item": "tofu", "notes": "200 grams (7 ounces) Tofu", "category": "refrigerated"}, {"quantity": 0.5, "unit": "cup", "item": "water", "notes": "1 deciliter ( - 1/2 cup) Water", "category": "beverages"}]'::jsonb, '["The tofu: Slice up the tofu (3/4 cm thick slices) and marinade it over night (or at least for 2 hours) in soya, sesame oil, and sliced garlic gloves.The marinade: Finely chop chili, ginger, and garlic.", "Heat up a large pan and fry the marinated tofu at medium heat untill golden brown. In a dish, pour boiled water over the broccoli florets and leave for 5 minutes before draining off excess water. Prepare the noodles according to the manufacturer. Finely chop the spring onion and remove the inner watery part of the cucumber. Slice up the carrot, cucumber, red pepper, and iceberg into fine screds and roughly chop both herbs and peanuts.Arrange in two large bowls. First iceberg, then noodles, vegetables, tofu, herbs, peanuts and marinade."]'::jsonb, 'https://www.foodista.com/recipe/NXYGJ2H6/vietnamese-noodle-salad-with-tofu', 'https://img.spoonacular.com/recipes/664835-312x231.jpg', FALSE, 2, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('red-curry-stew-vegetable-noodles', 'Red Curry Stew & Vegetable Noodles', 6, 0, 0, '{"calories": 253, "protein": 10.07, "carbs": 28.44, "fat": 11.48, "saturated_fat": 5.42, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1778.53, "potassium": null, "fiber": 5.74, "sugar": 8.7, "vitamin_a": null, "vitamin_c": 61.29, "calcium": 156.03, "iron": 2.26}'::jsonb, ARRAY['indian', 'asian', 'side dish', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'pescatarian', 'spoonacular', 'soup'], '[{"quantity": 8.0, "unit": "large", "item": "basil leaves", "notes": "8 large basil leaves, chopped", "category": "produce"}, {"quantity": 0.5, "unit": "head", "item": "cabbage", "notes": "1/2 head cabbage, chopped", "category": "produce"}, {"quantity": 2.0, "unit": "large", "item": "carrots", "notes": "2 large carrots, peeled", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "fish sauce", "notes": "2 tablespoons fish sauce", "category": "ethnic foods"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves of garlic (depending on what you like)", "category": "produce"}, {"quantity": 1.0, "unit": "inch", "item": "ginger", "notes": "1 inch piece of ginger, peeled and sliced", "category": "produce"}, {"quantity": 14.0, "unit": "ounces", "item": "coconut milk", "notes": "14 ounces can of light (or lite) coconut milk", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tablespoons", "item": "lime juice", "notes": "2 tablespoons lime juice", "category": "produce"}, {"quantity": 1.5, "unit": "Tbs", "item": "olive oil", "notes": "1 1/2 Tbs olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "large", "item": "potato", "notes": "1 large potato, peeled and diced", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "curry paste", "notes": "1 tablespoon heaping of red curry paste", "category": "ethnic foods"}, {"quantity": 0.33333334, "unit": "large", "item": "onion", "notes": "1/3 large red onion, chopped", "category": "produce"}, {"quantity": 1.5, "unit": "teaspoons", "item": "sea salt", "notes": "1 1/2 teaspoons sea salt", "category": "spices and seasonings"}, {"quantity": 14.0, "unit": "ounce", "item": "tofu", "notes": "1 14-ounce package of firm tofu", "category": "produce"}, {"quantity": 948.0, "unit": "ml", "item": "vegetable stock", "notes": "4 cups (948ml) vegetable stock", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "medium", "item": "squash", "notes": "1 medium yellow squash", "category": "produce"}, {"quantity": 2.0, "unit": "medium", "item": "zucchini", "notes": "2 medium zucchini", "category": "produce"}]'::jsonb, '["Make vegetable noodles with the carrots, yellow squash, and zucchini with a julienne pepper.", "Place all the noodles into a medium-sized bowl, and mix them together. Set aside. Chop up the parts of the vegetable that were not cut by the julienne peeler. Save it for the stew.", "Drain the water from the tofu package and rinse the tofu. Chop the tofu into smaller cubes, and set aside.", "Heat the olive oil in a medium-sized pot over medium-high heat. Once the pot is heated, pour in the diced onions and ginger. Saut them for about 2 minutes, or until the onions turn translucent. Next, add the minced garlic, curry paste, diced potatoes, chopped carrots, and stir everything together.", "Add the vegetable stock and cover the pot with a lid. Once the stock starts boiling, add the coconut milk, cabbage, and chopped summer squash, stir, and wait for the water to start boiling again. Once the stew boils, season with fish sauce, lime juice, and sea salt. Check to see if the potatoes are fully cooked by piercing a fork into a piece of potato. If the fork can go through it easily, they''re ready.Turn off the heat, and add the chopped basil. You can also save some for garnish.In a bowl, put about 1 to 1-1/2 cups of the vegetable noodles on the bottom, and pour the stew on top.", "Sprinkle black sesame seeds for garnish.Refrigerate leftover noodles in a separate container from the stew."]'::jsonb, 'https://www.foodista.com/recipe/NJ7CGSKG/red-curry-stew-vegetable-noodles', 'https://img.spoonacular.com/recipes/658058-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pork-fried-rice', 'Pork Fried Rice', 4, 0, 0, '{"calories": 634, "protein": 41.33, "carbs": 55.5, "fat": 26.27, "saturated_fat": 5.68, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1273.0, "potassium": null, "fiber": 1.94, "sugar": 6.34, "vitamin_a": null, "vitamin_c": 5.29, "calcium": 75.07, "iron": 2.69}'::jsonb, ARRAY['chinese', 'asian', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'dessert'], '[{"quantity": 4.0, "unit": "cups", "item": "rice", "notes": "4 cups steamed rice", "category": "pasta and rice"}, {"quantity": 4.0, "unit": "large", "item": "eggs", "notes": "4 large eggs, lightly beaten", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "piece", "item": "ginger", "notes": "1 piece of ginger, roughly half a thumbsize", "category": "produce"}, {"quantity": 0.6666667, "unit": "cup", "item": "green onions", "notes": "2/3 cup green onions, finely sliced at an angle", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "hoisin sauce", "notes": "2 tablespoons hoisin sauce", "category": "ethnic foods"}, {"quantity": 4.0, "unit": "tablespoons", "item": "soy sauce", "notes": "4 tablespoons Light soy sauce", "category": "condiments"}, {"quantity": 500.0, "unit": "gram", "item": "pork loin", "notes": "1 500 gram pork loin with skin", "category": "meat"}, {"quantity": 1.0, "unit": "small", "item": "onion", "notes": "1 small red onion, finely diced", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "sesame oil", "notes": "2 teaspoons Sesame oil", "category": "ethnic foods"}, {"quantity": 0.25, "unit": "cup", "item": "vegetable oil", "notes": "1/4 cup vegetable oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "teaspoons", "item": "sugar", "notes": "2 teaspoons white sugar", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "vinegar", "notes": "1 tablespoon white vinegar", "category": "oil, vinegar, salad dressing"}]'::jsonb, '["Cut pork into 1/4 inch slices, then cut into 1/4 inch strips and set aside.", "Heat half the oil in a hot wok until the surface begins to quiver.", "Pour in beaten eggs and allow to cook for 10 seconds, then fold egg mixture over onto itself with a spatula and lightly scramble for about 1 minute. Carefully remove egg from wok with a spatula and drain on paper towel. Set aside.", "Heat remaining oil in hot wok and stir fry onion and ginger for 30 seconds.", "Add sugar and stir fry for 30 more seconds.", "Add pork and stir fry for a further 30 seconds. Stir in hoisin sauce, soy sauce, vinegar, and sesame oil and cook, stirring, for 1 minute. Toss in rice and cooked egg and stir, using a spatula to break up the egg into smaller pieces, for 1 minute. Finally, add green onions and stir fry for a further 30 seconds or until well combined and rice is heated through.", "Transfer rice to a platter and serve."]'::jsonb, 'https://www.foodista.com/recipe/5N4TG2KX/pork-fried-rice', 'https://img.spoonacular.com/recipes/656777-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('masala-raisin-chicken', 'Masala Raisin Chicken', 3, 0, 0, '{"calories": 318, "protein": 13.4, "carbs": 12.76, "fat": 24.52, "saturated_fat": 3.92, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 310.38, "potassium": null, "fiber": 2.82, "sugar": 1.45, "vitamin_a": null, "vitamin_c": 34.73, "calcium": 42.65, "iron": 2.05}'::jsonb, ARRAY['indian', 'asian', 'side dish', 'gluten free', 'dairy free', 'whole 30', 'spoonacular'], '[{"quantity": 400.0, "unit": "g", "item": "chicken", "notes": "400g chicken", "category": "meat"}, {"quantity": 1.5, "unit": "tbsp", "item": "chili powder", "notes": "1 1/2 tbsp (or as needed) plain chili powder (add water and mix into a thick paste)", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tbsp", "item": "raisins", "notes": "2 tbsp dried raisins", "category": "produce"}, {"quantity": 0.5, "unit": "tbsp", "item": "ginger paste", "notes": "1/2 tbsp ginger paste", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tsp", "item": "garlic paste", "notes": "1 tsp garlic paste", "category": "produce"}, {"quantity": 0.5, "unit": "tbsp", "item": "onion paste", "notes": "1/2 tbsp onion paste", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "tomato", "notes": "1 tomato - chopped", "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "spices - 1 cinnamon", "notes": "Spices - 1 cinnamon, 1 star anise and 3 cloves", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "sprigs", "item": "curry leaves", "notes": "2-3 sprigs curry leaves", "category": "ethnic foods"}, {"quantity": 3.0, "unit": "tbsp", "item": "oil", "notes": "3 tbsp oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 3.0, "unit": "servings", "item": "salt", "notes": "Salt to taste", "category": "spices and seasonings"}]'::jsonb, '["Heat oil and fry spices with ginger, garlic and onion paste.(Just for 1-2 mins)", "Add chili paste and continue to fry over low heat till oil splits.Put in chicken, tomato, curry leaves and raisins.Season with salt.", "Add a bit of water if needed to cook the chicken.Continue to stir till everything comes together;a thick gravy coated over the chicken pieces."]'::jsonb, 'https://www.foodista.com/recipe/RQBMR85Z/masala-raisin-chicken', 'https://img.spoonacular.com/recipes/651184-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fresh-cherry-scones', 'Fresh Cherry Scones', 8, 0, 0, '{"calories": 335, "protein": 9.12, "carbs": 53.72, "fat": 9.82, "saturated_fat": 1.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 332.42, "potassium": null, "fiber": 5.55, "sugar": 11.96, "vitamin_a": null, "vitamin_c": 3.14, "calcium": 101.49, "iron": 2.65}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "cherries", "notes": "1 cup Fresh Cherries, pitted and frozen", "category": "produce"}, {"quantity": 2.5, "unit": "cups", "item": "oat flour", "notes": "2-1/2 cups Oat Flour (Bob''s Red Mill)", "category": "health foods"}, {"quantity": 1.0, "unit": "cup", "item": "grind cornmeal", "notes": "1 cup Fine Grind Cornmeal (Bob''s Red Mill)", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "teaspoons", "item": "baking powder", "notes": "2 teaspoons baking powder", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "baking soda", "notes": "½ teaspoon baking soda", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "½ teaspoon salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ground nutmeg", "notes": "1 teaspoon ground nutmeg", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "ground ginger", "notes": "2 teaspoons ground ginger", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "walnuts", "notes": "½ cup walnuts, chopped", "category": "baking"}, {"quantity": 0.33333334, "unit": "cup", "item": "agave nectar", "notes": "1/3 cup agave nectar (or 1/3 cup sugar)", "category": "ethnic foods"}, {"quantity": 0.75, "unit": "cup", "item": "applesauce", "notes": "3/4 cup unsweetened applesauce", "category": "canned and jarred"}, {"quantity": 0.25, "unit": "cup", "item": "yogurt", "notes": "¼ cup plain yogurt", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "teaspoons", "item": "vanilla extract", "notes": "2 teaspoons vanilla extract", "category": "baking"}]'::jsonb, '["Cut cherries in half and pit them (or use a cherry pitter).", "Place the cherries in a freezer-safe container and freeze for at least 3 hours prior to baking the scones. This ensures the cherries dont pop in the dough while theyre baking.", "In a Kitchen", "Aid (with the wire whisk attachment) or food processor, add the oat flour, cornmeal, baking powder, baking soda, nutmeg, ginger and salt.", "Mix or pulse to combine dry ingredients. In a bowl, combine the applesauce, yogurt, vanilla extract and agave nectar.  Stir to combine Very slowly pour the wet ingredients into the mixer with the dry ingredients about a quarter of a cup at a time (similar idea to making pie crust), mixing on medium speed. Once all the wet ingredients are combined with the dry, add chopped walnuts and mix until integrated into the dough. Taking the dough in your hands, form it into a disc shape. Refrigerate in a sealable container or plastic wrap for 1 hour.", "Preheat the oven to 375 degrees. Using a bread knife, cut the dough in half horizontally like you would a bun.", "Place half of the frozen cherries on one of the dough halves then place the other half of the dough on top. Press the dough halves together to seal the cherries in.  Press the remaining frozen cherries into the top of the dough. Using a serrated knife, cut diagonals into the dough in order to create eight triangles. Arrange on a parchment paper-lined baking sheet (be sure to give the triangles enough space to bake evenly).", "Bake for 23 minutes or until the tops of the scones are golden brown.", "Serve with butter, jam, honey, or nutella."]'::jsonb, 'https://www.foodista.com/recipe/6LXB248N/fresh-cherry-scones', 'https://img.spoonacular.com/recipes/643450-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('peanut-butter-cup-trifle', 'Peanut Butter Cup Trifle', 4, 0, 0, '{"calories": 808, "protein": 15.96, "carbs": 79.52, "fat": 51.42, "saturated_fat": 19.82, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 460.98, "potassium": null, "fiber": 4.13, "sugar": 68.72, "vitamin_a": null, "vitamin_c": 0, "calcium": 117.05, "iron": 1.59}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'dessert', 'spoonacular', 'vegetarian'], '[{"quantity": 4.0, "unit": "large", "item": "brownies", "notes": "4 large brownies, cut into cubes", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "vanilla pudding--the pudding is already made", "notes": "1 cup instant vanilla pudding--the pudding is already made", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "peanut butter cups", "notes": "1 cup mini peanut butter cups, cut into quarters", "category": "sweet snacks"}, {"quantity": 1.0, "unit": "cup", "item": "whipped topping", "notes": "1 cup whipped topping", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "cup", "item": "creamy peanut butter", "notes": "1/2 cup creamy peanut butter", "category": "nut butters, jams, and honey"}, {"quantity": 0.5, "unit": "cup", "item": "whipping cream", "notes": "1/2 cup heavy or whipping cream", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "Tbs", "item": "corn syrup", "notes": "2 Tbs light corn syrup", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "brown sugar", "notes": "1/4 cup light brown sugar", "category": "baking"}]'::jsonb, '["Prepare peanut butter sauce by mixing the peanut butter, cream, corn syrup and brown sugar in a small saucepan.", "Heat over medium heat until sugar is melted and sauce is very smooth.", "Remove from heat; set aside.", "Fold together the whipped topping and the vanilla pudding in a small bowl.  Set aside.", "Assemble trifle by taking 4 mini trifle bowls or dishes of an equal size (a stemless wine glass or an old-fashioned glass works well here too), and build layers:  layer 1/2 of the brownies on the bottom of the 4 trifle bowls.  Next, layer 1/2 of the quartered peanut butter cups on top of the brownie layer, then top with 1/2 the pudding.", "Drizzle about 1-2 tbs of the peanut butter sauce over the pudding.  Repeat the layer brownie and the pudding layer once more.  Top with remaining quartered peanut butter cups and liberally drizzle with more peanut butter sauce--and yep, let the sauce drip down the sides!!!  You can garnish with chocolate sprinkles if desired too.", "Remember--you are distributing what you have between 4 small bowls.", "Let your eye be your judge as to the amounts of each bowl so they will look even."]'::jsonb, 'https://www.foodista.com/recipe/5RGZFKJV/peanut-butter-cup-trifle', 'https://img.spoonacular.com/recipes/655300-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cranberry-orange-scones', 'Cranberry Orange Scones', 24, 0, 0, '{"calories": 151, "protein": 2.66, "carbs": 30.56, "fat": 2.32, "saturated_fat": 1.17, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 98.97, "potassium": null, "fiber": 0.71, "sugar": 18.88, "vitamin_a": null, "vitamin_c": 86.52, "calcium": 50.49, "iron": 0.92}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "flour", "notes": "2 cups all-purpose flour", "category": "baking"}, {"quantity": 2.5, "unit": "teaspoon", "item": "baking powder", "notes": "2 1/2 teaspoon baking powder", "category": "baking"}, {"quantity": 0.25, "unit": "teaspoon", "item": "baking soda", "notes": "1/4 teaspoon baking soda", "category": "baking"}, {"quantity": 0.25, "unit": "teaspoon", "item": "salt", "notes": "1/4 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "sugar", "notes": "1/4 cup sugar", "category": "baking"}, {"quantity": 3.5, "unit": "tablespoon", "item": "butter", "notes": "3 1/2 tablespoon butter,cut into small pieces", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "cranberries", "notes": "1/4 cup cranberries, dried", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoon", "item": "orange peel", "notes": "2 teaspoon orange peel, grated", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "non fat milk", "notes": "1/4 cup non fat milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "orange juice", "notes": "1/4 cup fresh orange juice", "category": "beverages"}, {"quantity": 1.0, "unit": "large", "item": "egg", "notes": "1 large egg, lightly beaten", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "powdered sugar", "notes": "1/4 cup powdered sugar", "category": "baking"}, {"quantity": 24.0, "unit": "servings", "item": "squirt of orange juice", "notes": "Squirt of fresh orange juice", "category": "beverages"}]'::jsonb, '["Preheat oven to 37", "Combine flour, baking soda, baking powder, salt and sugar in a bowl.", "Cut in butter with pastry blender or 2 knives until mixture resembles coarse meal (I used my hands). Stir in cranberries and rind.", "Add milk, orange juice and egg stirring just until moist.", "Turn dough out onto a lightly floured surface, and knead 15 times or until smooth.", "Form into an 8 x8x square.", "Cut 4 even rows into the dough.", "Cut into triangles.  I got 6 scones per row. (sorry no picture, my hands were to sticky to pull out my camera)", "Carefully", "Transfer dough to a baking sheet coated with cooking spray or lined with parchment paper", "Bake at 375 for 10-12 minutes or until golden.", "Let them slightly cool for about 5 minutes.  Meanwhile make your glaze.", "In a small bowl add your powdered sugar and orange juice (I juiced a 1/4 of an orange) mix until a consistency you like.", "Add more sugar if to thin, add more juice if to thick.", "Drizzle over the top of scones.", "Eat and Enjoy!"]'::jsonb, 'https://www.foodista.com/recipe/NLMXJ8FY/cranberry-orange-scones', 'https://img.spoonacular.com/recipes/640398-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('savory-cheese-dill-scones', 'Savory Cheese Dill Scones', 12, 0, 0, '{"calories": 216, "protein": 5.93, "carbs": 24.35, "fat": 10.67, "saturated_fat": 6.36, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 213.14, "potassium": null, "fiber": 1.26, "sugar": 2.48, "vitamin_a": null, "vitamin_c": 0, "calcium": 86.95, "iron": 1.35}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 0.75, "unit": "teaspoon", "item": "baking powder", "notes": "3/4 teaspoon baking powder", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "a pinch of baking soda", "notes": "1/2 teaspoon and a pinch of baking soda", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "pepper", "notes": "1/2 teaspoon freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "tablespoons butter", "notes": "1/2 cup (or 1 stick) and 3 tablespoons cold butter, sliced", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "buttermilk", "notes": "1 cup buttermilk", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "cup", "item": "coarsely cheddar cheese", "notes": "1/2 cup coarsely grated Cheddar cheese", "category": "cheese"}, {"quantity": 0.5, "unit": "cup", "item": "cottage cheese", "notes": "1/2 cup cottage cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "tablespoon", "item": "dill", "notes": "1 tablespoon chopped fresh dill", "category": "produce"}, {"quantity": 1.0, "unit": "large", "item": "shallot", "notes": "1 large shallot, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "sugar", "notes": "1 tablespoon sugar", "category": "baking"}, {"quantity": 2.25, "unit": "cups", "item": "unbleached flour", "notes": "2 1/4 cups unbleached all-purpose flour", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "flour", "notes": "1/2 cup whole wheat flour", "category": "baking"}]'::jsonb, '["Preheat oven to 375F with the rack in middle position.Make the Scone", "Place half the butter and half the dry ingredients in the bowl. Pulse until the butter is reduced to pea-sized pieces, with dough still dry.", "Place all the ingredients in a large bowl and use a pastry cutter to incorporate the butter into the dough.", "Cut by pressing on butter, then gathering flour onto it in two quick strokes.", "Cut until butter slices become pea-sized.Dont over process or mix. Dough will be dry. Break large lumps of butter by hand, and toss dry dough with your fingers.Blend the cheeses, dill, shallot and pepper with the Scone", "Mix using a wooden spoon.", "Drizzle the buttermilk over the dough and drop the cottage cheese in the middle, and stir until mixed.", "Add more buttermilk if dough is too dry to hold together.", "Place dough on a lightly floured surface and divide into two. Form 2 discs and flatten each to a thickness of about 1-1/2 inches, cut into 6 wedges for a total of 1", "Arrange an inch apart on a cookie sheet.", "Bake for 15 minutes, rotate the pan, and bake another 10 to 15 minutes, until scones are light brown on top and darker at the bottom. Bread should no longer be soft and doughy in the center.", "Bake in 2 batches if scones dont fit in one cookie sheet.", "Serve warm or cool in a wire rack before wrapping in foil or plastic wrap/bag. Freshly baked scones can be kept at room temperature for up to 2 days, and in the refrigerator for a week."]'::jsonb, 'https://www.foodista.com/recipe/CHQQMT5Q/savory-cheese-dill-scones', 'https://img.spoonacular.com/recipes/659463-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('berry-and-white-chocolate-trifle', 'Berry and White Chocolate Trifle', 8, 0, 0, '{"calories": 432, "protein": 6.92, "carbs": 40.39, "fat": 20.36, "saturated_fat": 11.95, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 112.81, "potassium": null, "fiber": 1.57, "sugar": 17.37, "vitamin_a": null, "vitamin_c": 31.25, "calcium": 176.29, "iron": 1.41}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'dessert', 'spoonacular', 'vegetarian'], '[{"quantity": 12.0, "unit": "", "item": "lady fingers biscuits", "notes": "12 Boudoir or lady fingers Biscuits", "category": "sweet snacks"}, {"quantity": 500.0, "unit": "milliliters", "item": "custard- i used woolworth''s", "notes": "500 milliliters bought custard- I used Woolworth''s", "category": "baking"}, {"quantity": 250.0, "unit": "milliliters", "item": "cream", "notes": "250 milliliters cream", "category": "milk, eggs, other dairy"}, {"quantity": 100.0, "unit": "grams", "item": "chocolate", "notes": "100 grams slab white chocolate", "category": "baking"}, {"quantity": 125.0, "unit": "grams", "item": "berries", "notes": "125 grams blue berries", "category": "produce"}, {"quantity": 400.0, "unit": "grams", "item": "strawberries", "notes": "400 grams strawberries- hulled and cut in smallish chunks", "category": "produce"}, {"quantity": 1.0, "unit": "medium", "item": "cream sherry- i used a cap full", "notes": "medium cream sherry- I used a cap full per mini trifle", "category": "alcoholic beverages"}, {"quantity": 8.0, "unit": "servings", "item": "more chocolate", "notes": "more white chocolate for decorating- optional", "category": "baking"}]'::jsonb, '["Break the chocolate into smaller pieces and place in a glass bowl over boiling water and allow to melt.", "In the meantime, beat the cream until it forms soft peaks.", "Once the chocolate has melted, fold it into the cream with  a spatula.", "Get your 6 glasses or small bowls ready and place two boudoir biscuits in each.", "Drizzle some sherry over the biscuits.", "Pour some custard in each glass followed by some fresh berries.", "Spoon some of the cream white chocolate mixture on top of the berries and repeat the layers ending with some white chocolate.", "Scatter a few berries on the top and finish off with a sprig of  mint and some chocolate shavings.", "Keep refrigerated  for at least 1 hour."]'::jsonb, 'https://www.foodista.com/recipe/JTQVYQ6S/berry-and-white-chocolate-trifle', 'https://img.spoonacular.com/recipes/634847-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
