.com/recipe/RXWYTJSZ/caramel-almond-berry-trifle-recipe', 'https://img.spoonacular.com/recipes/636970-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('strawberries-and-cream-scones', 'Strawberries and Cream Scones', 8, 0, 0, '{"calories": 286, "protein": 5.04, "carbs": 46.93, "fat": 9.4, "saturated_fat": 5.52, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 374.76, "potassium": null, "fiber": 2.44, "sugar": 20.09, "vitamin_a": null, "vitamin_c": 42.03, "calcium": 103.04, "iron": 2.03}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 2.25, "unit": "teaspoon", "item": "baking powder", "notes": "2 1/4 teaspoon baking powder", "category": "baking"}, {"quantity": 2.0, "unit": "tablespoons", "item": "butter", "notes": "2 tablespoons Butter", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "teaspoon", "item": "cinnamon", "notes": "1/4 teaspoon cinnamon", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg lightly beaten mixed with a tablespoon of water for egg wash", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "cup", "item": "flour", "notes": "2 cup flour", "category": "baking"}, {"quantity": 0.33333334, "unit": "cup", "item": "granulated sugar", "notes": "1/3 cup granulated white sugar", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "heavy cream", "notes": "1/2 cup heavy cream", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "", "item": "lemon", "notes": "1 lemon", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoon", "item": "milk", "notes": "2-3 tablespoon milk", "category": "milk, eggs, other dairy"}, {"quantity": 8.0, "unit": "servings", "item": "powdered sugar", "notes": "powdered sugar", "category": "baking"}, {"quantity": 0.75, "unit": "teaspoon", "item": "salt", "notes": "3/4 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "pint", "item": "strawberries", "notes": "1 pint strawberries", "category": "produce"}]'::jsonb, '["Preheat the oven to 425F.Cube and chill butter.", "Combine dry ingredients (flour, sugar, baking powder, lemon zest, salt, and cinnamon) in a large bowl.With your fingertips work the butter into the flour mixture.Make a well in the center of the butter and flour mixture.", "Add the heavy cream and stir.", "Add a tablespoon of milk and stir until the dough is moistened but not wet.", "Add the diced strawberries.Gently work the strawberries into the dough and knead it together.Pat into an 8 inch circle and cut triangles. Do not be afraid of using flour, excess flour can always be dusted off.", "Transfer scones to a parchment lined baking sheet.", "Brush with egg wash.", "Bake at 425F for 12-15 minutes or until the tops and edges are golden.Cool on a cooling rack.", "Drizzle with glaze (powdered sugar mixed with a bit of liquid of your choice)"]'::jsonb, 'https://www.foodista.com/recipe/W43T6ZBG/strawberries-and-cream-scones', 'https://img.spoonacular.com/recipes/661725-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lemon-poppy-seed-scones', 'Lemon-Poppy Seed Scones', 8, 0, 0, '{"calories": 381, "protein": 5.85, "carbs": 36.81, "fat": 23.92, "saturated_fat": 14.17, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 514.9, "potassium": null, "fiber": 1.6, "sugar": 8.7, "vitamin_a": null, "vitamin_c": 0, "calcium": 150.76, "iron": 2.23}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 2.5, "unit": "teaspoons", "item": "baking powder", "notes": "2-1/2 teaspoons baking powder", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "brown sugar", "notes": "1 tablespoon brown sugar, preferably turbinado or raw sugar", "category": "baking"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg, lightly beaten", "category": "milk, eggs, other dairy"}, {"quantity": 1.75, "unit": "ounces", "item": "granulated sugar", "notes": "1/4 cup (1-3/4 ounces) granulated sugar", "category": "baking"}, {"quantity": 8.0, "unit": "ounces", "item": "heavy whipping cream", "notes": "1 cup (8 ounces) chilled heavy whipping cream", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "lemon zest", "notes": "1 teaspoon lemon zest grated", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "poppy seeds", "notes": "1/4 cup poppy seeds", "category": "baking"}, {"quantity": 1.25, "unit": "teaspoons", "item": "salt", "notes": "1 1/4 teaspoons salt", "category": "spices and seasonings"}, {"quantity": 10.0, "unit": "ounces", "item": "unbleached flour", "notes": "2 cups (10 ounces) unbleached all-purpose flour", "category": "baking"}, {"quantity": 4.0, "unit": "ounces", "item": "butter", "notes": "1 stick (4 ounces) cold unsalted butter, cut into 1/2-inch cubes", "category": "milk, eggs, other dairy"}]'::jsonb, '["Preheat oven to 425 ad position oven rack in the center. Line baking sheet with parchment paper or a silicone mat.In the bowl of a food processor fitted with a metal blade, place the flour, sugar, poppy seeds, lemon zest, baking powder and salt and process for 10 seconds to blend well.", "Add the cold butter pieces and pulse five times at 1 second intervals, or until the butter into cut into medium pieces.", "Add the cream and pulse another 20 times, or until the dough holds together in small, thick clumps. Use a spatula to scrape the dough onto a lightly floured work surface. Gently squeeze the clumps together until they form a cohesive dough.Pat the dough into a circle 7 inches in diameter and about 1-inch thick. Use a chef''s knife to cut the dough into 8 equal wedges and transfer to the prepared baking sheet, spacing them about 2 inches apart.", "Brush the tops with a thin coating of the lightly beaten egg (you will not use all of the egg).", "Sprinkle evenly with sugar.", "Bake the scones for 17-20 minutes, until firm to the touch and golden brown.", "Transfer to a rack and let cool for 5 minutes.", "Serve warm or at room temperature."]'::jsonb, 'https://www.foodista.com/recipe/BLBMWT3D/lemon-poppy-seed-scones', 'https://img.spoonacular.com/recipes/649853-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('dried-fruit-and-ginger-scones', 'Dried Fruit and Ginger Scones', 8, 0, 0, '{"calories": 272, "protein": 4.55, "carbs": 39.3, "fat": 11.08, "saturated_fat": 6.76, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 376.1, "potassium": null, "fiber": 1.23, "sugar": 14.97, "vitamin_a": null, "vitamin_c": 0, "calcium": 129.53, "iron": 1.12}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "tbsp", "item": "baking powder", "notes": "1 tbsp baking powder", "category": "baking"}, {"quantity": 5.0, "unit": "tbsp", "item": "butter", "notes": "5 tbsp butter, cut into cubes", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "cake flour", "notes": "1 cup cake flour", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "candied ginger", "notes": "1/4 cup chopped candied ginger", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "apples", "notes": "1/4 cup dried apples", "category": "dried fruits"}, {"quantity": 0.25, "unit": "cup", "item": "cranberries", "notes": "1/4 cup chopped dried cranberries", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "flour", "notes": "1 cup all-purpose flour", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "heavy cream", "notes": "¼ cup heavy cream", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "salt", "notes": "½ tsp salt", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "tbsp", "item": "turbinado sugar", "notes": "4 tbsp turbinado sugar", "category": "baking"}, {"quantity": 0.75, "unit": "cup", "item": "milk", "notes": "¾ cup whole milk", "category": "milk, eggs, other dairy"}]'::jsonb, '["Position a rack in the middle of your oven and preheat to 425F.  If you will be baking on a pizza stone, put it in the oven to preheat as well.  If you will be using a cookie sheet, line it with parchment paper and set it aside.", "Whisk together the flours, baking powder, 3 TB of the sugar, and salt in a medium bowl.", "Cut in the butter using a pastry blender, two knives, or your fingers, until the largest chunks of butter are the size of small peas.", "Pour in the cream and milk (or just use all cream, if you have it) and mix it around with a fork until an evenly hydrated, extremely sticky dough forms.", "Add the fruits and mix again until evenly distributed (you may have to work a bit to break up the ginger pieces).Dump the sticky mass out onto a well-floured board.", "Sprinkle a little flour on top as well, then pat the dough out into a circle about 1-inch thick.  Try not to add too much flour, lest they become dense and tough.  Dip a pizza cutter or other thin, sharp knife into flour, then cut the circle into 8 equal sized pieces.  You may need to scrape off and re-flour your slicing instrument between slices.Using a bench scraper, a thin spatula, or (if you are brave) your hands, relocate your 8 scones to your prepared baking vessel, spacing them a half inch or so apart (they will puff and rise a little bit, but not tremendously).", "Sprinkle the tops with the remaining 1 TB of sugar.", "Bake for 13-15 minutes, or until lightly golden on top and cooked through.Cool at least 10 minutes before removing to a wire rack.  Eat warm or cool."]'::jsonb, 'https://www.foodista.com/recipe/6B2W4D67/dried-fruit-and-ginger-scones', 'https://img.spoonacular.com/recipes/641651-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('english-berry-trifle', 'English Berry Trifle', 16, 0, 0, '{"calories": 268, "protein": 3.85, "carbs": 42.6, "fat": 9.62, "saturated_fat": 5.31, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 198.46, "potassium": null, "fiber": 1.44, "sugar": 32.3, "vitamin_a": null, "vitamin_c": 37.7, "calcium": 47.95, "iron": 1.29}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'dessert', 'gluten free', 'spoonacular', 'vegetarian'], '[{"quantity": 4.0, "unit": "large", "item": "eggs", "notes": "4 large eggs", "category": "milk, eggs, other dairy"}, {"quantity": 0.33333334, "unit": "cup", "item": "lemon juice", "notes": "1/3 cup fresh lemon juice", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "lemon peel", "notes": "1 tablespoon grated lemon peel", "category": "produce"}, {"quantity": 16.0, "unit": "ounce", "item": "pound cake", "notes": "1 16-ounce pound cake", "category": "bakery/bread"}, {"quantity": 0.25, "unit": "cup", "item": "sherry", "notes": "1/4 cup (or to taste) Sweet Sherry or Port", "category": "alcoholic beverages"}, {"quantity": 2.0, "unit": "pints", "item": "strawberries", "notes": "2 pints fresh strawberries", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "strawberry preserves", "notes": "1/4 cup strawberry preserves", "category": "nut butters, jams, and honey"}, {"quantity": 0.25, "unit": "cup", "item": "sugar", "notes": "1/4 cup plus 3 tablespoons sugar", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "sugar", "notes": "1 cup sugar", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "butter", "notes": "1/2 cup (1 stick) unsalted butter, room temperature", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "cups", "item": "whipped cream", "notes": "2 cups whipped cream, chilled", "category": "milk, eggs, other dairy"}]'::jsonb, '["Whisk eggs, sugar, and lemon juice in heavy medium saucepan to blend.", "Add butter and lemon peel. Stir over medium heat until curd thickens to pudding consistency, about 10 minutes.", "Combine 2 pints strawberries and 1/4 cup sugar in bowl. Mash berries coarsely with fork.", "Let stand until juices form, stirring occasionally, about 30 minutes.", "Cut cake crosswise into 8 pieces.", "Cut each piece into 3 strips. Line bottom of 3-quart trifle bowl with 8 cake strips, trimming to fit.", "Drizzle with 3 tablespoons Sherry or Port; spread with a thin layer of preserves, then spread 2/3 cup curd, then half of mashed berries. Repeat layering. Top with remaining cake, alcohol, preserves, and curd. Cover; chill (preferably overnight).Beat cream and 3 tablespoons sugar in bowl until peaks form; spread over trifle. Mound remaining berries in center."]'::jsonb, 'https://www.foodista.com/recipe/4WVZZX8K/english-berry-trifle', 'https://img.spoonacular.com/recipes/642413-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ricotta-chocolate-chips-scones', 'Ricotta Chocolate Chips Scones', 4, 0, 0, '{"calories": 291, "protein": 5.92, "carbs": 39.92, "fat": 12.18, "saturated_fat": 7.53, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 238.87, "potassium": null, "fiber": 0.78, "sugar": 16.52, "vitamin_a": null, "vitamin_c": 0, "calcium": 122.18, "iron": 1.54}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 115.0, "unit": "grams", "item": "flour", "notes": "115 grams (4 oz or a bit less than 1 cup) all-purpose flour", "category": "baking"}, {"quantity": 2.0, "unit": "tbsp", "item": "sugar", "notes": "25 grams (2 tbsp) sugar", "category": "baking"}, {"quantity": 0.75, "unit": "teaspoon", "item": "baking powder", "notes": "3/4 teaspoon baking powder", "category": "baking"}, {"quantity": 1.0, "unit": "pinch", "item": "baking soda", "notes": "1 pinch baking soda", "category": "baking"}, {"quantity": 1.0, "unit": "pinch", "item": "salt", "notes": "1 pinch salt", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "oz", "item": "milk ricotta cheese", "notes": "70 grams (3 oz) whole milk ricotta cheese", "category": "cheese"}, {"quantity": 2.0, "unit": "tbsp", "item": "butter", "notes": "30 grams (2 tbsp) butter, chilled and cut into small pieces", "category": "milk, eggs, other dairy"}, {"quantity": 60.0, "unit": "milliliters", "item": "buttermilk", "notes": "60 milliliters (2 fl oz or ¼ cup) buttermilk", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "milliliters", "item": "tsp vanilla extract", "notes": "2 milliliters (¼) tsp vanilla extract", "category": "baking"}, {"quantity": 40.0, "unit": "grams", "item": "chocolate chips", "notes": "40 grams (1.3 oz or ¼ cup) chocolate chips", "category": "baking"}, {"quantity": 4.0, "unit": "servings", "item": "milk to brush and brown sugar", "notes": "milk to brush and brown sugar to top", "category": "baking"}]'::jsonb, '["Preheat the oven to 400F degress. Line a baking sheet with parchment paper.", "In a bowl whisk together the flour, the sugar, the baking powder, the baking soda and the salt.", "Cut in the ricotta and butter and lightly work with your fingers until the mixture resembles coarse sand. Gently stir in the buttermilk, the vanilla extract and the chocolate chips.", "Turn the dough out onto a floured surface. Knead gently for 1  2 minutes, the dough should hold together but be a bit crumbly.", "Place the dough on the prepared baking sheet lined with parchment paper. Pat the dough into a 3/4-inch-thick circle.", "Cut  the dough into 4 wedges without separating them. Use a pastry brush to brush the surface of the dough with milk and then sprinkle with brown sugar.", "Bake for about 15 minutes or until lightly browned.", "Let them cool on a cooling  rack."]'::jsonb, 'https://www.foodista.com/recipe/JG6PXQBS/ricotta-chocolate-chips-scones', 'https://img.spoonacular.com/recipes/658326-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('blueberry-orange-maple-scones', 'Blueberry & Orange Maple Scones', 16, 0, 0, '{"calories": 278, "protein": 3.32, "carbs": 33.32, "fat": 14.84, "saturated_fat": 9.11, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 307.12, "potassium": null, "fiber": 0.81, "sugar": 18.8, "vitamin_a": null, "vitamin_c": 31.5, "calcium": 78.12, "iron": 1.1}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "c", "item": "flour", "notes": "2 c. plus 2 tbsp flour", "category": "baking"}, {"quantity": 1.0, "unit": "tbsp", "item": "baking powder", "notes": "1 tbsp baking powder", "category": "baking"}, {"quantity": 1.0, "unit": "tsp", "item": "salt", "notes": "1 tsp salt", "category": "spices and seasonings"}, {"quantity": 0.33333334, "unit": "c", "item": "maple syrup", "notes": "1/3 c. maple syrup", "category": "cereal"}, {"quantity": 12.0, "unit": "tbsp", "item": "butter", "notes": "12 tbsp cold butter, cut into 1/4\" cubes", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs, lightly beaten", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "c", "item": "heavy cream", "notes": "1 c. plus 2 tbsp heavy cream", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "tsp", "item": "orange extract", "notes": "2 tsp orange extract", "category": "baking"}, {"quantity": 2.0, "unit": "tsp", "item": "vanilla extract", "notes": "2 tsp vanilla extract", "category": "baking"}, {"quantity": 1.0, "unit": "tbsp", "item": "orange zest", "notes": "1 tbsp finely chopped orange zest", "category": "produce"}, {"quantity": 1.0, "unit": "c", "item": "blueberries", "notes": "1 c. blueberries", "category": "produce"}, {"quantity": 16.0, "unit": "servings", "item": "maple sugar", "notes": "Sugar or Maple Sugar", "category": "gourmet"}, {"quantity": 1.0, "unit": "c", "item": "icing sugar", "notes": "1 c. icing sugar", "category": "baking"}, {"quantity": 2.0, "unit": "tsp", "item": "vanilla extract", "notes": "2 tsp vanilla extract (I used vanilla paste)", "category": "baking"}, {"quantity": 16.0, "unit": "", "item": "juice of orange", "notes": "juice from one orange", "category": "beverages"}]'::jsonb, '["Preheat oven to 400F", "In the bowl of a mixer, mix together 2 cups flour, baking powder, salt and maple syrup", "Add in the butter and mix until it''s the size of peas", "In separate bowl, mix together 1 cup of the cream, eggs, orange zest, vanilla and orange extracts, and slowly add into the mixer.", "Toss the blueberries in the remaining 2 tbsp of flour and gently fold into the batter", "On a floured surface, carefully shape the dough into a ball and cut in half.", "Lightly dust the surface of the dough with more flour and press into disc shape about 3/4\" thick.", "Brush each disc with the remaining 2 tbsp of cream and sprinkle with sugar", "Bake for 25 min, or until browned and slightly firm to the touch.", "Cool on wire rack", "In bowl, mix together the icing sugar, vanilla and orange juice. Stir until no lumps are left and is combined.", "Drizzle over top the scones and allow to cool completely."]'::jsonb, 'https://www.foodista.com/recipe/4FW7FLXJ/blueberry-orange-maple-scones', 'https://img.spoonacular.com/recipes/635394-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('royal-wedding-pear-and-coriander-scones', 'Royal Wedding Pear and Coriander Scones', 8, 0, 0, '{"calories": 284, "protein": 5.0, "carbs": 32.84, "fat": 16.24, "saturated_fat": 8.99, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 474.0, "potassium": null, "fiber": 4.04, "sugar": 9.93, "vitamin_a": null, "vitamin_c": 1.09, "calcium": 135.02, "iron": 1.52}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "", "item": "pear", "notes": "1 pear, peeled, cored and chopped", "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "flour", "notes": "2 cups of gluten-free flour", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "xanthan gum)", "notes": "1 teaspoon xanthan gum)", "category": "health foods"}, {"quantity": 1.0, "unit": "teaspoon", "item": "baking soda", "notes": "1 teaspoon baking soda", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "baking powder", "notes": "1 tablespoon baking powder", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "tablespoons", "item": "butter", "notes": "8 tablespoons cold unsalted butter, cubed", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "sucanat", "notes": "1/4 cup sucanat", "category": "baking"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs, separated", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "cup", "item": "cream", "notes": "1/2 cup sour cream", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "coriander", "notes": "1 teaspoon coriander", "category": "spices and seasonings"}]'::jsonb, '["Preheat your oven to 40", "In a large bowl, whisk together flour, soda, powder and salt.", "Cut in the butter with your fingers until grainy, like cornmeal.", "Add sugar and whisk in.", "Add pear and toss in.", "Make a well in the center and fill with 1 egg and sour cream.", "Mix in with a fork until the dough comes together.", "Turn out onto a floured board and knead slightly until smooth.", "Roll into a log and cut into 8 triangles and place on an ungreased cookie sheet.", "Place the coriander between two pieces of wax paper and gently break with a rolling pin until crushed.  Try not to lose yourself in the gorgeous fragrance!", "Gently wash the tops of the scones with the remaining beaten egg and sprinkle with coriander.", "Bake for 16 minutes or until browned on top."]'::jsonb, 'https://www.foodista.com/recipe/FS6V8XD5/royal-wedding-pear-and-coriander-scones', 'https://img.spoonacular.com/recipes/658850-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('strawberry-scones', 'Strawberry Scones', 8, 0, 0, '{"calories": 271, "protein": 5.45, "carbs": 35.88, "fat": 12.76, "saturated_fat": 7.52, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 214.85, "potassium": null, "fiber": 3.36, "sugar": 14.07, "vitamin_a": null, "vitamin_c": 10.63, "calcium": 110.27, "iron": 1.03}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cup", "item": "flour", "notes": "2 cup white whole wheat flour", "category": "baking"}, {"quantity": 0.33333334, "unit": "cup", "item": "sugar", "notes": "⅓ cup sugar", "category": "baking"}, {"quantity": 2.0, "unit": "tsp", "item": "baking powder", "notes": "2 tsp baking powder", "category": "baking"}, {"quantity": 0.25, "unit": "tsp", "item": "salt", "notes": "¼ tsp salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "large", "item": "egg", "notes": "1 large egg", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "heavy cream", "notes": "¼ cup heavy cream", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "buttermilk", "notes": "¼ cup buttermilk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tsp", "item": "vanilla extract", "notes": "1 tsp vanilla extract", "category": "baking"}, {"quantity": 6.0, "unit": "Tbsp", "item": "butter", "notes": "6 Tbsp unsalted butter, chilled and cut into small cubes", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "strawberries", "notes": "1 cup fresh strawberries, chopped", "category": "produce"}, {"quantity": 8.0, "unit": "tsp", "item": "sparkling sugar", "notes": "8 tsp sparkling sugar", "category": "baking"}]'::jsonb, '["Preheat oven to 375 degrees. Line a baking sheet with silpat or parchment paper.", "In a large mixing combine flour sugar, baking powder, and salt with a whisk; set aside.", "In a small bowl beat egg.", "Add heavy cream, buttermilk, and vanilla; whisk to combine.", "Add butter to the flour mixture. Using your fingers rub the butter into the flour for form a coarse meal.", "Add milk mixture to flour. Stir with a fork to combine batter into a loose dough.", "Gently stir in the strawberries.", "Transfer dough onto a lightly flour counter top. Gently press dough together to form a 8 inch circle about 1 inch thick.", "Cut into 8 wedges.", "Place on baking sheet.", "Sprinkle each scone with 1 tsp of sugar.", "Bake for 12-15 minutes or until lightly browned."]'::jsonb, 'https://pickfreshfoods.com/strawberry-scones/', 'https://img.spoonacular.com/recipes/1646939-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('blackberry-scones-with-orange-zest-gluten-free', 'Blackberry Scones with Orange Zest (gluten-free)', 20, 0, 0, '{"calories": 158, "protein": 3.69, "carbs": 18.91, "fat": 7.89, "saturated_fat": 3.94, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 203.46, "potassium": null, "fiber": 1.64, "sugar": 9.22, "vitamin_a": null, "vitamin_c": 5.59, "calcium": 117.45, "iron": 0.63}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 4.5, "unit": "cup", "item": "pamela''s pancake and baking mix", "notes": "4 1/2 cup Pamela''s Pancake and Baking Mix", "category": "cereal"}, {"quantity": 2.0, "unit": "teaspoons", "item": "baking powder", "notes": "2 teaspoons baking powder  ", "category": "baking"}, {"quantity": 0.75, "unit": "cup", "item": "vanilla sugar", "notes": "3/4 cup vanilla sugar *(or 3/4 cup sugar and 1 teaspoon vanilla) ", "category": "baking"}, {"quantity": 1.0, "unit": "stick", "item": "butter", "notes": "1 stick unsalted butter", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs, lightly beaten", "category": "milk, eggs, other dairy"}, {"quantity": 1.3333334, "unit": "cup", "item": "milk", "notes": "1 1/3 cup whole milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "orange blossom water", "notes": "1 teaspoon orange blossom water", "category": "gourmet"}, {"quantity": 2.0, "unit": "", "item": "orange zest", "notes": "zest of 2 oranges", "category": "produce"}, {"quantity": 2.5, "unit": "cups", "item": "blackberries", "notes": "2 1/2 cups fresh blackberries", "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "turbinado sugar", "notes": "Turbinado sugar for topping", "category": "baking"}, {"quantity": 0.0, "unit": "Scoop sheets", "item": "orange zest", "notes": "Fold in blackberries and orange zest. Scoop mounds of dough onto an un-greased baking sheet. Sprinkle Turbinado sugar over the tops.", "category": "baking"}, {"quantity": 1.0, "unit": "serving", "item": "bake", "notes": "Bake for 15-17 minutes, until tops are golden brown. Eat and enjoy!", "category": "?"}]'::jsonb, '["My boy Otis was on his first baseball team this year - the Fighting Phillies - and amazingly they ended up in the championship game. Most of the season the Phillies bleachers were full of mellow, kind, supportive parents. But somehow when the Playoffs came around, everyone seemed to get really nervous for the kids.", "Andy, one of the dads, thought we could calm parental nerves by plying everyone with food on the morning of the final game. Being that we don''t eat wheat in my family, stopping by the donut shop before the game was not an option. So I baked up this big batch of scones in honor of Otis. ", " INGREDIENTS ", "1/2 cup Pamela''s Pancake and Baking", "Mix", "teaspoons baking powder  ", "/4 cup vanilla sugar *(or 3/4 cup sugar and 1 teaspoon vanilla) ", "stick unsalted butter", "eggs, lightly beaten", "1/3 cup whole milk", "teaspoon orange blossom water", "zest of 2 oranges", "1/2 cups fresh blackberries", "Turbinado sugar for topping", "*To make Vanilla Sugar, stick a vanilla pod or two in a jar with a few cups of sugar. Cover the jar and let sit at room temp for a few days. Voila. The sugar is infused with vanilla flavor. After using vanilla sugar,  just replenish the sugar in your jar and you will have it on hand to use in so many baking recipes.", "Preheat oven to 375. ", "Combine Pamela''s mix, baking powder, and sugar in a bowl. Integrate butter with all dry ingredients.", "Add in milk, (already beaten) eggs, and orange blossom water. ", "Fold in blackberries and orange zest. Scoop mounds of dough onto an un-greased baking sheet.", "Sprinkle Turbinado sugar over the tops.", "Bake for 15-17 minutes, until tops are golden brown. Eat and enjoy!", "  Makes 20 small scones"]'::jsonb, 'http://yummysupper.blogspot.com/2010/06/blackberry-scones-with-orange-zest.html', 'https://img.spoonacular.com/recipes/50423-312x231.png', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cheese-and-corn-scones', 'Cheese and Corn Scones', 16, 0, 0, '{"calories": 230, "protein": 5.03, "carbs": 23.57, "fat": 13.32, "saturated_fat": 7.89, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 287.97, "potassium": null, "fiber": 1.45, "sugar": 2.16, "vitamin_a": null, "vitamin_c": 0.88, "calcium": 95.8, "iron": 1.42}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 3.0, "unit": "cups", "item": "all purpose flour", "notes": "3 cups all purpose flour", "category": "baking"}, {"quantity": 2.0, "unit": "tsp", "item": "baking powder", "notes": "2 tsp. baking powder", "category": "baking"}, {"quantity": 0.5, "unit": "tsp", "item": "baking soda", "notes": "1/2 tsp. baking soda", "category": "baking"}, {"quantity": 0.33333334, "unit": "cup", "item": "bran", "notes": "1/3 cup bran", "category": "baking"}, {"quantity": 0.75, "unit": "cup", "item": "butter", "notes": "3/4 cup butter, cold and cubed", "category": "milk, eggs, other dairy"}, {"quantity": 0.75, "unit": "cup", "item": "creamy mexicana cheese", "notes": "3/4 – 1 cup Kraft Creamy Mexicana Shredded Cheese with a Touch of Philadelphia", "category": "cheese"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg, beaten (to form an egg wash)", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "corn", "notes": "1 cup frozen corn", "category": "frozen"}, {"quantity": 0.5, "unit": "cup", "item": "heavy cream", "notes": "1/2 cup heavy cream, half and half or milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "tsp", "item": "cracked pepper", "notes": "1/4 tsp. fresh cracked black pepper", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "salt", "notes": "1/2 tsp. salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "cream", "notes": "1/2 cup sour cream", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "water", "notes": "¼ cup cold water, or as needed", "category": "beverages"}, {"quantity": 2.0, "unit": "tbsp", "item": "sugar", "notes": "2 tbsp. white sugar", "category": "baking"}]'::jsonb, '["See http://www.becauseilikechocolate.com/2014/04/cheese-corn-scones.html for the full recipe!"]'::jsonb, 'http://spoonacular.com/-1397498120697', 'https://img.spoonacular.com/recipes/471334-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('raisin-scones', 'Raisin Scones', 12, 0, 0, '{"calories": 159, "protein": 2.77, "carbs": 24.75, "fat": 5.86, "saturated_fat": 3.47, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 171.16, "potassium": null, "fiber": 0.91, "sugar": 5.7, "vitamin_a": null, "vitamin_c": 0, "calcium": 114.6, "iron": 1.22}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 4.0, "unit": "tsp", "item": "baking powder", "notes": "4 tsp. baking powder", "category": "baking"}, {"quantity": 1.0, "unit": "", "item": "egg yolk", "notes": "1 egg yolk, beaten", "category": "milk, eggs, other dairy"}, {"quantity": 1.75, "unit": "cups", "item": "flour", "notes": "1 3/4 cups all-purpose flour", "category": "baking"}, {"quantity": 0.6666667, "unit": "cup", "item": "milk", "notes": "2/3 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "cup", "item": "raisins", "notes": "1/2 cup raisins", "category": "produce"}, {"quantity": 5.0, "unit": "tbsp", "item": "sugar", "notes": "5 tbsp. sugar", "category": "baking"}, {"quantity": 5.0, "unit": "tbsp", "item": "butter", "notes": "5 tbsp. unsalted butter, softened", "category": "milk, eggs, other dairy"}]'::jsonb, '["Preheat oven to 400 degrees F. Lightly grease baking sheet.Sift flour and baking powder into a med. bowl. Rub butter and sugar into flour to form a fine crumble. Make a well in center, add milk and raisins. Knead gently together, do not over mix. Dough will be sticky.On generously floured surface, roll out to 3/4 inch thickness.", "Cut into 2 1/2 inch rounds with a cookie cutter. Alternatively, you can scoop dough with a spoon and shape into rounds.", "Transfer to baking sheet, brush tops with yolk. Allow to stand for 10 mins.", "Bake in preheated oven until risen and tops are golden, 12 to 15 mins."]'::jsonb, 'https://www.foodista.com/recipe/68J6C6RW/raisin-scones', 'https://img.spoonacular.com/recipes/657768-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('rich-jelly-scones', 'Rich Jelly Scones', 4, 0, 0, '{"calories": 640, "protein": 13.71, "carbs": 81.54, "fat": 29.14, "saturated_fat": 16.97, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 509.89, "potassium": null, "fiber": 3.59, "sugar": 29.42, "vitamin_a": null, "vitamin_c": 2.61, "calcium": 238.97, "iron": 4.11}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "all purpose flour", "notes": "2 cups all purpose flour", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "granulated sugar", "notes": "1/4 cup granulated white sugar", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "baking powder", "notes": "2 teaspoons baking powder", "category": "baking"}, {"quantity": 0.25, "unit": "teaspoon", "item": "baking soda", "notes": "1/4 teaspoon baking soda", "category": "baking"}, {"quantity": 0.25, "unit": "teaspoon", "item": "salt", "notes": "1/4 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "butter", "notes": "1/2 cup unsalted butter, very cold", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "milk", "notes": "cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.5, "unit": "teaspoons", "item": "vanilla extract", "notes": "1 1/2 teaspoons pure vanilla extract", "category": "baking"}, {"quantity": 4.0, "unit": "servings", "item": "fruit preserves", "notes": "Thick jam or fruit preserves", "category": "produce"}, {"quantity": 1.0, "unit": "large", "item": "egg", "notes": "1 large egg, beaten well", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "milk", "notes": "1 tablespoon milk", "category": "milk, eggs, other dairy"}]'::jsonb, '["Pre-heat oven to 400 degrees.", "Mix dry ingredients together.", "Cut butter into the dry ingredients using a fork or hand-held pastry blender. When well blended, the mixture will have the look of crumbly sand.", "Add the vanilla, eggs, and milk, mixing only long enough to blend the ingredients. *You do not want to begin to melt the butter into the flour mixture by over-mixing.", "Turn the dough onto a lightly floured counter top or pastry board. Shape it into a round disc 8 inches across, slightly thicker in the center.", "Using a long knife, cut the dough into eight even pie-shaped portions.", "Place scones on a lightly greased baking sheet. Using a spoon, press a well into the wide end of each triangle, and fill the well with a spoonful of fruit jam.", "Brush the exposed surface of each scone with the milk/egg mixture,", "Bake for twenty-five minutes, until scones are a beautiful golden brown."]'::jsonb, 'https://www.foodista.com/recipe/5GK2BSP6/rich-jelly-scones', 'https://img.spoonacular.com/recipes/658300-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('dried-cherry-almond-scones', 'Dried Cherry-Almond Scones', 16, 0, 0, '{"calories": 216, "protein": 5.54, "carbs": 32.1, "fat": 7.39, "saturated_fat": 3.11, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 197.73, "potassium": null, "fiber": 2.12, "sugar": 5.74, "vitamin_a": null, "vitamin_c": 0, "calcium": 72.43, "iron": 1.93}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 0.5, "unit": "teaspoon", "item": "almond extract", "notes": "1/2 teaspoon almond extract", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "almonds", "notes": "1/2 cup chopped toasted almonds", "category": "nuts"}, {"quantity": 1.0, "unit": "tablespoon", "item": "baking powder", "notes": "1 tablespoon baking powder", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "baking soda", "notes": "1/2 teaspoon baking soda", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "cherries", "notes": "1 cup dried cherries", "category": "produce"}, {"quantity": 2.0, "unit": "large", "item": "eggs", "notes": "2 large eggs", "category": "milk, eggs, other dairy"}, {"quantity": 500.0, "unit": "g", "item": "flour", "notes": "500g Plain flour, sifted", "category": "baking"}, {"quantity": 0.5, "unit": "tsp", "item": "salt", "notes": "1/2 tsp Salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tbsp", "item": "sugar", "notes": "2 tbsp Sugar", "category": "baking"}, {"quantity": 6.0, "unit": "tablespoons", "item": "butter", "notes": "6 tablespoons unsalted butter, cut into pieces", "category": "milk, eggs, other dairy"}, {"quantity": 0.6666667, "unit": "cup", "item": "buttermik", "notes": "2/3 cup buttermik", "category": "?"}, {"quantity": 0.6666667, "unit": "cup", "item": "buttermik", "notes": "2/3 cup buttermik", "category": "?"}]'::jsonb, '["Preheat oven to 400 degree F.  Stir together flour, 1/4 cup sugar, and next 3 ingredients in a large bowl; cut int butter with a pastry blender or fork until crumbly.  Stir in cherries and almonds.", "Whisk together buttermilk, 1 egg, and almond extract; add to flour mixture, stirring with a fork just until dry ingredients are moistened and mixture forms a shaggy dough.Use floured hands to pat dough into a 1/2-inch thick, 10-x7-inch rectangle on a lightly floured surface; cut into 16 rectangles.", "Place scone dough on a parchment paper-lined baking sheet.", "Whisk together remaining egg and 1 teaspoon water.", "Brush scones with egg wash; sprinkle with remaining 1/4 cup sugar.", "Bake in preheated oven for 12 to 15 minutes or until golden."]'::jsonb, 'http://www.foodista.com/recipe/5434SY2K/dried-cherry-almond-scones', 'https://img.spoonacular.com/recipes/641650-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('raspberry-thumbprint-wholewheat-scones-with-macadamia-nuts', 'Raspberry Thumbprint Wholewheat Scones With Macadamia Nuts', 20, 0, 0, '{"calories": 142, "protein": 1.98, "carbs": 19.81, "fat": 6.56, "saturated_fat": 3.01, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 155.96, "potassium": null, "fiber": 1.23, "sugar": 9.08, "vitamin_a": null, "vitamin_c": 0, "calcium": 43.68, "iron": 0.72}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "flour", "notes": "1 cup all-purpose flour", "category": "baking"}, {"quantity": 0.75, "unit": "cup", "item": "flour", "notes": "3/4 cup whole-wheat flour", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "rolled oats", "notes": "1/2 cup rolled oats", "category": "cereal"}, {"quantity": 0.25, "unit": "cup", "item": "brown sugar", "notes": "1/4 cup packed brown sugar", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "baking powder", "notes": "2 teaspoons baking powder", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "baking soda", "notes": "1/2 teaspoon baking soda", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground cinnamon", "notes": "1/2 teaspoon ground cinnamon", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground allspice", "notes": "1/2 teaspoon ground allspice", "category": "spices and seasonings"}, {"quantity": 5.0, "unit": "tablespoons", "item": "butter", "notes": "5 tablespoons chilled butter, cut into small pieces", "category": "milk, eggs, other dairy"}, {"quantity": 0.75, "unit": "cup", "item": "nonfat-sour cream", "notes": "3/4 cup nonfat-sour cream (a little over ¾ cup is fine too)", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "teaspoons", "item": "vanilla extract", "notes": "2 teaspoons vanilla extract, divided", "category": "baking"}, {"quantity": 0.33333334, "unit": "cup", "item": "cranberries", "notes": "1/3 cup chopped dried cranberries", "category": "produce"}, {"quantity": 0.33333334, "unit": "cup", "item": "macadamia nuts", "notes": "1/3 cup coarsely chopped macadamia nuts", "category": "nuts"}, {"quantity": 0.5, "unit": "cup", "item": "powdered sugar", "notes": "1/2 cup powdered sugar", "category": "baking"}, {"quantity": 4.0, "unit": "teaspoons", "item": "milk", "notes": "4 teaspoons reduced-fat milk", "category": "milk, eggs, other dairy"}, {"quantity": 3.0, "unit": "tablespoons", "item": "raspberry jam", "notes": "3 tablespoons raspberry jam - sugar free", "category": "nut butters, jams, and honey"}]'::jsonb, '["Preheat oven to 400 F", "Place oats in a food processor. Process until finely ground", "Add flours, brown sugar, baking powder, baking soda, salt, cinnamon, and allspice to a food processor. Pulse 3 times", "Add butter; pulse 5 times until mixture resembles coarse meal. Be very careful - Don''t over beat.", "Add 1 tsp vanilla and sour cream; pulse 3 times or just until combined ( DO NOT over-mix). If you''re afraid you might over-mix, you can transfer the mixture into a big bowl and add sour cream and vanilla. Use spatula to mix. If you over-mix, the mixture will be too runny.", "Add cranberries, and nuts. Use spatula to mix well.", "Turn dough out onto a lightly floured surface; knead lightly 3 times.", "Roll dough to a 1/2 inch thickness; cut with a 2 1/2 inch biscuit cutter", "Place cut dough on a baking sheet. Use a watermelon scoop or small round spoon to press in a middle of each cut though to make a half hole for raspberry jam", "Mix together jam and the remaining vanilla extract.", "Add 1/2 teaspoon of jam into a hole. Don''t over put it otherwise it will run all over a scone.", "Bake for 14 minutes or until golden brown.", "Remove from baking sheet; transfer to a wire rack", "While they''re cooling, combine powdered sugar and milk. Stir with a whisk until smooth.", "Drizzle the glaze evenly over scones."]'::jsonb, 'https://www.foodista.com/recipe/J2745NV4/raspberry-thumbprint-wholewheat-scones-with-macadamia-nuts', 'https://img.spoonacular.com/recipes/657907-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vegetarian-mushroom-shepherds-pie', 'Vegetarian Mushroom Shepherd''s Pie', 12, 0, 0, '{"calories": 113, "protein": 4.77, "carbs": 23.59, "fat": 4.96, "saturated_fat": 0.85, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 220.57, "potassium": null, "fiber": 5.36, "sugar": 6.3, "vitamin_a": null, "vitamin_c": 30.59, "calcium": 27.6, "iron": 1.74}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "kg", "item": "skin potatoes", "notes": "1 kg red skin potatoes", "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "soy granules", "notes": "100g soy granules", "category": "health foods"}, {"quantity": 1.0, "unit": "kg", "item": "mushrooms", "notes": "1 kg mushrooms", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "carrot", "notes": "1 carrot", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 red bell pepper", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "onions", "notes": "2 onions, diced", "category": "produce"}, {"quantity": 1.0, "unit": "bunch", "item": "dill", "notes": "1 bunch of dill, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "bunch", "item": "parsley", "notes": "1 bunch of parsley, chopped", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs ( or egg substitutes for vegans, you can also add 3-4 tbsp dry yeast flakes)", "category": "baking"}, {"quantity": 12.0, "unit": "servings", "item": "sea salt", "notes": "sea salt, to taste", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "ground pepper", "notes": "1/2 tsp ground pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "paprika", "notes": "1 tsp sweet paprika", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tbsp", "item": "thyme", "notes": "1 tbsp dry thyme", "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "unrefined sunflower oil", "notes": "2 tbsp unrefined sunflower oil", "category": "oil, vinegar, salad dressing"}]'::jsonb, '["Peel potatoes and put them in a large pot filled with water. Boil them until they''re tender. Mash them and let them cool for a while.", "Chop the mushrooms, carrot and red bell pepper.", "Add them into your food processor and pulse until all ingredients are well mixed together.", "Heat oil in a large skillet.", "Add the mixture above, diced onions, chopped dill and parsley, soy granules, eggs (or egg substitute) and spices. Saut for 10 minutes.", "* I added the soy granules without boiling them because the mushrooms contain a lot of water and these soy granules will absorb all excess water.", "Put some parchment paper on the bottom of a casserole. Divide the mashed potatoes in two.", "Place the first half in the casserole and spread it with a spatula.", "Add the filling.", "Place over the other half of mashed potatoes.", "Heat your oven at 39", "Put the casserole in the oven. Cook for 40 minutes.", "Don''t serve immediately.", "Let it cool for at least half an hour."]'::jsonb, 'https://www.foodista.com/recipe/Q8LZSX4D/vegetarian-mushroom-shepherd-s-pie-with-vegan-version', 'https://img.spoonacular.com/recipes/664680-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lean-shepherds-pie', 'Lean Shepherd''s Pie', 4, 0, 0, '{"calories": 611, "protein": 44.1, "carbs": 51.05, "fat": 26.27, "saturated_fat": 13.7, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1038.49, "potassium": null, "fiber": 6.41, "sugar": 5.95, "vitamin_a": null, "vitamin_c": 43.64, "calcium": 442.71, "iron": 4.73}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'spoonacular', 'dessert', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "cup", "item": "chicken broth", "notes": "1 cup chicken broth", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "cups", "item": "corn kernels", "notes": "2 cups corn kernels", "category": "produce"}, {"quantity": 1.0, "unit": "pound", "item": "ground beef", "notes": "1 pound lean ground beef", "category": "meat"}, {"quantity": 2.0, "unit": "tablespoons", "item": "onion", "notes": "2 tablespoons chopped onion", "category": "produce"}, {"quantity": 4.0, "unit": "medium", "item": "potatoes", "notes": "4 mediums potatoes, peeled and quartered", "category": "produce"}, {"quantity": 8.0, "unit": "ounces", "item": "reduced fat cheddar cheese", "notes": "8 ounces reduced fat cheddar cheese, grated", "category": "cheese"}, {"quantity": 4.0, "unit": "servings", "item": "salt", "notes": "Salt to taste", "category": "spices and seasonings"}]'::jsonb, '["Brown ground beef with onion", "Cook potatoes in water till soft, drain", "Mash potatoes, add chicken broth as needed to make smooth mashed potatoes", "Spread browned ground beef in bottom of 8x11 Pyrex dish", "Spread mashed potatoes over beef layer", "Spead corn kernels over mashed potato layer", "Sprinkle grated cheese over corn layer", "Bake at 350 for 25-30 minutes or until heated through and cheese is melted", "When the pie comes out of the oven, lightly dust the top with a little pepper if desired."]'::jsonb, 'https://www.foodista.com/recipe/L64TMDV2/lean-shepherds-pie', 'https://img.spoonacular.com/recipes/649395-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('easy-shepherds-pie-beef-andor-lamb-combo', 'Easy Shepherd''s Pie (Beef And/or Lamb Combo)', 6, 0, 0, '{"calories": 643, "protein": 29.48, "carbs": 36.05, "fat": 42.53, "saturated_fat": 18.78, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 306.45, "potassium": null, "fiber": 5.18, "sugar": 5.02, "vitamin_a": null, "vitamin_c": 40.97, "calcium": 88.51, "iron": 4.88}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'dessert', 'soup', 'baking'], '[{"quantity": 1.0, "unit": "cup", "item": "beef stock", "notes": "1 cup beef stock or broth", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tablespoons", "item": "butter", "notes": "2 tablespoons butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "", "item": "carrot", "notes": "1 carrot, peeled and finely chopped", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "cream cheese", "notes": "2 tablespoons cream cheese (or sour cream)", "category": "cheese"}, {"quantity": 1.0, "unit": "large", "item": "egg yolk", "notes": "1 large egg yolk", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "tablespoons", "item": "flour", "notes": "2 tablespoons all-purpose flour", "category": "baking"}, {"quantity": 2.0, "unit": "tablespoons", "item": "parsley leaves", "notes": "2 tablespoons chopped fresh parsley leaves, for garnish", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "thyme", "notes": "2 teaspoons thyme (fresh or dried)", "category": "produce"}, {"quantity": 1.75, "unit": "pounds", "item": "ground lamb", "notes": "1 3/4 pounds ground beef or ground lamb*", "category": "meat"}, {"quantity": 0.5, "unit": "cup", "item": "1%% milk", "notes": "1/2 cup 1%% milk (or heavy cream for richer flavor)", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "olive oil", "notes": "1 tablespoon extra-virgin olive oil, 1 turn of the pan", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 onion, chopped", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "to 1 peas", "notes": "1/2 cup to 1 frozen peas, a couple of handfuls", "category": "produce"}, {"quantity": 2.0, "unit": "pounds", "item": "potatoes", "notes": "2 pounds potatoes, such as russet, peeled and cubed", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "paprika", "notes": "1 teaspoon sweet paprika", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "tomato paste", "notes": "2 tablespoons tomato paste", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "teaspoons", "item": "worcestershire", "notes": "2 teaspoons Worcestershire, eyeball it", "category": "condiments"}]'::jsonb, '["Boil potatoes in salted water until tender, about 12 minutes.", "Drain potatoes and pour them into a bowl.", "Combine cream cheese (or sour cream), egg yolk and milk (or heavy cream).", "Add the cream mixture into potatoes and mash until potatoes are almost smooth.While potatoes boil, preheat a large skillet over medium high heat.", "Add oil to hot pan with beef and/or lamb.Season meat with salt and pepper. Brown and crumble meat for 3 or 4 minutes. If you are using lamb and the pan is fatty, spoon away some of the drippings.", "Add chopped carrot* and onion to the meat. Cook veggies with meat 5 minutes, stirring frequently.NOTE:*by finely chopping the carrots, they will cook a little faster.", "Add the thyme.OPTIONAL", "Add the tomato paste, which gives the meat filling a richer flavor.In a second small skillet over medium heat cook butter and flour together 2 minutes.", "Whisk in broth and Worcestershire sauce. Thicken gravy 1 minute.", "Add gravy to meat and vegetables. Stir in peas.Preheat broiler to high.Fill a small rectangular casserole with meat and vegetable mixture. Spoon potatoes over meat evenly.Top potatoes with paprika and broil 6 to 8 inches from the heat until potatoes are evenly browned. Top casserole dish with chopped parsley and serve"]'::jsonb, 'https://www.foodista.com/recipe/MZ6R763H/easy-shepherds-pie-beef-andor-lamb-combo', 'https://img.spoonacular.com/recipes/642091-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bridget-joness-shepherds-pie', 'Bridget Jones''s Shepherd''s Pie', 4, 0, 0, '{"calories": 817, "protein": 31.2, "carbs": 39.9, "fat": 59.25, "saturated_fat": 26.67, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 264.81, "potassium": null, "fiber": 5.1, "sugar": 4.44, "vitamin_a": null, "vitamin_c": 40.23, "calcium": 91.89, "iron": 4.36}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'lunch', 'main course', 'main dish', 'dinner', 'spoonacular', 'dessert', 'soup', 'baking'], '[{"quantity": 2.0, "unit": "", "item": "onions", "notes": "2 onions, finely chopped", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 600.0, "unit": "grams", "item": "lamb", "notes": "600 grams minced lamb", "category": "meat"}, {"quantity": 2.0, "unit": "tablespoons", "item": "flour", "notes": "2 tablespoons plain flour", "category": "baking"}, {"quantity": 4.0, "unit": "servings", "item": "thyme", "notes": "thyme", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "rosemary", "notes": "rosemary", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "small", "item": "tomatoes", "notes": "1 small tin chopped tomatoes", "category": "canned and jarred"}, {"quantity": 100.0, "unit": "milliliters", "item": "lamb stock", "notes": "100 milliliters chicken, beef or lamb stock", "category": "gourmet"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 700.0, "unit": "grams", "item": "potatoes", "notes": "700 grams potatoes", "category": "produce"}, {"quantity": 55.0, "unit": "milliliters", "item": "milk", "notes": "55 milliliters milk", "category": "milk, eggs, other dairy"}, {"quantity": 75.0, "unit": "grams", "item": "butter", "notes": "75 grams butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "", "item": "egg yolk", "notes": "1 free-range egg yolk", "category": "milk, eggs, other dairy"}]'::jsonb, '["Preheat the oven to 180 C.", "In a large frying pan, heat a little olive oil and fry the chopped onion and garlic.", "Add the mince, stirring, until browned all over.", "While the meat is frying, break up any lumps with the back of the spoon.", "Add the flour (this helps to thicken the juices) and stir.", "Mix well and add the thyme and the rosemary and stir.", "Add the chopped tomatoes and pour the stock mixture.", "Add a pinch of salt and freshly ground black pepper and let it simmer for about 5 minutes.", "For the mash, boil the potatoes, then drain them in a sieve and place into a clean bowl.", "Add the milk, butter and egg yolk, and mash together.", "Season with salt and freshly ground black pepper.", "Pour the meat into an ovenproof dish and spread the mash on top, smooth over and mark with a spatula.", "Put the dish into the oven and cook until the surface is bubbling and golden-brown."]'::jsonb, 'https://www.foodista.com/recipe/GSQRFN7D/bridget-joness-shepherds-pie', 'https://img.spoonacular.com/recipes/636096-312x231.jpg', TRUE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('classic-scones', 'Classic scones', 4, 0, 0, '{"calories": 398, "protein": 9.17, "carbs": 61.26, "fat": 12.65, "saturated_fat": 7.43, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 26.41, "potassium": null, "fiber": 1.72, "sugar": 12.1, "vitamin_a": null, "vitamin_c": 1.76, "calcium": 72.65, "iron": 0.66}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 0.75, "unit": "cup", "item": "milk", "notes": "3/4 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "cups", "item": "self raising flour", "notes": "2 cups self raising flour", "category": "baking"}, {"quantity": 4.0, "unit": "servings", "item": "strawberry jam and cream", "notes": "strawberry jam and cream, for serving", "category": "nut butters, jams, and honey"}, {"quantity": 50.0, "unit": "g", "item": "butter", "notes": "50g unsalted butter, softened", "category": "milk, eggs, other dairy"}]'::jsonb, '["Using fingertips, rub butter into flour until mixture resembles fine breadcrumbs.Make a well in the centre of the dry ingredients and add milk, stirring with a metal spatula or butter knife until mixture comes away from the sides of the bowl. If mixture is dry, add a little extra milk.Turn mixture onto a lightly floured bench and bring the dough together until a rough ball of dough is formed. Do not over-knead. Pat dough to 2 cm thickness. With a clean knife, quarter the dough or use a round cutter to cut rounds.Arrange scones onto a baking paper lined tray and bake at 220C for 12-15 minutes until golden and they sound hollow when lightly tapped on the base.", "Serve scones straight from the oven with jam and cream."]'::jsonb, 'https://www.foodista.com/recipe/8R27PR6L/classic-scones', 'https://img.spoonacular.com/recipes/639637-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cheesy-potato-corn-scones', 'Cheesy Potato Corn Scones', 8, 0, 0, '{"calories": 247, "protein": 7.34, "carbs": 27.93, "fat": 12.01, "saturated_fat": 6.81, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 463.69, "potassium": null, "fiber": 1.87, "sugar": 1.17, "vitamin_a": null, "vitamin_c": 4.05, "calcium": 249.15, "iron": 1.55}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 0.6666667, "unit": "cup", "item": "water", "notes": "2/3 cup water", "category": "beverages"}, {"quantity": 0.6666667, "unit": "cup", "item": "potato flakes", "notes": "2/3 cup instant mashed potato flakes", "category": "pasta and rice"}, {"quantity": 0.25, "unit": "cup", "item": "butter", "notes": "1/4 cup cold unsalted butter, diced", "category": "milk, eggs, other dairy"}, {"quantity": 1.25, "unit": "cups", "item": "flour", "notes": "1 1/4 cups all-purpose flour", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "cornmeal", "notes": "1/2 cup yellow cornmeal", "category": "ethnic foods"}, {"quantity": 4.0, "unit": "ounces", "item": "cheddar cheese", "notes": "1 cup shredded cheddar cheese (4 ounces)", "category": "cheese"}, {"quantity": 4.0, "unit": "teaspoons", "item": "baking powder", "notes": "4 teaspoons baking powder", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "poppy seeds", "notes": "1 teaspoon poppy seeds", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "milk", "notes": "1/2 cup milk", "category": "milk, eggs, other dairy"}]'::jsonb, '["Lightly greased a baking sheet; set aside.  In a small saucepan, bring the water just to a simmer; remove from heat.  Stir in potato flakes until moistened.  Stir in butter until it''s incorporated to potato flakes.", "In a large bowl, combine flour, cornmeal, 3/4 cup of the cheese, baking powder, salt, and poppy seeds; stir in potato mixture and milk.  With floured hand, gently knead and fold the dough for five to six strokes, or until the dough comes together in one mass.  Pat the dough lightly to flatten it into a 9-inch circle on prepared baking sheet.", "Cut dough into eight wedges using a pizza cutter or floured knife (do not separate).", "Sprinkle edges with remaining cheese.", "Bake in a preheated 400 degree F oven for about 25 minutes or until lightly browned.  Gently pull or cut scones to separate.", "Serve warm."]'::jsonb, 'https://www.foodista.com/recipe/8NXFR4H8/cheesy-potato-corn-scones', 'https://img.spoonacular.com/recipes/637675-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('parmesan-cheese-scones', 'Parmesan Cheese Scones', 8, 0, 0, '{"calories": 245, "protein": 7.7, "carbs": 16.14, "fat": 16.86, "saturated_fat": 9.93, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 433.41, "potassium": null, "fiber": 0.79, "sugar": 1.49, "vitamin_a": null, "vitamin_c": 1.4, "calcium": 208.28, "iron": 1.24}'::jsonb, ARRAY['english', 'british', 'scottish', 'european', 'morning meal', 'brunch', 'breakfast', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "teaspoons", "item": "baking powder", "notes": "2 teaspoons Baking powder", "category": "baking"}, {"quantity": 2.0, "unit": "large", "item": "eggs", "notes": "2 large Eggs, lightly beaten", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "flour", "notes": "1 cup all-purpose flour", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "milk", "notes": "1/2 cup Milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.75, "unit": "cup", "item": "onion", "notes": "3/4 cup Onion, finely chopped", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "oregano", "notes": "1 teaspoon Dried oregano", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "parmesan cheese", "notes": "1 cup Freshly-grated Parmesan cheese", "category": "cheese"}, {"quantity": 0.25, "unit": "teaspoon", "item": "salt", "notes": "1/4 teaspoon Salt", "category": "spices and seasonings"}, {"quantity": 0.75, "unit": "teaspoon", "item": "tabasco sauce", "notes": "3/4 teaspoon Tabasco sauce", "category": "condiments"}, {"quantity": 0.5, "unit": "cup", "item": "butter", "notes": "1/2 cup unsalted butter (cold)", "category": "milk, eggs, other dairy"}]'::jsonb, '["Preheat oven to 400F degrees. Grease baking sheet; set aside.", "Combine flour, cheese, baking powder, oregano and salt in large bowl or food processor.", "Cut in butter with pastry blender, two knives or pulses of the food processor until mixture resembles coarse crumbs. (If blended in food processor, transfer mixture to large bowl.)", "Combine milk, eggs and Tabasco sauce in small bowl until well blended; stir into flour mixture just until moistened. Stir in onion. (The dough will be sticky.)", "Place dough onto center of prepared baking sheet; pat dough into 9\" circle.", "Cut circle into 8 wedges.", "Bake 20-25 minutes or until golden brown and wooden pick inserted in center comes out clean.", "Remove from pan. Cool on wire rack 10 minutes.", "Serve warm or cool completely."]'::jsonb, 'https://www.foodista.com/recipe/Z8XTFW6J/parmesan-cheese-scones', 'https://img.spoonacular.com/recipes/654657-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('green-monster-ice-pops', 'Green Monster Ice Pops', 6, 0, 0, '{"calories": 109, "protein": 1.72, "carbs": 14.96, "fat": 5.88, "saturated_fat": 0.77, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 92.11, "potassium": null, "fiber": 3.61, "sugar": 9.37, "vitamin_a": null, "vitamin_c": 17.9, "calcium": 93.14, "iron": 0.57}'::jsonb, ARRAY['dessert', 'gluten free', 'dairy free', 'spoonacular', 'vegetarian'], '[{"quantity": 1.5, "unit": "cup", "item": "almond milk", "notes": "1 1/2 cup unsweetened almond milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "", "item": "avocado", "notes": "1 avocado", "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "baby spinach", "notes": "2 cups baby spinach", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "banana", "notes": "1 banana", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "honey", "notes": "1 tablespoon honey", "category": "nut butters, jams, and honey"}, {"quantity": 1.0, "unit": "cup", "item": "mango", "notes": "1 cup mango, fresh or frozen", "category": "produce"}]'::jsonb, '["Place all ingredients into a blender and mix well.Taste the smoothie. If you find that it is not sweet enough, add 1 to 2 tablespoons of maple syrup or honey into the smoothie and blend.", "Pour smoothie into the ice pop molds. Insert a wooden popsicle stick into the mold, leaving about a quarter of the stick above the mold.", "Place the molds into the freezer for 2-3 hours to let freeze before serving."]'::jsonb, 'https://www.foodista.com/recipe/3584LCSQ/green-monster-ice-pops', 'https://img.spoonacular.com/recipes/645479-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('caramel-peanut-fudge-cake', 'Caramel Peanut Fudge Cake', 10, 0, 0, '{"calories": 459, "protein": 15.8, "carbs": 39.85, "fat": 35.12, "saturated_fat": 15.72, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 54.0, "potassium": null, "fiber": 14.7, "sugar": 17.57, "vitamin_a": null, "vitamin_c": 0, "calcium": 119.1, "iron": 5.55}'::jsonb, ARRAY['dessert', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 100.0, "unit": "g", "item": "almonds", "notes": "100g almonds, finely ground", "category": "nuts"}, {"quantity": 25.0, "unit": "g", "item": "cocoa", "notes": "25g cocoa", "category": "baking"}, {"quantity": 300.0, "unit": "g", "item": "chocolate of at least cocoa parts", "notes": "300g chocolate of at least 70% cocoa parts", "category": "baking"}, {"quantity": 500.0, "unit": "ml", "item": "cream", "notes": "500ml cream", "category": "milk, eggs, other dairy"}, {"quantity": 6.0, "unit": "", "item": "eggs", "notes": "6 eggs, egg yolks separated from the egg whites", "category": "milk, eggs, other dairy"}, {"quantity": 150.0, "unit": "g", "item": "peanuts", "notes": "150g peanuts, coarsely chopped", "category": "nuts"}, {"quantity": 1.0, "unit": "Tbs", "item": "rum", "notes": "1 Tbs rum", "category": "alcoholic beverages"}, {"quantity": 150.0, "unit": "g", "item": "sugar", "notes": "150g sugar", "category": "baking"}, {"quantity": 2.0, "unit": "Tbs", "item": "water", "notes": "2 Tbs water", "category": "beverages"}]'::jsonb, '["For the sponge, beat egg yolks with sugar for 3-4 minutes until the mixture doubles in volume and becomes pale yellow.", "Whisk the egg whites until soft peaks form.Fold the egg whites gently into the egg yolks cream.Gently stir in almonds and cocoa.Lightly butter and flour a 20 round cake pan, line with parchment paper.", "Pour in the sponge mixture", "Bake in preheated oven at 180C for about 20 minutes or until done (the trick with a toothpick).Leave the cake to cool completely in the cake pan, then carefully remove it and split into two layers.For the caramel cream heat sugar and water over medium heat and cook, stirring occasionally, until the sugar dissolves and comes to a boil. Continue cooking, but without stirring, until mixture becomes golden amber in color.", "Remove from flame and set aside.Whip the cream, gradually stir in the caramel syrup.", "Add peanuts, stir and combine.", "Mixture must be smooth (at first it will foam up a little).", "Transfer the cream to a bowl to cool down to room temperature and thicken.For the ganache bring the cream just to a boil over medium-high heat; pour over chocolate.", "Let stand 10 minutes. Stir very gently for 3-4 minutes until smooth and glossy, incorporating the cream steadily, without overworking.Cool ganache for an hour or until completely chilled, then beat for 2-3 minutes or until it becomes fluffy and lighter in color. Do not overbeat because it will become too thick and not spreadable.To assemble the cake, first sprinkle each cake layer with half of the rum and water syrup.", "Spread the caramel cream over the bottom layer, cover with the top layer (wet side down).Immediately spread ganache over top and sides of cake."]'::jsonb, 'https://www.foodista.com/recipe/DFQVM7MF/caramel-peanut-cake', 'https://img.spoonacular.com/recipes/637016-312x231.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cacao-chia-pudding-with-avocado-mousse', 'Cacao chia pudding with avocado mousse', 1, 0, 0, '{"calories": 441, "protein": 19.11, "carbs": 38.47, "fat": 30.68, "saturated_fat": 6.97, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 385.89, "potassium": null, "fiber": 23.14, "sugar": 1.86, "vitamin_a": null, "vitamin_c": 10.58, "calcium": 575.42, "iron": 4.38}'::jsonb, ARRAY['dessert', 'gluten free', 'dairy free', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "almond milk", "notes": "1 cup unsweetened almond milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "", "item": "avocado", "notes": "1/2 ripe avocado", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "cacao powder", "notes": "2 tablespoons cacao powder", "category": "baking"}, {"quantity": 2.0, "unit": "tablespoons", "item": "chia seeds", "notes": "2 tablespoons of chia seeds", "category": "health foods"}, {"quantity": 1.0, "unit": "tablespoon", "item": "coconut milk", "notes": "1 tablespoon of coconut milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "psyllium husk", "notes": "1 teaspoon of psyllium husk", "category": "health foods"}, {"quantity": 2.0, "unit": "packets", "item": "stevia", "notes": "2 packets of stevia", "category": "baking"}, {"quantity": 3.0, "unit": "packets", "item": "stevia", "notes": "3 packets stevia", "category": "baking"}, {"quantity": 0.5, "unit": "scoop", "item": "vanilla protein powder", "notes": "1/2 scoop vanilla protein powder", "category": "health foods"}, {"quantity": 150.0, "unit": "mls", "item": "water", "notes": "150 mls water", "category": "beverages"}]'::jsonb, '["Add the chia seeds and psyllium in and slowly stir whilst adding the remainder almond milk. Put in the fridge overnight or for a few hours for the pudding to grow.for the mousse place the remainder ingredients in a blender and blend untill it becomes a thick mousse like consistancy.Take the premade cacao chia pudding and place in a glass bowltop with the avocado mousse"]'::jsonb, 'https://www.foodista.com/recipe/LYFSNZLB/cacao-chia-pudding-with-avocado-mousse', 'https://img.spoonacular.com/recipes/636676-312x231.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chocolate-pudding-rave-diet', 'Chocolate Pudding - Rave Diet', 3, 0, 0, '{"calories": 382, "protein": 6.35, "carbs": 51.35, "fat": 19.29, "saturated_fat": 1.79, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 14.35, "potassium": null, "fiber": 5.36, "sugar": 33.87, "vitamin_a": null, "vitamin_c": 1.89, "calcium": 116.67, "iron": 2.3}'::jsonb, ARRAY['dessert', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'breakfast', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "water", "notes": "2 cups cold water", "category": "beverages"}, {"quantity": 0.5, "unit": "cup", "item": "maple syrup", "notes": "1/2 cup maple syrup", "category": "cereal"}, {"quantity": 4.0, "unit": "tablespoons", "item": "corn flour", "notes": "4 tablespoons cornstarch or corn flour", "category": "baking"}, {"quantity": 3.0, "unit": "tablespoons", "item": "cocoa powder", "notes": "3 tablespoons cocoa powder", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "vanilla", "notes": "1 teaspoon vanilla", "category": "baking"}, {"quantity": 3.0, "unit": "servings", "item": "roasted hazelnuts", "notes": "chopped and roasted hazelnuts for topping", "category": "baking"}]'::jsonb, '["Combine water, maple syrup, cocoa, cornstarch or corn flour and vanilla together in a saucepan.", "Whisk smooth with a spoon or hand whisker.", "Cook over medium heat and stir constantly until pudding is very thick.", "Pour into dessert dishes and top with chopped hazelnuts.", "Cool and serve."]'::jsonb, 'https://www.foodista.com/recipe/MFW2SBXZ/chocolate-pudding-recipe-rave-diet', 'https://img.spoonacular.com/recipes/639177-312x231.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('raw-vegan-chocolate-and-raspberry-cake', 'Raw Vegan Chocolate and Raspberry Cake', 12, 0, 0, '{"calories": 565, "protein": 9.82, "carbs": 68.73, "fat": 32.8, "saturated_fat": 8.55, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 144.36, "potassium": null, "fiber": 9.18, "sugar": 43.81, "vitamin_a": null, "vitamin_c": 7.43, "calcium": 138.04, "iron": 2.85}'::jsonb, ARRAY['dessert', 'dairy free', 'spoonacular', 'vegetarian'], '[{"quantity": 12.0, "unit": "servings", "item": "crust", "notes": "Crust", "category": "refrigerated"}, {"quantity": 3.0, "unit": "cups", "item": "walnuts", "notes": "- 3 cups raw walnuts", "category": "baking"}, {"quantity": 0.6666667, "unit": "cup", "item": "cocoa / carob powder", "notes": "- 2/3 cup raw cocoa / carob powder", "category": "health foods"}, {"quantity": 1.0, "unit": "pinch", "item": "sea salt", "notes": "- a pinch of sea salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "dates", "notes": "- 1 cup dates, pitted", "category": "dried fruits"}, {"quantity": 12.0, "unit": "servings", "item": "chocolate cream", "notes": "Chocolate cream", "category": "frozen"}, {"quantity": 0.25, "unit": "cup", "item": "honey", "notes": "- 1/4 cup honey (or any other healthy sweetener)", "category": "nut butters, jams, and honey"}, {"quantity": 3.0, "unit": "", "item": "bananas", "notes": "- 3 bananas, ripe", "category": "produce"}, {"quantity": 0.33333334, "unit": "cup", "item": "cocoa/carob", "notes": "- 1/3 cup cocoa/carob", "category": "baking"}, {"quantity": 1.5, "unit": "cups", "item": "raspberries", "notes": "- about 1 1/2 cups raspberries", "category": "produce"}, {"quantity": 5.0, "unit": "tbsp", "item": "chocolate flakes)", "notes": "- 5 tbsp dark chocolate flakes( I used 85% cocoa)", "category": "baking"}]'::jsonb, '["Go to my blog for the full instructions: http://gourmandelle.com/raw-vegan-chocolate-and-raspberry-birthday-cake/"]'::jsonb, 'https://www.foodista.com/recipe/CDSD8KXF/raw-vegan-chocolate-and-raspberry-cake', 'https://img.spoonacular.com/recipes/658007-312x231.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('applesauce-carrot-cake-muffins', 'Applesauce Carrot Cake Muffins', 24, 0, 0, '{"calories": 271, "protein": 8.06, "carbs": 53.66, "fat": 3.77, "saturated_fat": 0.67, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 216.6, "potassium": null, "fiber": 6.59, "sugar": 14.76, "vitamin_a": null, "vitamin_c": 1.08, "calcium": 37.15, "iron": 2.52}'::jsonb, ARRAY['morning meal', 'dessert', 'brunch', 'breakfast', 'dairy free', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 3.0, "unit": "c", "item": "flour", "notes": "3 c. whole wheat flour", "category": "baking"}, {"quantity": 3.0, "unit": "tbsp", "item": "ground flax seed", "notes": "3 tbsp. ground flax seed (optional)", "category": "health foods"}, {"quantity": 2.0, "unit": "tsp", "item": "baking soda", "notes": "2 tsp. baking soda", "category": "baking"}, {"quantity": 2.0, "unit": "tsp", "item": "ground cinnamon", "notes": "2 tsp. ground cinnamon", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "ground nutmeg", "notes": "1/2 tsp. ground nutmeg", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "ground ginger", "notes": "1/2 tsp. ground ginger", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "salt", "notes": "1 tsp. salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "c", "item": "honey", "notes": "1 c. honey", "category": "nut butters, jams, and honey"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs, lightly beaten", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "tsp", "item": "vanilla extract", "notes": "2 tsp. pure vanilla extract", "category": "baking"}, {"quantity": 2.25, "unit": "c", "item": "applesauce", "notes": "2 1/4 c. unsweetened applesauce", "category": "canned and jarred"}, {"quantity": 1.5, "unit": "c", "item": "carrots", "notes": "1 1/2 c. shredded carrots", "category": "produce"}, {"quantity": 0.5, "unit": "c", "item": "cranberries", "notes": "1/2 c. cranberries (optional- or nuts would be good)", "category": "produce"}, {"quantity": 24.0, "unit": "servings", "item": "oats", "notes": "oats (to sprinkle on top)", "category": "cereal"}]'::jsonb, '["Preheat the oven to 350 degrees F. Lightly spray oil on two regular-size 12-cup muffin tins or two large 6-cup muffin tins.", "In a large bowl whisk together the flour, ground flax, baking soda, cinnamon, nutmeg, ginger and salt.", "Make a small well in the center of the dry ingredients and add the honey, eggs, vanilla and applesauce.", "Stir the ingredients together until just combined and there are still some spots of flour remaining.", "Fold in the shredded carrots and cranberries just until combined (don''t over mix or the muffins will be dense).", "Distribute the batter evenly among the muffin tin cups and sprinkle some oats on top.", "Bake for 20-24 min for large muffins (mine came out perfect at about 23 min) or 18-20 min. for regular-size muffins, until a toothpick inserted in the center of a muffin comes out clean.", "Remove to a wire rack to cool completely, Enjoy right away or make extra to freeze for a quick snack!"]'::jsonb, 'https://www.foodista.com/recipe/CTFGJLFC/applesauce-carrot-cake-muffins', 'https://img.spoonacular.com/recipes/632639-312x231.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('wholemeal-cake', 'Wholemeal Cake', 4, 0, 0, '{"calories": 362, "protein": 8.54, "carbs": 44.39, "fat": 14.23, "saturated_fat": 1.08, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 41.54, "potassium": null, "fiber": 4.06, "sugar": 25.98, "vitamin_a": null, "vitamin_c": 1.92, "calcium": 42.08, "iron": 2.01}'::jsonb, ARRAY['dessert', 'dairy free', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 3.0, "unit": "", "item": "egg whites", "notes": "3 Large egg whites (about 130g or slightly more)", "category": "milk, eggs, other dairy"}, {"quantity": 60.0, "unit": "g", "item": "sugar", "notes": "60g Sugar", "category": "baking"}, {"quantity": 90.0, "unit": "g", "item": "ground hazelnut", "notes": "90g Ground hazelnut", "category": "baking"}, {"quantity": 30.0, "unit": "g", "item": "brown sugar", "notes": "30g Brown sugar", "category": "baking"}, {"quantity": 25.0, "unit": "g", "item": "flour", "notes": "25g Plain flour", "category": "baking"}, {"quantity": 60.0, "unit": "g", "item": "wholemeal flour", "notes": "60g Wholemeal flour", "category": "baking"}, {"quantity": 65.0, "unit": "g", "item": "butter", "notes": "65g Melted butter with 1/2 tsp vanilla extract", "category": "baking"}, {"quantity": 20.0, "unit": "g", "item": "apricots and cranberries - cut to smaller pieces", "notes": "20g each Dried apricots and dried cranberries - cut to smaller pieces", "category": "produce"}]'::jsonb, '["In a large bowl, mix ground hazelnut, brown sugar, plain flour and wholemeal flour together and set aside.", "Whisk egg whites and sugar at medium high speed till firm and smooth.", "Use hand to fold one quarter of beaten egg whites to the flour mixture evenly and remaining egg white in two batches.", "Lastly add in melted butter in two batches and mix well with a rubber spatula follow by the dried apricots and dried cranberries.", "Pour mixture into a 7 inch (lined) round cake pan and sprinkle more dried apricots and dried cranberries over it.", "Bake at preheated oven 170C for about 30-35 minutes or until skewer inserted comes out clean. Leave cake to cool in pan for 15 minutes and remove to wire rack to cool down completely."]'::jsonb, 'https://www.foodista.com/recipe/JDYXYDJY/wholemeal-cake', 'https://img.spoonacular.com/recipes/665303-312x231.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('strawberry-cheesecake-chocolate-crepes', 'Strawberry Cheesecake Chocolate Crepes', 4, 20, 20, '{"calories": 618, "protein": 16.47, "carbs": 55.54, "fat": 37.95, "saturated_fat": 21.71, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 331.57, "potassium": null, "fiber": 4.16, "sugar": 14.57, "vitamin_a": null, "vitamin_c": 26.94, "calcium": 192.58, "iron": 3.76}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 8.0, "unit": "oz", "item": "cream cheese", "notes": "8 oz cream cheese", "category": "cheese"}, {"quantity": 1.25, "unit": "cup", "item": "strawberries", "notes": "1 1/4 cup diced strawberries", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "vanilla extract", "notes": "1 tsp vanilla extract", "category": "baking"}, {"quantity": 1.0, "unit": "tsp", "item": "lemon juice", "notes": "1 tsp lemon juice", "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "granulated sugar", "notes": "2 tbsp granulated sugar", "category": "baking"}, {"quantity": 1.5, "unit": "cups", "item": "flour", "notes": "1 1/2 cups all-purpose flour", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "cocoa powder", "notes": "1/4 cup cocoa powder unsweetened", "category": "baking"}, {"quantity": 0.125, "unit": "tsp", "item": "kosher salt", "notes": "1/8 tsp kosher salt", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "", "item": "eggs", "notes": "3 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.25, "unit": "cups", "item": "milk", "notes": "1 1/4 cups milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "water", "notes": "1/4 cup water", "category": "beverages"}, {"quantity": 4.0, "unit": "tbsp", "item": "butter", "notes": "4 tbsp unsalted butter melted", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "vanilla extract", "notes": "1/2 tsp vanilla extract", "category": "baking"}]'::jsonb, '["How to Make Strawberry Creme Cheese Filling", "Add cream cheese, strawberries, vanilla extract, lemon juice, and granulated sugar into a medium-sized mixing bowl.", "Use a hand mixer, wooden spoon, or spatula to mix ingredients.", "Mix until smooth.", "Set aside.", "How to Blend Chocolate Crepes Ingredients", "Combine flour, sugar, cocoa powder, salt, and eggs to a food processor or blender.", "If using a food processor, keep it running as you add milk and water. Continue to pulse intil blended well.", "Pour in melted butter and vanilla extract.", "Set bowl aside.", "How to Make Chocolate Crepes", "Heat crepe pan or 8\"-10\" omelet pan over medium heat.", "Pour 1/4 cup of batter directly into the middle of the pan and swirl to cover the bottom.", "Cook the crepe for 2-3 minutes or until the bottom is light brown and the edges are completely set.", "Flip the crepe over and cook for an additional minute.", "Transfer to a serving platter and repeat for the rest of the batter."]'::jsonb, 'https://www.pinkwhen.com/strawberry-cheesecake-chocolate-crepes/', 'https://img.spoonacular.com/recipes/715569-312x231.jpg', FALSE, 2, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fig-and-walnut-pudding', 'Fig and Walnut Pudding', 2, 0, 0, '{"calories": 540, "protein": 7.47, "carbs": 61.81, "fat": 34.57, "saturated_fat": 4.13, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 300.83, "potassium": null, "fiber": 12.29, "sugar": 46.71, "vitamin_a": null, "vitamin_c": 12.97, "calcium": 85.12, "iron": 1.99}'::jsonb, ARRAY['dessert', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "mission figs", "notes": "1 cup black mission figs", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "walnuts", "notes": "1/2 cup walnuts", "category": "baking"}, {"quantity": 1.0, "unit": "medium", "item": "avocado", "notes": "1 medium avocado", "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "unfiltered honey", "notes": "3 tablespoons unfiltered honey", "category": "nut butters, jams, and honey"}, {"quantity": 0.5, "unit": "", "item": "vanilla bean", "notes": "1/2 vanilla bean", "category": "baking"}, {"quantity": 1.0, "unit": "pinch", "item": "nutmeg", "notes": "pinch fresh grated nutmeg", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "himalayan salt", "notes": "1/4 teaspoon himalayan salt", "category": "gourmet"}]'::jsonb, '["Slice figs into quarters.", "Spoon out avocado into a blender along with all remaining ingredients.", "Blend on medium speed until creamy, using a tamper or spatula if necessary.", "Serve with fresh slices of figs and crushed walnut pieces."]'::jsonb, 'https://www.foodista.com/recipe/HQYSXMGL/fig-and-walnut-pudding', 'https://img.spoonacular.com/recipes/642780-312x231.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('blackberry-peach-pie', 'Blackberry Peach Pie', 10, 0, 0, '{"calories": 279, "protein": 5.48, "carbs": 61.7, "fat": 3.04, "saturated_fat": 0.79, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 57.86, "potassium": null, "fiber": 8.32, "sugar": 37.74, "vitamin_a": null, "vitamin_c": 24.47, "calcium": 41.29, "iron": 2.32}'::jsonb, ARRAY['dessert', 'dairy free', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.5, "unit": "cups", "item": "all purpose flour", "notes": "1 1/2 cups all purpose flour", "category": "baking"}, {"quantity": 4.0, "unit": "cups", "item": "blackberries", "notes": "4 cups fresh blackberries", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "lightly brown sugar", "notes": "1/4 cup lightly packed brown sugar", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "butter", "notes": "1 tablespoon butter or margarine", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "tablespoons", "item": "cornstarch", "notes": "2 tablespoons cornstarch", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "granulated sugar", "notes": "1/4 cup granulated sugar", "category": "baking"}, {"quantity": 0.75, "unit": "teaspoon", "item": "ground cinnamon", "notes": "3/4 teaspoon ground cinnamon", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "ice water", "notes": "- 1/2 cup ice water", "category": "beverages"}, {"quantity": 0.5, "unit": "", "item": "juice of lemon", "notes": "Juice of 1/2 lemon", "category": "produce"}, {"quantity": 9.0, "unit": "servings", "item": "gratings of nutmeg", "notes": "few gratings of fresh nutmeg", "category": "spices and seasonings"}, {"quantity": 10.0, "unit": "servings", "item": "blackberry peach pie", "notes": "Blackberry Peach Pie", "category": "produce"}, {"quantity": 3.0, "unit": "lbs", "item": "peaches", "notes": "5 large white (or yellow) peaches ( - 3 lbs), peeled & sliced into 1/3” wedges", "category": "produce"}, {"quantity": 1.0, "unit": "pinch", "item": "salt", "notes": "pinch of salt", "category": "spices and seasonings"}]'::jsonb, '["-Prepare Pie Dough-", "Combine flour, salt, and sugar in large bowl.  Meanwhile, cut up cold butter into cubes and place in separate bowl.", "Place both in freezer for 5-10 minutes to chill.", "Remove butter and flour from freezer.  Working quickly, use a pastry cutter (or your fingers) to incorporate butter into dry ingredients until butter resembles the size of small peas.Using a spatula, slowly stir in ice water.  Using hands, knead dough together briefly to form a ball (add an additional tablespoon of water at a time, if more is required).Divide dough in half, wrap tightly in plastic wrap, and allow to chill in fridge for roughly 2 hours.Prepare filling (see below) and preheat oven to 425 degrees.After dough has chilled, remove one disc of dough (roll bottom pie crust first).", "Place dough on a well floured surface, dust with more flour, and roll out evenly into a large, roughly 12-13 diameter discrotating the dough continuously as you go.  Fold into quarters and transfer to pie dish to unfold.  Using knife or kitchen scissors, trim any remaining overhang to one inch.", "Brush off any excess flour with a pastry brush.Repeat procedure above with remaining dough to form top pie crust.  Trim any overhang to the diameter of the pie dish.Fold the rim of the bottom crust over the top and crimp using a fork or your fingertips (for more detailed instructions, read this tutorial).Using a sharp paring knife, make several ~1 inch vents in pie dough.", "Place pie dish on foil-lined baking sheet (this prevents any juices from overflowing onto your oven floor and creating a smoke-filled kitchen) and bake for roughly 20 minutes.Turn down temperature to 375 degrees and continue to bake for another 30-40 minutes until crust is golden brown.  **If crust is beginning to brown too quickly, cover with a foil tent for remainder of baking time.", "Serve warm with a big scoop of vanilla ice cream (or allow to cool completely if you prefer a thicker, less runny pie)!-Filling-Bring medium saucepan of water to boil.  Using a paring knife, make a small X on the bottom of each peach and carefully drop into boiling water.  Allow to poach for roughly a minute (depending on the ripeness of your peaches), before removing and placing in a large bowl of ice water.Using paring knife, carefully peel skin from peaches and set aside.Once all peaches have been peeled, remove pits and slice into roughly 1/3 slices.", "Place in large bowl.", "Add blackberries and toss with lemon juice.In separate bowl, combine brown sugar, sugar, cinnamon, nutmeg, salt, and cornstarch.", "Add to fruit and stir to thoroughly coat.  Set aside.I promise, the most challenging part of this recipe will be waiting for it to cool down once it comes out of the oven.  Enjoy!"]'::jsonb, 'https://www.foodista.com/recipe/FB6VZC4K/blackberry-peach-pie', 'https://img.spoonacular.com/recipes/635228-312x231.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('creamy-chocolate-pudding-with-coconut-whipped-cream', 'Creamy Chocolate Pudding With Coconut Whipped Cream', 2, 0, 0, '{"calories": 843, "protein": 25.5, "carbs": 37.78, "fat": 68.6, "saturated_fat": 54.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 82.06, "potassium": null, "fiber": 7.51, "sugar": 20.88, "vitamin_a": null, "vitamin_c": 6.33, "calcium": 403.85, "iron": 6.24}'::jsonb, ARRAY['dessert', 'gluten free', 'dairy free', 'fodmap friendly', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "package", "item": "tofu", "notes": "1 package soft tofu", "category": "refrigerated"}, {"quantity": 5.0, "unit": "tbsp", "item": "chocolate chips", "notes": "5 tbsp. dark chocolate chips", "category": "baking"}, {"quantity": 1.0, "unit": "tbsp", "item": "non-dairy milk", "notes": "1 tbsp. non-dairy milk (almond, soy, rice)", "category": "other"}, {"quantity": 1.0, "unit": "can", "item": "coconut milk", "notes": "1 can coconut milk (chilled in fridge overnight)", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "tsp", "item": "vanilla extract", "notes": "1 tsp. vanilla extract", "category": "baking"}, {"quantity": 2.0, "unit": "servings", "item": "chocolate shavings", "notes": "chocolate shavings", "category": "baking"}]'::jsonb, '["Melt chocolate in a microwave safe container with non-dairy milk.", "Add melted chocolate with tofu in blender (I use a magic bullet).", "Blend until smooth.", "Put into serving dishes.", "Put 1 can of coconut milk in fridge overnight.", "Flip can upside down (do not shake!). Open can and pour coconut liquid into another container (do not need).", "Scoop out hardened coconut mixture into a separate bowl and whip.", "Add vanilla extract or a sweetener for added flavour.", "Add a spoonful of ''whipped cream'' topping onto pudding mixture and garnish with chocolate shavings or fruit if desired."]'::jsonb, 'https://www.foodista.com/recipe/YL46Y5ZH/creamy-chocolate-pudding-with-coconut-whipped-cream-vegan', 'https://img.spoonacular.com/recipes/640625-312x231.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('autumn-pumpkin-cake', 'Autumn Pumpkin Cake', 12, 0, 0, '{"calories": 131, "protein": 1.91, "carbs": 23.36, "fat": 3.91, "saturated_fat": 3.12, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 4.87, "potassium": null, "fiber": 1.12, "sugar": 6.94, "vitamin_a": null, "vitamin_c": 5.49, "calcium": 14.19, "iron": 1.24}'::jsonb, ARRAY['dessert', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 500.0, "unit": "g", "item": "pumpkin", "notes": "500g pumpkin, steamed", "category": "produce"}, {"quantity": 180.0, "unit": "g", "item": "brown rice flour", "notes": "180g brown rice flour (ground some brown rice)", "category": "health foods"}, {"quantity": 200.0, "unit": "ml", "item": "coconut milk", "notes": "200ml coconut milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "raisins", "notes": "1/4 cup raisins", "category": "produce"}, {"quantity": 100.0, "unit": "g", "item": "agave syrup", "notes": "100g agave syrup or Sucanat", "category": "ethnic foods"}]'::jsonb, '["Go to my blog for the full instructions: http://gourmandelle.com/pumpkin-cake-the-ideal-dessert-for-a-sunny-autumn-day/"]'::jsonb, 'https://www.foodista.com/recipe/5K5VD54Q/pumpkin-cake-the-ideal-dessert-for-a-sunny-autumn-day', 'https://img.spoonacular.com/recipes/633101-312x231.jpg', FALSE, 3, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well 