INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('coffee-chia-pudding', 'Coffee Chia Pudding', 2, 0, 0, '{"calories": 269, "protein": 8.31, "carbs": 27.22, "fat": 15.53, "saturated_fat": 1.6, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 91.91, "potassium": null, "fiber": 16.7, "sugar": 6.07, "vitamin_a": null, "vitamin_c": 0, "calcium": 390.77, "iron": 3.72}'::jsonb, ARRAY['dessert', 'gluten free', 'dairy free', 'fodmap friendly', 'spoonacular', 'breakfast', 'vegetarian'], '[{"quantity": 90.0, "unit": "ml", "item": "coffee", "notes": "90ml brewed coffee", "category": "tea and coffee"}, {"quantity": 120.0, "unit": "ml", "item": "almond milk", "notes": "120ml of unsweetened almond milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "maple syrup", "notes": "1 tablespoon of maple syrup", "category": "cereal"}, {"quantity": 8.0, "unit": "tablespoons", "item": "chia seeds", "notes": "8 tablespoons of chia seeds", "category": "health foods"}, {"quantity": 2.0, "unit": "drops", "item": "vanilla extract", "notes": "2 drops of vanilla extract", "category": "baking"}]'::jsonb, '["In a mixing bowl, add all of the ingredients and stir until fully combined.Fill your glasses or bowls with the chia pudding mixture and pop them into the fridge to chill for at least 4 hours or, better, overnight.If desired, you can add dairy free whipped cream on top (totally optional!)"]'::jsonb, 'https://www.foodista.com/recipe/JRRN2VFD/coffee-chia-pudding', 'https://img.spoonacular.com/recipes/1096302-312x231.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients 