INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('easy-strawberry-shortcake-for-one', 'Easy Strawberry Shortcake for One', 1, 0, 0, '{"calories": 141, "protein": 2.33, "carbs": 28.74, "fat": 2.68, "saturated_fat": 0.75, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 106.49, "potassium": null, "fiber": 2.96, "sugar": 16.22, "vitamin_a": null, "vitamin_c": 71.53, "calcium": 49.89, "iron": 1.08}'::jsonb, ARRAY['dessert', 'lacto ovo vegetarian', 'spoonacular'], '[{"quantity": 4.0, "unit": "tablespoons", "item": "cool whip", "notes": "4 tablespoons of cool whip", "category": "milk, eggs, other dairy"}, {"quantity": 10.0, "unit": "", "item": "strawberries", "notes": "10 strawberries", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "table sugar", "notes": "1 tsp table sugar", "category": "baking"}, {"quantity": 0.5, "unit": "tsp", "item": "lemon juice", "notes": "1/2 tsp lemon juice", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "graham cracker", "notes": "1 graham cracker", "category": "sweet snacks"}]'::jsonb, '["Wash strawberries.", "Remove the tops and then cut into slices from the top to the bottom.", "Mix the strawberry slices with the sugar and lemon juice and gently toss together. Set to the side", "Place 3 tablespoons of strawberries in the bottom of a small glass jar, top with  crumbled graham cracker, cover with 2 heaping tablespoons of cool whip. Repeat layers. End with cool whip and then use remaining crumbs over the top of the cool whip.Chill for 24 hours if possible, but it is ready to eat immediately if there is no time."]'::jsonb, 'https://www.foodista.com/recipe/MWQZV35T/marybruces-easy-strawberry-shortcak', 'https://img.spoonacular.com/recipes/1096301-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('strawberry-lime-basil-sherbet', 'Strawberry Lime Basil Sherbet', 6, 0, 0, '{"calories": 190, "protein": 5.16, "carbs": 35.15, "fat": 4.45, "saturated_fat": 2.29, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 48.84, "potassium": null, "fiber": 3.23, "sugar": 30.36, "vitamin_a": null, "vitamin_c": 95.5, "calcium": 180.51, "iron": 0.73}'::jsonb, ARRAY['dessert', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "sugar", "notes": "½ cup sugar", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "water", "notes": "¼ cup water", "category": "beverages"}, {"quantity": 0.5, "unit": "cup", "item": "basil", "notes": "1/2 cup chopped basil", "category": "produce"}, {"quantity": 1.0, "unit": "quart", "item": "strawberries", "notes": "1 quart strawberries, hulled and chopped", "category": "produce"}, {"quantity": 3.0, "unit": "cups", "item": "milk", "notes": "3 cups milk", "category": "milk, eggs, other dairy"}, {"quantity": 3.0, "unit": "tablespoons", "item": "lime juice", "notes": "3 -4 tablespoons lime juice", "category": "produce"}, {"quantity": 1.5, "unit": "teaspoon", "item": "lime zest", "notes": "1 ½ teaspoon lime zest", "category": "produce"}]'::jsonb, '["Place sugar, water, and basil in small pot.Gently boil until the sugar has dissolved, about 8 minutes.Take off heat and strain out the basil.Chill.To make the sherbet: Use a blender or immersion blender to puree the strawberries, milk, basil syrup, lime juice, and lime zest together.Churn in ice cream maker according to manufacturer''s directions.Note: This doesn''t freeze particularly well, so if you do freeze it, you may want to take out the sherbet 20 minutes before you serve."]'::jsonb, 'https://www.foodista.com/recipe/6RLPS4JJ/strawberry-lime-basil-sherbet', 'https://img.spoonacular.com/recipes/1096280-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('classic-carrot-cake-with-cream-cheese-frosting', 'Classic Carrot Cake With Cream Cheese Frosting', 8, 0, 0, '{"calories": 900, "protein": 13.05, "carbs": 67.38, "fat": 66.3, "saturated_fat": 29.23, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 870.53, "potassium": null, "fiber": 4.58, "sugar": 36.63, "vitamin_a": null, "vitamin_c": 3.59, "calcium": 193.0, "iron": 2.82}'::jsonb, ARRAY['dessert', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "teaspoons", "item": "baking powder", "notes": "2 teaspoons baking powder", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "baking soda", "notes": "2 teaspoons baking soda", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "buttermilk", "notes": "1/2 cup buttermilk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "pound", "item": "carrots", "notes": "1 pound carrots, peeled and coarsely shredded", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "cinnamon", "notes": "1 teaspoon cinnamon", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cups", "item": "confectioners'' sugar", "notes": "2 cups confectioners'' sugar", "category": "baking"}, {"quantity": 16.0, "unit": "ounces", "item": "cream cheese", "notes": "2 8-ounces packages cream cheese, softened", "category": "cheese"}, {"quantity": 4.0, "unit": "large", "item": "eggs", "notes": "4 large eggs", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "cups", "item": "flour", "notes": "2 cups all-purpose flour", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "pecans", "notes": "1/2 cup chopped pecans (optional)", "category": "savory snacks"}, {"quantity": 4.0, "unit": "ounces", "item": "pecans", "notes": "1 cup 1 pecans (4 ounces)", "category": "baking"}, {"quantity": 0.75, "unit": "teaspoon", "item": "salt", "notes": "3/4 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sugar", "notes": "1 teaspoon sugar", "category": "baking"}, {"quantity": 2.0, "unit": "sticks", "item": "butter", "notes": "2 sticks unsalted butter, softened", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "vanilla extract", "notes": "1 tablespoon pure vanilla extract", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "vegetable oil", "notes": "1 cup vegetable oil", "category": "oil, vinegar, salad dressing"}]'::jsonb, '["Preheat the oven to 32", "Spread the pecans on a baking sheet and toast for 8 minutes, until fragrant. Cool and finely chop.In a bowl, whisk the flour, baking powder, baking soda, cinnamon and salt.In a small bowl, whisk the oil, buttermilk and vanilla.In a large bowl, using an electric mixer, beat the eggs and sugar at high speed until pale, 5 minutes.Beat in the liquid ingredients, then beat in the dry ingredients just until moistened.Stir in the carrots and pecans.Divide the batter between the pans and bake the cakes for 55 minutes to 1 hour, until springy and golden.", "Let the cakes cool on a rack for 30 minutes, then unmold the cakes and let cool completely.For the Frosting:In a large bowl, using an electric mixer, beat the butter and cream cheese at high speed until light, about 5 minutes.Beat in the vanilla, then the confectioners'' sugar; beat at low speed until incorporated. Increase the speed to high and beat until light and fluffy, about 3 minutes.Peel off the parchment paper and invert one cake layer onto a plate.", "Spread with a slightly rounded cup of the frosting. Top with the second cake layer, right side up.", "Spread the top and sides with the remaining frosting and refrigerate the cake until chilled, about 1 hour."]'::jsonb, 'https://www.foodista.com/recipe/8777NMTV/classic-carrot-cake-with-cream-cheese-frosting', 'https://img.spoonacular.com/recipes/639580-312x231.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('muesli-cookies', 'Muesli Cookies', 8, 0, 0, '{"calories": 413, "protein": 7.01, "carbs": 77.46, "fat": 12.37, "saturated_fat": 1.44, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 294.04, "potassium": null, "fiber": 6.04, "sugar": 43.43, "vitamin_a": null, "vitamin_c": 2.7, "calcium": 85.15, "iron": 3.24}'::jsonb, ARRAY['dessert', 'dairy free', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.5, "unit": "cups", "item": "flour", "notes": "1 1/2 cups whole wheat flour", "category": "baking"}, {"quantity": 1.5, "unit": "cups", "item": "muesli", "notes": "1 1/2 cups muesli", "category": "cereal"}, {"quantity": 1.5, "unit": "tsp", "item": "baking powder", "notes": "1 1/2 tsp baking powder", "category": "baking"}, {"quantity": 0.5, "unit": "tsp", "item": "salt", "notes": "1/2 tsp salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "ginger root", "notes": "1 ginger root (peeled and grated)", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "ground ginger", "notes": "1 tsp ground ginger", "category": "spices and seasonings"}, {"quantity": 1.5, "unit": "tsp", "item": "cinnamon", "notes": "1 1/2 tsp cinnamon", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "nutmeg", "notes": "1/2 tsp nutmeg", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "anise star", "notes": "1 anise star (crushed)", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "raisins", "notes": "1/2 cup raisins", "category": "produce"}, {"quantity": 1.0, "unit": "large", "item": "apple", "notes": "1 large apple (chopped into small pieces)", "category": "produce"}, {"quantity": 1.0, "unit": "large", "item": "carrot", "notes": "1 large carrot (grated)", "category": "produce"}, {"quantity": 1.0, "unit": "large", "item": "egg", "notes": "1 large whole egg", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "honey", "notes": "1 cup honey", "category": "nut butters, jams, and honey"}, {"quantity": 1.0, "unit": "cup", "item": "walnut oil", "notes": "1 cup walnut oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.5, "unit": "cup", "item": "walnuts", "notes": "1/2 cup crushed walnuts", "category": "baking"}]'::jsonb, '["Preheat the oven to 175 degrees Celsius.In a large bowl, combine the flour, muesli, baking powder, salt, ground ginger, cinnamon, nutmeg, anise, and raisins.In another bowl, use a mixer to beat the egg and oil until the mixture is homogenized.", "Add the honey and mix again.Gradually, add the dry mixture to the wet mixture while stirring. You can mix by hand.When everything is combined, add the grated ginger, chopped apple, grated carrot, and walnuts. Stir everything again.When the mixture is ready, scoop out some of it with a spoon, place on the greased baking tray, and form a cookie. Use a fork to push down each one.", "Bake them for about 15 minutes.", "Remove from the oven,wait for 3-4 min to cool down and use spatula to place the cooked cookies on serving plate.", "Serve and enjoy!"]'::jsonb, 'https://www.foodista.com/recipe/63SRZ55B/homemade-cookies', 'https://img.spoonacular.com/recipes/1095878-312x231.jpg', FALSE, 5, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sholeh-zard-saffron-infused-rice-pudding', 'Sholeh Zard: Saffron Infused Rice Pudding', 12, 0, 0, '{"calories": 528, "protein": 14.25, "carbs": 46.67, "fat": 34.85, "saturated_fat": 5.9, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 47.24, "potassium": null, "fiber": 8.52, "sugar": 21.15, "vitamin_a": null, "vitamin_c": 1.96, "calcium": 153.48, "iron": 2.71}'::jsonb, ARRAY['dessert', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'vegetarian'], '[{"quantity": 12.0, "unit": "servings", "item": "almonds", "notes": "Almonds", "category": "nuts"}, {"quantity": 1.0, "unit": "cup", "item": "basmati rice", "notes": "1 cup basmati rice", "category": "pasta and rice"}, {"quantity": 5.0, "unit": "tablespoons", "item": "butter", "notes": "5 tablespoons butter", "category": "milk, eggs, other dairy"}, {"quantity": 12.0, "unit": "servings", "item": "candied orange peel", "notes": "Candied Orange peel", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "cardamom powder", "notes": "1 teaspoon cardamom powder", "category": "spices and seasonings"}, {"quantity": 12.0, "unit": "servings", "item": "cinnamon", "notes": "Cinnamon", "category": "spices and seasonings"}, {"quantity": 12.0, "unit": "servings", "item": "edible flowers", "notes": "Edible flowers", "category": "produce"}, {"quantity": 12.0, "unit": "servings", "item": "pistachios", "notes": "Pistachios", "category": "savory snacks"}, {"quantity": 0.5, "unit": "cup", "item": "rose water", "notes": "1/2 cup rose water", "category": "gourmet"}, {"quantity": 0.5, "unit": "teaspoon", "item": "saffron", "notes": "1/2 teaspoon saffron", "category": "gourmet"}, {"quantity": 0.5, "unit": "cup", "item": "slivered almonds", "notes": "1/2 cup slivered almonds", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "sugar", "notes": "1 cup sugar", "category": "baking"}, {"quantity": 7.0, "unit": "cups", "item": "water", "notes": "7 cups water", "category": "beverages"}]'::jsonb, '["Wash the rice with cold water several times. Until the water is clear.In a heavy bottom pot, add the rice and 5 cups water. Bring to a boil.It is recommended that you skim the foam off the top as it rises.Cover and let it simmer on medium heat for about a half hour.Once the rice has softened, add 2 more cups of water and the sugar.Cover and cook for 30 more minutes, stirring occasionally to make sure the sugary rice is not sticking to the bottom of the pot.", "Add the almonds, saffron water, butter, cardamom powder, and rose water.", "Mix and cover on low heat for another half hour.Check to see if it has become thick.", "Remove lid and on low heat cook until the mixture becomes pudding-like.At this point, you can ladle some either into individual heat resistance dishes or into a larger serving dish.Decorate.Cool in fridge and serve cold."]'::jsonb, 'https://www.foodista.com/recipe/Y6JN2Q6W/sholeh-zard-saffron-infused-rice-pudding', 'https://img.spoonacular.com/recipes/659867-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('dreamy-chai-rice-pudding', 'Dreamy Chai Rice Pudding', 4, 0, 0, '{"calories": 375, "protein": 11.47, "carbs": 63.3, "fat": 8.22, "saturated_fat": 4.65, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 101.83, "potassium": null, "fiber": 1.09, "sugar": 25.32, "vitamin_a": null, "vitamin_c": 0, "calcium": 334.01, "iron": 0.76}'::jsonb, ARRAY['dessert', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "rice", "notes": "1 cup rice (I used long grain rice)", "category": "pasta and rice"}, {"quantity": 4.0, "unit": "cups", "item": "milk", "notes": "4 cups whole milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "freshly tea", "notes": "1 cup freshly brewed tea (I used Twinings English Breakfast and left the tea left to brew for five minutes)", "category": "tea and coffee"}, {"quantity": 1.0, "unit": "teaspoon", "item": "cinnamon powder", "notes": "1 teaspoon cinnamon powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ginger powder", "notes": "1 teaspoon ginger powder", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "", "item": "cardomon pods", "notes": "3 whole cardomon pods", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "star anise", "notes": "1 whole star anise", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "", "item": "large cloves", "notes": "6 large cloves", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "vanilla essence", "notes": "1 teaspoon vanilla essence (or 1 vanilla bean)", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "brown sugar", "notes": "1/4 cup brown sugar", "category": "baking"}]'::jsonb, '["Put milk, tea, rice and all spices in a small saucepan and bring to boil. The turn down and simmer for around 20 minutes, stirring occasionally.", "Add sugar and turn heat back up to high. Cook for three to four minutes, stirring all the time as the pudding thickens.", "Serve in individual bowls. If you wish, you can pick out the spices before serving (use a spoon as the pudding will be very hot) but I figure most people can cope with minor details like that."]'::jsonb, 'https://www.foodista.com/recipe/CHRFL534/dreamy-chai-rice-pudding', 'https://img.spoonacular.com/recipes/641644-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('baked-caramel-custard', 'Baked Caramel Custard', 6, 0, 0, '{"calories": 249, "protein": 11.41, "carbs": 48.78, "fat": 1.09, "saturated_fat": 0.39, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 180.39, "potassium": null, "fiber": 0, "sugar": 48.76, "vitamin_a": null, "vitamin_c": 0.97, "calcium": 300.17, "iron": 1.08}'::jsonb, ARRAY['dessert', 'gluten free', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "egg substitute", "notes": "1 cup egg substitute", "category": "health foods"}, {"quantity": 1.0, "unit": "", "item": "egg yolk", "notes": "1 egg yolk", "category": "milk, eggs, other dairy"}, {"quantity": 1.5, "unit": "cups", "item": "evaporated skim milk", "notes": "1 1/2 cups evaporated skim milk", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "port wine", "notes": "2 teaspoons port wine", "category": "alcoholic beverages"}, {"quantity": 1.5, "unit": "cups", "item": "skim milk", "notes": "1 1/2 cups skim milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "sugar plus", "notes": "cup sugar plus", "category": "baking"}, {"quantity": 2.0, "unit": "tablespoons", "item": "sugar", "notes": "2 tablespoons sugar", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "vanilla", "notes": "2 teaspoons vanilla", "category": "baking"}]'::jsonb, '["Preheat the oven to 350 degrees. Scald the milks together in a heavy saucepan.", "Remove from the heat.Caramelize the sugar in a skillet over medium heat until it melts and turns brown. Slowly add the milks to the sugar, stirring constantly until the sugar dissolves.In a medium bowl, beat the egg substitute and egg yolk together until it is lemon-colored.", "Add the milk mixture, port, and vanilla and stir well.", "Pour the mixture into 6 custard cups and place them into a baking dish.", "Pour boiling water into the baking dish so that the water comes halfway up the sides of the cups.", "Place in the oven and bake until set, about 35 to 40 minutes.", "Remove the custard cups from the oven and cool completely in the refrigerator. When they are chilled, place a dessert plate on top of each custard cup and invert.", "Serve immediately.This recipe yields 6 servings.Serving size: 1/2 cup."]'::jsonb, 'https://www.foodista.com/recipe/WFB2KTYC/baked-caramel-custard', 'https://img.spoonacular.com/recipes/633492-312x231.jpeg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('raw-vegan-blueberry-chocolate-crust-cheesecake', 'Raw Vegan Blueberry Chocolate Crust "Cheesecake', 6, 0, 0, '{"calories": 557, "protein": 8.88, "carbs": 66.29, "fat": 35.76, "saturated_fat": 10.53, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 13.36, "potassium": null, "fiber": 7.27, "sugar": 47.04, "vitamin_a": null, "vitamin_c": 23.26, "calcium": 62.09, "iron": 3.3}'::jsonb, ARRAY['dessert', 'gluten free', 'dairy free', 'spoonacular', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "cup", "item": "agave", "notes": "cup of raw agave", "category": "ethnic foods"}, {"quantity": 0.25, "unit": "cup", "item": "almonds", "notes": "1/4 cup of raw almonds", "category": "nuts"}, {"quantity": 4.0, "unit": "tablespoons", "item": "blueberries", "notes": "4 tablespoons of fresh blueberries", "category": "produce"}, {"quantity": 2.5, "unit": "tablespoons", "item": "cacao powder", "notes": "2 1/2 tablespoons raw cacao powder", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "coconut oil", "notes": "cup of cold pressed coconut oil", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "lemon juice", "notes": "cup of fresh lemon juice", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "macadamia nuts", "notes": "1/2 cup raw macadamia nuts", "category": "nuts"}, {"quantity": 6.0, "unit": "", "item": "to 7 medjool dates", "notes": "6 to 7 medjool dates", "category": "dried fruits"}, {"quantity": 1.25, "unit": "cups", "item": "cashews", "notes": "1 1/4 cups of raw cashews (soaked overnight in filtered water)", "category": "nuts"}, {"quantity": 1.0, "unit": "pinch", "item": "sea salt", "notes": "1 pinch Himalayan or sea salt", "category": "spices and seasonings"}, {"quantity": 2.5, "unit": "tablespoons", "item": "soy lecithin granules", "notes": "2 1/2 tablespoons of soy lecithin granules", "category": "health foods"}, {"quantity": 1.0, "unit": "teaspoon", "item": "vanilla extract", "notes": "1 teaspoon vanilla extract", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "walnuts", "notes": "1/4 cup of raw walnuts", "category": "baking"}, {"quantity": 0.125, "unit": "cup", "item": "water", "notes": "1/8 cup of water", "category": "beverages"}]'::jsonb, '["Place all the filling ingredients (cashews, vanilla extract, lemon juice, water, raw agave, coconut oil, lecithin, salt, and blueberries) in the processor.   Process for a good 3 to 5 minutes, or until the filling is nice and smooth.", "Place over the crust in the pan, then FREEZE for a few hours or until it is firm. Enjoy!"]'::jsonb, 'https://www.foodista.com/recipe/2YFNDJB6/raw-vegan-blueberry-chocolate-crust-cheesecake', 'https://img.spoonacular.com/recipes/658004-312x231.jpg', FALSE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
