 germ", "category": "health foods"}, {"quantity": 0.5, "unit": "cup", "item": "pastry flour", "notes": "1/2 cup whole wheat pastry flour", "category": "baking"}, {"quantity": 1.0, "unit": "", "item": "preheat the oven degrees", "notes": "1Preheat the oven to 350 degrees.", "category": "pasta and rice"}]'::jsonb, '["Preheat the oven to 350 degrees.In a mixing bowl, combine the fruits with the next 5ingredients and stir together until evenly coated.", "Pour into a lightly oiled 9- by 13-inch baking pan.In a small bowl, combine the first 4 topping ingredients and toss to coat.", "Drizzle in the oil and stir until evenly coated.", "Sprinkle the crumble topping evenly over the fruit mixture.", "Bake for 35 to 40 minutes, or until the fruits are soft and the topping is golden. If desired, serve warm in bowls over frozen dessert."]'::jsonb, 'https://www.foodista.com/recipe/2ZLWM7GX/pear-and-apple-crumble', 'https://img.spoonacular.com/recipes/655392-312x231.jpg', TRUE, 3, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('beetroot-oats-halwa-pudding', 'Beetroot & Oats Halwa Pudding', 3, 0, 0, '{"calories": 550, "protein": 10.59, "carbs": 68.38, "fat": 29.02, "saturated_fat": 9.88, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 158.75, "potassium": null, "fiber": 9.24, "sugar": 46.49, "vitamin_a": null, "vitamin_c": 9.26, "calcium": 80.23, "iron": 3.21}'::jsonb, ARRAY['dessert', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'vegetarian'], '[{"quantity": 4.0, "unit": "cups", "item": "beetroot", "notes": "4 cups Beetroot, peeled & shredded", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "sugar/jaggery", "notes": "1/2 cup Sugar/Jaggery (adjust according to your taste)", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "old fashioned oats", "notes": "1/2 cup Old Fashioned Oats (optional, it gives a chewy and sticky texture)", "category": "cereal"}, {"quantity": 3.0, "unit": "servings", "item": "handfull of nuts..)", "notes": "Handfull of nuts..( I used almonds, cashew & pistachios)", "category": "nuts"}, {"quantity": 0.5, "unit": "teaspoon", "item": "cardamom powder", "notes": "1/2 teaspoon Cardamom powder", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "half & half", "notes": "1/4 cup Milk OR Half & Half", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "tablespoons", "item": "clarified butter/ghee", "notes": "2 tablespoons Clarified Butter/Ghee", "category": "ethnic foods"}]'::jsonb, '["Peel, shred/grate beetroot and steam for couple of minutes in microwave, just to quicken the cooking process. Its optional.", "On a medium flame, add ghee in a heavy bottom pan, fry nuts, then add shredded beets for 3-5 minutes on medium heat.", "OR Cook it more if you did not steam earlier.", "As the water from beets, starts to evaporate, slowly start adding a tablespoon of milk, every 2 mins untill done.", "Now cooking oats, sugar/jaggery and stir well, cook untill the sugar syrup evaporates.", "Add cardamom powder at the end of the process and serve hot."]'::jsonb, 'https://www.foodista.com/recipe/SWHMT4RX/beetroot-oats-halwa-pudding', 'https://img.spoonacular.com/recipes/634794-312x231.jpg', TRUE, 4, TRUE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
