teaspoon", "item": "pepper", "notes": "1/2 teaspoon black pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "servings", "item": "hot sauce", "notes": "Cayenne or hot sauce to taste", "category": "condiments"}, {"quantity": 1.0, "unit": "cup", "item": "rice", "notes": "1 cup long grain rice (Could use instant rice)", "category": "pasta and rice"}]'::jsonb, '["Put all ingredients in crockpot and cook on high for 4 hours or low for 6 to 7 hours."]'::jsonb, 'https://www.foodista.com/recipe/SYGHTJML/slow-cooker-chicken-gumbo-soup', 'https://img.spoonacular.com/recipes/660283-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
