ory": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "thyme", "notes": "1/2 teaspoon thyme", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "pepper", "notes": "1/2 teaspoon black pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "okra", "notes": "1 cup okra sliced into ½ inch pieces", "category": "produce"}]'::jsonb, '["Add oil to a large pot.", "Heat pot over medium flame.", "Stir in flour", "Cook, stirring constantly until flour begins to turn golden brown.", "Slowly stir in all the broth and cook for 2 minutes. The mixture should not be lumpy.", "Add all the ingredients except okra. Bring to a boil, then reduce heat and let simmer for 30 minutes.", "Add okra and let cook for 20 more minutes", "Remove bay leaf", "Serve over rice"]'::jsonb, 'https://www.foodista.com/recipe/NZVMMBWD/chicken-gumbo-luisiana-style', 'https://img.spoonacular.com/recipes/638108-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
