ion, and bell pepper in a separate pan until onions are soft.", "Add sausage to onions and saute together for a minute or two.", "Add bouillon, onion soup, and tomato sauce.", "Pour mixture into a Dutch oven; add butter, crawfish tails and rice.", "Bake for 1 hour at 350 degrees.", "Serve immediately."]'::jsonb, 'https://www.foodista.com/recipe/6LYZHBTV/easy-crawfish-jambalaya', 'https://img.spoonacular.com/recipes/641943-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('red-kidney-bean-jambalaya', 'Red Kidney Bean Jambalaya', 6, 0, 0, '{"calories": 392, "protein": 18.13, "carbs": 69.36, "fat": 6.45, "saturated_fat": 0.96, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1111.47, "potassium": null, "fiber": 16.25, "sugar": 10.19, "vitamin_a": null, "vitamin_c": 45.07, "calcium": 118.78, "iron": 6.09}'::jsonb, ARRAY['cajun', 'creole', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'soup', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "brown rice", "notes": "2/3 cup dried brown rice (2 cups cooked)", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "medium", "item": "carrots", "notes": "2 medium carrots, sliced", "category": "produce"}, {"quantity": 2.0, "unit": "stalks", "item": "celery", "notes": "2 stalks celery, sliced", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "celery seed", "notes": "1 teaspoon celery seed", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cups", "item": "kidney beans", "notes": "2/3 cup dried kidney beans (2 cups cooked)", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "teaspoon", "item": "marjoram", "notes": "1 teaspoon dried marjoram", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "thyme", "notes": "2 teaspoons dried thyme", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "medium", "item": "eggplant", "notes": "1 medium eggplant, chopped", "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves garlic, minced or crushed", "category": "produce"}, {"quantity": 3.0, "unit": "handfuls", "item": "green beans", "notes": "3 handfuls of green beans, chopped", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "ground pepper", "notes": "fresh ground black pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "ground sage", "notes": "2 teaspoons ground sage", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "liquid smoke", "notes": "1/2 to 1 teaspoon liquid smoke, to taste", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 red bell pepper, seeded and chopped", "category": "produce"}, {"quantity": 1.0, "unit": "small", "item": "onion", "notes": "1 small white or red onion, diced", "category": "produce"}, {"quantity": 1.5, "unit": "teaspoons", "item": "sea salt", "notes": "1 1/2 teaspoons sea salt, or to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sriracha", "notes": "1 teaspoon sriracha or other hot sauce", "category": "condiments"}, {"quantity": 2.0, "unit": "medium", "item": "tomatoes", "notes": "2 medium tomatoes, diced", "category": "produce"}, {"quantity": 3.0, "unit": "cups", "item": "vegetable stock", "notes": "3 cups vegetable stock", "category": "canned and jarred"}]'::jsonb, '["Rinse the kidney beans and brown rice separately. Cover the kidney beans with water and soak for 8 hours or overnight. In a separate bowl, cover the brown rice with water and soak for 8 hours or overnight.", "Drain and rinse the kidney beans, then transfer to a medium saucepan and cover with fresh water. Bring to a boil, reduce heat to medium-low, cover, and simmer for 1 hour or until just tender but not falling apart.", "Drain and set aside.", "Heat the oil in a large saucepan over medium heat. When hot, add the onion and saut for 5 minutes. Now add the garlic, carrots, celery and green beans, and stir for another 5 minutes. Next add the tomatoes, red pepper, eggplant, sage, thyme, marjoram and celery seed, and continue to stir for another few minutes.", "Pour in the vegetable stock, liquid smoke, rice and the cooked kidney beans. Bring to a boil, reduce heat to medium low, cover, and cook, stirring occasionally, for 45 minutes or until the rice is tender.", "Add water as necessary if the stew becomes too dry.Season with sriracha, salt and pepper, and taste for seasoning  add more liquid smoke, sriracha, salt, pepper or herbs as desired."]'::jsonb, 'https://www.foodandspice.com/2016/05/red-kidney-bean-jambalaya.html', 'https://img.spoonacular.com/recipes/782601-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jeans-seafood-gumbo', 'Jean''s Seafood Gumbo', 9, 0, 0, '{"calories": 524, "protein": 67.59, "carbs": 20.56, "fat": 18.76, "saturated_fat": 5.48, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1830.99, "potassium": null, "fiber": 4.52, "sugar": 4.39, "vitamin_a": null, "vitamin_c": 55.86, "calcium": 261.6, "iron": 3.88}'::jsonb, ARRAY['cajun', 'creole', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'baking'], '[{"quantity": 2.0, "unit": "pounds", "item": "shrimp", "notes": "2 pounds fresh or frozen medium-size shrimp, in shells if possible, for stock", "category": "seafood"}, {"quantity": 12.0, "unit": "", "item": "crabs", "notes": "1 dozen fresh or frozen blue crabs, cleaned and shells removed (substitute: 2 pounds fresh crabmeat, crawfish, oyster, or turtle)", "category": "seafood"}, {"quantity": 4.0, "unit": "stalks", "item": "celery", "notes": "4 stalks celery, chopped", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "parsley", "notes": "½ cup chopped parsley", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "peppers", "notes": "2 green peppers, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "large", "item": "onion", "notes": "1 large onion, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "green onions", "notes": "1 cup chopped green onions", "category": "produce"}, {"quantity": 4.0, "unit": "cloves", "item": "garlic", "notes": "4 cloves garlic, chopped", "category": "produce"}, {"quantity": 3.0, "unit": "", "item": "bay leaves", "notes": "3 bay leaves", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "ounce", "item": "tomato paste", "notes": "1 ounce tomato paste", "category": "pasta and rice"}, {"quantity": 4.0, "unit": "teaspoons", "item": "vegetable oil", "notes": "4 teaspoons vegetable oil or shortening", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.5, "unit": "cup", "item": "flour", "notes": "½ cup flour", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "salt", "notes": "2 teaspoons salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "ground pepper", "notes": "2 teaspoons ground black pepper", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "thyme", "notes": "½ teaspoon dried thyme", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "worcestershire sauce", "notes": "1 teaspoon Worcestershire sauce", "category": "condiments"}, {"quantity": 1.0, "unit": "can", "item": "canned tomatoes", "notes": "1 can whole peeled tomatoes, chopped", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "can", "item": "all the tabasco sauce you handle", "notes": "All the Tabasco sauce you can handle", "category": "condiments"}, {"quantity": 9.0, "unit": "servings", "item": "creole seasoning", "notes": "Creole seasoning to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "pound", "item": "andouille", "notes": "1 pound andouille, turkey, kielbasa or smoked sausage, cubed", "category": "meat"}, {"quantity": 2.0, "unit": "tablespoons", "item": "filé powder", "notes": "2 tablespoons filé powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "pound", "item": "okra", "notes": "1 pound fresh or frozen sliced okra", "category": "produce"}, {"quantity": 1.0, "unit": "bag", "item": "louisiana rice", "notes": "1 bag Louisiana rice (or white rice)", "category": "pasta and rice"}]'::jsonb, '["Fill a 14-16-quart pot with two quarts of water and bring to a boil.", "Meanwhile, peel and devein the shrimp, keeping the heads and hulls. Set the shrimp aside in cold water. In the large \"gumbo pot\" boil heads and hulls for 30 minutes to an hour. This will give you Creole gumbo. Strain shrimp heads and hulls from stock and set aside. Discard heads and hull immediately. Otherwise, the next day your kitchen will smell like Bayou St. John.", "Clean the fresh crabs  If the crabs are fresh, you must take time to clean them. Discard the hard back shell and some of the so-called \"dead man,\" or yellow insides. Clean and separate crabs and set aside. (Note: If necessary, you can use meat from king, Dungeness, snow or stone crabs for your gumbo).", "Before you fire up the stove again, cut up your celery, parsley, peppers, onions and garlic, especially if you''re alone and there is no one to help you stir the pots. It takes time peeling the onions and garlic", "Put the celery and parsley in a separate container from the other chopped ingredients and refrigerate until needed to keep them fresh.", "Place the gumbo pot with the shrimp stock on the stove.", "Add cleaned crabs and bay leaves. Stir slowly. You don''t want your shrimp stock messing up the floor.", "Add celery, parsley, and tomato paste to the gumbo brewing on the stove. Bring to a boil. Turn down heat, cover, and let simmer.", "Here comes the roux -- a thick and flavorful sauce that has become one of the most important staples of Louisiana cuisine.", "Pour oil or shortening into a separate heavy skillet (please do not use a thin omelet pan) over a medium-low heat. Slowly stir in flour to make the roux. Keep your eyes on the skillet. If the phone rings, let the answering machine pick it up. Cook roux until it has a dark mahogany color. Do not stop stirring until roux appears nutty or grainy. If black specks appear, the roux is burned. Throw it out and start from scratch. A good roux could take 30 to 45 minutes cooking time.", "Now you are ready to add the holy trinity of onions, garlic, and green peppers to the roux mixture. Stir ingredients in slowly because the flour is still sizzling. The moisture will begin to disappear. This is when Jean would add another quart or two of water to the gumbo pot.", "Add roux to the gumbo pot. Bring to a boil, stirring constantly. Lower heat and cover. The kitchen should smell good right now.", "Pour yourself another cold something-or-other. You''re halfway there. Come back to look and stir in an hour or so.", "Season to taste: add salt, pepper, thyme, Worcestershire sauce, Tabasco sauce and any Creole seasoning you like. Don''t overdo it right now.", "Let the roux work its magic absorbing all the wonderful ingredients. Gumbo is usually very spicy, but you can keep it mild. Remember, if you have decided to use andouille sausage it is also hot.", "Fry sausages and okra with a little bit of the leftover grease.", "Sprinkle a little leftover flour if the okra is fresh.", "Add to gumbo pot.", "Add chopped peeled tomatoes, stirring until well blended.", "Add more water if necessary. The roux will keep it thick and tasty. Return to a boil and simmer for 10 minutes. Reduce heat and let simmer, uncovered, for 2 1/2 to 3 hours over low heat.", "Skim any excess fat.", "Add shrimp. Stir in slowly as you increase the heat one last time. It''s time to stir in the fil powder. Cook another 20 to 30 minutes until the gumbo is thick. Taste and adjust seasonings one more time. Did I mention the rice? Seafood gumbo is served over Louisiana rice. Of course, you can substitute for your own favorite rice. Just plain old brown or white rice will do. Before serving, taste one more time and adjust seasoning. Turn off heat and remove seafood gumbo from the stove.", "To cool down the pot before serving, place it in the sink with a few inches of ice-cold water. If needed, add additional salt and Tabasco sauce. If you can see through the gumbo to the bottom of the pot, work on your roux next time."]'::jsonb, 'https://www.foodista.com/recipe/Z2KPLCN3/jean-s-seafood-gumbo', 'https://img.spoonacular.com/recipes/648524-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('how-to-make-a-louisiana-style-gumbo', 'How to Make a Louisiana Style Gumbo', 10, 60, 60, '{"calories": 462, "protein": 50.92, "carbs": 23.06, "fat": 16.96, "saturated_fat": 4.03, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 751.77, "potassium": null, "fiber": 3.64, "sugar": 5.88, "vitamin_a": null, "vitamin_c": 25.0, "calcium": 76.96, "iron": 4.51}'::jsonb, ARRAY['cajun', 'creole', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'baking'], '[{"quantity": 1.0, "unit": "cup", "item": "all purpose flour", "notes": "1 cup all purpose flour", "category": "baking"}, {"quantity": 12.0, "unit": "oz", "item": "beer", "notes": "1 12oz bottle or can of beer (I prefer Michelob Ultra)", "category": "alcoholic beverages"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 bell pepper diced", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "cajun seasoning in the seasoning aisle at your local grocery store", "notes": "1/4 cup cajun seasoning in the seasoning aisle at your local grocery store, and if you are really looking for some flavor you can kick things up by adding an additional 1/4 cup of seasoning to make it a full 1/2 cup of cajun seasoning.", "category": "spices and seasonings"}, {"quantity": 10.0, "unit": "oz", "item": "canned tomatoes", "notes": "1 10oz can diced tomatoes with green chili peppers (with juice)", "category": "canned and jarred"}, {"quantity": 14.5, "unit": "oz", "item": "canned tomatoes", "notes": "1 14.5oz can petite diced tomatoes (with juice)", "category": "produce"}, {"quantity": 6.0, "unit": "stalks", "item": "celery", "notes": "6 stalks of celery diced", "category": "produce"}, {"quantity": 43.5, "unit": "oz", "item": "chicken broth", "notes": "3 14.5oz cans chicken broth", "category": "canned and jarred"}, {"quantity": 3.0, "unit": "", "item": "chicken breasts", "notes": "3 chicken breasts cooked and cubed", "category": "meat"}, {"quantity": 1.0, "unit": "cup", "item": "extra virgin olive oil", "notes": "1 cup extra virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "Tbsp", "item": "filé powder", "notes": "1 Tbsp filé powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "Tbsp", "item": "garlic powder", "notes": "1 Tbsp garlic powder", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "Tbsp", "item": "parsley", "notes": "2 Tbsp parsley", "category": "produce"}, {"quantity": 1.0, "unit": "package", "item": "sausage", "notes": "1 package sausage cooked and sliced", "category": "meat"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 sweet onion diced", "category": "produce"}]'::jsonb, '["To get started with this dish you will want to get two post of water boiling and cook your chicken breasts in one and your sausage in the other. I usually boil my chicken breasts for 15-20 minutes until the juices run clear when cut into, then cube them. For the sausage, slice it into bite sized pieces and boil for 10 minutes. Set aside after cooking to use later with the gumbo.", "The roux is the most important part of a gumbo. If you don''t get the roux right, you are probably not going to like your gumbo. There are many recipes you can try for a roux, but this is probably going to be one of the best you have ever had if you are a true gumbo fan.", "Let''s get start making the gumbo.", "Over medium heat in a large pot, add your olive oil. Allow to warm for a minute, and then add in the flour. Stir constantly until all of the flour has disolved and the mixture has a lot of tiny bubbles. Once you have reached that consistency it''s time to add in your garlic powder. Allow to bubble, constantly stirring for one minute.", "Gradually stir in the chicken broth and the beer, stirring constantly until the mixture comes to a slow simmer.", "Add the celery, all tomatoes, onion, bell pepper, parsley, and cajun seasoning. Reduce heat to a slow simmer, cover, and continue to simmer for 40 minutes, stirring often.", "Mix the chicken and sausage into the roux mixture, cover, and cook for an additional 20 minutes, stirring often.", "Add in the fil powder, stir well.", "Once finished, serve over rice and with a side of french bread. So delicious!"]'::jsonb, 'https://www.pinkwhen.com/louisiana-style-gumbo-recipe/', 'https://img.spoonacular.com/recipes/1055614-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cajun-lobster-pasta', 'Cajun Lobster Pasta', 1, 0, 0, '{"calories": 683, "protein": 35.0, "carbs": 27.68, "fat": 49.82, "saturated_fat": 22.97, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2291.34, "potassium": null, "fiber": 7.08, "sugar": 12.71, "vitamin_a": null, "vitamin_c": 258.15, "calcium": 254.45, "iron": 3.9}'::jsonb, ARRAY['cajun', 'creole', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'primal', 'spoonacular', 'breakfast', 'soup', 'pasta'], '[{"quantity": 3.0, "unit": "strips", "item": "bacon", "notes": "3 strips of Bacon", "category": "meat"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 Bell Pepper, any Color, Chopped", "category": "produce"}, {"quantity": 0.75, "unit": "cup", "item": "veggie broth", "notes": "3/4 cup Chicken, Seafood, or Veggie Broth", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "teaspoon", "item": "cajun spice", "notes": "1 teaspoon of Cajun Spice", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves of Garlic, Minced", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "garlic powder", "notes": "1/2 teaspoon of Garlic Powder", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "", "item": "green onions", "notes": "3 Green Onions, Chopped", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "heavy cream", "notes": "1/4 cup of Heavy Cream", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "teaspoon", "item": "lemon pepper", "notes": "1/2 teaspoon of Lemon Pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "pd of lobster", "notes": "1 pd of Lobster", "category": "seafood"}, {"quantity": 1.0, "unit": "teaspoon", "item": "old bay seasoning", "notes": "1 teaspoon of Old Bay Seasoning", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "onion powder", "notes": "1/2 teaspoon of Onion Powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "oregano", "notes": "1/2 teaspoon of Oregano", "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "bell pepper", "notes": "Pepper to taste", "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "salt", "notes": "1/4 tsp salt", "category": "spices and seasonings"}]'::jsonb, '["Cook up your bacon in a small frying pan over medium heat.", "Remove the bacon and drain off the fat, reserving about a tablespoon.To the pan add in your garlic and pepper. Cook it up on medium heat for about two to three minutes.", "Add in the green onions.", "Let cook for an additional minute.Chop up your bacon and add it to the pan along with the broth. Love me some bacon.Now add in your spices; the cajun, old bay, onion powder, garlic powder, lemon pepper, oregano, and pepper.Allow the mixture to heat back up and then turn your heat down to medium low.", "Add in your lobster and allow it about three to five minutes to heat up completely.Last up, add in your cream.", "Serve your finished lobster over fresh cooked pasta with a few pinches of parmesan cheese and a sprinkle of chopped green onions over the top."]'::jsonb, 'https://www.foodista.com/recipe/36T2YS7G/cajun-lobster-pasta', 'https://img.spoonacular.com/recipes/636732-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('seafood-gumbo', 'Seafood Gumbo', 12, 0, 0, '{"calories": 376, "protein": 34.59, "carbs": 47.88, "fat": 5.15, "saturated_fat": 0.84, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1433.66, "potassium": null, "fiber": 4.89, "sugar": 5.05, "vitamin_a": null, "vitamin_c": 46.64, "calcium": 256.67, "iron": 2.94}'::jsonb, ARRAY['cajun', 'creole', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'dairy free', 'pescatarian', 'spoonacular', 'baking'], '[{"quantity": 2.0, "unit": "", "item": "bay leaves", "notes": "2 bay leaves", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "ribs", "item": "celery", "notes": "3 ribs celery, finely diced", "category": "produce"}, {"quantity": 8.0, "unit": "cups", "item": "rice", "notes": "8 cups cooked long-grain white rice", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "tablespoon", "item": "filé powder", "notes": "1 tablespoon filé powder", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "quarts", "item": "fish stock", "notes": "4 quarts shrimp stock, crab stock or fish stock", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "cup", "item": "flour", "notes": "1/2 cup flour", "category": "baking"}, {"quantity": 6.0, "unit": "cloves", "item": "garlic", "notes": "6 cloves garlic, minced", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "bell peppers", "notes": "2 green bell peppers, diced", "category": "produce"}, {"quantity": 1.0, "unit": "pound", "item": "lump crab meat", "notes": "1 pound fresh lump crab meat, picked over for shells and cartilage", "category": "seafood"}, {"quantity": 0.5, "unit": "cup", "item": "oil", "notes": "1/2 cup oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "pounds", "item": "okra", "notes": "2 pounds okra, chopped", "category": "produce"}, {"quantity": 2.0, "unit": "medium", "item": "onions", "notes": "2 medium onions, diced", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "dozens oysters", "notes": "2 dozens oysters, freshly shucked, liquor reserved", "category": "seafood"}, {"quantity": 12.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and freshly ground black pepper to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "creole seasoning blend", "notes": "1 tablespoon Creole seasoning blend", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "pounds", "item": "shrimp", "notes": "2 pounds medium shrimp, peeled and deveined", "category": "seafood"}, {"quantity": 1.0, "unit": "teaspoon", "item": "thyme leaves", "notes": "1 teaspoon dried thyme leaves", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "tomato purée", "notes": "1 cup tomato purée", "category": "canned and jarred"}, {"quantity": 4.0, "unit": "", "item": "tomatoes", "notes": "4 tomatoes, seeded and diced", "category": "produce"}]'::jsonb, '["Heat oil in a large heavy stockpot over medium-high heat.", "Add the flour and stir constantly until a light brown roux is formed.", "Add the onions, bell pepper, celery and garlic. Saut until the onions become translucent and the vegetables are tender.", "Add the tomatoes and tomato pure and cook over medium heat for 10 minutes.", "Add the Creole seasoning, thyme, bay leaves and about 1/2 teaspoon each of salt and pepper, and continue to cook another 10 minutes.", "Add the okra, and cook for another 10 minutes, then add the stock. Bring to a boil, then reduce heat to simmer and cook another 30 minutes.Reduce heat to low.About 10 minutes prior to serving, add the shrimp, oysters and oyster liquor. Just prior to serving, add the crab meat (the crab meat does not need to be cooked, just stir until it is heated through.Taste and correct seasonings if necessary.", "Remove from heat and sprinkle the fil powder on the surface of the gumbo; cover and let stand for 15 minutes. Uncover and stir to mix.", "Serve hot with French bread and cold beverages."]'::jsonb, 'https://www.foodista.com/recipe/XJJFHR6X/seafood-gumbo', 'https://img.spoonacular.com/recipes/659638-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('how-to-make-the-best-chicken-jambalaya', 'How to Make the Best Chicken Jambalaya', 8, 10, 45, '{"calories": 449, "protein": 26.41, "carbs": 37.93, "fat": 20.86, "saturated_fat": 7.5, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 989.87, "potassium": null, "fiber": 2.63, "sugar": 5.11, "vitamin_a": null, "vitamin_c": 24.8, "calcium": 48.57, "iron": 2.05}'::jsonb, ARRAY['cajun', 'creole', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'spoonacular', 'soup', 'baking'], '[{"quantity": 2.0, "unit": "tbsp", "item": "▢ butter", "notes": "▢ 2 tbsp unsalted butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "lb", "item": "▢ sausage", "notes": "▢ 1 lb sliced sausage", "category": "meat"}, {"quantity": 1.0, "unit": "lb", "item": "▢ chicken breasts", "notes": "▢ 1 lb boneless skinless chicken breasts cut into bite sized pieces", "category": "meat"}, {"quantity": 1.0, "unit": "cup", "item": "▢ onion", "notes": "▢ 1 cup yellow onion chopped", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "▢ celery", "notes": "▢ 1 cup celery chopped", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "▢ bell pepper", "notes": "▢ 1/2 cup bell pepper chopped", "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "▢ garlic", "notes": "▢ 1 tbsp minced garlic", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "▢ tomato sauce", "notes": "▢ 1 cup tomato sauce", "category": "canned and jarred"}, {"quantity": 14.5, "unit": "oz", "item": "▢ tomatoes", "notes": "▢ 14.5 oz diced tomatoes", "category": "produce"}, {"quantity": 2.5, "unit": "cups", "item": "▢ chicken stock", "notes": "▢ 2 1/2 cups chicken stock", "category": "canned and jarred"}, {"quantity": 1.5, "unit": "cups", "item": "▢ rice", "notes": "▢ 1 1/2 cups rice uncooked and rinsed", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "leaves", "item": "▢ 2 bay", "notes": "▢ 2 bay leaves whole", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tsp", "item": "▢ ground pepper", "notes": "▢ 2 tsp ground black pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "▢ salt", "notes": "▢ 1 tsp salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "▢ pepper", "notes": "▢ 1 tsp white pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "▢ thyme", "notes": "▢ 1 tsp thyme dried", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "▢ pepper flakes", "notes": "▢ 1 tsp red pepper flakes", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "▢ sage", "notes": "▢ 1/2 tsp sage", "category": "spices and seasonings"}]'::jsonb, '["Combine the creole seasoning ingredients in a small bowl and set aside.", "Melt butter in a large dutch oven over medium-high heat.", "Add the sausage until it starts to brown, about 3 minutes.", "Add the chicken and continue to cook until brown, about 3-5 minutes. Stir frequently.", "Turn the stove top down to medium heat.", "Preheat your oven to 350 degrees.", "Stir in the seasoning mix of cajun spices and 1/2 of the chopped onion, celery, green bell pepper, and garlic. Cook until vegetables get tender, about 3-5 minutes. Stir frequently and scrape the bottom of the pot frequently.", "Stir in the tomato sauce and cook for about one minute.", "Stir in the remaining onion, celery, bell pepper, garlic, and the diced tomatoes then remove from heat.", "Stir in the rice and chicken stock, mix the ingredients well.", "Bake uncovered in the oven at 350 degrees for one hour or until the rice is tender but still has a little crunch.", "Remove from the oven, add the bay leaves and stir well.", "Allow the dish to cool for five minutes before serving. OPTIONAL: Top with green onions before serving."]'::jsonb, 'https://www.pinkwhen.com/chicken-and-sausage-jambalaya/', 'https://img.spoonacular.com/recipes/715545-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cajun-seafood-and-andouille-sausage-gumbo', 'Cajun Seafood and Andouille Sausage Gumbo', 4, 0, 0, '{"calories": 766, "protein": 43.64, "carbs": 43.08, "fat": 47.09, "saturated_fat": 10.82, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1271.18, "potassium": null, "fiber": 3.7, "sugar": 3.01, "vitamin_a": null, "vitamin_c": 45.44, "calcium": 214.9, "iron": 5.2}'::jsonb, ARRAY['cajun', 'creole', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'baking'], '[{"quantity": 9.0, "unit": "oz", "item": "andouille sausage", "notes": "9 oz andouille sausage, cut into ½ inch rounds", "category": "meat"}, {"quantity": 2.0, "unit": "", "item": "bay leaves", "notes": "2 bay leaves, left whole", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "t", "item": "pepper", "notes": "½ t white pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "pepper", "notes": "1 Tablespoon Black Pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "cayenne pepper", "notes": "1 Tablespoon Cayenne Pepper", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "stalks", "item": "celery", "notes": "3 stalks celery, cut into 1 inch pieces", "category": "produce"}, {"quantity": 3.0, "unit": "C", "item": "clam juice", "notes": "3 C fish stock or clam juice", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "C", "item": "rice", "notes": "2 C white rice, cooked, washed and drained", "category": "pasta and rice"}, {"quantity": 0.5, "unit": "", "item": "crab meat", "notes": "½ # canned or fresh crab meat", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "thyme", "notes": "1 Tablespoon Dried Thyme", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "large cloves", "item": "garlic", "notes": "3 large cloves of garlic, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "jalapeno pepper", "notes": "1 jalapeno pepper, seeded", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "", "item": "orange bell pepper", "notes": "1 red or orange Bell pepper, chopped coarse", "category": "produce"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "oregano", "notes": "1 Tablespoon Dried Oregano", "category": "produce"}, {"quantity": 10.0, "unit": "oz", "item": "oysters", "notes": "1 10 oz jar of oysters or 8-10 oysters with their juices", "category": "seafood"}, {"quantity": 0.5, "unit": "C", "item": "peanut oil", "notes": "½ C peanut oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "pound", "item": "shrimp", "notes": "1 pound shrimp", "category": "seafood"}, {"quantity": 0.5, "unit": "C", "item": "flour", "notes": "½ C white flour", "category": "baking"}]'::jsonb, '["In a small bowl, combine the seasoning ingredients and set aside.", "In a medium bowl, combine the onions, peppers and celeryand set aside.", "In a lightly oiled 5  quart Dutch oven, brown the sausage rounds over medium high heat and set aside.", "Add the  C oil and when it starts to smoke, slowly combine the flour and cook while whisking until the roux reaches a dark reddish brown color.", "Immediately add half of the vegetables and stir in for 1 minute. Then add the remaining vegetables, mix thoroughly and cook for 2 more minutes.", "Add the seasoning mix, stir in well and cook 2 more minutes or so. Then add the garlic, stir in and cook for another minute.", "Add the fish stock or clam juice and, mix well, bring to a boil and reduce to a simmer; then simmer this for about 30 minutes covered.", "Add the reserved browned sausage rounds, the crab, shrimps and oysters with their liquid and cook over medium heat for about 10 minutes stirring occasionally."]'::jsonb, 'https://www.foodista.com/recipe/SQBW5QGT/cajun-seafood-and-andouille-sausage-gumbo', 'https://img.spoonacular.com/recipes/636736-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jambalaya-stew', 'Jambalaya Stew', 4, 0, 0, '{"calories": 263, "protein": 17.13, "carbs": 32.49, "fat": 7.66, "saturated_fat": 1.6, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 891.92, "potassium": null, "fiber": 3.53, "sugar": 5.65, "vitamin_a": null, "vitamin_c": 39.54, "calcium": 93.53, "iron": 2.12}'::jsonb, ARRAY['cajun', 'creole', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular'], '[{"quantity": 6.0, "unit": "oz", "item": "chicken sausage links", "notes": "2 fully cooked chicken sausage Links (about 6 oz) sliced into coins – I used Trader Joe''s Sweet Italian Chicken Sausage", "category": "meat"}, {"quantity": 14.5, "unit": "oz", "item": "canned tomatoes", "notes": "1 14.5-oz. can fire-roasted diced tomatoes, no salt added", "category": "canned and jarred"}, {"quantity": 0.75, "unit": "cup", "item": "onion", "notes": "3/4 cup onion, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "large", "item": "bell pepper", "notes": "1 large green bell pepper, seeded, chopped – I used yellow", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "celery", "notes": "1 cup celery, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "chicken broth", "notes": "1 cup low-sodium chicken broth", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "cup", "item": "brown rice", "notes": "1/2 cup uncooked brown rice", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "tbsp", "item": "garlic", "notes": "1 tbsp. garlic, minced", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "cajun seasoning", "notes": "1 tsp. cajun seasoning", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "hot sauce", "notes": "1/2 tsp. hot sauce, or more to taste", "category": "condiments"}, {"quantity": 0.25, "unit": "tsp", "item": "oregano", "notes": "1/4 tsp. dried oregano", "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "thyme", "notes": "1/4 tsp. dried thyme", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "oz", "item": "shrimp", "notes": "6 oz. raw shrimp, tails removed, deveined, chopped", "category": "seafood"}]'::jsonb, '["Add all ingredients except shrimp to a large pot on the stove.", "Mix thoroughly. Bring to a boil.", "Reduce heat to medium low. Cover and simmer until vegetables are tender and rice is fluffy, about 35 minutes.", "Add shrimp and re-cover. Continue to cook until shrimp are tender and cooked through, about 6 minutes.", "If you like, season to taste with salt, black pepper, and additional hot sauce.", "Serve and enjoy!!!"]'::jsonb, 'https://www.foodista.com/recipe/HG72GN7R/jambalaya-stew', 'https://img.spoonacular.com/recipes/648432-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('jambalaya-soup', 'Jambalaya Soup', 8, 0, 0, '{"calories": 293, "protein": 26.41, "carbs": 20.15, "fat": 11.65, "saturated_fat": 3.26, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 343.63, "potassium": null, "fiber": 2.7, "sugar": 3.18, "vitamin_a": null, "vitamin_c": 28.76, "calcium": 85.76, "iron": 1.86}'::jsonb, ARRAY['cajun', 'creole', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'slow-cooker', 'baking'], '[{"quantity": 3.0, "unit": "ounces", "item": "andouille or", "notes": "3 ounces fully cooked andouille or", "category": "meat"}, {"quantity": 0.6666667, "unit": "cup", "item": "brown rice", "notes": "2/3 cup long-grain brown rice", "category": "pasta and rice"}, {"quantity": 14.5, "unit": "oz", "item": "canned tomatoes", "notes": "1 14.5-oz. can fire-roasted diced tomatoes, no salt added", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "teaspoon", "item": "cayenne pepper", "notes": "1/2 teaspoon cayenne pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "thinly- celery", "notes": "1 cup thinly-sliced celery", "category": "produce"}, {"quantity": 3.0, "unit": "ounces", "item": "chicken broth", "notes": "3 ounces can chicken broth - (14 ½ ea)", "category": "canned and jarred"}, {"quantity": 8.0, "unit": "", "item": "chicken drumsticks skinned", "notes": "8 chicken drumsticks skinned", "category": "meat"}, {"quantity": 8.0, "unit": "servings", "item": "chorizo sausage", "notes": "chorizo sausage diced", "category": "meat"}, {"quantity": 1.0, "unit": "teaspoon", "item": "marjoram", "notes": "1 teaspoon dried marjoram", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "tsp", "item": "thyme", "notes": "1/4 tsp. dried thyme", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "", "item": "garlic cloves", "notes": "4 garlic cloves crushed", "category": "produce"}, {"quantity": 0.5, "unit": "pound", "item": "okra cut", "notes": "1/2 pound fresh okra cut ½\" slices", "category": "produce"}, {"quantity": 0.75, "unit": "cup", "item": "onion", "notes": "3/4 cup onion, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 red bell pepper diced", "category": "produce"}, {"quantity": 0.5, "unit": "pound", "item": "shrimp", "notes": "1/2 pound medium shrimp peeled, deveined", "category": "seafood"}]'::jsonb, '["In saucepan, bring broth, tomatoes, garlic, herbs and pepper to a boil. In 5- or 6-quart slow cooker, mix onion, celery, rice and sausage.", "Add broth. Tuck in drumsticks, meaty-sides down, to cover. Cover; cook on LOW 7 to 8 hours, or on HIGH 2 1/2 to 3 hours, until rice has softened and chicken is tender.Uncover; turn to HIGH.", "Add shrimp and okra; cover. Simmer 5 minutes, until shrimp are cooked and okra is crisp-tender.", "Remove drumsticks; remove bones, if desired. Ladle soup into bowls; add chicken to each serving.Stovetop Method: In 5- or 6-quart covered Dutch oven, simmer all ingredients except shrimp and okra, 1 hour and 10 minutes.", "Add shrimp and okra; simmer 5 to 8 minutes.This recipe yields 8 servings."]'::jsonb, 'https://www.foodista.com/recipe/25VNNKMX/jambalaya-soup', 'https://img.spoonacular.com/recipes/648430-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
