INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cornmeal-crusted-catfish-with-cajun-seasoning-and-spicy-tartar-sauce', 'Cornmeal-Crusted Catfish with Cajun Seasoning and Spicy Tartar Sauce', 4, 0, 0, '{"calories": 406, "protein": 26.7, "carbs": 15.41, "fat": 26.13, "saturated_fat": 4.56, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 712.11, "potassium": null, "fiber": 1.91, "sugar": 2.35, "vitamin_a": null, "vitamin_c": 6.54, "calcium": 44.47, "iron": 1.43}'::jsonb, ARRAY['cajun', 'creole', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'pescatarian', 'spoonacular', 'dessert'], '[{"quantity": 1.0, "unit": "large", "item": "egg", "notes": "1 large egg", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tbsp", "item": "milk", "notes": "1 tbsp milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.33333334, "unit": "cup", "item": "cornmeal", "notes": "1/3 cup yellow cornmeal", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tsp", "item": "chile powder", "notes": "1 tsp chile powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "cayenne powder", "notes": "1/2 tsp cayenne powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "paprika", "notes": "1/2 tsp hot smoked paprika", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "granulated garlic", "notes": "1/2 tsp granulated garlic", "category": "spices and seasonings"}, {"quantity": 20.0, "unit": "oz", "item": "catfish filets", "notes": "4 5-oz. skinless catfish filets", "category": "seafood"}, {"quantity": 3.0, "unit": "tbsp", "item": "olive oil", "notes": "3 tbsp olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "servings", "item": "sea salt", "notes": "sea salt", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "pepper", "notes": "freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 0.75, "unit": "cup", "item": "mayonnaise", "notes": "3/4 cup light mayonnaise", "category": "condiments"}, {"quantity": 2.0, "unit": "tbsp", "item": "dill pickle", "notes": "2 tbsp finely chopped dill pickle", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "tbsp", "item": "jalapeno chile", "notes": "1 tbsp finely chopped jalapeno chile", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "tbsp", "item": "scallion", "notes": "1 tbsp finely chopped scallion (white and green parts)", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "dill pickle juice", "notes": "1 tsp dill pickle juice", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "tsp", "item": "lemon juice", "notes": "1 tsp fresh lemon juice", "category": "produce"}]'::jsonb, '["Whisk the egg and milk in a medium bowl.", "Combine the cornmeal, chile powder, cayenne powder, paprika, and garlic in a large zip-top bag.", "Dip each catfish filet in the egg mixture.", "Let excess egg drip off and place the filets in the bag with the cornmeal mixture. Zip the top and shake the bag until all pieces are well coated.", "Remove the filets and lay side by side on a plate (do not overlap).", "Place in the refrigerator for 30 minutes. (Refrigeration helps keep the crust adhered during cooking.)", "While the fish chills, make the sauce.", "Whisk the first 6 ingredients (through lemon juice) in a small bowl. Season with salt and pepper and set aside.", "Heat a large, nonstick skillet over medium heat and add the olive oil. When the oil is hot (but not smoking), season the catfish filets with salt and pepper and add to the skillet. Fry until crispy on the outside and tender on the inside, 3-4 minutes per side, depending on thickness.", "Divide the fish among 4 plates and top each with a dollop of tartar sauce or pass the sauce at the table."]'::jsonb, 'https://www.foodista.com/recipe/XGXZYJ88/cornmeal-crusted-catfish-with-cajun-seasoning-and-spicy-tartar-sauce', 'https://img.spoonacular.com/recipes/640166-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
