alsa', 'https://img.spoonacular.com/recipes/640062-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spicy-black-eyed-pea-curry-with-swiss-chard-and-roasted-eggplant', 'Spicy Black-Eyed Pea Curry with Swiss Chard and Roasted Eggplant', 6, 0, 0, '{"calories": 128, "protein": 6.73, "carbs": 23.17, "fat": 2.2, "saturated_fat": 0.34, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 551.5, "potassium": null, "fiber": 8.23, "sugar": 7.24, "vitamin_a": null, "vitamin_c": 28.12, "calcium": 59.15, "iron": 3.04}'::jsonb, ARRAY['indian', 'asian', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "black-eyed peas", "notes": "2/3 cup dried black-eyed peas (2 cups cooked)", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "teaspoons", "item": "curry powder", "notes": "2 teaspoons curry powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "garam masala", "notes": "1/2 teaspoon garam masala", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "large", "item": "globe", "notes": "1 large globe or Italian eggplant", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground coriander", "notes": "1/2 teaspoon ground coriander", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground cumin", "notes": "1/2 teaspoon ground cumin", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground mustard powder", "notes": "1/2 teaspoon ground mustard powder", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "", "item": "juice of lemon", "notes": "juice from 1 lemon (3 tablespoons)", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "olive oil", "notes": "2 teaspoons olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "", "item": "chilies", "notes": "2 green or red chilies, seeded and finely chopped", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sea salt", "notes": "1 teaspoon sea salt, or to taste", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "shallots", "notes": "2 shallots, mined", "category": "produce"}, {"quantity": 1.0, "unit": "bunch", "item": "swiss chard", "notes": "1 bunch Swiss chard, trimmed and chopped", "category": "produce"}, {"quantity": 1.0, "unit": "medium", "item": "tomato", "notes": "1 medium tomato, finely chopped", "category": "produce"}, {"quantity": 5.0, "unit": "tablespoons", "item": "water", "notes": "5 tablespoons water, or more as needed", "category": "beverages"}]'::jsonb, '["Rinse the black-eyed peas and soak in several inches of water for 6 hours or overnight.", "Drain and rinse, then transfer to a large saucepan and cover with fresh water. Bring to a boil, reduce heat to medium-low, cover, and simmer for 40 to 60 minutes. Take care not to overcook  the beans should be tender but not be falling apart.", "Drain and set aside.To prepare the eggplant, cut of the stem and bottom edge and then cut in half lengthwise. Score the flesh into diagonal 1-inch lines, then turn and score again until you have a diagonal pattern. Take care not to cut through the skin.", "Sprinkle with some salt and let sit for 40 minutes. Rinse and squeeze out any excess water.", "Brush the eggplant with some oil and transfer to a roasting pan.", "Bake in a preheated 400 oven until the flesh appears collapsed and is wrinkly.", "Remove from heat and let cool for about 10 minutes, season with a bit of salt, and remove the flesh from the eggplant. If there is too much water, drain in a strainer. Set aside.", "Heat the oil over medium heat in the same saucepan used to cook the black-eyed peas. When hot, toss in the shallots and chilies and saut for 2 to 3 minutes. Now add the spices and stir for another minute, until fragrant.", "Add the tomato, cook for another few minutes, and then add the eggplant and black-eyed peas, and cook for another few minutes, stirring often.", "Pour a few tablespoons of water into the pan and add handfuls of chard at a time until wilted.", "Add more water as necessary.", "Add the lemon juice and salt to taste near the end of the cooking time.", "Remove from heat, cover, and let sit for a few minutes before serving."]'::jsonb, 'https://www.foodandspice.com/2016/08/spicy-black-eyed-pea-curry-with-swiss.html', 'https://img.spoonacular.com/recipes/798400-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('strawberry-mango-quinoa-salad', 'Strawberry-Mango Quinoa Salad', 4, 0, 0, '{"calories": 353, "protein": 7.78, "carbs": 45.92, "fat": 16.8, "saturated_fat": 2.35, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 208.34, "potassium": null, "fiber": 6.46, "sugar": 14.33, "vitamin_a": null, "vitamin_c": 140.5, "calcium": 56.66, "iron": 2.82}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'vegetarian'], '[{"quantity": 0.75, "unit": "cup", "item": "cucumber", "notes": "3/4 cup cucumber", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "mint", "notes": "2 tablespoons chopped fresh mint", "category": "produce"}, {"quantity": 1.0, "unit": "T", "item": "honey", "notes": "1 T. honey", "category": "nut butters, jams, and honey"}, {"quantity": 2.0, "unit": "T", "item": "lime juice", "notes": "2 T. lime juice", "category": "produce"}, {"quantity": 0.5, "unit": "t", "item": "lime zest", "notes": "1/2 t. lime zest", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "mango", "notes": "1/2 mango", "category": "produce"}, {"quantity": 0.25, "unit": "c", "item": "olive oil", "notes": "1/4 c. olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "servings", "item": "bell pepper", "notes": "pepper", "category": "produce"}, {"quantity": 1.0, "unit": "c", "item": "quinoa", "notes": "1 c. quinoa, well rinsed", "category": "pasta and rice"}, {"quantity": 4.0, "unit": "servings", "item": "salt", "notes": "salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "T", "item": "cream", "notes": "1 T. sour cream (or plain yogurt can be subbed)", "category": "milk, eggs, other dairy"}, {"quantity": 1.5, "unit": "cups", "item": "strawberries", "notes": "1 1/2 cups strawberries, hulled and quartered", "category": "produce"}, {"quantity": 1.5, "unit": "c", "item": "water", "notes": "1 1/2 c. water", "category": "beverages"}]'::jsonb, '["Prepare the quinoa: In a medium saucepan combine the quinoa, water and 1/4 t. salt. Bring to a boil, reduce heat to low, cover and simmer until the liquid is just absorbed, about 15 minutes.", "Spread the cooked quinoa out on a baking sheet to cool for about 20 minutes.In a large bowl whisk together lime juice, zest, honey, sour cream and olive oil.", "Add the cooled quinoa, strawberries, mango, cucumber and mint. Toss well to combine and season with salt &amp; pepper.", "Serve immediately."]'::jsonb, 'https://www.foodista.com/recipe/K2BYJP76/strawberry-mango-quinoa-salad', 'https://img.spoonacular.com/recipes/661925-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
