und pepper", "notes": "fresh ground black pepper to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "juice of lemon", "notes": "juice from 1 lemon", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 - 3 tablespoons olive oil (or more to achieve your desired consistency", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "", "item": "chilies", "notes": "2 fresh green or red chilies, seeded and chopped", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sea salt", "notes": "1 teaspoon sea salt, or to taste", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "tahini", "notes": "1/4 cup tahini", "category": "health foods"}, {"quantity": 1.0, "unit": "teaspoon", "item": "turmeric", "notes": "1 teaspoon turmeric", "category": "spices and seasonings"}]'::jsonb, '["Rinse the chickpeas and soak for 8 hours or overnight covered in several inches of water with a little yogurt whey or lemon juice added.", "Drain and rinse, then transfer to a large saucepan.  Cover with several inches of fresh water, bring to a boil, reduce the heat to medium-low and cover.  Simmer for 1 to 1 1/2 hours or until the beans are buttery soft.", "Drain.In a food processor, combine all of the ingredients and process until you have a thick, smooth paste. You may need to add extra olive oil or a bit of water if you want a thinner paste. Makes 3 cups, nutrition information is based on 1/4 cup serving."]'::jsonb, 'https://www.foodandspice.com/2012/07/spicy-hummus-indian-style.html', 'https://img.spoonacular.com/recipes/716195-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
