INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('curried-butternut-squash-and-apple-soup', 'Curried Butternut Squash and Apple Soup', 1, 0, 0, '{"calories": 134, "protein": 7.47, "carbs": 23.64, "fat": 2.66, "saturated_fat": 0.42, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 63.89, "potassium": null, "fiber": 5.36, "sugar": 9.56, "vitamin_a": null, "vitamin_c": 65.79, "calcium": 130.01, "iron": 1.75}'::jsonb, ARRAY['antipasti', 'soup', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 3.5, "unit": "oz", "item": "cauliflower", "notes": "1 cup chopped cauliflower (3.5 oz)", "category": "produce"}, {"quantity": 2.5, "unit": "oz", "item": "butternut squash", "notes": "1/2 cup chopped butternut squash (2.5 oz)", "category": "produce"}, {"quantity": 2.0, "unit": "oz", "item": "apple", "notes": "1/2 cup peeled and chopped apple (2 oz)", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "water", "notes": "1 cup water, plus about 1/2 cup extra", "category": "beverages"}, {"quantity": 2.0, "unit": "tsp", "item": "braggs liquid aminos", "notes": "2-3 tsp Braggs liquid aminos", "category": "condiments"}, {"quantity": 0.5, "unit": "tsp", "item": "curry powder", "notes": "1/2 heaping tsp: curry powder (or even 1 tsp, if you like the heat), garlic powder, onion powder", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "tsp", "item": "ginger powder", "notes": "1/4 tsp ginger powder", "category": "spices and seasonings"}, {"quantity": 0.125, "unit": "tsp", "item": "a squirt sriracha", "notes": "a small squirt (1/8 tsp) sriracha", "category": "condiments"}, {"quantity": 0.125, "unit": "", "item": "block lite tofu", "notes": "1/8 block pressed lite firm tofu, cubed", "category": "produce"}]'::jsonb, '["Get ready two small saucepans.", "In one have together 1/2 of the squash and 1/2 of the apple  bring to a simmer, and simmer until just tender when pierced with a fork.", "In the other, add in the rest of the vegetables along with 1 cup of water  bring this to a rolling boil, reduce to a simmer, and simmer until very very tender. When very tender, remove the vegetables from the heat, and blend these vegetables together (without draining) with the Braggs, spices, sriracha and the additional 1/2 cup water.", "Mix the blended part of the soup with the simmered squash and apples.", "Mix in the cubed tofu, gently re-heat and serve."]'::jsonb, 'https://www.foodista.com/recipe/FKQCYKYR/curried-butternut-squash-and-apple-soup', 'https://img.spoonacular.com/recipes/641057-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('amaranth-and-roast-veggie-salad', 'Amaranth and Roast Veggie Salad', 2, 0, 0, '{"calories": 360, "protein": 9.32, "carbs": 43.97, "fat": 18.02, "saturated_fat": 2.75, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 214.87, "potassium": null, "fiber": 6.82, "sugar": 8.01, "vitamin_a": null, "vitamin_c": 112.44, "calcium": 169.97, "iron": 4.93}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "amaranth", "notes": "1/2 cup amaranth", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "servings", "item": "basil-infused olive oil", "notes": "basil-infused olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "servings", "item": "bell pepper", "notes": "pepper", "category": "produce"}, {"quantity": 0.5, "unit": "packet", "item": "pumpkin", "notes": "1/2 packet diced pumpkin", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 red onion", "category": "produce"}, {"quantity": 9.0, "unit": "servings", "item": "rocket leaves", "notes": "few rocket leaves", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "herbal salt", "notes": "herbal salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "", "item": "punnet baby tomatoes", "notes": "1/2 punnet (basket) baby tomatoes", "category": "produce"}]'::jsonb, '["Cook the amaranth with about a cup of water until it reaches a sticky consistency", "Cut the onion roughly into chunks", "Add the onion and diced pumpkin to a tinfoil lined baking tray", "Drizzled over the olive oil and sprinkle with the herbal salt and pepper", "Put into a hot oven and roast until the edges of the pumpkin go crispy", "Just before the veggies are done, throw in the baby tomatoes", "Coat the veggies in the cooked amaranth", "Tear a few rocket leaves", "Toss together and there you have it, an unusual roast veggie salad!", "Serve warm"]'::jsonb, 'https://www.foodista.com/recipe/BPXZ2RCY/amaranth-and-roast-veggie-salad', 'https://img.spoonacular.com/recipes/632269-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
