INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('butternut-squash-soup-in-half-an-hour', 'Butternut Squash Soup (In Half An Hour!)', 8, 0, 0, '{"calories": 251, "protein": 8.73, "carbs": 42.38, "fat": 6.49, "saturated_fat": 1.3, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 666.45, "potassium": null, "fiber": 8.51, "sugar": 5.97, "vitamin_a": null, "vitamin_c": 33.24, "calcium": 158.12, "iron": 3.1}'::jsonb, ARRAY['antipasti', 'soup', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "", "item": "butternut squash", "notes": "1 butternut squash, peeled, seeded and cut into small cubes", "category": "produce"}, {"quantity": 1.0, "unit": "can", "item": "black-eyed peas", "notes": "1 can black-eyed peas", "category": "canned and jarred"}, {"quantity": 8.0, "unit": "servings", "item": "collard greens", "notes": "Collard greens (my choice), kale, spinach, beet greens, etc. cut into small pieces", "category": "produce"}, {"quantity": 8.0, "unit": "servings", "item": "quinoa", "notes": "Leftover cooked quinoa", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "piece", "item": "kombu", "notes": "1 piece of kombu", "category": "ethnic foods"}, {"quantity": 8.0, "unit": "servings", "item": "nutmeg", "notes": "Nutmeg", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "T", "item": "olive oil", "notes": "2 T butter, ghee, or olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 8.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper", "category": "spices and seasonings"}, {"quantity": 32.0, "unit": "oz", "item": "vegetable broth", "notes": "1 32 oz. organic vegetable broth (I like the Pacifica brand for its lack of unnecessary ingredients)", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "small", "item": "onions", "notes": "1-2 small yellow onions, cut up", "category": "produce"}]'::jsonb, '["In large pot, saute onion in butter, ghee or olive oil until soft", "Add cubed squash and saute for a couple of minutes", "Add vegetable stock and 1 3 inch piece of kombu and bring to a boil", "Reduce heat and simmer until squash is soft (about 15 minutes)Using a slotted spoon, remove squash and puree in blender", "Return squash to pot and stir in black-eyed peas and cooked quinoa.", "Add greens for about five minutes until soft", "Add nutmeg, sea salt and pepper to taste"]'::jsonb, 'https://www.foodista.com/recipe/24DYGNYL/butternut-squash-soup-in-half-an-hour', 'https://img.spoonacular.com/recipes/636602-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
