INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('radish-snap-pea-quinoa-salad', 'Radish & Snap Pea Quinoa Salad', 4, 0, 0, '{"calories": 262, "protein": 11.24, "carbs": 39.09, "fat": 7.31, "saturated_fat": 1.23, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 231.39, "potassium": null, "fiber": 6.56, "sugar": 5.68, "vitamin_a": null, "vitamin_c": 75.19, "calcium": 114.07, "iron": 4.83}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "quinoa", "notes": "1 cup quinoa, rinsed", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "cups", "item": "water", "notes": "2 cups water", "category": "beverages"}, {"quantity": 1.0, "unit": "pint", "item": "snap peas", "notes": "1 pint snap peas, cut in half (about 2 cups total)", "category": "produce"}, {"quantity": 7.0, "unit": "medium", "item": "radishes", "notes": "7 or 8 medium radishes, sliced", "category": "produce"}, {"quantity": 1.0, "unit": "large handful", "item": "flat leaf parsley", "notes": "large handful of flat leaf parsley, minced", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "yogurt", "notes": "1/4 cup plain yogurt (cultured coconut milk is my favorite option, but any plain yogurt will work)", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "tbsp", "item": "tahini", "notes": "2 tbsp tahini", "category": "health foods"}, {"quantity": 0.5, "unit": "", "item": "juice of lemon", "notes": "juice of 1/2 a lemon", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "sea salt", "notes": "sea salt to taste", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "water", "notes": "water as needed", "category": "beverages"}]'::jsonb, '["Make the quinoa: combine the quinoa and water in a sauce pan and bring to a boil.  Reduce the heat to a simmer (medium-low), stir the quinoa, then cover it and cook for 10 to 15 minutes until all of the water has been absorbed.", "Remove it from the heat, let it sit for 5 minutes, then fluff it up with a fork.  Cool the quinoa a bit before making the salad.  The quinoa can be made several days in advance and kept in the fridge if needed before using.", "Combine the yogurt, tahini, lemon juice, and a pinch of sea salt in a bowl and whisk until smooth.  Thin the dressing out with a bit of water if it is too thick.  Set aside.", "Combine the quinoa, snap peas, radishes, and parsley in a bowl.", "Pour over about half of the dressing, then toss to combine.  Taste the salad and add more dressing or sea salt if desired.  Enjoy at room temperature or chilled.  Makes 3 to 4 main dish servings or 6 to 8 side servings."]'::jsonb, 'https://www.foodista.com/recipe/684WRQ6L/radish-snap-pea-quinoa-salad', 'https://img.spoonacular.com/recipes/657719-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
