s. Top with almonds."]'::jsonb, 'https://www.foodista.com/recipe/4KHXC282/baby-bok-choy-stir-fry', 'https://img.spoonacular.com/recipes/633226-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('baked-penne', 'Baked Penne', 8, 0, 0, '{"calories": 237, "protein": 10.18, "carbs": 48.59, "fat": 1.13, "saturated_fat": 0.17, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 221.81, "potassium": null, "fiber": 5.58, "sugar": 4.89, "vitamin_a": null, "vitamin_c": 29.16, "calcium": 80.05, "iron": 2.05}'::jsonb, ARRAY['side dish', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'pasta', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "small", "item": "butternut squash", "notes": "1 small butternut squash, peeled& seeded", "category": "produce"}, {"quantity": 0.5, "unit": "large", "item": "onion", "notes": "1/2 large onion, chopped", "category": "produce"}, {"quantity": 4.0, "unit": "", "item": "baby portobella mushrooms", "notes": "4 baby portobella mushrooms, chopped", "category": "produce"}, {"quantity": 12.0, "unit": "ounces", "item": "penne pasta", "notes": "12 ounces penne pasta (I used Garden Delight, any would work)", "category": "pasta and rice"}, {"quantity": 0.25, "unit": "cup", "item": "tomato paste", "notes": "1/4 cup tomato paste", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "", "item": "jalapeño pepper", "notes": "1 jalapeño pepper, chopped& partially seeded (depends how hot you want it!)", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "cup", "item": "water", "notes": "1 cup water", "category": "beverages"}, {"quantity": 1.0, "unit": "cup", "item": "nutritional yeast", "notes": "cup nutritional yeast", "category": "health foods"}, {"quantity": 0.5, "unit": "teaspoon", "item": "garlic powder", "notes": "1/2 teaspoon garlic powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "pepper", "notes": "1/2 teaspoon black pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "seasoning", "notes": "1 teaspoon Italian seasoning", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cups", "item": "kale", "notes": "2 cups kale, chopped", "category": "produce"}]'::jsonb, '["Preheat the oven to 400*.", "Chop butternut squash into 1\" pieces and roast on a baking sheet sprayed with cooking spray until lightly browned, about 30-40 minutes.", "Once the squash is done baking, reduce heat to 350*.", "Bring a pot of water to a boil and cook pasta according to package directions, using the shortest recommended cooking time.", "While pasta is cooking, saute onions and mushrooms.", "In a food processor, combine about 1 cup roasted butternut squash cubes, tomato paste, jalapeo, water, nutritional yeast, garlic powder, salt, black pepper, and Italian seasoning until well blended.", "Mix with drained pasta, onions, mushrooms and kale.", "Spray a 9\"x13\" pan with cooking spray and pour pasta mixture into pan.", "Bake uncovered at 350* for 30 minutes."]'::jsonb, 'https://www.foodista.com/recipe/VVH5Y7PG/baked-penne', 'https://img.spoonacular.com/recipes/633711-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spicy-lentil-and-black-rice-soup-with-kale-spinach-and-leek', 'Spicy lentil and black rice soup with kale, spinach and leek', 12, 0, 0, '{"calories": 202, "protein": 10.82, "carbs": 38.01, "fat": 1.25, "saturated_fat": 0.21, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 759.28, "potassium": null, "fiber": 12.35, "sugar": 3.36, "vitamin_a": null, "vitamin_c": 18.69, "calcium": 92.26, "iron": 3.87}'::jsonb, ARRAY['antipasti', 'soup', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "rice", "notes": "1 cup black rice", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "cups", "item": "carrot", "notes": "2 cups diced carrot", "category": "produce"}, {"quantity": 0.25, "unit": "tsp", "item": "cayenne", "notes": "1/4 tsp cayenne", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "celery stalks", "notes": "2 celery stalks (diced)", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "chili powder", "notes": "1 tablespoon chili powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "cumin", "notes": "1 tsp cumin", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cups", "item": "green lentils", "notes": "2 cups green lentils", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "tsp", "item": "thyme", "notes": "1 tsp dried thyme", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "", "item": "garlic cloves", "notes": "3 garlic cloves (minced)", "category": "produce"}, {"quantity": 1.0, "unit": "bunch", "item": "kale", "notes": "1 bunch kale (chopped - I used purple kale but you can use any type)", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "leek", "notes": "1 leek (sliced)", "category": "produce"}, {"quantity": 0.5, "unit": "tsp", "item": "oregano", "notes": "1/2 tsp oregano", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "cracked pepper", "notes": "1 tsp cracked black pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 red onion (diced)", "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "sea salt", "notes": "2 tsp sea salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "bunch", "item": "spinach", "notes": "1/2 bunch fresh spinach (chopped)", "category": "produce"}, {"quantity": 4.0, "unit": "cups", "item": "vegetable broth", "notes": "4 cups vegetable broth", "category": "canned and jarred"}, {"quantity": 10.0, "unit": "cups", "item": "water", "notes": "10 cups water", "category": "beverages"}]'::jsonb, '["Start by soaking your beautiful green lentils in water while you dice up all of your veggies.While your lentils are soaking in the water, chop up your  carrots, celery, garlic, onion and leek.Once all your veggies are chopped, heat up the olive oil in a stock pot over medium high heat and add the diced veggies.  Cook just until the the onion and garlic softens, about 7 minutes or so.While your veggies are cooking, chop up your kale and get it ready to go, but don''t add it yet.  You don''t need to worry about chopping the spinach leaves, when it comes time to add them, just use the whole leaf.Once your veggies are cooked, drain your lentils and add them and the rice to the veggies. If you can''t find a black rice, just use wild rice.Give the veggies, rice and lentils a stir and then add your veggie broth, water, kale, spinach and all of the spices and turn the heat to high.Keep the burner on high just until the soup boils, reduce the heat to low and cover for 25 minutes. Covering the soup will ensure that the lentils and rice cook thoroughly.After the soup cooks covered for 25 minutes, remove the cover and continue to cook on low for another 30 minutes or so.  I added another 1/2 tsp of salt and a bit of pepper for flavoring at this point and it was a perfect balance.After the final 30 minutes of simmer, simply serve and enjoy!"]'::jsonb, 'https://www.foodista.com/recipe/CWDP84PH/spicy-lentil-and-black-rice-soup-with-kale-spinach-and-leek', 'https://img.spoonacular.com/recipes/661122-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('quinoa-tomato-green-onion-side-salad', 'Quinoa, Tomato, Green Onion Side Salad', 2, 0, 0, '{"calories": 396, "protein": 10.84, "carbs": 50.04, "fat": 18.24, "saturated_fat": 2.43, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 216.82, "potassium": null, "fiber": 7.34, "sugar": 4.49, "vitamin_a": null, "vitamin_c": 35.86, "calcium": 72.87, "iron": 3.86}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "green onions", "notes": "1/2 cup minced green onions", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "lemon", "notes": "1/2 lemon", "category": "produce"}, {"quantity": 2.0, "unit": "Tbs", "item": "olive oil", "notes": "2 Tbs. olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.75, "unit": "cup", "item": "quinoa", "notes": "3/4 cup uncooked quinoa", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "medium size", "item": "tomatoes", "notes": "2 medium size tomatoes", "category": "produce"}, {"quantity": 1.5, "unit": "cups", "item": "water", "notes": "1-1/2 cups water", "category": "beverages"}]'::jsonb, '["Put your quinoa and your water in a pan.", "Heat over medium heat until bubbling, then cover and reduce heat to low. Cook for about 15 minutes or until all the water is absorbed.While your quinoa is cooking, get out and wash your green onions and tomatoes. Chop them roughly.Chop a lemon in half and squeeze one half''s juice into a bowl, picking out the seeds.", "Let your quinoa cool. A little warm is fine.", "Add olive oil, lemon juice, and tomatoes and green onions to the pan. Stir.", "Add salt and pepper to your liking.", "Serve chilled"]'::jsonb, 'https://www.foodista.com/recipe/ZHJ4PP8P/quinoa-tomato-green-onion-salad', 'https://img.spoonacular.com/recipes/657698-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vegan-colcannon-soup', 'Vegan Colcannon Soup', 8, 0, 0, '{"calories": 186, "protein": 5.56, "carbs": 34.51, "fat": 4.05, "saturated_fat": 0.58, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 615.5, "potassium": null, "fiber": 5.05, "sugar": 3.67, "vitamin_a": null, "vitamin_c": 40.15, "calcium": 98.73, "iron": 2.17}'::jsonb, ARRAY['european', 'irish', 'antipasti', 'soup', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'whole 30', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "extra virgin olive oil", "notes": "2 tablespoons extra virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "medium", "item": "leeks", "notes": "2 medium leeks, tough green outer leaves removed, washed well (see Kitchen Tip), and thinly sliced", "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves garlic, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "stalk", "item": "celery", "notes": "1 stalk celery (with leaves), roughly chopped", "category": "produce"}, {"quantity": 3.0, "unit": "large", "item": "russet potatoes", "notes": "3 large russet potatoes, peeled and cut into cubes (about 2 cups)", "category": "produce"}, {"quantity": 3.0, "unit": "cups", "item": "savoy cabbage", "notes": "¼ head savoy cabbage, roughly chopped (3 cups)", "category": "produce"}, {"quantity": 8.0, "unit": "cups", "item": "kale", "notes": "1 head kale, stemmed and roughly chopped (about 8 cups)", "category": "produce"}, {"quantity": 8.0, "unit": "cups", "item": "vegetable broth", "notes": "8 cups Roasted Vegetable Stock or store-bought low-sodium vegetable broth", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "teaspoons", "item": "kosher salt", "notes": "2 teaspoons kosher salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "pepper", "notes": "1 teaspoon freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "juice of lemon", "notes": "Juice of 1 lemon", "category": "produce"}]'::jsonb, '["Heat the oil in a large stockpot set over medium-high heat, until it shimmers.", "Add the leeks, garlic, and celery, and cook, stirring frequently, for 3 to 4 minutes, until the edges are golden.", "Add the parsnips, potatoes, cabbage, kale, stock, salt, and pepper and stir well. Reduce the heat to medium and cover.", "Bring the soup to a boil; then reduce the heat to a low simmer. Cook for 30 to 35 minutes, until the vegetables are tender and soft.", "Add the lemon juice.", "Using an immersion blender (or working in batches in a blender), pure until completely smooth.", "Serve immediately or store in an airtight container for up to 3 days."]'::jsonb, 'https://www.foodista.com/recipe/LKGLSJ48/vegan-colcannon-soup', 'https://img.spoonacular.com/recipes/664419-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('seasonal-autumn-stew', 'Seasonal Autumn Stew', 4, 0, 0, '{"calories": 231, "protein": 7.21, "carbs": 47.56, "fat": 4.8, "saturated_fat": 0.75, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 627.14, "potassium": null, "fiber": 11.59, "sugar": 15.61, "vitamin_a": null, "vitamin_c": 81.47, "calcium": 230.43, "iron": 4.18}'::jsonb, ARRAY['antipasti', 'soup', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'whole 30', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 2.0, "unit": "", "item": "bay leaves", "notes": "2 bay leaves", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "medium", "item": "butternut squash", "notes": "1 medium butternut squash, cubed", "category": "produce"}, {"quantity": 1.0, "unit": "can", "item": "canned tomatoes", "notes": "1 can (28 oz, 796 ml) whole tomatoes, pureed", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "teaspoon", "item": "chili flakes", "notes": "1 teaspoon chili flakes", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "pinches", "item": "cinnamon", "notes": "1 pinches of cinnamon", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "fennel bulb", "notes": "1 fennel bulb, thinly sliced", "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves garlic, minced", "category": "produce"}, {"quantity": 0.5, "unit": "bunch", "item": "kale", "notes": "1/2 bunch of kale", "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "mushrooms", "notes": "2 cups mushrooms, thinly sliced", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "olive oil", "notes": "1 tablespoon olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 onion, diced", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "parsnip", "notes": "1 parsnip, cored and diced", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "rosemary", "notes": "1 tablespoon rosemary, minced", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "vegetable broth", "notes": "1 cup vegetable broth", "category": "canned and jarred"}]'::jsonb, '["In a large soup pot, heat the olive oil over a medium heat. Cook onions, stirring, until golden and beginning to caramelize.", "Add garlic, fennel, squash, parsnip, rosemary, bay leaves, salt and pepper. Continue to cook for about five minutes until the vegetables start to soften.", "Add stock, pureed tomatoes and chili flakes. Cover and simmer until the vegetables are tender, about 15 minutes.Meanwhile, saute thinly sliced mushrooms in a little olive oil and butter until they start to brown.Once the vegetables are tender, add mushrooms and kale to the stew along with a pinch or two of cinnamon. Taste and adjust seasoning, adding more salt, pepper or chili flakes if needed.Try serving topped with a little Italian flat leaf parsley and sour cream and whole wheat bread on the side"]'::jsonb, 'https://www.foodista.com/recipe/CS67PMR7/seasonal-autumn-stew', 'https://img.spoonacular.com/recipes/659689-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('minted-pea-spinach-soup', 'Minted Pea & Spinach Soup', 6, 0, 0, '{"calories": 184, "protein": 7.5, "carbs": 29.81, "fat": 4.66, "saturated_fat": 2.71, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 244.12, "potassium": null, "fiber": 6.75, "sugar": 10.08, "vitamin_a": null, "vitamin_c": 54.94, "calcium": 95.79, "iron": 2.85}'::jsonb, ARRAY['antipasti', 'soup', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'grilling'], '[{"quantity": 1.0, "unit": "cube", "item": "chicken stock", "notes": "1 cube chicken stock", "category": "canned and jarred"}, {"quantity": 0.25, "unit": "cup", "item": "cream", "notes": "1/4 cup cream", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "teaspoons", "item": "mint", "notes": "2 teaspoons dried mint (I like mint a lot, but you can use less if you prefer)", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "milk", "notes": "1/4 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "lb", "item": "peas", "notes": "500 grams (1 lb) frozen peas", "category": "produce"}, {"quantity": 2.0, "unit": "medium", "item": "potatoes", "notes": "2 mediums potatoes, diced", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "salt & pepper", "notes": "salt & pepper to taste", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "pound", "item": "spinach", "notes": "250 grams (½ pound) fresh spinach, chopped", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "sugar", "notes": "2 tablespoons sugar", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "water", "notes": "1 cup water (add more or less, depending on how thick you like your soup)", "category": "beverages"}, {"quantity": 2.0, "unit": "tablespoons", "item": "yoghurt", "notes": "2 tablespoons yoghurt", "category": "milk, eggs, other dairy"}]'::jsonb, '["Place pototoes in a medium sized pot with a little bit of water and some salt & pepper.", "Place lid on and cook for 20 minutes until almost soft.", "Add peas and cook for a further 5 minutes until potatoes are soft and cooked through.", "Add spinach and cook a further 3 -5 minutes, until wilted.Take off the heat and let cool for a few minutes, then blend to a puree with an immersion blender.", "Place pot back on the stovetop, adding cream, milk, water and chicken stock. Re-heat for a few minutes until piping-hot.", "Add yoghurt, mint, sugar, salt and pepper to taste and stir through.", "Serve immediately, scattered with some crispy croutons or bacon bits (or if you''re like me and you just have some cheesegrillers on hand, fry them up in thin slices with a bit of sweet chilli sauce and use as topper)."]'::jsonb, 'https://www.foodista.com/recipe/QGDZZM3X/minted-pea-spinach-soup', 'https://img.spoonacular.com/recipes/652038-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('carolina-caviar-black-bean-salsa', 'Carolina Caviar - Black Bean Salsa', 4, 0, 0, '{"calories": 432, "protein": 15.19, "carbs": 65.57, "fat": 17.17, "saturated_fat": 2.52, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 643.75, "potassium": null, "fiber": 20.6, "sugar": 13.03, "vitamin_a": null, "vitamin_c": 160.19, "calcium": 148.08, "iron": 5.69}'::jsonb, ARRAY['mexican', 'antipasti', 'condiment', 'starter', 'snack', 'appetizer', 'dip', 'antipasto', 'hor d''oeuvre', 'spread', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 15.0, "unit": "ounce", "item": "black beans", "notes": "2 cans (15 ounce) black beans, rinsed and drained", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "", "item": "avocados", "notes": "2 avocados, peeled, cored, sliced and diced", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 yellow bell pepper, cored, seeded, and diced", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "orange bell pepper", "notes": "1 orange bell pepper, cored, seeded, and diced", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 green bell pepper, cored, seeded, and diced", "category": "produce"}, {"quantity": 1.0, "unit": "bunch", "item": "green onions", "notes": "1 bunch green onions, sliced", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "onion", "notes": "1/2 of a medium red onion, finely chopped", "category": "produce"}, {"quantity": 1.0, "unit": "can", "item": "package corn", "notes": "1 can small package frozen corn, thawed or 1 yellow& white corn", "category": "produce"}, {"quantity": 2.0, "unit": "cans", "item": "rotel tomatoes and chiles", "notes": "2 cans Rotel tomatoes and chiles (be careful, this might be too", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "bunch", "item": "cilantro", "notes": "1 bunch of fresh cilantro, stems removed, leaves finely chopped", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "tablespoons", "item": "garlic", "notes": "4 tablespoons minced garlic", "category": "produce"}, {"quantity": 0.25, "unit": "", "item": "juice of lime", "notes": "1/4 juice of lime", "category": "produce"}, {"quantity": 0.25, "unit": "teaspoon", "item": "hot sauce", "notes": "1/4 teaspoon hot sauce, or to taste", "category": "condiments"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and pepper to taste", "category": "spices and seasonings"}]'::jsonb, '["Add all ingredients together in a large bowl; tasting and adjusting as you go!", "Chill in the refrigerator overnight.", "Adjust seasoning to preference levels after the salsa sets overnight and the flavors blend/marry.", "Serve with tortilla chips."]'::jsonb, 'https://www.foodista.com/recipe/YX8KH6ZY/carolina-caviar-black-bean-salsa', 'https://img.spoonacular.com/recipes/637157-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('yellow-squash-noodles-with-tomato-basil-sauce', 'Yellow Squash Noodles with Tomato Basil Sauce', 3, 0, 0, '{"calories": 219, "protein": 6.94, "carbs": 25.24, "fat": 12.83, "saturated_fat": 1.88, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 71.57, "potassium": null, "fiber": 8.28, "sugar": 15.14, "vitamin_a": null, "vitamin_c": 88.78, "calcium": 119.82, "iron": 2.58}'::jsonb, ARRAY['side dish', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'whole 30', 'vegan', 'spoonacular', 'pasta', 'vegetarian'], '[{"quantity": 3.0, "unit": "servings", "item": "squash noodles", "notes": "Yellow Squash Noodles", "category": "produce"}, {"quantity": 1.5, "unit": "Tbs", "item": "olive oil", "notes": "1 1/2 Tbs olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 5.0, "unit": "medium", "item": "roma tomatoes", "notes": "5 medium roma tomatoes, halved and seeded", "category": "produce"}, {"quantity": 4.0, "unit": "cloves", "item": "garlic", "notes": "4 cloves garlic, peeled", "category": "produce"}, {"quantity": 3.0, "unit": "", "item": "sun-dried tomatoes", "notes": "3 sun-dried tomatoes (I used the kind that is not packed in oil)", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "cup", "item": "basil leaves", "notes": "1/2 cup fresh basil leaves, loosely packed", "category": "produce"}, {"quantity": 1.0, "unit": "pinch", "item": "sea salt", "notes": "pinch of sea salt", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "large", "item": "squash", "notes": "3 large yellow squash", "category": "produce"}, {"quantity": 0.6666667, "unit": "cup", "item": "plum tomatoes", "notes": "2/3 cup yellow plum tomatoes (optional)", "category": "produce"}, {"quantity": 3.0, "unit": "servings", "item": "sautéed fennel", "notes": "Sautéed Fennel (Optional)", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "fennel bulb", "notes": "1 fennel bulb, thinly sliced", "category": "produce"}, {"quantity": 1.0, "unit": "Tbs", "item": "olive oil", "notes": "1 Tbs olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "Tbs", "item": "dill", "notes": "1 Tbs fresh dill, chopped", "category": "produce"}]'::jsonb, '["Heat 1 and 1/2 tablespoons of olive oil in a small saut pan over medium-high heat. When the pan is hot, add the garlic and tomatoes cut side down.", "Let the tomatoes cook for 3 minutes before turning them over. Cook for another 2-3 minutes and then turn off the heat.", "In a food processor or blender, mix the sauted tomatoes, garlic, sun-dried tomatoes, basil, and salt until smooth.", "Cut off both ends of each of the yellow squash. Spiralize the squash with Blade B, and chop the noodles several times so that they are easier to eat. Be sure to slice the part of the squash that is not spiralized and mix them with the noodles. NOTE: If you do not own a spiralizer, use a vegetable peeler to create yellow squash ribbons.", "If you are adding fennel to this dish, heat a tablespoon of oil in a small saut pan over medium-high heat. When the pan is hot, add the fennel and saut them for about 4-5 minutes or until they turn translucent. Season with some fresh dill and salt.", "In a large bowl, mix the noodles and sauce together.", "Serve with the fennel and plum tomatoes.", "Refrigerate any leftovers in an airtight container."]'::jsonb, 'https://www.foodista.com/recipe/PTQSXRCL/yellow-squash-noodles-with-tomato-basil-sauce', 'https://img.spoonacular.com/recipes/665527-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('quinoa-tabouli-salad', 'Quinoa Tabouli Salad', 4, 0, 0, '{"calories": 244, "protein": 8.09, "carbs": 35.6, "fat": 8.48, "saturated_fat": 1.11, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 309.82, "potassium": null, "fiber": 5.6, "sugar": 4.54, "vitamin_a": null, "vitamin_c": 42.66, "calcium": 69.11, "iron": 3.5}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "quinoa", "notes": "1 cup Quinoa, rinsed well", "category": "pasta and rice"}, {"quantity": 0.5, "unit": "teaspoon", "item": "kosher salt", "notes": "1/2 teaspoon kosher salt plus more", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tbsp", "item": "lemon juice", "notes": "2 tbsp fresh lemon juice", "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": "1 clove minced garlic", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "quality extra virgin olive oil", "notes": "1/2 cup Good Quality Extra Virgin Olive Oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "servings", "item": "pepper", "notes": "Freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "large", "item": "hothouse cucumber", "notes": "1 large English hothouse cucumber (diced radish works too)", "category": "produce"}, {"quantity": 1.0, "unit": "pint", "item": "grape tomatoes", "notes": "1 pint grape tomatoes, halved (or try 2 carrots grated)", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "flat-leaf parsley", "notes": "1 cup chopped flat-leaf parsley", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "scallions", "notes": "2 scallions, thinly sliced", "category": "produce"}]'::jsonb, '["Prepare quinoa according to the package instructions.", "Let stand, covered, for 5 minutes. Fluff with a fork.", "Whisk lemon juice and minced garlic in a small bowl.Gradually stir in olive oil.", "Add cucumber, tomatoes, herbs, ginger, and scallions to bowl with quinoa; toss to coat.Season to taste with salt and pepper.", "Drizzle dressing over the salad and fold in to incorporate.Allow to sit and marinate for at least 1 hour before serving.Season salad to taste with salt and pepper."]'::jsonb, 'https://www.foodista.com/recipe/JKGT4W6M/a-simple-winter-salad-quinoa-tabouli', 'https://img.spoonacular.com/recipes/1096186-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('creamy-healthy-asparagus-soup-with-avocado-and-fennel', 'Creamy, Healthy Asparagus Soup with Avocado and Fennel', 4, 0, 0, '{"calories": 238, "protein": 9.0, "carbs": 24.07, "fat": 15.01, "saturated_fat": 2.22, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 242.97, "potassium": null, "fiber": 11.37, "sugar": 8.93, "vitamin_a": null, "vitamin_c": 44.53, "calcium": 133.64, "iron": 6.55}'::jsonb, ARRAY['antipasti', 'soup', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'primal', 'spoonacular'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons olive oil plus more for serving", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "large", "item": "leek and pale parts", "notes": "1 large leek white and pale green parts finely chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "fennel bulb", "notes": "1 fennel bulb thinly sliced", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "kosher salt", "notes": "Kosher salt", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "cups", "item": "chicken bone broth", "notes": "4 cups Chicken Bone Broth", "category": "meat"}, {"quantity": 2.0, "unit": "pounds", "item": "asparagus", "notes": "2 pounds asparagus trimmed and cut into 1-inch pieces", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "lemon thyme leaves", "notes": "1 tablespoon lemon thyme leaves minced", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "lemon", "notes": "1 lemon juiced", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "avocado", "notes": "1 avocado peeled, pitted, and diced", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "pepper", "notes": "Freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "tbsp", "item": "greek yogurt", "notes": "4 tbsp Greek yogurt", "category": "milk, eggs, other dairy"}]'::jsonb, '["In a large saucepan over medium-low heat, warm oil.", "Add leek and fennel and a large pinch of salt. Cook, stirring frequently, until fully softened but not browned, 3 to 5 minutes. Stir in bone broth and bring to a simmer.", "Add asparagus and thyme. Bring to a simmer and cook for 1 minute.", "Remove a few asparagus tips and use them for garnish. Continue simmering soup until asparagus is soft, 4 to 5 minutes.", "Remove from heat and add lemon juice and avocado.Blend soup using an immersion blender or in batches using a blender until it''s smooth. Season to taste with salt and pepper and serve.", "Garnish with reserved asparagus tips, fennel fronds, olive oil and Greek yogurt, if using."]'::jsonb, 'https://www.foodista.com/recipe/G532D7M3/creamy-healthy-asparagus-soup-with-avocado-and-fennel', 'https://img.spoonacular.com/recipes/1096213-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('egyptain-cauliflower-side-salad', 'Egyptain Cauliflower Side Salad', 2, 0, 0, '{"calories": 183, "protein": 3.6, "carbs": 12.29, "fat": 14.87, "saturated_fat": 2.17, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 240.79, "potassium": null, "fiber": 4.47, "sugar": 5.91, "vitamin_a": null, "vitamin_c": 167.52, "calcium": 49.9, "iron": 1.87}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'whole 30', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "small", "item": "cauliflower", "notes": "1 small cauliflower", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "cumin", "notes": "1 teaspoon cumin", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "servings", "item": "parsley", "notes": "chopped fresh parsley", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "lemon juice", "notes": "1 tablespoon lemon juice", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "olive oil", "notes": "Olive oil for drizzling", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "servings", "item": "bell pepper", "notes": "pepper", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "salt", "notes": "Salt", "category": "spices and seasonings"}]'::jsonb, '["Separate the cauliflower into medium sized pieces.Steam in a steamer (if you don''t have a steamer you can boil the cauliflower whole in water and then cut it into pieces).", "Place in a bowl.", "Mix the olive oil, cumin, lemon juice and salt and pepper.", "Pour over the cauliflower and mix.", "Garnish with parsley."]'::jsonb, 'https://www.foodista.com/recipe/C32D4Y44/egyptain-cauliflower-salad', 'https://img.spoonacular.com/recipes/642346-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chipotle-black-bean-soup-with-avocado-cream', 'Chipotle Black Bean Soup with Avocado Cream', 8, 0, 0, '{"calories": 283, "protein": 11.79, "carbs": 40.47, "fat": 9.42, "saturated_fat": 1.91, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1076.32, "potassium": null, "fiber": 16.75, "sugar": 5.83, "vitamin_a": null, "vitamin_c": 12.48, "calcium": 90.76, "iron": 4.05}'::jsonb, ARRAY['antipasti', 'soup', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'lacto ovo vegetarian', 'spoonacular'], '[{"quantity": 1.0, "unit": "small", "item": "avocado", "notes": "1 small ripe avocado, pitted, peeled and cut into cubes (about 1/2 cup)", "category": "produce"}, {"quantity": 45.0, "unit": "ounces", "item": "black beans", "notes": "3 cans (about 15 ounces each) black beans, rinsed and drained", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "cups", "item": "carrots", "notes": "4 large carrots, peeled and diced (about 2 cups)", "category": "produce"}, {"quantity": 4.0, "unit": "cups", "item": "chicken broth", "notes": "4 cups Swanson® Chicken Broth (Regular, Natural Goodness® or Certified Organic)", "category": "canned and jarred"}, {"quantity": 7.0, "unit": "ounces", "item": "chipotle peppers in adobo sauce", "notes": "1 can (7 ounces) chipotle peppers in adobo sauce, minced", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tablespoons", "item": "cilantro leaves", "notes": "2 tablespoons chopped fresh cilantro leaves", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "lemon juice", "notes": "1 tablespoon lemon juice", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "cups", "item": "onions", "notes": "2 large onions, diced (about 2 cups)", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "cream", "notes": "1/4 cup sour cream", "category": "milk, eggs, other dairy"}]'::jsonb, '["Heat the oil in a 4-quart saucepan.", "Add the carrots and onions and cook until they''re tender-crisp, stirring occasionally.", "Add the peppers and cook and stir for 1 minute.Stir the broth and beans into the saucepan and heat to a boil. Reduce the heat to low. Cook for 25 minutes.Mash the avocado with a fork in a small bowl.  Stir in the sour cream, cilantro and lemon juice.Spoon one-third of the broth mixture into a blender. Cover and blend until the mixture is smooth.", "Pour the mixture into a large bowl. Repeat twice more with the remaining broth mixture. Return the blended mixture to the saucepan. Cook over medium heat until the mixture is hot and bubbling.  Divide the soup among 8 serving bowls. Top with the avocado mixture."]'::jsonb, 'https://www.foodista.com/recipe/BLKBQ5DY/chipotle-black-bean-soup-with-avocado-cream', 'https://img.spoonacular.com/recipes/638741-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('trinidad-callaloo-soup', 'Trinidad Callaloo Soup', 4, 0, 0, '{"calories": 582, "protein": 18.78, "carbs": 38.48, "fat": 41.68, "saturated_fat": 30.65, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1073.9, "potassium": null, "fiber": 3.61, "sugar": 4.2, "vitamin_a": null, "vitamin_c": 37.74, "calcium": 159.43, "iron": 6.66}'::jsonb, ARRAY['central american', 'caribbean', 'lunch', 'soup', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'salad'], '[{"quantity": 0.5, "unit": "cup", "item": "onion", "notes": "1/2 cup chopped onion", "category": "produce"}, {"quantity": 10.0, "unit": "", "item": "okra", "notes": "10 fresh okra, chopped", "category": "produce"}, {"quantity": 1.5, "unit": "ounces", "item": "salt pork", "notes": "1 1/2 ounces salt pork or bacon, chopped", "category": "meat"}, {"quantity": 1.0, "unit": "tsp", "item": "thyme", "notes": "1 tsp. fresh thyme", "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves garlic, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "habanero chile", "notes": "1 fresh habanero chile, seeds removed and chopped", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "scallions", "notes": "1 cup chopped scallions", "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "coconut oil", "notes": "2 tbsp. coconut oil", "category": "baking"}, {"quantity": 8.0, "unit": "ounces", "item": "baby spinach leaves", "notes": "8 ounces fresh callaloo leaves, Swiss chard, or baby spinach leaves", "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "chicken stock", "notes": "2 cups chicken stock", "category": "canned and jarred"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper to taste", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cups", "item": "coconut milk", "notes": "2 cups coconut milk", "category": "milk, eggs, other dairy"}, {"quantity": 6.0, "unit": "ounces", "item": "crab meat", "notes": "6 ounces fresh crab meat, picked over for shell bits", "category": "seafood"}, {"quantity": 4.0, "unit": "servings", "item": "rice", "notes": "cooked long grain rice or prepared foo-foo (plantain)", "category": "pasta and rice"}]'::jsonb, '["Saute onion, okra, salt pork, thyme, garlic, habanero and scallions until the okra and onions brown.", "Stir in the callaloo with the chicken stock and simmer until the callaloo is tender.", "Puree with a stick blender. Adjust seasoning to taste with salt and pepper.", "Stir in coconut milk and crab, then warm gently.", "Serve with rice."]'::jsonb, 'https://www.foodista.com/recipe/YPSCBJTN/trinidad-callaloo-soup', 'https://img.spoonacular.com/recipes/663822-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('caribbean-chicken-thighs', 'Caribbean Chicken Thighs', 2, 0, 0, '{"calories": 783, "protein": 48.98, "carbs": 38.67, "fat": 48.53, "saturated_fat": 13.14, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 3722.63, "potassium": null, "fiber": 3.47, "sugar": 22.92, "vitamin_a": null, "vitamin_c": 36.14, "calcium": 110.88, "iron": 4.16}'::jsonb, ARRAY['central american', 'caribbean', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'dessert', 'baking'], '[{"quantity": 4.0, "unit": "", "item": "chicken thighs", "notes": "4 bone in chicken thighs", "category": "meat"}, {"quantity": 6.0, "unit": "oz", "item": "pineapple juice", "notes": "6 oz. pineapple juice", "category": "beverages"}, {"quantity": 3.0, "unit": "", "item": "juice of lime", "notes": "3 limes, juiced", "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves garlic, roughly chopped", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "onion", "notes": "½ onion, roughly chopped", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "green onions", "notes": "2 green onions, roughly chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "jalapeno", "notes": "1 jalapeno, roughly chopped", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "TBSP", "item": "brown sugar", "notes": "2 TBSP Brown Sugar", "category": "baking"}, {"quantity": 1.0, "unit": "", "item": "tsp cinnamon", "notes": "1 TSP Cinnamon", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "tsp allspice", "notes": "1 TSP Allspice", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "tsp ground ginger", "notes": "1 TSP Ground Ginger", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "tsp seasoning", "notes": "1 TSP Italian Seasoning", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "tsp pepper", "notes": "1 TSP Pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "TBSP", "item": "salt", "notes": "1 TBSP Salt", "category": "spices and seasonings"}]'::jsonb, '["Prepare marinade: In a food processor, add lime juice, garlic, onion, jalapeno, and green onion . Pulse until pureed.", "Pour into a small bowl, add pineapple juice, brown sugar, and spices.", "Mix together.", "In a gallon plastic bag, add chicken, and marinade.", "Mix together.", "Place in fridge and let marinate for at least 4 hours to 24 hours.", "Preheat broiler.", "Remove from bag and place chicken skin side down in a baking sheet lined with aluminum foil. Cook for 5 minutes till the tops are no longer pink. Flip over and cook for remaining 25 minutes till the skin is crispy.", "Serve immediately. Enjoy!"]'::jsonb, 'https://www.foodista.com/recipe/JQ2NJZ7B/caribbean-chicken-thighs', 'https://img.spoonacular.com/recipes/637103-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('caribbean-black-bean-and-sweet-potato-soup', 'Caribbean black bean and sweet potato soup', 6, 0, 0, '{"calories": 190, "protein": 3.68, "carbs": 34.89, "fat": 4.95, "saturated_fat": 3.9, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 2088.59, "potassium": null, "fiber": 4.82, "sugar": 11.59, "vitamin_a": null, "vitamin_c": 33.01, "calcium": 80.73, "iron": 1.79}'::jsonb, ARRAY['central american', 'caribbean', 'antipasti', 'soup', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'dessert', 'vegetarian'], '[{"quantity": 1.0, "unit": "pound", "item": "turtle beans", "notes": "1 pound dry organic black turtle beans", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "coconut oil", "notes": "2 tablespoons organic coconut oil (or olive oil)", "category": "baking"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 organic onion, chopped (I used sweet yellow)", "category": "produce"}, {"quantity": 4.0, "unit": "", "item": "jalapenos", "notes": "4 jalapenos, seeded and chopped", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tsp", "item": "ground ginger", "notes": "2 tsp ground ginger", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "ground allspice", "notes": "1/2 tsp ground allspice", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "thyme", "notes": "1/2 tsp thyme", "category": "produce"}, {"quantity": 2.0, "unit": "tsp", "item": "course sea salt", "notes": "2 tsp course sea salt", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "cups", "item": "vegetable broth", "notes": "8 cups of vegetable broth or water", "category": "canned and jarred"}, {"quantity": 4.0, "unit": "cups", "item": "sweet potatoes and into", "notes": "4 cups local or organic sweet potatoes peeled and chopped into 1/2 inch cubes", "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "brown sugar", "notes": "1 tbsp brown sugar", "category": "baking"}, {"quantity": 1.0, "unit": "bunch", "item": "green onions", "notes": "1 bunch organic green onions, thinly cut", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "cilantro", "notes": "1/2 cup fresh cilantro, chopped", "category": "spices and seasonings"}]'::jsonb, '["Rinse beans and place in a large bowl. Cover beans with   4 inches of water and soak overnight (or 8 hours). Strain and rinse black beans.", "In a large soup pot, heat the oil over medium heat.", "Add onion and jalapeno and saut for 10 minutes, until soft.", "Add beans and vegetable broth or water. Stir in ginger, allspice, thyme and salt. Bring to a boil, then reduce heat and simmer for 1 hour 30 minutes.", "Add sweet potatoes and brown sugar and simmer for an additional 30 minutes, until beans and sweet potatoes are soft.", "Puree 1 cup of the soup in a blender and then add it back into the soup pot. Stir in cilantro and green onion. Salt and pepper to taste."]'::jsonb, 'https://www.foodista.com/recipe/4YVH7XVD/caribbean-black-bean-and-sweet-potato-soup', 'https://img.spoonacular.com/recipes/637099-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('caribbean-truffle-pie', 'Caribbean Truffle Pie', 8, 0, 0, '{"calories": 702, "protein": 8.29, "carbs": 73.98, "fat": 42.58, "saturated_fat": 21.59, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 392.02, "potassium": null, "fiber": 1.88, "sugar": 34.18, "vitamin_a": null, "vitamin_c": 2.42, "calcium": 112.43, "iron": 1.92}'::jsonb, ARRAY['central american', 'caribbean', 'dessert', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 0.25, "unit": "cup", "item": "coconut", "notes": "1/4 cup coconut", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "coconut", "notes": "2 tablespoons coconut", "category": "produce"}, {"quantity": 8.0, "unit": "ounce", "item": "cream cheese", "notes": "1 package (8 ounce) cream cheese, softened", "category": "cheese"}, {"quantity": 2.0, "unit": "", "item": "egg yolks", "notes": "2 egg yolks", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "flour", "notes": "1/4 cup all-purpose flour", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "heavy whipping cream", "notes": "1/2 cup heavy whipping cream", "category": "milk, eggs, other dairy"}, {"quantity": 2.9, "unit": "ounce", "item": "lemon pudding mix", "notes": "1 package (2.9 ounce) lemon pudding mix", "category": "baking"}, {"quantity": 1.0, "unit": "slices", "item": "lime", "notes": "lime slices", "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "lime juice", "notes": "3 tablespoons lime juice", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "lime peel", "notes": "1 teaspoon grated lime peel", "category": "produce"}, {"quantity": 15.0, "unit": "ounce", "item": "pie crust", "notes": "1 (15 ounce) refrigerated pie crust", "category": "refrigerated"}, {"quantity": 6.0, "unit": "tablespoons", "item": "cream", "notes": "6 tablespoons sour cream", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "sugar", "notes": "1/4 cup sugar", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "sugar", "notes": "1/2 cup sugar", "category": "baking"}, {"quantity": 4.0, "unit": "teaspoons", "item": "butter", "notes": "4 teaspoons unsalted butter", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "cups", "item": "water", "notes": "2 cups water", "category": "beverages"}, {"quantity": 1.0, "unit": "cup", "item": "chocolate chips", "notes": "1 cup white chocolate chips", "category": "baking"}]'::jsonb, '["Heat oven to 450 degrees. Allow 1 crust pouch to stand at room temperature for 15 to 20 minutes. (Refrigerate remaining crust for a later use.)", "Remove pie crust from pouch. Unfold crust; remove plastic sheet.", "Sprinkle with 2 tablespoons coconut; press in lightly. Carefully lift crust off second plastic sheet.", "Place crust, coconut side up, in 9-inch pie pan; press in bottom and up sides of pan. Flute edge; prick crust generously with fork.", "Bake at 450 degrees for 9 to 11 minutes or until golden brown. Cool crust while preparing streusel and filling. Reduce oven temperature to 425 degrees.In small bowl, combine flour and 1/4 cup sugar. With pastry blender or fork, cut in butter until mixture resembles coarse crumbs. Stir in 1/4 cup coconut.", "Spread mixture in ungreased shallow baking pan.", "Bake at 425 degrees for 4 to 8 minutes or until golden brown, stirring every minutes. Set aside.In medium saucepan, combine pudding mix, 1/2 cup sugar, lime juice and egg yolks; mix well. Stir in 2 cups water. Cook and stir over medium heat until mixture comes to a full boil.", "Remove from heat; stir in lime peel. In small bowl, combine white chocolate chips and 1/2 cup of the hot pudding mixture; stir until chips are melted.In small bowl, beat cream cheese until light and fluffy.", "Add white chocolate chip mixture; beat until smooth. Spoon and spread in baked crust. Stir sour cream into remaining pie filling mixture; blend well. Spoon and spread over cream cheese layer. Refrigerate 2 hours or until chilled.In small bowl, beat whipping cream until stiff peaks form. Pipe or spoon around edge of pie; garnish with line slices.", "Sprinkle steusel in center of pie. Store in refrigerator."]'::jsonb, 'https://www.foodista.com/recipe/355FGG5N/caribbean-truffle-pie', 'https://img.spoonacular.com/recipes/637116-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('peppermint-white-chocolate-fudge', 'Peppermint White Chocolate Fudge', 8, 0, 0, '{"calories": 420, "protein": 2.64, "carbs": 55.63, "fat": 21.33, "saturated_fat": 9.99, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 118.74, "potassium": null, "fiber": 0, "sugar": 53.47, "vitamin_a": null, "vitamin_c": 0, "calcium": 90.83, "iron": 0}'::jsonb, ARRAY['central american', 'caribbean', 'dessert', 'gluten free', 'dairy free', 'spoonacular', 'vegetarian', 'vegan'], '[{"quantity": 2.0, "unit": "cups", "item": "chocolate chips", "notes": "2 cups white chocolate chips", "category": "baking"}, {"quantity": 12.0, "unit": "ounce", "item": "vanilla frosting", "notes": "1 Container vanilla frosting (12 ounce)", "category": "baking"}, {"quantity": 8.0, "unit": "servings", "item": "food coloring", "notes": "Red food coloring", "category": "baking"}, {"quantity": 0.5, "unit": "tsp", "item": "peppermint flavoring", "notes": "1/2 tsp peppermint flavoring", "category": "baking"}, {"quantity": 1.0, "unit": "handful", "item": "peppermint candies", "notes": "1 handful of peppermint flavored candies, crushed", "category": "sweet snacks"}]'::jsonb, '["Line an 8X8 pan with plastic wrap or wax paper", "In a large bowl, melt white chocolate chips by microwaving 30 seconds at a time, stirring between sessions.", "Add the container of vanilla frosting", "Stir well", "Add Peppermint flavoring and stir well", "Reheat for 10 seconds if needed, so the mixture is still soft enough to pour", "Pour mixture into lined pan", "Place 6-8 drops of red food coloring on the top of the warm fudge", "With a toothpick or knife, swirl the color into the top of the fudge", "Sprinkle crushed candies over the top of the fudge", "Cool in fridge until hard", "Cut and enjoy!"]'::jsonb, 'https