INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spicy-salad-with-kidney-beans-cheddar-and-nuts', 'Spicy Salad with Kidney Beans, Cheddar, and Nuts', 1, 0, 0, '{"calories": 719, "protein": 26.74, "carbs": 51.2, "fat": 49.33, "saturated_fat": 11.22, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 351.63, "potassium": null, "fiber": 17.91, "sugar": 4.84, "vitamin_a": null, "vitamin_c": 47.92, "calcium": 328.36, "iron": 6.78}'::jsonb, ARRAY['side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'vegetarian'], '[{"quantity": 15.0, "unit": "grams", "item": "almonds", "notes": "15 grams almonds", "category": "nuts"}, {"quantity": 0.5, "unit": "", "item": "avocado", "notes": "1/2 avocado", "category": "produce"}, {"quantity": 5.0, "unit": "ml", "item": "balsamic vinegar", "notes": "5 ml balsamic vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 30.0, "unit": "grams", "item": "cheddar cheese", "notes": "1/4 cup (30 grams) cheddar cheese", "category": "cheese"}, {"quantity": 113.0, "unit": "grams", "item": "kidney beans", "notes": "1/2 cup (113 grams) cooked kidney beans", "category": "canned and jarred"}, {"quantity": 150.0, "unit": "grams", "item": "greens", "notes": "150 grams mixed greens", "category": "produce"}, {"quantity": 10.0, "unit": "ml", "item": "olive oil", "notes": "10 ml olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 15.0, "unit": "grams", "item": "roasted cashews", "notes": "15 grams roasted salted cashews", "category": "savory snacks"}, {"quantity": 2.0, "unit": "", "item": "sundried tomatoes", "notes": "2-3 sundried tomatoes", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "dashes", "item": "tabasco", "notes": "2 dashes (or more if you like it hot!) Tabasco", "category": "condiments"}]'::jsonb, '["Rinse and drain the kidney beans, cut the sundried tomatoes, and tear the slice of cheese into small pieces.", "Put the mixed greens in a bowl and top with kidney beans, sundried tomatoes, cheddar cheese, and nuts.", "Mix together the olive oil, balsamic vinegar, and hot sauce in a small bowl.", "Pour the dressing over the salad.", "Fast, easy, and healthy-- one of my favorite lunches!"]'::jsonb, 'http://spoonacular.com/-1384191937003', 'https://img.spoonacular.com/recipes/157344-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
