item": "celery", "notes": "1 cup diced celery", "category": "produce"}, {"quantity": 4.0, "unit": "Tbs", "item": "raisins", "notes": "4 Tbs raisins", "category": "produce"}, {"quantity": 1.0, "unit": "can", "item": "garbanzo beans", "notes": "1 can -15oz garbanzo beans", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "cup", "item": "hazelnuts", "notes": "1 cup whole hazelnuts, toasted and chopped", "category": "baking"}, {"quantity": 0.33333334, "unit": "cup", "item": "onion", "notes": "1/3 cup diced red onion", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "parsley", "notes": "½ cup chopped parsley, loosely packed", "category": "produce"}]'::jsonb, '["Whisk together the lemon zest, lemon juice, sugar, mustard, and salt.Slowly add in the olive oil, continuing to whisk, until emulsified.Prepare the couscous according to the package instructions.Toast the hazelnuts for approximately 10 minutes at 350F.", "Let cool until safe to touch, then chop.", "Mix all remaining ingredients in a large bowl.", "Add the couscous and dressing.", "Mix well and serve."]'::jsonb, 'https://www.foodista.com/recipe/8S3RLBHN/north-by-northwest-couscous-salad', 'https://img.spoonacular.com/recipes/1096185-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('farro-salad-with-parsley-pesto', 'Farro salad with parsley pesto', 2, 0, 0, '{"calories": 411, "protein": 12.02, "carbs": 52.26, "fat": 19.67, "saturated_fat": 2.98, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 348.52, "potassium": null, "fiber": 12.52, "sugar": 4.69, "vitamin_a": null, "vitamin_c": 77.2, "calcium": 167.76, "iron": 4.63}'::jsonb, ARRAY['side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'spoonacular', 'vegetarian', 'vegan'], '[{"quantity": 0.5, "unit": "tbsp", "item": "balsamic vinegar", "notes": "1/2-1 tbsp balsamic vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "servings", "item": "pepper", "notes": "black pepper to taste", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "medium", "item": "brussels sprouts", "notes": "3-4 medium brussels sprouts, shredded", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "farro", "notes": "1/2 cup farro dry", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "cup", "item": "flat leaf parsley", "notes": "1 cup flat leaf parsley, roughly chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "garlic clove", "notes": "1 garlic clove", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "lemon juice", "notes": "Lemon juice to taste", "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "olive oil", "notes": "1 tbsp olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tbsp", "item": "parmesan", "notes": "2 tbsp parmesan, shredded", "category": "cheese"}, {"quantity": 2.0, "unit": "servings", "item": "chili flakes", "notes": "Red chili flakes", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "red/yellow onion", "notes": "1/4 cup red/yellow onion, chopped", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "salt", "notes": "Salt to taste", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "servings", "item": "sunflower seeds", "notes": "Sunflower seeds for garnishing", "category": "savory snacks"}, {"quantity": 0.5, "unit": "cup", "item": "tomatoes", "notes": "1/2 cup tomatoes, finely chopped", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "walnuts", "notes": "1/4 cup walnuts, toasted", "category": "baking"}, {"quantity": 1.5, "unit": "cups", "item": "water", "notes": "1.5 cups water", "category": "beverages"}]'::jsonb, '["Let the farro cool down after cooking in 1.5 cups water. In a big bowl, add farro, pesto, tomatoes, onions, sprouts, vinegar.", "Mix it all up nicely.", "Add salt, black pepper, lemon juicve and red chili flakes and give it a good shake. Taste and adjust seasoning.", "Serve right away or chill it in refrigerator.Before serving garnish with sunflower seeds."]'::jsonb, 'https://www.foodista.com/recipe/GBY3XST4/farro-salad-with-parsley-pesto', 'https://img.spoonacular.com/recipes/642602-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
