oil.", "Pour over the salad."]'::jsonb, 'https://www.foodista.com/recipe/VNXX86Q3/fennel-peppers-lettuce-salad', 'https://img.spoonacular.com/recipes/665831-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('roast-cauliflower-salad-with-green-beans-and-cherry-tomatoes', 'Roast Cauliflower Salad with Green Beans and Cherry Tomatoes', 6, 0, 0, '{"calories": 188, "protein": 6.46, "carbs": 20.39, "fat": 11.31, "saturated_fat": 1.46, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 239.61, "potassium": null, "fiber": 7.29, "sugar": 9.85, "vitamin_a": null, "vitamin_c": 170.23, "calcium": 91.7, "iron": 2.49}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'whole 30', 'vegan', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.5, "unit": "oz", "item": "almonds", "notes": "1.5 oz. toasted flaked almonds", "category": "nuts"}, {"quantity": 1.0, "unit": "medium", "item": "cauliflower", "notes": "1 medium cauliflower", "category": "produce"}, {"quantity": 14.0, "unit": "oz", "item": "cherry tomatoes", "notes": "14 oz. cherry tomatoes, halved or quartered.", "category": "produce"}, {"quantity": 1.0, "unit": "handful", "item": "flat leaved parsley", "notes": "A handful of flat leaved parsley chopped finely", "category": "produce"}, {"quantity": 3.0, "unit": "", "item": "garlic cloves", "notes": "3 garlic cloves chopped finely", "category": "produce"}, {"quantity": 1.1, "unit": "lb", "item": "green beans", "notes": "1.1 lb green beans", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "juice of lemon", "notes": "juice of 1/2 lemon", "category": "produce"}, {"quantity": 3.0, "unit": "tbsp", "item": "olive oil", "notes": "3 tbsp olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 6.0, "unit": "servings", "item": "bell pepper", "notes": "pepper to taste", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "salt", "notes": "Salt", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "", "item": "spring onions", "notes": "3 spring onions (scallions) chopped finely", "category": "produce"}]'::jsonb, '["Pre-heat your oven to 220C / 420F", "Place the cauliflower florets in a roasting tin.", "Drizzle over 1 tablespoon olive oil and the lemon juice.", "Sprinkle over the salt and garlic, mix through and roast in the oven for about 15 to 20 minutes or until the cauliflower has softened slightly and taken on some colour.Whilst the cauliflower is cooking place the salad ingredients in a bowl.", "Add your beans whilst they are hot.  The heat helps bring out and blend the rest of the flavours.", "Add the cauliflower to your dish (also hot if you like).", "Add the dressing ingredients to your salad and mix through until everything is covered, check for seasoning, sprinkle with the almonds and serve."]'::jsonb, 'https://www.foodista.com/recipe/ZCRN8JDC/roast-cauliflower-salad-with-green-beans-and-cherry-tomatoes', 'https://img.spoonacular.com/recipes/658414-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
