2x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('quinoa-salad-with-barberries-nuts', 'Quinoa Salad with Barberries & Nuts', 4, 0, 0, '{"calories": 458, "protein": 14.11, "carbs": 59.7, "fat": 18.73, "saturated_fat": 2.09, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 607.83, "potassium": null, "fiber": 7.16, "sugar": 0.79, "vitamin_a": null, "vitamin_c": 2.47, "calcium": 84.61, "iron": 4.16}'::jsonb, ARRAY['side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 300.0, "unit": "g", "item": "quinoa", "notes": "300g quinoa", "category": "pasta and rice"}, {"quantity": 1.5, "unit": "liters", "item": "water", "notes": "1 1/2 liters boiling water", "category": "beverages"}, {"quantity": 1.0, "unit": "tsp", "item": "salt", "notes": "1 tsp salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tbsp", "item": "olive oil", "notes": "2 tbsp olive oil (not extra-virgin, it will overpower other flavours)", "category": "oil, vinegar, salad dressing"}, {"quantity": 50.0, "unit": "g", "item": "barberries", "notes": "50g barberries", "category": "online"}, {"quantity": 4.0, "unit": "tbsp", "item": "slivered almonds", "notes": "4 tbsp slivered almonds", "category": "baking"}, {"quantity": 2.0, "unit": "tbsp", "item": "slivered pistachios", "notes": "2 tbsp slivered pistachios", "category": "savory snacks"}, {"quantity": 30.0, "unit": "g", "item": "coriander", "notes": "30g chopped coriander, chopped", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "sprigs", "item": "mint", "notes": "A few sprigs of mint, chopped", "category": "produce"}]'::jsonb, '["Put the quinoa in a sieve and rinse under running water.", "Drain.", "Pour the boiling water over quinoa in a medium saucepan.", "Add salt, stir well and cook over medium-low heat until quinoa is cooked through but still has a bite in the center.", "Drain in a sieve.Pick over the barberries, rinse in a sieve and dry on kitchen paper.While the quinoa is cooking, heat 1 tablespoon of oil in a saucepan over medium heat and lightly toast the almond slivers.", "Add the slivered pistachios, then the rest of the oil and the rinsed barberries. Cook briefly until the barberries are shiny and a little puffed.Save a tablespoon of the barberry and nut mix and a tablespoon of the chopped herbs for garnishing the finished dish.", "Mix all of the remaining nut and barberry mix, herbs and quinoa. Return to the pot and place on low heat. Cover with a lid and cook for ten minutes or until completely heated through and steam is rising. Turn into a serving dish and fluff with a fork.", "Add a little extra olive oil and a twist of black pepper if you wish.", "Sprinkle the quinoa with the rest of the berry-nut mix and chopped herbs and serve on its own as a main dish or as a side dish."]'::jsonb, 'https://www.foodista.com/recipe/PBQJCDDG/quinoa-salad-with-barberries-nuts', 'https://img.spoonacular.com/recipes/1098387-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('watermelon-zucchini-carrot-salad', 'Watermelon, Zucchini, Carrot Salad', 3, 0, 0, '{"calories": 69, "protein": 2.28, "carbs": 16.28, "fat": 0.58, "saturated_fat": 0.08, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 49.63, "potassium": null, "fiber": 3.44, "sugar": 10.21, "vitamin_a": null, "vitamin_c": 67.28, "calcium": 55.06, "iron": 1.01}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'whole 30', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 2.0, "unit": "", "item": "carrots", "notes": "2 carrots", "category": "produce"}, {"quantity": 0.25, "unit": "", "item": "zucchini", "notes": "1/4 of a zucchini", "category": "produce"}, {"quantity": 0.25, "unit": "", "item": "cabbage", "notes": "1/4 of a red cabbage", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "bell pepper", "notes": "1/2 green pepper", "category": "produce"}, {"quantity": 1.5, "unit": "cups", "item": "watermelon", "notes": "1 1/2 cups watermelon", "category": "produce"}, {"quantity": 1.0, "unit": "Handful", "item": "sunflower seeds", "notes": "Handful of sunflower seeds", "category": "savory snacks"}]'::jsonb, '["Chop the carrots, zucchini, cabbage and pepper into long thin slivers.", "Juice half a cup of the watermelon (just squeeze the juice out with your hands or use a blender). The other one cup of watermelon will be chopped up and added to the salad. Be sure to scrape the watermelon right off the rind and include some of the green portion as well- that''s where all the good stuff is, nutritionally.", "Combine all the ingredients except the watermelon juice and the sunflower seeds.", "Add the watermelon juice over the salad - A lame dressing, I know, but to be honest, you don''t even need it!", "Finish off with the sunflower seeds on top."]'::jsonb, 'https://www.foodista.com/recipe/2BVQXF4H/watermelon-zucchini-carrot-salad', 'https://img.spoonacular.com/recipes/665043-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('colorful-red-quinoa-not-so-tabbouleh-salad', 'Colorful Red Quinoa Not So Tabbouleh Salad', 4, 0, 0, '{"calories": 283, "protein": 7.59, "carbs": 34.16, "fat": 13.64, "saturated_fat": 1.87, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 601.59, "potassium": null, "fiber": 6.06, "sugar": 1.37, "vitamin_a": null, "vitamin_c": 53.29, "calcium": 58.92, "iron": 3.46}'::jsonb, ARRAY['middle eastern', 'side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "quinoa", "notes": "1 cup red quinoa", "category": "pasta and rice"}, {"quantity": 1.5, "unit": "cups", "item": "water", "notes": "1 1/2 cups water", "category": "beverages"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "", "item": "avocado", "notes": "1/2 avocado, diced", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "tomato", "notes": "1/2 tomato, diced", "category": "produce"}, {"quantity": 5.0, "unit": "", "item": "radishes", "notes": "5 red radishes, diced", "category": "produce"}, {"quantity": 5.0, "unit": "", "item": "green onions", "notes": "5 green onions, chopped", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "parsley", "notes": "1/2 cup parsley, chopped", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "bell pepper", "notes": "1/2 cup yellow pepper,diced", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "cucumber", "notes": "1/2 cup English cucumber, diced", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "cayenne pepper", "notes": "1 teaspoon cayenne pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "tumeric", "notes": "1 teaspoon tumeric", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "cumin", "notes": "1/2 teaspoon cumin", "category": "spices and seasonings"}, {"quantity": 3.5, "unit": "tablespoons", "item": "red wine vinegar", "notes": "3 1/2 tablespoons red wine vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tablespoons", "item": "extra virgin olive oil", "notes": "2 tablespoons extra virgin olive oil", "category": "oil, vinegar, salad dressing"}]'::jsonb, '["Wash the 1 cup of quinoa in a colander for several seconds.", "Add quinoa, water and salt to a small pot and boil for 15 minutes. You will know it is cooked when it becomes soft and you see little white antennas pop from the grain.", "Meanwhile, wash all your veggies well and chop and dice them accordingly.", "Add all the veggies to a medium glass bowl and toss. In a small bowl mix the red wine vinegar, olive oil and all the spices and blend well.", "Add the vinagrette to the salad and enjoy.", "Will keep for 1 day, but best eaten the same day."]'::jsonb, 'https://www.foodista.com/recipe/BZ5TWVLJ/colorful-red-quinoa-not-so-tabbouleh-salad', 'https://img.spoonacular.com/recipes/639950-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spring-salad-with-walnut-vinaigrette', 'Spring Salad with Walnut Vinaigrette', 2, 0, 0, '{"calories": 603, "protein": 8.73, "carbs": 43.22, "fat": 47.5, "saturated_fat": 4.47, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 160.99, "potassium": null, "fiber": 11.33, "sugar": 24.94, "vitamin_a": null, "vitamin_c": 123.07, "calcium": 174.9, "iron": 3.02}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'spoonacular', 'vegetarian'], '[{"quantity": 0.33333334, "unit": "cup", "item": "apple cider vinegar", "notes": "1/3 cup apple cider vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "large", "item": "carrot", "notes": "1 large carrot, peeled and chopped", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "basil", "notes": "½ teaspoon dried basil", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "small", "item": "bulb fennel", "notes": "1 small bulb fennel, thinly sliced", "category": "produce"}, {"quantity": 3.0, "unit": "ounces", "item": "spring greens", "notes": "3 ounces (1/2 a bag) spring greens", "category": "produce"}, {"quantity": 0.125, "unit": "teaspoon", "item": "ground ginger", "notes": "1/8 teaspoon ground ginger", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "honey", "notes": "1 teaspoon honey", "category": "nut butters, jams, and honey"}, {"quantity": 2.0, "unit": "large", "item": "kiwis", "notes": "2 large ripe kiwis, peeled and chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "mandarin", "notes": "1 mandarin, peeled and seperated into pieces", "category": "canned and jarred"}, {"quantity": 0.25, "unit": "teaspoon", "item": "oregano", "notes": "1/4 teaspoon dried oregano", "category": "produce"}, {"quantity": 0.25, "unit": "", "item": "onion", "notes": "¼ red onion, very thinly sliced", "category": "produce"}, {"quantity": 2.0, "unit": "large", "item": "strawberries", "notes": "2 large ripe strawberries, stems removed and chopped", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "walnut oil", "notes": "¼ cup walnut oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.5, "unit": "cup", "item": "walnuts", "notes": "1/2 cup walnuts, toasted", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "grain mustard", "notes": "2 teaspoons whole grain mustard", "category": "condiments"}]'::jsonb, '["Place all salad ingredients in a large mixing bowl. In a blender or food processor, add all of the vinaigrette ingredients.  Blend on a high setting until all ingredients are mixed thoroughly.", "Add desired amount of vinaigrette to the veggies and fruit. Toss the salad until there is an even coat of vinaigrette over the veggies and fruit.", "Serve in heaping portions with walnuts on top."]'::jsonb, 'https://www.foodista.com/recipe/LW2GVYRT/spring-salad-with-walnut-vinaigrette', 'https://img.spoonacular.com/recipes/661433-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('avocado-and-orange-salad-with-orange-ginger-dressing', 'Avocado and Orange Salad With Orange-Ginger Dressing', 4, 0, 0, '{"calories": 501, "protein": 5.63, "carbs": 39.22, "fat": 40.33, "saturated_fat": 5.77, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 209.59, "potassium": null, "fiber": 17.06, "sugar": 17.9, "vitamin_a": null, "vitamin_c": 113.07, "calcium": 87.13, "iron": 1.45}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 4.0, "unit": "", "item": "avocados", "notes": "4 ripe avocados, cut into long strips", "category": "produce"}, {"quantity": 3.0, "unit": "large", "item": "oranges", "notes": "3 large oranges, segmented", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "green onions", "notes": "2 green onions, cut finely", "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "orange juice", "notes": "3 tablespoons orange juice", "category": "beverages"}, {"quantity": 4.0, "unit": "", "item": "juice of lemon", "notes": "Juice of half a lemon", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ginger paste", "notes": "1/2 teaspoon fresh ginger paste", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "agave syrup", "notes": "1 teaspoon agave syrup", "category": "ethnic foods"}, {"quantity": 3.0, "unit": "tablespoons", "item": "olive oil", "notes": "3 tablespoons olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper to taste", "category": "spices and seasonings"}]'::jsonb, '["Arrange the avocado and orange slices overlapping each other on a platter. Squeeze over the juice from the orange left after segmenting the pieces.", "Sprinkle over the spring onions and some salt over the salad. Cover with cling film and refrigerate until ready to serve.", "Blend all the dressing ingredients together. Season to taste with salt and pepper. Before serving pour the dressing over the salad."]'::jsonb, 'https://www.foodista.com/recipe/YPMB288Y/avocado-and-orange-salad-with-orange-ginger-dressing', 'https://img.spoonacular.com/recipes/633126-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('steak-salad-with-chimichurri-sauce', 'Steak Salad with Chimichurri Sauce', 4, 0, 0, '{"calories": 474, "protein": 29.01, "carbs": 15.71, "fat": 33.93, "saturated_fat": 6.32, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 591.16, "potassium": null, "fiber": 5.51, "sugar": 5.09, "vitamin_a": null, "vitamin_c": 62.87, "calcium": 89.12, "iron": 4.7}'::jsonb, ARRAY['south american', 'latin american', 'side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'gluten free', 'dairy free', 'paleolithic', 'primal', 'whole 30', 'ketogenic', 'spoonacular', 'soup', 'baking', 'grilling', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "pound", "item": "flank steak", "notes": "1 pound flank steak, 1-inch thick", "category": "meat"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper to season", "notes": "salt and pepper to season", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 red onion, sliced into 1\" rings", "category": "produce"}, {"quantity": 4.0, "unit": "ounces", "item": "baby bella mushrooms", "notes": "4 ounces baby bella mushrooms, quartered", "category": "produce"}, {"quantity": 5.0, "unit": "ounces", "item": "spring mix", "notes": "5 ounces spring mix", "category": "produce"}, {"quantity": 1.0, "unit": "pint", "item": "cherry tomatoes", "notes": "1 pint cherry tomatoes, halved", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "avocado", "notes": "1 avocado, sliced", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "lightly parsley", "notes": "1 cup lightly packed fresh parsley", "category": "produce"}, {"quantity": 2.0, "unit": "large cloves", "item": "garlic", "notes": "2 large cloves garlic", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "thyme", "notes": "1 teaspoon dried thyme", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "pepper flakes", "notes": "1/4 teaspoon red pepper flakes", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "bone broth", "notes": "1/4 cup bone broth", "category": "canned and jarred"}, {"quantity": 0.25, "unit": "cup", "item": "red wine vinegar", "notes": "1/4 cup organic red wine vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.25, "unit": "cup", "item": "extra virgin olive oil", "notes": "1/4 cup extra virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.125, "unit": "teaspoon", "item": "pepper", "notes": "1/8 teaspoon freshly ground black pepper", "category": "spices and seasonings"}]'::jsonb, '["Preheat grill to medium high heat.Season red onion rings and mushrooms with 1 tablespoon olive oil, salt and pepper to taste.", "Place onion rings and mushrooms on grill. Grill for 4-5 minutes per side until char marks appear.", "Remove and set aside.Take steak out of your fridge and let it sit in the room temperature for 5 minutes. Use a paper towel to gently pat the surface of both sides of the steak dry.", "Brush olive oil on both sides of the steak or use olive oil cooking spray. Generously season the steak with salt and freshly ground pepper.", "Place the steak on the grill. Grill each side for 3-5 minutes until the internal temperature of the steak reaches 145°F for medium doneness; 135°F for medium rare and 155°F for medium well.", "Let rest for 5 minutes before slicing.To make the Chimichurri sauce, place all ingredients in a food processor, blend for about 30 seconds or until all ingredients are combined well (any remaining sauce can be stored in the refrigerator for up to 2 weeks).To assemble, arrange baby spinach spring mix on the bottom of a large serving plate, followed by the onion rings and mushrooms. Slice the steak and place on top of the vegetables. Top with cherry tomatoes and sliced avocado.", "Drizzle the Chimichurri sauce over the steak salad and serve!"]'::jsonb, 'https://www.foodista.com/recipe/ZSDGBCXH/steak-salad-with-chimichurri-sauce', 'https://img.spoonacular.com/recipes/1096025-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('red-quinoa-kale-blood-orange-and-pom-salad-with-meyer-lemon-vinaigrette', 'Red Quinoa, Kale, Blood Orange and Pom Salad With Meyer Lemon Vinaigrette', 4, 0, 0, '{"calories": 463, "protein": 12.65, "carbs": 55.86, "fat": 22.19, "saturated_fat": 2.93, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 741.78, "potassium": null, "fiber": 9.54, "sugar": 11.15, "vitamin_a": null, "vitamin_c": 40.37, "calcium": 152.76, "iron": 4.13}'::jsonb, ARRAY['side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'spoonacular', 'soup', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "water", "notes": "2 cups water", "category": "beverages"}, {"quantity": 1.0, "unit": "", "item": "juice of lemon", "notes": "Juice and zest of 1 Meyer lemon", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "salt", "notes": "Salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "quinoa", "notes": "1 cup red quinoa", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "tablespoon", "item": "olive oil", "notes": "1 tablespoon olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "", "item": "shallots", "notes": "2 shallots, sliced into strips", "category": "produce"}, {"quantity": 1.0, "unit": "bunch", "item": "kale", "notes": "1 bunch black kale", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "apple cider vinegar", "notes": "1 tablespoon apple cider vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "", "item": "lemon zest", "notes": "Zest of 2 Meyer Lemons", "category": "produce"}, {"quantity": 3.0, "unit": "inches", "item": "blood oranges", "notes": "3 inches small blood oranges, cut ⅛s", "category": "produce"}, {"quantity": 1.0, "unit": "package", "item": "pomegranate seeds", "notes": "1 package pomegranate seeds, one 8-ounce package", "category": "produce"}, {"quantity": 15.0, "unit": "ounce", "item": "garbanzo beans", "notes": "1 15-ounce can garbanzo beans", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "", "item": "juice of lemon", "notes": "Zest of 2 Meyer lemons (juice reserved)", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "honey", "notes": "2 tablespoons honey", "category": "nut butters, jams, and honey"}, {"quantity": 0.25, "unit": "cup", "item": "olive oil", "notes": "1/4 cup extra-virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tablespoons", "item": "meyer lemon juice", "notes": "2 tablespoons Meyer lemon juice", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "blood orange juice", "notes": "2 tablespoons blood orange juice", "category": "beverages"}, {"quantity": 4.0, "unit": "tablespoons", "item": "apple cider vinegar", "notes": "4 tablespoons citrus champagne vinegar or apple cider vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tablespoons", "item": "vegetable stock", "notes": "2 tablespoons vegetable (or chicken) stock (it gives the dressing more", "category": "canned and jarred"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and Pepper to taste", "category": "spices and seasonings"}]'::jsonb, '["Bring 2 cups of water to a boil.", "Add zest and juice of 1 meyer lemon and salt and stir into water.", "Add quinoa and cook according to package directions.", "Wash kale and let dry. Pull the leaves off of the tough center stem and slice into small ribbons.", "Meanwhile, in a large skilled heat olive oil and add shallots. Saut for about 3 minutes until just softened.", "Add kale and stir just long enough for the kale to wilt, about 1 minute.", "Add vinegar and lemon zest, stir and cook for 1 minute longer.", "Remove pan from the heat.", "Add orange slices, pomegranate seeds, garbanzo beans and cooked quinoa.", "In a large bowl, whisk together lemon zest, honey, olive oil, lemon juice, orange juice, vinegar, stock, salt and pepper. Toss with salad (there may be some extra vinaigrette)."]'::jsonb, 'https://www.foodista.com/recipe/QRH8PJRQ/red-quinoa-kale-blood-orange-and-pom-salad-with-meyer-lemon-vinaigrette', 'https://img.spoonacular.com/recipes/658091-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fruit-and-spinach-salad-with-xocai-activ-vinaigrette', 'Fruit and Spinach Salad with "Xocai Activ" Vinaigrette', 8, 0, 0, '{"calories": 108, "protein": 2.53, "carbs": 8.47, "fat": 8.1, "saturated_fat": 1.08, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 36.66, "potassium": null, "fiber": 2.55, "sugar": 4.29, "vitamin_a": null, "vitamin_c": 22.74, "calcium": 53.18, "iron": 1.54}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'vegan', 'spoonacular', 'dessert', 'vegetarian'], '[{"quantity": 2.0, "unit": "tbsp", "item": "balsamic vinegar", "notes": "2 tbsp balsamic vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.5, "unit": "tsp", "item": "chocolate )", "notes": "1 1/2 tsp dark chocolate ((1- 1 1/2 tsp \"Xocai Activ\" powder))", "category": "sweet snacks"}, {"quantity": 2.0, "unit": "sprig", "item": "green onions", "notes": "2 sprig green onions ((separate bulbs from tops))", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "olive oil", "notes": "1/2 cup extra-virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "", "item": "pears", "notes": "1 whole pears ((peeled and cut into slices))", "category": "produce"}, {"quantity": 1.0, "unit": "dash", "item": "pepper )", "notes": "1 dash pepper ((to taste))", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "dash", "item": "salt )", "notes": "1 dash salt ((to taste))", "category": "spices and seasonings"}, {"quantity": 10.0, "unit": "cup", "item": "spinach", "notes": "10 cup spinach ((8-10 cups spinach leaves, washed and dried))", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "strawberries )", "notes": "1 cup strawberries ((fresh- cleaned and sliced))", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "walnuts )", "notes": "1/2 cup chopped walnuts ((can be toasted))", "category": "nuts"}]'::jsonb, '["Put bulbs of green onions and vinegar in bowl to sit while preparing salad. Slowly whisk in \"Xocai Activ,\" then olive oil.", "Combine spinach, pear, strawberries, green onion tops, and walnuts in a large bowl. Gradually add vinaigrette in small amounts, until the leaves are lightly coated. Season with salt and pepper. Remaining vinaigrette can be saved for another use.", "Serves 8"]'::jsonb, 'https://www.foodista.com/recipe/7T88D2Q3/fruit-and-spinach-salad-with-xocai-activ-vinaigrette', 'https://img.spoonacular.com/recipes/643945-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('warm-quinoa-spinach-and-shiitake-salad', 'Warm Quinoa Spinach and Shiitake Salad', 6, 0, 0, '{"calories": 226, "protein": 5.55, "carbs": 18.38, "fat": 15.81, "saturated_fat": 2.71, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 408.78, "potassium": null, "fiber": 2.77, "sugar": 2.78, "vitamin_a": null, "vitamin_c": 37.62, "calcium": 132.42, "iron": 1.93}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'lacto ovo vegetarian', 'primal', 'spoonacular', 'soup'], '[{"quantity": 6.0, "unit": "cups", "item": "baby spinach", "notes": "6 cups loosely packed stemmed baby spinach", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "pepper", "notes": "Freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 500.0, "unit": "mL", "item": "chicken broth", "notes": "2 cups (500 mL) Chicken Broth", "category": "canned and jarred"}, {"quantity": 50.0, "unit": "mL", "item": "feta cheese", "notes": "¼ cup (50 mL) crumbled feta cheese", "category": "cheese"}, {"quantity": 6.0, "unit": "servings", "item": "olive oil", "notes": "Extra-virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 125.0, "unit": "mL", "item": "bell pepper", "notes": "½ cup (125 mL) finely chopped sweet red pepper", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "red wine vinegar", "notes": "2 tablespoons Red wine vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 225.0, "unit": "g", "item": "pc organics roasted garlic and herbs quinoa", "notes": "1 pkg (225 g) PC Organics Roasted Garlic and Fine Herbs Quinoa", "category": "produce"}, {"quantity": 1.0, "unit": "pinch", "item": "salt", "notes": "Pinch Salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "shallots", "notes": "2 Shallots, finely diced", "category": "produce"}, {"quantity": 180.0, "unit": "g", "item": "shiitake mushrooms", "notes": "6 oz (180 g) shiitake mushrooms, stems discarded and caps thinly sliced", "category": "produce"}]'::jsonb, '["In saucepan, bring chicken broth to a boil. Stir in quinoa and contents of seasoning pouch. Reduce heat to low, cover and simmer for 12 to 15 minutes or until tender.", "Remove from heat; let stand, covered, for 5 minutes. Fluff with a fork.In large nonstick frying pan, heat oil over medium heat; cook shallots and red pepper for 4 to 6 minutes, stirring occasionally, or until lightly golden and softened. Stir in mushrooms; cook, stirring occasionally, for 6 to 8 minutes or until mushrooms have released their juices and are starting to turn golden.", "Add vinegar; cook, stirring to bring up browned bits, for 1 minute. Stir in spinach; cook, stirring, for 2 minutes or just until wilted. Stir in salt and pepper.", "Remove from heat.In large bowl, toss quinoa with warm spinach mixture.", "Serve sprinkled with feta.More recipe ideas are available online at pc.ca."]'::jsonb, 'https://www.foodista.com/recipe/FWQCKZYC/impress-with-this-warm-quinoa-spinach-and-shiitake-salad', 'https://img.spoonacular.com/recipes/664969-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lentil-salad-with-rye-berries-and-sun-dried-tomatoes', 'Lentil Salad with Rye Berries and Sun-Dried Tomatoes', 4, 0, 0, '{"calories": 500, "protein": 23.8, "carbs": 73.13, "fat": 13.85, "saturated_fat": 1.89, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1189.75, "potassium": null, "fiber": 27.45, "sugar": 8.77, "vitamin_a": null, "vitamin_c": 27.41, "calcium": 98.84, "iron": 8.21}'::jsonb, ARRAY['salad', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'soup', 'vegetarian'], '[{"quantity": 1.0, "unit": "leaves", "item": "baby arugula leaves", "notes": "baby kale leaves or other salad greens to serve", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "balsamic vinegar", "notes": "2 tablespoons balsamic vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.5, "unit": "cup", "item": "dried green lentils", "notes": "1/2 cup green lentils", "category": "canned and jarred"}, {"quantity": 0.33333334, "unit": "cup", "item": "fresh chives", "notes": "1/3 cup chopped fresh chives", "category": "produce"}, {"quantity": 0.33333334, "unit": "cup", "item": "fresh parsley", "notes": "1/3 cup chopped fresh parsley", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "fresh thyme", "notes": "2 tablespoons fresh thyme or 2 teaspoons dried", "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": "1 clove garlic, minced", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground coriander", "notes": "1/2 teaspoon ground coriander", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "jalapeno", "notes": "1 jalapeño, seeded and finely chopped", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "cup", "item": "lentils", "notes": "1 cup Puy (French) lentils", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "mustard powder", "notes": "1/2 teaspoon mustard powder", "category": "spices and seasonings"}, {"quantity": 3.5, "unit": "tablespoons", "item": "olive oil", "notes": "3 1/2 tablespoons olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "servings", "item": "pepper", "notes": "fresh cracked black pepper to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "small", "item": "red onion", "notes": "1 small red onion, finely chopped", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sea salt", "notes": "1 teaspoon sea salt, or to taste", "category": "spices and seasonings"}, {"quantity": 0.33333334, "unit": "cup", "item": "sun-dried tomatoes", "notes": "1/3 cup sun-dried tomatoes", "category": "canned and jarred"}, {"quantity": 2.5, "unit": "cups", "item": "vegetable stock", "notes": "2 1/2 cups vegetable stock or water", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "cup", "item": "wheat berries", "notes": "1/2 cup rye or wheat berries", "category": "health foods"}]'::jsonb, '["Rinse the rye or wheat berries and soak for 8 hours or overnight in several inches of water. Bring to a boil, reduce heat to medium-low, cover, and simmer for 50 minutes or until tender.", "Drain and set aside.Meanwhile, rinse the lentils and transfer to a medium saucepan along with the stock or water. Bring to a boil, reduce heat to medium-low, cover, and simmer for 25 minutes or until the lentils are tender, taking care not to overcook.While the grains and lentils are cooking, soak the sun-dried tomatoes in hot water for 20 to 30 minutes.", "Drain and chop.Meanwhile, mix the onion, jalapeo, balsamic vinegar and salt in a large bowl.", "Sprinkle in the parsley, chives, thyme and garlic and let marinate while the other grains and lentils are cooking.", "Drain the lentils and add to the bowl with the onions and herbs, along with the cooked grains, olive oil, mustard powder, coriander and black pepper. Stir to combine.", "Serve at room temperature or chilled over a few handfuls of baby kale leaves or other fresh salad greens."]'::jsonb, 'https://www.foodandspice.com/2015/11/lentil-salad-with-rye-berries-and-sun.html', 'https://img.spoonacular.com/recipes/692503-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('colorful-wild-rice-salad', 'Colorful Wild Rice Salad', 3, 0, 0, '{"calories": 384, "protein": 12.88, "carbs": 62.77, "fat": 11.44, "saturated_fat": 2.21, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 21.13, "potassium": null, "fiber": 6.59, "sugar": 13.27, "vitamin_a": null, "vitamin_c": 13.92, "calcium": 57.52, "iron": 3.1}'::jsonb, ARRAY['side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "handful", "item": "arugula", "notes": "1 handful arugula", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "carrot", "notes": "1/2 carrot grated", "category": "produce"}, {"quantity": 5.0, "unit": "", "item": "apricots", "notes": "5 dried apricots", "category": "dried fruits"}, {"quantity": 0.25, "unit": "", "item": "juice of orange", "notes": "juice of 1/4 orange", "category": "beverages"}, {"quantity": 0.25, "unit": "", "item": "orange zest", "notes": "zest of 1/4 orange", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 red onion", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "roasted cashew nuts", "notes": "1/2 cup roasted cashew nuts", "category": "nuts"}, {"quantity": 1.0, "unit": "", "item": "tomato", "notes": "1 tomato", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "rice", "notes": "1 cup wild rice", "category": "pasta and rice"}]'::jsonb, '["Cut the apricots into small cubes and soak them in the juice of 1/4 an orange for 10 minutes.", "Saute the onions in oil on low heat for 15 minutes.Cook the rice in 2 cups of water until done but still with a bite, let it cool down until luke warm.", "Mix all the ingredients together, except for the arugula and nuts, and season with pepper and salt. Now mix in the arugula and sprinkle the nuts on top."]'::jsonb, 'https://www.foodista.com/recipe/RRSS27DD/colorful-wild-rice-salad', 'https://img.spoonacular.com/recipes/639954-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fall-farro-salad-with-pomegranate-walnut-truffles', 'Fall Farro Salad with Pomegranate, Walnut & Truffles', 4, 0, 0, '{"calories": 722, "protein": 25.4, "carbs": 60.66, "fat": 46.53, "saturated_fat": 9.48, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 695.63, "potassium": null, "fiber": 11.58, "sugar": 14.73, "vitamin_a": null, "vitamin_c": 10.56, "calcium": 415.0, "iron": 4.36}'::jsonb, ARRAY['side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'spoonacular', 'dessert', 'vegetarian', 'vegan'], '[{"quantity": 0.33333334, "unit": "cup", "item": "extra virgin olive oil", "notes": "1/3 cup extra virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 8.0, "unit": "ounces", "item": "farro", "notes": "8 ounces (250 gr) farro or spelt", "category": "pasta and rice"}, {"quantity": 4.0, "unit": "servings", "item": "parmesan into ribbons", "notes": "parmesan shaved into ribbons", "category": "cheese"}, {"quantity": 1.0, "unit": "", "item": "pomegranate", "notes": "1 pomegranate", "category": "produce"}, {"quantity": 1.0, "unit": "small head", "item": "radicchio thinly", "notes": "1 small head of radicchio sliced thinly", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "truffle mushroom", "notes": "1 truffle mushroom", "category": "produce"}, {"quantity": 30.0, "unit": "ml", "item": "vinegar", "notes": "2-3 tablespoons (30ml) vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "ounces", "item": "walnuts", "notes": "4 ounces (100gr) toasted walnuts", "category": "baking"}]'::jsonb, '["In plenty of cold water boil farro until al dente (cooked but with a bite) - about 20-35 minutes. Feel free to add some vegetable scraps if available (unused piece of carrot, onion, celery, etc.)", "Drizzle over the salad a couple tablespoons of vinegar followed by three times the amount of extra virgin olive oil. Give it another good mix.To finish, give it a good shave of fresh truffles, if not available truffle salt or oil works well too. Top with a few pulls of a potato peeler across a wedge of parmesan.Allow to sit for at least 20 minutes up to a day - it needs a little time for it to all come together.Before serving - give it one last good stir, taste &amp; adjust the seasoning - making sure the dressing is balanced (not too vinegary or oily)."]'::jsonb, 'https://www.foodista.com/recipe/W4B5S88Y/fall-farro-salad-with-pomegranate-walnut-truffles', 'https://img.spoonacular.com/recipes/642556-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('warm-duck-salad-with-roasted-beetroot', 'Warm Duck Salad With Roasted Beetroot', 4, 0, 0, '{"calories": 520, "protein": 40.43, "carbs": 33.54, "fat": 25.65, "saturated_fat": 7.97, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1397.39, "potassium": null, "fiber": 5.06, "sugar": 23.52, "vitamin_a": null, "vitamin_c": 84.42, "calcium": 444.05, "iron": 7.48}'::jsonb, ARRAY['side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'gluten free', 'primal', 'spoonacular', 'baking'], '[{"quantity": 500.0, "unit": "g", "item": "duck breast meat - skin left on", "notes": "500g ( - 1.1 pound) of duck breast meat (about 2slabs) – skin left on", "category": "meat"}, {"quantity": 300.0, "unit": "g", "item": "baby beets", "notes": "300g ( - 1/2 pound +) baby beets or beetroot", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "orange zest", "notes": "zest of 1 orange", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "honey", "notes": "2 teaspoons honey", "category": "nut butters, jams, and honey"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "cups", "item": "arugula greens", "notes": "3 cups of rocket or arugula greens", "category": "produce"}, {"quantity": 4.0, "unit": "tablespoons", "item": "pine nuts", "notes": "4 tablespoons of toasted almond flakes or pine nuts", "category": "baking"}, {"quantity": 1.0, "unit": "can", "item": "mandarin orange segents", "notes": "1 can of mandarin orange segments (drained)", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "Bunch", "item": "mint", "notes": "Bunch of fresh mint or basil", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "feta cheese", "notes": "Shaved parmesan cheese or crumbled goat or feta cheese", "category": "cheese"}, {"quantity": 6.0, "unit": "", "item": "juice of orange", "notes": "Juice of 1 orange (about 6 tablespoons)", "category": "beverages"}, {"quantity": 2.0, "unit": "tablespoons", "item": "extra virgin olive oil", "notes": "2 tablespoons extra virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "teaspoons", "item": "balsamic vinegar", "notes": "4 teaspoons balsamic vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper to taste", "category": "spices and seasonings"}]'::jsonb, '["Pre-heat the oven to 200 deg Celsius (400 F).", "Start by roasting the beetroots. Clean the beets of all mud and trim the stems. Wrap each beet tightly in aluminum foil.", "Place the wrapped beets on a pan and in a 200 deg Celsius oven for 30 to 40mins. They are done when they are very tender.", "While the beets are cooking, use a peeler and peel an orange, taking note to get as much of zest and as little of pith (the white parts) as possible. Stack the strips of orange zest and cut into fine strips with a sharp knife. Set aside.", "Clean and dry the duck breasts. Score the skin of the duck. Make cuts into the fat layer and take care not to cut into the meat layer. Rub some salt into the skin side only of the duck.", "Add the duck breasts to a clean and COLD pan. Do not add any oil.", "Place the pan on the stove and turn the heat to medium.", "As the pan heats up, the fat from the duck will render off and the skin will brown beautifully. Always keep the heat to between medium to medium-high. Never use high heat as the skin will burn before the duck is cooked through. Once the skin is a gorgeous dark golden brown, flip the duck breasts to the other side and cook for a few more minutes till the other sides are also golden brown. Be careful not to overcook the duck. Set the cooked duck aside and leave to rest covered with foil. Duck, like beef must be rested. The resting time is half that of cooking time. If the duck was cooked for 6 mins, then it should be rested for at least 3 minutes.", "While the duck is resting, make the vinaigrette. Squeeze the juice of the zested orange into a bowl. About 5 to 6 tablespoons of juice.", "Add 2 tablespoons of extra virgin olive oil. Use the best quality one you have.", "Add 4 teaspoons of balsamic vinegar.", "Add salt and pepper to taste.", "Whisk the mixture well. Set aside.", "When the beets are done, remove them from the oven and let them cool for a few minutes so that they are easier to hold. Put on some disposable gloves (else get blood red stained fingers later). Open the foil-wrapped beets. Using the rough surface of each piece of foil, rub the beets with the foil to remove the skin.", "Cut the cooked beets into small pieces. Set aside in a bowl.", "Drizzle 2 tablespoons of vinaigrette into the beets.", "Add 2 teaspoons of honey. Toss well to coat the beets with the dressing.", "Slice the rested duck into thin slices. The meat should be a beautiful pink.", "Serve by layering the salad with greens, nuts and cheese of your choice, and the duck and beets.", "I like rocket greens with fresh basil or mint, mandarin orange segments, toasted almond flakes or pine nuts and some shaved parmesan cheese or some crumbed feta or goats cheese.", "Garnish with the orange zest.", "Trickle the vinaigrette over the salad.", "Best served immediately."]'::jsonb, 'https://www.foodista.com/recipe/KD7D3V7L/warm-duck-salad-with-roasted-beetroot', 'https://img.spoonacular.com/recipes/664960-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('watermelon-feta-and-mint-salad', 'Watermelon, Feta And Mint Salad', 6, 0, 0, '{"calories": 250, "protein": 7.65, "carbs": 17.77, "fat": 17.93, "saturated_fat": 6.37, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 644.98, "potassium": null, "fiber": 3.14, "sugar": 11.73, "vitamin_a": null, "vitamin_c": 112.85, "calcium": 226.01, "iron": 1.48}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'lacto ovo vegetarian', 'primal', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "tbsp", "item": "clear honey", "notes": "1 tbsp clear honey", "category": "nut butters, jams, and honey"}, {"quantity": 0.5, "unit": "", "item": "cucumber", "notes": "1/2 cucumber, washed", "category": "produce"}, {"quantity": 1.0, "unit": "head", "item": "curly leaf lettuce", "notes": "1 head curly leaf lettuce", "category": "produce"}, {"quantity": 1.0, "unit": "package", "item": "feta cheese", "notes": "1 package feta cheese, sliced", "category": "cheese"}, {"quantity": 3.0, "unit": "tbsp", "item": "mint", "notes": "3 tbsp chopped fresh mint", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "lemon", "notes": "1/2 lemon", "category": "produce"}, {"quantity": 4.0, "unit": "tbsp", "item": "olive oil", "notes": "4 tbsp olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 6.0, "unit": "servings", "item": "bell pepper", "notes": "pepper", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "salt", "notes": "salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "pound", "item": "watermelon", "notes": "1 pound ripe watermelon", "category": "produce"}]'::jsonb, '["Cut the watermelon into big wedges, then cut the flesh away from the skin. Slice the flesh into bite sized pieces.", "Cut the cucumber in half then half lengthways too. Use a potato peeler to slice ribbons off the cucumber.Arrange the lettuce leaves in a large bowl, top with the watermelon, cucumber, feta and mint.Finally place all the dressing ingredients together (juice of 1/2 lemon, olive oil, honey) in a small bowl and whisk together with a fork. Season to taste.", "Drizzle the dressing over the salad and serve."]'::jsonb, 'https://www.foodista.com/recipe/QHTL4ZZS/watermelon-feta-and-mint-salad', 'https://img.spoonacular.com/recipes/665041-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fresh-green-bean-and-tomato-salad-with-creamy-garlic-dressing', 'Fresh Green Bean and Tomato Salad with Creamy Garlic Dressing', 4, 0, 0, '{"calories": 196, "protein": 6.1, "carbs": 21.48, "fat": 11.76, "saturated_fat": 1.45, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 771.01, "potassium": null, "fiber": 8.25, "sugar": 9.88, "vitamin_a": null, "vitamin_c": 37.13, "calcium": 110.68, "iron": 3.07}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'whole 30', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 2.0, "unit": "pounds", "item": "green beans", "notes": "2 pounds Fresh green beans", "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves garlic, cut into pieces", "category": "produce"}, {"quantity": 0.5, "unit": "pint", "item": "grape tomatoes", "notes": "1/2 pint yellow grape tomatoes, washed and cut in half", "category": "produce"}, {"quantity": 0.125, "unit": "teaspoon", "item": "ground pepper", "notes": "1/8 teaspoon ground black pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "olive oil", "notes": "2 tablespoons olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tablespoons", "item": "pecans )", "notes": "2 tablespoons toasted and chopped pecans for garnish (substitute almonds or pine nuts if you''d prefer)", "category": "savory snacks"}, {"quantity": 2.0, "unit": "tablespoons", "item": "red wine vinegar", "notes": "2 tablespoons red wine vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon Salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "shallot", "notes": "1 shallot", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "spicy brown mustard", "notes": "1/4 cup spicy brown mustard", "category": "condiments"}]'::jsonb, '["For the dressing", "Add all the ingredients to a blender and pulse until smooth. Taste the dressing and season, as needed.Refrigerate for at least 30 minutes.For the salad", "Refrigerate the clean tomatoes until ready to assemble the salad.Blanch the green beans in boiling water for about three minutes.", "Drain them and immediately place them in ice water. Once cold, drain and refrigerate until ready to assemble the salad.When ready to serve, add the green beans and tomatoes to a large bowl.", "Drizzle the chilled dressing over the salad and toss to coat.", "Serve on individual plates and garnish with the toasted pecans.", "Add more dressing as desired"]'::jsonb, 'https://www.foodista.com/recipe/ZVJWW8NM/fresh-green-bean-and-tomato-salad-with-creamy-garlic-dressing', 'https://img.spoonacular.com/recipes/643505-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spicy-lump-crab-and-avocado-salad', 'Spicy Lump Crab and Avocado Salad', 4, 0, 0, '{"calories": 502, "protein": 25.34, "carbs": 20.58, "fat": 38.23, "saturated_fat": 5.64, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1539.02, "potassium": null, "fiber": 14.2, "sugar": 3.15, "vitamin_a": null, "vitamin_c": 70.14, "calcium": 92.92, "iron": 2.44}'::jsonb, ARRAY['side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'gluten free', 'dairy free', 'whole 30', 'pescatarian', 'ketogenic', 'spoonacular'], '[{"quantity": 4.0, "unit": "", "item": "avocados", "notes": "4 avocados", "category": "produce"}, {"quantity": 0.5, "unit": "large", "item": "bell peppered", "notes": "1/2 large red bell peppered, chopped", "category": "produce"}, {"quantity": 3.0, "unit": "Tablespoons", "item": "parsley", "notes": "3 Tablespoons fresh parsley, chopped", "category": "produce"}, {"quantity": 2.0, "unit": "Tablespoons", "item": "lemon juice", "notes": "2 Tablespoons fresh lemon juice", "category": "produce"}, {"quantity": 1.0, "unit": "pound", "item": "lump crabmeat", "notes": "1 pound jumbo lump crabmeat", "category": "seafood"}, {"quantity": 3.0, "unit": "Tablespoons", "item": "mayonnaise", "notes": "3 Tablespoons mayonnaise", "category": "condiments"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper to taste", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "scallions", "notes": "2 scallions, chopped", "category": "produce"}, {"quantity": 3.0, "unit": "Tablespoons", "item": "sriracha chile sauce", "notes": "3 Tablespoons Sriracha chile sauce", "category": "condiments"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "worcestershire sauce", "notes": "1 Tablespoon worcestershire sauce", "category": "condiments"}]'::jsonb, '["In a small bowl, combine the mayonnaise, chile sauce, worcestershire sauce, lemon juice, salt and pepper.  Stir to combine and set aside.In a medium bowl, carefully toss together the crabmeat, scallions, bell pepper and parsley being careful to not break up the lumps of crab.  Lightly fold in the spicy sauce.Slice the avocados in half and remove the pit.  Slice a small amount from the bottom of the avocado half so it will sit flat on a plate.", "Pour or brush the lemon juice over the entire cut surface of the avocado to avoid browning. (You can remove the avocado from the skin with a spoon and serve that way but be sure to cover the entire avocado flesh with lemon juice before serving.)", "Place avocado halves on a plate and fill with the crab salad.", "Serve immediately.Note: The salad can be made a few hours in advance and chilled until ready to serve."]'::jsonb, 'https://www.foodista.com/recipe/2F6R3J76/spicy-lump-crab-and-avocado-salad', 'https://img.spoonacular.com/recipes/661126-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spring-salad-with-radishes-and-beets', 'Spring Salad with Radishes and Beets', 1, 0, 0, '{"calories": 368, "protein": 7.86, "carbs": 26.42, "fat": 28.07, "saturated_fat": 5.57, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 532.37, "potassium": null, "fiber": 10.56, "sugar": 13.42, "vitamin_a": null, "vitamin_c": 49.03, "calcium": 203.49, "iron": 2.91}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'lacto ovo vegetarian', 'primal', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.5, "unit": "cup", "item": "baby spinach", "notes": "1 1/2 cup baby spinach", "category": "produce"}, {"quantity": 0.33333334, "unit": "cup", "item": "roasted golden beets", "notes": "1/3 cup roasted golden beets (see directions for roasting beets)", "category": "produce"}, {"quantity": 1.0, "unit": "medium", "item": "watermelon radish", "notes": "1 medium watermelon radish, thinly sliced", "category": "produce"}, {"quantity": 2.0, "unit": "medium", "item": "breakfast radishes", "notes": "2 medium French breakfast radishes, thinly sliced", "category": "produce"}, {"quantity": 0.25, "unit": "medium", "item": "avocado", "notes": "1/4 medium avocado, sliced", "category": "produce"}, {"quantity": 0.33333334, "unit": "medium", "item": "fuji apple", "notes": "1/3 medium fuji apple, sliced", "category": "produce"}, {"quantity": 1.0, "unit": "Tbs", "item": "feta cheese", "notes": "1 Tbs feta cheese", "category": "cheese"}, {"quantity": 0.5, "unit": "Tbs", "item": "roasted almonds", "notes": "1/2 Tbs sliced roasted almonds", "category": "nuts"}, {"quantity": 1.0, "unit": "Tbs", "item": "olive oil", "notes": "1 to 2 Tbs olive oil (for roasting beets)", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "serving", "item": "salt and pepper", "notes": "salt and pepper to taste", "category": "spices and seasonings"}]'::jsonb, '["Preheat the oven to 375F. Line a baking sheet with parchment paper or a silicone mat.", "Peel 3-4 medium beets and dice them into small cubes.", "In a medium-sized bowl, toss the beets with 1 to 2 tablespoons of olive oil.", "Sprinkle a dash of salt on the beets and mix again.", "Spread the beets onto a baking sheet in a single layer.", "Bake for about 30 to 35 minutes, or until they can be easily pierced with a fork.", "In a small bowl, mix the spinach, radishes, 1/3 cup beets, feta, and sliced almonds together.", "Pour the salad onto a plate and top with sliced avocado and apples.", "Refrigerate any leftover beets in an airtight container", "Season salad with salt and pepper and enjoy with your dressing of choice."]'::jsonb, 'https://www.foodista.com/recipe/RBW5C3NB/spring-salad-w-radishes-beets', 'https://img.spoonacular.com/recipes/661431-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('quinoa-tabbouleh-salad', 'Quinoa Tabbouleh Salad', 8, 0, 0, '{"calories": 135, "protein": 3.53, "carbs": 16.18, "fat": 6.65, "saturated_fat": 0.89, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 7.49, "potassium": null, "fiber": 2.18, "sugar": 1.0, "vitamin_a": null, "vitamin_c": 8.44, "calcium": 26.03, "iron": 1.34}'::jsonb, ARRAY['middle eastern', 'side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "quinoa", "notes": "1 cup uncooked quinoa", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "cups", "item": "water", "notes": "2 cups water", "category": "beverages"}, {"quantity": 4.0, "unit": "", "item": "green onions", "notes": "4 green onions, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "tomato", "notes": "1 tomato, diced", "category": "produce"}, {"quantity": 0.5, "unit": "large", "item": "cucumber", "notes": "1/2 large cucumber, diced", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "mint", "notes": "1/4 cup loosely packed fresh mint, finely minced", "category": "produce"}, {"quantity": 0.125, "unit": "cup", "item": "parsley", "notes": "1/8 cup fresh parsley, finely minced", "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "olive oil", "notes": "3 tablespoons olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.25, "unit": "cup", "item": "lemon juice", "notes": "1/4 cup lemon juice, or less (to taste- I like a lot!)", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "garlic powder", "notes": "1 teaspoon garlic powder", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "servings", "item": "freshly cracked pepper", "notes": "Freshly cracked black pepper, to taste", "category": "spices and seasonings"}]'::jsonb, '["Bring water to a boil in a medium saucepan.", "Add quinoa and stir. Cover and reduce heat. Allow quinoa to simmer on medium-low heat until all water is cooked off, about 20 minutes. Stir occasionally. Be careful not to burn your quinoa. Allow to cool.", "Place cooled quinoa into a large bowl (preferably something with an airtight lid).", "Add all remaining ingredients and gently stir until very well-mixed. Cover and refrigerate for at least an hour.", "Stir again before serving.", "Can be stored, covered, in the refrigerator for two or three days. But it''s best on the first day, when the veggies are still fresh and crisp!"]'::jsonb, 'https://www.foodista.com/recipe/SBXR5T6R/quinoa-tabbouleh-salad', 'https://img.spoonacular.com/recipes/657686-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('orange-cashew-salad', 'Orange Cashew Salad', 3, 0, 0, '{"calories": 142, "protein": 4.49, "carbs": 17.0, "fat": 7.69, "saturated_fat": 1.34, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 200.24, "potassium": null, "fiber": 3.59, "sugar": 9.66, "vitamin_a": null, "vitamin_c": 48.26, "calcium": 61.18, "iron": 2.05}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'whole 30', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 125.0, "unit": "g", "item": "leaves - i used a mix of romaine lettuce & spinach", "notes": "3 cups mixed green leaves (125 g) - I used a mix of romaine lettuce & spinach", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "oranges", "notes": "2 oranges", "category": "produce"}, {"quantity": 50.0, "unit": "g", "item": "cashew nuts", "notes": "1/3 cup cashew nuts (50 g)", "category": "nuts"}, {"quantity": 1.0, "unit": "tsp", "item": "cumin", "notes": "1 tsp cumin", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "servings", "item": "salt & pepper", "notes": "salt & pepper", "category": "spices and seasonings"}]'::jsonb, '["Cut or tear the mixed greens into small pieces.", "Put them in a bowl and set aside.", "Peel the oranges and cut them into small bite size pieces. Roast them with cumin, salt and pepper on a dry frying pan over medium heat. No oil is required as the oranges contain enough juice to prevent them from sticking to the pan. Cook the oranges for about five minutes.", "Take the oranges off the pan and add them to your bowl of greens. Roast the cashew nuts on the same pan for 3-5 minutes or until they are slightly golden.", "Take the cashew nuts off the heat and mix them with the oranges and greens.", "Serve immediately."]'::jsonb, 'https://www.foodista.com/recipe/ZS7F6DQG/orange-cashew-salad', 'https://img.spoonacular.com/recipes/653824-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('raw-kale-salad', 'Raw Kale Salad', 6, 0, 0, '{"calories": 139, "protein": 3.13, "carbs": 11.87, "fat": 10.05, "saturated_fat": 1.43, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 517.01, "potassium": null, "fiber": 4.59, "sugar": 3.4, "vitamin_a": null, "vitamin_c": 57.76, "calcium": 147.19, "iron": 1.84}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'vegan', 'spoonacular', 'breakfast', 'vegetarian'], '[{"quantity": 1.0, "unit": "bunch", "item": "kale", "notes": "1 bunch kale (remove thick stems)", "category": "produce"}, {"quantity": 2.0, "unit": "Tbsp", "item": "lemon juice", "notes": "2 Tbsp lemon juice", "category": "produce"}, {"quantity": 2.0, "unit": "Tbsp", "item": "soy sauce", "notes": "2 Tbsp coconut aminos, braggs, or soy sauce", "category": "health foods"}, {"quantity": 1.0, "unit": "Tbsp", "item": "maple syrup", "notes": "1 Tbsp maple syrup", "category": "cereal"}, {"quantity": 1.0, "unit": "tsp", "item": "sesame oil", "notes": "1 tsp sesame oil", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2-3 cloves of garlic, minced", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "sea salt", "notes": "1 tsp sea salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tsp", "item": "ginger", "notes": "2 tsp ginger, grated", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "avocado", "notes": "1 avocado, diced", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "bell pepper", "notes": "½ red bell pepper", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "bell pepper", "notes": "½ yellow bell pepper", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "onion", "notes": "½ red onion, diced", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "cherry tomatoes", "notes": "½ red cherry tomatoes", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "sesame seeds to garnish", "notes": "sesame seeds to garnish", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "escallion", "notes": "1 escallion finely chopped", "category": "?"}, {"quantity": 1.0, "unit": "", "item": "escallion", "notes": "1 escallion finely chopped", "category": "?"}]'::jsonb, '["Wash and dry kale leaves, finely cut leaves and place into a large bowl. Into a small bowl, combine the lemon juice, coconut aminos, maple syrup, sesame oil, escallion, garlic, sea salt, ginger.", "Add mixture into kale leaves and massage until wilted, add  of the avocado and massage for a creamy sauce. Then add the rest of the ingredients, garnish with sesame seeds and serve."]'::jsonb, 'https://www.foodista.com/recipe/4TWGVMRK/raw-kale-salad', 'https://img.spoonacular.com/recipes/657981-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('massaged-kale-salad-with-pine-nuts-dried-cranberries', 'Massaged Kale Salad with Pine Nuts & Dried Cranberries', 6, 0, 0, '{"calories": 364, "protein": 5.08, "carbs": 15.22, "fat": 33.61, "saturated_fat": 4.83, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 549.71, "potassium": null, "fiber": 4.79, "sugar": 8.18, "vitamin_a": null, "vitamin_c": 66.82, "calcium": 272.0, "iron": 2.77}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'primal', 'spoonacular', 'breakfast', 'vegetarian'], '[{"quantity": 1.0, "unit": "bunch", "item": "curly kale", "notes": "1 bunch of curly kale", "category": "produce"}, {"quantity": 1.0, "unit": "bunch", "item": "lacinato kale", "notes": "1 bunch of Lacinato kale", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "olive oil", "notes": "Olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 6.0, "unit": "servings", "item": "salt", "notes": "Salt", "category": "spices and seasonings"}, {"quantity": 0.33333334, "unit": "cup", "item": "pine nuts", "notes": "1/3 cup pine nuts", "category": "baking"}, {"quantity": 0.33333334, "unit": "cup", "item": "cranberries", "notes": "1/3 cup dried cranberries", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "parmesan cheese", "notes": "1/4 cup Parmesan cheese, shaved", "category": "cheese"}, {"quantity": 6.0, "unit": "servings", "item": "pepper", "notes": "Freshly ground black pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "dijon mustard", "notes": "2 tablespoons Dijon mustard", "category": "condiments"}, {"quantity": 0.25, "unit": "cup", "item": "lemon juice", "notes": "1/4 cup lemon juice", "category": "produce"}, {"quantity": 3.0, "unit": "tablespoons", "item": "oregano leaves", "notes": "3 tablespoons fresh oregano leaves", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "kosher salt", "notes": "1/2 teaspoon Kosher salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "pepper flakes", "notes": "1/2 teaspoon red pepper flakes", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "maple syrup", "notes": "1 tablespoon maple syrup", "category": "cereal"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves garlic", "category": "produce"}, {"quantity": 0.33333334, "unit": "cup", "item": "extra virgin olive oil", "notes": "1/3 cup extra virgin olive oil", "category": "oil, vinegar, salad dressing"}]'::jsonb, '["Remove the stems from the kale and tear into pieces.", "Place prepared kale in a large bowl, rinse and drain.", "Add some olive oil and a pinch of salt and massage kale with both of your hands for about 5 minutes. (This step will help reduce the bitter flavor of the kale. Set aside.)Clean hands. Make the vinaigrette by adding Dijon mustard, lemon juice, oregano leaves, salt, red pepper flakes, maple syrup and garlic in a blender. Blend until smooth, then slowly add extra virgin olive oil, continue blending until well combined.", "Add pine nuts and dried cranberries into the large bowl with the kale.", "Pour the vinaigrette over and toss all ingredients together.", "Transfer the kale salad to a large serving bowl or small bowls for individual servings.Use a vegetable peeler, shave some Parmesan cheese on top and season with freshly ground black pepper.", "Serve!"]'::jsonb, 'https://www.foodista.com/recipe/HMJJ8BBC/massaged-kale-salad-with-pine-nuts-dried-cranberries', 'https://img.spoonacular.com/recipes/1096040-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('barley-salad-with-vegetables', 'Barley salad with vegetables', 1, 0, 0, '{"calories": 346, "protein": 9.25, "carbs": 50.48, "fat": 15.92, "saturated_fat": 2.37, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 113207.64, "potassium": null, "fiber": 20.07, "sugar": 30.73, "vitamin_a": null, "vitamin_c": 205.62, "calcium": 176.43, "iron": 3.56}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'whole 30', 'vegan', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "", "item": "aubergine", "notes": "1 aubergine", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "courgette", "notes": "1 courgette", "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "extra virgin olive oil", "notes": "extra virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 onion", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 red pepper", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "salt", "notes": "1 cup salt (common table salt is fine here)", "category": "spices and seasonings"}]'::jsonb, '["Simply wash the vegetables and cut them in small chunks.In a large pan cook them with some extra virgin olive oil until tender.Season with salt and if you like with grounded pepper.Cook the barley in salted boiling water for 10 mins.", "Let it cool down with some cold water and then toss with the vegetables.A perfect summer dish with lots of veggie. You can enjoy this meal hot or cold as you prefer"]'::jsonb, 'https://www.foodista.com/recipe/WJG6SHB5/barley-salad-with-vegetables', 'https://img.spoonacular.com/recipes/634342-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('middle-eastern-chopped-salad', 'Middle Eastern Chopped Salad', 8, 0, 0, '{"calories": 179, "protein": 3.21, "carbs": 6.81, "fat": 17.14, "saturated_fat": 1.94, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 402.5, "potassium": null, "fiber": 2.39, "sugar": 2.0, "vitamin_a": null, "vitamin_c": 36.13, "calcium": 51.19, "iron": 1.7}'::jsonb, ARRAY['middle eastern', 'side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'whole 30', 'vegan', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "walnuts", "notes": "1 cup chopped, toasted walnuts", "category": "baking"}, {"quantity": 2.0, "unit": "cups", "item": "parsley", "notes": "2 cups finely chopped Italian parsley (approximately 2 bunches)", "category": "produce"}, {"quantity": 0.75, "unit": "cup", "item": "niçoise olives", "notes": "3/4 cup chopped, pitted kalamata, Greek, or niçoise olives (about 1 ¼ cups with pits)", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "cup", "item": "scallion", "notes": "1/2 cup minced scallion (about 1 bunch)", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "tomato", "notes": "1 cup peeled, seeded, and chopped tomato (2 large)", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "extra virgin olive oil", "notes": "cup extra virgin olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "cup", "item": "squeezed lemon juice", "notes": "cup fresh squeezed lemon juice", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "cumin powder", "notes": "1/2 teaspoon cumin powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "chili flake", "notes": "1/2 teaspoon red chili flake", "category": "produce"}, {"quantity": 8.0, "unit": "servings", "item": "kosher salt and coarsely ground pepper", "notes": "Kosher salt and coarsely ground black pepper (to taste)", "category": "spices and seasonings"}]'::jsonb, '["Preheat the oven to 325 F.", "Place the nuts on a baking sheet and toast for about 10 minutes until they begin to emit a toasted nut aroma. Cool completely before using the nuts in the recipe.", "Remove the stems from the parsley and mince either by hand or with quick pulses in a food processor. The parsley should be finely minced, but if you use a food processor be careful not to pure it. The parsley should form a fluffy base for the other textures.", "Chop the olives, walnuts, and scallions by hand into a rough dice. Dice the prepared tomatoes and drain.", "Combine all of the chopped ingredients. Toss in a large wooden bowl with the olive oil, fresh lemon juice, cumin, and chili flakes. Season to taste with salt and black pepper."]'::jsonb, 'https://www.foodista.com/recipe/YWH5QKBS/middle-eastern-chopped-salad', 'https://img.spoonacular.com/recipes/651823-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('raspberry-arugula-side-salad', 'Raspberry Arugula Side Salad', 2, 0, 0, '{"calories": 142, "protein": 2.72, "carbs": 8.41, "fat": 11.93, "saturated_fat": 1.59, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 657.4, "potassium": null, "fiber": 3.95, "sugar": 3.76, "vitamin_a": null, "vitamin_c": 22.31, "calcium": 105.79, "iron": 1.59}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'fodmap friendly', 'whole 30', 'vegan', 'ketogenic', 'spoonacular', 'vegetarian'], '[{"quantity": 2.0, "unit": "oz", "item": "arugula", "notes": "2 oz arugula", "category": "produce"}, {"quantity": 1.0, "unit": "oz", "item": "baby spinach", "notes": "1 oz baby spinach", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "cucumber", "notes": "1 cucumber, chopped", "category": "produce"}, {"quantity": 10.0, "unit": "", "item": "cilantro leaves", "notes": "10-15 parsley or cilantro leaves", "category": "spices and seasonings"}, {"quantity": 14.0, "unit": "", "item": "olives", "notes": "14 pitted olives", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "servings", "item": "salt", "notes": "Salt to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "olive oil", "notes": "1 Tablespoon olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "lemon juice", "notes": "1 Tablespoon lemon juice", "category": "produce"}, {"quantity": 14.0, "unit": "", "item": "raspberries", "notes": "14 raspberries", "category": "produce"}]'::jsonb, '["Place all the ingredients into a salad bowl (excluding the raspberries) and toss well.", "Add salt to taste. Top with raspberries but do not mix in as they get crushed easily."]'::jsonb, 'https://www.foodista.com/recipe/GR74D5VW/raspberry-arugula-salad-recipe-paleo-keto-aip', 'https://img.spoonacular.com/recipes/1095693-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bulgur-wheat-salad-with-chickpeas-bell-peppers-tomatoes', 'Bulgur Wheat Salad with Chickpeas, Bell Peppers & Tomatoes', 2, 0, 0, '{"calories": 543, "protein": 21.84, "carbs": 105.22, "fat": 8.1, "saturated_fat": 0.91, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 818.62, "potassium": null, "fiber": 27.1, "sugar": 15.35, "vitamin_a": null, "vitamin_c": 211.34, "calcium": 151.83, "iron": 6.05}'::jsonb, ARRAY['side dish', 'lunch', 'main course', 'salad', 'main dish', 'dinner', 'dairy free', 'lacto ovo vegetarian', 'spoonacular', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "bulgur", "notes": "1 cup bulgur", "category": "pasta and rice"}, {"quantity": 1.5, "unit": "cup", "item": "water", "notes": "1 1/2 cup water", "category": "beverages"}, {"quantity": 1.0, "unit": "tsp", "item": "oil", "notes": "1 tsp oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 red pepper", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "orange pepper", "notes": "1 orange pepper", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 green pepper", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "spring onions", "notes": "2 Spring onions", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 Red onion", "category": "produce"}, {"quantity": 15.0, "unit": "oz", "item": "chickpeas", "notes": "1 15 oz can chickpeas", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "", "item": "juice of lime", "notes": "Juice of 1 lime", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "cilantro", "notes": "Cilantro", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "cumin", "notes": "1 tsp cumin", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tsp", "item": "honey", "notes": "2 tsp honey", "category": "nut butters, jams, and honey"}]'::jsonb, '["Combine bulgur, 1 1/2 cups water, salt, and a drizzle of oil in a saucepan. Bring to a simmer, then cover and cook over low heat until tender, about 12 minutes.", "Remove from heat; let stand, covered, 10 minutes. Fluff with a fork. While the bulgur is cooking, dice the bell peppers, slice the spring onions thinly, dice the red onion into small pieces, and roughly chop up the cilantro.Once the bulgur reaches room temperature, you can mix it with all the other ingredients.Season with salt and pepper to taste."]'::jsonb, 'https://www.foodista.com/recipe/YTTY6HD2/bulgur-wheat-salad-with-chickpeas-bell-peppers-tomatoes', 'https://img.spoonacular.com/recipes/1095768-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('colorful-and-crunchy-pomegranate-and-spinach-side-salad', 'Colorful and Crunchy Pomegranate and Spinach Side Salad', 4, 0, 0, '{"calories": 115, "protein": 2.82, "carbs": 13.11, "fat": 6.66, "saturated_fat": 0.75, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 242.18, "potassium": null, "fiber": 3.14, "sugar": 8.74, "vitamin_a": null, "vitamin_c": 13.57, "calcium": 54.45, "iron": 1.31}'::jsonb, ARRAY['side dish', 'antipasti', 'salad', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'gluten free', 'dairy free', 'paleolithic', 'lacto ovo vegetarian', 'primal', 'spoonacular', 'vegetarian'], '[{"quantity": 2.0, "unit": "tablespoons", "item": "almonds", "notes": "2 tablespoons almonds, sliced", "category": "nuts"}, {"quantity": 4.0, "unit": "cups", "item": "baby spinach", "notes": "4 cups baby spinach", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "pomegranate balsamic vinegar", "notes": "2 tablespoons pomegranate balsamic vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.5, "unit": "tablespoon", "item": "dijon mustard", "notes": "1/2 tablespoon dijon mustard", "category": "condiments"}, {"quantity": 4.0, "unit": "small", "item": "green onion", "notes": "4 smalls green onion, sliced", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "honey", "notes": "1 teaspoon honey", "category": "nut butters, jams, and honey"}, {"quantity": 1.0, "unit": "tablespoon", "item": "olive oil", "notes": "1 tablespoon olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "cup", "item": "pomegranate seeds", "notes": "1 cup pomegranate seeds", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper to taste", "category": "spices and seasonings"}]'::jsonb, '["Whisk olive oil, vinegar, honey and dijon with salt and pepper to taste.", "Combine spinach, pomegranate seeds and onion. Toss with dressing.Top with almonds."]'::jsonb, 'https://www.foodista.com/recipe/7RC6J8DZ/colorful-and-crunchy-pomegranate-and-spinach-salad', 'https://img.spoonacular.com/recipes/639948-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('korean-sweet-n-sour-chicken', 'Korean Sweet n Sour Chicken', 4, 0, 0, '{"calories": 604, "protein": 56.26, "carbs": 41.26, "fat": 22.47, "saturated_fat": 3.81, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 808.52, "potassium": null, "fiber": 3.42, "sugar": 14.35, "vitamin_a": null, "vitamin_c": 8.03, "calcium": 73.26, "iron": 3.23}'::jsonb, ARRAY['chinese', 'asian', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'dessert', 'baking'], '[{"quantity": 2.0, "unit": "", "item": "carrots", "notes": "•2 carrots, cut into thin pieces", "category": "produce"}, {"quantity": 2.0, "unit": "lbs", "item": "chicken breasts", "notes": "2 lbs boneless chicken breasts, cut into strips", "category": "meat"}, {"quantity": 3.0, "unit": "tbsp", "item": "cider vinegar", "notes": "•3 tbsp cider vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tbsp", "item": "corn starch", "notes": "•2 tbsp corn starch (+ 2 tbsp water mixed together)", "category": "baking"}, {"quantity": 2.0, "unit": "tbsp", "item": "cornstarch", "notes": "•2 tbsp cornstarch", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "edamame", "notes": "•1 cup edamame", "category": "health foods"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "•1 beaten egg", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "cup", "item": "flour", "notes": "•½ cup flour", "category": "baking"}, {"quantity": 1.0, "unit": "medium size", "item": "onion", "notes": "•1 medium size onion, cut into strips", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "pineapple juice", "notes": "•1/4 cup pineapple juice (optional if available)", "category": "beverages"}, {"quantity": 2.0, "unit": "tbsp", "item": "soy sauce", "notes": "•2 tbsp soy sauce", "category": "ethnic foods"}, {"quantity": 3.0, "unit": "tbsp", "item": "sugar", "notes": "•3 tbsp sugar", "category": "baking"}, {"quantity": 4.0, "unit": "servings", "item": "vegetable oil", "notes": "Vegetable Oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "cup", "item": "water", "notes": "•1 cup of water", "category": "beverages"}]'::jsonb, '["Cut the chicken into thin strips, about 1 or 2-inch pieces.", "Add soy sauce to the chicken for a short marination; mix well and set aside.", "Cut the vegetables into large bite-sized pieces. Set aside until the sauce is ready and thickened.Make batter by mixing the flour, cornstarch, water and beaten egg.", "Add more flour until a thick consistency is reached. Dip the marinated chicken strips into the batter.Bring vegetable oil to medium high heat. Deep fry each of the strips for about 3, 4 min for each batch or until browned and cooked through. When finished, place on paper towel-lined dish to remove excess oil. Once the first round of frying is done, heat the oil and re-fry the batch for the 2nd time to make it really crispy (optional).To make the sauce bring the following ingredients in a saucepan: one cup of water along 3 tbsp vinegar, 3 tbsp sugar, and 2 tbsp of soy sauce. Bring to a rapid boil and then add the mixture of cornstarch and water.", "Add desired vegetables and let simmer for about 5 minutes or until it thickens.On a large plate, add the fried chicken strips, then pour over the sauce/vegetable mixture and serve while warm."]'::jsonb, 'https://www.foodista.com/recipe/6458DTC4/chicken-tangsuyuk-sweet-n-sour-chicken', 'https://img.spoonacular.com/recipes/638369-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chinese-style-stewed-meatballs', 'Chinese Style Stewed Meatballs', 4, 0, 0, '{"calories": 440, "protein": 25.68, "carbs": 12.29, "fat": 31.76, "saturated_fat": 10.16, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 818.37, "potassium": null, "fiber": 1.96, "sugar": 3.14, "vitamin_a": null, "vitamin_c": 40.95, "calcium": 150.42, "iron": 3.15}'::jsonb, ARRAY['chinese', 'asian', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'dessert', 'soup', 'baking'], '[{"quantity": 400.0, "unit": "grams", "item": "ground beef", "notes": "400 grams ground beef", "category": "meat"}, {"quantity": 80.0, "unit": "grams", "item": "ground pork", "notes": "80 grams ground pork", "category": "meat"}, {"quantity": 3.0, "unit": "tablespoons", "item": "water", "notes": "3 tablespoons cold water", "category": "beverages"}, {"quantity": 0.5, "unit": "cup", "item": "canola oil", "notes": "1/2 cup canola oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 600.0, "unit": "grams", "item": "napa cabbage", "notes": "600 grams Napa cabbage", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "beef stock", "notes": "1 cup beef stock", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "tablespoon", "item": "green onion", "notes": "1 tablespoon sliced green onion", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "ginger", "notes": "1 teaspoon finely chopped ginger", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "teaspoon", "item": "baking soda", "notes": "1/4 teaspoon baking soda", "category": "baking"}, {"quantity": 0.5, "unit": "tablespoon", "item": "soy sauce", "notes": "1/2 tablespoon soy sauce", "category": "ethnic foods"}, {"quantity": 0.25, "unit": "teaspoon", "item": "salt", "notes": "1/4 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tablespoon", "item": "shaoxing wine", "notes": "1/2 tablespoon Shaoxing wine", "category": "alcoholic beverages"}, {"quantity": 1.0, "unit": "tablespoon", "item": "cornstarch", "notes": "1 tablespoon cornstarch", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "soy sauce", "notes": "1 tablespoon soy sauce", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "teaspoon", "item": "sugar", "notes": "1/2 teaspoon sugar", "category": "baking"}, {"quantity": 2.0, "unit": "tablespoons", "item": "cornstarch", "notes": "2 tablespoons teaspoons cornstarch+ 1 water", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "sesame oil", "notes": "1/2 teaspoon sesame oil", "category": "ethnic foods"}]'::jsonb, '["Grind ground beef and pork in a food processor with cold water for about 1 minute until the mixture comes together smoothly.", "Add the seasonings for the meatballs to the mixture, and using your fingers blend them into the mixture until it comes together.", "Slice the Napa cabbage into large pieces.  Stir fry with 2 tablespoons oil and season with 1/3 teaspoon salt.  Cover and cook until the cabbage is soft but still has bite to it.", "Remove to a platter and keep warm.", "Heat the remaining oil in a large skillet over medium heat.  Wet hands with water and form ball from about 2 to 3 tablespoons of meat mixture.  Drop the meatballs to the hot pan and press slightly on top of each meatballs.  Cook each side approximate 3-4 minutes, or until they are golden brown.", "Drain off the oil from the skillet.", "Pour 1 cup of beef stock to the skillet, add soy sauce, salt, and sugar.", "Let it boil then simmer fro 2 minutes.  Adjust the seasoning if needed at this time.  Thicken the sauce with the mixture of cornstarch and water, stir continuously until the sauce thicken.  Splash sesame oil and sprinkle chopped green onions on top.", "Place meatballs over Napa cabbage on the platter."]'::jsonb, 'https://www.foodista.com/recipe/7QHTKPF5/chinese-style-stewed-meatballs', 'https://img.spoonacular.com/recipes/638722-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chinese-style-chicken-and-noodle-stir-fry', 'Chinese Style Chicken and Noodle Stir Fry', 6, 0, 0, '{"calories": 469, "protein": 30.94, "carbs": 62.7, "fat": 10.01, "saturated_fat": 1.71, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1192.51, "potassium": null, "fiber": 6.06, "sugar": 5.61, "vitamin_a": null, "vitamin_c": 38.92, "calcium": 39.95, "iron": 3.91}'::jsonb, ARRAY['chinese', 'asian', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'dessert', 'soup', 'pasta'], '[{"quantity": 454.0, "unit": "gram", "item": "chow mein noodles", "notes": "16 ounces (454 gram) package of chow mein noodles", "category": "ethnic foods"}, {"quantity": 0.25, "unit": "cup", "item": "chicken broth", "notes": "1/4 cup chicken broth", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sugar", "notes": "1 teaspoon sugar", "category": "baking"}, {"quantity": 4.0, "unit": "tablespoons", "item": "oyster sauce", "notes": "4 tablespoons oyster sauce", "category": "ethnic foods"}, {"quantity": 1.5, "unit": "tablespoons", "item": "soy sauce", "notes": "1 1/2 tablespoons soy sauce", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "cup", "item": "water", "notes": "1/2 cup water", "category": "beverages"}, {"quantity": 2.0, "unit": "tablespoons", "item": "vegetable oil", "notes": "2 tablespoons vegetable oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "tablespoons", "item": "garlic", "notes": "2 tablespoons minced garlic", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "ginger", "notes": "2 tablespoons minced ginger", "category": "produce"}, {"quantity": 5.0, "unit": "", "item": "chicken thighs", "notes": "5 boneless, skinless chicken thighs, cut into bite sized pieces", "category": "meat"}, {"quantity": 1.0, "unit": "", "item": "onion", "notes": "1 onion, chopped", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "bell pepper", "notes": "1 red pepper, sliced into thin strips", "category": "produce"}, {"quantity": 2.0, "unit": "large", "item": "carrots", "notes": "2 large carrots, cut into matchsticks", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "sugar snap peas", "notes": "1 cup sugar snap peas, sliced lengthwise", "category": "produce"}]'::jsonb, '["Soak noodles in hot water until softened, about 5 minutes.", "Drain and set aside.", "In a small bowl, combine chicken broth, sugar, oyster sauce, soy sauce and water. Set aside.", "Heat oil in a wok over medium high heat. When hot, add garlic and ginger. Cook until fragrant , about 30 seconds, then add chicken and cook until done.", "Add vegetables and cook until tender crisp, about 4 -5 minutes, then add chicken broth mixture.", "Stir in drained noodles and cook until heated through, about 2 minutes. Enjoy!"]'::jsonb, 'https://www.foodista.com/recipe/8F8C33VG/chinese-style-chicken-and-noodle-stir-fry', 'https://img.spoonacular.com/recipes/638714-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fried-stuffed-wontons-with-healthy-dark-chocolate', 'Fried Stuffed Wontons with Healthy Dark Chocolate', 6, 0, 0, '{"calories": 313, "protein": 8.03, "carbs": 19.89, "fat": 24.02, "saturated_fat": 3.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 293.35, "potassium": null, "fiber": 5.07, "sugar": 4.55, "vitamin_a": null, "vitamin_c": 95.36, "calcium": 49.81, "iron": 3.73}'::jsonb, ARRAY['chinese', 'asian', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'dairy free', 'spoonacular'], '[{"quantity": 0.5, "unit": "cup", "item": "almonds", "notes": "1/2 cup Toasted Almonds, chopped (1tbsp reserved for sprinkling)", "category": "nuts"}, {"quantity": 1.0, "unit": "", "item": "chicken breast", "notes": "1 Chicken Breast- cooked and shredded", "category": "meat"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 Egg", "category": "milk, eggs, other dairy"}, {"quantity": 6.0, "unit": "servings", "item": "bell pepper", "notes": "pepper", "category": "produce"}, {"quantity": 6.0, "unit": "servings", "item": "salt", "notes": "salt", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "servings", "item": "vegetable oil", "notes": "vegetable oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 5.0, "unit": "", "item": "xocai nuggets", "notes": "5 Xocai Nuggets, chopped", "category": "frozen"}, {"quantity": 1.0, "unit": "Tbsp", "item": "water", "notes": "1 Tbsp Water", "category": "beverages"}, {"quantity": 12.0, "unit": "", "item": "wonton", "notes": "12 Wonton Sheets", "category": "ethnic foods"}]'::jsonb, '["Beat together egg and water.", "Combine almonds (all but 1 tbsp), Nuggets, Chicken and salt and the pepper.", "Place a small scoop of the filling in the center of each wonton, ans then brush lightly with egg wash. Bring sides together and pinch at the top to seal. Make sure your oil is hot, and drop our wontons in carefully; turn to brown all sides (it does not take long.)", "Remove from oil and drain on paper towel.", "Sprinkle with leftover chopped almonds.", "Serves 6"]'::jsonb, 'https://www.foodista.com/recipe/C6DCLFYW/fried-stuffed-wontons', 'https://img.spoonacular.com/recipes/643808-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chinese-scallion-pancakes', 'Chinese Scallion Pancakes', 2, 0, 0, '{"calories": 594, "protein": 10.77, "carbs": 78.07, "fat": 26.23, "saturated_fat": 2.97, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1753.07, "potassium": null, "fiber": 3.32, "sugar": 0.83, "vitamin_a": null, "vitamin_c": 4.51, "calcium": 35.24, "iron": 5.01}'::jsonb, ARRAY['chinese', 'asian', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'dessert', 'breakfast', 'baking', 'vegetarian'], '[{"quantity": 200.0, "unit": "g", "item": "flour", "notes": "200g all-purpose flour", "category": "baking"}, {"quantity": 1.5, "unit": "teaspoon", "item": "salt", "notes": "1 1/2 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 125.0, "unit": "ml", "item": "water", "notes": "125ml water", "category": "beverages"}, {"quantity": 4.0, "unit": "", "item": "green onions", "notes": "4 scallions or green onions, green parts only", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "sesame seed oil", "notes": "2 tablespoons sesame seed oil, for brushing", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "cup", "item": "oil", "notes": "1/2 cup oil, for frying", "category": "oil, vinegar, salad dressing"}]'::jsonb, '["Combine the sifted flour and salt in a large bowl", "Bring the water to the boil, then stir slowly into the flour. Knead continuously for about 15 minutes until the dough loses its stickiness and becomes a smooth ball.", "Add more flour is the dough is still sticky, or a little more water if it''s too dry.", "Place the dough in a bowl, cover with a damp cloth, and leave for 30 minutes", "Add the scallions/spring onions to the dough, and mix/fold well into the mixture.", "Cut the dough into 4 separate pieces.Use a rolling pin to roll each piece to roll it into a flat thin disk.", "Brush on some oil (use sesame seed oil if you want to add some extra flavor), then roll the disk into a long, thin sausage.Curl the sausages up into a snail, then roll into a flat, round pancake.", "Add 6mm of oil into a frying pan and shallow fry each pancake. Fry for about 1 minute, then flip over to cook the other side. Continue flipping if necessary, and press down with a spatula to cook the whole surface evenly", "Once cooked, take out the pan and place onto a piece of kitchen towel to absorb the excess oil.", "Cut into small, pizza-shaped segments, then serve"]'::jsonb, 'https://www.foodista.com/recipe/HMKTT3PR/sichuan-saliva-chicken', 'https://img.spoonacular.com/recipes/1095843-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('rice-noodles-with-wontonchinese-ravioli-in-mushroom-sauce', 'Rice Noodles With Wonton/chinese Ravioli In Mushroom Sauce', 2, 0, 0, '{"calories": 396, "protein": 25.67, "carbs": 12.99, "fat": 27.23, "saturated_fat": 6.47, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1043.94, "potassium": null, "fiber": 2.32, "sugar": 3.26, "vitamin_a": null, "vitamin_c": 5.0, "calcium": 90.21, "iron": 1.45}'::jsonb, ARRAY['chinese', 'asian', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'pasta'], '[{"quantity": 2.0, "unit": "servings", "item": "half carrot", "notes": "half carrot, finely chopped", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "cornstarch", "notes": "2 teaspoons cornstarch + 2 tbsp water", "category": "baking"}, {"quantity": 3.0, "unit": "", "item": "shiitake mushrooms", "notes": "3 shiitake dried mushrooms, thinly sliced (note:soak the mushr", "category": "produce"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": "1 clove of garlic, finely chopped", "category": "produce"}, {"quantity": 1.5, "unit": "tablespoons", "item": "oyster sauce", "notes": "1 1/2 tablespoons oyster sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "dash", "item": "pepper", "notes": "dash of white pepper", "category": "spices and seasonings"}, {"quantity": 100.0, "unit": "grams", "item": "pork", "notes": "100 grams pork, minced", "category": "meat"}, {"quantity": 150.0, "unit": "grams", "item": "prawns", "notes": "150 grams prawns, minced", "category": "seafood"}, {"quantity": 1.0, "unit": "packet", "item": "rice noodles", "notes": "some rice noodles (slightly less than half packet)", "category": "gluten free"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sesame oil", "notes": "1 teaspoon sesame oil", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tablespoon", "item": "soya sauce", "notes": "1 tablespoon dark soya sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "inch", "item": "spring onions", "notes": "1 inch stalk of spring onions, finely sliced lengthwise", "category": "produce"}, {"quantity": 2.0, "unit": "servings", "item": "vegetable oil", "notes": "some olive or vegetable oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 150.0, "unit": "ml", "item": "water", "notes": "150 ml water", "category": "beverages"}, {"quantity": 2.0, "unit": "servings", "item": "wonton wrappers", "notes": "some wonton wrappers", "category": "ethnic foods"}]'::jsonb, '["Soak the rice noodles in warm water for about 20 minutes or until they are soft. Then, set aside.In a small bowl, place just enough warm water and soak the mushrooms until soft. (This water can be incorporated into the recipe you are making and can add a lot of flavor to your dish. Strain it if you wish to use). Squeeze out excess water, slice mushrooms up to the stem on all sides and discard the stem since it is usually too tough to eat.To quickly cook the finely chopped carrots, put the carrots in the bowl with some water. Then, put in the microwave for about 1-2 minutes. Set aside for garnish later.To make the wontons, mix all the ingredients in a bowl.", "Place a wonton skin with one point towards you. Spoon about 1 tsp of the filling just off-center of skin. Fold bottom point of wonton skin over filling to make it into triangle shape. Press the edges to seal. Repeat until the filling is finished. Set aside.", "Heat a pan with some olive or vegetable oil. Put in the chopped garlic, cook until almost brown. Then, put in the sliced shiitake mushroom. Stir for 2-3 minutes.", "Add in the seasonings. After that, add in the water.", "Let it simmer for about 10  15 minutes.While the mushroom sauce is cooking away, bring a saucepan to boil and cook wontons in batches. It should take about 5 minutes or less (depending on the size of the filling) for each wonton to cook.Meanwhile, reheat the noodles and arrange desired portion on the plate.Thicken the sauce with the cornflour mixture. Spoon fair amount of sauce over the noodles.", "Garnish the noodles with carrots and spring onion.Finally, top the noodles with (some) wontons.", "Drizzle some sesame oil over the sauce before serving if you wish."]'::jsonb, 'https://www.foodista.com/recipe/GDCGKNJY/rice-noodles-with-wontonchinese-ravioli-in-mushroom-sauce', 'https://img.spoonacular.com/recipes/658270-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sweet-sour-chicken-with-lychees', 'Sweet & Sour Chicken with Lychees', 4, 0, 0, '{"calories": 329, "protein": 26.19, "carbs": 11.12, "fat": 19.41, "saturated_fat": 2.36, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 623.75, "potassium": null, "fiber": 1.45, "sugar": 5.48, "vitamin_a": null, "vitamin_c": 11.78, "calcium": 40.84, "iron": 1.41}'::jsonb, ARRAY['chinese', 'asian', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'dessert', 'baking'], '[{"quantity": 500.0, "unit": "g", "item": "chicken thigh meat", "notes": "500g chicken thigh meat (bones and skinless)", "category": "meat"}, {"quantity": 1.0, "unit": "", "item": "egg white", "notes": "1 egg white", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "corn flour", "notes": "1 tablespoon corn flour", "category": "baking"}, {"quantity": 0.25, "unit": "teaspoon", "item": "salt", "notes": "1/4 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "pepper", "notes": "1/4 teaspoon black or white pepper", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "tablespoons", "item": "cooking oil", "notes": "4 tablespoons cooking oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 200.0, "unit": "g", "item": "cucumber", "notes": "1 small cucumber (about 200g)", "category": "produce"}, {"quantity": 1.0, "unit": "large", "item": "onion", "notes": "1 large onion", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "garlic", "notes": "1 tablespoon of minced garlic", "category": "produce"}, {"quantity": 1.0, "unit": "can", "item": "lychees", "notes": "1 can of lychees (I used 565g can)", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tablespoons", "item": "liquid from the lychees above", "notes": "2 to 4 tablespoons liquid from the can of lychees above", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "oyster sauce", "notes": "1 tablespoon oyster sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tablespoon", "item": "ketchup", "notes": "1 tablespoon ketchup", "category": "condiments"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sugar", "notes": "1 teaspoon sugar", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "shaoxing huatiao cooking wine", "notes": "1 tablespoon Shaoxing Huatiao cooking wine", "category": "alcoholic beverages"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper to taste", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "chives/spring onions to garnish", "notes": "Chives/spring onions to garnish", "category": "produce"}]'::jsonb, '["Cut 500g of chicken thigh meat into bite size pieces. About 1 inch by 1 inch.", "Place the meat in a bowl.", "Add 1 egg white.", "Then add 1 tablespoon of corn flour.", "And add 1/4 teaspoon of salt and 1/4 teaspoon of pepper. I use Masterfoods Garlic Pepper Seasonings whenever salt and pepper is required. A generous shake of this to get about 1/2 teaspoon will do.", "Mix it all well with your fingers. Set aside till ready to use.", "Peel and cut a large onion into bite size pieces, approximately the same size as the chicken.", "Do the same for the cucumber. But keep the skin on the cucumber.", "Drain a can of lychees. Reserve the juice.", "Add 4 tablespoons of cooking oil in a hot pan. Keep the heat at medium high at all times.", "When the pan is hot.", "Add the chicken and make sure they are evenly distributed on one side on the pan.", "Let the chicken cook. It will eventually turn golden brown. When that happens, turn it around and cook the other side.", "Once the chicken is golden brown on both sides, dish them out of the pan and set aside in a warm place.", "Pour away excess oil in the pan and reserve about 1 tablespoon of oil. Return the pan to the stove and add the onions. Stir fry for a minute.", "Add 1 tablespoon of minced garlic. Stir fry till garlic is slightly toasted and fragrant.", "Add the cucumbers. Keep stir frying for another 30 seconds.", "Add the drained lychees.", "Mix well.", "Add 1 tablespoon of oyster sauce.", "Add 1 tablespoon of ketchup.", "Add 1 tablespoon of Shaoxing Huatiao cooking wine.", "Add 1 teaspoon of sugar.", "Add 2 tablespoons of the reserved lychee juice from the can. If the pan looks very dry, add 1 to 2 more tablespoons of the juice. Do not make too much sauce. We want the sauce to gently coat the meat and not drown the meat in it.", "Stir well to combine.", "Add a pinch of salt and pepper or 1/4 teaspoon of Masterfoods Garlic Pepper Seasonings.", "At this point, taste the sauce and adjust sweetness-sour levels accordingly. If too sweet, add a little more ketchup. If too sour, add more sugar. If not salty enough, add more salt+pepper. Different brands of oyster sauce and ketchup will affect this, so a taste test is a must.", "Once the sauce is ready, add the cooked chicken back to the sauce and toss evenly. The sauce should just gently coat the chicken without soaking it and making it soggy.", "Dish up and garnish with chives or spring onions.", "Serve immediately. Best eaten with rice."]'::jsonb, 'https://www.foodista.com/recipe/DYT75J32/sweet-sour-chicken-with-lychees', 'https://img.spoonacular.com/recipes/662422-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('korean-saewoo-bokkeumbap-shrimp-fried-rice', 'Korean Saewoo Bokkeumbap (Shrimp Fried Rice)', 4, 0, 0, '{"calories": 528, "protein": 34.26, "carbs": 66.03, "fat": 13.53, "saturated_fat": 3.92, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1424.76, "potassium": null, "fiber": 1.85, "sugar": 2.01, "vitamin_a": null, "vitamin_c": 14.92, "calcium": 127.99, "iron": 1.86}'::jsonb, ARRAY['chinese', 'asian', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'pescatarian', 'spoonacular'], '[{"quantity": 5.0, "unit": "cups", "item": "rice", "notes": "•4, 5 cups cooked rice", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "tbsp", "item": "vegetable oil", "notes": "•2 tbsp olive or vegetable oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.5, "unit": "", "item": "bell pepper", "notes": "•1/2 green bell pepper, diced", "category": "produce"}, {"quantity": 0.5, "unit": "", "item": "onion", "notes": "•1/2 onion, diced", "category": "produce"}, {"quantity": 0.5, "unit": "can", "item": "kernel corn", "notes": "•1/2 can whole kernel corn", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "carrot", "notes": "•1 carrot, diced", "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "•2 cloves garlic, thinly sliced", "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "shrimp", "notes": "•2 cups small shrimp (use larger ones if available)", "category": "seafood"}, {"quantity": 3.0, "unit": "tbsp", "item": "oyster sauce", "notes": "•2, 3 tbsp oyster sauce", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "tbsp", "item": "soy sauce", "notes": "•2 tbsp soy sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tbsp", "item": "butter", "notes": "•1 tbsp butter", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "salt", "notes": "•1/2 tsp salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "scrambled eggs", "notes": "•2 scrambled eggs", "category": "milk, eggs, other dairy"}]'::jsonb, '["In a skillet or non-stick frying pan, heat 1 tbsp olive oil and stir fry the \"hard\" vegetables first--diced bell peppers and carrots, 5 minutes. Next add the diced onions, corn, and shrimp to the pan, another 5 minutes. If there is excess water/liquid, discard carefully and set aside on lowest heat setting. Optional: Cooking each ingredient separately (pepper, carrot / garlic, onion / shrimp) to ensure that they cook consistently is perfectly fine, but it will add another 5~10 minutes to your cooking time.", "In another pan or skillet, scramble 2 eggs in generous amount of oil. When finished, add eggs to the main skillet with other ingredients. Optional: Prepare 4 sunny-side up eggs for the topping/garnish.", "On low heat, add cooled rice, butter, soy sauce and oyster sauce and mix thoroughly with spoon (wooden works best). Make sure to coat sauce on rice and rest of ingredients well; this will take a few minutes and some hand/wrist strength from continuous mixing.", "Plate the fried rice topped with a sunny-side up egg. If wanting a semi-round shape (see pic above), stuff fried rice in a round bowl pressing down firmly. Set the bowl upside down on a plate; the fried rice should sit upright in a round shape. Enjoy with kimchi and other banchan (side dishes).", "*Some people like to stir fry the ingredients separately because they cook at different times. For fried rice, this can be skipped since the main point is to get them slightly tender; this means cooking the harder veggies (carrots) first and adding the softer ones (onions) later. This will save you valuable minutes in cooking time and the hassle of washing unnecessary, extra dishes."]'::jsonb, 'https://www.foodista.com/recipe/T56C5NDJ/korean-saewoo-bokkeumbap-shrimp-fried-rice', 'https://img.spoonacular.com/recipes/649073-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('southwest-egg-rolls-with-cilantro-lime-pesto', 'Southwest Egg Rolls with Cilantro Lime Pesto', 12, 0, 0, '{"calories": 192, "protein": 2.55, "carbs": 13.92, "fat": 14.79, "saturated_fat": 2.03, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 269.86, "potassium": null, "fiber": 1.4, "sugar": 1.11, "vitamin_a": null, "vitamin_c": 17.66, "calcium": 17.17, "iron": 0.81}'::jsonb, ARRAY['chinese', 'asian', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'dairy free', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "bunch", "item": "cilantro", "notes": "1 bunch cilantro, stems discarded", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves garlic", "category": "produce"}, {"quantity": 1.0, "unit": "Tbsp", "item": "almonds", "notes": "1 heaping Tbsp sliced almonds", "category": "baking"}, {"quantity": 12.0, "unit": "", "item": "juice of lime", "notes": "juice of lime, divided", "category": "produce"}, {"quantity": 12.0, "unit": "servings", "item": "olive oil", "notes": "olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 12.0, "unit": "servings", "item": "salt & pepper", "notes": "salt & pepper", "category": "spices and seasonings"}, {"quantity": 12.0, "unit": "", "item": "egg roll wrappers", "notes": "12 egg roll wrappers", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "small", "item": "bell pepper", "notes": "1 red bell pepper, small dice", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "corn", "notes": "1/2 cup corn", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "black beans", "notes": "1/2 cup black beans, rinsed and drained", "category": "pasta and rice"}]'::jsonb, '["Oven at 385 degrees.", "Make the pesto: In a small food processor add the garlic and almonds. Pulse until finely chopped.", "Add the cilantro leaves and about 3-4 Tbsp olive oil, the amount is really a preference of how loose or thick you like the pesto. Start with a little and add a little at a time until you reach the consistency of your preference. Stir in the juice of 1/2 a lime. If you are making this ahead of time...place in a bowl and drizzle just enough olive oil on top to coat, this keeps the air from getting to the cilantro. Cover with plastic wrap and refrigerate.", "Saut the peppers with a drizzle of olive oil in a pan over medium high heat for just a couple minutes.", "Mix the peppers, corn and black beans in a bowl.", "Lay out the egg roll wrappers. Smear some of the cilantro lime pesto on the end closest to you, leaving about an inch of the wrapper on the very end.", "Add a spoon full of the veggies along the line of pesto.", "Brush the ends of the wrapper with water, this will help seal the egg roll. Fold the end nearest you over the veggies and the two", "sides fold in as well.", "Roll up the wrapper to the end.", "Place seam side down on a lined baking sheet that his been brushed with a bit of olive oil to prevent sticking.", "Brush the egg rolls lightly with olive oil as well, this will help get that golden color.", "Bake for approx 18 minutes, or until golden and crispy."]'::jsonb, 'https://www.foodista.com/recipe/CM34KFZM/southwest-egg-rolls', 'https://img.spoonacular.com/recipes/660707-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chinese-steamed-flan', 'Chinese Steamed Flan', 6, 0, 0, '{"calories": 251, "protein": 7.83, "carbs": 42.85, "fat": 6.29, "saturated_fat": 2.58, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 80.02, "potassium": null, "fiber": 2.88, "sugar": 38.89, "vitamin_a": null, "vitamin_c": 84.67, "calcium": 142.1, "iron": 1.19}'::jsonb, ARRAY['chinese', 'asian', 'dessert', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'vegetarian'], '[{"quantity": 4.0, "unit": "large", "item": "eggs", "notes": "4 large eggs", "category": "milk, eggs, other dairy"}, {"quantity": 0.33333334, "unit": "cup", "item": "granulated sugar", "notes": "1/3 cup granulated sugar", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "granulated sugar", "notes": "1/2 cup granulated sugar", "category": "baking"}, {"quantity": 6.0, "unit": "servings", "item": "strawberries", "notes": "strawberries", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "vanilla", "notes": "1 tsp vanilla", "category": "baking"}, {"quantity": 2.0, "unit": "cups", "item": "milk", "notes": "2 cups whole milk", "category": "milk, eggs, other dairy"}]'::jsonb, '["Place 2 inches of water on the bottom portion of steamer.  Cover and allow water to come to a boil.  In the meantime, heat milk and sugar in a saucepan until just warmed and sugar has dissolved.", "Whisk eggs and vanilla in a large bowl until blended.  Slowly pour warmed milk into the eggs, beating until well combined.  Scoop off foam and discard.  Ladle into prepared ramekins and place into steamer.Turn down heat  this is very important  to medium and steam for 15 minutes.", "Remove and allow to cool.  Once cool, cover and refrigerate overnight.  When ready to serve, carefully run a knife around the inside each ramekin to loosen the flan.", "Place a plate on top of the flan and invert until flan pops out.", "Serve with sliced strawberries."]'::jsonb, 'https://www.foodista.com/recipe/GNDGXPZK/chinese-steamed-flan', 'https://img.spoonacular.com/recipes/638717-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chinese-hot-pots-gluten-free-and-low-carb', 'Chinese Hot Pots Gluten-Free and Low-Carb', 8, 0, 0, '{"calories": 310, "protein": 18.92, "carbs": 27.59, "fat": 13.52, "saturated_fat": 3.4, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1972.01, "potassium": null, "fiber": 1.57, "sugar": 5.13, "vitamin_a": null, "vitamin_c": 29.62, "calcium": 98.7, "iron": 2.61}'::jsonb, ARRAY['chinese', 'asian', 'lunch', 'main course', 'main dish', 'dinner', 'dairy free', 'spoonacular', 'soup', 'pasta'], '[{"quantity": 6.0, "unit": "cups", "item": "chicken stock", "notes": "6 cups chicken stock", "category": "canned and jarred"}, {"quantity": 6.0, "unit": "cups", "item": "water", "notes": "6 cups water", "category": "beverages"}, {"quantity": 0.5, "unit": "cup", "item": "rice vinegar", "notes": "1/2 cup rice vinegar", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "cup", "item": "soy sauce", "notes": "cup soy sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tablespoon", "item": "sesame oil", "notes": "1 tablespoon sesame oil", "category": "ethnic foods"}, {"quantity": 5.0, "unit": "slices", "item": "ginger", "notes": "5 slices of fresh ginger", "category": "produce"}, {"quantity": 5.0, "unit": "", "item": "garlic cloves", "notes": "5 garlic cloves, cracked", "category": "produce"}, {"quantity": 1.0, "unit": "pound", "item": "chicken thighs", "notes": "1 pound boneless chicken thighs, thinly sliced", "category": "meat"}, {"quantity": 5.0, "unit": "ounces", "item": "rice stick noodles", "notes": "5 ounces bean thread noodles, or rice stick noodles", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "bunch", "item": "of green onions", "notes": "1 bunch large of green onions", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "mung bean sprouts", "notes": "1 cup mung bean sprouts", "category": "ethnic foods"}, {"quantity": 8.0, "unit": "ounces", "item": "mushrooms", "notes": "8 ounces mushrooms, any variety", "category": "produce"}, {"quantity": 4.0, "unit": "", "item": "baby bok choy", "notes": "4 baby bok choy", "category": "produce"}, {"quantity": 8.0, "unit": "servings", "item": "chile-garlic paste", "notes": "Chile-garlic paste", "category": "produce"}]'::jsonb, '["In a large pot, bring the chicken stock, water, vinegar, soy sauce, sesame oil, ginger and garlic to a boil.", "Add the chicken and simmer for 5-7 minutes, until just cooked through.", "Add the noodles. Stir, then cover and remove from heat.", "Meanwhile chop all the veggies and place in serving bowls.", "When ready to serve, allow each person to fill their bowls with fresh vegetables and a bit of chile sauce.", "Then ladle the scalding hot soup over the veggies and let them sit for 5 minutes.", "Mix and eat!"]'::jsonb, 'https://www.foodista.com/recipe/ZTHZGV7D/chinese-hot-pots-gluten-free-and-low-carb', 'https://img.spoonacular.com/recipes/638668-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('salmon-and-brown-rice-eggrolls', 'Salmon and Brown Rice Eggrolls', 20, 0, 0, '{"calories": 175, "protein": 6.22, "carbs": 28.83, "fat": 3.7, "saturated_fat": 0.43, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 358.06, "potassium": null, "fiber": 1.42, "sugar": 0.53, "vitamin_a": null, "vitamin_c": 1.06, "calcium": 24.16, "iron": 1.31}'::jsonb, ARRAY['chinese', 'asian', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'dairy free', 'pescatarian', 'spoonacular', 'baking'], '[{"quantity": 2.0, "unit": "cups", "item": "left over brown rice", "notes": "2 cups of left over brown rice", "category": "pasta and rice"}, {"quantity": 3.0, "unit": "tablespoons", "item": "canola oil", "notes": "3 tablespoons of canola oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 3.0, "unit": "medium", "item": "sized carrots", "notes": "3 mediums sized carrots, diced", "category": "produce"}, {"quantity": 1.0, "unit": "package", "item": "eggroll wrappers", "notes": "1 package eggroll wrappers", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "large clove", "item": "garlic", "notes": "1 large clove garlic, crushed", "category": "produce"}, {"quantity": 1.0, "unit": "inch", "item": "ginger", "notes": "1 inch of grated ginger", "category": "produce"}, {"quantity": 4.0, "unit": "stalks", "item": "green onions", "notes": "4 stalks of green onions, white and green part, finely chopped", "category": "produce"}, {"quantity": 20.0, "unit": "servings", "item": "ground pepper", "notes": "ground black pepper", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "pound", "item": "salmon", "notes": "1/2 pound of wild caught salmon, skin on", "category": "seafood"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "soy sauce", "notes": "2 tablespoons of soy sauce", "category": "ethnic foods"}]'::jsonb, '["Pre-heat oven to 500 degrees.", "Brush on olive oil and sprinkle salt/pepper on salmon.Put in oven for 13-15 minutes.", "Let sit for 5-10 minutes or refrigerate.", "Heat a wok with canola oil and on low heat, add the minced garlic and ginger.", "Let steep in oil for 5 minutes.Then add rice, carrots and green onions.  Stir for 2 minutes.Then add housin sauce and soy sauce.  Stir for another minute or until the rice has absorbed all the sauce.Flake in the salmon.  Stir gently, being careful not to completely disintegrate the salmon.", "Let the mixture cool completely before wrapping in wonton wrappers.Once mixture is cool, fold the eggrolls following the instructions on the back of the eggroll wrapper to prepare the eggrolls.Using canola oil, fill your frying pot to about 2-3 inches from the bottom of the pot.Then, fry eggrolls at 350 degrees for about 1-2 minutes (you can check to see if oil is at the right temperature by putting a piece of the eggroll wrapper in the oil  if it floats to the top and bubbles form around it immediately, the oil is hot enough).   The egg roll will be a nice golden brown.", "Let oil drain on paper towels and serve warm with soy sauce or another dip!"]'::jsonb, 'https://www.foodista.com/recipe/QM4GVVKY/salmon-and-brown-rice-eggrolls', 'https://img.spoonacular.com/recipes/659038-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fried-rice-chinese-comfort-food', 'Fried Rice - Chinese comfort food', 4, 0, 0, '{"calories": 422, "protein": 15.75, "carbs": 46.9, "fat": 18.88, "saturated_fat": 5.87, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1458.34, "potassium": null, "fiber": 3.32, "sugar": 2.2, "vitamin_a": null, "vitamin_c": 7.44, "calcium": 61.76, "iron": 2.21}'::jsonb, ARRAY['chinese', 'asian', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'breakfast'], '[{"quantity": 0.5, "unit": "kg", "item": "rice", "notes": "½ kg rice, cooked earlier and cooled. You can cook the rice the day before and leave it in the fridge overnight to make things simple.", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "large", "item": "onion", "notes": "1 large onion, diced", "category": "produce"}, {"quantity": 0.5, "unit": "bunch", "item": "spring onions", "notes": "1/2 bunch spring onions, washed and diced", "category": "produce"}, {"quantity": 3.0, "unit": "", "item": "eggs", "notes": "3 eggs, beaten, mixed with a dash of milk", "category": "milk, eggs, other dairy"}, {"quantity": 6.0, "unit": "", "item": "rashers bacon", "notes": "6 rashers bacon, diced", "category": "meat"}, {"quantity": 0.5, "unit": "large bag", "item": "vegetables from the freezer", "notes": "½ large bag mixed diced vegetables (peas, carrots, corn) from the freezer", "category": "frozen"}, {"quantity": 2.0, "unit": "teaspoons", "item": "soy sauce", "notes": "2 teaspoons light soy sauce", "category": "condiments"}, {"quantity": 4.0, "unit": "servings", "item": "soy sauce", "notes": "Dark soy sauce", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "teaspoons", "item": "sesame oil", "notes": "2 teaspoons sesame oil", "category": "ethnic foods"}, {"quantity": 4.0, "unit": "servings", "item": "bell pepper", "notes": "White pepper", "category": "spices and seasonings"}]'::jsonb, '["Heat a large fry pan or work and add oil. Slide in the beaten egg mixture and cook for a minute or two until partly set. Turn over carefully and cook the other side. Once its cooked through, remove from pan, slice into small squares and set aside.", "Add a dash more vegetable oil in wok and fry onion over low heat until soft.", "Add bacon and cook for a couple of minutes, stirring. Once bacon is browning, turn heat up to high and add frozen vegetables. Cook, stirring occasionally for 3-4 minutes.", "Add cooked rice, breaking it up with wooden spoon as you go. Continue stirring for a few minutes until the rice starts to form a brown crust in places. Season with light soy sauce and a dash of dark soy sauce.", "Add a little soy sauce to start with and taste before you add more.", "Sprinkle with white pepper to taste.", "Mix thoroughly so rice is evenly coated and coloured.", "Add reserved omelette pieces and chopped spring onion. Stir through and let warm through for one minute. Turn off heat then add a few shakes of sesame oil. Stir to combine.", "Serve in deep, generous bowls."]'::jsonb, 'https://www.foodista.com/recipe/8MCFVMXR/fried-rice-chinese-comfort-food', 'https://img.spoonacular.com/recipes/643786-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fried-xocai-healthy-chocolate-stuffed-wontons', 'Fried Xocai Healthy Chocolate Stuffed Wontons', 6, 0, 0, '{"calories": 196, "protein": 15.73, "carbs": 11.85, "fat": 9.65, "saturated_fat": 1.68, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 535.01, "potassium": null, "fiber": 1.87, "sugar": 0.8, "vitamin_a": null, "vitamin_c": 0, "calcium": 62.27, "iron": 1.74}'::jsonb, ARRAY['chinese', 'asian', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'dairy free', 'spoonacular', 'dessert'], '[{"quantity": 0.5, "unit": "cup", "item": "almonds )", "notes": "1/2 cup chopped almonds (toasted (reserve 1 tbsp. for sprinkling))", "category": "nuts"}, {"quantity": 1.0, "unit": "", "item": "chicken breasts", "notes": "1 whole chicken breasts (cooked and shredded)", "category": "meat"}, {"quantity": 5.0, "unit": "chunks", "item": "chocolate", "notes": "5 chunks dark chocolate (Xocai Healthy Chocolate Nuggets, chopped)", "category": "sweet snacks"}, {"quantity": 3.0, "unit": "", "item": "eggs", "notes": "3 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "teaspoon", "item": "pepper", "notes": "1/4 teaspoon Pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 4.5, "unit": "cups", "item": "water", "notes": "4 1/2 cups water", "category": "beverages"}, {"quantity": 12.0, "unit": "sheets", "item": "wonton wrappers", "notes": "12 sheets wonton wrappers", "category": "ethnic foods"}]'::jsonb, '["Beat together egg and water.", "Combine almonds (all but 1 tbsp.) Nuggets, Chicken and salt and pepper.", "Place a small scoop of the filling in the center of each wanton, and then brush lightly with egg wash. Bring sides together and pinch at the top seal. Make sure your oil is HOT, and drop our wantons in carefully; turn to brown all sides (it does not take long).", "Remove from oil ans drain on paper towel.", "Sprinkle with leftover chopped almonds."]'::jsonb, 'https://www.foodista.com/recipe/SFCFV28T/fried-xocai-healthy-chocolate-stuffed-wontons', 'https://img.spoonacular.com/recipes/643832-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chinese-bbq-pork-ribs', 'Chinese Bbq Pork Ribs', 6, 0, 0, '{"calories": 288, "protein": 19.1, "carbs": 15.12, "fat": 17.18, "saturated_fat": 5.77, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 459.82, "potassium": null, "fiber": 0.67, "sugar": 11.89, "vitamin_a": null, "vitamin_c": 0, "calcium": 84.69, "iron": 1.23}'::jsonb, ARRAY['chinese', 'asian', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'spoonacular', 'dessert', 'baking', 'grilling', 'vegetarian'], '[{"quantity": 2.0, "unit": "pounds", "item": "baby back rib", "notes": "2 pounds baby back rib", "category": "meat"}, {"quantity": 2.0, "unit": "tablespoons", "item": "honey", "notes": "2 tablespoons honey", "category": "nut butters, jams, and honey"}, {"quantity": 6.0, "unit": "servings", "item": "sauce a", "notes": "Sauce A: (for marinate)", "category": "condiments"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "sugar", "notes": "2 teaspoons sugar", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "five spices", "notes": "2 teaspoons Chinese five spices", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sar cheong powder", "notes": "1 teaspoon Sar Cheong powder (a type of a ginger)", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "cooking wine", "notes": "2 teaspoons Chinese cooking wine", "category": "alcoholic beverages"}, {"quantity": 1.0, "unit": "teaspoon", "item": "garlic powder", "notes": "1 teaspoon garlic powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "cinnamon", "notes": "1 teaspoon cinnamon", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "servings", "item": "sauce b", "notes": "Sauce B: (for basting)", "category": "condiments"}, {"quantity": 2.0, "unit": "tablespoons", "item": "hoisin sauce", "notes": "2 tablespoons Hoisin sauce", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "teaspoons", "item": "ground bean paste", "notes": "2 teaspoons ground bean paste", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tablespoon", "item": "sesame seed paste", "notes": "1 tablespoon sesame seed paste", "category": "health foods"}, {"quantity": 1.0, "unit": "tablespoon", "item": "sugar", "notes": "1 tablespoon sugar", "category": "baking"}, {"quantity": 2.0, "unit": "pieces", "item": "preserved beancurd", "notes": "2 pieces of preserved red hot beancurd", "category": "refrigerated"}, {"quantity": 1.0, "unit": "teaspoon", "item": "garlic", "notes": "1 teaspoon garlic, minced", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "shallots", "notes": "1 teaspoon shallots, minced", "category": "produce"}]'::jsonb, '["Cut ribs in equal size and pat dry.", "Mix sauce A ingredients to a smooth paste. Season ribs well with this mixture and leave overnight in refrigerator.", "Mix sauce B and season ribs with half of the sauce at least 4 hours before cooking. This will allow the ribs to absorb most of the seasoning. Cover and refrigerated.", "Preheat oven to 350F. Put ribs on a pan place and roast on the top shelf.", "Place a metal bowl of water in the bottom shelf. The steam from the water keeps the meat from drying out. Roast for 30-45 minutes till golden brown but not burnt. Baste both sides of the ribs every 15 minutes.", "Remove from oven and brush ribs with honey."]'::jsonb, 'https://www.foodista.com/recipe/YTBZ6682/chinese-bbq-pork-ribs', 'https://img.spoonacular.com/recipes/638631-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_