INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('shrimp-fried-rice', 'Shrimp Fried Rice', 4, 0, 0, '{"calories": 399, "protein": 20.24, "carbs": 60.33, "fat": 8.1, "saturated_fat": 4.28, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1074.19, "potassium": null, "fiber": 2.09, "sugar": 1.97, "vitamin_a": null, "vitamin_c": 31.58, "calcium": 82.48, "iron": 1.63}'::jsonb, ARRAY['chinese', 'asian', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'pescatarian', 'spoonacular', 'soup'], '[{"quantity": 0.5, "unit": "teaspoon", "item": "basil leaves", "notes": "1/2 teaspoon of basil leaves (substitute with scent leaves)", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "pepper", "notes": "1/2 teaspoon of black pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "butter", "notes": "2 tablespoons of butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "", "item": "chicken bouillon cube", "notes": "1 chicken bouillon cube", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "teaspoon", "item": "curry powder", "notes": "1/2 teaspoon of curry powder", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "large", "item": "egg", "notes": "1 large egg", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves of garlic chopped", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ginger", "notes": "1/2 teaspoon of grated ginger", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "cooking spoon of olive oil", "notes": "1 cooking spoon of Olive Oil (substitute with vegetable oil)", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.5, "unit": "", "item": "bulb of onions", "notes": "1/2 bulb of red onions", "category": "produce"}, {"quantity": 1.5, "unit": "cups", "item": "rice", "notes": "1.5 cups rice", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "cup", "item": "vegetables", "notes": "1 cup of chopped vegetables (red and green bell peppers, carrots, spring onions)", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "salt", "notes": "Salt to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "shrimps", "notes": "1 cup of chopped shrimps", "category": "seafood"}, {"quantity": 2.0, "unit": "tablespoons", "item": "soy sauce", "notes": "2 tablespoons of Soy Sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "pinch", "item": "thyme", "notes": "A pinch of thyme", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "pepper", "notes": "1/2 teaspoon of white pepper", "category": "spices and seasonings"}]'::jsonb, '["Boil your rice a day before till soft and season with one chicken bouillon cube and leave in the fridge to cool. (You can also use this immediately if you don’t want to wait)In a pan, heat up your butter and and olive oil and fry your chopped garlic, onions and ginger on medium heat.", "Add your chopped shrimps and stir fry. Season with chicken seasoning cubes and allow to fry for 2 minutes.", "Add the chopped vegetables, the white and black pepper, basil,curry and thyme.Break your egg into the pan and stir fry it and add 1 tablespoon of soy sauce.Begin to slowly stir in your rice, one spoon at a time so that all the seasoning is absorbed.", "Add the other spoon of soy sauce and stir till all the rice absorbs all seasoning. Check for salt and serve your shrimp fried rice."]'::jsonb, 'https://www.afrolems.com/2015/10/09/shrimp-fried-rice/', 'https://img.spoonacular.com/recipes/682619-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
