Soy sauce", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "tablespoons", "item": "water", "notes": "2 tablespoons Water", "category": "beverages"}]'::jsonb, '["Mix until smooth."]'::jsonb, 'https://www.foodista.com/recipe/CWT7NX5T/kung-pao-chicken-with-peanuts', 'https://img.spoonacular.com/recipes/649129-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vegetable-fried-wontons', 'Vegetable Fried Wontons', 16, 0, 0, '{"calories": 53, "protein": 1.1, "carbs": 5.71, "fat": 2.94, "saturated_fat": 0.23, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 200.77, "potassium": null, "fiber": 0.38, "sugar": 0.64, "vitamin_a": null, "vitamin_c": 0.91, "calcium": 0, "iron": 0.35}'::jsonb, ARRAY['chinese', 'asian', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'dairy free', 'pescatarian', 'spoonacular', 'soup'], '[{"quantity": 1.0, "unit": "", "item": "scallion", "notes": "1 scallion, minced", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "jicama", "notes": "¼ cup minced jicama", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "carrot", "notes": "¼ cup minced carrot", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "celery", "notes": "¼ cup minced celery", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "ginger", "notes": "2 teaspoons minced ginger", "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves garlic, minced", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "soy sauce", "notes": "2 tablespoons soy sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "teaspoon", "item": "oyster sauce", "notes": "1 teaspoon oyster sauce", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "teaspoon", "item": "honey", "notes": "½ teaspoon honey", "category": "nut butters, jams, and honey"}, {"quantity": 1.0, "unit": "teaspoon", "item": "rice wine", "notes": "1 teaspoon rice wine", "category": "alcoholic beverages"}, {"quantity": 2.0, "unit": "tablespoons", "item": "chicken broth", "notes": "2 tablespoons chicken broth", "category": "canned and jarred"}, {"quantity": 16.0, "unit": "", "item": "wonton wrappers", "notes": "16-20 wonton wrappers", "category": "ethnic foods"}, {"quantity": 16.0, "unit": "servings", "item": "canola oil", "notes": "canola oil, for frying", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "pinch", "item": "cinnamon", "notes": "pinch of cinnamon", "category": "spices and seasonings"}, {"quantity": 16.0, "unit": "servings", "item": "sauce", "notes": "sweet and sour sauce, for serving", "category": "condiments"}]'::jsonb, '["Place the scallions, jicama, carrot, celery, ginger, and garlic in a medium-sized bowl.", "In a small bowl, whisk soy sauce, oyster sauce, honey, rice wine, and chicken broth.", "Pour the liquids over the vegetables.", "Let the mixture sit for at least 30 minutes.", "Take a wonton wrapper and place in the palm of your hand.", "Place  tablespoon of the mixture in the middle.", "Dab water around two adjacent sides of the wrapper, then bring up the other two sides of the wrapper to form a triangle.", "Place canola oil in small pot and heat to 325-350 degrees.", "Fry 4-5 wontons at a time until golden brown, about 5-8 minutes.", "Place on paper towels and then fry another batch.", "Sprinkle cinnamon on the wontons, and then serve with sweet and sour sauce."]'::jsonb, 'https://www.foodista.com/recipe/HBQWW65S/vegetable-fried-wontons', 'https://img.spoonacular.com/recipes/664551-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vegetarian-chinese-pot-stickers', 'Vegetarian Chinese Pot Stickers', 24, 0, 0, '{"calories": 152, "protein": 1.04, "carbs": 5.79, "fat": 14.15, "saturated_fat": 2.16, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 91.71, "potassium": null, "fiber": 0.3, "sugar": 0.28, "vitamin_a": null, "vitamin_c": 0, "calcium": 0, "iron": 0.32}'::jsonb, ARRAY['chinese', 'asian', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'dairy free', 'spoonacular', 'vegetarian', 'vegan'], '[{"quantity": 24.0, "unit": "", "item": "won ton wrappers", "notes": "24 won ton wrappers", "category": "ethnic foods"}, {"quantity": 8.0, "unit": "oz", "item": "mushrooms", "notes": "8 oz. mushrooms (your choice – I used half whites & half baby portobellos)", "category": "produce"}, {"quantity": 1.0, "unit": "Tbs", "item": "soy sauce", "notes": "1 Tbs. tamari or soy sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tsp", "item": "sriracha hot sauce", "notes": "1 tsp. sriracha hot sauce", "category": "condiments"}, {"quantity": 1.0, "unit": "tsp", "item": "ginger", "notes": "1 tsp. grated fresh ginger", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "garlic", "notes": "1 tsp. fresh garlic (pressed through a garlic press)", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "scallions", "notes": "2 scallions, white & green parts, roughly chopped", "category": "produce"}, {"quantity": 24.0, "unit": "servings", "item": "little cornstarch", "notes": "A little cornstarch", "category": "baking"}, {"quantity": 24.0, "unit": "servings", "item": "little vegetable oil", "notes": "A little vegetable oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "cup", "item": "water", "notes": "1 cup water, divided", "category": "beverages"}]'::jsonb, '["Add all of the ingredients (except the wrappers, cornstarch, oil, and water) to the bowl of a food processor. Pulse until the mushrooms are finely minced and all of the ingredients are well combined. It will help if youve given the mushrooms a bit of a rough chop first, or if you use pre-sliced mushrooms.", "Place a won ton wrapper on your work surface, turned so that it appears to be a diamond shape.", "Place a teaspoon of filling in the middle of the wrapper.", "Dip a fingertip into the bowl of water and trace along the two edges farthest from you. Bring up the end closest to you, fold over the filling, and pinch the edges together to seal. Make sure youve gently pressed the wrapper around the filling so there are no air pockets.", "Stand up your little triangle pocket so that the filling side sits on your work surface. Fold the top point down, away from you, and pinch. Now, give the edges on either side of that fold 2 little pleats and pinch. Your pot sticker will now look like it has wings.", "Place it on a large plate thats been dusted with a bit of cornstarch, to prevent sticking.  (Traditionally, pot stickers are made with round dumpling wrappers, so if you have them, you can skip the part about folding the top point down.)", "Heat the skillet over medium-high heat.", "Brush just a few drops of oil onto the hot pan surface, and place 12 of the pot stickers, upright, into the pan. Allow the bottoms to brown. Carefully add 1/2 cup water to the pan and cover it quickly. Cook for about 3-4 minutes, or until all of the water has been absorbed.", "Remove the pot stickers immediately to another plate to keep warm, and repeat the procedure with the rest of the uncooked ones.", "*Feel like you have to have meat? Substitute 4 oz. of ground chicken (or pork, if you must) for half of the mushrooms, just dont run it through the food processor.", "Mix the processed ingredients with the ground chicken thoroughly and fill the wrappers as before.", "Add a full cup of water (instead of 1/2 cup) to the pan, and steam until the water evaporates, about 5-6 minutes."]'::jsonb, 'https://www.foodista.com/recipe/KF58KP4Y/vegan-vegetarian-pot-stickers', 'https://img.spoonacular.com/recipes/664650-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vegetable-wontons', 'Vegetable Wontons', 10, 0, 0, '{"calories": 108, "protein": 4.77, "carbs": 14.44, "fat": 3.18, "saturated_fat": 0.46, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1527.35, "potassium": null, "fiber": 1.25, "sugar": 1.63, "vitamin_a": null, "vitamin_c": 4.95, "calcium": 27.75, "iron": 1.39}'::jsonb, ARRAY['chinese', 'asian', 'antipasti', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'dairy free', 'spoonacular', 'vegetarian', 'vegan'], '[{"quantity": 1.0, "unit": "cup", "item": "cabbage", "notes": "cup Cabbage. finely shredded", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "carrots", "notes": "cup Carrots, finely shredded", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "chili oil", "notes": "1 teaspoon Chili oil (or ½ tsp. red Pepper)", "category": "produce"}, {"quantity": 4.0, "unit": "tablespoons", "item": "cilantro", "notes": "4 tablespoons Fresh cilantro, chopped", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "", "item": "gloves garlic", "notes": "3 Gloves garlic, minced", "category": "produce"}, {"quantity": 3.0, "unit": "", "item": "green onions", "notes": "3 Green onions, minced", "category": "produce"}, {"quantity": 10.0, "unit": "servings", "item": "sauce", "notes": "Sauce", "category": "condiments"}, {"quantity": 1.0, "unit": "teaspoon", "item": "bell pepper", "notes": "teaspoon Crushed red pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "seasoned rice vinegar", "notes": "cup Seasoned rice vinegar", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "tablespoons", "item": "sesame oil", "notes": "2 tablespoons Sesame oil", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "cup", "item": "soy sauce", "notes": "cup Soy sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "tablespoon", "item": "soy sauce", "notes": "1 tablespoon Soy sauce", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "cup", "item": "water", "notes": "cup boiling water", "category": "beverages"}, {"quantity": 24.0, "unit": "", "item": "wonton wrappers", "notes": "24 Wonton wrappers", "category": "ethnic foods"}, {"quantity": 10.0, "unit": "servings", "item": "wontons", "notes": "Wontons", "category": "?"}, {"quantity": 10.0, "unit": "servings", "item": "wontons", "notes": "Wontons", "category": "?"}]'::jsonb, '["Combine all ingredients.", "Place a small spoonful in the center of wonton. Fold corners to make a triangle, then fold in corners like an envelope. Coat bottom of nonstick frying pan with vegetable oil. Cook over medium high heat until bottoms are golden and crusty.", "Pour in 1/8 c. water, cover pan and steam for about 2 minutes.", "Serve immediately with sauce.Makes approximately 24."]'::jsonb, 'https://www.foodista.com/recipe/HC76P8L5/vegetable-wontons', 'https://img.spoonacular.com/recipes/664624-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('coconut-chow-mein-butterscotch-cookies', 'Coconut Chow Mein Butterscotch Cookies', 24, 0, 0, '{"calories": 208, "protein": 2.86, "carbs": 27.17, "fat": 10.13, "saturated_fat": 7.44, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 341.07, "potassium": null, "fiber": 1.58, "sugar": 16.42, "vitamin_a": null, "vitamin_c": 0, "calcium": 16.82, "iron": 0.59}'::jsonb, ARRAY['chinese', 'asian', 'dessert', 'spoonacular', 'pasta', 'baking', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "butter", "notes": "1/2 cup unsalted butter, softened", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "cup", "item": "brown sugar", "notes": "1/2 cup light brown sugar, firmly packed", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "granulated sugar", "notes": "1/4 cup granulated sugar", "category": "baking"}, {"quantity": 1.0, "unit": "large", "item": "egg", "notes": "1 large egg", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "vanilla extract", "notes": "1 teaspoon vanilla extract", "category": "baking"}, {"quantity": 1.5, "unit": "cups", "item": "flour", "notes": "1 1/2 cups white whole wheat flour (or all-purpose flour)", "category": "baking"}, {"quantity": 0.75, "unit": "teaspoon", "item": "baking soda", "notes": "3/4 teaspoon baking soda", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.75, "unit": "cup", "item": "coconut flakes", "notes": "3/4 cup unsweetened coconut flakes", "category": "baking"}, {"quantity": 0.75, "unit": "cup", "item": "chow mein noodles", "notes": "3/4 cup chow mein noodles", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "cup", "item": "butterscotch morsels", "notes": "1 cup butterscotch morsels", "category": "condiments"}, {"quantity": 24.0, "unit": "servings", "item": "flaky sea salt", "notes": "flaky sea salt (I use Maldon, but any coarse salt will work.)", "category": "spices and seasonings"}]'::jsonb, '["Preheat oven to 350F.", "Beat butter and sugars until creamy.", "Add egg and vanilla extract.", "In a separate bowl combine the flour, baking soda, salt, and coconut.", "Add the dry ingredients to the wet. Stir in noodles and butterscotch chips.", "Roll dough into balls about the size of golf balls (approx. 1 1/2 tablespoons of dough) and place two inches apart on ungreased baking sheets. Flatten the tops slightly with a glass.", "Sprinkle lightly with sea salt.", "Bake for 12-15 minutes or until lightly browned but still soft. (I prefer mine slightly under cooked.)", "Cool slightly on baking sheets.", "Remove to wire racks to cool completely."]'::jsonb, 'https://www.foodista.com/recipe/5MRHLT4K/coconut-chow-mein-butterscotch-cookies', 'https://img.spoonacular.com/recipes/639741-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('salmon-fried-rice', 'salmon fried rice', 4, 0, 0, '{"calories": 444, "protein": 26.06, "carbs": 56.94, "fat": 11.68, "saturated_fat": 2.36, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 838.18, "potassium": null, "fiber": 4.01, "sugar": 5.82, "vitamin_a": null, "vitamin_c": 49.97, "calcium": 70.32, "iron": 2.61}'::jsonb, ARRAY['chinese', 'asian', 'side dish', 'lunch', 'main course', 'main dish', 'dinner', 'gluten free', 'dairy free', 'pescatarian', 'spoonacular', 'dessert'], '[{"quantity": 1.0, "unit": "teaspoon", "item": "brown sugar", "notes": "1 teaspoon brown sugar", "category": "baking"}, {"quantity": 4.0, "unit": "servings", "item": "cilantro", "notes": "Cilantro (or parsley) for garnish", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "", "item": "eggs", "notes": "3 eggs, well beaten", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves garlic, minced", "category": "produce"}, {"quantity": 1.0, "unit": "inch", "item": "ginger", "notes": "1-inch piece of ginger, grated", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "green onions", "notes": "2 green onions, thinly sliced, including the greens", "category": "produce"}, {"quantity": 1.0, "unit": "Tbsp", "item": "olive oil", "notes": "1 Tbsp olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "cup", "item": "peas", "notes": "1 cup frozen peas, thawed", "category": "produce"}, {"quantity": 0.6666667, "unit": "cup", "item": "bell pepper", "notes": "2/3 cup diced red bell pepper", "category": "produce"}, {"quantity": 0.6666667, "unit": "cup", "item": "onion", "notes": "2/3 cup diced red onion", "category": "produce"}, {"quantity": 4.0, "unit": "cups", "item": "day old rice", "notes": "4 cups day old cooked white rice (from about 2 cups of raw rice)", "category": "pasta and rice"}, {"quantity": 2.0, "unit": "cups", "item": "salmon in chunks", "notes": "2 cups cooked salmon in large chunks", "category": "seafood"}, {"quantity": 3.0, "unit": "Tbsp", "item": "soy sauce", "notes": "3 Tbsp soy sauce", "category": "ethnic foods"}]'::jsonb, '["Dissolve the brown sugar in the soy sauce in a small bowl. Set aside.2", "Heat the olive oil in a large sauté pan or wok on medium high heat.", "Add the diced red onion and bell pepper and sauté until lightly browned, about 5 minutes. Lower the heat to medium and stir in the garlic and grated ginger. Cook for a minute more. 3", "Add the beaten eggs and stir until just cooked.", "Add the cooked rice, increase the heat to medium high and cook for a couple minutes more, stirring often.", "Add the peas, salmon, and green onions. (Be gentle with the salmon so you don''t break it up too much.) Stir in the soy sauce mixture and remove from heat.", "Garnish with cilantro to serve, serve immediately."]'::jsonb, 'https://spoonacular.com/-1436561050590', 'https://img.spoonacular.com/recipes/667701-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ancient-grains-bread', 'Ancient Grains Bread', 14, 0, 0, '{"calories": 284, "protein": 12.73, "carbs": 53.89, "fat": 2.99, "saturated_fat": 0.42, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 132.72, "potassium": null, "fiber": 7.09, "sugar": 9.91, "vitamin_a": null, "vitamin_c": 0, "calcium": 144.52, "iron": 3.45}'::jsonb, ARRAY['bread', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "package", "item": "yeast", "notes": "1 package instant yeast", "category": "baking"}, {"quantity": 2.25, "unit": "cups", "item": "flour", "notes": "2 1/4 cups flour", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "flour", "notes": "1 cup whole wheat flour", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "rye flakes", "notes": "cup rye flakes", "category": "baking"}, {"quantity": 3.0, "unit": "tablespoons", "item": "ground flaxseed", "notes": "3 tablespoons ground flaxseed", "category": "health foods"}, {"quantity": 3.0, "unit": "tablespoons", "item": "amaranth grain", "notes": "3 tablespoons amaranth grain", "category": "pasta and rice"}, {"quantity": 1.0, "unit": "cup", "item": "quinoa", "notes": "cup quinoa", "category": "pasta and rice"}, {"quantity": 0.25, "unit": "cup", "item": "soy flour", "notes": "1/4 cup soy flour", "category": "gluten free"}, {"quantity": 1.5, "unit": "tablespoons", "item": "vital wheat gluten", "notes": "1 1/2 tablespoons vital wheat gluten", "category": "health foods"}, {"quantity": 1.0, "unit": "cup", "item": "skim milk powder", "notes": "cup skim milk powder", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cups", "item": "warm water", "notes": "cups warm water", "category": "beverages"}, {"quantity": 0.25, "unit": "cup", "item": "honey", "notes": "1/4 cup honey", "category": "nut butters, jams, and honey"}]'::jsonb, '["In a large bowl or stand mixer, whisk together yeast, flours, rye flakes, flaxseed, amaranth, quinoa, soy flour, wheat gluten, skim milk powder and salt.", "Stir in warm water and honey, mixing thoroughly to form a cohesive, fairly firm (but workable) dough.", "Turn out onto a floured board or knead with the dough hook for 12 minutes, until very elastic and smooth.", "Place into a bowl, cover and allow to rest 30 minutes.", "Roll rested dough into a log shape and tuck into a greased loaf pan.", "Cover with a clean towel and allow to rise 50-60 minutes.", "Preheat oven to 350F.", "Slash the top of the loaf 2-3 times with a sharp knife or lame.", "Bake 40 minutes. Turn out of pan immediately and cool on a rack before slicing"]'::jsonb, 'https://www.foodista.com/recipe/Y3ZZC68V/ancient-grains-bread', 'https://img.spoonacular.com/recipes/632347-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spinach-coriander-chive-bread', 'Spinach Coriander Chive Bread', 4, 0, 0, '{"calories": 452, "protein": 18.3, "carbs": 62.19, "fat": 15.4, "saturated_fat": 5.58, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 655.02, "potassium": null, "fiber": 4.78, "sugar": 15.62, "vitamin_a": null, "vitamin_c": 9.7, "calcium": 411.2, "iron": 3.59}'::jsonb, ARRAY['bread', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 100.0, "unit": "grams", "item": "all purpose flour", "notes": "100 grams - all purpose flour", "category": "baking"}, {"quantity": 100.0, "unit": "grams", "item": "flour", "notes": "100 grams - whole wheat flour", "category": "baking"}, {"quantity": 10.0, "unit": "tablespoons", "item": "milk", "notes": "10 tablespoons - low fat milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.5, "unit": "tablespoons", "item": "sunflower oil", "notes": "1 1/2 tablespoons - sunflower oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "teaspoon", "item": "yeast", "notes": "1 teaspoon - dried yeast", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "sugar", "notes": "1/2 teaspoon - white sugar", "category": "baking"}, {"quantity": 0.75, "unit": "teaspoon", "item": "salt", "notes": "3/4 teaspoon - salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "chives", "notes": "2 tablespoons - chives, finely chopped", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "coriander leaves", "notes": "2 tablespoons - coriander leaves, finely chopped", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "tablespoons", "item": "spinach", "notes": "3 tablespoons - spinach, shredded", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "milk to brush the bread", "notes": "some milk to brush the bread", "category": "milk, eggs, other dairy"}, {"quantity": 3.0, "unit": "", "item": "seeds to sprinkle on the bread", "notes": "3 assorted seeds to sprinkle on the bread (pumpkin, sesa", "category": "bakery/bread"}]'::jsonb, '["Preheat the oven to 200 degree C and grease a baking tray.", "Place the milk, sugar and yeast in a bowl.", "Mix well and leave in a warm place until frothy, about 10 - 15 minutes", "Sift the flours, chives, coriander leaves, spinach and salt into a bowl. Rub in the oil until the mixture resembles fine breadcrumbs.", "Add the yeast mixture to the flour and mix to form a soft but manageable dough( add 1 tbsp of flour at a time, if the dough is too sticky, but avoid adding too much of flour).", "Place the dough in an oiled bowl, cover with cling film and leave to rise in a warm place until double in size (about an hr).", "Turn out onto a floured surface, knead again lightly and shape the dough into a loaf.", "Allow the loaves to rest on a greased baking tray, covered loosely with a plastic wrap and leave to rise in a warm place until it doubles in size.", "Remove the plastic wrap.", "Brush the top of the loaves with some milk and sprinkle the seeds.", "Bake in the preheated oven for 15-20 minutes.", "Allow to cool on a wire rack completely."]'::jsonb, 'https://www.foodista.com/recipe/7VCTX2NZ/spinach-coriander-chive-bread', 'https://img.spoonacular.com/recipes/661292-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pan-roasted-raspberries-bread', 'Pan Roasted Raspberries Bread', 9, 0, 0, '{"calories": 229, "protein": 5.74, "carbs": 43.64, "fat": 4.91, "saturated_fat": 0.48, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 268.27, "potassium": null, "fiber": 5.71, "sugar": 12.38, "vitamin_a": null, "vitamin_c": 5.24, "calcium": 143.54, "iron": 1.74}'::jsonb, ARRAY['bread', 'dairy free', 'spoonacular', 'dessert', 'breakfast', 'baking', 'vegetarian'], '[{"quantity": 1.5, "unit": "cups", "item": "raspberries", "notes": "1 ½ cups raspberries", "category": "produce"}, {"quantity": 0.25, "unit": "cups", "item": "maple syrup", "notes": "¼ cups maple syrup", "category": "cereal"}, {"quantity": 2.0, "unit": "tbsp", "item": "flax oil", "notes": "2 tbsp flax oil", "category": "health foods"}, {"quantity": 0.25, "unit": "cups", "item": "tbsp brown sugar", "notes": "¼ cups + 1 tbsp brown sugar", "category": "baking"}, {"quantity": 1.0, "unit": "tsp", "item": "vinegar", "notes": "1 tsp vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.5, "unit": "cups", "item": "vanilla almond milk", "notes": "1 ½ cups vanilla unsweetened almond milk", "category": "milk, eggs, other dairy"}, {"quantity": 3.0, "unit": "cups", "item": "flour", "notes": "3 cups whole wheat flour", "category": "baking"}, {"quantity": 2.0, "unit": "tsp", "item": "baking powder", "notes": "2 tsp baking powder", "category": "baking"}, {"quantity": 0.5, "unit": "tsp", "item": "baking soda", "notes": "½ tsp baking soda", "category": "baking"}, {"quantity": 0.125, "unit": "tsp", "item": "salt", "notes": "1/8 tsp salt", "category": "spices and seasonings"}]'::jsonb, '["Warm a nonstick pan in a low flame over the stove.", "Add raspberries and maple syrup. Lightly mix them so that the raspberries are properly coated with the maple syrup. Cover and cook in the medium flame for 5 minutes.", "When it is slightly liquid turn off the flame and remove the pan from the hot stove.", "Mash the raspberries lightly with the spatula and let them cool to room temperature.", "Preheat the oven at 425 degree Fahrenheit and prepare the loaf pan by greasing and dusting it.", "In the meantime combine all the liquid ingredients in a bowl and mix properly.", "In another bowl combine the dry ingredients and mix with a spoon.", "When the raspberries are cooled add them to the liquid ingredients bowl and mix well so that all the liquids are properly blended.", "Pour the liquids into the dry ingredients and mix well with a spoon. Make sure you dont overdo it. Just mix gently with a spoon so that all the ingredients are properly combined. The batter will change into purplish in color.", "Spoon the batter into the loaf pan and put it in the  oven.", "Bake for 40 minutes or until the knife comes out clean.", "Take the bread out of the oven and let it cool. Once cooled the bread will leave the loaf pan.", "Cut into slightly thick slices and serve at room temperature."]'::jsonb, 'https://www.foodista.com/recipe/3L6PQKWX/pan-roasted-raspberries-bread', 'https://img.spoonacular.com/recipes/654425-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('fenugreek-roti', 'Fenugreek Roti', 10, 0, 0, '{"calories": 79, "protein": 4.19, "carbs": 12.53, "fat": 1.55, "saturated_fat": 0.33, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 271.5, "potassium": null, "fiber": 2.28, "sugar": 1.54, "vitamin_a": null, "vitamin_c": 0, "calcium": 15.22, "iron": 1.17}'::jsonb, ARRAY['indian', 'asian', 'bread', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 0.5, "unit": "teaspoon", "item": "ajwain seeds", "notes": "1/2 teaspoon ajwain seeds", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "pinch", "item": "asafetida", "notes": "pinch of asafetida", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "baking soda", "notes": "1/4 teaspoon baking soda", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "cayenne", "notes": "1/2 teaspoon cayenne", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "chickpea flour", "notes": "1 cup chickpea flour (besan)", "category": "health foods"}, {"quantity": 0.5, "unit": "teaspoon", "item": "chili powder", "notes": "1/2 teaspoon chili powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "fenugreek leaves", "notes": "1/2 cup dried fenugreek leaves", "category": "spices and seasonings"}, {"quantity": 10.0, "unit": "servings", "item": "ghee", "notes": "ghee or oil for frying", "category": "ethnic foods"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground coriander", "notes": "1/2 teaspoon ground coriander", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "ground cumin", "notes": "1/2 teaspoon ground cumin", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "yogurt", "notes": "2 tablespoons plain yogurt", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sea salt", "notes": "1 teaspoon sea salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "flour", "notes": "1/2 cup whole wheat flour", "category": "baking"}]'::jsonb, '["Soak the dried fenugreek leaves in warm water for 5 to 10 minutes.", "Drain, making sure to squeeze out excess liquid.Sift the flours and baking soda in a small strainer into a medium bowl. Stir in the salt, chili powder, cayenne, cumin, coriander, ajwain seeds, asafetida, yogurt and fenugreek leaves.", "Mix in about 1/4 cup of water to make a semi-hard batter. Cover and let stand at room temperature for 1 hour. Dusting your hands with flour, divide the dough into 10 to 12 small balls.", "Roll out each ball into a roughly 3-inch circle.", "Brush a non-stick pan with a bit of ghee or oil and heat over medium heat. When hot, add a rolled out portion to the pan and cook for 4 minutes or until the bottom is browned.", "Sprinkle with a bit of oil, flip and fry for another 2 to 3 minutes or until both sides are browned.", "Transfer to a plate, keep heated in a 150 oven, and repeat for the rest of the pancakes."]'::jsonb, 'https://www.foodandspice.com/2012/07/fenugreek-roti.html', 'https://img.spoonacular.com/recipes/716202-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('rosemary-walnut-bread', 'Rosemary Walnut Bread', 16, 0, 0, '{"calories": 308, "protein": 8.87, "carbs": 36.21, "fat": 14.87, "saturated_fat": 3.23, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 238.33, "potassium": null, "fiber": 2.51, "sugar": 4.07, "vitamin_a": null, "vitamin_c": 1.4, "calcium": 66.18, "iron": 2.54}'::jsonb, ARRAY['bread', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 4.0, "unit": "ounces", "item": "cream cheese", "notes": "4 ounces cream cheese", "category": "cheese"}, {"quantity": 2.0, "unit": "packages", "item": "yeast", "notes": "2 packages dry yeast", "category": "baking"}, {"quantity": 3.0, "unit": "", "item": "eggs", "notes": "3 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 5.0, "unit": "cups", "item": "flour", "notes": "5 cups flour", "category": "baking"}, {"quantity": 2.0, "unit": "tablespoons", "item": "honey", "notes": "2 tablespoons honey", "category": "nut butters, jams, and honey"}, {"quantity": 2.0, "unit": "tablespoons", "item": "lemon zest", "notes": "2 tablespoons lemon zest", "category": "produce"}, {"quantity": 1.5, "unit": "cups", "item": "milk", "notes": "1 1/2 cups milk (100 to 110 degrees)", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "olive oil", "notes": "1 tablespoon olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 3.0, "unit": "tablespoons", "item": "rosemary", "notes": "3 tablespoons chopped rosemary", "category": "spices and seasonings"}, {"quantity": 16.0, "unit": "servings", "item": "salt", "notes": "Salt to taste", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cups", "item": "walnuts", "notes": "2 cups walnuts", "category": "baking"}]'::jsonb, '["Combine first four ingredients, add yeast, and let stand for 5 minutes.Stir in two cups flour, cover with plastic, and place in a warm spot (85 degrees) for 15 minutes.", "Add rest of flour, nuts, lemon, rosemary, and 2 eggs.", "Mix in bowl until it sticks together, then turn onto floured surface and knead for 10 minutes.Rub top with olive oil and place in oiled bowl.Cover with damp cloth, and let rise for 1 hour.Return dough to floured surface and form into two leaf-shaped loaves.Make three diagonal slashes,  inch deep.", "Brush top with egg, and let rise for 30 minutes.", "Bake in 375 degree oven for 40 minutes.", "Let stand twenty minutes before slicingor as long as you can wait."]'::jsonb, 'https://www.foodista.com/recipe/74NR222W/rosemary-walnut-bread', 'https://img.spoonacular.com/recipes/658813-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('cheddar-chile-beer-bread', 'Cheddar Chile Beer Bread', 12, 0, 0, '{"calories": 203, "protein": 8.35, "carbs": 25.16, "fat": 7.26, "saturated_fat": 3.74, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 510.81, "potassium": null, "fiber": 2.35, "sugar": 0.19, "vitamin_a": null, "vitamin_c": 3.29, "calcium": 211.07, "iron": 1.64}'::jsonb, ARRAY['bread', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.5, "unit": "cups", "item": "flour", "notes": "1 1/2 cups Whole Wheat Flour (run a fork through it before measuring)", "category": "baking"}, {"quantity": 1.5, "unit": "cups", "item": "flour", "notes": "1 1/2 cups All-purpose Flour (run a fork through it before measuring)", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "teaspoon baking powder", "notes": "1 tablespoon + 1 teaspoon Baking Powder", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon Salt", "category": "spices and seasonings"}, {"quantity": 1.5, "unit": "teaspoons", "item": "mustard", "notes": "1 1/2 teaspoons Dry Mustard", "category": "spices and seasonings"}, {"quantity": 12.0, "unit": "ounces", "item": "beer", "notes": "12 ounces Beer (any kind will work)", "category": "alcoholic beverages"}, {"quantity": 2.0, "unit": "cups", "item": "extra sharp cheddar cheese", "notes": "2 cups shredded Extra Sharp Cheddar Cheese (I used White)", "category": "cheese"}, {"quantity": 4.0, "unit": "ounces", "item": "chiles", "notes": "4 ounces cans Green Chiles, chopped, with juices", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "teaspoon", "item": "sesame seeds", "notes": "1 teaspoon Sesame Seeds", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "poppy seeds", "notes": "1 teaspoon Poppy Seeds", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "caraway seeds", "notes": "1 teaspoon Caraway Seeds", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "sea salt", "notes": "1/4 teaspoon Sea Salt", "category": "spices and seasonings"}]'::jsonb, '["Preheat oven to 425 degrees. Grease a loaf pan.", "In a large bowl whisk together the dry ingredients.", "Add the green chiles, cheddar, and beer. Stir until combined. Batter will be very thick.", "Scrape it out into the loaf and spread it out evenly.", "Sprinkle the seeds and salt over the top. Gently press them into the batter using your fingers.", "Turn oven down to 400 degrees.", "Bake for 45-50 minutes until a toothpick comes out clean from center.", "Cool on wire rack 15 minutes, turn out from pan and continue cooling while you sample!"]'::jsonb, 'https://www.foodista.com/recipe/583RP66G/cheddar-chile-beer-bread', 'https://img.spoonacular.com/recipes/637506-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('whole-wheat-focaccia-bread-with-caramelized-onion', 'Whole Wheat Focaccia Bread with Caramelized Onion', 10, 0, 0, '{"calories": 274, "protein": 8.63, "carbs": 40.46, "fat": 10.48, "saturated_fat": 4.01, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 65.99, "potassium": null, "fiber": 6.24, "sugar": 2.64, "vitamin_a": null, "vitamin_c": 2.59, "calcium": 59.11, "iron": 2.26}'::jsonb, ARRAY['mediterranean', 'italian', 'european', 'bread', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "teaspoon", "item": "rosemary", "notes": "1 teaspoon dried rosemary", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "package", "item": "yeast", "notes": "1 package dry yeast", "category": "baking"}, {"quantity": 0.75, "unit": "cup", "item": "basil leaves", "notes": "¾ cup fresh basil leaves (loosely packed), chopped", "category": "produce"}, {"quantity": 2.5, "unit": "tablespoons", "item": "grapeseed oil", "notes": "2.5 tablespoons grapeseed oil, separated", "category": "oil, vinegar, salad dressing"}, {"quantity": 10.0, "unit": "servings", "item": "ground pepper", "notes": "Ground black pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "honey", "notes": "1 teaspoon honey", "category": "nut butters, jams, and honey"}, {"quantity": 0.25, "unit": "", "item": "kosher salt", "notes": "¼ - ½ teaspoon kosher salt", "category": "spices and seasonings"}, {"quantity": 0.33333334, "unit": "cup", "item": "parmesan cheese", "notes": "1/3 cup grated parmesan cheese", "category": "cheese"}, {"quantity": 0.33333334, "unit": "cup", "item": "sun-dried tomatoes", "notes": "1/3 cup julienned sun-dried tomatoes, patted dry", "category": "canned and jarred"}, {"quantity": 0.25, "unit": "cup", "item": "butter", "notes": "1/4 cup unsalted butter, melted", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "warm water", "notes": "1 cup warm water", "category": "beverages"}, {"quantity": 500.0, "unit": "grams", "item": "flour", "notes": "500 grams Whole Wheat flour (finely ground)", "category": "baking"}, {"quantity": 1.0, "unit": "medium", "item": "onion", "notes": "1 medium yellow onion, sliced", "category": "produce"}]'::jsonb, '["In a bowl or mixer, stir together the water, yeast and honey. The water should be between 100 and 110 degrees. Allow the mixture to sit about 10 minutes until the yeast looks puffy and smells pungent.  In a separate bowl, combine the whole wheat flour, salt and dried rosemary. Stir together to combine.", "Add the flour mixture to the mixer along with the grapeseed oil.If youre doing this by hand, mix the ingredients together well until you can form a ball. Turn the ball of dough out onto a floured surface, press the chopped basil leaves into the dough and kneed the dough until smooth, about 8 to 10 minutes.  If youre using a Kitchen Aid, simply use the dough hook attachment, turn the mixer on a medium setting (I use speed", "and allow the hook to do the work for 10 minutes.", "Place the ball of dough in a bowl and allow it to sit covered (by plastic wrap or a kitchen towel) for 1 hour in a warm place; it should be twice the size you started out with after about an hour.To caramelize the onions, add half a tablespoon of grapeseed oil and a tablespoon of butter to a skillet and heat over medium.", "Add the onion and saut, stirring frequently until translucent. Once onion is translucent, reduce heat to medium low and allow onions to brown, stirring every few minutes. Allowing the onions to wilt, turn completely brown and caramelize will take about 30 to 40 minutes.Preheat the oven to 450 degrees F.Prepare a lightly oiled baking sheet  (a 9 x 13 works great, but no worries if yours is bigger). Turn the dough out onto the sheet and press it into the sheet with your palms until the dough meets the edges or until dough is about  thick. Poke holes into the surface of the dough with your finger then drizzle 2 tablespoons of grapeseed oil over it. Use your hands to evenly coat the dough with the oil. Allow the dough to sit another 10 to 20 minutes until it appears puffy and swollen again.", "Spread the parmesan cheese, salt and black pepper over the dough then spread the sun-dried tomatoes and caramelized onions on top, pressing them into the dough slightly.", "Bake in the oven until golden brown around the edges, about 15 minutes.  Turn temperature down to 350 and bake another 5 minutes (until the center is cooked all the way through). Allow the bread to cool about 10 minutes then serve with dinner!"]'::jsonb, 'https://www.foodista.com/recipe/X7XVYFSY/whole-wheat-focaccia-bread-with-caramelized-onion', 'https://img.spoonacular.com/recipes/665285-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('garlic-butter-naan', 'Garlic-Butter Naan', 4, 0, 0, '{"calories": 461, "protein": 9.92, "carbs": 56.13, "fat": 21.67, "saturated_fat": 5.22, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 492.94, "potassium": null, "fiber": 2.02, "sugar": 2.08, "vitamin_a": null, "vitamin_c": 0, "calcium": 38.88, "iron": 3.42}'::jsonb, ARRAY['indian', 'asian', 'fingerfood', 'antipasti', 'bread', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 0.5, "unit": "c", "item": "ice water", "notes": "1/2 c. ice water", "category": "beverages"}, {"quantity": 0.33333334, "unit": "c", "item": "nonfat greek yogurt", "notes": "1/3 c. nonfat greek yogurt", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "c", "item": "canola oil", "notes": "1/4 c. canola oil, plus 1 t. for cooking the naan", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "large", "item": "egg yolk", "notes": "1 large egg yolk", "category": "milk, eggs, other dairy"}, {"quantity": 2.25, "unit": "c", "item": "flour", "notes": "2 1/4 c. flour", "category": "baking"}, {"quantity": 1.25, "unit": "t", "item": "sugar", "notes": "1 1/4 t. sugar", "category": "baking"}, {"quantity": 0.5, "unit": "t", "item": "rapid-rise yeast", "notes": "1/2 t. instant or rapid-rise yeast", "category": "baking"}, {"quantity": 0.75, "unit": "t", "item": "salt", "notes": "3/4 t. salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "T", "item": "butter", "notes": "2 T. butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": "1 clove garlic, minced", "category": "produce"}]'::jsonb, '["In a small bowl, mix together water, yogurt, 1/4 c. oil and egg yolk. In the workbowl of a food processor, pulse together flour, sugar and yeast to combine. With the motor running, slowly add the liquid ingredients to the flour. Process until combined.", "Let mixture rest for 10 minutes.", "Add salt and process another 30-60 seconds. It will form a sticky dough that should clear the sides of the food processor workbowl.", "Scrape dough out onto a floured worksurface and knead just until smooth, about a minute. Form into a ball and place in a lightly oiled bowl (large). Cover tightly with plastic wrap and refrigerate 16-24 hours.", "After the dough has rested, turn out onto a lightly floured work surface and divide dough into 4 pieces and shape each piece into a ball. Cover lightly with plastic wrap and let rest 15-20 minutes.", "Meanwhile melt the butter in a small saucepan, then add the garlic. Set aside.", "Roll the first piece of dough out into a 9 inch round. Using a fork, poke the dough all over, 20-25 times. Lightly mist the top side with water.", "Heat the remaining oil in a large nonstick skillet over medium heat until the oil begins to shimmer. Wipe the oil out of the skillet with paper towels, then add the rolled out dough, sprayed side down and spray the other side lightly. Cover skillet and cook until spotty brown underneath, 2-4 minutes (poke any large bubbles that form). Flip naan, cook, covered, another 2-3 minutes until browned. Flip again, brush with butter, then transfer to a plate and cover with foil. While rolling out and cooking the remaining naan."]'::jsonb, 'https://www.foodista.com/recipe/6BPCGSNT/garlic-butter-naan', 'https://img.spoonacular.com/recipes/644376-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('black-olive-tomato-bread', 'Black Olive & Tomato Bread', 16, 0, 0, '{"calories": 166, "protein": 4.24, "carbs": 25.53, "fat": 5.6, "saturated_fat": 0.84, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 286.47, "potassium": null, "fiber": 2.0, "sugar": 2.97, "vitamin_a": null, "vitamin_c": 2.72, "calcium": 18.54, "iron": 2.0}'::jsonb, ARRAY['bread', 'dairy free', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 3.5, "unit": "cups", "item": "flour", "notes": "3 1/2 cups all-purpose flour", "category": "baking"}, {"quantity": 1.0, "unit": "tsp", "item": "salt", "notes": "1 tsp. salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "envelope", "item": "active yeast", "notes": "1 envelope of active yeast", "category": "baking"}, {"quantity": 1.0, "unit": "tsp", "item": "sugar", "notes": "1 tsp. sugar", "category": "baking"}, {"quantity": 1.0, "unit": "tbsp", "item": "rosemary", "notes": "1 tbsp. fresh rosemary (chopped)", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "just under of water", "notes": "Just under 1 cup of lukewarm water", "category": "beverages"}, {"quantity": 4.0, "unit": "tbsp", "item": "olive oil", "notes": "4 tbsp. olive oil (and extra for brushing)", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "cup", "item": "olives", "notes": "1 cup black olives (sliced)", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "cup", "item": "oil-packed sun-dried tomatoes", "notes": "1 cup oil-packed sun-dried tomatoes (drained and sliced)", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "", "item": "egg yolk", "notes": "1 egg yolk (beaten)", "category": "milk, eggs, other dairy"}]'::jsonb, '["In a large bowl sift flour and salt", "Add in yeast, sugar and rosemary and mix", "In a cup mix the oil and water", "Make a well in the center of the flour mixture and pour in the oil/water mixture", "Stir with a wooden spoon until dough comes together", "Using your hands, knead until it holds together", "Turn dough out onto a floured surface, and knead a few times", "Flatten slightly and layer on sliced olives and sliced tomatoes.", "Roll like a jelly roll, then continue to knead for about 5 minutes until dough feels smooth", "Shape into a ball", "Brush bowl with oil and place dough into bowl", "Cover with plastic or damp dish towel and let rise in a warm place for about 1 1/2 hours (or until dough has doubled in size)Dust cookie sheet with flour", "Turn dough onto floured counter, punch down and cut in 1/2Shape each 1/2 into a round", "Place them on the cookie sheet, and cover with plastic or damp cloth", "Allow to rise for another 45 minutes in a warm place", "While the dough is rising turn oven to 400 FWhen dough is ready, make 3 shallow slashes across the top of each loaf, and brush with beaten egg yolk", "Bake in preheated oven for about 40 minutes until golden brown and the loaves sound hollow when tapped on the bottom", "Remove from pan onto a wire rack to cool.This recipe makes 2 loaves."]'::jsonb, 'https://www.foodista.com/recipe/KL577LZS/black-olive-tomato-bread', 'https://img.spoonacular.com/recipes/1096055-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('armenian-tahini-rolls', 'Armenian tahini rolls', 12, 0, 0, '{"calories": 235, "protein": 6.37, "carbs": 20.5, "fat": 15.96, "saturated_fat": 2.59, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 215.49, "potassium": null, "fiber": 2.09, "sugar": 13.61, "vitamin_a": null, "vitamin_c": 0.91, "calcium": 134.51, "iron": 2.22}'::jsonb, ARRAY['bread', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg beaten", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "flour", "notes": "1 tablespoon flour", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "honey", "notes": "1/2 cup honey", "category": "nut butters, jams, and honey"}, {"quantity": 1.0, "unit": "cup", "item": "milk", "notes": "1 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "olive oil", "notes": "1 teaspoon olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 12.0, "unit": "servings", "item": "sesame seeds", "notes": "sesame seeds", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "sugar", "notes": "1 tablespoon sugar", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "tahini", "notes": "1 cup tahini", "category": "health foods"}, {"quantity": 2.25, "unit": "tsp", "item": "yeast", "notes": "2 1/4 tsp (1 envelope, 7 gr) yeast", "category": "baking"}]'::jsonb, '["Pre heat oven to 325F.", "Combine flour, sugar, yeast, and salt in a bowl. In a small bowl combine egg and oil. Warm up the milk.", "Add the milk to the flour mixture, then add in the egg mixture to make a smooth, elastic and not sticky dough. If sticky add more flour.Cover with a damp cloth and let it rest for 30 minutes. The dough wont rise like other bread doughs, so dont worry.Divide the dough into 12 pieces, cover and let them sit for around 20 minutes.", "Roll one ball of dough out to a very wide thin circle.", "Spread a thin layer of the tahini mixture. Starting at the longest edge, roll up the dough into a rope. Holding one end of the rope, start folding up so it makes a coiled bun. Gently flatten the bun with the rolling pin or with your hand.", "Place on a greased or lined baking sheet. Repeat with the remaining dough.", "Brush the rolls with the beaten egg, then sprinkle a few sesame seeds over top.", "Bake 25-30 minutes or until light brown.Enjoy. Keep them in air tight containers. They taste good by themselves or smear them with butter."]'::jsonb, 'https://www.foodista.com/recipe/MCPFRD83/armenian-tahini-rolls', 'https://img.spoonacular.com/recipes/632723-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lemon-chia-seed-cornmeal-bread', 'Lemon Chia Seed Cornmeal Bread', 8, 0, 0, '{"calories": 284, "protein": 4.43, "carbs": 48.1, "fat": 9.12, "saturated_fat": 1.25, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 187.87, "potassium": null, "fiber": 4.03, "sugar": 20.35, "vitamin_a": null, "vitamin_c": 3.24, "calcium": 94.17, "iron": 2.0}'::jsonb, ARRAY['bread', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "teaspoons", "item": "baking powder", "notes": "2 teaspoons baking powder", "category": "baking"}, {"quantity": 0.25, "unit": "teaspoon", "item": "baking soda", "notes": "1/4 teaspoon baking soda", "category": "baking"}, {"quantity": 0.6666667, "unit": "cup", "item": "brown sugar", "notes": "2/3 cup coconut or brown sugar", "category": "baking"}, {"quantity": 3.0, "unit": "tablespoons", "item": "chia seeds", "notes": "3 tablespoons chia seeds (or poppy seeds)", "category": "health foods"}, {"quantity": 1.0, "unit": "cup", "item": "flour", "notes": "1 cup all-purpose flour", "category": "baking"}, {"quantity": 2.0, "unit": "", "item": "juice of lemon", "notes": "juice and zest from 2 lemons (1/2 tablespoon zest and 1/2 cup juice)", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "olive oil", "notes": "1/4 cup olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.5, "unit": "cup", "item": "pastry flour", "notes": "1/2 cup pastry flour", "category": "baking"}, {"quantity": 3.0, "unit": "pinches", "item": "sea salt", "notes": "3 pinches of sea salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "turmeric", "notes": "1/2 teaspoon turmeric (optional)", "category": "spices and seasonings"}, {"quantity": 0.75, "unit": "cup", "item": "unsweetened apple sauce", "notes": "3/4 cup unsweetened apple sauce", "category": "canned and jarred"}, {"quantity": 0.5, "unit": "cup", "item": "yellow cornmeal", "notes": "1/2 cup yellow cornmeal", "category": "ethnic foods"}]'::jsonb, '["Line a standard 9  5 inch loaf pan with parchment paper or grease the pan well. Preheat an oven to 350.In a large bowl, combine the flours, cornmeal, chia seeds or poppy seeds, baking powder and soda, turmeric if using, and sea salt.In a medium bowl, whisk together the lemon zest, lemon juice, sugar, apple sauce and olive oil.Make a well in the center of the flour mixture and pour in the moist ingredients. Stir until just combined.", "Transfer to the prepared pan, spreading evenly.", "Bake for 30 to 40 minutes or until lightly golden and a cake tester inserted into the middle of the bread comes out clean.", "Let cool in the pan before removing. Slice and serve."]'::jsonb, 'https://www.foodandspice.com/2016/11/lemon-chia-seed-cornmeal-bread.html', 'https://img.spoonacular.com/recipes/841432-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('almond-buns', 'Almond Buns', 12, 0, 0, '{"calories": 601, "protein": 13.81, "carbs": 57.64, "fat": 37.16, "saturated_fat": 11.97, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 334.33, "potassium": null, "fiber": 4.91, "sugar": 20.56, "vitamin_a": null, "vitamin_c": 0, "calcium": 131.35, "iron": 3.27}'::jsonb, ARRAY['southern', 'bread', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "", "item": "yeast cake compressed", "notes": "2 yeast cake compressed", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "sugar", "notes": "1 tablespoon sugar", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "flour", "notes": "1 cup flour", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "butter", "notes": "cup melted butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "cups", "item": "flour", "notes": "3 cups flour", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "water", "notes": "cup water", "category": "beverages"}, {"quantity": 1.0, "unit": "cup", "item": "milk scalded", "notes": "1 cup milk scalded", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "", "item": "egg yolks", "notes": "2 egg yolks", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "sugar", "notes": "cup sugar", "category": "baking"}, {"quantity": 1.0, "unit": "pound", "item": "blanched almonds ¼ cup", "notes": "pound blanched almonds ¼ cup finely chopped for the topping", "category": "savory snacks"}, {"quantity": 1.0, "unit": "tablespoon", "item": "milk to brush the top", "notes": "1 tablespoon milk to brush the top", "category": "milk, eggs, other dairy"}]'::jsonb, '["Dissolve yeast in water and sugar. Scald milk. When milk is tepid, add yeast mixture.", "Add 1 c flour and mix well. Set in a warm place to rise.", "Add remaining ingredients (except topping ingredients) and mix well. The dough should be stiff. Allow to rise until doubled and light. Shape into small rounds and place in a well greased pan 1 1/2 inches apart.", "Brush tops with egg yolk and milk mixture, then sprinkle with chopped almonds.", "Let rise until doubled in size.", "Bake at 350'' for 20-30 minutes."]'::jsonb, 'https://www.foodista.com/recipe/7XPD77R4/almond-buns', 'https://img.spoonacular.com/recipes/632099-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('ridiculously-easy-naan', 'Ridiculously Easy Naan', 8, 0, 0, '{"calories": 124, "protein": 4.71, "carbs": 22.8, "fat": 2.48, "saturated_fat": 0.63, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 421.38, "potassium": null, "fiber": 3.21, "sugar": 1.22, "vitamin_a": null, "vitamin_c": 0, "calcium": 67.9, "iron": 1.14}'::jsonb, ARRAY['indian', 'asian', 'fingerfood', 'antipasti', 'bread', 'starter', 'snack', 'appetizer', 'antipasto', 'hor d''oeuvre', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "teaspoon", "item": "baking powder", "notes": "1 teaspoon baking powder", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "baking soda", "notes": "1/2 teaspoon baking soda", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "canola oil", "notes": "2 teaspoons canola oil (if use a strong flavored oil it will change the taste of the bread)", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.75, "unit": "cup", "item": "milk", "notes": "3/4 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cups", "item": "flour", "notes": "2 cups cups flour (you can use 1 whole wheat and 1 cup white…I find that bread flour works best)", "category": "baking"}]'::jsonb, '["Put the dry ingredients in a mixing bowl and stir.", "Mix the wet ingredients, warm the liquid either in the microwave (about 40 seconds) or on the stovetop you want the temperature to be that of a hot bath.Slowly incorporate the liquid into the dry ingredients while stirring.When you can stir no more, start to knead the dough with your hands.  I just knead it right in the bowl.  Stop kneading as soon as the dough comes together and is soft and not too stickydo not over knead!  Try to knead it no more than 10 times if that helps.Form a ball, place it in the center of the mixing bowl, cover with plastic wrap and let the dough rest in a warm spot for 20 minutes.After 20 minutes the dough wont really look any different, dont worry about it.  Divide the dough into 8 sections and roll into balls.Re-cover the balls with the plastic wrap and let them rest for 10 minutes.On a floured surface roll the balls out, either in a round or oval shape.  Meanwhile heat an iron skillet (or just plain skillet if thats all you have) on medium-high heat.Whack the rolled out dough onto the hot skillet and cover with a lid.  In less than the time you can roll out another ball the first side will be done, check the bread, when its nice and bubbly on the raw side flip it over and cook for a few more seconds.Thats it, get it out of the pan and put it on a plate or in your mouth or whatever! yum!"]'::jsonb, 'https://www.foodista.com/recipe/FJH4RZ8W/ridiculously-easy-naan', 'https://img.spoonacular.com/recipes/658347-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('banana-nut-chocolate-bread', 'Banana Nut Chocolate Bread', 6, 0, 0, '{"calories": 777, "protein": 8.29, "carbs": 79.25, "fat": 49.79, "saturated_fat": 10.84, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 805.7, "potassium": null, "fiber": 3.85, "sugar": 39.93, "vitamin_a": null, "vitamin_c": 3.54, "calcium": 168.32, "iron": 2.82}'::jsonb, ARRAY['southern', 'bread', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "butter", "notes": "cup butter or margarine, softened", "category": "milk, eggs, other dairy"}, {"quantity": 0.75, "unit": "cup", "item": "sugar", "notes": "3/4 cup sugar", "category": "baking"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "banana", "notes": "1 cup mashed banana", "category": "produce"}, {"quantity": 2.0, "unit": "cups", "item": "flour", "notes": "2 cups all-purpose flour", "category": "baking"}, {"quantity": 2.5, "unit": "teaspoons", "item": "baking powder", "notes": "2 1/2 teaspoons baking powder", "category": "baking"}, {"quantity": 0.25, "unit": "teaspoon", "item": "baking soda", "notes": "1/4 teaspoon baking soda", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "pecans", "notes": "1 cup chopped pecans (or walnuts)", "category": "savory snacks"}, {"quantity": 0.5, "unit": "cup", "item": "chocolate chips", "notes": "1/2 cup chocolate chips (or more if desired)", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "buttermilk", "notes": "1/2 cup buttermilk", "category": "milk, eggs, other dairy"}]'::jsonb, '["Preheat oven to 350 F", "Cream butter and sugar.", "Mix in egg and banana.", "Stirr together flour baking powder, baking soda, salt, nuts and chocolate chips.", "Add to this mixture to cream mixture alternately with buttermilk.", "Stir until just blended.", "Pour chocolate batter into a greased and floured pan. 9x5x3 inches.", "Bake for 65 minutes, or until bread tests done.", "Cool in plan for about 5 minutes, then turn out on a wire rack.", "Cool completely.", "Makes one loaf"]'::jsonb, 'https://www.foodista.com/recipe/HBS3QM4Q/banana-nut-chocolate-bread', 'https://img.spoonacular.com/recipes/634137-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pumpkin-corn-bread', 'Pumpkin Corn Bread', 6, 0, 0, '{"calories": 339, "protein": 6.43, "carbs": 51.99, "fat": 12.22, "saturated_fat": 1.45, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 312.26, "potassium": null, "fiber": 3.62, "sugar": 19.55, "vitamin_a": null, "vitamin_c": 1.72, "calcium": 83.47, "iron": 2.6}'::jsonb, ARRAY['southern', 'bread', 'dairy free', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "Tsp", "item": "baking powder", "notes": "1 Tsp. - Baking Powder", "category": "baking"}, {"quantity": 0.5, "unit": "Tsp", "item": "baking soda", "notes": "1/2 Tsp. - Baking Soda", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "brown sugar", "notes": "1/2 cup Brown Sugar", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "pumpkin puree", "notes": "1 cup Canned Pumpkin Puree", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "canola oil", "notes": "1/4 cup Canola Oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 - Eggs Beaten", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "flour", "notes": "1 cup Flour", "category": "baking"}, {"quantity": 0.25, "unit": "Tsp", "item": "salt", "notes": "1/4 Tsp. - Salt", "category": "spices and seasonings"}, {"quantity": 0.75, "unit": "cup", "item": "cornmeal", "notes": "3/4 cup Yellow Cornmeal", "category": "ethnic foods"}]'::jsonb, '["Preheat oven to 425 degrees. Grease muffin cups or an 8 x 8 baking dish. In a large bowl stir the flour, cornmeal, baking powder, baking soda and salt. In a small bowl, stir together the eggs, pumpkin, sugar and oil.", "Mix together the wet and flour mixture and stir well, do not over mix. Divide the mixture among the muffin cups or evenly spread into the baking dish.", "Bake in the 425 degree oven for 15-18 minutes or until a toothpick inserted into the center comes out clean."]'::jsonb, 'https://www.foodista.com/recipe/NQBDBYXY/pumpkin-corn-bread', 'https://img.spoonacular.com/recipes/657277-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('one-bowl-jalapeno-cheddar-cornbread', 'One Bowl Jalapeno Cheddar Cornbread', 6, 0, 0, '{"calories": 527, "protein": 12.64, "carbs": 60.93, "fat": 26.49, "saturated_fat": 14.88, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 790.65, "potassium": null, "fiber": 3.61, "sugar": 25.23, "vitamin_a": null, "vitamin_c": 4.66, "calcium": 201.59, "iron": 2.44}'::jsonb, ARRAY['southern', 'bread', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "butter", "notes": "½ cup unsalted butter", "category": "milk, eggs, other dairy"}, {"quantity": 0.6666667, "unit": "cup", "item": "sugar", "notes": "⅔ cup white sugar", "category": "baking"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "buttermilk", "notes": "1 cup buttermilk", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "teaspoon", "item": "baking soda", "notes": "½ teaspoon baking soda", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "cornmeal", "notes": "1 cup cornmeal", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "cup", "item": "flour", "notes": "1 cup all-purpose flour", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "½ teaspoon salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "cheddar cheese", "notes": "1 cup shredded cheddar cheese", "category": "cheese"}, {"quantity": 4.0, "unit": "oz", "item": "jalapenos", "notes": "1 (4 oz) can diced jalapenos, drained", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "", "item": "jalapeno", "notes": "1 jalapeno, thinly sliced", "category": "canned and jarred"}]'::jsonb, '["Start by melting a stick of butter in a microwave safe bowl. Microwave the butter for 30 second intervals until the butter has completely melted.", "Then whisk in some granulated sugar.", "Next, whisk in two eggs.", "Now you''re going to mix together some buttermilk and baking soda and pour this into the mixture. Stir until well combined.", "Lastly, pour in cornmeal, flour, salt, shredded cheddar cheese, and canned diced jalapenos! Make sure you mix this until the mixture is *just* combined. Don''t over mix, or you''ll end up with tough bread!", "Preheat your oven to 375 degrees F and prepare a pan with cooking spray. I used a mini loaf pan very similar to this mini loaf pan, but an 8 x 8 pan would work, too! Although, the cooking time may vary. Spoon the batter into the prepared pan and top the batter with thinly sliced fresh jalapenos.", "Bake for about 25 to 35 minutes - again, the cooking time may vary depending on the size of your pan.", "Remove from the oven, and let the loaves cool in the pan for a few minutes.", "Remove from the pan and let set on a cooling rack until you''re ready to serve!"]'::jsonb, 'https://www.foodista.com/recipe/CGHQ4SLZ/one-bowl-jalapeno-cheddar-cornbread', 'https://img.spoonacular.com/recipes/653670-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
