 = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('whole-wheat-dinner-rolls', 'Whole Wheat Dinner Rolls', 19, 0, 0, '{"calories": 155, "protein": 5.04, "carbs": 29.89, "fat": 2.41, "saturated_fat": 1.11, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 386.73, "potassium": null, "fiber": 2.85, "sugar": 4.18, "vitamin_a": null, "vitamin_c": 0, "calcium": 30.17, "iron": 1.53}'::jsonb, ARRAY['bread', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "water", "notes": "1 cup Water", "category": "beverages"}, {"quantity": 0.33333334, "unit": "cups", "item": "cracked wheat", "notes": "1/3 cups Coaches Oats Or Cracked Wheat", "category": "health foods"}, {"quantity": 2.0, "unit": "teaspoons", "item": "active yeast", "notes": "2-¼ teaspoons Active Dry Yeast", "category": "baking"}, {"quantity": 0.25, "unit": "teaspoons", "item": "granulated sugar", "notes": "¼ teaspoons Granulated Sugar", "category": "baking"}, {"quantity": 0.33333334, "unit": "cups", "item": "warm water", "notes": "1/3 cups Warm Water", "category": "beverages"}, {"quantity": 2.0, "unit": "Tablespoons", "item": "butter", "notes": "2 Tablespoons Butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "table salt", "notes": "1 Tablespoon Table Salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "Tablespoons", "item": "molasses", "notes": "2 Tablespoons Molasses", "category": "baking"}, {"quantity": 2.0, "unit": "Tablespoons", "item": "honey", "notes": "2 Tablespoons Honey", "category": "nut butters, jams, and honey"}, {"quantity": 2.0, "unit": "Tablespoons", "item": "wheat germ", "notes": "2 Tablespoons Wheat Germ", "category": "health foods"}, {"quantity": 1.0, "unit": "cup", "item": "milk", "notes": "1 cup Milk, Warm", "category": "milk, eggs, other dairy"}, {"quantity": 3.0, "unit": "cups", "item": "flour", "notes": "3 cups Whole Wheat Flour", "category": "baking"}, {"quantity": 2.0, "unit": "cups", "item": "flour", "notes": "2 cups All-purpose Flour", "category": "baking"}, {"quantity": 1.0, "unit": "", "item": "egg white", "notes": "1 whole Egg White For Egg Wash", "category": "milk, eggs, other dairy"}]'::jsonb, '["In a small saucepan, bring the 1 cup water and the Coaches Oats to a boil, turn down to medium low and simmer for about 6 minutes.", "Remove from heat and cool to lukewarm.", "Dissolve the yeast in a medium sized bowl with 1/3 cup warm water and the sugar. Stir together, then let sit 10 minutes.", "Add the Coach Oats mixture to yeast mixture and add the butter, salt, molasses, honey, wheat germ and milk to the bowl of an electric mixer and with the paddle attachment, mix together to combine.", "Add the one cup of whole wheat flour and two cups of the all purpose flour.", "Mix until well combined. Clean off the paddle attachment, scrape the sides of the bowl and add the dough attachment to the mixer.", "With the mixer going on low speed, add the remaining whole wheat flour a little at a time until the dough starts coming together.", "After two of the remaining cups are added, let the mixer knead the dough for a minute or so. If it is still sticking to the sides, add about 1/4 cup more flour, let it mix. Keep adding a little flour at a time until the ball of dough no longer sticks to the sides.", "Let it knead for 8-10 minutes on medium-low speed.", "Remove the bowl from the mixer.", "Take the dough out of the bowl and spray it with cooking spray. Return the ball of dough to the bowl, cover it with a towel or plastic wrap and let sit in a warm, dry place for an hour until doubled in size (mine took almost 2 hours).", "Punch down the dough and make 2.50 ounce sized balls of doughyoull get about 19 rolls. Set them on a baking sheet and cover with a tea towel.", "Let them rise for about 45 minutes.", "During the last 20 minutes of rise time, preheat oven to 375 degrees.", "Fill a dutch oven or oven safe pot with water and place on the lowest shelf of the oven, this will add steam in the oven.", "Brush each roll with egg wash.", "Bake the rolls for 17-23 minutes (you may have to do this in two batches, unless you have a huge oven).", "Let the rolls sit on the baking sheet sit for a few minutes, then remove rolls from pan and place on a wire rack to  cool completely.", "NOTE:  Due to the molasses, the rolls will have a brown tone, so when your baking them, make sure the bottom has a light brown color to them, at first I thought I was over cooking the rolls, and I wasnt, 19 minutes seemed to be perfect amount of time.", "Serving Size: 19  2.5 oz rolls", "Calories per roll:  145,  Fat:  1.2,  Cholesterol:  .03,  Sodium:  20,  Potassium:  117,  Carbs:  29,  Fiber:  3,  Sugar:  3.8,  Protein:  4.9"]'::jsonb, 'https://www.foodista.com/recipe/MQZZ3YMC/whole-wheat-dinner-rolls', 'https://img.spoonacular.com/recipes/665282-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('simply-amazing-cinnamon-swirl-wheat-bread', 'Simply Amazing Cinnamon Swirl Wheat Bread', 8, 0, 0, '{"calories": 329, "protein": 6.7, "carbs": 49.5, "fat": 13.05, "saturated_fat": 7.66, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 179.97, "potassium": null, "fiber": 4.33, "sugar": 17.84, "vitamin_a": null, "vitamin_c": 0, "calcium": 47.26, "iron": 1.9}'::jsonb, ARRAY['bread', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 0.33333334, "unit": "C", "item": "brown sugar", "notes": "1/3 C brown sugar", "category": "baking"}, {"quantity": 4.0, "unit": "ounces", "item": "butter", "notes": "4 ounces (1 stick) butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tbsp", "item": "cinnamon", "notes": "1 tbsp cinnamon", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg, room temperature", "category": "milk, eggs, other dairy"}, {"quantity": 0.75, "unit": "cup", "item": "flour", "notes": "3/4 cup flour", "category": "baking"}, {"quantity": 2.5, "unit": "tsp", "item": "yeast", "notes": "2 1/2 tsp instant dry yeast", "category": "baking"}, {"quantity": 0.25, "unit": "C", "item": "non-fat milk", "notes": "1/4 C non-fat milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "nutmeg", "notes": "1/2 tsp nutmeg", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "salt", "notes": "1/4 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.33333334, "unit": "C", "item": "sugar", "notes": "1/3 C sugar", "category": "baking"}, {"quantity": 0.75, "unit": "C", "item": "warm water", "notes": "3/4 C warm water", "category": "beverages"}, {"quantity": 2.0, "unit": "C", "item": "flour", "notes": "2 C whole wheat flour", "category": "baking"}]'::jsonb, '["Put egg, milk, and water into bread machine pan.", "Add butter, sugar, flour, salt, nutmeg, cinnamon, and yeast.Set bread machine to dough cycle.", "Remove dough at end of cycle and roll into approx. a 10x12 rectangle.", "Spread softened butter on surface of dough to the edges.", "Sprinkle with brown sugar and cinnamon.Starting with short side, roll tightly.  Pinch and fold down ends.", "Place in bread pan. Cover and let rise in a warm spot for about an hour or until dough has doubled in size.Preheat oven to 350.Once dough has risen, bake for 35 minutes.", "Remove from oven and let cool in pan for at least 10 minutes to allow filling to set."]'::jsonb, 'https://www.foodista.com/recipe/YFKMZCPN/simply-amazing-cinnamon-swirl-wheat-bread', 'https://img.spoonacular.com/recipes/660157-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sweet-potato-green-tea-pancake-roll', 'Sweet Potato Green Tea Pancake Roll', 6, 0, 0, '{"calories": 138, "protein": 4.15, "carbs": 25.75, "fat": 2.04, "saturated_fat": 1.02, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 62.41, "potassium": null, "fiber": 2.02, "sugar": 8.7, "vitamin_a": null, "vitamin_c": 1.4, "calcium": 62.11, "iron": 1.1}'::jsonb, ARRAY['bread', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'breakfast', 'baking', 'vegetarian'], '[{"quantity": 2.5, "unit": "tbsp", "item": "brown sugar", "notes": "2 1/2 tbsp Brown sugar", "category": "baking"}, {"quantity": 0.5, "unit": "tbsp", "item": "butter", "notes": "1/2 tbsp Soft butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "", "item": "eggs", "notes": "1 Eggs", "category": "milk, eggs, other dairy"}, {"quantity": 60.0, "unit": "g", "item": "flour", "notes": "60g Flour", "category": "baking"}, {"quantity": 1.0, "unit": "tsp", "item": "tea powder", "notes": "1 tsp Green tea powder", "category": "tea and coffee"}, {"quantity": 1.0, "unit": "tbsp", "item": "milk", "notes": "1 tbsp Low fat milk", "category": "milk, eggs, other dairy"}, {"quantity": 150.0, "unit": "ml", "item": "low far milk", "notes": "150ml Low far milk", "category": "milk, eggs, other dairy"}, {"quantity": 350.0, "unit": "g", "item": "sweet potato", "notes": "350g Sweet potato (peeled)", "category": "produce"}]'::jsonb, '["Steam thinly sliced sweet potatoes for about 20 minutes or till soft. Mash them while hot with a fork, add low fat milk and butter, mix well, set aside.First sieve flour and green powder, fold in brown sugar, then slowly add egg and milk stir well, then add 1 tbsp melted butter, mix well. Pass through a sift and rest for 10 minutes.", "Spread little butter on frying pan at medium small heat, pour in a ladle of batter and spread evenly, let the pancake stand for about 1 minute.", "Place pancake on the rolling mat.", "Add mashed potato at one side of the pancake and roll up.Seal the opening with a little butter.Turn the opening downward and put in the fry pan, fry slightly.", "Cut pancake roll into pieces with a sharp knife and dust some green tea powder on it before serve."]'::jsonb, 'https://www.foodista.com/recipe/YFXBSDZ8/sweet-potato-green-tea-pancake-roll', 'https://img.spoonacular.com/recipes/662582-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('honey-wheat-hamburger-buns', 'Honey Wheat Hamburger Buns', 8, 0, 0, '{"calories": 386, "protein": 10.13, "carbs": 66.45, "fat": 9.72, "saturated_fat": 1.28, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 319.29, "potassium": null, "fiber": 3.04, "sugar": 21.39, "vitamin_a": null, "vitamin_c": 0, "calcium": 39.39, "iron": 1.3}'::jsonb, ARRAY['american', 'bread', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 0.75, "unit": "cup", "item": "warm water", "notes": "3/4 cup warm water", "category": "beverages"}, {"quantity": 2.0, "unit": "Tablespoons", "item": "active yeast", "notes": "2 Tablespoons dry active yeast", "category": "baking"}, {"quantity": 2.0, "unit": "Tablespoons", "item": "granulated sugar", "notes": "2 Tablespoons granulated sugar", "category": "baking"}, {"quantity": 3.0, "unit": "cups", "item": "bread flour", "notes": "3 cups bread flour, sifted", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "flour", "notes": "1 cup whole wheat flour, sifted", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "kosher salt", "notes": "1 teaspoon kosher salt", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "canola oil", "notes": "1/4 cup canola oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.5, "unit": "cup", "item": "milk", "notes": "1/2 cup 2% milk", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "large", "item": "eggs", "notes": "2 large eggs, at room temperature", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "cup", "item": "honey", "notes": "1/2 cup honey", "category": "nut butters, jams, and honey"}, {"quantity": 2.0, "unit": "tablespoons", "item": "water", "notes": "2 tablespoons water", "category": "beverages"}]'::jsonb, '["In a small bowl, combine the water, yeast and sugar.  Set aside for 5 minutes.", "In a large bowl, whisk together the bread flour, whole wheat flour and salt.  Set aside.", "Pour the yeast mixture, into the bowl of an electric mixer fitted with the dough hook.  On low-speed, mix together the yeast mixture, canola oil, milk, egg and honey until thoroughly combined.  Slowly add the flour mixture and mix until the dough forms a ball. Continue kneading the dough in the mixer, or by hand, for approximately 5 minutes.", "Lightly oil a large bowl, place the dough in the bowl and cover with a kitchen towel.  Allow the dough to rise in a warm location for approximately two hours or until it has doubled in size.", "Line a baking sheet with parchment paper.", "Punch down the dough and divide into 8 equal size balls.", "Place the dough balls on the baking sheet and cover with a clean kitchen towel.", "Let the dough rise in a warm location for an hour or until it has doubled in size.", "Heat the oven to 400 degrees.", "In a small bowl, whisk together the remaining egg and water.  Using a pastry brush, lightly cover each bun with the egg wash.", "Bake the buns for 15-18 minutes or until they turn golden brown.", "The buns are best if enjoyed within three days.  Alternatively, you can wrap them each in plastic wrap and foil to freeze them for up to 6 weeks."]'::jsonb, 'https://www.foodista.com/recipe/GXR6WVLB/honey-wheat-hamburger-buns', 'https://img.spoonacular.com/recipes/647296-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('greek-inspired-spring-omelet', 'Greek Inspired Spring Omelet', 1, 0, 0, '{"calories": 133, "protein": 13.55, "carbs": 7.28, "fat": 5.94, "saturated_fat": 2.79, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 606.45, "potassium": null, "fiber": 1.64, "sugar": 3.81, "vitamin_a": null, "vitamin_c": 19.32, "calcium": 132.92, "iron": 1.76}'::jsonb, ARRAY['mediterranean', 'european', 'greek', 'lunch', 'main course', 'morning meal', 'brunch', 'main dish', 'breakfast', 'dinner', 'gluten free', 'lacto ovo vegetarian', 'primal', 'spoonacular', 'vegetarian'], '[{"quantity": 3.0, "unit": "", "item": "asparagus spears", "notes": "3 Asparagus spears", "category": "produce"}, {"quantity": 0.33333334, "unit": "cup", "item": "egg whites", "notes": "1/3 cup egg whites", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "Tbsp", "item": "feta cheese", "notes": "1 Tbsp. Feta cheese, crumbled", "category": "cheese"}, {"quantity": 1.0, "unit": "serving", "item": "green onions", "notes": "green onions, diced", "category": "produce"}, {"quantity": 1.0, "unit": "serving", "item": "salt and pepper", "notes": "salt and pepper to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "Tbsp", "item": "tzatziki", "notes": "1 Tbsp. tzatziki", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "", "item": "cherry tomatoes", "notes": "4 cherry tomatoes (red, yellow or a mix), diced", "category": "produce"}]'::jsonb, '["In a medium skillet saute asparagus until tender, about 7 minutes. Set aside.In a small bowl combine egg whites and tzatziki; stir to combine.Spray non stick skillet with cooking spray and bring to medium heat.", "Pour in egg white and allow it to spread over the skillet surface. Cook until egg turns white; about 2 minutes.Slide omelette onto a plate and place asparagus, tomatoes, green onions and feta in the middle. Fold the omelette into thirds to cover the fillings.", "Serve hot with additional tzatziki. Salt and pepper to taste."]'::jsonb, 'https://www.foodista.com/recipe/NCS56WWG/greek-inspired-spring-omelet', 'https://img.spoonacular.com/recipes/645315-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pittata-pizza-frittata', 'Pittata - Pizza Frittata', 2, 0, 0, '{"calories": 598, "protein": 41.6, "carbs": 8.53, "fat": 43.2, "saturated_fat": 18.09, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 1328.36, "potassium": null, "fiber": 0, "sugar": 3.76, "vitamin_a": null, "vitamin_c": 0, "calcium": 518.35, "iron": 3.71}'::jsonb, ARRAY['mediterranean', 'italian', 'european', 'lunch', 'main course', 'morning meal', 'brunch', 'main dish', 'breakfast', 'dinner', 'gluten free', 'primal', 'ketogenic', 'spoonacular', 'baking'], '[{"quantity": 8.0, "unit": "", "item": "eggs", "notes": "8 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "servings", "item": "basil", "notes": "fresh basil", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "milk", "notes": "1/2 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "servings", "item": "parmesan cheese", "notes": "freshly grated Parmesan cheese", "category": "cheese"}, {"quantity": 2.0, "unit": "servings", "item": "pepperoni", "notes": "pepperoni", "category": "meat"}, {"quantity": 0.25, "unit": "cup", "item": "mozzarella cheese", "notes": "1/4 cup shredded mozzarella cheese", "category": "cheese"}]'::jsonb, '["Pre-heat oven to ~450°F (230°C), top heat only.", "On the stove, heat cooking fat in a large oven-safe skillet over medium heat.", "Beat the eggs with the milk (again milk is optional), salt, pepper, and any herbs or spices desired.", "Add any desired add-ins (other than cheese) to the skillet. For the pittata, we didn''t use anything, but this is when you would add your cooked vegetables or raw vegetables that don''t require much cooking (e.g. bell pepper).", "Pour in the egg mixture and tilt the skillet to ensure it evenly surrounds any add-ins. Now distribute the shredded cheese and pepperoni slices (if using).", "Allow the eggs to cook on the stove until the edges of the eggs are set. The center will still be a bit jiggly. Now is a good time to top with Parmesan cheese (be generous!)", "Transfer the pan to the hot oven and bake until the eggs are puffed and browned with a firm center.", "Remove from oven and let cool for a couple minutes before cutting into wedges."]'::jsonb, 'https://spoonacular.com/-1418233867224', 'https://img.spoonacular.com/recipes/622598-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sun-dried-tomato-and-leek-quiche', 'Sun-Dried Tomato and Leek Quiche', 4, 0, 0, '{"calories": 681, "protein": 20.11, "carbs": 59.87, "fat": 42.81, "saturated_fat": 6.21, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 958.06, "potassium": null, "fiber": 8.63, "sugar": 6.74, "vitamin_a": null, "vitamin_c": 11.25, "calcium": 252.72, "iron": 6.16}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'lunch', 'main course', 'morning meal', 'brunch', 'main dish', 'breakfast', 'dinner', 'dairy free', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 4.0, "unit": "servings", "item": "crust", "notes": "Crust", "category": "refrigerated"}, {"quantity": 1.0, "unit": "cup", "item": "pastry flour", "notes": "1 cup whole-wheat pastry flour", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "pine nuts", "notes": "1/4 cup pine nuts", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "almonds", "notes": "1/4 cup whole almonds", "category": "nuts"}, {"quantity": 0.25, "unit": "teaspoon", "item": "baking powder", "notes": "1/4 teaspoon baking powder", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "almond milk", "notes": "1/4 cup unsweetened almond milk", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "Tbs", "item": "olive oil", "notes": "2 Tbs. olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.25, "unit": "teaspoon", "item": "salt", "notes": "1/4 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "Tbs", "item": "olive oil", "notes": "4 Tbs. olive oil, divided", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "cups", "item": "leek", "notes": "1 large leek, white and light green parts chopped (about 2 cups)", "category": "produce"}, {"quantity": 12.0, "unit": "ounces", "item": "extra-firm tofu", "notes": "12 ounces extra-firm tofu, drained and cut into 1.5-inch cubes", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "lemon juice", "notes": "2 tablespoons fresh lemon juice", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "miso paste", "notes": "2 teaspoons miso paste", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "clove", "item": "garlic", "notes": "1 clove garlic, minced", "category": "produce"}, {"quantity": 0.75, "unit": "teaspoon", "item": "salt", "notes": "3/4 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "panko breadcrumbs", "notes": "1 cup Panko breadcrumbs", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "seasonings", "notes": "1 teaspoon Italian seasonings", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "reconstituted sun-dried tomatoes", "notes": "1/4 cup chopped reconstituted sun-dried tomatoes, drained", "category": "canned and jarred"}]'::jsonb, '["Crust", "Preheat oven to 350F.", "Coat four 5-inch tart pans with cooking spray.", "Pulse flour, pine nuts,almonds,baking powder", "In food processor until finely ground.", "Whisk together almond milk, oil and salt in bowl.", "Stir in flour mixture. Press into pan.", "Bake 5 minutes, then cool.", "Filling", "Heat 1 Tbs. oil in skillet over medium heat.", "Add leeks, and saute'' 8 minutes, or until softened. Set aside.", "Bring large saucepan of water to a boil.", "Add tofu, and simmer 5 minutes.", "Drain and pat dry.", "Whisk 3 Tbsp. oil, lemon juice, miso, garlic and salt in bowl.", "Add tofu and blend with an immersion blender.", "Stir in breadcrumbs,seasonings, sun-dried tomatoes and leeks.", "Spoon filling into crust.", "Bake 40 minutes, or until crust is browned.", "Cool 5 minutes, then unmold."]'::jsonb, 'https://www.foodista.com/recipe/KGMNJ3TN/sun-dried-tomato-and-leek-quiche', 'https://img.spoonacular.com/recipes/662291-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mushroom-crepes-with-vegetarian-sauce', 'Mushroom Crepes with Vegetarian Sauce', 8, 0, 0, '{"calories": 184, "protein": 7.11, "carbs": 24.45, "fat": 6.4, "saturated_fat": 1.67, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 251.19, "potassium": null, "fiber": 3.68, "sugar": 1.73, "vitamin_a": null, "vitamin_c": 10.06, "calcium": 56.85, "iron": 1.93}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'morning meal', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "corn", "notes": "½ cup canned corn", "category": "produce"}, {"quantity": 1.0, "unit": "tbsp", "item": "chives", "notes": "1-2 tbsp chopped chives", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "dill", "notes": "1/2 cup chopped dill", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "", "item": "garlic cloves", "notes": "2-3 garlic cloves, mashed", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "garlic powder", "notes": "1 tsp garlic powder", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "ground coriander", "notes": "1/2 tsp ground coriander", "category": "spices and seasonings"}, {"quantity": 0.33333334, "unit": "tsp", "item": "ground pepper", "notes": "1/3 tsp ground pepper", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "cream", "notes": "½ cup low fat sour cream", "category": "milk, eggs, other dairy"}, {"quantity": 300.0, "unit": "g", "item": "mushrooms", "notes": "300g mushrooms", "category": "produce"}, {"quantity": 8.0, "unit": "servings", "item": "oil", "notes": "Oil – for frying", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "", "item": "big onion", "notes": "1 big onion, chopped", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "parsley", "notes": "1/2 cup chopped parsley", "category": "produce"}, {"quantity": 1.0, "unit": "pinch", "item": "sea salt", "notes": "a pinch of sea salt", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "servings", "item": "sea salt", "notes": "sea salt, to taste", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tsp", "item": "paprika", "notes": "1tsp sweet paprika", "category": "spices and seasonings"}, {"quantity": 250.0, "unit": "ml", "item": "water", "notes": "250 ml water", "category": "beverages"}, {"quantity": 0.5, "unit": "cup", "item": "white wine", "notes": "1/2 cup white wine", "category": "alcoholic beverages"}, {"quantity": 200.0, "unit": "g", "item": "flour", "notes": "200g whole wheat flour", "category": "baking"}]'::jsonb, '["Whisk the eggs.", "Add the water and mix well (you can also use a hand-held mixer).", "Sprinkle the flour while continuously whisking/mixing until it has the right consistency.", "Heat some oil in a frying pan over medium-high heat. Grease the whole surface of the pan and then pour the oil in a cup. You’ll be reusing it.", "Add the mushrooms and wine in your food processor. Blend until you get a thick paste.", "Heat some 1 tbsp oil in a large saucepan.", "Add the chopped onion. Sauté until golden, then add the mushroom paste and corn.", "Add spices.Cook for 15 minutes ten add the chopped dill and parsley and cook for another 5 minutes.", "Mix last four ingredients and pour sauce over the vegetarian mushroom crepes."]'::jsonb, 'https://www.foodista.com/recipe/LZFR2QTP/mushroom-crepes-with-vegan-vegetarian-sauce', 'https://img.spoonacular.com/recipes/652651-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('salmon-and-broccoli-crepes', 'Salmon and Broccoli Crepes', 4, 0, 0, '{"calories": 208, "protein": 16.74, "carbs": 17.65, "fat": 8.54, "saturated_fat": 3.37, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 131.03, "potassium": null, "fiber": 3.48, "sugar": 2.33, "vitamin_a": null, "vitamin_c": 48.74, "calcium": 83.63, "iron": 1.76}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'morning meal', 'brunch', 'breakfast', 'pescatarian', 'spoonacular', 'baking'], '[{"quantity": 2.0, "unit": "cups", "item": "broccoli florets", "notes": "2 cups broccoli florets, cut into small pieces", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "butter", "notes": "1 tablespoon butter", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "teaspoons", "item": "dijon mustard", "notes": "2 teaspoons dijon mustard", "category": "condiments"}, {"quantity": 1.0, "unit": "large", "item": "egg white", "notes": "1 large egg white", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "tablespoons", "item": "lemon juice", "notes": "2 tablespoons lemon juice", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "lemon thyme", "notes": "1 tablespoon lemon thyme, fresh finely chopped", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "lemon zest", "notes": "1 tablespoon lemon zest", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "milk", "notes": "1/4 cup low fat milk", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "tablespoons", "item": "reduced fat cream", "notes": "4 tablespoons reduced fat sour cream", "category": "milk, eggs, other dairy"}, {"quantity": 8.0, "unit": "ounces", "item": "alaskan salmon filets", "notes": "8 ounces wild Alaskan Salmon filets, cooked and flaked into pieces", "category": "seafood"}, {"quantity": 1.0, "unit": "pinch", "item": "salt", "notes": "1 pinch salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "shallot", "notes": "2 tablespoons shallot, finely minced", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "water", "notes": "1/4 cup water", "category": "beverages"}, {"quantity": 0.5, "unit": "cup", "item": "pastry flour", "notes": "1/2 cup whole wheat pastry flour", "category": "baking"}]'::jsonb, '["Combine milk, water, egg and melted butter in a small bowl.", "Add flour and salt and whip until well blended. Allow to sit for 10 minutes.Steam broccoli until just tender, and combine salmon, shallot, thyme, lemon juice, dijon and 1/2 cup sour cream. Chop pieces of salmon and broccoli with a spoon if you have extra large pieces. Warm salmon mixture in the microwave for 2 minutes.", "Combine remaining sour cream and lemon zest.", "Heat a medium non-stick skillet over medium heat and spray with cooking spray.", "Add 1/4 cup crepe batter to the pan and swirl around to create an even pancake. Cook 1  2 minutes on the first side to brown crepe, then flip and brown the other side. Crepes cook quickly because they are so thin.", "Remove to a plate and keep warm.Fill a crepe with 1/4 salmon lengthwise and gently roll. Slice in half on a diagonal and top with a tablespoon of sour cream and lemon zest mixture."]'::jsonb, 'https://www.foodista.com/recipe/B85Z3KP2/salmon-and-broccoli-crepes', 'https://img.spoonacular.com/recipes/659037-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('irish-brown-soda-bread', 'Irish Brown Soda Bread', 12, 0, 0, '{"calories": 182, "protein": 6.85, "carbs": 34.11, "fat": 2.43, "saturated_fat": 1.0, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 333.06, "potassium": null, "fiber": 2.9, "sugar": 2.11, "vitamin_a": null, "vitamin_c": 0, "calcium": 58.79, "iron": 1.86}'::jsonb, ARRAY['european', 'irish', 'morning meal', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 260.0, "unit": "grams", "item": "flour", "notes": "2 cups All-Purpose Flour (260 grams)", "category": "baking"}, {"quantity": 260.0, "unit": "grams", "item": "wholemeal flour", "notes": "2 cups Wholemeal Flour (260 grams)", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon Salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "baking soda", "notes": "1 teaspoon Baking Soda", "category": "baking"}, {"quantity": 2.0, "unit": "cups", "item": "buttermilk", "notes": "2 cups Buttermilk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 Small Egg for brushing", "category": "milk, eggs, other dairy"}]'::jsonb, '["Combine both types of flour with baking soda and salt in a large bowl.", "Add the buttermilk and using a wooden spoon mix until you get nice dough.", "Transfer onto a floured surface and form into a loaf (do not knead, the less you work the dough the better). Using both hands make moves like if you wanted to lift the dough, then tuck it under and at the same time turn it in clockwise/anticlockwise direction. Repeat several times. This will shape the dough into a nice round loaf.", "Place the dough onto a baking tray lined with baking paper and mark a cross using a knife (you can also cut it into quarters, if you prefer smaller loaves).", "Brush with egg wash and place in a preheated oven.", "Bake at 200 C/400 F for 30 minutes or until ready (if you knock on the bottom of the bread and you hear a hollow sound you know its ready).", "Let it cool down on a wire rack before serving."]'::jsonb, 'https://www.foodista.com/recipe/3RS8JBV3/irish-brown-soda-bread', 'https://img.spoonacular.com/recipes/1095888-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mushroom-crepes', 'Mushroom Crepes', 3, 0, 0, '{"calories": 186, "protein": 7.23, "carbs": 24.45, "fat": 1.21, "saturated_fat": 0.19, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 661.96, "potassium": null, "fiber": 4.46, "sugar": 6.71, "vitamin_a": null, "vitamin_c": 9.15, "calcium": 35.98, "iron": 1.66}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'morning meal', 'brunch', 'breakfast', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'soup', 'baking', 'vegetarian'], '[{"quantity": 1.5, "unit": "tablespoons", "item": "arrowroot", "notes": "1 1/2 tablespoons Arrowroot or 2 tsp kudzu powder", "category": "baking"}, {"quantity": 2.0, "unit": "", "item": "bay leaves", "notes": "2 Bay leaves", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "servings", "item": "cayenne", "notes": "Cayenne to taste", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "tablespoons", "item": "wine", "notes": "2 tablespoons Dry red wine", "category": "alcoholic beverages"}, {"quantity": 4.0, "unit": "cups", "item": "mushrooms", "notes": "4 cups Mushrooms, fresh, finely chopped", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "garlic cloves", "notes": "2 garlic cloves pressed", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "onion", "notes": "1 cup Onion, finely chopped", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "shiitake mushrooms", "notes": "1/2 cup Shiitake mushrooms, 2 tablespoons Olive oil", "category": "produce"}, {"quantity": 1.0, "unit": "tablespoon", "item": "tamari", "notes": "1 tablespoon Tamari, or more to taste", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "teaspoon", "item": "tarragon", "notes": "1 teaspoon Tarragon", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "mild vegetable stock", "notes": "1 cup water or mild vegetable stock", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "tablespoons", "item": "pastry flour", "notes": "2 tablespoons Whole wheat pastry flour", "category": "baking"}, {"quantity": 1.0, "unit": "cup", "item": "wine", "notes": "cup Dry red wine", "category": "alcoholic beverages"}]'::jsonb, '["Prepare the crepes.", "Place the shiitake mushrooms in a bowl. Cover them with water and let them soak for at least 1 hour.Discard the stems and finely chop the mushrooms. Set aside.", "Heat the oil in a skillet.", "Add the onion, garlic and bay leaves.", "Saute over low heat until the onions are translucent.", "Add the shiitake mushrooms, the fresh mushrooms, and the tarragon. Cook until the mushrooms are done.Stir in the flour and mix well.", "Pour in the wine while continuing to stir.Cook until the mixture thickens.", "Add the tamari and cayenne to taste. Set the filling aside while you make the sauce.Sauce: Dissolve the arrowroot or kudzu in the water.", "Add the wine. Cook in small saucepan over high heat, stirring constantly, until the sauce thickens. This is not supposed to be very thick, so do not overcook it.", "Add the tamari to taste and mix well.To assemble: If the filling mixture has cooled down, heat it by returning the skillet to the stove and stirring the mixture over medium-high heat until it is hot.", "Place about 1/4 cup of filling in the center of each crepe and roll up the crepes.", "Place the crepes on individual serving plates.", "Pour some of the sauce over each crepe and serve."]'::jsonb, 'https://www.foodista.com/recipe/PV7RBFHW/mushroom-crepes', 'https://img.spoonacular.com/recipes/652652-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('rosemary-rum-raisin-soda-bread-with-pecans', 'Rosemary Rum Raisin Soda Bread with Pecans', 16, 0, 0, '{"calories": 173, "protein": 4.85, "carbs": 28.95, "fat": 3.61, "saturated_fat": 0.8, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 295.09, "potassium": null, "fiber": 2.66, "sugar": 2.42, "vitamin_a": null, "vitamin_c": 0, "calcium": 41.3, "iron": 1.5}'::jsonb, ARRAY['european', 'irish', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "raisins", "notes": "1/2 cup raisins", "category": "produce"}, {"quantity": 0.33333334, "unit": "cup", "item": "rum", "notes": "1/3 cup dark rum", "category": "alcoholic beverages"}, {"quantity": 2.0, "unit": "cups", "item": "flour", "notes": "2 cups all-purpose flour, plus 2 teaspoons for dusting the pan", "category": "baking"}, {"quantity": 2.0, "unit": "cups", "item": "flour", "notes": "2 cups whole wheat flour", "category": "baking"}, {"quantity": 2.0, "unit": "teaspoons", "item": "baking soda", "notes": "2 teaspoons baking soda", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "rosemary", "notes": "1 tablespoon fresh rosemary, finely chopped", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "pecans", "notes": "1/2 cup pecans, toasted and roughly chopped", "category": "baking"}, {"quantity": 1.5, "unit": "cups", "item": "yogurt", "notes": "1 1/2 cups plain yogurt", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "honey", "notes": "1 tablespoon honey", "category": "nut butters, jams, and honey"}, {"quantity": 1.0, "unit": "tablespoon", "item": "milk", "notes": "1 tablespoon milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.75, "unit": "teaspoon", "item": "anise seeds", "notes": "3/4 teaspoon anise seeds (optional) (Sesame seeds or rolled oats are nice substitutes, if you''re not an anise lover.)", "category": "spices and seasonings"}]'::jsonb, '["Combine the rum and raisins in a small saucepan. Bring to a boil. Simmer for 30 seconds, then remove from heat. Cover and allow the raisins to macerate for at least 4 hours, but preferably overnight.", "When youre ready to bake the bread, preheat the oven to 375F.", "Coat a baking sheet with olive oil and lightly dust it with flour, or line it with parchment paper.", "In a large mixing bowl whisk together the flours, baking soda, salt, and rosemary. Stir in the toasted pecans.", "In a separate bowl combine the raisins with the rum, the yogurt, and honey.", "Add the wet ingredients to the dry.", "Mix until the dough is too stiff to stir. Use your hands to bring it together in the bowl.", "Add additional yogurt one teaspoon at a time if its too dry. You want a stiff, slightly tacky ball.", "Turn dough onto a lightly floured board and shape into a round loaf. (Dont over-knead the dough. Too much kneading will produce a tough bread.).", "Transfer the loaf to the prepared baking sheet. Use a sharp knife to make deep slashes across the top of the loaf, 4-6 cuts about half way through.", "Brush the top with milk.", "Sprinkle with seeds or oats if using.", "Bake for 40-45 minutes, until a toothpick comes out clean. When you tap the loaf, it will sound hollow.", "Cool on a wire rack.", "Serve warm or at room temperature with a generous slather of butter."]'::jsonb, 'https://www.foodista.com/recipe/D3WCB7PW/rosemary-rum-raisin-soda-bread-with-pecans', 'https://img.spoonacular.com/recipes/658803-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('simple-broccoli-cheddar-quiche', 'Simple Broccoli Cheddar Quiche', 4, 0, 0, '{"calories": 441, "protein": 23.67, "carbs": 27.38, "fat": 26.57, "saturated_fat": 13.83, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 927.12, "potassium": null, "fiber": 2.1, "sugar": 7.51, "vitamin_a": null, "vitamin_c": 39.25, "calcium": 520.15, "iron": 2.69}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'lunch', 'main course', 'morning meal', 'brunch', 'main dish', 'breakfast', 'dinner', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "cups", "item": "broccoli", "notes": "2 cups cooked broccoli – chopped", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "cheddar cheese", "notes": "1 cup cheddar cheese – shredded", "category": "cheese"}, {"quantity": 5.0, "unit": "", "item": "eggs", "notes": "5 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.5, "unit": "cups", "item": "milk", "notes": "1½ cups milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "salt", "notes": "½ tsp. salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "pepper", "notes": "½ tsp. black pepper", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "garlic powder", "notes": "½ tsp. garlic powder", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "parmesan cheese", "notes": "¼ cup grated Romano cheese or Parmesan cheese", "category": "cheese"}, {"quantity": 6.0, "unit": "slices", "item": "bread", "notes": "6 slices white bread", "category": "bakery/bread"}, {"quantity": 2.0, "unit": "tablespoons", "item": "butter", "notes": "2 -3 tablespoons of butter", "category": "milk, eggs, other dairy"}]'::jsonb, '["Preheat oven to 350 degrees F.Butter a 9 inch pie plate.  Press the bread into the plate and bake it until it becomes slightly golden, approximately, 10-11 minutes.", "Remove from oven and let cool slightly before adding the quiche batter.For the quiche batter, place the cooked chopped broccoli, cheddar cheese, Romano cheese, salt and pepper, and butter in a large bowl.  Beat the milk with the eggs and add to the bowl.  Toss the mixture and pour into the baking dish.  Top the quiche with a little more grated Romano cheese.", "Bake 35-40 minutes.", "Let cool for at least 20 -25 minutes before serving."]'::jsonb, 'https://www.foodista.com/recipe/3XS4X4V8/simple-broccoli-cheddar-quiche', 'https://img.spoonacular.com/recipes/1095851-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('leek-and-mushroom-quiche', 'Leek and Mushroom Quiche', 4, 0, 0, '{"calories": 453, "protein": 18.31, "carbs": 37.06, "fat": 26.37, "saturated_fat": 14.39, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 395.2, "potassium": null, "fiber": 2.29, "sugar": 7.14, "vitamin_a": null, "vitamin_c": 7.55, "calcium": 260.18, "iron": 3.66}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'lunch', 'main course', 'morning meal', 'brunch', 'main dish', 'breakfast', 'dinner', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 0.5, "unit": "cup", "item": "tasty cheese", "notes": "1/2 cup grated tasty cheese", "category": "cheese"}, {"quantity": 0.5, "unit": "cup", "item": "cream", "notes": "1/2 cup cream", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "", "item": "egg yolks", "notes": "1 egg yolks", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "", "item": "eggs", "notes": "4 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "Clove", "item": "garlic", "notes": "1 Clove garlic", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "leeks", "notes": "2 leeks", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "lemon juice", "notes": "1 teaspoon lemon juice", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "milk", "notes": "1 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 250.0, "unit": "grams", "item": "mushrooms", "notes": "250 grams mushrooms", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "flour", "notes": "1 cup flour, plain", "category": "baking"}, {"quantity": 4.0, "unit": "servings", "item": "salt", "notes": "salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "butter", "notes": "1 tablespoon unsalted butter", "category": "milk, eggs, other dairy"}]'::jsonb, '["Pastry:Sift flour and salt into a bowl, rub in butter, add egg yolk and lemon juice and mix to a firm dough. Cover and refrigerate 20 minutes.", "Roll dough out large enough to line a 25cm flan tin, trim the edges. Cover pastry with greaseproof paper and fill with dried beans or rice to hold in shape while cooking.", "Bake in a moderate oven for 7 minutes, remove paper and beans and bake a furthur 7 minutes. Set aside until required.", "Whisk eggs, cream, milk and cheeses together and set aside.Slice leeks and mushrooms.Melt butter in a pan and cook garlic, mushrooms and leeks about 4 minutes until tender.", "Spread leek mushroom mixture evenly over pastry.", "Pour over egg mixture and sprinkle with paprika.", "Bake in a moderate oven for about 30 minutes or until set.", "Serves 4."]'::jsonb, 'https://www.foodista.com/recipe/CF64ZCCX/leek-and-mushroom-quiche', 'https://img.spoonacular.com/recipes/649431-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('chavrie-spinach-quiche', 'Chavrie Spinach Quiche', 8, 0, 0, '{"calories": 259, "protein": 10.06, "carbs": 14.06, "fat": 18.43, "saturated_fat": 8.85, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 378.5, "potassium": null, "fiber": 1.64, "sugar": 2.13, "vitamin_a": null, "vitamin_c": 2.45, "calcium": 133.34, "iron": 2.01}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'antipasti', 'starter', 'morning meal', 'snack', 'brunch', 'appetizer', 'antipasto', 'breakfast', 'hor d''oeuvre', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 5.3, "unit": "oz", "item": "chavrie goat cheese", "notes": "1 package (5.3 oz.) Chavrie goat cheese", "category": "cheese"}, {"quantity": 4.0, "unit": "", "item": "eggs", "notes": "4 Eggs", "category": "milk, eggs, other dairy"}, {"quantity": 6.0, "unit": "ounces", "item": "alouette crème fraiche", "notes": "6 ounces Heavy cream or Alouette crème fraiche", "category": "milk, eggs, other dairy"}, {"quantity": 6.0, "unit": "ounces", "item": "half and half", "notes": "6 ounces Half and Half", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "teaspoon", "item": "cayenne", "notes": "1/2 teaspoon Cayenne", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon Salt", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "ground pepper", "notes": "1/4 teaspoon Ground white pepper", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "servings", "item": "es pie crust pre-baked", "notes": "9 inches pie crust pre-baked", "category": "refrigerated"}, {"quantity": 1.0, "unit": "package", "item": "spinach", "notes": "1 package Frozen spinach, thawed and drained", "category": "frozen"}, {"quantity": 1.0, "unit": "pinch", "item": "nutmeg", "notes": "1 pinch Nutmeg", "category": "spices and seasonings"}]'::jsonb, '["Blend Chavrie with eggs and mix well.", "Add cream and half and half to make custard and season with salt, pepper, cayenne and nutmeg.", "Scatter the spinach evenly over the bottom of the pre-baked piecrust.", "Pour custard into the shell stirring with a fork to evenly distribute the spinach.", "Bake at 350 F for 45 minutes, until a knife blade inserted into it comes out clean.", "Let rest and serve warm.", "Substitute Spinach with 12 oz. fresh diced asparagus."]'::jsonb, 'https://www.foodista.com/recipe/DDMB7GG4/chavrie-spinach-quiche', 'https://img.spoonacular.com/recipes/637478-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('oatmeal-apricot-walnut-soda-bread', 'Oatmeal, Apricot, Walnut Soda Bread', 8, 0, 0, '{"calories": 357, "protein": 10.47, "carbs": 55.74, "fat": 11.26, "saturated_fat": 3.69, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 741.46, "potassium": null, "fiber": 4.44, "sugar": 13.37, "vitamin_a": null, "vitamin_c": 0, "calcium": 95.49, "iron": 2.74}'::jsonb, ARRAY['european', 'irish', 'morning meal', 'dessert', 'brunch', 'breakfast', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 7.5, "unit": "oz", "item": "old-fashioned oatmeal", "notes": "2 1/2 c. (7 1/2 oz.) old-fashioned oatmeal", "category": "cereal"}, {"quantity": 1.75, "unit": "c", "item": "buttermilk", "notes": "1 3/4 c. buttermilk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "large", "item": "egg", "notes": "1 large egg", "category": "milk, eggs, other dairy"}, {"quantity": 6.75, "unit": "oz", "item": "unbleached flour", "notes": "1 1/2 c. (6 3/4 oz.) unbleached all-purpose flour", "category": "baking"}, {"quantity": 5.5, "unit": "oz", "item": "flour", "notes": "1 c. (5 1/2 oz.) whole-wheat flour", "category": "baking"}, {"quantity": 2.0, "unit": "oz", "item": "cake flour", "notes": "1/2 c. (2 oz.) plain cake flour", "category": "baking"}, {"quantity": 1.75, "unit": "oz", "item": "brown sugar", "notes": "1/4 c. (1 3/4 oz.) dark brown sugar", "category": "baking"}, {"quantity": 1.5, "unit": "t", "item": "baking soda", "notes": "1 1/2 t. baking soda", "category": "baking"}, {"quantity": 1.5, "unit": "t", "item": "cream of tartar", "notes": "1 1/2 t. cream of tartar", "category": "spices and seasonings"}, {"quantity": 1.5, "unit": "t", "item": "salt", "notes": "1 1/2 t. salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "T", "item": "butter", "notes": "2 T. unsalted butter, softened plus 1 T. additional butter, melted, for brushing the top of the baked bread", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "c", "item": "walnuts", "notes": "1/2 c. walnuts, toasted and chopped", "category": "baking"}, {"quantity": 0.5, "unit": "c", "item": "apricots", "notes": "1/2 c. dried apricots, chopped", "category": "dried fruits"}]'::jsonb, '["In a medium bowl, combine 2 c. oats and buttermilk.", "Let sit for 1 hour.", "Adjust oven rack to the upper-middle position and preheat to 400 degrees f. In a large bowl, combine flours, remaining 1/2 c. oats, brown sugar, baking soda, cream of tartar and salt.", "Add in the 2 T. softened butter and using your fingertips, rub the butter into the flour until the texture resembles coarse crumbs.", "After the oats have soaked for an hour add the egg and mix well.", "Add this mix into the flour mixture along with the walnuts and apricots.", "Mix with a fork until it starts to come together (it still is going to be very loose). Turn the mix out onto a floured surface and knead a few times (around 12-14 times or so) to get everything to come together. Don''t overdo it with the kneading or the bread will be tough.", "Shape the dough into a round shape that is 6-inches in diameter and 2-inches high.", "Place on a large parchment-lined (or greased) baking sheet. Using a serrated knife, make a large X in the top of the loaf.", "Bake for 45- 50 minutes, until a skewer inserted in the center comes out clean. As soon as it is out of the oven, brush the crust with the melted butter.", "Let cool to room temperature before slicing."]'::jsonb, 'https://www.foodista.com/recipe/WT3FB3SD/oatmeal-apricot-walnut-soda-bread', 'https://img.spoonacular.com/recipes/653500-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('buckwheat-crepes', 'Buckwheat Crepes', 1, 0, 0, '{"calories": 374, "protein": 13.18, "carbs": 54.68, "fat": 13.98, "saturated_fat": 8.39, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 369.25, "potassium": null, "fiber": 6.29, "sugar": 13.23, "vitamin_a": null, "vitamin_c": 0, "calcium": 60.67, "iron": 3.31}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 0.75, "unit": "cup", "item": "water minus 2 tbsp & add 2", "notes": "3/4 cup kefir, cultured buttermilk or water minus 2 Tbsp & add 2", "category": "beverages"}, {"quantity": 2.0, "unit": "teaspoons", "item": "coconut oil", "notes": "2 teaspoons coconut oil (or your choice of oil)", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "buckwheat flour or", "notes": "1/2 cup buckwheat flour or 1/3 cup whole buckwheat", "category": "health foods"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg", "category": "milk, eggs, other dairy"}, {"quantity": 0.125, "unit": "teaspoon", "item": "salt", "notes": "1/8 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "teaspoons", "item": "honey", "notes": "2 teaspoons honey (for sweet crepes)", "category": "nut butters, jams, and honey"}, {"quantity": 0.25, "unit": "teaspoon", "item": "cinnamon", "notes": "1/4 teaspoon cinnamon (for sweet crepes)", "category": "spices and seasonings"}]'::jsonb, '["Combine kefir (or other), oil and grain in the blender. Blend for about 3 minutes on high or just 30 seconds if using flour. Cover blender and let batter stand overnight at room temp to break down the phytates. After soaking, add egg, salt, honey & cinnamon (if making sweet style). Blend till well mixed.", "Rub your cast iron pan with oil and get it nicely hot, but not smokey. Have a napkin ready for rubbing more in between crepes.", "Pour about 1/4 cup of batter into the hot pan and quickly tilt the pan to spread the batter evenly to the edges.", "Mix your batter each time before making each new crepe. Cook till edges are browned and loosen along the edges with a thin table knife or spatula. Turn over crepe and cook for about 30 seconds. Turn over onto a plate and keep it warm with a light towel covering it. Rub more oil on pan and continue till batter is used up.", "Top with Creamy Honey Cheese, your choice of fruit and syrup. For the blackberry syrup... I cooked the berries with a little water till they were mush, added arrowroot powder and boiled it gently till it thicken. Then I added honey and pour the mixture in my blender. Gave it a whirl till smooth and poured into a jar to serve. Simple, tart and sweet!"]'::jsonb, 'https://www.foodista.com/recipe/MVWCZNGC/buckwheat-crepes', 'https://img.spoonacular.com/recipes/636392-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('quiche-with-swiss-chard-and-mushroom', 'Quiche with Swiss Chard and Mushroom', 7, 0, 0, '{"calories": 392, "protein": 12.47, "carbs": 24.9, "fat": 27.27, "saturated_fat": 15.78, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 677.45, "potassium": null, "fiber": 1.32, "sugar": 2.38, "vitamin_a": null, "vitamin_c": 6.71, "calcium": 197.02, "iron": 2.2}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'lunch', 'main course', 'morning meal', 'brunch', 'main dish', 'breakfast', 'dinner', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 3.0, "unit": "large", "item": "pastured eggs", "notes": "3 large pastured organic eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "heavy cream", "notes": "1 cup heavy cream", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "ounces", "item": "crimini mushrooms", "notes": "4 ounces white or crimini mushrooms, chopped", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "onion", "notes": "1/4 cup finely chopped red onion or shallot", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "butter", "notes": "2 tablespoons butter", "category": "milk, eggs, other dairy"}, {"quantity": 5.0, "unit": "ounces", "item": "swiss chard leaves", "notes": "5 ounces Swiss chard leaves (no stems), chopped", "category": "produce"}, {"quantity": 7.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and black pepper to taste", "category": "spices and seasonings"}, {"quantity": 5.0, "unit": "ounces", "item": "prima donna aged gouda cheese", "notes": "5 ounces Prima Donna aged Gouda cheese, shredded", "category": "cheese"}, {"quantity": 1.0, "unit": "tablespoon", "item": "butter", "notes": "1 tablespoon butter, cut into small pieces", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "dash", "item": "nutmeg", "notes": "dash nutmeg", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "quiche pastry dough", "notes": "1 prepared pie crust or quiche pastry dough", "category": "frozen"}]'::jsonb, '["Preheat oven to 350 F.", "Beat room temperature eggs with heavy cream in a small bowl.", "Place pie crust in a deep-dish glass pie plate and crimp edges.", "Heat 2 tablespoons butter in a saute pan and cook mushroom ond shallot until browned.", "Season vegetables to taste with salt and pepper and stir in chopped chard leaves, cooking only long enough to allow them to wilt; cool mixture.", "Sprinkle about 2 ounces of the cheese in the bottom of the pie crust and spread vegetables over that, then top with remaining cheese.", "Pour the custard (cream and egg) mixture over all.", "Make sure the cheese and vegetables are covered or wet with the custard mixture.", "Dot with butter pieces and sprinkle with nutmeg.", "Bake quiche uncovered, in a preheated oven, for about 45 minutes or until domed and puffy and custard is set.", "Allow to sit undisturbed for about 15 minutes before slicing and serving."]'::jsonb, 'https://www.foodista.com/recipe/H5RCRWRL/quiche-with-swiss-chard-and-mushroom', 'https://img.spoonacular.com/recipes/657511-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('crepes-suzette', 'Crepes Suzette', 4, 0, 0, '{"calories": 618, "protein": 11.49, "carbs": 54.81, "fat": 39.95, "saturated_fat": 23.88, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 176.97, "potassium": null, "fiber": 1.39, "sugar": 18.38, "vitamin_a": null, "vitamin_c": 6.87, "calcium": 97.89, "iron": 2.87}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 4.0, "unit": "tablespoons", "item": "butter", "notes": "4 tablespoons butter", "category": "milk, eggs, other dairy"}, {"quantity": 3.0, "unit": "large", "item": "eggs", "notes": "3 large eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.5, "unit": "cups", "item": "flour", "notes": "1 1/2 cups all-purpose flour", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "lemon juice", "notes": "1/4 cup freshly squeezed lemon juice", "category": "produce"}, {"quantity": 0.5, "unit": "tablespoon", "item": "lemon zest", "notes": "1/2 tablespoon lemon zest", "category": "produce"}, {"quantity": 0.75, "unit": "cup", "item": "milk", "notes": "3/4 cup cold milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "pinch", "item": "salt", "notes": "pinch of salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tablespoon", "item": "sugar", "notes": "1 tablespoon sugar", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "butter", "notes": "1/2 cup unsalted butter", "category": "milk, eggs, other dairy"}, {"quantity": 0.75, "unit": "cup", "item": "water", "notes": "3/4 cup cold water", "category": "beverages"}, {"quantity": 0.25, "unit": "cup", "item": "sugar", "notes": "1/4 cup white sugar", "category": "baking"}]'::jsonb, '["Combine all liquid ingredients in a blender.", "Add the dry ingredients and 1/4 cup melted butter; mix on high.", "Let batter rest for 30 minutes.", "Heat a nonstick 10 inch skillet over medium high heat.", "Brush bottom and sides of pan with a bit of melted butter.Ladle 1/2 cup batter into skillet and swirl to coat bottom evenly. Cook until lightly browned, about 1-2 minutes. Using a spatula or your fingers, flip the crepe and cook the other side until lightly browned, about 30 seconds to 1 minute.", "Transfer crepes to a platter.", "Layer crepes over each other with parchment paper in between.If necessary, add more butter to the pan. Repeat with the rest of the batter.FOR THE SAUCE: Melt 1/4 cup butter in a skillet over LOW fire.", "Add the sugar and allow to melt. Be patient. Make sure that the heat is at its lowest.", "Add the lemon juice and mix well.", "Add the lemon zest.", "Add the crepes, 3-4 at a time and allow to cook in the sauce for 1 minute.", "Remove from the pan. Arrange on a plate and pour the sauce over the crepes and serve warm.Makes 8 crepes. Serving size is 2 crepes."]'::jsonb, 'https://www.foodista.com/recipe/KD8ZMRJ6/crepes-suzette', 'https://img.spoonacular.com/recipes/640767-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('spinach-ham-quiche', 'Spinach & Ham Quiche', 8, 0, 0, '{"calories": 304, "protein": 10.0, "carbs": 20.84, "fat": 20.2, "saturated_fat": 11.46, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 378.7, "potassium": null, "fiber": 1.07, "sugar": 1.04, "vitamin_a": null, "vitamin_c": 4.53, "calcium": 93.85, "iron": 1.96}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'antipasti', 'starter', 'morning meal', 'snack', 'brunch', 'appetizer', 'antipasto', 'breakfast', 'hor d''oeuvre', 'spoonacular', 'baking'], '[{"quantity": 100.0, "unit": "grams", "item": "butter", "notes": "100 grams Cold butter", "category": "milk, eggs, other dairy"}, {"quantity": 50.0, "unit": "grams", "item": "cheddar cheese", "notes": "50 grams Cheddar cheese- grated", "category": "cheese"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 Large eggs", "category": "milk, eggs, other dairy"}, {"quantity": 125.0, "unit": "grams", "item": "picnic ham", "notes": "125 grams Chicken or Picnic Ham (shredded)", "category": "meat"}, {"quantity": 5.0, "unit": "tablespoons", "item": "ice water", "notes": "5 tablespoons Ice water", "category": "beverages"}, {"quantity": 80.0, "unit": "milliliters", "item": "milk", "notes": "80 milliliters milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "dash", "item": "pepper", "notes": "dash of white pepper", "category": "spices and seasonings"}, {"quantity": 200.0, "unit": "grams", "item": "flour", "notes": "200 grams Plain flour", "category": "baking"}, {"quantity": 0.125, "unit": "teaspoon", "item": "salt", "notes": "1/8 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tablespoon", "item": "shallots", "notes": "1/2 tablespoon Shallots (sliced)", "category": "produce"}, {"quantity": 125.0, "unit": "grams", "item": "spinach", "notes": "125 grams Spinach (wash& drain well, shredded)", "category": "produce"}, {"quantity": 80.0, "unit": "milliliters", "item": "whipping cream", "notes": "80 milliliters Whipping cream", "category": "milk, eggs, other dairy"}]'::jsonb, '["With little oil, fry shallot till fragrant and golden brown.", "Add ham fry for a while and add spinach and fry till spinach cooked, dish up and set aside.Measure whipping cream and milk together in measuring cup (you can omit whipping cream and use all 160ml milk) add eggs, lightly beaten and pinch of salt, mix well.", "Spread ham spinach and cheddar cheese evenly over the bottom of the prepared tart pan, add a dash of pepper then gently pour egg mixture over it.", "Bake at preheated 180C for 40 mins and serve hot or warm."]'::jsonb, 'https://www.foodista.com/recipe/Z7KLXBR8/spinach-ham-quiche', 'https://img.spoonacular.com/recipes/661249-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('baked-swedish-pancake', 'Baked Swedish Pancake', 4, 0, 0, '{"calories": 524, "protein": 15.49, "carbs": 84.09, "fat": 14.85, "saturated_fat": 6.94, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 182.67, "potassium": null, "fiber": 6.1, "sugar": 48.23, "vitamin_a": null, "vitamin_c": 134.31, "calcium": 203.31, "iron": 3.41}'::jsonb, ARRAY['nordic', 'scandinavian', 'european', 'morning meal', 'brunch', 'breakfast', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "tbsp", "item": "butter", "notes": "Butter - 2 tbsp, softened", "category": "milk, eggs, other dairy"}, {"quantity": 6.0, "unit": "", "item": "eggs", "notes": "6 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "flour", "notes": "1 cup flour", "category": "baking"}, {"quantity": 4.0, "unit": "servings", "item": "jam", "notes": "Jam", "category": "nut butters, jams, and honey"}, {"quantity": 4.0, "unit": "servings", "item": "maple syrup", "notes": "Maple syrup", "category": "cereal"}, {"quantity": 1.0, "unit": "cup", "item": "milk", "notes": "1 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "servings", "item": "cranberry-orange relish", "notes": "Or cranberry-orange relish", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "powdered sugar", "notes": "Powdered sugar", "category": "baking"}, {"quantity": 1.0, "unit": "Dash", "item": "salt", "notes": "Dash of salt", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "servings", "item": "strawberries", "notes": "Fresh sliced strawberries", "category": "produce"}]'::jsonb, '["Heat oven to 400 degrees and place butter in 9 x 13 inch casserole to melt.", "Mix other ingredients into a batter and pour into hot pan.", "Bake 20 minutes. It will puff up and edges will curl in and brown when done.", "Cut in squares and serve with a variety of toppings. Makes 10 slices per pan.", "Serves 6 to 8."]'::jsonb, 'https://www.foodista.com/recipe/66J4MJKZ/baked-swedish-pancake', 'https://img.spoonacular.com/recipes/633830-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('irish-soda-bread-by-mommie-cooks', 'Irish Soda Bread By Mommie Cooks', 8, 0, 0, '{"calories": 380, "protein": 9.94, "carbs": 65.49, "fat": 8.45, "saturated_fat": 4.74, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 384.05, "potassium": null, "fiber": 2.11, "sugar": 8.89, "vitamin_a": null, "vitamin_c": 0, "calcium": 69.93, "iron": 3.63}'::jsonb, ARRAY['european', 'irish', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 4.75, "unit": "cups", "item": "flour", "notes": "4 3/4 cups Flour", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon Salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "baking soda", "notes": "1 teaspoon Baking Soda", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "caraway seeds", "notes": "1 teaspoon Caraway Seeds", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "tablespoons", "item": "honey", "notes": "3 tablespoons Honey", "category": "nut butters, jams, and honey"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 Egg", "category": "milk, eggs, other dairy"}, {"quantity": 1.5, "unit": "cups", "item": "buttermilk", "notes": "1 1/2 cups Buttermilk", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "tablespoons", "item": "butter", "notes": "4 tablespoons Butter", "category": "milk, eggs, other dairy"}]'::jsonb, '["To a bowl add together your dry ingredients; the flour, salt, and baking soda.", "Mix well.", "Add in the caraway seed and combine.", "Now add in the honey, egg, and buttermilk. Stir it up until a dough just begins to form.", "Add in the melted butter and knead dough until all ingredients are combined. Don''t overknead.", "Form into a ball and cut a few 1\" slits at the top.", "Place dough on a baking sheet and place in an oven preheated to 350 degrees for 50 min. to an hour.", "Test with a toothpick in the center to assure loaf is cooked completely."]'::jsonb, 'https://www.foodista.com/recipe/RNKM52BK/irish-soda-bread-by-mommie-cooks', 'https://img.spoonacular.com/recipes/648006-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('caramelised-onion-and-mushroom-quiche', 'Caramelised Onion and Mushroom Quiche', 4, 0, 0, '{"calories": 428, "protein": 13.75, "carbs": 29.25, "fat": 28.71, "saturated_fat": 12.19, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 622.19, "potassium": null, "fiber": 2.23, "sugar": 4.34, "vitamin_a": null, "vitamin_c": 5.44, "calcium": 243.13, "iron": 2.08}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'lunch', 'main course', 'morning meal', 'brunch', 'main dish', 'breakfast', 'dinner', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "", "item": "nine-inch pie shell", "notes": "1 nine-inch pie shell", "category": "refrigerated"}, {"quantity": 1.0, "unit": "tablespoon", "item": "olive oil", "notes": "1 tablespoon olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 2.0, "unit": "", "item": "onions", "notes": "2 white onions, sliced finely", "category": "produce"}, {"quantity": 3.0, "unit": "cloves", "item": "garlic", "notes": "3 cloves of garlic, sliced finely", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "chilli flakes", "notes": "1/2 teaspoon dried chilli flakes", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "box", "item": "mushrooms", "notes": "1 box mushrooms, sliced thick", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "thyme", "notes": "1 teaspoon thyme, dried", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 0.75, "unit": "cup", "item": "half and half cream", "notes": "3/4 cup half and half cream", "category": "milk, eggs, other dairy"}, {"quantity": 100.0, "unit": "grams", "item": "havarti cheese", "notes": "100 grams Havarti cheese, grated", "category": "cheese"}, {"quantity": 4.0, "unit": "servings", "item": "salt and pepper", "notes": "salt and pepper to taste", "category": "spices and seasonings"}]'::jsonb, '["Heat the oven to 400F. Dock the pie shell with a fork and bake for 10 to 15 minutes until lightly golden.", "In the meantime, heat the olive oil.", "Add the onions along with the garlic and chilli flakes and cook on high until the onion caramelise (about ten minutes).", "Now add the mushrooms and continue to cook on high so the mushrooms caramelise as well, about five minutes. Take off the fire, add the thyme and salt and pepper to taste.", "Beat the eggs in a large bowl with the cream and half the quantity of cheese.", "Add the onion-mushroom mixture and mix well.", "Place the pie shell on a cookie tray to catch any spillage.", "Pour the filling into the pie shell. Top the quiche with the remaining cheese.", "Drop the temperature to 375F and cook until the filling is set and golden.", "Serve when still warm from the oven."]'::jsonb, 'https://www.foodista.com/recipe/S7XHL4C5/caramelised-onion-and-mushroom-quiche', 'https://img.spoonacular.com/recipes/637042-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('leek-and-goats-cheese-quiche', 'Leek and goat’s cheese quiche', 6, 0, 0, '{"calories": 234, "protein": 11.85, "carbs": 13.21, "fat": 15.51, "saturated_fat": 8.82, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 404.05, "potassium": null, "fiber": 2.12, "sugar": 4.0, "vitamin_a": null, "vitamin_c": 9.93, "calcium": 135.06, "iron": 3.38}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'antipasti', 'starter', 'morning meal', 'snack', 'brunch', 'appetizer', 'antipasto', 'breakfast', 'hor d''oeuvre', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "", "item": "ready-rolled pastry", "notes": "1 ready-rolled pastry", "category": "cereal"}, {"quantity": 1.0, "unit": "lb", "item": "leeks", "notes": "1 lb leeks, sliced very thinly", "category": "produce"}, {"quantity": 2.0, "unit": "tbsp", "item": "butter", "notes": "2 tbsp butter", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "tbsp", "item": "tarragon leaves", "notes": "2 tbsp tarragon leaves, chopped", "category": "spices and seasonings"}, {"quantity": 6.0, "unit": "servings", "item": "nutmeg", "notes": "Freshly grated nutmeg", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "", "item": "eggs", "notes": "4 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 7.0, "unit": "oz", "item": "log goat''s cheese", "notes": "7 oz. log goat''s cheese, half chopped, the rest sliced", "category": "cheese"}, {"quantity": 6.0, "unit": "servings", "item": "salt and pepper", "notes": "Salt and pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "tbsp", "item": "almonds", "notes": "1 tbsp chopped almonds", "category": "nuts"}]'::jsonb, '["Preheat your oven to 200C/400F.Line your tin with baking parchment. Unroll the pastry and fit it into the tin.Line with more baking parchment, fill with baking beans and blind bake for 15-20 minutes.", "Remove the paper and beans and bake 5 minutes more to dry the base.Meanwhile, in a large non-stick frying pan, fry the leeks and tarragon in the butter until they have rendered their liquid and it has evaporated. Set aside to cool a little.Take the log of goat cheese and chop half and slice the other half.In a large bowl, whisk together the milk, eggs, nutmeg, salt &amp; pepper.", "Whisk until well mixed, then stir in the chopped goat cheese.Carefully tip the leek mixture into the pastry, arrange the sliced goat cheese on top and scatter over the chopped almonds, if using.", "Bake for 30-40 minutes, until golden and the filling is set.", "Serve warm, cold or at room temperature."]'::jsonb, 'https://www.foodista.com/recipe/6DV5HSP8/leek-and-goat-s-cheese-quiche', 'https://img.spoonacular.com/recipes/1096190-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('pepperoni-pizza-muffins', 'Pepperoni Pizza Muffins', 6, 0, 0, '{"calories": 304, "protein": 10.32, "carbs": 23.96, "fat": 18.72, "saturated_fat": 6.13, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 875.04, "potassium": null, "fiber": 1.21, "sugar": 5.23, "vitamin_a": null, "vitamin_c": 3.21, "calcium": 216.04, "iron": 1.89}'::jsonb, ARRAY['mediterranean', 'italian', 'european', 'morning meal', 'brunch', 'breakfast', 'spoonacular', 'dessert', 'baking'], '[{"quantity": 1.0, "unit": "cup", "item": "all purpose flour - 500ml", "notes": "cup All Purpose Flour – 2 500mL", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "baking power - 15 ml", "notes": "tablespoon Baking Power – 1 15 mL", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "baking soda - ½ 2ml", "notes": "teaspoon Baking Soda – ½ 2mL", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt - ½ 2ml", "notes": "teaspoon Salt – ½ 2mL", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "basil - ½ 2ml", "notes": "teaspoon Dried Basil – ½ 2mL", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "teaspoon", "item": "oregano - ½ 2ml", "notes": "teaspoon Dried Oregano – ½ 2mL", "category": "produce"}, {"quantity": 1.0, "unit": "teaspoon", "item": "garlic powder - ½ 2ml", "notes": "teaspoon Garlic Powder – ½ 2mL", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "Large Egg – 1", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "milk - 250ml", "notes": "cup Milk – 1 250mL", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "cooking oil - ¼ 60ml", "notes": "cup Cooking Oil – ¼ 60mL", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "tablespoon", "item": "granulated sugar - 30ml", "notes": "tablespoon Granulated Sugar – 2 30mL", "category": "baking"}, {"quantity": 0.5, "unit": "can", "item": "tomatoes", "notes": "Diced Tomatoes – 1/2 can", "category": "canned and jarred"}, {"quantity": 1.0, "unit": "cup", "item": "cheese - ⅔ 150ml", "notes": "cup Grated Cheese – ⅔ (or more!) 150mL", "category": "cheese"}, {"quantity": 1.0, "unit": "ounce", "item": "pepperoni stick - 2 ½ 70g", "notes": "ounce Pepperoni Stick – 2 ½ (or more!) 70g (cut up into squares)", "category": "meat"}]'::jsonb, '["Measure first 7 dry ingredients into a large bowl.  Stir.  Make a well in the centre.", "Combine the next 4 ingredients in a medium bowl.", "Add to well.", "Add tomato, cheese, and pepperoni to well.  Stir until just moistened.  Fill 12 greased muffin cups 3/4 full. (I had extra mix, so I made mini muffins too!)", "Bake in a 3750F (1900C) oven for about 20 minutes until a wooden pick inserted into the center of the muffin comes clean.", "Let stand in pan for about 5 minutes before removing to wire rack to cool."]'::jsonb, 'https://www.foodista.com/recipe/ZBB4CYW8/pepperoni-pizza-muffins', 'https://img.spoonacular.com/recipes/655698-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('zucchini-quiche-almond-flax-crust', 'Zucchini Quiche & Almond Flax Crust', 6, 0, 0, '{"calories": 388, "protein": 13.37, "carbs": 20.09, "fat": 29.95, "saturated_fat": 5.62, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 258.0, "potassium": null, "fiber": 5.43, "sugar": 2.35, "vitamin_a": null, "vitamin_c": 8.5, "calcium": 168.86, "iron": 2.76}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'lunch', 'main course', 'morning meal', 'brunch', 'main dish', 'breakfast', 'dinner', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.3333334, "unit": "cups", "item": "almond meal", "notes": "1 1/3 cups almond meal", "category": "health foods"}, {"quantity": 1.0, "unit": "tsp", "item": "thyme", "notes": "1 tsp dried thyme (or any other dried herb)", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "", "item": "eggs", "notes": "3 Eggs", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cup", "item": "golden flaxseed meal", "notes": "1/4 cup golden flaxseed meal", "category": "health foods"}, {"quantity": 0.25, "unit": "cup", "item": "milk", "notes": "1/4 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "Tbs", "item": "milk", "notes": "2 Tbs milk (I used 1% milk)", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "Tbs", "item": "olive oil", "notes": "2 Tbs olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.25, "unit": "cup", "item": "orange pepper", "notes": "1/4 cup chopped orange pepper (or any other bell pepper)", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "oregano", "notes": "1 tsp dried oregano (or any other dried herb)", "category": "produce"}, {"quantity": 3.0, "unit": "Tbs", "item": "parmesan cheese", "notes": "3 Tbs freshly grated parmesan cheese", "category": "cheese"}, {"quantity": 6.0, "unit": "servings", "item": "crust", "notes": "Crust", "category": "refrigerated"}, {"quantity": 3.0, "unit": "Tbs", "item": "onion", "notes": "3 Tbs chopped red onion", "category": "produce"}, {"quantity": 0.125, "unit": "teaspoon", "item": "salt", "notes": "1/8 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.33333334, "unit": "cup", "item": "mozzarella cheese", "notes": "1/3 cup shredded mozzarella cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "small", "item": "zucchini", "notes": "1 small zucchini (gently run a vegetable peeler the length of the zucchini to make thin “ribbons”)", "category": "frozen"}]'::jsonb, '["Preheat oven to 375F (~190C). Grease an 8-inch pie dish with olive oil or cooking spray.In a medium-sized bowl, mix all of the ingredients of the crust together until a crumbly dough forms.", "Pour all of the dough into the pie dish.", "Spread and flatten the dough on the bottom and up the sides of the pie dish. The dough reached about halfway up the sides of the pie dish for me.Chop off the ends of the zucchini and spiralize it using Blade B. Give the zucchini noodles several chops. This will make it easier to cut and serve the quiche later. Chop the part of the zucchini that did not get spiralized into small pieces. NOTE: If you do not own a spiralizer, simply grate the zucchini or create zucchini ribbons with a vegetable peeler.", "Mix all the vegetables and cheese, and place them into the pie dish. I made sure that some of the zucchini noodles were on top of the quiche, but that is just for presentation.", "Mix the whisked eggs, milk, thyme, and salt in a small bowl. Fill the pie dish with this egg mixture.", "Bake the quiche for 30-40 minutes or until the eggs are cooked through and the quiche is browned and firm to touch.", "Let the quiche cool for about 10 minutes before serving.Refrigerate any leftovers in an airtight container."]'::jsonb, 'https://www.foodista.com/recipe/X4RDRKMQ/zucchini-quiche-almond-flax-crust', 'https://img.spoonacular.com/recipes/665776-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('mushroom-gruyere-quiche', 'Mushroom & Gruyere Quiche', 10, 0, 0, '{"calories": 255, "protein": 10.5, "carbs": 15.58, "fat": 17.25, "saturated_fat": 8.31, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 225.9, "potassium": null, "fiber": 1.59, "sugar": 3.3, "vitamin_a": null, "vitamin_c": 4.06, "calcium": 188.39, "iron": 1.39}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'antipasti', 'starter', 'morning meal', 'snack', 'brunch', 'appetizer', 'antipasto', 'breakfast', 'hor d''oeuvre', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "teaspoon", "item": "pepper", "notes": "1 teaspoon black pepper", "category": "spices and seasonings"}, {"quantity": 3.0, "unit": "large", "item": "eggs", "notes": "3 large eggs", "category": "milk, eggs, other dairy"}, {"quantity": 3.0, "unit": "tablespoons", "item": "basil", "notes": "3 tablespoons chopped fresh basil", "category": "produce"}, {"quantity": 2.0, "unit": "teaspoons", "item": "thyme", "notes": "2 teaspoons chopped fresh thyme", "category": "produce"}, {"quantity": 2.0, "unit": "large cloves", "item": "garlic", "notes": "2 large cloves garlic, minced", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "gruyere", "notes": "1 cup grated Gruyere", "category": "cheese"}, {"quantity": 1.25, "unit": "cups", "item": "half-and-half", "notes": "1 1/4 cups half-and-half", "category": "milk, eggs, other dairy"}, {"quantity": 1.5, "unit": "pounds", "item": "mushrooms", "notes": "1 1/2 pounds assorted mushrooms, wiped clean and sliced", "category": "produce"}, {"quantity": 10.0, "unit": "servings", "item": "pie crust", "notes": "Store bought pie crust", "category": "refrigerated"}, {"quantity": 10.0, "unit": "servings", "item": "salt", "notes": "salt, rice wine vinegar, soy sauce,<", "category": "ethnic foods"}, {"quantity": 2.0, "unit": "", "item": "shallots", "notes": "2 shallots, chopped", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "tomatoes", "notes": "1/2 cup diced tomatoes", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "butter", "notes": "2 tablespoons unsalted butter", "category": "milk, eggs, other dairy"}]'::jsonb, '["Preheat the oven to 375 degrees F.In a large skillet melt the butter over medium-high heat.", "Add the mushroom, cook, stirring, until liquid is rendered.", "Add shallots and garlic.  Cook for a few minutes.", "Add the tomatoes, basil, and thyme and season lightly with salt and pepper.Cook, stirring, for 1 minute.", "Remove from the heat and let cool.In a bowl, beat the eggs and half-and-half together.", "Add the salt, pepper, and grated Gruyere.Spoon the vegetable mixture into the prepared piecrust, pour in the egg mixture.", "Bake for 25 to 30 minutes until set.", "Remove from the oven and let cool for 30 minutes before serving."]'::jsonb, 'https://www.foodista.com/recipe/7YD4F7D6/mushroom-gruyere-quiche', 'https://img.spoonacular.com/recipes/652605-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('apple-cinnamon-quiche', 'Apple Cinnamon Quiche', 6, 0, 0, '{"calories": 607, "protein": 16.65, "carbs": 27.26, "fat": 48.79, "saturated_fat": 26.71, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 457.16, "potassium": null, "fiber": 2.34, "sugar": 10.3, "vitamin_a": null, "vitamin_c": 3.16, "calcium": 338.68, "iron": 1.54}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'lunch', 'main course', 'morning meal', 'brunch', 'main dish', 'breakfast', 'dinner', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "", "item": "apples", "notes": "2 apples, peeled and sliced", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "butter", "notes": "2 tablespoons butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "sugar", "notes": "1 tablespoon white sugar", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "cinnamon", "notes": "1 teaspoon cinnamon", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "unbaked 0-inch pie shell", "notes": "1 unbaked 10-inch pie shell", "category": "refrigerated"}, {"quantity": 8.0, "unit": "ounces", "item": "cheddar cheese", "notes": "8 ounces Cheddar cheese, grated", "category": "cheese"}, {"quantity": 4.0, "unit": "large", "item": "eggs", "notes": "4 large eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.5, "unit": "cups", "item": "whipping cream", "notes": "1 1/2 cups whipping cream", "category": "milk, eggs, other dairy"}]'::jsonb, '["Preheat the oven to 375 degrees Fahrenheit.In a large skillet, saute the apples in the butter over medium heat for 5 minutes.", "Transfer the apples into a large bowl, and toss with the sugar and cinnamon until well coated.", "Layer the apples in the pastry shell.", "Sprinkle the cheese evenly over the apple mixture.In a medium bowl, lightly whisk together the eggs and whipping cream until well blended.", "Pour the egg mixture over the apples and cheese.", "Bake for 35 minutes, or until set."]'::jsonb, 'https://www.foodista.com/recipe/FB6ZK6JM/apple-cinnamon-quiche', 'https://img.spoonacular.com/recipes/1096246-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('make-ahead-quiche', 'Make Ahead Quiche', 8, 0, 0, '{"calories": 310, "protein": 13.51, "carbs": 15.02, "fat": 21.75, "saturated_fat": 10.39, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 483.82, "potassium": null, "fiber": 0.74, "sugar": 1.52, "vitamin_a": null, "vitamin_c": 2.49, "calcium": 257.66, "iron": 1.33}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'lunch', 'main course', 'morning meal', 'brunch', 'main dish', 'breakfast', 'dinner', 'spoonacular', 'baking'], '[{"quantity": 1.0, "unit": "9-inch", "item": "unbaked pie crust", "notes": "1 (9 inch) unbaked pie crust", "category": "refrigerated"}, {"quantity": 1.0, "unit": "cup", "item": "cheddar cheese", "notes": "1 cup shredded cheddar cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "cup", "item": "monterrey jack cheese", "notes": "1 cup shredded Monterrey Jack cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "tablespoon", "item": "flour", "notes": "1 tablespoon flour", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "ham", "notes": "1/2 cup cooked ham, diced", "category": "meat"}, {"quantity": 4.0, "unit": "", "item": "eggs", "notes": "4 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "half and half", "notes": "1 cup half and half", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "", "item": "green onions", "notes": "2 green onions, chopped", "category": "produce"}, {"quantity": 0.25, "unit": "teaspoon", "item": "salt", "notes": "1/4 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "teaspoon", "item": "ground mustard", "notes": "1/4 teaspoon ground dry mustard", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "Dash", "item": "pepper", "notes": "Dash of pepper", "category": "spices and seasonings"}]'::jsonb, '["In a medium bowl, toss the flour with the grated cheese.  Evenly spread the cheese over the bottom of the pie crust.  Top the cheese with the diced ham.  In a medium bowl, whisk together eggs, half and half, salt, pepper and dry mustard.  Stir in the green onions.", "Pour the egg mixture over the ham and cheese.", "Cover the unbaked quiche with plastic wrap, then with foil, sealing the edges well.", "Place the prepared quiche in the freezer.  When ready to bake, preheat the oven to 400 degrees.  Do not thaw the quiche!", "Remove the foil and plastic wrap.", "Place the foil around the edges of the crust to prevent burning.", "Place the frozen quiche in the oven and bake for about 1 hour, or until the filling is set and the crust is golden brown.", "To cook the quiche immediately (without freezing first), preheat the oven to 350 degrees and bake for 45 minutes to 1 hour."]'::jsonb, 'https://www.foodista.com/recipe/SLFFTBGD/make-ahead-quiche', 'https://img.spoonacular.com/recipes/650650-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('havarti-and-asparagus-quiche', 'Havarti and Asparagus Quiche', 8, 0, 0, '{"calories": 536, "protein": 11.73, "carbs": 41.7, "fat": 36.94, "saturated_fat": 23.06, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 398.16, "potassium": null, "fiber": 0.86, "sugar": 26.23, "vitamin_a": null, "vitamin_c": 1.22, "calcium": 217.19, "iron": 1.53}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'antipasti', 'starter', 'morning meal', 'snack', 'brunch', 'appetizer', 'antipasto', 'breakfast', 'hor d''oeuvre', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 8.0, "unit": "stalks", "item": "asparagus", "notes": "8 stalks asparagus", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "cream", "notes": "1 cup cream", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 Eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.25, "unit": "cups", "item": "flour", "notes": "1 1/4 cups Flour", "category": "baking"}, {"quantity": 0.5, "unit": "pound", "item": "havarti", "notes": "1/2 pound Havarti with Dill Cheese (approximately ½ lb.)", "category": "cheese"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon Salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "sugar", "notes": "1 cup Sugar", "category": "baking"}, {"quantity": 0.75, "unit": "cup", "item": "butter", "notes": "3/4 cup cold, unsalted butter cut into small cubes", "category": "milk, eggs, other dairy"}, {"quantity": 8.0, "unit": "c", "item": "water", "notes": "2 quarts (8 c.) water", "category": "beverages"}]'::jsonb, '["In the bowl of a food processor, combine flour, salt, and sugar.", "Add butter and pulse until the mixture resembles the size of small peas.", "Add the first 5 tablespoons of water, one at a time.Check consistency - if the mixture holds together when pinched, the crust is perfect  dont add any more water.If, however, the crust still crumbles apart and wont stay together when pinched, that means it wont stay together while rolling either; go ahead and add the last tablespoon of water one teaspoon at a time, rechecking the consistency between each teaspoon.The exact amount of water you need will depend on the amount of humidity in the air and therefore in the flour.Once finished, turn the dough out onto a piece of plastic wrap.Form the dough into a disk, and refrigerate 30 minutes before rolling it out.You want that flour to relax and the butter to be nice and cold  that will ensure you have a nice flaky crust.Meanwhile, boil a pot of water large enough to fit the stalks of asparagus.Trim the ends of your asparagus making sure they will fit nicely into your quiche pan, arranged like the spokes in a bicycle wheel with the ends touching in the middle.", "Place in boiling water, and blanch for 2-3 minutes.", "Remove from boiling water and place in an ice bath to stop the cooking and keep the color nice and vibrant green.Set aside.Preheat oven to 350 degrees.On a lightly floured surface, roll the dough out into a circle a few inches larger than your quiche or pie pan.Fold the dough back up over the rolling pin if needed, to gently lift the crust into the dish.Once the dough is neatly into the pan, make sure it is smoothly tucked into the corners.Trim excess crust from the edges leaving about a 1 border.Fold the excess dough under itself, making sure not to fold it over the edge of the pan, to ensure a nice even border.Crimp the dough between your fingers to make little pinches.Poke a few fork holes in it to allow the steam to escape, this will prevent a soggy bottom crust.Blind bake the crust for 5 minutes.This will prevent all of the custard from getting absorbed into the crust making it soggy.", "Remove crust from oven and sprinkle with Havarti with Dill cheese.  Set aside.Increase oven temperature to 375 degrees.In a large bowl, combine eggs, heavy cream, and milk and whisk thoroughly.", "Pour egg mixture gently over the cheese mixture.", "Place asparagus stalks, tips pointing outwards into a spoke pattern like on a bicycle wheel, making sure the ends come together in the middle.", "Bake 40 minutes.Check to make sure the crust isnt getting too brown.If it is, loosely drape a piece of foil over the top, making sure you dont lay it on the actual custard mixture in the middle.", "Bake 10-12 minutes longer.To test doneness, slide a butter knife under the edge of one of the asparagus stalks.The knife should come out clean.It should be moist  after all the quiche is moist, but it should be free of egg mixture.If not, put it back in the oven with your tent foil on top for 3-4 more minutes."]'::jsonb, 'https://www.foodista.com/recipe/WVNLTYYJ/havarti-and-asparagus-quiche', 'https://img.spoonacular.com/recipes/646348-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('baileys-irish-cream-crepes-with-creme', 'Bailey''s Irish Cream Crepes With Creme', 4, 0, 0, '{"calories": 474, "protein": 7.34, "carbs": 54.91, "fat": 24.26, "saturated_fat": 14.17, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 754.56, "potassium": null, "fiber": 3.28, "sugar": 40.15, "vitamin_a": null, "vitamin_c": 11.07, "calcium": 113.78, "iron": 0.76}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'gluten free', 'spoonacular', 'vegetarian'], '[{"quantity": 4.0, "unit": "servings", "item": "bananas", "notes": "sliced bananas", "category": "produce"}, {"quantity": 4.0, "unit": "servings", "item": "brown sugar", "notes": "brown sugar", "category": "baking"}, {"quantity": 70.0, "unit": "grams", "item": "browned butter", "notes": "70 grams (a bit less than 5 tablespoons) browned butter", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "servings", "item": "creme fraiche", "notes": "creme fraiche (or sour cream)", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 100.0, "unit": "milliliters", "item": "bailey''s irish cream", "notes": "100 milliliters (a bit less than ½ cup) Bailey''s Irish Cream (or milk, if you prefer)", "category": "alcoholic beverages"}, {"quantity": 1.0, "unit": "cup", "item": "milk", "notes": "250 milliliters (1 cup) milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "teaspoon", "item": "salt", "notes": "1 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "cup", "item": "sugar", "notes": "1/4 cup sugar", "category": "baking"}]'::jsonb, '["Brown your butter by adding slices of butter to a heavy bottomed saucepan. One melted, whisk it frequently until you see small brown specks begin to form at the bottom of the pan. The butter should have a nutty aroma.", "Remove it from the pan to prevent further cooking.", "Mix the browned butter with the flour, salt, sugar, eggs, milk and Bailey''s. Using an immersion blender, blend the mixture until completely smooth.", "Let the mixture rest for 1/2 hour.Butter a non-stick frying pan and heat over medium heat. Using a ladle, spoon in the batter and quickly pick up the pan and swish it around so that the entire pan bottom is covered with a very thin layer of batter.When the underside is golden, use your fingers or a spatula to flip the crepe over to cook the other side.", "Serve with sliced bananas, creme fraiche (or sour cream) and brown sugar. We also had Dulce de Leche on the table!"]'::jsonb, 'https://www.foodista.com/recipe/SGM537DK/baileys-irish-cream-crepes-with-creme', 'https://img.spoonacular.com/recipes/633399-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('simple-whole-wheat-crepes', 'Simple Whole Wheat Crepes', 4, 0, 0, '{"calories": 272, "protein": 10.25, "carbs": 27.46, "fat": 14.11, "saturated_fat": 7.56, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 147.69, "potassium": null, "fiber": 3.0, "sugar": 6.06, "vitamin_a": null, "vitamin_c": 0, "calcium": 121.49, "iron": 1.29}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 3.0, "unit": "Tablespoons", "item": "butter", "notes": "3 Tablespoons butter, melted", "category": "milk, eggs, other dairy"}, {"quantity": 3.0, "unit": "", "item": "eggs", "notes": "3 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "maple syrup", "notes": "1 Tablespoon maple syrup (optional)", "category": "cereal"}, {"quantity": 1.0, "unit": "cup", "item": "milk", "notes": "1 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "pinch", "item": "sea salt", "notes": "pinch of sea salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "flour", "notes": "1 cup white whole wheat flour", "category": "baking"}]'::jsonb, '["Place all ingredients in a blender and mix until smooth. The batter should be thin.", "Let it sit at least 30 minutes—or even overnight.When it comes time to cook your crêpes you can do it the traditional way, in a crêpe pan, or you can use an electric crêpe maker."]'::jsonb, 'https://fullbellysisters.blogspot.com/2014/11/simple-whole-wheat-crepes.html', 'https://img.spoonacular.com/recipes/716407-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('lemon-rum-crêpes', 'Lemon Rum Crêpes', 6, 0, 0, '{"calories": 332, "protein": 6.34, "carbs": 36.31, "fat": 17.18, "saturated_fat": 10.26, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 276.79, "potassium": null, "fiber": 1.34, "sugar": 4.34, "vitamin_a": null, "vitamin_c": 2.58, "calcium": 24.25, "iron": 2.21}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "cups", "item": "water", "notes": "2 cups water", "category": "beverages"}, {"quantity": 1.0, "unit": "Tbs", "item": "rum", "notes": "1 Tbs dark rum", "category": "alcoholic beverages"}, {"quantity": 1.0, "unit": "tsp", "item": "vanilla extract", "notes": "1 tsp vanilla extract", "category": "baking"}, {"quantity": 2.0, "unit": "Tbs", "item": "sugar", "notes": "2 Tbs sugar", "category": "baking"}, {"quantity": 0.33333334, "unit": "tsp", "item": "salt", "notes": "1/3 tsp salt", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "cups", "item": "flour", "notes": "2 cups flour", "category": "baking"}, {"quantity": 8.0, "unit": "Tbs", "item": "butter", "notes": "8 Tbs melted butter or more", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "", "item": "lemon zest", "notes": "Finely grated zest of 2 lemons", "category": "produce"}]'::jsonb, '["For the batter, whisk together the eggs, water, rum, vanilla, sugar and salt in a large bowl, until well blended.Sift the flour, a bit at a time, whisking each addition until smooth.", "Add in half the melted butter and the lemon zest, whisking until the batter has slightly thickened, with the consistency of melted ice cream.", "Put the remaining butter in a small cup and keep it warm.", "Heat the crepe pan or a nonstick skillet over medium heat until quite hot. Lightly brush with melted butter. Ladle in a scant  cup of batter, tilt and swirl so it coats the bottom. Lower the heat and cook the pancake until underside is golden brown, 2 to 3 minutes. Flip it over with a spatula and fry for a half minute or longer, until the second side is lightly browned. Slide the crepe out of skillet and repeat with the remaining batter. (Coat pan with butter as needed.)Fold the crepes and squeeze some lemon juice over them, sprinkle with granulated sugar or cinnamon or spread with a filling of your choice."]'::jsonb, 'https://www.foodista.com/recipe/CVV8QJ6Q/shrove-tuesday-cr-pes', 'https://img.spoonacular.com/recipes/1095797-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('classic-custard-quiche-lorraine', 'Classic Custard Quiche Lorraine', 8, 0, 0, '{"calories": 352, "protein": 9.96, "carbs": 15.4, "fat": 28.06, "saturated_fat": 14.22, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 259.34, "potassium": null, "fiber": 0.83, "sugar": 2.91, "vitamin_a": null, "vitamin_c": 1.4, "calcium": 161.67, "iron": 1.14}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'antipasti', 'starter', 'morning meal', 'snack', 'brunch', 'appetizer', 'antipasto', 'breakfast', 'hor d''oeuvre', 'spoonacular', 'baking'], '[{"quantity": 3.0, "unit": "slices", "item": "bacon", "notes": "3 slices thick bacon", "category": "meat"}, {"quantity": 0.25, "unit": "teaspoon", "item": "tarragon", "notes": "1/4 teaspoon dried tarragon", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "", "item": "eggs", "notes": "4 Eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "flour", "notes": "1 tablespoon all-purpose flour", "category": "baking"}, {"quantity": 0.25, "unit": "teaspoon", "item": "ground pepper", "notes": "1/4 teaspoon ground white pepper", "category": "spices and seasonings"}, {"quantity": 0.75, "unit": "cup", "item": "milk", "notes": "3/4 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.75, "unit": "cup", "item": "onion", "notes": "3/4 cup minced onion", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "parmesan cheese", "notes": "1/4 cup grated Parmesan cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "", "item": "pie crust dough", "notes": "1 refrigerated pie crust dough (1/2 of a 15-ounce box), at room temperature", "category": "refrigerated"}, {"quantity": 0.5, "unit": "cup", "item": "swiss cheese", "notes": "1/2 cup grated Swiss cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "pinch", "item": "thyme and nutmeg", "notes": "Pinch each of dried thyme and nutmeg", "category": "produce"}, {"quantity": 1.25, "unit": "cups", "item": "whipping cream", "notes": "1 1/4 cups heavy or whipping cream", "category": "milk, eggs, other dairy"}]'::jsonb, '["Preheat oven to 325 degrees F.", "Place pie crust dough onto a lightly floured surface and unroll it.Using a rolling pin, roll crust into a circle about 13 inches in diameter.", "Place crust into a spring form pan and fold the edge of the crust to the outside of the pan, pressing it into the sides of pan. (This is so crust doesnt shrink in baking.)Prick crust all over bottom and sides with a fork.", "Bake, uncovered, until crust begins to brown just slightly, about 7 minutes.", "Remove from oven and set aside.While crust bakes, cook bacon in a medium skillet over medium heat until very crisp and brown on both sides, about 8 to 10 minutes.While bacon cooks, peel and mince onion, and set aside.When bacon is done, remove to a plate lined with paper towels, blot any extra fat, and set aside.", "Remove all but about 1 teaspoon of the fat in the skillet, add onion and cook until translucent, about 4 to 5 minutes.Scatter onions and half of cheeses evenly over crust bottom. Set aside.Finely chop bacon, and scatter half of it over cheese in crust. Set remaining bacon and cheese aside.Break eggs into a blender container.", "Add cream, milk, flour, pepper, tarragon, thyme and nutmeg, and process on high until very foamy, about 1 minute.", "Pour half of egg mixture into pie crust.Scatter in remaining bacon and cheese.Top with remaining egg mixture.", "Bake, uncovered, until top is light brown and quiche is just set (center should still jiggle very slightly) 55 to 60 minutes.", "Remove from oven and cool at least 15 minutes before removing sides of spring form pan.Quiche may be cooled to room temperature and frozen, still in pan and covered tightly with both plastic wrap and foil, for up to 2 weeks. Defrost in refrigerator 2 days, bring back to room temperature and reheat 5 minutes, uncovered, in a 300-degree oven before preparing to serve. Alternately, quiche can be refrigerated for up to two days. Follow directions above for reheating.To serve, cut quiche crust away from the spring form pans side with a serrated knife, leaving about a 1-inch crust side above filling of the quiche.", "Remove sides of spring form pan, slice and serve."]'::jsonb, 'https://www.foodista.com/recipe/LR7FP65S/classic-custard-quiche-lorraine', 'https://img.spoonacular.com/recipes/639590-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('roasted-tomato-and-garlic-quiche', 'Roasted Tomato and Garlic Quiche', 8, 0, 0, '{"calories": 271, "protein": 11.03, "carbs": 14.54, "fat": 18.86, "saturated_fat": 9.2, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 579.16, "potassium": null, "fiber": 0.95, "sugar": 2.46, "vitamin_a": null, "vitamin_c": 8.87, "calcium": 179.81, "iron": 1.55}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'antipasti', 'starter', 'morning meal', 'snack', 'brunch', 'appetizer', 'antipasto', 'breakfast', 'hor d''oeuvre', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 10.0, "unit": "oz", "item": "cherry tomatoes - cut tomatoes in half", "notes": "1 10oz package of cherry tomatoes – cut tomatoes in half", "category": "produce"}, {"quantity": 6.0, "unit": "cloves", "item": "garlic - peel and cut cloves in half", "notes": "6 cloves garlic – peel and cut cloves in half", "category": "produce"}, {"quantity": 1.0, "unit": "tsp", "item": "basil", "notes": "1 tsp dried basil", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "salt", "notes": "½ tsp salt", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "tsp", "item": "pepper", "notes": "¼ tsp black pepper", "category": "spices and seasonings"}, {"quantity": 0.25, "unit": "tsp", "item": "chipotle pepper", "notes": "¼ tsp Chipotle pepper (if not available may use same amount of hot pepper flakes).", "category": "ethnic foods"}, {"quantity": 1.0, "unit": "", "item": "pie crust", "notes": "1 refrigerated pie crust (the kind near the canned biscuits in the grocery – not the prefrozen kind)", "category": "refrigerated"}, {"quantity": 1.5, "unit": "Cups", "item": "mozzarella cheese", "notes": "1 ½ Cups Shredded mozzarella Cheese (may use preshredded or fresh if necessary).", "category": "cheese"}, {"quantity": 0.5, "unit": "Cup", "item": "heavy cream", "notes": "½ Cup heavy Cream", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "Cup", "item": "milk", "notes": "½ Cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "large", "item": "eggs", "notes": "4 large eggs – beaten", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "tsp", "item": "salt and pepper", "notes": "½ tsp each of salt and pepper", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "Tbs", "item": "parmesan cheese", "notes": "2 Tbs Parmesan cheese", "category": "cheese"}]'::jsonb, '["Preheat oven to 350", "In a small bowl mix the tomatoes, garlic, dried basil, salt, black pepper and chipotle pepper, toss well and spread out onto a metal baking dish.", "Bake for 30 mins. The tomatoes will be shriveled and the garlic should be tender when done. There may be slight darkening on the garlic cloves - but they should not be burnt. If they are burnt there will be a bitter taste", "Remove tomatoes and garlic from the oven and allow to cool enough to touch. Set oven temp to 37", "Press the pie shell into a deep dish pie plate. Flute the edges of the pie crust", "Using a fork, poke holes into the bottom crust.", "Sprinkle half of the shredded mozzarella into the bottom of the pie crust.", "Cover with the tomatoe/garlic mixture and top with the remaining mozzarella cheese.", "In a small bowl, mix the half and half, salt and pepper and the beaten eggs together.", "Pour this mixture over the ingredients in the pie shell.", "Sprinkle top with Parmesan cheese.", "Bake 35-40 minutes until the center is no longer loose when the edges of the pie plate are gently shaken and the center no longer looks wet", "Allow the quiche to sit on the counter top for 10 minutes before cutting (this allows the quiche to rest and keeps the insides from being too runny)"]'::jsonb, 'https://www.foodista.com/recipe/XVT5HZGH/roasted-tomato-and-garlic-quiche', 'https://img.spoonacular.com/recipes/658681-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vegetable-quiche-made-with-fresh-tomatoes-spinach-basil-and-goat-cheese', 'Vegetable Quiche Made With Fresh Tomatoes, Spinach, Basil and Goat Cheese', 8, 0, 0, '{"calories": 68, "protein": 4.77, "carbs": 2.63, "fat": 4.44, "saturated_fat": 2.61, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 269.85, "potassium": null, "fiber": 0.53, "sugar": 1.28, "vitamin_a": null, "vitamin_c": 5.01, "calcium": 45.43, "iron": 0.75}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'antipasti', 'starter', 'morning meal', 'snack', 'brunch', 'appetizer', 'antipasto', 'breakfast', 'hor d''oeuvre', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs, lightly beaten", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "tablespoon", "item": "flour", "notes": "1 tablespoon of flour (I used Spelt)", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "basil", "notes": "1 tablespoon chopped fresh basil", "category": "produce"}, {"quantity": 0.5, "unit": "cup", "item": "goat cheese", "notes": "1/2 cup goat cheese", "category": "cheese"}, {"quantity": 0.33333334, "unit": "cup", "item": "green onion", "notes": "1/3 cup slices green onion", "category": "produce"}, {"quantity": 1.0, "unit": "pinch", "item": "ground nutmeg", "notes": "pinch of ground nutmeg", "category": "spices and seasonings"}, {"quantity": 0.125, "unit": "teaspoon", "item": "ground pepper", "notes": "1/8 teaspoon ground white pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "kale", "notes": "1 cup spinach or kale, leaves only and chopped (no stems)", "category": "produce"}, {"quantity": 0.25, "unit": "cup", "item": "milk", "notes": "1/4 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "10-inch", "item": "pie crust", "notes": "1 10-inch pie crust", "category": "refrigerated"}, {"quantity": 8.0, "unit": "servings", "item": "salt", "notes": "Salt to taste", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "small", "item": "tomatoes", "notes": "2 small tomatoes, finely chopped", "category": "produce"}]'::jsonb, '["Preheat the oven to 450 degrees F for pie crust. Line a 9-inch pie plate with pastry.  Cover the bottom &amp; top of the pie crust with aluminum foil and bake 8 minutes to allow the crust to cook.", "Remove foil and bake another 4 minutes. While baking the crust, whisk together the milk, salt, pepper, nutmeg, flour and eggs in a bowl. Then add the tomatoes, spinach or kale, onion, basil, and goat cheese.", "Remove from the crust from the oven. The crust should be light brown on the edges.Reduce oven temperature to 325 degrees F. Now, add the milk, vegetable, and cheese mixture to the cooked crust. Cover the edges of the pie crust with foil.", "Bake in the oven until the middle of the quiche is set, about 50-60 minutes.", "Let set 10 minutes."]'::jsonb, 'https://www.foodista.com/recipe/8KLLFP2C/vegetable-quiche-made-with-fresh-tomatoes-spinach-basil-and-goat-cheese', 'https://img.spoonacular.com/recipes/664585-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('caprese-quick-bread', 'Caprese Quick Bread', 12, 0, 0, '{"calories": 117, "protein": 5.47, "carbs": 14.16, "fat": 4.64, "saturated_fat": 2.01, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 284.23, "potassium": null, "fiber": 1.37, "sugar": 2.03, "vitamin_a": null, "vitamin_c": 0.9, "calcium": 151.93, "iron": 1.27}'::jsonb, ARRAY['mediterranean', 'italian', 'european', 'morning meal', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 0.75, "unit": "cups", "item": "flour", "notes": "¾ cups All-purpose Flour", "category": "baking"}, {"quantity": 0.75, "unit": "cups", "item": "flour", "notes": "¾ cups White Whole Wheat Flour", "category": "baking"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "baking powder", "notes": "1 Tablespoon Baking Powder", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoons", "item": "salt", "notes": "½ teaspoons Salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "basil", "notes": "1 Tablespoon Dried Basil", "category": "spices and seasonings"}, {"quantity": 4.0, "unit": "ounces", "item": "weight lite mozzarella cheese", "notes": "4 ounces, weight Lite Mozzarella Cheese, Shredded", "category": "cheese"}, {"quantity": 1.0, "unit": "Tablespoon", "item": "olive oil", "notes": "1 Tablespoon Olive Oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 whole Egg, Lightly Beaten", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "non-fat milk", "notes": "1 cup Non-fat Milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "cups", "item": "sundried tomatoes", "notes": "¼ cups Sundried Tomatoes, Diced, Not Oil Packed", "category": "canned and jarred"}, {"quantity": 0.75, "unit": "Tablespoons", "item": "butter", "notes": "¾ Tablespoons Butter, Melted", "category": "milk, eggs, other dairy"}]'::jsonb, '["Heat oven to 35", "Spray a 9x5x3 loaf pan or two mini bread pans with cooking spray.", "Stir together flours,cheese, baking powder, basil and salt in medium bowl.", "Add olive oil, egg and milk, stir till combined. Fold in sundried tomatoes.", "Pour into pan, drizzle melted butter over top of bread. (Bread will be thick, flatten it out with your fingers)", "Bake 30 minutes for mini loaf pans and 40  50 minutes for large loaf pan, or until golden brown and toothpick inserted in center comes out clean. Cool 5 minutes, remove from pan to wire rack. Cool 30 minutes before slicing, if you can control yourself!"]'::jsonb, 'https://www.foodista.com/recipe/W5MF623S/caprese-quick-bread', 'https://img.spoonacular.com/recipes/636962-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('reduced-fat-blueberry-cheesecake-crepes', 'Reduced Fat Blueberry Cheesecake Crepes', 8, 0, 0, '{"calories": 162, "protein": 5.89, "carbs": 24.0, "fat": 4.73, "saturated_fat": 2.55, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 217.51, "potassium": null, "fiber": 0.87, "sugar": 10.81, "vitamin_a": null, "vitamin_c": 1.79, "calcium": 79.56, "iron": 1.0}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "blueberries", "notes": "1 cup Fresh Blueberries", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "butter", "notes": "2 tablespoons butter, melted", "category": "milk, eggs, other dairy"}, {"quantity": 4.0, "unit": "oz", "item": "cream cheese- room temp", "notes": "4 oz. Fat-Free Cream Cheese- room temp", "category": "cheese"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "flour", "notes": "1 cup all-purpose flour", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "milk", "notes": "1/2 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "Cup", "item": "powdered sugar", "notes": "½ Cup powdered sugar", "category": "baking"}, {"quantity": 0.25, "unit": "teaspoon", "item": "salt", "notes": "1/4 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "tsp", "item": "vanilla extract", "notes": "½ tsp. Vanilla extract", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "water", "notes": "1/2 cup water", "category": "beverages"}]'::jsonb, '["Cheesecake Filling:With an electric mixer mix cream cheese and butter on medium speed until smooth", "Using a rubber spatula scrape the sides of the bowl to ensure complete mixing", "Add vanilla", "Slowly add powdered sugar", "Pour in blueberries and mix well on low. Just enough to give the mixture a pink/purple tint. You want most blueberries intact.", "Transfer to an air-tight container or cover with plastic wrap and refrigerate until ready to use.Crepes:In a large mixing bowl, whisk together the flour and the eggs. Gradually add in the milk and water, stirring to combine.", "Add the salt and butter; beat until smooth.", "Heat a lightly oiled griddle or frying pan over medium high heat.", "Pour or scoop the batter onto the griddle, using approximately 1/4 cup for each crepe. Tilt the pan with a circular motion so that the batter coats the surface evenly.Cook the crepe for about 2 minutes, until the bottom is light brown. Loosen with a spatula, turn and cook the other side.", "Lay crepe flat and put a small amount of Blueberry Cheesecake Filling in the center (This is rich so you don''t want to over fill)", "Roll Crepe and put on plate.", "Serve hot."]'::jsonb, 'https://www.foodista.com/recipe/Y6BXKNC4/reduced-fat-blueberry-cheesecake-crepes', 'https://img.spoonacular.com/recipes/658132-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('tiramisu-overnight-oats', 'Tiramisu Overnight Oats', 1, 5, 0, '{"calories": 548, "protein": 22.16, "carbs": 66.66, "fat": 21.52, "saturated_fat": 10.99, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 95.39, "potassium": null, "fiber": 6.9, "sugar": 32.14, "vitamin_a": null, "vitamin_c": 0, "calcium": 370.1, "iron": 2.59}'::jsonb, ARRAY['mediterranean', 'italian', 'european', 'morning meal', 'brunch', 'breakfast', 'gluten free', 'lacto ovo vegetarian', 'spoonacular', 'dessert', 'quick', 'vegetarian'], '[{"quantity": 0.5, "unit": "c", "item": "old fashioned rolled oats", "notes": "1/2 c old fashioned rolled oats", "category": "cereal"}, {"quantity": 1.5, "unit": "tsp", "item": "chia seeds", "notes": "1-1/2 tsp chia seeds", "category": "health foods"}, {"quantity": 2.0, "unit": "Tbsp", "item": "honey", "notes": "2 Tbsp honey, divided (or substitute agave or maple syrup instead)", "category": "cereal"}, {"quantity": 0.25, "unit": "tsp", "item": "vanilla extract", "notes": "1/4 tsp vanilla extract", "category": "baking"}, {"quantity": 6.0, "unit": "Tbsp", "item": "milk", "notes": "6 Tbsp milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "c", "item": "strong coffee", "notes": "1/4 c espresso or strong brewed coffee", "category": "tea and coffee"}, {"quantity": 0.5, "unit": "c", "item": "greek yogurt", "notes": "1/2 c plain Greek yogurt", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "Tbsp", "item": "mascarpone cheese", "notes": "2 Tbsp mascarpone cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "tsp", "item": "cocoa powder", "notes": "1 tsp cocoa powder", "category": "baking"}, {"quantity": 1.0, "unit": "serving", "item": "chocolate & extra cocoa powder", "notes": "Shaved chocolate &amp; extra cocoa powder for garnish", "category": "baking"}]'::jsonb, '["In a bowl, stir together oats, chia seeds, vanilla, 1 tablespoon honey, milk, and coffee.", "Cover and refrigerate overnight (or 8 hours).", "In the morning, in a separate bowl, combine yogurt, mascarpone, cocoa powder, and 1 tablespoon honey.", "Finally, in a tall glass or jelly jar, layer first the oats, then the yogurt mixture; and repeat once more.", "Garnish the top with a little extra cocoa powder and shaved chocolate.", "Enjoy!"]'::jsonb, 'https://maplewoodroad.com/tiramisu-overnight-oats/', 'https://img.spoonacular.com/recipes/1697783-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('asparagus-quiche', 'Asparagus Quiche', 8, 0, 0, '{"calories": 288, "protein": 9.25, "carbs": 7.8, "fat": 25.17, "saturated_fat": 12.55, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 325.25, "potassium": null, "fiber": 1.17, "sugar": 3.71, "vitamin_a": null, "vitamin_c": 13.67, "calcium": 195.36, "iron": 1.11}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'antipasti', 'starter', 'morning meal', 'snack', 'brunch', 'appetizer', 'antipasto', 'breakfast', 'hor d''oeuvre', 'spoonacular', 'baking'], '[{"quantity": 250.0, "unit": "grams", "item": "asparagus tips", "notes": "250 grams asparagus tips, tinned", "category": "canned and jarred"}, {"quantity": 2.0, "unit": "", "item": "slcs bacon", "notes": "2 slcs bacon", "category": "meat"}, {"quantity": 3.0, "unit": "tablespoons", "item": "butter", "notes": "3 tablespoons butter or margarine", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "tasty cheese", "notes": "1 cup grated tasty cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "cup", "item": "cream", "notes": "1 cup cream", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "", "item": "egg yolks", "notes": "1 egg yolks", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 eggs beaten", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "tablespoons", "item": "flour", "notes": "2 tablespoons flour", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "garlic", "notes": "1 teaspoon garlic, crushed", "category": "produce"}, {"quantity": 1.0, "unit": "", "item": "lemons", "notes": "1 lemons", "category": "produce"}, {"quantity": 1.0, "unit": "cup", "item": "milk", "notes": "cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "medium", "item": "onions", "notes": "1 onions, medium", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "parmesan cheese", "notes": "2 tablespoons Parmesan cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "", "item": "pch salt", "notes": "1 pch salt", "category": "spices and seasonings"}]'::jsonb, '["Pastry:Sift flour and salt into a bowl, rub in butter, add egg yolk and lemon juice and mix to a firm dough. Cover and refrigerate 20 minutes.", "Roll dough out large enough to line a 25cm flan tin, trim the edges. Cover pastry with greaseproof paper and fill with dried beans or rice to hold in shape while cooking.", "Bake in a moderate oven for 7 minutes, remove paper and beans and bake a further 7 minutes. Set aside until required.", "Whisk eggs, cream, milk and cheeses together and set aside.Slice onion and cut bacon into strips.Melt butter in a pan and cook onion and bacon for 2 minutes until tender.", "Spread onion-bacon mixture evenly over pastry. Top with well drained asparagus spears.", "Pour over egg mixture and sprinkle with paprika.", "Bake in a moderate oven for about 30 minutes or until set.", "Serves 4.Use commercially prepared short pastry if desired.(Available at supermarket)"]'::jsonb, 'http://www.foodista.com/recipe/W8Y7DRYC/asparagus-quiche', 'https://img.spoonacular.com/recipes/632949-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
