ell, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('bacon-and-arugula-quiche', 'Bacon and Arugula Quiche', 9, 0, 0, '{"calories": 224, "protein": 7.5, "carbs": 5.82, "fat": 19.35, "saturated_fat": 10.03, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 201.09, "potassium": null, "fiber": 1.04, "sugar": 2.12, "vitamin_a": null, "vitamin_c": 8.29, "calcium": 134.42, "iron": 1.21}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'antipasti', 'starter', 'morning meal', 'snack', 'brunch', 'appetizer', 'antipasto', 'breakfast', 'hor d''oeuvre', 'spoonacular', 'salad', 'baking'], '[{"quantity": 8.0, "unit": "ounces", "item": "baby spinach leaves", "notes": "8 ounces baby arugula or baby spinach leaves, coarsely chopped", "category": "produce"}, {"quantity": 6.0, "unit": "slices", "item": "bacon", "notes": "6 bacon slices, cut into 1/2-inch pieces", "category": "meat"}, {"quantity": 2.0, "unit": "teaspoons", "item": "balsamic vinegar", "notes": "2 teaspoons balsamic vinegar", "category": "oil, vinegar, salad dressing"}, {"quantity": 0.25, "unit": "teaspoon", "item": "pepper", "notes": "1/4 teaspoon Black pepper, to taste", "category": "spices and seasonings"}, {"quantity": 2.0, "unit": "", "item": "eggs", "notes": "2 Eggs, beaten", "category": "milk, eggs, other dairy"}, {"quantity": 1.0, "unit": "cup", "item": "heavy cream", "notes": "1 cup heavy cream", "category": "milk, eggs, other dairy"}, {"quantity": 9.0, "unit": "inch", "item": "pre-baked pastry crust", "notes": "A 9-inch pre-baked pastry crust", "category": "frozen"}, {"quantity": 0.125, "unit": "teaspoon", "item": "salt", "notes": "1/8 teaspoon salt", "category": "spices and seasonings"}, {"quantity": 0.5, "unit": "cup", "item": "shallots", "notes": "1/2 cup chopped shallots", "category": "produce"}, {"quantity": 0.75, "unit": "cup", "item": "swiss cheese", "notes": "3/4 cup shredded Gruyere, Emmental or Swiss cheese", "category": "cheese"}]'::jsonb, '["Preheat oven to 400 F. Thaw purchased crust for 10 minutes.", "Bake 10-12 minutes until golden. After pre-baking purchased crust, lower oven temperature to 375F.In a large skillet on medium heat,cook bacon pieces until crispy.", "Drain on paper towels, reserving 2 tablespoons bacon drippings.", "Add chopped shallots and saute until tender.", "Add chopped arugula, saute until just wilted, about 1 minute.", "Remove from heat, add balsamic vinegar and toss to combine.In prepared pastry, layer arugula mixture, then crispy bacon pieces. In a large measuring cup or bowl, whisk together heavy cream, eggs and salt and pepper. Stir in Gruyere cheese.", "Pour this mixture over the arugula bacon layers.", "Bake until puffed and golden, about 35 minutes.", "Let stand at least 10 minutes before slicing."]'::jsonb, 'http://www.foodista.com/recipe/G4TLNK7J/bacon-and-arugula-quiche', 'https://img.spoonacular.com/recipes/633267-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('puff-paste-quiche', 'Puff Paste quiche', 4, 0, 0, '{"calories": 541, "protein": 29.26, "carbs": 53.24, "fat": 25.5, "saturated_fat": 10.93, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 4939.65, "potassium": null, "fiber": 8.11, "sugar": 22.48, "vitamin_a": null, "vitamin_c": 7.34, "calcium": 379.47, "iron": 4.89}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'lunch', 'main course', 'morning meal', 'brunch', 'main dish', 'breakfast', 'dinner', 'gluten free', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 20.0, "unit": "g", "item": "butter", "notes": "20 g butter", "category": "milk, eggs, other dairy"}, {"quantity": 100.0, "unit": "gram", "item": "mold cheese", "notes": "100 gram blue mold cheese", "category": "cheese"}, {"quantity": 500.0, "unit": "g", "item": "puff paste", "notes": "500 g puff paste", "category": "ethnic foods"}, {"quantity": 3.0, "unit": "", "item": "eggs", "notes": "3 eggs", "category": "milk, eggs, other dairy"}, {"quantity": 250.0, "unit": "gram", "item": "grapes", "notes": "250 gram grapes", "category": "produce"}, {"quantity": 2.0, "unit": "", "item": "stems leek", "notes": "2 stems leek", "category": "produce"}, {"quantity": 250.0, "unit": "ml", "item": "milk", "notes": "250ml milk", "category": "milk, eggs, other dairy"}]'::jsonb, '["cut the leek in stripes and stew it for ten minutes in the buttercut the grapes to halfes and remove the coresput the milk, the eggs, the leak and the grapes together with the cheese (little pieces) in a bowl and and stir it.arrange the puff paste on two baking bowls (see photo)put the mix of leek, cheese and eggs in the bowlsbake it for 25 minutes at 200 degree Warning: don''t put the eggs on the hot leek"]'::jsonb, 'http://spoonacular.com/-1381569952945', 'https://img.spoonacular.com/recipes/157093-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('sterling-cooper-blini-with-caviar', 'Sterling Cooper Blini with Caviar', 16, 0, 0, '{"calories": 83, "protein": 1.49, "carbs": 3.84, "fat": 7.03, "saturated_fat": 4.22, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 82.89, "potassium": null, "fiber": 0, "sugar": 0.78, "vitamin_a": null, "vitamin_c": 0, "calcium": 30.27, "iron": 0.37}'::jsonb, ARRAY['eastern european', 'european', 'morning meal', 'brunch', 'breakfast', 'pescatarian', 'spoonacular', 'dessert', 'baking', 'vegetarian'], '[{"quantity": 0.5, "unit": "teaspoon", "item": "baking powder", "notes": "1/2 teaspoon baking powder", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "butter", "notes": "1/2 cup butter", "category": "milk, eggs, other dairy"}, {"quantity": 16.0, "unit": "servings", "item": "caviar", "notes": "Caviar, for topping", "category": "gourmet"}, {"quantity": 1.0, "unit": "", "item": "egg", "notes": "1 egg", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "cup", "item": "flour", "notes": "1/2 cup sifted all-purpose flour", "category": "baking"}, {"quantity": 0.75, "unit": "cup", "item": "milk", "notes": "¾ cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 3.0, "unit": "tablespoons", "item": "cream", "notes": "3 tablespoons sour cream, plus additional for topping blini", "category": "milk, eggs, other dairy"}, {"quantity": 0.5, "unit": "teaspoon", "item": "sugar", "notes": "1/2 teaspoon sugar", "category": "baking"}]'::jsonb, '["In a large bowl, sift the flour and baking powder together.", "Add the milk, sugar and 2 tablespoons sour cream. Beat the egg until frothy, add to batter and stir well.", "Let batter stand for 20 minutes.Melt butter on a griddle or large skillet.  Fry small (2-3 inch) pancakes in very hot butter.", "Drain on paper towels. Top each blini with sour cream and caviar before serving."]'::jsonb, 'https://www.foodista.com/recipe/FR7746PB/sterling-cooper-blini-with-caviar', 'https://img.spoonacular.com/recipes/661602-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('vegetable-cheddar-quiche', 'Vegetable Cheddar Quiche', 8, 0, 0, '{"calories": 279, "protein": 6.78, "carbs": 14.76, "fat": 21.76, "saturated_fat": 6.55, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 426.19, "potassium": null, "fiber": 1.43, "sugar": 1.91, "vitamin_a": null, "vitamin_c": 13.21, "calcium": 155.52, "iron": 0.95}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'antipasti', 'starter', 'morning meal', 'snack', 'brunch', 'appetizer', 'antipasto', 'breakfast', 'hor d''oeuvre', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 1.0, "unit": "cup", "item": "broccoli florets", "notes": "1 cup Broccoli florets", "category": "produce"}, {"quantity": 0.125, "unit": "tsp", "item": "cayenne pepper", "notes": "⅛ tsp cayenne pepper", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "servings", "item": "cilantro", "notes": "Cilantro for garnish", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "mushrooms", "notes": "1 cup sliced fresh mushrooms", "category": "produce"}, {"quantity": 2.0, "unit": "cloves", "item": "garlic", "notes": "2 cloves minced garlic", "category": "produce"}, {"quantity": 0.33333334, "unit": "cup", "item": "mayonnaise", "notes": "1/3 cup mayonnaise", "category": "condiments"}, {"quantity": 0.33333334, "unit": "cup", "item": "milk", "notes": "1/3 cup milk", "category": "milk, eggs, other dairy"}, {"quantity": 2.0, "unit": "Tbs", "item": "olive oil", "notes": "2 Tbs olive oil", "category": "oil, vinegar, salad dressing"}, {"quantity": 1.0, "unit": "cup", "item": "onions", "notes": "1 cup chopped onions", "category": "produce"}, {"quantity": 3.0, "unit": "Tbs", "item": "parmesan cheese - is best", "notes": "3 Tbs parmesan cheese – freshly grated is best.", "category": "cheese"}, {"quantity": 0.5, "unit": "tsp", "item": "pepper", "notes": "½ tsp pepper", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "", "item": "pie crust", "notes": "1 refrigerated pie crust", "category": "refrigerated"}, {"quantity": 0.5, "unit": "tsp", "item": "salt", "notes": "½ tsp salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "sharp cheddar cheese", "notes": "1 cup shredded Sharp Cheddar cheese", "category": "cheese"}, {"quantity": 1.0, "unit": "cup", "item": "spinach", "notes": "1 cup fresh spinach", "category": "produce"}]'::jsonb, '["Preheat oven to 37", "Unroll pie crust and place into pie plate, crimp edges and set aside. Cook vegetables and garlic in frying pan over medium heat on stove top for about 5 minutes until tender  stir occasionally.", "Add salt, pepper and cayenne pepper while cooking. After vegetables are tender, remove pan from the heat and set aside to cool.In a bowl, beat the eggs, mayonnaise and milk with a whisk until all is blended and smooth. Once vegetables have cooled, add them to the egg mix.", "Add the cheese as well and then pour the mixture into the pie crust. Top with the 3 tbs of grated parmesan cheese.", "Bake for 40-45 minutes until you can jiggle the pie plate and the center of the quiche is set and not jiggly! The top should be golden brown.", "Let quiche stand for 10 minutes before cutting to serve.", "Garnish with cilantro"]'::jsonb, 'http://www.foodista.com/recipe/KH7DRH22/vegetable-cheddar-quiche', 'https://img.spoonacular.com/recipes/664533-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('gluten-free-quinoa-and-corn-flour-crepes', 'Gluten Free Quinoa and Corn Flour Crepes', 4, 40, 20, '{"calories": 423, "protein": 4.27, "carbs": 65.98, "fat": 17.16, "saturated_fat": 11.69, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 218.79, "potassium": null, "fiber": 2.69, "sugar": 10.13, "vitamin_a": null, "vitamin_c": 0, "calcium": 50.46, "iron": 1.32}'::jsonb, ARRAY['mediterranean', 'french', 'european', 'morning meal', 'dessert', 'brunch', 'breakfast', 'gluten free', 'dairy free', 'lacto ovo vegetarian', 'vegan', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 4.0, "unit": "servings", "item": "virgin coconut oil", "notes": "virgin coconut oil for cooking", "category": "baking"}, {"quantity": 0.5, "unit": "cup", "item": "corn flour", "notes": "1/2 cup corn flour (different from cornmeal)", "category": "baking"}, {"quantity": 1.0, "unit": "tablespoon", "item": "ground flax seeds", "notes": "1 tablespoon ground flax seeds (plus 3 tablespoons boiling water, whisked)", "category": "health foods"}, {"quantity": 1.0, "unit": "tablespoon", "item": "maple syrup", "notes": "1 tablespoon pure maple syrup", "category": "cereal"}, {"quantity": 0.5, "unit": "cup", "item": "quinoa flour", "notes": "1/2 cup quinoa flour", "category": "gluten free"}, {"quantity": 2.5, "unit": "cups", "item": "rice milk", "notes": "2 1/2 cups hemp, soy, almond, or rice milk", "category": "milk, eggs, other dairy"}, {"quantity": 0.25, "unit": "teaspoon", "item": "sea salt", "notes": "1/4 teaspoon sea salt", "category": "spices and seasonings"}, {"quantity": 1.0, "unit": "cup", "item": "tapioca flour", "notes": "cup tapioca flour", "category": "baking"}, {"quantity": 0.5, "unit": "teaspoon", "item": "xanthan gum", "notes": "1/2 teaspoon xanthan gum", "category": "health foods"}]'::jsonb, '["Whisk the dry ingredients together in a bowl. In a separate bowl, whisk 2 1/2 cups hemp milk, flax seed mixture, maple syrup, and the melted coconut oil together.", "Add the wet ingredients to the dry ingredients and gently mix together. If the batter is too thick, add a few tablespoons of hemp milk at a time, up to 1/2 cup more hemp milk to make a pourable batter. (The batter should be thin enough to spread easily in the pan). Allow the batter rest in the refrigerator for at least 30 minutes.", "Heat an 8- or 10-inch nonstick skillet over medium heat.", "Add a small dab of virgin coconut oil for cooking.", "Pour about 1/2 cup batter into the skillet and at the same time, rotate the pan so the batter covers a thin layer on the bottom. Use small amounts of batter to repair any holes; work quickly and keep the crepe thin.Cook until the top of the crepe is dry, after about 1 minute, loosen the edges of the crepe from the pan with a spatula. Flip with your fingers or gently toss and flip (this may take a few attempts, but works best) and cook the other side for 30 to 60 seconds. Stack the cooked crepes on a plate. Keep them warm in a low oven or fill each crepe while it''s in the pan, spooning the filling across the lower third of the crepe.", "Roll the crepe from the filling end or fold the bottom third over the filling, fold in the sides, then fold the crepe from the bottom up to make a pocket. Repeat the process, adding more coconut oil between crepes as needed, until all the batter is used up."]'::jsonb, 'http://www.foodista.com/recipe/MGMB6CBY/gluten-free-quinoa-and-corn-flour-crepes', 'https://img.spoonacular.com/recipes/644854-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('irish-soda-bread-with-raisins', 'Irish Soda Bread with Raisins', 8, 0, 0, '{"calories": 158, "protein": 2.21, "carbs": 22.34, "fat": 7.37, "saturated_fat": 4.53, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 458.04, "potassium": null, "fiber": 0.93, "sugar": 9.7, "vitamin_a": null, "vitamin_c": 0, "calcium": 101.66, "iron": 0.6}'::jsonb, ARRAY['european', 'irish', 'morning meal', 'dessert', 'brunch', 'breakfast', 'lacto ovo vegetarian', 'spoonacular', 'baking', 'vegetarian'], '[{"quantity": 0.25, "unit": "cup", "item": "all purpose flour", "notes": "1/4 cup all purpose flour", "category": "baking"}, {"quantity": 1.5, "unit": "teaspoons", "item": "baking powder", "notes": "1 1/2 teaspoons baking powder", "category": "baking"}, {"quantity": 1.0, "unit": "teaspoon", "item": "baking soda", "notes": "1 teaspoon Baking Soda", "category": "baking"}, {"quantity": 0.25, "unit": "cup", "item": "butter", "notes": "1/4 cup Butter", "category": "milk, eggs, other dairy"}, {"quantity": 1.5, "unit": "cups", "item": "buttermilk", "notes": "1 1/2 cups Buttermilk", "category": "milk, eggs, other dairy"}, {"quantity": 0.6666667, "unit": "cup", "item": "raisins", "notes": "2/3 cup raisins", "category": "produce"}, {"quantity": 0.5, "unit": "teaspoon", "item": "salt", "notes": "1/2 teaspoon Salt", "category": "spices and seasonings"}, {"quantity": 5.0, "unit": "tablespoons", "item": "sugar", "notes": "5 tablespoons sugar, divided", "category": "baking"}]'::jsonb, '["Preheat oven to 375F. Spray 8-inch-diameter cake pan with nonstick spray.", "Whisk flour, 4 tablespoons sugar, baking powder, salt, and baking soda in large bowl to blend.", "Add butter. Using fingertips, rub in until coarse meal forms. Make well in center of flour mixture.", "Add buttermilk. Gradually stir dry ingredients into milk to blend.", "Mix in raisins.Using floured hands, shape dough into ball.", "Transfer to prepared pan and flatten slightly (dough will not come to edges of pan). With a sharp knife, slice a shallow X across the top (optional).", "Sprinkle dough with remaining 1 tablespoon sugar.", "Bake bread until brown and tester inserted into center comes out clean, about 40 minutes. Cool bread in pan 10 minutes.", "Transfer to rack.", "Serve warm or at room temperature."]'::jsonb, 'https://www.foodista.com/recipe/HZ8H3Y4H/irish-soda-bread-with-raisins', 'https://img.spoonacular.com/recipes/648004-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
INSERT INTO public.recipes (slug, name, servings, prep_time_minutes, cook_time_minutes, nutrition, tags, ingredients, instructions, source_url, image_url, reheats_well, stores_days, packs_well_as_lunch) VALUES ('my-grandmothers-migas', 'My Grandmother''s Migas', 8, 0, 0, '{"calories": 56, "protein": 2.26, "carbs": 2.91, "fat": 4.11, "saturated_fat": 0.89, "polyunsaturated_fat": null, "monounsaturated_fat": null, "sodium": 970.85, "potassium": null, "fiber": 0.38, "sugar": 0.27, "vitamin_a": null, "vitamin_c": 1.8, "calcium": 12.98, "iron": 0.38}'::jsonb, ARRAY['spanish', 'european', 'morning meal', 'brunch', 'breakfast', 'dairy free', 'spoonacular'], '[{"quantity": 1.0, "unit": "handful", "item": "bacon rashers", "notes": "1 handful bacon rashers", "category": "meat"}, {"quantity": 1.0, "unit": "", "item": "hunk of dense crumb bread", "notes": "1 hunk of dense crumb stale bread, diced in chickpea-sized pieces", "category": "bakery/bread"}, {"quantity": 2.0, "unit": "", "item": "chorizos", "notes": "2 chorizos for frying, diced", "category": "meat"}, {"quantity": 8.0, "unit": "", "item": "garlic", "notes": "8 garlic", "category": "produce"}, {"quantity": 2.0, "unit": "tablespoons", "item": "jamón", "notes": "2 tablespoons diced Spanish jamón", "category": "meat"}, {"quantity": 2.0, "unit": "teaspoons", "item": "pimentón", "notes": "2 teaspoons sweet Spanish pimentón", "category": "ethnic foods"}, {"quantity": 3.0, "unit": "teaspoons", "item": "salt", "notes": "3 teaspoons salt", "category": "spices and seasonings"}, {"quantity": 8.0, "unit": "servings", "item": "virgin olive oil", "notes": "Virgin olive oil for frying", "category": "oil, vinegar, salad dressing"}]'::jsonb, '["Pick the hunk of stale bread and dice it carefully.", "Put the diced bread in a large bowl. Then sprinkle the bread with water, enough to slightly moisten it.", "Sprinkle the salt and toss the bread to evenly distribute the salt. Do the same with the pimentn. Then cover with a damp cloth and leave to rest overnight.The next day, pour 6-8 tablespoons of olive oil in a deep frying pan and put it on medium heat.", "Cut the garlic cloves in half, without peeling.Fry the garlic until lightly browned, just to flavor the oil, then discard.", "Add the crumbled or diced chorizo, the ham and the bacon. Stir-fry till they''re almost done.Tip the diced bread on the pan. Toss and turn around for the bread to thoroughly soak the oil.Go on tossing for 3-4 minutes, on medium heat. The migas should be lightly toasted and crisp on the outside, while they should remain soft in the inside."]'::jsonb, 'https://www.foodista.com/recipe/Q7JJSL2N/my-grandmothers-migas', 'https://img.spoonacular.com/recipes/652864-312x231.jpg', FALSE, 0, FALSE) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, servings = EXCLUDED.servings, prep_time_minutes = EXCLUDED.prep_time_minutes, cook_time_minutes = EXCLUDED.cook_time_minutes, nutrition = EXCLUDED.nutrition, tags = EXCLUDED.tags, ingredients = EXCLUDED.ingredients, instructions = EXCLUDED.instructions, source_url = EXCLUDED.source_url, image_url = EXCLUDED.image_url, reheats_well = EXCLUDED.reheats_well, stores_days = EXCLUDED.stores_days, packs_well_as_lunch = EXCLUDED.packs_well_as_lunch;
